INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2a5bb785-01ca-47fc-8e54-c27d4dfea77d', 'benefits', 'https://familienportal.de/', 'active', NULL, '2026-03-16T15:07:40.627738+00:00', '{"id":"2a5bb785-01ca-47fc-8e54-c27d4dfea77d","title":"Familienportal","summary":{"de":"Das Familienportal bündelt alle relevanten Informationen zu staatlichen Familienleistungen, gesetzlichen Regelungen und Beratungsangeboten für Familien."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Hier finden Sie Informationen rund um die Familie. Informationen für Pflegefamilien Sie möchten Pflegeeltern werden? Wir informieren Sie über Voraussetzungen und Unterstützungsangebote für Pflegeeltern. Sie möchten Pflegeeltern werden? Wir informieren Sie über Voraussetzungen und Unterstützungsangebote für Pflegeeltern. Checklisten rund um die Geburt Bevor und nachdem ein Baby auf die Welt kommt, gibt es viel zu organisieren. Damit Sie nichts vergessen, gibt es unsere praktischen Checklisten: Digital oder zum Ausdrucken. Bevor und nachdem ein Baby auf die Welt kommt, gibt es viel zu organisieren. Damit Sie nichts vergessen, gibt es unsere praktischen Checklisten: Digital oder zum Ausdrucken."},"url":"https://familienportal.de/","topics":["family","financial_support","benefits"],"tags":["application_required","benefit"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-16T15:07:40.627738+00:00","lastSeen":"2026-03-16T15:07:40.627738+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Das Familienportal bündelt alle relevanten Informationen zu staatlichen Familienleistungen, gesetzlichen Regelungen und Beratungsangeboten für Familien."},"provenance":{"source":"http://www.familienportal.de/","crawledAt":"2026-03-16T15:07:40.637384Z","crawlId":"benefits-seeded-1773673660","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"6a6745dbd9d49d0a379719d0fa6925e57984db5b2053fbfc6ff83ebdedab3b48"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:40.637384+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e959e414-8a5d-4c8b-9816-b7fdb757f41a', 'benefits', 'https://familienportal.de/familienportal/familienleistungen/kinderzuschlag', 'active', NULL, '2026-03-16T13:43:19.707303+00:00', '{"id":"e959e414-8a5d-4c8b-9816-b7fdb757f41a","title":"Kinderzuschlag","summary":{"de":"Der Kinderzuschlag ist eine staatliche Familienleistung in Deutschland. Hier erfahren Sie, was Sie zum Kinderzuschlag wissen müssen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Den Kinderzuschlag (kurz: KiZ) können Sie bekommen, wenn Ihr Einkommen für den eigenen Lebensunterhalt reicht, aber es nicht oder nur knapp ausreicht, um auch für den gesamten Bedarf Ihrer Familie aufzukommen. Der Kinderzuschlag beträgt ab 1. Januar 2025 pro Kind bis zu 297 Euro im Monat, abhängig von der Situation Ihrer Familie. Darin ist der Sofortzuschlag von monatlich 25 Euro je Kind enthalten. Wenn Ihr Einkommen höher ist als Ihr eigener Bedarf, verringert sich der Kinderzuschlag. Auch das Einkommen Ihrer Kinder wird berücksichtigt, zum Beispiel, wenn Ihre Kinder Unterhalt, Unterhaltsvorschuss oder Waisenrente bekommen. Das Einkommen Ihrer Kinder wird jedoch nicht in vollem Umfang auf den Kinderzuschlag angerechnet, sondern nur zu 45 Prozent. Wenn Sie Kinderzuschlag und/oder Wohngeld bekommen, dann können Sie zusätzlich für ihre Kinder Leistungen für Bildung und Teilhabe erhalten. Das ist zum Beispiel ein kostenloses Mittagessen in Schule und Kita oder ein Schulbedarfspaket in Höhe von 195 Euro. Bezieherinnen und Bezieher des Kinderzuschlags können sich außerdem von den Kita-Gebühren befreien lassen. Der Kinderzuschlag wird zusammen mit dem Kindergeld ausgezahlt. Hier finden Sie eine Übersicht der Auszahlungstermine."},"url":"https://familienportal.de/familienportal/familienleistungen/kinderzuschlag","topics":["financial_support","kinderzuschlag"],"tags":["official_rule_source","family_benefits"],"targetGroups":["families","parents"],"status":"active","firstSeen":"2026-03-16T13:43:19.707303+00:00","lastSeen":"2026-03-16T13:43:19.707303+00:00","sourceUnavailable":false,"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://familienportal.de/familienportal/familienleistungen/kinderzuschlag","crawledAt":"2026-03-16T13:43:19.708307Z","crawlId":"benefits-seeded-1773668599","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"3e24d1423b20b68cfd76be7d2b12053d1199454617ccd9da9180a75b502a39a0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:19.708307+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c6fb568f-2e9a-4b26-b6c6-74c0e38205c9', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld', 'active', NULL, '2026-03-15T07:13:17.338461+00:00', '{"title":"Bürgergeld (Arbeitslosengeld II)","translations":{"de-LEICHT":{"title":"Bürgergeld","timestamp":"2026-03-01T18:38:38.422182Z","provenance":{"source":"https://www.arbeitsagentur.de/arbeitslosengeld-2","crawledAt":"2026-03-01T18:38:38.422182Z"},"method":"human","reviewed":true}},"summary":{"de":"Informieren Sie sich über Bürgergeld, wenn Sie schon länger arbeitslos sind, keinen Anspruch auf Arbeitslosengeld haben oder Ihr Einkommen nicht für den Lebensunterhalt reicht."},"content":{"de":"Stellen Sie den Antrag auf Bürgergeld online bei Ihrem Jobcenter. Beantragen Sie online die Weiterbewilligung von Bürgergeld. Teilen Sie online Veränderungen Ihrer persönlichen und finanziellen Verhältnisse mit. Tauschen Sie Nachrichten online mit Ihrem Jobcenter aus. Melden Sie sich dazu in Ihrem Profil an. Schritt für Schritt: Wie Sie Bürgergeld online bei Ihrem Jobcenter beantragen. Was Sie über Antrag und Bezug der Leistung wissen sollten."},"eligibilityCriteria":{"de":"Ihr Jobcenter unterstützt Sie, wenn Sie länger arbeitslos sind, keinen Anspruch auf Arbeitslosengeld haben oder Ihr Einkommen nicht für den Lebensunterhalt ausreicht. Informieren Sie sich zum Beispiel, wie Sie Bürgergeld erhalten und wie das Jobcenter Ihnen hilft, neue Arbeit zu finden."},"applicationSteps":[{"de":"Bundesministerium für Arbeit und Soziales: Bürgergeld auf einen Blick"}],"topics":["financial_support","employment"],"tags":["means_tested","application_required"],"targetGroups":["unemployed","single_parents","families"],"id":"c6fb568f-2e9a-4b26-b6c6-74c0e38205c9","url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld","status":"active","firstSeen":"2026-03-01T18:38:38.422093+00:00","lastSeen":"2026-03-15T07:13:17.338461+00:00","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld","crawledAt":"2026-03-15T07:13:17.339351Z","crawlId":"arbeitsagentur-1773558797","checksum":"20acd53f2652d47309a2d5a3c74928281b146a896770ca1341a40114dc346b4a","crawlerVersion":"0.1.0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T07:13:17.339351+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('83b1d3da-801a-4156-a66b-938aa72a433b', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/arbeit-finden', 'active', NULL, '2026-03-16T15:07:22.978004+00:00', '{"id":"83b1d3da-801a-4156-a66b-938aa72a433b","title":"Arbeit finden mit Hilfe des Jobcenters","summary":{"de":"Das Jobcenter hilft Ihnen zurück ins Arbeitsleben: Informieren Sie sich über finanziellen Förderungen und Beratungsangebote."},"content":{"de":"So unterstützt Sie die Arbeitsvermittlung Mithilfe unserer Beratung finden Sie Ihren Weg zu einem neuen Arbeitsplatz – Schritt für Schritt. Mithilfe unserer Beratung finden Sie Ihren Weg zu einem neuen Arbeitsplatz – Schritt für Schritt. Betreuung in schwierigen Lebenssituationen Wenn Sie aufgrund persönlicher Probleme nur schwer ins Arbeitsleben finden, kann Ihnen eine Fallmanagerin oder ein Fallmanager zur Seite stehen. Wenn Sie aufgrund persönlicher Probleme nur schwer ins Arbeitsleben finden, kann Ihnen eine Fallmanagerin oder ein Fallmanager zur Seite stehen. Ganzheitliche Betreuung Persönliche Schwierigkeiten verhindern, dass Sie eine Arbeit oder Ausbildung aufnehmen. Finden Sie mit Unterstützung zu neuen Lösungen. Persönliche Schwierigkeiten verhindern, dass Sie eine Arbeit oder Ausbildung aufnehmen. Finden Sie mit Unterstützung zu neuen Lösungen."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/arbeit-finden","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:22.978004+00:00","lastSeen":"2026-03-16T15:07:22.978004+00:00","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/arbeit-finden","crawledAt":"2026-03-16T15:07:22.979564Z","crawlId":"benefits-seeded-1773673642","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"5753c5ba57f5c1ec4b32de7b98334d3e065d2f5be33c71f05f71efc243bf051e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:22.979564+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('71df207c-ef03-4426-b185-f6f7441f26bb', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/buergergeld-beantragen', 'active', NULL, '2026-03-16T15:07:12.991674+00:00', '{"id":"71df207c-ef03-4426-b185-f6f7441f26bb","title":"Bürgergeld online beantragen","summary":{"de":"Bürgergeld (ehemals: Arbeitslosengeld II) einfach online beantragen. Alle Infos und den Link zum digitalen Antrag gibt es hier."},"content":{"de":"Wenn Sie mehr über das Bürgergeld wissen möchten, finden Sie auf folgenden Seiten weitere Informationen: Wenn Sie Fragen zum Bürgergeld oder zum Antrag haben, berät Sie Ihr zuständiges Jobcenter. Die Kontaktdaten ermitteln Sie über die Dienststellensuche: Jobcenter finden Tipp: Tipp: Die Jobcenter-App erleichtert Ihnen die Kommunikation mit Ihrem Jobcenter. Sie können direkt Nachrichten an Ihr Jobcenter senden und Dokumente hochladen. Erfahren Sie im Überblick, wie Sie Bürgergeld beim Jobcenter beantragen. Um Bürgergeld online zu beantragen, melden Sie sich bei Ihrem Benutzerkonto bei der Bundesagentur für Arbeit an. Falls Sie noch kein solches Benutzerkonto haben, müssen Sie sich zunächst registrieren. Anschließend können Sie direkt mit dem Antrag beginnen."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/buergergeld-beantragen","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:12.991674+00:00","lastSeen":"2026-03-16T15:07:12.991674+00:00","sourceUnavailable":false,"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"requiredDocuments":[{"de":"Pruefen Sie auf der Quellseite, welche Unterlagen und Nachweise fuer Ihren Fall verlangt werden."}],"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/buergergeld-beantragen","crawledAt":"2026-03-16T15:07:12.994672Z","crawlId":"benefits-seeded-1773673632","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"d6e26f2279adfd2d3d74bfe3b451be90baaf8aae98b2068c8138d2875dd24f89"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:12.994672+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('34f48c10-23f5-45fd-a2f1-71357830cfd5', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern', 'active', NULL, '2026-03-16T15:07:14.970213+00:00', '{"id":"34f48c10-23f5-45fd-a2f1-71357830cfd5","title":"Finanziell absichern mit Bürgergeld","summary":{"de":"Wann Sie Anspruch auf Bürgergeld haben, wie Sie es beantragen und welche Leistungen Sie erhalten, erfahren Sie hier."},"content":{"de":"Wie Sie Bürgergeld beantragen und was Sie zu Ihrem Bescheid wissen sollten. Wann Sie Anspruch auf Bürgergeld haben und was Sie bei Einkommen und Vermögen beachten müssen. Wie lange Sie Bürgergeld erhalten und wann es ausgezahlt wird. Informieren Sie sich, aus welchen Teilen das Bürgergeld besteht. Wichtiges zur finanziellen Unterstützung rund um Medikamente, Krankenversicherung und Co. Wenn Ihr Anspruch auf Arbeitslosengeld endet und Sie Bürgergeld brauchen."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:14.970213+00:00","lastSeen":"2026-03-16T15:07:14.970213+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Wann Sie Anspruch auf Bürgergeld haben, wie Sie es beantragen und welche Leistungen Sie erhalten, erfahren Sie hier."},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern","crawledAt":"2026-03-16T15:07:14.970810Z","crawlId":"benefits-seeded-1773673634","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"fd2b155a52611fd7d82d33970689151717cbd903f300b0d9147444b12c71a163"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:14.970810+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f5814251-8e87-421d-bb89-3a8d4eb078a4', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/antrag-bescheid', 'active', NULL, '2026-03-16T13:42:55.012960+00:00', '{"id":"f5814251-8e87-421d-bb89-3a8d4eb078a4","title":"Bürgergeld: Antrag und Bescheid","summary":{"de":"Bürgergeld beantragen: Was Sie bei Antrag und Anlagen beachten und Sie bei Ihrem Bescheid prüfen müssen. Jetzt informieren!"},"content":{"de":"Wenn Sie Bürgergeld beantragen, benötigt Ihr Jobcenter Informationen von Ihnen. Anhand Ihrer Angaben prüft Ihr Jobcenter, ob Sie die Voraussetzungen für Bürgergeld erfüllen und damit einen rechtlichen Anspruch darauf haben. Ist das der Fall, ermittelt das Jobcenter zudem, wie viel Bürgergeld Sie grundsätzlich erhalten können. Wichtig: Wichtig: Leben Sie mit anderen Personen in einer Bedarfsgemeinschaft, stellen Sie den Antrag für alle diese Personen. Entsprechend müssen Sie in diesem Fall Informationen zu allen Mitgliedern Ihrer Bedarfsgemeinschaft liefern. Sie sind in diesem Fall die Vertreterin oder der Vertreter Ihrer Bedarfsgemeinschaft. Grundsätzlich ist der Antrag auf Bürgergeld an keine Form gebunden. Sie können ihn online, persönlich, telefonisch oder schriftlich stellen. Am besten stellen Sie den Bürgergeld-Antrag online. Sie haben dadurch folgende Vorteile: positiv: Sie können den Antrag jederzeit und von überall an Ihr Jobcenter schicken – schnell und sicher. positiv: Sie werden Schritt für Schritt durch den Antrag geführt und erhalten zusätzliche Hilfetexte."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/antrag-bescheid","topics":["financial_support","buergergeld","application_process"],"tags":["official_rule_source","application_required"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:42:55.012960+00:00","lastSeen":"2026-03-16T13:42:55.012960+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Bürgergeld beantragen: Was Sie bei Antrag und Anlagen beachten und Sie bei Ihrem Bescheid prüfen müssen. Jetzt informieren!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/antrag-bescheid","crawledAt":"2026-03-16T13:42:55.012960Z","crawlId":"benefits-seeded-1773668575","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"f6a811844cd5c25a70206e825966b796b8df3c439b43bdd55566eb1210c82733"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:42:55.012960+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6dbce676-e79b-4b7c-b860-24f70839dcab', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/einkommen-ergaenzen', 'active', NULL, '2026-03-16T13:43:03.030078+00:00', '{"id":"6dbce676-e79b-4b7c-b860-24f70839dcab","title":"Einkommen mit Bürgergeld ergänzen","summary":{"de":"Reicht Ihr Lohn nicht für den Lebensunterhalt, können Sie ihn mit Bürgergeld aufstocken. Jetzt informieren!"},"content":{"de":"Wenn Ihr Einkommen nicht für Ihren Lebensunterhalt beziehungsweise den Ihrer Bedarfsgemeinschaft reicht, können Sie es mit Bürgergeld ergänzen (umgangssprachlich: aufstocken ). Dabei spielt es keine Rolle, ob Sie angestellt oder selbstständig sind. Sie können diese Leistung beim zuständigen Jobcenter beantragen. Wenn Sie Bürgergeld beziehen, müssen Sie sogenannte vorrangige Leistungen beantragen, wenn Sie darauf Anspruch haben. Damit sind finanzielle Hilfen von anderen Trägern gemeint, die Ihnen oder Mitgliedern Ihrer Bedarfsgemeinschaft zustehen. Wichtig: Wichtig: Wenn Sie trotz Einkommens und vorrangiger Leistungen hilfebedürftig sind, können Sie Ihr Einkommen zusätzlich mit Bürgergeld ergänzen. Wie hoch der Ergänzungsbetrag ist, auf den Sie Anspruch haben, hängt von Ihrem Einkommen und Vermögen sowie Ihrem Bedarf ab. Mit Bedarf ist der Betrag gemeint, der Ihnen und Ihrer Familie für den Lebensunterhalt zusteht. Dieser setzt sich vor allem aus einem festen Regelbedarf und den Kosten für Unterkunft und Heizung zusammen. Von Ihrem Bedarf zieht das Jobcenter Ihr Einkommen ab. Es gibt dabei aber einen bestimmten Teil des Einkommens, der nicht berücksichtigt wird, den sogenannten Frei- oder Absetzungsbetrag. Wie hoch Ihr persönlicher Freibetrag ist, hängt unter anderem von Ihrem Bruttoverdienst und Ihren Beiträgen zur Sozialversicherung ab."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/einkommen-ergaenzen","topics":["financial_support","buergergeld","aufstocker"],"tags":["official_rule_source","income_support"],"targetGroups":["low_income_workers","families"],"status":"active","firstSeen":"2026-03-16T13:43:03.030078+00:00","lastSeen":"2026-03-16T13:43:03.030078+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Reicht Ihr Lohn nicht für den Lebensunterhalt, können Sie ihn mit Bürgergeld aufstocken. Jetzt informieren!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/einkommen-ergaenzen","crawledAt":"2026-03-16T13:43:03.030078Z","crawlId":"benefits-seeded-1773668583","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"bc1a3f833705d47e2c14ad13cdcbf0f001dd9effd206e220e4f3ace6585773fa"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:03.030078+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('afdca595-4615-4493-bafc-5a92b806e965', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/voraussetzungen-einkommen-vermoegen', 'active', NULL, '2026-03-16T13:42:53.026421+00:00', '{"id":"afdca595-4615-4493-bafc-5a92b806e965","title":"Bürgergeld: Voraussetzungen, Einkommen und Vermögen","summary":{"de":"Wer Anspruch auf Bürgergeld hat, welche Voraussetzungen es gibt und was Sie bei Einkommen und Vermögen beachten müssen."},"content":{"de":"Sie können Bürgergeld erhalten, wenn Sie erwerbsfähig und leistungsberechtigt sind und damit mindestens folgende Bedingungen erfüllen: Sie sind mindestens 15 Jahre alt und Sie haben die Altersgrenze für Ihre Rente noch nicht erreicht. Sie wohnen in Deutschland und haben hier Ihren Lebensmittelpunkt. Sie oder Mitglieder Ihrer Bedarfsgemeinschaft sind hilfebedürftig. Hilfebedürftig bedeutet, dass das Einkommen Ihrer Bedarfsgemeinschaft unter dem Existenzminimum liegt und Sie den Lebensunterhalt nicht ausreichend aus eigenen Mitteln bestreiten können. Erwerbsfähig bedeutet, dass keine Krankheit oder Behinderung Sie hindert, eine Arbeit aufzunehmen."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/voraussetzungen-einkommen-vermoegen","topics":["financial_support","buergergeld","eligibility"],"tags":["official_rule_source","eligibility"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:42:53.026421+00:00","lastSeen":"2026-03-16T13:42:53.026421+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Wer Anspruch auf Bürgergeld hat, welche Voraussetzungen es gibt und was Sie bei Einkommen und Vermögen beachten müssen."},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/voraussetzungen-einkommen-vermoegen","crawledAt":"2026-03-16T13:42:53.027420Z","crawlId":"benefits-seeded-1773668573","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"40fb46740262f9f2cfa710d52c84c1d7f546cb8244c75fed8f3bacfb6104b4fe"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:42:53.027420+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('41aabbf4-4d7c-4e7b-af58-0f5815b31aa8', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/zusammensetzung-bedarfe', 'active', NULL, '2026-03-16T13:42:57.038197+00:00', '{"id":"41aabbf4-4d7c-4e7b-af58-0f5815b31aa8","title":"Bedarfe: So setzt sich Bürgergeld zusammen","summary":{"de":"Erfahren Sie, wie sich Ihr Bürgergeld berechnet und bei welchen weiteren Kosten das Jobcenter hilft. Jetzt informieren!"},"content":{"de":"Bürgergeld bekommen Menschen, die hilfebedürftig sind. Das bedeutet, dass Sie Ihren Lebensunterhalt und den Ihrer Bedarfsgemeinschaft nicht selbst bestreiten können. Bürgergeld besteht aus verschiedenen Bausteinen. Diese heißen Bedarfe und bestimmen die Höhe des Bürgergeld. Welche Bedarfe in Ihrem Fall bewilligt wurden, teilt Ihnen das Jobcenter schriftlich mit. Dazu erhalten Sie einen sogenannten Bewilligungsbescheid. Damit sind die Kosten gemeint, die Ihren Lebensunterhalt sichern sollen. Dazu gehören vor allem … Für den Regelbedarf erhalten Sie einen monatlichen Pauschalbetrag. Die genauen Beträge finden Sie auf der Seite des Bundesministeriums für Arbeit und Soziales: Leistungen und Bedarfe im Bürgergeld Tipp: Tipp: Wie Sie den Regelbedarf verwenden, entscheiden Sie selbst. Sie sollten monatlich einen Betrag anzusparen – für den Fall, dass Sie zum Beispiel ein Haushaltsgerät ersetzen müssen. Angemessene Kosten für Miete, Heizung und Betriebskosten werden vom Jobcenter übernommen. Welche Kosten angemessen sind, kann örtlich unterschiedlich sein. Bitte fragen Sie bei Ihrem Jobcenter nach, welche Kosten in Ihrer Region als angemessen gelten."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/zusammensetzung-bedarfe","topics":["financial_support","buergergeld","regelbedarf","mehrbedarf"],"tags":["official_rule_source","benefit_amount"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:42:57.038197+00:00","lastSeen":"2026-03-16T13:42:57.038197+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Erfahren Sie, wie sich Ihr Bürgergeld berechnet und bei welchen weiteren Kosten das Jobcenter hilft. Jetzt informieren!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/zusammensetzung-bedarfe","crawledAt":"2026-03-16T13:42:57.038197Z","crawlId":"benefits-seeded-1773668577","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"2ec9210fa70761abb141a3f49a1aaf647c28fbb9ff99108f3c0dc9a961127c1f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:42:57.038197+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('785fb3e2-3f9b-43b1-9864-f8d3aaafe1b1', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/gesundheit', 'active', NULL, '2026-03-16T15:07:26.980024+00:00', '{"id":"785fb3e2-3f9b-43b1-9864-f8d3aaafe1b1","title":"Jobcenter: Unterstützung bei gesundheitlichen Problemen","summary":{"de":"Bei körperlichen oder psychischen Erkrankungen oder einer Behinderung unterstützt Sie das Jobcenter durch zusätzliche Hilfe. Mehr erfahren!"},"content":{"de":"Arbeitslosigkeit ist für die meisten Menschen eine belastende Erfahrung. Wenn sie lange andauert, kann sie die körperliche und seelische Gesundheit beeinflussen. Gesundheitliche Probleme wiederum können Auswirkungen darauf haben, ob es gelingt, sich erfolgreich auf eine Stelle zu bewerben oder eine Arbeit langfristig zu halten. In solchen Fällen begleiten wir Sie – durch professionelle Beratung und zusätzliche Unterstützung. Das gilt auch, wenn gesundheitliche Probleme oder Einschränkungen der Auslöser für Ihre Arbeitslosigkeit sind. Es spielt dabei keine Rolle, ob Sie eine körperliche Erkrankung, psychische Probleme oder Einschränkung oder eine Behinderung haben. Unser Ziel ist es, dass Sie trotz Erkrankung oder Behinderung neue Chancen im Berufsleben finden. Wir suchen für Sie nach Stellen, die zu Ihren Fähigkeiten und Möglichkeiten passen. Darüber hinaus vermitteln wir Ihnen zum Beispiel … Angebote, mit denen Sie eine Ausbildung, Umschulungen oder Anpassungsqualifizierungen absolvieren können, Coachings, mit denen Sie Ihre Chancen auf eine neue Stelle verbessern und sich persönlich weiterentwickeln oder Programme, mit denen Sie eine neue Tätigkeit ausprobieren können."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/gesundheit","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:26.980024+00:00","lastSeen":"2026-03-16T15:07:26.980024+00:00","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/gesundheit","crawledAt":"2026-03-16T15:07:26.981026Z","crawlId":"benefits-seeded-1773673646","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"a5158bdcaf76dd58012aa86999cb51c59ab0906ad6ad6429b8cfea1a81936e92"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:26.981026+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fa4eb194-899c-4bb3-8e1c-c9f40864d6c5', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/infos-fuer-menschen-aus-dem-ausland', 'active', NULL, '2026-03-16T15:07:28.968606+00:00', '{"id":"fa4eb194-899c-4bb3-8e1c-c9f40864d6c5","title":"Jobcenter: Infos für Menschen aus dem Ausland","summary":{"de":"Auch ausländische Arbeitslose und Geflüchtete können die Beratung und finanzielle Hilfe des Jobcenters nutzen. Hier finden Sie die wichtigsten Informationen."},"content":{"de":"Bürgergeld ist eine staatliche Leistung für Menschen, die kein oder wenig Geld für ihren Lebensunterhalt zur Verfügung haben. Sie können in dieser Situation sein, wenn Sie keine Arbeit haben oder nur sehr wenig verdienen. Wir als Jobcenter sind für das Bürgergeld zuständig. Bürgergeld können Sie auch erhalten, wenn Sie nicht aus Deutschland kommen. Dafür müssen Sie aber bestimmte Voraussetzungen erfüllen. Welche das sind, erfahren Sie auf der Seite Finanzielle Unterstützung in Deutschland. Die wichtigsten Informationen zum Bürgergeld finden Sie gesammelt in der Kurzinformation zur Grundsicherung für Arbeitslose. Das Dokument können Sie am Ende der Seite auch in weiteren Sprachen herunterladen. Wenn Sie aus der Ukraine kommen, finden Sie weitere Informationen auf der Seite Hilfe für Geflüchtete aus der Ukraine. Wir unterstützen Sie nicht nur finanziell, sondern helfen Ihnen auch zum Beispiel in folgenden Situationen: Sie brauchen Hilfe, um in Deutschland eine passende Arbeit zu finden."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/infos-fuer-menschen-aus-dem-ausland","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:28.968606+00:00","lastSeen":"2026-03-16T15:07:28.968606+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Auch ausländische Arbeitslose und Geflüchtete können die Beratung und finanzielle Hilfe des Jobcenters nutzen. Hier finden Sie die wichtigsten Informationen."},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/infos-fuer-menschen-aus-dem-ausland","crawledAt":"2026-03-16T15:07:28.969606Z","crawlId":"benefits-seeded-1773673648","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"fcba5e074d3831edf653ae070f99717fce6595a814c1b9632337008f0e5f9f36"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:28.969606+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('82d61e23-e525-4328-81fe-5dbd65a25005', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/kooperationsplan', 'active', NULL, '2026-03-16T15:07:21.382452+00:00', '{"id":"82d61e23-e525-4328-81fe-5dbd65a25005","title":"Kooperationsplan mit dem Jobcenter","summary":{"de":"Wenn Sie Bürgergeld erhalten, schließen Sie mit Jobcenter einen Kooperationsplan ab. Erfahren Sie, worum es dabei geht. Jetzt informieren!"},"content":{"de":"Erhalten Sie Bürgergeld, erstellen Sie gemeinsam mit Ihrer Ansprechpartnerin beziehungsweise Ihrem Ansprechpartner einen Kooperationsplan. In diesem legen wir gemeinsam ein Ziel fest und beschreiben den Weg, wie wir dieses erreichen. Der Kooperationsplan ist dabei auf das Wesentliche reduziert und verständlich formuliert. Sie haben alles Notwendige kompakt zusammengefasst und können auf einen Blick sehen, welche Schritte gemeinsam unternommen werden. Er ist rechtlich unverbindlich und stellt eine vertrauensvolle und partnerschaftliche Zusammenarbeit in den Mittelpunkt. Es gibt möglicherweise Situationen, in denen Sie und Ihre Ansprechpartnerin beziehungsweise Ihr Ansprechpartner bei der Erstellung oder Verlängerung des Kooperationsplans unterschiedliche Vorstellungen haben. Kommt es dabei zu keiner gemeinsamen Lösung, besteht die Möglichkeit, ein Schlichtungsverfahren einzuleiten. Wenden Sie sich hierzu bitte an Ihre Ansprechpartnerin beziehungsweise Ihren Ansprechpartner im Jobcenter. Weitere Informationen zum Kooperationsplan und dem Schlichtungsverfahren finden Sie im Flyer (Download-Bereich). Wir sind für Sie da. Kommen Sie persönlich vorbei oder kontaktieren Sie uns."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/kooperationsplan","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:21.382452+00:00","lastSeen":"2026-03-16T15:07:21.382452+00:00","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/kooperationsplan","crawledAt":"2026-03-16T15:07:21.383453Z","crawlId":"benefits-seeded-1773673641","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"7b42528395fa481d12727295e5a0e70632bbb25c003ae2e079986098d668c4a1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:21.383453+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8db7919b-63db-4c73-a0b9-b4c14bb8c104', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/pflichten-verstehen-und-beachten', 'active', NULL, '2026-03-16T13:43:01.025928+00:00', '{"id":"8db7919b-63db-4c73-a0b9-b4c14bb8c104","title":"Bürgergeld: Pflichten verstehen und beachten","summary":{"de":"Änderungen mitteilen, Erreichbarkeit absprechen und Co.: Welche Pflichten Sie haben, wenn Sie Bürgergeld erhalten."},"content":{"de":"Welche Änderungen wichtig sind und was Sie bei Nachweisen beachten müssen. Informieren Sie sich darüber, was Sie tun müssen, wenn Sie vorübergehend nicht erreichbar sind, weil Sie zum Beispiel verreisen wollen. Wie Sie das Jobcenter unterstützt, welche Pflichten Sie haben und was Minderungen bedeuten. Erfahren Sie, wie wir Ihre persönlichen Daten schützen. Wir sind für Sie da. Kommen Sie persönlich vorbei oder kontaktieren Sie uns. Bundesministerium für Arbeit und Soziales: Grundsicherung für Arbeitsuchende"},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/pflichten-verstehen-und-beachten","topics":["financial_support","buergergeld","pflichten"],"tags":["official_rule_source","obligations"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:43:01.025928+00:00","lastSeen":"2026-03-16T13:43:01.025928+00:00","sourceUnavailable":false,"requiredDocuments":[{"de":"Pruefen Sie auf der Quellseite, welche Unterlagen und Nachweise fuer Ihren Fall verlangt werden."}],"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/pflichten-verstehen-und-beachten","crawledAt":"2026-03-16T13:43:01.025928Z","crawlId":"benefits-seeded-1773668581","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"214106ce267e5df24b17c8b2a0e7ecd111f56aa2303da3bfce529ecb670c0eac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:01.025928+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('083273b2-cb31-4c26-9d80-b9edbb53f2d7', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/schulabschluss-nachholen', 'active', NULL, '2026-03-16T15:07:30.977372+00:00', '{"id":"083273b2-cb31-4c26-9d80-b9edbb53f2d7","title":"Den Hauptschulabschluss nachholen: Ihre Möglichkeiten","summary":{"de":"Von Abendschule bis Externenprüfung: Viele Wege führen zum Hauptschulabschluss – Ihr Jobcenter unterstützt Sie dabei."},"content":{"de":"Ein Hauptschulabschluss (auch Berufsbildungsreife genannt) ist in den meisten Betrieben eine Grundvoraussetzung für eine Ausbildung. Das heißt: Holen Sie den Abschluss nach, erhöhen Sie Ihre Chancen auf eine Ausbildung um ein Vielfaches. Wichtig ist, dass Sie einen Weg zum Abschluss wählen, der zu Ihrer Lebenssituation passt. Lassen Sie sich dazu von Ihrem Jobcenter beraten. Wir zeigen Ihnen auch finanzielle Unterstützungen auf, die währenddessen für Sie infrage kommen können. Im Folgenden finden Sie eine Übersicht über die unterschiedlichen Wege, wie Sie einen Hauptschulabschluss nachholen können. Sie können sich im Selbststudium auf den Hauptschulabschluss vorbereiten und dann die staatliche Externenprüfung (auch: Nichtschülerprüfung) an einer Bildungseinrichtung für Erwachsene ablegen. Informieren Sie sich über die Externenprüfung bei Ihrem Schulamt vor Ort. Dort erfahren Sie auch, welche Anmeldefristen Sie einhalten müssen, wenn Sie die Prüfung ablegen wollen. Nutzen Sie das Kursangebot zum Nachholen des Hauptschulabschlusses an einer Einrichtung der Erwachsenenbildung, wie zum Beispiel einer Volkshochschule (VHS). Diese Kurse müssen Sie selbst finanzieren. Tipp: Tipp: Empfehlenswert ist der Besuch einer Abendschule. Nur so stellen Sie sicher, dass Sie auch an dem Kurs teilnehmen können, wenn Sie tagsüber arbeiten. In einigen Bundesländern vermitteln Berufsfachschulen fachbezogenes Wissen in einem oder mehreren anerkannten Ausbildungsberufen. Bei einigen Berufsfachschulen können Sie gleichzeitig den Hauptschulabschluss erwerben."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/schulabschluss-nachholen","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:30.977372+00:00","lastSeen":"2026-03-16T15:07:30.977372+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Von Abendschule bis Externenprüfung: Viele Wege führen zum Hauptschulabschluss – Ihr Jobcenter unterstützt Sie dabei."},"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/schulabschluss-nachholen","crawledAt":"2026-03-16T15:07:30.978369Z","crawlId":"benefits-seeded-1773673650","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"fefb79bc828edc06c44d40d33ae8e0422a35ccc73298d669b26ce5d54dba1dfe"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:30.978369+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('95d0bc66-64b4-4e76-985f-09f49b8a832e', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/termin-jobcenter', 'active', NULL, '2026-03-16T15:07:18.978796+00:00', '{"id":"95d0bc66-64b4-4e76-985f-09f49b8a832e","title":"Termin beim Jobcenter","summary":{"de":"Erfahren Sie, um was es bei den Terminen im Jobcenter geht, wie Sie ablaufen und was Sie tun müssen, wenn Sie nicht kommen können. Jetzt informieren!"},"content":{"de":"Termine beim Jobcenter haben eine sogenannte Meldepflicht. Das bedeutet: Sie müssen zu diesen Terminen erscheinen. Das gehört zu Ihren Pflichten, wenn Sie Bürgergeld erhalten. ob Sie die Voraussetzungen für Bürgergeld oder andere finanzielle Unterstützung erfüllen, dass es noch Fragen zu einem Antrag gibt oder Nachweise fehlen, wie Sie sich Ihre berufliche Zukunft vorstellen und wie wir gemeinsam Ihre Jobchancen verbessern, welche Voraussetzungen Sie für das Einstiegsgeld für eine Beschäftigung oder das Einstiegsgeld für eine Selbstständigkeit erfüllen müssen oder wie Sie eine anstehende Weiterbildung oder Umschulung vorbereiten."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/termin-jobcenter","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:18.978796+00:00","lastSeen":"2026-03-16T15:07:18.978796+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Erfahren Sie, um was es bei den Terminen im Jobcenter geht, wie Sie ablaufen und was Sie tun müssen, wenn Sie nicht kommen können. Jetzt informieren!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"requiredDocuments":[{"de":"Pruefen Sie auf der Quellseite, welche Unterlagen und Nachweise fuer Ihren Fall verlangt werden."}],"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/termin-jobcenter","crawledAt":"2026-03-16T15:07:18.981063Z","crawlId":"benefits-seeded-1773673638","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"f5c3c3431ff9b4d1062eb8d0ee7f8bcc61b4ee461a744f42802afb85c9a1ca5f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:18.981063+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0d1484d8-90f9-4af4-8ca0-d11b81252d28', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/unterstuetzung-fuer-familien', 'active', NULL, '2026-03-16T15:07:24.978597+00:00', '{"id":"0d1484d8-90f9-4af4-8ca0-d11b81252d28","title":"Jobcenter: Unterstützung für Familien","summary":{"de":"Sie und Ihre Familie benötigen Unterstützung – wir sind für Sie da: mit Beratung und konkreten Hilfsangeboten."},"content":{"de":"Als Kundin oder Kunde des Jobcenters können Sie auf eine umfassende Beratung und Unterstützung bauen. Dabei haben wir auch Ihre familiären Bedürfnisse im Blick. Wir unterstützen Sie nicht nur finanziell, sondern beraten Sie und bringen Sie mit Netzwerkpartnerinnen und -partnern zusammen, die Ihnen bei Problemen und Fragen rund um Ihre Familie weiterhelfen. Sprechen Sie mit Ihrer Integrationsfachkraft zum Beispiel über … Jobangebote, die flexible Arbeitszeiten ermöglichen, eine Ausbildung, Qualifizierung oder Umschulung in Teilzeit oder Coaching-Angebote, die sich speziell an Alleinerziehende richten. Vereinbaren Sie einen persönlichen oder telefonischen Termin mit uns. Welches Jobcenter für Sie zuständig ist, finden Sie mit der Dienststellen-Suche am Ende dieser Seite heraus."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/unterstuetzung-fuer-familien","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:24.978597+00:00","lastSeen":"2026-03-16T15:07:24.978597+00:00","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/unterstuetzung-fuer-familien","crawledAt":"2026-03-16T15:07:24.979597Z","crawlId":"benefits-seeded-1773673644","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"2e1c4e8590955c726174480cdb38b9763d5b14b903e5d8b6207f0a060a3d6fdb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:24.979597+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0454c2e9-e29f-433a-b5a4-e345b4434b68', 'benefits', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/wohnen', 'active', NULL, '2026-03-16T15:07:16.960566+00:00', '{"id":"0454c2e9-e29f-433a-b5a4-e345b4434b68","title":"Bürgergeld: Wohnen und Miete","summary":{"de":"Erfahren sie hier, welche Kosten das Jobcenter für Miete, Heizung und Co. übernimmt und was Sie beachten müssen."},"content":{"de":"Wenn Sie Bürgergeld beziehen, übernimmt Ihr Jobcenter die Kosten für Unterkunft und Heizung in angemessener Höhe. Welche Kosten angemessen sind, erfahren Sie bei Ihrem Jobcenter. Ihr Jobcenter achtet darauf, dass die Mietkosten und die Größe Ihrer Unterkunft bestimmte Richtwerte nicht überschreiten. Ist Ihre Wohnung nicht angemessen, müssen Sie die Kosten möglichst senken. Das kann zum Beispiel bedeuten, dass Sie in eine günstigere Wohnung umziehen oder ein Zimmer untervermieten. Wichtig: Wichtig: Unterschreiben Sie den Mietvertrag für Ihre neue Unterkunft erst, nachdem Sie sich mit Ihrem (neu) zuständigen Jobcenter abgestimmt haben. Es muss Ihnen zusichern, dass es die Kosten anerkennt. Lassen Sie sich von der Leistungsabteilung Ihres Jobcenters rechtzeitig beraten. Im ersten Jahr des Bezuges von Bürgergeld wird die Angemessenheit der Kosten der Unterkunft nicht geprüft (Karenzzeit). Monate ohne Leistungsbezug in diesem Zeitraum verlängern die Karenzzeit. Wurden in der Vergangenheit nur die angemessenen Kosten übernommen, gilt jedoch Folgendes: Es werden weiterhin ausschließlich die angemessenen Unterkunftskosten berücksichtigt."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/wohnen","topics":["financial_support","buergergeld"],"tags":["application_required","official_rule_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T15:07:16.960566+00:00","lastSeen":"2026-03-16T15:07:16.960566+00:00","sourceUnavailable":false,"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/wohnen","crawledAt":"2026-03-16T15:07:16.961573Z","crawlId":"benefits-seeded-1773673636","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"a57045c68eeac0314e4b52384e2c86fae5d2e53a9e9d19a68b85a8a095957bd0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:16.961573+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d1e12a82-3d83-4f38-8f2d-c1fc11aba996', 'benefits', 'https://www.arbeitsagentur.de/familie-und-kinder', 'active', NULL, '2026-03-16T15:07:36.962872+00:00', '{"id":"d1e12a82-3d83-4f38-8f2d-c1fc11aba996","title":"Familie und Kinder","summary":{"de":"Mit Kindergeld, Kinderzuschlag und weiteren finanziellen Hilfen unterstützt Sie die Familienkasse der Bundesagentur für Arbeit. Jetzt online beantragen!"},"content":{"de":"Ihr Profil im Online-Konto der Bundesagentur für Arbeit ist Ihr digitaler Zugang zur Familienkasse. Mit Ihrem Profil können Sie vieles direkt online erledigen – schnell, rund um die Uhr und von überall. Beantragen Sie Kindergeld für Ihr neugeborenes Kind. Beantragen Sie Kindergeld für Ihr volljähriges Kind. Ändern Sie Ihre persönlichen Daten (zum Beispiel Anschrift, Bankverbindung) oder laden Sie Unterlagen hoch. Beantragen Sie online Kinderzuschlag für Ihr Kind. Kindergeld erhalten Sie für Kinder unter 18 Jahren, unter bestimmten Voraussetzungen auch länger. Informieren Sie sich, wie Sie Kindergeld beantragen und in welcher Höhe es ausgezahlt wird."},"url":"https://www.arbeitsagentur.de/familie-und-kinder","topics":["employment","financial_support","benefits"],"tags":["application_required","public_service","benefit"],"targetGroups":["unemployed","general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-16T15:07:36.962872+00:00","lastSeen":"2026-03-16T15:07:36.962872+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Mit Kindergeld, Kinderzuschlag und weiteren finanziellen Hilfen unterstützt Sie die Familienkasse der Bundesagentur für Arbeit. Jetzt online beantragen!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"requiredDocuments":[{"de":"Pruefen Sie auf der Quellseite, welche Unterlagen und Nachweise fuer Ihren Fall verlangt werden."}],"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder","crawledAt":"2026-03-16T15:07:36.963872Z","crawlId":"benefits-seeded-1773673656","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"7239bdc10388d38dbb6c2f165b45a1381f56ca7194aef321ffd55ad51ded3b5e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T15:07:36.963872+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f20b9ffa-c79e-49ef-9e63-d260b865af25', 'benefits', 'https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen', 'active', NULL, '2026-03-16T13:43:07.013051+00:00', '{"id":"f20b9ffa-c79e-49ef-9e63-d260b865af25","title":"Kinderzuschlag verstehen","summary":{"de":"Kinderzuschlag (auch: Kindergeldzuschlag): Voraussetzungen erfahren, Anspruch berechnen und Antrag stellen. Jetzt informieren!"},"content":{"de":"Der KiZ-Lotse: Anspruch auf Kinderzuschlag ermitteln Zu viel erhaltenes Kindergeld oder Kinderzuschlag zurückzahlen Wir sind für Sie da. Kommen Sie persönlich vorbei oder kontaktieren Sie uns. Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend: Informationen zu Familienleistungen Die wichtigsten Merkblätter, Formulare und Anträge der Familienkasse stehen Ihnen zum Download zur Verfügung. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen","topics":["financial_support","kinderzuschlag"],"tags":["official_rule_source","application_required"],"targetGroups":["families","parents"],"status":"active","firstSeen":"2026-03-16T13:43:07.013051+00:00","lastSeen":"2026-03-16T13:43:07.013051+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Kinderzuschlag (auch: Kindergeldzuschlag): Voraussetzungen erfahren, Anspruch berechnen und Antrag stellen. Jetzt informieren!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen","crawledAt":"2026-03-16T13:43:07.013051Z","crawlId":"benefits-seeded-1773668587","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"069f156297aed47a84ce0c9177fff8d4426a39b1fa7e1ea5d976074dc9c0c39e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:07.013051+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a89c337d-f370-4eb1-9ca7-11ca27aea334', 'benefits', 'https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kinderzuschlag-anspruch-hoehe-dauer', 'active', NULL, '2026-03-16T13:43:09.015887+00:00', '{"id":"a89c337d-f370-4eb1-9ca7-11ca27aea334","title":"Kinderzuschlag: Anspruch, Höhe, Dauer","summary":{"de":"Kinderzuschlag (auch: Kindergeldzuschlag): Wer Kinderzuschlag bekommt, wie Sie den Antrag stellen und wie lange Sie Kinderzuschlag erhalten. Mehr erfahren!"},"content":{"de":"Wenn das Einkommen nicht für die ganze Familie reicht, können Eltern zusätzlich zum Kindergeld den Kinderzuschlag erhalten. Der Antrag auf Kinderzuschlag muss jedoch gesondert bei der Familienkasse gestellt werden. Sie erhalten Kinderzuschlag für 6 Monate. Ist der Bewilligungszeitraum abgelaufen, müssen Sie Kinderzuschlag neu beantragen. Sie haben Anspruch auf Kinderzuschlag, wenn Sie bestimmte Voraussetzungen erfüllen. Ob Sie Kinderzuschlag erhalten, hängt davon ab, wie viel Einkommen und erhebliches Vermögen Sie, Ihr Partner beziehungsweise Ihre Partnerin und Ihr Kind haben. Erhalten Sie Kinderzuschlag, müssen Sie die Familienkasse über Änderungen Ihrer persönlichen Verhältnisse und die Ihrer Familie informieren. positiv: Ihr Kind lebt in Ihrem Haushalt, ist unter 25 Jahre alt und nicht verheiratet beziehungsweise nicht in einer eingetragenen Lebenspartnerschaft. positiv: Sie erhalten Kindergeld (oder eine vergleichbare Leistung) für Ihr Kind."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kinderzuschlag-anspruch-hoehe-dauer","topics":["financial_support","kinderzuschlag","eligibility"],"tags":["official_rule_source","benefit_amount"],"targetGroups":["families","parents"],"status":"active","firstSeen":"2026-03-16T13:43:09.015887+00:00","lastSeen":"2026-03-16T13:43:09.015887+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Kinderzuschlag (auch: Kindergeldzuschlag): Wer Kinderzuschlag bekommt, wie Sie den Antrag stellen und wie lange Sie Kinderzuschlag erhalten. Mehr erfahren!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kinderzuschlag-anspruch-hoehe-dauer","crawledAt":"2026-03-16T13:43:09.015887Z","crawlId":"benefits-seeded-1773668589","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"61ac3b8b2978b104f485cbcf515e321cdd7751abaa70ea106a32f9eaa15e16a8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:09.015887+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ab6ecb16-b9df-4654-bde8-94a02f0d3302', 'benefits', 'https://www.arbeitsagentur.de/kurzarbeitergeld', 'active', NULL, '2026-03-01T20:10:00Z', '{"id":"ab6ecb16-b9df-4654-bde8-94a02f0d3302","title":"Kurzarbeitergeld","translations":{"de-LEICHT":{"title":"Hilfe bei Kurzarbeit","timestamp":"2026-03-01T20:10:00Z","provenance":{"source":"https://www.arbeitsagentur.de/kurzarbeitergeld","crawledAt":"2026-03-01T20:10:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Kurzarbeitergeld unterstützt Betriebe und Beschäftigte bei vorübergehendem Arbeitsausfall, um Beschäftigung zu stabilisieren."},"content":{"de":"Die BA-Seite bündelt Voraussetzungen, Hinweise zur Beantragung und praktische Orientierung für die Umsetzung von Kurzarbeit. Sie ordnet die Leistung in den Kontext der Arbeitslosenversicherung und betrieblicher Krisenbewältigung ein."},"url":"https://www.arbeitsagentur.de/kurzarbeitergeld","topics":["financial_support","employment"],"tags":["application_required","time_limited"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-01T20:10:00Z","lastSeen":"2026-03-01T20:10:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/kurzarbeitergeld","crawlId":"manual-curation-20260301-realdata-v1","checksum":"2ef8ee37d9f5582f3b8debf465436172d0870f3e1977fc89ceef0ad80b0b7e4a","crawledAt":"2026-03-01T20:10:00Z"},"qualityScores":{"iqs":77.4,"ais":49.7,"computedAt":"2026-03-01T20:10:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('eb5b494f-8c92-4023-8e2c-5f7586523a47', 'benefits', 'https://www.arbeitsagentur.de/lexikon/aufstocker', 'active', NULL, '2026-03-16T13:43:04.987965+00:00', '{"id":"eb5b494f-8c92-4023-8e2c-5f7586523a47","title":"Begriffserklärung: Aufstocker","summary":{"de":"Aufstocken und Ergänzen: Was es bedeutet und was der Unterschied ist. Mehr erfahren!"},"content":{"de":"In manchen Fällen reicht Arbeitslosengeld nicht aus, um den Lebensunterhalt zu bestreiten. In solchen Fällen können Arbeitslose zusätzlich Bürgergeld beziehen. Die Bundesagentur für Arbeit (BA) bezeichnet arbeitslose Erwerbsfähige, die zur Existenzsicherung beide Leistungen beziehen, als Aufstocker. Die alltagssprachliche Verwendung dieses Begriffs weicht davon ab: Vielfach werden Erwerbstätige „Aufstocker“ genannt, wenn ihr Lohn nicht für den Lebensunterhalt reicht und sie darum zusätzlich Bürgergeld erhalten. Informieren Sie sich, unter welchen Voraussetzungen Sie Ihr zu geringes Einkommen mit Bürgergeld ergänzen können. Die BA bezeichnet diese Leistungsempfänger als Ergänzer oder erwerbstätige erwerbsfähige Leistungsberechtigte. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/lexikon/aufstocker","topics":["financial_support","aufstocker","glossary"],"tags":["official_glossary_source","glossary"],"targetGroups":["low_income_workers","families"],"status":"active","firstSeen":"2026-03-16T13:43:04.987965+00:00","lastSeen":"2026-03-16T13:43:04.987965+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Aufstocken und Ergänzen: Was es bedeutet und was der Unterschied ist. Mehr erfahren!"},"provenance":{"source":"https://www.arbeitsagentur.de/lexikon/aufstocker","crawledAt":"2026-03-16T13:43:04.989012Z","crawlId":"benefits-seeded-1773668584","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"2ca967687a62b5b6c1885e1343c3cba2eabc7c927ae6ea9b89671461f9c782e8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:04.989012+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0d93f2a5-e468-432c-8b1b-78aa56f675f9', 'benefits', 'https://www.arbeitsagentur.de/lexikon/bedarfsgemeinschaft', 'active', NULL, '2026-03-16T13:42:59.019881+00:00', '{"id":"0d93f2a5-e468-432c-8b1b-78aa56f675f9","title":"Begriffserklärung: Bedarfsgemeinschaft","summary":{"de":"Der Begriff „Bedarfsgemeinschaft“ spielt eine wichtige Rolle in der Grundsicherung und hat Einfluss auf die Höhe der Leistungen. Mehr erfahren!"},"content":{"de":"Der Rechtsbegriff „Bedarfsgemeinschaft“ spielt beim Bezug von Bürgergeld eine wichtige Rolle. Obwohl er das Wort „Gemeinschaft“ enthält, gilt: Die Antragsstellerin oder der Antragssteller allein wird schon als Bedarfsgemeinschaft bezeichnet. Lebt sie oder er mit anderen Menschen zusammen und übernehmen alle eine wechselseitige Verantwortung füreinander, bilden sie gemeinsam die Bedarfsgemeinschaft. Der Rechtsbegriff wird darum in der Regel angewandt auf... eingetragene gleichgeschlechtliche Lebenspartnerinnen oder Lebenspartner, die nicht dauerhaft getrennt leben, oder Personen in einer Verantwortungs- und Einstehensgemeinschaft („eheähnliche Gemeinschaft“). Zur Bedarfsgemeinschaft gehören auch die Kinder, die im Haushalt leben und jünger als 25 Jahre sind. Voraussetzung: Sie sind unverheiratet, erwerbsfähig und können ihren Lebensunterhalt nicht aus eigenem Einkommen bestreiten. Zum Einkommen von Kindern zählen zum Beispiel Kindergeld oder Unterhaltszahlungen. Umgekehrt gilt: Beantragt ein unverheiratetes erwerbsfähiges Kind, das mindestens 15, aber noch keine 25 Jahre alt ist, Leistungen nach dem SGB II, gehören auch die im Haushalt lebenden Eltern oder Elternteile zur Bedarfsgemeinschaft."},"url":"https://www.arbeitsagentur.de/lexikon/bedarfsgemeinschaft","topics":["financial_support","bedarfsgemeinschaft","glossary"],"tags":["official_glossary_source","glossary"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:42:59.019881+00:00","lastSeen":"2026-03-16T13:42:59.019881+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Der Begriff „Bedarfsgemeinschaft“ spielt eine wichtige Rolle in der Grundsicherung und hat Einfluss auf die Höhe der Leistungen. Mehr erfahren!"},"applicationSteps":[{"de":"Pruefen Sie die Hinweise auf der verlinkten Seite und stellen Sie den Antrag ueber die genannte Stelle oder den Onlinedienst."}],"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://www.arbeitsagentur.de/lexikon/bedarfsgemeinschaft","crawledAt":"2026-03-16T13:42:59.019881Z","crawlId":"benefits-seeded-1773668579","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"990c9e581ac66166717138e5c63f014352137be9dab632ba768a1f5d4dc620dc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:42:59.019881+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3a80a294-54fd-40fe-9fff-aef900e79301', 'benefits', 'https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/Anspruchsvoraussetzungen/anspruchsvoraussetzungen.html', 'active', NULL, '2026-03-16T13:43:13.628668+00:00', '{"id":"3a80a294-54fd-40fe-9fff-aef900e79301","title":"Anspruchsvoraussetzungen","summary":{"de":"Das Bürgergeld wird von der neuen Grundsicherung abgelöst. Die neuen Regelungen treten nahezu vollständig zum 1. Juli in Kraft. Infos zum neuen Grundsicherungsgeld erhalten Sie hier. Ansonsten finden Sie Informationen zum bestehenden Bürgergeld."},"content":{"de":"die trotz intensiver Bemühungen keinen Arbeitsplatz finden können oder mit ihrer Erwerbstätigkeit ein nicht bedarfsdeckendes Einkommen erzielen, haben bei Hilfebedürftigkeit Anspruch auf Leistungen zur Sicherung des Lebensunterhalts als Bürgergeld. Dieses ist auch als ergänzende (aufstockende) Leistung zum Einkommen zu gewähren."},"url":"https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/Anspruchsvoraussetzungen/anspruchsvoraussetzungen.html","topics":["financial_support","buergergeld","eligibility"],"tags":["official_rule_source","eligibility"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:43:13.628668+00:00","lastSeen":"2026-03-16T13:43:13.628668+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Das Bürgergeld wird von der neuen Grundsicherung abgelöst. Die neuen Regelungen treten nahezu vollständig zum 1. Juli in Kraft. Infos zum neuen Grundsicherungsgeld erhalten Sie hier. Ansonsten finden Sie Informationen zum bestehenden Bürgergeld."},"provenance":{"source":"https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/Anspruchsvoraussetzungen/anspruchsvoraussetzungen.html","crawledAt":"2026-03-16T13:43:13.628668Z","crawlId":"benefits-seeded-1773668593","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6af7944693ee300fcc5c6d006f8dc1363e274714bef2bfaddac3fb88c2664020"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:13.628668+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('57087be1-4454-4912-a64b-18e600fd6260', 'benefits', 'https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/Leistungen-und-Bedarfe-im-Buergergeld/leistungen-und-bedarfe-im-buergergeld.html', 'active', NULL, '2026-03-16T13:43:15.462736+00:00', '{"id":"57087be1-4454-4912-a64b-18e600fd6260","title":"Leistungen und Bedarfe im Bürgergeld","summary":{"de":"Das Bürgergeld ist Teil der Leistungen zur Sicherung des Lebensunterhalts und damit Teil der Leistungen zur Sicherung eines menschenwürdigen Existenzminimums."},"content":{"de":"Das Bürgergeld wird von der neuen Grundsicherung abgelöst. Die neuen Regelungen treten nahezu vollständig zum 1. Juli in Kraft. Infos zum neuen Grundsicherungsgeld erhalten Sie hier. Ansonsten finden Sie Informationen zum bestehenden Bürgergeld. Bürgergeld: Das Bürgergeld sichert den Lebensunterhalt von Menschen, die nicht selbst für sich sorgen können. Regelbedarf: Die Höhe des Bürgergeldes basiert auf Regelsätzen. Zusätzlich werden Mehrbedarfe und Wohnkosten berücksichtigt. Ziel: Das Bürgergeld soll die berufliche Eingliederung und Weiterbildung fördern, um die Teilhabe am Arbeitsmarkt zu verbessern. Das Bürgergeld ist Teil der Leistungen zur Sicherung des Lebensunterhalts und damit Teil der Leistungen zur Sicherung eines menschenwürdigen Existenzminimums. Das Bürgergeld umfasst neben dem Regelbedarf, der in Höhe der so genannten regelbedarfsrelevanten Bedarfe berücksichtigt wird, auch die angemessenen Bedarfe für Unterkunft und Heizung, soweit diese Bedarfe nicht durch Einkommen oder Vermögen unter Beachtung von Absetzbeträgen und Schonvermögen gedeckt sind. Hinzu kommen gegebenenfalls Mehrbedarfe, die für besondere Lebenslagen wie Alleinerziehung, Schwangerschaft oder bei aus medizinischen Gründen erforderlicher kostenaufwändiger Ernährung berücksichtigt werden. Der Regelbedarf zur Sicherung des Lebensunterhalts umfasst insbesondere Bedarfe für Ernährung, Kleidung, Körperpflege, Hausrat, Haushaltsenergie ohne die auf die Heizung und Erzeugung von Warmwasser entfallenen Anteile sowie Bedarfe zur Teilnahme am sozialen und kulturellen Leben in der Gemeinschaft (das sog. sozio-kulturelle Existenzminimum). Der Regelbedarf wird als monatlicher Pauschalbetrag berücksichtigt. Über die Verwendung der zur Deckung des Regelbedarfs erbrachten Leistungen (Teil des Bürgergeldes) entscheidet der Bürgergeldberechtigte eigenverantwortlich. Neben regelmäßig anfallenden Bedarfen u.a. für Lebensmittel sind auch unregelmäßig anfallende Bedarfe wie z.B. für Bekleidung aus den entsprechenden Leistungen zu decken. Die Höhe der maßgebenden Regelbedarfe ist der nachstehenden Tabelle zu entnehmen."},"url":"https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/Leistungen-und-Bedarfe-im-Buergergeld/leistungen-und-bedarfe-im-buergergeld.html","topics":["financial_support","buergergeld","regelbedarf","mehrbedarf"],"tags":["official_background_source","benefit_amount"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:43:15.462736+00:00","lastSeen":"2026-03-16T13:43:15.462736+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Das Bürgergeld ist Teil der Leistungen zur Sicherung des Lebensunterhalts und damit Teil der Leistungen zur Sicherung eines menschenwürdigen Existenzminimums."},"benefitAmount":{"de":"Die verlinkte Quelle enthaelt die aktuellen Hinweise zur Hoehe oder Zusammensetzung der Leistung."},"provenance":{"source":"https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/Leistungen-und-Bedarfe-im-Buergergeld/leistungen-und-bedarfe-im-buergergeld.html","crawledAt":"2026-03-16T13:43:15.462736Z","crawlId":"benefits-seeded-1773668595","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"503ccc8ee49910dc8fdb2cf7a4f4e305601c23519782666abd547bf4365ea13e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:15.464240+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9eeec337-a70e-49e2-8db7-c715061a830b', 'benefits', 'https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/grundsicherung-buergergeld.html', 'active', NULL, '2026-03-16T13:43:12.083819+00:00', '{"id":"9eeec337-a70e-49e2-8db7-c715061a830b","title":"Grundsicherung / Bürgergeld","summary":{"de":"Das Bürgergeld soll Menschen, die erwerbsfähig und leistungsberechtigt sind, in Beschäftigung bringen und ihnen den Lebensunterhalt sichern. Hier finden Sie aktuelle Neuigkeiten und Infos zu diesem Thema."},"content":{"de":"Das Bürgergeld wird von der neuen Grundsicherung abgelöst. Die neuen Regelungen treten nahezu vollständig zum 1. Juli in Kraft. Infos zum neuen Grundsicherungsgeld erhalten Sie hier. Ansonsten finden Sie Informationen zum bestehenden Bürgergeld. Am 5. März 2026 hat d er Deutsche Bundestag mehrheitlich dem Gesetz zur Umgestaltung der Grundsicherung für Arbeitsuchende zugestimmt – dem 13. Gesetz zur Änderung des Zweiten Buches Sozialgesetzbuch und anderer Gesetze. Rede von Bundesministerin Bärbel Bas zur 1. Lesung Grundsicherung im Plenum am 15. Januar 2026. Das Bundeskabinett hat 17. Dezember 2025 den Gesetzentwurf zur Umgestaltung der Grundsicherung für Arbeitsuchende beschlossen. Die Bundesregierung setzt mit dem 13. SGB II-Änderungsgesetz den entsprechenden Auftrag aus dem Koalitionsvertrag um. Bundesagentur für Arbeit: Unterstützung durch Bürgergeld"},"url":"https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/grundsicherung-buergergeld.html","topics":["financial_support","buergergeld"],"tags":["official_background_source"],"targetGroups":["unemployed","families"],"status":"active","firstSeen":"2026-03-16T13:43:12.083819+00:00","lastSeen":"2026-03-16T13:43:12.083819+00:00","sourceUnavailable":false,"eligibilityCriteria":{"de":"Das Bürgergeld soll Menschen, die erwerbsfähig und leistungsberechtigt sind, in Beschäftigung bringen und ihnen den Lebensunterhalt sichern. Hier finden Sie aktuelle Neuigkeiten und Infos zu diesem Thema."},"provenance":{"source":"https://www.bmas.de/DE/Arbeit/Grundsicherung-Buergergeld/grundsicherung-buergergeld.html","crawledAt":"2026-03-16T13:43:12.083819Z","crawlId":"benefits-seeded-1773668592","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c6e3ea4d0247e668f4992c03695d0712c174ffea85d869a08481c70d30a9d94e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:12.083819+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3796a0aa-6057-4072-8c9a-cf40d666342d', 'benefits', 'https://www.bmas.de/DE/Leichte-Sprache/Soziale-Sicherheit/soziale-sicherheit.html', 'active', NULL, '2026-03-16T13:43:17.537112+00:00', '{"id":"3796a0aa-6057-4072-8c9a-cf40d666342d","title":"Soziale Sicherheit","summary":{"de":"Allen Menschen in Deutschland soll es gut gehen. Und alle sollen sich sicher fühlen. Der Staat hilft deswegen allen Menschen. Der Staat hilft Ihnen mit Geld. Und mit vielen anderen Hilfen."},"content":{"de":"Sie sind auf der Internet-Seite vom Bundes-Ministerium für Arbeit und Soziales. Hier finden Sie Infos in Leichter Sprache. Allen Menschen in Deutschland soll es gut gehen. Und alle sollen sich sicher fühlen. Egal, was in ihrem Leben gerade passiert. Auch Sie persönlich bekommen im Notfall Unterstützung. Sie bekommen in diesen Situationen Geld. Aber auch viele andere Hilfen. Damit Sie keine Sorgen haben müssen. Unten sehen Sie Fragen zur sozialen Sicherheit. Die Antworten sieht man nicht. Sie wollen die Antwort lesen? Klicken Sie auf die Frage. Dann kommt die Antwort. Manche Menschen haben zu wenig Geld für ihr Leben. Sie haben auch keine Ersparnisse. Lebenshilfe für Menschen mit geistiger Behinderung Bremen e.V., Illustrator Stefan Albers Dafür gibt es viele Gründe. Zum Beispiel:"},"url":"https://www.bmas.de/DE/Leichte-Sprache/Soziale-Sicherheit/soziale-sicherheit.html","topics":["financial_support","leichte_sprache_soziale_sicherheit"],"tags":["official_light_language_source","light_language"],"targetGroups":["general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-16T13:43:17.537112+00:00","lastSeen":"2026-03-16T13:43:17.537112+00:00","sourceUnavailable":false,"provenance":{"source":"https://www.bmas.de/DE/Leichte-Sprache/Soziale-Sicherheit/soziale-sicherheit.html","crawledAt":"2026-03-16T13:43:17.537112Z","crawlId":"benefits-seeded-1773668597","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"16fb18be6aa7c1e25d82c64d69c707e1f40ca9d8b69d6426bfa052c614e1ecfb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-16T13:43:17.538673+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f0d4693b-32e1-4ec6-95fb-e9d75efefdfa', 'benefits', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen', 'active', NULL, '2026-03-01T20:10:00Z', '{"id":"f0d4693b-32e1-4ec6-95fb-e9d75efefdfa","title":"Familienleistungen (BMBFSFJ)","translations":{"de-LEICHT":{"title":"Familien-Leistungen","timestamp":"2026-03-01T20:10:00Z","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen","crawledAt":"2026-03-01T20:10:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Das BMBFSFJ stellt zentrale Familienleistungen wie Elterngeld, Kindergeld, Kinderzuschlag und weitere Unterstützungen im Überblick dar."},"content":{"de":"Die Seite strukturiert bundesweite Familienleistungen und verlinkt auf vertiefende Informationen zu Anspruch, Zweck und Antrag. Damit dient sie als offizieller Orientierungspunkt für Familien in unterschiedlichen Lebenslagen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen","topics":["financial_support","family"],"tags":["application_required","means_tested"],"targetGroups":["families","single_parents"],"status":"active","firstSeen":"2026-03-01T20:10:00Z","lastSeen":"2026-03-01T20:10:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen","crawlId":"manual-curation-20260301-realdata-v1","checksum":"ec0ed83e469778b0fdf1d2a7c70fd4fa7f1a6f8c5e372514ce717fce83032630","crawledAt":"2026-03-01T20:10:00Z"},"qualityScores":{"iqs":81,"ais":53,"computedAt":"2026-03-01T20:10:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('76c47e08-9f3b-4053-97bc-62c4e09aa6ee', 'benefits', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/kindergeld/kindergeld-73892', 'active', NULL, '2026-03-01T20:10:00Z', '{"id":"76c47e08-9f3b-4053-97bc-62c4e09aa6ee","title":"Kindergeld","translations":{"de-LEICHT":{"title":"Geld für Kinder","timestamp":"2026-03-01T20:10:00Z","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/kindergeld/kindergeld-73892","crawledAt":"2026-03-01T20:10:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Kindergeld ist eine zentrale familienpolitische Leistung zur finanziellen Entlastung von Familien in Deutschland."},"content":{"de":"Die Ministeriumsseite ordnet das Kindergeld im Gesamtsystem der Familienleistungen ein und verweist auf weiterführende Informationen. Sie unterstützt die erste Orientierung zu Zweck, Anspruchsrahmen und Zuständigkeiten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/kindergeld/kindergeld-73892","topics":["financial_support","family"],"tags":["application_required","automatic"],"targetGroups":["families","single_parents"],"status":"active","firstSeen":"2026-03-01T20:10:00Z","lastSeen":"2026-03-01T20:10:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/kindergeld/kindergeld-73892","crawlId":"manual-curation-20260301-realdata-v1","checksum":"fa664ec8eb3f7782ac29965f22420ab0f6dbc9d7f03041e2caeb1f4cce5a8d6d","crawledAt":"2026-03-01T20:10:00Z"},"qualityScores":{"iqs":80.3,"ais":52.4,"computedAt":"2026-03-01T20:10:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2c5473e5-cef4-4eae-8b41-bcc405c2e95c', 'aid', 'https://familienportal.de/familienportal/lebenslagen/alter/angebote-und-beratung', 'active', NULL, '2026-03-15T16:25:46.846255+00:00', '{"id":"2c5473e5-cef4-4eae-8b41-bcc405c2e95c","title":"Angebote & Beratung","summary":{"de":"Von Familienpflegezeit über finanzielle Unterstützung bis Altersteilzeit: Hier finden Sie Informationen zu Angeboten und Beratungsmöglichkeiten im Alter."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Ältere Menschen schaffen es manchmal nicht mehr, Dinge des täglichen Lebens allein zu erledigen. Soziale Dienste können sie dabei mit verschiedenen Angeboten unterstützen. Sozialstationen übernehmen beispielsweise die Krankenpflege, die Altenpflege sowie die Haus- und Familienpflege. Die Kosten für häusliche Krankenpflege oder häusliche Pflege tragen unter bestimmten Voraussetzungen Pflegekassen, Krankenkassen oder das Sozialamt. Meist erbringen oder vermitteln Sozialstationen noch weitere Hilfen und Dienstleistungen. Aber auch private Pflegedienste bieten häusliche Pflege an. Fachkräfte führen auch zu Hause mobile Therapien wie Bewegungstherapie, Massagen oder medizinische Bäder durch. Private Anbieter, Gemeinden oder Verbände bieten zum Teil auch noch weitere Dienstleistungen an, wie zum Beispiel:"},"url":"https://familienportal.de/familienportal/lebenslagen/alter/angebote-und-beratung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:46.846255+00:00","lastSeen":"2026-03-15T16:25:46.846255+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/alter/angebote-und-beratung","crawledAt":"2026-03-15T16:25:46.846255Z","crawlId":"aid-seeded-1773591946","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"fb56435c6ac5067989884035c8dd9801de8e2517ecc32996bb6c32a4d1be94bd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:46.846255+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c4993b26-d325-46fa-b745-c9ee26f70191', 'aid', 'https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/hilfe-beratung-familien', 'active', NULL, '2026-03-15T16:25:47.245136+00:00', '{"id":"c4993b26-d325-46fa-b745-c9ee26f70191","title":"Hilfe & Beratung für Familien","summary":{"de":"Ob Schulden, drohende Wohnungslosigkeit oder weitere Krisensituationen: Hier finden Sie Beratungsstellen und Unterstützungsmöglichkeiten für Familien."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Wenn Sie Schulden haben oder in einer wirtschaftlichen Notlage sind, dann können Sie sich bei einer Schuldnerberatungsstelle professionellen Rat holen. Je schneller Sie sich Hilfe holen, desto besser kann Ihnen die Beraterin oder der Berater dabei helfen, einen Weg aus der Krise zu finden. Eine Schuldnerberatungsstelle unterstützt Sie dabei, einen Weg aus der Schuldenfalle zu finden. Dabei steht im Vordergrund, dass Ihre Einnahmen und Ausgaben wieder in ein ausgewogenes Verhältnis gebracht werden und dass Sie sich so schnell wie möglich mit Ihren Gläubigern einigen, ohne dass es zu einem Gerichtsverfahren kommt. Wenn Sie überschuldet sind oder einen sozialen Abstieg befürchten, können Sie sich an Ihr Jobcenter, Ihr Sozialamt,,Ihre Kommune oder eine anerkannte Schuldner- und Insolvenzberatungsstelle wenden. Anerkannte Schuldner- und Insolvenzberatungsstellen in Ihrer Nähe finden Sie anonym und kostenlos auf der vom Bundesministerium für Umwelt, Klimaschutz, Naturschutz, nukleare Sicherheit geförderten Website www.vz-schuldnerberatung.de. Ergänzend finden Sie dort auch Informationen rund um den Beratungsprozess in der Schuldnerberatung. Bitte beachten Sie, dass es bundesweit keine einheitliche Regelung zur Kostenübernahme der Schuldnerberatung gibt. Lassen Sie sich sicherheitshalber immer vor Beginn der Beratung aufklären, inwiefern Kosten auf Sie zukommen könnten. Bitte beachten Sie auch die Hinweise der Informationsseiten der Polizei zum Thema Kreditbetrug. Es gibt auch Beratungsstellen, die Sie unterstützen, wenn Sie in einem sogenannten Verbraucher-Insolvenzverfahren sind. Die Beraterin oder der Berater hilft Ihnen dann dabei, Ihre restlichen Schulden zu tilgen und sich möglicherweise von übrig gebliebenen Verbindlichkeiten zu befreien. Denn auch bei wiedererlangter Schuldenfreiheit ist es möglich, dass noch bestehende Verträge (zum Beispiel Handyverträge) künftig Kosten verursachen können."},"url":"https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/hilfe-beratung-familien","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:47.245136+00:00","lastSeen":"2026-03-15T16:25:47.245136+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/krise-und-konflikt/hilfe-beratung-familien","crawledAt":"2026-03-15T16:25:47.246143Z","crawlId":"aid-seeded-1773591947","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"a270dc7f980241f70b528e61b5b91e778b4ed0ff7f499e3e75747f7bd7a25a95"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:47.246143+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0a97f174-7db4-4085-bfa5-df6fb741ff52', 'aid', 'https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/hilfe-kinder-jugendliche-notlagen', 'active', NULL, '2026-03-15T16:25:47.732818+00:00', '{"id":"0a97f174-7db4-4085-bfa5-df6fb741ff52","title":"Hilfe für Kinder & Jugendliche in schwierigen Situationen","summary":{"de":"Kinder und Jugendliche mit Sorgen oder in Not finden Rat, Hilfe und Unterstützung bei verschiedenen Beratungsstellen. Ein Überblick."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Kinder und Jugendliche mit Sorgen oder in Not können Rat, Hilfe und Unterstützung bei verschiedenen Beratungsangeboten online oder telefonisch bekommen. Die Beratungsangebote und Hilfen per Telefon, Chat oder Mail sind anonym und kostenfrei. Jugendberatung der Bundeskonferenz für Erziehungsberatung e.V. (bke) Hilfe-Telefon Sexueller Missbrauch für Kinder und Jugendliche Pausentaste: Hilfe für Kinder und Jugendliche, die sich um ihre Familie kümmern Hilfen im Netz: Unterstützung für Kinder suchtkranker und psychisch kranker Eltern"},"url":"https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/hilfe-kinder-jugendliche-notlagen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:47.732818+00:00","lastSeen":"2026-03-15T16:25:47.732818+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/krise-und-konflikt/hilfe-kinder-jugendliche-notlagen","crawledAt":"2026-03-15T16:25:47.732818Z","crawlId":"aid-seeded-1773591947","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"fdd9fe9b03810109f008629c725b6ca757e0d9af5b46f2091e0f8477efa793ac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:47.732818+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('99933dee-bd82-40fd-a2d3-341b74f300f8', 'aid', 'https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/kinder-und-jugendhilfe', 'active', NULL, '2026-03-15T16:25:48.781376+00:00', '{"id":"99933dee-bd82-40fd-a2d3-341b74f300f8","title":"Angebote der Kinder- & Jugendhilfe","summary":{"de":"Hier erfahren Sie alles zur Kinder- und Jugendhilfe und zu weiteren Angeboten für Familien in Deutschland."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Kinder- und Jugendhilfen sind Leistungen und Aufgaben öffentlicher und freier Träger für junge Menschen und deren Familien. Die Kinder- und Jugendhilfe fördert die Entwicklung von Kindern und Jugendlichen zu eigenverantwortlichen und gemeinschaftsfähigen Persönlichkeiten. Sie schützt Kinder und Jugendliche vor Gefahren. Weitere Leitziele der Kinder- und Jugendhilfe sind: Förderung der individuellen und sozialen Entwicklung junger Menschen Beratung und Unterstützung von Eltern und anderen Erziehungsberechtigten bei der Erziehung Schaffen und Erhalten von positiven Lebensbedingungen für junge Menschen und ihre Familien sowie einer kinder- und familienfreundlichen Umwelt Die Kinder- und Jugendhilfe richtet sich an alle jungen Menschen unter 27 Jahren. An alle Mütter, Väter und Personensorgeberechtigten, die in Deutschland leben. Das sind:"},"url":"https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/kinder-und-jugendhilfe","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:48.781376+00:00","lastSeen":"2026-03-15T16:25:48.781376+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/krise-und-konflikt/kinder-und-jugendhilfe","crawledAt":"2026-03-15T16:25:48.781376Z","crawlId":"aid-seeded-1773591948","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"c5ade144b8bd7d37d68170015e17cf255a66281947730353b0bee829c114b73f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:48.781376+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('74a16b85-c5db-4838-8134-aac7c2ded4b0', 'aid', 'https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/hilfe-im-alltag', 'active', NULL, '2026-03-15T16:25:49.235856+00:00', '{"id":"74a16b85-c5db-4838-8134-aac7c2ded4b0","title":"Hilfe im Alltag","summary":{"de":"Sie benötigen Hilfe im Alltag oder bei der Pflege von Angehörigen mit Behinderung? Hier finden Sie alle Informationen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Menschen mit Behinderungen und Menschen, die einen Angehörigen mit Behinderung pflegen, haben im Alltag oft zusätzliche Belastungen. Unsere Übersicht zeigt, welche Hilfen diesen Alltag entlasten können. Es gibt unterschiedliche Angebote, um die Entwicklung von Kindern mit Behinderungen zu fördern und sie trotz ihrer Behinderungen in den Alltag und in das gesellschaftliche Leben zu integrieren. Zusätzlich gibt es viele Bildungseinrichtungen, die sich auf die Arbeit mit Kindern mit Behinderungen spezialisiert haben. Die Aufgabe der Frühförderung ist es, frühestmöglich mit gezielten Maßnahmen die Beeinträchtigung des Kindes zu vermindern und seine Entwicklung zu fördern. Zur Frühförderung gehören die Diagnose der Erkrankung, Therapie, pädagogische Förderung und Beratung sowie Unterstützung der Eltern. Die Leistungen werden von sozialpädiatrischen Zentren oder von Frühförderstellen erbracht. Die Leistungen müssen die Eltern nicht selbst bezahlen, sondern sie werden bei Bedarf von Ihrer Krankenkasse oder Ihrem zuständigen Träger der Eingliederungshilfe übernommen. Mehr zu dem Thema finden Sie beim Portal Kindergesundheit der Bundeszentrale für gesundheitliche Aufklärung (BZgA). Kinder mit Behinderungen haben, wie jedes andere Kind, ab dem vollendeten ersten Lebensjahr das Recht, in einer Kindertageseinrichtung oder Kindertagespflegestelle gefördert zu werden. Es gibt immer mehr inklusive Kitas, die Kinder mit und ohne Behinderungen gemeinsam betreuen. Daneben arbeiten auch viele Tagesmütter und Tagesväter inklusiv. Heilpädagogische Kitas haben sich auf die Betreuung von Kindern mit Behinderungen spezialisiert. Die Kosten für den Besuch eines Heilpädagogischen Kindergartens übernimmt der Träger der Eingliederungshilfe im Rahmen der Eingliederungshilfe. Eltern müssen sich an diesen Kosten nicht beteiligen. Beim Besuch eines inklusiven Kindergartens können von den Eltern die üblichen Kostenbeiträge erhoben werden. Ist für den Besuch des Kindergartens eine persönliche Assistenz erforderlich, kann der Träger der Eingliederungshilfe diese Leistung übernehmen. Benötigt das Kind im Kindergarten medizinische Versorgung, kann die Krankenkasse dies als häusliche Krankenpflege übernehmen."},"url":"https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/hilfe-im-alltag","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:49.235856+00:00","lastSeen":"2026-03-15T16:25:49.235856+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/hilfe-im-alltag","crawledAt":"2026-03-15T16:25:49.235856Z","crawlId":"aid-seeded-1773591949","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"15457c987f8be1460553d1d06fa54137db43fd34c70bcac72ceeb3efe3aa8a85"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:49.235856+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1ab27f06-5ea0-4a89-9f0a-18aedfa0cbf4', 'aid', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/fruehe-hilfen', 'active', NULL, '2026-03-15T16:25:49.733621+00:00', '{"id":"1ab27f06-5ea0-4a89-9f0a-18aedfa0cbf4","title":"Hilfen für Schwangere & Eltern mit Kindern bis 3 Jahre","summary":{"de":"Frühe Hilfen sind kostenlose Angebote für Eltern ab der Schwangerschaft und Familien mit Kindern. Hier finden Sie Angebote, Netzwerke und Beratungen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Frühe Hilfen sind Angebote für Eltern ab der Schwangerschaft und Familien mit Kindern bis drei Jahre. Sie helfen Ihnen, wenn Sie in der Schwangerschaft oder nach der Geburt unsicher oder nervös sind, sich genervt oder gestresst fühlen. Die Angebote sind freiwillig und kosten kein Geld. Netzwerke Frühe Hilfen © BMBFSFJ Die Frühen Hilfen unterstützen Sie zum Beispiel in diesen Situationen: Sie fühlen sich oft erschöpft im Alltag mit ihrem Kind. Sie fragen sich, ob Sie sich ausreichend um Ihr Kind kümmern können. Es gibt Streit mit Ihrer Partnerin oder Ihrem Partner."},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/fruehe-hilfen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:49.733621+00:00","lastSeen":"2026-03-15T16:25:49.733621+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/fruehe-hilfen","crawledAt":"2026-03-15T16:25:49.733621Z","crawlId":"aid-seeded-1773591949","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"7392d42daf7b42ff853f69fc70c8087cff651b40eae33712875b87b293e0eed0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:49.733621+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('032eb8a3-7495-4854-b770-f7672ca64eef', 'aid', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/gesundheit-und-beratung', 'active', NULL, '2026-03-15T16:25:50.263168+00:00', '{"id":"032eb8a3-7495-4854-b770-f7672ca64eef","title":"Beratung & Gesundheit","summary":{"de":"Wo kann ich mich beraten lassen, wenn ich schwanger bin? Wer unterstützt mich? Hier finden Sie Antworten auf Fragen rund um das Thema Schwangerschaft."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Die Schwangerschafts-Beratung ist eine freiwillige Beratung. Sie informiert Frauen und Männer rund um Familienplanung, Schwangerschaft und Geburt. Auf Familienplanung.de finden Sie Beratungsstellen in Ihrer Nähe, die Schwangerschafts-Beratungen und Schwangerschaftskonflikt-Beratungen anbieten. Dort erhalten Sie auch Antworten auf Fragen rund um die Themen Schwangerschaft und Geburt. Schwangerschafts-Beratungsstellen informieren und beraten in der Regel kostenlos und auf Wunsch anonym über alle Fragen im Zusammenhang mit einer Schwangerschaft. Auch wenn Sie sich in einer Notsituation befinden, erhalten Sie Hilfe und Unterstützung bei Schwangerschafts-Beratungsstellen. Beratung für werdende Eltern mit Beeinträchtigungen Soziale, finanzielle und Frühe Hilfen für werdende Mütter, werdende Väter und Familien Gesetzliche Ansprüche und Leistungen, Unterstützung bei der Antragstellung und Durchsetzung von Rechtsansprüchen"},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/gesundheit-und-beratung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:50.263168+00:00","lastSeen":"2026-03-15T16:25:50.263168+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/gesundheit-und-beratung","crawledAt":"2026-03-15T16:25:50.263168Z","crawlId":"aid-seeded-1773591950","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"b071f502d135d5b3ed883a5e28ba8e246ec4f6a70bca2a10161680d39a0ba148"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:50.263168+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e74da8c2-9c3e-45d4-9871-6b955e3e388f', 'aid', 'https://maennerberatungsnetz.de/', 'active', NULL, '2026-03-15T16:26:17.802315+00:00', '{"id":"e74da8c2-9c3e-45d4-9871-6b955e3e388f","title":"Männerberatungsnetz • Beratungsangebote für Jungen, Männer und Väter.","summary":{"de":"Das Männerberatungsnetz bündelt Beratungsangebote, die auf Anliegen und Konfliktlagen von Jungen, Männern und Vätern spezialisiert sind."},"content":{"de":"Auf der Suche nach einem passenden Beratungsangebot? Wir unterstützen dich dabei! Das Männerberatungsnetz bündelt Beratungsangebote, die auf Anliegen und Konfliktlagen von Jungen, Männern und Vätern spezialisiert sind. Männerberatung auf einen Blick. In unserer Beratungslandkarte findest du eine Übersicht der Beratungsanbieter in unterschiedlichen Themenfeldern. Durch Filter kannst du deine Suche verfeinern. Für Inhalte, die Konzeption, Qualität und Durchführung der Beratungsangebote sind ausschließlich die Anbieter verantwortlich. Haftungsausschluss. Hier findest du eine Auswahl zentraler Beratungsstellen! Hilfetelefon für Männer, die Gewalt erlebt haben – in der Kindheit, auf der Straße, in Institutionen, in der Partnerschaft. Onlineberatung und Beraternetzwerk mit Kontaktdaten von Fachberatern in Deutschland. Zielgruppe sind Jungen und Männer, die sich ich in einer Krise befinden. Dies kann Gewalttätigkeit gegenüber der Partnerin oder den Kindern sein – ebenso eigene Gewalterfahrungen oder Krisen im Bereich Beziehung, Trennung, Arbeit oder Vaterschaft."},"url":"https://maennerberatungsnetz.de/","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:17.802315+00:00","lastSeen":"2026-03-15T16:26:17.802315+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://maennerberatungsnetz.de/","crawledAt":"2026-03-15T16:26:17.803284Z","crawlId":"aid-seeded-1773591977","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"9c22c5e2914ac0cc25af9885b8473a767139aa92c5ee3a6e3a4930999a3400c8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:17.803284+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('617c0244-23c7-4923-96fd-bcb389b7b9c1', 'aid', 'https://maennerberatungsnetz.de/beratung', 'active', NULL, '2026-03-15T16:26:18.392272+00:00', '{"id":"617c0244-23c7-4923-96fd-bcb389b7b9c1","title":"Locations – Männerberatungsnetz","summary":{"de":"Die Beratungs- und Vernetzungsstelle rosa Alter unterstützt lesbische, bisexuelle, schwule, trans* und inter* Senior_innen (LGBTIQ*) in unterschiedlichen Fragestellungen rund um das Älterwerden. Natürlich können sich bei uns auch ­Menschen beraten lassen, die Angehörige und Freund_innen von rosa Senior_innen sind."},"content":{"de":"Wir beraten per Telefon, Email, ­Videokonferenz, persönlich in unseren ­Räumen oder bei Haus­besuchen. Selbst­verständlich beraten wir auf Wunsch auch ­anonym. Wir bieten professionelle Trauerbegleitung durch qualifizierte Mitglieder, Aus- und Fortbildungen für Trauerbegleiter mit Fokus auf die besonderen Bedürfnisse trauernder Männer, Vorträge, Workshops, Veröffentlichungen und öffentliche Veranstaltungen zur Förderung des politischen und gesellschaftlichen Austauschs und Aufklärung über Defizite sowie Vernetzung und Vermittlung von Fachleuten und Einrichtungen, die in der Trauerbegleitung tätig sind. Das Angebot richtet sich an Männer und Frauen ab dem 18. Lebensjahr, die von häuslicher Gewalt und Stalking betroffen sind/waren. Die Beratung von Fachkräften oder Angehörigen zählt ebenso zu unseren Aufgaben. Psychologisches und systemisches Einzel, Paar-, und Familiencoaching, spezifische Arbeit mit Männern, u.a. auch Workshops, Männergruppen, Meditationsabende für Männer. Stecken Sie in einer persönlichen Lebenskrise oder vor einer neuen Herausforderung? Gibt es für Sie in der Familie, Ihren Kindern schwierige Situationen zu klären? Stoßen Sie in der Kommunikation mit Ihrem Partner/Ihrer Partnerin immer wieder an Grenzen? Ich arbeite mit Ihnen zusammen an Ihrem Anliegen und unterstütze Sie in Ihrer Lebenssituation. Wir schaffen gemeinsam einen wohlwollenden Raum, in dem Klärung geschehen kann und sich Lösungen für Sie zeigen."},"url":"https://maennerberatungsnetz.de/beratung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:18.392272+00:00","lastSeen":"2026-03-15T16:26:18.392272+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://maennerberatungsnetz.de/beratung","crawledAt":"2026-03-15T16:26:18.392272Z","crawlId":"aid-seeded-1773591978","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"f7df4dce493640015140777ca66c8ade90278138eb46511af4e8541989bf7ecc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:18.392272+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bf301738-99d3-47e2-8d3c-896eb1901ea9', 'aid', 'https://onlineberatung.hilfetelefon.de/', 'active', NULL, '2026-03-15T16:26:21.350888+00:00', '{"id":"bf301738-99d3-47e2-8d3c-896eb1901ea9","title":"116016, Hilfetelefon bei Gewalt gegen Frauen","summary":{"de":"Alle Beratungsangebote sind anonym, sicher, vertraulich und kostenlos"},"content":{"de":"Sofort-Beratung im Chat - ohne Anmeldung. Täglich zwischen 12.00 und 20.00 Uhr. An 365 Tagen im Jahr. Ist nur in deutscher Sprache möglich. Beratung am Telefon. 24/7 an 365 Tagen – auch an Feiertagen oder Wochenenden. Mehrsprachig. Beratung via E-Mail. Anmeldung erforderlich. Beraterinnen antworten innerhalb von 24 Stunden. Ist nur in deutscher Sprache möglich. Terminvereinbarung für die Chat-Beratung. Anmeldung erforderlich. Ist nur in deutscher Sprache möglich. Zur Beantwortung von ersten Fragen rund um unser Online-Beratungsangebot, können Sie sich hier in unserem FAQ-Bereich informieren. Für die Termin-Chat-Beratung und die E-Mail-Beratung wird eine Registrierung notwendig."},"url":"https://onlineberatung.hilfetelefon.de/","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:21.350888+00:00","lastSeen":"2026-03-15T16:26:21.350888+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://onlineberatung.hilfetelefon.de/","crawledAt":"2026-03-15T16:26:21.350888Z","crawlId":"aid-seeded-1773591981","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"e413253ef7ddae5331b7cf9e60bb21bb2953b78aa7e8ed27f67589fcb5383ac4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:21.350888+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9d2e2743-9fda-4aa8-aa11-85fea8fa969b', 'aid', 'https://weisser-ring.de/hilfe-fuer-opfer/opfer-telefon', 'active', NULL, '2026-03-15T16:26:22.264718+00:00', '{"id":"9d2e2743-9fda-4aa8-aa11-85fea8fa969b","title":"Opfer-Telefon","summary":{"de":"\"Den Mut zu haben, sich jemandem anzuvertrauen, ist der erste Schritt zur (Selbst-)Hilfe.\""},"content":{"de":"Der WEISSE RING erhielt 2010 von der Bundesnetzagentur die Zuteilung für die Rufnummer 116 006. Wer eine Straftat erlebt hat, hat ein Recht darauf, gehört und ernst genommen zu werden. Unsere geschulten, ehrenamtlichen Beraterinnen und Berater am Opfer-Telefon gehen auf Sie ein, wenn Sie Unterstützung nach einer Straftat brauchen oder in Vertretung für jemanden anrufen. Gemeinsam mit Ihnen können wir als Lotsen im Hilfenetzwerk Wege erörtern, um Ihnen die bestmögliche Hilfe und Unterstützung zukommen zu lassen. Dabei arbeiten wir eng mit den Außenstellen des WEISSEN RINGS zusammen, die flächendeckend und bundesweit Opferhilfe vor Ort leisten. Darüber hinaus verweisen wir auch an externe Beratungsstellen oder andere Unterstützungsmöglichkeiten im erreichbaren Umfeld. Der Wille der Betroffenen steht dabei stets an erster Stelle! Auch zu Opferschutzorganisationen in anderen Ländern pflegt der WEISSE RING durch die Mitgliedschaft im europäischen Dachverband Victim Support Europe eine gute Verbindung. Wir weisen darauf hin, dass bei Aktivierung Daten an YOUTUBE übermittelt werden. Was passiert, wenn Sie anrufen? Unsere Opfer-Telefonberaterin Julia und -berater Alexander berichten über ihre ehrenamtliche Arbeit am Opfer-Telefon:"},"url":"https://weisser-ring.de/hilfe-fuer-opfer/opfer-telefon","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:22.264718+00:00","lastSeen":"2026-03-15T16:26:22.264718+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://weisser-ring.de/hilfe-fuer-opfer/opfer-telefon","crawledAt":"2026-03-15T16:26:22.264718Z","crawlId":"aid-seeded-1773591982","crawlerVersion":"0.1.0","sourceTier":"tier_2_ngo_watchdog","institutionType":"ngo","jurisdiction":"DE","checksum":"cdfd44bac26516debca08effd924121daa4a00ce8df4d9756485b8cdf2e92719"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:22.264718+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('abb61703-f37e-43bd-b1ff-8f9bc4fa3d77', 'aid', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/antrag-bescheid', 'active', NULL, '2026-03-17T07:01:20.177591+00:00', '{"id":"abb61703-f37e-43bd-b1ff-8f9bc4fa3d77","title":"Bürgergeld: Antrag und Bescheid","summary":{"de":"Bürgergeld beantragen: Was Sie bei Antrag und Anlagen beachten und Sie bei Ihrem Bescheid prüfen müssen. Jetzt informieren!"},"content":{"de":"Wenn Sie Bürgergeld beantragen, benötigt Ihr Jobcenter Informationen von Ihnen. Anhand Ihrer Angaben prüft Ihr Jobcenter, ob Sie die Voraussetzungen für Bürgergeld erfüllen und damit einen rechtlichen Anspruch darauf haben. Ist das der Fall, ermittelt das Jobcenter zudem, wie viel Bürgergeld Sie grundsätzlich erhalten können. Wichtig: Wichtig: Leben Sie mit anderen Personen in einer Bedarfsgemeinschaft, stellen Sie den Antrag für alle diese Personen. Entsprechend müssen Sie in diesem Fall Informationen zu allen Mitgliedern Ihrer Bedarfsgemeinschaft liefern. Sie sind in diesem Fall die Vertreterin oder der Vertreter Ihrer Bedarfsgemeinschaft. Grundsätzlich ist der Antrag auf Bürgergeld an keine Form gebunden. Sie können ihn online, persönlich, telefonisch oder schriftlich stellen. Am besten stellen Sie den Bürgergeld-Antrag online. Sie haben dadurch folgende Vorteile: positiv: Sie können den Antrag jederzeit und von überall an Ihr Jobcenter schicken – schnell und sicher. positiv: Sie werden Schritt für Schritt durch den Antrag geführt und erhalten zusätzliche Hilfetexte."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/antrag-bescheid","topics":["buergergeld"],"tags":["official_rule_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:20.177591+00:00","lastSeen":"2026-03-17T07:01:20.177591+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/antrag-bescheid","crawledAt":"2026-03-17T07:01:20.177591Z","crawlId":"aid-seeded-1773730880","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"9838db830b5be083f7e9acc983f4c8b8cd22010816a4f78314d3c456ecfce9ec"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:20.177591+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('01121533-ec12-4b36-9290-1240892eeadb', 'aid', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/einkommen-ergaenzen', 'active', NULL, '2026-03-17T07:01:21.711681+00:00', '{"id":"01121533-ec12-4b36-9290-1240892eeadb","title":"Einkommen mit Bürgergeld ergänzen","summary":{"de":"Reicht Ihr Lohn nicht für den Lebensunterhalt, können Sie ihn mit Bürgergeld aufstocken. Jetzt informieren!"},"content":{"de":"Wenn Ihr Einkommen nicht für Ihren Lebensunterhalt beziehungsweise den Ihrer Bedarfsgemeinschaft reicht, können Sie es mit Bürgergeld ergänzen (umgangssprachlich: aufstocken ). Dabei spielt es keine Rolle, ob Sie angestellt oder selbstständig sind. Sie können diese Leistung beim zuständigen Jobcenter beantragen. Wenn Sie Bürgergeld beziehen, müssen Sie sogenannte vorrangige Leistungen beantragen, wenn Sie darauf Anspruch haben. Damit sind finanzielle Hilfen von anderen Trägern gemeint, die Ihnen oder Mitgliedern Ihrer Bedarfsgemeinschaft zustehen. Wichtig: Wichtig: Wenn Sie trotz Einkommens und vorrangiger Leistungen hilfebedürftig sind, können Sie Ihr Einkommen zusätzlich mit Bürgergeld ergänzen. Wie hoch der Ergänzungsbetrag ist, auf den Sie Anspruch haben, hängt von Ihrem Einkommen und Vermögen sowie Ihrem Bedarf ab. Mit Bedarf ist der Betrag gemeint, der Ihnen und Ihrer Familie für den Lebensunterhalt zusteht. Dieser setzt sich vor allem aus einem festen Regelbedarf und den Kosten für Unterkunft und Heizung zusammen. Von Ihrem Bedarf zieht das Jobcenter Ihr Einkommen ab. Es gibt dabei aber einen bestimmten Teil des Einkommens, der nicht berücksichtigt wird, den sogenannten Frei- oder Absetzungsbetrag. Wie hoch Ihr persönlicher Freibetrag ist, hängt unter anderem von Ihrem Bruttoverdienst und Ihren Beiträgen zur Sozialversicherung ab."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/einkommen-ergaenzen","topics":["aufstocker","buergergeld"],"tags":["official_rule_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:21.711681+00:00","lastSeen":"2026-03-17T07:01:21.711681+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/einkommen-ergaenzen","crawledAt":"2026-03-17T07:01:21.711681Z","crawlId":"aid-seeded-1773730881","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"a001042584a575740a6d6038abbb53b90959f90d2bd5c96731e106a31a6502d2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:21.712210+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('750ed334-6a37-440b-9b3b-09f3e4acd2e6', 'aid', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/voraussetzungen-einkommen-vermoegen', 'active', NULL, '2026-03-17T07:01:23.807362+00:00', '{"id":"750ed334-6a37-440b-9b3b-09f3e4acd2e6","title":"Bürgergeld: Voraussetzungen, Einkommen und Vermögen","summary":{"de":"Wer Anspruch auf Bürgergeld hat, welche Voraussetzungen es gibt und was Sie bei Einkommen und Vermögen beachten müssen."},"content":{"de":"Sie können Bürgergeld erhalten, wenn Sie erwerbsfähig und leistungsberechtigt sind und damit mindestens folgende Bedingungen erfüllen: Sie sind mindestens 15 Jahre alt und Sie haben die Altersgrenze für Ihre Rente noch nicht erreicht. Sie wohnen in Deutschland und haben hier Ihren Lebensmittelpunkt. Sie oder Mitglieder Ihrer Bedarfsgemeinschaft sind hilfebedürftig. Hilfebedürftig bedeutet, dass das Einkommen Ihrer Bedarfsgemeinschaft unter dem Existenzminimum liegt und Sie den Lebensunterhalt nicht ausreichend aus eigenen Mitteln bestreiten können. Erwerbsfähig bedeutet, dass keine Krankheit oder Behinderung Sie hindert, eine Arbeit aufzunehmen."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/voraussetzungen-einkommen-vermoegen","topics":["bedarfsgemeinschaft","buergergeld"],"tags":["official_rule_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:23.807362+00:00","lastSeen":"2026-03-17T07:01:23.807362+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/voraussetzungen-einkommen-vermoegen","crawledAt":"2026-03-17T07:01:23.807362Z","crawlId":"aid-seeded-1773730883","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"d74b3c9b9714076913e7119ca348ea9eead76c0de86a7e717e117f33f8e77900"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:23.807362+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('444d0ff3-afe6-48e1-bc5a-f12afc6363d3', 'aid', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/zusammensetzung-bedarfe', 'active', NULL, '2026-03-17T07:01:25.726782+00:00', '{"id":"444d0ff3-afe6-48e1-bc5a-f12afc6363d3","title":"Bedarfe: So setzt sich Bürgergeld zusammen","summary":{"de":"Erfahren Sie, wie sich Ihr Bürgergeld berechnet und bei welchen weiteren Kosten das Jobcenter hilft. Jetzt informieren!"},"content":{"de":"Bürgergeld bekommen Menschen, die hilfebedürftig sind. Das bedeutet, dass Sie Ihren Lebensunterhalt und den Ihrer Bedarfsgemeinschaft nicht selbst bestreiten können. Bürgergeld besteht aus verschiedenen Bausteinen. Diese heißen Bedarfe und bestimmen die Höhe des Bürgergeld. Welche Bedarfe in Ihrem Fall bewilligt wurden, teilt Ihnen das Jobcenter schriftlich mit. Dazu erhalten Sie einen sogenannten Bewilligungsbescheid. Damit sind die Kosten gemeint, die Ihren Lebensunterhalt sichern sollen. Dazu gehören vor allem … Für den Regelbedarf erhalten Sie einen monatlichen Pauschalbetrag. Die genauen Beträge finden Sie auf der Seite des Bundesministeriums für Arbeit und Soziales: Leistungen und Bedarfe im Bürgergeld Tipp: Tipp: Wie Sie den Regelbedarf verwenden, entscheiden Sie selbst. Sie sollten monatlich einen Betrag anzusparen – für den Fall, dass Sie zum Beispiel ein Haushaltsgerät ersetzen müssen. Angemessene Kosten für Miete, Heizung und Betriebskosten werden vom Jobcenter übernommen. Welche Kosten angemessen sind, kann örtlich unterschiedlich sein. Bitte fragen Sie bei Ihrem Jobcenter nach, welche Kosten in Ihrer Region als angemessen gelten."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/zusammensetzung-bedarfe","topics":["bedarfsgemeinschaft","buergergeld","mehrbedarf","regelbedarf"],"tags":["official_rule_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:25.726782+00:00","lastSeen":"2026-03-17T07:01:25.726782+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/finanziell-absichern/zusammensetzung-bedarfe","crawledAt":"2026-03-17T07:01:25.726782Z","crawlId":"aid-seeded-1773730885","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"7c181a930ed8a6efffa47419968e609938863a28819473e089d17c384c1f43f5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:25.726782+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('306f0949-de16-4138-8dae-890c693cdeef', 'aid', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/pflichten-verstehen-und-beachten', 'active', NULL, '2026-03-17T07:01:27.708570+00:00', '{"id":"306f0949-de16-4138-8dae-890c693cdeef","title":"Bürgergeld: Pflichten verstehen und beachten","summary":{"de":"Änderungen mitteilen, Erreichbarkeit absprechen und Co.: Welche Pflichten Sie haben, wenn Sie Bürgergeld erhalten."},"content":{"de":"Welche Änderungen wichtig sind und was Sie bei Nachweisen beachten müssen. Informieren Sie sich darüber, was Sie tun müssen, wenn Sie vorübergehend nicht erreichbar sind, weil Sie zum Beispiel verreisen wollen. Wie Sie das Jobcenter unterstützt, welche Pflichten Sie haben und was Minderungen bedeuten. Erfahren Sie, wie wir Ihre persönlichen Daten schützen. Wir sind für Sie da. Kommen Sie persönlich vorbei oder kontaktieren Sie uns. Bundesministerium für Arbeit und Soziales: Grundsicherung für Arbeitsuchende"},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/pflichten-verstehen-und-beachten","topics":["buergergeld","pflichten"],"tags":["official_rule_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:27.708570+00:00","lastSeen":"2026-03-17T07:01:27.708570+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/buergergeld/pflichten-verstehen-und-beachten","crawledAt":"2026-03-17T07:01:27.708570Z","crawlId":"aid-seeded-1773730887","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"c60ce02343971e76651262a07443d574a6444fc088d1a7e28e8d4823ea205a96"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:27.708570+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('857b3af6-5d6c-413a-95d1-355b5cfe72a5', 'aid', 'https://www.arbeitsagentur.de/familie-und-kinder', 'active', NULL, '2026-03-15T16:15:30.847912+00:00', '{"id":"857b3af6-5d6c-413a-95d1-355b5cfe72a5","title":"Familie und Kinder","summary":{"de":"Mit Kindergeld, Kinderzuschlag und weiteren finanziellen Hilfen unterstützt Sie die Familienkasse der Bundesagentur für Arbeit. Jetzt online beantragen!"},"content":{"de":"Ihr Profil im Online-Konto der Bundesagentur für Arbeit ist Ihr digitaler Zugang zur Familienkasse. Mit Ihrem Profil können Sie vieles direkt online erledigen – schnell, rund um die Uhr und von überall. Beantragen Sie Kindergeld für Ihr neugeborenes Kind. Beantragen Sie Kindergeld für Ihr volljähriges Kind. Ändern Sie Ihre persönlichen Daten (zum Beispiel Anschrift, Bankverbindung) oder laden Sie Unterlagen hoch. Beantragen Sie online Kinderzuschlag für Ihr Kind. Kindergeld erhalten Sie für Kinder unter 18 Jahren, unter bestimmten Voraussetzungen auch länger. Informieren Sie sich, wie Sie Kindergeld beantragen und in welcher Höhe es ausgezahlt wird."},"url":"https://www.arbeitsagentur.de/familie-und-kinder","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:30.847912+00:00","lastSeen":"2026-03-15T16:15:30.847912+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder","crawledAt":"2026-03-15T16:15:30.847912Z","crawlId":"aid-seeded-1773591330","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"922ac556dd5ace743ef82215f7d2e22d4c862cc604626c2a31081506ec999995"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:30.847912+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8156537e-95c7-4b13-9b92-8cb8ecf946c5', 'aid', 'https://www.arbeitsagentur.de/familie-und-kinder/informationen-zum-bildungspaket', 'active', NULL, '2026-03-15T16:15:16.288519+00:00', '{"id":"8156537e-95c7-4b13-9b92-8cb8ecf946c5","title":"Leistungen für Bildung und Teilhabe","summary":{"de":"Für Familien ohne oder nur mit geringem Einkommen gibt es viele Zuschüsse und Kostenübernahmen aus dem Bildungspaket. Mehr erfahren!"},"content":{"de":"Leistungen aus dem Bildungspaket sind in der Regel Geld- oder Sachleistungen (in Form von Gutscheinen). Sie erhalten sie von Ihrer Stadt oder Gemeinde. die Kosten für Nachhilfe-Stunden werden übernommen der Mitgliedsbeitrag des Sportvereins wird bezuschusst die Kosten für ein Sportgerät oder Musikinstrument werden teilweise übernommen Wenn Ihre Familie Bürgergeld beziehungsweise Kinderzuschlag (KiZ) erhält, können Sie Leistungen für Bildung und Teilhabe beantragen, wenn Ihr Kind … positiv: eine Kindertagesstätte (Kita) oder eine allgemein- oder berufsbildende Schule besucht und"},"url":"https://www.arbeitsagentur.de/familie-und-kinder/informationen-zum-bildungspaket","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:16.288519+00:00","lastSeen":"2026-03-15T16:15:16.288519+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/informationen-zum-bildungspaket","crawledAt":"2026-03-15T16:15:16.288519Z","crawlId":"aid-seeded-1773591316","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"8312738ab78ecfeda64394ad0b9677d901c7c185fa0f9d3266602bfcb981f854"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:16.288519+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('89bed917-c2c9-411c-af65-95a96cdf5a38', 'aid', 'https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen', 'active', NULL, '2026-03-17T07:01:31.722234+00:00', '{"id":"89bed917-c2c9-411c-af65-95a96cdf5a38","title":"Kinderzuschlag verstehen","summary":{"de":"Kinderzuschlag (auch: Kindergeldzuschlag): Voraussetzungen erfahren, Anspruch berechnen und Antrag stellen. Jetzt informieren!"},"content":{"de":"Der KiZ-Lotse: Anspruch auf Kinderzuschlag ermitteln Zu viel erhaltenes Kindergeld oder Kinderzuschlag zurückzahlen Wir sind für Sie da. Kommen Sie persönlich vorbei oder kontaktieren Sie uns. Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend: Informationen zu Familienleistungen Die wichtigsten Merkblätter, Formulare und Anträge der Familienkasse stehen Ihnen zum Download zur Verfügung. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen","topics":["buergergeld","kinderzuschlag"],"tags":["official_rule_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:31.722234+00:00","lastSeen":"2026-03-17T07:01:31.722234+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen","crawledAt":"2026-03-17T07:01:31.722234Z","crawlId":"aid-seeded-1773730891","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"5b4dd522e2b474e910248c1fd744f353cc94618ba0c4412868ae8e6853e77e59"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:31.722764+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8e556c2b-9fdb-4d5f-94d0-3c5ae964f378', 'aid', 'https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kinderzuschlag-anspruch-hoehe-dauer', 'active', NULL, '2026-03-17T07:01:33.724248+00:00', '{"id":"8e556c2b-9fdb-4d5f-94d0-3c5ae964f378","title":"Kinderzuschlag: Anspruch, Höhe, Dauer","summary":{"de":"Kinderzuschlag (auch: Kindergeldzuschlag): Wer Kinderzuschlag bekommt, wie Sie den Antrag stellen und wie lange Sie Kinderzuschlag erhalten. Mehr erfahren!"},"content":{"de":"Wenn das Einkommen nicht für die ganze Familie reicht, können Eltern zusätzlich zum Kindergeld den Kinderzuschlag erhalten. Der Antrag auf Kinderzuschlag muss jedoch gesondert bei der Familienkasse gestellt werden. Sie erhalten Kinderzuschlag für 6 Monate. Ist der Bewilligungszeitraum abgelaufen, müssen Sie Kinderzuschlag neu beantragen. Sie haben Anspruch auf Kinderzuschlag, wenn Sie bestimmte Voraussetzungen erfüllen. Ob Sie Kinderzuschlag erhalten, hängt davon ab, wie viel Einkommen und erhebliches Vermögen Sie, Ihr Partner beziehungsweise Ihre Partnerin und Ihr Kind haben. Erhalten Sie Kinderzuschlag, müssen Sie die Familienkasse über Änderungen Ihrer persönlichen Verhältnisse und die Ihrer Familie informieren. positiv: Ihr Kind lebt in Ihrem Haushalt, ist unter 25 Jahre alt und nicht verheiratet beziehungsweise nicht in einer eingetragenen Lebenspartnerschaft. positiv: Sie erhalten Kindergeld (oder eine vergleichbare Leistung) für Ihr Kind."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kinderzuschlag-anspruch-hoehe-dauer","topics":["buergergeld","kinderzuschlag"],"tags":["official_rule_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:33.724248+00:00","lastSeen":"2026-03-17T07:01:33.724248+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kinderzuschlag-anspruch-hoehe-dauer","crawledAt":"2026-03-17T07:01:33.724248Z","crawlId":"aid-seeded-1773730893","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"2d0d3ed2b2de66cf75e65c36afb2e7706acf367f06f7cee3d5f77802f63935f9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:33.724248+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('99f38dea-8e00-4670-a549-5598afb83757', 'aid', 'https://www.arbeitsagentur.de/familie-und-kinder/weitere-hilfen-fuer-eltern', 'active', NULL, '2026-03-15T16:15:16.518648+00:00', '{"id":"99f38dea-8e00-4670-a549-5598afb83757","title":"Unterstützung für Eltern","summary":{"de":"Finanzielle Hilfe für Eltern, Alleinerziehende, Schwangere: Welche zusätzlichen Unterstützung es gibt, wenn Ihre Mittel nicht ausreichen. Jetzt Informieren!"},"content":{"de":"Wer Kinder hat oder schwanger ist, ist besonderen Belastungen ausgesetzt. Unter anderem haben sie mehr Ausgaben beziehungsweise höhere Kosten. Es gibt darum eine Reihe von staatlichen Unterstützungsangeboten und Leistungen, die Eltern, Alleinerziehende und Schwangere entlasten. Wichtig: Informieren Sie sich, welche Stelle oder Behörde für die jeweilige Leistung zuständig ist. Ihre Familienkasse ist Ihr Ansprechpartner nur dann, wenn es um Kindergeld oder Kinderzuschlag geht. Eltern können Anspruch auf Elterngeld haben, wenn sie nach der Geburt ihres Kindes nicht mehr erwerbstätig sind oder auf eine Teilzeit-Stelle wechseln. Wer nach der Geburt seines Kindes weniger Einkommen hat, weil er weniger oder gar nicht mehr arbeitet, hat Anspruch auf diese Leistung. Ansprechpartner sind die lokalen Elterngeldstellen. Dort können Sie Elterngeld beantragen. Weitere Informationen zum Elterngeld finden Sie im Familienportal des Bundesfamilienministeriums. Dort erhalten Sie auch die Kontaktdaten Ihrer lokalen Elterngeldstelle."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/weitere-hilfen-fuer-eltern","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:16.518648+00:00","lastSeen":"2026-03-15T16:15:16.518648+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/weitere-hilfen-fuer-eltern","crawledAt":"2026-03-15T16:15:16.518648Z","crawlId":"aid-seeded-1773591316","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"34d2f04dbb570ec56457fc49761d1a0b7c54b2aed18274f4e868bac32044aaae"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:16.518648+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a212f605-2c54-43fe-b31f-4897b31b408d', 'aid', 'https://www.arbeitsagentur.de/freiwillige-arbeitslosenversicherung', 'active', NULL, '2026-03-15T16:15:31.860393+00:00', '{"id":"a212f605-2c54-43fe-b31f-4897b31b408d","title":"Freiwillige Arbeitslosenversicherung","summary":{"de":"Mit der Antragspflichtversicherung können Sie sich gegen das Risiko einer Arbeitslosigkeit absichern. Jetzt beantragen!"},"content":{"de":"Egal, ob Sie sich selbstständig machen oder beruflich umschulen, eine Beschäftigung im Ausland aufnehmen oder in Elternzeit Kinder betreuen: Wenn Sie nicht versicherungspflichtig in der Arbeitslosenversicherung sind, erwerben Sie keinen Anspruch auf Arbeitslosengeld. Falls Sie arbeitslos werden, kann das ein finanzielles Risiko für Sie bedeuten. Mit der freiwilligen Arbeitslosenversicherung können Sie dieses Risiko verringern: Werden Sie arbeitslos, können Sie bei Erfüllung der Anspruchsvoraussetzungen Arbeitslosengeld erhalten. Sie müssen die freiwillige Arbeitslosenversicherung innerhalb von 3 Monaten nach Beginn der Selbstständigkeit, Elternzeit, Umschulung oder der Beschäftigung im Ausland bei Ihrer Agentur für Arbeit beantragen. Sie können sich freiwillig in der Arbeitslosenversicherung versichern, wenn einer der folgenden Fälle auf Sie zutrifft: Sie starten in die Selbstständigkeit, die Sie mindestens 15 Stunden pro Woche ausüben werden. Sie betreuen in Elternzeit ein Kind, das älter als 3 Jahre ist. Sie machen eine Weiterbildung, um beruflich aufzusteigen, den Beruf zu wechseln oder einen Berufsabschluss zu erreichen."},"url":"https://www.arbeitsagentur.de/freiwillige-arbeitslosenversicherung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:31.860393+00:00","lastSeen":"2026-03-15T16:15:31.860393+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.arbeitsagentur.de/freiwillige-arbeitslosenversicherung","crawledAt":"2026-03-15T16:15:31.860393Z","crawlId":"aid-seeded-1773591331","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"37606e4d320e6f0463b358bfcf28d9f78745db93d200c414d846f198a474ed63"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:31.861907+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f624e734-8cc7-4756-9843-026f7360adfd', 'aid', 'https://www.arbeitsagentur.de/hilfe', 'active', NULL, '2026-03-15T16:15:17.021064+00:00', '{"id":"f624e734-8cc7-4756-9843-026f7360adfd","title":"Information und Hilfe","summary":{"de":"Beim Einsatz unterschiedlicher Browser für das Internet und aufgrund unterschiedlicher Software-Einstellungen kann es bei der Darstellung der Daten zu Abweichungen kommen. Unsere Internetseiten sind optimiert für die Browser"},"content":{"de":"Bei anderen Browsern, die Cascading Style Sheets CSS3 und HTML5 unterstützen, sollten keine Probleme bei der Darstellung auftreten. Ältere Browser-Versionen sind grundsätzlich nutzbar, doch kann es zu grafischen Abweichungen in der Anzeige von Schriften und Styles und zu Einschränkungen ausgewählter Funktionen kommen. Wir bitten um Ihr Verständnis. Um den Anwendern die bestmöglichste Darstellung zu gewährleisten, wurden unsere Seiten für folgende Ausgabemedien und Auflösungen optimiert: Entsprechend des verwendeten Endgerätes kann die Darstellung der jeweiligen Seitenbereiche (Tabellen, Bilder, Spalten, Navigation, etc.) variieren. Um die Darstellungsgröße in Ihrem Browser zu verändern, halten Sie die Taste \"Strg\" gedrückt und bewegen das Scrollrad auf der Maus oder halten Sie die Taste \"Strg\" gedrückt und verwenden die \"Plus\"-Taste zum Vergrößern oder die \"Minus\"-Taste zum Verkleinern. Dadurch werden alle Seitenelemente (auch die Schriften) in ihrer Größe nach Ihren Wünschen angepasst. Eine alternative Möglichkeit, nur die Schriftgröße über die für jeden Browser spezifisch anpassbaren Einstellungen zu verändern, wird nicht angeboten. Weitere Erläuterungen erhalten Sie in der Hilfe zu Ihrem Browser. Viele Betriebssysteme bieten eine verbesserte Schriftendarstellung durch eine sogenannte Kantenglättung der Schriftzeichen an."},"url":"https://www.arbeitsagentur.de/hilfe","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:17.021064+00:00","lastSeen":"2026-03-15T16:15:17.021064+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.arbeitsagentur.de/hilfe","crawledAt":"2026-03-15T16:15:17.021064Z","crawlId":"aid-seeded-1773591317","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4c4fed4dcb86387f765dd44eeb4675531a5cb8cd84f0c92f88db308326cc4a71"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:17.021064+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('14489f52-8ee3-4bec-8560-67df001841af', 'aid', 'https://www.arbeitsagentur.de/lexikon/aufstocker', 'active', NULL, '2026-03-17T07:01:35.723961+00:00', '{"id":"14489f52-8ee3-4bec-8560-67df001841af","title":"Begriffserklärung: Aufstocker","summary":{"de":"Aufstocken und Ergänzen: Was es bedeutet und was der Unterschied ist. Mehr erfahren!"},"content":{"de":"In manchen Fällen reicht Arbeitslosengeld nicht aus, um den Lebensunterhalt zu bestreiten. In solchen Fällen können Arbeitslose zusätzlich Bürgergeld beziehen. Die Bundesagentur für Arbeit (BA) bezeichnet arbeitslose Erwerbsfähige, die zur Existenzsicherung beide Leistungen beziehen, als Aufstocker. Die alltagssprachliche Verwendung dieses Begriffs weicht davon ab: Vielfach werden Erwerbstätige „Aufstocker“ genannt, wenn ihr Lohn nicht für den Lebensunterhalt reicht und sie darum zusätzlich Bürgergeld erhalten. Informieren Sie sich, unter welchen Voraussetzungen Sie Ihr zu geringes Einkommen mit Bürgergeld ergänzen können. Die BA bezeichnet diese Leistungsempfänger als Ergänzer oder erwerbstätige erwerbsfähige Leistungsberechtigte. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/lexikon/aufstocker","topics":["aufstocker","bedarfsgemeinschaft","buergergeld","leichte_sprache_soziale_sicherheit"],"tags":["official_glossary_source","glossary"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:35.723961+00:00","lastSeen":"2026-03-17T07:01:35.723961+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/lexikon/aufstocker","crawledAt":"2026-03-17T07:01:35.723961Z","crawlId":"aid-seeded-1773730895","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"dd4ee76b9f3389056a237266daa007e7e022e388fa872842944c175772bbdd16"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:35.724638+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e8a3d91b-30ed-4288-85bc-3abf91dc2576', 'aid', 'https://www.arbeitsagentur.de/lexikon/bedarfsgemeinschaft', 'active', NULL, '2026-03-17T07:01:37.907992+00:00', '{"id":"e8a3d91b-30ed-4288-85bc-3abf91dc2576","title":"Begriffserklärung: Bedarfsgemeinschaft","summary":{"de":"Der Begriff „Bedarfsgemeinschaft“ spielt eine wichtige Rolle in der Grundsicherung und hat Einfluss auf die Höhe der Leistungen. Mehr erfahren!"},"content":{"de":"Der Rechtsbegriff „Bedarfsgemeinschaft“ spielt beim Bezug von Bürgergeld eine wichtige Rolle. Obwohl er das Wort „Gemeinschaft“ enthält, gilt: Die Antragsstellerin oder der Antragssteller allein wird schon als Bedarfsgemeinschaft bezeichnet. Lebt sie oder er mit anderen Menschen zusammen und übernehmen alle eine wechselseitige Verantwortung füreinander, bilden sie gemeinsam die Bedarfsgemeinschaft. Der Rechtsbegriff wird darum in der Regel angewandt auf... eingetragene gleichgeschlechtliche Lebenspartnerinnen oder Lebenspartner, die nicht dauerhaft getrennt leben, oder Personen in einer Verantwortungs- und Einstehensgemeinschaft („eheähnliche Gemeinschaft“). Zur Bedarfsgemeinschaft gehören auch die Kinder, die im Haushalt leben und jünger als 25 Jahre sind. Voraussetzung: Sie sind unverheiratet, erwerbsfähig und können ihren Lebensunterhalt nicht aus eigenem Einkommen bestreiten. Zum Einkommen von Kindern zählen zum Beispiel Kindergeld oder Unterhaltszahlungen. Umgekehrt gilt: Beantragt ein unverheiratetes erwerbsfähiges Kind, das mindestens 15, aber noch keine 25 Jahre alt ist, Leistungen nach dem SGB II, gehören auch die im Haushalt lebenden Eltern oder Elternteile zur Bedarfsgemeinschaft."},"url":"https://www.arbeitsagentur.de/lexikon/bedarfsgemeinschaft","topics":["bedarfsgemeinschaft","buergergeld","leichte_sprache_soziale_sicherheit","regelbedarf"],"tags":["official_glossary_source","glossary"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:37.907992+00:00","lastSeen":"2026-03-17T07:01:37.907992+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"arbeitsagentur.de","provenance":{"source":"https://www.arbeitsagentur.de/lexikon/bedarfsgemeinschaft","crawledAt":"2026-03-17T07:01:37.908993Z","crawlId":"aid-seeded-1773730897","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"88d22847e476dc6d9da41e0c5762a4be7968fdada9b8880e5e0c61267b6ff3fa"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:37.908993+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e55008c7-a9be-4028-88ca-18e2e799a124', 'aid', 'https://www.arbeitsagentur.de/menschen-mit-behinderungen/spezielle-hilfe-und-unterstuetzung/gleichstellung/gleichstellung-upload', 'active', NULL, '2026-03-15T16:25:13.497569+00:00', '{"id":"e55008c7-a9be-4028-88ca-18e2e799a124","title":"Gleichstellungsantrag: Upload-Service","summary":{"de":"Laden Sie den Antrag und Dokumente zu Kurzarbeit und Kurzarbeitergeld für Ihre Arbeitsagentur hoch. Nutzen Sie den Upload-Service einfach ohne Anmeldung!"},"content":{"de":"Auf dieser Seite finden Sie das Antragsformular, das Sie online ausfüllen können. Sie erfahren außerdem, welche weiteren Dokumente Sie benötigen und gegebenenfalls vorab besorgen müssen. Liegen Ihnen alle notwendigen Dokumente als Datei vor, können Sie sie hochladen und an uns übermitteln. Füllen Sie das Antragsformular online aus. Die Ausfüllhilfe unterstützt Sie dabei. Hinweis: Ihr Antrag braucht keine Unterschrift, wenn Sie ihn per Upload-Service übermitteln. Welche Nachweise Sie erbringen müssen, entnehmen Sie bitte dem Antragsformular. In jedem Fall müssen Sie Art und Grad der Behinderung nachweisen, zum Beispiel mit dem Feststellungsbescheid des Versorgungsamtes. Für alle Dateien gelten folgende technische Voraussetzungen: maximale Datenmenge insgesamt: 19 MB. Falls Sie diese Datenmenge ausgeschöpft haben, führen Sie bitte einen weiteren Upload-Vorgang aus. Wie Sie umfangreiche Dokumente für einen Upload vorbereiten, erfahren Sie in der Anleitung zum Hochladen von umfangreichen Dokumenten."},"url":"https://www.arbeitsagentur.de/menschen-mit-behinderungen/spezielle-hilfe-und-unterstuetzung/gleichstellung/gleichstellung-upload","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:13.497569+00:00","lastSeen":"2026-03-15T16:25:13.497569+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.arbeitsagentur.de/menschen-mit-behinderungen/spezielle-hilfe-und-unterstuetzung/gleichstellung/gleichstellung-upload","crawledAt":"2026-03-15T16:25:13.497569Z","crawlId":"aid-seeded-1773591913","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"5d7b4d5f5aa72e12956a9ac286f979a96e4507fc78e23ce9a823afc48ce3de1f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:13.497569+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6a369ca5-0c7e-401c-b5ee-a7fdd0acb658', 'aid', 'https://www.arbeitsagentur.de/ueber-uns/technischer-beratungsdienst', 'active', NULL, '2026-03-15T16:25:57.731286+00:00', '{"id":"6a369ca5-0c7e-401c-b5ee-a7fdd0acb658","title":"Technischer Beratungsdienst","summary":{"de":"Bundesweit sind 90 Ingenieurinnen und Ingenieure im Technischen Beratungsdienst der BA tätig. Diese übernehmen darüber hinaus in den Agenturen für Arbeit und Jobcenter die Funktion als Fachkräfte für Arbeitssicherheit."},"content":{"de":"Der TBD arbeitet im Auftrag der Fachabteilungen der Arbeitsagenturen und Jobcenter. Er wird von diesen mit Beratungsaufträgen und technischen Begutachtungen betraut. Ziel der Arbeit des TBD ist es, durch seine Expertise die Einstellungschancen von Arbeitssuchenden oder Arbeitslosen mit Behinderungen zu verbessern. Der TBD unterstützt Arbeitgeberinnen und Arbeitgeber, die Menschen mit Schwerbehinderungen oder Rehabilitanden beschäftigen oder zukünftig beschäftigen möchten. Im Vordergrund stehen dabei erforderliche Anpassungen von Arbeitsplätzen, die Herstellung der baulichen Barrierefreiheit, zum Beispiel bei den Zugängen zur Arbeitsstätte und arbeitsschutzrelevante Themen. Der TBD berät Arbeitergeberinnen und Arbeitgeber sowie bei Bedarf weitere Stellen innerhalb der Betriebe. Das sind zum Beispiel die Schwerbehindertenvertretung oder der Personal- und Betriebsrat. Themen können unter anderem grundlegende Abläufe und Fördermöglichkeiten sein. Gegebenenfalls stellt der TBD auch den Kontakt zu Vermittlungs- und Integrationsfachkräften in den Arbeitsagenturen beziehungsweise Jobcentern her. Die Mitarbeiterinnen und Mitarbeiter des TBD beraten und begutachten überwiegend vor Ort. Sie erarbeiten passgenaue Lösungen, die sie auf die Anforderungen aller Beteiligten abstimmen. Der Technische Beratungsdienst steht im engen Austausch mit den Reha-Teams sowie Vermittlungs- und Integrationsfachkräften in den Agenturen und Jobcentern. Zudem arbeiten sie mit anderen Behörden und Stellen aus dem Bereich Inklusion zusammen, zum Beispiel dem Integrationsfachdienst."},"url":"https://www.arbeitsagentur.de/ueber-uns/technischer-beratungsdienst","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:57.731286+00:00","lastSeen":"2026-03-15T16:25:57.731286+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/technischer-beratungsdienst","crawledAt":"2026-03-15T16:25:57.731286Z","crawlId":"aid-seeded-1773591957","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"da607a759f44173fb936e05d42806744fff8bb622dcfd89ea3a548c4379551fb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:57.731286+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('81599348-35c0-470d-988d-deb6c3e5d469', 'aid', 'https://www.bke-beratung.de/elternberatung/willkommen', 'active', NULL, '2026-03-15T16:26:23.090418+00:00', '{"id":"81599348-35c0-470d-988d-deb6c3e5d469","title":"Willkommen bei der bke-Elternberatung!","summary":{"de":"Mailberatung Schreiben Sie in Ruhe Ihre Gedanken und Sorgen … ganz ohne Zeitdruck Forum Rund um die Uhr mitdiskutieren, begleitet von unseren Beraterinnen und Beratern. Gruppenchat Mit anderen Eltern chatten. Zu offenen oder speziellen Themen Einzelchat Probleme und Fragen vertraulich mit einer Beraterin oder einem Berater besprechen..."},"content":{"de":"Mailberatung Schreiben Sie in Ruhe Ihre Gedanken und Sorgen … ganz ohne Zeitdruck Forum Rund um die Uhr mitdiskutieren, begleitet von unseren Beraterinnen und Beratern. Gruppenchat Mit anderen Eltern chatten. Zu offenen oder speziellen Themen Einzelchat Probleme und Fragen vertraulich mit einer Beraterin oder einem Berater besprechen..."},"url":"https://www.bke-beratung.de/elternberatung/willkommen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:23.090418+00:00","lastSeen":"2026-03-15T16:26:23.090418+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bke-beratung.de/elternberatung/willkommen","crawledAt":"2026-03-15T16:26:23.090418Z","crawlId":"aid-seeded-1773591983","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"3d1a0d5e8127d2f4ba3a887780c7fc2ec855597b12e11f2a6cf5abe8fd7fd5b4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:23.090418+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5b8ede69-85c7-4653-9fcf-3acb8923ff54', 'aid', 'https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Beratung-und-Vermittlung/beratung-und-vermittlung.html', 'active', NULL, '2026-03-15T17:45:51.648829+00:00', '{"id":"5b8ede69-85c7-4653-9fcf-3acb8923ff54","title":"Beratung und Vermittlung","summary":{"de":"Einen wesentlichen Bestandteil unter den Leistungen der Arbeitsförderung stellt die Arbeitsvermittlung dar."},"content":{"de":"Einen wesentlichen Bestandteil unter den Leistungen der Arbeitsförderung stellt die Arbeitsvermittlung dar."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Beratung-und-Vermittlung/beratung-und-vermittlung.html","topics":["employment","financial_support","aid"],"tags":["application_required","aid"],"targetGroups":["unemployed","general_public","families","single_parents"],"status":"active","firstSeen":"2026-03-15T17:45:51.648829+00:00","lastSeen":"2026-03-15T17:45:51.648829+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Beratung-und-Vermittlung/beratung-und-vermittlung.html","crawledAt":"2026-03-15T17:45:51.648829Z","crawlId":"aid-seeded-1773596751","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"517fc860031cc1088fb3db16dee33cbcc13f7f1d1f8d7c7b0d143ccc3a1095ca"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:45:51.650414+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8293c4c6-1c8e-4fd8-af30-6bf31bb03c5f', 'aid', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Beratungsangebot-Faire-Integration/beratungsangebot-faire-integration.html', 'active', NULL, '2026-03-15T16:25:59.686495+00:00', '{"id":"8293c4c6-1c8e-4fd8-af30-6bf31bb03c5f","title":"Faire Integration","summary":{"de":"Beratungsangebot für Arbeitnehmerinnen und Arbeitnehmer aus Drittstaaten zu arbeits- und sozialrechtlichen Fragen und gegen Arbeitsausbeutung."},"content":{"de":"Die Bundesregierung sorgt mit Beratungsangeboten zu arbeits- und sozialrechtlichen Fragen dafür, dass Drittstaatsangehörige vor Arbeitsausbeutung geschützt werden. Informations- und Hinweispflicht für Arbeitgeber*innen und Vermittler*innen Beratungsangebot für EU-Arbeitnehmerinnen und Arbeitnehmer Das Beratungs- und Informationsangebot \"Faire Integration\" wird seit dem 1. Januar 2026 auf Grundlage von § 45b Aufenthaltsgesetz i. V. m. der Drittstaats­angehörigen­beratungs­verordnung durchgeführt. Zuvor wurde das Beratungsangebot als Programmlinie des ESF Plus-Förderprogramms \"IQ – Integration durch Qualifizierung\" gefördert. \"Faire Integration\" ist ein Beratungsangebot für im In- und Ausland lebende Drittstaatsangehörige zu arbeits- und sozialrechtlichen Fragen. Die Beratungsstellen vermitteln Drittstaatsangehörigen Kenntnisse über die eigenen Rechte und Pflichten im Arbeitsverhältnis und unterstützen sie dabei, sich vor Ausbeutung und Benachteiligung im Arbeitsverhältnis zu schützen. Von diesem Schutz profitieren auch einheimische Beschäftigte, indem unfairer Wettbewerb durch unangemessene Arbeitsbedingungen, insbesondere durch Lohndumping, verhindert wird. In jedem Bundesland ist eine Beratungsstelle durch jeweils einen Träger eingerichtet. Jeder Träger ist für die Beratung von Personen aller Berufsgruppen und Wirtschaftszweige zuständig. Beratungsgegenstand sind Fragen von Drittstaatsangehörigen zu arbeits- und sozialrechtlichen Themen, die mit dem Beschäftigungsverhältnis zusammenhängen, zum Beispiel zu Lohn, Arbeitszeit, Urlaub, Kündigung, Krankenversicherung und Rentenansprüchen. Die Inanspruchnahme der Beratung ist für die Drittstaatsangehörigen kostenlos und soll möglichst in der Muttersprache des Drittstaatsangehörigen erfolgen."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Beratungsangebot-Faire-Integration/beratungsangebot-faire-integration.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:59.686495+00:00","lastSeen":"2026-03-15T16:25:59.686495+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Beratungsangebot-Faire-Integration/beratungsangebot-faire-integration.html","crawledAt":"2026-03-15T16:25:59.686495Z","crawlId":"aid-seeded-1773591959","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6ced0e5c407d6b6bc7c616173bbe0c162f962b35e576a205585e7f276a5caa35"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:59.686495+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d27af04d-5dde-43ba-9dd8-991efa737a60', 'aid', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Kuendigungsschutz/kuendigungsschutz.html', 'active', NULL, '2026-03-15T16:15:36.352852+00:00', '{"id":"d27af04d-5dde-43ba-9dd8-991efa737a60","title":"Kündigungsschutz","summary":{"de":"Wird ein Arbeitsverhältnis beendet, so besteht für Arbeitnehmerinnen und Arbeitnehmer ein allgemeiner Kündigungsschutz."},"content":{"de":"Besonderer Kündigungsschutz bestimmter Arbeitnehmergruppen Die Beendigung des Arbeitsverhältnisses ist nur unter bestimmten Voraussetzungen möglich, die das Kündigungsschutzrecht näher regelt. In Betrieben mit mehr als zehn Arbeitnehmerinnen bzw. Arbeitnehmern gilt das Kündigungsschutzgesetz. In diesem Fall kann der Arbeitgeber das Arbeitsverhältnis nur kündigen, wenn ein Kündigungsgrund vorliegt. Kündigungsgründe, die das Kündigungsschutzgesetz zulässt, sind Gründe in der Person oder dem Verhalten der Arbeitnehmerin bzw. des Arbeitnehmers sowie betriebsbedingte Gründe. Die Broschüre informiert über den allgemeinen und besonderen Kündigungsschutz. Sowohl Arbeitgeber als auch Arbeitnehmerin bzw. Arbeitnehmer müssen die gesetzlichen oder vereinbarten Kündigungsfristen einhalten. Eine fristlose Kündigung kann nur dann ausgesprochen werden, wenn ein wichtiger Grund vorliegt. Eine Arbeitnehmerin bzw. ein Arbeitnehmer, die bzw. der die Wirksamkeit seiner Kündigung gerichtlich überprüfen lassen möchte, kann innerhalb von drei Wochen nach Zugang der schriftlichen Kündigung Kündigungsschutzklage erheben. Wird die Frist versäumt, gilt die Kündigung als von Anfang an rechtswirksam."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Kuendigungsschutz/kuendigungsschutz.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:36.352852+00:00","lastSeen":"2026-03-15T16:15:36.352852+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Kuendigungsschutz/kuendigungsschutz.html","crawledAt":"2026-03-15T16:15:36.352852Z","crawlId":"aid-seeded-1773591336","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"211cd109bf732ddc460942ef700f201e63a451d080053aaf20934c93262911a7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:36.352852+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('eb504f9f-2ebe-4dfc-9564-075609a3a904', 'aid', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Berufsberatung-und-Berufsorientierung/berufsberatung-und-berufsorientierung.html', 'active', NULL, '2026-03-15T16:26:00.299242+00:00', '{"id":"eb504f9f-2ebe-4dfc-9564-075609a3a904","title":"Berufsberatung und Berufsorientierung","summary":{"de":"Angebote zur Berufsberatung und -orientierung helfen bei der Berufsentscheidung, indem sie über Tätigkeiten, Anforderungen und Fördermöglichkeiten informieren."},"content":{"de":"Ausbildungsvermittlung: Wo finde ich meinen Platz? Die Bundesagentur für Arbeit (BA) ist ein wichtiger Partner, wenn es darum geht, jungen Menschen den Weg in Ausbildung und Beruf zu erleichtern. Sie bietet unter anderem eine individuelle Berufsberatung und Berufsorientierung an. Außerdem führt die BA Angebot und Nachfrage nach Ausbildungs- und Arbeitsplätzen auf unterschiedlichen Wegen zusammen: Offene Stellen sammelt sie in der Jobbörse, Informationen zu Berufsbildern verbreitet sie in Printmedien und via Social Media und sie betreibt gezielte Ausbildungs- und Arbeitsvermittlung. Junge Arbeitsuchende, die Anspruch auf Grundsicherung haben (nach dem Sozialgesetzbuch SGB II ) bekommen in den Jobcentern kompetente Unterstützung. In gemeinsamen Vereinbarungen (den sogenannten Bildungsketten ) setzen sich Bund, Länder und BA auch dafür ein, die Förderinstrumente zur Berufsorientierung miteinander zu verknüpfen und aufeinander abzustimmen. Auf Basis der BO-Konzepte der Schulen bieten die Agenturen für Arbeit Orientierungsangebote an. Das heißt, dass die Schüler*innen konkrete Einblicke in verschiedene Berufe, deren Anforderungen und Aussichten bekommen. Auch die individuelle Berufsberatung beginnt bereits während der Schulzeit. Für Schüler*innen von allgemeinbildenden Schulen kann die Orientierung und Vorbereitung für die Berufswahl noch zusätzlich durch Berufsorientierungsmaßnahmen vertieft werden. Die Kosten dafür werden zu maximal 50 Prozent von der Bundesagentur für Arbeit übernommen, den Rest muss ein Dritter ( z.B. Schule, Länder, Kommunen oder Kammern etc. ) übernehmen. Die Berufsberatung bietet Rat und Informationen zu allen Berufswegen und den jeweiligen Anforderungen. Sie informiert zu aktuellen Trends oder Entwicklungen am Ausbildungs- und Arbeitsmarkt, von denen junge Menschen profitieren können. Gemeinsam mit den Berater*innen gehen die Ratsuchenden ihren beruflichen Wünschen, Fähigkeiten und Zielen auf den Grund. Auch werden, falls für den Wunschberuf bestimmte Voraussetzungen fehlen, realistische Alternativen gesucht und gefunden. Die Berufsberatung beginnt bereits während der Schulzeit und kann darüber hinaus in den Agenturen für Arbeit in Anspruch genommen werden. Um die Entscheidung für ein Beruf / Berufsfeld abzurunden, prüft die Berufsberatung auch, welche Fördermöglichkeiten nötig und vorhanden sind. Je nach individuellem Fall kann die Empfehlung am Ende der Beratung eine Ausbildung, ein Studium oder auch eine Kombination aus beidem sein."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Berufsberatung-und-Berufsorientierung/berufsberatung-und-berufsorientierung.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:00.299242+00:00","lastSeen":"2026-03-15T16:26:00.299242+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Berufsberatung-und-Berufsorientierung/berufsberatung-und-berufsorientierung.html","crawledAt":"2026-03-15T16:26:00.300754Z","crawlId":"aid-seeded-1773591960","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c00603c8a3bdbebf386a355a156caffd8fe013277ee63e903a77bb570a4dec27"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:00.300754+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('455a0814-d3c9-42db-a6d7-573735a79bcd', 'aid', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Hilfe-beim-Hauptschulabschluss/hilfe-beim-hauptschulabschluss.html', 'active', NULL, '2026-03-15T16:26:00.890510+00:00', '{"id":"455a0814-d3c9-42db-a6d7-573735a79bcd","title":"Hilfe beim Hauptschulabschluss","summary":{"de":"Menschen ohne Schulabschluss haben einen Rechtsanspruch auf Förderung der Vorbereitung zum nachträglichen Erwerb des Hauptschulabschlusses oder eines gleichwertigen Schulabschlusses."},"content":{"de":"Ein fehlender Schulabschluss ist eines der zentralen Hemmnisse bei der Aufnahme einer Berufsausbildung und dem erfolgreichen Einstieg in das Berufsleben. Daher wurde mit dem Gesetz zur Neuausrichtung der arbeitsmarktpolitischen Instrumente für junge Menschen und Erwachsene ohne Schulabschluss zum 1. Januar 2009 ein Rechtsanspruch auf Förderung der Vorbereitung auf den nachträglichen Erwerb des Hauptschulabschlusses oder eines gleichwertigen Schulabschlusses eingeführt. Die Umsetzung erfolgt für junge Menschen im Rahmen berufsvorbereitender Bildungsmaßnahmen. Die inhaltliche Ausgestaltung einer berufsvorbereitenden Bildungsmaßnahme durch die Bundesagentur für Arbeit erfolgt anhand des Fachkonzepts für berufsvorbereitende Bildungsmaßnahmen, das von der Bundesagentur für Arbeit zuletzt im November 2012 überarbeitet worden ist. Die gesetzliche Regelung ist inhaltlich offen - ohne Benennung einer Mindest- oder Höchstförderdauer - gestaltet, sodass bei der Konzeption einzelner Maßnahmen nach dem Fachkonzept der Bundesagentur für Arbeit auch besondere Bedürfnisse und Problemlagen von jungen Menschen aus dem Rechtskreis des SGB II Berücksichtigung finden können. Die Förderinhalte werden flexibel am individuellen Bedarf der jungen Menschen ausgerichtet. Neben beruflicher und allgemeinbildender Qualifizierung - unterstützt durch Zeiten betrieblicher Praktika - werden auch persönliche und soziale Kompetenzen gefördert. Systematische sozialpädagogische Begleitung sowie kontinuierliche Bildungsbegleitung sind in die Förderung eingebettet. Auf den nachträglichen Erwerb des Hauptschulabschlusses wird vorbereitet, indem sich Phasen zum Erlernen berufspraktischer Fertigkeiten und sozialer Qualifikationen und Zeiten zur theoretischen Wissensvermittlung ergänzen. Hierfür ist eine Regelförderdauer von bis zu zwölf Monaten vorgesehen. Für Erwachsene erfolgt die Umsetzung des Rechtsanspruchs im Rahmen der Förderung einer beruflichen Weiterbildung mit dem Ziel des Nachholens eines Hauptschul- oder vergleichbaren Abschlusses. Über eine Förderung entscheidet die Agentur für Arbeit oder das Jobcenter."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Hilfe-beim-Hauptschulabschluss/hilfe-beim-hauptschulabschluss.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:00.890510+00:00","lastSeen":"2026-03-15T16:26:00.890510+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Hilfe-beim-Hauptschulabschluss/hilfe-beim-hauptschulabschluss.html","crawledAt":"2026-03-15T16:26:00.890510Z","crawlId":"aid-seeded-1773591960","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"5963ba2499ea103d8de40ef96defceb4c27b8db60ad2590437329daf5abc9db8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:00.890510+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f2afff0b-d167-4410-9a56-2a55fce508fc', 'aid', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Informationen-und-Beratung/informationen-und-beratung.html', 'active', NULL, '2026-03-15T16:26:01.543669+00:00', '{"id":"f2afff0b-d167-4410-9a56-2a55fce508fc","title":"Informationen und Beratung","summary":{"de":"Unabhängig davon, wo sie tatsächlich versichert sind, haben Menschen in Ihrem Wohnsitzland Anspruch auf Sachleistungen im Krankheitsfall, etwa medizinische Leistungen und Medikamente."},"content":{"de":"Leben Sie im Ausland? Unabhängig davon, wo Sie tatsächlich versichert sind, haben Sie in Ihrem Wohnsitzland Anspruch auf Sachleistungen im Krankheitsfall, etwa medizinische Leistungen und Medikamente. Dabei steht Ihnen genau dieselbe Behandlung zu wie Staatsangehörigen des betreffenden Landes. Falls Sie außerhalb Ihres Wohnsitzlandes versichert sind, sollten Sie sich bei der für Ihren Wohnsitz zuständigen Krankenkasse registrieren lassen. Dazu sollten Sie sich von Ihrem Krankenversicherungs­träger einen \"Vordruck S1\" zur Vorlage bei der Krankenkasse an Ihrem Wohnsitz geben lassen. Dies ist in der Regel bei Rentnern der Fall, die ihren Ruhestand außerhalb des Landes verbringen, das ihre Rente zahlt und in dem sie versichert sind. Allgemeine Informationen zu den Leistungen der Sozialversicherung bei Krankheit, Arbeitsunfall und -Berufskrankheit sind auf den Internetseiten des GKV-Spitzenverbandes bzw. der Deutschen Gesetzlichen Unfallversicherung erhältlich. Sie sind Rentnerin oder Rentner? Grundsätzlich gilt: Renten aus der deutschen gesetzlichen Rentenversicherung werden ohne Abzug, Aufschub oder Änderung ausgezahlt, ganz gleich, wo in der EU Sie zum Zeitpunkt der Rentenauszahlung leben. Haben Sie in mehr als einem Mitgliedstaat gearbeitet, brauchen Sie ebenfalls keine Nachteile zu befürchten. Es gibt zwar keine \"Europarente\", aber jeder Staat zahlt im Rahmen der europäischen und seiner nationalen Rechtsvorschriften grundsätzlich eine Rente. Nähere Informationen zum Thema \"Rente und Ausland\" finden Sie auf der Homepage der Deutschen Rentenversicherung und auf der Website der EU-Kommission. Wenn Sie vergleichende Informationen zu den Systemen der sozialen Sicherheit anderer EU-Staaten interessieren, finden Sie diese auf der Website des Sozialschutzsystems MISSOC ( Mutual Information System on Social Protection ), einem System der EU, das Informationen zur sozialen Sicherheit bereitstellt. MISSOC veröffentlicht vergleichende Tabellen zur sozialen Sicherheit in: 31 Ländern (den 27 EU-Ländern sowie Island, Liechtenstein, Norwegen und der Schweiz), 12 großen Schutzbereichen: Finanzierung, Gesundheitsfürsorge, Krankheit, Mutterschaft, Invalidität, Alter, Hinterbliebene, Arbeitsunfälle und Berufskrankheiten, Familie, Arbeitslosigkeit, Mindestsicherung, Pflege, Die bereitgestellten Informationen sind auf Deutsch, Englisch und Französisch abrufbar. Zudem werden die Informationen über nationale Systeme regelmäßig aktualisiert und detailliert in Tabellenform dargestellt."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Informationen-und-Beratung/informationen-und-beratung.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:01.543669+00:00","lastSeen":"2026-03-15T16:26:01.543669+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Informationen-und-Beratung/informationen-und-beratung.html","crawledAt":"2026-03-15T16:26:01.543669Z","crawlId":"aid-seeded-1773591961","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"0e562f0ab632279ea2fae48cd4aa33bacbae12d0865ba5af403f6917b936f7f0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:01.544672+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('12aca3a3-21d8-48eb-805a-1a9fedb5cef9', 'aid', 'https://www.bmas.de/DE/Service/Publikationen/Broschueren/a206-regelbedarf.html', 'active', NULL, '2026-03-17T07:01:44.329828+00:00', '{"id":"12aca3a3-21d8-48eb-805a-1a9fedb5cef9","title":"Regelbedarf","summary":{"de":"In der Broschüre werden die wichtigsten Fragen im Zusammenhang mit der Methodik der Regelbedarfsermittlung beantwortet."},"content":{"de":"In­fo­blatt – Fort­schrei­bung der Re­gel­be­dar­fe zum 1. Ja­nu­ar 2026 In­fo­blatt zur Bro­schü­re A206 \"Re­gel­be­darf\" [PDF, 30KB] Methodik der Regelbedarfsermittlung – Fragen und Antworten"},"url":"https://www.bmas.de/DE/Service/Publikationen/Broschueren/a206-regelbedarf.html","topics":["buergergeld","regelbedarf"],"tags":["official_background_source"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:44.329828+00:00","lastSeen":"2026-03-17T07:01:44.329828+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Service/Publikationen/Broschueren/a206-regelbedarf.html","crawledAt":"2026-03-17T07:01:44.329828Z","crawlId":"aid-seeded-1773730904","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"038fa8dafe6a74f2be46fc59114856a01c0318d458ccf3df74b68946981a7de2"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-17T07:01:44.329828+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e5d4a5fc-bbdc-4a79-9b05-12da0125651a', 'aid', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/Schnelle-Hilfen/schnelle-hilfen.html', 'active', NULL, '2026-03-15T16:26:02.206514+00:00', '{"id":"e5d4a5fc-bbdc-4a79-9b05-12da0125651a","title":"Schnelle Hilfen","summary":{"de":"Die Leistungen der Schnellen Hilfen sind in Kapitel 4 SGB XIV geregelt und umfassen das Fallmanagement und die Leistungen der Traumaambulanz."},"content":{"de":"Beim Fallmanagement begleiten Fallmanagerinnen und Fallmanager die Berechtigten durch das gesamte Antrags- und Leistungsverfahren. Sie stehen Berechtigten während des gesamten Verfahrens als persönliche Ansprechpartnerinnen oder Ansprechpartner zur Verfügung. Sie ermitteln u. a. den möglichen Hilfebedarf und weisen auch auf andere in Betracht kommende Sozialleistungen hin. Betroffene von Gewalttaten oder anderen schädigenden Ereignissen können sich an so genannte Fallmanager wenden. Diese bieten schnell und unkompliziert Hilfestellung bei der Beantragung der Leistungen. In diesem Video lernen Sie Fallmanagerin Simone Müller kennen, die Betroffene sowie Angehörige und Hinterbliebene berät und bei der Antragstellung unterstützt. In der Traumaambulanz erhalten Berechtigte schnell und unbürokratisch psychotherapeutische Unterstützung. Dabei genügt es, wenn der Antrag hierauf spätestens nach der zweiten Sitzung in der Traumaambulanz gestellt wird. Voraussetzung für die Inanspruchnahme der Traumaambulanz ist, dass Betroffene sie innerhalb von zwölf Monaten nach dem schädigenden Ereignis oder Kenntnis hiervon aufsuchen. Bei länger zurückliegenden Ereignissen, die zu einer akuten psychischen Belastung geführt haben, kann die Traumaambulanz innerhalb von zwölf Monaten nach Auftreten der akuten Krise ebenfalls aufgesucht werden. Betroffene erhalten bis zu 15 Sitzungen in der Traumaambulanz, Kinder und Jugendliche bis zu 18 Sitzungen. Besteht anschließend weiterer psychotherapeutischer Behandlungsbedarf, werden Betroffene auf weitere psychotherapeutische Behandlungsangebote verwiesen. Weitere Regelungen im Zusammenhang mit der Traumaambulanz enthält die Traumaambulanz-Verordnung."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/Schnelle-Hilfen/schnelle-hilfen.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:02.206514+00:00","lastSeen":"2026-03-15T16:26:02.206514+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/Schnelle-Hilfen/schnelle-hilfen.html","crawledAt":"2026-03-15T16:26:02.206514Z","crawlId":"aid-seeded-1773591962","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"87ca73ab30683cc9d10e70930c72ad903dddd407fb32a03a86611bba333dec6c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:02.206514+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1dd8200f-65c4-4525-8db4-c6594771392d', 'aid', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Anerkennung-und-Erinnerung/anerkennung-und-erinnerung.html', 'active', NULL, '2026-03-15T16:26:05.422760+00:00', '{"id":"1dd8200f-65c4-4525-8db4-c6594771392d","title":"Anerkennung und Erinnerung","summary":{"de":"Informationen zu den Aktivitäten der Stiftung, Beiträge von Betroffenen und die Gedenktafeln-Initiative"},"content":{"de":"Veranstaltung am 13. Mai 2019 zur öffentlichen Anerkennung des Leids und Unrechts, das Kinder und Jugendliche in der Vergangenheit in stationären Einrichtungen der Behindertenhilfe bzw. Psychiatrie erfahren haben. Am 13. Mai 2019 fand im Museum für Kommunikation in Berlin die Veranstaltung der Stiftung Anerkennung und Hilfe mit dem Titel \"Zeit, über das Leid zu sprechen\" statt. Auf der Veranstaltung wurde gemeinsam über die Geschehnisse in der Vergangenheit in den Einrichtungen der Behindertenhilfe und der Psychiatrie gesprochen sowie über die Unterstützung, die die Stiftung Anerkennung und Hilfe leisten kann. Betroffene berichteten von ihren Erfahrungen und erste Zwischenergebnisse der wissenschaftlichen Aufarbeitung wurden vorgestellt. Die gesamte Veranstaltung wurde aufgezeichnet und steht in drei Teilen zum Abruf zur Verfügung. Hier finden Sie zudem die Aufzeichnung mit Übersetzung in Leichte Sprache, Gebärdensprachendolmetschung und Untertitel: In Leichter Sprache, mit Untertiteln und Gebärdensprach­dolmetschung. Begrüßung durch Kerstin Griese, MdB, Parlamentarische Staatssekretärin beim Bundesminister für Arbeit und Soziales"},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Anerkennung-und-Erinnerung/anerkennung-und-erinnerung.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:05.422760+00:00","lastSeen":"2026-03-15T16:26:05.422760+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Anerkennung-und-Erinnerung/anerkennung-und-erinnerung.html","crawledAt":"2026-03-15T16:26:05.423717Z","crawlId":"aid-seeded-1773591965","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"497fb1d12f2969d569c68110bb99c0cd2edafc5b34c625d1e516443118c8d026"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:05.423717+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2edac7b3-c62a-4367-a85b-2c4888f471b9', 'aid', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Aufarbeitung/aufarbeitung.html', 'active', NULL, '2026-03-15T16:26:06.266254+00:00', '{"id":"2edac7b3-c62a-4367-a85b-2c4888f471b9","title":"Aufarbeitung","summary":{"de":"Informationen zur wissenschaftlichen Aufarbeitung und deren Ergebnissen"},"content":{"de":"Die Arbeit der Stiftung wurde in den Jahren 2018 bis 2021 von einem Forschungsprojekt begleitet. Die Forschungsgruppe bestand aus vier Teams und war fachübergreifend organisiert. Die beteiligten Wissenschaftlerinnen und Wissenschaftler kamen aus dem Bereich der Medizingeschichte, der Medizinethik, der Geschichte, der Ethik und Pädagogik. Sie verfügten über sehr gute Erfahrungen im Bereich der historischen Aufarbeitung von Institutionen. Die Forschungsgruppe untersuchte die Unterbringungssituation von Kindern und Jugendlichen in Einrichtungen der Behindertenhilfe und Psychiatrie in der BRD (1949 - 1975) und der DDR (1949 - 1990). Ziel war es, die Leid- und Unrechtserfahrungen intensiv zu beleuchten und zu erfassen sowie Art und Umfang der Geschehnisse nachvollziehbar zu machen. Damit wurde ein wesentlicher Beitrag zur Bewältigung und Aufarbeitung des Erlebten auch in der Gesellschaft geleistet; das erlebte Leid und Unrecht wurde öffentlich sichtbar gemacht. Die Missstände der Vergangenheit sollten nicht nur aufgedeckt, sondern es sollten auch Lehren für die Zukunft gezogen werden. Zusammensetzung des Teams zur wissenschaftlichen Aufarbeitung Prof. Dr. Maike Rotzoll Dr. Christof Beyer Universität Heidelberg Prof. Dr. Karsten Laudien Prof. Dr. Anke Dreier-Horning DIH - Deutsches Institut für Heimerziehungsforschung gGmbH - Evangelische Hochschule Berlin"},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Aufarbeitung/aufarbeitung.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:06.266254+00:00","lastSeen":"2026-03-15T16:26:06.266254+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Aufarbeitung/aufarbeitung.html","crawledAt":"2026-03-15T16:26:06.267345Z","crawlId":"aid-seeded-1773591966","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b890e0be7f4f6c67da1066a8d81563518727aea7a52bc8afbe17c41b825d6341"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:06.267345+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('cce2f820-d10a-4107-b918-baa6777ced2a', 'aid', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Infos-ueber-die-Stiftung/infos-ueber-die-stiftung.html', 'active', NULL, '2026-03-15T16:26:06.993907+00:00', '{"id":"cce2f820-d10a-4107-b918-baa6777ced2a","title":"Infos über die Stiftung","summary":{"de":"Informationen über die Stiftung in Deutscher Gebärdensprache (DGS)"},"content":{"de":"Die Stiftung Anerkennung und Hilfe hat in den Jahren 2017 bis 2022 Menschen unterstützt, die in der Zeit vom 23. Mai 1949 bis zum 31. Dezember 1975 in der Bundesrepublik Deutschland bzw. vom 7. Oktober 1949 bis zum 2. Oktober 1990 in der ehemaligen DDR als Kinder und Jugendliche in stationären Einrichtungen der Behindertenhilfe oder stationären psychiatrischen Einrichtungen untergebracht waren, dort Leid und Unrecht erfahren haben und zum Zeitpunkt der Anmeldung noch an den Folgen gelitten haben. Sie wurde zum 1. Januar 2017 errichtet. Alle Anmeldungen, die innerhalb der mehrfach verlängerten Anmeldefrist bis zum 30. Juni 2021 eingegangen waren, sind bis zum 31. Dezember 2022 geprüft und abschließend bearbeitet worden. Ziel der Stiftung war die Anerkennung des während der Unterbringung erlittenen Leids und erlebten Unrechts sowie die Abmilderung noch bestehender Folgewirkungen zur Verbesserung der Lebenssituation. Die Stiftung wurde von Bund, Ländern und Kirchen errichtet (Errichter der Stiftung; siehe unten). Sie hatte einen Lenkungsausschuss, einen überregionalen Fachbeirat, eine Geschäftsstelle und regionale Anlauf- und Beratungsstellen. Der Lenkungsausschuss bestand aus 12 Mitgliedern und setzte sich zusammen aus Vertreterinnen und Vertretern der Errichter der Stiftung (Bund, Länder und Kirchen) sowie aus Vertreterinnen und Vertretern von Betroffenen, deren Interessensvertreterinnen und Interessensvertretern und Sachverständigen (entsendet vom überregionalen Fachbeirat). Er nahm die Aufgabe der Steuerung und Kontrolle der Stiftung für die Errichter wahr und entschied sowohl in Grundsatzangelegenheiten als auch in besonderen Einzelfällen. Der überregionale Fachbeirat aus neun ehrenamtlich tätigen Mitgliedern (Betroffene, Interessensvertreterinnen und Vertretern und Sachverständige) unterstützte die Stiftung. Eine zentrale Aufgabe des überregionalen Fachbeirats war es, den Lenkungsausschuss fachlich zu beraten und die Anlauf- und Beratungsstellen mit seinem Expertenwissen zu unterstützen."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Infos-ueber-die-Stiftung/infos-ueber-die-stiftung.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:06.993907+00:00","lastSeen":"2026-03-15T16:26:06.993907+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/Infos-ueber-die-Stiftung/infos-ueber-die-stiftung.html","crawledAt":"2026-03-15T16:26:06.993907Z","crawlId":"aid-seeded-1773591966","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b54581f38d7a55e84d6411610987717233eb9a9fbd4ed58befad4cfa8af8c82c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:06.993907+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
