":"f419ac1a7e3be345e9cb4a1d96ecabc9802a84f73bf7f8fe640c95bfdae898af"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:07.638155+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7859c92b-4dbb-438b-8eb7-836217895363', 'aid', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/stiftung-anerkennung-und-hilfe.html', 'active', NULL, '2026-03-15T16:26:08.390965+00:00', '{"id":"7859c92b-4dbb-438b-8eb7-836217895363","title":"Stiftung Anerkennung und Hilfe","summary":{"de":"Die Stiftung Anerkennung und Hilfe war ein zeitlich befristetes Hilfesystem für Menschen, die als Kinder und Jugendliche in der Zeit vom 23. Mai 1949 bis zum 31. Dezember 1975 in der Bundesrepublik Deutschland bzw. vom 7. Oktober 1949 bis zum 2. Oktober 1990 in der DDR in stationären Einrichtungen der Behindertenhilfe oder der Psychiatrie Leid und Unrecht erfahren haben."},"content":{"de":"Die Stiftung Anerkennung und Hilfe war ein zeitlich befristetes Hilfesystem für Menschen, die als Kinder und Jugendliche in der Zeit vom 23. Mai 1949 bis zum 31. Dezember 1975 in der Bundesrepublik Deutschland bzw. vom 7. Oktober 1949 bis zum 2. Oktober 1990 in der DDR in stationären Einrichtungen der Behindertenhilfe oder der Psychiatrie Leid und Unrecht erfahren haben."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/stiftung-anerkennung-und-hilfe.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:08.390965+00:00","lastSeen":"2026-03-15T16:26:08.390965+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Stiftung-Anerkennung-und-Hilfe/stiftung-anerkennung-und-hilfe.html","crawledAt":"2026-03-15T16:26:08.390965Z","crawlId":"aid-seeded-1773591968","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"ee0f73b6d89fcc72386a307cc03d8fa11ecf5824e8177b6cf5c06529ff062b8c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:08.390965+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5fd47a9a-ab17-4a4b-93ee-797b2fda11af', 'aid', 'https://www.bmas.de/DE/Soziales/Sozialhilfe/Allgemeines-zur-Sozialhilfe/allgemeines-zur-sozialhilfe.html', 'active', NULL, '2026-03-15T16:26:09.268800+00:00', '{"id":"5fd47a9a-ab17-4a4b-93ee-797b2fda11af","title":"Allgemeines zur Sozialhilfe","summary":{"de":"Im Einzelfall entscheidend: Die Träger der Sozialhilfe"},"content":{"de":"Menschen, die in eine Notlage geraten, können sich auf die Hilfe der Gemeinschaft verlassen. Das ist eines der grundlegenden Versprechen unseres Sozialstaates. Diese Unterstützung zu leisten, ist Aufgabe der Sozialhilfe. Der Begriff \"Sozialhilfe\" steht für eine Vielzahl von unterstützenden Leistungen, die den verschiedenen persönlichen Lebenslagen entsprechen. Nämlich: Hilfe zum Lebensunterhalt (Drittes Kapitel - §§ 27 bis 40 SGB XII ) sowie Grundsicherung im Alter und bei Erwerbsminderung (Viertes Kapitel - §§ 41 bis 46b SGB XII ) Hilfen zur Gesundheit (Fünftes Kapitel - §§ 47 bis 52 SGB XII ) Hilfe zur Pflege (Siebtes Kapitel - §§ 61 bis 66a SGB XII )"},"url":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Allgemeines-zur-Sozialhilfe/allgemeines-zur-sozialhilfe.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:09.268800+00:00","lastSeen":"2026-03-15T16:26:09.268800+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Allgemeines-zur-Sozialhilfe/allgemeines-zur-sozialhilfe.html","crawledAt":"2026-03-15T16:26:09.268800Z","crawlId":"aid-seeded-1773591969","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"8f2c8739caf9c86c47958cf1d71ecfb3f46631ec2308a62e29203abe05865f2a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:09.268800+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a48991c9-d1b6-4aa8-ab75-26fe0a2bb89e', 'aid', 'https://www.bmas.de/DE/Soziales/Sozialhilfe/Daten-zur-Grundsicherung-im-Alter-und-bei-Erwerbsminderung/daten-zur-grundsicherung-im-alter-und-bei-erwerbsminderung.html', 'active', NULL, '2026-03-15T16:26:09.958033+00:00', '{"id":"a48991c9-d1b6-4aa8-ab75-26fe0a2bb89e","title":"Daten zur Grundsicherung im Alter und bei Erwerbsminderung","summary":{"de":"Nettoausgaben für Geldleistungen der Grundsicherung (SGB XII)"},"content":{"de":"Was sind dies für Zahlen und wie werden diese ermittelt? Entsprechen die Jahresauswertungen den im Bundeshaushaltsplan jährlich ausgewiesenen Finanzansatz des Bundes zur Erstattung der Nettoausgaben für Geldleistungen der Grundsicherung? Hier finden Sie die Nettoausgaben für Geldleistungen der Grundsicherung im Alter und bei Erwerbsminderung nach dem Vierten Kapitel des Zwölften Buches Sozialgesetzbuch wie sie in den Bundesländern seit 2017 erbracht wurden. 2024: Nettoausgaben für Geldleistungen der Grundsicherung im Alter und bei Erwerbsminderung 2023: Nettoausgaben für Geldleistungen der Grundsicherung im Alter und bei Erwerbsminderung 2022: Nettoausgaben für Geldleistungen der Grundsicherung im Alter und bei Erwerbsminderung"},"url":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Daten-zur-Grundsicherung-im-Alter-und-bei-Erwerbsminderung/daten-zur-grundsicherung-im-alter-und-bei-erwerbsminderung.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:09.958033+00:00","lastSeen":"2026-03-15T16:26:09.958033+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Daten-zur-Grundsicherung-im-Alter-und-bei-Erwerbsminderung/daten-zur-grundsicherung-im-alter-und-bei-erwerbsminderung.html","crawledAt":"2026-03-15T16:26:09.958033Z","crawlId":"aid-seeded-1773591969","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4a77626ec65805d2aad439e126489e63f45a977bc72fd057e4b6f78076528810"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:09.958033+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('758dec7e-bd20-4bff-80fd-1b0afc323f86', 'aid', 'https://www.bmas.de/DE/Soziales/Sozialhilfe/Fragen-und-Antworten-Sozialhilfe/fragen-und-antworten-sozialhilfe.html', 'active', NULL, '2026-03-15T16:26:10.805295+00:00', '{"id":"758dec7e-bd20-4bff-80fd-1b0afc323f86","title":"Oft gestellte Fragen und Antworten zur Sozialhilfe","summary":{"de":"Die Sozialhilfe ist eine nachrangige Hilfe. Bevor sie gewährt wird, müssen zunächst alle anderen Möglichkeiten der Hilfe ausgeschöpft sein. Die Sozialhilfe setzt ein, sobald das Sozialamt von der Notlage eines Menschen erfährt, dem Sozialhilfe zusteht."},"content":{"de":"Zuständig für die Sozialhilfe ist das Sozialamt der Stadt oder des Kreises, wo sich eine Hilfe suchende Person tatsächlich aufhält. Das muss nicht unbedingt das Sozialamt des Ortes sein, in dem die Person polizeilich gemeldet ist. In besonderen Fällen können auch andere Stellen zuständig sein. Wenden Sie sich zuerst an Ihr örtliches Sozialamt. Dieses wird dann in der Regel alles Weitere veranlassen. Auf Leistungen der Sozialhilfe muss nicht notwendigerweise ein Antrag gestellt werden. Trotzdem empfiehlt es sich, dies beim zuständigen Sozialamt schriftlich zu tun. Das gilt sowohl für den ersten Antrag als auch für spätere Anträge auf weitere Leistungen. Hinweis: Für die Grundsicherung im Alter und bei Erwerbsminderung ist immer ein Antrag erforderlich. Zuvor gilt es, sich eingehend darüber zu informieren, welche Hilfe in Anspruch genommen werden kann. Die Sozialämter sind zu entsprechender Auskunft und Beratung verpflichtet. Das bedeutet, dass die Sozialämter Möglichkeiten aufzeigen, nach denen man gar nicht gefragt hat, weil man sie nicht kannte oder andere Stellen nennen, wenn sie nicht zuständig sind."},"url":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Fragen-und-Antworten-Sozialhilfe/fragen-und-antworten-sozialhilfe.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:10.805295+00:00","lastSeen":"2026-03-15T16:26:10.805295+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Fragen-und-Antworten-Sozialhilfe/fragen-und-antworten-sozialhilfe.html","crawledAt":"2026-03-15T16:26:10.805295Z","crawlId":"aid-seeded-1773591970","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"5dfd6888e458623c9735e75328ec74aefde3f323398c960fb88ce7195debf87b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:10.805295+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8c29af3a-3eb1-4d09-a359-a0aefb866cc2', 'aid', 'https://www.bmas.de/DE/Soziales/Sozialhilfe/Methodik-der-Regelbedarfsermittlung-FAQ/regelbedarfsermittlung-sozialhilfe-faq.html', 'active', NULL, '2026-03-15T16:26:12.335150+00:00', '{"id":"8c29af3a-3eb1-4d09-a359-a0aefb866cc2","title":"Methodik der Regelbedarfsermittlung","summary":{"de":"1. Regelbedarf, Regelbedarfsstufen und Regelsatz – was ist das?"},"content":{"de":"5. Gut zu wissen: Antworten auf häufig gestellte Fragen (FAQ) Regelbedarfe – und in diesem Zusammenhang auch Regelsätze – sind Bestandteil von Leistungen der sozialen Mindestsicherung. die Grundsicherung im Alter und bei Erwerbsminderung. Diese Leistungen decken das im Grundgesetz verankerte lebensnotwendige Existenzminimum. Insofern handelt es sich bei den Regelbedarfen und den Regelsätzen auch nicht um willkürliche Beträge einer Regierung. Vielmehr sind die Leistungen der sozialen Mindestsicherungssysteme so bemessen, dass die grundgesetzlichen Vorgaben berücksichtigt werden. Das Verfahren zur Ermittlung und zur Fortschreibung der Regelbedarfe ist gesetzlich geregelt und entspricht den Vorgaben des Bundesverfassungsgerichts. Die Höhe der Regelbedarfe wird in einem aufwendigen statistischen Verfahren ermittelt. Dieses Verfahren wird im Folgenden erläutert. Außerdem werden häufig gestellte Fragen zur Ermittlung der Regelbedarfe beantwortet. Kurzinformation: Der Regelbedarf ist Bestandteil der Leistungen zur Sicherung des existenznotwendigen Lebensunterhaltes. Er wird als monatliche Pauschale gezahlt."},"url":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Methodik-der-Regelbedarfsermittlung-FAQ/regelbedarfsermittlung-sozialhilfe-faq.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:12.335150+00:00","lastSeen":"2026-03-15T16:26:12.335150+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialhilfe/Methodik-der-Regelbedarfsermittlung-FAQ/regelbedarfsermittlung-sozialhilfe-faq.html","crawledAt":"2026-03-15T16:26:12.335150Z","crawlId":"aid-seeded-1773591972","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7edba253fcca14a5d0eeff6e555482b6ea492df96e01763327689b541c0f1728"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:12.335150+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1ac5fc8e-86eb-4317-a824-f4bf7b631d7d', 'aid', 'https://www.bmas.de/DE/Soziales/Sozialhilfe/sozialhilfe.html', 'active', NULL, '2026-03-15T16:26:13.093846+00:00', '{"id":"1ac5fc8e-86eb-4317-a824-f4bf7b631d7d","title":"Sozialhilfe","summary":{"de":"Sozialhilfe ermöglicht als letztes \"Auffangnetz\" eine menschenwürdige Lebensführung und gesellschaftliche Teilhabe. Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Sozialhilfe ermöglicht als letztes \"Auffangnetz\" eine menschenwürdige Lebensführung und gesellschaftliche Teilhabe. Das Bundeskabinett hat heute der Festsetzung der Regelbedarfe im Bürgergeld und der Sozialhilfe für das Jahr 2026 zugestimmt. Die geltende Fortschreibungsregelung wird voraussichtlich letztmalig angewendet. Das Bundesministerium für Arbeit und Soziales gibt offiziellen Startschuss für 55 Projekte zur Verbesserung der Lebenssituation und der gesellschaftlichen Teilhabe von Familien und ihren Kindern, die von sozialer Ausgrenzung und Armut bedroht sind. Das Bundeskabinett hat beschlossen, die für Juli vorgesehene Einmalzahlung von 100 Euro auf 200 Euro zu erhöhen. Zudem sollen hilfebedürftige geflüchtete Menschen aus der Ukraine ab 01.06.2022 Leistungen nach dem SGB II oder SGB XII erhalten. Das Bundesministerium für Arbeit und Soziales hat die Regelbedarfe auf Grundlage der Ergebnisse der EVS neu ermittelt und einen entsprechenden Gesetzesentwurf vorgelegt. Infoblatt – Fortschreibung der Regelbedarfe zum 1. Januar 2026"},"url":"https://www.bmas.de/DE/Soziales/Sozialhilfe/sozialhilfe.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:13.093846+00:00","lastSeen":"2026-03-15T16:26:13.093846+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialhilfe/sozialhilfe.html","crawledAt":"2026-03-15T16:26:13.093846Z","crawlId":"aid-seeded-1773591973","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6ca9c2f1731d65b5c76a911460976d86b6211276e751fa8f49479fd31ee47eb9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:13.093846+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('201c6365-2366-4e5b-bc22-c960bec13b39', 'aid', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Formen-der-Hilfe-fuer-Menschen-mit-Behinderungen/formen-der-hilfe-fuer-menschen-mit-behinderungen.html', 'active', NULL, '2026-03-15T16:26:13.710382+00:00', '{"id":"201c6365-2366-4e5b-bc22-c960bec13b39","title":"Formen der Hilfe für Menschen mit Behinderungen","summary":{"de":"Das Leben behinderter Menschen braucht viele Formen der Hilfe."},"content":{"de":"Das Leben behinderter Menschen braucht viele Formen der Hilfe und Unterstützung. Materielle Leistungsverbesserungen helfen oft nur bedingt. Deshalb wird mit dem SGB IX angestrebt, neue Chancen für Menschen mit Behinderungen zu erschließen. Zentrales Anliegen dabei: Die Teilhabe soll in allen Bereichen des Lebens gestärkt werden. Die folgenden Seiten zeigen, welche Möglichkeiten das neue Recht dazu schafft. Chancen bei der medizinischen Rehabilitation ergeben sich zum Beispiel mit ambulanten Leistungen. Chancen im Arbeitsleben gibt es durch Rechte für Menschen mit Behinderungen in den Betrieben und Werkstätten, durch die Arbeit der Integrationsfachdienste, durch behindertengerechtere Arbeitsabläufe und durch besondere berufliche Angebote für Frauen. Und auch die Chancen zur Teilhabe am Leben in der Gemeinschaft werden durch integrative Angebote gestärkt. Menschen mit Behinderungen erhalten Chancen für ein selbstbestimmtes Leben. Sie haben aber auch einen Anspruch darauf, dass sie am gesellschaftlichen Leben wirklich teilnehmen. Deshalb ist Handeln gefragt – auf allen Seiten. Mehr als früher können Menschen mit Behinderungen das Angebot einer ambulanten Rehabilitation nutzen. Dafür macht das Recht den Weg frei. Wichtig dabei ist: Das Angebot richtet sich an alle behinderten und von Behinderung bedrohten Menschen. Ambulante Rehabilitation ist kein reduziertes Angebot nur für \"leichtere\" Fälle. Sie kommt bei von einer Behinderung bedrohten Menschen genauso in Frage wie bei Menschen mit schweren geistigen oder körperlichen Behinderungen. Ambulante Rehabilitation setzt neue Kräfte frei. Denn sie nutzt den besonderen Rückhalt durch das soziale Umfeld. Kindern ist die Nähe der Eltern und Freunde bei ihrer Betreuung besonders wichtig. Erwachsene profitieren von der engagierten Anteilnahme ihrer Lebenspartner, Kinder und Angehörigen. Man kann es auch so sagen: Weil die Betreuung in die Nähe des Wohnortes rückt, rückt sie für viele näher ans individuelle Leben. Viele Wege führen zu den ambulanten Angeboten. Der Zugang ist zum Beispiel aus der hausärztlichen Behandlung und aus der Krankenhausbehandlung möglich. Aber auch, wer bisher stationär betreut wurde, kann zusammen mit seinem Arzt oder seinen Angehörigen die Chancen nutzen. Natürlich wird es auch weiterhin Therapien in Kurorten und Rehabilitationszentren geben. Denn oft ist der Abstand zum gewohnten Alltag besonders wichtig. Welche Rehabilitationsform jeweils gewählt wird, können die behinderten Menschen im beratenden Gespräch mit Fachleuten selbst klären."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Formen-der-Hilfe-fuer-Menschen-mit-Behinderungen/formen-der-hilfe-fuer-menschen-mit-behinderungen.html","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:13.710382+00:00","lastSeen":"2026-03-15T16:26:13.710382+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Formen-der-Hilfe-fuer-Menschen-mit-Behinderungen/formen-der-hilfe-fuer-menschen-mit-behinderungen.html","crawledAt":"2026-03-15T16:26:13.711383Z","crawlId":"aid-seeded-1773591973","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b09b7d7628958d5652a6bf50c32b3b815f1966dbb7b0853db516582f453a66d1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:13.711383+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e55e6c90-9b4d-4003-a262-408cc110c384', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/bauprogramm-des-bundes-in-der-kinder-und-jugendhilfe', 'active', NULL, '2026-03-15T16:26:14.456450+00:00', '{"id":"e55e6c90-9b4d-4003-a262-408cc110c384","title":"Bauprogramm des Bundes in der Kinder- und Jugendhilfe","summary":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend fördert im Rahmen des Bauprogramms des Bundes in der Kinder- und Jugendhilfe Baumaßnahmen von anerkannten Trägern der..."},"content":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend fördert im Rahmen des Bauprogramms des Bundes in der Kinder- und Jugendhilfe Baumaßnahmen von anerkannten Trägern der freien Kinder- und Jugendhilfe im Sinne von Paragraph 75 des Achten Buches Sozialgesetzbuch - Kinder- und Jugendhilfe (SGB VIII). Zuwendungen für Baumaßnahmen können für den Bau, den Erwerb, die Einrichtungen und zur Bauerhaltung von Jugendbildungs- und Jugendbegegnungsstätten sowie Jugendherbergen gegeben werden. Hinweise zu den Fördervoraussetzungen und dem Antragsverfahren können in den Anlagen abgerufen werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/bauprogramm-des-bundes-in-der-kinder-und-jugendhilfe","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:14.456450+00:00","lastSeen":"2026-03-15T16:26:14.456450+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/bauprogramm-des-bundes-in-der-kinder-und-jugendhilfe","crawledAt":"2026-03-15T16:26:14.456450Z","crawlId":"aid-seeded-1773591974","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"5d8ad89c8d4ab0714d90f839bde5f6ea728b31ff2f7806df84cc06b4443e3867"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:14.456450+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('acd5993a-5b53-46d7-ad91-d713e49164f4', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/das-pflegetelefon-schnelle-hilfe-fuer-angehoerige-187090', 'active', NULL, '2026-03-15T16:26:14.696823+00:00', '{"id":"acd5993a-5b53-46d7-ad91-d713e49164f4","title":"Das Pflegetelefon","summary":{"de":"Hier finden Sie Studien, Broschüren, Flyer und weitere Publikationen zu den Themenbereichen des Bundesministeriums für Familie, Senioren, Frauen und Jugend."},"content":{"de":"Die Publikation »Das Pflegetelefon - Schnelle Hilfe für Angehörige« wurde in den Warenkorb gelegt Das Pflegetelefon des BMBFSFJ steht Ihnen bundesweit anonym als Ansprechpartner für Fragen zu Entlastungs- und Freistellungsmöglichkeiten zur besseren Vereinbarkeit von Pflege und Beruf zur Verfügung. Der vorliegende Flyer liefert einen Überblick über die Zielgruppen und Themen, zu denen die Mitarbeiterinnen und Mitarbeiter des Pflegetelefons beraten. Mehr Informationen zum Pflegetelefon erhalten Sie unter wege-zur-pflege.de."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/das-pflegetelefon-schnelle-hilfe-fuer-angehoerige-187090","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:14.696823+00:00","lastSeen":"2026-03-15T16:26:14.696823+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/das-pflegetelefon-schnelle-hilfe-fuer-angehoerige-187090","crawledAt":"2026-03-15T16:26:14.697594Z","crawlId":"aid-seeded-1773591974","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"cff91ea66b91f045ed167487eac29943fb618e954d528ce209955fbfe246cf9d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:14.697594+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b158d8eb-f495-470d-a53e-14d8bd9fbcdf', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/hilfe-suchen-hilfe-finden-280182', 'active', NULL, '2026-03-15T16:25:26.964395+00:00', '{"id":"b158d8eb-f495-470d-a53e-14d8bd9fbcdf","title":"Hilfe suchen","summary":{"de":"Hier finden Sie Studien, Broschüren, Flyer und weitere Publikationen zu den Themenbereichen des Bundesministeriums für Familie, Senioren, Frauen und Jugend."},"content":{"de":"Die Publikation »Hilfe suchen - Hilfe finden« wurde in den Warenkorb gelegt „Hilfe suchen, Hilfe finden“ ist ein Faltblatt über sexualisierte Gewalt und sexuellen Missbrauch. Es zeigt, wo Betroffene und Ratsuchende Unterstützung bekommen können und erklärt leicht verständlich, was unter sexualisierter Gewalt zu verstehen ist. Deutlich wird dabei: Übergriffe können überall passieren – in der Familie, im Freundeskreis, in der Schule oder im Internet. Ebenso wichtig ist die Botschaft, dass niemand mit seinen Erlebnissen oder Sorgen allein bleiben muss. Im Mittelpunkt stehen konkrete Hilfeangebote: das Hilfe-Telefon Sexueller Missbrauch und die Online-Beratung Schreib-Ollie. Beide Angebote sind anonym, kostenfrei und vertraulich. Sie richten sich an Betroffene und an Menschen, die sich Sorgen machen, einen Verdacht haben oder einfach Fragen stellen möchten. Qualifizierte Fachkräfte beraten telefonisch oder schriftlich und unterstützen dabei, die eigene Situation einzuordnen und mögliche nächste Schritte zu planen. Das kompakte Format richtet sich an Kinder, Jugendliche und Erwachsene gleichermaßen. Es will dazu ermutigen, Hilfe zu suchen – auch dann, wenn man unsicher ist. Die zentrale Botschaft: Hilfe anzunehmen ist mutig und kann der erste wichtige Schritt sein, um Entlastung, Schutz und Unterstützung zu erfahren."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/hilfe-suchen-hilfe-finden-280182","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:26.964395+00:00","lastSeen":"2026-03-15T16:25:26.964395+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/hilfe-suchen-hilfe-finden-280182","crawledAt":"2026-03-15T16:25:26.964395Z","crawlId":"aid-seeded-1773591926","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"d24f1c37bc7462333a4ecf3694fc405c18b94386676890bcdbfa97cba1b73bb8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:26.964395+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
