INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3a3a9a90-65f6-4be0-94c4-f19ab9a792cf', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/hilfetelefon-schwangere-in-not-visitenkarte-96200', 'active', NULL, '2026-03-15T16:25:28.698168+00:00', '{"id":"3a3a9a90-65f6-4be0-94c4-f19ab9a792cf","title":"Hilfetelefon \"Schwangere in Not\"","summary":{"de":"Hier finden Sie Studien, Broschüren, Flyer und weitere Publikationen zu den Themenbereichen des Bundesministeriums für Familie, Senioren, Frauen und Jugend."},"content":{"de":"Visitenkarte mit dem Hinweis auf das Hilfetelefon „Schwangere in Not“ und das Internetportal www.schwanger-und-viele-fragen.de. Die Visitenkarte passt in jedes Portmonee oder Brieftasche und ist somit jederzeit griffbereit. Über das Internetportal finden sich Informationen rund um die Schwangerschaft, Geburt und Familienplanung und Anschriften von Schwangerschaftsberatungsstellen vor Ort sowie Informationen zur vertraulichen Geburt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/hilfetelefon-schwangere-in-not-visitenkarte-96200","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:28.698168+00:00","lastSeen":"2026-03-15T16:25:28.698168+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/service/publikationen/hilfetelefon-schwangere-in-not-visitenkarte-96200","crawledAt":"2026-03-15T16:25:28.698168Z","crawlId":"aid-seeded-1773591928","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","provi