INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0249e48f-7fae-46b2-9b82-7168492f2a48', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen', 'active', NULL, '2026-03-15T16:15:46.859164+00:00', '{"id":"0249e48f-7fae-46b2-9b82-7168492f2a48","title":"Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bildung ist der Schlüssel zu gesellschaftlicher Teilhabe, sozialem Aufstieg, Fortschritt und persönlicher Freiheit. Indem wir uns für beste Bildung einsetzen, unterstützen wir Menschen dabei, Chancen zu erkennen und ihre Ziele und Träume zu verwirklichen. Familien darin zu unterstützen, ihr Leben nach den eigenen Vorstellungen gestalten zu können - das ist das Ziel einer guten Familienpolitik. Dafür brauchen Familien vor allem Zeit für Kinder und Beruf, finanzielle Stabilität und eine gute Kinderbetreuung. Auch im hohen Alter selbstbestimmt leben und an der Gesellschaft teilhaben - das wünschen sich die meisten Menschen. Sie dabei zu unterstützen, ist zentrales Ziel der Seniorenpolitik. Die Gleichstellung von Frauen und Männern ist eine der zentralen Herausforderungen, um das Leben in unserem Land zukunftsfähig und gerecht zu gestalten. Dafür müssen Frauen und Männer auf dem gesamten Lebensweg die gleichen Chancen erhalten – persönlich, beruflich und familiär. Alle Kinder und Jugendlichen haben ein Recht auf ein beschütztes Auf­wachsen und gleiche Chancen - unabhängig von Herkunft, Geschlecht, Religion oder dem sozialen Status. Chancengleichheit und der Schutz von Kindern und Jugendlichen ist daher ein zentrales Anliegen des Bundesjugendministeriums. Das Bundesfamilienministerium versteht sich als Partner der Zivilgesellschaft - auf Augenhöhe mit Millionen von freiwillig engagierten Bürgerinnen und Bürgern, Vereinen, Verbänden, Unternehmen und Stiftungen. Deshalb unterstützt es die starke Engagementlandschaft in Deutschland."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:46.859164+00:00","lastSeen":"2026-03-15T16:15:46.859164+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","crawledAt":"2026-03-15T16:15:46.859164Z","crawlId":"aid-seeded-1773591346","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"453631bfa91749a15882beef59dc54f247df9a71185f07f9ef8593b889e202d2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:46.859164+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('68f66902-6a85-4835-9655-88d5f9c38c8e', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter', 'active', NULL, '2026-03-15T16:15:47.857581+00:00', '{"id":"68f66902-6a85-4835-9655-88d5f9c38c8e","title":"Aktiv im Alter","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bildung und Digitalisierung im Alter Bildung und digitale Kompetenzen sind für ältere Menschen eine wichtige Voraussetzung, um aktiv und selbstbestimmt am gesellschaftlichen Leben teilzuhaben. Das Bundesseniorenministerium unterstützt sie dabei. Bildung und digitale Kompetenzen sind für ältere Menschen eine wichtige Voraussetzung, um aktiv und selbstbestimmt am gesellschaftlichen Leben teilzuhaben. Das Bundesseniorenministerium unterstützt sie dabei. Allianz gegen Einsamkeit Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung wirksam zu begegnen - zum Beispiel mit Orten, an die sich einsame Menschen wenden können. Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung wirksam zu begegnen - zum Beispiel mit Orten, an die sich einsame Menschen wenden können. Altersberichte Seit 1993 erscheint in jeder Legislaturperiode ein Altersbericht zu einem seniorenpolitischen Thema. Die Altersberichte sind wichtige Entscheidungsgrundlage für die Seniorenpolitik des Bundes. Seit 1993 erscheint in jeder Legislaturperiode ein Altersbericht zu einem seniorenpolitischen Thema. Die Altersberichte sind wichtige Entscheidungsgrundlage für die Seniorenpolitik des Bundes."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:47.857581+00:00","lastSeen":"2026-03-15T16:15:47.857581+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter","crawledAt":"2026-03-15T16:15:47.857581Z","crawlId":"aid-seeded-1773591347","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"d4bdaa5c8d2fe9cab9ac8bda060951a16e7f5ac1d487adf35b747e9409feca9b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:47.857581+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('08dfc868-9323-4400-868c-d354ab8a9d71', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege', 'active', NULL, '2026-03-15T16:15:48.402678+00:00', '{"id":"08dfc868-9323-4400-868c-d354ab8a9d71","title":"Pflegeausbildung","summary":{"de":"Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der..."},"content":{"de":"Ausbildung zur Pflegefachperson Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Eckpunkte für eine neue bundeseinheitliche Pflegeassistenzausbildung Eine neue bundeseinheitliche Pflegeassistenzausbildung soll die Ausbildung attraktiver machen und einen effektiven Qualifikationsmix in der Pflege unterstützen. Eine neue bundeseinheitliche Pflegeassistenzausbildung soll die Ausbildung attraktiver machen und einen effektiven Qualifikationsmix in der Pflege unterstützen. Ausbildungsoffensive Pflege Um die Einführung der neuen Pflegeausbildungen nach dem Pflegeberufegesetz zu unterstützen, hat das Bundesfamilienministerium gemeinsam mit dem Bundesgesundheitsministerium und dem Bundesarbeitsministerium eine Ausbildungsoffensive gestartet. Um die Einführung der neuen Pflegeausbildungen nach dem Pflegeberufegesetz zu unterstützen, hat das Bundesfamilienministerium gemeinsam mit dem Bundesgesundheitsministerium und dem Bundesarbeitsministerium eine Ausbildungsoffensive gestartet."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:48.402678+00:00","lastSeen":"2026-03-15T16:15:48.402678+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege","crawledAt":"2026-03-15T16:15:48.402678Z","crawlId":"aid-seeded-1773591348","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"103e6bc1cf7b1636817ecdfe45cc291a61988527bca0417fdcfcd6022217605a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:48.402678+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e10437c2-b5d2-45fb-93fa-3841ac995a39', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen', 'active', NULL, '2026-03-15T16:15:48.848164+00:00', '{"id":"e10437c2-b5d2-45fb-93fa-3841ac995a39","title":"Ausbildung zur Pflegefachperson","summary":{"de":"Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller..."},"content":{"de":"Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Das Pflegeberufegesetz führt die bisherigen Berufsausbildungen der Altenpflege, der Gesundheits- und Krankenpflege und der Gesundheits- und Kinderkrankenpflege zusammen. Am 1. Januar 2020 ist die Pflegeausbildung zur Pflegefachperson gestartet. Sie ermöglicht es, in allen Versorgungsbereichen zu arbeiten. Damit werden die Ausbildungsbedingungen verbessert und die Attraktivität des Berufsfeldes Pflege wird gesteigert. Für die Ausbildung muss nun kein Schulgeld mehr bezahlt werden, die Auszubildenden erhalten eine angemessene Ausbildungsvergütung. Außerdem ist eine Ausbildung an einer Hochschule mit Bachelor-Niveau möglich. Damit wird die Pflegeausbildung attraktiver und neue Zielgruppen werden für die Pflege angesprochen. Mit dem Pflegeberufegesetz werden erstmals bestimmte berufliche Tätigkeiten festgelegt, die nur den Pflegefachpersonen vorbehalten sind. Der Pflegeberuf wird durch zusätzliche Einsatz- und Aufstiegsmöglichkeiten aufgewertet. Zum ersten Mal ist auch langfristig eine verbindliche Regelung vorgesehen, die Ausbildungskosten bei Umschulungsmaßnahmen vollständig zu finanzieren. Alle Auszubildenden starten mit dem Berufsziel \"Pflegefachperson\". Das ist im Ausbildungsvertrag mit dem Träger der praktischen Ausbildung festgelegt. Neben dem generalistischen Berufsabschluss nach drei Jahren in Vollzeitform beziehungsweise bis zu fünf Jahren in Teilzeitform können Auszubildende auch einen gesonderten Abschluss erlangen - als \"Altenpflegerin\" oder \"Altenpfleger\", als \"Gesundheits- und Kinderkrankenpfleger\" beziehungsweise \"Gesundheits- und Kinderkrankenpflegerin\". Die Möglichkeit, nach zwei Dritteln der Ausbildung einen gesonderten Abschluss zu wählen, haben die Auszubildenden, die zu Beginn ihrer Ausbildung einen Vertiefungseinsatz in der Altenpflege oder Kinderkrankenpflege gewählt haben. Mit dem Pflegeberufegesetz wird ein Pflegestudium zur unmittelbaren Berufsqualifizierung mit erweitertem Ausbildungsziel eingeführt. Die Berufsbezeichnung \"Pflegefachperson\" wird in Verbindung mit dem akademischen Grad (zum Beispiel \"B.Sc.\") geführt. Die mit dem Pflegestudiumstärkungsgesetz eingeführte Ausbildungsvergütung für Studierende erhöht die Attraktivität einer hochschulischen Pflegeausbildung zusätzlich."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:48.848164+00:00","lastSeen":"2026-03-15T16:15:48.848164+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen","crawledAt":"2026-03-15T16:15:48.848164Z","crawlId":"aid-seeded-1773591348","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"6744daea28ffbc60b6e9bc71635cbf493f31d49b42f174d372fa464eefacc6bb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:48.848164+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d0b4da51-17ab-4045-9d26-4edcccbd8523', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz', 'active', NULL, '2026-03-15T16:15:49.283241+00:00', '{"id":"d0b4da51-17ab-4045-9d26-4edcccbd8523","title":"Demenz","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Informationen rund um Demenz Wegweiser Demenz, Alzheimer Telefon, Lokale Allianzen: Mit einem Wissens- und Hilfenetzwerk unterstützt das Bundesseniorenministerium Menschen mit Demenz und ihre Angehörigen. Wegweiser Demenz, Alzheimer Telefon, Lokale Allianzen: Mit einem Wissens- und Hilfenetzwerk unterstützt das Bundesseniorenministerium Menschen mit Demenz und ihre Angehörigen. Nationale Demenzstrategie Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern. Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern. Lokale Allianzen für Menschen mit Demenz Lokale Allianzen für Menschen mit Demenz sind Hilfe- und Unterstützungsnetzwerke mit Angeboten für Menschen mit Demenz und ihre Angehörigen. Das Bundesseniorenministerium fördert die Allianzen mit einem Bundesprogramm. Lokale Allianzen für Menschen mit Demenz sind Hilfe- und Unterstützungsnetzwerke mit Angeboten für Menschen mit Demenz und ihre Angehörigen. Das Bundesseniorenministerium fördert die Allianzen mit einem Bundesprogramm."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:49.283241+00:00","lastSeen":"2026-03-15T16:15:49.283241+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz","crawledAt":"2026-03-15T16:15:49.283241Z","crawlId":"aid-seeded-1773591349","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"c17d5a767dafeb121b37873d888da11371652718920d035cc8f375915ccc0b3c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:49.283241+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3427e3fb-4218-4b85-89d5-59968bb38a16', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie', 'active', NULL, '2026-03-15T16:15:49.788211+00:00', '{"id":"3427e3fb-4218-4b85-89d5-59968bb38a16","title":"Nationale Demenzstrategie","summary":{"de":"Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern."},"content":{"de":"In Deutschland leben rund 1,8 Millionen Menschen mit einer Demenz. Bis zum Jahr 2050 wird die Zahl der Betroffenen voraussichtlich auf 2,8 Millionen steigen. Um dieser Herausforderung zu begegnen und um die Gesellschaft demenzfreundlich zu gestalten, hat die Bundesregierung die Nationale Demenzstrategie verabschiedet. Die Umsetzung hat am 23. September 2020 begonnen. Ziel der Strategie ist, die Lebenssituation von Menschen mit Demenz und ihren Angehörigen in Deutschland zu verbessern und ein offenes Klima für den Umgang mit Betroffenen zu schaffen. Dafür enthält die Nationale Demenzstrategie über 160 konkrete Maßnahmen, die in den kommenden Jahren umgesetzt werden sollen. Die Strategie definiert dafür vier Handlungsfelder: Strukturen zur gesellschaftlichen Teilhabe von Menschen mit Demenz an ihrem Lebensort aus- und aufbauen Menschen mit Demenz und ihre Angehörigen unterstützen Medizinische und pflegerische Versorgung von Menschen mit Demenz weiterentwickeln"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:49.788211+00:00","lastSeen":"2026-03-15T16:15:49.788211+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie","crawledAt":"2026-03-15T16:15:49.788211Z","crawlId":"aid-seeded-1773591349","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"b76a2fa1b9a96f25e47d3a461d297e911616a33595db7d99ffb0ac7e35af3b4e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:49.789212+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('db75737c-50d4-49a5-8726-751d1a4188dd', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege', 'active', NULL, '2026-03-15T16:15:17.599494+00:00', '{"id":"db75737c-50d4-49a5-8726-751d1a4188dd","title":"Hilfe und Pflege","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Hilfe und Pflege Menschen, die im Alter auf Hilfe und Pflege angewiesen sind, haben sehr unterschiedliche Bedürfnisse. Dementsprechend umfassend und differenziert ist das Angebot an Leistungen zur Hilfe, Betreuung und Pflege. Menschen, die im Alter auf Hilfe und Pflege angewiesen sind, haben sehr unterschiedliche Bedürfnisse. Dementsprechend umfassend und differenziert ist das Angebot an Leistungen zur Hilfe, Betreuung und Pflege. Gesetzliche Regelungen zur Pflege und Betreuung Für die Pflege und Betreuung älterer und pflegebedürftiger Menschen sowie von Menschen mit Behinderung in Pflegeeinrichtungen und anderen Wohnformen gelten unterschiedliche Bestimmungen. Für die Pflege und Betreuung älterer und pflegebedürftiger Menschen sowie von Menschen mit Behinderung in Pflegeeinrichtungen und anderen Wohnformen gelten unterschiedliche Bestimmungen. Familienpflegezeit-Rechner Der Familienpflegezeit-Rechner bietet eine erste individuelle Berechnungshilfe für Beschäftigte. (Externer Link) Der Familienpflegezeit-Rechner bietet eine erste individuelle Berechnungshilfe für Beschäftigte. (Externer Link)"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:17.599494+00:00","lastSeen":"2026-03-15T16:15:17.599494+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege","crawledAt":"2026-03-15T16:15:17.599494Z","crawlId":"aid-seeded-1773591317","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"b952edf4df7e669b1541d462571cd8133ce549194e6bca58aaf5903336b9e603"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:17.599494+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('03afc707-9830-404b-a0c9-70cafdee8fb3', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/charta-der-rechte-hilfe-und-pflegebeduerftiger-menschen-77426', 'active', NULL, '2026-03-15T16:15:50.338774+00:00', '{"id":"03afc707-9830-404b-a0c9-70cafdee8fb3","title":"Charta der Rechte hilfe- und pflegebedürftiger Menschen","summary":{"de":"Menschen können in unterschiedlichen Lebenslagen hilfe- oder pflegebedürtig sein. Die Pflegecharta informiert Pflegebedürftige und Angehörige über ihre Rechte."},"content":{"de":"Die \"Charta der Rechte hilfe- und pflegebedürftiger Menschen\" informiert über die Rechte von Pflegebedürftigen und Angehörigen. Menschen können in verschiedenen Lebenslagen hilfe- und pflegebedürftig sein. Die \"Charta der Rechte hilfe- und pflegebedürftiger Menschen\" beschreibt, welche Rechte diese Menschen und ihre Angehörigen in Deutschland haben und informiert, wie der Hilfe- und Pflegeprozess konkret gestaltet werden kann. Viele Einrichtungen und Dienste nutzen die Charta bereits als Instrument ihres Qualitätsmanagements oder zur Unterstützung ihrer täglichen Praxis. In Deutschland ist dazu in allen Bereichen der Pflege bereits viel Engagement und Wissen vorhanden. Zahlreiche gute Praxisbeispiele belegen das. Die Pflege-Charta soll dieses gemeinsame Bestreben nach Verbesserung der Qualität in der Pflege in die Öffentlichkeit tragen, um anderen Mut zu machen, den guten Beispielen zu folgen. Und nicht zuletzt auch, um den Menschen zu zeigen: Auch bei Hilfe- und Pflegebedarf ist Lebensqualität möglich! Um die Pflege-Charta praxisnah zu verankern, wurden mit Praktikern Schulungs- und Fortbildungsmaterialien erarbeitet. Die Arbeitsmaterialien in den Kategorien Wissen, Reflexion, Methoden und Verbreitung können online hier abgerufen werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/charta-der-rechte-hilfe-und-pflegebeduerftiger-menschen-77426","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:50.338774+00:00","lastSeen":"2026-03-15T16:15:50.338774+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/charta-der-rechte-hilfe-und-pflegebeduerftiger-menschen-77426","crawledAt":"2026-03-15T16:15:50.338774Z","crawlId":"aid-seeded-1773591350","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"83f60de8fdf032957592cabb688a849b3cd36940ca6b5bc70ad1a63fe31cc760"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:50.338774+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c461f114-02f0-4d00-a2c8-7e617d530f0d', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/gesetz-ueber-die-berufe-in-der-altenpflege-altenpflegegesetz--77744', 'active', NULL, '2026-03-15T16:15:50.845102+00:00', '{"id":"c461f114-02f0-4d00-a2c8-7e617d530f0d","title":"Gesetz über die Berufe in der Altenpflege (Altenpflegegesetz)","summary":{"de":"Mit dem Altenpflegegesetz hat der Bund die Ausbildung in der Altenpflege erstmals bundesweit geregelt. Damit soll ein einheitliches Ausbildungsniveau..."},"content":{"de":"Mit dem Gesetz über die Berufe in der Altenpflege, das am 1. August 2003 in Kraft getreten ist, ist die Ausbildung in der Altenpflege erstmals bundeseinheitlich geregelt worden. Der Bund hat dabei aufgrund seiner Zuständigkeit für die Zulassung zu den sogenannten nicht-ärztlichen Heilberufen im Sinne des Artikel 74 Absatz 1 Nummer 19 GG gehandelt. Die Ausbildung in der Altenpflegehilfe wird von den Bundesländern geregelt. Ziel des Altenpflegegesetzes ist es, bundesweit ein einheitliches Ausbildungsniveau sicherzustellen, das Berufsbild attraktiver zu gestalten und dem Beruf insgesamt ein klares Profil zu geben. Dies wird durch bundesweit einheitliche Regelungen zu den Ausbildungsstrukturen, Ausbildungsinhalten und Prüfungsanforderungen erreicht. Den Bundesländern obliegt die Durchführung des Altenpflegegesetzes. Das Gesetz regelt bundesweit einheitlich die grundlegenden Anforderungen an die Ausbildung zur Altenpflegefachkraft. Die Ausbildung soll die Kenntnisse, Fähigkeiten und Fertigkeiten vermitteln, die zur selbstständigen und eigenverantwortlichen Pflege einschließlich der Beratung, Begleitung und Betreuung alter Menschen erforderlich sind (§ 3 Absatz 1). Die Berufsbezeichnungen \"Altenpflegerin\" oder \"Altenpfleger\" dürfen nur Personen führen, denen auf Antrag die Erlaubnis hierzu erteilt worden ist. Dies setzt unter anderem voraus, dass die nach dem Altenpflegegesetz vorgeschriebene Ausbildung abgeleistet und die staatliche Abschlussprüfung bestanden worden ist (§ 1)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/gesetz-ueber-die-berufe-in-der-altenpflege-altenpflegegesetz--77744","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:50.845102+00:00","lastSeen":"2026-03-15T16:15:50.845102+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/gesetz-ueber-die-berufe-in-der-altenpflege-altenpflegegesetz--77744","crawledAt":"2026-03-15T16:15:50.846094Z","crawlId":"aid-seeded-1773591350","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"29c1744ef9036a380a3d3a9ede88b58cd27361505890ff8dfa6c152efc0d7ddb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:50.846094+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('baa2ec2f-6b99-4fa3-9d29-88b9e111db5d', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/gesetzliche-regelungen', 'active', NULL, '2026-03-15T16:15:51.351736+00:00', '{"id":"baa2ec2f-6b99-4fa3-9d29-88b9e111db5d","title":"Gesetzliche Regelungen zur Pflege und Betreuung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Gesetz zur Regelung von Verträgen über Wohnraum mit Pflege- oder Betreuungsleistungen (Wohn- und Betreuungsvertragsgesetz) Durch das Wohn- und Betreuungsvertragsgesetz regelt der Bund auf dem Gebiet des Heimrechts zivilrechtliche Verträge zwischen volljährigen Personen und Unternehmern, die Wohnraum in Verbindung mit Pflege- oder Betreuungsleistungen anbieten. Durch das Wohn- und Betreuungsvertragsgesetz regelt der Bund auf dem Gebiet des Heimrechts zivilrechtliche Verträge zwischen volljährigen Personen und Unternehmern, die Wohnraum in Verbindung mit Pflege- oder Betreuungsleistungen anbieten. Pflegeversicherung Sozialgesetzbuch - SGB XI Die gesetzliche Pflegeversicherung ist ein eigenständiger Zweig der Sozialversicherung. Sie wurde 1995 eingeführt und kontinuierlich weiterentwickelt. Es gilt eine umfassende Versicherungspflicht für alle gesetzlich und privat Krankenversicherten. Die gesetzliche Pflegeversicherung ist ein eigenständiger Zweig der Sozialversicherung. Sie wurde 1995 eingeführt und kontinuierlich weiterentwickelt. Es gilt eine umfassende Versicherungspflicht für alle gesetzlich und privat Krankenversicherten. Gesetz zur besseren Vereinbarkeit von Familie, Pflege und Beruf Mit dem Gesetz zur besseren Vereinbarkeit von Familie, Pflege und Beruf werden die bestehenden Regelungen im Pflegezeitgesetz (PflegeZG) und im Familienpflegezeitgesetz (FamiliepflegeZG) weiter entwickelt und besser miteinander verzahnt. Mit dem Gesetz zur besseren Vereinbarkeit von Familie, Pflege und Beruf werden die bestehenden Regelungen im Pflegezeitgesetz (PflegeZG) und im Familienpflegezeitgesetz (FamiliepflegeZG) weiter entwickelt und besser miteinander verzahnt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/gesetzliche-regelungen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:51.351736+00:00","lastSeen":"2026-03-15T16:15:51.351736+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/gesetzliche-regelungen","crawledAt":"2026-03-15T16:15:51.351736Z","crawlId":"aid-seeded-1773591351","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"0f7c7af28bc35bdd7aa97f66147685668efba5d24dbcdf68a987e0f5cfd10952"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:51.351736+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ddaa7f4f-fe85-464a-a4ef-01ffe8da5a71', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/pausentaste-beratung-fuer-pflegende-kinder-und-jugendliche/beratung-fuer-pflegende-kinder-jugendliche-und-junge-erwachsene-sowie-auszubildende-und-studierende-121244', 'active', NULL, '2026-03-15T16:15:52.365685+00:00', '{"id":"ddaa7f4f-fe85-464a-a4ef-01ffe8da5a71","title":"Beratung für pflegende Kinder, Jugendliche und junge Erwachsene sowie Auszubildende und Studierende","summary":{"de":"Rund 500.000 Kinder und Jugendliche in Deutschland kümmern sich um chronisch kranke oder pflegebedürftige Angehörige. Das Projekt \"Pausentaste\" unterstützt junge Pflegende mit gezielter Beratung und Information."},"content":{"de":"In Deutschland kümmern sich etwa 500.000 Kinder und Jugendliche regelmäßig um chronisch kranke Familienmitglieder. Die jungen Pflegenden übernehmen vielfältige alltägliche, pflegerische und administrative Aufgabenbereiche von Haushaltstätigkeiten über Geschwisterbetreuung bis hin zur Intimpflege. Mögliche Auswirkungen der Pflegesituation auf Kinder und Jugendliche sind psychische und physische Beschwerden, Probleme in der Schule, soziale Isolation, Müdigkeit, Mangel an Freizeit, Überforderung sowie Rollenumkehr. Vor diesem Hintergrund hat das Bundesfamilienministerium 2018 das Projekt \"Pausentaste – Wer anderen hilft, braucht manchmal selber Hilfe\" ins Leben gerufen. Das Angebot richtet sich in erster Linie an pflegende Kinder und Jugendliche. Aber auch Lehrkräfte, ambulante Pflegedienste, Sozialdienste an Schulen, Hochschulen und Kliniken sowie Jugendorganisationen und die Öffentlichkeit sollen auf das Thema aufmerksam gemacht werden. Seit 2021 nimmt die \"Pausentaste\" auch die Bedarfe und die Situation von pflegenden Studierenden sowie Auszubildenden in den Blick. Auf dem Webportal \"Pausentaste\" finden junge Pflegende, Fachkräfte und Interessierte Erfahrungsberichte, Interviews und Medientipps. Darüber hinaus weist das Webportal auf Beratungsstellen, Hilfsangebote, Gesprächsgruppen und Workshop-Angebote von Initiativen vor Ort hin. Zudem gibt es Tipps für Eltern und Fachkräfte sowie verschiedene Materialien zum Downloaden (Flyer, Plakate, Infokarten). Zur Entlastung von pflegenden Kindern und Jugendlichen wurde im Jahr 2024 ein onlinebasierter, niedrigschwelliger Selbsteinschätzungstest auf der Website integriert. Die Betreuung der Telefon- und Online-Beratung übernimmt der Verein \"Nummer gegen Kummer\". Das Beratungsangebot ist kostenlos und anonym. Unter der Nummer 116 111 erreichen ratsuchende Kinder und Jugendliche das Kinder- und Jugendtelefon von Montag bis Samstag jeweils von 14 bis 20 Uhr. Das Beratungsangebot ist kostenlos und auf Wunsch auch anonym. An Samstagen gibt es zudem eine \"Peer-to-Peer\"-Beratung (\"Jugendliche beraten Jugendliche\") durch ehrenamtliche Beraterinnen und Berater im Alter von 16 bis 27 Jahren. Die Beratung per Mail ist über die Website \"Nummer gegen Kummer\" rund um die Uhr erreichbar. Zusätzlich gibt es eine Chat-Beratung von Montag bis Donnerstag jeweils von 14 bis 20 Uhr - die ebenfalls über die Webseite erreichbar ist. Im Juli 2017 hat das Bundesfamilienministerium ein Netzwerk zur Unterstützung von Kindern und Jugendlichen mit Pflegeverantwortung ins Leben gerufen. Dem Netzwerk gehören mittlerweile rund 140 Initiativen, Hilfetelefone sowie Interessenvertretungen von jungen Pflegenden an. Das Netzwerk trifft sich mindestens einmal im Jahr zu einem fachlichen Austausch, bei dem ein Thema inhaltlich vertieft wird. Im Jahr 2023 befasste sich der siebte Fachtag schwerpunktmäßig mit den Bedarfen und Herausforderungen pflegender Kinder und Jugendlicher mit Migrations- und Fluchtbiografie. Der achte Fachtag im Oktober 2024 behandelte den Themenbereich Einsamkeit und soziale Isolation. Um den internen Austausch innerhalb des Netzwerks zu unterstützen, erscheint seit September 2019 halbjährlich ein Newsletter."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/pausentaste-beratung-fuer-pflegende-kinder-und-jugendliche/beratung-fuer-pflegende-kinder-jugendliche-und-junge-erwachsene-sowie-auszubildende-und-studierende-121244","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:52.365685+00:00","lastSeen":"2026-03-15T16:15:52.365685+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/pausentaste-beratung-fuer-pflegende-kinder-und-jugendliche/beratung-fuer-pflegende-kinder-jugendliche-und-junge-erwachsene-sowie-auszubildende-und-studierende-121244","crawledAt":"2026-03-15T16:15:52.365685Z","crawlId":"aid-seeded-1773591352","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"439088175e1d67af8013edc84ccee0e4e10e34ae2998e0ae9c9c6ee634039d2e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:52.365685+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3b569661-5713-44f5-a5a9-541c43291754', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/zehn-jahre-pflegetelefon', 'active', NULL, '2026-03-15T16:15:52.921852+00:00', '{"id":"3b569661-5713-44f5-a5a9-541c43291754","title":"Zehn Jahre Pflegetelefon","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"2011 hat das Bundesfamilienministerium das Pflegetelefon als niedrigschwelliges Beratungsangebot gestartet. Die Beraterinnen und Berater helfen seitdem Pflegebedürftigen und pflegenden Angehörigen bei der Suche nach Angeboten vor Ort, bei Fragen rund um das Thema Pflege oder wenn sie schlicht ratlos sind. In den vergangenen Jahren haben dadurch zahlreiche Menschen Unterstützung bekommen und Rat gefunden. Jetzt feiert das Pflegetelefon sein Jubiläum zum zehnjährigen Bestehen. Millionen Menschen in Deutschland kümmern sich um pflegebedürftige Angehörige. Sie nehmen sich Zeit, helfen, hören zu. Damit nehmen sie eine äußerst wichtige familiäre, aber auch eine bedeutsame gesellschaftliche Aufgabe wahr, was große Anerkennung verdient. Doch die Pflegesituation stellt pflegende Angehörigen häufig vor Herausforderungen: Wie vereinbare ich die Pflege mit Beruf und Familie? Welche gesetzlichen Möglichkeiten zur Unterstützung gibt es? Aber auch viele andere Fragen beschäftigen pflegende Angehörige: Wie wird die Pflege organisiert? Welche Einrichtungen oder Dienste gibt es? Welche Kosten entstehen? Deshalb hat das Bundesfamilienministerium das Pflegetelefon ins Leben gerufen. Es hilft seit 2011 bei allen Fragen rund um das Thema Pflege und ermöglicht einen schnellen und unkomplizierten Zugang zu relevanten Informationen. Das Pflegetelefon wird ergänzt durch Informationen des Portals wege-zur-pflege.de."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/zehn-jahre-pflegetelefon","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:52.921852+00:00","lastSeen":"2026-03-15T16:15:52.921852+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/zehn-jahre-pflegetelefon","crawledAt":"2026-03-15T16:15:52.921852Z","crawlId":"aid-seeded-1773591352","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"2f0debf74971b1db1a1f70b05816833e746a483c4841f2a557628c4ac2586abc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:52.921852+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b0a2a0da-dd06-4187-b371-0851418f5612', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/zuhause-im-alter-75580', 'active', NULL, '2026-03-15T16:15:53.366351+00:00', '{"id":"b0a2a0da-dd06-4187-b371-0851418f5612","title":"Zuhause im Alter","summary":{"de":"Selbstständiges und selbstbestimmtes Wohnen so lange wie möglich - das ist das Ziel vielfältiger Programme und Initiativen. Dabei geht es um eine altersgerechte Gestaltung von Wohnraum und Wohnumfeld sowie die Schaffung von Hilfestrukturen."},"content":{"de":"Wohnen ist ein Grundbedürfnis der Menschen. Wohnen heißt, ein Zuhause zu haben und einen Raum für gelebte Beziehungen mit Angehörigen, Freundinnen und Freunden oder Menschen aus der Nachbarschaft. Über 90 Prozent der älteren Menschen leben in einer standardmäßig ausgestatteten Wohnung. Die meisten wollen in der vertrauten Wohnumgebung bleiben - auch, wenn sie auf Hilfe und Pflege angewiesen sind. Deshalb hat das Bundesfamilienministerium das Modellprogramm \"Leben wie gewohnt\" gestartet. Ziel ist, anhand innovativer Praxisprojekte aufzuzeigen, wie ein selbstbestimmtes und selbstständiges Leben im vertrauten Wohnumfeld gelingen kann - auch im hohen Alter und bei Beeinträchtigungen. Schwerpunkte des Programms sind: Inklusives, gemeinschaftliches und Barrieren vermeidendes Wohnen Das Programm läuft von Oktober 2020 bis Dezember 2023. Weitere Informationen zu den inhaltlichen Voraussetzungen und zum Verfahren können hier abgerufen werden. Mit dem Pilotprogramm \"Sterben wo man lebt und zu Hause ist\" sollen Impulse gesetzt werden, um die stationären und insbesondere die teilstationären Angebote in der Hospiz- und Palliativversorgung weiterzuentwickeln und zu verbessern. Das Programm soll den Verbleib im eigenen Zuhause am Lebensende unterstützen und die Pflege der Beziehungen zu Nachbarn, Freunden und Angehörigen ermöglichen. Folgende Schwerpunkte setzt das Programm: Selbstbestimmtheit, Selbstständigkeit und Lebensqualität so lange wie möglich erhalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/zuhause-im-alter-75580","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:53.366351+00:00","lastSeen":"2026-03-15T16:15:53.366351+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/hilfe-und-pflege/zuhause-im-alter-75580","crawledAt":"2026-03-15T16:15:53.366351Z","crawlId":"aid-seeded-1773591353","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"6eb709ec03978668bf5a38a82964ae29c9668f047313afed3afe529a3d08486d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:53.366351+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1d1b164f-7883-4299-a1c7-e83d89365970', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen', 'active', NULL, '2026-03-15T16:15:53.893888+00:00', '{"id":"1d1b164f-7883-4299-a1c7-e83d89365970","title":"Internationale Politik für ältere Menschen","summary":{"de":"Der Anteil älterer Menschen an der Bevölkerung steigt weltweit. Das Bundesseniorenministerium setzt sich für ihre Belange, Rechte und gleichberechtigte Teilhabe ein - auch international. Das..."},"content":{"de":"Der Anteil älterer Menschen an der Bevölkerung steigt weltweit. Das Bundesseniorenministerium setzt sich für ihre Belange, Rechte und gleichberechtigte Teilhabe ein - auch international. Das stärkt den Zusammenhalt über Generationen und Länder hinweg. Die Menschen werden bei guter Gesundheit immer älter. In internationalen Gremien setzt sich die Bundesrepublik Deutschland für die Stärkung der Rechte Älterer ein - bei den Vereinten Nationen (VN), im Europarat, in der Europäischen Union (EU) und im direkten Erfahrungsaustausch mit Partnerstaaten. Insbesondere der fachliche Austausch mit Frankreich, Polen und Japan stellen hier Schwerpunkte dar. Die offene Arbeitsgruppe Altern (Open-Ended Working Group on Ageing - OEWGA) der VN befasste sich in 14 Sitzungen mit der Stärkung der Rechte älterer Menschen. Im Rahmen der jährlich stattfindenden Sitzungen in New York wurden in einer offenen Debatte wichtige Themenbereiche beleuchtet und mögliche Schutzlücken diskutiert. Am 23. Mai 2024 hat die OEWGA in einer Abschlussempfehlung 14 Bereiche für potentielle Lücken im internationalen Menschenrechtsschutz älterer Menschen identifiziert und elf Handlungsoptionen, wie diesen begegnet werden kann, vorgeschlagen. Die VN-Generalversammlung hat am 13. August 2024 das Mandat der OEWGA für erfüllt erklärt und die Arbeit der OEWGA mit einer Entschließung am 20. Dezember beendet. Alle einschlägigen VN-Gremien sind aufgefordert, sich mit den Empfehlungen der OEWGA zu befassen. Am 8. Mai 2025 wird ein hochrangiges Treffen entscheiden, welcher Nachfolgeprozess international aufgesetzt wird. In der Zwischenzeit hat der Menschenrechtsrat am 3. April 2025 die Einsetzung einer intergouvernementalen Arbeitsgruppe beschlossen, die einen Entwurf für ein rechtlich bindendes Instrument zum Schutz der Menschenrechte Älterer erarbeiten soll. Der Zweite Weltaltenplan der VN wurde im Jahr 2002 in Madrid beschlossen ( Madrid International Plan of Action on Ageing - MIPAA ). Dieser politische Aktionsplan wird von den Mitgliedsstaaten mit Hilfe von nationalen Aktionsplänen, die auf regionalen Implementierungsstrategien basieren, umgesetzt. Alle fünf Jahre informiert ein Nationaler Bericht über den Stand der Umsetzung des Weltaltenplans. Der letzte Bericht wurde 2021 unter Federführung des Bundesseniorenministeriums erstellt. Für die Umsetzung des Zweiten Weltaltenplans auf europäischer Ebene ist die Regionalkommission UNECE (United Nations Economic Commission for Europe) verantwortlich. Die zugehörige ständige Arbeitsgruppe Altern (UNECE - Standing Working Group on Ageing - UNECE-SWGA) hält alle fünf Jahre eine Ministerkonferenz ab, um europäische Lösungen zu entwickeln."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:53.893888+00:00","lastSeen":"2026-03-15T16:15:53.893888+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen","crawledAt":"2026-03-15T16:15:53.893888Z","crawlId":"aid-seeded-1773591353","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"a0553795ecc167f1c8f76477c3b9ec4ab0913535eb0cd9b0fd48520caef7c74f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:53.893888+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('db42e441-d3d0-42d2-b3d3-1fdab97253d3', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege', 'active', NULL, '2026-03-15T16:15:54.422926+00:00', '{"id":"db42e441-d3d0-42d2-b3d3-1fdab97253d3","title":"Letzte Wege - Begleitung am Lebensende","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Diagnose einer lebensbedrohlichen Erkrankung ändert alles. Unsicherheit, Trauer und Angst schleichen sich schnell auch in das Leben von Angehörigen. Das Bundesfamilienministerium fördert Projekte der Hospiz-und Palliativversorgung, um Sterbenden und deren Angehörigen beizustehen und sie gut zu unterstützen. Nana starb 2012 an Knochenkrebs. 15 Monate lang wurde sie von ihrer Familie in der Krankheit und zum Schluss auch im Sterben begleitet. Ihre Mutter, Barbara Stäcker, spricht im Interview über das, was in dieser Zeit wichtig war. Ihre Tochter Nana starb mit nur 21 Jahren an Krebs. Sie und Ihre Familie sind den Weg mit ihr gemeinsam gegangen. Was hat Ihnen allen in dieser Zeit besonders geholfen? BARBARA STÄCKER: Für Nana war am wichtigsten, dass sie ihre ganze Familie um sich hatte. Wir waren damals zu sechst im Haus: Nana und ihr Freund, unser Sohn mit seiner Freundin und wir Eltern. Damit hat man ganz automatisch eine gewisse Normalität im Alltag, die wir bis zum Schluss aufrechterhalten konnten. Jeder von uns ist sehr unterschiedlich mit Nana umgegangen und daher konnten wir ganz individuell auf ihre Bedürfnisse eingehen. Was war für Nana in dieser Zeit besonders wichtig? Ihr hat es viel bedeutet, dass sie ihre Ressourcen in dieser Zeit nutzen konnte. Wir haben kurze Ausflüge gemacht, wenn es ihr gut genug ging. Wir sind spontan alle zusammen in den Urlaub gefahren. Sie hat in dieser Zeit ihr Schmink- und Fotoprojekt \"Recover your Smile\" ins Leben gerufen. Am wichtigsten war ihr aber, dass wir offen und ehrlich miteinander umgegangen sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:54.422926+00:00","lastSeen":"2026-03-15T16:15:54.422926+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege","crawledAt":"2026-03-15T16:15:54.422926Z","crawlId":"aid-seeded-1773591354","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"833d7556dc15d759505985f6bed21e962c92821be87ab08204d785b09b5544d7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:54.422926+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('340b2bba-57ac-488d-a711-607cc10e0792', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf', 'active', NULL, '2026-03-15T16:15:54.871614+00:00', '{"id":"340b2bba-57ac-488d-a711-607cc10e0792","title":"Vereinbarkeit von Pflege und Beruf","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Pflegetelefon Das Pflegetelefon des Bundesfamilienministeriums bietet Hilfe und Beratung. Es ist bundesweit von Montag bis Donnerstag derzeit zwischen 9:00 und 16:00 Uhr und per E-Mail: info@wege-zur-pflege.de erreichbar. Das Pflegetelefon des Bundesfamilienministeriums bietet Hilfe und Beratung. Es ist bundesweit von Montag bis Donnerstag derzeit zwischen 9:00 und 16:00 Uhr und per E-Mail: info@wege-zur-pflege.de erreichbar. Beirat für die Vereinbarkeit von Pflege und Beruf Der Unabhängige Beirat für die Vereinbarkeit von Pflege und Beruf besteht aus 21 Mitgliedern und befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Der Unabhängige Beirat für die Vereinbarkeit von Pflege und Beruf besteht aus 21 Mitgliedern und befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Familienpflegezeit Die Familienpflegezeit unterstützt Angehörige bei der Vereinbarkeit von Pflege und Beruf. Beschäftigte können sich für die Pflege eines nahen Angehörigen bis zu 24 Monate teilweise von der Arbeit freistellen lassen. Die Familienpflegezeit unterstützt Angehörige bei der Vereinbarkeit von Pflege und Beruf. Beschäftigte können sich für die Pflege eines nahen Angehörigen bis zu 24 Monate teilweise von der Arbeit freistellen lassen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:54.871614+00:00","lastSeen":"2026-03-15T16:15:54.871614+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf","crawledAt":"2026-03-15T16:15:54.871614Z","crawlId":"aid-seeded-1773591354","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"9489e7ee1793ca094195bdcc368a6571110c714f876da56a20d1c0321fe18e5c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:54.871614+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5b969339-0305-4105-9e27-294dbdda4c3b', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter', 'active', NULL, '2026-03-15T16:15:55.360359+00:00', '{"id":"5b969339-0305-4105-9e27-294dbdda4c3b","title":"Zuhause im Alter","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Sicherheit im Alter In gemeinsamen Projekten haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei Konzepte erarbeitet, wie ältere Menschen besser vor Eigentums- und Vermögensdelikten oder gewalttätigen Übergriffen geschützt werden können. In gemeinsamen Projekten haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei Konzepte erarbeitet, wie ältere Menschen besser vor Eigentums- und Vermögensdelikten oder gewalttätigen Übergriffen geschützt werden können. Serviceportal \"Zuhause im Alter\" Das Serviceportal bietet Informationen und Hinweise zum Thema selbstständiges und selbstbestimmtes Wohnen im Alter. Das Serviceportal bietet Informationen und Hinweise zum Thema selbstständiges und selbstbestimmtes Wohnen im Alter. Eine neue Studie zeigt: Die große Mehrheit der über 65-Jährigen nutzt das Internet und wünscht sich mehr Tempo bei der Digitalisierung. Karin Prien und Bitkom-Präsident Ralf Wintergerst stellten die Ergebnisse am 15. Januar vor. Das Projekt \"Digitaler Engel\" des Vereins Deutschland sicher im Netz e. V. bietet digitale Aufklärung für ältere Menschen. Es wurde bei den European Digital Skills Awards 2025 in Brüssel in der Kategorie \"Cybersecurity Skills\" ausgezeichnet."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:55.360359+00:00","lastSeen":"2026-03-15T16:15:55.360359+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter","crawledAt":"2026-03-15T16:15:55.360359Z","crawlId":"aid-seeded-1773591355","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"de0551897ba7dc673ed6c5def82d77641a53dce0040292d80b666c0a03738d03"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:55.360359+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('421fe7a1-093e-4be1-9cbd-9998fb185545', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter/sicherheit-im-alter', 'active', NULL, '2026-03-15T16:15:55.866312+00:00', '{"id":"421fe7a1-093e-4be1-9cbd-9998fb185545","title":"Sicherheit im Alter","summary":{"de":"In gemeinsamen Projekten haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei Konzepte erarbeitet, wie ältere Menschen besser vor Eigentums- und Vermögensdelikten oder gewalttätigen Übergriffen geschützt werden können."},"content":{"de":"Seniorinnen und Senioren leben in Deutschland sicher. Dennoch gibt es bestimmte Lebensbereiche und Situationen, in denen gerade ältere Menschen im Visier von Kriminellen sind. Diese haben es zumeist auf Geld und Wertgegenstände abgesehen. Ablenkung und Täuschung spielen dabei eine große Rolle. Oft ist das eigene Zuhause der Tatort. Im Rahmen des Aktionsprogramms \"Sicher leben im Alter\" haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei (DHPOL) unterschiedliche Maßnahmen zum Schutz älterer Menschen erarbeitet. Nachzulesen sind sie unter anderem in der Broschüre \"Rate mal, wer dran ist?\". Die mehrfach überarbeitete und 2021 neu aufgelegte Publikation gibt Tipps, wie sich ältere Menschen vor Vermögensdelikten wie etwa Trickdiebstählen oder dem sogenannten Enkeltrick schützen können. Beraterinnen und Berater wurden im Rahmen des Aktionsprogramms zu spezifischen Bedürfnissen älterer Opfer von häuslicher Gewalt und zur Schaffung von Schutzraumangeboten geschult. In der Modellregion Hamburg wurden seither Beratungs- und Hilfsangebote aus dem Bereich Opferhilfe gezielt auf ältere betroffene Frauen abgestimmt. Ein weiterer Schwerpunkt des Aktionsprogramms war die Prävention von Misshandlung und Vernachlässigung in der häuslichen Pflege. In einer Kooperation mit sechs Pflegediensten und einer Pflegeberaterin wurden hierzu in der Modellregion Essen Handlungsansätze entwickelt und in der Praxis erprobt. Das Forschungsprojekt \"Sicherheitspotenziale im höheren Lebensalter\" widmete sich der Frage, wie ältere Menschen selbst für die eigene Sicherheit sorgen können. Außerdem befassten sich die Teilnehmenden mit der besonderen Gefährdung älterer Menschen durch Vermögensdelikte und unseriöse Geschäftspraktiken. Die entstandenen Materialien stehen auf der Projektseite der DHPOL zum Download zur Verfügung. Dazu zählt unter anderem die Broschüre \"Vollmacht, aber sicher!\". Das Projekt widmete sich der Prävention von aggressivem Verhalten unter Bewohnerinnen und Bewohnern in Pflegeeinrichtungen. In Kooperation mit dem Zentrum für Qualität in der Pflege (ZQP) und der DHPOL entstanden im Jahr 2020 praxiserprobte Materialien, die auf der Website der DHPOL und auf der Website des ZQP heruntergeladen werden können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter/sicherheit-im-alter","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:55.866312+00:00","lastSeen":"2026-03-15T16:15:55.866312+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter/sicherheit-im-alter/sicherheit-im-alter-77484","crawledAt":"2026-03-15T16:15:55.867292Z","crawlId":"aid-seeded-1773591355","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"9a5c879dff34f9448c09bbc1f31fd5b663619bb43dfd93891bf6c46f2ee5025d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:55.867292+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b073c294-fb81-4ac0-a1ff-0ed3dc8a6a89', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung', 'active', NULL, '2026-03-15T16:15:56.926785+00:00', '{"id":"b073c294-fb81-4ac0-a1ff-0ed3dc8a6a89","title":"Ausbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Ausbildung Wichtige praktische Berufserfahrungen und strukturiertes Lernen: Die duale Ausbildung bereitet junge Menschen perfekt auf ihre berufliche Karriere vor. Nebenbei sichert sie Fachkräfte für die Betriebe in Deutschland. Wichtige praktische Berufserfahrungen und strukturiertes Lernen: Die duale Ausbildung bereitet junge Menschen perfekt auf ihre berufliche Karriere vor. Nebenbei sichert sie Fachkräfte für die Betriebe in Deutschland. Berufliche Orientierung Stärken erkunden, Berufe ausprobieren: Berufliche Orientierung unterstützt junge Menschen mit vielfältigen Angeboten bei der Wahl ihres beruflichen Weges und stärkt so Teilhabe und Fachkräftesicherung. Stärken erkunden, Berufe ausprobieren: Berufliche Orientierung unterstützt junge Menschen mit vielfältigen Angeboten bei der Wahl ihres beruflichen Weges und stärkt so Teilhabe und Fachkräftesicherung. Auszubildende Während ihrer Ausbildung haben junge Menschen die Möglichkeit, konkrete praktische Erfahrungen mit theoretischem Wissen aus der Berufsschule zu verknüpfen. Auszubildende erhalten somit den idealen Start in die berufliche Karriere. Während ihrer Ausbildung haben junge Menschen die Möglichkeit, konkrete praktische Erfahrungen mit theoretischem Wissen aus der Berufsschule zu verknüpfen. Auszubildende erhalten somit den idealen Start in die berufliche Karriere."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:56.926785+00:00","lastSeen":"2026-03-15T16:15:56.926785+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung","crawledAt":"2026-03-15T16:15:56.926785Z","crawlId":"aid-seeded-1773591356","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"a5c430bf7685bfea32f58155aede6263e7157b2dcd1953ca3f5bdafdf92ca0bb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:56.926785+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('76f0c51b-87a7-48c1-b118-d7b1d4d2e9b1', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung', 'active', NULL, '2026-03-15T16:15:57.428806+00:00', '{"id":"76f0c51b-87a7-48c1-b118-d7b1d4d2e9b1","title":"Außerschulische Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Außerschulische Bildung Von der Kita bis ins hohe Alter: Menschen bilden sich auch außerhalb der Schule weiter. Deshalb fördert das Bundesbildungsministerium unterschiedliche Programme, um Menschen die Möglichkeit zu geben, sich frei entfalten zu können. Von der Kita bis ins hohe Alter: Menschen bilden sich auch außerhalb der Schule weiter. Deshalb fördert das Bundesbildungsministerium unterschiedliche Programme, um Menschen die Möglichkeit zu geben, sich frei entfalten zu können. MINT-Bildung Die Ausbildung in einem MINT-Fach vermittelt zukunftsorientiertes Wissen für naturwissenschaftliche und technologische Zusammenhänge. Der MINT-Aktionsplan soll vor allem junge Menschen für MINT-Bildung begeistern. Die Ausbildung in einem MINT-Fach vermittelt zukunftsorientiertes Wissen für naturwissenschaftliche und technologische Zusammenhänge. Der MINT-Aktionsplan soll vor allem junge Menschen für MINT-Bildung begeistern. Stiftung Kinder forschen Wieso, weshalb, warum: Kinder sind neugierig und wollen die Welt mit allen Sinnen begreifen. Durch Bildung in den Bereichen Mathematik, Informatik, Naturwissenschaften und Technik (MINT) lernen Kinder, die Welt nachhaltig mitzugestalten. Wieso, weshalb, warum: Kinder sind neugierig und wollen die Welt mit allen Sinnen begreifen. Durch Bildung in den Bereichen Mathematik, Informatik, Naturwissenschaften und Technik (MINT) lernen Kinder, die Welt nachhaltig mitzugestalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:57.428806+00:00","lastSeen":"2026-03-15T16:15:57.428806+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung","crawledAt":"2026-03-15T16:15:57.428806Z","crawlId":"aid-seeded-1773591357","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"2365723d669ad38b8b6eb1c0f3604966343db1f974ab59b061f3c797c2955f5a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:57.428806+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('113cee8c-0dc9-4aa7-afad-f19dcc165ad7', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung', 'active', NULL, '2026-03-15T16:15:57.865173+00:00', '{"id":"113cee8c-0dc9-4aa7-afad-f19dcc165ad7","title":"Berufliche Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Beruflicher Erfolg wird praktisch erlebbar Moderne Rahmenbedingungen machen Berufsbildung attraktiv. Das Bundesbildungsministerium entwickelt Ausbildungsberufe weiter und gestaltet sie zukunftssicher, nachhaltig und digital. Moderne Rahmenbedingungen machen Berufsbildung attraktiv. Das Bundesbildungsministerium entwickelt Ausbildungsberufe weiter und gestaltet sie zukunftssicher, nachhaltig und digital. Anerkennung ausländischer Berufsqualifikationen Der Fachkräftemangel ist eine unserer größten Herausforderungen. Wir konkurrieren international um Fachkräfte. Unser Ziel: Ausländische Fachkräfte sollen ihre Fähigkeiten noch einfacher im Arbeitsmarkt einsetzen können. Der Fachkräftemangel ist eine unserer größten Herausforderungen. Wir konkurrieren international um Fachkräfte. Unser Ziel: Ausländische Fachkräfte sollen ihre Fähigkeiten noch einfacher im Arbeitsmarkt einsetzen können. Teilqualifikationen An- oder ungelernte Menschen können mit Teilqualifikationen einen Berufsabschluss erlangen. Das Bundesbildungsministerium fördert den Ausbau dieses Instruments zur Fachkräftesicherung, damit mehr Menschen eine berufliche Perspektive erhalten. An- oder ungelernte Menschen können mit Teilqualifikationen einen Berufsabschluss erlangen. Das Bundesbildungsministerium fördert den Ausbau dieses Instruments zur Fachkräftesicherung, damit mehr Menschen eine berufliche Perspektive erhalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:57.865173+00:00","lastSeen":"2026-03-15T16:15:57.865173+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung","crawledAt":"2026-03-15T16:15:57.865173Z","crawlId":"aid-seeded-1773591357","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"74a3cd214025785aa6570f7413607efe36177c8cbcdd3367c213a103f401889f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:57.865173+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bba40fb1-0edf-4b47-a481-dfe1d6ad02a5', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung', 'active', NULL, '2026-03-15T16:15:58.384050+00:00', '{"id":"bba40fb1-0edf-4b47-a481-dfe1d6ad02a5","title":"Bildungsforschung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Bildungsforschung beschäftigt sich mit den Voraussetzungen, die es braucht, damit alle Menschen in Deutschland die beste Bildung erhalten. Bildungsforschende untersuchen hierbei fortlaufend die Stärken und Schwächen unseres Bildungssystems. Wie ermöglichen wir die beste Bildung für alle in Deutschland lebenden Menschen? Zur Beantwortung dieser Frage liefert die Bildungsforschung wichtige Erkenntnisse. Ob gleiche Chancen für alle, bessere Bildung oder Innovationen beim Lernen und Lehren: Bildungsforschung hilft, das Bildungssystem in Deutschland zu verbessern. Bildungsforschung trägt dazu bei, Ungleichheiten im Bildungssystem aufzuzeigen und wirksame Gegenstrategien zu entwickeln - damit alle Menschen gleiche Bildungschancen erhalten. Bildungsforschende werten fortlaufend die Stärken und Schwächen des Bildungswesens aus. Auf der Grundlage ihrer Erkenntnisse entstehen gezielte Maßnahmen zur Verbesserung der Qualität. Bildungsforschende liefern stichhaltige Daten und Erkenntnisse im Hinblick darauf, was oder wie wir lernen und welche Fähigkeiten wir in Zukunft brauchen. Fachleute aus Politik, Bildung und Verwaltung erhalten dadurch eine wissenschaftliche Grundlage, um Bildungsangebote an die Bedürfnisse der Bevölkerung anzupassen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:58.384050+00:00","lastSeen":"2026-03-15T16:15:58.384050+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung","crawledAt":"2026-03-15T16:15:58.384050Z","crawlId":"aid-seeded-1773591358","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"0c22a31d538df7b40735b9bd09dec0667cb00fb68439cdaf9d6df54de6851fb3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:58.384050+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bc56523e-3d45-488f-bc0b-aaf715dbbeba', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung', 'active', NULL, '2026-03-15T16:15:58.863898+00:00', '{"id":"bc56523e-3d45-488f-bc0b-aaf715dbbeba","title":"Frühe Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Frühe Bildung Die frühe Bildung fördert Kinder in den ersten Lebensjahren und gibt ihnen die bestmöglichen Chancen für ihre spätere schulische und persönliche Entwicklung. Die frühe Bildung fördert Kinder in den ersten Lebensjahren und gibt ihnen die bestmöglichen Chancen für ihre spätere schulische und persönliche Entwicklung. Sprachliche Bildung Eine gute sprachliche Entwicklung stärkt Lernen, Austausch und Teilhabe an der Gesellschaft. Gezielte frühe sprachliche Förderung ermöglicht es Kindern, sich sicher mitzuteilen und Bildungswege erfolgreich zu gestalten. Eine gute sprachliche Entwicklung stärkt Lernen, Austausch und Teilhabe an der Gesellschaft. Gezielte frühe sprachliche Förderung ermöglicht es Kindern, sich sicher mitzuteilen und Bildungswege erfolgreich zu gestalten. Bildung für nachhaltige Entwicklung Bildung für nachhaltige Entwicklung (BNE) befähigt Menschen zu zukunftsfähigem Denken und Handeln. Sie vermittelt früh Kompetenzen, um ökologische, soziale und wirtschaftliche Zusammenhänge aktiv zu verstehen und nachhaltig mitzugestalten. Bildung für nachhaltige Entwicklung (BNE) befähigt Menschen zu zukunftsfähigem Denken und Handeln. Sie vermittelt früh Kompetenzen, um ökologische, soziale und wirtschaftliche Zusammenhänge aktiv zu verstehen und nachhaltig mitzugestalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:58.863898+00:00","lastSeen":"2026-03-15T16:15:58.863898+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung","crawledAt":"2026-03-15T16:15:58.863898Z","crawlId":"aid-seeded-1773591358","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"07f7e0f937ac78628352a0d8acb48328b515d17500f6d6a8bd70c5129e7d989a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:58.864943+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0386a739-430f-4d3f-9f37-a26d0c5f0e22', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung', 'active', NULL, '2026-03-15T16:15:59.361635+00:00', '{"id":"0386a739-430f-4d3f-9f37-a26d0c5f0e22","title":"Integration durch Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Inklusive Bildung Inklusive Bildung bedeutet, dass Menschen mit unterschiedlichen Lern- und Leistungsvoraussetzungen gemeinsam und gleichberechtigt lernen. Sie bildet die Grundlage für die persönliche Entwicklung und soziale Teilhabe aller Lernenden. Inklusive Bildung bedeutet, dass Menschen mit unterschiedlichen Lern- und Leistungsvoraussetzungen gemeinsam und gleichberechtigt lernen. Sie bildet die Grundlage für die persönliche Entwicklung und soziale Teilhabe aller Lernenden. Informationen für Geflüchtete Wer als Geflüchtete oder Geflüchteter nach Deutschland kommt, hat viele Fragen. Auf dieser Seite finden Sie einen ersten Überblick sowie hilfreiche Informationen zu bildungsspezifischen Unterstützungsangeboten in verschiedenen Sprachen. Wer als Geflüchtete oder Geflüchteter nach Deutschland kommt, hat viele Fragen. Auf dieser Seite finden Sie einen ersten Überblick sowie hilfreiche Informationen zu bildungsspezifischen Unterstützungsangeboten in verschiedenen Sprachen. Bildung für alle in der Einwanderungsgesellschaft Bildung ist der Schlüssel für Integration und Teilhabe. Als Gesellschaft profitieren wir, wenn alle ihre Talente und Fähigkeiten bestmöglich entwickeln und einbringen können. Bildung ist der Schlüssel für Integration und Teilhabe. Als Gesellschaft profitieren wir, wenn alle ihre Talente und Fähigkeiten bestmöglich entwickeln und einbringen können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:59.361635+00:00","lastSeen":"2026-03-15T16:15:59.361635+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung","crawledAt":"2026-03-15T16:15:59.361635Z","crawlId":"aid-seeded-1773591359","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"849edc3a05c7ab7b446983f1acef149cf22633d80827317306e6da9a73fed251"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:59.361635+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1cc7a8c5-c0b2-4954-aedf-62d953e2bda5', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement', 'active', NULL, '2026-03-15T16:15:59.906016+00:00', '{"id":"1cc7a8c5-c0b2-4954-aedf-62d953e2bda5","title":"Kommunales Bildungsmanagement","summary":{"de":"Bessere Planung und Verteilung lokaler Ressourcen, bessere Transparenz über die Bildungsbedürfnisse der Menschen: ein datenbasiertes Bildungsmanagement bietet zahlreiche Vorteile für die Menschen..."},"content":{"de":"Bessere Planung und Verteilung lokaler Ressourcen, bessere Transparenz über die Bildungsbedürfnisse der Menschen: ein datenbasiertes Bildungsmanagement bietet zahlreiche Vorteile für die Menschen vor Ort. Die \" Transferinitiative Kommunales Bildungsmanagement\" unterstützt Städte und Landkreise darin, ein datenbasiertes Bildungsmanagement aufzubauen. Dieses hilft, vor Ort passende Bildungsangebote für alle Lebensphasen anzubieten und zukunftsfähig zu gestalten. Ein datenbasiertes kommunales Bildungsmanagement hilft, mehr Transparenz über die Bildungsbedürfnisse der Menschen in allen Lebensphasen zur Bereitstellung eines individualisierten Bildungsangebots zu schaffen. Eine bessere Planung und Verteilung lokaler Ressourcen unter Einbindung der Zivilgesellschaft und von Kooperationsnetzwerken werden möglich. Außerdem ergibt sich eine stärkere Resilienz bei Krisensituationen durch schnellen Zugriff auf kontinuierlich fortgeschriebene Bildungsdaten und Bildungssteuerung in kommunaler Verantwortungsgemeinschaft. Die Förderung von Chancengerechtigkeit und Teilhabe in der kommunalen Bildungslandschaft wird verbessert."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:59.906016+00:00","lastSeen":"2026-03-15T16:15:59.906016+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement","crawledAt":"2026-03-15T16:15:59.906016Z","crawlId":"aid-seeded-1773591359","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"458a6b3fbb7f965e2ff00b00a625e39feca23753ae2eae4edb2b9a27fed3caf9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:59.906016+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('185d9a04-dc82-404c-9121-2d08fa1f8ce2', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule', 'active', NULL, '2026-03-15T16:16:00.401055+00:00', '{"id":"185d9a04-dc82-404c-9121-2d08fa1f8ce2","title":"Schule","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Startchancen-Programm Das Startchancen-Programm des Bundesbildungsministeriums unterstützt Schulen mit einem hohen Anteil sozial benachteiligter Schülerinnen und Schüler. Das Startchancen-Programm des Bundesbildungsministeriums unterstützt Schulen mit einem hohen Anteil sozial benachteiligter Schülerinnen und Schüler. Digitalisierung der Bildung Die Digitalisierung des Lehrens und Lernens ist unverzichtbar. Das Bundesbildungsministerium setzt sich für eine gut funktionierende Infrastruktur, moderne Ausstattung der Schulen und entsprechend ausgebildete Lehrkräfte ein. Die Digitalisierung des Lehrens und Lernens ist unverzichtbar. Das Bundesbildungsministerium setzt sich für eine gut funktionierende Infrastruktur, moderne Ausstattung der Schulen und entsprechend ausgebildete Lehrkräfte ein. DigitalPakt Schule Digitale Bildung schafft neue Möglichkeiten: Der DigitalPakt Schule unterstützt Schulen beim Ausbau digitaler Infrastruktur und Ausstattung - für flexibles Lernen, mehr Chancengleichheit und einen guten Start in die digitale Arbeitswelt. Digitale Bildung schafft neue Möglichkeiten: Der DigitalPakt Schule unterstützt Schulen beim Ausbau digitaler Infrastruktur und Ausstattung - für flexibles Lernen, mehr Chancengleichheit und einen guten Start in die digitale Arbeitswelt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:00.401055+00:00","lastSeen":"2026-03-15T16:16:00.401055+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule","crawledAt":"2026-03-15T16:16:00.401833Z","crawlId":"aid-seeded-1773591360","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"a179632068097276701c029a252d5347c154994433e8fec39ee205e0f9a932b8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:00.401833+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9233c3f2-c141-4ee4-880b-3e43723e4b2f', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung', 'active', NULL, '2026-03-15T16:16:00.878121+00:00', '{"id":"9233c3f2-c141-4ee4-880b-3e43723e4b2f","title":"Weiterbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Weiterbildung Ob berufliche oder allgemeine Weiterbildung: In einer sich ständig verändernden Welt ist es wichtig, stetig neue Kompetenzen zu erwerben. Eine Weiterbildung hilft bei der beruflichen wie auch persönlichen Weiterentwicklung. Ob berufliche oder allgemeine Weiterbildung: In einer sich ständig verändernden Welt ist es wichtig, stetig neue Kompetenzen zu erwerben. Eine Weiterbildung hilft bei der beruflichen wie auch persönlichen Weiterentwicklung. Allgemeine Weiterbildung Viele Bildungsangebote außerhalb des beruflichen Aufgabenbereiches fördern Schlüsselkompetenzen, die nicht nur für den Alltag wichtig sind. Eine allgemeine Weiterbildung ermöglicht es somit Kompetenzen zu erwerben, die auch beruflich weiterhelfen. Viele Bildungsangebote außerhalb des beruflichen Aufgabenbereiches fördern Schlüsselkompetenzen, die nicht nur für den Alltag wichtig sind. Eine allgemeine Weiterbildung ermöglicht es somit Kompetenzen zu erwerben, die auch beruflich weiterhelfen. Alphabetisierung und Grundbildung In Deutschland gibt es etwa 6,2 Millionen Erwachsene, die nicht oder nur auf niedrigstem Niveau lesen und schreiben können. Die AlphaDekade ermöglicht den Betroffenen einen Zugang zu Lern- und Unterstützungsangeboten. In Deutschland gibt es etwa 6,2 Millionen Erwachsene, die nicht oder nur auf niedrigstem Niveau lesen und schreiben können. Die AlphaDekade ermöglicht den Betroffenen einen Zugang zu Lern- und Unterstützungsangeboten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:00.878121+00:00","lastSeen":"2026-03-15T16:16:00.878121+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung","crawledAt":"2026-03-15T16:16:00.878121Z","crawlId":"aid-seeded-1773591360","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"612309585e3369d262c8cd54f11fdf7238fc5c48b5c3050c604cba29d2007ae8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:00.878121+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8eaa51da-372e-41c3-b005-b09d72a7a799', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit', 'active', NULL, '2026-03-15T16:16:01.898512+00:00', '{"id":"8eaa51da-372e-41c3-b005-b09d72a7a799","title":"Allianz gegen Einsamkeit","summary":{"de":"Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung..."},"content":{"de":"Wissen zu Einsamkeit vertiefen Einsamkeit ist ein vielschichtiges Phänomen mit unterschiedlichen Ursachen. Davon betroffen sind sowohl ältere als auch jüngere Menschen. Einsamkeit ist ein vielschichtiges Phänomen mit unterschiedlichen Ursachen. Davon betroffen sind sowohl ältere als auch jüngere Menschen. Modellprojekte gegen Einsamkeit Um Einsamkeit und Isolation wirksam zu begegnen, fördert das Bundesgesellschaftsministerium Orte für Gemeinsamkeit und gemeinsames Erleben. Um Einsamkeit und Isolation wirksam zu begegnen, fördert das Bundesgesellschaftsministerium Orte für Gemeinsamkeit und gemeinsames Erleben. Über Einsamkeit reden Betroffene sprechen häufig nicht über ihre Einsamkeit. Deshalb muss das Thema sichtbarer und dafür sensibilisiert werden. Betroffene sprechen häufig nicht über ihre Einsamkeit. Deshalb muss das Thema sichtbarer und dafür sensibilisiert werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:01.898512+00:00","lastSeen":"2026-03-15T16:16:01.898512+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit","crawledAt":"2026-03-15T16:16:01.898512Z","crawlId":"aid-seeded-1773591361","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"0a380576d8a607d820b950d5b75054c2f4ef26d928c4a3cda9e91a1e827cbf9d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:01.898512+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('aaf6ca79-a145-4d69-a483-1d111ef16475', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948', 'active', NULL, '2026-03-15T16:16:02.396898+00:00', '{"id":"aaf6ca79-a145-4d69-a483-1d111ef16475","title":"Bundesprogramm \"Demokratie leben! \"","summary":{"de":"Demokratie fördern. Vielfalt gestalten. Extremismus vorbeugen - das sind die Kernziele des Bundesprogramms \"Demokratie leben!\". Dieser inhaltliche Dreiklang ist handlungsleitend."},"content":{"de":"\"Demokratie leben!\" ist seit 2015 als lernendes Bundesprogramm konzipiert. Es reagiert auf aktuelle gesellschaftliche Herausforderungen und wird kontinuierlich weiterentwickelt. Über bereits zwei Förderperioden hinweg hat sich \"Demokratie leben!\" zum inhaltlich umfassendsten Präventions- und Gestaltungsprogramm des Bundes zur zivilgesellschaftlichen Demokratieförderung, Vielfaltgestaltung und Extremismusprävention entwickelt. Für die 3. Förderperiode (2025 bis 2032) hat das Bundesfamilienministerium das Bundesprogramm angepasst. Dabei wurden die Ziele und Strukturen neu justiert und stärker fokussiert - vor allem mit Blick auf die aktuellen gesellschaftlichen Herausforderungen und auf Grundlage der gewonnenen Erfahrungen aus der ersten (2015 bis 2019) und zweiten (2020 bis 2024) Förderperiode. Das Bundesprogramm ist im Januar 2025 in seine 3. Förderperiode (2025 bis 2032) gestartet. Mit dem Programm fördert das Bundesfamilienministerium zivilgesellschaftliches Engagement auf allen Ebenen des Staates für ein vielfältiges und demokratisches Miteinander und die Arbeit gegen Radikalisierungen und Polarisierungen in der Gesellschaft. In seiner 3. Förderperiode (2025 bis 2032) ist das Bundesprogramm Teil der Strategie \"Gemeinsam für Demokratie und gegen Extremismus - Strategie der Bundesregierung für eine starke, wehrhafte Demokratie und eine offene und vielfältige Gesellschaft\". Sie ersetzt die \" Strategie der Bundesregierung zur Extremismusprävention und Demokratieförderung \" aus dem Jahr 2016. Ziel des Bundesprogramms ist es, zur Stärkung der Demokratie und eines friedlichen, respektvollen Zusammenlebens beizutragen, Teilhabe zu fördern und die Arbeit gegen jede Form von Gruppenbezogener Menschenfeindlichkeit und Demokratiefeindlichkeit zu ermöglichen. Dazu wird das Bundesprogramm in drei Handlungsfeldern aktiv: Demokratie fördern - Vielfalt gestalten - Extremismus vorbeugen. Das Bundesprogramm stärkt die Zivilgesellschaft in diesen Handlungsfeldern durch geeignete Rahmenbedingungen in diesen Handlungsfeldern."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:02.396898+00:00","lastSeen":"2026-03-15T16:16:02.396898+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948","crawledAt":"2026-03-15T16:16:02.396898Z","crawlId":"aid-seeded-1773591362","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"271f4e21fb8a24d323391351331ce198237a051775d29ffc8aa2a8717888e2ff"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:02.396898+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fc062edf-b13a-4b93-85d3-d7079d3e6581', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit', 'active', NULL, '2026-03-15T16:16:02.892691+00:00', '{"id":"fc062edf-b13a-4b93-85d3-d7079d3e6581","title":"Demografischer Wandel und Nachhaltigkeit","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Antworten auf den demografischen Wandel Die demografische Entwicklung wird unsere Gesellschaft tiefgreifend verändern. Im Dialog mit Wissenschaft und Praxis erarbeitet das Bundesfamilienministerium neue Ansätze, wie Kommunen sich darauf einstellen können. Die demografische Entwicklung wird unsere Gesellschaft tiefgreifend verändern. Im Dialog mit Wissenschaft und Praxis erarbeitet das Bundesfamilienministerium neue Ansätze, wie Kommunen sich darauf einstellen können. Zukunftsraum Demografie Das Netzwerk \"Zukunftsraum Demografie\" unterstützt Gemeinden, Städte und Landkreise dabei, die Herausforderungen des demografischen Wandels zu gestalten. Das Netzwerk \"Zukunftsraum Demografie\" unterstützt Gemeinden, Städte und Landkreise dabei, die Herausforderungen des demografischen Wandels zu gestalten. Nachhaltige Entwicklung Die Herausforderungen unserer Zeit sind vielfältig, überschreiten Grenzen und betreffen uns alle. Das Bundesfamilienministerium trägt mit seinen gesellschaftspolitischen Maßnahmen zu einer nachhaltigen Entwicklung bei. Die Herausforderungen unserer Zeit sind vielfältig, überschreiten Grenzen und betreffen uns alle. Das Bundesfamilienministerium trägt mit seinen gesellschaftspolitischen Maßnahmen zu einer nachhaltigen Entwicklung bei."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:02.892691+00:00","lastSeen":"2026-03-15T16:16:02.892691+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit","crawledAt":"2026-03-15T16:16:02.893741Z","crawlId":"aid-seeded-1773591362","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"42b9b208fdd543059d08cf891f2dae08cac032d42a4099008317cbb4068d0ff8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:02.893741+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5735a210-06fe-447f-b91c-03f6c3119763', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt', 'active', NULL, '2026-03-15T16:16:03.385959+00:00', '{"id":"5735a210-06fe-447f-b91c-03f6c3119763","title":"Deutsche Stiftung für Engagement und Ehrenamt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Engagement für Geflüchtete aus der Ukraine fördern Mit dem Förderprogramm \"Ehrenamt hilft gemeinsam\" stärkt die Deutsche Stiftung für Engagement und Ehrenamt zivilgesellschaftliche Strukturen im Bereich des Bürgerschaftlichen Engagements für ukrainische Geflüchtete. Mit dem Förderprogramm \"Ehrenamt hilft gemeinsam\" stärkt die Deutsche Stiftung für Engagement und Ehrenamt zivilgesellschaftliche Strukturen im Bereich des Bürgerschaftlichen Engagements für ukrainische Geflüchtete. Hilfe für die Ukraine: Die Stiftung vernetzt und informiert Die Deutsche Stiftung für Engagement und Ehrenamt vernetzt deutschlandweit Engagierte, die sich für Geflüchtete aus der Ukraine einsetzten wollen und gibt einen Überblick über Unterstützungsmöglichkeiten. Die Deutsche Stiftung für Engagement und Ehrenamt vernetzt deutschlandweit Engagierte, die sich für Geflüchtete aus der Ukraine einsetzten wollen und gibt einen Überblick über Unterstützungsmöglichkeiten. Der Gründungs-Vorstand der Stiftung Der erste Vorstand der Deutschen Stiftung für Engagement und Ehrenamt besteht aus einer Doppelspitze. Katarina Peranić und Jan Holze werden die Stiftung aufbauen. Der erste Vorstand der Deutschen Stiftung für Engagement und Ehrenamt besteht aus einer Doppelspitze. Katarina Peranić und Jan Holze werden die Stiftung aufbauen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:03.385959+00:00","lastSeen":"2026-03-15T16:16:03.385959+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt","crawledAt":"2026-03-15T16:16:03.385959Z","crawlId":"aid-seeded-1773591363","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"ec08949e8ac9a70b1c6286f18ea484c234c4d469bf4e227e99588e9f865bc1bd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:03.385959+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1944698f-cc98-422f-a390-53a0af23fda5', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken', 'active', NULL, '2026-03-15T16:16:03.894150+00:00', '{"id":"1944698f-cc98-422f-a390-53a0af23fda5","title":"Engagement stärken","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Menschen stärken Menschen Mit dem Bundesprogramm \"Menschen stärken Menschen\" fördert und unterstützt das Bundesfamilienministerium bürgerschaftliches Engagement in Form von Patenschaften - für mehr gesellschaftlichen Zusammenhalt und bessere Teilhabechancen. Mit dem Bundesprogramm \"Menschen stärken Menschen\" fördert und unterstützt das Bundesfamilienministerium bürgerschaftliches Engagement in Form von Patenschaften - für mehr gesellschaftlichen Zusammenhalt und bessere Teilhabechancen. Verbände, Stiftungen und Spenden Verbände, Stiftungen und Spenden sind wichtige Säulen der Engagementpolitik. Deshalb arbeitet das Bundesfamilienministerium eng mit Verbänden der freien Wohlfahrtspflege zusammen. Es unterstützt Bürgerstiftungen und fördert die Spendenberatung. Verbände, Stiftungen und Spenden sind wichtige Säulen der Engagementpolitik. Deshalb arbeitet das Bundesfamilienministerium eng mit Verbänden der freien Wohlfahrtspflege zusammen. Es unterstützt Bürgerstiftungen und fördert die Spendenberatung. Engagementberichterstattung Die Engagementberichte der Bundesregierung sind eine Bestandsaufnahme zur Entwicklung des bürgerschaftlichen Engagements in Deutschland. Die Engagementberichte der Bundesregierung sind eine Bestandsaufnahme zur Entwicklung des bürgerschaftlichen Engagements in Deutschland."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:03.894150+00:00","lastSeen":"2026-03-15T16:16:03.894150+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken","crawledAt":"2026-03-15T16:16:03.894150Z","crawlId":"aid-seeded-1773591363","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"fd143d2642833529fabd12ea1e257739fd044384927cc9183fb6581bc84b2d2c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:03.894150+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6f671c61-fec2-4df9-abb0-01ca97e605fc', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration', 'active', NULL, '2026-03-15T16:16:04.398319+00:00', '{"id":"6f671c61-fec2-4df9-abb0-01ca97e605fc","title":"Flüchtlingspolitik und Integration","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Angebote zur Sprachförderung und Integration Sprachkurse, Patenschaften, Existenzgründung - mit unterschiedlichen Maßnahmen sorgt die Bundesregierung dafür, dass Integration gelingt. Eine aktuelle Publikation gibt einen Überblick. Sprachkurse, Patenschaften, Existenzgründung - mit unterschiedlichen Maßnahmen sorgt die Bundesregierung dafür, dass Integration gelingt. Eine aktuelle Publikation gibt einen Überblick. Informationen für geflüchtete Menschen Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Viele davon sind in verschiedenen Sprachen erhältlich. Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Viele davon sind in verschiedenen Sprachen erhältlich. Jugendmigrationsdienste Als Teil der Initiative \"JUGEND STÄRKEN\" beraten und begleiten die Jugendmigrationsdienste junge Menschen mit Einwanderungsgeschichte im Alter zwischen 12 und 27 Jahren. Das vielseitige Angebot hilft bei Fragen zum Schulbesuch, bei der... Als Teil der Initiative \"JUGEND STÄRKEN\" beraten und begleiten die Jugendmigrationsdienste junge Menschen mit Einwanderungsgeschichte im Alter zwischen 12 und 27 Jahren. Das vielseitige Angebot hilft bei Fragen zum Schulbesuch, bei der..."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:04.398319+00:00","lastSeen":"2026-03-15T16:16:04.398319+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration","crawledAt":"2026-03-15T16:16:04.398319Z","crawlId":"aid-seeded-1773591364","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"209838816f26c89b9031c76566513739288820299cbadb14fc6300219693abe1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:04.398319+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dd5f2633-0d79-4858-8b4d-c123726427c3', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete', 'active', NULL, '2026-03-15T16:16:04.902616+00:00', '{"id":"dd5f2633-0d79-4858-8b4d-c123726427c3","title":"Informationen für geflüchtete Menschen","summary":{"de":"Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Einige..."},"content":{"de":"Mit dem \"Bericht zu dem Gesetz zur Verbesserung der Unterbringung, Versorgung und Betreuung ausländischer Kinder und Jugendlicher\" kommt die Bundesregierung ihrer Verpflichtung nach, jährlich über die Situation unbegleiteter ausländischer Minderjähriger (UMA) in Deutschland zu informieren. Mindeststandards in Flüchtlingsunterkünften Das Bundesfamilienministerium und das Kinderhilfswerk UNICEF haben gemeinsam Mindeststandards zum Schutz von Kindern, Jugendlichen und Frauen in Flüchtlingsunterkünften erarbeitet. Das Bundesfamilienministerium und das Kinderhilfswerk UNICEF haben gemeinsam Mindeststandards zum Schutz von Kindern, Jugendlichen und Frauen in Flüchtlingsunterkünften erarbeitet. Menschen stärken Menschen Ein Flyer informiert über unterschiedliche Möglichkeiten des persönlichen Engagements für Flüchtlinge im Programm \"Menschen stärken Menschen\" - ob als Patin oder Pate, Gastfamilie oder Vormund. Ein Flyer informiert über unterschiedliche Möglichkeiten des persönlichen Engagements für Flüchtlinge im Programm \"Menschen stärken Menschen\" - ob als Patin oder Pate, Gastfamilie oder Vormund. Hilfs- und Beratungsangebote für Frauen und LSBTI Unter den derzeit nach Deutschland kommenden Flüchtlingen sind Frauen und LSBTI besonders schutzbedürftig. Mit einem mehrsprachigen Flyer sollen sie schnell Zugang zum deutschen Hilfesystem finden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:04.902616+00:00","lastSeen":"2026-03-15T16:16:04.902616+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete","crawledAt":"2026-03-15T16:16:04.902616Z","crawlId":"aid-seeded-1773591364","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"f39321c42b205c771729b8455a75231e43d8bc1d48691b0f9930250ca45bae57"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:04.902616+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f56d97f6-669b-44a8-88e2-27182fd04811', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste', 'active', NULL, '2026-03-15T16:16:05.398038+00:00', '{"id":"f56d97f6-669b-44a8-88e2-27182fd04811","title":"Freiwilligendienste","summary":{"de":"Rund 100.000 Menschen leisten Jahr für Jahr einen Freiwilligendienst. Politische Aufmerksamkeit gilt vor allem finanziellen und organisatorischen..."},"content":{"de":"Die Jugendfreiwilligendienste Nach der Schulzeit etwas Neues ausprobieren und gleichzeitig Gutes tun: Knapp 55.000 Jugendliche und junge Erwachsene verwirklichen diesen Wunsch jedes Jahr. Nach der Schulzeit etwas Neues ausprobieren und gleichzeitig Gutes tun: Knapp 55.000 Jugendliche und junge Erwachsene verwirklichen diesen Wunsch jedes Jahr. Der Bundesfreiwilligendienst Der Bundesfreiwilligendienst ist eine Erfolgsgeschichte. Viele Bürgerinnen und Bürger nutzen die Möglichkeit, sich für die Gesellschaft und das Gemeinwohl zu engagieren. Der Bundesfreiwilligendienst ist eine Erfolgsgeschichte. Viele Bürgerinnen und Bürger nutzen die Möglichkeit, sich für die Gesellschaft und das Gemeinwohl zu engagieren. Wie ermöglicht ein Freiwilliges Ökologisches Jahr positive Demokratie- und Selbstwirksamkeitserfahrungen? Zu diesen und weiteren Fragen tauschte sich Michael Brand auf der Fachtagung 2026 aus. Wie können junge Menschen sich über Schule hinaus bilden? Wie können junge Menschen einen Beitrag für eine nachhaltige Zukunft leisten? Diese und weitere Fragen diskutierte Karin Prien bei der Jahrestagung 2025 Freiwilliges Soziales Jahr."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:05.398038+00:00","lastSeen":"2026-03-15T16:16:05.398038+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste","crawledAt":"2026-03-15T16:16:05.398038Z","crawlId":"aid-seeded-1773591365","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"797ccb3a15c19b6d77f9eb39f2629181efd64d8794c334cf5734659e2f644fb1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:05.398038+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('11275f2e-3c96-42f4-ac4c-b177ad6d0aa0', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser', 'active', NULL, '2026-03-15T16:16:05.942112+00:00', '{"id":"11275f2e-3c96-42f4-ac4c-b177ad6d0aa0","title":"Mehrgenerationenhäuser","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Programmschwerpunkte Um die Herausforderungen vor Ort zu meistern und passende Lösungen zu entwickeln, brauchen die Mehrgenerationenhäuser Handlungsspielraum. Deshalb legen die Häuser die Schwerpunkte ihrer Arbeit selbst fest. Um die Herausforderungen vor Ort zu meistern und passende Lösungen zu entwickeln, brauchen die Mehrgenerationenhäuser Handlungsspielraum. Deshalb legen die Häuser die Schwerpunkte ihrer Arbeit selbst fest. Die Querschnittsaufgaben Generationenübergreifende Arbeit, Teilhabe, freiwilliges Engagement und Sozialraumorientierung: Das sind die vier Querschnittsaufgaben der Mehrgenerationenhäuser. Generationenübergreifende Arbeit, Teilhabe, freiwilliges Engagement und Sozialraumorientierung: Das sind die vier Querschnittsaufgaben der Mehrgenerationenhäuser. Am 23. September hielt der Parlamentarische Staatssekretär Michael Brand das Grußwort bei der Ideenkonferenz des Bundesprogramms Mehrgenerationenhaus mit dem Thema \"Gemeinsam stark - Lokale Kooperationen und Fundraising für nachhaltigen Erfolg\". Die Aktionstage finden unter dem Motto \"Nachbarschaft mit Herz und Hand\" bundesweit statt und bieten die Möglichkeit, sich über die Arbeit der Mehrgenerationenhäuser zu informieren. Karin Prien eröffnete sie mit einer Kochaktion in Berlin."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:05.942112+00:00","lastSeen":"2026-03-15T16:16:05.942112+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser","crawledAt":"2026-03-15T16:16:05.942112Z","crawlId":"aid-seeded-1773591365","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"8f47bea6f495cdb551b0175de31c99b6325d199d81583884f63715f2ae1c0c7c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:05.942112+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bcd5663a-7b97-4066-9f47-7211f6671975', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/chancen-und-teilhabe-fuer-familien', 'active', NULL, '2026-03-15T16:16:06.898642+00:00', '{"id":"bcd5663a-7b97-4066-9f47-7211f6671975","title":"Chancen und Teilhabe für Familien","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Unterstützung für Allein- und Getrennterziehende In jeder fünften Familie in Deutschland werden die Kinder von ihren Eltern allein oder getrennt erzogen. Diese Familien stehen vor besonderen Herausforderungen und brauchen eine zielgerichtete Unterstützung. In jeder fünften Familie in Deutschland werden die Kinder von ihren Eltern allein oder getrennt erzogen. Diese Familien stehen vor besonderen Herausforderungen und brauchen eine zielgerichtete Unterstützung. Familien mit Migrationshintergrund Mehr als jede vierte Familie in Deutschland hat eine Einwanderungsgeschichte. Ihre Integration zu unterstützen, ist ein Anliegen des Bundesfamilienministeriums. Mehr als jede vierte Familie in Deutschland hat eine Einwanderungsgeschichte. Ihre Integration zu unterstützen, ist ein Anliegen des Bundesfamilienministeriums. Familienbildung und Familienberatung Die Erziehung und Förderung der eigenen Kinder sowie der Umgang mit Problemen und Konflikten sind oft mit vielen Fragen verbunden. Eltern können auf vielfältige Unterstützungsangebote zurückgreifen. Die Erziehung und Förderung der eigenen Kinder sowie der Umgang mit Problemen und Konflikten sind oft mit vielen Fragen verbunden. Eltern können auf vielfältige Unterstützungsangebote zurückgreifen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/chancen-und-teilhabe-fuer-familien","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:06.898642+00:00","lastSeen":"2026-03-15T16:16:06.898642+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/chancen-und-teilhabe-fuer-familien","crawledAt":"2026-03-15T16:16:06.898642Z","crawlId":"aid-seeded-1773591366","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"09d1998a198554aa353123e318f0a7127d8061ed0b2a58d45ca05937de6f0903"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:06.898642+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d3c7bc30-7da2-4aa4-b84e-ba9e784d34cf', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familie-und-arbeitswelt', 'active', NULL, '2026-03-15T16:16:07.388775+00:00', '{"id":"d3c7bc30-7da2-4aa4-b84e-ba9e784d34cf","title":"Familie und Arbeitswelt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Erfolgsfaktor Familie Ziel des Unternehmensprogramms ist es, Familienfreundlichkeit zu einem Markenzeichen der deutschen Wirtschaft zu machen. Ziel des Unternehmensprogramms ist es, Familienfreundlichkeit zu einem Markenzeichen der deutschen Wirtschaft zu machen. Lokale Bündnisse für Familie In Lokalen Bündnissen für Familie engagieren sich verschiedenste Akteure gemeinsam für mehr Familienfreundlichkeit vor Ort. In Lokalen Bündnissen für Familie engagieren sich verschiedenste Akteure gemeinsam für mehr Familienfreundlichkeit vor Ort. Elterngeldrechner Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link) Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link)"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familie-und-arbeitswelt","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:07.388775+00:00","lastSeen":"2026-03-15T16:16:07.388775+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familie-und-arbeitswelt","crawledAt":"2026-03-15T16:16:07.388775Z","crawlId":"aid-seeded-1773591367","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"5ff56bf143a4495c54fba88bd396a5e54e5d52591944ae2174073d0feffd57c6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:07.388775+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('402306bc-9c63-41a3-a58d-0b1a09747e49', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen', 'active', NULL, '2026-03-15T16:15:14.033962+00:00', '{"id":"402306bc-9c63-41a3-a58d-0b1a09747e49","title":"Familienleistungen","summary":{"de":"Familien benötigen wirtschaftliche Stabilität. Hier finden Sie Informationen zu Leistungen wie beispielsweise Kindergeld, Kinderzuschlag oder Elterngeld."},"content":{"de":"Elterngeld Das Elterngeld unterstützt Mütter und Väter, die nach der Geburt eine Zeitlang zu Hause bleiben oder weniger in ihrem Beruf arbeiten möchten. Die unterschiedlichen Varianten Basiselterngeld, ElterngeldPlus und Partnerschaftsbonus bieten... Das Elterngeld unterstützt Mütter und Väter, die nach der Geburt eine Zeitlang zu Hause bleiben oder weniger in ihrem Beruf arbeiten möchten. Die unterschiedlichen Varianten Basiselterngeld, ElterngeldPlus und Partnerschaftsbonus bieten... Elternzeit Elternzeit ist eine Auszeit vom Berufsleben für Eltern, die ihre Kinder selbst betreuen und erziehen. Jeder Elternteil hat einen Anspruch auf bis zu drei Jahre Elternzeit. Elternzeit ist eine Auszeit vom Berufsleben für Eltern, die ihre Kinder selbst betreuen und erziehen. Jeder Elternteil hat einen Anspruch auf bis zu drei Jahre Elternzeit. Elterngeldrechner Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link) Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link)"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:14.033962+00:00","lastSeen":"2026-03-15T16:15:14.033962+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen","crawledAt":"2026-03-15T16:15:14.033962Z","crawlId":"aid-seeded-1773591314","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"36a30e13e80c26800dd45f6a1f40ef9757a395d3faa91c984ec18f8e9570d2f0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:14.033962+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8b613997-b9ca-4ec9-ac98-b6251771059d', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/kinderzuschlag-und-leistungen-fuer-bildung-und-teilhabe-73906', 'active', NULL, '2026-03-15T16:15:14.253549+00:00', '{"id":"8b613997-b9ca-4ec9-ac98-b6251771059d","title":"Kinderzuschlag und Leistungen für Bildung und Teilhabe","summary":{"de":"Wenn Ihr Einkommen nicht ausreicht, haben Sie eventuell Anspruch auf finanzielle Unterstützung durch den Kinderzuschlag. Informationen des Bundesfamilienministeriums."},"content":{"de":"Der Kinderzuschlag unterstützt Alleinerziehende und Familien mit kleinen Einkommen. Den Antrag können Sie online stellen. Der Kinderzuschlag ist eine zusätzliche finanzielle Unterstützung für erwerbstätige Eltern, die genug für sich selbst verdienen, aber bei denen es nicht oder nur knapp reicht, um auch für den gesamten Bedarf der Familie aufzukommen. Der Kinderzuschlag beträgt ab dem 1. Januar 2025 bis zu 297 Euro monatlich je Kind und deckt zusammen mit dem Kindergeld den Bedarf eines Kindes. Wer den Kinderzuschlag erhält, hat außerdem Anspruch auf Leistungen für Bildung und Teilhabe und kann sich von Kitagebühren befreien lassen. Der Kinderzuschlag wird für jedes unverheiratete Kind bis 25 Jahre gezahlt, wenn Sie die folgenden Voraussetzungen erfüllen: Ihr Kind lebt in Ihrem Haushalt und Sie erhalten Kindergeld für es."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/kinderzuschlag-und-leistungen-fuer-bildung-und-teilhabe-73906","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:14.253549+00:00","lastSeen":"2026-03-15T16:15:14.253549+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/kinderzuschlag-und-leistungen-fuer-bildung-und-teilhabe-73906","crawledAt":"2026-03-15T16:15:14.253549Z","crawlId":"aid-seeded-1773591314","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"25794e8d523298fd868f8f7356e2030e55f27bdc1b0e89e24825b4fed0039d38"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:14.254550+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b9f1809e-1b43-463a-b12d-34cf37b20cf7', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/mutterschaftsleistungen/mutterschutz-und-mutterschaftsleistungen-73754', 'active', NULL, '2026-03-15T16:15:15.328107+00:00', '{"id":"b9f1809e-1b43-463a-b12d-34cf37b20cf7","title":"Mutterschutz und Mutterschaftsleistungen","summary":{"de":"Das Mutterschaftsgeld sichert Ihr Einkommen als werdende oder junge Mutter in der Zeit, in der eine Beschäftigung aus Schutzgründen verboten ist."},"content":{"de":"Abhängig beschäftigte Frauen sind am Arbeitsplatz während der Schwangerschaft und in der Zeit nach der Geburt umfassend geschützt - vor gesundheitlichen Gefährdungen am Arbeitsplatz, vor einer Kündigung und vor Einkommensverlusten. Ziel des Mutterschutzes ist es, die Gesundheit der Frau und die ihres (ungeborenen) Kindes während der Schwangerschaft, nach der Geburt und in der Stillzeit zu schützen und gleichzeitig ihre Weiterbeschäftigung zu ermöglichen. Dabei soll sie auch vor Benachteiligungen geschützt werden. Neben den abhängig beschäftigten Frauen gibt es weitere geschützte Gruppen, zum Beispiel Schülerinnen und Studentinnen. Für Selbstständige gilt das Mutterschutzgesetz grundsätzlich nicht. ein Beschäftigungsverbot in den Wochen vor und nach der Geburt, die Sicherung des Einkommens während des Beschäftigungsverbots, eine bezahlte Freistellung für Untersuchungen und zum Stillen. Für die Zeit unmittelbar vor und nach der Geburt sieht das Mutterschutzgesetz Schutzfristen für alle abhängig beschäftigten Frauen vor. Diese Schutzfristen beginnen grundsätzlich sechs Wochen vor dem errechneten Entbindungstermin und enden im Regelfall acht Wochen nach der Geburt. Dabei handelt es sich um ein Beschäftigungsverbot, dessen Adressat der Arbeitgeber ist. In der Zeit vor der Geburt kann sich die Frau jedoch selbstbestimmt zur Arbeitsleistung bereit erklären."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/mutterschaftsleistungen/mutterschutz-und-mutterschaftsleistungen-73754","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:15.328107+00:00","lastSeen":"2026-03-15T16:15:15.328107+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/mutterschaftsleistungen/mutterschutz-und-mutterschaftsleistungen-73754","crawledAt":"2026-03-15T16:15:15.328107Z","crawlId":"aid-seeded-1773591315","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"730385b268f7d94e1c94999fb475b71a99cf28951a3ad213fe3b84a1222c3ca7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:15.328107+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6ee909fd-748f-4e9b-9f1a-1566da274878', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/unterhaltsvorschuss', 'active', NULL, '2026-03-15T16:15:14.810769+00:00', '{"id":"6ee909fd-748f-4e9b-9f1a-1566da274878","title":"Unterhaltsvorschuss","summary":{"de":"Wenn Sie keinen oder unregelmäßig Unterhalt erhalten, können Sie Unterhaltsvorschuss beantragen. Hier finden Sie Informationen des Bundesfamilienministeriums."},"content":{"de":"Unterhaltsvorschuss ist eine besondere Hilfe für Kinder von Alleinerziehenden. Alleinerziehende, die für ihr Kind keinen oder nicht regelmäßig Unterhalt erhalten, können Unterhaltsvorschuss beantragen. Alleinerziehende erziehen ihre Kinder meist unter erschwerten Bedingungen. Die Situation verschärft sich noch, wenn das Kind keinen oder nicht regelmäßig Unterhalt von dem anderen Elternteil erhält oder dieser nicht rechtzeitig gezahlt wird. Diese besondere Lebenssituation soll mit der Unterhaltsleistung nach dem Unterhaltsvorschussgesetz erleichtert werden. Anspruch auf Unterhaltsvorschuss haben Kinder, die bei einem alleinerziehenden Elternteil leben und keinen oder keinen regelmäßigen Unterhalt von dem anderen Elternteil erhalten. Hierbei gibt es keine Einkommensgrenze für den alleinerziehenden Elternteil. Eine gerichtliche Entscheidung über den Unterhalt gegen den anderen Elternteil ist nicht erforderlich. Ist der andere Elternteil ganz oder teilweise leistungsfähig, wird er vom Staat in Höhe des gezahlten Unterhaltsvorschusses in Anspruch genommen. Bis zur Vollendung des 12. Lebensjahres (12. Geburtstag) können Kinder ohne zeitliche Einschränkung Unterhaltsvorschuss erhalten. Kinder im Alter von zwölf Jahren bis zum vollendeten 18. Lebensjahr (18. Geburtstag) können ebenfalls Unterhaltsvorschuss erhalten. Voraussetzung dafür ist, dass sie nicht auf Leistungen nach dem Zweiten Buch Sozialgesetzbuch (SGB II) angewiesen sind oder dass der alleinerziehende Elternteil im SGB II-Bezug mindestens 600 Euro brutto verdient."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/unterhaltsvorschuss","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:15:14.810769+00:00","lastSeen":"2026-03-15T16:15:14.810769+00:00","sourceUnavailable":false,"aidType":"financial","modality":"application","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/unterhaltsvorschuss/unterhaltsvorschuss-73558","crawledAt":"2026-03-15T16:15:14.810769Z","crawlId":"aid-seeded-1773591314","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"dd3be165f331ba984ee0629185602066c63631b0d5924e2d4efbf2d844c45608"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:15:14.810769+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2f0ef62f-2e7f-4eb8-bf8a-3b4941734bb6', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/unterhaltsvorschuss/unterhaltsvorschuss-73558', 'active', NULL, '2026-03-01T20:12:00Z', '{"id":"2f0ef62f-2e7f-4eb8-bf8a-3b4941734bb6","title":"Unterhaltsvorschuss","translations":{"de-LEICHT":{"title":"Vorschuss bei fehlendem Unterhalt","timestamp":"2026-03-01T20:12:00Z","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/unterhaltsvorschuss/unterhaltsvorschuss-73558","crawledAt":"2026-03-01T20:12:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Unterhaltsvorschuss hilft Kindern von Alleinerziehenden, wenn Unterhalt ausbleibt oder unregelmäßig gezahlt wird."},"content":{"de":"Die Informationsseite erklärt den Charakter der Leistung als verlässliche Unterstützung in Ausfallsituationen. Sie gibt einen offiziellen Einstieg in Anspruchskontext und Verfahrenslogik."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/unterhaltsvorschuss/unterhaltsvorschuss-73558","topics":["financial_support","family"],"tags":["means_tested","application_required"],"targetGroups":["single_parents","families"],"status":"active","aidType":"financial","modality":"application","providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","firstSeen":"2026-03-01T20:12:00Z","lastSeen":"2026-03-01T20:12:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/familienleistungen/unterhaltsvorschuss/unterhaltsvorschuss-73558","crawlId":"manual-curation-20260301-realdata-v1","checksum":"8f8b614f4ffad84bb7a3f2b2c70d269115ee9b178a8d107a5f9082cf3f8c1c2b","crawledAt":"2026-03-01T20:12:00Z"},"qualityScores":{"iqs":79.6,"ais":49.2,"computedAt":"2026-03-01T20:12:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0835147e-a9fe-43a6-a638-e40f8e9173d9', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/karin-prien-startet-wettbewerb-fuer-kleine-und-mittlere-unternehmen-281112', 'active', NULL, '2026-03-15T16:16:07.879085+00:00', '{"id":"0835147e-a9fe-43a6-a638-e40f8e9173d9","title":"Karin Prien startet Wettbewerb für kleine und mittlere Unternehmen","summary":{"de":"Bundesfamilienministerin Karin Prien hat den Wettbewerb \"Kleine Lösungen - große Wirkung\" gestartet. Gesucht werden kleine und mittlere Unternehmen mit kreativen Ideen für die Vereinbarkeit von Familie und Beruf."},"content":{"de":"Bundesfamilienministerin Karin Prien hat am 4. März den Start für den bundesweiten Unternehmenswettbewerb \"Kleine Lösungen - große Wirkung. Kleine und mittlere Unternehmen (KMU) gewinnen mit Vereinbarkeit\" bekanntgegeben. Der Wettbewerb richtet sich an Unternehmen mit bis zu 250 Beschäftigten, die gute Maßnahmen zur besseren Vereinbarkeit von Familie und Beruf entwickelt und umgesetzt haben. Karin Prien: \" Auch und gerade in der aktuellen Lage unserer Wirtschaft ist die Vereinbarkeit von Beruf und Familie ein Motor für Veränderungen und bietet Chancen für die Gewinnung und Bindung von Fachkräften. Viele kleine und mittlere Unternehmen zeigen bereits heute, wie sich Familienfreundlichkeit ohne großen Aufwand, aber mit guten Ideen, viel Innovationskraft und Kreativität erfolgreich umsetzen lässt. Solche Konzepte würdigen wir mit unserem Wettbewerb und geben sie als Inspiration an andere Unternehmen weiter. Der demografische Wandel erfordert, Vereinbarkeit als wesentlichen Bestandteil einer modernen Arbeitswelt zu verankern.\" Unternehmen mit bis zu 250 Beschäftigten können sich bis zum 24. April 2026 über die Website des Programms \"Erfolgsfaktor Familie\" bewerben. Die Auszeichnung der Preisträgerinnen und Preisträger erfolgt im Rahmen des Unternehmenstags \"Erfolgsfaktor Familie\" am 11. September 2026 in Berlin. Die Ehrung nehmen Bundesfamilienministerin Karin Prien sowie der Präsident der Deutschen Industrie- und Handelskammer, Peter Adrian, vor. Ziel des Wettbewerbs ist es, konkrete betriebliche Lösungen zu zeigen, die Beschäftigten zugutekommen und zugleich die Wettbewerbsfähigkeit der Unternehmen stärken. Ausgezeichnet werden Ansätze, die im jeweiligen betrieblichen Zusammenhang wirksam sind und sich durch Umsetzbarkeit und Praxisnähe auszeichnen. Der Wettbewerb soll dazu beitragen, erfolgreiche Modelle aus KMU bundesweit bekannt zu machen und Impulse für andere Unternehmen zu geben. Der Wettbewerb ist offen gestaltet und sieht keine festen Kategorien vor. Entscheidend sind die Passgenauigkeit und die nachweisbare Wirkung der jeweiligen Maßnahme. Eingereicht werden können zum Beispiel flexible Arbeitszeitmodelle, spezielle Angebote für Väter oder pflegende Beschäftigte, betriebliche Unterstützungsangebote wie Hausaufgabenhilfen oder Kooperationen mit anderen Unternehmen zur Organisation von Ferienbetreuung. Der Unternehmenswettbewerb ist Teil des Unternehmensprogramms \"Erfolgsfaktor Familie\" des Bundesbildungs- und -familienministeriums. Partner des Programms sind die Spitzenverbände der deutschen Wirtschaft wie beispielsweise die Bundesvereinigung der Deutschen Arbeitgeberverbände (BDA), die Deutsche Industrie- und Handelskammer (DIHK), der Zentralverband des Deutschen Handwerks (ZDH), der Deutsche Gewerkschaftsbund (DGB) sowie die Branchen- und Fachverbände Bundesverband der Personalmanagerinnen (BPM), Verband der Unternehmerinnen in Deutschland (VdU), Deutscher Mittelstands-Bund (DMB) und Verband der Internetwirtschaft e.V. (eco)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/karin-prien-startet-wettbewerb-fuer-kleine-und-mittlere-unternehmen-281112","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:07.879085+00:00","lastSeen":"2026-03-15T16:16:07.879085+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/karin-prien-startet-wettbewerb-fuer-kleine-und-mittlere-unternehmen-281112","crawledAt":"2026-03-15T16:16:07.879085Z","crawlId":"aid-seeded-1773591367","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"f794686d1fa83d6b74f111c57e7abd8f27efe8f8837fe97e9b723eb42d35faad"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:07.879085+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('15bc8ed3-2f69-427f-8447-30ed6584728e', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung', 'active', NULL, '2026-03-15T16:16:08.395184+00:00', '{"id":"15bc8ed3-2f69-427f-8447-30ed6584728e","title":"Gute Kinderbetreuung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"KiTa-Qualität Die Qualitätsentwicklung in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe, die der Bund mit dem KiTa-Qualitätsgesetz und weiteren Initiativen unterstützt. Die Qualitätsentwicklung in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe, die der Bund mit dem KiTa-Qualitätsgesetz und weiteren Initiativen unterstützt. Kita-Ausbau Um eine gute frühkindliche Bildung, Betreuung und Erziehung sicherzustellen, unterstützt der Bund die Länder beim Ausbau und der Weiterentwicklung von Angeboten der Kindertagesbetreuung. Um eine gute frühkindliche Bildung, Betreuung und Erziehung sicherzustellen, unterstützt der Bund die Länder beim Ausbau und der Weiterentwicklung von Angeboten der Kindertagesbetreuung. Ganztagsbetreuung für Grundschulkinder Ab 2026 gibt es einen Rechtsanspruch auf Ganztagsbetreuung für Grundschulkinder. Das stärkt die Kinder und hilft den Eltern bei der Vereinbarkeit von Familie und Beruf. Ab 2026 gibt es einen Rechtsanspruch auf Ganztagsbetreuung für Grundschulkinder. Das stärkt die Kinder und hilft den Eltern bei der Vereinbarkeit von Familie und Beruf."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:08.395184+00:00","lastSeen":"2026-03-15T16:16:08.395184+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung","crawledAt":"2026-03-15T16:16:08.395184Z","crawlId":"aid-seeded-1773591368","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"4467524438ce8695ae1e2718ee9b69df0b566508f02dc3e9196d0a0ce689adff"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:08.395184+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('93a4c985-d18c-45d3-acf4-bb6d9bec3db7', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet', 'active', NULL, '2026-03-15T16:16:08.899341+00:00', '{"id":"93a4c985-d18c-45d3-acf4-bb6d9bec3db7","title":"Mehr Qualität in der frühen Bildung","summary":{"de":"Kitas sind ein Bildungs- und Zukunftsort. Um die Qualität der Kindertagesbetreuung und der Kindertagespflege weiterzuentwickeln und zu stärken..."},"content":{"de":"Für gute Kinderbetreuung bundesweit: das KiTa-Qualitätsgesetz Die Weiterentwicklung der Qualität in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe und gemeinsames Ziel von Bund, Ländern und Kommunen. Hier setzt das KiTa-Qualitätsgesetz an. Die Weiterentwicklung der Qualität in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe und gemeinsames Ziel von Bund, Ländern und Kommunen. Hier setzt das KiTa-Qualitätsgesetz an. Die Verträge der Bundesländer zum KiTa-Qualitäts- und -Teilhabeverbesserungsgesetz Um die Qualität in der frühkindlichen Bildung, Betreuung und Erziehung zu verbessern, unterstützt der Bund die Länder im Rahmen des KiTa-Qualitäts- und Teilhabeverbesserungsgesetzes seit 2019 mit zusätzlichen Mitteln. Um die Qualität in der frühkindlichen Bildung, Betreuung und Erziehung zu verbessern, unterstützt der Bund die Länder im Rahmen des KiTa-Qualitäts- und Teilhabeverbesserungsgesetzes seit 2019 mit zusätzlichen Mitteln. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun. Kindern ein Zuhause geben, wo sie Zuwendung, Stabilität und \"Zeit, die prägt\" erfahren können: Eine neue Kampagne des Bundesfamilienministeriums rückt Pflegeelternschaft stärker ins öffentliche Bewusstsein und will neue Pflegefamilien gewinnen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:08.899341+00:00","lastSeen":"2026-03-15T16:16:08.899341+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet","crawledAt":"2026-03-15T16:16:08.899341Z","crawlId":"aid-seeded-1773591368","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"f8b135788b5f9e1010c09f5e48681173874e90ea74b96c96e2735eea2d122e34"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:08.899341+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('53f21a90-0c2c-4a02-b417-6c702b51af77', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/nationaler-aktionsplan-kinderchancen', 'active', NULL, '2026-03-15T16:16:09.406542+00:00', '{"id":"53f21a90-0c2c-4a02-b417-6c702b51af77","title":"Nationaler Aktionsplan \"Neue Chancen für Kinder in Deutschland\"","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Was ist der Nationale Aktionsplan? Der Nationale Aktionsplan soll die Zugänge benachteiligter Kinder und Jugendlicher in fünf Handlungsfeldern verbessern. Der Nationale Aktionsplan soll die Zugänge benachteiligter Kinder und Jugendlicher in fünf Handlungsfeldern verbessern. Wer wirkt wie am Nationalen Aktionsplan mit? Ein Ausschuss begleitet die Umsetzung und Weiterentwicklung des Nationalen Aktionsplans. Ein Ausschuss begleitet die Umsetzung und Weiterentwicklung des Nationalen Aktionsplans. In welchem europäischen Kontext steht der Nationale Aktionsplan? Die Kindergarantie der Europäischen Union ist eine wichtige Grundlage für den Aktionsplan. Die Kindergarantie der Europäischen Union ist eine wichtige Grundlage für den Aktionsplan."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/nationaler-aktionsplan-kinderchancen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:09.406542+00:00","lastSeen":"2026-03-15T16:16:09.406542+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/nationaler-aktionsplan-kinderchancen","crawledAt":"2026-03-15T16:16:09.406542Z","crawlId":"aid-seeded-1773591369","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"39a3effcff96c538e4e616037aee7b66a6455b697b3c59f6e427d899ae90eed5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:09.406542+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('20e1b1e9-a477-43e3-828f-da96acf1757c', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/neuer-katalog-urlaub-mit-der-familie-erschienen-279088', 'active', NULL, '2026-03-15T16:16:09.885583+00:00', '{"id":"20e1b1e9-a477-43e3-828f-da96acf1757c","title":"Neuer Katalog \"Urlaub mit der Familie\" erschienen","summary":{"de":"Der neue Urlaubskatalog der Bundesarbeitsgemeinschaft Familienerholung für 2026/2027 enthält rund 80 Familienferienstätten, die Familien unabhängig vom Einkommen einen gemeinsamen Urlaub ermöglichen."},"content":{"de":"Der Jahresanfang ist für viele Familien der ideale Zeitpunkt, um den Sommer- oder Herbsturlaub zu planen. Der am 16. Januar veröffentlichte Katalog \"Urlaub mit der Familie 2026/2027\" der Bundesarbeitsgemeinschaft Familienerholung e.V. bietet eine wertvolle Orientierung. Der Katalog stellt zertifizierte Familienferienstätten in ganz Deutschland vor und informiert umfassend über Angebote, Ausstattung, besondere Schwerpunkte sowie Freizeit- und Erholungsmöglichkeiten und sortiert nach Urlaubsregionen. Ob Meer, Berge oder Naturregionen - Familien finden hier familiengerechte Unterkünfte, Ferienhäuser und Apartments mit und ohne Verpflegung sowie Angebote mit Kinderbetreuung und vielfältigen Freizeitaktivitäten. Der Katalog lässt sich auch gezielt nach barrierefreien und barrierearmen Unterkünften durchsuchen. Im Mittelpunkt steht das Ziel, bezahlbare Erholung für alle Familien zu ermöglichen - unabhängig von Einkommen oder Lebenssituation. Viele Familienferienstätten verzichten auch in der Hochsaison auf Preissteigerungen. Zudem unterstützen zahlreiche Bundesländer den Aufenthalt durch Zuschüsse. Ergänzt durch Kinderseiten, praktische Hinweise und anschauliche Einblicke hilft der Katalog Familien dabei, unter den rund 80 gemeinnützigen Familienferienstätten in ganz Deutschland frühzeitig den passenden Urlaubsort zu finden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/neuer-katalog-urlaub-mit-der-familie-erschienen-279088","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:09.885583+00:00","lastSeen":"2026-03-15T16:16:09.885583+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/neuer-katalog-urlaub-mit-der-familie-erschienen-279088","crawledAt":"2026-03-15T16:16:09.885583Z","crawlId":"aid-seeded-1773591369","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"dc36b7c72e5ec70353338c9a3358c0cddb200a027b0810aadcba012e78f1bd6f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:09.885583+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c506fc92-db49-4018-aba8-4b9f8c2f5cc4', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch', 'active', NULL, '2026-03-15T16:16:10.425314+00:00', '{"id":"c506fc92-db49-4018-aba8-4b9f8c2f5cc4","title":"Schwangerschaft und Kinderwunsch","summary":{"de":"Eine Schwangerschaft kann werdende Eltern vor Herausforderungen stellen. Hilfe erhalten sie durch die Bundesstiftung Mutter und Kind. Auch Paare mit..."},"content":{"de":"Familienplanung von Frauen und Männern Schwangere oder Männer und Frauen mit Kinderwunsch stehen oft vor vielen Fragen. Ein dichtes Netz von Beratungsstellen und Online-Angebote informiert über Familienplanung, Schwangerschaft und Verhütungsmöglichkeiten. Schwangere oder Männer und Frauen mit Kinderwunsch stehen oft vor vielen Fragen. Ein dichtes Netz von Beratungsstellen und Online-Angebote informiert über Familienplanung, Schwangerschaft und Verhütungsmöglichkeiten. Ungewollte Kinderlosigkeit Der medizinische und technische Fortschritt ermöglicht vielen ungewollt kinderlosen Paaren die Erfüllung des Kinderwunsches. Viele Bundesländer unterstützen die Behandlung finanziell. Der medizinische und technische Fortschritt ermöglicht vielen ungewollt kinderlosen Paaren die Erfüllung des Kinderwunsches. Viele Bundesländer unterstützen die Behandlung finanziell. Informationsportal Kinderwunsch Das Informationsportal Kinderwunsch zeigt Beratungsangebote und finanzielle Fördermöglichkeiten für ungewollt kinderlose Paare auf. Das Informationsportal Kinderwunsch zeigt Beratungsangebote und finanzielle Fördermöglichkeiten für ungewollt kinderlose Paare auf."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:10.425314+00:00","lastSeen":"2026-03-15T16:16:10.425314+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch","crawledAt":"2026-03-15T16:16:10.425314Z","crawlId":"aid-seeded-1773591370","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"f265215a9dd9698bba0792d8052c68eada5a9278e80897babd89dcc4b2dcfe93"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:10.425314+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bda25a78-7f13-4f23-b538-08e1c996cc10', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik', 'active', NULL, '2026-03-15T16:16:10.995792+00:00', '{"id":"bda25a78-7f13-4f23-b538-08e1c996cc10","title":"Agenda für smarte Gesellschaftspolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Agenda für smarte Gesellschaftspolitik Überblick: Die neue Strategie für die digitale Gesellschaft Mit der \"Agenda für smarte Gesellschaftspolitik\" präsentiert das Bundesministerium für Bildung und Familie seine Vision für die digitale Gesellschaft von morgen. Ziel ist eine intelligente und innovative Digitalpolitik, die Mensch und Gemeinwohl in den Mittelpunkt stellt. Mit der \"Agenda für smarte Gesellschaftspolitik\" präsentiert das Bundesministerium für Bildung und Familie seine Vision für die digitale Gesellschaft von morgen. Ziel ist eine intelligente und innovative Digitalpolitik, die Mensch und Gemeinwohl in den Mittelpunkt stellt. Handlungsfeld 1: Smarte Lebensführung Mit Technik das Alltagsleben erleichtern Digitale Innovationen können die Vereinbarkeit von Familie und Beruf verbessern und ein längeres selbstbestimmtes Leben zu Hause ermöglichen. Wie smarte Lebensführung den Alltag erleichtert. Digitale Innovationen können die Vereinbarkeit von Familie und Beruf verbessern und ein längeres selbstbestimmtes Leben zu Hause ermöglichen. Wie smarte Lebensführung den Alltag erleichtert. Handlungsfeld 2: Digitale Teilhabe Digitalisierung als Chance für mehr Vielfalt und Teilhabe nutzen Bunter, freier und demokratischer kann die Gesellschaft durch die Digitalisierung werden. Aber nur, wenn alle mit anpacken und sich engagieren. Bunter, freier und demokratischer kann die Gesellschaft durch die Digitalisierung werden. Aber nur, wenn alle mit anpacken und sich engagieren."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:10.995792+00:00","lastSeen":"2026-03-15T16:16:10.995792+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik","crawledAt":"2026-03-15T16:16:10.995792Z","crawlId":"aid-seeded-1773591370","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"1a56e252215b2666fb7f3711e4c538bd7263a9a7f1a28789b5480d686fce8406"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:10.997404+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('91de6036-75f0-4eb4-96ee-30f64233bf03', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe', 'active', NULL, '2026-03-15T16:16:11.886069+00:00', '{"id":"91de6036-75f0-4eb4-96ee-30f64233bf03","title":"Politik für die Aufwertung sozialer Berufe","summary":{"de":"Soziale Berufe tragen zur Bildung, Gesundheit und Teilhabe bei und sichern ein gutes Zusammenleben"},"content":{"de":"Erzieherberufe - guter Einstieg und Aufstieg 3,7 Millionen Kinder nutzten im Jahr 2019 deutschlandweit Angebote der Kindertagesbetreuung. Sie wurden von insgesamt rund 676.000 Beschäftigten betreut und gefördert. 3,7 Millionen Kinder nutzten im Jahr 2019 deutschlandweit Angebote der Kindertagesbetreuung. Sie wurden von insgesamt rund 676.000 Beschäftigten betreut und gefördert. Pflegeausbildung - Berufsfeld Pflege Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der Pflegeberufe zu verbessern, wird die Pflegeausbildung reformiert. Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der Pflegeberufe zu verbessern, wird die Pflegeausbildung reformiert."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:11.886069+00:00","lastSeen":"2026-03-15T16:16:11.886069+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe","crawledAt":"2026-03-15T16:16:11.886069Z","crawlId":"aid-seeded-1773591371","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"93dd70f21315fd3aacfab04af933e6a3f1ced48a1456a295b8d58636d7e5f09c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:11.886069+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5380af77-f7c8-4ce1-83ce-69692a0c94a4', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/feministische-digitalpolitik', 'active', NULL, '2026-03-15T16:16:12.392844+00:00', '{"id":"5380af77-f7c8-4ce1-83ce-69692a0c94a4","title":"Feministische Digitalpolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Smarte Gesellschaftspolitik Digitalisierungspolitik ist Gesellschaftspolitik. Für ein gutes Zusammenleben in der digitalen Gesellschaft muss der technologische Wandel so geschehen, dass er den Menschen und der Gesellschaft dient. Digitalisierungspolitik ist Gesellschaftspolitik. Für ein gutes Zusammenleben in der digitalen Gesellschaft muss der technologische Wandel so geschehen, dass er den Menschen und der Gesellschaft dient. Dritter Gleichstellungsbericht Der Dritte Gleichstellungsbericht gibt Empfehlungen für eine gleichstellungsorientierte Digitalisierung. Der Dritte Gleichstellungsbericht gibt Empfehlungen für eine gleichstellungsorientierte Digitalisierung. Bundesstiftung Gleichstellung Im Dialog mit Zivilgesellschaft, Wirtschaft und Politik trägt die Bundesstiftung Gleichstellung dazu bei, die Gleichberechtigung von Frauen und Männern effektiver durchzusetzen. Im Dialog mit Zivilgesellschaft, Wirtschaft und Politik trägt die Bundesstiftung Gleichstellung dazu bei, die Gleichberechtigung von Frauen und Männern effektiver durchzusetzen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/feministische-digitalpolitik","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:12.392844+00:00","lastSeen":"2026-03-15T16:16:12.392844+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/feministische-digitalpolitik","crawledAt":"2026-03-15T16:16:12.392844Z","crawlId":"aid-seeded-1773591372","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"761c1424f7aa68c40b92f9cced7dcb9f3840cb7a91abc9afd95ecd1d2ef6e3fb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:12.392844+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('983ecb30-e41b-4c29-810d-2e39de31094d', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-und-arbeitswelt', 'active', NULL, '2026-03-15T16:16:12.930293+00:00', '{"id":"983ecb30-e41b-4c29-810d-2e39de31094d","title":"Wirtschaftliche Gleichstellung, Frauen und Arbeitswelt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Verschaffen Sie sich hier einen Überblick über regionale Unterschiede bei der Gleichstellung in Deutschland. Klicken Sie sich durch über 40 Indikatoren in unterschiedlichen Themenfeldern. Lohngerechtigkeit Die Lohnlücke zwischen Männern und Frauen hat vielschichtige Ursachen. Sie kann nur im Zusammenwirken verschiedener Maßnahmen verringert werden. Ein wichtiger Baustein ist das Gesetz zur Förderung der Transparenz in Entgeltstrukturen. Die Lohnlücke zwischen Männern und Frauen hat vielschichtige Ursachen. Sie kann nur im Zusammenwirken verschiedener Maßnahmen verringert werden. Ein wichtiger Baustein ist das Gesetz zur Förderung der Transparenz in Entgeltstrukturen. Entgelttransparenzgesetz Das Gesetz zur Förderung der Transparenz von Entgeltstrukturen ist zum 6. Juli 2017 in Kraft getreten. Es soll Frauen dabei unterstützen, ihren Anspruch auf gleiches Entgelt bei gleicher oder gleichwertiger Arbeit künftig besser durchzusetzen. Das Gesetz zur Förderung der Transparenz von Entgeltstrukturen ist zum 6. Juli 2017 in Kraft getreten. Es soll Frauen dabei unterstützen, ihren Anspruch auf gleiches Entgelt bei gleicher oder gleichwertiger Arbeit künftig besser durchzusetzen. Geschlechtergerechte Berufsorientierung fördern Mit der Bundesinitiative \"Klischeefrei\", dem Aktionstag Girls''Day und der Initiative YouCodeGirls fördert die Bundesregierung eine geschlechtergerechte Berufsorientierung und Berufsberatung."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-und-arbeitswelt","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:12.930293+00:00","lastSeen":"2026-03-15T16:16:12.930293+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-und-arbeitswelt","crawledAt":"2026-03-15T16:16:12.930293Z","crawlId":"aid-seeded-1773591372","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"a69c69047a00f593e004af759ea188f2c62051bc76d77c921a574a71d5d78924"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:12.930293+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fc6445c8-b934-422b-a340-2e4a32f2e353', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-vor-gewalt-schuetzen', 'active', NULL, '2026-03-15T16:16:13.429577+00:00', '{"id":"fc6445c8-b934-422b-a340-2e4a32f2e353","title":"Frauen vor Gewalt schützen","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Formen der Gewalt erkennen Gewalt hat viele Gesichter und sie begegnet uns überall: Zuhause, auf der Arbeit, im öffentlichen Raum, im Netz. Sie beginnt nicht erst mit Schlägen. Auch Bedrohungen, Beschimpfungen und Kontrolle sind Formen von Gewalt. Gewalt hat viele Gesichter und sie begegnet uns überall: Zuhause, auf der Arbeit, im öffentlichen Raum, im Netz. Sie beginnt nicht erst mit Schlägen. Auch Bedrohungen, Beschimpfungen und Kontrolle sind Formen von Gewalt. Hilfe und Beratung bei Gewalt Von Gewalt betroffene Frauen und Männer brauchen schnelle und unbürokratische Hilfe sowie qualifizierte Beratung und Unterstützung. Hier finden sie Anlaufstellen, an die sich auch Angehörige und Freunde sowie Fachkräfte wenden können. Von Gewalt betroffene Frauen und Männer brauchen schnelle und unbürokratische Hilfe sowie qualifizierte Beratung und Unterstützung. Hier finden sie Anlaufstellen, an die sich auch Angehörige und Freunde sowie Fachkräfte wenden können. Schutz und Beratung durch das Gewalthilfegesetz Das Gewalthilfegesetz sichert den Zugang zu Schutz- und Beratungsangeboten bei geschlechtsspezifischer und häuslicher Gewalt. Betroffene erhalten künftig die Hilfe und Unterstützung, die sie in ihrer individuellen Lage brauchen. Das Gewalthilfegesetz sichert den Zugang zu Schutz- und Beratungsangeboten bei geschlechtsspezifischer und häuslicher Gewalt. Betroffene erhalten künftig die Hilfe und Unterstützung, die sie in ihrer individuellen Lage brauchen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-vor-gewalt-schuetzen","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:13.429577+00:00","lastSeen":"2026-03-15T16:16:13.429577+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-vor-gewalt-schuetzen","crawledAt":"2026-03-15T16:16:13.429577Z","crawlId":"aid-seeded-1773591373","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"f403cf26d031b742d18e627c8f4e1b5b68e2267fcfd445f9edd76d32d0ef8501"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:13.429577+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7aa42364-37bc-4dc0-a995-852b0b59e462', 'aid', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap', 'active', NULL, '2026-03-15T16:16:13.901183+00:00', '{"id":"7aa42364-37bc-4dc0-a995-852b0b59e462","title":"Erwerbs- und Sorgearbeit gleichberechtigt gestalten","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Verschaffen Sie sich hier einen Überblick über regionale Unterschiede bei der Gleichstellung in Deutschland. Klicken Sie sich durch über 40 Indikatoren in unterschiedlichen Themenfeldern. Gender Care Gap - ein Indikator für die Gleichstellung Kindererziehung, Pflege von Angehörigen, Hausarbeit, Ehrenamt: Frauen wenden pro Tag im Durchschnitt 43,4 Prozent mehr Zeit für unbezahlte Sorgearbeit auf als Männer. Dieser Unterschied wird als Gender Care Gap bezeichnet. Kindererziehung, Pflege von Angehörigen, Hausarbeit, Ehrenamt: Frauen wenden pro Tag im Durchschnitt 43,4 Prozent mehr Zeit für unbezahlte Sorgearbeit auf als Männer. Dieser Unterschied wird als Gender Care Gap bezeichnet. Projekt erforscht Ungleichheiten bei der unbezahlten Sorgearbeit Der Gender Care Gap führt dazu, dass viele Frauen wirtschaftliche Nachteile haben. Für eine gerechte Verteilung der unbezahlten Sorgearbeit analysiert das Gender-Care-Gap-Projekt die Unterschiede und entwickelt Handlungsempfehlungen. Der Gender Care Gap führt dazu, dass viele Frauen wirtschaftliche Nachteile haben. Für eine gerechte Verteilung der unbezahlten Sorgearbeit analysiert das Gender-Care-Gap-Projekt die Unterschiede und entwickelt Handlungsempfehlungen. Wie können pflegende Angehörige im Alltag besser unterstützt werden? Unter anderem darum ging es bei einer internationalen Online-Konferenz zur Geschlechtergerechtigkeit in der Pflege."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:16:13.901183+00:00","lastSeen":"2026-03-15T16:16:13.901183+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap","crawledAt":"2026-03-15T16:16:13.901183Z","crawlId":"aid-seeded-1773591373","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmfsfj","providerName":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","providerLevel":"federal","checksum":"b9900ad11e5c251a0dfbbc417f18fb9c5effd6db1d44fcf9475e884b8dbd8541"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:16:13.901183+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
