INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('826e2115-ca4d-409b-a019-6bc74947291e', 'aid', 'https://www.hilfetelefon-schwangere.de/', 'active', NULL, '2026-03-15T16:26:16.301949+00:00', '{"id":"826e2115-ca4d-409b-a019-6bc74947291e","title":"Hilfetelefon","summary":{"de":"Wenn die Schwangerschaft zur Herausforderung wird, sind die Beraterinnen vom Hilfetelefon Schwangere in Not für Sie da."},"content":{"de":"Schwangere, ihr direktes Umfeld und auch Fachkräfte können sich vor und nach der Geburt rund um die Uhr an die Beraterinnen wenden, die passende Hilfsangebote kennen. Die Beraterinnen unterstützen Sie unabhängig von Geschlecht, Herkunft, Glaube, sexueller Orientierung und sexueller Identität. Sie beraten bei Bedarf auch rund um die Möglichkeit einer vertraulichen Geburt. Sie können einfach und sicher im Chat Kontakt zu einer Beraterin aufnehmen. Diese unterliegt der gesetzlichen Schweigepflicht und die Beratung läuft über eine verschlüsselte Verbindung. Ergebnisoffen, verständlich, anonym und vertraulich, immer erreichbar und in 19 Sprachen verfügbar: Deutsch, Englisch, Spanisch, Französisch, Albanisch, Arabisch, Bulgarisch, Persisch, Kurdisch, Polnisch, Rumänisch, Russisch, Serbisch. Türkisch, Ukrainisch, Chinesisch/Mandarin, Italienisch, Portugiesisch, Vietnamesisch Die qualifizierten Beraterinnen hören aufmerksam zu, vermitteln passende Hilfsangebote und den Kontakt zu Beratungsstellen in Ihrer Nähe. Wenden Sie sich vertraulich per E-Mail an unsere Beraterinnen. Auch auf diesem Weg ist die Beratung schnell, sicher und verschlüsselt. Ihre Identität bleibt geschützt."},"url":"https://www.hilfetelefon-schwangere.de/","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:16.301949+00:00","lastSeen":"2026-03-15T16:26:16.301949+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.hilfetelefon-schwangere.de/","crawledAt":"2026-03-15T16:26:16.301949Z","crawlId":"aid-seeded-1773591976","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"16f0ed13bc0aefcf4912c7e21886617d43ff92b8f1bc7f929c34e8df491f77ea"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:16.301949+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8942ac13-74e1-45f1-9abe-8a57fe52ef0e', 'aid', 'https://www.hilfetelefon.de/', 'active', NULL, '2026-03-15T16:25:56.946491+00:00', '{"id":"8942ac13-74e1-45f1-9abe-8a57fe52ef0e","title":"Das Hilfetelefon– Beratung und Hilfe für Frauen","summary":{"de":"Herzlich willkommen! Das Hilfetelefon \"Gewalt gegen Frauen\" ist ein bundesweites Beratungsangebot für Frauen, die Gewalt erlebt haben oder noch erleben. Unter der Nummer 116 016 und via Online-Beratung unterstuetzen wir Betroffene aller Nationalitaeten, mit und ohne Behinderung – 365 Tage im Jahr, rund um die Uhr. Auch Angehoerige, Freundinnen und Freunde sowie Fachkraefte beraten wir anonym und kostenfrei."},"content":{"de":"Unser Newsletter informiert Sie über aktuelle Themen, Aktionen und Hintergründe rund um das Hilfetelefon. Werden Sie jetzt Fan unserer Facebookseite und beteiligen Sie sich an unseren Mitmach-Aktionen. Weitersagen heißt helfen. Herzlich willkommen! Das Hilfetelefon \"Gewalt gegen Frauen\" ist ein bundesweites Beratungsangebot für Frauen, die Gewalt erlebt haben oder noch erleben. Unter der Nummer 116 016 und via Online-Beratung unterstützen wir Betroffene aller Nationalitäten, mit und ohne Behinderung – 365 Tage im Jahr, rund um die Uhr. Auch Angehörige, Freundinnen und Freunde sowie Fachkräfte beraten wir anonym und kostenfrei. Erfahren Sie mehr über die Highlights der diesjährigen Mitmachaktion: von der Plakataktion in Göppingen bis zur Aktions-Straßenbahn in Köln. Rückblick auf die Mitmachaktion 2025 Erfahren Sie mehr über die Highlights der diesjährigen Mitmachaktion: von der Plakataktion in Göppingen bis zur Aktions-Straßenbahn in Köln. Claudia Röske von der Stadt Rostock spricht im Interview über Maßnahmen und Tipps zum Orange Day 2025. Stadt Rostock bricht das Schweigen"},"url":"https://www.hilfetelefon.de/","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:25:56.946491+00:00","lastSeen":"2026-03-15T16:25:56.946491+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"http://www.hilfetelefon.de","crawledAt":"2026-03-15T16:25:56.946491Z","crawlId":"aid-seeded-1773591956","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"8a294208b24157c742572e2619ef5c9020c9288e4335e914165f6b28e5299899"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:25:56.946491+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d2fd74ff-f129-4ec9-8638-8e04de74c31b', 'aid', 'https://www.maennerhilfetelefon.de/', 'active', NULL, '2026-03-15T16:26:40.995907+00:00', '{"id":"d2fd74ff-f129-4ec9-8638-8e04de74c31b","title":"Gewalt schmerzt. Auch Männer.","summary":{"de":"Montag bis Donnerstag 08:00 - 20:00 Uhr Freitag 08:00 - 15:00 Uhr"},"content":{"de":"Montag bis Donnerstag 12:00 - 15:00 Uhr 17:00 - 19:00 Uhr Sie haben verschiedene Möglichkeiten, mit uns per Mail in Kontakt zu treten. Männern werden in ihrem Leben Opfer von Gewaltkriminalität Männern erlebt innerhalb einer Partnerschaft sexualisierte Gewalt Männern hat nach erlittener Partnerschaftsgewalt Kontakt zur Polizei Wir vom Hilfetelefon Gewalt an Männern haben einen weiten Gewaltbegriff: Für uns ist nicht ausschlaggebend, inwieweit das, was Sie erlitten haben, strafrechtlich relevant ist oder nicht. Entscheidend ist, dass Sie unter der Grenzverletzung, die Sie erfahren mussten, leiden und daher Unterstützung benötigen. Zögern Sie daher nicht, uns zu kontaktieren, wenn Sie irgendeine Form von Grenzverletzung erleben mussten, die Sie nicht zur Ruhe kommen lässt – ganz egal, was und wann es passiert ist! Beratung und Unterstützung gibt es etwa zu folgenden Formen von Gewalt:"},"url":"https://www.maennerhilfetelefon.de/","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:40.995907+00:00","lastSeen":"2026-03-15T16:26:40.995907+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.maennerhilfetelefon.de/","crawledAt":"2026-03-15T16:26:40.995907Z","crawlId":"aid-seeded-1773592000","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"d689a82b18ce050f6bffc7538a78ceaaa4a362723e1b5316e81a4d2f6b9721ac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:40.995907+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('45a7bb82-fb6d-4e85-bc7d-05f3e7a3c805', 'aid', 'https://www.nummergegenkummer.de/kinder-und-jugendberatung', 'active', NULL, '2026-03-15T17:47:29.346592+00:00', '{"id":"45a7bb82-fb6d-4e85-bc7d-05f3e7a3c805","title":"Beratung für Kinder und Jugendliche","summary":{"de":"Die Berater*innen von Nummer gegen Kummer e.V. bieten Kindern und Jugendlichen ein offenes Ohr für ihre Probleme, Ängste und Sorgen."},"content":{"de":"Die Berater*innen von Nummer gegen Kummer e.V. bieten Kindern und Jugendlichen ein offenes Ohr für ihre Probleme, Ängste und Sorgen."},"url":"https://www.nummergegenkummer.de/kinder-und-jugendberatung","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T17:47:29.346592+00:00","lastSeen":"2026-03-15T17:47:29.346592+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"nummergegenkummer.de","provenance":{"source":"https://www.nummergegenkummer.de/kinder-und-jugendberatung","crawledAt":"2026-03-15T17:47:29.347589Z","crawlId":"aid-seeded-1773596849","crawlerVersion":"0.1.0","sourceTier":"tier_2_ngo_watchdog","institutionType":"ngo","jurisdiction":"DE","sourceId":"nummergegenkummer_de","providerName":"nummergegenkummer.de","providerLevel":"unknown","checksum":"6facf6a3eec55adb472567be93fd7946f9ecebbcb55122a7125b015fd73f769f"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:47:29.347589+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('77ba428c-66fe-4ac5-98e1-d8649e8ea6fc', 'aid', 'https://www.wege-zur-pflege.de/wege-zur-pflege/pflegende-angehoerige/beratungsangebote/das-pflegetelefon-252968', 'active', NULL, '2026-03-15T16:26:44.549416+00:00', '{"id":"77ba428c-66fe-4ac5-98e1-d8649e8ea6fc","title":"Das Pflegetelefon","summary":{"de":"Das Pflegetelefon des Bundesseniorenministeriums bietet Beratung zu den Regelungen des Pflegezeit- und Familienpflegezeitgesetzes. Falls nötig – beispielsweise bei starker Belastung durch die Pflegesituation – vermittelt Sie das Pflegetelefon an andere Beratungsstellen."},"content":{"de":"Als pflegende Angehörige oder pflegender Angehöriger sind Sie – manchmal rund um die Uhr – für den von Ihnen gepflegten Menschen da. Nicht nur der Umgang mit unterschiedlichen Ansprüchen und Erwartungen aller Beteiligten ist eine herausfordernde Aufgabe, die nicht immer leicht ist. Auch die Balance zwischen Beruf, eigener Familie und der Pflege naher Angehöriger ist schwierig. Das Team des Pflegetelefons berät Sie zu Entlastungs- und Freistellungsmöglichkeiten zur besseren Vereinbarkeit von Pflege und Beruf. Dazu gehören zum Beispiel die Regelungen zu kurzzeitiger Arbeitsverhinderung, Pflegezeit oder Familienpflegezeit. Diese finden sich im Pflegezeitgesetz und Familienpflegezeitgesetz. Das Beratungsteam des Pflegetelefons erreichen Sie bundesweit unter der Telefonnummer 030 20 17 91 31. Derzeit berät Sie das Team von Montag bis Donnerstag zwischen 9:00 und 18:00 Uhr. Sie können auch eine E-Mail schreiben an: info@wege-zur-pflege.de. Wenn Sie sich durch die Pflegesituation stark belastet fühlen oder wenn es Konflikte mit der pflegebedürftigen Person oder innerhalb der Familie gibt, steht das Team des Pflegetelefons Ihnen zur Seite und vermittelt Sie bei Bedarf an geeignete Unterstützungsangebote. Das Angebot des Pflegetelefons ist anonym und vertraulich. Die Pflegekassen und die privaten Versicherungsunternehmen, die die private Pflege-Pflichtversicherung durchführen, sind verpflichtet, Ihnen Auskunft und umfassende Informationen zu erteilen. Sie können sich daher mit allen Fragen jederzeit an Ihre zuständige Pflegekasse oder Ihr privates Versicherungsunternehmen wenden."},"url":"https://www.wege-zur-pflege.de/wege-zur-pflege/pflegende-angehoerige/beratungsangebote/das-pflegetelefon-252968","topics":["financial_support","aid"],"tags":["aid"],"targetGroups":["families","single_parents","general_public"],"status":"active","firstSeen":"2026-03-15T16:26:44.549416+00:00","lastSeen":"2026-03-15T16:26:44.549416+00:00","sourceUnavailable":false,"aidType":"advisory","modality":"information","eligibilityCriteria":{"de":"Anspruch und Voraussetzungen sind in der jeweiligen Leistungsbeschreibung der Quelle dokumentiert."},"providingOrganization":"Unbekannte Organisation","provenance":{"source":"https://www.wege-zur-pflege.de/wege-zur-pflege/pflegende-angehoerige/beratungsangebote/das-pflegetelefon-252968","crawledAt":"2026-03-15T16:26:44.549416Z","crawlId":"aid-seeded-1773592004","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"e30f5a3d391e338ab8e1c5a409663d0a79b2617982f07083e1afe2036f20dac6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:26:44.549416+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
