INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1b3ef911-b62a-4b28-90eb-5880c5ca57b5', 'tools', 'https://familienportal.de/familienportal', 'active', NULL, '2026-03-15T17:26:48.373780+00:00', '{"id":"1b3ef911-b62a-4b28-90eb-5880c5ca57b5","title":"Familienportal","summary":{"de":"Das Familienportal bündelt alle relevanten Informationen zu staatlichen Familienleistungen, gesetzlichen Regelungen und Beratungsangeboten für Familien."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Hier finden Sie Informationen rund um die Familie. Informationen für Pflegefamilien Sie möchten Pflegeeltern werden? Wir informieren Sie über Voraussetzungen und Unterstützungsangebote für Pflegeeltern. Sie möchten Pflegeeltern werden? Wir informieren Sie über Voraussetzungen und Unterstützungsangebote für Pflegeeltern. Checklisten rund um die Geburt Bevor und nachdem ein Baby auf die Welt kommt, gibt es viel zu organisieren. Damit Sie nichts vergessen, gibt es unsere praktischen Checklisten: Digital oder zum Ausdrucken. Bevor und nachdem ein Baby auf die Welt kommt, gibt es viel zu organisieren. Damit Sie nichts vergessen, gibt es unsere praktischen Checklisten: Digital oder zum Ausdrucken."},"url":"https://familienportal.de/familienportal","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:48.373780+00:00","lastSeen":"2026-03-15T17:26:48.373780+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal","crawledAt":"2026-03-15T17:26:48.373780Z","crawlId":"tools-seeded-1773595608","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"47391597a8031a8b24762687a99feab4d9eaf3289d97f4f6e442be7922ea3f9d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:48.374776+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d1d1f018-1fa1-4687-95ec-ae4c66d76f91', 'tools', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/ausbildung-studium-mit-kind', 'active', NULL, '2026-03-15T17:26:50.474972+00:00', '{"id":"d1d1f018-1fa1-4687-95ec-ae4c66d76f91","title":"Ausbildung & Studium mit Kind","summary":{"de":"Von Elterngeld über BAföG bis Steuerentlastungen: Hier finden Sie Informationen zur Unterstützung von Studierenden und Auszubildenden mit Kind."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Für Eltern in Studium und Ausbildung gibt es verschiedene finanzielle Unterstützungen, Hilfen und Beratungsangebote für ihre spezielle Situation. Wenn Sie studieren oder eine Ausbildung machen, können Sie Elterngeld bekommen. Mehr Informationen dazu finden Sie unter Elterngeld während des Studiums oder der Ausbildung. Wenn Sie BAföG beantragen, wird Ihr Elterngeld wie Einkommen behandelt und auf das BAföG angerechnet, sofern Ihr Elterngeld über dem Mindestbetrag liegt. Hier finden Sie weitere Informationen zu Elterngeld und BAföG. Auszubildende und Studierende können Elternzeit nehmen. Hier finden Sie weitere Informationen, wenn Sie wissenschaftliche Mitarbeiterin oder Mitarbeiter oder"},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/ausbildung-studium-mit-kind","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:50.474972+00:00","lastSeen":"2026-03-15T17:26:50.474972+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/ausbildung-studium-mit-kind","crawledAt":"2026-03-15T17:26:50.474972Z","crawlId":"tools-seeded-1773595610","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"15c28a852f7d3ac3e2ea4dc25d788dae33417d2a41cbc0c1121d6edc2d5110e1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:50.474972+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a4dee588-d24f-4e66-b7ba-8bc63586473e', 'tools', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/freiwilliges-engagement', 'active', NULL, '2026-03-15T17:26:50.984956+00:00', '{"id":"a4dee588-d24f-4e66-b7ba-8bc63586473e","title":"Freiwilliges Engagement","summary":{"de":"Ob Freiwilliges Soziales Jahr oder Bundesfreiwilligendienst: Hier erfahren Sie alles über freiwilliges Engagement."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. In Deutschland engagieren sich mehr als 30 Millionen Menschen aktiv für das Gemeinwohl. Sie stellen sich täglich in den Dienst anderer und tragen damit wesentlich zum Zusammenhalt unserer Gesellschaft bei. Ehrenämter, Freiwilligenarbeit und bürgerschaftliches Engagement sind wichtige Bestandteile unserer Demokratie. Ob bei der Freiwilligen Feuerwehr, im Sportverein, in einer Kindertagesstätte oder bei einer Bürgerinitiative – in vielen spannenden Tätigkeitsfeldern können Sie sich freiwillig engagieren. So bringen Sie sich in die Gesellschaft ein und gestalten sie mit. Von diesem Engagement profitieren Sie auch persönlich: Sie sind aktiv, lernen dazu, knüpfen neue Kontakte und können das Gefühl genießen, etwas Gutes zu tun. Um das Engagement zu würdigen, erhalten Aktive zudem eine steuerliche Förderung. Freiwilliges Engagement ist etwas für junge und ältere Menschen."},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/freiwilliges-engagement","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:50.984956+00:00","lastSeen":"2026-03-15T17:26:50.984956+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/freiwilliges-engagement","crawledAt":"2026-03-15T17:26:50.985635Z","crawlId":"tools-seeded-1773595610","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"a185bd1ef9b5e4665301bb37995963a920fc7dd4b5bf55888f251a041d8cbdc7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:50.985635+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('16e0917a-d586-4892-a06a-800fdf17a9f0', 'tools', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/kinderbetreuung', 'active', NULL, '2026-03-15T17:26:51.536569+00:00', '{"id":"16e0917a-d586-4892-a06a-800fdf17a9f0","title":"Kinderbetreuung","summary":{"de":"Wie finde ich einen Kita-Platz? Was ist, wenn mein Kind krank ist? Hier finden Sie Antworten rund um Fragen zur Kinderbetreuung."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Bei der Suche nach einem geeigneten Betreuungsangebot vor Ort unterstützt Sie Ihr jeweiliges Landesministerium mit hilfreichen Informationen. Darüber hinaus stellen einige Bundesländer Übersichten der Angebote zu Kinderbetreuung nach Landkreisen und Bezirken zur Verfügung. Vereinzelt ist auch ein zentrales Anmeldeverfahren möglich. In Städten, Landkreisen und Bezirken ist in der Regel Ihr Jugendamt für die Vermittlung eines Kitaplatzes zuständig. Das Serviceportal Baden-Württembergs stellt Informationen für die Anmeldung und Aufnahmen in Kindertageseinrichtungen bereit. Der Kommunalverband für Jugend und Soziales Baden-Württemberg stellt zudem eine Übersicht aller Kindertageseinrichtungen in Städten und Landkreisen bereit. Das Bayerische Staatsministerium für Familie, Arbeit und Soziales stellt Informationen rund um die Kindertagesbetreuung bereit. Darunter auch Links zu Info-Filmen und Antworten auf häufige Fragen (FAQ) von Eltern."},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/kinderbetreuung","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:51.536569+00:00","lastSeen":"2026-03-15T17:26:51.536569+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/kinderbetreuung","crawledAt":"2026-03-15T17:26:51.537456Z","crawlId":"tools-seeded-1773595611","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"3bfc75eaf2bd5fc8ee766dd84a189e91e57c63aafca2a26473e03f8934f6c0e8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:51.537456+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('79d60bf2-002c-41fe-93e6-2714373c7fb5', 'tools', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/selbststaendigkeit', 'active', NULL, '2026-03-15T17:26:52.007784+00:00', '{"id":"79d60bf2-002c-41fe-93e6-2714373c7fb5","title":"Selbstständigkeit mit Kind","summary":{"de":"Von Elterngeld bis Mutterschaftsleistungen: Hier finden Sie Informationen zur Unterstützung von Selbstständingen mit Kind."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Für Selbstständige gibt es Familienleistungen, wie das Kindergeld und unter bestimmten Voraussetzungen Kinderzuschlag oder Leistungen für Bildung und Teilhabe. Für Elterngeld und Mutterschaftsleistungen gelten teilweise spezielle Regelungen. Eine Übersicht dazu finden Sie hier. Als selbständige Person können Sie Elterngeld erhalten. Maßgeblich für die Bemessung des Elterngeldbetrags ist dabei, ob sie als selbständig oder nicht-selbständig gelten. Wie sich eine selbständige Tätigkeit auf die Berechnung des Elterngelds auswirkt, finden Sie hier: Wie wird mein bisheriges Einkommen für die Berechnung des Elterngelds bestimmt? Welches Einkommen wird für mein Elterngeld berücksichtigt, wenn ich vor der Geburt meines Kindes selbständig war?"},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/selbststaendigkeit","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:52.007784+00:00","lastSeen":"2026-03-15T17:26:52.007784+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/selbststaendigkeit","crawledAt":"2026-03-15T17:26:52.007784Z","crawlId":"tools-seeded-1773595612","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"9ce893adb1ac742e60f7bcf37011e9b4c35c5f7e158289ae38b6ed49255828de"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:52.007784+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('93f39e89-dbaf-459a-96bf-0edfe4aa47a5', 'tools', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/vereinbarkeit-familie-und-beruf', 'active', NULL, '2026-03-15T17:26:52.537361+00:00', '{"id":"93f39e89-dbaf-459a-96bf-0edfe4aa47a5","title":"Vereinbarkeit Familie & Beruf","summary":{"de":"Die Mehrheit der Eltern möchte Beruf und Familie besser miteinander vereinbaren können. Hier erfahren Sie, worauf Sie achten sollten."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Die Mehrheit der Eltern möchte Beruf und Familie besser miteinander vereinbaren können. Dazu sind vor allem familienfreundliche Arbeitgeber, geregelte Kinderbetreuung und finanzielle Sicherheit wichtig. Familienfreundliche Arbeitsbedingungen tragen viel dazu bei, dass Eltern Familie und Beruf miteinander vereinbaren können. Neun von zehn Arbeitnehmerinnen und Arbeitnehmern mit Kindern sagen, dass ihnen familienfreundliche Angebote mindestens so wichtig sind wie die Höhe des Gehalts. In den vergangenen Jahren sind viele Fortschritte erzielt worden. Das zeigt etwa das Unternehmensnetzwerk Erfolgsfaktor Familie des Familienministeriums und des Deutschen Industrie- und Handelskammertages. Es vereint bundesweit über 6.700 Unternehmen und Institutionen, die sich zu einer familienbewussten Personalpolitik bekennen. Familienfreundlichkeit rechnet sich: Unternehmen binden damit qualifizierte Beschäftigte an sich. Das eröffnet Vorteile beim Wettbewerb um die besten Köpfe - gerade vor dem Hintergrund der demografischen Entwicklung. Wer Beschäftigte mit familiären Verpflichtungen gewinnen möchte, punktet vor allem mit familienbewussten Arbeitszeiten, denn für die Arbeitnehmerinnen und Arbeitnehmer ist die Frage, wie sich der Alltag organisieren lässt, oft entscheidend."},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/vereinbarkeit-familie-und-beruf","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:52.537361+00:00","lastSeen":"2026-03-15T17:26:52.537361+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/vereinbarkeit-familie-und-beruf","crawledAt":"2026-03-15T17:26:52.537361Z","crawlId":"tools-seeded-1773595612","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"22cec8bc7f4bd17c95b184364a8bfa24d06f8a6377e13c55924c3ed2fbf9330a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:52.537361+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('47191dc9-8ee9-40ed-952e-96b2099c69a7', 'tools', 'https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/familienversicherung', 'active', NULL, '2026-03-15T17:26:53.481536+00:00', '{"id":"47191dc9-8ee9-40ed-952e-96b2099c69a7","title":"Familienversicherung","summary":{"de":"Sie können Familienmitglieder beitragsfrei mitversichern. Hier finden Sie alle Informationen zur Familienversicherung."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Sowohl in der gesetzlichen Krankenversicherung als auch in der sozialen Pflegeversicherung haben Sie die Möglichkeit, Familienmitglieder beitragsfrei mitzuversichern. In der Familienversicherung können Sie Familienangehörige mitversichern, wenn diese einen Wohnsitz oder gewöhnlichen Aufenthalt in Deutschland haben, nicht versicherungsfrei oder von der Versicherung befreit sind, kein über einer bestimmten Grenze liegendes regelmäßiges Gesamteinkommen haben."},"url":"https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/familienversicherung","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:53.481536+00:00","lastSeen":"2026-03-15T17:26:53.481536+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinder-jugendliche/familienversicherung","crawledAt":"2026-03-15T17:26:53.482325Z","crawlId":"tools-seeded-1773595613","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"56f0e8a41db006c7582872b5bae99521f03dd2458ff8fb4d74ac979914e4191b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:53.482325+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bf00db3c-b966-440a-92e5-2779c6bd1193', 'tools', 'https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/gesundheit-erholung', 'active', NULL, '2026-03-15T17:26:53.971726+00:00', '{"id":"bf00db3c-b966-440a-92e5-2779c6bd1193","title":"Gesundheit & Erholung","summary":{"de":"Hier finden Sie Informationen zu Kuren, Familienerholung und das Thema Gesundheit und Ernährung."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Die Verantwortung für eine Familie zu tragen kann außerordentlich anstrengend und für Körper und Psyche sehr belastend sein. Wenn Sie im Zusammenhang mit familiären Belastungen ein erhöhtes Risiko für bestimmte Krankheiten haben oder schon krank sind, haben Sie einen gesetzlichen Anspruch auf stationäre Vorsorge- und Rehabilitationsmaßnahmen. Das Müttergenesungswerk unterstützt mit über 70 Einrichtungen bundesweit Mütter, Väter und pflegende Angehörige mit umfassenden Gesundheitsangeboten. Die vom Müttergenesungswerk anerkannten, gemeinnützigen Kliniken bieten Kuren für Mütter und Väter sowie für pflegende Angehörige an. Es gibt Mütter-Kuren (ohne Kinder), Mutter-Kind-Kuren und Vater-Kind-Kuren oder Kuren speziell für pflegende Angehörige. Die Mutter-Kind-Kuren und Vater-Kind-Kuren sind eine Pflichtleistung der gesetzlichen Krankenversicherung. Eine solche Kur dauert in der Regel drei Wochen und soll Ihnen helfen, den Alltag besser zu meistern und mit Zuversicht in die Zukunft zu schauen. Wenn bei Ihnen eine Kurbedürftigkeit vorliegt, kann Ihr Arzt Ihnen eine Kur verschreiben, die Sie dann bei ihrer Krankenkasse beantragen müssen. Wenn Sie den gesetzlichen Eigenanteil für eine Kur nicht bezahlen können, können Sie Unterstützung beim Deutschen Müttergenesungswerk beantragen. Die Beratungsstellen der Wohlfahrtsverbände im Müttergenesungswerk-Verbund stehen als Anlaufpunkte für Fragen zu Mütter-Kuren sowie Mutter-Kind-Kuren oder Vater-Kind-Kuren zur Verfügung. Sie erhalten dort Unterstützung beim Antragsverfahren, bei der Wahl der geeigneten Klinik sowie Hilfe bei der Organisation der Kurmaßnahme. Die nächstgelegene Beratungsstelle finden Sie auf der Internetseite des Deutschen Müttergenesungswerks. Dort gibt es auch nähere Informationen zu den Schwerpunktmaßnahmen für alleinerziehende Mütter und Väter."},"url":"https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/gesundheit-erholung","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:53.971726+00:00","lastSeen":"2026-03-15T17:26:53.971726+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinder-jugendliche/gesundheit-erholung","crawledAt":"2026-03-15T17:26:53.971726Z","crawlId":"tools-seeded-1773595613","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"17dbbaeebb82c64bfbd0c89bce444897bb5ab10a9c6880a95d5a505e6ff0d98b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:53.971726+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b140eabf-1883-41cd-9d8b-681525fd5b6d', 'tools', 'https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/kinder-jugendschutz', 'active', NULL, '2026-03-15T17:26:54.535784+00:00', '{"id":"b140eabf-1883-41cd-9d8b-681525fd5b6d","title":"Kinder- & Jugendschutz","summary":{"de":"Was ist der Kinder- und Jugendschutz? Wie kann ich mein Kind vor Alkoholmissbrauch schützen? Hier finden Sie Antworten auf diese und weitere Fragen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Kinder und Jugendliche sind sich nicht immer der Gefahren und Risiken des Alltags bewusst. Deshalb ist es wichtig, sie vor Gewalt, Missbrauch, Vernachlässigungen und anderen gefährdenden Einflüssen zu schützen. Helfen Sie Ihrem Kind dabei, Gefahren zu erkennen. Unter Mitwirkung der Erzieherinnen und Erzieher in den Kitas und der Lehrerinnen und Lehrer in der Schule sind Sie gefordert, Ihrem Kind alle Kompetenzen zu vermitteln, die es braucht, und ihm Grenzen aufzuzeigen. Aber auch der Staat setzt sich für das Wohl von Kindern und Jugendlichen ein und unterstützt Eltern in ihrem Erziehungsauftrag. Das \"Übereinkommen über die Rechte des Kindes\" wurde am 20. November 1989 von der Vollversammlung der Vereinten Nationen verabschiedet. Am 5. April 1992 trat die Kinderrechtskonvention in Deutschland in Kraft. Sie regelt umfassend den Schutz, die Förderung und Befähigung sowie die Teilhabe und Beteiligung von Kindern und Jugendlichen und gilt in fast allen Staaten der Erde. In Deutschland ist der Kinder- und Jugendschutz eine staatliche Aufgabe mit Verfassungsrang. Er fällt unter den Auftrag der öffentlichen Fürsorge (Artikel 74 Absatz 1 Nr. 7 Grundgesetz). Dadurch ist der Staat verpflichtet, Eltern bei der Erziehung ihrer Kinder, zum Schutz vor Gefährdungen und zum Schutz des Kindeswohls, zu unterstützen (sogenanntes \"Wächteramt\" auf Basis von Artikel 6 Absatz 2 Satz 2 Grundgesetz). Kinder und Jugendliche bedürfen entsprechend ihrem Alter und Entwicklungsstand des Schutzes, der Hilfe und der Förderung, um sich zu eigenverantwortlichen Persönlichkeiten innerhalb der sozialen Gemeinschaft zu entwickeln und an ihr teilzuhaben. Deshalb hat das Grundrecht auf Entfaltung ihrer Persönlichkeit (Artikel 2 Absatz 1 Grundgesetz) sowie der Schutz der Menschenwürde (Artikel 1 Absatz 1 Grundgesetz) für sie eine besondere Bedeutung."},"url":"https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/kinder-jugendschutz","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:54.535784+00:00","lastSeen":"2026-03-15T17:26:54.535784+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinder-jugendliche/kinder-jugendschutz","crawledAt":"2026-03-15T17:26:54.535784Z","crawlId":"tools-seeded-1773595614","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"bc03883bd00df7c084fb43c6b206d8e2e0dfc386df9a15740c95b4af9141bda5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:54.535784+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('62bcfa2a-ba15-43ef-9b68-6d4090ed1f41', 'tools', 'https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/adoption', 'active', NULL, '2026-03-15T17:26:55.590170+00:00', '{"id":"62bcfa2a-ba15-43ef-9b68-6d4090ed1f41","title":"Adoption","summary":{"de":"Informationen des Bundesfamilienministeriums zu den Themen Adoption, Vermittlung, Voraussetzungen, finanzielle Hilfen und weiteres mehr..."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. In Deutschland dürfen Adoptionen nur von bestimmten Stellen vermittelt werden. Wenn Sie ein Kind adoptieren möchten, wenden Sie sich an: Adoptionsdienst in evangelischer Trägerschaft oder die Adoptionsvermittlungsstelle in nichtkonfessioneller Trägerschaft. Die Adoptionsvermittlungsstellen haben den Auftrag, für jedes zu vermittelnde Kind die Eltern auszuwählen, die am besten zum Kind passen. Dabei stehen das Wohl des Kindes und die Wahrung seiner Rechte und Bedürfnisse im Mittelpunkt. Es besteht kein Rechtsanspruch auf Vermittlung eines Kindes. Im Zentrum jeder Adoption steht das Wohl des Kindes. Das heißt, es werden die besten Eltern für ein Kind gesucht, das aus unterschiedlichen Gründen nicht bei seinen leiblichen Eltern aufwachsen kann. Ziel einer Adoption ist es, dass das Kind Geborgenheit und Zuwendung in einer neuen Familie findet."},"url":"https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/adoption","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:55.590170+00:00","lastSeen":"2026-03-15T17:26:55.590170+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/adoption","crawledAt":"2026-03-15T17:26:55.590170Z","crawlId":"tools-seeded-1773595615","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"e911ea0f67ba47f5485ab15345473d6aa92c0cbfb3f18f61520f8d060ef89c8a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:55.590170+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2f63dc9b-0980-413c-8d7e-3456b6507061', 'tools', 'https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/kinderwunsch', 'active', NULL, '2026-03-15T17:26:55.978698+00:00', '{"id":"2f63dc9b-0980-413c-8d7e-3456b6507061","title":"Kinderwunsch","summary":{"de":"Hier finden Sie Informationen zu ungewollter Kinderlosigkeit, Kinderwunsch-Behandlung und finanzielle Zuschüssen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Frauen und Männer, die auf natürlichem Weg keine Kinder bekommen können, haben die Möglichkeit sich reproduktionsmedizinisch behandeln zu lassen. Den verschiedenen reproduktionsmedizinischen Behandlungsmethoden gehen meist ärztliche Untersuchungen voraus, um Gründe und Ursachen zu diagnostizieren und die geeignete Methode auszuwählen. Unerfüllter Kinderwunsch – Behandlungs­möglichkeiten © BMFSFJ Von ungewollter Kinderlosigkeit spricht man, wenn nach zwölf Monaten mit regelmäßigem ungeschütztem Geschlechtsverkehr (ca. zweimal pro Woche), keine Schwangerschaft eingetreten ist. Eine ungewollte Kinderlosigkeit kann körperliche Gründe haben, die Fertilität kann aufgrund emotionaler Belastungen oder aufgrund einer ungesunden Lebensweise beeinträchtigt sein. Manche Paare schieben den Kinderwunsch so lange auf, bis es aufgrund ihres Alters schwierig wird, dass eine Schwangerschaft auf natürlichem Wege eintritt. Wenn Sie nicht schwanger werden, ist es wichtig, sich untersuchen zu lassen: Reproduktionsmedizinische Zentren oder Spezialpraxen bieten umfassende Diagnose- und Behandlungsmöglichkeiten an. Eine gute Übersicht, wenn auch nicht vollständig, da die Angaben freiwillig sind, bietet die Datenbank auf dem Informationsportal-Kinderwunsch.de."},"url":"https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/kinderwunsch","topics":["family","financial_support","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","single_parents","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:26:55.978698+00:00","lastSeen":"2026-03-15T17:26:55.978698+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/kinderwunsch","crawledAt":"2026-03-15T17:26:55.979712Z","crawlId":"tools-seeded-1773595615","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"c1641d7cd3c972c1c769bdc0cf826896e1b2e2b7f2f7b77952dd606ae94f7f40"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:55.979712+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f20707ad-4c16-4a8d-a812-c31a6200b0b2', 'tools', 'https://mein-now.de/new-plan', 'active', NULL, '2026-03-15T16:05:40.586335+00:00', '{"id":"f20707ad-4c16-4a8d-a812-c31a6200b0b2","title":"New Plan – Online-Tool zur beruflichen Entwicklung","summary":{"de":"Nutzen Sie das Online-Tool New Plan für Ihre berufliche Weiterbildung: Möglichkeiten testen, inspirieren lassen und passende Weiterbildungen finden."},"content":{"de":"Bitte beachten Sie: New Plan ist seit dem 25. Juni 2024 in „mein NOW“ integriert. Alle Funktionen von New Plan bleiben auch zukünftig in neuem Design erhalten. Testen Sie Ihr Können, lernen Sie Ihre Stärken kennen und finden Sie heraus, was beruflich zu Ihnen passt. Erfahren Sie, wohin andere Personen mit Ihrem Beruf gewechselt sind und informieren Sie sich über diese Berufe. Falls Sie bereits wissen, wohin Sie sich entwickeln möchten, können Sie hier direkt nach passenden Weiterbildungen suchen. Sie möchten sich beruflich verändern und suchen den richtigen Weg? New Plan bietet Ihnen: Entwicklungsmöglichkeiten und alternative Tätigkeiten, die zu Ihren Stärken passen"},"url":"https://mein-now.de/new-plan","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T16:05:40.586335+00:00","lastSeen":"2026-03-15T16:05:40.586335+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://mein-now.de/new-plan","crawledAt":"2026-03-15T16:05:40.586335Z","crawlId":"tools-seeded-1773590740","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"cbc615a1be5a03814469ce06ea33214c5cfef52f4cfd52813daa0ca96e3217d9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:05:40.587335+00:00"}}') ON CONFLICT(