INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ba10ba0d-ea3f-421a-88b1-ee28d0197c21', 'tools', 'https://web.arbeitsagentur.de/vermittlung/nks-ui/pd?reglevel=pin', 'active', NULL, '2026-03-15T17:23:59.181576+00:00', '{"id":"ba10ba0d-ea3f-421a-88b1-ee28d0197c21","title":"Arbeitsmarktprofil","summary":{"de":"Wir beraten Sie, damit Sie schnell wieder Arbeit finden. Füllen Sie hier in wenigen Schritten Ihr Arbeitsmarktprofil aus."},"content":{"de":"Wir beraten Sie, damit Sie schnell wieder Arbeit finden. Füllen Sie hier in wenigen Schritten Ihr Arbeitsmarktprofil aus."},"url":"https://web.arbeitsagentur.de/vermittlung/nks-ui/pd?reglevel=pin","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:23:59.181576+00:00","lastSeen":"2026-03-15T17:23:59.181576+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://web.arbeitsagentur.de/vermittlung/nks-ui/pd?reglevel=pin","crawledAt":"2026-03-15T17:23:59.182527Z","crawlId":"tools-seeded-1773595439","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"1b6db508235e9c5ce6149965fd5de2879b079b4e2ae3c88eed6db2e2f52072f8"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:23:59.182527+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('868a22e9-9650-4c5c-8e20-cb7438ebab91', 'tools', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/dokumente-aerztlicher-dienst', 'active', NULL, '2026-03-15T17:24:02.678743+00:00', '{"id":"868a22e9-9650-4c5c-8e20-cb7438ebab91","title":"Ärztlicher Dienst der BA: Dokumente online senden","summary":{"de":"Sie haben einen Termin beim Ärztlichen Dienst der BA. Sende Sie die benötigten Unterlagen vorab online zu – einfach, schnell und sicher."},"content":{"de":"Mit Ihrer Vermittlungs- oder Beratungsfachkraft haben Sie eine ärztliche Begutachtung durch den Ärztlichen Dienst der BA vereinbart. Ziel ist es, die Auswirkungen Ihrer gesundheitlichen Einschränkungen auf Ihre berufliche Leistungsfähigkeit zu beurteilen. Damit die Untersuchung stattfinden kann, benötigt der Ärztliche Dienst der BA von Ihnen ausgefüllte Unterlagen, die Sie vorab zuschicken müssen. Dazu gehören zum Beispiel: positiv: Befunde Ihrer Ärztin oder Ihres Arztes (Ergebnisse vorangegangener Untersuchungen) Sie haben ein Beratungsgespräch mit Ihrer Vermittlungs- oder Beratungsfachkraft geführt und einen Gesundheitsfragebogen und eine Schweigepflichtentbindung erhalten. Füllen Sie beide Formulare vollständig aus und unterschreiben Sie sie. Falls Sie die Formulare nicht vorliegen haben, können Sie sie hier herunterladen:"},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/dokumente-aerztlicher-dienst","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:02.678743+00:00","lastSeen":"2026-03-15T17:24:02.678743+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/dokumente-aerztlicher-dienst","crawledAt":"2026-03-15T17:24:02.678743Z","crawlId":"tools-seeded-1773595442","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"d30973a6933f800be186e1f288c54154c68e1d6d5785b839897cd49d9ff06260"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:02.680142+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a0ca0a8e-0e53-4e82-9f90-50b493271470', 'tools', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/massnahme-bei-traeger-beantragen', 'active', NULL, '2026-03-15T17:24:03.174637+00:00', '{"id":"a0ca0a8e-0e53-4e82-9f90-50b493271470","title":"Maßnahme bei einem Träger (MAT) beantragen","summary":{"de":"Erwerben Sie in Trainings und Lehrgängen bei Trägern neue Kompetenzen, um Ihre Aussicht auf eine Stelle zu verbessern. Jetzt informieren!"},"content":{"de":"Wenn Sie einen Job oder einen Ausbildungsplatz suchen, können Sie Ihre Chancen auf eine Stelle mit Lehrgängen oder Trainings erhöhen. Unter bestimmten Voraussetzungen übernehmen wir die Kosten dafür. Die Lehrgänge, Trainings oder Coachings finden bei zugelassenen Unternehmen und Einrichtungen statt (Fachbegriff: Träger). Der Fachbegriff dafür ist: Maßnahmen bei einem Träger, kurz: MAT. Die MAT können in Gruppen oder im Rahmen von Einzelcoachings stattfinden. Folgende Ziele können Sie zum Beispiel mit einer MAT erreichen: Sie können Ihre neu angetretene Arbeitsstelle halten. Wichtig: Wichtig: Ihre Vermittlungs- oder Integrationsfachkraft bietet Ihnen eine Maßnahme nach Ihren Wünschen an, wenn die entsprechenden Voraussetzungen erfüllt sind. Alternativ erhalten Sie einen Gutschein, mit dem Sie sich selber eine Maßnahme aussuchen können. Damit wir die Kosten Ihrer MAT übernehmen können, muss einer der folgenden Punkte auf Sie zutreffen: sind von Arbeitslosigkeit bedroht und haben sich darum bei uns arbeitsuchend gemeldet."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/massnahme-bei-traeger-beantragen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:03.174637+00:00","lastSeen":"2026-03-15T17:24:03.174637+00:00","sourceUnavailable":false,"toolType":"application","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/massnahme-bei-traeger-beantragen","crawledAt":"2026-03-15T17:24:03.174637Z","crawlId":"tools-seeded-1773595443","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"fe18c0f4d57e4205d64ec1a9812741bef52afb21a1c8b5f7a1e3ad6ffee932a7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:03.174637+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6d6520f3-f7ae-4059-b08f-fb5c42b42354', 'tools', 'https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/massnahme-beim-arbeitgeber-beantragen', 'active', NULL, '2026-03-15T17:24:03.684633+00:00', '{"id":"6d6520f3-f7ae-4059-b08f-fb5c42b42354","title":"Maßnahme beim Arbeitgeber (MAG)","summary":{"de":"Durch praktische Erfahrung in einem Betrieb können Sie herausfinden, ob eine bestimmte berufliche Tätigkeit zu Ihnen passt. Außerdem knüpfen Sie Kontakt zu Arbeitgebern."},"content":{"de":"Einen Einblick in einen Betrieb erhalten und berufliche Tätigkeiten ausprobieren – das ermöglicht Ihnen eine sogenannte Maßnahme bei einem Arbeitgeber, kurz: MAG. positiv: Sie lernen einen Betrieb unverbindlich kennen. positiv: Sie erhalten einen Eindruck vom Aufgabengebiet, das Sie sich wünschen. positiv: Der Betrieb lernt Sie und Ihre Stärken kennen. positiv: Im optimalen Fall erkennt der Betrieb Ihr berufliches Potenzial und bietet Ihnen im Anschluss eine Stelle an. Eine MAG dauert in der Regel wenige Tage. Maximal sind 6 Wochen, in manchen Fällen bis zu 12 Wochen möglich."},"url":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/massnahme-beim-arbeitgeber-beantragen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:03.684633+00:00","lastSeen":"2026-03-15T17:24:03.684633+00:00","sourceUnavailable":false,"toolType":"application","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/arbeitslos-arbeit-finden/massnahme-beim-arbeitgeber-beantragen","crawledAt":"2026-03-15T17:24:03.684633Z","crawlId":"tools-seeded-1773595443","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"01e3cd2511da06a0008dc9787ddd686ff28d78bc185aa29391b56be004dac144"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:03.684633+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ffb9279a-3b30-4469-9a42-3489787432be', 'tools', 'https://www.arbeitsagentur.de/bildung/welche-ausbildung-welches-studium-passt', 'active', NULL, '2026-03-15T17:24:04.666673+00:00', '{"id":"ffb9279a-3b30-4469-9a42-3489787432be","title":"Check-U: Der Berufsorientierungstest","summary":{"de":"Check-U ist ein kostenloser Berufsorientierungstest. Damit findest du heraus, welches Studium oder welche Ausbildung zu dir passt. Gleich loslegen!"},"content":{"de":"Entdecke deine beruflichen Stärken mit dem kostenlosen Berufsorientierungstest der Bundesagentur für Arbeit. Finde heraus, welche Ausbildungen und welches Studium zu dir passen. Bei deiner Berufswahl geht es um deine berufliche Zukunft. Nimm dir also Zeit. Unser Berufstest dauert circa 80 Minuten und er speichert alles automatisch. Du kannst jederzeit pausieren und mit deinem persönlichen Zugangscode zu Check-U zurückkehren. Entdecke, welche Stärken du hast! Die Ergebnisse deines Kompetenz-Checks werden in deinem persönlichen Stärkenprofil zusammengefasst. So hast du deine Stärken immer auf einen Blick! Nenne uns deine Talente, bevorzugten Arbeitsbedingungen und Berufsfelder, die dich interessieren. Dadurch können wir dich bei deiner Berufswahl besser unterstützen. Erfahre, welche Ausbildungen (ab Klasse 8) und Studienfächer (ab der 10. Klasse) am besten zu dir passen. Und wenn das Richtige dabei ist, kannst du direkt nach Ausbildungsangeboten und Studiengängen suchen. Eine Ausbildung im Betrieb, in der Schule oder doch lieber ein Studium: Den meisten Jugendlichen fällt es schwer, sich für einen Weg zu entscheiden. Und genau dabei hilft dir Check-U!"},"url":"https://www.arbeitsagentur.de/bildung/welche-ausbildung-welches-studium-passt","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:04.666673+00:00","lastSeen":"2026-03-15T17:24:04.666673+00:00","sourceUnavailable":false,"toolType":"checker","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/bildung/welche-ausbildung-welches-studium-passt","crawledAt":"2026-03-15T17:24:04.667679Z","crawlId":"tools-seeded-1773595444","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"25aba8ffcfb8744628dedeb834060ad297b122362fb3040bae5548ea73db3320"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:04.667679+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('aa24a8fb-34d2-4f3e-8712-8b0d8ffd6c5e', 'tools', 'https://www.arbeitsagentur.de/erklaerung-barrierefreiheit', 'active', NULL, '2026-03-15T17:24:05.685577+00:00', '{"id":"aa24a8fb-34d2-4f3e-8712-8b0d8ffd6c5e","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Die Bundesagentur für Arbeit ist bemüht, die Webseiten unter www.arbeitsagentur.de und mobilen Anwendungen barrierefrei zugänglich zu gestalten. Rechtsgrundlagen sind die UN-Behindertenrechtskonvention (UN-BRK), das Behindertengleichstellungsgesetz (BGG) sowie die Barrierefreie Informationstechnik-Verordnung (BITV 2.0) in ihren jeweils gültigen Fassungen."},"content":{"de":"Die Überprüfung der Einhaltung der Anforderungen beruht auf unabhängigen BITV 2.0-Tests, die im Rahmen der Weiterentwicklung an jeweiligen Teilbereichen des Internetauftritts kontinuierlich durchgeführt werden. Die Webseiten und mobilen Anwendungen sind mit den genannten Anforderungen zum größten Teil vereinbar. Die Bundesagentur für Arbeit ist bemüht, die verbleibenden Barrieren schnellstmöglich zu beheben. Die nachstehend aufgeführten Inhalte sind aus folgenden Gründen nicht barrierefrei: Unvereinbarkeit mit der BITV 2.0: Anmeldung/Registrierung: Die Nutzung eines Freischaltcodes ist derzeit noch nicht barrierefrei möglich. An einer barrierefreien Lösung auch für § 10 BGG-Kunden wird gearbeitet. Online-Portal - Menü: Das Hauptmenu ist derzeit eingeschränkt barrierefrei bedienbar. Eine barrierefreie Lösung soll bis 02/2026 zur Verfügung stehen. PDF-Dokumente: PDF-Dokumente älteren Datums sind nicht durchgehend barrierefrei. Neu herausgegebene PDF-Dokumente werden in der Regel in barrierefreier Version zur Verfügung gestellt oder zeitnah durch eine solche ersetzt. Falls Sie eine bestimmte PDF-Datei von uns benötigen, die noch nicht barrierefrei zur Verfügung steht, teilen Sie uns dies gerne über unser Kontaktformular mit."},"url":"https://www.arbeitsagentur.de/erklaerung-barrierefreiheit","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:05.685577+00:00","lastSeen":"2026-03-15T17:24:05.685577+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/erklaerung-barrierefreiheit","crawledAt":"2026-03-15T17:24:05.685577Z","crawlId":"tools-seeded-1773595445","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"5f42e6dc0ae192a6376646cea78857879dde0fe3ae3266962530e6c6c6d6c67a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:05.685577+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('69b5efb7-53f2-43f4-bec9-a1ad9ebef67e', 'tools', 'https://www.arbeitsagentur.de/eservices', 'active', NULL, '2026-03-01T20:14:00Z', '{"id":"69b5efb7-53f2-43f4-bec9-a1ad9ebef67e","title":"e Services für Bürgerinnen und Bürger","translations":{"de-LEICHT":{"title":"Online-Dienste","timestamp":"2026-03-01T20:14:00Z","provenance":{"source":"https://www.arbeitsagentur.de/eservices","crawledAt":"2026-03-01T20:14:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Die eServices der Bundesagentur ermöglichen digitale Antragstellung, Dokumentenübermittlung und Statusprozesse über ein Benutzerkonto."},"content":{"de":"Die Plattform deckt Anliegen zu Arbeitslosigkeit, Jobcenter-Leistungen, Familienkasse sowie Aus- und Weiterbildung ab. Sie reduziert Behördengänge und unterstützt standardisierte Online-Prozesse für Bürgerinnen und Bürger."},"url":"https://www.arbeitsagentur.de/eservices","topics":["employment","financial_support"],"tags":["application_required","automatic"],"targetGroups":["unemployed","families"],"status":"active","toolType":"portal","relatedBenefits":["c6fb568f-2e9a-4b26-b6c6-74c0e38205c9"],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"firstSeen":"2026-03-01T20:14:00Z","lastSeen":"2026-03-01T20:14:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/eservices","crawlId":"manual-curation-20260301-realdata-v1","checksum":"b8d88e44fb83f497869ae8c8d67ff2a07f3e2f922afce01dbf75f6c2de5f45e3","crawledAt":"2026-03-01T20:14:00Z"},"qualityScores":{"iqs":82.5,"ais":59.1,"computedAt":"2026-03-01T20:14:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('82e38ab7-ca2b-459a-bdf0-e772cf713380', 'tools', 'https://www.arbeitsagentur.de/familie-und-kinder', 'active', NULL, '2026-03-15T17:24:06.163776+00:00', '{"id":"82e38ab7-ca2b-459a-bdf0-e772cf713380","title":"Familie und Kinder","summary":{"de":"Mit Kindergeld, Kinderzuschlag und weiteren finanziellen Hilfen unterstützt Sie die Familienkasse der Bundesagentur für Arbeit. Jetzt online beantragen!"},"content":{"de":"Ihr Profil im Online-Konto der Bundesagentur für Arbeit ist Ihr digitaler Zugang zur Familienkasse. Mit Ihrem Profil können Sie vieles direkt online erledigen – schnell, rund um die Uhr und von überall. Beantragen Sie Kindergeld für Ihr neugeborenes Kind. Beantragen Sie Kindergeld für Ihr volljähriges Kind. Ändern Sie Ihre persönlichen Daten (zum Beispiel Anschrift, Bankverbindung) oder laden Sie Unterlagen hoch. Beantragen Sie online Kinderzuschlag für Ihr Kind. Kindergeld erhalten Sie für Kinder unter 18 Jahren, unter bestimmten Voraussetzungen auch länger. Informieren Sie sich, wie Sie Kindergeld beantragen und in welcher Höhe es ausgezahlt wird."},"url":"https://www.arbeitsagentur.de/familie-und-kinder","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:06.163776+00:00","lastSeen":"2026-03-15T17:24:06.163776+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder","crawledAt":"2026-03-15T17:24:06.163776Z","crawlId":"tools-seeded-1773595446","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"174743f1618ab480cbc1b5508f8e7d6c968feca00dddc6411af5bf73a500f2be"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:06.163776+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fa25ff9b-37d4-4753-a14e-b0bb30c5a9f2', 'tools', 'https://www.arbeitsagentur.de/familie-und-kinder/auszahlungstermine', 'active', NULL, '2026-03-15T17:24:06.683815+00:00', '{"id":"fa25ff9b-37d4-4753-a14e-b0bb30c5a9f2","title":"Kindergeld 2026: Auszahlungstermine","summary":{"de":"Wann das Kindergeld und der Kinderzuschlag 2026 ausgezahlt werden: Die offiziellen Termine der Familienkasse auf einen Blick. Erfahren Sie, wann Sie Ihre Zahlung erhalten!"},"content":{"de":"Kindergeld und Kinderzuschlag werden zeitgleich gezahlt. Die letzte Zahl Ihrer Kindergeldnummer (die sogenannte Endziffer) entscheidet darüber, wann die entsprechenden Beträge auf Ihr Konto überwiesen werden. Ein Beispiel: Bei der Kindergeldnummer xxxFKxxxxx 9 ist die Endziffer eine 9. Diese Ziffer bestimmt, an welchen Tagen die Leistungen der Familienkasse überwiesen werden. Der folgenden Übersicht können Sie entnehmen, welche Auszahlungstermine 2026 für die Endziffer Ihrer Kindergeldnummer gelten. Konnten wir Ihnen mit der Seite weiterhelfen? Lassen Sie es uns wissen! Kindergeld und Kinderzuschlag werden überwiesen und können nicht bar ausgezahlt werden. Im Laufe des Überweisungstages wird der Betrag Ihrem Konto gutgeschrieben und Sie können darüber verfügen. Aus technischen Gründen überweist die Familienkasse die monatlichen Leistungen an ihre Kundinnen und Kunden nicht am selben Tag, sondern gestaffelt. Zur Strukturierung der Überweisungen zieht die Familienkasse die Endziffern der Kindergeldnummern heran."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/auszahlungstermine","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:06.683815+00:00","lastSeen":"2026-03-15T17:24:06.683815+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/auszahlungstermine","crawledAt":"2026-03-15T17:24:06.683815Z","crawlId":"tools-seeded-1773595446","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"8c57e61a2eb96e05ad31f6c5b9086f14bb5fad2c1abfa154b02ec60c9a9b43ab"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:06.684851+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b646e342-fb1d-4f5a-8b19-dfb8ac982d27', 'tools', 'https://www.arbeitsagentur.de/familie-und-kinder/downloads-familie-und-kinder', 'active', NULL, '2026-03-15T17:24:07.223019+00:00', '{"id":"b646e342-fb1d-4f5a-8b19-dfb8ac982d27","title":"Die wichtigsten Merkblätter, Formulare und Anträge der Familienkasse zum Download","summary":{"de":"Downloadcenter, Sammlung von den wichtigsten Formularen und Merkblättern zum Kindergeld und Kinderzuschlag"},"content":{"de":"Ergänzende PDF-Formulare für Kindergeld und Abzweigungsantrag für volljährige Kinder Ergänzende PDF-Formulare für Kindergeld für erwachsene Kinder mit Behinderung PDF-Formulare für die Veränderungsmitteilung für Kindergeld und Kinderzuschlag Öffnet in neuem Tab Merkblatt zum Kindergeld (KG2) Überblick über die gesetzlichen Regelungen zum Kindergeld pdf | 2.55 MB | nicht barrierefrei Ausgaben des Merkblatts Kindergeld (KG2) aus den Vorjahren. Diese sind nicht mehr gültig. Öffnet in neuem Tab Child Benefit leaflet (KG2-en) Merkblatt zum Kindergeld (englisch) pdf | 330.15 KB | barrierefrei"},"url":"https://www.arbeitsagentur.de/familie-und-kinder/downloads-familie-und-kinder","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:07.223019+00:00","lastSeen":"2026-03-15T17:24:07.223019+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/downloads-familie-und-kinder","crawledAt":"2026-03-15T17:24:07.223019Z","crawlId":"tools-seeded-1773595447","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"32a40c8dbb30af618456ddada8dbb59f007ebd2284f1c656381e1e74712c8f47"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:07.223019+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4c775d10-830d-4dcf-ad58-019e98fbe5ff', 'tools', 'https://www.arbeitsagentur.de/familie-und-kinder/infos-rund-um-kindergeld/kindergeld-anspruch-hoehe-dauer/kindergeld-antrag-starten', 'active', NULL, '2026-03-15T16:05:20.113343+00:00', '{"id":"4c775d10-830d-4dcf-ad58-019e98fbe5ff","title":"Familienkasse: Kindergeld-Antrag stellen","summary":{"de":"Beantragen Sie Kindergeld für Ihr neugeborenes Kind bei der Familienkasse. Jetzt Antrag stellen!"},"content":{"de":"Nach der Geburt Ihres Kindes erhalten Sie vom Bundeszentralamt für Steuern die steuerliche Identifikationsnummer (Steuer-IdNr.) für Ihr Kind. Wenige Tage danach folgt automatisch ein Begrüßungsschreiben Ihrer Familienkasse mit Ihrem persönlichen Zugangscode für den Kindergeldantrag. Wenn Sie den Zugangscode verwenden, sind die meisten Angaben für Sie bereits ausgefüllt. Unsere Empfehlung: Warten Sie das Schreiben ab, bevor Sie den Kindergeld-Antrag stellen. Starten Sie Ihren personalisierten Antrag auf Kindergeld. Halten Sie das Schreiben mit dem Zugangscode bereit. Sie können den Antrag mit Ihrer BundID direkt online abschicken. Starten Sie den Antrag ohne Zugangscode. Halten Sie Ihre Steuer-ID, die Ihres Kindes und Ihre Bankverbindung bereit. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/infos-rund-um-kindergeld/kindergeld-anspruch-hoehe-dauer/kindergeld-antrag-starten","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T16:05:20.113343+00:00","lastSeen":"2026-03-15T16:05:20.113343+00:00","sourceUnavailable":false,"toolType":"application","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/infos-rund-um-kindergeld/kindergeld-anspruch-hoehe-dauer/kindergeld-antrag-starten","crawledAt":"2026-03-15T16:05:20.113343Z","crawlId":"tools-seeded-1773590720","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"e959eb1b03b53eee793823f2b29ec85abbcfb05ab9224c1f08f31039ba920358"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:05:20.113343+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c5afa8a3-18c7-4ba7-9ebe-a37bd4830e1d', 'tools', 'https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kiz-lotse', 'active', NULL, '2026-03-15T16:05:20.625519+00:00', '{"id":"c5afa8a3-18c7-4ba7-9ebe-a37bd4830e1d","title":"Ki Z-Lotse: Anspruch auf Kinderzuschlag online prüfen","summary":{"de":"Finden Sie einfach und schnell heraus, ob Sie Kinderzuschlag beantragen können. Jetzt Anspruch prüfen und online beantragen!"},"content":{"de":"Wichtig: Wichtig: Der KiZ-Lotse berechnet nicht die Höhe des KiZ. Wenn Sie einen Antrag auf KiZ stellen, informieren wir Sie danach, ob Sie ihn erhalten und falls ja, in welcher Höhe. Der KiZ-Lotse besteht aus 4 kurzen Videos: Sie erfahren darin, welche Informationen von Ihnen benötigt werden, damit Ihr Anspruch auf Kinderzuschlag direkt online geprüft werden kann. Geben Sie die entsprechenden Informationen über Ihre Computer- oder Handytastatur ein. Anschließend errechnet der KiZ-Lotse, ob Sie einen Anspruch auf KiZ haben könnten. Wichtig: Tipp: Sie haben in der Vergangenheit beim KiZ-Lotsen ein negatives Ergebnis erhalten? Dann könnte es sich lohnen, heute noch einmal zu testen – denn durch den Sofortzuschlag für Kinder hat sich die Höchstgrenze erhöht. Auch bei höheren Betriebs- oder Heizkosten könnten sich Ihr individueller Anspruch auf Kinderzuschlag ändern. Der KiZ-Lotse: Anspruch auf Kinderzuschlag ermitteln Zu viel erhaltenes Kindergeld oder Kinderzuschlag zurückzahlen"},"url":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kiz-lotse","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T16:05:20.625519+00:00","lastSeen":"2026-03-15T16:05:20.625519+00:00","sourceUnavailable":false,"toolType":"checker","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/kinderzuschlag-verstehen/kiz-lotse","crawledAt":"2026-03-15T16:05:20.625519Z","crawlId":"tools-seeded-1773590720","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"cf5f4968986dbb5621e1ade8bf981e63f25bd81e2115f36207cf48ef52659678"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:05:20.625519+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1a1e0a46-6af7-4fce-9841-9eef1564e2a7', 'tools', 'https://www.arbeitsagentur.de/familie-und-kinder/veraenderungen-mitteilen', 'active', NULL, '2026-03-15T17:24:07.696692+00:00', '{"id":"1a1e0a46-6af7-4fce-9841-9eef1564e2a7","title":"Familienkasse: Änderung und Nachweise online übermitteln","summary":{"de":"Informieren Sie die Familienkasse über Veränderungen und reichen Sie Nachweise zu Kindergeld oder Kinderzuschlag online ein. Jetzt informieren!"},"content":{"de":"In Ihrem Antrag auf Kindergeld oder Kinderzuschlag haben Sie Angaben zu sich und Ihren Lebensumständen gemacht. Bestimmte Änderungen bei Ihnen oder Ihrem Kind können sich darauf auswirken, ob und in welcher Höhe Sie weiterhin Kindergeld oder Kinderzuschlag erhalten. Aber auch andere Änderungen sind wichtig, zum Beispiel Ihre Bankverbindung oder Wohnadresse. Informieren Sie uns rechtzeitig, wenn sich Ihre Bankdaten geändert haben oder Sie umgezogen sind. Sie stellen dadurch sicher, dass die Familienkasse das Kindergeld beziehungsweise den Kinderzuschlag rechtzeitig an Sie auszahlt. Wichtig: Wichtig: Sie müssen der Familienkasse alle Änderungen direkt mitteilen. Es genügt nicht, eine andere Behörde, zum Beispiel das Einwohnermeldeamt, das Jobcenter oder die Agentur für Arbeit zu informieren. Wenn Sie Kindergeld für ein Kind unter 18 Jahren erhalten, sind zum Beispiel folgende Änderungen wichtig: Sie trennen sich auf Dauer von Ihrer Partnerin beziehungsweise Ihrem Partner oder werden geschieden. Sie oder ein Kind verlassen Ihren bisherigen Haushalt."},"url":"https://www.arbeitsagentur.de/familie-und-kinder/veraenderungen-mitteilen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:07.696692+00:00","lastSeen":"2026-03-15T17:24:07.696692+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/familie-und-kinder/veraenderungen-mitteilen","crawledAt":"2026-03-15T17:24:07.696692Z","crawlId":"tools-seeded-1773595447","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"44901cbaa5abb766b6137a9c40df7cdfe8f6fedda8bdd39323f992caee2e9142"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:07.696692+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d8b24040-f508-4538-8a9a-1574d8f938b3', 'tools', 'https://www.arbeitsagentur.de/freiwillige-arbeitslosenversicherung', 'active', NULL, '2026-03-15T17:24:08.205851+00:00', '{"id":"d8b24040-f508-4538-8a9a-1574d8f938b3","title":"Freiwillige Arbeitslosenversicherung","summary":{"de":"Mit der Antragspflichtversicherung können Sie sich gegen das Risiko einer Arbeitslosigkeit absichern. Jetzt beantragen!"},"content":{"de":"Egal, ob Sie sich selbstständig machen oder beruflich umschulen, eine Beschäftigung im Ausland aufnehmen oder in Elternzeit Kinder betreuen: Wenn Sie nicht versicherungspflichtig in der Arbeitslosenversicherung sind, erwerben Sie keinen Anspruch auf Arbeitslosengeld. Falls Sie arbeitslos werden, kann das ein finanzielles Risiko für Sie bedeuten. Mit der freiwilligen Arbeitslosenversicherung können Sie dieses Risiko verringern: Werden Sie arbeitslos, können Sie bei Erfüllung der Anspruchsvoraussetzungen Arbeitslosengeld erhalten. Sie müssen die freiwillige Arbeitslosenversicherung innerhalb von 3 Monaten nach Beginn der Selbstständigkeit, Elternzeit, Umschulung oder der Beschäftigung im Ausland bei Ihrer Agentur für Arbeit beantragen. Sie können sich freiwillig in der Arbeitslosenversicherung versichern, wenn einer der folgenden Fälle auf Sie zutrifft: Sie starten in die Selbstständigkeit, die Sie mindestens 15 Stunden pro Woche ausüben werden. Sie betreuen in Elternzeit ein Kind, das älter als 3 Jahre ist. Sie machen eine Weiterbildung, um beruflich aufzusteigen, den Beruf zu wechseln oder einen Berufsabschluss zu erreichen."},"url":"https://www.arbeitsagentur.de/freiwillige-arbeitslosenversicherung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:08.205851+00:00","lastSeen":"2026-03-15T17:24:08.205851+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/freiwillige-arbeitslosenversicherung","crawledAt":"2026-03-15T17:24:08.205851Z","crawlId":"tools-seeded-1773595448","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"af2ab47a638ffc798baa80ad87ea8de36e2e2f5bea9317da9d54cb1fd2282eac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:08.205851+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e3f4dcdc-e22d-42ca-9024-12f2e6c3cc57', 'tools', 'https://www.arbeitsagentur.de/gebaerdensprache', 'active', NULL, '2026-03-15T17:24:08.685571+00:00', '{"id":"e3f4dcdc-e22d-42ca-9024-12f2e6c3cc57","title":"Informationen in Gebärdensprache","summary":{"de":"Übersicht zu den Seiten rund um die Angebote für Arbeitgeberinnen und Arbeitgeber"},"content":{"de":"Sehen Sie im Video, wie das Portal der BA aufgebaut ist und wie Sie schnell die Informationen finden, die Sie suchen. Überblick zu den Portalseiten für Bildungsträger, Netzwerke und Schulen Informationen zu den Voraussetzungen beim Bezug von Kurzarbeitergeld für Unternehmen Informationen zum Kurzarbeitergeld-Verfahren für Unternehmen Die Videos in Gebärdensprache finden Sie direkt in den monatlichen Presseinformationen zum Arbeitsmarkt. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/gebaerdensprache","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:08.685571+00:00","lastSeen":"2026-03-15T17:24:08.685571+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/gebaerdensprache","crawledAt":"2026-03-15T17:24:08.685571Z","crawlId":"tools-seeded-1773595448","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"7ed727d504221f3096a408068d1300f17804ca663b3336cd5f56efac2f366c74"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:08.686567+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, 