INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('12866f74-af9b-4f6f-bf13-0f60d994168a', 'tools', 'https://www.arbeitsagentur.de/jobsuche/', 'active', NULL, '2026-03-01T20:14:00Z', '{"id":"12866f74-af9b-4f6f-bf13-0f60d994168a","title":"Jobsuche","translations":{"de-LEICHT":{"title":"Jobs finden","timestamp":"2026-03-01T20:14:00Z","provenance":{"source":"https://www.arbeitsagentur.de/jobsuche/","crawledAt":"2026-03-01T20:14:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Die Jobsuche der BA bietet bundesweite Stellensuche mit Filtern nach Berufsfeld, Ort, Arbeitszeit und weiteren Kriterien."},"content":{"de":"Das Tool unterstützt sowohl schnelle Einstiege als auch detaillierte Suchstrategien. Es ist ein zentraler digitaler Zugang zu offenen Stellen im öffentlichen Vermittlungssystem."},"url":"https://www.arbeitsagentur.de/jobsuche/","topics":["employment","education"],"tags":["application_required","automatic"],"targetGroups":["unemployed","students"],"status":"active","toolType":"job-search","accessibility":{"languages":["de"],"screenReaderCompatible":true},"firstSeen":"2026-03-01T20:14:00Z","lastSeen":"2026-03-01T20:14:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.arbeitsagentur.de/jobsuche/","crawlId":"manual-curation-20260301-realdata-v1","checksum":"f61ef5b4f3d6fb7ad95ea4b0ea1f7c8c60f6bfc9b198f7bb3250d7e5d6a21d36","crawledAt":"2026-03-01T20:14:00Z"},"qualityScores":{"iqs":81.2,"ais":60.4,"computedAt":"2026-03-01T20:14:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1842f5ba-c6b7-4062-b91c-419133f57d9b', 'tools', 'https://www.arbeitsagentur.de/leichte-sprache', 'active', NULL, '2026-03-15T17:24:09.705286+00:00', '{"id":"1842f5ba-c6b7-4062-b91c-419133f57d9b","title":"Herzlich willkommen auf der Internet-Seite von der Bundesagentur für Arbeit!","summary":{"de":"Die Seite der Bundes-Agentur für Arbeit in Leichter Sprache. Jetzt informieren"},"content":{"de":"Infos über die Bundesagentur für Arbeit in Leichter Sprache Die Bundesagentur für Arbeit ist eine der größten deutschen Behörden. Es arbeiten über 110.000 Personen für die Bundesagentur für Arbeit. Zur Bundesagentur für Arbeit gehören: Der Hauptsitz ist in der Stadt Nürnberg. Ein Vorstand leitet die Bundesagentur für Arbeit. Andrea Nahles ist seit August 2022 die Vorsitzende vom Vorstand. Alle Menschen in Deutschland sollen eine Arbeit haben. Die Bundesagentur für Arbeit hilft dabei. Zum Beispiel: Sie hilft Menschen, die ihre Arbeit verloren haben. Sie hilft Arbeitgebern, die neue Mitarbeiter suchen."},"url":"https://www.arbeitsagentur.de/leichte-sprache","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:09.705286+00:00","lastSeen":"2026-03-15T17:24:09.705286+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/leichte-sprache","crawledAt":"2026-03-15T17:24:09.705286Z","crawlId":"tools-seeded-1773595449","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"36b26e4ad994e69cb4fff5f78cdb428e24a0b0895d99cdce2a4636167f79bbd3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:09.705286+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('54bf55eb-62bf-4445-9e77-d7bf363ad32f', 'tools', 'https://www.arbeitsagentur.de/menschen-mit-behinderungen/berufliche-rehabilitation', 'active', NULL, '2026-03-15T17:24:10.226433+00:00', '{"id":"54bf55eb-62bf-4445-9e77-d7bf363ad32f","title":"Berufliche Rehabilitation","summary":{"de":"Am Arbeitsleben teilhaben – trotz gesundheitlicher Einschränkungen: Eine berufliche Reha hilft Ihnen weiter. Jetzt informieren!"},"content":{"de":"Sie sind gesundheitlich beeinträchtigt und haben es deshalb schwerer als andere, ins Berufsleben einzusteigen, eine Arbeit zu finden oder zu behalten. Egal, ob eine Behinderung, ein Unfall oder eine Erkrankung die Ursache ist: Wir unterstützen Sie unter bestimmten Voraussetzungen mit Maßnahmen der beruflichen Rehabilitation. Das gilt auch, wenn Ihnen eine Behinderung droht, die Ihre Fähigkeit zu arbeiten einschränken würde. Berufliche Rehabilitation hilft Menschen mit gesundheitlichen Problemen in unterschiedlichen Situationen weiter: Eine spezielle Berufsvorbereitung oder Unterstützung bei der Suche nach einem geeigneten Ausbildungsplatz helfen dabei, ins Arbeitsleben einzusteigen. Technische Arbeitshilfen können dafür sorgen, dass der Beruf trotz Einschränkungen weiter ausgeübt werden kann. Kann der bisherige Beruf nicht weiter ausgeübt werden, hilft die berufliche Rehabilitation dabei, sich beruflich neu zu orientieren. Anschließend können möglicherweise eine Weiterbildung oder Umschulung folgen. Die Unterstützungsmöglichkeiten im Rahmen der beruflichen Rehabilitation werden unter dem Begriff Leistungen zur Teilhabe am Arbeitsleben zusammengefasst. Gemeinsam mit Ihnen wählen wir die erforderlichen Maßnahmen für Ihre berufliche Rehabilitation aus. Dabei beziehen wir Ihre Fähigkeiten, Interessen und Neigungen mit ein."},"url":"https://www.arbeitsagentur.de/menschen-mit-behinderungen/berufliche-rehabilitation","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:10.226433+00:00","lastSeen":"2026-03-15T17:24:10.226433+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/menschen-mit-behinderungen/berufliche-rehabilitation","crawledAt":"2026-03-15T17:24:10.226433Z","crawlId":"tools-seeded-1773595450","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"e9f374ea88cdcf49ac594db5dcbef912e39fbdc5ef78cb4df948f7f8d7d2daed"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:10.226433+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('eb5a363f-6f5b-4e78-bcc8-14465c9290e3', 'tools', 'https://www.arbeitsagentur.de/rechtliche-hinweise', 'active', NULL, '2026-03-15T17:24:10.690177+00:00', '{"id":"eb5a363f-6f5b-4e78-bcc8-14465c9290e3","title":"Rechtliche Hinweise","summary":{"de":"Rechtliche Hinweise für Inhalte der Bundesagentur für Arbeit"},"content":{"de":"Es ist das Anliegen der Bundesagentur für Arbeit (BA), die Inhalte ihres Internetangebots stets inhaltlich richtig und aktuell verfügbar zu halten. Die Inhalte der Webseite werden sorgfältig verfasst und regelmäßig auf ihre Aktualität hin überprüft. Das Auftreten von Fehlern kann bei der Vielzahl von Themen und Informationen nicht völlig ausgeschlossen werden. Die BA übernimmt daher keine Gewähr dafür, dass alle Angaben des Internetauftritts zu jeder Zeit vollständig, richtig und in letzter Aktualität dargestellt sind. Die Darstellung der Inhalte orientiert sich an den Bedürfnissen der Kundinnen und Kunden der BA. Die BA bemüht sich, rechtliche Inhalte klar und verständlich darzustellen und dabei Rechts- oder Fachbegriffe nach Möglichkeit zu vermeiden. Trotzdem gilt: Rechtlich verbindlich ist das, was im Gesetz steht. Die Angaben im Internetauftritt der BA berücksichtigen möglicherweise nicht Ihre persönliche Situation. Suchen Sie daher bei weiteren Fragen die persönliche Beratung in der für Sie zuständigen Agentur für Arbeit oder Ihrem Jobcenter. Alle Angaben können ohne vorherige Ankündigung ergänzt, entfernt oder geändert werden. Für einzelne Inhalte des Internetauftritts der BA, insbesondere Dienste, die eine vorherige Registrierung/Anmeldung erfordern, können gesonderte zusätzliche Nutzungsbedingungen gelten, die ggf. bei der Nutzung zu beachten sind. Links zu Webseiten Dritter werden auf dieser Website als reine Serviceleistung, bzw. als Hinweis auf weiterführende Quellen angeboten. Für die Inhalte, zu denen verlinkt wird, sind die Anbieter der jeweiligen Webseiten ausschließlich selbst verantwortlich. Die BA macht sich diese Inhalte nicht zu eigen. Anbieter sind für die eigenen Inhalte, die sie zur Nutzung bereithalten, nach den allgemeinen Gesetzen verantwortlich. Von diesen eigenen Inhalten sind Querverweise auf die von anderen Anbietern bereitgehaltenen Inhalte zu unterscheiden."},"url":"https://www.arbeitsagentur.de/rechtliche-hinweise","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:10.690177+00:00","lastSeen":"2026-03-15T17:24:10.690177+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.arbeitsagentur.de/rechtliche-hinweise","crawledAt":"2026-03-15T17:24:10.690177Z","crawlId":"tools-seeded-1773595450","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur","providerName":"Bundesagentur für Arbeit","providerLevel":"federal","checksum":"1a64582bc6d927902a2575e1c825941ce3ebfb5dfd1ad67721677f9e7b0a952c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:10.690177+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ccd97f55-248e-4f76-885b-6f932a547d80', 'tools', 'https://www.bafza.de/klartext', 'active', NULL, '2026-03-15T17:24:28.422443+00:00', '{"id":"ccd97f55-248e-4f76-885b-6f932a547d80","title":"Klartext","summary":{"de":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben"},"content":{"de":"Für die Mitarbeitenden des Bundesamtes für Familie und zivilgesellschaftliche Aufgaben ( BAFzA ) ist der Name Programm: Wir engagieren uns gemeinsam für eine tolerante und offene Gesellschaft, fördern zivilgesellschaftliche Projekte und setzen uns für die Belange der Bürger*innen ein. Ausgrenzung, Spaltung, Intoleranz, gruppenbezogene Menschenfeindlichkeit sowie jedes Verhalten, das sich gegen die demokratische Grundordnung und die rechtsstaatlichen Grundsätze richtet, haben in unserem Denken und Handeln keinen Platz. Für uns zählt das Miteinander. Denn eine freiheitliche Demokratie lebt von der aktiven Teilhabe und dem sozialen Engagement ihrer Mitglieder. Telefon: 0221 3673-0 Telefax: 0221 3673-4661 E-Mail: service[at]bafza.bund.de Postanschrift: Bundesamt für Familie und zivilgesellschaftliche Aufgaben 50964 Köln Besucheranschrift: An den Gelenkbogenhallen 2-6 50679 Köln"},"url":"https://www.bafza.de/klartext","topics":["family","aid","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:28.422443+00:00","lastSeen":"2026-03-15T17:24:28.422443+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bafza.de/klartext","crawledAt":"2026-03-15T17:24:28.422443Z","crawlId":"tools-seeded-1773595468","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bafza","providerName":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben","providerLevel":"federal","checksum":"d91495a087ce9040e1f2f21e773ad695d0c98c2677362e0a1f9bf0f15505ea94"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:28.422443+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('829c9fb3-6277-4829-ae7d-940f5490f877', 'tools', 'https://www.bafza.de/ueber-das-bundesamt/aktuelles/detailansicht?cHash=8681f8050e7c760b9767e2c8992c74d0&tx_news_pi1%5Bnews%5D=1166', 'active', NULL, '2026-03-15T17:24:42.354683+00:00', '{"id":"829c9fb3-6277-4829-ae7d-940f5490f877","title":"Ein bunter Dom fürs Bundesamt","summary":{"de":"So wie in Berlin bereits seit einigen Jahren bunte Bären das Stadtbild prägen, tummeln sich in Dortmund seit der Fußball-Weltmeisterschaft 2006 bunte Nashörner – und in Köln seit 2018 bunte Dome."},"content":{"de":"So wie in Berlin bereits seit einigen Jahren bunte Bären das Stadtbild prägen, tummeln sich in Dortmund seit der Fußball-Weltmeisterschaft 2006 bunte Nashörner – und in Köln seit 2018 bunte Dome."},"url":"https://www.bafza.de/ueber-das-bundesamt/aktuelles/detailansicht?cHash=8681f8050e7c760b9767e2c8992c74d0&tx_news_pi1%5Bnews%5D=1166","topics":["family","aid","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:42.354683+00:00","lastSeen":"2026-03-15T17:24:42.354683+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bafza.de/ueber-das-bundesamt/aktuelles/detailansicht?cHash=1e6b8211eb12bf607b854d5a5b9fbacf&tx_news_pi1%5Bnews%5D=1166","crawledAt":"2026-03-15T17:24:42.354683Z","crawlId":"tools-seeded-1773595482","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bafza","providerName":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben","providerLevel":"federal","checksum":"8fbd9d6dea65c8fd862d21c3b3a57f97d5208b08850a83b386f9d6c87909a567"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:24:42.354683+00:00"