INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5a7f4f2b-5850-4bb7-845b-8d9e9274ed94', 'tools', 'https://www.bafza.de/ueber-das-bundesamt/wegbeschreibung/bafza-koeln', 'active', NULL, '2026-03-15T17:24:45.429017+00:00', '{"id":"5a7f4f2b-5850-4bb7-845b-8d9e9274ed94","title":"BAFz A Köln","summary":{"de":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben"},"content":{"de":"Sofern Sie die Funktion „ Find my Location “ benutzen, werden Ihre Standortdaten an das Bundesamt für Kartographie und Geodäsie übermittelt. Weiter Informationen hierzu finden Sie hier. Aus allen Richtungen folgen Sie bitte den grünen Hinweisschildern: Kölnmesse Congress Centrum Ost. Direkt gegenüber dem Messeeingang befindet sich das weiße Bürogebäude. Vom Kölner Hauptbahnhof haben Sie folgende Möglichkeiten, um zum Bahnhof Köln-Deutz/Messe zu gelangen: Den Bahnhof Köln-Deutz/Messe durch den Hauptausgang verlassen und links halten (an den Gleisen entlang) Unter der Eisenbahnbrücke links in die Deutz-Mülheimer Straße einbiegen"},"url":"https://www.bafza.de/ueber-das-bundesamt/wegbeschreibung/bafza-koeln","topics":["family","aid","digital_service","tools"],"tags":["application_required","tool"],"targetGroups":["families","general_public","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:45.429017+00:00","lastSeen":"2026-03-15T17:24:45.429017+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bafza.de/ueber-das-bundesamt/wegbeschreibung/bafza-koeln","crawledAt":"2026-03-15T17:24:45.429017Z","crawlId":"tools-seeded-1773595485","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bafza","providerName":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben","providerLevel":"federal","checksum":"4c10283671afece124b71498730ddf2feb530870fbff365e258a2e4e3a806ec9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:45.429017+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('55636445-397d-485d-8848-1367ffc93eb8', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj', 'active', NULL, '2026-03-15T17:24:46.468012+00:00', '{"id":"55636445-397d-485d-8848-1367ffc93eb8","title":"BMBFSFJ","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Am 8. März ist Bundesfrauenministern Karin Prien nach New York gereist, um an der 70. Frauenrechtskommission der Vereinten Nationen (UN) teilzunehmen. Im Fokus der Konferenz: der Zugang zu Recht und Justiz für Frauen und Mädchen weltweit. Mit der Braunschweiger Zeitung hat Bundesfrauenministerin Karin Prien darüber gesprochen, wie es um die Gleichstellung von Frauen steht und welche Rolle Künstliche Intelligenz (KI) dabei spielt. Am 10. März hat die Parlamentarische Staatssekretärin im Bundesbildungsministerium, Mareike Wulf, in Köln die didacta miteröffnet. Das Motto \"Alles im Wandel. Bildung im Fokus\" stellt Innovationen und mentale Gesundheit ins Zentrum. Das Bundesfamilienministerium bietet einen umfassenden Überblick über finanzielle Unterstützung für Familien in 2026. Informieren Sie sich über Kindergeld, Elterngeld, Kinderzuschlag und mehr. Flyer Das Pflegetelefon - Schnelle Hilfe für Angehörige"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:46.468012+00:00","lastSeen":"2026-03-15T17:24:46.468012+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj","crawledAt":"2026-03-15T17:24:46.468012Z","crawlId":"tools-seeded-1773595486","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"07a4926008202deac9010b7e5c080f219136934fb8598cffba7ac12d754333c7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:46.468012+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c1fbea23-6704-47cd-9f30-3ba24ec8ed19', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles', 'active', NULL, '2026-03-15T17:24:46.756215+00:00', '{"id":"c1fbea23-6704-47cd-9f30-3ba24ec8ed19","title":"Aktuell","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bundesfamilienministerin Karin Prien hat den Wettbewerb \"Kleine Lösungen - große Wirkung\" gestartet. Gesucht werden kleine und mittlere Unternehmen mit kreativen Ideen für die Vereinbarkeit von Familie und Beruf. Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Das Bundesfrauenministerium hat Dr. Petra Volke als deutsche Kandidatin für die Expertengruppe GREVIO des Europarats vorgestellt - ein bedeutender Beitrag Deutschlands zur Bekämpfung von geschlechtsspezifischer und häuslicher Gewalt. Presse Medienschaffende finden hier alle wichtigen Informationen aus der Pressestelle des Ministeriums: Pressemitteilungen, Kontaktdaten und Termine sowie Porträts. Medienschaffende finden hier alle wichtigen Informationen aus der Pressestelle des Ministeriums: Pressemitteilungen, Kontaktdaten und Termine sowie Porträts. Reden und Interviews Medieninterviews sowie ausgewählte Reden der Ministerin, der Parlamentarischen Staatssekretäre sowie der Staatssekretärin finden Sie hier."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:46.756215+00:00","lastSeen":"2026-03-15T17:24:46.756215+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles","crawledAt":"2026-03-15T17:24:46.756215Z","crawlId":"tools-seeded-1773595486","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"9efddec8c3edef5fd3326e44d0efe75fbc33258200d800b089a185e75b0681cd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:46.756215+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
