INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dec50ccb-950d-454b-a2e4-53669ba57064', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242', 'active', NULL, '2026-03-15T17:24:49.727335+00:00', '{"id":"dec50ccb-950d-454b-a2e4-53669ba57064","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Diese Erklärung zur Barrierefreiheit gilt für die unter www.bmbfsfj.bund.de veröffentlichte Website. Als öffentliche Stelle im Sinne der Richtlinie (EU) 2016/2102 ist das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend bestrebt, die Website www.bmbfsfj.bund.de im Einklang mit den Bestimmungen des Behindertengleichstellungsgesetztes des Bundes (BGG) sowie der Barrierefreien-Informationstechnik-Verordnung (BITV 2.0) zur Umsetzung der Richtlinie (EU) 2016/2102 barrierefrei zugänglich zu machen. Die Anforderungen der Barrierefreiheit ergeben sich aus § 3 Abs. 1 bis 4 und § 4 der BITV 2.0, die auf der Grundlage von § 12d BGG erlassen wurde. Zur Überprüfung der Anforderungen wurde im September 2023 ein BITV-Test durch den Prüfverbund BIK durchgeführt. Dabei wurde eine repräsentative Seitenauswahl untersucht. Der vollständige Prüfbericht kann hier eingesehen werden. Aufgrund der Überprüfung ist die Website mit den zuvor genannten Anforderungen teilweise vereinbar. Einige der im Prüfbericht festgestellten Mängel wurden zwischenzeitlich behoben. Die nachstehend aufgeführten Mängel bestehen nach wie vor: Die Inhalte im Logoband auf der Startseite sind im Lesemodus des Screenreaders nur eingeschränkt nutzbar. Das Verhalten (Ein- und Ausblenden von Inhalten) wird über Fokus-Events gesteuert, die im Screenreader zu leeren oder irreführenden Ausgaben führen können (WCAG 2.1, 1.3.2 Meaningful Sequence, Level A). Anderssprachige Inhalte (Wörter, Textabschnitte) in Überschriften sind nicht ausgezeichnet, das kann die Nutzung mit dem Screenreader erschweren (WCAG 2.1, 3.1.2 Language of Parts, Level AA)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:49.727335+00:00","lastSeen":"2026-03-15T17:24:49.727335+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242","crawledAt":"2026-03-15T17:24:49.727335Z","crawlId":"tools-seeded-1773595489","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"986e6662a17704c3a3636f3fd9c614fc192305ebf0f3e3d325e4081d3683feb9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:49.727335+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('86eb9e91-8b68-498d-bd99-2698f3ba1b38', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428', 'active', NULL, '2026-03-15T17:24:50.786307+00:00', '{"id":"86eb9e91-8b68-498d-bd99-2698f3ba1b38","title":"Informationen zur Verarbeitung personenbezogener Daten","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Zu den Aufgaben des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ) gehört es unter anderem, die Öffentlichkeit über seine Arbeit zu informieren. Dies umfasst die Bereitstellung von Informationen im Internet und in Sozialen Netzwerken, die direkte Kommunikation mit Bürgerinnen und Bürgern beziehungsweise der Fachöffentlichkeit, den Empfang von Besuchergruppen im Ministerium und die Organisation von Fachveranstaltungen. Sofern bei diesen Tätigkeiten personenbezogene Daten verarbeitet werden, geschieht dies auf Grundlage der rechtlichen Bestimmungen, insbesondere der Europäischen Datenschutz-Grundverordnung (EU DSGVO) und dem Bundesdatenschutzgesetz (BDSG). Personenbezogene Daten sind alle Informationen, die sich auf einen (lebenden) Menschen beziehen, der entweder bereits identifiziert ist oder der durch diese Informationen identifizierbar wird. Identifizierbarkeit kann entweder durch eine Zusammenführung der vorliegenden Informationen oder unter Einbeziehung von zusätzlichen Maßnahmen erfolgen, zum Beispiel der Zuordnung zu einer Namenskennung, einer Kennnummer, zu Standortdaten, einer Online-Kennung oder mittels einer Recherche in allgemein zugänglichen Informationspools wie Datenbanken, Bibliotheken oder dem Internet. Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend ]init[ AG (Auftragsverarbeiter für Hosting und Betrieb) Köpenicker Str. 9, 10997 Berlin TV1 GmbH, Beta-Straße 9a, 85774 Unterföhring (Auftragsverarbeiter für Video-Streaming)"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:50.786307+00:00","lastSeen":"2026-03-15T17:24:50.786307+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428","crawledAt":"2026-03-15T17:24:50.787287Z","crawlId":"tools-seeded-1773595490","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"795e0e00dd77050a1c54295621cb6a58d5d240bd1c008eced43bf0c022b8a633"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:50.787287+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e96e4a0d-349a-41e1-b4a0-ebc958fcb409', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/informationsfreiheitsgesetz-99434', 'active', NULL, '2026-03-15T17:24:51.241735+00:00', '{"id":"e96e4a0d-349a-41e1-b4a0-ebc958fcb409","title":"Informationsfreiheitsgesetz","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Für die Behörden des Bundes gilt das Informationsfreiheitsgesetz (IFG). Danach hat jede Bürgerin und jeder Bürger einen voraussetzungslosen, wenn auch nicht ausnahmslosen Anspruch auf Zugang zu amtlichen Informationen gegenüber den Behörden des Bundes. Es liegt im eigenen Interesse von Antragstellern und Antragstellerinnen, den Antrag so bestimmt zu fassen, dass das Informationsbegehren klar erkennbar ist. Dem Informationsanspruch können Ausnahmegründe entgegenstehen. Das IFG schützt – mit unterschiedlichen Abwägungsmaßstäben – öffentliche Belange (§ 3 IFG), laufende Verfahren (§ 4 IFG), personenbezogene Daten (§ 5 IFG) sowie Betriebs- und Geschäftsgeheimnisse und das geistige Eigentum (§ 6 IFG). Die Informationen sollen Antragstellern innerhalb eines Monats zugänglich gemacht werden. Sofern es sich nicht um die Erteilung einer einfachen Auskunft handelt, werden für Amtshandlungen der Behörden (Bearbeitungsaufwand für die Antragsbearbeitung) nach dem IFG Gebühren und Auslagen erhoben (§ 10 IFG). Nähere Informationen hierzu finden Sie in der Verordnung über die Gebühren und Auslagen nach dem Informationsfreiheitsgesetz."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/informationsfreiheitsgesetz-99434","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:51.241735+00:00","lastSeen":"2026-03-15T17:24:51.241735+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/informationsfreiheitsgesetz-99434","crawledAt":"2026-03-15T17:24:51.242753Z","crawlId":"tools-seeded-1773595491","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"46b3001670a648a71dab94fecd1e014d9bc9d7f5ab42ea696b76bb7735a05027"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:51.242753+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
