INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bf895d0a-0bfd-4306-ae6c-9a3122a5c43b', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/meta/en', 'active', NULL, '2026-03-15T17:24:52.285128+00:00', '{"id":"bf895d0a-0bfd-4306-ae6c-9a3122a5c43b","title":"Federal Ministry for Education, Family Affairs, Senior Citizens, Women and Youth","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Accept Decline"},"content":{"de":"Families Family is where people of different generations accept long-term responsibility for one another and in doing so, support and care for each other. Family is where people of different generations accept long-term responsibility for one another and in doing so, support and care for each other. Older Persons Policy-making for senior citizens means policy-making with them - they must be allowed to participate. Valuing their experience and life achievements and giving them more scope and influence makes society stronger. Policy-making for senior citizens means policy-making with them - they must be allowed to participate. Valuing their experience and life achievements and giving them more scope and influence makes society stronger. Equality Germany''s Grundgesetz (Basic Law) states that women and men are equal and that the state has to promote substantive, de facto gender equality. Germany is also committed to fulfilling its gender equality obligations under European law as well as international human rights law, for example by having ratified the UN Convention on the Elimination of All Forms of Discrimination against Women and its Optional Protocol. Germany''s Grundgesetz (Basic Law) states that women and men are equal and that the state has to promote substantive, de facto gender equality. Germany is also committed to fulfilling its gender equality obligations under European law as well as international human rights law, for example by having ratified the UN Convention on the Elimination of All Forms of Discrimination against Women and its Optional Protocol."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/en","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:52.285128+00:00","lastSeen":"2026-03-15T17:24:52.285128+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/en","crawledAt":"2026-03-15T17:24:52.285128Z","crawlId":"tools-seeded-1773595492","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"8c2d30ea260612e88e652b5081c1f6bc5bf4082794bcff9c061eed5c885a271e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:52.285128+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('64c94cff-f801-4f1f-a656-caf22df50613', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/meta/gebaerdensprache', 'active', NULL, '2026-03-15T17:24:52.743900+00:00', '{"id":"64c94cff-f801-4f1f-a656-caf22df50613","title":"Deutsche Gebärdensprache","summary":{"de":"Arbeit und Aufgaben des Bundesfamilien­ministeriums gebaerdensprache-aufgaben Das Bundesfamilienministerium ist zuständig für die Politikbereiche \"Familie\", \"Ältere Menschen\"..."},"content":{"de":"Das Bundesfamilienministerium ist zuständig für die Politikbereiche \"Familie\", \"Ältere Menschen\", \"Gleichstellung\", \"Kinder und Jugend\" und \"Freiwilliges Engagement\". In diesem Video erklären wir Ihnen Arbeit und Aufgaben des Ministeriums."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/gebaerdensprache","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:52.743900+00:00","lastSeen":"2026-03-15T17:24:52.743900+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/gebaerdensprache","crawledAt":"2026-03-15T17:24:52.743900Z","crawlId":"tools-seeded-1773595492","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"52197b300c1db625e73b58e6e982f0563ed6510bbe32b7b9cebffd436a1761db"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:52.743900+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c2f32630-f50a-4cc9-945a-8714a84c1186', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/meta/leichte-sprache', 'active', NULL, '2026-03-15T17:24:53.280861+00:00', '{"id":"c2f32630-f50a-4cc9-945a-8714a84c1186","title":"Leichte Sprache","summary":{"de":"Herzlich willkommen auf der Internet-Seite vom Bundes-Ministerium für Bildung, Familie, Senioren, Frauen und Jugend Auf dieser Seite erklären wir Ihnen die Aufgaben vom Bundes-Ministerium. Und..."},"content":{"de":"Auf dieser Seite erklären wir Ihnen die Aufgaben vom Bundes-Ministerium. Und wir erklären Ihnen die Internet-Seite. Das Bundes-Ministerium gehört zur Bundes-Regierung. Ein wichtiges Thema vom Bundes-Ministerium sind Familien. Deshalb heißt das Ministerium auch kurz: Bundes-Familien-Ministerium. Wir machen zum Beispiel Vorschläge für Gesetze, damit Familien Geld bekommen. Und wir helfen Familien bei der Kinder-Erziehung. Ein anderes Thema vom Ministerium sind alte Menschen. Wir wollen, dass alte Menschen gut und sicher leben. Manchmal brauchen alte Menschen Hilfe von der Familie. Die Familie soll genug Zeit haben für alte Menschen. Zum Beispiel bei der Pflege. Wir setzen uns für Gleich-Stellung ein. Gleich-Stellung heißt: Männer und Frauen werden gleich behandelt. Und sie haben die gleichen Möglichkeiten. Frauen sollen für ihre Arbeit gleich viel Geld bekommen wie Männer. Und wir wollen Frauen vor Gewalt schützen. Viele Mütter und Väter arbeiten. Dann muss sich jemand um das Kind kümmern."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/leichte-sprache","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:53.280861+00:00","lastSeen":"2026-03-15T17:24:53.280861+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/leichte-sprache","crawledAt":"2026-03-15T17:24:53.281395Z","crawlId":"tools-seeded-1773595493","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"cb4f4ad2c9fc3548aab34416f031b98a9deb01b91b366ed3ec3b26ff0758df58"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:53.281395+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b456656f-9798-4c12-8676-d0492ddee452', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/nachhaltigkeit-im-berufsalltag-276056', 'active', NULL, '2026-03-15T17:24:53.772791+00:00', '{"id":"b456656f-9798-4c12-8676-d0492ddee452","title":"Nachhaltigkeit im Berufsalltag","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Mit der Broschüre soll die Bedeutung von Beruflicher Bildung für nachhaltige Entwicklung (BBNE) im beruflichen Alltag konkret aufgezeigt, verständlich und (be-)greifbar gemacht werden. Anschaulich schildern Ausbildende, Auszubildende sowie Führungskräfte ihre Erfahrungen aus der Projektarbeit."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/nachhaltigkeit-im-berufsalltag-276056","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:53.772791+00:00","lastSeen":"2026-03-15T17:24:53.772791+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/nachhaltigkeit-im-berufsalltag-276056","crawledAt":"2026-03-15T17:24:53.772791Z","crawlId":"tools-seeded-1773595493","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b53db85546baa04a1f74066ca2d6b7dc0bdfaf7443f3282c096be6a8c044c2e5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:53.772791+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
