ance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/service/online-rechner/projekt-landkarte","crawledAt":"2026-03-15T16:05:26.223020Z","crawlId":"tools-seeded-1773590726","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"9a1f8c31e8cefc2bb16598cddccdd502d0b6e9ad946edf53354bc671c4c88883"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:05:26.223020+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5e86decc-0b1b-45ed-b0be-3e5f73068dac', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen', 'active', NULL, '2026-03-15T17:25:02.280074+00:00', '{"id":"5e86decc-0b1b-45ed-b0be-3e5f73068dac","title":"Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bildung ist der Schlüssel zu gesellschaftlicher Teilhabe, sozialem Aufstieg, Fortschritt und persönlicher Freiheit. Indem wir uns für beste Bildung einsetzen, unterstützen wir Menschen dabei, Chancen zu erkennen und ihre Ziele und Träume zu verwirklichen. Familien darin zu unterstützen, ihr Leben nach den eigenen Vorstellungen gestalten zu können - das ist das Ziel einer guten Familienpolitik. Dafür brauchen Familien vor allem Zeit für Kinder und Beruf, finanzielle Stabilität und eine gute Kinderbetreuung. Auch im hohen Alter selbstbestimmt leben und an der Gesellschaft teilhaben - das wünschen sich die meisten Menschen. Sie dabei zu unterstützen, ist zentrales Ziel der Seniorenpolitik. Die Gleichstellung von Frauen und Männern ist eine der zentralen Herausforderungen, um das Leben in unserem Land zukunftsfähig und gerecht zu gestalten. Dafür müssen Frauen und Männer auf dem gesamten Lebensweg die gleichen Chancen erhalten – persönlich, beruflich und familiär. Alle Kinder und Jugendlichen haben ein Recht auf ein beschütztes Auf­wachsen und gleiche Chancen - unabhängig von Herkunft, Geschlecht, Religion oder dem sozialen Status. Chancengleichheit und der Schutz von Kindern und Jugendlichen ist daher ein zentrales Anliegen des Bundesjugendministeriums. Das Bundesfamilienministerium versteht sich als Partner der Zivilgesellschaft - auf Augenhöhe mit Millionen von freiwillig engagierten Bürgerinnen und Bürgern, Vereinen, Verbänden, Unternehmen und Stiftungen. Deshalb unterstützt es die starke Engagementlandschaft in Deutschland."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:02.280074+00:00","lastSeen":"2026-03-15T17:25:02.280074+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","crawledAt":"2026-03-15T17:25:02.280074Z","crawlId":"tools-seeded-1773595502","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"43ef03c9d0cf69a77a3c1da876724d2d4a013400ea212128037294de8fac706a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:02.280074+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e9e38eb7-9651-4fda-b84f-3012da6f3f7a', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen', 'active', NULL, '2026-03-15T17:25:02.805883+00:00', '{"id":"e9e38eb7-9651-4fda-b84f-3012da6f3f7a","title":"Politik für ältere Menschen","summary":{"de":"Selbstbestimmung und Teilhabe an der Gesellschaft auch im Alter - das ist zentrales Ziel der Seniorenpolitik des Bundesseniorenministeriums."},"content":{"de":"Eine neue Studie zeigt: Die große Mehrheit der über 65-Jährigen nutzt das Internet und wünscht sich mehr Tempo bei der Digitalisierung. Karin Prien und Bitkom-Präsident Ralf Wintergerst stellten die Ergebnisse am 15. Januar vor. Michael Brand hat sich in Köln mit dem Direktor des Zentrums für Palliativmedizin Prof. Dr. Raymond Voltz und Ärztin Dr. Birgit Weihrauch über neue Ansätze zur Betreuung und Begleitung schwerstkranker und sterbender Menschen ausgetauscht. Der Parlamentarische Staatssekretär Michael Brand spricht zum Bundeshaushalt 2026 im Bundestag und betont, wie wichtig gezielte und strukturelle Reformen für bessere Bildung, starke Familien und eine resiliente Demokratie sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:02.805883+00:00","lastSeen":"2026-03-15T17:25:02.805883+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen","crawledAt":"2026-03-15T17:25:02.805883Z","crawlId":"tools-seeded-1773595502","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"8d1485c988f93f6fc075164388930fa31a0aea71b67dd2609c77913dfe765996"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:02.805883+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('565f8bd9-cc97-4792-8ddd-66eeb789cc93', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter', 'active', NULL, '2026-03-15T17:25:03.302449+00:00', '{"id":"565f8bd9-cc97-4792-8ddd-66eeb789cc93","title":"Aktiv im Alter","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bildung und Digitalisierung im Alter Bildung und digitale Kompetenzen sind für ältere Menschen eine wichtige Voraussetzung, um aktiv und selbstbestimmt am gesellschaftlichen Leben teilzuhaben. Das Bundesseniorenministerium unterstützt sie dabei. Bildung und digitale Kompetenzen sind für ältere Menschen eine wichtige Voraussetzung, um aktiv und selbstbestimmt am gesellschaftlichen Leben teilzuhaben. Das Bundesseniorenministerium unterstützt sie dabei. Allianz gegen Einsamkeit Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung wirksam zu begegnen - zum Beispiel mit Orten, an die sich einsame Menschen wenden können. Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung wirksam zu begegnen - zum Beispiel mit Orten, an die sich einsame Menschen wenden können. Altersberichte Seit 1993 erscheint in jeder Legislaturperiode ein Altersbericht zu einem seniorenpolitischen Thema. Die Altersberichte sind wichtige Entscheidungsgrundlage für die Seniorenpolitik des Bundes. Seit 1993 erscheint in jeder Legislaturperiode ein Altersbericht zu einem seniorenpolitischen Thema. Die Altersberichte sind wichtige Entscheidungsgrundlage für die Seniorenpolitik des Bundes."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:03.302449+00:00","lastSeen":"2026-03-15T17:25:03.302449+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter","crawledAt":"2026-03-15T17:25:03.302449Z","crawlId":"tools-seeded-1773595503","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"22c6111d13fc21654f7b44de3549b5e112d747adb44469c1e09210883b5fdcda"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:03.302449+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('034dce40-816a-4b43-862a-8bb464e80b51', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege', 'active', NULL, '2026-03-15T17:25:03.778760+00:00', '{"id":"034dce40-816a-4b43-862a-8bb464e80b51","title":"Pflegeausbildung","summary":{"de":"Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der..."},"content":{"de":"Ausbildung zur Pflegefachperson Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Eckpunkte für eine neue bundeseinheitliche Pflegeassistenzausbildung Eine neue bundeseinheitliche Pflegeassistenzausbildung soll die Ausbildung attraktiver machen und einen effektiven Qualifikationsmix in der Pflege unterstützen. Eine neue bundeseinheitliche Pflegeassistenzausbildung soll die Ausbildung attraktiver machen und einen effektiven Qualifikationsmix in der Pflege unterstützen. Ausbildungsoffensive Pflege Um die Einführung der neuen Pflegeausbildungen nach dem Pflegeberufegesetz zu unterstützen, hat das Bundesfamilienministerium gemeinsam mit dem Bundesgesundheitsministerium und dem Bundesarbeitsministerium eine Ausbildungsoffensive gestartet. Um die Einführung der neuen Pflegeausbildungen nach dem Pflegeberufegesetz zu unterstützen, hat das Bundesfamilienministerium gemeinsam mit dem Bundesgesundheitsministerium und dem Bundesarbeitsministerium eine Ausbildungsoffensive gestartet."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:03.778760+00:00","lastSeen":"2026-03-15T17:25:03.778760+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege","crawledAt":"2026-03-15T17:25:03.778760Z","crawlId":"tools-seeded-1773595503","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0f07f1bacb99b3233b06fdc095cf76c639b64631a1df4c5a3d84d07b567338fb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:03.778760+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f0b3f8d0-e919-42cd-ab32-1e462bee6364', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen', 'active', NULL, '2026-03-15T17:25:04.285170+00:00', '{"id":"f0b3f8d0-e919-42cd-ab32-1e462bee6364","title":"Ausbildung zur Pflegefachperson","summary":{"de":"Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller..."},"content":{"de":"Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Das Pflegeberufegesetz führt die bisherigen Berufsausbildungen der Altenpflege, der Gesundheits- und Krankenpflege und der Gesundheits- und Kinderkrankenpflege zusammen. Am 1. Januar 2020 ist die Pflegeausbildung zur Pflegefachperson gestartet. Sie ermöglicht es, in allen Versorgungsbereichen zu arbeiten. Damit werden die Ausbildungsbedingungen verbessert und die Attraktivität des Berufsfeldes Pflege wird gesteigert. Für die Ausbildung muss nun kein Schulgeld mehr bezahlt werden, die Auszubildenden erhalten eine angemessene Ausbildungsvergütung. Außerdem ist eine Ausbildung an einer Hochschule mit Bachelor-Niveau möglich. Damit wird die Pflegeausbildung attraktiver und neue Zielgruppen werden für die Pflege angesprochen. Mit dem Pflegeberufegesetz werden erstmals bestimmte berufliche Tätigkeiten festgelegt, die nur den Pflegefachpersonen vorbehalten sind. Der Pflegeberuf wird durch zusätzliche Einsatz- und Aufstiegsmöglichkeiten aufgewertet. Zum ersten Mal ist auch langfristig eine verbindliche Regelung vorgesehen, die Ausbildungskosten bei Umschulungsmaßnahmen vollständig zu finanzieren. Alle Auszubildenden starten mit dem Berufsziel \"Pflegefachperson\". Das ist im Ausbildungsvertrag mit dem Träger der praktischen Ausbildung festgelegt. Neben dem generalistischen Berufsabschluss nach drei Jahren in Vollzeitform beziehungsweise bis zu fünf Jahren in Teilzeitform können Auszubildende auch einen gesonderten Abschluss erlangen - als \"Altenpflegerin\" oder \"Altenpfleger\", als \"Gesundheits- und Kinderkrankenpfleger\" beziehungsweise \"Gesundheits- und Kinderkrankenpflegerin\". Die Möglichkeit, nach zwei Dritteln der Ausbildung einen gesonderten Abschluss zu wählen, haben die Auszubildenden, die zu Beginn ihrer Ausbildung einen Vertiefungseinsatz in der Altenpflege oder Kinderkrankenpflege gewählt haben. Mit dem Pflegeberufegesetz wird ein Pflegestudium zur unmittelbaren Berufsqualifizierung mit erweitertem Ausbildungsziel eingeführt. Die Berufsbezeichnung \"Pflegefachperson\" wird in Verbindung mit dem akademischen Grad (zum Beispiel \"B.Sc.\") geführt. Die mit dem Pflegestudiumstärkungsgesetz eingeführte Ausbildungsvergütung für Studierende erhöht die Attraktivität einer hochschulischen Pflegeausbildung zusätzlich."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:04.285170+00:00","lastSeen":"2026-03-15T17:25:04.285170+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen","crawledAt":"2026-03-15T17:25:04.285170Z","crawlId":"tools-seeded-1773595504","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"167fea1151ea246574932e6534b4a5c70d6add59d8b34c23e8e066dd9e36dcbc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:04.286172+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6f0b32bb-4755-46e9-b5ea-b26c0a4982d3', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz', 'active', NULL, '2026-03-15T17:25:04.785651+00:00', '{"id":"6f0b32bb-4755-46e9-b5ea-b26c0a4982d3","title":"Demenz","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Informationen rund um Demenz Wegweiser Demenz, Alzheimer Telefon, Lokale Allianzen: Mit einem Wissens- und Hilfenetzwerk unterstützt das Bundesseniorenministerium Menschen mit Demenz und ihre Angehörigen. Wegweiser Demenz, Alzheimer Telefon, Lokale Allianzen: Mit einem Wissens- und Hilfenetzwerk unterstützt das Bundesseniorenministerium Menschen mit Demenz und ihre Angehörigen. Nationale Demenzstrategie Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern. Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern. Lokale Allianzen für Menschen mit Demenz Lokale Allianzen für Menschen mit Demenz sind Hilfe- und Unterstützungsnetzwerke mit Angeboten für Menschen mit Demenz und ihre Angehörigen. Das Bundesseniorenministerium fördert die Allianzen mit einem Bundesprogramm. Lokale Allianzen für Menschen mit Demenz sind Hilfe- und Unterstützungsnetzwerke mit Angeboten für Menschen mit Demenz und ihre Angehörigen. Das Bundesseniorenministerium fördert die Allianzen mit einem Bundesprogramm."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:04.785651+00:00","lastSeen":"2026-03-15T17:25:04.785651+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz","crawledAt":"2026-03-15T17:25:04.785651Z","crawlId":"tools-seeded-1773595504","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"681f8a80b830291ffccddbf56ce2a09c3a7894cc6024f883703ebd1ce208a744"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:04.785651+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b59e560c-2b48-4d5f-9613-73256da75b38', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie', 'active', NULL, '2026-03-15T17:25:05.265731+00:00', '{"id":"b59e560c-2b48-4d5f-9613-73256da75b38","title":"Nationale Demenzstrategie","summary":{"de":"Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern."},"content":{"de":"In Deutschland leben rund 1,8 Millionen Menschen mit einer Demenz. Bis zum Jahr 2050 wird die Zahl der Betroffenen voraussichtlich auf 2,8 Millionen steigen. Um dieser Herausforderung zu begegnen und um die Gesellschaft demenzfreundlich zu gestalten, hat die Bundesregierung die Nationale Demenzstrategie verabschiedet. Die Umsetzung hat am 23. September 2020 begonnen. Ziel der Strategie ist, die Lebenssituation von Menschen mit Demenz und ihren Angehörigen in Deutschland zu verbessern und ein offenes Klima für den Umgang mit Betroffenen zu schaffen. Dafür enthält die Nationale Demenzstrategie über 160 konkrete Maßnahmen, die in den kommenden Jahren umgesetzt werden sollen. Die Strategie definiert dafür vier Handlungsfelder: Strukturen zur gesellschaftlichen Teilhabe von Menschen mit Demenz an ihrem Lebensort aus- und aufbauen Menschen mit Demenz und ihre Angehörigen unterstützen Medizinische und pflegerische Versorgung von Menschen mit Demenz weiterentwickeln"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:05.265731+00:00","lastSeen":"2026-03-15T17:25:05.265731+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie","crawledAt":"2026-03-15T17:25:05.266739Z","crawlId":"tools-seeded-1773595505","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"bbafe6879832b08a1fb76c4c843e442d704475c91da6cc523c1af5dff47da81e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:05.266739+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ba8cc10e-1928-4209-98d5-d8d08a75df41', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen', 'active', NULL, '2026-03-15T17:25:05.770761+00:00', '{"id":"ba8cc10e-1928-4209-98d5-d8d08a75df41","title":"Internationale Politik für ältere Menschen","summary":{"de":"Der Anteil älterer Menschen an der Bevölkerung steigt weltweit. Das Bundesseniorenministerium setzt sich für ihre Belange, Rechte und gleichberechtigte Teilhabe ein - auch international. Das..."},"content":{"de":"Der Anteil älterer Menschen an der Bevölkerung steigt weltweit. Das Bundesseniorenministerium setzt sich für ihre Belange, Rechte und gleichberechtigte Teilhabe ein - auch international. Das stärkt den Zusammenhalt über Generationen und Länder hinweg. Die Menschen werden bei guter Gesundheit immer älter. In internationalen Gremien setzt sich die Bundesrepublik Deutschland für die Stärkung der Rechte Älterer ein - bei den Vereinten Nationen (VN), im Europarat, in der Europäischen Union (EU) und im direkten Erfahrungsaustausch mit Partnerstaaten. Insbesondere der fachliche Austausch mit Frankreich, Polen und Japan stellen hier Schwerpunkte dar. Die offene Arbeitsgruppe Altern (Open-Ended Working Group on Ageing - OEWGA) der VN befasste sich in 14 Sitzungen mit der Stärkung der Rechte älterer Menschen. Im Rahmen der jährlich stattfindenden Sitzungen in New York wurden in einer offenen Debatte wichtige Themenbereiche beleuchtet und mögliche Schutzlücken diskutiert. Am 23. Mai 2024 hat die OEWGA in einer Abschlussempfehlung 14 Bereiche für potentielle Lücken im internationalen Menschenrechtsschutz älterer Menschen identifiziert und elf Handlungsoptionen, wie diesen begegnet werden kann, vorgeschlagen. Die VN-Generalversammlung hat am 13. August 2024 das Mandat der OEWGA für erfüllt erklärt und die Arbeit der OEWGA mit einer Entschließung am 20. Dezember beendet. Alle einschlägigen VN-Gremien sind aufgefordert, sich mit den Empfehlungen der OEWGA zu befassen. Am 8. Mai 2025 wird ein hochrangiges Treffen entscheiden, welcher Nachfolgeprozess international aufgesetzt wird. In der Zwischenzeit hat der Menschenrechtsrat am 3. April 2025 die Einsetzung einer intergouvernementalen Arbeitsgruppe beschlossen, die einen Entwurf für ein rechtlich bindendes Instrument zum Schutz der Menschenrechte Älterer erarbeiten soll. Der Zweite Weltaltenplan der VN wurde im Jahr 2002 in Madrid beschlossen ( Madrid International Plan of Action on Ageing - MIPAA ). Dieser politische Aktionsplan wird von den Mitgliedsstaaten mit Hilfe von nationalen Aktionsplänen, die auf regionalen Implementierungsstrategien basieren, umgesetzt. Alle fünf Jahre informiert ein Nationaler Bericht über den Stand der Umsetzung des Weltaltenplans. Der letzte Bericht wurde 2021 unter Federführung des Bundesseniorenministeriums erstellt. Für die Umsetzung des Zweiten Weltaltenplans auf europäischer Ebene ist die Regionalkommission UNECE (United Nations Economic Commission for Europe) verantwortlich. Die zugehörige ständige Arbeitsgruppe Altern (UNECE - Standing Working Group on Ageing - UNECE-SWGA) hält alle fünf Jahre eine Ministerkonferenz ab, um europäische Lösungen zu entwickeln."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:05.770761+00:00","lastSeen":"2026-03-15T17:25:05.770761+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen","crawledAt":"2026-03-15T17:25:05.770761Z","crawlId":"tools-seeded-1773595505","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5b9fbd1a9bca4c757f2eaa3aa22a42fa2642ef0860b5ba6fa8f872c48d5bda73"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:05.772278+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8bc51d3f-32c8-450d-843a-9c0566cfc369', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege', 'active', NULL, '2026-03-15T17:25:06.302668+00:00', '{"id":"8bc51d3f-32c8-450d-843a-9c0566cfc369","title":"Letzte Wege - Begleitung am Lebensende","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Diagnose einer lebensbedrohlichen Erkrankung ändert alles. Unsicherheit, Trauer und Angst schleichen sich schnell auch in das Leben von Angehörigen. Das Bundesfamilienministerium fördert Projekte der Hospiz-und Palliativversorgung, um Sterbenden und deren Angehörigen beizustehen und sie gut zu unterstützen. Nana starb 2012 an Knochenkrebs. 15 Monate lang wurde sie von ihrer Familie in der Krankheit und zum Schluss auch im Sterben begleitet. Ihre Mutter, Barbara Stäcker, spricht im Interview über das, was in dieser Zeit wichtig war. Ihre Tochter Nana starb mit nur 21 Jahren an Krebs. Sie und Ihre Familie sind den Weg mit ihr gemeinsam gegangen. Was hat Ihnen allen in dieser Zeit besonders geholfen? BARBARA STÄCKER: Für Nana war am wichtigsten, dass sie ihre ganze Familie um sich hatte. Wir waren damals zu sechst im Haus: Nana und ihr Freund, unser Sohn mit seiner Freundin und wir Eltern. Damit hat man ganz automatisch eine gewisse Normalität im Alltag, die wir bis zum Schluss aufrechterhalten konnten. Jeder von uns ist sehr unterschiedlich mit Nana umgegangen und daher konnten wir ganz individuell auf ihre Bedürfnisse eingehen. Was war für Nana in dieser Zeit besonders wichtig? Ihr hat es viel bedeutet, dass sie ihre Ressourcen in dieser Zeit nutzen konnte. Wir haben kurze Ausflüge gemacht, wenn es ihr gut genug ging. Wir sind spontan alle zusammen in den Urlaub gefahren. Sie hat in dieser Zeit ihr Schmink- und Fotoprojekt \"Recover your Smile\" ins Leben gerufen. Am wichtigsten war ihr aber, dass wir offen und ehrlich miteinander umgegangen sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:06.302668+00:00","lastSeen":"2026-03-15T17:25:06.302668+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege","crawledAt":"2026-03-15T17:25:06.303667Z","crawlId":"tools-seeded-1773595506","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"762b63e1f2dcf5122fb0de1850a2456894cbd01bde91c0ec4e573df7703b77e4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:06.303667+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('debcbabc-c9fc-46d0-a43e-c148fe5596cd', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf', 'active', NULL, '2026-03-15T17:25:06.778363+00:00', '{"id":"debcbabc-c9fc-46d0-a43e-c148fe5596cd","title":"Vereinbarkeit von Pflege und Beruf","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Pflegetelefon Das Pflegetelefon des Bundesfamilienministeriums bietet Hilfe und Beratung. Es ist bundesweit von Montag bis Donnerstag derzeit zwischen 9:00 und 16:00 Uhr und per E-Mail: info@wege-zur-pflege.de erreichbar. Das Pflegetelefon des Bundesfamilienministeriums bietet Hilfe und Beratung. Es ist bundesweit von Montag bis Donnerstag derzeit zwischen 9:00 und 16:00 Uhr und per E-Mail: info@wege-zur-pflege.de erreichbar. Beirat für die Vereinbarkeit von Pflege und Beruf Der Unabhängige Beirat für die Vereinbarkeit von Pflege und Beruf besteht aus 21 Mitgliedern und befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Der Unabhängige Beirat für die Vereinbarkeit von Pflege und Beruf besteht aus 21 Mitgliedern und befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Familienpflegezeit Die Familienpflegezeit unterstützt Angehörige bei der Vereinbarkeit von Pflege und Beruf. Beschäftigte können sich für die Pflege eines nahen Angehörigen bis zu 24 Monate teilweise von der Arbeit freistellen lassen. Die Familienpflegezeit unterstützt Angehörige bei der Vereinbarkeit von Pflege und Beruf. Beschäftigte können sich für die Pflege eines nahen Angehörigen bis zu 24 Monate teilweise von der Arbeit freistellen lassen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:06.778363+00:00","lastSeen":"2026-03-15T17:25:06.778363+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf","crawledAt":"2026-03-15T17:25:06.778363Z","crawlId":"tools-seeded-1773595506","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5c4733594e4ddcf2015824cb4061c559545e4da438cebf873e73e11257464d99"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:06.778363+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f148621c-74fe-4ea5-a75a-054b5756f711', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter', 'active', NULL, '2026-03-15T17:25:07.294061+00:00', '{"id":"f148621c-74fe-4ea5-a75a-054b5756f711","title":"Zuhause im Alter","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Sicherheit im Alter In gemeinsamen Projekten haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei Konzepte erarbeitet, wie ältere Menschen besser vor Eigentums- und Vermögensdelikten oder gewalttätigen Übergriffen geschützt werden können. In gemeinsamen Projekten haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei Konzepte erarbeitet, wie ältere Menschen besser vor Eigentums- und Vermögensdelikten oder gewalttätigen Übergriffen geschützt werden können. Serviceportal \"Zuhause im Alter\" Das Serviceportal bietet Informationen und Hinweise zum Thema selbstständiges und selbstbestimmtes Wohnen im Alter. Das Serviceportal bietet Informationen und Hinweise zum Thema selbstständiges und selbstbestimmtes Wohnen im Alter. Eine neue Studie zeigt: Die große Mehrheit der über 65-Jährigen nutzt das Internet und wünscht sich mehr Tempo bei der Digitalisierung. Karin Prien und Bitkom-Präsident Ralf Wintergerst stellten die Ergebnisse am 15. Januar vor. Das Projekt \"Digitaler Engel\" des Vereins Deutschland sicher im Netz e. V. bietet digitale Aufklärung für ältere Menschen. Es wurde bei den European Digital Skills Awards 2025 in Brüssel in der Kategorie \"Cybersecurity Skills\" ausgezeichnet."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:07.294061+00:00","lastSeen":"2026-03-15T17:25:07.294061+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter","crawledAt":"2026-03-15T17:25:07.294061Z","crawlId":"tools-seeded-1773595507","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"10ffe011fb4af00b3b9b1c6c71f53bebf43a116b65abbcd9c65a95dfeef1e48b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:07.294061+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('829927d6-72b3-4d76-8a19-bc6bdb9e6392', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung', 'active', NULL, '2026-03-15T17:25:07.765867+00:00', '{"id":"829927d6-72b3-4d76-8a19-bc6bdb9e6392","title":"Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bundesbildungsministerin Karin Prien hat die Qualifizierungsoffensive Berufliche Bildung gestartet. Die Initiative soll dem Fachkräftemangel begegnen und die Ausbildung entlang der gesamten Bildungskette stärken. Für einen besseren Jugendmedienschutz ist die Kooperation der Online-Plattformen wichtig. Das betonte Dr. Petra Bahr, Staatssekretärin im Bundesjugendministerium, bei einem Austausch mit Vertretern der Unternehmen und Verbände. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:07.765867+00:00","lastSeen":"2026-03-15T17:25:07.765867+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung","crawledAt":"2026-03-15T17:25:07.765867Z","crawlId":"tools-seeded-1773595507","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b52a3e9a763304c09c0b8055bd009f5b851079543071604bdf33dfb8a6faa7cf"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:07.765867+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9a3a472f-b711-41e6-8c8b-271ccc68f676', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung', 'active', NULL, '2026-03-15T17:25:08.276688+00:00', '{"id":"9a3a472f-b711-41e6-8c8b-271ccc68f676","title":"Ausbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Ausbildung Wichtige praktische Berufserfahrungen und strukturiertes Lernen: Die duale Ausbildung bereitet junge Menschen perfekt auf ihre berufliche Karriere vor. Nebenbei sichert sie Fachkräfte für die Betriebe in Deutschland. Wichtige praktische Berufserfahrungen und strukturiertes Lernen: Die duale Ausbildung bereitet junge Menschen perfekt auf ihre berufliche Karriere vor. Nebenbei sichert sie Fachkräfte für die Betriebe in Deutschland. Berufliche Orientierung Stärken erkunden, Berufe ausprobieren: Berufliche Orientierung unterstützt junge Menschen mit vielfältigen Angeboten bei der Wahl ihres beruflichen Weges und stärkt so Teilhabe und Fachkräftesicherung. Stärken erkunden, Berufe ausprobieren: Berufliche Orientierung unterstützt junge Menschen mit vielfältigen Angeboten bei der Wahl ihres beruflichen Weges und stärkt so Teilhabe und Fachkräftesicherung. Auszubildende Während ihrer Ausbildung haben junge Menschen die Möglichkeit, konkrete praktische Erfahrungen mit theoretischem Wissen aus der Berufsschule zu verknüpfen. Auszubildende erhalten somit den idealen Start in die berufliche Karriere. Während ihrer Ausbildung haben junge Menschen die Möglichkeit, konkrete praktische Erfahrungen mit theoretischem Wissen aus der Berufsschule zu verknüpfen. Auszubildende erhalten somit den idealen Start in die berufliche Karriere."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:08.276688+00:00","lastSeen":"2026-03-15T17:25:08.276688+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung","crawledAt":"2026-03-15T17:25:08.276688Z","crawlId":"tools-seeded-1773595508","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"556ce8397fe047d019366eab30fbff77c259294f05778b05025449ff970c2c91"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:08.276688+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('cb496db8-ea1f-46df-8678-719142e446d2', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung', 'active', NULL, '2026-03-15T17:25:08.764155+00:00', '{"id":"cb496db8-ea1f-46df-8678-719142e446d2","title":"Außerschulische Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Außerschulische Bildung Von der Kita bis ins hohe Alter: Menschen bilden sich auch außerhalb der Schule weiter. Deshalb fördert das Bundesbildungsministerium unterschiedliche Programme, um Menschen die Möglichkeit zu geben, sich frei entfalten zu können. Von der Kita bis ins hohe Alter: Menschen bilden sich auch außerhalb der Schule weiter. Deshalb fördert das Bundesbildungsministerium unterschiedliche Programme, um Menschen die Möglichkeit zu geben, sich frei entfalten zu können. MINT-Bildung Die Ausbildung in einem MINT-Fach vermittelt zukunftsorientiertes Wissen für naturwissenschaftliche und technologische Zusammenhänge. Der MINT-Aktionsplan soll vor allem junge Menschen für MINT-Bildung begeistern. Die Ausbildung in einem MINT-Fach vermittelt zukunftsorientiertes Wissen für naturwissenschaftliche und technologische Zusammenhänge. Der MINT-Aktionsplan soll vor allem junge Menschen für MINT-Bildung begeistern. Stiftung Kinder forschen Wieso, weshalb, warum: Kinder sind neugierig und wollen die Welt mit allen Sinnen begreifen. Durch Bildung in den Bereichen Mathematik, Informatik, Naturwissenschaften und Technik (MINT) lernen Kinder, die Welt nachhaltig mitzugestalten. Wieso, weshalb, warum: Kinder sind neugierig und wollen die Welt mit allen Sinnen begreifen. Durch Bildung in den Bereichen Mathematik, Informatik, Naturwissenschaften und Technik (MINT) lernen Kinder, die Welt nachhaltig mitzugestalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:08.764155+00:00","lastSeen":"2026-03-15T17:25:08.764155+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung","crawledAt":"2026-03-15T17:25:08.765736Z","crawlId":"tools-seeded-1773595508","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f5b7dd585aafe4bc9cb172608812afc0746d4aeca2ecd571d8409169e9871ad9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:08.765736+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2a193dfa-4441-40e1-a9f4-a75b5236d25b', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung', 'active', NULL, '2026-03-15T17:25:09.283759+00:00', '{"id":"2a193dfa-4441-40e1-a9f4-a75b5236d25b","title":"Berufliche Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Beruflicher Erfolg wird praktisch erlebbar Moderne Rahmenbedingungen machen Berufsbildung attraktiv. Das Bundesbildungsministerium entwickelt Ausbildungsberufe weiter und gestaltet sie zukunftssicher, nachhaltig und digital. Moderne Rahmenbedingungen machen Berufsbildung attraktiv. Das Bundesbildungsministerium entwickelt Ausbildungsberufe weiter und gestaltet sie zukunftssicher, nachhaltig und digital. Anerkennung ausländischer Berufsqualifikationen Der Fachkräftemangel ist eine unserer größten Herausforderungen. Wir konkurrieren international um Fachkräfte. Unser Ziel: Ausländische Fachkräfte sollen ihre Fähigkeiten noch einfacher im Arbeitsmarkt einsetzen können. Der Fachkräftemangel ist eine unserer größten Herausforderungen. Wir konkurrieren international um Fachkräfte. Unser Ziel: Ausländische Fachkräfte sollen ihre Fähigkeiten noch einfacher im Arbeitsmarkt einsetzen können. Teilqualifikationen An- oder ungelernte Menschen können mit Teilqualifikationen einen Berufsabschluss erlangen. Das Bundesbildungsministerium fördert den Ausbau dieses Instruments zur Fachkräftesicherung, damit mehr Menschen eine berufliche Perspektive erhalten. An- oder ungelernte Menschen können mit Teilqualifikationen einen Berufsabschluss erlangen. Das Bundesbildungsministerium fördert den Ausbau dieses Instruments zur Fachkräftesicherung, damit mehr Menschen eine berufliche Perspektive erhalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:09.283759+00:00","lastSeen":"2026-03-15T17:25:09.283759+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung","crawledAt":"2026-03-15T17:25:09.283759Z","crawlId":"tools-seeded-1773595509","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"180d0232f2fe5ae0439b3418da5c5ff99497a27cd061e4f18568bacf4540a597"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:09.283759+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9192b7cd-9307-49b2-9258-400c88d4036a', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung', 'active', NULL, '2026-03-15T17:25:09.787959+00:00', '{"id":"9192b7cd-9307-49b2-9258-400c88d4036a","title":"Bildungsforschung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Bildungsforschung beschäftigt sich mit den Voraussetzungen, die es braucht, damit alle Menschen in Deutschland die beste Bildung erhalten. Bildungsforschende untersuchen hierbei fortlaufend die Stärken und Schwächen unseres Bildungssystems. Wie ermöglichen wir die beste Bildung für alle in Deutschland lebenden Menschen? Zur Beantwortung dieser Frage liefert die Bildungsforschung wichtige Erkenntnisse. Ob gleiche Chancen für alle, bessere Bildung oder Innovationen beim Lernen und Lehren: Bildungsforschung hilft, das Bildungssystem in Deutschland zu verbessern. Bildungsforschung trägt dazu bei, Ungleichheiten im Bildungssystem aufzuzeigen und wirksame Gegenstrategien zu entwickeln - damit alle Menschen gleiche Bildungschancen erhalten. Bildungsforschende werten fortlaufend die Stärken und Schwächen des Bildungswesens aus. Auf der Grundlage ihrer Erkenntnisse entstehen gezielte Maßnahmen zur Verbesserung der Qualität. Bildungsforschende liefern stichhaltige Daten und Erkenntnisse im Hinblick darauf, was oder wie wir lernen und welche Fähigkeiten wir in Zukunft brauchen. Fachleute aus Politik, Bildung und Verwaltung erhalten dadurch eine wissenschaftliche Grundlage, um Bildungsangebote an die Bedürfnisse der Bevölkerung anzupassen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:09.787959+00:00","lastSeen":"2026-03-15T17:25:09.787959+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung","crawledAt":"2026-03-15T17:25:09.787959Z","crawlId":"tools-seeded-1773595509","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"4922537e5ac3a2624d1c55c4b2dd75a25255820f70fab8439179b1f03c8845a9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:09.787959+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e447317c-da43-4f0c-9d6f-a5126ae69d58', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung', 'active', NULL, '2026-03-15T17:25:10.301875+00:00', '{"id":"e447317c-da43-4f0c-9d6f-a5126ae69d58","title":"Frühe Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Frühe Bildung Die frühe Bildung fördert Kinder in den ersten Lebensjahren und gibt ihnen die bestmöglichen Chancen für ihre spätere schulische und persönliche Entwicklung. Die frühe Bildung fördert Kinder in den ersten Lebensjahren und gibt ihnen die bestmöglichen Chancen für ihre spätere schulische und persönliche Entwicklung. Sprachliche Bildung Eine gute sprachliche Entwicklung stärkt Lernen, Austausch und Teilhabe an der Gesellschaft. Gezielte frühe sprachliche Förderung ermöglicht es Kindern, sich sicher mitzuteilen und Bildungswege erfolgreich zu gestalten. Eine gute sprachliche Entwicklung stärkt Lernen, Austausch und Teilhabe an der Gesellschaft. Gezielte frühe sprachliche Förderung ermöglicht es Kindern, sich sicher mitzuteilen und Bildungswege erfolgreich zu gestalten. Bildung für nachhaltige Entwicklung Bildung für nachhaltige Entwicklung (BNE) befähigt Menschen zu zukunftsfähigem Denken und Handeln. Sie vermittelt früh Kompetenzen, um ökologische, soziale und wirtschaftliche Zusammenhänge aktiv zu verstehen und nachhaltig mitzugestalten. Bildung für nachhaltige Entwicklung (BNE) befähigt Menschen zu zukunftsfähigem Denken und Handeln. Sie vermittelt früh Kompetenzen, um ökologische, soziale und wirtschaftliche Zusammenhänge aktiv zu verstehen und nachhaltig mitzugestalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:10.301875+00:00","lastSeen":"2026-03-15T17:25:10.301875+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung","crawledAt":"2026-03-15T17:25:10.301875Z","crawlId":"tools-seeded-1773595510","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"7261ef0efdfce298dde7779499bb8fb7a569cbcbc6c65f2973fb156852a56a1c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:10.301875+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('94603f31-d8d2-4582-80af-d997b713e91e', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung', 'active', NULL, '2026-03-15T17:25:10.766590+00:00', '{"id":"94603f31-d8d2-4582-80af-d997b713e91e","title":"Integration durch Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Inklusive Bildung Inklusive Bildung bedeutet, dass Menschen mit unterschiedlichen Lern- und Leistungsvoraussetzungen gemeinsam und gleichberechtigt lernen. Sie bildet die Grundlage für die persönliche Entwicklung und soziale Teilhabe aller Lernenden. Inklusive Bildung bedeutet, dass Menschen mit unterschiedlichen Lern- und Leistungsvoraussetzungen gemeinsam und gleichberechtigt lernen. Sie bildet die Grundlage für die persönliche Entwicklung und soziale Teilhabe aller Lernenden. Informationen für Geflüchtete Wer als Geflüchtete oder Geflüchteter nach Deutschland kommt, hat viele Fragen. Auf dieser Seite finden Sie einen ersten Überblick sowie hilfreiche Informationen zu bildungsspezifischen Unterstützungsangeboten in verschiedenen Sprachen. Wer als Geflüchtete oder Geflüchteter nach Deutschland kommt, hat viele Fragen. Auf dieser Seite finden Sie einen ersten Überblick sowie hilfreiche Informationen zu bildungsspezifischen Unterstützungsangeboten in verschiedenen Sprachen. Bildung für alle in der Einwanderungsgesellschaft Bildung ist der Schlüssel für Integration und Teilhabe. Als Gesellschaft profitieren wir, wenn alle ihre Talente und Fähigkeiten bestmöglich entwickeln und einbringen können. Bildung ist der Schlüssel für Integration und Teilhabe. Als Gesellschaft profitieren wir, wenn alle ihre Talente und Fähigkeiten bestmöglich entwickeln und einbringen können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:10.766590+00:00","lastSeen":"2026-03-15T17:25:10.766590+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung","crawledAt":"2026-03-15T17:25:10.766590Z","crawlId":"tools-seeded-1773595510","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d8ad9a4607042d5b901186f423d589e698c178aa529c1a2cc98ef95593d5f6c0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:10.766590+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0ed94712-173c-46b6-ab30-8bcf61e08013', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement', 'active', NULL, '2026-03-15T17:25:11.270701+00:00', '{"id":"0ed94712-173c-46b6-ab30-8bcf61e08013","title":"Kommunales Bildungsmanagement","summary":{"de":"Bessere Planung und Verteilung lokaler Ressourcen, bessere Transparenz über die Bildungsbedürfnisse der Menschen: ein datenbasiertes Bildungsmanagement bietet zahlreiche Vorteile für die Menschen..."},"content":{"de":"Bessere Planung und Verteilung lokaler Ressourcen, bessere Transparenz über die Bildungsbedürfnisse der Menschen: ein datenbasiertes Bildungsmanagement bietet zahlreiche Vorteile für die Menschen vor Ort. Die \" Transferinitiative Kommunales Bildungsmanagement\" unterstützt Städte und Landkreise darin, ein datenbasiertes Bildungsmanagement aufzubauen. Dieses hilft, vor Ort passende Bildungsangebote für alle Lebensphasen anzubieten und zukunftsfähig zu gestalten. Ein datenbasiertes kommunales Bildungsmanagement hilft, mehr Transparenz über die Bildungsbedürfnisse der Menschen in allen Lebensphasen zur Bereitstellung eines individualisierten Bildungsangebots zu schaffen. Eine bessere Planung und Verteilung lokaler Ressourcen unter Einbindung der Zivilgesellschaft und von Kooperationsnetzwerken werden möglich. Außerdem ergibt sich eine stärkere Resilienz bei Krisensituationen durch schnellen Zugriff auf kontinuierlich fortgeschriebene Bildungsdaten und Bildungssteuerung in kommunaler Verantwortungsgemeinschaft. Die Förderung von Chancengerechtigkeit und Teilhabe in der kommunalen Bildungslandschaft wird verbessert."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:11.270701+00:00","lastSeen":"2026-03-15T17:25:11.270701+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement","crawledAt":"2026-03-15T17:25:11.270701Z","crawlId":"tools-seeded-1773595511","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"bdcee05748d44dd550507524cced31205b73b2bce6c90b1c3aacebb66c67e396"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:11.270701+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('01bd03aa-a7ac-4041-bc51-86517f468f7e', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule', 'active', NULL, '2026-03-15T17:25:11.783435+00:00', '{"id":"01bd03aa-a7ac-4041-bc51-86517f468f7e","title":"Schule","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Startchancen-Programm Das Startchancen-Programm des Bundesbildungsministeriums unterstützt Schulen mit einem hohen Anteil sozial benachteiligter Schülerinnen und Schüler. Das Startchancen-Programm des Bundesbildungsministeriums unterstützt Schulen mit einem hohen Anteil sozial benachteiligter Schülerinnen und Schüler. Digitalisierung der Bildung Die Digitalisierung des Lehrens und Lernens ist unverzichtbar. Das Bundesbildungsministerium setzt sich für eine gut funktionierende Infrastruktur, moderne Ausstattung der Schulen und entsprechend ausgebildete Lehrkräfte ein. Die Digitalisierung des Lehrens und Lernens ist unverzichtbar. Das Bundesbildungsministerium setzt sich für eine gut funktionierende Infrastruktur, moderne Ausstattung der Schulen und entsprechend ausgebildete Lehrkräfte ein. DigitalPakt Schule Digitale Bildung schafft neue Möglichkeiten: Der DigitalPakt Schule unterstützt Schulen beim Ausbau digitaler Infrastruktur und Ausstattung - für flexibles Lernen, mehr Chancengleichheit und einen guten Start in die digitale Arbeitswelt. Digitale Bildung schafft neue Möglichkeiten: Der DigitalPakt Schule unterstützt Schulen beim Ausbau digitaler Infrastruktur und Ausstattung - für flexibles Lernen, mehr Chancengleichheit und einen guten Start in die digitale Arbeitswelt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:11.783435+00:00","lastSeen":"2026-03-15T17:25:11.783435+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule","crawledAt":"2026-03-15T17:25:11.784516Z","crawlId":"tools-seeded-1773595511","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"fd58d09b3a4f64c2a8676b254c965eb08ea506ab66842705fa811e4ee5a5ae12"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:11.784516+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('59bf2d19-b55f-425a-b461-364e7cb71227', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung', 'active', NULL, '2026-03-15T17:25:12.277823+00:00', '{"id":"59bf2d19-b55f-425a-b461-364e7cb71227","title":"Weiterbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Weiterbildung Ob berufliche oder allgemeine Weiterbildung: In einer sich ständig verändernden Welt ist es wichtig, stetig neue Kompetenzen zu erwerben. Eine Weiterbildung hilft bei der beruflichen wie auch persönlichen Weiterentwicklung. Ob berufliche oder allgemeine Weiterbildung: In einer sich ständig verändernden Welt ist es wichtig, stetig neue Kompetenzen zu erwerben. Eine Weiterbildung hilft bei der beruflichen wie auch persönlichen Weiterentwicklung. Allgemeine Weiterbildung Viele Bildungsangebote außerhalb des beruflichen Aufgabenbereiches fördern Schlüsselkompetenzen, die nicht nur für den Alltag wichtig sind. Eine allgemeine Weiterbildung ermöglicht es somit Kompetenzen zu erwerben, die auch beruflich weiterhelfen. Viele Bildungsangebote außerhalb des beruflichen Aufgabenbereiches fördern Schlüsselkompetenzen, die nicht nur für den Alltag wichtig sind. Eine allgemeine Weiterbildung ermöglicht es somit Kompetenzen zu erwerben, die auch beruflich weiterhelfen. Alphabetisierung und Grundbildung In Deutschland gibt es etwa 6,2 Millionen Erwachsene, die nicht oder nur auf niedrigstem Niveau lesen und schreiben können. Die AlphaDekade ermöglicht den Betroffenen einen Zugang zu Lern- und Unterstützungsangeboten. In Deutschland gibt es etwa 6,2 Millionen Erwachsene, die nicht oder nur auf niedrigstem Niveau lesen und schreiben können. Die AlphaDekade ermöglicht den Betroffenen einen Zugang zu Lern- und Unterstützungsangeboten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:12.277823+00:00","lastSeen":"2026-03-15T17:25:12.277823+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung","crawledAt":"2026-03-15T17:25:12.277823Z","crawlId":"tools-seeded-1773595512","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"bcc0e3c457265d438f1401dd12623957c5561f358615c52018e77639f87436e7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:12.277823+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9c0d169e-8401-44e8-aa1b-bfa1a541e209', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft', 'active', NULL, '2026-03-15T17:25:12.784232+00:00', '{"id":"9c0d169e-8401-44e8-aa1b-bfa1a541e209","title":"Engagement und Gesellschaft","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Am 10. März hat die Parlamentarische Staatssekretärin im Bundesbildungsministerium, Mareike Wulf, in Köln die didacta miteröffnet. Das Motto \"Alles im Wandel. Bildung im Fokus\" stellt Innovationen und mentale Gesundheit ins Zentrum. Am 26. Februar hat die Staatssekretärin im Bundesbildungsministerium, Dr. Petra Bahr, an der Veranstaltung \"Wem gehört die Kindheit?\" teilgenommen und insbesondere darüber diskutiert, wie die Interessen von Kindern angemessen berücksichtigt werden. Am 3. Februar empfing Karin Prien die japanische Botschafterin Mitsuko Shino. Die Politikerinnen tauschten sich zu gesellschafts- und bildungspolitischen Initiativen aus, die aufgrund ähnlicher Entwicklungen für beide Länder von Interesse sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:12.784232+00:00","lastSeen":"2026-03-15T17:25:12.784232+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft","crawledAt":"2026-03-15T17:25:12.784232Z","crawlId":"tools-seeded-1773595512","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"9773ffc6cef20326c0d1185051f17160ac13b847f239f57c385af3edc6b43de4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:12.784232+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4241e649-839c-4fb6-a0f3-80cb3a10d113', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit', 'active', NULL, '2026-03-15T17:25:13.310797+00:00', '{"id":"4241e649-839c-4fb6-a0f3-80cb3a10d113","title":"Allianz gegen Einsamkeit","summary":{"de":"Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung..."},"content":{"de":"Wissen zu Einsamkeit vertiefen Einsamkeit ist ein vielschichtiges Phänomen mit unterschiedlichen Ursachen. Davon betroffen sind sowohl ältere als auch jüngere Menschen. Einsamkeit ist ein vielschichtiges Phänomen mit unterschiedlichen Ursachen. Davon betroffen sind sowohl ältere als auch jüngere Menschen. Modellprojekte gegen Einsamkeit Um Einsamkeit und Isolation wirksam zu begegnen, fördert das Bundesgesellschaftsministerium Orte für Gemeinsamkeit und gemeinsames Erleben. Um Einsamkeit und Isolation wirksam zu begegnen, fördert das Bundesgesellschaftsministerium Orte für Gemeinsamkeit und gemeinsames Erleben. Über Einsamkeit reden Betroffene sprechen häufig nicht über ihre Einsamkeit. Deshalb muss das Thema sichtbarer und dafür sensibilisiert werden. Betroffene sprechen häufig nicht über ihre Einsamkeit. Deshalb muss das Thema sichtbarer und dafür sensibilisiert werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:13.310797+00:00","lastSeen":"2026-03-15T17:25:13.310797+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit","crawledAt":"2026-03-15T17:25:13.311320Z","crawlId":"tools-seeded-1773595513","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"7859334fd43517a90f863a807ae3ace632365d3894c4bdf1121fc2d309485086"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:13.311320+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4f07715f-4e94-4759-b585-48803e3c8db4', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948', 'active', NULL, '2026-03-15T17:25:13.773705+00:00', '{"id":"4f07715f-4e94-4759-b585-48803e3c8db4","title":"Bundesprogramm \"Demokratie leben! \"","summary":{"de":"Demokratie fördern. Vielfalt gestalten. Extremismus vorbeugen - das sind die Kernziele des Bundesprogramms \"Demokratie leben!\". Dieser inhaltliche Dreiklang ist handlungsleitend."},"content":{"de":"\"Demokratie leben!\" ist seit 2015 als lernendes Bundesprogramm konzipiert. Es reagiert auf aktuelle gesellschaftliche Herausforderungen und wird kontinuierlich weiterentwickelt. Über bereits zwei Förderperioden hinweg hat sich \"Demokratie leben!\" zum inhaltlich umfassendsten Präventions- und Gestaltungsprogramm des Bundes zur zivilgesellschaftlichen Demokratieförderung, Vielfaltgestaltung und Extremismusprävention entwickelt. Für die 3. Förderperiode (2025 bis 2032) hat das Bundesfamilienministerium das Bundesprogramm angepasst. Dabei wurden die Ziele und Strukturen neu justiert und stärker fokussiert - vor allem mit Blick auf die aktuellen gesellschaftlichen Herausforderungen und auf Grundlage der gewonnenen Erfahrungen aus der ersten (2015 bis 2019) und zweiten (2020 bis 2024) Förderperiode. Das Bundesprogramm ist im Januar 2025 in seine 3. Förderperiode (2025 bis 2032) gestartet. Mit dem Programm fördert das Bundesfamilienministerium zivilgesellschaftliches Engagement auf allen Ebenen des Staates für ein vielfältiges und demokratisches Miteinander und die Arbeit gegen Radikalisierungen und Polarisierungen in der Gesellschaft. In seiner 3. Förderperiode (2025 bis 2032) ist das Bundesprogramm Teil der Strategie \"Gemeinsam für Demokratie und gegen Extremismus - Strategie der Bundesregierung für eine starke, wehrhafte Demokratie und eine offene und vielfältige Gesellschaft\". Sie ersetzt die \" Strategie der Bundesregierung zur Extremismusprävention und Demokratieförderung \" aus dem Jahr 2016. Ziel des Bundesprogramms ist es, zur Stärkung der Demokratie und eines friedlichen, respektvollen Zusammenlebens beizutragen, Teilhabe zu fördern und die Arbeit gegen jede Form von Gruppenbezogener Menschenfeindlichkeit und Demokratiefeindlichkeit zu ermöglichen. Dazu wird das Bundesprogramm in drei Handlungsfeldern aktiv: Demokratie fördern - Vielfalt gestalten - Extremismus vorbeugen. Das Bundesprogramm stärkt die Zivilgesellschaft in diesen Handlungsfeldern durch geeignete Rahmenbedingungen in diesen Handlungsfeldern."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:13.773705+00:00","lastSeen":"2026-03-15T17:25:13.773705+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948","crawledAt":"2026-03-15T17:25:13.773705Z","crawlId":"tools-seeded-1773595513","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"7de44b0ec3a84ddee9026807ee671607f0b6040e2dcbde9c0e72b0f22165534a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:13.773705+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bb3eebf1-818c-4166-a0e5-16a51a656e90', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit', 'active', NULL, '2026-03-15T17:25:14.297842+00:00', '{"id":"bb3eebf1-818c-4166-a0e5-16a51a656e90","title":"Demografischer Wandel und Nachhaltigkeit","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Antworten auf den demografischen Wandel Die demografische Entwicklung wird unsere Gesellschaft tiefgreifend verändern. Im Dialog mit Wissenschaft und Praxis erarbeitet das Bundesfamilienministerium neue Ansätze, wie Kommunen sich darauf einstellen können. Die demografische Entwicklung wird unsere Gesellschaft tiefgreifend verändern. Im Dialog mit Wissenschaft und Praxis erarbeitet das Bundesfamilienministerium neue Ansätze, wie Kommunen sich darauf einstellen können. Zukunftsraum Demografie Das Netzwerk \"Zukunftsraum Demografie\" unterstützt Gemeinden, Städte und Landkreise dabei, die Herausforderungen des demografischen Wandels zu gestalten. Das Netzwerk \"Zukunftsraum Demografie\" unterstützt Gemeinden, Städte und Landkreise dabei, die Herausforderungen des demografischen Wandels zu gestalten. Nachhaltige Entwicklung Die Herausforderungen unserer Zeit sind vielfältig, überschreiten Grenzen und betreffen uns alle. Das Bundesfamilienministerium trägt mit seinen gesellschaftspolitischen Maßnahmen zu einer nachhaltigen Entwicklung bei. Die Herausforderungen unserer Zeit sind vielfältig, überschreiten Grenzen und betreffen uns alle. Das Bundesfamilienministerium trägt mit seinen gesellschaftspolitischen Maßnahmen zu einer nachhaltigen Entwicklung bei."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:14.297842+00:00","lastSeen":"2026-03-15T17:25:14.297842+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit","crawledAt":"2026-03-15T17:25:14.298489Z","crawlId":"tools-seeded-1773595514","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d5d2904457f2503f3bad0f5221e6525cc5da1fc5aad03c87b1a8a769b0e523da"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:14.298489+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b74b5e44-c629-47fe-9a09-08661e9af347', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt', 'active', NULL, '2026-03-15T17:25:14.790241+00:00', '{"id":"b74b5e44-c629-47fe-9a09-08661e9af347","title":"Deutsche Stiftung für Engagement und Ehrenamt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Engagement für Geflüchtete aus der Ukraine fördern Mit dem Förderprogramm \"Ehrenamt hilft gemeinsam\" stärkt die Deutsche Stiftung für Engagement und Ehrenamt zivilgesellschaftliche Strukturen im Bereich des Bürgerschaftlichen Engagements für ukrainische Geflüchtete. Mit dem Förderprogramm \"Ehrenamt hilft gemeinsam\" stärkt die Deutsche Stiftung für Engagement und Ehrenamt zivilgesellschaftliche Strukturen im Bereich des Bürgerschaftlichen Engagements für ukrainische Geflüchtete. Hilfe für die Ukraine: Die Stiftung vernetzt und informiert Die Deutsche Stiftung für Engagement und Ehrenamt vernetzt deutschlandweit Engagierte, die sich für Geflüchtete aus der Ukraine einsetzten wollen und gibt einen Überblick über Unterstützungsmöglichkeiten. Die Deutsche Stiftung für Engagement und Ehrenamt vernetzt deutschlandweit Engagierte, die sich für Geflüchtete aus der Ukraine einsetzten wollen und gibt einen Überblick über Unterstützungsmöglichkeiten. Der Gründungs-Vorstand der Stiftung Der erste Vorstand der Deutschen Stiftung für Engagement und Ehrenamt besteht aus einer Doppelspitze. Katarina Peranić und Jan Holze werden die Stiftung aufbauen. Der erste Vorstand der Deutschen Stiftung für Engagement und Ehrenamt besteht aus einer Doppelspitze. Katarina Peranić und Jan Holze werden die Stiftung aufbauen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:14.790241+00:00","lastSeen":"2026-03-15T17:25:14.790241+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt","crawledAt":"2026-03-15T17:25:14.790241Z","crawlId":"tools-seeded-1773595514","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"44799d91a5e2b55c37788bbc903cdb16f63c61deba835d674e54d86a42fc9429"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:14.790241+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e74d1aae-4ae9-4bb1-bcf5-ff2fdfa4889a', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken', 'active', NULL, '2026-03-15T17:25:15.291773+00:00', '{"id":"e74d1aae-4ae9-4bb1-bcf5-ff2fdfa4889a","title":"Engagement stärken","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Menschen stärken Menschen Mit dem Bundesprogramm \"Menschen stärken Menschen\" fördert und unterstützt das Bundesfamilienministerium bürgerschaftliches Engagement in Form von Patenschaften - für mehr gesellschaftlichen Zusammenhalt und bessere Teilhabechancen. Mit dem Bundesprogramm \"Menschen stärken Menschen\" fördert und unterstützt das Bundesfamilienministerium bürgerschaftliches Engagement in Form von Patenschaften - für mehr gesellschaftlichen Zusammenhalt und bessere Teilhabechancen. Verbände, Stiftungen und Spenden Verbände, Stiftungen und Spenden sind wichtige Säulen der Engagementpolitik. Deshalb arbeitet das Bundesfamilienministerium eng mit Verbänden der freien Wohlfahrtspflege zusammen. Es unterstützt Bürgerstiftungen und fördert die Spendenberatung. Verbände, Stiftungen und Spenden sind wichtige Säulen der Engagementpolitik. Deshalb arbeitet das Bundesfamilienministerium eng mit Verbänden der freien Wohlfahrtspflege zusammen. Es unterstützt Bürgerstiftungen und fördert die Spendenberatung. Engagementberichterstattung Die Engagementberichte der Bundesregierung sind eine Bestandsaufnahme zur Entwicklung des bürgerschaftlichen Engagements in Deutschland. Die Engagementberichte der Bundesregierung sind eine Bestandsaufnahme zur Entwicklung des bürgerschaftlichen Engagements in Deutschland."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:15.291773+00:00","lastSeen":"2026-03-15T17:25:15.291773+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken","crawledAt":"2026-03-15T17:25:15.291773Z","crawlId":"tools-seeded-1773595515","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"ec671cd8024b10d15ef10df83b230d51954279fda6f5e57b0ef07d7913137b5b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:15.291773+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1f148486-b9e5-4ed2-a9fe-eadd8d4892c8', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration', 'active', NULL, '2026-03-15T17:25:15.826723+00:00', '{"id":"1f148486-b9e5-4ed2-a9fe-eadd8d4892c8","title":"Flüchtlingspolitik und Integration","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Angebote zur Sprachförderung und Integration Sprachkurse, Patenschaften, Existenzgründung - mit unterschiedlichen Maßnahmen sorgt die Bundesregierung dafür, dass Integration gelingt. Eine aktuelle Publikation gibt einen Überblick. Sprachkurse, Patenschaften, Existenzgründung - mit unterschiedlichen Maßnahmen sorgt die Bundesregierung dafür, dass Integration gelingt. Eine aktuelle Publikation gibt einen Überblick. Informationen für geflüchtete Menschen Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Viele davon sind in verschiedenen Sprachen erhältlich. Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Viele davon sind in verschiedenen Sprachen erhältlich. Jugendmigrationsdienste Als Teil der Initiative \"JUGEND STÄRKEN\" beraten und begleiten die Jugendmigrationsdienste junge Menschen mit Einwanderungsgeschichte im Alter zwischen 12 und 27 Jahren. Das vielseitige Angebot hilft bei Fragen zum Schulbesuch, bei der... Als Teil der Initiative \"JUGEND STÄRKEN\" beraten und begleiten die Jugendmigrationsdienste junge Menschen mit Einwanderungsgeschichte im Alter zwischen 12 und 27 Jahren. Das vielseitige Angebot hilft bei Fragen zum Schulbesuch, bei der..."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:15.826723+00:00","lastSeen":"2026-03-15T17:25:15.826723+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration","crawledAt":"2026-03-15T17:25:15.826723Z","crawlId":"tools-seeded-1773595515","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"7569b8ae95dcd4be72520f598c4c2facfeb14c67882ecbbc3f7c506f05d1cd75"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:15.826723+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d42524e8-bb2d-4cac-b0e4-40f810b7df91', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete', 'active', NULL, '2026-03-15T17:25:16.339237+00:00', '{"id":"d42524e8-bb2d-4cac-b0e4-40f810b7df91","title":"Informationen für geflüchtete Menschen","summary":{"de":"Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Einige..."},"content":{"de":"Mit dem \"Bericht zu dem Gesetz zur Verbesserung der Unterbringung, Versorgung und Betreuung ausländischer Kinder und Jugendlicher\" kommt die Bundesregierung ihrer Verpflichtung nach, jährlich über die Situation unbegleiteter ausländischer Minderjähriger (UMA) in Deutschland zu informieren. Mindeststandards in Flüchtlingsunterkünften Das Bundesfamilienministerium und das Kinderhilfswerk UNICEF haben gemeinsam Mindeststandards zum Schutz von Kindern, Jugendlichen und Frauen in Flüchtlingsunterkünften erarbeitet. Das Bundesfamilienministerium und das Kinderhilfswerk UNICEF haben gemeinsam Mindeststandards zum Schutz von Kindern, Jugendlichen und Frauen in Flüchtlingsunterkünften erarbeitet. Menschen stärken Menschen Ein Flyer informiert über unterschiedliche Möglichkeiten des persönlichen Engagements für Flüchtlinge im Programm \"Menschen stärken Menschen\" - ob als Patin oder Pate, Gastfamilie oder Vormund. Ein Flyer informiert über unterschiedliche Möglichkeiten des persönlichen Engagements für Flüchtlinge im Programm \"Menschen stärken Menschen\" - ob als Patin oder Pate, Gastfamilie oder Vormund. Hilfs- und Beratungsangebote für Frauen und LSBTI Unter den derzeit nach Deutschland kommenden Flüchtlingen sind Frauen und LSBTI besonders schutzbedürftig. Mit einem mehrsprachigen Flyer sollen sie schnell Zugang zum deutschen Hilfesystem finden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:16.339237+00:00","lastSeen":"2026-03-15T17:25:16.339237+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete","crawledAt":"2026-03-15T17:25:16.339237Z","crawlId":"tools-seeded-1773595516","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"428583dd92aab0c739afd99ab7df2de951119dc51ebb956d31232be6ac6d346b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:16.339237+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fa36eb46-7df1-4017-8b2c-47772300fc62', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste', 'active', NULL, '2026-03-15T17:25:16.797964+00:00', '{"id":"fa36eb46-7df1-4017-8b2c-47772300fc62","title":"Freiwilligendienste","summary":{"de":"Rund 100.000 Menschen leisten Jahr für Jahr einen Freiwilligendienst. Politische Aufmerksamkeit gilt vor allem finanziellen und organisatorischen..."},"content":{"de":"Die Jugendfreiwilligendienste Nach der Schulzeit etwas Neues ausprobieren und gleichzeitig Gutes tun: Knapp 55.000 Jugendliche und junge Erwachsene verwirklichen diesen Wunsch jedes Jahr. Nach der Schulzeit etwas Neues ausprobieren und gleichzeitig Gutes tun: Knapp 55.000 Jugendliche und junge Erwachsene verwirklichen diesen Wunsch jedes Jahr. Der Bundesfreiwilligendienst Der Bundesfreiwilligendienst ist eine Erfolgsgeschichte. Viele Bürgerinnen und Bürger nutzen die Möglichkeit, sich für die Gesellschaft und das Gemeinwohl zu engagieren. Der Bundesfreiwilligendienst ist eine Erfolgsgeschichte. Viele Bürgerinnen und Bürger nutzen die Möglichkeit, sich für die Gesellschaft und das Gemeinwohl zu engagieren. Wie ermöglicht ein Freiwilliges Ökologisches Jahr positive Demokratie- und Selbstwirksamkeitserfahrungen? Zu diesen und weiteren Fragen tauschte sich Michael Brand auf der Fachtagung 2026 aus. Wie können junge Menschen sich über Schule hinaus bilden? Wie können junge Menschen einen Beitrag für eine nachhaltige Zukunft leisten? Diese und weitere Fragen diskutierte Karin Prien bei der Jahrestagung 2025 Freiwilliges Soziales Jahr."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:16.797964+00:00","lastSeen":"2026-03-15T17:25:16.797964+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste","crawledAt":"2026-03-15T17:25:16.797964Z","crawlId":"tools-seeded-1773595516","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"9af043ee0d58a97cae28528bd4d1890103dcddfef7ca4e85c6428333fa33f574"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:16.797964+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1b639726-966d-490a-9fd2-5cf8ca3ac41d', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser', 'active', NULL, '2026-03-15T17:25:17.296192+00:00', '{"id":"1b639726-966d-490a-9fd2-5cf8ca3ac41d","title":"Mehrgenerationenhäuser","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Programmschwerpunkte Um die Herausforderungen vor Ort zu meistern und passende Lösungen zu entwickeln, brauchen die Mehrgenerationenhäuser Handlungsspielraum. Deshalb legen die Häuser die Schwerpunkte ihrer Arbeit selbst fest. Um die Herausforderungen vor Ort zu meistern und passende Lösungen zu entwickeln, brauchen die Mehrgenerationenhäuser Handlungsspielraum. Deshalb legen die Häuser die Schwerpunkte ihrer Arbeit selbst fest. Die Querschnittsaufgaben Generationenübergreifende Arbeit, Teilhabe, freiwilliges Engagement und Sozialraumorientierung: Das sind die vier Querschnittsaufgaben der Mehrgenerationenhäuser. Generationenübergreifende Arbeit, Teilhabe, freiwilliges Engagement und Sozialraumorientierung: Das sind die vier Querschnittsaufgaben der Mehrgenerationenhäuser. Am 23. September hielt der Parlamentarische Staatssekretär Michael Brand das Grußwort bei der Ideenkonferenz des Bundesprogramms Mehrgenerationenhaus mit dem Thema \"Gemeinsam stark - Lokale Kooperationen und Fundraising für nachhaltigen Erfolg\". Die Aktionstage finden unter dem Motto \"Nachbarschaft mit Herz und Hand\" bundesweit statt und bieten die Möglichkeit, sich über die Arbeit der Mehrgenerationenhäuser zu informieren. Karin Prien eröffnete sie mit einer Kochaktion in Berlin."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:17.296192+00:00","lastSeen":"2026-03-15T17:25:17.296192+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser","crawledAt":"2026-03-15T17:25:17.297279Z","crawlId":"tools-seeded-1773595517","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"eef19ae8ecab7725ceea978a9ce086fc20d8b1a3a77c5395c433b48f951608f2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:17.297279+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3434aeee-5ef7-4a31-b262-2176dbd35db6', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie', 'active', NULL, '2026-03-15T17:25:17.789621+00:00', '{"id":"3434aeee-5ef7-4a31-b262-2176dbd35db6","title":"Familienpolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Elterngeldrechner Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link) Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link) Nationaler Aktionsplan für chancengerechtes Aufwachsen Bundesfamilienministerin Karin Prien hat den Wettbewerb \"Kleine Lösungen - große Wirkung\" gestartet. Gesucht werden kleine und mittlere Unternehmen mit kreativen Ideen für die Vereinbarkeit von Familie und Beruf. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun. Die ehemalige Bundesfrauenministerin und Bundestagspräsidentin Prof. Dr. Rita Süssmuth ist verstorben. Karin Prien und Nina Warken würdigten sie als großes Vorbild und Vorkämpferin für Frauenrechte und sozialen Zusammenhalt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:17.789621+00:00","lastSeen":"2026-03-15T17:25:17.789621+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie","crawledAt":"2026-03-15T17:25:17.789621Z","crawlId":"tools-seeded-1773595517","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f12f7344b75308699b6ba2987e993e84a99dae8b7fff3c5be48f860c9fc3e19a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:17.789621+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
