ältige Unterstützungsangebote zurückgreifen. Die Erziehung und Förderung der eigenen Kinder sowie der Umgang mit Problemen und Konflikten sind oft mit vielen Fragen verbunden. Eltern können auf vielfältige Unterstützungsangebote zurückgreifen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/chancen-und-teilhabe-fuer-familien","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:18.299669+00:00","lastSeen":"2026-03-15T17:25:18.299669+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/chancen-und-teilhabe-fuer-familien","crawledAt":"2026-03-15T17:25:18.299669Z","crawlId":"tools-seeded-1773595518","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"acd51f39aa0ff916da91ff8f6d4dbd9c157fba7bd6d23eed395fdff1e85c75a1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:18.299669+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
