INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('66037d37-87bc-4067-8d47-b9f602fe9180', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung', 'active', NULL, '2026-03-15T17:25:19.333510+00:00', '{"id":"66037d37-87bc-4067-8d47-b9f602fe9180","title":"Gute Kinderbetreuung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"KiTa-Qualität Die Qualitätsentwicklung in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe, die der Bund mit dem KiTa-Qualitätsgesetz und weiteren Initiativen unterstützt. Die Qualitätsentwicklung in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe, die der Bund mit dem KiTa-Qualitätsgesetz und weiteren Initiativen unterstützt. Kita-Ausbau Um eine gute frühkindliche Bildung, Betreuung und Erziehung sicherzustellen, unterstützt der Bund die Länder beim Ausbau und der Weiterentwicklung von Angeboten der Kindertagesbetreuung. Um eine gute frühkindliche Bildung, Betreuung und Erziehung sicherzustellen, unterstützt der Bund die Länder beim Ausbau und der Weiterentwicklung von Angeboten der Kindertagesbetreuung. Ganztagsbetreuung für Grundschulkinder Ab 2026 gibt es einen Rechtsanspruch auf Ganztagsbetreuung für Grundschulkinder. Das stärkt die Kinder und hilft den Eltern bei der Vereinbarkeit von Familie und Beruf. Ab 2026 gibt es einen Rechtsanspruch auf Ganztagsbetreuung für Grundschulkinder. Das stärkt die Kinder und hilft den Eltern bei der Vereinbarkeit von Familie und Beruf."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:19.333510+00:00","lastSeen":"2026-03-15T17:25:19.333510+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung","crawledAt":"2026-03-15T17:25:19.333510Z","crawlId":"tools-seeded-1773595519","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"2bfaf6852497f95b017c12596ec7a8427349c2ab818f4868a72adcd4a49a114f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:19.333510+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5e3d9906-4f75-4460-9cc7-2f0e7d6aea35', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet', 'active', NULL, '2026-03-15T17:25:19.791915+00:00', '{"id":"5e3d9906-4f75-4460-9cc7-2f0e7d6aea35","title":"Mehr Qualität in der frühen Bildung","summary":{"de":"Kitas sind ein Bildungs- und Zukunftsort. Um die Qualität der Kindertagesbetreuung und der Kindertagespflege weiterzuentwickeln und zu stärken..."},"content":{"de":"Für gute Kinderbetreuung bundesweit: das KiTa-Qualitätsgesetz Die Weiterentwicklung der Qualität in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe und gemeinsames Ziel von Bund, Ländern und Kommunen. Hier setzt das KiTa-Qualitätsgesetz an. Die Weiterentwicklung der Qualität in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe und gemeinsames Ziel von Bund, Ländern und Kommunen. Hier setzt das KiTa-Qualitätsgesetz an. Die Verträge der Bundesländer zum KiTa-Qualitäts- und -Teilhabeverbesserungsgesetz Um die Qualität in der frühkindlichen Bildung, Betreuung und Erziehung zu verbessern, unterstützt der Bund die Länder im Rahmen des KiTa-Qualitäts- und Teilhabeverbesserungsgesetzes seit 2019 mit zusätzlichen Mitteln. Um die Qualität in der frühkindlichen Bildung, Betreuung und Erziehung zu verbessern, unterstützt der Bund die Länder im Rahmen des KiTa-Qualitäts- und Teilhabeverbesserungsgesetzes seit 2019 mit zusätzlichen Mitteln. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun. Kindern ein Zuhause geben, wo sie Zuwendung, Stabilität und \"Zeit, die prägt\" erfahren können: Eine neue Kampagne des Bundesfamilienministeriums rückt Pflegeelternschaft stärker ins öffentliche Bewusstsein und will neue Pflegefamilien gewinnen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:19.791915+00:00","lastSeen":"2026-03-15T17:25:19.791915+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet","crawledAt":"2026-03-15T17:25:19.791915Z","crawlId":"tools-seeded-1773595519","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c4d1196cf7157e4ab40a07b6c6e450645933239247d88d79f9d0273a422280fc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:19.791915+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
