INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fa7bb845-780e-48af-9be0-dda31ab9b6a8', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch', 'active', NULL, '2026-03-15T17:25:20.808874+00:00', '{"id":"fa7bb845-780e-48af-9be0-dda31ab9b6a8","title":"Schwangerschaft und Kinderwunsch","summary":{"de":"Eine Schwangerschaft kann werdende Eltern vor Herausforderungen stellen. Hilfe erhalten sie durch die Bundesstiftung Mutter und Kind. Auch Paare mit..."},"content":{"de":"Familienplanung von Frauen und Männern Schwangere oder Männer und Frauen mit Kinderwunsch stehen oft vor vielen Fragen. Ein dichtes Netz von Beratungsstellen und Online-Angebote informiert über Familienplanung, Schwangerschaft und Verhütungsmöglichkeiten. Schwangere oder Männer und Frauen mit Kinderwunsch stehen oft vor vielen Fragen. Ein dichtes Netz von Beratungsstellen und Online-Angebote informiert über Familienplanung, Schwangerschaft und Verhütungsmöglichkeiten. Ungewollte Kinderlosigkeit Der medizinische und technische Fortschritt ermöglicht vielen ungewollt kinderlosen Paaren die Erfüllung des Kinderwunsches. Viele Bundesländer unterstützen die Behandlung finanziell. Der medizinische und technische Fortschritt ermöglicht vielen ungewollt kinderlosen Paaren die Erfüllung des Kinderwunsches. Viele Bundesländer unterstützen die Behandlung finanziell. Informationsportal Kinderwunsch Das Informationsportal Kinderwunsch zeigt Beratungsangebote und finanzielle Fördermöglichkeiten für ungewollt kinderlose Paare auf. Das Informationsportal Kinderwunsch zeigt Beratungsangebote und finanzielle Fördermöglichkeiten für ungewollt kinderlose Paare auf."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:20.808874+00:00","lastSeen":"2026-03-15T17:25:20.808874+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch","crawledAt":"2026-03-15T17:25:20.809280Z","crawlId":"tools-seeded-1773595520","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"2ea6efc8c611b9df07383aa947f8d1691d73842d85a6d3f4579267a85273a8e2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:20.809280+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5a23ed69-9267-4ae1-961d-98906b130a03', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik', 'active', NULL, '2026-03-15T17:25:21.352998+00:00', '{"id":"5a23ed69-9267-4ae1-961d-98906b130a03","title":"Agenda für smarte Gesellschaftspolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Agenda für smarte Gesellschaftspolitik Überblick: Die neue Strategie für die digitale Gesellschaft Mit der \"Agenda für smarte Gesellschaftspolitik\" präsentiert das Bundesministerium für Bildung und Familie seine Vision für die digitale Gesellschaft von morgen. Ziel ist eine intelligente und innovative Digitalpolitik, die Mensch und Gemeinwohl in den Mittelpunkt stellt. Mit der \"Agenda für smarte Gesellschaftspolitik\" präsentiert das Bundesministerium für Bildung und Familie seine Vision für die digitale Gesellschaft von morgen. Ziel ist eine intelligente und innovative Digitalpolitik, die Mensch und Gemeinwohl in den Mittelpunkt stellt. Handlungsfeld 1: Smarte Lebensführung Mit Technik das Alltagsleben erleichtern Digitale Innovationen können die Vereinbarkeit von Familie und Beruf verbessern und ein längeres selbstbestimmtes Leben zu Hause ermöglichen. Wie smarte Lebensführung den Alltag erleichtert. Digitale Innovationen können die Vereinbarkeit von Familie und Beruf verbessern und ein längeres selbstbestimmtes Leben zu Hause ermöglichen. Wie smarte Lebensführung den Alltag erleichtert. Handlungsfeld 2: Digitale Teilhabe Digitalisierung als Chance für mehr Vielfalt und Teilhabe nutzen Bunter, freier und demokratischer kann die Gesellschaft durch die Digitalisierung werden. Aber nur, wenn alle mit anpacken und sich engagieren. Bunter, freier und demokratischer kann die Gesellschaft durch die Digitalisierung werden. Aber nur, wenn alle mit anpacken und sich engagieren."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:21.352998+00:00","lastSeen":"2026-03-15T17:25:21.352998+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik","crawledAt":"2026-03-15T17:25:21.352998Z","crawlId":"tools-seeded-1773595521","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"83ae58ed414799265f5db2300d4626562a921a7be89639da2dc3aeb52b5cee13"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:21.352998+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a3aaa332-3abd-468b-820d-b69b686cc466', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung', 'active', NULL, '2026-03-15T17:25:21.851610+00:00', '{"id":"a3aaa332-3abd-468b-820d-b69b686cc466","title":"Gleichstellungspolitik: Politik für Frauen und Männer","summary":{"de":"Frauen und Männer müssen die gleichen Chancen erhalten – persönlich, beruflich und familiär. Hier finden Sie Informationen zur Gleichstellungspolitik."},"content":{"de":"Digitaler Gleichstellungsatlas Der digitale Gleichstellungsatlas liefert einen umfassenden Überblick über die regionalen Unterschiede bei der Gleichstellung von Männern und Frauen in Deutschland. (Nicht barrierefrei) Der digitale Gleichstellungsatlas liefert einen umfassenden Überblick über die regionalen Unterschiede bei der Gleichstellung von Männern und Frauen in Deutschland. (Nicht barrierefrei) Am 10. März hat die Parlamentarische Staatssekretärin im Bundesbildungsministerium, Mareike Wulf, in Köln die didacta miteröffnet. Das Motto \"Alles im Wandel. Bildung im Fokus\" stellt Innovationen und mentale Gesundheit ins Zentrum. Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Das Bundesfrauenministerium hat Dr. Petra Volke als deutsche Kandidatin für die Expertengruppe GREVIO des Europarats vorgestellt - ein bedeutender Beitrag Deutschlands zur Bekämpfung von geschlechtsspezifischer und häuslicher Gewalt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:21.851610+00:00","lastSeen":"2026-03-15T17:25:21.851610+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung","crawledAt":"2026-03-15T17:25:21.851610Z","crawlId":"tools-seeded-1773595521","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c4c42e0df25c6d0358af517eda65f89408b1150367650471019f8bde7c5fefed"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:21.851610+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9a15eaa8-beb7-44cd-b899-ca26713087d5', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe', 'active', NULL, '2026-03-15T17:25:22.285030+00:00', '{"id":"9a15eaa8-beb7-44cd-b899-ca26713087d5","title":"Politik für die Aufwertung sozialer Berufe","summary":{"de":"Soziale Berufe tragen zur Bildung, Gesundheit und Teilhabe bei und sichern ein gutes Zusammenleben"},"content":{"de":"Erzieherberufe - guter Einstieg und Aufstieg 3,7 Millionen Kinder nutzten im Jahr 2019 deutschlandweit Angebote der Kindertagesbetreuung. Sie wurden von insgesamt rund 676.000 Beschäftigten betreut und gefördert. 3,7 Millionen Kinder nutzten im Jahr 2019 deutschlandweit Angebote der Kindertagesbetreuung. Sie wurden von insgesamt rund 676.000 Beschäftigten betreut und gefördert. Pflegeausbildung - Berufsfeld Pflege Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der Pflegeberufe zu verbessern, wird die Pflegeausbildung reformiert. Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der Pflegeberufe zu verbessern, wird die Pflegeausbildung reformiert."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:22.285030+00:00","lastSeen":"2026-03-15T17:25:22.285030+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe","crawledAt":"2026-03-15T17:25:22.285030Z","crawlId":"tools-seeded-1773595522","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c0f3d6b5ae10d7adff643aa2b5d1eeb71f5e545ae6584863e142876f6f9e2d9b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:22.285030+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c8bdfa9f-4cbc-4a45-9e50-8adc1feb7a27', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/feministische-digitalpolitik', 'active', NULL, '2026-03-15T17:25:22.802230+00:00', '{"id":"c8bdfa9f-4cbc-4a45-9e50-8adc1feb7a27","title":"Feministische Digitalpolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Smarte Gesellschaftspolitik Digitalisierungspolitik ist Gesellschaftspolitik. Für ein gutes Zusammenleben in der digitalen Gesellschaft muss der technologische Wandel so geschehen, dass er den Menschen und der Gesellschaft dient. Digitalisierungspolitik ist Gesellschaftspolitik. Für ein gutes Zusammenleben in der digitalen Gesellschaft muss der technologische Wandel so geschehen, dass er den Menschen und der Gesellschaft dient. Dritter Gleichstellungsbericht Der Dritte Gleichstellungsbericht gibt Empfehlungen für eine gleichstellungsorientierte Digitalisierung. Der Dritte Gleichstellungsbericht gibt Empfehlungen für eine gleichstellungsorientierte Digitalisierung. Bundesstiftung Gleichstellung Im Dialog mit Zivilgesellschaft, Wirtschaft und Politik trägt die Bundesstiftung Gleichstellung dazu bei, die Gleichberechtigung von Frauen und Männern effektiver durchzusetzen. Im Dialog mit Zivilgesellschaft, Wirtschaft und Politik trägt die Bundesstiftung Gleichstellung dazu bei, die Gleichberechtigung von Frauen und Männern effektiver durchzusetzen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/feministische-digitalpolitik","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:22.802230+00:00","lastSeen":"2026-03-15T17:25:22.802230+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/feministische-digitalpolitik","crawledAt":"2026-03-15T17:25:22.802230Z","crawlId":"tools-seeded-1773595522","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"beae1401849090323180f17f69205a4cca205450da825b6350b2c9751d40491c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:22.802230+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8b2ee8ae-e31b-431a-9b6d-0c1807345265', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-und-arbeitswelt', 'active', NULL, '2026-03-15T17:25:23.346817+00:00', '{"id":"8b2ee8ae-e31b-431a-9b6d-0c1807345265","title":"Wirtschaftliche Gleichstellung, Frauen und Arbeitswelt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Verschaffen Sie sich hier einen Überblick über regionale Unterschiede bei der Gleichstellung in Deutschland. Klicken Sie sich durch über 40 Indikatoren in unterschiedlichen Themenfeldern. Lohngerechtigkeit Die Lohnlücke zwischen Männern und Frauen hat vielschichtige Ursachen. Sie kann nur im Zusammenwirken verschiedener Maßnahmen verringert werden. Ein wichtiger Baustein ist das Gesetz zur Förderung der Transparenz in Entgeltstrukturen. Die Lohnlücke zwischen Männern und Frauen hat vielschichtige Ursachen. Sie kann nur im Zusammenwirken verschiedener Maßnahmen verringert werden. Ein wichtiger Baustein ist das Gesetz zur Förderung der Transparenz in Entgeltstrukturen. Entgelttransparenzgesetz Das Gesetz zur Förderung der Transparenz von Entgeltstrukturen ist zum 6. Juli 2017 in Kraft getreten. Es soll Frauen dabei unterstützen, ihren Anspruch auf gleiches Entgelt bei gleicher oder gleichwertiger Arbeit künftig besser durchzusetzen. Das Gesetz zur Förderung der Transparenz von Entgeltstrukturen ist zum 6. Juli 2017 in Kraft getreten. Es soll Frauen dabei unterstützen, ihren Anspruch auf gleiches Entgelt bei gleicher oder gleichwertiger Arbeit künftig besser durchzusetzen. Geschlechtergerechte Berufsorientierung fördern Mit der Bundesinitiative \"Klischeefrei\", dem Aktionstag Girls''Day und der Initiative YouCodeGirls fördert die Bundesregierung eine geschlechtergerechte Berufsorientierung und Berufsberatung."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-und-arbeitswelt","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:23.346817+00:00","lastSeen":"2026-03-15T17:25:23.346817+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-und-arbeitswelt","crawledAt":"2026-03-15T17:25:23.347336Z","crawlId":"tools-seeded-1773595523","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"4a4d9abe5021f68dc4a81ad6695a5f8332a089d31143f3b8a5aa744fd468fb9b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:23.347336+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bcaca84c-adc0-4ff6-a3ba-ff12338e7207', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-vor-gewalt-schuetzen', 'active', NULL, '2026-03-15T17:25:23.812889+00:00', '{"id":"bcaca84c-adc0-4ff6-a3ba-ff12338e7207","title":"Frauen vor Gewalt schützen","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Formen der Gewalt erkennen Gewalt hat viele Gesichter und sie begegnet uns überall: Zuhause, auf der Arbeit, im öffentlichen Raum, im Netz. Sie beginnt nicht erst mit Schlägen. Auch Bedrohungen, Beschimpfungen und Kontrolle sind Formen von Gewalt. Gewalt hat viele Gesichter und sie begegnet uns überall: Zuhause, auf der Arbeit, im öffentlichen Raum, im Netz. Sie beginnt nicht erst mit Schlägen. Auch Bedrohungen, Beschimpfungen und Kontrolle sind Formen von Gewalt. Hilfe und Beratung bei Gewalt Von Gewalt betroffene Frauen und Männer brauchen schnelle und unbürokratische Hilfe sowie qualifizierte Beratung und Unterstützung. Hier finden sie Anlaufstellen, an die sich auch Angehörige und Freunde sowie Fachkräfte wenden können. Von Gewalt betroffene Frauen und Männer brauchen schnelle und unbürokratische Hilfe sowie qualifizierte Beratung und Unterstützung. Hier finden sie Anlaufstellen, an die sich auch Angehörige und Freunde sowie Fachkräfte wenden können. Schutz und Beratung durch das Gewalthilfegesetz Das Gewalthilfegesetz sichert den Zugang zu Schutz- und Beratungsangeboten bei geschlechtsspezifischer und häuslicher Gewalt. Betroffene erhalten künftig die Hilfe und Unterstützung, die sie in ihrer individuellen Lage brauchen. Das Gewalthilfegesetz sichert den Zugang zu Schutz- und Beratungsangeboten bei geschlechtsspezifischer und häuslicher Gewalt. Betroffene erhalten künftig die Hilfe und Unterstützung, die sie in ihrer individuellen Lage brauchen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-vor-gewalt-schuetzen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:23.812889+00:00","lastSeen":"2026-03-15T17:25:23.812889+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/frauen-vor-gewalt-schuetzen","crawledAt":"2026-03-15T17:25:23.812889Z","crawlId":"tools-seeded-1773595523","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c8cee34ea4a57cd65a91482fd5f86da49115a8db8249d2645e87fa20f0b73f4a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:23.812889+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('435d9633-5eaf-459e-80b0-9411d9b1aee5', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap', 'active', NULL, '2026-03-15T17:25:24.303136+00:00', '{"id":"435d9633-5eaf-459e-80b0-9411d9b1aee5","title":"Erwerbs- und Sorgearbeit gleichberechtigt gestalten","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Verschaffen Sie sich hier einen Überblick über regionale Unterschiede bei der Gleichstellung in Deutschland. Klicken Sie sich durch über 40 Indikatoren in unterschiedlichen Themenfeldern. Gender Care Gap - ein Indikator für die Gleichstellung Kindererziehung, Pflege von Angehörigen, Hausarbeit, Ehrenamt: Frauen wenden pro Tag im Durchschnitt 43,4 Prozent mehr Zeit für unbezahlte Sorgearbeit auf als Männer. Dieser Unterschied wird als Gender Care Gap bezeichnet. Kindererziehung, Pflege von Angehörigen, Hausarbeit, Ehrenamt: Frauen wenden pro Tag im Durchschnitt 43,4 Prozent mehr Zeit für unbezahlte Sorgearbeit auf als Männer. Dieser Unterschied wird als Gender Care Gap bezeichnet. Projekt erforscht Ungleichheiten bei der unbezahlten Sorgearbeit Der Gender Care Gap führt dazu, dass viele Frauen wirtschaftliche Nachteile haben. Für eine gerechte Verteilung der unbezahlten Sorgearbeit analysiert das Gender-Care-Gap-Projekt die Unterschiede und entwickelt Handlungsempfehlungen. Der Gender Care Gap führt dazu, dass viele Frauen wirtschaftliche Nachteile haben. Für eine gerechte Verteilung der unbezahlten Sorgearbeit analysiert das Gender-Care-Gap-Projekt die Unterschiede und entwickelt Handlungsempfehlungen. Wie können pflegende Angehörige im Alltag besser unterstützt werden? Unter anderem darum ging es bei einer internationalen Online-Konferenz zur Geschlechtergerechtigkeit in der Pflege."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:24.303136+00:00","lastSeen":"2026-03-15T17:25:24.303136+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap","crawledAt":"2026-03-15T17:25:24.303136Z","crawlId":"tools-seeded-1773595524","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"fbc0e217c55d6c4cc67388dfb53d1f4ff68678be3a128648990b483dc1c714ed"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:24.303136+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('876366b5-44ce-4524-b059-41fb0973daea', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gleichstellung-und-teilhabe', 'active', NULL, '2026-03-15T17:25:24.810297+00:00', '{"id":"876366b5-44ce-4524-b059-41fb0973daea","title":"Gleichstellung und Teilhabe","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Verschaffen Sie sich hier einen Überblick über regionale Unterschiede bei der Gleichstellung in Deutschland. Klicken Sie sich durch über 40 Indikatoren in unterschiedlichen Themenfeldern. Frauen und Politik 100 Jahre nach Einführung des Frauenwahlrechts sind in Politik und Parlamenten weiter mehr Männer als Frauen vertreten. Das zeigt: Frauenrechte müssen immer wieder neu erstritten werden. 100 Jahre nach Einführung des Frauenwahlrechts sind in Politik und Parlamenten weiter mehr Männer als Frauen vertreten. Das zeigt: Frauenrechte müssen immer wieder neu erstritten werden. Gleichstellungsberichte der Bundesregierung In jeder Legislaturperiode berichtet die Bundesregierung über den Stand der Gleichstellung von Frauen und Männern in Deutschland. In jeder Legislaturperiode berichtet die Bundesregierung über den Stand der Gleichstellung von Frauen und Männern in Deutschland. Gleichstellungsstrategie der Bundesregierung Gleichstellung stärkt Deutschland. Deshalb wird die ressortübergreifende Gleichstellungsstrategie in der 21. Legislaturperiode fortgeführt. Im Fokus steht die stärkere Zusammenarbeit der Bundesressorts."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gleichstellung-und-teilhabe","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:24.810297+00:00","lastSeen":"2026-03-15T17:25:24.810297+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gleichstellung-und-teilhabe","crawledAt":"2026-03-15T17:25:24.810297Z","crawlId":"tools-seeded-1773595524","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"63294e8aa800cd57e102723ec17eb340b1694a037df0f6fcffdd8eb4ad98e996"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:24.810297+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('eb3bc5d2-4e37-43da-b57e-ee8544e5a764', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gleichstellungsatlas', 'active', NULL, '2026-03-15T17:25:25.440364+00:00', '{"id":"eb3bc5d2-4e37-43da-b57e-ee8544e5a764","title":"Digitaler Gleichstellungsatlas","summary":{"de":"Nutzen Sie den Digitalen Gleichstellungsatlas - mehr als 40 Indikatoren, interaktive Anwendung und Hintergrundinformationen!"},"content":{"de":"Die interaktive Anwendung des Gleichstellungsatlas liefert einen umfassenden Überblick über die regionalen Unterschiede bei der Gleichstellung von Frauen und Männern in Deutschland. Anhand von mehr als 40 Indikatoren zeigt er auf, wie hoch der Anteil von Frauen und Männern an Führungspositionen in Politik, Wissenschaft und Wirtschaft ist, welche geschlechtsspezifischen Unterschiede es bei Bildung und Berufswahl gibt oder wie sich Frauen und Männer Erwerbs- und Sorgearbeit aufteilen. Sie können sich die Indikatoren als Karte, Balken- oder Verlaufsdiagramm anzeigen lassen. Damit sind sowohl Vergleiche zwischen Regionen, als auch im Zeitverlauf möglich. Bitte wählen Sie einen Gleichstellungsindikator aus den fünf Themenfeldern aus: Für den ausgewählten Gleichstellungsindikator können Sie hier unterschiedliche Regionen im Zeitverlauf miteinander vergleichen. Bitte wählen Sie die Regionen aus, die Sie miteinander vergleichen wollen. Sie können maximal fünf Regionen miteinander (Länder und Landkreise) vergleichen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gleichstellungsatlas","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:25.440364+00:00","lastSeen":"2026-03-15T17:25:25.440364+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gleichstellungsatlas","crawledAt":"2026-03-15T17:25:25.440364Z","crawlId":"tools-seeded-1773595525","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"2314fd4ce115ff6873094adf726911743302fc995d2ced0d97dd25a9eb75ef8a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:25.440364+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4ea99e2b-1f5f-478b-8fca-ebb84830275c', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk', 'active', NULL, '2026-03-15T17:25:25.811860+00:00', '{"id":"4ea99e2b-1f5f-478b-8fca-ebb84830275c","title":"Internationale Gleichstellungspolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Gleichstellungspolitik in Europa Die uneingeschränkte und gleichberechtigte Teilhabe von Frauen und Männern am öffentlichen Leben - insbesondere am Erwerbsleben - ist ein wesentliches Ziel europäischer Politik. Die uneingeschränkte und gleichberechtigte Teilhabe von Frauen und Männern am öffentlichen Leben - insbesondere am Erwerbsleben - ist ein wesentliches Ziel europäischer Politik. Gleichstellung im Rahmen der Vereinten Nationen Deutschland setzt sich in den VN-Gremien für die Gleichstellung und den Schutz der Frauenrechte ein. Seit April 2019 ist Deutschland wieder Mitglied der Frauenrechtskommission. Zuvor war Deutschland von 1997 bis 2017 ununterbrochen Mitglied. Deutschland setzt sich in den VN-Gremien für die Gleichstellung und den Schutz der Frauenrechte ein. Seit April 2019 ist Deutschland wieder Mitglied der Frauenrechtskommission. Zuvor war Deutschland von 1997 bis 2017 ununterbrochen Mitglied. Multilaterale Gleichstellungspolitik der G7- und G20-Staaten Die Beseitigung von Ungleichheiten, insbesondere mit Blick auf die Gleichstellung der Geschlechter, ist eines der zentralen Anliegen der G7- und G20-Staaten. Die Beseitigung von Ungleichheiten, insbesondere mit Blick auf die Gleichstellung der Geschlechter, ist eines der zentralen Anliegen der G7- und G20-Staaten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:25.811860+00:00","lastSeen":"2026-03-15T17:25:25.811860+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk","crawledAt":"2026-03-15T17:25:25.812874Z","crawlId":"tools-seeded-1773595525","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"69d77a6df0fc00338dd8d52de3ee576d141b237a33b116aac4efc85ced8c69a5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:25.812874+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d4c6e759-96e7-463e-a3d1-febe1de66284', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk/gleichstellungspolitik-in-europa', 'active', NULL, '2026-03-15T17:25:26.304720+00:00', '{"id":"d4c6e759-96e7-463e-a3d1-febe1de66284","title":"Gleichstellungspolitik in Europa","summary":{"de":"Die uneingeschränkte und gleichberechtigte Teilhabe von Frauen und Männern am öffentlichen Leben - insbesondere am Erwerbsleben - ist ein wesentliches Ziel europäischer Politik."},"content":{"de":"Sowohl die Europäische Union (EU) als auch der Europarat setzen sich für die Verwirklichung der Gleichstellung der Geschlechter ein. Die EU ist durch mehrere Artikel im Vertrag über die EU, im Vertrag über die Arbeitsweise der EU sowie in der Charta der Grundrechte dazu verpflichtet, die Gleichstellung von Frauen und Männern zu fördern. Ihre Institutionen (Kommission, Rat und Parlament) arbeiten seit vielen Jahren darauf hin, dass Männer und Frauen sowohl auf europäischer Ebene als auch in den einzelnen Mitgliedstaaten vor dem Gesetz und im gelebten Alltag gleichgestellt sind. Das Bundesfrauenministerium setzt sich dafür in den relevanten Gremien des Rates und in allen anderen für die Gleichstellungspolitik wichtigen Expertengruppen und Ausschüssen auf EU-Ebene ein - zum Beispiel im Beratenden Ausschuss für die Chancengleichheit von Frauen und Männern der EU-Kommission. Gleichstellungspolitik wurde in der Europäischen Union von 2016 bis 2019 im Rahmen des strategischen Engagements für die Gleichstellung der Geschechter betrieben. Im März 2020 hat die Europäische Kommission ihre Strategie für die Gleichstellung der Geschlechter für den Zeitraum von 2020 bis 2025 in Form einer verbindlichen Kommissionsmitteilung vorgestellt. Inhaltlich werden durch die Gleichstellungsstrategie sechs Aktionsschwerpunkte gesetzt: Gleichberechtigte Führungsverantwortung in der Gesellschaft; Gender Mainstreaming und eine intersektionelle Perspektive in EU-Politikmaßnahmen;"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk/gleichstellungspolitik-in-europa","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:26.304720+00:00","lastSeen":"2026-03-15T17:25:26.304720+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk/gleichstellungspolitik-in-europa","crawledAt":"2026-03-15T17:25:26.305439Z","crawlId":"tools-seeded-1773595526","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b6c7cf17545d7930d2b9e82c0de252d3d7785937e5beefeb2538aefc0b7f8a5a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:26.305439+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('46c03ddc-f7bf-48da-8f3f-1ff03e0a63f6', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/jungen-und-maenner', 'active', NULL, '2026-03-15T17:25:26.811566+00:00', '{"id":"46c03ddc-f7bf-48da-8f3f-1ff03e0a63f6","title":"Jungen und Männer","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Gleichstellungspolitik für Jungen und Männer Das Bundesfamilienministerium unterstützt Jungen und Männer bei der selbstbestimmten Berufs- und Lebensplanung jenseits von Rollenklischees und hilft bei Problemen und in Krisen. Das Bundesfamilienministerium unterstützt Jungen und Männer bei der selbstbestimmten Berufs- und Lebensplanung jenseits von Rollenklischees und hilft bei Problemen und in Krisen. Geschlechterstereotypen in allen Lebensbereichen überwinden Das Bundesfamilienministerium unterstützt alle Menschen unabhängig von ihrem Geschlecht dabei, ihre Potenziale und Interessen voll zu entfalten. Das Bundesfamilienministerium unterstützt alle Menschen unabhängig von ihrem Geschlecht dabei, ihre Potenziale und Interessen voll zu entfalten. Neue Wege für Jungs: Boys''Day - Jungen-Zukunftstag Der Boys''Day soll dazu beitragen, dass überholte Rollenbilder überwunden und neue Perspektiven für Jungen eröffnet werden, zum Beispiel im erzieherischen Bereich und der Gesundheitsbranche. Der Boys''Day soll dazu beitragen, dass überholte Rollenbilder überwunden und neue Perspektiven für Jungen eröffnet werden, zum Beispiel im erzieherischen Bereich und der Gesundheitsbranche."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/jungen-und-maenner","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:26.811566+00:00","lastSeen":"2026-03-15T17:25:26.811566+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/jungen-und-maenner","crawledAt":"2026-03-15T17:25:26.811566Z","crawlId":"tools-seeded-1773595526","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5d001d9ed21a895e8ff447e704f234ef1fe7da8a2c4533db7c0550c08b68c78c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:26.811566+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ecc02774-0710-4056-b8e6-bc44cbadd338', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/sexuelle-und-geschlechtliche-vielfalt', 'active', NULL, '2026-03-15T17:25:27.308256+00:00', '{"id":"ecc02774-0710-4056-b8e6-bc44cbadd338","title":"Sexuelle und geschlechtliche Vielfalt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Gleichstellungspolitische Meilensteine Für mehr Akzeptanz und weniger Diskriminierung von LSBTIQ*-Personen: Die politisch und gesetzlichen Meilensteine der vergangenen Jahre. Für mehr Akzeptanz und weniger Diskriminierung von LSBTIQ*-Personen: Die politisch und gesetzlichen Meilensteine der vergangenen Jahre. Aufklärung und Beratung fördern Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend arbeitet kontinuierlich daran, Informations-, Beratungs- und Unterstützungsstrukturen für LSBTIQ*-Personen und ihre Angehörigen auszubauen. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend arbeitet kontinuierlich daran, Informations-, Beratungs- und Unterstützungsstrukturen für LSBTIQ*-Personen und ihre Angehörigen auszubauen. Gesetz über die Selbstbestimmung in Bezug auf den Geschlechtseintrag (SBGG) Das Selbstbestimmungsgesetz soll trans-, intergeschlechtlichen und nichtbinären Personen erleichtern, ihren Geschlechtseintrag ändern zu lassen. Antworten auf die wichtigsten Fragen. Das Selbstbestimmungsgesetz soll trans-, intergeschlechtlichen und nichtbinären Personen erleichtern, ihren Geschlechtseintrag ändern zu lassen. Antworten auf die wichtigsten Fragen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/sexuelle-und-geschlechtliche-vielfalt","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:27.308256+00:00","lastSeen":"2026-03-15T17:25:27.308256+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/sexuelle-und-geschlechtliche-vielfalt","crawledAt":"2026-03-15T17:25:27.308256Z","crawlId":"tools-seeded-1773595527","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f1bf2e043a3c9f0db546656ea7a246f66117d5835b0769f3311ab66793ba8d02"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:27.308256+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5caee2bd-1767-4e56-b431-0dad524eb594', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales', 'active', NULL, '2026-03-15T17:25:27.877839+00:00', '{"id":"5caee2bd-1767-4e56-b431-0dad524eb594","title":"Internationales und Europa","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Internationale Tätigkeitsfelder des Bundesfamilienministeriums Internationale Politik für Demokratie und Engagement"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:27.877839+00:00","lastSeen":"2026-03-15T17:25:27.877839+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales","crawledAt":"2026-03-15T17:25:27.877839Z","crawlId":"tools-seeded-1773595527","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"2de4064303f25375f79b6810fecd492fe27bae290a20dd2a77870b945a70c521"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:25:27.877839+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('94386890-ca80-4887-b87a-1856d790c071', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/erasmus-plus', 'active', NULL, '2026-03-15T17:25:28.299543+00:00', '{"id":"94386890-ca80-4887-b87a-1856d790c071","title":"Erasmus+","summary":{"de":"Als EU-Programm, das Menschen dabei hilft, über Ländergrenzen hinweg interkulturelle Kompetenzen zu erwerben, steht Erasmus+ vor allem für erleichterte Mobilität für Lernende, die die heimische..."},"content":{"de":"Als EU-Programm, das Menschen dabei hilft, über Ländergrenzen hinweg interkulturelle Kompetenzen zu erwerben, steht Erasmus+ vor allem für erleichterte Mobilität für Lernende, die die heimische Komfortzone verlassen möchten. Ein Auslandssemester in Estland, ein Berufspraktikum in Frankreich, ein Austausch mit einer Schulklasse in Polen, ein Freiwilligendienst in Griechenland: Erasmus+ macht Europa erfahrbar. Ziel ist die Förderung des interkulturellen Austauschs und die Stärkung der europäischen Identität. Durch das Verlassen der heimischen Komfortzone schafft das Erasmus+ Programm die Chance, den eigenen Horizont zu erweitern und sich somit persönlich weiterzuentwickeln. Eine Auslandserfahrung und das Erlernen einer zusätzlichen Sprache kann zudem ein attraktiver Faktor auf dem Arbeitsmarkt sein und sogar neue Berufsperspektiven ermöglichen. Nichts stärkt die europäische Identität mehr als Begegnung und gelebtes Miteinander über Ländergrenzen hinweg. Dafür steht auch Erasmus+, das EU-Programm für allgemeine und berufliche Bildung, Jugend und Sport (2021 - 2027)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/erasmus-plus","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:28.299543+00:00","lastSeen":"2026-03-15T17:25:28.299543+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/erasmus-plus","crawledAt":"2026-03-15T17:25:28.300633Z","crawlId":"tools-seeded-1773595528","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5071b22c5ad3cd4254abe38f9d1acbec3501a14838a24e25980b03aab0b94b58"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:28.300633+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('228deb3b-c643-4778-912d-8ce5704d1821', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/europaeischer-sozialfonds-esf', 'active', NULL, '2026-03-15T17:25:28.805731+00:00', '{"id":"228deb3b-c643-4778-912d-8ce5704d1821","title":"Europäischer Sozialfonds","summary":{"de":"Der Europäische Sozialfonds (ESF) ist Europas wichtigstes Instrument zur Förderung der Beschäftigung und sozialer Integration in Europa."},"content":{"de":"Seit über 60 Jahren verbessert der Europäische Sozialfonds (ESF) die Beschäftigungschancen der Menschen in Deutschland und in Europa: Er fördert eine bessere Bildung, unterstützt durch Ausbildung und Qualifizierung und trägt zum Abbau von Benachteiligungen am Arbeitsmarkt bei. Der Europäische Sozialfonds (ESF) wird auch künftig als ESF Plus wichtigstes Finanzierungs- und damit auch Förderinstrument der Europäischen Union (EU) für Investitionen in Menschen sein. Hauptziel ist es, zu einem sozialeren Europa beizutragen und die europäische Säule sozialer Rechte in die Praxis umzusetzen. Der ESF investiert vor Ort in Maßnahmen, um Menschen bei der Bewältigung wirtschaftlicher und sozialer Herausforderungen zu unterstützen. In der aktuellen Förderperiode wird der neue ESF Plus noch stärker auf den Gedanken eines sozialeren Europas ausgerichtet. Inhaltlich soll der ESF Plus insbesondere den Zugang zu Beschäftigung, allgemeiner und beruflicher Bildung verbessern, die sozioökonomische Integration von Drittstaatsangehörigen,"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/europaeischer-sozialfonds-esf","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:28.805731+00:00","lastSeen":"2026-03-15T17:25:28.805731+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/europaeischer-sozialfonds-esf","crawledAt":"2026-03-15T17:25:28.806204Z","crawlId":"tools-seeded-1773595528","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"de14edb483d2d3ddbff904d75ada4dea24f54772e8552c232e393a6d222e208c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:28.806204+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c39681ec-94d5-4f2a-935a-d9e7c5a8010d', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-familienpolitik', 'active', NULL, '2026-03-15T17:25:29.299336+00:00', '{"id":"c39681ec-94d5-4f2a-935a-d9e7c5a8010d","title":"Internationale Familienpolitik","summary":{"de":"Familienpolitik liegt in erster Linie in nationaler Zuständigkeit und ist daher von den in den Mitgliedstaaten der Europäischen Union (EU) jeweils vorherrschenden Einstellungen..."},"content":{"de":"Die Mitgliedstaaten der Europäischen Union (EU) stehen alle vor ähnlichen familienpolitischen Herausforderungen. Ihre Familienpolitik zielt daher auf die Vereinbarkeit von Familie und Beruf sowie gute Entwicklungschancen für Kinder ab. Familienpolitik liegt in erster Linie in nationaler Zuständigkeit und ist daher von den in den Mitgliedstaaten der Europäischen Union (EU) jeweils vorherrschenden Einstellungen, gesellschaftlichen Rahmenbedingungen und Traditionen geprägt. Entsprechend groß ist die Bandbreite von Erwerbs- und Vereinbarkeitsmodellen in Europa. In allen EU-Staaten zielt die Familienpolitik jedoch auf die Vereinbarkeit von Familie und Beruf sowie gute Entwicklungschancen für alle Kinder ab. Die Vereinbarkeitsrichtlinie der Europäischen Union schafft einen EU-weiten Mindeststandard für eine partnerschaftliche Aufteilung der Familienarbeit. Das Bundeskabinett hat im Juni 2022 einem Gesetz zugestimmt, um die wenigen in Deutschland noch offenen Punkte aus der Richtlinie bis Ende des Jahres 2022 umzusetzen. Ziel ist, eine bessere Vereinbarkeit von Beruf und Privatleben für Eltern und pflegende Angehörige. Der Rat der Europäischen Union hat im Juni 2021 einstimmig eine Empfehlung zur Einführung einer EU-Kindergarantie beschlossen. Deren Ziel ist es, die soziale Ausgrenzung von Kindern zu bekämpfen, Kinderrechte zu stärken und Chancengleichheit zu fördern. Dabei geht es um den Zugang zu In einem Nationalen Aktionsplan \"Neue Chancen für Kinder in Deutschland\" mit einer Laufzeit bis 2030 soll die Ratsempfehlung zu einer EU-Kindergarantie umgesetzt werden. Zur Steuerung dieses Prozesses ernannte die damalige Bundesministerin Lisa Paus die damalige Parlamentarische Staatssekretärin Ekin Deligöz zur Nationalen Kinderchancen-Koordinatorin. Die Erarbeitung des Nationalen Aktionsplans soll von einem breit angelegten Beteiligungsprozess mit Akteurinnen und Akteuren aus Politik und Zivilgesellschaft begleitet werden. Die Verabschiedung des Nationalen Aktionsplans im Bundeskabinett ist für Anfang 2023 geplant."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-familienpolitik","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:29.299336+00:00","lastSeen":"2026-03-15T17:25:29.299336+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-familienpolitik","crawledAt":"2026-03-15T17:25:29.299336Z","crawlId":"tools-seeded-1773595529","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"3d0e9a0f2466545bc12105bfe81c60bb1c9ca05f090cceacaa6a276d9570d1b2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:29.299336+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ada06104-dea1-4ccf-a7d7-0cf6e2748da3', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik', 'active', NULL, '2026-03-15T17:25:29.818924+00:00', '{"id":"ada06104-dea1-4ccf-a7d7-0cf6e2748da3","title":"Internationale und europäische Jugendpolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Jugend und Europa Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Das Europäische Jahr der Jugend 2022 Die Europäische Union hat 2022 das Europäische Jahr der Jugend ausgerufen. Es soll neue Chancen für junge Menschen eröffnen und ihren Meinungen und Ideen mehr Gehör verschaffen. Die Europäische Union hat 2022 das Europäische Jahr der Jugend ausgerufen. Es soll neue Chancen für junge Menschen eröffnen und ihren Meinungen und Ideen mehr Gehör verschaffen. Die Jugendstrategie der Bundesregierung \"In gemeinsamer Verantwortung: Politik für, mit und von Jugend\" unter diesem Motto steht die Jugendstrategie der Bundesregierung. Im Mittelpunkt stehen junge Menschen zwischen zwölf und 27 Jahren. \"In gemeinsamer Verantwortung: Politik für, mit und von Jugend\" unter diesem Motto steht die Jugendstrategie der Bundesregierung. Im Mittelpunkt stehen junge Menschen zwischen zwölf und 27 Jahren."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:29.818924+00:00","lastSeen":"2026-03-15T17:25:29.818924+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik","crawledAt":"2026-03-15T17:25:29.818924Z","crawlId":"tools-seeded-1773595529","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"85615af593a23b4fc80ef5f936beb6fee86c364d547454c2a40b4f717258f0a9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:29.819909+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0db3d36d-f668-444e-9b4f-f156165139b7', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik/internationale-und-europaeische-jugendpolitik', 'active', NULL, '2026-03-15T17:25:30.304339+00:00', '{"id":"0db3d36d-f668-444e-9b4f-f156165139b7","title":"Internationale und europäische Jugendpolitik","summary":{"de":"Durch die internationale und europäische Jugendpolitik wird die bi- und multilaterale Zusammenarbeit und Verständigung im Jugendbereich mit anderen Ländern in Europa sowie weltweit aktiv..."},"content":{"de":"Durch die internationale und europäische Jugendpolitik wird die bi- und multilaterale Zusammenarbeit und Verständigung im Jugendbereich mit anderen Ländern in Europa sowie weltweit aktiv gefördert und nachhaltig gestärkt. Die internationale und europäische Jugendpolitik ist ein wichtiger Bestandteil der nationalen Jugendpolitik sowie der auswärtigen Kultur- und Bildungspolitik und umfasst die bi- und multilaterale Zusammenarbeit mit Ländern in Europa und anderen Regionen der Welt. Wichtige Partnerinnen und Partner sind dabei die Europäische Union (EU), der Europarat und die Vereinten Nationen. Die 2019 verabschiedete Jugendstrategie der Bundesregierung stellt die Interessen und Bedürfnisse der jungen Generationen in den Fokus. \"Europa und die Welt\" bildet eines von neun Handlungsfeldern, mit denen die Lebenslage junger Menschen verbessert werden soll. Dabei steht die Förderung von grenzüberschreitender Mobilität im Vordergrund, außerdem soll jungen Menschen die Möglichkeit gegeben werden, sich mit internationalen Entwicklungen auseinanderzusetzen und Europa aktiv mitzugestalten. Der internationale Jugendaustausch ist auch ein wichtiges Mittel, um Fremdenfeindlichkeit und Rassismus vorzubeugen. Internationale Erfahrungen bringen andere Menschen und andere Sprachen näher und schärfen den Blick für das eigene Land und die eigene Kultur. Jugendaustausch stärkt den europäischen Gedanken und fördert Verständigung und Toleranz auch über Europa hinaus. Das Bundesjugendministerium fördert daher zahlreiche Jugendbegegnungen und Fachkräfteprogramme und ermöglicht jungen Menschen, internationale Erfahrungen zu sammeln, interkulturelle Kompetenzen zu erwerben und Vielfalt wertschätzen zu lernen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik/internationale-und-europaeische-jugendpolitik","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:30.304339+00:00","lastSeen":"2026-03-15T17:25:30.304339+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik/internationale-und-europaeische-jugendpolitik","crawledAt":"2026-03-15T17:25:30.305333Z","crawlId":"tools-seeded-1773595530","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"143dedc653dd639c93c3ecf5dd0eca8458fda6af538d16435e4debe912a37e8f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:30.305333+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('98f9bcb2-1cf2-4f3c-8848-7c7df1887f1e', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-politik-fuer-demokratie-und-engagement', 'active', NULL, '2026-03-15T17:25:30.812626+00:00', '{"id":"98f9bcb2-1cf2-4f3c-8848-7c7df1887f1e","title":"Internationale Politik für Demokratie und Engagement","summary":{"de":"Millionen Menschen engagieren sich für ein friedliches, demokratisches und vielfältiges Miteinander im In- und Ausland. Das Bundesfamilienministerium fördert zahlreiche Projekte."},"content":{"de":"Täglich engagieren sich Menschen freiwillig in und außerhalb von Vereinen, Stiftungen oder Initiativen für ein friedliches, demokratisches und vorurteilfreies Miteinander. Auch international setzt sich die Bundesregierung dafür ein, diese Menschen zu unterstützen und in ihrem Engagement zu fördern, denn Engagement macht nicht an Landesgrenzen halt: Ob über den deutsch-französischen Bürgerfonds oder den Internationalen Jugendfreiwilligendienst - es gibt verschiedene Formate, in denen sich Bürgerinnen und Bürger über Grenzen hinweg für eine gute Sache einsetzen. Hier finden Sie Informationen zu den vom Bundesfamilienministerium geförderten, grenzüberschreitenden Engagementprogrammen und -formaten. Seit April 2020 werden mithilfe des Deutsch-Französischen Bürgerfonds Städtepartnerschaften und Bürgerinitiativen gefördert und unterstützt. Deutschland und Frankreich haben gemeinsam mit dem Vertrag von Aachen, der im Januar 2019 unterzeichnet wurde, ein klares Signal für die Stärkung des grenzüberschreitenden bürgerschaftlichen Engagements gesetzt. Der Deutsch-Französische Bürgerfonds soll helfen, die deutsche und die französische Zivilgesellschaft einander noch näherzubringen und den intergenerationellen Austausch zwischen den Bürgerinnen und Bürgern beider Staaten in einem geeinten Europa zu bestärken und zu vertiefen. Neue Ideen und innovative Projekte können so niedrigschwelligen Zugang zur Förderung erhalten. Gefördert werden kleine Projekte und Initiativen mit bis zu 5000 Euro sowie mittelgroße Projekte bis hin zu Leuchtturmprojekten mit über 50.000 Euro. Der Internationale Jugendfreiwilligendienst (IJFD) ist der Auslandsfreiwilligendienst des Bundesfamilienministeriums. Er ermöglicht jungen Menschen durch einen freiwilligen Dienst im Ausland interkulturelle, gesellschaftspolitische und persönliche Erfahrungen zu sammeln und so die eigene Persönlichkeit zu bereichern und sich weiterzubilden. In der Regel findet der Einsatz im sozialen oder ökologischen Bereich sowie in der Friedens- und Versöhnungsarbeit statt. Weitere Informationen über den IJFD bietet eine Website des Bundesfamilienministeriums. Mit dem Programm \"Citizens, Equality, Rights and Values\" (CERV) verfolgt die Europäische Union (EU) das Ziel, die in den EU-Verträgen verankerten Rechte und Werte zu fördern und zu schützen. CERV fördert Projekte mit einem Gesamtbudget von bis zu 1,55 Milliarden Euro für den Zeitraum 2021 bis 2027 in vier Aktionsbereichen:"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-politik-fuer-demokratie-und-engagement","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:30.812626+00:00","lastSeen":"2026-03-15T17:25:30.812626+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-politik-fuer-demokratie-und-engagement","crawledAt":"2026-03-15T17:25:30.812626Z","crawlId":"tools-seeded-1773595530","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"2c153e6a9415fefbd2503524018ce343f464f2c8c45137c2bf201379fec2aaf8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:30.812626+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('160bf2fc-9d25-4129-a2ee-28289096f8af', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend', 'active', NULL, '2026-03-15T17:25:31.329387+00:00', '{"id":"160bf2fc-9d25-4129-a2ee-28289096f8af","title":"Politik für Kinder und Jugendliche","summary":{"de":"Alle Kinder und Jugendlichen haben ein Recht auf gutes Aufwachsen und gleiche Chancen - unabhängig von Herkunft, Geschlecht, Religion oder sozialem..."},"content":{"de":"Bundesbildungsministerin Karin Prien hat die Qualifizierungsoffensive Berufliche Bildung gestartet. Die Initiative soll dem Fachkräftemangel begegnen und die Ausbildung entlang der gesamten Bildungskette stärken. Für einen besseren Jugendmedienschutz ist die Kooperation der Online-Plattformen wichtig. Das betonte Dr. Petra Bahr, Staatssekretärin im Bundesjugendministerium, bei einem Austausch mit Vertretern der Unternehmen und Verbände. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:31.329387+00:00","lastSeen":"2026-03-15T17:25:31.329387+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend","crawledAt":"2026-03-15T17:25:31.329387Z","crawlId":"tools-seeded-1773595531","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"cc2441929b8a3e9910da0fbedc259ab2923aa326687d2ca4be173a5b0a296272"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:31.329387+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6e6ece35-3b2c-4601-8c6b-4488e63d3e2c', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/integration-und-chancen-fuer-junge-menschen', 'active', NULL, '2026-03-15T17:25:31.819603+00:00', '{"id":"6e6ece35-3b2c-4601-8c6b-4488e63d3e2c","title":"Integration und Chancen für junge Menschen","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Initiative \"JUGEND STÄRKEN\" Mit den Programmen \"Jugendmigrationsdienste\", \"Respekt Coaches\" und \"JUGEND STÄRKEN - Brücken in die Eigenständigkeit\" unterstützt das Bundesjugendministerium junge Menschen und fördert Toleranz und Vielfalt im sozialen und schulischen Bereich. Mit den Programmen \"Jugendmigrationsdienste\", \"Respekt Coaches\" und \"JUGEND STÄRKEN - Brücken in die Eigenständigkeit\" unterstützt das Bundesjugendministerium junge Menschen und fördert Toleranz und Vielfalt im sozialen und schulischen Bereich. Garantiefonds Hochschule Mit den Richtlinien \"Garantiefonds Hochschule\" werden Spätaussiedlerinnen und Spätaussiedler, Flüchtlinge und Zugewanderte auf dem Weg zum Abitur und ins Studium unterstützt. Mit den Richtlinien \"Garantiefonds Hochschule\" werden Spätaussiedlerinnen und Spätaussiedler, Flüchtlinge und Zugewanderte auf dem Weg zum Abitur und ins Studium unterstützt. Kriminalitäts- und Gewaltprävention Das Bundesjugendministerium trägt aktiv zu Handlungsstrategien bei, um Kinder- und Jugendkriminalität vorzubeugen. Es regt Fachdiskussionen an und setzt thematische Schwerpunkte. Das Bundesjugendministerium trägt aktiv zu Handlungsstrategien bei, um Kinder- und Jugendkriminalität vorzubeugen. Es regt Fachdiskussionen an und setzt thematische Schwerpunkte."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/integration-und-chancen-fuer-junge-menschen","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:31.819603+00:00","lastSeen":"2026-03-15T17:25:31.819603+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/integration-und-chancen-fuer-junge-menschen","crawledAt":"2026-03-15T17:25:31.819603Z","crawlId":"tools-seeded-1773595531","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"61f13ce946ad194edc62e427f6edd80bdedb1d83d2319b782afff4ec93ba2004"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:31.819603+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1f512d77-61a7-4baa-ad61-4ecb4ce4db19', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung', 'active', NULL, '2026-03-15T17:25:32.339255+00:00', '{"id":"1f512d77-61a7-4baa-ad61-4ecb4ce4db19","title":"Jugendbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Kinder- und Jugendarbeit Kinder- und Jugendarbeit setzt an den Stärken junger Menschen an und unterstützt ihre Entwicklung zu eigenverantwortlichen und gemeinschaftsfähigen Persönlichkeiten. Kinder- und Jugendarbeit setzt an den Stärken junger Menschen an und unterstützt ihre Entwicklung zu eigenverantwortlichen und gemeinschaftsfähigen Persönlichkeiten. Jugend und Europa Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Förderprogramm \"Jugend erinnert\" Ziel des Förderprogramms \"Jugend erinnert\" ist es, möglichst vielen Jugendlichen den Besuch eines Lernorts der NS-Vergangenheit zu ermöglichen. Dabei berücksichtigt das Programm auch weniger bekannte Gedenkstätten und Opfergruppen. Ziel des Förderprogramms \"Jugend erinnert\" ist es, möglichst vielen Jugendlichen den Besuch eines Lernorts der NS-Vergangenheit zu ermöglichen. Dabei berücksichtigt das Programm auch weniger bekannte Gedenkstätten und Opfergruppen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:32.339255+00:00","lastSeen":"2026-03-15T17:25:32.339255+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung","crawledAt":"2026-03-15T17:25:32.339255Z","crawlId":"tools-seeded-1773595532","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"4d8a9d407c4b0e1e16d9d54428cca3a14130119bacaace166793d69b26e63eab"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:32.339255+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('eca9c11d-cd0e-43d6-8b2f-d663c257c128', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung/jugendstrategie/jugendstrategie', 'active', NULL, '2026-03-15T17:25:32.846457+00:00', '{"id":"eca9c11d-cd0e-43d6-8b2f-d663c257c128","title":"Die Jugendstrategie der Bundesregierung","summary":{"de":"Mit ihrer gemeinsamen Jugendstrategie zeigt die Bundesregierung, dass sie die Interessen und Bedürfnisse der jungen Generation berücksichtigt. Die Jugendstrategie umfasst 163 Maßnahmen in neun..."},"content":{"de":"Mit ihrer gemeinsamen Jugendstrategie zeigt die Bundesregierung, dass sie die Interessen und Bedürfnisse der jungen Generation berücksichtigt. Die Jugendstrategie umfasst 163 Maßnahmen in neun Handlungsfeldern. Um die Jugendstrategie umzusetzen, wird die interministerielle Zusammenarbeit fortgesetzt. Bestehende Maßnahmen der Jugendstrategie werden weiterentwickelt, die Ressorts konzipieren neue Formate und Angebote für, mit und von Jugendlichen. Alle Ressorts sind dabei beteiligt. Mit der Interministeriellen Arbeitsgruppe (IMA) Jugend unter Federführung des Bundesjugendministeriums wird die ressortübergreifende Zusammenarbeit im Bereich Jugendpolitik gestärkt. I n Deutschland leben 14 Millionen junge Menschen zwischen 12 und 27 Jahren. Das sind 17 Prozent der Gesamtbevölkerung. Jugend ist ebenso vielfältig wie die Gesellschaft, deren Teil sie ist. Aber für alle Jugendlichen und jungen Erwachsenen geht es in dieser Lebensphase darum, selbstständig zu werden, sich zu qualifizieren und ihren Platz in der Gesellschaft zu finden. Ob bedarfsgerechter Nahverkehr, schnelles Internet, bezahlbare Mieten oder wirksamer Klimaschutz - Maßnahmen in allen Politikfeldern können Auswirkungen auf die junge Generation haben. Daher hat die Bundesregierung unter Federführung des Bundesjugendministeriums gemeinsam mit allen Ressorts eine Jugendstrategie entwickelt. Bei der Entwicklung der Jugendstrategie wurden junge Menschen als Expertinnen und Experten in eigener Sache beteiligt. Viele von ihnen brachten ihre Vorstellungen und Wünsche ein bei den JugendPolitikTagen, in themenspezifischen Audits oder via Online-Konsultation."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung/jugendstrategie/jugendstrategie","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:32.846457+00:00","lastSeen":"2026-03-15T17:25:32.846457+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung/jugendstrategie/jugendstrategie","crawledAt":"2026-03-15T17:25:32.846457Z","crawlId":"tools-seeded-1773595532","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"050156db03d869a0f54a7c2d399494e4266d2f53a30fcc14e3feece2f3963c84"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:32.846457+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('efa459ca-0828-48dc-bdab-c64c384d811a', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendgesundheit', 'active', NULL, '2026-03-15T17:25:33.340804+00:00', '{"id":"efa459ca-0828-48dc-bdab-c64c384d811a","title":"Kinder- und Jugendgesundheit","summary":{"de":"Körperliche und seelische Gesundheit ist eine wesentliche Voraussetzung für ein gutes Aufwachsen von Kindern und Jugendlichen. Das..."},"content":{"de":"Mentale Gesundheit Die mentale Gesundheit von Kindern und Jugendlichen ist weiterhin stark gefordert. Das Bundesjugendministerium unterstützt junge Menschen bei der Stärkung ihrer mentalen Gesundheit. Die mentale Gesundheit von Kindern und Jugendlichen ist weiterhin stark gefordert. Das Bundesjugendministerium unterstützt junge Menschen bei der Stärkung ihrer mentalen Gesundheit. Suizidprävention Suizid ist die häufigste Todesursache bei jungen Menschen. Rund 500 junge Menschen nehmen sich jedes Jahr in Deutschland das Leben. Häufig haben sie Ängste und Sorgen, die suizidale Gedanken auslösen können. Darüber zu sprechen fällt vielen schwer. Suizid ist die häufigste Todesursache bei jungen Menschen. Rund 500 junge Menschen nehmen sich jedes Jahr in Deutschland das Leben. Häufig haben sie Ängste und Sorgen, die suizidale Gedanken auslösen können. Darüber zu sprechen fällt vielen schwer. Kinder und Jugendliche nach der Pandemie Welche Auswirkungen hatte die Corona-Pandemie auf junge Menschen? Eine von der Bundesregierung geleitete Arbeitsgruppe aus Expertinnen und Experten hat die Folgen analysiert und Lösungsansätze entwickelt. Welche Auswirkungen hatte die Corona-Pandemie auf junge Menschen? Eine von der Bundesregierung geleitete Arbeitsgruppe aus Expertinnen und Experten hat die Folgen analysiert und Lösungsansätze entwickelt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendgesundheit","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:33.340804+00:00","lastSeen":"2026-03-15T17:25:33.340804+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendgesundheit","crawledAt":"2026-03-15T17:25:33.341324Z","crawlId":"tools-seeded-1773595533","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"4ab37b87e7f954e31cc0af7274bf5fb838b7616574a870df50718ce3aa9899bc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:33.341324+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('856ec256-aa50-4ee9-a697-a814d29a4c6e', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz', 'active', NULL, '2026-03-15T17:25:33.873541+00:00', '{"id":"856ec256-aa50-4ee9-a697-a814d29a4c6e","title":"Kinder- und Jugendschutz","summary":{"de":"Kinder und Jugendliche haben ein Recht auf Schutz vor körperlicher, sexueller und seelischer Gewalt. Im Kinder- und Jugendschutz geht es sowohl um..."},"content":{"de":"Bundesstiftung Frühe Hilfen Die Bundesstiftung Frühe Hilfen unterstützt werdende und junge Eltern in schwierigen Situationen. Im Fokus steht ein gesundes und gewaltfreies Aufwachsen von Kindern. Die Bundesstiftung Frühe Hilfen unterstützt werdende und junge Eltern in schwierigen Situationen. Im Fokus steht ein gesundes und gewaltfreies Aufwachsen von Kindern. Schutz vor sexualisierter Gewalt Die Bundesregierung unternimmt eine Reihe von Maßnahmen, um den Schutz von Kindern und Jugendlichen vor sexualisierter Gewalt kontinuierlich zu verbessern. Die Bundesregierung unternimmt eine Reihe von Maßnahmen, um den Schutz von Kindern und Jugendlichen vor sexualisierter Gewalt kontinuierlich zu verbessern. Hilfe-Telefon Sexueller Missbrauch Bei Verdachtsfällen von sexuellem Missbrauch berät das Hilfe-Telefon unter der Nummer 0800 22 55 530 montags, mittwochs und freitags von 9:00 bis 14:00 Uhr sowie dienstags und donnerstags von 15:00 bis 20:00 Uhr - kostenfrei und anonym. Bei Verdachtsfällen von sexuellem Missbrauch berät das Hilfe-Telefon unter der Nummer 0800 22 55 530 montags, mittwochs und freitags von 9:00 bis 14:00 Uhr sowie dienstags und donnerstags von 15:00 bis 20:00 Uhr - kostenfrei und anonym."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:33.873541+00:00","lastSeen":"2026-03-15T17:25:33.873541+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz","crawledAt":"2026-03-15T17:25:33.873541Z","crawlId":"tools-seeded-1773595533","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"96f13a853adb00ef3313490c4744521b551681b2ab778956f991570153fd6c4b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:33.873541+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('cbd0d945-6cba-4102-9798-d1ce6a2784cf', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz/aktiver-jugendschutz', 'active', NULL, '2026-03-15T17:25:34.318443+00:00', '{"id":"cbd0d945-6cba-4102-9798-d1ce6a2784cf","title":"Aktiver Jugendschutz","summary":{"de":"Kinder und Jugendliche begegnen in ihrem Alltag immer wieder Gefahren für ihre körperliche und geistige Gesundheit. Das Jugendschutzgesetz regelt den Umgang mit diesen Gefahrenquellen."},"content":{"de":"Kinder und Jugendliche begegnen in ihrem Alltag immer wieder Gefahren für ihre körperliche und geistige Gesundheit. Das Jugendschutzgesetz regelt den Umgang mit diesen Gefahrenquellen, zum Beispiel durch Bestimmungen für die Abgabe von Alkohol oder Tabak. Aufgabe des Staates ist es, Kinder und Jugendliche durch effektive und praxiswirksame Jugendschutzvorschriften vor Gefährdungen in der Öffentlichkeit zu schützen und ein gutes Aufwachsen mit Medien zu gewährleisten. Das Jugendschutzgesetz (JuSchG) regelt unter anderem den Verkauf und die Abgabe von Tabak, Alkohol, Filmen, Computerspielen sowie den Aufenthalt in Diskotheken und Gaststätten. Gemeinsam mit dem Jugendmedienschutz-Staatsvertrag (JMStV) der Länder wurde eine einheitliche Rechtsgrundlage für den Jugendschutz in den elektronischen Medien (Internet, Fernsehen, Rundfunk) geschaffen. Das vom Bundesjugendministerium vorgelegte Gesetz zum Schutz von Kindern und Jugendlichen vor den Gefahren des Konsums von elektronischen Zigaretten und elektronischen Shishas ist am 1. April 2016 in Kraft getreten. Damit werden die Abgabe- und Konsumverbote des Jugendschutzgesetzes und des Jugendarbeitsschutzgesetzes für Tabakwaren auf E-Zigaretten und E-Shishas ausgedehnt. Zudem wird sichergestellt, dass die Abgabeverbote von Tabakwaren, E-Zigaretten- und E-Shishas an Kinder und Jugendliche auch im Wege des Versandhandels gelten. Das Ziel des \"Zweiten Gesetzes zur Änderung des Jugendschutzgesetzes\" ist ein zeitgemäßer und zukunftssicherer Kinder- und Jugendmedienschutz, der die wesentlichen Risiken erfasst und Kindern und Jugendlichen ein gutes Aufwachsen mit Medien gewährleistet. Das Gesetz ist am 1. Mai 2021 in Kraft getreten. Schutz von Kindern und Jugendlichen vor Interaktionsrisiken wie Mobbing, sexueller Anmache oder Kostenfallen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz/aktiver-jugendschutz","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:34.318443+00:00","lastSeen":"2026-03-15T17:25:34.318443+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz/aktiver-jugendschutz","crawledAt":"2026-03-15T17:25:34.318443Z","crawlId":"tools-seeded-1773595534","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d5f5bd36681437618733c0a8c01c92077fd0ac9b6cd7bc4b33d9beceeaf6aa01"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:34.318443+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('66c2187e-24d1-48a4-9cbf-cc0171915db7', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinderrechte', 'active', NULL, '2026-03-15T17:25:34.840387+00:00', '{"id":"66c2187e-24d1-48a4-9cbf-cc0171915db7","title":"Starke Kinder","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"UN-Kinderrechtskonvention Die UN-Kinderrechtskonvention wurde 1989 verabschiedet und trat 1992 in Deutschland in Kraft. Sie schützt weltweit die Rechte der Kinder. Die UN-Kinderrechtskonvention wurde 1989 verabschiedet und trat 1992 in Deutschland in Kraft. Sie schützt weltweit die Rechte der Kinder. Kinderrechte im Alltag Die Rechte von Kindern stehen im Alltag oft in Konflikt mit anderen Interessen. Aber die UN-Kinderrechtskonvention sagt klar: Das Kindeswohl hat Vorrang. Die Rechte von Kindern stehen im Alltag oft in Konflikt mit anderen Interessen. Aber die UN-Kinderrechtskonvention sagt klar: Das Kindeswohl hat Vorrang. Partnerinnen und Partner Das Bundesbildungsministerium steht im stetigen Austausch mit vielen Organisationen, die Kinder und Jugendliche unterstützen und ihre Rechte stärken. Das Bundesbildungsministerium steht im stetigen Austausch mit vielen Organisationen, die Kinder und Jugendliche unterstützen und ihre Rechte stärken."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinderrechte","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:34.840387+00:00","lastSeen":"2026-03-15T17:25:34.840387+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinderrechte","crawledAt":"2026-03-15T17:25:34.841514Z","crawlId":"tools-seeded-1773595534","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"8fd252a36783b5cf0b47fd3e83b0f7368ad7571feda5c0f343d5cff775cd31e1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:34.841514+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bca52f0b-3b68-490a-8649-7e5e1c16895f', 'tools', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/medienkompetenz', 'active', NULL, '2026-03-15T17:25:35.336699+00:00', '{"id":"bca52f0b-3b68-490a-8649-7e5e1c16895f","title":"Medienkompetenz","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"\"SCHAU HIN! - Was Dein Kind mit Medien macht\" Medien spielen für Kinder und Jugendliche eine zentrale Rolle. Viele Eltern und Erziehende stehen vor der Herausforderung: Wie unterstütze ich mein Kind dabei, Smartphone, Konsole, Apps und soziale Netzwerke altersgerecht und sicher zu nutzen? Medien spielen für Kinder und Jugendliche eine zentrale Rolle. Viele Eltern und Erziehende stehen vor der Herausforderung: Wie unterstütze ich mein Kind dabei, Smartphone, Konsole, Apps und soziale Netzwerke altersgerecht und sicher zu nutzen? Kinder-Ministerium Das Kinder-Ministerium ist ein Online-Angebot für Kinder zwischen sieben und elf Jahren. Spielerisch können sie dort mehr über die Themen Politik und Kinderrechte erfahren. Das Kinder-Ministerium ist ein Online-Angebot für Kinder zwischen sieben und elf Jahren. Spielerisch können sie dort mehr über die Themen Politik und Kinderrechte erfahren. Bundesbildungsministerin Karin Prien hat die Qualifizierungsoffensive Berufliche Bildung gestartet. Die Initiative soll dem Fachkräftemangel begegnen und die Ausbildung entlang der gesamten Bildungskette stärken. Bund und Länder investieren bis 2030 gemeinsam fünf Milliarden Euro in die digitale Modernisierung der Schulen. Darauf verständigte sich die Bildungsministerkonferenz in Berlin."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/medienkompetenz","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:25:35.336699+00:00","lastSeen":"2026-03-15T17:25:35.336699+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/medienkompetenz","crawledAt":"2026-03-15T17:25:35.336699Z","crawlId":"tools-seeded-1773595535","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"3c0b3bee565ddd7b5f9ef9cf28ad7daf773b875bf45b94dfa33ff8fa7370260b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:35.336699+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
