INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a6e672b8-b7d4-4a9c-b483-e5b6056b0636', 'tools', 'https://www.das-steht-dir-zu.de/arbeit/buergergeld/der-buergergeld-rechner/index.html', 'active', NULL, '2026-03-17T07:01:24.084318+00:00', '{"id":"a6e672b8-b7d4-4a9c-b483-e5b6056b0636","title":"Der Bürgergeld-Rechner der Caritas.","summary":{"de":"Mit dem Bürgergeld-Rechner können Sie einen eventuellen Anspruch auf Bürgergeld direkt online berechnen."},"content":{"de":"Dabei wird der aktuelle Basis-Regelsatz von 563 Euro ab dem 1. Januar 2024 berücksichtigt, der maßgeblich für die gesamte Berechnung der Leistungen ist. Der Bürgergeld-Rechner berechnet einen eventuellen Anspruch anhand der fortgeschriebenen Regelsätze und Mehrbedarfe. Mit dem Bürgergeldrechner können Leistungsansprüche berechnet werden, die vom Gesetzgeber (Bundestag und Bundesrat) festgelegt sind. „Das Bürgergeld ist ein Auffangnetz für Menschen, die keine Möglichkeit haben, ihren Lebensunterhalt aus eigener Kraft zu bestreiten. Es ist eine solidarische Leistung, die keine großen Sprünge zulässt: Von derzeit 563 Euro (ab Januar 2024) im Monat ist alles zu zahlen, was man zum Leben braucht: Lebensmittel, Kleidung, Haushaltswaren, Fahrkarten, Reparaturen, Handy und nicht zu vergessen: die Stromkosten. Wer hingegen sozialversicherungspflichtig beschäftigt ist, der der hat durch Freibeträge nicht nur mehr Geld zur Verfügung, sondern erwirbt auch Ansprüche: für das ALG I, eine Erwerbsminderungsrente, die Rente und vieles mehr. Arbeiten lohnt sich also immer!“ Michaela Hofmann Die Höhe des Bürgergeldanspruchs ist abhängig von Ihren Kosten für Kalt- und Warmmiete, Ihrem Alter und der Anzahl Ihrer Kinder sowie Ihrem Einkommen und das Ihrer Partnerin oder ihres Partners. Zudem werden Ihre jeweiligen Lebensumstände berücksichtigt, ob Sie zum Beispiel alleinerziehend sind. Einberechnet in die Bedarfsermittlung werden auch Faktoren wie: Schwangerschaft, Behinderungen oder Krankheit. Bitte beachten Sie die Hinweise zu der nachfolgenden Berechnung:"},"url":"https://www.das-steht-dir-zu.de/arbeit/buergergeld/der-buergergeld-rechner/index.html","topics":["buergergeld_rechner"],"tags":["trusted_tool_source","calculator"],"targetGroups":["unemployed","families","general_public"],"status":"active","firstSeen":"2026-03-17T07:01:24.084318+00:00","lastSeen":"2026-03-17T07:01:24.084318+00:00","sourceUnavailable":false,"toolType":"calculator","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://www.das-steht-dir-zu.de/arbeit/buergergeld/der-buergergeld-rechner/index.html","crawledAt":"2026-03-17T07:01:24.084318Z","crawlId":"tools-seeded-1773730884","crawlerVersion":"0.1.0","sourceTier":"tier_2_ngo_watchdog","institutionType":"advisory","jurisdiction":"DE","sourceId":"dasstehtdirzu","providerName":"Das steht dir zu","providerLevel":"civil_society","checksum":"862d4b26e1bb07ca16ba2fc2afc0bdd1239cca72ee43b7d2213378a2c3e6b3a7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T07:01:24.084318+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a4796f0e-5326-4da1-b6f3-5f30ef7af590', 'tools', 'https://www.familienportal.de/familienportal/rechner-antraege/elterngeldrechner', 'active', NULL, '2026-03-01T20:14:00Z', '{"id":"a4796f0e-5326-4da1-b6f3-5f30ef7af590","title":"Elterngeldrechner","translations":{"de-LEICHT":{"title":"Rechner für Elterngeld","timestamp":"2026-03-01T20:14:00Z","provenance":{"source":"https://familienportal.de/familienportal/rechner-antraege/elterngeldrechner","crawledAt":"2026-03-01T20:14:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Der Elterngeldrechner im Familienportal ermöglicht eine unverbindliche Einschätzung des möglichen Elterngeldanspruchs."},"content":{"de":"Das Angebot führt strukturiert durch relevante Angaben und zeigt orientierende Ergebnisse für die persönliche Planung. Es unterstützt Familien bei der Vorbereitung auf einen späteren Antrag."},"url":"https://www.familienportal.de/familienportal/rechner-antraege/elterngeldrechner","topics":["financial_support","family"],"tags":["means_tested","automatic"],"targetGroups":["families","single_parents"],"status":"active","toolType":"calculator","accessibility":{"languages":["de"],"screenReaderCompatible":true},"firstSeen":"2026-03-01T20:14:00Z","lastSeen":"2026-03-01T20:14:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.familienportal.de/familienportal/rechner-antraege/elterngeldrechner","crawlId":"manual-curation-20260301-realdata-v1","checksum":"b839f7057a958da61ad22047de6d13dd5f0c84ff5f0a5ac0fd085737f258df11","crawledAt":"2026-03-01T20:14:00Z"},"qualityScores":{"iqs":79.9,"ais":58,"computedAt":"2026-03-01T20:14:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6829b206-c8d6-4ebb-9250-7028827ea676', 'tools', 'https://www.wege-zur-pflege.de/', 'active', NULL, '2026-03-15T17:24:01.224203+00:00', '{"id":"6829b206-c8d6-4ebb-9250-7028827ea676","title":"Wege zur Pflege","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Hier finden Sie Menschen, die Ihnen rund um das Thema Pflege mit Rat und Tat zur Seite stehen. Sie pflegen und betreuen Angehörige. Diese Situation kann herausfordernd sein. Insbesondere, wenn Sie zudem noch arbeiten. Deswegen finden Sie auf den nachfolgenden Seiten Angebote, die Sie unterstützen und entlasten können. Pflegende Beschäftigte sind verschiedenen Belastungen ausgesetzt. Sie zu unterstützen, wird für Arbeitgeber immer wichtiger. Erfahren Sie mehr zur Pflegezeit, Familienpflegezeit und betrieblichen Möglichkeiten. Sie werden zu Hause von Ihren Angehörigen oder anderen nahestehenden Menschen versorgt. Hier erhalten Sie einen kleinen Einblick, wie Sie ihre gemeinsame Pflegesituation gut gestalten können. Das Pflegetelefon des Bundesseniorenministeriums berät Sie zu den Regelungen des Pflegezeit- und Familienpflegezeitgesetzes. Dazu gehören beispielsweise eine kurzzeitige Arbeitsverhinderung, Pflegezeit und Familienpflegezeit. Das Pflegetelefon ist eine erste Anlaufstelle für Fragen zur Organisation der Pflege, für Fragen zur Finanzierung der Pflege und bei starker Belastung durch die Pflegesituation. Das Team des Pflegetelefons vermittelt Sie auch an eine für Ihre Situation geeignete Beratungsstelle weiter. Das Beratungsteam des Pflegetelefons erreichen Sie bundesweit telefonisch unter 030 20 17 91 31. Beirat Der Unabhängige Beirat für Pflege und Beruf berät das Bundesfamilienministerium in Fragen rund um die Vereinbarkeit von Pflege und Beruf."},"url":"https://www.wege-zur-pflege.de/","topics":["digital_service","tools"],"tags":["tool"],"targetGroups":["general_public","families","job_seekers"],"status":"active","firstSeen":"2026-03-15T17:24:01.224203+00:00","lastSeen":"2026-03-15T17:24:01.224203+00:00","sourceUnavailable":false,"toolType":"portal","relatedBenefits":[],"accessibility":{"languages":["de"],"screenReaderCompatible":true},"provenance":{"source":"https://wege-zur-pflege.de/","crawledAt":"2026-03-15T17:24:01.224203Z","crawlId":"tools-seeded-1773595441","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"wege-zur-pflege_de","providerName":"wege-zur-pflege.de","providerLevel":"federal","checksum":"2179ae1b7db5efdeeccd31cf704e118ceea36f5f16313752c3415ad0f9e50d53"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:24:01.224203+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1a2f056a-bc5e-41a0-8495-c009c40b3cd5', 'organizations', 'https://www.arbeitsagentur.de/bakarriere', 'active', NULL, '2026-03-15T17:25:53.795571+00:00', '{"id":"1a2f056a-bc5e-41a0-8495-c009c40b3cd5","title":"Ihre Karriere bei uns","summary":{"de":"Karriere bei der Bundesagentur für Arbeit: Finden Sie Stellenangebote und informieren Sie sich über eine Ausbildung, Studium oder Direkteinstieg bei der BA. Mehr erfahren!"},"content":{"de":"Gestalten Sie mit uns die soziale Zukunft Deutschlands! Vertrauen und gegenseitige Wertschätzung sind für uns sehr wichtig: Bei der Bundesagentur für Arbeit unterscheiden wir nicht nach Herkunft, Alter oder Geschlecht. Wir ermöglichen die Vereinbarkeit von Familie und Arbeit und unterstützen Sie bei gesundheitlichen Einschränkungen. Werden Sie jetzt Teil der Bundesagentur für Arbeit. Wir bringen Menschen und Arbeit zusammen und sichern Existenzen. Mit uns gemeinsam übernehmen Sie soziale Verantwortung. Als größte Dienstleisterin auf dem deutschen Arbeitsmarkt bieten wir einen sicheren Arbeitsplatz – jetzt und in Zukunft. Wir leben Vielfalt und Verantwortung: Mehr als 55% unserer Führungskräfte sind Frauen (Stand: Dezember 2024). Zudem setzen wir uns aktiv für die Klimaziele des Bundes ein - unser Ziel: Klimaneutralität bis 2030. Die Inklusion schwerbehinderter Menschen ist uns ein besonderes Anliegen. In jeder Dienststelle gibt es eine Schwerbehinderten-Vertretung (SbV), die Sie dabei unterstützt, Ihre Tätigkeit und Ihren Arbeitsplatz nach Ihren individuellen Belangen zu gestalten. Sie wollen mehr über Ihre Vorteile bei der Bundesagentur für Arbeit erfahren? Wir haben alle unsere Benefits für Sie zusammengefasst."},"url":"https://www.arbeitsagentur.de/bakarriere","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:25:53.795571+00:00","lastSeen":"2026-03-15T17:25:53.795571+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/bakarriere"},"provenance":{"source":"https://www.arbeitsagentur.de/bakarriere","crawledAt":"2026-03-15T17:25:53.795571Z","crawlId":"organizations-seeded-1773595553","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"6e9e95b7fd15e0640bbdc51baaeec26de8947557f54c1612e1e167aa2b886b13"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:25:53.795571+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
