INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dff469a9-6e09-4726-ac92-ca308b00476c', 'organizations', 'https://www.arbeitsagentur.de/erklaerung-barrierefreiheit', 'active', NULL, '2026-03-15T17:26:13.605640+00:00', '{"id":"dff469a9-6e09-4726-ac92-ca308b00476c","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Die Bundesagentur für Arbeit ist bemüht, die Webseiten unter www.arbeitsagentur.de und mobilen Anwendungen barrierefrei zugänglich zu gestalten. Rechtsgrundlagen sind die UN-Behindertenrechtskonvention (UN-BRK), das Behindertengleichstellungsgesetz (BGG) sowie die Barrierefreie Informationstechnik-Verordnung (BITV 2.0) in ihren jeweils gültigen Fassungen."},"content":{"de":"Die Überprüfung der Einhaltung der Anforderungen beruht auf unabhängigen BITV 2.0-Tests, die im Rahmen der Weiterentwicklung an jeweiligen Teilbereichen des Internetauftritts kontinuierlich durchgeführt werden. Die Webseiten und mobilen Anwendungen sind mit den genannten Anforderungen zum größten Teil vereinbar. Die Bundesagentur für Arbeit ist bemüht, die verbleibenden Barrieren schnellstmöglich zu beheben. Die nachstehend aufgeführten Inhalte sind aus folgenden Gründen nicht barrierefrei: Unvereinbarkeit mit der BITV 2.0: Anmeldung/Registrierung: Die Nutzung eines Freischaltcodes ist derzeit noch nicht barrierefrei möglich. An einer barrierefreien Lösung auch für § 10 BGG-Kunden wird gearbeitet. Online-Portal - Menü: Das Hauptmenu ist derzeit eingeschränkt barrierefrei bedienbar. Eine barrierefreie Lösung soll bis 02/2026 zur Verfügung stehen. PDF-Dokumente: PDF-Dokumente älteren Datums sind nicht durchgehend barrierefrei. Neu herausgegebene PDF-Dokumente werden in der Regel in barrierefreier Version zur Verfügung gestellt oder zeitnah durch eine solche ersetzt. Falls Sie eine bestimmte PDF-Datei von uns benötigen, die noch nicht barrierefrei zur Verfügung steht, teilen Sie uns dies gerne über unser Kontaktformular mit."},"url":"https://www.arbeitsagentur.de/erklaerung-barrierefreiheit","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:13.605640+00:00","lastSeen":"2026-03-15T17:26:13.605640+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/erklaerung-barrierefreiheit"},"provenance":{"source":"https://www.arbeitsagentur.de/erklaerung-barrierefreiheit","crawledAt":"2026-03-15T17:26:13.605640Z","crawlId":"organizations-seeded-1773595573","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"0c9f3f966abbc18b44e4fcc2f0d18638f689f0d46a0d50733ee4e09302037622"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:13.605640+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('52720823-c0bd-4877-9855-a21bf99515d5', 'organizations', 'https://www.arbeitsagentur.de/gebaerdensprache', 'active', NULL, '2026-03-15T17:26:14.076522+00:00', '{"id":"52720823-c0bd-4877-9855-a21bf99515d5","title":"Informationen in Gebärdensprache","summary":{"de":"Übersicht zu den Seiten rund um die Angebote für Arbeitgeberinnen und Arbeitgeber"},"content":{"de":"Sehen Sie im Video, wie das Portal der BA aufgebaut ist und wie Sie schnell die Informationen finden, die Sie suchen. Überblick zu den Portalseiten für Bildungsträger, Netzwerke und Schulen Informationen zu den Voraussetzungen beim Bezug von Kurzarbeitergeld für Unternehmen Informationen zum Kurzarbeitergeld-Verfahren für Unternehmen Die Videos in Gebärdensprache finden Sie direkt in den monatlichen Presseinformationen zum Arbeitsmarkt. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/gebaerdensprache","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:14.076522+00:00","lastSeen":"2026-03-15T17:26:14.076522+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/gebaerdensprache"},"provenance":{"source":"https://www.arbeitsagentur.de/gebaerdensprache","crawledAt":"2026-03-15T17:26:14.076522Z","crawlId":"organizations-seeded-1773595574","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"ef61088a2eddb02c424b340fc5c7ca5b94858ec68b6e5c1c404b2306a2955c59"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:14.077147+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e086ed5e-f48e-42c4-a6a3-63d9a4d1d6df', 'organizations', 'https://www.arbeitsagentur.de/leichte-sprache', 'active', NULL, '2026-03-15T17:26:15.074736+00:00', '{"id":"e086ed5e-f48e-42c4-a6a3-63d9a4d1d6df","title":"Herzlich willkommen auf der Internet-Seite von der Bundesagentur für Arbeit!","summary":{"de":"Die Seite der Bundes-Agentur für Arbeit in Leichter Sprache. Jetzt informieren"},"content":{"de":"Infos über die Bundesagentur für Arbeit in Leichter Sprache Die Bundesagentur für Arbeit ist eine der größten deutschen Behörden. Es arbeiten über 110.000 Personen für die Bundesagentur für Arbeit. Zur Bundesagentur für Arbeit gehören: Der Hauptsitz ist in der Stadt Nürnberg. Ein Vorstand leitet die Bundesagentur für Arbeit. Andrea Nahles ist seit August 2022 die Vorsitzende vom Vorstand. Alle Menschen in Deutschland sollen eine Arbeit haben. Die Bundesagentur für Arbeit hilft dabei. Zum Beispiel: Sie hilft Menschen, die ihre Arbeit verloren haben. Sie hilft Arbeitgebern, die neue Mitarbeiter suchen."},"url":"https://www.arbeitsagentur.de/leichte-sprache","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:15.074736+00:00","lastSeen":"2026-03-15T17:26:15.074736+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/leichte-sprache"},"provenance":{"source":"https://www.arbeitsagentur.de/leichte-sprache","crawledAt":"2026-03-15T17:26:15.074736Z","crawlId":"organizations-seeded-1773595575","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"b9591e31548d88cb1df37c1b5db3111e2a8c167e8eeb17f735f585845521bd6f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:15.074736+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('93322a3a-a36f-4fcd-bf12-0453d3b2e173', 'organizations', 'https://www.arbeitsagentur.de/news', 'active', NULL, '2026-03-15T17:26:15.593781+00:00', '{"id":"93322a3a-a36f-4fcd-bf12-0453d3b2e173","title":"Aktuelle Meldungen der BA","summary":{"de":"Alle News und Meldungen der Bundesagentur für Arbeit im Überblick. Jetzt informieren!"},"content":{"de":"Wichtig: Hinweis: Aktuelle Informationen zu r Entwicklung des Arbeitsmarkts in Deutschland finden Sie auf der Seite Arbeitslosenquote & Arbeitslosenzahlen. 05.01.2026 – Anspruchsberechtigte Familien erhalten ab Januar 2026 automatisch mehr Kindergeld. 30.10.2025 – BA legt Bilanz des Berufsberatungsjahres 2024/25 vor. 22.07.2025 – Unbekannte Dritte geben sich als Bundesagentur für Arbeit aus und versprechen die Vermittlung von Online-Jobs. 14.07.2025 – Die Bundesagentur schränkt die unsichere E-Mail-Kommunikation ein und setzt auf die sicheren digitalen Zugangswege von Online-Portal und App-Angebot. 30.04.2025 – Noch bis zum 16.05. sammelt die Bundesagentur für Arbeit (BA) Erfahrungen und Ideen rund um die digitale Berufsorientierung. Beteiligen können sich Schülerinnen und Schüler sowie Lehrkräfte und Eltern."},"url":"https://www.arbeitsagentur.de/news","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:15.593781+00:00","lastSeen":"2026-03-15T17:26:15.593781+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/news"},"provenance":{"source":"https://www.arbeitsagentur.de/news","crawledAt":"2026-03-15T17:26:15.593781Z","crawlId":"organizations-seeded-1773595575","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"1410325adbe99bfeb28f446c149da3b7017a99f70e568b450e2308d2e39c8bac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:15.593781+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2fb273d6-787c-449e-91ad-16eb043023c7', 'organizations', 'https://www.arbeitsagentur.de/presse/presse-archiv', 'active', NULL, '2026-03-15T17:26:16.167822+00:00', '{"id":"2fb273d6-787c-449e-91ad-16eb043023c7","title":"Pressearchiv","summary":{"de":"Während der Woche der Ausbildung vom 16. bis 20. März 2026 wirbt die Bundesagentur für Arbeit bundesweit dafür, jungen Menschen den Einstieg ins Berufsleben zu ermöglichen und Betriebe für Ausbildungen zu gewinnen. Mit zahlreichen Aktionen sollen Unternehmen motiviert werden, auch in wirtschaftlich schwierigen Zeiten in Ausbildung zu investieren und damit die Fachkräfte von morgen zu sichern."},"content":{"de":"Um 140 Prozent ist die Zahl der von der Bundesagentur für Arbeit erteilten Arbeitsmarktzulassungen seit 2021 gestiegen – auf gut 521.000 im Jahr 2025. Das ist auch gegenüber dem Vorjahr ein deutliches Plus von 17 Prozent. Über 80 Großunternehmen und Branchenvertretungen informieren im Rahmen der digitalen Elternabende der BA vom 02. bis zum 15. März 2026 Jugendliche und ihre Eltern über Ausbildungs- und Studienmöglichkeiten. Jahreszeitlich üblicher Anstieg der Arbeitslosigkeit • 17,5 Millionen Kinder und ihre Familien erhielten 2025 Kindergeld • Ausgaben in Höhe von 58,6 Milliarden Euro für Kindergeld und Kinderzuschlag • Deutschlandweit einheitliche Organisation ermöglicht Digitalisierung und ab Mitte 2026 stufenweise automatisierte Kindergeldbearbeitung Wirtschaftliche Schwäche wirkt sich deutlich am Arbeitsmarkt aus Eine Auslandserfahrung steigert die Chancen am Arbeitsmarkt. Doch bei der Planung stoßen Menschen mit Behinderungen oft auf Barrieren. Für mehr Chancengleichheit sorgt jetzt die Bundesagentur für Arbeit mit einem neuen Inklusionsprojekt. Damit können sich Menschen mit Behinderungen, die gerne mal im EU-Ausland arbeiten würden, online über die Regelungen vor Ort informieren."},"url":"https://www.arbeitsagentur.de/presse/presse-archiv","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:16.167822+00:00","lastSeen":"2026-03-15T17:26:16.167822+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/presse/presse-archiv"},"provenance":{"source":"https://www.arbeitsagentur.de/presse/presse-archiv","crawledAt":"2026-03-15T17:26:16.167822Z","crawlId":"organizations-seeded-1773595576","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"52392598ecc47428ded21cffa2f2ebf3fe0d0c825453c5a6b3d8f435d1ddb467"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:16.167822+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3c0ed1f6-1919-492e-9070-15a6da541d9a', 'organizations', 'https://www.arbeitsagentur.de/rechtliche-hinweise', 'active', NULL, '2026-03-15T17:26:16.582324+00:00', '{"id":"3c0ed1f6-1919-492e-9070-15a6da541d9a","title":"Rechtliche Hinweise","summary":{"de":"Rechtliche Hinweise für Inhalte der Bundesagentur für Arbeit"},"content":{"de":"Es ist das Anliegen der Bundesagentur für Arbeit (BA), die Inhalte ihres Internetangebots stets inhaltlich richtig und aktuell verfügbar zu halten. Die Inhalte der Webseite werden sorgfältig verfasst und regelmäßig auf ihre Aktualität hin überprüft. Das Auftreten von Fehlern kann bei der Vielzahl von Themen und Informationen nicht völlig ausgeschlossen werden. Die BA übernimmt daher keine Gewähr dafür, dass alle Angaben des Internetauftritts zu jeder Zeit vollständig, richtig und in letzter Aktualität dargestellt sind. Die Darstellung der Inhalte orientiert sich an den Bedürfnissen der Kundinnen und Kunden der BA. Die BA bemüht sich, rechtliche Inhalte klar und verständlich darzustellen und dabei Rechts- oder Fachbegriffe nach Möglichkeit zu vermeiden. Trotzdem gilt: Rechtlich verbindlich ist das, was im Gesetz steht. Die Angaben im Internetauftritt der BA berücksichtigen möglicherweise nicht Ihre persönliche Situation. Suchen Sie daher bei weiteren Fragen die persönliche Beratung in der für Sie zuständigen Agentur für Arbeit oder Ihrem Jobcenter. Alle Angaben können ohne vorherige Ankündigung ergänzt, entfernt oder geändert werden. Für einzelne Inhalte des Internetauftritts der BA, insbesondere Dienste, die eine vorherige Registrierung/Anmeldung erfordern, können gesonderte zusätzliche Nutzungsbedingungen gelten, die ggf. bei der Nutzung zu beachten sind. Links zu Webseiten Dritter werden auf dieser Website als reine Serviceleistung, bzw. als Hinweis auf weiterführende Quellen angeboten. Für die Inhalte, zu denen verlinkt wird, sind die Anbieter der jeweiligen Webseiten ausschließlich selbst verantwortlich. Die BA macht sich diese Inhalte nicht zu eigen. Anbieter sind für die eigenen Inhalte, die sie zur Nutzung bereithalten, nach den allgemeinen Gesetzen verantwortlich. Von diesen eigenen Inhalten sind Querverweise auf die von anderen Anbietern bereitgehaltenen Inhalte zu unterscheiden."},"url":"https://www.arbeitsagentur.de/rechtliche-hinweise","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:16.582324+00:00","lastSeen":"2026-03-15T17:26:16.582324+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/rechtliche-hinweise"},"provenance":{"source":"https://www.arbeitsagentur.de/rechtliche-hinweise","crawledAt":"2026-03-15T17:26:16.583248Z","crawlId":"organizations-seeded-1773595576","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"000df1de5dc0ecdff56e762ef2d8cd343dd05207ba4fe0991ba686ac647144c2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:16.583248+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2ec45c4d-f563-46d4-b03f-c35bb830f5a3', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns', 'active', NULL, '2026-03-15T15:59:57.090269+00:00', '{"id":"2ec45c4d-f563-46d4-b03f-c35bb830f5a3","title":"Über uns | Bundesagentur für Arbeit","summary":{"de":"Auf Über uns erhalten Sie einen Überblick über Leitung, Organisation, Dienststellen, Fachdienste, Ziele und Richtlinien der Bundesagentur für Arbeit."},"content":{"de":"Informieren Sie sich, wer die Bundesagentur für Arbeit leitet und ihre Geschäfte führt. Erfahren Sie mehr über den Verwaltungsrat und die Verwaltungsausschüsse. Der Geschäftsbericht der Bundesagentur für Arbeit informiert über die Geschäfts- und Rechnungsergebnisse für das Jahr 2024. Vorstand und Verwaltungsrat legen die Strategie der BA fest. Die Zentrale entwickelt hierzu Produkte und Programme und führt die Regionaldirektionen. Die 10 Regionaldirektionen setzen die Strategie der BA deutschlandweit um und leiten die Agenturen für Arbeit vor Ort. Die 146 Agenturen für Arbeit mit ihren etwa 600 Niederlassungen setzen die Aufgaben der BA vor Ort um. Außerdem haben die Agenturen gemeinsam mit Landkreisen oder kreisfreien Städten 300 Jobcenter eingerichtet. Dazu kommen die Familienkassen der BA mit rund 100 Standorten."},"url":"https://www.arbeitsagentur.de/ueber-uns","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T15:59:57.090269+00:00","lastSeen":"2026-03-15T15:59:57.090269+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns","crawledAt":"2026-03-15T15:59:57.090269Z","crawlId":"organizations-seeded-1773590397","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4167266d0ad1ff4fd15e12d4f2c6cdcd312520ec193acf60e2793395e4f931de"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T15:59:57.090269+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('41414ae2-8ef3-4eef-a09b-e061ab86d810', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/aerztlicher-dienst', 'active', NULL, '2026-03-15T17:26:17.076403+00:00', '{"id":"41414ae2-8ef3-4eef-a09b-e061ab86d810","title":"Aufgabe des Ärztlichen Dienstes","summary":{"de":"Hindern Sie gesundheitliche Gründe an Ihrer Berufsausübung, wenden Sie sich an den Ärztlichen Dienst. Lesen Sie hier, welche Möglichkeiten es dazu gibt."},"content":{"de":"Wenn Ihnen gesundheitliche Probleme die Arbeitsuche oder die Arbeit erschweren, besprechen Sie dies am besten mit Ihrer Vermittlungs- oder Beratungsfachkraft der Agentur für Arbeit oder des Jobcenters. Diese kann den Ärztlichen Dienst bitten, Sie zu begutachten. Dabei geht es ausschließlich um gesundheitliche Beschwerden, die Sie so einschränken, dass Sie nicht oder nur in begrenztem Umfang einer Arbeit nachgehen können. Mit dem Ergebnis entscheiden die Fachkräfte dann gemeinsam mit Ihnen, wie Sie wieder in Arbeit kommen oder weiterarbeiten können. Die Sozialmedizinische Stellungnahme dient außerdem zur Beantwortung der Frage, ob Sie eine Förderung oder Geldleistung bekommen. Der Ärztliche Dienst unterstützt die Fachkräfte der Agenturen für Arbeit und der Jobcenter dabei, für Arbeitsuchende und Beschäftigte mit gesundheitlichen Einschränkungen passende Lösungen zu finden. Dazu beurteilen die Ärztinnen und Ärzte individuell in jedem Einzelfall: die Eignung speziell von Jugendlichen für bestimmte Berufe welche Reha bei einer Erkrankung oder nach einem Unfall helfen kann Diese Aufgaben erfüllen derzeit etwa 350 Ärztinnen und Ärzte unterschiedlicher Fachrichtungen in den Agenturen für Arbeit. Dazu kommen nach Bedarf Vertragsärztinnen und Vertragsärzte, die zum Beispiel in Praxen und Kliniken arbeiten. Alle sind sozialmedizinisch spezialisiert und erfahren. Außerdem stellen Fortbildungen sicher, dass Sie qualifizierte Unterstützung erhalten. Das Qualitätsmanagement des Ärztlichen Dienstes ist zertifiziert. Das heißt, es wird regelmäßig durch eine unabhängige Stelle kontrolliert. Sie können sich nicht direkt an die Ärztinnen und Ärzte wenden. Ihre Vermittlungs- oder Beratungsfachkraft übernimmt dies. Auch Jobcenter können den Ärztlichen Dienst beauftragen."},"url":"https://www.arbeitsagentur.de/ueber-uns/aerztlicher-dienst","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:17.076403+00:00","lastSeen":"2026-03-15T17:26:17.076403+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/aerztlicher-dienst"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/aerztlicher-dienst","crawledAt":"2026-03-15T17:26:17.076403Z","crawlId":"organizations-seeded-1773595577","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"1e2c435f555011334177a46818166b0a025b9b277c1edd9b4f10d55bb5c2d61d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:17.076747+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fc339c87-50e1-4dd4-9e29-a94baf0b4df0', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/antikorruptionsbeauftragter', 'active', NULL, '2026-03-15T17:26:17.575275+00:00', '{"id":"fc339c87-50e1-4dd4-9e29-a94baf0b4df0","title":"Antikorruptionsbeauftragter","summary":{"de":"Sie möchten ein Hinweise auf Korruption melden? Lesen Sie, wie Sie dazu vorgehen."},"content":{"de":"Mitarbeitende der Bundesagentur für Arbeit (BA) sind explizit aufgefordert, Korruption und sonstige Rechtsverstöße in der BA zu melden. Aber auch Sie als unsere Kundinnen und Kunden, als Bürgerinnen und Bürger oder als Geschäftspartnerinnen und Geschäftspartner haben dazu die Möglichkeit. Sie möchten einen Hinweis auf Korruption oder einen sonstigen Rechtsverstoß innerhalb der Bundesagentur für Arbeit (BA) melden? Dann wenden Sie sich an unseren Antikorruptionsbeauftragten. Hinweise können (anonymisiert) per E-Mail, per Telefon oder auch in einem persönlichen Gespräch erfolgen. Auf ausdrücklichen Wunsch bleibt der Hinweisgeber im weiteren Verlauf ungenannt. Dies gilt jedoch nicht gegenüber Ermittlungs- und Strafverfolgungsbehörden. Anhaltspunkte auf ein Fehlverhalten gibt der Antikorruptionsbeauftragte an den Fachbereich Interne Ermittlungen bei der Zentrale der BA weiter. Wichtig: Hinweis: Der Antikorruptionsbeauftragte ist nicht zuständig für allgemeine Anregungen, Fragen, Kritik, Beschwerden oder Hinweise darauf, dass Personen Leistungen zu Unrecht erhalten."},"url":"https://www.arbeitsagentur.de/ueber-uns/antikorruptionsbeauftragter","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:17.575275+00:00","lastSeen":"2026-03-15T17:26:17.575275+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/antikorruptionsbeauftragter"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/antikorruptionsbeauftragter","crawledAt":"2026-03-15T17:26:17.575275Z","crawlId":"organizations-seeded-1773595577","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"f72e7faa12a3eb9d70123f88f7d8ef0285c67fe11d135a134d880420b6939474"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:17.575275+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3054048c-5ba7-4af6-bdae-5f09092e249c', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/ba-klar', 'active', NULL, '2026-03-15T17:26:18.111812+00:00', '{"id":"3054048c-5ba7-4af6-bdae-5f09092e249c","title":"BA klar! Unternehmensbroschüre der Bundesagentur für Arbeit","summary":{"de":"Die BA unterstützt Menschen, Arbeit und Zukunft. Verschaffen Sie sich einen Überblick welche Themen uns beschäftigen und wofür wir uns einsetzen!"},"content":{"de":"Herzlich willkommen auf der Webseite der Bundesagentur für Arbeit! Seit fast 100 Jahren bringen wir Menschen in Arbeit und sichern ihre Existenz. Mit unserem umfangreichenden Dienstleistungsangebot bilden wir eine tragende Säule in Deutschland. Menschen und Unternehmen stehen im Mittelpunkt, wir sind für sie da – vor Ort und digital. Als moderne Dienstleisterin stehen wir an der Seite unserer Kundinnen und Kunden, und als Arbeitgeberin bieten wir vielfältige Chancen und Entwicklungsmöglichkeiten. Digitalisierung, ökologische Nachhaltigkeit sowie Chancengleichheit am Arbeitsmarkt sind uns ebenfalls wichtig. Die Bundesagentur für Arbeit begleitet Sie als verlässliche Partnerin vor Ort. Ob es um die erste große Entscheidung bei der Berufswahl, den Wiedereinstieg ins Arbeitsleben oder eine berufliche Neuorientierung geht - das Berufsleben ist eine Reise voller Wendungen und neuer Möglichkeiten. \"mein NOW\" - Nationale Online-Weiterbildungsplattform Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/ueber-uns/ba-klar","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:18.111812+00:00","lastSeen":"2026-03-15T17:26:18.111812+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/ba-klar"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/ba-klar","crawledAt":"2026-03-15T17:26:18.112801Z","crawlId":"organizations-seeded-1773595578","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"7cd4e9dd71f5cda557e0c116c2f6f9e6e8f331e6514bf36e529baf8aaf874570"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:18.112801+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0aba1d53-43e2-4b6d-b19a-e0adb7673c3f', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/befragungen', 'active', NULL, '2026-03-15T17:26:18.584269+00:00', '{"id":"0aba1d53-43e2-4b6d-b19a-e0adb7673c3f","title":"Zentrum für Kunden- und Mitarbeiterbefragungen","summary":{"de":"Bewerten Sie uns! Wir möchten wissen, wie zufrieden Sie mit unseren Dienstleistungen sind. Erfahren Sie mehr zu den Umfragen"},"content":{"de":"Uns interessiert, wie zufrieden Sie mit unseren Dienstleistungen sind. Daher befragen wir Sie zu unseren Ihre Einschätzung unterstützt uns auch in anderen Bereichen, zum Beispiel bei Ihre Rückmeldung hilft uns, unsere Services für Sie kontinuierlich zu verbessern. Tipp: Gut zu wissen: Das ZKM ist durch den TÜV Süd Management-Service nach ISO 9001:2015 zertifiziert. Hier bekommen Sie Antworten auf die wichtigsten Fragen zu Interviews über Internet oder Telefon. Lesen Sie die Ergebnisse der Befragungen im Überblick."},"url":"https://www.arbeitsagentur.de/ueber-uns/befragungen","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:18.584269+00:00","lastSeen":"2026-03-15T17:26:18.584269+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/befragungen"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/befragungen","crawledAt":"2026-03-15T17:26:18.584269Z","crawlId":"organizations-seeded-1773595578","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"77d74f57c464c9cc4e2ebe5cc1ab1f164cd82218a8e9cc272d0afd5b55109781"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:18.584269+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('67449035-de46-4d9e-9e10-697f3cd70c74', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/compliance', 'active', NULL, '2026-03-15T17:26:19.105939+00:00', '{"id":"67449035-de46-4d9e-9e10-697f3cd70c74","title":"Compliance | Bundesagentur für Arbeit","summary":{"de":"Lernen Sie die Grundsätze der BA kennen und erfahren Sie, wie die Maßnahmen und Prinzipien gewährleisten werden."},"content":{"de":"Tipp: Definition Compliance: Für die Bundesagentur für Arbeit bedeutet Compliance neben der ordnungsgemäßen Aufgabenwahrnehmung und der Einhaltung von Gesetzen und Regelungen auch die Beachtung und Pflege ethisch-moralischer Grundsätze, wie zum Beispiel Integrität, Verlässlichkeit und vorurteilsfreies Verhalten jedes einzelnen Beschäftigten. Die Bundesagentur für Arbeit (BA) hat die Pflicht, ihre Aufgaben loyal, unparteiisch, rechtmäßig und zum Wohl der Allgemeinheit zu erfüllen. Das Handeln der BA muss zu jedem Zeitpunkt transparent und nachvollziehbar sein. Kunden und die Öffentlichkeit im Allgemeinen müssen Vertrauen in die Integrität der BA haben. Der Vorstand der BA räumt der Integrität der BA einen hohen Stellenwert ein. Deshalb wurde ein umfassendes System zur Prävention und Bekämpfung von Korruption und sonstigen strafbewehrten Handlungen installiert. Dieses System enthält eine Vielzahl an Maßnahmen und Vorkehrungen zur Risikominimierung. Anwendung der Richtlinie der Bundesregierung zur Korruptionsprävention in der Bundesverwaltung Schulungen zu Compliance und zur Korruptionsprävention Regelmäßige Analyse und Feststellung von besonders korruptionsgefährdeten Arbeitsgebieten"},"url":"https://www.arbeitsagentur.de/ueber-uns/compliance","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:19.105939+00:00","lastSeen":"2026-03-15T17:26:19.105939+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/compliance"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/compliance","crawledAt":"2026-03-15T17:26:19.105939Z","crawlId":"organizations-seeded-1773595579","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"5d7c3fba0a3ab5eaba9fd1cb88110d66c9a6273422c8cb5a161c40ea9d08ae42"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:19.105939+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0b96e688-d7f1-418a-b828-d06ab8a0d338', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/e-rechnung', 'active', NULL, '2026-03-15T17:26:20.126423+00:00', '{"id":"0b96e688-d7f1-418a-b828-d06ab8a0d338","title":"E-Rechnung | Bundesagentur für Arbeit","summary":{"de":"Als Lieferant oder Dienstleister können Sie elektronische Rechnungen an die BA übermitteln. Informieren Sie sich jetzt über die Übertragungswege."},"content":{"de":"Die Bundesagentur für Arbeit kann Ihre elektronischen Rechnungen annehmen und verarbeiten. Auf den folgenden Seiten finden Sie die wichtigsten Informationen zur E-Rechnung: Rechnungsstellung über die OZG-RE (Rechnungseingangs-Plattform der Bundesdruckerei) Tipp: Gut zu wissen: Ab dem 27. November 2020 sind Sie als Lieferant oder Dienstleister gesetzlich verpflichtet, Rechnungen elektronisch bei der BA einzureichen. PEPPOL-Netzwerk für elektronische Kommunikation mit Öffentlichen Auftraggebern EU-Norm CEN 16931: Elektronischer Rechnungsstandard"},"url":"https://www.arbeitsagentur.de/ueber-uns/e-rechnung","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:20.126423+00:00","lastSeen":"2026-03-15T17:26:20.126423+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/e-rechnung"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/e-rechnung","crawledAt":"2026-03-15T17:26:20.126423Z","crawlId":"organizations-seeded-1773595580","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"5694f30e4c3c303832a4f272a5f2218dd51f92b46ea6d9c3b951fdafded94047"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:20.126423+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b654a9a9-0e3e-4ac4-8583-b27b46fb0f26', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/europavertretung', 'active', NULL, '2026-03-15T17:26:20.583177+00:00', '{"id":"b654a9a9-0e3e-4ac4-8583-b27b46fb0f26","title":"Schnittstelle Europavertretung","summary":{"de":"Erfahren Sie mehr über die vielfältigen Aufgaben der Europavertretung. Jetzt informieren!"},"content":{"de":"Die Europavertretung der Bundesagentur für Arbeit ist seit mehr als 10 Jahren das zentrale Bindeglied zwischen der Europäischen Union (EU), ihren Institutionen und der BA. Die Mitarbeiterinnen und Mitarbeiter der Europavertretung der BA nehmen vielfältige Aufgaben wahr. Dazu zählen unter anderem: positiv: die beratende Mitwirkung am politischen Entscheidungsprozess der EU positiv: die Analyse und Bewertung aller für die BA wichtigen Entscheidungen, Trends und Entwicklungen in der EU positiv: die Beteiligung an der Meinungsbildung zu den Themen Beschäftigung, Bildung, Migration und Soziales positiv: die Betreuung und Beratung europäischer Institutionen, Interessensvertreter und Netzwerke. Dazu zählt zum Beispiel die Kooperation mit unseren Partnern im Europäischen Netzwerk der öffentlichen Arbeitsmarktservices („European Network of Public Employment Services“)."},"url":"https://www.arbeitsagentur.de/ueber-uns/europavertretung","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:20.583177+00:00","lastSeen":"2026-03-15T17:26:20.583177+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/europavertretung"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/europavertretung","crawledAt":"2026-03-15T17:26:20.583177Z","crawlId":"organizations-seeded-1773595580","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"02e00f6280e84008ab5af1b7eb02f2bc3cf91315bb0ab630e65ba093adb8c3c9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:20.583177+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3f04b89e-f83d-42b5-9b58-355c5b070f20', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/familienkasse-der-ba', 'active', NULL, '2026-03-15T17:26:21.120112+00:00', '{"id":"3f04b89e-f83d-42b5-9b58-355c5b070f20","title":"Familienkasse: Wir helfen Familien","summary":{"de":"Die Familienkasse der Bundesagentur für Arbeit ist Ihre Ansprechpartnerin für die finanzielle Unterstützung von Familien. Jetzt Kontakt aufnehmen!"},"content":{"de":"Erfahren Sie mehr über uns und wo Sie die nächste Familienkasse in Ihrer Nähe finden. Die Familienkasse ist Ihre Ansprechpartnerin bei Fragen zu Kindergeld und Kinderzuschlag. Lesen Sie mehr dazu. Mitteilungen und Anträge an die Familienkasse können Sie ganz bequem online und von überall aus erledigen. Hier erfahren Sie wie. Familien können für direkte Mitteilungen unsere eServices nutzen. Für Anfragen aus Politik, Verwaltung und von den Medien stehen wir gerne zur Verfügung. Wir sind Teil der Bundesagentur für Arbeit. Wir gliedern uns in eine Direktion mit Sitz in Nürnberg und 15 regionale Familienkassen. Diese sind in vielen Orten in ganz Deutschland ansässig. Wir helfen Ihnen gerne bei Ihren Anliegen. Wir möchten die beste und modernste Dienstleisterin für Familienleistungen in Deutschland und Europa sein."},"url":"https://www.arbeitsagentur.de/ueber-uns/familienkasse-der-ba","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:21.120112+00:00","lastSeen":"2026-03-15T17:26:21.120112+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/familienkasse-der-ba"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/familienkasse-der-ba","crawledAt":"2026-03-15T17:26:21.120112Z","crawlId":"organizations-seeded-1773595581","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"bcf6ac6ce3e851e841d40f4dffec70cd7edbbbde7fccfc01229364a2b176d892"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:21.120112+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('01fb1b40-144e-4936-bc59-fec4f12dc372', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/gemeinsam-bringt-weiter', 'active', NULL, '2026-03-15T17:26:21.622458+00:00', '{"id":"01fb1b40-144e-4936-bc59-fec4f12dc372","title":"Gemeinsam. bringt weiter – Strategische Ausrichtung der BA bis 2030","summary":{"de":"Wie will sich die Bundesagentur für Arbeit für die Zukunft rüsten? Erfahren Sie alles in der Vorstellung unserer Strategie bis 2030. Jetzt informieren!"},"content":{"de":"Unser Leben ist geprägt von politischen, gesellschaftlichen und wirtschaftlichen Herausforderungen und Krisen. Die Auswirkungen der Megatrends Digitalisierung, demografischer Wandel und Energiewende spüren wir täglich. Dieser Realität müssen und wollen wir uns als Bundesagentur für Arbeit stellen. „ GEMEINSAM. bringt weiter – Strategische Ausrichtung der BA bis zum Jahr 2030“ bildet die Grundlage eines gemeinsamen, zielorientierten Handelns in der BA bis zum Jahr 2030. Unsere Kulturdimensionen, unser humanistisches Menschenbild und unser Führungsverständnis stellen unser Wertefundament dar. Als Mitglied der Global Compact-Initiative der Vereinten Nationen setzen wir uns zudem für die Verwirklichung nachhaltiger Entwicklungsziele ein. positiv: Für uns stehen Menschen und Unternehmen im Mittelpunkt. Ihre Anliegen bestimmen unser Handeln. Zusammen mit unseren externen Partnerinnen und Partnern helfen wir Menschen, ihre Chancen in Arbeit und Ausbildung zu verbessern und zu nutzen. Mit Rat und Tat stärken wir als Expertin am Arbeitsmarkt die Wirtschaft und unterstützen Unternehmen, Fachkräfte zu gewinnen. positiv: Als digitale Dienstleisterin stellen wir Kundinnen und Kunden unsere Angebote und Leistungen schnell und zuverlässig zur Verfügung und halten unser Versprechen eines persönlichen Beratungsangebotes. positiv: Wir entwickeln uns konsequent zu einer nachhaltigen und klimaneutralen Organisation."},"url":"https://www.arbeitsagentur.de/ueber-uns/gemeinsam-bringt-weiter","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:21.622458+00:00","lastSeen":"2026-03-15T17:26:21.622458+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/gemeinsam-bringt-weiter"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/gemeinsam-bringt-weiter","crawledAt":"2026-03-15T17:26:21.622458Z","crawlId":"organizations-seeded-1773595581","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"582ffe40d63c48b33ade0a14fd079f115551556d281f39916d1f41f9fe2a3564"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:21.622458+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('eae6fa6b-5d28-4370-9ede-706ccc1655c7', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/geschaeftsbericht-2024', 'active', NULL, '2026-03-15T17:26:22.150979+00:00', '{"id":"eae6fa6b-5d28-4370-9ede-706ccc1655c7","title":"Geschäftsbericht für das Jahr 2024","summary":{"de":"Der Geschäftsbericht der Bundesagentur für Arbeit informiert über die Geschäfts- und Rechnungsergebnisse für das Jahr 2024. Hier steht Ihnen der komplette Bericht zum Download bereit."},"content":{"de":"Mit diesem Geschäftsbericht wollen wir darüber Bilanz ziehen, was wir 2024 geschafft haben und welche Aktivitäten umgesetzt wurden. Gleichzeitig legen wir Rechenschaft gegenüber dem Bundesministerium für Arbeit und Soziales (BMAS) zu unseren Geschäfts- und Rechnungsergebnissen ab. Dies ist der Grund dafür, dass der Geschäftsbericht der BA nach der Aufsichtsfunktion des BMAS den Rechtskreis SGB III bilanziert. Wir, der Vorstand der BA sowie der Verwaltungsrat, wünschen Ihnen viel Spaß beim Lesen. Bürgerinnen und Bürger, Unternehmen und unsere Sozialpartner erwarten eine zeitgemäße Sozialverwaltung, die den aktuellen Herausforderungen, insbesondere durch Krisen und Megatrends, gewachsen ist und diesen vorausschauend begegnet. Daher haben wir eine neue strategische Ausrichtung für die BA bis zum Jahr 2030 erarbeitet. Unter dem Motto: \"GEMEINSAM. bringt weiter\" gibt sie langfristige Orientierung für alle drei Teile der Organisation – für das SGB II, das SGB III und die Familienkasse. In einer Welt im Wandel geben wir Menschen und Unternehmen in Deutschland Orientierung und Sicherheit. Wir entwickeln gemeinsam mit ihnen individuelle Perspektiven am Arbeitsmarkt, sichern Existenzen und ebnen Wege in ein selbstbestimmtes Arbeitsleben. Dafür arbeiten Agenturen für Arbeit, Jobcenter und Familienkassen Hand in Hand. Zusammen mit unseren externen Partnerinnen und Partnern helfen wir Menschen, ihre Chancen in Arbeit und Ausbildung zu verbessern und zu nutzen. Mit Rat und Tat stärken wir als Expertin am Arbeitsmarkt die Wirtschaft und unterstützen Unternehmen, Fachkräfte zu gewinnen. Als digitale Dienstleisterin stellen wir Kundinnen und Kunden unsere Angebote und Leistungen schnell und zuverlässig zur Verfügung und halten unser Versprechen eines persönlichen Beratungsangebotes. Wir entwickeln uns konsequent zu einer nachhaltigen und klimaneutralen Organisation. Wir stellen uns Veränderungen und sind flexibel, lernend und krisenfest. Wir handeln partnerschaftlich nach innen und außen, auf Augenhöhe und mit Respekt. Wir nehmen Eigenverantwortung ernst und fordern sie ein. Die deutsche Wirtschaft steckt in einer Phase der Stagnation. Im Jahr 2023 hatte sich die Wirtschaftsleistung um 0,3 Prozent verringert und auch für 2024 zeichnet sich eine ähnliche Entwicklung ab. Das außenwirtschaftliche Umfeld der deutschen Wirtschaft entwickelte sich 2024 zwar moderat aufwärtsgerichtet, die deutschen Exporte konnten davon aber nicht profitieren. Ihre Entwicklung blieb wie schon im Vorjahr schwach. Der verhaltene Außenhandel wirkte sich insbesondere auf die Industrieproduktion aus, die seit über einem Jahr rückläufig ist. Im Zusammenhang damit sind die Unternehmensinvestitionen 2024 deutlich gesunken. Investitionen in Ausrüstungen als auch in Bauten haben gleichermaßen abgenommen. Dekarbonisierung, Digitalisierung und demografischer Wandel üben Anpassungsdruck auf die Unternehmen aus. Die immer noch hohen Zinsen und die erhöhte Unsicherheit – bezogen auf die Transformations- und Klimapolitik – beeinträchtigen gleichzeitig die für Anpassungen notwendigen Investitionen. Infolge der anhaltend schwachen Wirtschaftslage sind Arbeitslosigkeit und Unterbeschäftigung im Jahresdurchschnitt 2024 erneut deutlich gestiegen. Die Arbeitskräftenachfrage war einerseits zu schwach, um das zunehmende Arbeitsangebot aufzunehmen, andererseits passten die Profile der Arbeitslosen oftmals nicht zur Nachfrage. Das Risiko, aus Beschäftigung arbeitslos zu werden, ist zwar im langjährigen Vergleich niedrig, hat sich gegenüber dem Vorjahr aber weiter erhöht. Gleichzeitig sind die Chancen, die Arbeitslosigkeit durch eine Beschäftigungsaufnahme zu beenden, rückläufig und liegen auf einem historisch niedrigen Niveau."},"url":"https://www.arbeitsagentur.de/ueber-uns/geschaeftsbericht-2024","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:22.150979+00:00","lastSeen":"2026-03-15T17:26:22.150979+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/geschaeftsbericht-2024"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/geschaeftsbericht-2024","crawledAt":"2026-03-15T17:26:22.152062Z","crawlId":"organizations-seeded-1773595582","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"622150217c786c5af0cd278e7582c540cf1ae97f2b85e8b736b877186a868a9f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:22.152062+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('59a92c47-797f-46fd-b3b2-21e0114f624c', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/hauptstadtvertretung', 'active', NULL, '2026-03-15T17:26:22.579543+00:00', '{"id":"59a92c47-797f-46fd-b3b2-21e0114f624c","title":"Hauptstadtvertretung","summary":{"de":"Finden Sie Informationen die Hauptstadtvertretung als Bindeglied zwischen der Bundesagentur für Arbeit und den Ministerien und dem Bundestag."},"content":{"de":"Die Hauptstadtvertretung ist die Verbindung zwischen der Zentrale der Bundesagentur für Arbeit und den in Berlin ansässigen Ministerien sowie dem Bundestag. Ihre Mitarbeiterinnen und Mitarbeiter nehmen vielfältige Aufgaben wahr, unter anderem folgende: positiv: Bewertung und Analyse BA-relevanter Gesetzesvorhaben, politischer Entscheidungen, Themen und Entwicklungen positiv: Information des Vorstands und der Führungskräfte der BA über diese Vorhaben oder Entscheidungen positiv: Informations- und Meinungsaustausch mit Vertretern von Bundestag, Bundesrat, Kanzleramt, Ministerien und Verbänden über die aktuelle BA-Geschäftspolitik positiv: erste Bewertung und Koordinierung der Anfragen von Abgeordneten"},"url":"https://www.arbeitsagentur.de/ueber-uns/hauptstadtvertretung","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:22.579543+00:00","lastSeen":"2026-03-15T17:26:22.579543+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/hauptstadtvertretung"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/hauptstadtvertretung","crawledAt":"2026-03-15T17:26:22.579543Z","crawlId":"organizations-seeded-1773595582","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"b9d9fa5f89279f6c0b103870fe817110a1ac38047461028eeacd9af4a2ef1428"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:22.579543+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('84d90820-9754-4030-a1b9-2e34415b10f9', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/inklusion-bringt-weiter', 'active', NULL, '2026-03-15T17:26:23.125435+00:00', '{"id":"84d90820-9754-4030-a1b9-2e34415b10f9","title":"Vielfalt Leben – Inklusion bringt weiter","summary":{"de":"Lesen Sie, wie sich die Bundesagentur für Arbeit (BA) für Inklusion innerhalb der BA und am Arbeitsmarkt einsetzt und engagiert."},"content":{"de":"Deutschland ratifizierte 2009 die UN-Behindertenrechtskonvention (UN-BRK) über die Rechte von Menschen mit Behinderungen. Dadurch wurde auch die Idee der Inklusion bekannt – insbesondere mit einem Fokus auf Menschen mit Behinderungen. Die UN-BRK macht Behinderung nicht an einem amtlich festgestellten Grad der Behinderung fest. Deshalb gehören zur Zielgruppe dieses Aktionsplans Menschen, die langfristige körperliche, seelische, geistige oder Sinnesbeeinträchtigungen haben, welche sie in Wechselwirkung mit verschiedenen Barrieren an der vollen, wirksamen und gleichberechtigten Teilhabe an der Gesellschaft hindern (Art. 1 UN-BRK). Menschen mit Beeinträchtigungen sollen gleichberechtigt an der Gesellschaft teilhaben. Eine Voraussetzung dafür: Sie können am Arbeitsleben selbstbestimmt teilnehmen und sind so unter anderem in der Lage, selbst für ihren Lebensunterhalt zu sorgen. Teilhabe am Arbeitsmarkt ist damit auch Voraussetzung für ein selbstbestimmtes und würdevolles Leben. Die Mitarbeiterinnen und Mitarbeiter der BA legen großen Wert darauf, Menschen mit Beeinträchtigungen respektvoll zu begegnen und gleichberechtigt zu unterstützen – nicht erst seit Inkrafttreten der UN-BRK. Wir sind uns der Vorbildfunktion bewusst, die wir als großer Arbeitgeber und Dienstleister am Arbeitsmarkt haben. Die BA möchte Strukturen verändern und das Bewusstsein für die Belange von Menschen mit Behinderungen schärfen. Deshalb hat sie einen Aktionsplan Inklusion entwickelt und daraus Maßnahmen abgeleitet. Diese sollen dafür sorgen, dass die UN-BRK planvoll und zielgerichtet umgesetzt wird. Mit dem Aktionsplan sowie dem Maßnahmenkatalog aus dem Jahr 2020 verpflichtet sich die BA dazu, einen Beitrag zur Umsetzung der UN BRK zu leisten und sie sichtbar werden zu lassen."},"url":"https://www.arbeitsagentur.de/ueber-uns/inklusion-bringt-weiter","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:23.125435+00:00","lastSeen":"2026-03-15T17:26:23.125435+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/inklusion-bringt-weiter"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/inklusion-bringt-weiter","crawledAt":"2026-03-15T17:26:23.125435Z","crawlId":"organizations-seeded-1773595583","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"4a8d97b465300d6c4b33e5a9455297bec2f61f5c3383ebb6f3989c423b28dc7a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:23.125435+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('883144d9-98dc-4a7f-948a-af1dac4bf5d8', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/kundenreaktionsmanagement', 'active', NULL, '2026-03-15T17:26:23.585483+00:00', '{"id":"883144d9-98dc-4a7f-948a-af1dac4bf5d8","title":"Kundenreaktionsmanagement (KRM)","summary":{"de":"Sie möchten uns Feedback geben? Wir freuen uns! Das KRM nimmt Ihre Anregungen, Lob und Kritik entgegen."},"content":{"de":"Ihr Feedback ist für uns als KRM der Bundesagentur für Arbeit (BA) wichtig, um eine Rückmeldung über die Qualität unserer Dienstleistungen zu erhalten und Verbesserungsmöglichkeiten zu erkennen. Wir bearbeiten pro Jahr durchschnittlich 100.000 Anliegen unserer Kundinnen und Kunden. Als eigenständige und neutrale Anlaufstelle kümmern wir uns um Kundinnen und Kunden, die sich mit Beschwerden, Lob, Anregungen und Kritik an uns wenden. In allen Dienststellen der BA bundesweit ist ein KRM eingerichtet. Kolleginnen und Kollegen vor Ort in den Agenturen für Arbeit, Jobcentern oder Familienkassen nehmen sich Ihres Anliegens an. Wenn Ihr Anliegen bundesweite Bedeutung hat, wird es dem zentralen KRM in Nürnberg zugeleitet. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/ueber-uns/kundenreaktionsmanagement","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:23.585483+00:00","lastSeen":"2026-03-15T17:26:23.585483+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/kundenreaktionsmanagement"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/kundenreaktionsmanagement","crawledAt":"2026-03-15T17:26:23.585483Z","crawlId":"organizations-seeded-1773595583","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"14a988b6ea35b6bcbb9885e653d22f2107a86f3626616c5e489ca04d2bea2d90"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:23.585483+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2dfb7fe1-5b98-4400-82d4-5af9b6ed05cf', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/messe-veranstaltungsmanagement', 'active', NULL, '2026-03-15T17:26:24.110153+00:00', '{"id":"2dfb7fe1-5b98-4400-82d4-5af9b6ed05cf","title":"Messe- und Veranstaltungsmanagement (MVM)","summary":{"de":"Lesen Sie, wie die Agenturen für Arbeit nicht nur Berufsorientierungs- und Bildungsmessen organisieren."},"content":{"de":"Das MVM unterstützt als zentrale Abteilung der BA die Agenturen für Arbeit bundesweit, wenn sie auf Messen und Veranstaltungen die Besucherinnen und Besucher über berufliche Themen informieren. Dazu organisieren die Mitarbeiterinnen und Mitarbeiter des MVM zeitgemäße Ausstattung für rund 2.000 Veranstaltungen pro Jahr. Die Agenturen für Arbeit können zwischen verschiedenen Messeständen wählen, die das MVM zur Verfügung stellt. So gibt es Stände in verschiedenen Größen von 6 bis 80 Quadratmetern. Dabei steht die direkte Kommunikation mit den Besucherinnen und Besuchern im Vordergrund. Für eine zielgerichtete Stellensuche und die Vorstellung des Dienstleistungsangebotes der Bundesagentur für Arbeit, liegen Tablets auf Messeständen ab einer Größe von 15 Quadratmeter bereit. Bei nachfolgenden Veranstaltungen werden Messestände eingesetzt: MVM stellt auch die gesamte Ausstattung für JOBAKTIV-Veranstaltungen bereit, die die Agenturen für Arbeit regelmäßig bundesweit veranstalten. JOBAKTIV richtet sich an Menschen, die eine Arbeits- oder Ausbildungsstelle suchen oder sich beruflich verändern wollen. Die Besucherinnen und Besucher können mit Unternehmen in Kontakt treten, sich bei Vorträgen informieren und sich Tipps für ihre Bewerbungen geben lassen. Als weiteres besonderes Highlight werden auf einigen JOBAKTIV-Veranstaltungen kostenfreie Bewerbungsfotos erstellt. Die Berufsberatung findet für Schülerinnen und Schüler in den Berufsinformationszentren (BiZ) in den Agenturen für Arbeit und über das Digitale BiZ-MOBIL statt. Die Koffer mit Tablets und WLAN-Technik kommen an Schulen zum Einsatz, die in der Regel weit vom nächsten BiZ entfernt sind. Das MVM ist für die Technik des Digitalen BiZ-MOBIL verantwortlich. Für mehr Informationen zum Digitalen BiZ-MOBIL wenden Sie sich bitte an die Berufsberatung Ihrer Agentur für Arbeit. Sie können dem MVM-Stützpunkt in Ihrer Nähe oder der MVM-Zentrale per E-Mail schreiben."},"url":"https://www.arbeitsagentur.de/ueber-uns/messe-veranstaltungsmanagement","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:24.110153+00:00","lastSeen":"2026-03-15T17:26:24.110153+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/messe-veranstaltungsmanagement"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/messe-veranstaltungsmanagement","crawledAt":"2026-03-15T17:26:24.111133Z","crawlId":"organizations-seeded-1773595584","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"48e8c0315aa080bf14868584b367a216299de51f618fbb5f43cb9f8e380451c2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:24.111133+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('88764266-cb05-47dc-87d8-3bedc678b971', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/oekologische-nachhaltigkeit', 'active', NULL, '2026-03-15T17:26:24.607148+00:00', '{"id":"88764266-cb05-47dc-87d8-3bedc678b971","title":"Ökologische Nachhaltigkeit in der BA","summary":{"de":"Die BA will sich zu einer nachhaltig arbeitenden Organisation entwickeln. Erfahren Sie mehr zu unserem Umsetzungsprogramm."},"content":{"de":"Der Klimawandel stellt die Bundesagentur für Arbeit (BA) nicht nur vor strukturelle Herausforderungen am Arbeitsmarkt, sondern verpflichtet zu nachhaltigem, ressourcenbewussten Handeln. Als größte europäische Sozialbehörde wollen wir unserer gesamtgesellschaftlichen Verantwortung gerecht werden, eine Vorbildfunktion im öffentlichen Sektor einnehmen und einen Beitrag dazu leisten, unsere Umwelt-, Arbeits- und Lebensbedingungen nachhaltiger zu gestalten. Der Fokus dieses Umsetzungsprogramms liegt – angesichts gesetzlicher Vorgaben für eine klimaneutral organisierte Bundesverwaltung – auf der ökologischen Nachhaltigkeit. Die weiteren Dimensionen werden zu einem späteren Zeitpunkt betrachtet. Mit diesem Umsetzungsprogramm konkretisiert und verankert die Bundesagentur für Arbeit die wesentlichen Handlungsfelder zu einer klimaneutral organisierten Bundesagentur für Arbeit. Wo stehen wir, welche Ziele haben wir und mit welchen Maßnahmen wollen wir diese Ziele erreichen – eine erste Antwort auf diese Fragen bietet dieses Umsetzungsprogramm: Die BA ist seit dem 31. Juli 2022 Mitglied im United Nations Global Compact (UN GC), einer Kooperation von Unternehmen mit den Vereinten Nationen (UN), die die Vision einer inklusiven und nachhaltigen Wirtschaft verfolgt. Die Mitglieder des UN GC verpflichten sich, alle zwei Jahre einen Fortschrittsbericht (die sog. „Communication on Engagement“) zu schreiben. In diesem werden Aktivitäten, Maßnahmen und Ergebnisse zur ökologischen Nachhaltigkeit, Inklusion und Gleichstellung dargestellt."},"url":"https://www.arbeitsagentur.de/ueber-uns/oekologische-nachhaltigkeit","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:24.607148+00:00","lastSeen":"2026-03-15T17:26:24.607148+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/oekologische-nachhaltigkeit"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/oekologische-nachhaltigkeit","crawledAt":"2026-03-15T17:26:24.607148Z","crawlId":"organizations-seeded-1773595584","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"b5ffbb19fa8a72dd6dd56307bb199aaab3a104fbd11e52774fdd4760ad9f40d6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:24.607460+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ecfce3c8-a5dc-447b-b08e-67ef328167d5', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/regionaldirektionen', 'active', NULL, '2026-03-15T17:26:25.122375+00:00', '{"id":"ecfce3c8-a5dc-447b-b08e-67ef328167d5","title":"Regionaldirektionen","summary":{"de":"Die Regionaldirektionen sind für den Erfolg der regionalen Arbeitsmarktpolitik verantwortlich. Erfahren Sie hier mehr über ihre Aufgaben."},"content":{"de":"Sie setzen die Strategie der Bundesagentur für Arbeit um. Zur Abstimmung ihrer Aufgaben mit der Arbeitsmarkt-, Struktur- und Wirtschaftspolitik der Länder arbeiten sie eng mit den Landesregierungen zusammen. Die Regionaldirektionen führen die Agenturen für Arbeit. Sie haben spezielle Fragen? Dann wenden Sie sich mit Ihrem Anliegen direkt an die passenden Ansprechpartnerinnen und Ansprechpartner. Sie helfen Ihnen gerne weiter. Weitere Informationen zur Regionaldirektion Baden-Württemberg Weitere Informationen zur Regionaldirektion Bayern Friedrichstraße 34 10969 Berlin Fax: 030 555599-4999 Weitere Informationen zur Regionaldirektion Berlin-Brandenburg"},"url":"https://www.arbeitsagentur.de/ueber-uns/regionaldirektionen","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:25.122375+00:00","lastSeen":"2026-03-15T17:26:25.122375+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/regionaldirektionen"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/regionaldirektionen","crawledAt":"2026-03-15T17:26:25.122375Z","crawlId":"organizations-seeded-1773595585","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"10d2a452fb87614a6467dee4970365873fdcaebd62eddb6dc5ce56d50bc6fb5b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:25.122375+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('34b3e868-c6a2-4181-aa2d-a3977b165770', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/sabotageschutz', 'active', NULL, '2026-03-15T17:26:25.601021+00:00', '{"id":"34b3e868-c6a2-4181-aa2d-a3977b165770","title":"Sabotageschutz","summary":{"de":"Das Sicherheitsüberprüfungsgesetz: Lesen Sie, was das für Sie als Mitarbeiterin und Mitarbeiter oder externer Dienstleister der BA bedeutet."},"content":{"de":"Eine Beeinträchtigung von gewissen Bereichen im öffentlichen und im nichtöffentlichen Sektor kann Gefahren für das Leben oder die Gesundheit der Bevölkerung, für die öffentliche Sicherheit oder Ordnung nach sich ziehen. Eine besondere Gefahr kann hier von Personen ausgehen, die in diesen Einrichtungen eingesetzt sind. Der Gesetzgeber hat infolge der Anschläge vom 11. September 2001 durch Artikel 5 des Terrorismusbekämpfungsgesetzes den vorbeugenden personellen Sabotageschutz (vpS) in das Sicherheitsüberprüfungsgesetz (SÜG) aufgenommen. Dieser soll verhindern, dass in sicherheitsempfindlichen Stellen in lebens- oder verteidigungswichtigen Einrichtungen potentielle Saboteure tätig werden und als sogenannte Innentäter Schaden anrichten können. Zu den lebenswichtigen Einrichtungen unterfallen nach § 7 der Sicherheitsüberprüfungsfeststellungsverordnung (SÜFV) auch Bereiche der Informationsverarbeitung und der Informationstechnik bei der BA, die die Gewährung von unterhaltssichernden Leistungen sicherstellen. Personen, die in solch einem Bereich eingesetzt werden, haben sich nach den Bestimmungen des SÜG daher einer Sicherheitsüberprüfung zu unterziehen. Dies betrifft sowohl externe Dienstleister als auch Mitarbeiter der BA. Die externen Dienstleiter finden die erforderlichen Unterlagen nachfolgend: Staatenliste im Sinne von § 13 Abs. 1 Nr. 17 SÜG (Hinweis: externer Link zum Bundesministerium des Innern, für Bau und Heimat) Sicherheitserklärung für die erweiterte Sicherheitsüberprüfung"},"url":"https://www.arbeitsagentur.de/ueber-uns/sabotageschutz","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:25.601021+00:00","lastSeen":"2026-03-15T17:26:25.601021+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/sabotageschutz"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/sabotageschutz","crawledAt":"2026-03-15T17:26:25.601021Z","crawlId":"organizations-seeded-1773595585","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"ababa6e477720ab54f1b6264f3c147a69206a6337d0a16806d8d7378f746e0cd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:25.602026+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a1063957-e3a7-4282-b0bd-9d280767b807', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/selbstverwaltung-der-ba', 'active', NULL, '2026-03-15T17:26:26.121596+00:00', '{"id":"a1063957-e3a7-4282-b0bd-9d280767b807","title":"Verwaltung der BA","summary":{"de":"Die Bundesagentur für Arbeit ist eine Körperschaft des öffentlichen Rechts mit Selbstverwaltung. Lesen Sie hier, wie sich diese zusammensetzt."},"content":{"de":"Zentrales Organ der Selbstverwaltung ist der Verwaltungsrat. Er überwacht und berät den Vorstand bei der Aufgabenwahrnehmung und gibt wichtige Impulse zur weiteren Entwicklung der BA. Der Verwaltungsrat schlägt der Bundesregierung den Vorsitzenden oder die Vorsitzende und die übrigen Mitglieder des Vorstands der BA zur Ernennung durch den Bundespräsidenten vor. Neben den vom Verwaltungsrat geforderten Auskünften berichtet der Vorstand dem Verwaltungsrat regelmäßig zu allen wichtigen Themen und Entwicklungen. Weitere wesentliche Aufgaben des Verwaltungsrats sind: Festlegung der strategischen Ausrichtung und geschäftspolitischen Ziele Beschluss der Satzung der Bundesagentur für Arbeit Der Verwaltungsrat ist je zu einem Drittel mit Vertreterinnen und Vertretern aus den drei Gruppen der Arbeitnehmer, der Arbeitgeber und der öffentlichen Körperschaften besetzt. Je Gruppe werden sieben Mitglieder und fünf stellvertretende Mitglieder durch das Bundesministerium für Arbeit und Soziales berufen."},"url":"https://www.arbeitsagentur.de/ueber-uns/selbstverwaltung-der-ba","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:26.121596+00:00","lastSeen":"2026-03-15T17:26:26.121596+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/selbstverwaltung-der-ba"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/selbstverwaltung-der-ba","crawledAt":"2026-03-15T17:26:26.121596Z","crawlId":"organizations-seeded-1773595586","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"1f14aca8acf4d5b31f9d6492603de9c6f42b9d534042a2fb4fb4296e73446670"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:26.121596+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1a9c25c5-d310-4892-ac47-0b8d0c748b35', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen', 'active', NULL, '2026-03-15T17:26:26.623462+00:00', '{"id":"1a9c25c5-d310-4892-ac47-0b8d0c748b35","title":"Unsere Veröffentlichungen","summary":{"de":"Hier finden Sie alle Veröffentlichung der Bundesagentur für Arbeit (BA)."},"content":{"de":"Geschäftsberichte, Quartalsberichte, Auftragsberichte der Familienkasse sowie Haushaltspläne und Jahresrechnungen Informationen zu Ausschreibungen der Bundesagentur für Arbeit Unsere Statistiken, Analysen und Berichte geben Ihnen Aufschluss über den Arbeitsmarkt. Arbeits- und Fachkräfte für Deutschland – Gemeinsam Chancen nutzen Grundlagenpapier zur Weiterentwicklung der Beratungskonzeption der Bundesagentur für Arbeit (BeKo) Ganzheitliche Beratung und Betreuung im SGB II – Eine Handreichung für die Praxis"},"url":"https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:26.623462+00:00","lastSeen":"2026-03-15T17:26:26.623462+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen","crawledAt":"2026-03-15T17:26:26.623462Z","crawlId":"organizations-seeded-1773595586","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"aa8788556ea4bef2daf02d4c6322c744e507a68b264d26f00392645ad7de918f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:26.623462+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b21e5367-59d4-4584-b72d-e2ea25201ca1', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen/ausschreibungen', 'active', NULL, '2026-03-15T17:26:27.098148+00:00', '{"id":"b21e5367-59d4-4584-b72d-e2ea25201ca1","title":"Ausschreibungen","summary":{"de":"Informationen zu den Ausschreibungsverfahren der Bundesagentur für Arbeit"},"content":{"de":"Öffentliche Auftraggeber wie die Bundesagentur für Arbeit sind gesetzlich verpflichtet, Aufträge zur Deckung ihres Bedarfs an Gütern und Dienstleistungen sowie zur Durchführung ihrer Baumaßnahmen grundsätzlich im Rahmen von Ausschreibungen zu vergeben. Die Ausschreibungsverfahren für Arbeitsmarktdienstleistungen werden ausschließlich auf der Homepage des Bundesverwaltungsamtes unter www.bund.de und auf der e-Vergabe-Plattform des Beschaffungsamtes des Bundesministeriums des Innern www.evergabe-online.de veröffentlicht. Weiterführende Informationen finden Sie im Bereich Arbeitsmarktdienstleistungen. Hinweise zu Veröffentlichungen von aktuellen Ausschreibungen finden Sie im Bereich Liefer- und Dienstleistungen für Informationstechnik und Infrastruktur. Die Ausschreibungsverfahren werden ausschließlich auf der Homepage des Bundesverwaltungsamtes unter www.bund.de, und auf der e-Vergabe-Plattform des Beschaffungsamtes des Bundesministeriums des Innern www.evergabe-online.de veröffentlicht. Sofern es sich um Verfahren oberhalb des EU-Schwellenwertes handelt, werden diese zusätzlich im Supplement des Amtsblattes der EU (SIMAP) eingestellt. Die Ausschreibungsverfahren zu Bauleistungen und zum Liegenschaftsmanagement werden ausschließlich auf der Homepage des Bundesverwaltungsamtes unter www.bund.de und auf der e-Vergabe-Plattform des Beschaffungsamtes des Bundesministeriums des Innern www.evergabe-online.de veröffentlicht. Die Bundesagentur für Arbeit führt grundsätzlich elektronische Vergaben durch. Informationen zur Registrierung und zur Angebotserstellung finden Sie im Bereich e-Vergabe. Die Bundesagentur für Arbeit kann elektronische Rechnungen annehmen und verarbeiten. Informationen dazu finden Sie im Bereich E-Rechnung."},"url":"https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen/ausschreibungen","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:27.098148+00:00","lastSeen":"2026-03-15T17:26:27.098148+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen/ausschreibungen"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/veroeffentlichungen/ausschreibungen","crawledAt":"2026-03-15T17:26:27.098148Z","crawlId":"organizations-seeded-1773595587","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"885aef621906dbca30d37c0603a65995175e46d64ed78240e51ca0c6bb7b14db"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:27.100044+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b5abac1b-32cb-47cb-8f46-ea7354551177', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/vorstand-der-ba', 'active', NULL, '2026-03-15T17:26:27.629272+00:00', '{"id":"b5abac1b-32cb-47cb-8f46-ea7354551177","title":"Vorstand der Bundesagentur für Arbeit","summary":{"de":"Vorsitzende des Vorstandes der Bundesagentur für Arbeit"},"content":{"de":"1999: Abschluss Studium der Germanistik und Politikwissenschaften an der Friedrich-Wilhelms-Universität Bonn 2002 – 2005: Angestellte im Hauptstadtbüro der IG Metall 2007 – 2009: Arbeitsmarktpolitische Sprecherin und stellvertretende Vorsitzende der SPD-Bundestagsfraktion 2013 – 2017: Bundesministerin für Arbeit und Soziales 2017 – 2019: Vorsitzende der SPD-Bundestagsfraktion 2020 – 2022: Präsidentin der Bundesanstalt für Post und Telekommunikation"},"url":"https://www.arbeitsagentur.de/ueber-uns/vorstand-der-ba","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:27.629272+00:00","lastSeen":"2026-03-15T17:26:27.629272+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/vorstand-der-ba"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/vorstand-der-ba","crawledAt":"2026-03-15T17:26:27.630328Z","crawlId":"organizations-seeded-1773595587","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"1ba5706fa908b42344e198a8dbd6015cddcb3556d217b52f887183b886fa3c39"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:27.630328+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.