INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0357234f-a0ae-4bec-946d-09857d9f4b4d', 'organizations', 'https://www.arbeitsagentur.de/ueber-uns/zentrale', 'active', NULL, '2026-03-15T17:26:28.098747+00:00', '{"id":"0357234f-a0ae-4bec-946d-09857d9f4b4d","title":"Zentrale der Bundesagentur für Arbeit","summary":{"de":"Wie Sie die Zentrale der BA erreichen - lesen Sie die verschiedenen Anfahrtsbeschreibungen."},"content":{"de":"Mehrere Geschäftsbereiche setzen in der Zentrale die geschäftspolitischen Ziele der Selbstverwaltung und des Vorstands um. Sie steuern dabei unter anderem Arbeitsmarktprogramme, Finanzen und Personalentwicklung der BA. Wichtig: Wir bitten Sie, sich als Besucher im Eingangsbereich der Zentrale am Empfang anzumelden. Bringen Sie dazu bitte Ihren Personalausweis mit. Das Gebäude ist das höchste in der näheren Umgebung (17 Stockwerke) und daran einfach zu erkennen, wenn Sie sich mit dem Auto oder zu Fuß nähern. Von München auf der A9 bis zur Ausfahrt Nürnberg-Fischbach. Von Berlin auf der A9 bis zur Ausfahrt Nürnberg-Fischbach. Von Frankfurt/Würzburg kommend auf der A3 über das Autobahnkreuz Nürnberg zur A9 und bis zur Ausfahrt Nürnberg-Fischbach."},"url":"https://www.arbeitsagentur.de/ueber-uns/zentrale","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:28.098747+00:00","lastSeen":"2026-03-15T17:26:28.098747+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/ueber-uns/zentrale"},"provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/zentrale","crawledAt":"2026-03-15T17:26:28.098747Z","crawlId":"organizations-seeded-1773595588","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"4c48376c2d9d3c954b358ee68036139e0d07ccf22a79d3e79d53d5bb9a4c9dd3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:28.098747+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8ae7442c-0765-4c2b-b720-fc7e98a60fcd', 'organizations', 'https://www.arbeitsagentur.de/vor-ort/fba/startseite', 'active', NULL, '2026-03-15T17:26:28.606730+00:00', '{"id":"8ae7442c-0765-4c2b-b720-fc7e98a60fcd","title":"Willkommen bei Ihrer Führungsakademie der BA","summary":{"de":"Die Führungsakademie (FBA) steht für Bildung, Weiterbildung, Führungskräfte-Entwicklung und Management-Seminare in der Bundesagentur für Arbeit (BA)."},"content":{"de":"Die Führungsakademie ist der interne Bildungsdienstleister der Bundesagentur für Arbeit (BA). Wir haben unser Verständnis von Führung weiterentwickelt und kompakt formuliert. Alle relevanten Aspekte werden sukzessive an dieser Stelle zur Verfügung gestellt. Erfahren Sie mehr über die Tätigkeiten für die wir Verstärkung suchen. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/vor-ort/fba/startseite","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:28.606730+00:00","lastSeen":"2026-03-15T17:26:28.606730+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/vor-ort/fba/startseite"},"provenance":{"source":"https://www.arbeitsagentur.de/vor-ort/fba/startseite","crawledAt":"2026-03-15T17:26:28.607537Z","crawlId":"organizations-seeded-1773595588","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"9b07cf5abd939832bf21988f507d8483fac52e355c9a3fcac695c78b2d8fbb98"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:28.607537+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f467ca48-091c-4759-a26c-4906adbdac14', 'organizations', 'https://www.arbeitsagentur.de/vor-ort/it-systemhaus/startseite', 'active', NULL, '2026-03-15T17:26:29.134677+00:00', '{"id":"f467ca48-091c-4759-a26c-4906adbdac14","title":"Das IT-Systemhaus der Bundesagentur für Arbeit","summary":{"de":"Als interner Dienstleister der BA stellt das IT-Systemhaus umfassende IT- und Kommunikationslösungen für abgestimmte Fachanwendungen zur Verfügung. Mehr erfahren."},"content":{"de":"Als operativer IT-Dienstleister der BA betreiben wir am Hauptstandort Nürnberg/Fürth sowie an sieben weiteren Standorten deutschlandweit mit über 100 eigenen IT-Anwendungen, 180.000 vernetzten PC-Arbeitsplätzen und der dazugehörigen Infrastruktur eine der größten IT-Landschaften Deutschlands und entwickeln diese ständig weiter. Das IT-Systemhaus der Bundesagentur für Arbeit (BA) sucht berufserfahrene IT-Profis für vielfältige Einsatzbereiche. Wir bieten dir sichere, moderne und zukunftsorientierte Karrieremöglichkeiten mit sozialem Mehrwert. Entdecke unsere attraktiven Angebote zur IT-Ausbildung und dualem IT-Studium. Starte jetzt deine IT-Karriere bei einem der größten IT-Entwickler Deutschlands Berufsinfomesse 2026 - mit Angeboten für Ausbildung und dualen Studienplatz! Besuche uns auf LinkedIn und entdecke spannende Einblicke in unsere Projekte, alle News zu Veranstaltungen und die aktuellsten Stellenangebote. Das IT-Systemhaus ist Kununu Top-Company 2026! Damit gehören wir zu den Top 5 % aller Arbeitgeber auf kununu. Besuche unser Profil und lerne uns noch besser kennen."},"url":"https://www.arbeitsagentur.de/vor-ort/it-systemhaus/startseite","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:29.134677+00:00","lastSeen":"2026-03-15T17:26:29.134677+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/vor-ort/it-systemhaus/startseite"},"provenance":{"source":"https://www.arbeitsagentur.de/vor-ort/it-systemhaus/startseite","crawledAt":"2026-03-15T17:26:29.135679Z","crawlId":"organizations-seeded-1773595589","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"e9074ac652889e6e0eda063a320253d81a89b15863c0b7c156f1c169365eba6f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:29.135679+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2adebdb6-e687-4f06-a4c7-bf71d559e244', 'organizations', 'https://www.arbeitsagentur.de/vor-ort/zav/startseite', 'active', NULL, '2026-03-15T17:26:29.627368+00:00', '{"id":"2adebdb6-e687-4f06-a4c7-bf71d559e244","title":"Zentrale Auslands- und Fachvermittlung (ZAV)","summary":{"de":"Im Netzwerk der Bundesagentur für Arbeit (BA) ist die Zentrale Auslands- und Fachvermittlung (ZAV) vor allem für die Zuwanderung von Fachkräften aus dem Ausland und für die Vermittlung besonderer Berufsgruppen verantwortlich."},"content":{"de":"First point of contact for all questions about living and working in Germany We support skilled workers and trainees in our projects and programs on their way to Germany Find out more about all aspects of working and living in Germany in our online WebTutorials, or meet us in person at selected job fairs in Europe Wissenswertes zu Studium, Ausbildung, Praktika und Überbrückungsmöglichkeiten/Gap Year in Deutschland Überblick über unsere Projekte und Programme zur Anwerbung von Fachkräften und Auszubildenden im Ausland. Wir helfen Ihnen in ausgewählten Berufen und Branchen Ihr Personal im Ausland zu finden. Sie möchten ausländische Arbeits- oder Fachkräfte beschäftigen – wir unterstützen Sie dabei und beraten Sie bei der Zulassung zum deutschen Arbeitsmarkt"},"url":"https://www.arbeitsagentur.de/vor-ort/zav/startseite","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:26:29.627368+00:00","lastSeen":"2026-03-15T17:26:29.627368+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeitsvermittlung","Leistungsinformationen","Familienkasse"],"contactDetails":{"website":"https://www.arbeitsagentur.de/vor-ort/zav/startseite"},"provenance":{"source":"https://www.arbeitsagentur.de/vor-ort/zav/startseite","crawledAt":"2026-03-15T17:26:29.627368Z","crawlId":"organizations-seeded-1773595589","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"arbeitsagentur_de","providerName":"arbeitsagentur.de","providerLevel":"federal","checksum":"6637926726eb691e3c8806d984aa3d31afc851927f111abf742a554a6f44ab5f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:26:29.627368+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('44253a1b-b2db-4653-904a-504168fb3c98', 'organizations', 'https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Arbeiten-im-BMAS/arbeiten-im-bmas.html', 'active', NULL, '2026-03-15T17:28:21.592940+00:00', '{"id":"44253a1b-b2db-4653-904a-504168fb3c98","title":"Arbeiten im BMAS","summary":{"de":"Gestalten Sie mit uns einen modernen Sozialstaat und eine faire Arbeitswelt!"},"content":{"de":"Mit dem Video sucht das BMAS nach neuen Mitarbeitern. BMAS steht für Bundes-Ministerium für Arbeit und Soziales. Die Menschen im BMAS haben viele Aufgaben. Sie kümmern sich zum Beispiel um: Das BMAS freut sich über neue Mitarbeiter. Denn nur mit ihnen kann es seine Arbeit machen. Das Bundes-Ministerium für Arbeit und Soziales sucht neue Mitarbeiter. Denn: In der Politik. In der Gesellschaft. In unserem Zusammen·leben. Wir sichern Fach·kräfte. Wir sichern Löhne. Wir sichern Renten."},"url":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Arbeiten-im-BMAS/arbeiten-im-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:21.592940+00:00","lastSeen":"2026-03-15T17:28:21.592940+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Arbeiten-im-BMAS/arbeiten-im-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Arbeiten-im-BMAS/arbeiten-im-bmas.html","crawledAt":"2026-03-15T17:28:21.593941Z","crawlId":"organizations-seeded-1773595701","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"992a5b91dfb6d7c6124a9d0158c0c22572478ac39e9fc511dfea493ac7e482ec"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:21.593941+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c46a8a52-e912-4e4f-a58a-ec6a30e0cdc1', 'organizations', 'https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Ausbildung-im-BMAS/ausbildung-im-bmas.html', 'active', NULL, '2026-03-15T17:28:22.440493+00:00', '{"id":"c46a8a52-e912-4e4f-a58a-ec6a30e0cdc1","title":"Duale Berufsausbildung im Bundesministerium für Arbeit und Soziales","summary":{"de":"Wir stellen uns vor und unterstützen dich auf dem Weg von deiner Bewerbung bis zum Ausbildungsstart."},"content":{"de":"Du weißt, wie man Überblick und Ordnung bei der Arbeit behält. Abwechslungsreiche administrative Tätigkeiten machen dich zum Allrounder der Verwaltung. Du hast Freude am Einkauf, der Zubereitung und dem Anrichten von frischen Speisen. Dein handwerkliches Geschick macht dich zum/zur Held*in der Küche. Du weißt deine kommunikativen Fähigkeiten im Büro-Alltag richtig einzusetzen und sorgst durch dein Organisationstalent dafür, dass Projekte erfolgreich abgeschlossen werden. Mit deinem technischen Verständnis kannst du auch knifflige IT -Probleme lösen und anderen bei der Benutzung von IT-Systemen weiterhelfen. Das BMAS ist nicht nur ein attraktiver Arbeitgeber, sondern bildet auch junge Leute in verschiedenen Berufen aus. In diesem Video werden die Berufe kurz vorgestellt. Hier erhalten Sie Informationen über die einzelnen Ausbildungsberufe."},"url":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Ausbildung-im-BMAS/ausbildung-im-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:22.440493+00:00","lastSeen":"2026-03-15T17:28:22.440493+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Ausbildung-im-BMAS/ausbildung-im-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/Ausbildung-im-BMAS/ausbildung-im-bmas.html","crawledAt":"2026-03-15T17:28:22.440493Z","crawlId":"organizations-seeded-1773595702","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"dab5b13feddfb18281008f09921693c0b4936f71b180ec068ba626d2bd2dd427"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:22.440493+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('24d31a8a-cf59-4fbd-83ec-dd0f8de1c091', 'organizations', 'https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/arbeiten-und-ausbildung-im-bmas.html', 'active', NULL, '2026-03-15T17:28:24.180629+00:00', '{"id":"24d31a8a-cf59-4fbd-83ec-dd0f8de1c091","title":"Arbeiten und Ausbildung im BMAS","summary":{"de":"Karriere machen bei einem modernen Arbeitgeber – hier erfahren Sie mehr zu offenen Stellen, Ausbildungsmöglichkeiten sowie Praktika und Referendariaten im Bundesministerium für Arbeit und Soziales."},"content":{"de":"Karriere machen bei einem modernen Arbeitgeber – hier erfahren Sie mehr zu offenen Stellen, Ausbildungsmöglichkeiten sowie Praktika und Referendariaten im Bundesministerium für Arbeit und Soziales."},"url":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/arbeiten-und-ausbildung-im-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:24.180629+00:00","lastSeen":"2026-03-15T17:28:24.180629+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/arbeiten-und-ausbildung-im-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Arbeiten-und-Ausbildung-im-BMAS/arbeiten-und-ausbildung-im-bmas.html","crawledAt":"2026-03-15T17:28:24.180629Z","crawlId":"organizations-seeded-1773595704","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"ffdaaf3640acc6a32366d4a563dd58dafafae981d49946c8558bd84a8021c81d"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:28:24.180629+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c2049e2c-09b7-4241-bd96-0e21f6ffe897', 'organizations', 'https://www.bmas.de/DE/Ministerium/Beauftragte-der-Bundesregierung-beim-BMAS/beauftragte-der-bundesregierung-beim-bmas.html', 'active', NULL, '2026-03-15T17:28:24.976253+00:00', '{"id":"c2049e2c-09b7-4241-bd96-0e21f6ffe897","title":"Beauftragte der Bundesregierung beim BMAS","summary":{"de":"Die Beauftragten der Bundesregierung werden vom Bundeskanzler und die Bundes­beauftragten von den Bundesminister*innen ernannt und unterstützen in unabhängiger und beratender Form."},"content":{"de":"Natalie Pawlik ist in der 21. Wahlperiode die neue Beauftragte der Bundesregierung für Migration, Flüchtlinge und Integration sowie Beauftragte der Bundesregierung für Antirassismus. In der 21. Wahlperiode ist Jürgen Dusel der Beauftragte der Bundesregierung für die Belange von Menschen mit Behinderungen. Peter Weiß und Doris Barnett waren langjährige Abgeordnete des Deutschen Bundestages. Ihre Fachgebiete waren die Arbeits- und Sozialpolitik. Weiß und Barnett sind mit dem Auslaufen der 19. Wahlperiode des Bundestages aus ihren Mandaten ausgeschieden."},"url":"https://www.bmas.de/DE/Ministerium/Beauftragte-der-Bundesregierung-beim-BMAS/beauftragte-der-bundesregierung-beim-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:24.976253+00:00","lastSeen":"2026-03-15T17:28:24.976253+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Beauftragte-der-Bundesregierung-beim-BMAS/beauftragte-der-bundesregierung-beim-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Beauftragte-der-Bundesregierung-beim-BMAS/beauftragte-der-bundesregierung-beim-bmas.html","crawledAt":"2026-03-15T17:28:24.976253Z","crawlId":"organizations-seeded-1773595704","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"1d3f4641d52ce6295bfb78755fb03eb9884b0389a73134a70e816eaae84dbf77"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:24.976253+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6b9d6f5b-c945-4ba3-a558-60c2c0e4b4aa', 'organizations', 'https://www.bmas.de/DE/Ministerium/Ministerin-und-Hausleitung/ministerin-und-hausleitung.html', 'active', NULL, '2026-03-15T17:28:25.904907+00:00', '{"id":"6b9d6f5b-c945-4ba3-a558-60c2c0e4b4aa","title":"Die Leitung des Ministeriums","summary":{"de":"Hier erfahren Sie mehr zur Leitung des BMAS."},"content":{"de":"Am 6. Mai 2025 hat Bärbel Bas ihr Amt als Bundesministerin für Arbeit und Soziales angetreten. Staatssekretär und Amtschef im Bundesministerium für Arbeit und Soziales Beamtete Staatssekretärin im Bundesministerium für Arbeit und Soziales Parlamentarische Staatssekretärin bei der Bundesministerin für Arbeit und Soziales Sozialwahlbeauftragte – Peter Weiß und Doris Barnett Bärbel Bas, Bundesministerin für Arbeit und Soziales"},"url":"https://www.bmas.de/DE/Ministerium/Ministerin-und-Hausleitung/ministerin-und-hausleitung.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:25.904907+00:00","lastSeen":"2026-03-15T17:28:25.904907+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Ministerin-und-Hausleitung/ministerin-und-hausleitung.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Ministerin-und-Hausleitung/ministerin-und-hausleitung.html","crawledAt":"2026-03-15T17:28:25.904907Z","crawlId":"organizations-seeded-1773595705","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"5afa5c30e6201a00b768d2d03e7673f31f548e62fcb02e67a02c13ce19