INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e23fca17-e982-4d35-b7ef-e7d0b4bd9734', 'organizations', 'https://www.bmas.de/DE/Ministerium/Veranstaltungen/veranstaltungen.html', 'active', NULL, '2026-03-15T17:28:26.641803+00:00', '{"id":"e23fca17-e982-4d35-b7ef-e7d0b4bd9734","title":"Veranstaltungen des BMAS","summary":{"de":"Congress Center Leipzig, Seehausener Allee 1, 04356 Leipzig"},"content":{"de":"Dienstag, 24.03.26: 10:00 bis 18:00 Uhr Mittwoch, 25.03.26: 09:00 bis 18:00 Uhr Donnerstag, 26.03.26: 09:00 bis 14:30 Uhr Mercedes-Benz Niederlassung, Wittekindstraße 3, 44139 Dortmund Samstag, 18.04.26: 10:00 bis 16:00 Uhr Sonntag, 19.04.26: 11:00 bis 17:00 Uhr Rotes Rathaus und Open-Air-Stände, Rathausstr. 15, 10178 Berlin Siemens AG, Mosaik Halle, Berlin Siemensstadt, Rohrdamm 85, 13629 Berlin Der Vision Zero Fund zur Verbesserung des Arbeitsschutzes entlang globaler Lieferketten wurde 2015 unter Deutscher G7 -Präsidentschaft initiiert. Nun schaut das BMAS zusammen mit der Internationalen Arbeitsorganisation und weiteren Partnern des Fonds auf das Erreichte zurück. Bundesarbeitsministerin Bärbel Bas spricht um 13:40 Uhr als Opener."},"url":"https://www.bmas.de/DE/Ministerium/Veranstaltungen/veranstaltungen.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:26.641803+00:00","lastSeen":"2026-03-15T17:28:26.641803+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Veranstaltungen/veranstaltungen.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Veranstaltungen/veranstaltungen.html","crawledAt":"2026-03-15T17:28:26.642802Z","crawlId":"organizations-seeded-1773595706","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"d0b53699b2bbd7a88ed386c43423fe6cc3533c4b5da9d152beb9332f2ec960dc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:26.642802+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1cb52020-82a1-4cac-add3-9228329aaa92', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Aufgaben-des-BMAS/aufgaben-des-bmas.html', 'active', NULL, '2026-03-15T17:28:27.212090+00:00', '{"id":"1cb52020-82a1-4cac-add3-9228329aaa92","title":"Aufgaben des Bundesministeriums für Arbeit und Soziales","summary":{"de":"Arbeitssicherung und Bekämpfung der Arbeitslosigkeit sind Kernaufgaben des Bundesministeriums für Arbeit und Soziales."},"content":{"de":"Die Politik steht in der Pflicht, die sozialen Systeme funktionsfähig zu halten, für soziale Integration zu sorgen und die Rahmenbedingungen für mehr Beschäftigung zu schaffen. Diese Aufgaben berühren viele Politikfelder. Das Bundesministerium für Arbeit und Soziales strebt ressortübergreifende Lösungen an und stimmt seine Maßnahmen mit Ländern und Kommunen ab, sofern diese betroffen sind. Wesentlich für den Erfolg der Sozialpolitik ist auch die enge Kooperation des BMAS mit dem Ausschuss für Arbeit und Soziales. Er ist das zentrale Gremium der parlamentarischen Entscheidungsfindung. Die Grundlage zur Schaffung sozialversicherungspflichtiger Arbeitsplätze ist eine prosperierende Wirtschaft. Nur wenn die Wirtschaft gedeiht, ist der Sozialstaat handlungsfähig. Wir bekennen uns zu einer Wirtschaft, die für die Menschen da ist. Wirtschaft ist kein Selbstzweck. Wirtschafts-, Beschäftigungs- und Sozialpolitik sind ein Dreiklang - auch auf europäischer Ebene. Weil Wachstum mit sozialem Schutz einhergehen muss, ist und bleibt Sozialpolitik ein zentraler Baustein der Lissabon-Strategie. Wir wollen eine Stärkung des sozialen Dialogs und eine Beteiligung der Zivilgesellschaft. Europa ist eine große Chance, wenn wir richtig steuern. Zu unseren dringlichsten Aufgaben gehört die Stabilisierung der gesetzlichen Rentenversicherung. Für ihre Lösung gibt es zwei einander bedingende Voraussetzungen. Zum einen musste das Renteneintrittsalter sich der gestiegenen Lebenserwartung anpassen. Zum anderen müssen Ältere mehr Chancen auf dem Arbeitsmarkt erhalten. Darüber hinaus werden wir verstärkt die private Altersvorsorge fördern. Unsere Politik für behinderte und hilfebedürftige Menschen wird von einem breitem gesellschaftlichen Konsens getragen. Wir haben Teilhabe- und Verwirklichungschancen eröffnet, Barrieren und Benachteiligungen abgebaut und soziale Ausgrenzung reduziert. Diesen Weg zu mehr sozialer Integration werden wir konsequent fortsetzen."},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Aufgaben-des-BMAS/aufgaben-des-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:27.212090+00:00","lastSeen":"2026-03-15T17:28:27.212090+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Aufgaben-des-BMAS/aufgaben-des-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Aufgaben-des-BMAS/aufgaben-des-bmas.html","crawledAt":"2026-03-15T17:28:27.212090Z","crawlId":"organizations-seeded-1773595707","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f27b0b93e637c4b66f0a70f2c11f7ae2658077a7e413ebb3246102510dc07b48"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:27.212090+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('12058e02-dcd0-4b02-89b2-c604f5b1d7cd', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschaeftsbereich-BMAS/geschaeftsbereich-bmas.html', 'active', NULL, '2026-03-15T17:28:27.853469+00:00', '{"id":"12058e02-dcd0-4b02-89b2-c604f5b1d7cd","title":"Geschäftsbereich des BMAS","summary":{"de":"Zum unmittelbaren Geschäftsbereich des Bundesministeriums für Arbeit und Soziales gehören:"},"content":{"de":"die Bundesanstalt für Arbeitsschutz und Arbeitsmedizin Ferner gehören zum Geschäftsbereich des BMAS folgende unterliegenden Einrichtungen: die Gewerblichen Berufsgenossenschaften nach Anlage 1 SGB VII die Deutsche Rentenversicherung Knappschaft-Bahn-See die Sozialversicherung für Landwirtschaft, Forsten und Gartenbau die Zusatzversorgungskasse für Arbeitnehmer in der Land- und Forstwirtschaft"},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschaeftsbereich-BMAS/geschaeftsbereich-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:27.853469+00:00","lastSeen":"2026-03-15T17:28:27.853469+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschaeftsbereich-BMAS/geschaeftsbereich-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschaeftsbereich-BMAS/geschaeftsbereich-bmas.html","crawledAt":"2026-03-15T17:28:27.853469Z","crawlId":"organizations-seeded-1773595707","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":