INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0d02f5d8-b557-42a5-b40a-2d340e131853', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Bundesminister-seit-1949/ehemalige-bundesminister.html', 'active', NULL, '2026-03-15T17:28:28.775721+00:00', '{"id":"0d02f5d8-b557-42a5-b40a-2d340e131853","title":"Ehemalige Bundesminister für Arbeit und Soziales seit 1949","summary":{"de":"Geschäftsführende Leitung des Bundesministeriums für Arbeit und Soziales, SPD"},"content":{"de":"Bundesministerin für Gesundheit und Soziale Sicherung, SPD Minister für Arbeit und Soziales der DDR, CDU (DDR) Ministerin für Arbeit und Soziales der DDR, SPD (DDR)"},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Bundesminister-seit-1949/ehemalige-bundesminister.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:28.775721+00:00","lastSeen":"2026-03-15T17:28:28.775721+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Bundesminister-seit-1949/ehemalige-bundesminister.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Bundesminister-seit-1949/ehemalige-bundesminister.html","crawledAt":"2026-03-15T17:28:28.775721Z","crawlId":"organizations-seeded-1773595708","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"575ce5466cd78b6bed918003b8eec6161027bac39e4c2a7a3469ffc90321fb2c"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:28:28.775721+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5546a0fa-ee3c-48db-9dae-2f1ad0bd4023', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Geschichte-des-Dienstsitzes-in-Berlin/geschichte-des-dienstsitzes-in-berlin.html', 'active', NULL, '2026-03-15T17:28:29.316939+00:00', '{"id":"5546a0fa-ee3c-48db-9dae-2f1ad0bd4023","title":"Die Geschichte des Dienstsitzes des BMAS in Berlin","summary":{"de":"Einzug des Bundesministeriums für Arbeit und Soziales"},"content":{"de":"In der Wilhelmstraße, heute Sitz des Bundesministeriums für Arbeit und Soziales, hatten seit Anfang des 19. Jahrhunderts die wichtigsten Ministerien Preußens und - seit 1871 - des Deutschen Reiches ihren Sitz. In unmittelbarer Nähe siedelten sich die Botschaften der europäischen Großmächte an. Das Gebäude, das heute die Nummer 49 trägt, war ursprünglich ein barockes Adelspalais. 1826 ging es in den Besitz des Hohenzollern-Prinzen Karl über. Schinkel und Stüler bauten es im klassizistischen Stil umfassend um. Zwischen 1918 und 1933 diente das Gebäude der Presseabteilung der Reichsregierung als Sitz. Aus ihr formten die Nationalsozialisten das Ministerium für Volksaufklärung und Propaganda. Das zog Erweiterungen des Gebäudes nach sich, die zum Teil bis heute Bestand haben. Allerdings wurde die gesamte Anlage durch die Bombardierung Berlins 1945 erheblich beschädigt. Nach Instandsetzung wenig zerstörter Gebäudeteile bezog im Jahr 1947 der Zentralrat der Nationalen Front das ehemalige Propagandaministerium. Mit Gründung der DDR am 7. Oktober 1949 wurde es Sitz von Wilhelm Pieck. Das Arbeitszimmer des ersten und einzigen Präsidenten der DDR ist bis heute mit seiner ursprünglichen Einrichtung erhalten. 1996 wies das Bundeskabinett das Gebäude Wilhelmstraße 49 dem Bundesministerium für Arbeit und Sozialordnung zu. Seit Abschluss der Sanierungsarbeiten durch den Architekten Prof. Josef Paul Kleihues ist die Wilhemstraße 49 - mit Unterbrechung von 2002 bis 2005 - Dienstsitz des Bundesministeriums für Arbeit und Soziales. Wil­helm­stra­ße 49 - Ein Ber­li­ner Haus mit Ge­schich­te"},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Geschichte-des-Dienstsitzes-in-Berlin/geschichte-des-dienstsitzes-in-berlin.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:29.316939+00:00","lastSeen":"2026-03-15T17:28:29.316939+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Geschichte-des-Dienstsitzes-in-Berlin/geschichte-des-dienstsitzes-in-berlin.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Geschichte-des-Dienstsitzes-in-Berlin/geschichte-des-dienstsitzes-in-berlin.html","crawledAt":"2026-03-15T17:28:29.317939Z","crawlId":"organizations-seeded-1773595709","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"d74671a984359846a6395f5ae0aeb94ae316dd022c6be047c1e129a040618ed7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:29.317939+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('11864067-9a52-4acb-a519-1fe198eae5da', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Historikerkommission/historikerkommission.html', 'active', NULL, '2026-03-15T17:28:29.900108+00:00', '{"id":"11864067-9a52-4acb-a519-1fe198eae5da","title":"Das Reicharbeitsministerium während der NS-Zeit","summary":{"de":"Ein großangelegtes Forschungsprojekt des BMAS und einer unabhängigen Forschungskommission aus dem In- und Ausland hat sich ab 2013 mit der Aufarbeitung der Geschichte des Reichsarbeitsministeriums während der Zeit des Nationalsozialismus beschäftigt."},"content":{"de":"Mit dem Ziel, bestehende Lücken zu schließen und die Aufarbeitung voranzutreiben, wurden eigenständige Forschungsprojekte entwickelt. Auch der Frage, inwiefern Arbeits- und Sozialpolitik als Instrument langfristiger europäischer Herrschaftssicherung diente, gingen die Historiker*innen nach. Am 27. Juni 2017 wurde in Berlin ein Syntheseband mit den Ergebnissen des Forschungsprojektes vorgestellt. Fünf Monografien über die Geschichte des Reicharbeitsministeriums im Nationalsozialismus folgten und komplettierten die Reihe. Sehen Sie hier die interaktive Reportage der unabhängigen Forschungsgruppe. Die Inhalte sind für einige Nutzer*innengruppen nicht barrierefrei. Auf Grundlage der Arbeiten der unabhängigen Historikerkommission wurde 2019 eine Wanderausstellung mit dem Titel „Das Reichsarbeitsministerium 1933-1945. Beamte im Dienst des Nationalsozialismus“ entwickelt. Die Ausstellung wurde von der Stiftung Topographie des Terrors kuratiert und mit einer finanziellen Zuwendung des BMAS unterstützt. Sie bietet interessierten Stellen auch heute noch Gelegenheit, in ihren Bezügen auf die Thematik hinzuweisen."},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Historikerkommission/historikerkommission.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:29.900108+00:00","lastSeen":"2026-03-15T17:28:29.900108+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Historikerkommission/historikerkommission.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/Historikerkommission/historikerkommission.html","crawledAt":"2026-03-15T17:28:29.900108Z","crawlId":"organizations-seeded-1773595709","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"33ed48ad43eb44b8dc479beb1ab6683e3e9dc75bf14d4dc3463ac000d470bf56"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:29.900108+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('da27a945-1a21-4fe9-b822-e54ad98e6bec', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/geschichte-des-bmas.html', 'active', NULL, '2026-03-15T17:28:30.509652+00:00', '{"id":"da27a945-1a21-4fe9-b822-e54ad98e6bec","title":"BMAS - Geschichte des BMAS","summary":{"de":"Diese Broschüre gibt einen Überblick über die wechselhafte Geschichte des Berliner Dienstsitzes des Bundesministeriums für Arbeit und Soziales."},"content":{"de":"Diese Broschüre gibt einen Überblick über die wechselhafte Geschichte des Berliner Dienstsitzes des Bundesministeriums für Arbeit und Soziales."},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/geschichte-des-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:30.509652+00:00","lastSeen":"2026-03-15T17:28:30.509652+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/geschichte-des-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Geschichte-des-BMAS/geschichte-des-bmas.html","crawledAt":"2026-03-15T17:28:30.509652Z","crawlId":"organizations-seeded-1773595710","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"906d555347cec134d86319398adc7fb907dca62ebf16d4658723e480d315f06d"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:28:30.509652+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6e7ad952-53f9-4e11-a14c-bddcf7d34375', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Info-Stand/info-stand.html', 'active', NULL, '2026-03-15T17:28:32.025298+00:00', '{"id":"6e7ad952-53f9-4e11-a14c-bddcf7d34375","title":"Informationsstand des BMAS","summary":{"de":"Unser Info-Stand kommt auf Messen und Netzwerk-Veranstaltungen zum Einsatz. Kurz und barrierefrei informiert er über die Themen des Haues."},"content":{"de":"Wir gestalten die Arbeitswelt mit, ent­wickeln die Instrumente des Sozial­staates weiter und treten für mehr soziale Gerechtig­keit und Teilhabe ein. So sichern wir den gesellschaftlichen Zusammen­halt und gewährleisten soziale Sicherheit für alle. Über QR -Codes auf den Charts des Info-Standes können die weiter unten stehenden Themen aufgerufen werden. Ein Ministerium ist ein Teil von der deutschen Regierung. Wir gestalten Regeln für die Menschen in Deutschland. Das sind vor allem die Regeln für die Arbeits-Welt. Und die Regeln für den Sozial-Staat. Ein Mensch kommt in Not. Er verliert vielleicht seine Arbeit. Dann bekommt er Hilfe. Regeln bestimmen, wie das abläuft. Dann fühlen sich alle sicher. Dann leben Menschen friedlich zusammen. Dann leben Menschen gerne in Deutschland."},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Info-Stand/info-stand.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:32.025298+00:00","lastSeen":"2026-03-15T17:28:32.025298+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Info-Stand/info-stand.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Info-Stand/info-stand.html","crawledAt":"2026-03-15T17:28:32.025298Z","crawlId":"organizations-seeded-1773595712","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"912cb3c87b51b1a5bbe40dab6685a7e1707a0aedc38667ae86e7b00262beec67"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:32.025298+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('956d7c34-7fa3-4761-ae27-f424eb1db9ef', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Informationsfreiheit-Akteneinsicht/informationsfreiheit-akteneinsicht.html', 'active', NULL, '2026-03-15T17:28:32.670040+00:00', '{"id":"956d7c34-7fa3-4761-ae27-f424eb1db9ef","title":"Informationsfreiheit und Akteneinsicht","summary":{"de":"Mit Inkrafttreten des Informationsfreiheitsgesetzes (IFG) zum 1. Januar 2006 hat jeder nach Maßgabe des IFG gegenüber den Behörden des Bundes einen Anspruch auf Zugang zu amtlichen Informationen."},"content":{"de":"Mit Inkrafttreten des Informationsfreiheitsgesetzes (IFG) zum 1. Januar 2006 hat jeder nach Maßgabe des IFG gegenüber den Behörden des Bundes einen Anspruch auf Zugang zu amtlichen Informationen. Der Anspruch auf Zugang zu amtlichen Informationen hat jedoch auch Grenzen. So besteht der Anspruch auf Informationszugang nicht, wenn der Schutz von beson­deren öffentlichen Belangen entgegensteht. Gleiches gilt für den Schutz behördlicher Entschei­dungsprozesse, personenbezogener Daten und des geistigen Eigentums und von Betriebs- und Geschäftsgeheimnissen. Wegen des manchmal erheblichen Verwaltungsaufwandes kann die Behörde nach der Informationsgebührenverordnung dem Antragsteller für den Zugang zu amt­lichen Informationen Kosten in Rechnung stellen. Weitergehende Informationen entnehmen Sie bitte den folgenden Infos und Materialien. Anträge auf Zugang zu amtlichen Informationen aus dem Bun­desministerium für Arbeit und Soziales richten Sie bitte unter dem Stichwort \"Informationsfrei­heitsgesetz\" an das Bundesministerium für Arbeit und Soziales, Wilhelmstraße 49, 10117 Ber­lin, oder per E-Mail an poststelle@bmas.bund.de. Bitte benennen Sie im Betreff Ihres Antrages genau das Thema, zu dem Sie Informationen wünschen. In­for­ma­ti­ons­ge­büh­ren­ver­ord­nung [PDF, 23KB] An­wen­dungs­hin­wei­se des BMI zum In­for­ma­ti­ons­frei­heits­ge­setz [PDF, 536KB]"},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Informationsfreiheit-Akteneinsicht/informationsfreiheit-akteneinsicht.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:32.670040+00:00","lastSeen":"2026-03-15T17:28:32.670040+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Informationsfreiheit-Akteneinsicht/informationsfreiheit-akteneinsicht.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/Informationsfreiheit-Akteneinsicht/informationsfreiheit-akteneinsicht.html","crawledAt":"2026-03-15T17:28:32.671047Z","crawlId":"organizations-seeded-1773595712","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"21fb902273d4f1511ee7375d42cf1b5a7c0aa641728370e03a26e276ae869b07"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:32.671047+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b9870cd5-0288-4b17-bc77-85348ed78f63', 'organizations', 'https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/wir-stellen-uns-vor.html', 'active', NULL, '2026-03-15T17:28:33.340058+00:00', '{"id":"b9870cd5-0288-4b17-bc77-85348ed78f63","title":"Wir stellen uns vor","summary":{"de":"Auf dieser Seite finden Sie wichtige Informationen zu unseren Aufgaben, Geschäfts­bereichen und weiteren Themen."},"content":{"de":"Aufgaben, Geschäftsbereiche und weitere Infos über das Bundesministerium für Arbeit und Soziales Die Aufgaben und Themenschwerpunkte des BMAS sind vielfältig. Auf den folgenden Seiten informieren wir Sie über unsere Aufgabengebiete sowie Geschäftsbereiche und Gremien, die dem Ministerium zugeordnet sind. Die Aufgaben und Themen des BMAS sind vielfältig. Deswegen haben wir jedem Thema einen eigenen Flyer gewidmet. Klicken Sie sich durch und lernen Sie uns und unsere Aufgaben kennen. Die Arbeit des BMAS ist geprägt von dem Bild einer solidarischen Gesellschaft, in der sich alle nach ihren Fähigkeiten entfalten können und Verantwortung übernehmen."},"url":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/wir-stellen-uns-vor.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:33.340058+00:00","lastSeen":"2026-03-15T17:28:33.340058+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/wir-stellen-uns-vor.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Wir-stellen-uns-vor/wir-stellen-uns-vor.html","crawledAt":"2026-03-15T17:28:33.341190Z","crawlId":"organizations-seeded-1773595713","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f93553986f3a3befa8afc39e6f1aeeefb26d520cd4da3292f7296482491be79a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:33.341190+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dc7a0379-76b5-4a6f-9a0b-46a854ca3158', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Besucherdienst/besucherdienst.html', 'active', NULL, '2026-03-15T17:28:34.246558+00:00', '{"id":"dc7a0379-76b5-4a6f-9a0b-46a854ca3158","title":"Besucherdienst","summary":{"de":"SIe möchten möchten vor Ort mehr über unsere Geschichte und Arbeitsweise erfahren? Hier finden Sie alle Informationen zum Besuch des BMAS."},"content":{"de":"Besuchen Sie uns im Bundesministerium für Arbeit und Soziales Den Haupteingang des Bundesministeriums für Arbeit und Soziales können Sie auf diesem Bild an den zwei Fahnen auf dem Dach erkennen. Zum Komplex des Hauptgebäudes gehören u. a. jene Gebäude, die die zwei Innenhöfe bilden. Herzlich willkommen beim Besucherdienst des Bundesministeriums für Arbeit und Soziales! Sie möchten die Arbeit des BMAS kennenlernen? Dann sind Sie bei uns genau richtig. Direkt vor Ort empfangen wir pro Jahr rund 300 Gruppen mit politisch interessierten Bürgerinnen und Bürgern. Darunter sind zum Beispiel Gruppen aus den Wahlkreisen der Abgeordneten des Deutschen Bundestages, Schulklassen, Studierende und Vereine. Wir informieren über den Aufbau, die Aufgaben und die aktuellen Themen des BMAS sowie über die vielfältige Geschichte des Hauses. Für Schülerinnen und Schüler gibt es ein besonderes Angebot: das Planspiel \"Rente und Generationengerechtigkeit\". Bei Interesse zu anderen Themen bereiten wir für Schulklassen auch gern ein individuelles Programm vor. Für die Anmeldung senden Sie einfach eine E-Mail an: besucherdienst@bmas.bund.de. Die Gruppe sollte mindestens 15 bis maximal 50 Personen umfassen."},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Besucherdienst/besucherdienst.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:34.246558+00:00","lastSeen":"2026-03-15T17:28:34.246558+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Besucherdienst/besucherdienst.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Besucherdienst/besucherdienst.html","crawledAt":"2026-03-15T17:28:34.246558Z","crawlId":"organizations-seeded-1773595714","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"612d8640302ff0116725e5f0d058f355b256605ec8abc097f78d832d0e3dbf85"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:34.246558+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('553c780f-6d0c-4626-bc0a-29c40eff66b5', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Haupteingang/haupteingang.html', 'active', NULL, '2026-03-15T17:28:35.311009+00:00', '{"id":"553c780f-6d0c-4626-bc0a-29c40eff66b5","title":"Haupteingang","summary":{"de":"Eindrücke und Geschichte des Haupteingangs vom BMAS."},"content":{"de":"Begleiten Sie uns und betreten Sie das Ministerium durch den ältesten Gebäudeteil mit der offenen “Drei-Bogen-Fassade” an der Wilhelmstraße 49. Architektonische, bauliche und künstlerische Highlights finden sich in allen Gebäudeteilen dieses historischen Ensembles, hier atmet jeder Meter Geschichte – eine Zeitreise durch drei Jahrhunderte! Den historischen Steinsaal aus den 1930er Jahren erreicht man über das Haupttreppenhaus hinauf und über ein paar Treppenstufen hinab. Vis-à-vis zieht das zwischen zwei Pfeilern platzierte, große Tafelbild des 1953 geborenen Malers Peter Chevalier die Blicke auf sich. Seine „Sternenruhe“ ist eine abstrakte Komposition aus freien Formen und rein malerisch behandelten Flächen und setzt einen starken Akzent zum eher schlichten, aber großen Architektur-Raum. Haben Sie etwas in diesem historischen und dennoch modernen Besprechungsraum vermisst? Eine Videokonferenzanlage gibt es hier im Gegensatz zu allen anderen Besprechungsräumen nicht. Mit der Gründung des Kaiserreichs wird Berlin zur Hauptstadt. Im Jahr 1883 erhält das Ordenspalais einen Anbau: das Hofbeamtenhaus. Es dient als Wohn- und Verwaltungsgebäude. In den 1930er Jahren wird es Teil des Reichsministeriums für Volksaufklärung und Propaganda. Im Zuge dessen erhält das Gebäude eine Vorhalle mit Arkaden im Erdgeschoss, welche bis heute das Erscheinungsbild prägen. Die linksseitigen Arkaden und Fenster dienten dabei als Übergänge zum Ordenspalais. Nach Abriss des Ordenspalais wurden sie jedoch zugemauert."},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Haupteingang/haupteingang.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:35.311009+00:00","lastSeen":"2026-03-15T17:28:35.311009+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Haupteingang/haupteingang.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Haupteingang/haupteingang.html","crawledAt":"2026-03-15T17:28:35.311009Z","crawlId":"organizations-seeded-1773595715","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"76912d6e5b3a8a72cdbaf4b1d1c19ba17afea1e77249e5d88a8e5fe9b194f0b2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:35.311009+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3481f423-3a61-49ba-a232-0030057792ce', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Hauptgebaeude/hauptgebaeude.html', 'active', NULL, '2026-03-15T17:28:36.614656+00:00', '{"id":"3481f423-3a61-49ba-a232-0030057792ce","title":"Hauptgebäude","summary":{"de":"Historie und Eindrücke vom Hauptgebäude des BMAS."},"content":{"de":"Historische Besprechungsräume, lange Flure und immer wieder das Gefühl, in eine andere Zeit einzutauchen: Das ist unser Hauptgebäude. Das Hauptgebäude wird in der Zeit des Nationalsozialismus errichtet und ist der größte Gebäudeteil des heutigen BMAS. In der Zeit der DDR dient es vor allem als Sitz des Nationalrates der Nationalen Front. Besonders das ehemalige Büro von Staatspräsident Wilhelm Pieck und unser Besprechungsraum mit besonderer Beleuchtung nehmen uns mit auf eine kleine Zeitreise. Schauen Sie selbst weiter unten beim \"Rundum-Blick in besondere Räume\". Genau hier war einst das Reichsministerium für Volksaufklärung und Propaganda. Die graue triste Fassade wurde bewusst beibehalten, um daran zu erinnern. Wo vor ein paar Jahren noch streng geschnittene Buchsbäume die Beete zierten, finden sich nun bienenfreundliche Gewächse. Wir Mitarbeitenden können während der Mittagspause im Innenhof bescheinigen: Den Bienen gefällt''s! Mit Gründung der DDR am 7. Oktober 1949 wird das Gebäude Sitz der DDR-Verwaltung. Das Arbeitszimmer des ersten und einzigen Präsidenten der DDR, Wilhelm Pieck, ist bis heute mit seiner ursprünglichen Einrichtung erhalten. Traditionell hat ein Abteilungsleitender dieses Büro inne und ist somit die einzige Person im BMAS ohne höhenverstellbaren Tisch. Das besondere Ambiente und die weichen Stühle lassen das aber verkraften. Der historische DDR-Besprechungsraum oder wie wir ihn liebevoll nennen: Unser kleiner Lampenladen. Schauen Sie in der 360°-Aufnahme mal nach oben zur Zimmerdecke."},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Hauptgebaeude/hauptgebaeude.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:36.614656+00:00","lastSeen":"2026-03-15T17:28:36.614656+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Hauptgebaeude/hauptgebaeude.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Hauptgebaeude/hauptgebaeude.html","crawledAt":"2026-03-15T17:28:36.614656Z","crawlId":"organizations-seeded-1773595716","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"07315c4568fa3af2bdf0bc55f5025837813224ffa7381b3e47a0c5c46990bf03"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:28:36.614656+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e2e0a9d1-2738-4b90-94f9-55b56d22ac65', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Kleisthaus/kleisthaus.html', 'active', NULL, '2026-03-15T17:28:37.427245+00:00', '{"id":"e2e0a9d1-2738-4b90-94f9-55b56d22ac65","title":"Kleisthaus","summary":{"de":"Historie und Eindrücke vom Gebäudeteil \"Kleisthaus\" des BMAS."},"content":{"de":"Dieses schöne Haus wurde als Bankhaus erbaut und 1913 bezogen. Sie sind herzlich eingeladen, seine Architektur und Ausstattung näher zu betrachten. Heute haben die Beauftragten der Bundesregierung für die Belange von Menschen mit Behinderungen und deren Stab ihre Büroräume im Kleisthaus. Auch finden in diesem Gebäude öffentliche Veranstaltungen der Behindertenbeauftragten statt, so dass Sie auch persönlich einen Eindruck vor Ort gewinnen können. Bei der Sanierung wurde darauf Wert gelegt, dass auch ein altes Haus neben der angenehmen Atmosphäre, eine moderne Arbeitswelt beherbergt. So wurde der Hof des Hauses überdacht und steht nun als lichterfüllter Veranstaltungsort zur Verfügung. Der Zugang und die Veranstaltungen selbst sind barrierefrei. Das Kleisthaus trägt den Namen des Dichters Heinrich von Kleist. Dieser lebte von 1808 bis 1811 dort in einem Vorgängerbau. Nach dem Abriss des alten Gebäudes baut Carl von der Heydt hier 1912/1913 ein Bankhaus. Der Architekt Bodo Ebhardt, der zu dieser Zeit einer der bekanntesten Architekten ist, übernimmt die Planung. Die Familie von der Heydt nutzt das Gebäude bis 1936 für ihre Bankgeschäfte. Danach wird es Sitz der Deutschen Landesbankenzentrale und ab 1942 Teil des Reichsministeriums für Volksaufklärung und Propaganda. Nach dem Krieg dient es als Unterkunft für Geflüchtete. Zu DDR-Zeiten zieht das Rote Kreuz ein. Von 1997 bis 2001 wird es vom Architekten Josef Paul Kleihues umfassend saniert und teils neugestaltet. Heute ist es Sitz der Beauftragten der Bundesregierung für die Belange von Menschen mit Behinderungen. Im Foyer finden zahlreiche barrierefreie Veranstaltungen statt, wie Ausstellungen und Konzerte. Wir stellen uns vor: Aufgaben, Geschäftsbereiche und weitere Infos aus dem BMAS"},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Kleisthaus/kleisthaus.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:37.427245+00:00","lastSeen":"2026-03-15T17:28:37.427245+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Kleisthaus/kleisthaus.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Kleisthaus/kleisthaus.html","crawledAt":"2026-03-15T17:28:37.427245Z","crawlId":"organizations-seeded-1773595717","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"adae8db731c7a2fe799636516430bda08eddcfaad7a6d299602c6a319b91ac99"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:37.427245+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('29bb24db-d21a-4534-8e6c-9ccc02991ea0', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Regine-Hildebrandt-Haus/regine-hildebrandt-haus.html', 'active', NULL, '2026-03-15T17:28:38.722251+00:00', '{"id":"29bb24db-d21a-4534-8e6c-9ccc02991ea0","title":"Regine-Hildebrandt-Haus","summary":{"de":"Der Gebäudeteil \"Regine-Hildebrandt-Haus\" des BMAS: Geschichte und Gegenwart, Bilder und Videos."},"content":{"de":"Der neueste Teil des Bundesministeriums wurde zu Ehren der beliebten Politikerin benannt. 2020 zogen die ersten Mitarbeitenden ein. Das Gebäude beherbergt moderne Büros sowie eine Kindertagesstätte. Erbaut wird es ab 2017 nach Entwürfen der \"K9 Architekten\". Dort, wo heute das Regine-Hildebrandt-Haus steht, beginnt die Geschichte des Standortes des Bundesministeriums für Arbeit und Soziales. Im 18. Jahrhundert lässt Friedrich Wilhelm I. ein adliges Wohnviertel bauen. Es entsteht rund um die heutige Wilhelmstraße – damals noch der Stadtrand von Berlin. Im Jahr 1737 beginnt Karl Ludwig Truchsess Graf zu Waldenburg mit dem Bau eines Palais. Nach seinem Tod im ersten Baujahr verpflichtet der König den Johanniterorden, den Bau zu vollenden. Der Orden nutzt das Palais als repräsentativen Sitz. So entsteht der Name \"Ordenspalais\". Im 19. Jahrhundert wird das Viertel um die Wilhelmstraße zum Regierungszentrum. Der preußische Staat übernimmt viele Gebäude für Ministerien und Botschaften. Auch nach der Reichsgründung 1871 haben viele Reichsministerien hier ihren Sitz. Nach dem Ersten Weltkrieg zieht das Reichspresseamt in das ehemalige Ordenspalais. 1933 übernimmt Joseph Goebbels das Reichspresseamt und zieht in das Palais am Wilhelmplatz. Er errichtet dort das Reichsministerium für Volksaufklärung und Propaganda. In den letzten Wochen des Zweiten Weltkriegs wird das Ordenspalais schwer beschädigt und auf sowjetischen Befehl hin abgerissen."},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Regine-Hildebrandt-Haus/regine-hildebrandt-haus.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:38.722251+00:00","lastSeen":"2026-03-15T17:28:38.722251+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Regine-Hildebrandt-Haus/regine-hildebrandt-haus.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Regine-Hildebrandt-Haus/regine-hildebrandt-haus.html","crawledAt":"2026-03-15T17:28:38.722251Z","crawlId":"organizations-seeded-1773595718","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"5072bbcd9da65942778891085cadd5d9e25785519384923e8458ed7e8c47a5b0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:38.722251+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3da2bfd7-e005-408a-a3c7-b440ece855a4', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Ritterschaftsbank/ritterschaftsbank.html', 'active', NULL, '2026-03-15T17:28:39.679143+00:00', '{"id":"3da2bfd7-e005-408a-a3c7-b440ece855a4","title":"Ritterschaftsbank","summary":{"de":"Geschichte und Bilder der Ritterschaftsbank, einem Gebäudeteil des BMAS."},"content":{"de":"Ein ehemaliges Bankgebäude mit einem Treppenhaus voller Eleganz. Hier steigen wir freiwillig Treppen. Funfact: In den oberen Geschossen wurde das Treppengeländer immer niedriger. Aus Arbeitsschutzgründen musste daher ein zusätzliches Geländer installiert werden. Haben Sie in dem Video die schwarzen Flecken auf den Treppen gesehen? Hierbei soll es sich um Brandflecken aus dem Zweiten Weltkrieg handeln. Zurück in die 1920er Jahre. Zu dieser Zeit war hier das Bankenviertel von Berlin. Die besondere Atmosphäre erleben Mitarbeitende hautnah, wenn sie in dieses besondere Treppenhaus gehen. Die Ritterschaftsbank – oder auch als \"Kur- und Neumärkisches Ritterschaftliches Creditinstitut\" bekannt, entsteht zwischen 1890 und 1892. Das Bankhaus gehört zum damals neu entstehenden Bankenviertel. Es wird nach Plänen des Königlichen Baurats Herman Ditmar gebaut und ist inspiriert von prunkvollen Florentiner Renaissance-Palästen. Vor dem Zweiten Weltkrieg zieren deshalb viele Ornamente die Fassade. Nach schweren Kriegsschäden beginnt 1950 der Wiederaufbau. Ab 1951 nutzt die DDR -Regierung das Gebäude als Gästehaus. Zwischen 1999 und 2001 sind hier das Bundesgesundheitsministerium und die Landesvertretung Mecklenburg-Vorpommern untergebracht. Von 2004 bis 2008 erfolgt eine denkmalgerechte Sanierung. Verantwortlich sind die Architekten Josef Paul Kleihues und Norbert Hensel."},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Ritterschaftsbank/ritterschaftsbank.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:39.679143+00:00","lastSeen":"2026-03-15T17:28:39.679143+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Ritterschaftsbank/ritterschaftsbank.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Ritterschaftsbank/ritterschaftsbank.html","crawledAt":"2026-03-15T17:28:39.679143Z","crawlId":"organizations-seeded-1773595719","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"9568616e5dea66e78467e2dd0561191db64a659b30bee8f57b945e8ed4bc2cf3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:39.679143+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6c93b991-a98f-4275-9353-657280f33e2a', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Suederweiterung/suederweiterung.html', 'active', NULL, '2026-03-15T17:28:40.503621+00:00', '{"id":"6c93b991-a98f-4275-9353-657280f33e2a","title":"Süderweiterung","summary":{"de":"Die Süderweiterung des BMAS - Historie und Einblicke in den Gebäudeteil."},"content":{"de":"Ein funktionaler Neubau – oder wie wir ihn nennen: „Lückenfüller“. Links und rechts der früheren Ritterschaftsbank wurden Mitte der 2000er Jahre die Baulücken geschlossen. Die so genannte „Süderweiterung“ beherbergt Büros und den Presseraum. Das Modell verschafft uns eine gute Übersicht. Hier wird die Gebäudestruktur ganz deutlich: die neu entstandenen Höfe und wie alles zusammenhängt. Von 2004 bis 2008 entsteht die Süderweiterung nach Plänen von Josef Paul Kleihues und Norbert Hensel. Dadurch werden bauliche Lücken geschlossen. Gleichzeitig wird die benachbarte, denkmalgeschützte Ritterschaftsbank saniert. Wir stellen uns vor: Aufgaben, Geschäftsbereiche und weitere Infos aus dem BMAS"},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Suederweiterung/suederweiterung.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:40.503621+00:00","lastSeen":"2026-03-15T17:28:40.503621+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Suederweiterung/suederweiterung.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/Suederweiterung/suederweiterung.html","crawledAt":"2026-03-15T17:28:40.503621Z","crawlId":"organizations-seeded-1773595720","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"fa3780fa1449d93829a9eb41fcfcda273087c34b7a0d3a290213819cc6c984bd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:40.503621+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5ccb32a3-9a41-4877-a4b1-997a4661c444', 'organizations', 'https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/zu-gast-im-bmas.html', 'active', NULL, '2026-03-15T17:28:42.076351+00:00', '{"id":"5ccb32a3-9a41-4877-a4b1-997a4661c444","title":"Zu Gast im BMAS","summary":{"de":"Geschichte des Ministeriums, Eindrücke vom Gebäude und Informationen zu den Besuchsmöglichkeiten des BMAS."},"content":{"de":"Ein Blick ins Ministerium – jederzeit digital oder mit einem Termin beim Besucherdienst Einmal einen Blick ins Bundesministerium für Arbeit und Soziales werfen – und das am besten wann Sie wollen und von wo Sie wollen. Haben wir möglich gemacht: Wir laden Sie zu einem virtuellen Rundgang durch unser Haus ein. Erkunden Sie mit 360°-Aufnahmen und Videos die einzelnen Gebäude und Räume am Standort Berlin und erfahren Sie mehr über deren Geschichte. Wenn Sie noch mehr über das BMAS und sein Aufgabengebiet erfahren möchten, kommen Sie gerne persönlich vorbei. Mit unserem Besucherdienst empfangen wir alle interessierten Bürgerinnen und Bürger. Unsere Kolleginnen vom Besucherdienst begrüßen täglich Gruppen im BMAS. Wir konnten sie davon überzeugen, auch unsere Online-Besucherinnen und -Besucher durch das Haus zu führen. Klicken Sie dafür unten auf die Kacheln: Dort empfangen wir Sie mit historischen Fakten sowie Fotos und Videos der Gebäude und Räumlichkeiten."},"url":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/zu-gast-im-bmas.html","topics":["employment","financial_support","organizations"],"tags":["application_required","organization"],"targetGroups":["unemployed","general_public"],"status":"active","firstSeen":"2026-03-15T17:28:42.076351+00:00","lastSeen":"2026-03-15T17:28:42.076351+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Buergerinformationen"],"contactDetails":{"website":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/zu-gast-im-bmas.html"},"provenance":{"source":"https://www.bmas.de/DE/Ministerium/Zu-Gast-im-BMAS/zu-gast-im-bmas.html","crawledAt":"2026-03-15T17:28:42.076351Z","crawlId":"organizations-seeded-1773595722","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"913f7e472df001725ddb7a011af9ae65c0083c42c96389f30ac79c48b554fe82"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:28:42.076351+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('688d7da7-e9ef-4238-a6a6-a7ea0e818ef8', 'organizations', 'https://www.bmas.de/DE/Startseite/start.html', 'active', NULL, '2026-03-01T20:16:00Z', '{"id":"688d7da7-e9ef-4238-a6a6-a7ea0e818ef8","title":"Bundesministerium für Arbeit und Soziales (BMAS)","translations":{"de-LEICHT":{"title":"Arbeits-Ministerium","timestamp":"2026-03-01T20:16:00Z","provenance":{"source":"https://www.bmas.de/DE/Ministerium/ministerium.html","crawledAt":"2026-03-01T20:16:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Die BMAS-Startseite bietet zentrale Informationen zu Arbeit, Soziales, Service und ministeriellen Themenfeldern."},"content":{"de":"Sie verknüpft fachpolitische Inhalte mit praktischen Zugängen wie Kontaktmöglichkeiten und Bürgerinformationen. Dadurch entsteht ein zentraler Einstieg in arbeits- und sozialpolitische Bundesangebote."},"url":"https://www.bmas.de/DE/Startseite/start.html","topics":["employment","financial_support"],"tags":["automatic","application_required"],"targetGroups":["unemployed","disabled"],"status":"active","organizationType":"government","region":"Germany","services":["Arbeit","Soziales","Bürgertelefon"],"contactDetails":{"website":"https://www.bmas.de/"},"firstSeen":"2026-03-01T20:16:00Z","lastSeen":"2026-03-01T20:16:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.bmas.de/DE/Startseite/start.html","crawlId":"manual-curation-20260301-realdata-v1","checksum":"6bb366a68339f42f5e6a8bb30a78087f3f53384a426f6cf44ca4ac314ca31304","crawledAt":"2026-03-01T20:16:00Z"},"qualityScores":{"iqs":78.2,"ais":48.5,"computedAt":"2026-03-01T20:16:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e7641fb6-e9ef-46d8-acf1-77f79850e1a5', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj', 'active', NULL, '2026-03-15T15:59:57.891368+00:00', '{"id":"e7641fb6-e9ef-46d8-acf1-77f79850e1a5","title":"BMBFSFJ","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Am 8. März ist Bundesfrauenministern Karin Prien nach New York gereist, um an der 70. Frauenrechtskommission der Vereinten Nationen (UN) teilzunehmen. Im Fokus der Konferenz: der Zugang zu Recht und Justiz für Frauen und Mädchen weltweit. Mit der Braunschweiger Zeitung hat Bundesfrauenministerin Karin Prien darüber gesprochen, wie es um die Gleichstellung von Frauen steht und welche Rolle Künstliche Intelligenz (KI) dabei spielt. Am 10. März hat die Parlamentarische Staatssekretärin im Bundesbildungsministerium, Mareike Wulf, in Köln die didacta miteröffnet. Das Motto \"Alles im Wandel. Bildung im Fokus\" stellt Innovationen und mentale Gesundheit ins Zentrum. Das Bundesfamilienministerium bietet einen umfassenden Überblick über finanzielle Unterstützung für Familien in 2026. Informieren Sie sich über Kindergeld, Elterngeld, Kinderzuschlag und mehr. Flyer Das Pflegetelefon - Schnelle Hilfe für Angehörige"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T15:59:57.891368+00:00","lastSeen":"2026-03-15T15:59:57.891368+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj","crawledAt":"2026-03-15T15:59:57.891969Z","crawlId":"organizations-seeded-1773590397","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"80e71844c605089d9216c3b1bd97242924e069be3ac07e23d317302f77d24368"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T15:59:57.891969+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a949e1e5-03d5-4003-a58a-4b38bcdc753b', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles', 'active', NULL, '2026-03-15T17:29:30.089049+00:00', '{"id":"a949e1e5-03d5-4003-a58a-4b38bcdc753b","title":"Aktuell","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bundesfamilienministerin Karin Prien hat den Wettbewerb \"Kleine Lösungen - große Wirkung\" gestartet. Gesucht werden kleine und mittlere Unternehmen mit kreativen Ideen für die Vereinbarkeit von Familie und Beruf. Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Das Bundesfrauenministerium hat Dr. Petra Volke als deutsche Kandidatin für die Expertengruppe GREVIO des Europarats vorgestellt - ein bedeutender Beitrag Deutschlands zur Bekämpfung von geschlechtsspezifischer und häuslicher Gewalt. Presse Medienschaffende finden hier alle wichtigen Informationen aus der Pressestelle des Ministeriums: Pressemitteilungen, Kontaktdaten und Termine sowie Porträts. Medienschaffende finden hier alle wichtigen Informationen aus der Pressestelle des Ministeriums: Pressemitteilungen, Kontaktdaten und Termine sowie Porträts. Reden und Interviews Medieninterviews sowie ausgewählte Reden der Ministerin, der Parlamentarischen Staatssekretäre sowie der Staatssekretärin finden Sie hier."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:30.089049+00:00","lastSeen":"2026-03-15T17:29:30.089049+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles","crawledAt":"2026-03-15T17:29:30.089049Z","crawlId":"organizations-seeded-1773595770","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"ec23f4613f7785a9f89668dc1cf149e6bf3c6a3cad6f06ccd72381059e09d171"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:30.089049+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
