INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d38d8a87-64d8-4940-a6ec-d68c140afa86', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/antiziganismuspraevention-in-der-schulischen-bildung-staerken-277176', 'active', NULL, '2026-03-15T17:29:30.855440+00:00', '{"id":"d38d8a87-64d8-4940-a6ec-d68c140afa86","title":"Antiziganismusprävention in der schulischen Bildung stärken","summary":{"de":"Die Bund-Länder-Kommission zur Bekämpfung von Antiziganismus und für das Leben der Sinti und Roma diskutierte am 5. Dezember Herausforderungen, Ansätze und Empfehlungen zur Antiziganismusprävention in der schulischen Bildung."},"content":{"de":"Am 5. Dezember fand in Berlin die zweite ordentliche Sitzung der ständigen Bund-Länder-Kommission zur Bekämpfung von Antiziganismus und für das Leben der Sinti und Roma (BLK) statt. Die Sitzung wurde unter dem Vorsitz von Michael Brand, Parlamentarischer Staatssekretär im Bundesbildungsministerium und Beauftragter gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland, sowie dem Co-Vorsitzland Baden-Württemberg abgehalten. Schwerpunktthema der Kommissionssitzung war die Antiziganismusprävention in der schulischen Bildung. Bundesbildungsministerin Karin Prien wandte sich mit einem Grußwort an die Mitglieder und Gäste der Kommission. Karin Prien: \"Als Beauftragter der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland leistet Michael Brand einen wichtigen Beitrag für die gleichberechtigte Teilhabe der Sinti und Roma, für den Abbau von Vorurteilen und Diskriminierung und für das Wachhalten der Erinnerung an den Völkermord. Mein Ministerium unterstützt diese Arbeit ausdrücklich. Klar ist: nur gemeinsam - in Kooperation von Bund und Ländern - können wir Antiziganismus nachhaltig und entschieden begegnen. Dies gilt insbesondere für das Thema Bildung, aber auch darüber hinaus. Die Bund-Länder-Kommission zur Bekämpfung von Antiziganismus und für das Leben der Sinti und Roma ist hierfür ein maßgebliches Gremium, um die Perspektiven und Beiträge der Länder und des Bundes miteinander zu verknüpfen.\" Michael Brand: \" Die Sitzung der Bund-Länder-Kommission hat ein klares Signal dafür gesendet, dass der Kampf gegen Antiziganismus weiter mit Nachdruck geführt wird und die Stärkung von Sinti und Roma fest in der deutschen Politik verankert ist. Die Bund-Länder-Kommission hat sich dabei als zentrales Gremium, das gemeinsamen Ansätze berät und bei der Umsetzung die lokale Ebene mit einbezieht, mit dem Phänomen des Antiziganismus an Schulen befasst. Hier und in anderen Feldern werden Antiziganismusprävention sowie die Stärkung von Sinti und Roma in Deutschland auf der Agenda bleiben. Wir wollen eine Bildungskultur, die allen Kindern gleiche Chancen eröffnet und die Diskriminierung aktiv bekämpft.\" Schule ist ein zentraler Ort des Zusammenlebens, an dem Kinder grundlegende Erfahrungen von Gemeinschaft und sozialer Teilhabe machen. Doch für viele Sinti und Roma ist die Schule auch ein Ort, an dem sie Diskriminierung erfahren. Die BLK hat deshalb Herausforderungen thematisiert, und Handlungsempfehlungen besprochen. Das Gremium steht unter dem gemeinsamen Vorsitz des Bundesbeauftragten und einer oder einem jährlich wechselnden Co-Vorsitzenden der Länder. Zum 1. Januar 2026 übernimmt das Land Bayern den Co-Vorsitz."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/antiziganismuspraevention-in-der-schulischen-bildung-staerken-277176","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:30.855440+00:00","lastSeen":"2026-03-15T17:29:30.855440+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/antiziganismuspraevention-in-der-schulischen-bildung-staerken-277176"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/antiziganismuspraevention-in-der-schulischen-bildung-staerken-277176","crawledAt":"2026-03-15T17:29:30.855440Z","crawlId":"organizations-seeded-1773595770","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b27171c38e0a9b512ac6864cfd147dfb650a1d727e4f39cdb68c59dda117573f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:30.856437+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5ed75e8e-c38b-4d3d-ba74-efd823a7e8ac', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/beauftragte-fuer-akzeptanz-sexueller-und-geschlechtlicher-vielfalt-265346', 'active', NULL, '2026-03-15T17:29:31.358215+00:00', '{"id":"5ed75e8e-c38b-4d3d-ba74-efd823a7e8ac","title":"Beauftragte für Akzeptanz sexueller und geschlechtlicher Vielfalt","summary":{"de":"Sophie Koch, Mitglied des sächsischen Landtages, wurde als neue Beauftragte der Bundesregierung für Akzeptanz sexueller und geschlechtlicher Vielfalt berufen. Das Kabinett bestellte sie für die Dauer der 21. Legislaturperiode."},"content":{"de":"Das Bundeskabinett hat am 28. Mai eine Beauftragte der Bundesregierung für die Akzeptanz sexueller und geschlechtlicher Vielfalt bestellt. Sophie Koch übernimmt diese Aufgabe für die Dauer der 21. Wahlperiode, angesiedelt beim Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend. Sophie Koch, geboren am 26. Juli 1993 in Rodewisch, ist seit 2024 Mitglied des sächsischen Landtages und setzte sich von 2022 bis 2024 als Bildungsreferentin der LAG Queeres Netzwerk Sachsen für Fragen der Gleichstellung ein. Zudem ist sie seit 2023 Vorsitzende der SPD Frauen Dresden. Zur Politik kam Sophie Koch über den LandesSchülerRat und engagiert sich seither für mehr Mitspracherechte von jungen Menschen in der Politik. Anspruch der Bundesregierung ist, dass es für alle Menschen, unabhängig von ihrer sexuellen Orientierung oder Geschlechtsidentität, selbstverständlich ist, gleichberechtigt, diskriminierungs- und gewaltfrei leben zu können. Die Beauftragte der Bundesregierung für die Akzeptanz sexueller und geschlechtlicher Vielfalt wirkt bei entsprechenden Maßnahmen mit den Ressorts zusammen, um Bewusstsein schaffen, zu sensibilisieren und den Zusammenhalt und das Miteinander zu stärken in einem gesellschaftlichen Klima, in dem Vielfalt geschätzt wird."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/beauftragte-fuer-akzeptanz-sexueller-und-geschlechtlicher-vielfalt-265346","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:31.358215+00:00","lastSeen":"2026-03-15T17:29:31.358215+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/beauftragte-fuer-akzeptanz-sexueller-und-geschlechtlicher-vielfalt-265346"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/beauftragte-fuer-akzeptanz-sexueller-und-geschlechtlicher-vielfalt-265346","crawledAt":"2026-03-15T17:29:31.358215Z","crawlId":"organizations-seeded-1773595771","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"8fd7def0991bced70ee7d14d6800947f042536ad38daede36037bc50647ebd7d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:31.358215+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('406e0811-1f7b-4bd9-a519-30722a33f888', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/belange-von-menschen-afrikanischer-herkunft-in-den-fokus-ruecken-193358', 'active', NULL, '2026-03-15T17:29:31.854868+00:00', '{"id":"406e0811-1f7b-4bd9-a519-30722a33f888","title":"Belange von Menschen afrikanischer Herkunft in den Fokus rücken","summary":{"de":"Mehr Anerkennung, weniger Rassismus: Das sind Ziele der \"Dekade für Menschen afrikanischer Herkunft\" der Vereinten Nationen. Die Bundesregierung hat eine Koordinierungsstelle zur Umsetzung der Dekade eingerichtet."},"content":{"de":"Die Anerkennung, die Rechte und die Entwicklung von Menschen afrikanischer Herkunft zu fördern und rassistische Diskriminierung und Rassismus zu bekämpfen, das sind Ziele der \"Dekade für Menschen afrikanischer Herkunft\" der Vereinten Nationen (VN). Die Dekade wurde im Jahr 2015 ausgerufen und stellt die Belange Schwarzer, afrikanischer und afrodiasporischer Menschen in den Mittelpunkt. Damit die Umsetzung in Deutschland einen zusätzlichen Impuls erhält, hat die Bundesregierung jetzt eine Koordinierungsstelle offiziell eingerichtet. Margit Gottstein, Staatssekretärin im Bundesfamilienministerium, begrüßte am 25. Februar zusammen mit Juliane Seifert, Staatssekretärin im Bundesinnenministerium und Reem Alabali-Radovan, Staatsministerin beim Bundeskanzler und Beauftragte der Bundesregierung für Migration, Flüchtlinge und Integration, die Mitglieder des begleitenden Beirats zur ersten Sitzung. Die Bundesregierung hatte sich im Kabinettausschuss zur Bekämpfung von Rechtsextremismus und Rassismus dazu verpflichtet, die Koordinierungsstelle zur Umsetzung der \"VN-Dekade für Menschen afrikanischer Herkunft\" einzurichten. Die Koordinierungsstelle wird themenbezogene Aktivitäten der Bundesregierung, der Länder und weiterer Akteurinnen und Akteure aus Zivilgesellschaft und Wissenschaft bündeln und weiterentwickeln. Das Bundesfamilienministerium fördert die Stelle bis zum Ende der Laufzeit der Dekade im Jahr 2024. Eine zentrale Aufgabe der Koordinierungsstelle ist es, in den nächsten drei Jahren mit Veranstaltungen und Fachgesprächen auf die Perspektiven und die Lebenssituationen von Menschen afrikanischer Herkunft aufmerksam zu machen, Anti-Schwarzen Rassismus und damit zusammenhängende Diskriminierung in Gesellschaft und Strukturen zu adressieren und"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/belange-von-menschen-afrikanischer-herkunft-in-den-fokus-ruecken-193358","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:31.854868+00:00","lastSeen":"2026-03-15T17:29:31.854868+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/belange-von-menschen-afrikanischer-herkunft-in-den-fokus-ruecken-193358"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/belange-von-menschen-afrikanischer-herkunft-in-den-fokus-ruecken-193358","crawledAt":"2026-03-15T17:29:31.854868Z","crawlId":"organizations-seeded-1773595771","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c85228b64962bfaba8d932a2989e6e27e3db900808432b96f194103fe066e9aa"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:31.854868+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2f1755b4-cdca-422f-a113-29a1dc9bfad2', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundeskabinett-verabschiedet-nationalen-aktionsplan-78758', 'active', NULL, '2026-03-15T17:29:32.377726+00:00', '{"id":"2f1755b4-cdca-422f-a113-29a1dc9bfad2","title":"Bundeskabinett verabschiedet Nationalen Aktionsplan","summary":{"de":"Am 28. Juni hat das Bundeskabinett den neuen Nationalen Aktionsplan zur Umsetzung der VN-Behindertenrechtskonvention (NAP 2.0) verabschiedet. Ziel ist..."},"content":{"de":"Am 28. Juni hat das Bundeskabinett den neuen Nationalen Aktionsplan zur Umsetzung der Behindertenrechtskonvention der Vereinten Nationen (VN) NAP 2.0 verabschiedet. Der von Bundesozialministerin Andrea Nahles vorgelegte NAP 2.0 baut auf dem umfangreichen Maßnahmenbündel des ersten Aktionsplans aus dem Jahr 2011 auf. In optimierter Form soll der neue Aktionsplan dazu beitragen, dass Inklusion als universelles Prinzip in allen Lebensbereichen gilt und die praktische Umsetzung der Rechte von Menschen mit Behinderung verbessert wird. Mit dem NAP 2.0 ist es, auch durch einen intensiven Dialog mit der Zivilgesellschaft, gelungen, einen politikfeldübergreifenden Ansatz noch weiter zu stärken. Alle Bundesressorts haben Maßnahmen zum NAP 2.0 beigesteuert. In der von Andrea Nahles eingerichteten Steuerungsgruppe war somit auch das Bundesministerium für Familie, Senioren, Frauen und Jugend vertreten - aus allen Fachabteilungen des Bundesfamilienministeriums gingen insgesamt 16 neue, den Aktionsplan ergänzende Maßnahmen ein. Bundesfamilienministerin Manuela Schwesig betonte: \"Die Themen Inklusion und Teilhabe aller Menschen - von der Kita bis ins höchste Alter - betreffen viele Bereiche des Bundesfamilienministeriums. Das neue Mutterschutzgesetz, die inklusive Kita, das barrierefreie Hilfetelefon ''Gewalt gegen Frauen'', die Bundesjugendspiele für junge Menschen mit Behinderung, die Agenda ''Gemeinsam für Menschen mit Demenz'' – all diese Maßnahmen und Projekte leisten wichtige Beiträge für unser gemeinsames Ziel einer inklusiveren Gesellschaft.\" Die VN-Behindertenrechtskonvention von 2006 will sicherstellen, dass Menschen mit und ohne Behinderung den gleichen menschenrechtlichen Schutz erhalten und hat daher die universellen Menschenrechte für die Bedürfnisse und Lebenslagen von Menschen mit Behinderung konkretisiert. Die Konvention ist 2009 von Deutschland ratifiziert worden und verbindliches Recht."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundeskabinett-verabschiedet-nationalen-aktionsplan-78758","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:32.377726+00:00","lastSeen":"2026-03-15T17:29:32.377726+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundeskabinett-verabschiedet-nationalen-aktionsplan-78758"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundeskabinett-verabschiedet-nationalen-aktionsplan-78758","crawledAt":"2026-03-15T17:29:32.378364Z","crawlId":"organizations-seeded-1773595772","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5c295c76df9373ca899a52208204d506ebf75f1bf74174ed966c923923d40449"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:32.378364+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e19d93b3-1880-4034-9cf7-0bb0293f14cf', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundesregierung-legt-evaluierungsbericht-vor-279870', 'active', NULL, '2026-03-15T17:29:32.867063+00:00', '{"id":"e19d93b3-1880-4034-9cf7-0bb0293f14cf","title":"Bundesregierung legt Evaluierungsbericht vor","summary":{"de":"Wie weit ist Deutschland bei der Gleichstellung? Der Evaluierungsbericht zum Bundesgleichstellungsgesetz zeigt, dass die Maßnahmen Wirkung zeigen. Doch auch im Bundesdienst gibt es noch einiges zu tun."},"content":{"de":"Das Bundesfrauenministerium hat am 28. Januar den Evaluierungsbericht zum Bundesgleichstellungsgesetz (BGleiG) veröffentlicht. Der Bericht wurde in Auftrag gegeben, um die Wirksamkeit des BGleiG zu bewerten - nun lag er dem Kabinett vor. Damit kommt das Bundesfrauenministerium der gesetzlich vorgeschriebenen, vierjährlichen Berichtspflicht gegenüber dem Bundestag nach. Für den Berichtszeitraum 2021 bis 2024 wird deutlich, dass das Gesetz maßgeblich zur Gleichstellung von Frauen und Männern beiträgt. Gleichzeitig zeigt der Bericht, dass diese Gleichstellung in allen Dienststellen des Bundes noch nicht vollständig verwirklicht ist. Bundesgleichstellungsministerin Karin Prien: \"Das gesetzliche Ziel, Frauen in der Bundesverwaltung gleichberechtigt an Führungspositionen zu beteiligen, zeigt erfreuliche Erfolge. Der Bund geht hier als Arbeitgeber mit gutem Beispiel voran - doch unser Engagement darf nicht nachlassen. Wir setzen ein deutliches Zeichen für Gleichstellung und Chancengerechtigkeit. Unser Ziel ist klar: gleichberechtigte Teilhabe in allen Bereichen.\" Die ausgewerteten Daten zeigen einen kontinuierlichen Trend zu mehr Gleichstellung im Bundesdienst in den letzten Jahren. Seit 2019 stieg der Frauenanteil in den Führungspositionen in allen Verwaltungsbereichen deutlich an. Der Bericht kommt aber auch zu dem Schluss, dass sich die Dienststellen des Bundes noch deutlich in der Verankerung von Gleichstellungsorientierung in der Organisationskultur unterscheiden. Der Bericht enthält Empfehlungen, wie die Ziele des BGleiG noch besser zu erreichen sind. Ein geeignetes Mittel seien verpflichtende Schulungen von Führungskräften und Personalverwaltungen. Verbesserungsbedarf sieht der Bericht bei der Beteiligung und Unterstützung der Gleichstellungsbeauftragten. Eine bessere Vereinbarkeit von Familie, Pflege und Beruf wurde laut Bericht bereits in weiten Teilen erreicht. Trotzdem wurden die Potenziale des BGleiG zur Verbesserung von Familienfreundlichkeit und Vereinbarkeit noch nicht vollständig von allen Dienststellen ausgeschöpft. Vorbildhafte Gleichstellungsmaßnahmen, die die Sichtbarkeit von Gleichstellungsthemen und Gleichstellungsorientierung fördern, sind ebenfalls Teil der Berichterstattung: Dazu zählt unter anderem die Unterstützung beschäftigteninitiierter Netzwerke und Mentoringprogramme. Die Bundesregierung greift in ihrer Stellungnahme die Empfehlungen der Evaluierung als Handlungs- und Prüfempfehlungen auf. Das Bundesgleichstellungsministerium wird Unterstützungsangebote zur besseren Umsetzung des Gesetzes bereitstellen und den Dienststellen unter anderem einen Handlungsleitfaden zur Erstellung von Gleichstellungsplänen zur Verfügung stellen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundesregierung-legt-evaluierungsbericht-vor-279870","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:32.867063+00:00","lastSeen":"2026-03-15T17:29:32.867063+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundesregierung-legt-evaluierungsbericht-vor-279870"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/bundesregierung-legt-evaluierungsbericht-vor-279870","crawledAt":"2026-03-15T17:29:32.867063Z","crawlId":"organizations-seeded-1773595772","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"4425ae5b8ad622769cde46c27c981c13c2db191d8e648491f2f825971194029c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:32.868017+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4bd77774-735c-44c3-97a9-e5a36e1386c6', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/gemeinsames-gedenken-der-im-holocaust-ermordeten-sinti-und-roma-279904', 'active', NULL, '2026-03-15T17:29:33.495606+00:00', '{"id":"4bd77774-735c-44c3-97a9-e5a36e1386c6","title":"Gemeinsames Gedenken der im Holocaust ermordeten Sinti und Roma","summary":{"de":"Michael Brand gedachte gemeinsam mit Vertreterinnen und Vertretern der Zivilgesellschaft und dem Holocaust-Überlebenden Dieter Flack der im Holocaust ermordeten Sinti und Roma Europas."},"content":{"de":"Am 27. Januar, dem Internationalen Tag des Gedenkens an die Opfer des Holocaust, besuchte der Beauftragte der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma, Michael Brand, gemeinsam mit Vertreterinnen und Vertretern des Zentralrates Deutscher Sinti und Roma, des Dokumentations- und Kulturzentrums Deutscher Sinti und Roma und der Stiftung Denkmal für die ermordeten Juden Europas das Denkmal der im Nationalsozialismus ermordeten Sinti und Roma Europas im Berliner Tiergarten. Hauptredner der Veranstaltung war der Holocaust-Überlebende Dieter Flack. Michael Brand: \"Erinnern und Gedenken sind mehr als historischer Rückblick, sondern aktueller Auftrag an uns alle. Die Millionen Opfer des Holocausts verpflichten uns, Verantwortung zu übernehmen und aktiv für Demokratie, Menschenwürde und für die Rechte von Minderheiten einzutreten politisch - und das auch ganz konkret im Alltag. Nach dem Ende des Nazi-Terrors gab es für zu viele Opfer weiterhin Demütigung, weiter alte Vorurteile und schlimme Klischees. Zu oft gab es statt Verständnis und Anerkennung des erlittenen schweren Unrechts offen geäußerte Zweifel, statt Zuhören zu oft Abweisung, vielfach weiter Diskriminierung. Dies ehrlich anzuerkennen, bedeutet, heute glaubwürdig sagen zu können: Wir haben verstanden, wir machen es besser. Der 27. Januar mahnt dazu, weiter wachsam zu bleiben, Lehren aus der Geschichte zu ziehen und dort aktiv einzuschreiten, wo Menschen ausgegrenzt oder gar bedroht werden. Antisemitismus, Antiziganismus und jede Form gruppenbezogener Menschenfeindlichkeit werden wir auch weiter aktiv und energisch bekämpfen.\" Die Mitglieder der Volksgruppen der Sinti und Roma sind in Europa seit Jahrhunderten Diskriminierungen ausgesetzt. Während der Zeit des Nationalsozialismus wurden sie verfolgt und in Konzentrationslager deportiert. Schätzungen zufolge wurde dort zwischen 220.000 und 500.000 Sinti und Roma ermordet."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/gemeinsames-gedenken-der-im-holocaust-ermordeten-sinti-und-roma-279904","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:33.495606+00:00","lastSeen":"2026-03-15T17:29:33.495606+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/gemeinsames-gedenken-der-im-holocaust-ermordeten-sinti-und-roma-279904"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/gemeinsames-gedenken-der-im-holocaust-ermordeten-sinti-und-roma-279904","crawledAt":"2026-03-15T17:29:33.495606Z","crawlId":"organizations-seeded-1773595773","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"3dab31b2e1737bfa6110fe7aa92291d85fce99d092c7cafb3fbcad88093039ae"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:33.495606+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e8839d1c-5e04-43a0-87dd-a19b09934860', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/karin-prien-laedt-zum-vernetzungstreffen-280918', 'active', NULL, '2026-03-15T17:29:33.856585+00:00', '{"id":"e8839d1c-5e04-43a0-87dd-a19b09934860","title":"Karin Prien lädt zum Vernetzungstreffen","summary":{"de":"Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus."},"content":{"de":"Am 3. März hat Bundesfrauenministerin Karin Prien mit 50 Teilnehmenden auf dem alljährlichen Frauentags-Vernetzungstreffen des Bundesfrauenministeriums aktuelle gleichstellungspolitische Fragestellungen diskutiert und Ideen für eine Gleichstellungspolitik gesammelt. Auch Männer und Jungen sollen adressiert werden - als Unterstützer, aber auch als Zielgruppe von gleichstellungsorientierten Maßnahmen. Karin Prien: \"Gleichstellung gelingt besser, wenn auch Männer und Jungen adressiert werden - als Unterstützer und Partner, aber auch als Zielgruppe von gleichstellungsorientierten Maßnahmen. Gleichstellungspolitik für Männer ist kein Gegensatz zur Frauenpolitik, sondern deren notwendige Ergänzung.\" Das Frauentags-Vernetzungstreffen bietet bereits zum dritten Mal einen Rahmen für einen Austausch zwischen der Bundesregierung und zivilgesellschaftlichen Akteurinnen und Akteuren. Ziel ist, die akteursübergreifende gleichstellungspolitische Zusammenarbeit zu fördern. Fachexperte und Autor Markus Theunert und die Geschäftsführerin des Deutschen Frauenrates, Judith Rahner, tauschten sich zu Beginn des Vernetzungstreffens in einem Impuls-Dialog zur Rolle von Männlichkeitsbildern für die Gleichstellung aus und diskutierten aktuelle Herausforderungen und Möglichkeiten des gemeinsamen Vorgehens. Gleichstellung ist grundlegend für wirtschaftliche Stärke, Innovationskraft und gesellschaftliche Stabilität. Sie ist Voraussetzung einer resilienten Demokratie. Die Gleichstellung von Frauen und Männern muss daher ein Kernbestandteil jedes politischen Handelns sein und als Fundament wirtschaftlichen Wachstums anerkannt werden. Dafür setzt sich die Bundesregierung mit zahlreichen Vorhaben ein und will verstärkt auch Männer und Jungen in den Blick nehmen. Zum einen, weil sie als Partner für echte Gleichstellung gebraucht werden, zum anderen, weil Jungs und Männer ihre eigenen Bedürfnisse, Chancen und Herausforderungen haben, die ernst genommen werden müssen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/karin-prien-laedt-zum-vernetzungstreffen-280918","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:33.856585+00:00","lastSeen":"2026-03-15T17:29:33.856585+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/karin-prien-laedt-zum-vernetzungstreffen-280918"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/karin-prien-laedt-zum-vernetzungstreffen-280918","crawledAt":"2026-03-15T17:29:33.856585Z","crawlId":"organizations-seeded-1773595773","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"904fba8ee50f2f5b9648680d88e63d10c83db031d46aa13b03538318c3a5a4ad"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:33.856585+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('42d52d3c-c6b2-411a-878e-e5ee64bc3cb0', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-sinti-und-roma-leisten-wertvollen-beitrag-fuer-unser-land-274176', 'active', NULL, '2026-03-15T17:29:34.356667+00:00', '{"id":"42d52d3c-c6b2-411a-878e-e5ee64bc3cb0","title":"Michael Brand: Sinti und Roma leisten wertvollen Beitrag für unser Land","summary":{"de":"Anlässlich des 3. Forums Sinti und Roma rief Michael Brand dazu auf: \"Miteinander, nicht übereinander reden - Vorurteile beseitigen, Gemeinsamkeit stärken. Sinti und Roma leisten wertvollen Beitrag für unser Land und unsere Gesellschaft.\""},"content":{"de":"Zum 3. Forum Sinti und Roma unter dem Motto \"Wo stehen wir? Was zu tun ist! Zur Lage der Sinti und Roma in Deutschland\", zu dem über 180 Teilnehmer von Sinti und Roma, Politik, Zivilgesellschaft und Wissenschaft erwartet werden, hat der Parlamentarische Staatssekretär Michael Brand als Beauftragter der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland dazu aufgerufen: \"Mit alten Vorurteilen aufzuräumen und für eine gemeinsame Perspektive zu arbeiten. Bei allen Fortschritten ist Antiziganismus leider nach wie vor noch Realität - in Schulen, in der Öffentlichkeit, bei Wohnungssuche und auch in Behörden. Der Einsatz gegen Diskriminierung und für die legitimen Rechte von Sinti und Roma ist nicht Anliegen der Minderheit, sondern der gesamten Gesellschaft. Am Umgang mit Minderheiten zeigt sich die Haltung und Stärke einer offenen Gesellschaft. Neben Erinnerung und Aufarbeitung kommt es darauf an, das Verbindende statt falsche Vorurteile in den Vordergrund zu stellen. Begegnung, Dialog und Zusammenarbeit schaffen bessere Grundlagen für echtes Miteinander. Das Forum Sinti und Roma belegt eindrucksvoll, wie viel Kompetenz, Verantwortung und Einsatz Sinti und Roma für uns alle mit einbringen. Wir werden gemeinsam stärker, wenn wir mehr voneinander wissen. Sinti und Roma müssen auch deshalb mehr Gehör finden, ihr berechtigter Platz in unserer Gesellschaft muss besser sichtbarer werden.\""},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-sinti-und-roma-leisten-wertvollen-beitrag-fuer-unser-land-274176","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:34.356667+00:00","lastSeen":"2026-03-15T17:29:34.356667+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-sinti-und-roma-leisten-wertvollen-beitrag-fuer-unser-land-274176"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-sinti-und-roma-leisten-wertvollen-beitrag-fuer-unser-land-274176","crawledAt":"2026-03-15T17:29:34.356667Z","crawlId":"organizations-seeded-1773595774","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d1c4bba7526a840f2e107882806fb5ddcea90a9c5be6a5cff90471ea9467511d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:34.356667+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5e1e9c23-e9fe-46a6-a3f0-43afa87df049', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-wird-neuer-beauftragter-gegen-antiziganismus--265840', 'active', NULL, '2026-03-15T17:29:34.883498+00:00', '{"id":"5e1e9c23-e9fe-46a6-a3f0-43afa87df049","title":"Michael Brand wird neuer Beauftragter gegen Antiziganismus","summary":{"de":"Das Bundeskabinett hat Michael Brand zum Beauftragten der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland berufen."},"content":{"de":"Das Bundeskabinett hat am 18. Juni auf Vorschlag von Bundesgleichstellungsministerin Karin Prien den Parlamentarischen Staatssekretär im Bundesbildungs- und Familienministerium, Michael Brand, zum Beauftragten der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland für die Dauer der 21. Wahlperiode berufen. Michael Brand: \" Diese weitere Verantwortung im Rahmen meiner Tätigkeit als Parlamentarischer Staatssekretär zu übernehmen, ist mir nach meiner langjährigen Erfahrung im Bereich der Menschenrechte und auch im Kampf gegen Diskriminierung von Sinti und Roma ein Anliegen, dem ich mich vor dem Hintergrund dieser Erfahrung gerne widmen werde. Dabei liegt mir daran, dass wir den gesellschaftlichen Diskurs auch zur Frage der Sinti und Roma und des Antiziganismus in einer Art und Weise führen, dass wir die Ursachen benennen, aufklären und Lösungen aufzeigen. Wo Diskriminierung geschieht, muss ihr klar und entschieden entgegengetreten werden - durch Staat und Gesellschaft gleichermaßen. Es ist mir wichtig, auch die vielen positiven Beispiele des Miteinanders zwischen Mehrheitsgesellschaft und Minderheit stärker in den Fokus zu rücken. Der notwendige Diskurs darf nicht ausschließlich mit negativ besetzten Positionierungen, schon gar nicht mit Vorurteilen und Stereotypen geführt werden. Wobei völlig unstreitig bleibt, dass auf besorgniserregende Entwicklungen und Vorfälle selbstverständlich immer mit der notwendigen Klarheit des Staates und auch unserer Gesellschaft reagiert werden muss. Völlig klar ist, dass wir angesichts des Anstiegs von innen und außen befeuertem Extremismus gerade auch Minderheiten wie die Sinti und Roma besonders vor den Auswirkungen von Extremismus und Diskriminierung zu schützen haben. Vor dem Hintergrund meiner bisherigen Erfahrung werde ich den Dialog mit den Sinti und Roma, ihren Interessenvertretungen, staatlichen Institutionen und der Zivilgesellschaft suchen, um die bestmöglichen Strategien zu entwickeln und der besonderen historischen Verantwortung gegenüber dieser in der Zeit des Nationalsozialismus schwer verfolgten Minderheit gerecht zu werden. Es bleibt das selbstverständliche Ziel, Sinti und Roma in unserem demokratischen Rechtsstaat sämtliche Rechte zu garantieren und alle Möglichkeiten zu eröffnen, die ihnen zustehen. Auf die gemeinsame Arbeit freue ich mich sehr. \" Michael Brand ist studierter Politikwissenschaftler und seit vielen Jahren im Bereich Menschenrechte aktiv, unter anderem als Vorsitzender des Menschenrechtsausschusses im Deutschen Bundestag sowie als Sprecher für Menschenrechte der CDU/CSU-Bundestagsfraktion. Als Parlamentarier hat Michael Brand sich in seiner bisherigen Arbeit durch seinen Einsatz für Menschenrechte und die Belange von Minderheiten ausgezeichnet. Für die Sinti und Roma ist diese Entscheidung ein deutliches Zeichen, dass die Bundesregierung sie nicht nur in ihrem Einsatz gegen Stigmatisierung und Ausgrenzung unterstützt, sondern auch die Kultur der Sinti und Roma als Bestandteil unseres Lebens in Deutschland anerkennt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-wird-neuer-beauftragter-gegen-antiziganismus--265840","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:34.883498+00:00","lastSeen":"2026-03-15T17:29:34.883498+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-wird-neuer-beauftragter-gegen-antiziganismus--265840"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/michael-brand-wird-neuer-beauftragter-gegen-antiziganismus--265840","crawledAt":"2026-03-15T17:29:34.883498Z","crawlId":"organizations-seeded-1773595774","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"ce17f3d4f4916ebe3b208f2ca0c97a693b2310eebfa303903eefbc1db8b2775b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:34.883498+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('21f19b97-5cac-47cd-80d1-96be017a23b0', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/sebastian-gutknecht-als-erster-direktor-im-amt-eingefuehrt-181978', 'active', NULL, '2026-03-15T17:29:35.414010+00:00', '{"id":"21f19b97-5cac-47cd-80d1-96be017a23b0","title":"Sebastian Gutknecht als erster Direktor im Amt eingeführt","summary":{"de":"Mit dem Zweiten Gesetz zur Änderung des Jugendschutzgesetzes ist die Bundeszentrale für Kinder- und Jugendmedienschutz entstanden. Sebastian Gutknecht ist ab sofort ihr erster Direktor."},"content":{"de":"Die Staatssekretärin im Bundesjugendministerium, Juliane Seifert, hat am 8. Juni Sebastian Gutknecht als ersten Direktor der Bundeszentrale für Kinder- und Jugendmedienschutz (BzKJ) in sein Amt eingeführt. Mit dem am 1. Mai 2021 in Kraft getretenen Zweiten Gesetz zur Änderung des Jugendschutzgesetzes ist die BzKJ aus der bisherigen Bundesprüfstelle für jugendgefährdende Medien (BPjM) entstanden. \"Mit Sebastian Gutknecht erhält die Bundeszentrale für Kinder- und Jugendmedienschutz eine fachlich erfahrene Leitung, die sich der gewachsenen Bedeutung der Behörde annehmen wird. Größte Aufgabe ist es jetzt, den modernisierten Kinder- und Jugendmedienschutz umzusetzen, der im neuen Jugendschutzgesetz beschlossen wurde. Dabei wünsche ich Sebastian Gutknecht gutes Gelingen und viel Erfolg.\" Sebastian Gutknecht war zuletzt Geschäftsführer der Arbeitsgemeinschaft Kinder- und Jugendschutz Nordrhein-Westfalen. Seit 2008 hat er die Obersten Landesjugendbehörden in der Kommission für Jugendmedienschutz vertreten. Er ist Autor zahlreicher Veröffentlichungen zum Kinder- und Jugendmedienschutz und zum Jugendschutzrecht. Sebastian Gutknecht folgt auf die ehemalige Vorsitzende der BPjM, Martina Hannak. \"Der Bundeszentrale für Kinder- und Jugendmedienschutz kommt aufgrund der erfolgreichen Reform des Jugendschutzgesetzes eine wichtige Rolle dabei zu, Kindern und Jugendlichen ein gutes Aufwachsen mit Medien zu ermöglichen. Ich freue mich, den modernisierten Kinder- und Jugendmedienschutz in die Praxis umzusetzen.\" Die Bundeszentrale für Kinder- und Jugendmedienschutz mit Sitz in Bonn ist eine selbstständige Bundesoberbehörde im Geschäftsbereich des Bundesjugendministeriums. Mit dem neuen Jugendschutzgesetz wurden systemische Anbietervorsorgepflichten, zum Beispiel sichere Voreinstellungen, Beschwerde- und Hilfesysteme, zur Eindämmung von Interaktionsrisiken wie beispielsweise Cybergrooming, Cybermobbing und Kostenfallen eingeführt. Die BzKJ wacht über die Einhaltung dieser Pflichten und ist zur Verhängung empfindlicher Bußgelder von bis zu 50 Millionen Euro befugt. Zudem vernetzt sie alle im Kinder- und Jugendmedienschutz wichtigen Akteurinnen und Akteure, treibt die auch weiterhin notwendige Weiterentwicklung des Kinder- und Jugendmedienschutzes voran und ermöglicht Eltern, Fachkräften, Kindern und Jugendlichen Orientierung."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/sebastian-gutknecht-als-erster-direktor-im-amt-eingefuehrt-181978","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:35.414010+00:00","lastSeen":"2026-03-15T17:29:35.414010+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/sebastian-gutknecht-als-erster-direktor-im-amt-eingefuehrt-181978"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/alle-meldungen/sebastian-gutknecht-als-erster-direktor-im-amt-eingefuehrt-181978","crawledAt":"2026-03-15T17:29:35.414010Z","crawlId":"organizations-seeded-1773595775","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"2bdf38c12e45126fedea29a30b2ed4852fca16c418a15998a851ec74ec3c72a0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:35.414010+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
