INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6ef488d0-3680-42eb-a6e9-bcc1e482893f', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/rss', 'active', NULL, '2026-03-15T17:29:37.371319+00:00', '{"id":"6ef488d0-3680-42eb-a6e9-bcc1e482893f","title":"RSS-Service","summary":{"de":"Mit unserem Serviceangebot sind Sie immer topaktuell über die Themen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend informiert."},"content":{"de":"RSS-Feeds helfen Ihnen, sich schnell über Neuigkeiten auf unserer Internet-Seite zu informieren. Dafür müssen Sie die Seite nicht einmal besuchen. Besonders, wenn Sie über viele unterschiedliche Themen und Websites aktuell informiert sein wollen, hilft Ihnen der RSS-Service viel Zeit für die Recherche zu sparen. RSS ist eine Technik zur Übertragung von aktuellen Inhalten aus Internetseiten auf ein spezielles Leseprogramm, das Feed-Reader oder Newsreader genannt wird. Immer dann, wenn www.bmbfsfj.de aktualisiert wird, erhalten Sie die neuesten Meldungen bequem mit Hilfe Ihres aktivierten Feed-Reader auf Ihren Rechner. Um die Nachrichten automatisiert zu empfangen, müssen Sie den entsprechenden RSS-Feed über Ihren Feed-Reader oder Ihren Internet-Browser abonnieren. Der RSS-Service des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend informiert Sie über alle Themenbereiche des Hauses. Sie können auswählen, ob Sie unsere aktuelle Meldungen oder unsere Pressemitteilungen abonnieren möchten. Aktuelle Meldungen RSS Zusammenstellung von aktuellen Artikeln und Meldungen"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/rss","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:37.371319+00:00","lastSeen":"2026-03-15T17:29:37.371319+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/rss"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/rss","crawledAt":"2026-03-15T17:29:37.371319Z","crawlId":"organizations-seeded-1773595777","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f7b5a5cf1f9034b731c0d55fe92525fef101b8b2edcaba59f98cd267fec6aa8e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:37.372328+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5964c8aa-5e29-4e41-b958-8a328efba8d7', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242', 'active', NULL, '2026-03-15T17:29:37.865978+00:00', '{"id":"5964c8aa-5e29-4e41-b958-8a328efba8d7","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Diese Erklärung zur Barrierefreiheit gilt für die unter www.bmbfsfj.bund.de veröffentlichte Website. Als öffentliche Stelle im Sinne der Richtlinie (EU) 2016/2102 ist das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend bestrebt, die Website www.bmbfsfj.bund.de im Einklang mit den Bestimmungen des Behindertengleichstellungsgesetztes des Bundes (BGG) sowie der Barrierefreien-Informationstechnik-Verordnung (BITV 2.0) zur Umsetzung der Richtlinie (EU) 2016/2102 barrierefrei zugänglich zu machen. Die Anforderungen der Barrierefreiheit ergeben sich aus § 3 Abs. 1 bis 4 und § 4 der BITV 2.0, die auf der Grundlage von § 12d BGG erlassen wurde. Zur Überprüfung der Anforderungen wurde im September 2023 ein BITV-Test durch den Prüfverbund BIK durchgeführt. Dabei wurde eine repräsentative Seitenauswahl untersucht. Der vollständige Prüfbericht kann hier eingesehen werden. Aufgrund der Überprüfung ist die Website mit den zuvor genannten Anforderungen teilweise vereinbar. Einige der im Prüfbericht festgestellten Mängel wurden zwischenzeitlich behoben. Die nachstehend aufgeführten Mängel bestehen nach wie vor: Die Inhalte im Logoband auf der Startseite sind im Lesemodus des Screenreaders nur eingeschränkt nutzbar. Das Verhalten (Ein- und Ausblenden von Inhalten) wird über Fokus-Events gesteuert, die im Screenreader zu leeren oder irreführenden Ausgaben führen können (WCAG 2.1, 1.3.2 Meaningful Sequence, Level A). Anderssprachige Inhalte (Wörter, Textabschnitte) in Überschriften sind nicht ausgezeichnet, das kann die Nutzung mit dem Screenreader erschweren (WCAG 2.1, 3.1.2 Language of Parts, Level AA)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:37.865978+00:00","lastSeen":"2026-03-15T17:29:37.865978+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242","crawledAt":"2026-03-15T17:29:37.865978Z","crawlId":"organizations-seeded-1773595777","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"dab8d9fb8f28d858db6857b8eec3449d6913a5681488b3397680e22bdd688a89"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:37.865978+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7a950bb6-88aa-4eeb-a980-97a4674b1aae', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428', 'active', NULL, '2026-03-15T17:29:38.883621+00:00', '{"id":"7a950bb6-88aa-4eeb-a980-97a4674b1aae","title":"Informationen zur Verarbeitung personenbezogener Daten","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Zu den Aufgaben des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ) gehört es unter anderem, die Öffentlichkeit über seine Arbeit zu informieren. Dies umfasst die Bereitstellung von Informationen im Internet und in Sozialen Netzwerken, die direkte Kommunikation mit Bürgerinnen und Bürgern beziehungsweise der Fachöffentlichkeit, den Empfang von Besuchergruppen im Ministerium und die Organisation von Fachveranstaltungen. Sofern bei diesen Tätigkeiten personenbezogene Daten verarbeitet werden, geschieht dies auf Grundlage der rechtlichen Bestimmungen, insbesondere der Europäischen Datenschutz-Grundverordnung (EU DSGVO) und dem Bundesdatenschutzgesetz (BDSG). Personenbezogene Daten sind alle Informationen, die sich auf einen (lebenden) Menschen beziehen, der entweder bereits identifiziert ist oder der durch diese Informationen identifizierbar wird. Identifizierbarkeit kann entweder durch eine Zusammenführung der vorliegenden Informationen oder unter Einbeziehung von zusätzlichen Maßnahmen erfolgen, zum Beispiel der Zuordnung zu einer Namenskennung, einer Kennnummer, zu Standortdaten, einer Online-Kennung oder mittels einer Recherche in allgemein zugänglichen Informationspools wie Datenbanken, Bibliotheken oder dem Internet. Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend ]init[ AG (Auftragsverarbeiter für Hosting und Betrieb) Köpenicker Str. 9, 10997 Berlin TV1 GmbH, Beta-Straße 9a, 85774 Unterföhring (Auftragsverarbeiter für Video-Streaming)"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:38.883621+00:00","lastSeen":"2026-03-15T17:29:38.883621+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428","crawledAt":"2026-03-15T17:29:38.883621Z","crawlId":"organizations-seeded-1773595778","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"077f8eb918ba5cee34a0683e4d75770a940f2808a9753353a3273ad11dc318b6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:38.883621+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5f96f136-cf7c-4c2c-808b-63e03d07974e', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/inhalt-107174', 'active', NULL, '2026-03-15T17:29:39.457105+00:00', '{"id":"5f96f136-cf7c-4c2c-808b-63e03d07974e","title":"Inhalt","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Hier finden Sie die Inhalte der Website im Überblick: Themen Familie Familienleistungen Familie und Arbeitswelt Schwangerschaft und Kinderwunsch Chancen und Teilhabe für Familien Kinderbetreuung KiTa-Qualität Smarte Gesellschaftspolitik Nationaler Aktionsplan Kinderchancen Ältere Menschen Aktiv im Alter Hilfe und Pflege Zehn Jahre Pflegetelefon Vereinbarkeit von Pflege und Beruf Pflegeausbildung - Berufsfeld Pflege Demenz Letzte Wege Zuhause im Alter Internationale Politik für ältere Menschen Gleichstellung Wirtschaftliche Gleichstellung, Frauen und Arbeitswelt Lohngerechtigkeit Entgelttransparenzgesetz Frauen in Führungspositionen Jungen und Männer Frauen vor Gewalt schützen Prostituiertenschutzgesetz Aufwertung sozialer Berufe Gleichstellung und Teilhabe Gleichstellungsberichte der Bundesregierung Sexuelle und geschlechtliche Vielfalt Gender Care Gap Internationale Gleichstellungspolitik Digitaler Gleichstellungsatlas Feministische Digitalpolitik Kinder und Jugend Kinder- und Jugendschutz Schutz vor sexualisierter Gewalt Kinderrechte Kinderbetreuung KiTa-Qualität Jugendbildung Jugendstrategie Medienkompetenz Integration und Chancen für junge Menschen Kinder- und Jugendgesundheit Engagement und Gesellschaft Deutsche Stiftung für Engagement und Ehrenamt Demografischer Wandel und Nachhaltigkeit Engagement stärken Menschen stärken Menschen Beratung bei Auswanderung Mehrgenerationenhäuser Allianz gegen Einsamkeit Flüchtlingspolitik und Integration Freiwilligendienste Jugendfreiwilligendienste Bundesfreiwilligendienst Internationales und Europa Europäischer Sozialfonds - ESF Internationale Familienpolitik Internationale Politik für ältere Menschen Internationale Gleichstellungspolitik Internationale Politik für Demokratie und Engagement Internationale Jugendpolitik Internationale und europäische Jugendpolitik Erasmus+ Familie Familienleistungen Familie und Arbeitswelt Schwangerschaft und Kinderwunsch Chancen und Teilhabe für Familien Kinderbetreuung KiTa-Qualität Smarte Gesellschaftspolitik Nationaler Aktionsplan Kinderchancen Ältere Menschen Aktiv im Alter Hilfe und Pflege Zehn Jahre Pflegetelefon Vereinbarkeit von Pflege und Beruf Pflegeausbildung - Berufsfeld Pflege Demenz Letzte Wege Zuhause im Alter Internationale Politik für ältere Menschen Gleichstellung Wirtschaftliche Gleichstellung, Frauen und Arbeitswelt Lohngerechtigkeit Entgelttransparenzgesetz Frauen in Führungspositionen Jungen und Männer Frauen vor Gewalt schützen Prostituiertenschutzgesetz Aufwertung sozialer Berufe Gleichstellung und Teilhabe Gleichstellungsberichte der Bundesregierung Sexuelle und geschlechtliche Vielfalt Gender Care Gap Internationale Gleichstellungspolitik Digitaler Gleichstellungsatlas Feministische Digitalpolitik Wirtschaftliche Gleichstellung, Frauen und Arbeitswelt Lohngerechtigkeit Entgelttransparenzgesetz Frauen in Führungspositionen"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/inhalt-107174","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:39.457105+00:00","lastSeen":"2026-03-15T17:29:39.457105+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/inhalt-107174"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/inhalt-107174","crawledAt":"2026-03-15T17:29:39.457105Z","crawlId":"organizations-seeded-1773595779","crawlerVersion":"0.1.0","sou