INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c5312a2e-4761-4ece-b24a-e247309f1b11', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/kommissionen-im-bundesbildungs-und-familienministerium-276990', 'active', NULL, '2026-03-15T17:29:39.867990+00:00', '{"id":"c5312a2e-4761-4ece-b24a-e247309f1b11","title":"Kommissionen im Bundesbildungs- und -familienministerium","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Um Vorhaben gezielter umsetzen zu können, wird das Bundesbildungs- und -familienministerium bei seiner Arbeit in verschiedenen Bereichen von Kommissionen unterstützt. Prostitution ist in Deutschland zulässig - sofern sie freiwillig und von Erwachsenen ausgeübt wird. Um die Situation von Frauen und Männern, die in der Prostitution tätig sind, zu verbessern und sie vor Menschenhandel, Ausbeutung und Zwang zu schützen, wurde das Prostituiertenschutzgesetz verabschiedet. Zur Umsetzung des Gesetzes hat im Herbst 2025 eine von Bundesfrauenministerin Karin Prien Expertenkommission ihre Arbeit aufgenommen. Die gebündelten Informationen finden Sie hier. Im September 2025 hat Bundesbildungsministerin Karin Prien die Expertenkommission \"Kinder- und Jugendschutz in der digitalen Welt\" vorgestellt, die noch im Herbst 2025 ihre Arbeit aufgenommen hat. Ziel der Kommission ist es, eine Strategie für den \"Kinder- und Jugendschutz in der digitalen Welt\" mit konkreten Handlungsempfehlungen für die zuständigen Akteure wie Bund, Länder und Zivilgesellschaft zu erarbeiten. Mehr Informationen dazu finden Sie hier. Frauen verdienen in Deutschland immer noch etwa 16 Prozent weniger als Männer. Das Ziel der Bundesregierung ist, dass Frauen und Männer gleichen Lohn für gleiche und gleichwertige Arbeit erhalten. Dieses Ziel verfolgt auch die Entgelttransparenzrichtlinie der Europäischen Union (EU), die bis Juni 2026 in nationales Recht umzusetzen ist. Die Bundesgleichstellungsministerin Karin Prien hat in diesem Zusammenhang die Kommission \"Bürokratiearme Umsetzung der Entgelttransparenzrichtlinie\" eingesetzt. Diese hat im November 2025 einen Abschlussbericht vorgestellt. Weitere Informationen dazu finden Sie hier. Eine unabhängige Sachverständigenkommission hat im Herbst 2025 die Arbeit am 18. Kinder- und Jugendbericht aufgenommen. Die Kommission soll sich der Frage widmen, mit welchen Maßnahmen die Kinder- und Jugendhilfe so abgesichert werden kann, dass sie auch zukünftig junge Menschen verlässlich schützen kann. Weitere Informationen dazu finden Sie hier. Bundesseniorenministerin Karin Prien hat im September 2025 die Kommission für den Zehnten Altersbericht der Bundesregierung einberufen. Der Bericht soll untersuchen, wie Bildung älteren Menschen neue soziale Rollen und aktives Altern ermöglicht - unter besonderer Berücksichtigung non-formaler und informeller Lernformen sowie kognitiver Entwicklungen im Alter. Der Bericht soll Impulse für eine inklusive Bildungspolitik geben und Bildung im Alter stärker politisch verankern - auch im internationalen Vergleich. Weitere Informationen dazu finden Sie hier."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/kommissionen-im-bundesbildungs-und-familienministerium-276990","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:39.867990+00:00","lastSeen":"2026-03-15T17:29:39.867990+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/kommissionen-im-bundesbildungs-und-familienministerium-276990"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/kommissionen-im-bundesbildungs-und-familienministerium-276990","crawledAt":"2026-03-15T17:29:39.867990Z","crawlId":"organizations-seeded-1773595779","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"ad6c85954495c798746e43b128aa522fcd6c8bc090a5e26004fbf457f6b8b035"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:39.867990+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d3c249df-9ac1-4baf-9613-496127569a81', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium', 'active', NULL, '2026-03-15T16:00:01.455044+00:00', '{"id":"d3c249df-9ac1-4baf-9613-496127569a81","title":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend","summary":{"de":"Hier finden Sie Informationen über das Bundesfamilienministerium, nachgeordnete Behörden, Beiräte und Gremien sowie die Ministerin und die Staatssekretäre."},"content":{"de":"Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Die ehemalige Bundesfrauenministerin und Bundestagspräsidentin Prof. Dr. Rita Süssmuth ist verstorben. Karin Prien und Nina Warken würdigten sie als großes Vorbild und Vorkämpferin für Frauenrechte und sozialen Zusammenhalt. Wie weit ist Deutschland bei der Gleichstellung? Der Evaluierungsbericht zum Bundesgleichstellungsgesetz zeigt, dass die Maßnahmen Wirkung zeigen. Doch auch im Bundesdienst gibt es noch einiges zu tun."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:01.455044+00:00","lastSeen":"2026-03-15T16:00:01.455044+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium","crawledAt":"2026-03-15T16:00:01.455044Z","crawlId":"organizations-seeded-1773590401","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"1621ddd7508453ca824115e53f1