ng"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/ausschreibungen"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/ausschreibungen","crawledAt":"2026-03-15T16:00:02.461911Z","crawlId":"organizations-seeded-1773590402","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"2a63c8a8c7291a0692eabd1ac149b5a51773788680860aaddf857dc4c1b28470"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:02.462416+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c060d1eb-62fc-4149-83a2-aaad1559be21', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien', 'active', NULL, '2026-03-15T16:00:02.967981+00:00', '{"id":"c060d1eb-62fc-4149-83a2-aaad1559be21","title":"Förderrichtlinien des Bundes","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Richtlinien für den Bundesaltenplan Die Richtlinien für den Bundesaltenplan legen Vorhaben fest, die vom Bundesseniorenministerium gefördert werden können. Die Vorhaben sollen dazu führen, dass ältere Menschen selbstständiger und gleichberechtigter in der Gesellschaft leben können. Die Richtlinien für den Bundesaltenplan legen Vorhaben fest, die vom Bundesseniorenministerium gefördert werden können. Die Vorhaben sollen dazu führen, dass ältere Menschen selbstständiger und gleichberechtigter in der Gesellschaft leben können. Familienförderrichtlinien des Bundes Das Bundesfamilienministerium setzt sich für eine familienfreundliche Gesellschaft ein. Dafür werden Träger und Projekte mit familienpolitischem Bezug unterstützt. Ziel ist, dass sich Familien nach eigenen Vorstellungen optimal entwickeln können. Das Bundesfamilienministerium setzt sich für eine familienfreundliche Gesellschaft ein. Dafür werden Träger und Projekte mit familienpolitischem Bezug unterstützt. Ziel ist, dass sich Familien nach eigenen Vorstellungen optimal entwickeln können. Richtlinien des Kinder- und Jugendplans des Bundes Das Bundesjugendministerium fördert die Kinder- und Jugendhilfe, wenn diese von überregionaler Bedeutung ist und ihre Tätigkeit nicht durch ein Land allein wirksam gefördert werden kann. Das Bundesjugendministerium fördert die Kinder- und Jugendhilfe, wenn diese von überregionaler Bedeutung ist und ihre Tätigkeit nicht durch ein Land allein wirksam gefördert werden kann."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:02.967981+00:00","lastSeen":"2026-03-15T16:00:02.967981+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien","crawledAt":"2026-03-15T16:00:02.967981Z","crawlId":"organizations-seeded-1773590402","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"a7501fa4707e3f930b82bca62df98cd030c5958d63fe5a7392752f4906228843"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:02.967981+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('76d08b50-c00f-4bcb-b9f6-91beb688a504', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/demokratie-leben', 'active', NULL, '2026-03-15T17:29:42.385200+00:00', '{"id":"76d08b50-c00f-4bcb-b9f6-91beb688a504","title":"Förderrichtlinie des Bundesprogramms \"Demokratie leben! \" vom 20. November 2024","summary":{"de":"Das Bundesfamilienministerium unterstützt mit dem Bundesprogramm \"Demokratie leben!\" auf kommunaler und regionaler Ebene, auf Landes- und Bundesebene zivilgesellschaftliche Projekte, die sich der..."},"content":{"de":"Demokratieförderung, Vielfaltgestaltung und Extremismusprävention müssen stetig erfolgen, um ihre vorbeugende Wirkung nachhaltig entfalten zu können. Deshalb wurde das Bundesprogramm \"Demokratie leben!\" im Mai 2018 entfristet. Mit der Entfristung kann das weiterentwickelte Bundesprogramm über das Jahr 2019 hinaus fortgeführt werden. Im Rahmen der Weiterentwicklungsprozesse wurde eine Förderrichtlinie erarbeitet, auf deren Basis \"Demokratie leben!\" in seine 3. Förderperiode (2025 bis 2032) starten kann. Dabei wurden die Ziele und Strukturen neu justiert und stärker fokussiert - vor allem mit Blick auf die aktuellen gesellschaftlichen Herausforderungen und auf Grundlage der gewonnenen Erfahrungen aus der ersten (2015 bis 2019) und zweiten (2020 bis 2024) Förderperiode. Die Förderrichtlinie \"Demokratie leben!\" wurde im November 2024 im Gemeinsamen Ministerialblatt veröffentlicht und trat am 1. Januar 2025 in Kraft."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/demokratie-leben","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:42.385200+00:00","lastSeen":"2026-03-15T17:29:42.385200+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/demokratie-leben"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/demokratie-leben","crawledAt":"2026-03-15T17:29:42.385200Z","crawlId":"organizations-seeded-1773595782","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"ea9af2697391bd4b77a0395d22b37fa18dd206e4efdc6f6ab09b59ccae5f166c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:42.385200+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('79821979-8367-46d7-a7c5-b793c8c30e70', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-bundesaltenplan', 'active', NULL, '2026-03-15T17:29:42.878658+00:00', '{"id":"79821979-8367-46d7-a7c5-b793c8c30e70","title":"Richtlinien für den Bundesaltenplan","summary":{"de":"Mit diesen Richtlinien fördert das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend Projektträger, die dazu beitragen, ältere Menschen in ihrem selbstständigen und..."},"content":{"de":"Mit diesen Richtlinien fördert das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend Projektträger, die dazu beitragen, ältere Menschen in ihrem selbstständigen und gleichberechtigten Leben in der Gesellschaft zu unterstützen. Grundlegende und bedeutende Anliegen sind dabei die Gewährleistung von Schutz und Hilfe im Alter, die aktive Partizipation und Aktivierung der Potenziale von älteren Menschen sowie die Unterstützung von behinderten älteren Menschen für ihre selbstbestimmte Teilhabe am gesellschaftlichen Leben. In der Richtlinie für den Bundesaltenplan ist festgelegt, welche Vorhaben und Maßnahmen von seniorenpolitisch engagierten Akteurinnen und Akteuren vom Bundesministerium fürBildung, Familie, Senioren, Frauen und Jugend gefördert werden können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-bundesaltenplan","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:42.878658+00:00","lastSeen":"2026-03-15T17:29:42.878658+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-bundesaltenplan"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-bundesaltenplan","crawledAt":"2026-03-15T17:29:42.878658Z","crawlId":"organizations-seeded-1773595782","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0b035d68ec61b17fbf378f91f74af4b5ebd570e28c0d357826f8e025aeb49c78"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:42.878658+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f51da091-5f4a-4f97-bc73-2495ce9c4e15', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-familienfoerderrichtline-bund', 'active', NULL, '2026-03-15T17:29:43.417294+00:00', '{"id":"f51da091-5f4a-4f97-bc73-2495ce9c4e15","title":"Familienförderrichtlinien des Bundes","summary":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend gewährt Zuschüsse und Leistungen für laufende Zwecke an Träger und für Aufgaben der Familienpolitik (Projektförderung). Die..."},"content":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend gewährt Zuschüsse und Leistungen für laufende Zwecke an Träger und für Aufgaben der Familienpolitik (Projektförderung). Die Richtlinien sollen dazu beitragen, ein familienfreundliches Umfeld zu gestalten, in dem sich Familien nach eigenen Vorstellungen optimal entwickeln können. Der Vielfalt der familialen Lebensformen soll Rechnung getragen werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-familienfoerderrichtline-bund","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:43.417294+00:00","lastSeen":"2026-03-15T17:29:43.417294+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-familienfoerderrichtline-bund"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-familienfoerderrichtline-bund","crawledAt":"2026-03-15T17:29:43.417810Z","crawlId":"organizations-seeded-1773595783","c