INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b421bdcd-5a7d-4816-aec2-4831280a0f10', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-gleichstellungspolitische-vorhaben', 'active', NULL, '2026-03-15T17:29:43.881162+00:00', '{"id":"b421bdcd-5a7d-4816-aec2-4831280a0f10","title":"Förderrichtlinien des Bundes zu gleichstellungspolitischen Vorhaben","summary":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend hat die Aufgabe, die Gleichstellung von Frauen und Männern zu unterstützen. Schwerpunkte sind unter anderem die ökonomische..."},"content":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend hat die Aufgabe, die Gleichstellung von Frauen und Männern zu unterstützen. Schwerpunkte sind unter anderem die ökonomische Gleichstellung, Förderung von Erwerbstätigkeit von Frauen, Lohngerechtigkeit, Überwindung von Rollenstereotypen und gleiche Teilhabe in Politik, Wirtschaft und Gesellschaft. Die Förderrichtlinien legen fest, welche Vorhaben und Maßnahmen gefördert werden können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-gleichstellungspolitische-vorhaben","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:43.881162+00:00","lastSeen":"2026-03-15T17:29:43.881162+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-gleichstellungspolitische-vorhaben"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-gleichstellungspolitische-vorhaben","crawledAt":"2026-03-15T17:29:43.881162Z","crawlId":"organizations-seeded-1773595783","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"75668e119707c7b8ccddaa575ffaa76cfd1c13ddda9261516fc931d1ce140e9c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:43.881571+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5293ea35-d228-4e00-8f14-0dbe19e07efb', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-kinder-und-jugendplan-bund', 'active', NULL, '2026-03-15T17:29:44.420195+00:00', '{"id":"5293ea35-d228-4e00-8f14-0dbe19e07efb","title":"Richtlinien des Kinder- und Jugendplans des Bundes","summary":{"de":"Das Bundesjugendministerium regt als fachlich zuständige oberste Bundesbehörde die Tätigkeit der Kinder- und Jugendhilfe an und fördert diese, wenn sie von überregionaler Bedeutung ist und ihrer..."},"content":{"de":"Das Bundesjugendministerium regt als fachlich zuständige oberste Bundesbehörde die Tätigkeit der Kinder- und Jugendhilfe an und fördert diese, wenn sie von überregionaler Bedeutung ist und ihrer Art nach nicht durch ein Land allein wirksam gefördert werden kann (vgl. Paragraph 83 Absatz 1 Achtes Buch Sozialgesetzbuch - Kinder- und Jugendhilfe, SGB VIII). Diese Aufgabe erfüllt das Bundesjugendministerium mit dem im Jahr 1950 eingeführten Kinder- und Jugendplan des Bundes (KJP). Der Kinder- und Jugendplan ist das zentrale Förderinstrument der Kinder- und Jugendhilfe auf Bundesebene. Die Förderung aus dem KJP unterstützt die Leistungen und die Wahrnehmung anderer Aufgaben zugunsten junger Menschen und Familien nach § 2 SGB VIII und schafft Anregungen durch Sicherung, Stärkung und Weiterentwicklung der Kinder- und Jugendhilfe sowie durch Rahmenbedingungen für eine leistungsfähige bundeszentrale Infrastruktur der Kinder- und Jugendhilfe."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-kinder-und-jugendplan-bund","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:44.420195+00:00","lastSeen":"2026-03-15T17:29:44.420195+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-kinder-und-jugendplan-bund"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/foerderrichtlinien-kinder-und-jugendplan-bund","crawledAt":"2026-03-15T17:29:44.420195Z","crawlId":"organizations-seeded-1773595784","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0d3d666ec8bd536e3dda9904f2db34f5a89968ca3af59d403e6fd11627eb10c0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:44.420195+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('90b6377a-16ff-48cd-b207-e2bb236f511c', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/gewaltschutz-und-praevention', 'active', NULL, '2026-03-15T17:29:44.884678+00:00', '{"id":"90b6377a-16ff-48cd-b207-e2bb236f511c","title":"Förderrichtlinien des Bundes zu Gewaltschutz und -prävention im Rahmen der Gleichstellungspolitik","summary":{"de":"Für das Bundesfamilienministerium haben der Schutz von Frauen and Männern vor Gewalt und die Bekämpfung des Menschenhandels eine hohe Priorität. Mit der Istanbul-Konvention hat sich Deutschland..."},"content":{"de":"Für das Bundesfamilienministerium haben der Schutz von Frauen and Männern vor Gewalt und die Bekämpfung des Menschenhandels eine hohe Priorität. Mit der Istanbul-Konvention hat sich Deutschland verpflichtet, entsprechende politische Maßnahmen zu ergreifen, um dieses Ziel zu erreichen. Dazu gehört auch die Förderung der Arbeit von nichtstaatlichen Organisationen und der Zivilgesellschaft auf dem Gebiet des Gewaltschutzes. Die Förderrichtlinien legen fest, welche Vorhaben und Maßnahmen gefördert werden können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/gewaltschutz-und-praevention","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:44.884678+00:00","lastSeen":"2026-03-15T17:29:44.884678+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/gewaltschutz-und-praevention"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ausschreibungen-foerderung/foerderrichtlinien/gewaltschutz-und-praevention","crawledAt":"2026-03-15T17:29:44.884678Z","crawlId":"organizations-seeded-1773595784","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d70e15f5118986629f0e670b391ac3361219c1be572e7c5ab4694951098638a8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:44.884678+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
