INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('875d6d97-2028-4e75-a714-fe7880612adb', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien', 'active', NULL, '2026-03-15T16:00:03.471912+00:00', '{"id":"875d6d97-2028-4e75-a714-fe7880612adb","title":"Behörden, Beauftragte, Beiräte, Gremien und Kommissionen","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben Unabhängige Bundesbeauftragte gegen sexuellen Missbrauch Beauftragte für Akzeptanz sexueller und geschlechtlicher Vielfalt Beauftragter gegen Antiziganismus und für das Leben der Sinti und Roma Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Die ehemalige Bundesfrauenministerin und Bundestagspräsidentin Prof. Dr. Rita Süssmuth ist verstorben. Karin Prien und Nina Warken würdigten sie als großes Vorbild und Vorkämpferin für Frauenrechte und sozialen Zusammenhalt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:03.471912+00:00","lastSeen":"2026-03-15T16:00:03.471912+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien","crawledAt":"2026-03-15T16:00:03.471912Z","crawlId":"organizations-seeded-1773590403","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"f0f5322abc90c8a652040446bdaf43f26c31efe111704a1a54afa9e97824de0d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:03.471912+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a7616238-21f1-4141-a01d-bf9b9050975f', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antidiskriminierungsstelle', 'active', NULL, '2026-03-15T16:00:03.965692+00:00', '{"id":"a7616238-21f1-4141-a01d-bf9b9050975f","title":"Antidiskriminierungsstelle des Bundes","summary":{"de":"Die Antidiskriminierungsstelle des Bundes ist eine unabhängige Anlaufstelle für Menschen, die von Diskriminierung betroffen sind. Ihre Aufgaben sind im Antidiskriminierungsgesetz festgeschrieben."},"content":{"de":"Gesetzliche Aufgaben der Antidiskriminierungsstelle sind Information, Beratung und auf Wunsch Unterstützung von Betroffenen bei einer gütlichen Beilegung, ggf. Vermittlung ortsnaher Unterstützungsangebote, regelmäßige Vorlage eines Berichtes an den Deutschen Bundestag, verbunden mit Empfehlungen zur Beseitigung und Vermeidung von Benachteiligungen. Eine Zusammenarbeit ist gesetzlich vorgeschrieben mit den Beauftragten der Bundesregierung und des Deutschen Bundestages, deren Zuständigkeit berührt ist (zum Beispiel Integrationsbeauftragte, Behindertenbeauftragte), Nichtregierungsorganisationen sowie Einrichtungen, die auf europäischer, Bundes-, Landes- oder regionaler Ebene zum Schutz vor Benachteiligungen tätig sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antidiskriminierungsstelle","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:03.965692+00:00","lastSeen":"2026-03-15T16:00:03.965692+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antidiskriminierungsstelle"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antidiskriminierungsstelle","crawledAt":"2026-03-15T16:00:03.965692Z","crawlId":"organizations-seeded-1773590403","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"cfb45fa0ec171bcad90e6530d0146ba79d5de91aa82d95e823dc239e13414fcc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:03.967228+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1456b423-02c3-44c1-ae66-51bbd573ae63', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antiziganismusbeauftragter-der-bundesregierung', 'active', NULL, '2026-03-15T16:00:04.464164+00:00', '{"id":"1456b423-02c3-44c1-ae66-51bbd573ae63","title":"Beauftragter der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Kontaktformular Mithilfe des Kontaktformulars können Sie dem Beauftragten der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland eine Nachricht zukommen lassen. Mithilfe des Kontaktformulars können Sie dem Beauftragten der Bundesregierung gegen Antiziganismus und für das Leben der Sinti und Roma in Deutschland eine Nachricht zukommen lassen. Kooperationsverbund gegen Antiziganismus Der Kooperationsverbund besteht aus fünf zivilgesllschaftlichen Akteure. Sie vernetzen die diverse Akteursstruktur bundesweit. So soll eine tragfähige Basis für die Arbeit gegen Antiziganismus geschaffen und zu Teilhabe sowie Empowerment von Sinti und Roma beigetragen werden. Der Kooperationsverbund besteht aus fünf zivilgesllschaftlichen Akteure. Sie vernetzen die diverse Akteursstruktur bundesweit. So soll eine tragfähige Basis für die Arbeit gegen Antiziganismus geschaffen und zu Teilhabe sowie Empowerment von Sinti und Roma beigetragen werden. Michael Brand gedachte gemeinsam mit Vertreterinnen und Vertretern der Zivilgesellschaft und dem Holocaust-Überlebenden Dieter Flack der im Holocaust ermordeten Sinti und Roma Europas. Die Bund-Länder-Kommission zur Bekämpfung von Antiziganismus und für das Leben der Sinti und Roma diskutierte am 5. Dezember Herausforderungen, Ansätze und Empfehlungen zur Antiziganismusprävention in der schulischen Bildung."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antiziganismusbeauftragter-der-bundesregierung","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:04.464164+00:00","lastSeen":"2026-03-15T16:00:04.464164+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antiziganismusbeauftragter-der-bundesregierung"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/antiziganismusbeauftragter-der-bundesregierung","crawledAt":"2026-03-15T16:00:04.464164Z","crawlId":"organizations-seeded-1773590404","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6f076fe31acda0b130c35aab0a2d4827fd88d2946adb50c1feaa6578d8b11ceb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:04.464164+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2aa994dc-ce00-4735-85eb-1bfee6bb7a5c', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/ausschuss-fuer-mutterschutz', 'active', NULL, '2026-03-15T16:00:04.964729+00:00', '{"id":"2aa994dc-ce00-4735-85eb-1bfee6bb7a5c","title":"Ausschuss für Mutterschutz","summary":{"de":"Der Ausschuss für Mutterschutz besteht aus 15 Mitgliedern und befasst sich ehrenamtlich im Rahmen seiner gesetzlichen Zuständigkeit mit der Umsetzung des Mutterschutzgesetzes."},"content":{"de":"In § 30 des Mutterschutzgesetzes wurde mit der Reform 2018 die Bildung des Ausschusses für Mutterschutz festgelegt. Seine Aufgabe ist es, praxisgerechte Regeln zu entwickeln, die es Arbeitgeberinnen und Arbeitgebern erleichtern, bei der Umsetzung des Mutterschutzes den jeweils aktuellen Stand der Technik, Arbeitsmedizin und Hygiene sowie sonstige gesicherte wissenschaftliche Erkenntnisse zu berücksichtigen. Es gehört auch zu den Aufgaben des Ausschusses, Art, Ausmaß und Dauer einer möglichen unverantwortbaren Gefährdung einer schwangeren oder stillenden Frau und ihres Kindes am Arbeitsplatz zu ermitteln. Der Ausschuss für Mutterschutz arbeitet eng mit den arbeitsschutzrechtlichen Ausschüssen des Bundesarbeitsministeriums zusammen. Die Mitglieder werden alle vier Jahre vom Bundesfamilienministerium im Einvernehmen mit dem Bundesarbeitsministerium, dem Bundesgesundheitsministerium und dem Bundesforschungsministerium berufen. Alle weiterführenden Informationen über den Ausschuss und Informationen zum Mutterschutz finden Sie hier. Die Geschäftsstelle des Ausschusses ist im Bundesamt für Familie und zivilgesellschaftliche Aufgaben (BAFzA) angesiedelt. Die Geschäftsstelle unterstützt den Ausschuss für Mutterschutz sowohl organisatorisch als auch fachlich. Die Geschäftsstelle ist für Fragen oder die Kontaktaufnahme mit dem Ausschuss erreichbar: Bundesamt für Familie und zivilgesellschaftliche Aufgaben Geschäftsstelle Ausschuss für Mutterschutz"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/ausschuss-fuer-mutterschutz","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:04.964729+00:00","lastSeen":"2026-03-15T16:00:04.964729+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/ausschuss-fuer-mutterschutz"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/ausschuss-fuer-mutterschutz","crawledAt":"2026-03-15T16:00:04.964729Z","crawlId":"organizations-seeded-1773590404","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"782937c30a61cc2322443cea27b89cdb4d4cb60d9be954c3516e0a58524d5287"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:04.964729+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dfa26a59-32ff-472e-b83d-1a0a6c86f878', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bafza', 'active', NULL, '2026-03-15T16:00:05.466984+00:00', '{"id":"dfa26a59-32ff-472e-b83d-1a0a6c86f878","title":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben (BAFz A)","summary":{"de":"Das Bundesamt ist als selbstständige Bundesoberbehörde in vielen Themenbereichen tätig. Dazu zählt unter anderem die Durchführung des Bundesfreiwilligendienstes sowie Aufgaben im freiwilligen..."},"content":{"de":"Das Bundesamt ist als selbstständige Bundesoberbehörde in vielen Themenbereichen tätig. Dazu zählt unter anderem die Durchführung des Bundesfreiwilligendienstes sowie Aufgaben im freiwilligen Engagement. Am 1. Oktober 1973 wurde das Bundesamt für den Zivildienst (BAZ) in Köln errichtet. Das Bundesamt hatte die Aufgabe den Zivildienst nach dem Zivildienstgesetz durchzuführen. Am 1. Januar 1984 übernahm das Bundesamt als zusätzliche Aufgabe die Prüfung und Entscheidung von Anträgen auf Anerkennung als Kriegsdienstverweigerer nach dem Kriegsdienstverweigerungsgesetz. Mit der Aussetzung der allgemeinen Wehr- und Zivildienstpflicht zum 1. Juli 2011 und der gleichzeitigen Einführung eines Bundesfreiwilligendienstes wurde das Bundesamt in Bundesamt für Familie und zivilgesellschaftliche Aufgaben (BAFzA) umbenannt und zu einer modernen Dienstleistungsbehörde mit einem großen und vielseitigen Aufgabenspektrum umstrukturiert. Inzwischen nehmen die mehr als 1500 Beschäftigten des BAFzA vielfältige Aufgaben aus dem Geschäftsbereich des Bundesfamilienministeriums wahr. Dies sind vor allem die gesetzlichen Aufgaben der Durchführung des Bundesfreiwilligendienstgesetzes, des Familienpflegezeitgesetzes und des Hilfetelefongesetzes, die Aufgaben als Geschäftsstelle der Conterganstiftung und als Geschäftsstelle des Fonds Sexueller Missbrauch sowie die Umsetzung verschiedener nationaler und ESF-Förderprogramme aus den Bereichen Kinder- und Jugend-, Familien- und Seniorenförderung. Postanschrift: Bundesamt für Familie und zivilgesellschaftliche Aufgaben, 50964 Köln Besucheranschrift: An den Gelenkbogenhallen 2-6, 50679 Köln Telefon: 0221/ 3673-0 Fax: 0221/ 3673-4661 E-Mail: service@bafza.bund.de"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bafza","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:05.466984+00:00","lastSeen":"2026-03-15T16:00:05.466984+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bafza"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bafza","crawledAt":"2026-03-15T16:00:05.466984Z","crawlId":"organizations-seeded-1773590405","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"48abf4acbb1c28b89f8c2a976d9abd000c728b09ac7d22fe1ad861b75a5075ac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:05.466984+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ddfe6fd6-672e-4cf1-b7d7-c317b03a704b', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beauftragte-der-bundesregierung-fuer-die-akzeptanz-sexueller-und-geschlechtlicher-vielfalt', 'active', NULL, '2026-03-15T16:00:06.011571+00:00', '{"id":"ddfe6fd6-672e-4cf1-b7d7-c317b03a704b","title":"Beauftragte der Bundesregierung für die Akzeptanz sexueller und geschlechtlicher Vielfalt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Kontaktformular Mithilfe des Kontaktformulars können Sie der Beauftragten der Bundesregierung für die Akzeptanz sexueller und geschlechtlicher Vielfalt eine Nachricht zukommen lassen. Mithilfe des Kontaktformulars können Sie der Beauftragten der Bundesregierung für die Akzeptanz sexueller und geschlechtlicher Vielfalt eine Nachricht zukommen lassen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beauftragte-der-bundesregierung-fuer-die-akzeptanz-sexueller-und-geschlechtlicher-vielfalt","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:06.011571+00:00","lastSeen":"2026-03-15T16:00:06.011571+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beauftragte-der-bundesregierung-fuer-die-akzeptanz-sexueller-und-geschlechtlicher-vielfalt"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beauftragte-der-bundesregierung-fuer-die-akzeptanz-sexueller-und-geschlechtlicher-vielfalt","crawledAt":"2026-03-15T16:00:06.011571Z","crawlId":"organizations-seeded-1773590406","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"1c7731bfdc63f70edc0a95d95c79844eed57658e4e8d70e89288686288eda446"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:06.011571+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a5ceb186-9d68-4416-b3b8-9053f0e6b9bf', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-bundesfreiwilligendienst', 'active', NULL, '2026-03-15T16:00:06.462498+00:00', '{"id":"a5ceb186-9d68-4416-b3b8-9053f0e6b9bf","title":"Beirat für den Bundesfreiwilligendienst","summary":{"de":"Der Beirat für den Bundesfreiwilligendienst berät das Bundesfamilienministerium in Fragen des Bundesfreiwilligendienstes."},"content":{"de":"Der Beirat tagt jährlich und besteht aus insgesamt 23 Mitgliedern, die für die Dauer von vier Jahren berufen werden. Zu den Mitgliedern gehören Vertreterinnen und Vertreter der Zentralstellen des Bundesfreiwilligendienstes, der Kirchen, der Arbeitnehmer- und Arbeitgeberorganisationen, der Länder und der kommunalen Spitzenverbände sowie sieben Bundessprecherinnen und Bundessprecher der Freiwilligen. Aufgaben und Zusammensetzung sind in § 15 des Gesetzes über den Bundesfreiwilligendienst (BFDG) geregelt. Der Beirat gewährleistet durch seine Besetzung eine praxisorientierte Beratung auf einer breiten gesellschaftlichen Basis und kann dem Bundesfamilienministerium dadurch Impulse für die weitere Entwicklung des Bundesfreiwilligendienstes geben."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-bundesfreiwilligendienst","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:06.462498+00:00","lastSeen":"2026-03-15T16:00:06.462498+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-bundesfreiwilligendienst"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-bundesfreiwilligendienst","crawledAt":"2026-03-15T16:00:06.462498Z","crawlId":"organizations-seeded-1773590406","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"183051aaeb792983a2011b29ff103abbb30528c8cac68573dfd4e8adda113b50"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:06.462498+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('90781026-d6d4-4d4f-abf5-06e40a9f756e', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-familienfragen', 'active', NULL, '2026-03-15T16:00:06.975410+00:00', '{"id":"90781026-d6d4-4d4f-abf5-06e40a9f756e","title":"Wissenschaftlicher Beirat für Familienfragen","summary":{"de":"Der Wissenschaftliche Beirat für Familienfragen berät das Bundesfamilienministerium unabhängig und ehrenamtlich in allen Fragen der Familienforschung und Familienpolitik."},"content":{"de":"Der Beirat wurde in seiner jetzigen Form 1970 gegründet und ist damit eines der ältesten politischen Beratungsgremien der Bundesrepublik Deutschland. Er äußert sich eigenständig und unabhängig zu Schwerpunktfragen der Familienpolitik. Dazu zählen unter anderem Fragen zu Generationenbeziehungen, zur bildungspolitischen Bedeutung der Familie, zum Familienlastenausgleich oder auch zu Pflegefamilien und Migration. Die Bestimmung des jeweiligen Gegenstands der Beratungen nimmt der Beirat selbstständig vor, er trägt jedoch den Wünschen der Bundesfamilienministerin auf Beratung zu bestimmten Themen Rechnung. Im Beirat widmen sich aktuell 18 Wissenschaftlerinnen und Wissenschaftler aus verschiedenen Fachdisziplinen, die das Thema Familie als Arbeitsschwerpunkt haben, ehrenamtlich der wissenschaftlichen Politikberatung. Die Mitglieder werden auf Vorschlag des Beirats von der Bundesfamilienministerin berufen. Als neuestes Mitglied wurde Prof. Dr. Christina Boll vom Deutschen Jugendinstitut e.V. im Dezember 2024 in den Beirat berufen. Schuler-Harms, Prof. em. Dr., Margarete (Vorsitzende) Helmut Schmidt Universität/Universität der Bundeswehr Hamburg Professur für Öffentliches Recht, insbesondere Öffentliches Wirtschafts- und Umweltrecht Spieß, Prof. Dr., C. Katharina (Stellvertretende Vorsitzende) Bundesinstitut für Bevölkerungsforschung (BiB), Direktorin Johannes Gutenberg-Universität Mainz, Professur für Bevölkerungsökonomie Kreyenfeld, Prof. Dr., Michaela (Stellvertretende Vorsitzende) Hertie School Professor of Sociology"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-familienfragen","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:06.975410+00:00","lastSeen":"2026-03-15T16:00:06.975410+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-familienfragen"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/beirat-familienfragen","crawledAt":"2026-03-15T16:00:06.975410Z","crawlId":"organizations-seeded-1773590406","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c0e5cf4172eea2d9fc96b1208adac9c4bc19573e2f67fa6626061bffcda44d53"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:06.975410+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f63fa2f2-eda8-4658-b2c8-7c302819a758', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundesjugendkuratorium', 'active', NULL, '2026-03-15T16:00:07.468821+00:00', '{"id":"f63fa2f2-eda8-4658-b2c8-7c302819a758","title":"Bundesjugendkuratorium","summary":{"de":"Das Bundesjugendkuratorium berät die Bundesregierung in grundsätzlichen Fragen der Jugendhilfe und in Querschnittsfragen der Kinder- und Jugendpolitik."},"content":{"de":"Dem Bundesjugendkuratorium gehören bis zu 15 Sachverständige an, die für die Dauer einer Legislaturperiode des Deutschen Bundestages durch die Bundesministerin für Bildung, Familie, Senioren, Frauen und Jugend im Benehmen mit den anderen Bundesministerinnen und -ministern berufen werden. Das Kuratorium bezieht junge Menschen in geeigneter Weise in seine Beratungen ein. Die neue Berufung der Mitglieder des Bundesjugendkuratoriums erfolgt zeitnah. Aufgaben und Zusammensetzung sind im § 83 Abs. 2 SGB VIII Kinder- und Jugendhilfegesetz beziehungsweise in der Allgemeinen Verwaltungsvorschrift über das Bundesjugendkuratorium geregelt. Weitere Informationen zur Zusammensetzung des unabhängigen Beratungsgremiums sowie die veröffentlichten Stellungnahmen und Zwischenrufe können auf der Website des Bundesjugendkuratoriums eingesehen werdenDie Arbeit des Bundesjugendkuratoriums wird durch die vom Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend finanzierte Arbeitsstelle \"Kinder- und Jugendpolitik\" beim Deutschen Jugendinstitut e. V. unterstützt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundesjugendkuratorium","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:07.468821+00:00","lastSeen":"2026-03-15T16:00:07.468821+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundesjugendkuratorium"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundesjugendkuratorium","crawledAt":"2026-03-15T16:00:07.468821Z","crawlId":"organizations-seeded-1773590407","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7892e9a3900846df69159d9eabe3d7ca3312c4d68fd4723582b76c67b2033061"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:07.468821+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5aa4f8fd-0100-4aad-a159-377b9dbb774d', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundeszentrale-fuer-kinder-und-jugendmedienschutz-108190', 'active', NULL, '2026-03-15T17:29:49.599030+00:00', '{"id":"5aa4f8fd-0100-4aad-a159-377b9dbb774d","title":"Bundeszentrale für Kinder- und Jugendmedienschutz","summary":{"de":"Die Bundeszentrale für Kinder- und Jugendmedienschutz (BzKJ) ist eine selbstständige Bundesoberbehörde im Geschäftsbereich des Bundesministeriums für Familie, Senioren, Frauen und Jugend (BMFSFJ) mit Dienstsitz in Bonn. Ihre Aufgaben ergeben sich aus dem Jugendschutzgesetz (JuSchG)."},"content":{"de":"Am 14. Juli 1953 trat das vom Deutschen Bundestag zur Stärkung des Kinder- und Jugendmedienschutzes beschlossene \"Gesetz über die Verbreitung jugendgefährdender Schriften\" (GjS) in Kraft. Mit der Durchführung der dort normierten Aufgaben wurde die neu geschaffene \"Bundesprüfstelle für jugendgefährdende Schriften\" (BPjS) betraut. Mit dem Informations- und Kommunikationsdienste-Gesetz (IuKDG) vom 22. Juli 1997 wurde die Zuständigkeit der BPjS für Teledienste normiert. Die Gesetzesabkürzung GjS stand von da an für \"Gesetz über die Verbreitung jugendgefährdender Schriften und Medieninhalte\" (GjS). Mit dem Jugendschutzgesetz (JuSchG) vom 23. Juli 2002 (BGBl. I S. 2730) wurden das \"Gesetz zum Schutze der Jugend in der Öffentlichkeit\" (JÖSchG) und das GjS zusammengefasst. Neben Verfahrensänderungen wurde unter anderem die BPjS in \"Bundesprüfstelle für jugendgefährdende Medien\" (BPjM) umbenannt. Mit Inkrafttreten des Zweiten Gesetzes zur Änderung des Jugendschutzgesetzes am 1. Mai 2021 wurde die BPjM schließlich zur heutigen \"Bundeszentrale für Kinder- und Jugendmedienschutz\" (BzKJ) mit einem deutlich erweiterten Aufgabenbereich weiterentwickelt: Die BzKJ ist weiterhin zuständig für die Indizierung jugendgefährdender Medien und unterhält hierfür eine entsprechende Prüfstelle. Des Weiteren ist die BzKJ umfangreich zuständig für die Förderung der Weiterentwicklung des Kinder- und Jugendmedienschutzes. Sie erfüllt eine Orientierungsfunktion für Eltern, Fachkräfte sowie Kinder und Jugendliche selbst. Zudem wacht die bei ihr verortete Stelle zur Durchsetzung von Kinderrechten in digitalen Diensten (KidD) über die Einhaltung struktureller Vorsorgemaßnahmen bei Online-Plattformen (zum Beispiel sichere Voreinstellungen, Melde- und Abhilfeverfahren) und ist zur Verhängung hoher Bußgelder (bis zu 50 Millionen Euro) befugt. Die Zuständigkeit der KidD erstreckt sich auf Online-Plattformen mit Sitz oder einer Vertretung in Deutschland. Sie kann auch außerhalb der Europäischen Union (EU) tätig werden, wenn Anbieter aus Drittstaaten keine gesetzliche Vertretung in der EU benannt haben. Für sehr große Angebote ist die EU-Kommission zuständig. Gesetzliche Grundlage sind der europäische Digital Services Act (DSA), das nationale Digitale-Dienste-Gesetz (DDG) und das deutsche Jugendschutzgesetz (JuSchG). Weitere Informationen können unter www.bzkj.de sowie www.kidd.bund.de eingesehen werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundeszentrale-fuer-kinder-und-jugendmedienschutz-108190","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:49.599030+00:00","lastSeen":"2026-03-15T17:29:49.599030+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundeszentrale-fuer-kinder-und-jugendmedienschutz-108190"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bundeszentrale-fuer-kinder-und-jugendmedienschutz-108190","crawledAt":"2026-03-15T17:29:49.599030Z","crawlId":"organizations-seeded-1773595789","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"560709969f41ad78a81a584a0a0913dd8502208f28788bd2498c6e47f5d38aac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:49.599030+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e2c15843-27ee-4a61-a26f-67896ef330df', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bzkj', 'active', NULL, '2026-03-15T16:00:07.988852+00:00', '{"id":"e2c15843-27ee-4a61-a26f-67896ef330df","title":"Bundeszentrale für Kinder- und Jugendmedienschutz","summary":{"de":"Die Bundeszentrale für Kinder- und Jugendmedienschutz ist eine selbstständige Bundesoberbehörde im Geschäftsbereich des Bundesministeriums für Familie, Senioren, Frauen und Jugend (BMFSFJ). Ihre..."},"content":{"de":"Die Bundeszentrale für Kinder- und Jugendmedienschutz (BzKJ) ist eine selbstständige Bundesoberbehörde im Geschäftsbereich des Bundesministeriums für Familie, Senioren, Frauen und Jugend (BMFSFJ) mit Dienstsitz in Bonn. Ihre Aufgaben ergeben sich aus dem Jugendschutzgesetz (JuSchG). Am 14. Juli 1953 trat das vom Deutschen Bundestag zur Stärkung des Kinder- und Jugendmedienschutzes beschlossene \"Gesetz über die Verbreitung jugendgefährdender Schriften\" (GjS) in Kraft. Mit der Durchführung der dort normierten Aufgaben wurde die neu geschaffene \"Bundesprüfstelle für jugendgefährdende Schriften\" (BPjS) betraut. Mit dem Informations- und Kommunikationsdienste-Gesetz (IuKDG) vom 22. Juli 1997 wurde die Zuständigkeit der BPjS für Teledienste normiert. Die Gesetzesabkürzung GjS stand von da an für \"Gesetz über die Verbreitung jugendgefährdender Schriften und Medieninhalte\" (GjS). Mit dem Jugendschutzgesetz (JuSchG) vom 23. Juli 2002 (BGBl. I S. 2730) wurden das \"Gesetz zum Schutze der Jugend in der Öffentlichkeit\" (JÖSchG) und das GjS zusammengefasst. Neben Verfahrensänderungen wurde unter anderem die BPjS in \"Bundesprüfstelle für jugendgefährdende Medien\" (BPjM) umbenannt. Mit Inkrafttreten des Zweiten Gesetzes zur Änderung des Jugendschutzgesetzes am 1. Mai 2021 wurde die BPjM schließlich zur heutigen \"Bundeszentrale für Kinder- und Jugendmedienschutz\" (BzKJ) mit einem deutlich erweiterten Aufgabenbereich weiterentwickelt: Die BzKJ ist weiterhin zuständig für die Indizierung jugendgefährdender Medien und unterhält hierfür eine entsprechende Prüfstelle. Des Weiteren ist die BzKJ umfangreich zuständig für die Förderung der Weiterentwicklung des Kinder- und Jugendmedienschutzes. Sie erfüllt eine Orientierungsfunktion für Eltern, Fachkräfte sowie Kinder und Jugendliche selbst. Zudem wacht die bei ihr verortete Stelle zur Durchsetzung von Kinderrechten in digitalen Diensten (KidD) über die Einhaltung struktureller Vorsorgemaßnahmen bei Online-Plattformen (zum Beispiel sichere Voreinstellungen, Melde- und Abhilfeverfahren) und ist zur Verhängung hoher Bußgelder (bis zu 50 Millionen Euro) befugt. Die Zuständigkeit der KidD erstreckt sich auf Online-Plattformen mit Sitz oder einer Vertretung in Deutschland. Sie kann auch außerhalb der Europäischen Union (EU) tätig werden, wenn Anbieter aus Drittstaaten keine gesetzliche Vertretung in der EU benannt haben. Für sehr große Angebote ist die EU-Kommission zuständig. Gesetzliche Grundlage sind der europäische Digital Services Act (DSA), das nationale Digitale-Dienste-Gesetz (DDG) und das deutsche Jugendschutzgesetz (JuSchG)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bzkj","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:07.988852+00:00","lastSeen":"2026-03-15T16:00:07.988852+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bzkj"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/bzkj","crawledAt":"2026-03-15T16:00:07.988852Z","crawlId":"organizations-seeded-1773590407","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"0bc9b44956c448a407c06f1022045342c6e0ace394565d3f4b868aae4d010e03"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:07.988852+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6d72a56f-1b48-4305-ab3d-b68e96a9a9ee', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/geschichte-des-wissenschaftlichen-beirats-fuer-familienfragen-83724', 'active', NULL, '2026-03-15T17:29:50.047803+00:00', '{"id":"6d72a56f-1b48-4305-ab3d-b68e96a9a9ee","title":"Geschichte des Wissenschaftlichen Beirats für Familienfragen","summary":{"de":"Nach der Wahl zum zweiten Bundestag wurde 1953 als zusätzliches Ministerium das Bundesfamilienministerium geschaffen. Bereits 1954 berief der erste..."},"content":{"de":"Nach der Wahl zum zweiten Bundestag wurde 1953 als zusätzliches Ministerium das Bundesfamilienministerium geschaffen. Bereits 1954 berief der erste Familienminister der Bundesrepublik, Franz-Josef Wuermeling (CDU), einen mit zwölf Mitgliedern besetzten \"Wissenschaftlichen Beirat\". Den Vorsitz übernahm er selbst. Es war ein \"gemischter\" Beirat, dem neben Expertinnen für Eheberatung und Müttererholung Vertreter der Familienverbände und Wissenschaftler angehörten. 1959 erfolgte eine Erweiterung des Beirats auf zwanzig Mitglieder. Damit sollte nicht zuletzt eine stärkere Ausrichtung des Beirats auf eine wissenschaftlich fundierte Beratung erreicht werden. Neue Mitglieder waren unter anderem die späteren Professorinnen und Professoren Elisabeth Pfeil, Helga Schmucker, Willi Albers, Wilfrid Schreiber und Hermann Schubnell, aber auch die Professoren Oswald von Nell-Breuning und Gerhard Wurzbacher. Noch im selben Jahr verzichteten die Nicht-Wissenschaftler im Beirat freiwillig auf ihr Stimmrecht, um die Unabhängigkeit der wissenschaftlichen Mitglieder in Beiratsvoten zu gewährleisten. Die bis heute gültige Konstituierung des Wissenschaftlichen Beirats für Familienfragen beim damaligen Bundesministerium für Jugend, Familie und Gesundheit im Jahr 1970 fiel in die Zeit der Regierungsübernahme durch die Sozialliberale Koalition (ab 1969), in die Amtszeit der Familienministerin Käthe Strobel (SPD). Es war ein Zeitabschnitt, in dem auch die Vorbereitungsarbeiten stattfanden für den Zweiten Familienbericht, der unter dem Titel \"Erziehung als gesamtgesellschaftliche Aufgabe\" die Aufmerksamkeit der Politik und der Öffentlichkeit insbesondere auf die Sozialisierungs- und Platzierungsfunktion der Familie zu richten bemüht war. Neu war der Versuch, über die Familienberichterstattung die Wissenschaftlichkeit der Beratung von Politik voranzutreiben und die oft leidenschaftliche ideologische Debatte über Familie zu versachlichen. Ein Mehr an Rationalität in der Familienpolitik wurde gefordert durch eine Politik, die sich von emotionaler Beeinflussung trennt und sich auf wissenschaftliche Erkenntnisse stützt. Dazu bedürfe es einer Einigung auf die jeweils dringlichsten Zielsetzungen von Politik auf der Grundlage einer konkreten Analyse des aktuellen Handlungsbedarfs von Familien. Für beide Aufgabenstellungen wurde wissenschaftlicher Sachverstand und die völlige politische und wirtschaftliche Unabhängigkeit der Berater als unabdingbar erachtet. Beides glaubte man, am ehesten gewährleistet zu sehen durch ein Gremium von Wissenschaftlerinnen und Wissenschaftlern, das die Vielfalt seiner Kompetenzen selbst rekrutiert und seine in Kooperation miteinander erarbeiteten Stellungnahmen frei der Öffentlichkeit vortragen kann."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/geschichte-des-wissenschaftlichen-beirats-fuer-familienfragen-83724","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:50.047803+00:00","lastSeen":"2026-03-15T17:29:50.047803+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/geschichte-des-wissenschaftlichen-beirats-fuer-familienfragen-83724"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/geschichte-des-wissenschaftlichen-beirats-fuer-familienfragen-83724","crawledAt":"2026-03-15T17:29:50.047803Z","crawlId":"organizations-seeded-1773595790","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"e31767b766840deabc46ef26f70f1c2c6854ff56f14b3624404587a1b95e9267"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:50.047803+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1577c193-fa06-446b-bf59-a65d7dc57c81', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade', 'active', NULL, '2026-03-15T16:00:08.473001+00:00', '{"id":"1577c193-fa06-446b-bf59-a65d7dc57c81","title":"Koordinierungsstelle zur Umsetzung der \"UN-Dekade für Menschen afrikanischer Herkunft\"","summary":{"de":"Die Generalversammlung der Vereinten Nationen hat die \"UN-Dekade für Menschen afrikanischer Herkunft\" ausgerufen. Alle Mitgliedstaaten - darunter auch Deutschland - sind aufgerufen, die Rechte..."},"content":{"de":"Die Generalversammlung der Vereinten Nationen hat die \"UN-Dekade für Menschen afrikanischer Herkunft\" ausgerufen. Alle Mitgliedstaaten - darunter auch Deutschland - sind aufgerufen, die Rechte und die Anerkennung Menschen afrikanischer Herkunft zu fördern, Diskriminierung und Rassismus zu bekämpfen. Um einen Beitrag zur \"UN-Dekade für Menschen afrikanischer Herkunft\" zu leisten, hat die deutsche Bundesregierung eine Koordinierungsstelle zur Umsetzung der UN-Dekade eingerichtet. Mit der Koordinierungsstelle soll auf die Perspektiven und Lebenssituationen von Menschen afrikanischer Herkunft aufmerksam gemacht werden. Die \"UN-Dekade für Menschen afrikanischer Herkunft\" wurde 2015 durch die Generalversammlung der Vereinten Nationen ausgerufen. Die Mitgliedstaaten wurden damit aufgefordert, einen Beitrag zur Stärkung und Verwirklichung wirtschaftlicher, sozialer, kultureller und politischer Rechte von Schwarzen, afrikanischen und afrodiasporischen Menschen und deren gesellschaftlicher Teilhabe zu leisten. Die Bundesregierung hat sich im Rahmen des Kabinettsausschusses zur Bekämpfung von Rechtsextremismus und Rassismus zur Einrichtung einer Koordinierungsstelle zur Umsetzung der UN-Dekade verpflichtet. Das Bundesgleichstellungsministerium hat die Koordinierungsstelle gemeinsam mit dem Bundesministerium des Innern und für Heimat und der Beauftragten der Bundesregierung für Migration, Flüchtlinge und Integration am 25. Februar 2022 offiziell eingerichtet. Mit der Schaffung einer Koordinierungsstelle zur nationalen Unterstützung/Umsetzung der \"UN-Dekade für Menschen afrikanischer Herkunft\" möchte die Bundesregierung die verbleibende Zeit der Dekade nutzen, um den Fokus auf besondere Fragestellungen zur spezifischen Situation von Menschen afrikanischer Herkunft zu legen und um themenbezogene Aktivitäten der Bundesregierung, der Länder und weiterer Akteure, insbesondere der Zivilgesellschaft und der Wissenschaft zu bündeln. Die Koordinierungsstelle soll in den nächsten drei Jahren Veranstaltungen und Fachgespräche durchführen, die auf die Perspektiven und Lebenssituationen von Menschen afrikanischer Herkunft aufmerksam machen, Anti-Schwarzen Rassismus und damit zusammenhängende Diskriminierung in Gesellschaft und Strukturen adressieren und dieser entgegenwirken sowie das Empowerment von und für die Schwarze Community befördern. Ziel ist es ebenso, zu einer besseren Kenntnis und größeren Achtung der Vielfalt des Erbes und der Kultur von Menschen afrikanischer Herkunft beizutragen. Beides stellt eine Voraussetzung für die erfolgreiche Bekämpfung von Rassismus und Diskriminierung gegenüber Menschen afrikanischer Herkunft dar. Das Aktivitätenprogramm der UN-Dekade wird dabei die Arbeit der Koordinierungsstelle leiten. Die Koordinierungsstelle zur UN-Dekade soll eng mit Menschen afrikanischer Herkunft und Selbstorganisationen insbesondere aus der Schwarzen Community zusammenarbeiten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:08.473001+00:00","lastSeen":"2026-03-15T16:00:08.473001+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade","crawledAt":"2026-03-15T16:00:08.473001Z","crawlId":"organizations-seeded-1773590408","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"e4de13343d9a7f853ff735f3f54cc40aaefd650430299b15cf1282b54c806a54"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:08.473001+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c3409afc-500f-475d-8503-1c2c14ce2e4c', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade/der-beirat-der-koordinierungsstelle-223218', 'active', NULL, '2026-03-15T17:29:50.570510+00:00', '{"id":"c3409afc-500f-475d-8503-1c2c14ce2e4c","title":"Der Beirat der Koordinierungsstelle","summary":{"de":"Um die Belange von Menschen afrikanischer Herkunft stärker in den Fokus zu rücken, ist eine Koordinierungsstelle eingerichtet worden. Sie besteht aus einem Beirat, dem Vertreterinnen und Vertreter Schwarzer Initiativen angehören."},"content":{"de":"Menschen afrikanischer Herkunft sind häufig Rassismus, Vorurteilen und Diskriminierung ausgesetzt. Um ihre Rechte, ihre Anerkennung und ihre gesellschaftliche Teilhabe zu fördern, hat die Generalversammlung der Vereinten Nationen die \"UN-Dekade für Menschen afrikanischer Herkunft\" ausgerufen. Die Mitgliedstaaten - darunter auch Deutschland - sind aufgerufen, die Ziele der Dekade (2015 bis 2024) umzusetzen. Damit die Umsetzung neue Impulse bekommt, hat die Bundesregierung am 25. Februar 2022 eine Koordinierungsstelle eingerichtet. Sie besteht aus einem Beirat, dem Vertreterinnen und Vertreter Schwarzer zivilgesellschaftlicher Organisationen angehören. Der Beirat hat die Aufgabe, Themen und Arbeitsschwerpunkte zur Umsetzung der UN-Dekade festzulegen. Bei der Umsetzung der Aktivitäten wird der Beirat von einer Geschäftsstelle beim Bundesamt für Familie und zivilgesellschaftliche Aufgaben (BAFzA) unterstützt. Kompetenznetzwerk Anti-Schwarzer Rassismus (bestehend aus Each One Teach One e.V., Initiative Schwarze Menschen in Deutschland e.V. und Zentralrat der afrikanischen Gemeinde in Deutschland e.V.) Bundesministerium für Familie, Senioren, Frauen und Jugend Beauftragte der Bundesregierung für Migration, Flüchtlinge und Integration Am 3. Juni 2022 kam der Beirat zu einem Treffen im Bundeskanzleramt zusammen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade/der-beirat-der-koordinierungsstelle-223218","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:50.570510+00:00","lastSeen":"2026-03-15T17:29:50.570510+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade/der-beirat-der-koordinierungsstelle-223218"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/un-dekade/der-beirat-der-koordinierungsstelle-223218","crawledAt":"2026-03-15T17:29:50.570510Z","crawlId":"organizations-seeded-1773595790","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"46140636c27fab938817a806e75e247791563426e35f5e73f65fa272aeb0e622"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:50.570510+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e30faa13-b960-48bc-af7f-fa85f9a19e25', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengige-beauftragte', 'active', NULL, '2026-03-15T16:00:08.971205+00:00', '{"id":"e30faa13-b960-48bc-af7f-fa85f9a19e25","title":"Unabhängige Bundesbeauftragte gegen sexuellen Missbrauch von Kindern und Jugendlichen","summary":{"de":"Die Unabhängige Bundesbeauftragte gegen sexuellen Missbrauch von Kindern und Jugendlichen (UBSKM) ist das Amt der Bundesregierung für die Anliegen von Betroffenen und deren Angehörigen und für..."},"content":{"de":"Die Unabhängige Bundesbeauftragte gegen sexuellen Missbrauch von Kindern und Jugendlichen (UBSKM) ist das Amt der Bundesregierung für die Anliegen von Betroffenen und deren Angehörigen und für alle, die sich gegen sexuelle Gewalt engagieren. Die Unabhängige Bundesbeauftragte gegen sexuellen Missbrauch von Kindern und Jugendlichen (UBSKM) ist das Amt der Bundesregierung für die Anliegen von Betroffenen und deren Angehörigen, für Expertinnen und Experten aus Praxis und Wissenschaft sowie für alle Menschen in Politik und Gesellschaft, die sich gegen sexuelle Gewalt engagieren. Im März 2022 wurde Kerstin Claus das Amt der Unabhängigen Bundesbeauftragten übertragen. Seit dem 1. Juli 2025 ist das Amt durch das \" Gesetz zur Stärkung der Strukturen gegen sexuelle Gewalt an Kindern und Jugendlichen\" (BGBl. 2025 I Nr. 107 vom 08. April 2025) gesetzlich verankert. Kerstin Claus wurde 1969 in München geboren, ist Journalistin und seit 2015 in der Politik- und Strategieberatung im Themenbereich sexualisierter Gewalt gegen Kinder und Jugendliche tätig. Bevor sie das neue Amt antrat, war sie Mitglied im Betroffenenrat des UBSKM. Claus ist als Unabhängige Bundesbeauftragte nicht weisungsgebunden. Organisatorisch, personell und finanziell erfolgt die Anbindung beim Bundesfamilienministerium. Der Unabhängigen Bundesbeauftragten ist ein Arbeitsstab zugeordnet. Eintreten für die Belange und die Beteiligung von Menschen, die in ihrer Kindheit oder Jugend sexuelle Gewalt oder Ausbeutung erfahren oder erfahren haben, Entwicklung von Vorschlägen und Maßnahmen zur Verbesserung der Prävention und Intervention, Förderung des Zugangs zu Hilfe- und Unterstützungsleistungen,"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengige-beauftragte","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:08.971205+00:00","lastSeen":"2026-03-15T16:00:08.971205+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengige-beauftragte"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengige-beauftragte","crawledAt":"2026-03-15T16:00:08.971205Z","crawlId":"organizations-seeded-1773590408","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"151fe96a2cc62830cab11b55e8abd037860e03232bca7437ddf0512d02922264"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:08.971205+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('23ef060c-3aec-4a74-8d99-dafa5783dd54', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengiger-beirat-fuer-die-vereinbarkeit-von-pflege-und-beruf-108568', 'active', NULL, '2026-03-15T16:11:43.243297+00:00', '{"id":"23ef060c-3aec-4a74-8d99-dafa5783dd54","title":"Unabhängiger Beirat für die Vereinbarkeit von Pflege und Beruf","summary":{"de":"Ein unabhängiger Beirat befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Mehr Informationen."},"content":{"de":"Der unabhängige Beirat für die Vereinbarkeit von Pflege und Beruf besteht aus 21 Mitgliedern und befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Der Beirat für die Vereinbarkeit von Pflege und Beruf wurde 2015 durch das Bundesfamilienministerium eingesetzt. Er befasst sich als nicht öffentliches Gremium mit allgemeinen und spezifischen Fragen zur Vereinbarkeit von Pflege und Beruf. Als weitere Hauptaufgabe begleitet er die Umsetzung der einschlägigen gesetzlichen Regelungen - insbesondere des Pflegezeitgesetzes und des Familienpflegezeitgesetzes - und berät über deren Auswirkungen. Die Auswahl und Bearbeitung von Themenstellungen erfolgt selbstständig durch den Beirat, es können aber auch Themen zur Beratung durch das Bundesfamilienministerium vorgegeben werden. Die Beiratsmitglieder legen dem Bundesfamilienministerium alle vier Jahre einen Bericht vor. Den ersten Bericht hat der Beirat im Juni 2019 an das Bundesfamilienministerium übergeben. Der Bericht enthält Handlungsempfehlungen zur Weiterentwicklung der gesetzlichen Regelungen sowie eine Bestandsaufnahme bezüglich des Pflegezeitgesetzes und des Familienpflegezeitgesetzes. Zudem werden die im Beirat behandelten Themenstellungen und Ergebnisse beschrieben und Erkenntnisse von Sachverständigen, Auswertungen von Fachliteratur, Statistiken und Datensätzen sowie der Rechtsprechung dargelegt. Den zweiten Bericht hat der Beirat im Juli 2023 an das Bundesfamilienministerium übergeben. Kern des Berichts sind zukunftsweisende Empfehlungen zur Ausgestaltung einer praxistauglichen Familienpflegezeit und zur Einführung eines Familienpflegegelds für häuslich pflegende Erwerbstätige. Darüber hinaus enthält der Bericht wichtige Ausführungen zu Pflegenden in kleinen und mittelständischen Unternehmen und auch zu den herausfordernden Vereinbarkeitserfordernissen von Angehörigen, die pflegebedürftige Kinder, Jugendliche und junge Erwachsene versorgen. Der Beirat besteht aus 21 Mitgliedern, die sich aus Vertreterinnen oder Vertretern der fachlich betroffenen Interessenverbände, der Gewerkschaften, der Arbeitgeber, der Wohlfahrtsverbände und der Seniorenorganisationen sowie der sozialen und der privaten Pflege-Pflichtversicherung zusammensetzen. Des Weiteren gehören dem Beirat Wissenschaftlerinnen und Wissenschaftler, Vertreterinnen und Vertreter der Konferenz der Ministerinnen und Minister, Senatorinnen und Senatoren für Jugend und Familie, der Konferenz der Ministerinnen und Minister, Senatorinnen und Senatoren für Arbeit und Soziales sowie der kommunalen Spitzenverbände an. Die Vorsitzende des Beirats ist die Sozialwissenschaftlerin und Gerontologin Frau Prof. Dr. Annette Franke, stellvertretender Vorsitzender ist der Familien- und Gesundheitssoziologe Prof. Dr. Christian Deindl. Eine detaillierte Übersicht zur Arbeit des Beirates finden Sie hier. Unter anderem ist dort auch der erste Bericht des Beirates in zwei Sprachen verfügbar."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengiger-beirat-fuer-die-vereinbarkeit-von-pflege-und-beruf-108568","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:11:43.243297+00:00","lastSeen":"2026-03-15T16:11:43.243297+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengiger-beirat-fuer-die-vereinbarkeit-von-pflege-und-beruf-108568"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/behoerden-beauftragte-beiraete-gremien/unabhaengiger-beirat-fuer-die-vereinbarkeit-von-pflege-und-beruf-108568","crawledAt":"2026-03-15T16:11:43.243297Z","crawlId":"organizations-seeded-1773591103","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"10d5084f5b004080823c649efbb1160e1094fdf9597ed127ec6254ca00c37133"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:11:43.243297+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('844be8b1-bbfd-40d2-8b79-8bd7023c0fae', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung', 'active', NULL, '2026-03-15T16:00:09.475426+00:00', '{"id":"844be8b1-bbfd-40d2-8b79-8bd7023c0fae","title":"Berichte der Bundesregierung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:09.475426+00:00","lastSeen":"2026-03-15T16:00:09.475426+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung","crawledAt":"2026-03-15T16:00:09.475426Z","crawlId":"organizations-seeded-1773590409","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7ae2ebfe33523a234e101152d98e5d5c2a181ad29d4ec95a03b4e4160ca10bda"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:09.475426+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ad027182-12e6-484e-98a8-17b2e6614232', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/engagementbericht-250332', 'active', NULL, '2026-03-15T17:29:51.565805+00:00', '{"id":"ad027182-12e6-484e-98a8-17b2e6614232","title":"Vierter Engagementbericht","summary":{"de":"Nachhaltige Engagementpolitik unterstützen und Handlungsempfehlungen geben: Der Vierte Engagementbericht widmet sich dem Thema \"Zugangschancen zum freiwilligen Engagement\"."},"content":{"de":"Die Bundesregierung legt laut Beschluss des Deutschen Bundestags vom 19. März 2009 (Drucksache 16/11774) einmal in jeder Wahlperiode einen Bericht zum freiwilligen Engagement in Deutschland vor, der von einer unabhängigen Sachverständigenkommission erarbeitet wird. Dieser Bericht soll eine nachhaltige Engagementpolitik unterstützen und Handlungsempfehlungen geben. Das Thema des Vierten Engagementberichts lautet: \"Zugangschancen zum freiwilligen Engagement\". In Deutschland sind rund 29 Millionen Menschen freiwillig und ehrenamtlich engagiert. Ihr freiwilliges Engagement findet in allen gesellschaftlichen Bereichen statt, im Sport, in der Musik und Kultur, im Umwelt- und Naturschutz ebenso wie im sozialen Bereich und in der Selbsthilfe, im Rettungswesen, bei der Feuerwehr und dem Katastrophenschutz, in Kirchen und Religionsgemeinschaften, in der Selbstvertretung marginalisierter Gruppen bis hin zur Jugend-, Bildungs- und Seniorenarbeit. Dabei üben die Engagierten ihre freiwillige Tätigkeit in vielfältigen Formen aus, eher ungebunden in selbstorganisierten Gruppen und Initiativen oder als formales \"Ehrenamt\" in Vereinen und Verbänden bis hin zum digitalen Engagement. Freiwilliges Engagement ist ein zentraler Baustein für eine funktionierende Gesellschaft und ihren Zusammenhalt. Es stellt eine wichtige Form der gesellschaftlichen Teilhabe dar und ist von hoher Bedeutung für die soziale Integration. Aufnahme und Ausübung eines freiwilligen Engagements müssen unabhängig von Alter, Geschlecht, sexueller Orientierung, Bildungshintergrund, sozioökonomischem Status oder Herkunft individuell möglich sein, wenn Menschen dies wünschen. Der Vierte Engagementbericht analysiert differenziert, wie die Zugangsmöglichkeiten zum Engagement sich tatsächlich darstellen. Der Vierte Engagementbericht zeigt, dass soziale Ungleichheiten wie Unterschiede im Einkommen, in der Schulbildung oder ein Migrationshintergrund die Beteiligungsmöglichkeiten am freiwilligen Engagement mit beeinflussen. Bestehende Ungleichheiten werden im Engagement oft noch verstärkt. Es ist von allgemeinem Interesse zu verstehen, warum bestimmte gesellschaftliche Gruppen weniger häufig am freiwilligen Engagement beteiligt sind als andere. Hier setzt der Vierte Engagementbericht an: Er beleuchtet die Zugangswege und Zugangschancen zur Aufnahme eines Engagements und untersucht die Hindernisse, die einen Zugang für weniger privilegierte Gruppen erschweren oder verhindern. Im Bericht werden diese Hindernisse als \"Schwellen\" bezeichnet, weil sie oft unsichtbar, aber auch nicht unüberwindbar sind. Der Bericht untersucht diese verschiedenen Schwellen und erklärt, wie sie wirken. Die Berichtskommission hat dreizehn \"Schwellen\" herausgearbeitet, die den Zugang zu einem freiwilligen Engagement erschweren oder behindern können. Beispiele für solche Schwellen: Fehlen von Zeit(autonomie) und Geld, bürokratische und rechtliche Hürden, fehlende Räume für Engagement, ausgrenzende Organisationskulturen und Ansprache, fehlende Anerkennung und Einbeziehung informeller bzw. neuartiger Engagementstrukturen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/engagementbericht-250332","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:51.565805+00:00","lastSeen":"2026-03-15T17:29:51.565805+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/engagementbericht-250332"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/engagementbericht-250332","crawledAt":"2026-03-15T17:29:51.565805Z","crawlId":"organizations-seeded-1773595791","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"327dd0a94b23171877e5fa6115eb59e0b6df3148ef34f16a15daf6f1d0f16d42"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:51.565805+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('22d228fb-0922-4a7f-ab38-e3c1bb7894f2', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/kinder-und-jugendbericht-159966', 'active', NULL, '2026-03-15T17:29:52.066873+00:00', '{"id":"22d228fb-0922-4a7f-ab38-e3c1bb7894f2","title":"17. Kinder- und Jugendbericht","summary":{"de":"Bei aller Vielfalt haben junge Menschen eines gemeinsam: Um gut aufwachsen zu können, benötigen sie Orientierung und Sicherheit. Der 17. Kinder- und Jugendbericht analysiert die Situation junger Menschen und die Bestrebungen und Leistungen der Kinder- und Jugendhilfe."},"content":{"de":"In Deutschland leben derzeit rund 22 Millionen junge Menschen - Kinder, Jugendliche und junge Erwachsene. Sie wachsen unter verschiedenen Bedingungen auf, haben vielfältige Interessen und Bedürfnisse und gehen unterschiedliche Wege. Um die Rahmenbedingungen für ihr Aufwachsen und für die Arbeit der Kinder- und Jugendhilfe zu verbessern, benötigt die Bundesregierung aussagekräftige Analysen und fundierte Vorschläge. Am 18. September 2024 hat die damalige Bundesjugendministerin Lisa Paus gemeinsam mit Mitgliedern der Sachverständigenkommission den 17. Kinder- und Jugendbericht vorgestellt. Das Bundeskabinett hatte zuvor eine Stellungnahme dazu abgegeben. Beide Dokumente gingen anschließend dem Deutschen Bundestag und dem Bundesrat zu. Gemäß § 84 SGB VIII legt die Bundesregierung dem Deutschen Bundestag und dem Bundesrat in jeder Legislaturperiode einen Kinder- und Jugendbericht vor und nimmt dazu Stellung. Mit der Ausarbeitung des Berichtes wird jeweils eine unabhängige Sachverständigenkommission beauftragt. Der 17. Kinder- und Jugendbericht ist, wie jeder dritte Bericht, ein Gesamtbericht und liefert ein umfassendes Bild von der Lage der jungen Generation und der Situation der Kinder- und Jugendhilfe. Bei der Erstellung des Berichts hat die Sachverständigenkommission großen Wert auf eine umfängliche Beteiligung junger Menschen gelegt. Insgesamt hat sie rund 5400 junge Menschen zwischen fünf und 27 Jahren zu verschiedenen Fragestellungen beteiligt. Die heutige junge Generation ist so vielfältig wie nie zuvor. Bei aller Vielfalt haben junge Menschen eines gemeinsam: Für gutes Aufwachsen benötigen sie Orientierung und Sicherheit. Das ist gerade in der aktuellen dynamischen und unsicheren Zeit besonders wichtig. Kinder, Jugendliche und junge Erwachsene stehen vor komplexen Herausforderungen, vor allem durch eine alternde Gesellschaft, globale Fluchtmigration, den Verlust der vermeintlichen Selbstverständlichkeit von Frieden in Europa, eine Demokratie unter Druck, den Klimawandel, zunehmende Digitalisierung und Mediatisierung und die Nachwirkungen der Pandemie. Wie stark junge Menschen von diesen Entwicklungen betroffen sind, unterscheidet sich sehr - je nachdem, unter welchen Bedingungen und mit welchen Zugehörigkeiten und Zuschreibungen sie aufwachsen. Viele junge Menschen haben, so formuliert es die Berichtskommission, nach wie vor \"gute Gründe\" für Zuversicht. Der Bericht zeigt aber auch: Das Zukunftsvertrauen ist insgesamt gesunken. Zuversicht braucht Vertrauen! Politik und Gesellschaft sowie speziell die Kinder- und Jugendhilfe sind gefragt, auch in schwierigen Zeiten mit knappen Kassen jungen Menschen vertrauenswürdige Rahmenbedingungen mit starken und Angeboten und Leistungen zu bieten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/kinder-und-jugendbericht-159966","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:52.066873+00:00","lastSeen":"2026-03-15T17:29:52.066873+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/kinder-und-jugendbericht-159966"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/kinder-und-jugendbericht-159966","crawledAt":"2026-03-15T17:29:52.066873Z","crawlId":"organizations-seeded-1773595792","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"90273aa8a4147fa6d290adb5109899dc32ba6426397a468c2e09560642f7ef3a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:52.066873+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('82872dac-6177-4cf9-8032-c4d973e08f8b', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/neunter-altersbericht-251456', 'active', NULL, '2026-03-15T17:29:52.584735+00:00', '{"id":"82872dac-6177-4cf9-8032-c4d973e08f8b","title":"Neunter Altersbericht: Vielfalt der Potenziale und Ungleichheit der Teilhabechancen","summary":{"de":"Vielfalt anerkennen und Ungleichheiten abbauen: Der Neunte Altersbericht zeigt die unterschiedlichen Lebenssituationen älterer Menschen auf und untersucht ihre Teilhabechancen."},"content":{"de":"In Deutschland leben rund 18,7 Millionen Menschen im Alter von 65 Jahren und älter - und diese Bevölkerungsgruppe wächst. Sie steht vor vielen Herausforderungen, aber auch vor Chancen, die mit dem demografischen Wandel und gesellschaftlichen Veränderungen einhergehen. Dabei ist das Alter(n) in Deutschland von großer Vielfalt geprägt. Um die Rahmenbedingungen älterer Menschen für ein selbstbestimmtes und aktives Leben im Alter zu verbessern, stellt der Neunte Altersbericht die Vielfalt und Unterschiedlichkeit der Lebenssituationen älterer Menschen in Deutschland dar und untersucht, ob die Möglichkeiten zur gesellschaftlichen Teilhabe für alle in gleichem Maße gegeben sind. Darüber hinaus gibt er Anregungen dazu, wie die Teilhabechancen älterer Menschen gesichert und gestärkt werden können. Der Bericht besteht aus zwei Teilen, dem Sachverständigenbericht und der Stellungnahme der Bundesregierung. Die Altersberichte gehen auf einen Beschluss des Deutschen Bundestages vom 24. Juni 1994 (Drucksache 12/7992) zurück, der für jede Legislaturperiode einen Bericht zu einem alterspolitischen Schwerpunktthema fordert. Die Erstellung des Berichts erfolgt durch eine unabhängige Altersberichtskommission. Altern ist vielfältig: Um Altersdiskriminierung abzubauen, ist es wichtig, sich der Unterschiedlichkeit der Lebenssituationen und der Diversität älterer Menschen bewusst zu machen und anzuerkennen, dass trotz dieser Vielfalt alle älteren Menschen den gleichen Anspruch auf Teilhabechancen haben. Teilhabechancen, das heißt die Möglichkeiten, das eigene Leben im Alter selbstbestimmt zu gestalten, sind in Abhängigkeit von Alter, Bildung, Einkommen, Geschlecht, Migrationsstatus, sexueller Orientierung und geschlechtlicher Identität sozial ungleich verteilt. Die Überschneidung sozialer Ungleichheiten (Intersektionalität) kann zu gravierenden Benachteiligungen führen. Sie verstärken sich im Lebenslauf, sie verhindern Teilhabe im Alter und beeinträchtigen damit individuelle Potenziale und gesamtgesellschaftliche Chancen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/neunter-altersbericht-251456","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:52.584735+00:00","lastSeen":"2026-03-15T17:29:52.584735+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/neunter-altersbericht-251456"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/neunter-altersbericht-251456","crawledAt":"2026-03-15T17:29:52.584735Z","crawlId":"organizations-seeded-1773595792","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f106c9e400158a974f0c73165489c2ff7b167d301363d294593cb283ca8c46d3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:52.584735+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bc4a8844-d7e2-48c8-916b-28a5d78f24d7', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/vierter-gleichstellungsbericht-257274', 'active', NULL, '2026-03-15T17:29:53.071223+00:00', '{"id":"bc4a8844-d7e2-48c8-916b-28a5d78f24d7","title":"Vierter Gleichstellungsbericht","summary":{"de":"Die Gleichstellungsberichte der Bundesregierung informieren regelmäßig über den Stand der Gleichstellung von Frauen und Männern in Deutschland. Der Vierte Gleichstellungsbericht widmet sich der \"Gleichstellung in der sozial-ökologischen Transformation\"."},"content":{"de":"Die Gleichstellungsberichte der Bundesregierung informieren regelmäßig über den Stand der Gleichstellung von Frauen und Männern in Deutschland. Der Vierte Gleichstellungsbericht widmet sich der \"Gleichstellung in der sozial-ökologischen Transformation\". Die Folgen des Klimawandels und die Maßnahmen zu seiner Abmilderung werden sich unterschiedlich auf die Lebensrealitäten von Menschen auswirken. Ein entscheidender Faktor ist das Geschlecht. Deshalb muss die Gleichstellung der Geschlechter bei der Betrachtung und Gestaltung der sozial-ökologischen Transformation mitgedacht werden. Unter dem Begriff \"Sozial-ökologische Transformation\" werden zusammengefasst: die politischen Maßnahmen zur Eindämmung oder Anpassung an den Klimawandel die damit verbundenen notwendigen oder zwangsläufigen wirtschaftlichen und sozialen Veränderungen Die Sachverständigenkommission übergab ihr Gutachten zum Vierten Gleichstellungsbericht am 7. Januar 2025 an Lisa Paus. Die ökologische Krise ist in ihren Ursachen und Auswirkungen eng mit strukturellen Ungleichheiten verbunden und überschneidet sich dadurch mit Gleichstellungsfragen. Die bestehenden Ungleichheiten - unter anderem zwischen den Geschlechtern - in Verbindung mit anderen Dimensionen der Ungleichheit bestimmen, wie stark die Menschen von den Folgen der ökologischen Krise betroffen sein werden und in welchem Maße sie sich dagegen schützen können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/vierter-gleichstellungsbericht-257274","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:53.071223+00:00","lastSeen":"2026-03-15T17:29:53.071223+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/vierter-gleichstellungsbericht-257274"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/vierter-gleichstellungsbericht-257274","crawledAt":"2026-03-15T17:29:53.071223Z","crawlId":"organizations-seeded-1773595793","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"e51bb8bb1e555a0daae14b970bf92430e5eda82933fda57cf16dbc7857a0461f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:53.071223+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9a1f3df2-59e9-4a3a-9a6b-f519cf663e13', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/zehnter-familienbericht-253668', 'active', NULL, '2026-03-15T17:29:53.593092+00:00', '{"id":"9a1f3df2-59e9-4a3a-9a6b-f519cf663e13","title":"Zehnter Familienbericht","summary":{"de":"Die Familienberichte der Bundesregierung beleuchten regelmäßig die Situation von Familien in Deutschland. Der zehnte Familienbericht widmet sich der \"Unterstützung allein- und getrennterziehender Eltern und ihrer Kinder\"."},"content":{"de":"Allein- und Getrennterziehende sind eine weit verbreitete Familienform: Für das Jahr 2023 weist das Statistische Bundesamt 1,69 Millionen Alleinerziehende mit Kindern unter 18 Jahren im Haushalt aus. Dies entspricht einem Anteil von 20 Prozent an allen Familienformen. Weitere 12 Prozent entfallen auf nichteheliche Lebensgemeinschaften mit Kindern. Der Anteil der Ehepaare mit Kindern liegt bei 68 Prozent. 2,5 Millionen Kinder, das sind 17 Prozent aller Kinder, leben in Haushalten von Alleinerziehenden. Familie und Familienleben sind sehr vielfältig. Das gilt auch für die Gruppe der getrenntlebenden Familien, Allein- und Getrennterziehenden. Um passgenaue Unterstützung leisten zu können und gerechte Zugangschancen in unserer Gesellschaft zu schaffen, muss Familienpolitik die unterschiedlichen Lebenslagen und Bedarfe gut kennen. Der Deutsche Bundestag hat die Bundesregierung beauftragt, mindestens in jeder zweiten Wahlperiode einen Bericht über die Lage der Familien in der Bundesrepublik Deutschland mit einer Stellungnahme der Bundesregierung vorzulegen. Der Bericht wird von einer unabhängigen Sachverständigenkommission erstellt. Dabei soll jeder dritte Bericht die Situation der Familien möglichst umfassend darstellen, während die übrigen Berichte Schwerpunkte setzen können. Der Zehnte Familienbericht hat das Schwerpunktthema \" Unterstützung allein- und getrennterziehender Eltern und ihrer Kinder - Bestandsaufnahme und Handlungsempfehlungen \". Er wurde am 15. Januar 2025 von der damaligen Bundesfamilienministerin Lisa Paus gemeinsam mit der Vorsitzenden der Zehnten Familienberichtskommission, Prof. Dr. Michaela Kreyenfeld, vorgestellt. Mit seinen Analysen und Handlungsempfehlungen liefert der Bericht eine wichtige Grundlage für eine wirksame und zukunftsorientierte Weiterentwicklung der Unterstützungsmaßnahmen für Allein- und Getrennterziehende. Der Zehnte Familienbericht untersucht die heterogenen Lebenslagen Allein- und Getrennterziehender und nimmt dabei die Dynamiken im Lebensverlauf in den Blick. Er betont die Notwendigkeit einer Politik, die die Resilienz sowohl des Individuums als auch der Gesellschaft stärkt, insbesondere in krisenhaften Lebensphasen wie Trennung, Scheidung oder dem Verlust eines Partners. Zugleich sollten Eltern und Kinder auf die Unterstützung durch die Solidargemeinschaft vertrauen können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/zehnter-familienbericht-253668","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:53.593092+00:00","lastSeen":"2026-03-15T17:29:53.593092+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/zehnter-familienbericht-253668"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/berichte-der-bundesregierung/zehnter-familienbericht-253668","crawledAt":"2026-03-15T17:29:53.593092Z","crawlId":"organizations-seeded-1773595793","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"1cd87f2e7d9539596aba7cdc79d299ce88535c50f680750153a98c5f1df2ea46"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:53.593092+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f26ddb3c-848a-4906-896b-cf349d0fdbe9', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/besucherdienst', 'active', NULL, '2026-03-15T16:00:10.051093+00:00', '{"id":"f26ddb3c-848a-4906-896b-cf349d0fdbe9","title":"Besucherdienst","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Der Besucherdienst ist ein Angebot des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend. Er informiert Bürgerinnen und Bürger über die Struktur und Aufgaben des Ministeriums in den Politikbereichen Familie, Ältere Menschen, Gleichstellung, Kinder und Jugend, Demokratie und Engagement. Anmeldungen sind nur für Gruppen möglich. Einzelanmeldungen können aus organisatorischen Gründen leider nicht bearbeitet werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/besucherdienst","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:10.051093+00:00","lastSeen":"2026-03-15T16:00:10.051093+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/besucherdienst"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/besucherdienst","crawledAt":"2026-03-15T16:00:10.051093Z","crawlId":"organizations-seeded-1773590410","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"742cc063d43b22fd0fcc0d0613af6c84925ae3613434a45a6eabdbfc7deb625b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:10.051093+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('41415069-22cf-461a-a8b4-bfb1e9ab46c5', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber', 'active', NULL, '2026-03-15T16:00:10.535515+00:00', '{"id":"41415069-22cf-461a-a8b4-bfb1e9ab46c5","title":"Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend als Arbeitgeber","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Stellenangebote Aktuelle Stellenangebote des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend. Aktuelle Stellenangebote des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend. Praktikum und juristisches Referendariat Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend ermöglicht Studierenden ein vorgeschriebenes Pflichtpraktikum und bietet ein juristisches Referendariat an. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend ermöglicht Studierenden ein vorgeschriebenes Pflichtpraktikum und bietet ein juristisches Referendariat an. Ausbildung Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend stellt jedes Jahr neue Auszubildende für den Ausbildungsberuf der Kauffrau und des Kaufmannes für Büromanagement ein. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend stellt jedes Jahr neue Auszubildende für den Ausbildungsberuf der Kauffrau und des Kaufmannes für Büromanagement ein."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:10.535515+00:00","lastSeen":"2026-03-15T16:00:10.535515+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber","crawledAt":"2026-03-15T16:00:10.535515Z","crawlId":"organizations-seeded-1773590410","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"dea2c8326637b7b5c48c231d578ec41c34c32126d395c8bc8c0e61174d27a536"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:10.535515+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6390e2e2-7d45-411d-b8bd-6d0817908a72', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/aktionsplan-behindertenrechtskonvention', 'active', NULL, '2026-03-15T16:00:11.031879+00:00', '{"id":"6390e2e2-7d45-411d-b8bd-6d0817908a72","title":"Aktionsplan zur Umsetzung der UN-Behindertenrechtskonvention","summary":{"de":"Mit einem Aktionsplan zur UN-Behindertenrechtskonvention möchte das Bundesfamilienministerium dazu beitragen, dass auch den Beschäftigten mit Behinderung eine selbstbestimmte und..."},"content":{"de":"Mit einem Aktionsplan zur UN-Behindertenrechtskonvention möchte das Bundesfamilienministerium dazu beitragen, dass auch den Beschäftigten mit Behinderung eine selbstbestimmte und gleichberechtigte Teilhabe möglich ist. Ziel der UN-Behindertenrechtskonvention ist es, Menschen mit Behinderung die Teilhabe an allen gesellschaftlichen Prozessen zu garantieren. Die UN-Behindertenrechtskonvention ist seit dem Jahr 2009 in Deutschland verbindlich. Das Bundeskabinett hat im Jahr 2011 den Aktionsplan zur Umsetzung der UN-Behindertenkonvention \"Auf dem Weg in eine inklusive Gesellschaft\" beschlossen. Mit diesem Aktionsplan sollen zugleich auch Länder, Kommunen, Unternehmen der Privatwirtschaft und andere angeregt werden, in ihren eigenen Kompetenzbereichen eigene Aktionspläne zur Umsetzung der Behindertenrechtskonvention zu entwickeln. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend greift diese Anregung mit einem Aktionsplan auf und gestaltet damit aktiv den Weg von der Integration zur Inklusion. Bereits seit dem Jahr 2002 gibt es im Bundesfamilienministerium die Vereinbarung zur Integration schwerbehinderter Menschen und damit zahlreiche Regelungen zur Gleichberechtigung Beschäftigter mit Behinderung. In Abkehr vom Gedanken der Integration gibt es jedoch viele Bereiche, in denen die UN-Konvention heute weiter geht und dem Gedanken der Inklusion wichtige Impulse gibt. Ausgehend von dieser Basis wurden Handlungsfelder identifiziert, in denen konkrete Maßnahmen das Ziel der Inklusion in den Vordergrund stellen und damit dazu beitragen, dass allen, auch den Beschäftigten mit Behinderung in allen Bereichen eine selbstbestimmte und gleichberechtigte Teilhabe möglich ist."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/aktionsplan-behindertenrechtskonvention","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:11.031879+00:00","lastSeen":"2026-03-15T16:00:11.031879+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/aktionsplan-behindertenrechtskonvention"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/aktionsplan-behindertenrechtskonvention","crawledAt":"2026-03-15T16:00:11.031879Z","crawlId":"organizations-seeded-1773590411","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c8f6116bfd187735e36b43fecf6eab03466e9d4d55e82772a164c0b6a28ca36f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:11.031879+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
