gibt, findest du diese hier."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/ausbildung","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:11.549766+00:00","lastSeen":"2026-03-15T16:00:11.549766+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/ausbildung"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/ausbildung","crawledAt":"2026-03-15T16:00:11.549766Z","crawlId":"organizations-seeded-1773590411","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"11558975e414d08473aa3d6b64f9b8f1615679fa3d61b47f1be969bfbc7267de"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:11.549766+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
