INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('81a510bf-09cd-4efe-9a1d-adbb1caa6cbe', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/bundesgremiengesetz', 'active', NULL, '2026-03-15T16:00:12.573403+00:00', '{"id":"81a510bf-09cd-4efe-9a1d-adbb1caa6cbe","title":"Veröffentlichung nach § 6 Abs. 1 Bundesgremienbesetzungsgesetz","summary":{"de":"Die Veröffentlichung nach dem Bundesgremienbesetzungsgesetz schafft Transparenz und soll die Fortschritte des Bundes über die Besetzung der Gremien mit Frauen und Männern abbilden."},"content":{"de":"Das Bundesgremienbesetzungsgesetz sieht vor, dass die Institutionen des Bundes auf ihrer Internetseite eine Aufstellung über ihre Aufsichts- und wesentlichen Gremien sowie über die Anzahl der durch den Bund zu bestimmenden Mitglieder veröffentlichen. Die aktuelle Veröffentlichung des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (Stand Dezember 2024) ist hier zu finden. Wie hoch der Frauenanteil in den Gremien der übrigen Bundesressorts ist, kann in einer interaktiven Anwendung des Bundesfamilienministeriums nachvollzogen werden. Das neue Bundesgremienbesetzungsgesetz ist am 1. Mai 2015 in Kraft getreten und als Artikel 1 im Gesetz für die gleichberechtigte Teilhabe von Frauen und Männern an Führungspositionen in der Privatwirtschaft und im öffentlichen Dienst verankert."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/bundesgremiengesetz","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:12.573403+00:00","lastSeen":"2026-03-15T16:00:12.573403+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/bundesgremiengesetz"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/bundesgremiengesetz","crawledAt":"2026-03-15T16:00:12.573403Z","crawlId":"organizations-seeded-1773590412","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4c2728b929d7bedc4f4d07d363ba443b6190544c726e0d02598509b3d569ac98"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:12.573403+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5cc9b3c0-912d-4d87-af64-60a6c14f91d3', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/familienfreundlicher-arbeitgeber', 'active', NULL, '2026-03-15T16:00:13.030215+00:00', '{"id":"5cc9b3c0-912d-4d87-af64-60a6c14f91d3","title":"Das Bundesfamilienministerium als familienfreundlicher Arbeitgeber","summary":{"de":"Auch als Arbeitgeber ist das Bundesfamilienministerium dem Ziel der Vereinbarkeit von Familie und Beruf verpflichtet. In den vergangenen Jahren wurde das Angebot familienfreundlicher Maßnahmen..."},"content":{"de":"Auch als Arbeitgeber ist das Bundesfamilienministerium dem Ziel der Vereinbarkeit von Familie und Beruf verpflichtet. In den vergangenen Jahren wurde das Angebot familienfreundlicher Maßnahmen kontinuierlich weiterentwickelt. Die bessere Vereinbarkeit von Beruf und Familie ist ein zentraler Gegenstand der gesellschaftspolitischen Agenda des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend. Auch als Dienststelle und für das Bundesgleichstellungsgesetz federführendes Ressort ist das Bildungs- und Familienministerium dem Ziel der Vereinbarkeit von Familie und Beruf verpflichtet und geht mit gutem Beispiel voran. In den vergangenen Jahren wurde das Angebot familien- lebensphasenbewusster Maßnahmen kontinuierlich ausgebaut. Am 17. Juni 2025 ist das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend zum siebten Mal mit dem audit berufundfamilie ausgezeichnet worden. Damit trägt das Ministerium dieses Gütesiegel, das für eine familienfreundliche Personalpolitik verliehen wird, bereits seit mehr als zwanzig Jahren. Das von der gemeinnützigen Hertie-Stiftung entwickelte Audit ist ein Instrument zur kontinuierlichen Verbesserung einer familien- und lebensphasenbewussten Personalpolitik. Zertifizierte Unternehmen und Behörden stellen sich in regelmäßigen Abständen erneut einem Überprüfungsverfahren, mit dem Ziel einer langfristigen Implementierung. In den vergangenen Jahren wurde das bestehende Angebot familienfreundlicher Maßnahmen im Bildungs- und Familienministerium kontinuierlich weiterentwickelt. Zu nennen sind insbesondere folgende Schwerpunkte: Mit der mobilen und flexiblen Arbeit schafft das Bundesbildungs- und -familienministerium die Rahmenbedingungen für eine möglichst optimale Vereinbarkeit von Beruf und Privatleben, stärkt die Motivation und Leistungsbereitschaft aller Mitarbeitenden und ist Vorbild für vereinbarkeitsorientierte Arbeitsbedingungen innerhalb der Bundesverwaltung."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/familienfreundlicher-arbeitgeber","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:13.030215+00:00","lastSeen":"2026-03-15T16:00:13.030215+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/familienfreundlicher-arbeitgeber"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/familienfreundlicher-arbeitgeber","crawledAt":"2026-03-15T16:00:13.030215Z","crawlId":"organizations-seeded-1773590413","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"37a7d06e6c2a3b251a0d3f310697d3f995d6b8d6338c24e4a96ebe53e92f4484"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:13.030215+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bdc35056-e3a5-4d62-adb8-daba87af02da', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/praktika', 'active', NULL, '2026-03-15T16:00:13.534460+00:00', '{"id":"bdc35056-e3a5-4d62-adb8-daba87af02da","title":"Praktikum und juristisches Referendariat","summary":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend ermöglicht Studierenden ein vorgeschriebenes Pflichtpraktikum und bietet ein juristisches Referendariat an."},"content":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ) ermöglicht Studierenden ein nach der Hochschul- beziehungsweise Studienordnung vorgeschriebenes Pflichtpraktikum. Bitte benennen Sie für Ihr beabsichtigtes Praktikum den gewünschten Einsatzbereich mit Einsatzort (Berlin/Bonn). Die Fachabteilungen des Bundesministerium für Familie, Senioren, Frauen und Jugend finden Sie im Organisationsplan. Bitte richten Sie Ihre Bewerbung per E-Mail an: Praktika@bmbfsfj.bund.de. Aus organisatorischen Gründen sollte Ihre Bewerbung mindestens sechs Monate vor Praktikumsbeginn eingereicht werden. Für ein Praktikum wird eine steuerpflichtige Aufwandsentschädigung in Höhe von 450 Euro pro Kalendermonat gezahlt. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend hat besonderes Interesse an der Beschäftigung von Rechtsreferendarinnen und Rechtsreferendaren über einen Zeitraum von drei Monaten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/praktika","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:13.534460+00:00","lastSeen":"2026-03-15T16:00:13.534460+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/praktika"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/bmbfsfj-als-arbeitgeber/praktika","crawledAt":"2026-03-15T16:00:13.534460Z","crawlId":"organizations-seeded-1773590413","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4141f7ea121772f5229b6c85513659ace034316231b2f55d92f6f5dee43cd2bf"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:00:13.534460+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3ea1d104-1fbd-43bf-bf5a-31f2501ab6c5', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/geschichte', 'active', NULL, '2026-03-15T16:11:35.708785+00:00', '{"id":"3ea1d104-1fbd-43bf-bf5a-31f2501ab6c5","title":"Geschichte des Ministeriums","summary":{"de":"Die Geschichte des für Familien zuständigen Bundesministeriums ist vielfältig - deshalb lohnt sich ein Blick auf all jene, die als Ministerin und Minister in den vergangenen Jahrzehnten in der..."},"content":{"de":"Die Geschichte des für Familien zuständigen Bundesministeriums ist vielfältig - deshalb lohnt sich ein Blick auf all jene, die als Ministerin und Minister in den vergangenen Jahrzehnten in der Bundesregierung politisch für die Belange und Bedürfnisse der Familien Verantwortung getragen haben. Anne Spiegel bekleidete das Amt der Bundesministerin für Familie, Senioren, Frauen und Jugend von Dezember 2021 bis April 2022. In dieser Zeit gab sie den Anstoß für eine Kindergrundsicherung. Diese bündelt familienpolitische Leistungen und verbessert so die Chancen für alle Kinder. Als ersten Meilenstein brachte die Grünen-Politikerin einen Sofortzuschlag von monatlich 20 Euro pro Kind auf den Weg. Ebenfalls in Anne Spiegels Amtszeit fiel die Streichung des § 219a Strafgesetzbuch. Damit entfiel die strafrechtliche Verfolgung von Ärztinnen und Ärzten, die dazu informieren, dass sie Schwangerschaftsabbrüche vornehmen und welche Methoden sie dafür anwenden. Denn Schwangere, die überlegen, die Schwangerschaft abzubrechen, brauchen individuelle Beratung und Unterstützung - und keine Verbote. Mit Beginn des Krieges Russlands gegen die Ukraine im Februar 2022 setzte Anne Spiegel sich insbesondere für die gute Unterbringung von geflüchteten Heim- und Waisenkindern und den Schutz von geflüchteten Frauen ein. Christine Lambrecht, SPD, wurde im Mai 2021 zur Bundesministerin für Familie, Senioren, Frauen und Jugend ernannt. Sie übernahm diese Funktion zusätzlich zu ihrem Amt als Bundesministerin für Justiz und Verbraucherschutz. Bund und Länder einigten sich unter der Leitung von Bundesfamilien- und -justizministerin Christine Lambrecht auf die schrittweise Einführung eines Rechtsanspruchs auf Ganztagsbetreuung für Grundschulkinder ab 2026. Einen weiteren Schwerpunkt ihrer Arbeit bildete die Umsetzung des Aktionsprogramms \"Aufholen nach Corona für Kinder- und Jugendliche\". Während ihrer gut halbjährigen Amtszeit trat darüber hinaus das Zweite Führungspositionen-Gesetz in Kraft, an dessen Erarbeitung sie als Bundesjustizministerin mitgewirkt hatte. \"Damit es jedes Kind packt!\" - mit diesem Ziel gestaltete Franziska Giffey ihre Arbeit für Kinder und Familien. Im Jahr 2018 übernahm die Sozialdemokratin das Amt der Bundesministerin für Familie, Senioren, Frauen und Jugend."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/geschichte","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:11:35.708785+00:00","lastSeen":"2026-03-15T16:11:35.708785+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/geschichte"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/geschichte","crawledAt":"2026-03-15T16:11:35.708785Z","crawlId":"organizations-seeded-1773591095","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"fed26adefbda69f0e3012ff512a3c8257081ecdfa6c5a3744c09c6d7ecab0f09"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:11:35.708785+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('12b11b57-76e0-4490-9722-fe5b33a16183', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/inklusion', 'active', NULL, '2026-03-15T16:11:37.199068+00:00', '{"id":"12b11b57-76e0-4490-9722-fe5b33a16183","title":"Inklusion","summary":{"de":"Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend trägt dazu bei, eine inklusive Gesellschaft mitzugestalten."},"content":{"de":"Inklusion bedeutet, die gleichberechtigte Teilhabe eines jeden Menschen am gesellschaftlichen Leben zu sichern. Und zwar vom frühen Lebensbeginn an bis ins hohe Lebensalter, unabhängig vom Grad eines eventuellen Hilfebedarfs. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend nimmt hierbei die unterschiedlichen Bevölkerungsgruppen in den Blick, vor allem Kinder und Jugendliche, Familien, Frauen und ältere Menschen. Die Achtung der Würde jedes Menschen und die Gewährleistung von Teilhabe sind Grundvoraussetzungen, um die Menschenrechte aller zu sichern. Die Förderung von Chancengleichheit sowie eine Gleichbehandlung aller Menschen gelten als Voraussetzungen für die Sicherstellung der Teilhabe behinderter Menschen. Daher verbietet das Grundgesetz der Bundesrepublik Deutschland in Artikel 3 Benachteiligungen aufgrund einer Behinderung. Nach Schätzungen leben weltweit mehr als eine Milliarde Menschen mit einer Behinderung. Das entspricht etwa 16 Prozent der gesamten Weltbevölkerung. Die Generalversammlung der Vereinten Nationen hat 2001 beschlossen, dass Vorschläge für ein umfassendes internationales Übereinkommen zur Förderung und zum Schutz der Rechte von Menschen mit Behinderungen entwickelt werden sollen. Am 3. Mai 2008 trat das Übereinkommen der Vereinten Nationen über die Rechte von Menschen mit Behinderungen (UN-Behindertenrechtskonvention, kurz UN-BRK) in Kraft. In Deutschland ist die UN-BRK seit 2009 verbindlich. Die UN-BRK schafft keine Sonderrechte, sondern konkretisiert und spezifiziert die universellen Menschenrechte aus der Perspektive der Menschen mit Behinderungen vor dem Hintergrund ihrer Lebenslagen, die im Menschenrechtsschutz Beachtung finden müssen. Dazu greift sie auf die Allgemeine Erklärung der Menschenrechte sowie auf die wichtigsten Menschenrechtsverträge der Vereinten Nationen zurück und formuliert zentrale Bestimmungen dieser Dokumente für die Lebenssituation von Menschen mit Behinderungen. Zur konkreten Umsetzung der UN-BRK hat die Bundesregierung unter Einbeziehung der Zivilgesellschaft einen Nationalen Aktionsplan erarbeitet, der die Ziele und Maßnahmen der Bundesregierung in einer Gesamtstrategie zusammenfasst. Derzeit befindet sich bereits die zweite Auflage des Nationalen Aktionsplans zur UN-Behindertenrechtskonvention (NAP 2.0) in der Umsetzung und trägt dazu bei, Inklusion als in allen Lebensbereichen zu berücksichtigendes Prinzip durchzusetzen. Der NAP 2.0 setzt auf den ersten Aktionsplan aus dem Jahr 2011 auf und ist als dynamisches Instrument zu verstehen, denn seine Maßnahmen werden regelmäßig fortgeschrieben. Die Ziele Teilhabe, Selbstbestimmung und vollständige Gleichstellung werden durch unterschiedliche Maßnahmen gefördert, um alle Menschen zu befähigen, ihr Leben selbstbestimmt nach den eigenen Vorstellungen und Wünschen führen zu können. Das Bundesbildungs- und -familienministerium hat, neben dem für Inklusion federführend zuständigen Bundesministerium für Arbeit und Soziales, dabei die meisten Maßnahmen in Umsetzung. Zu den Maßnahmen des Bundesbildungs- und -familienministeriums gehört das Familienportal, auf welchem alle relevanten Informationen zu staatlichen Familienleistungen, gesetzlichen Regelungen und Unterstützungsmöglichkeiten gebündelt sind. Es orientiert sich an den unterschiedlichen Lebenslagen von Familien, darunter befindet sich auch die Lebenslage \"Leben mit Behinderung\". Daneben fördert das Bundesbildungs- und -familienministerium das Projekt \" Politische Interessenvertretung behinderter Frauen im Kontext Intersektionalität, Sexismus, Ableismus und Gewaltschutz \" des Vereins Weibernetz. Durch die Förderung des Projektes werden neue Impulse gesetzt, um die Lebenssituation von Frauen mit Beeinträchtigungen zu verbessern. Eine weitere Maßnahme ist die beauftragte Studie zu Gewalterfahrungen von Menschen mit Behinderungen in Werkstätten und in Einrichtungen. Die Abschlussberichte enthalten die Ergebnisse der quantitativen und qualitativen Befragungen sowie Handlungsempfehlungen und Beispiele guter Praxis zur Verbesserung des Gewaltschutzes."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/inklusion","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:11:37.199068+00:00","lastSeen":"2026-03-15T16:11:37.199068+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/inklusion"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/inklusion","crawledAt":"2026-03-15T16:11:37.199068Z","crawlId":"organizations-seeded-1773591097","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"47da9ad92de0f83ae390f64250e17242afe20f424f78464358486dc2c616dffd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:11:37.199068+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2d2f174b-e4ec-4bc9-8ff3-bd1a28341c9e', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/korruptionspraevention', 'active', NULL, '2026-03-15T16:11:37.671302+00:00', '{"id":"2d2f174b-e4ec-4bc9-8ff3-bd1a28341c9e","title":"Korruptionsprävention","summary":{"de":"Korruption ist ein Thema, welches in der täglichen Arbeit auf den ersten Blick kaum oder gar nicht relevant erscheint. Dabei verläuft Korruption in der Regel unbemerkt, hat viele Facetten und..."},"content":{"de":"Korruption ist ein Thema, welches in der täglichen Arbeit auf den ersten Blick kaum oder gar nicht relevant erscheint. Dabei verläuft Korruption in der Regel unbemerkt, hat viele Facetten und bedeutet schwerwiegende Konsequenzen für alle Beteiligten. Im Bereich der öffentlichen Verwaltung führt Korruption zu hohen materiellen Schäden, weniger Effizienz des Verwaltungshandelns und auch zu immateriellen Auswirkungen wie Vertrauensverlust der Bürgerinnen und Bürger in die Verwaltung. Die für alle Bundesministerien verpflichtende \"Richtlinie der Bundesregierung zur Korruptionsprävention in der Bundesverwaltung vom 30. Juli 2004\" ist Basis und Ausgangspunkt der Korruptionspräventionsarbeit im Bundesfamilienministerium und wird durch das Konzept \"Korruptionsmanagement im Bundesfamilienministerium\" konkret umgesetzt. Dieses umfasst eine ganzheitliche und systematische Präventionsstrategie sowie ein entsprechendes Risikomanagementsystem. Das Risikomanagementsystem sieht unter anderem die Umsetzung von risikominimierenden beziehungsweise risikoabsichernden Präventionsmaßnahmen vor. Eine wesentliche organisatorische Präventionsmaßnahme stellt hierbei die Bestellung einer Ansprechperson für Korruptionsprävention gemäß Nr. 5 der \"Richtlinie der Bundesregierung zur Korruptionsprävention in der Bundesverwaltung vom 30. Juli 2004\" dar. Die Ansprechperson für Korruptionsprävention hat ein unmittelbares Vortragsrecht bei der Behördenleitung. Sollten Sie begründete Hinweise oder Verdachtsmomente auf Angelegenheiten beziehungsweise Abläufe in Bezug auf korruptives Verhalten von Beschäftigten des Bundesfamilienministeriums haben, nimmt die Ansprechperson für Korruptionsprävention im Bundesfamilienministerium diese per E-Mail vertraulich entgegen. Der Zugriff auf dieses Mailpostfach erfolgt ausschließlich durch die Ansprechperson. Ein Zugriff durch Dritte (beispielsweise Vertretungen) ist nicht möglich. Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend Ansprechperson für Korruptionsprävention Doreen Herz 10117 Berlin"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/korruptionspraevention","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:11:37.671302+00:00","lastSeen":"2026-03-15T16:11:37.671302+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/korruptionspraevention"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/korruptionspraevention","crawledAt":"2026-03-15T16:11:37.672299Z","crawlId":"organizations-seeded-1773591097","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7351129cd2f0a6fc1aeae05ff530a85a5c2f1467f4edf37b6e905474f99454b7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:11:37.672299+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a27638ca-7ad3-4d91-9042-64f088e4ca1a', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ressortforschung', 'active', NULL, '2026-03-15T16:11:41.697591+00:00', '{"id":"a27638ca-7ad3-4d91-9042-64f088e4ca1a","title":"Ressortforschung","summary":{"de":"Politik braucht wissensbasierte Beratung. Eine besondere Stellung nehmen dabei die Einrichtungen mit Ressortforschungsaufgaben ein. Sie sind besonders praxisnah und interdisziplinär ausgerichtet."},"content":{"de":"Die Forschungs- und Entwicklungsaktivitäten des Bundes werden als \"Ressortforschung\" bezeichnet. An der Schnittstelle von Wissenschaft und Politik ist Ressortforschung besonders praxisnah und interdisziplinär ausgerichtet. Gleichzeitig werden in der Ressortforschung wissenschaftliche Fragestellungen auch langfristig und kontinuierlich bearbeitet. Damit bildet sie eine unverzichtbare Grundlage für viele politische Entscheidungen. Der Ressortforschung des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend kommt aufgrund seines gesellschaftspolitischen Auftrages eine besondere Bedeutung zu. Sie hat das Ziel, Datenlücken zu schließen, fachliche Fragestellungen zu beantworten und politische Entscheidungen sowie Gesetzesvorhaben vorzubereiten. Das Deutsche Jugendinstitut e.V. (DJI) ist europaweit eines der größten außeruniversitären sozialwissenschaftlichen Forschungsinstitute. Der Schwerpunkt liegt in der anwendungsorientierten Forschung sowie der Politikberatung zu Lebensverhältnissen von Kindern, Jugendlichen und Familien. Die Themen sind vielfältig: sie reichen von Fragen der Kinderbetreuung, des Kinderschutzes über Fragen der Jugendkriminalität, des sexuellen Missbrauchs bis hin zu Trennungsfamilien oder der Entwicklung von Ganztagsschulen. Teil der Politikberatung sind zum Beispiel die Kinder- und Jugendberichte. Sie werden von unabhängigen Sachverständigenkommissionen erstellt, die von der Bundesregierung berufen und vom DJI fachlich begleitet werden. Träger des 1963 gegründeten Instituts ist ein gemeinnütziger Verein mit Mitgliedern aus Politik, Wissenschaft, Verbänden und Einrichtungen der Kinder-, Jugend- und Familienhilfe. Das DJI wird institutionell durch das Bundesfamilienministerium gefördert, auch die Bundesländer sind zu einem geringeren Anteil am Haushalt beteiligt. Hinzu kommen zahlreiche Projekte des Ministeriums, anderer Bundes- und Landesministerien sowie weiterer Förderer. Das DJI wächst kontinuierlich: Inzwischen arbeiten mehr als 360 Beschäftigte, davon über 235 Wissenschaftlerinnen und Wissenschaftler, am Hauptsitz in München und an den Außenstellen in Halle/Saale und Leipzig. Das 1974 gegründete Deutsche Zentrum für Altersfragen e.V. (DZA) ist als Forschungsinstitut auf dem Gebiet der sozial- und verhaltenswissenschaftlichen Gerontologie tätig. Als Gerontologie wird die Wissenschaft vom Altern des Menschen bezeichnet. Das vom Bundesseniorenministerium finanzierte, in Vereinsform organisierte Institut hat die Aufgabe, Erkenntnisse über die Lebenslage alternder und alter Menschen zu erweitern und für die Politikberatung zu nutzen. Ein wichtiges Instrument dafür ist der Deutsche Alterssurvey, eine repräsentative Quer- und Längsschnittbefragung von Personen in der zweiten Lebenshälfte, die das DZA seit 1996 in regelmäßigen Abständen durchführt. Dabei geht es um die wirtschaftliche Lage und Wohnsituation, um familiäre und sonstige soziale Kontakte, das berufliche und ehrenamtliche Engagement sowie um Gesundheit, Wohlbefinden und Lebensziele der Menschen im mittleren und höheren Lebensalter. Hinzu kommen weitere Projekte des Ministeriums und von Drittmittelgebern."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ressortforschung","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:11:41.697591+00:00","lastSeen":"2026-03-15T16:11:41.697591+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ressortforschung"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/ministerium/ressortforschung","crawledAt":"2026-03-15T16:11:41.697591Z","crawlId":"organizations-seeded-1773591101","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"9dc7d68e5c5f69a1323d291bc36d0c7694e7bce18ee15fcab9ee3513495bcd8f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:11:41.697591+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9606b2be-b279-41da-8e4f-db1476dc9a8e', 'organizations', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen', 'active', NULL, '2026-03-15T17:29:58.111378+00:00', '{"id":"9606b2be-b279-41da-8e4f-db1476dc9a8e","title":"Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bildung ist der Schlüssel zu gesellschaftlicher Teilhabe, sozialem Aufstieg, Fortschritt und persönlicher Freiheit. Indem wir uns für beste Bildung einsetzen, unterstützen wir Menschen dabei, Chancen zu erkennen und ihre Ziele und Träume zu verwirklichen. Familien darin zu unterstützen, ihr Leben nach den eigenen Vorstellungen gestalten zu können - das ist das Ziel einer guten Familienpolitik. Dafür brauchen Familien vor allem Zeit für Kinder und Beruf, finanzielle Stabilität und eine gute Kinderbetreuung. Auch im hohen Alter selbstbestimmt leben und an der Gesellschaft teilhaben - das wünschen sich die meisten Menschen. Sie dabei zu unterstützen, ist zentrales Ziel der Seniorenpolitik. Die Gleichstellung von Frauen und Männern ist eine der zentralen Herausforderungen, um das Leben in unserem Land zukunftsfähig und gerecht zu gestalten. Dafür müssen Frauen und Männer auf dem gesamten Lebensweg die gleichen Chancen erhalten – persönlich, beruflich und familiär. Alle Kinder und Jugendlichen haben ein Recht auf ein beschütztes Auf­wachsen und gleiche Chancen - unabhängig von Herkunft, Geschlecht, Religion oder dem sozialen Status. Chancengleichheit und der Schutz von Kindern und Jugendlichen ist daher ein zentrales Anliegen des Bundesjugendministeriums. Das Bundesfamilienministerium versteht sich als Partner der Zivilgesellschaft - auf Augenhöhe mit Millionen von freiwillig engagierten Bürgerinnen und Bürgern, Vereinen, Verbänden, Unternehmen und Stiftungen. Deshalb unterstützt es die starke Engagementlandschaft in Deutschland."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T17:29:58.111378+00:00","lastSeen":"2026-03-15T17:29:58.111378+00:00","sourceUnavailable":false,"organizationType":"government","region":"Germany","services":["Familie","Jugend","Gleichstellung"],"contactDetails":{"website":"https://www.bmbfsfj.bund.de/bmbfsfj/themen"},"provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","crawledAt":"2026-03-15T17:29:58.111378Z","crawlId":"organizations-seeded-1773595798","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"fc53c15a9fdff898d6f3b05b2315049856e723bcfc62d3b6b39d27c13188f617"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:29:58.111378+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
