INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('62f9dd41-8aa0-4214-b47e-ba7be02e646a', 'organizations', 'https://www.fitko.de/produktmanagement/115', 'active', NULL, '2026-03-15T16:00:01.276134+00:00', '{"id":"62f9dd41-8aa0-4214-b47e-ba7be02e646a","title":"115","summary":{"de":"Einheitliche Behördennummer für Bürger:innen und Unternehmen Die bundesweit einheitliche Rufnummer 115 ist ein bürger:innennaher und direkter Kanal in die Verwaltung. Ihr Kern ist die telefonische Antwort auf Fragen zu allen Angelegenheiten der öffentlichen Verwaltung auf kommunaler, Landes- und Bundesebene. Für gehörlose oder hörgeschädigte Personen steht das 115-Gebärdentelefon zur Verfügung. Zur Website von 115"},"content":{"de":"Die bundesweit einheitliche Rufnummer 115 ist ein bürger:innennaher und direkter Kanal in die Verwaltung. Ihr Kern ist die telefonische Antwort auf Fragen zu allen Angelegenheiten der öffentlichen Verwaltung auf kommunaler, Landes- und Bundesebene. Für gehörlose oder hörgeschädigte Personen steht das 115-Gebärdentelefon zur Verfügung. Thorsten Maid Teamleitung | Produktmanagement 115 Telefon +49 (69) 401270 106 E-Mail Kontakt aufnehmen Antje Zahn Produktmanagement 115 | Flächendeckung und Qualitätsmanagement Telefon +49 (69) 401270 151 E-Mail Kontakt aufnehmen Produktmanagement 115 | Flächendeckung und Qualitätsmanagement"},"url":"https://www.fitko.de/produktmanagement/115","topics":["organizations"],"tags":["organization"],"targetGroups":["general_public"],"status":"active","firstSeen":"2026-03-15T16:00:01.276134+00:00","lastSeen":"2026-03-15T16:00:01.276134+00:00","sourceUnavailable":false,"organizationType":"unknown","region":"Germany","services":["Informationsangebote","Service und Kontakt"],"contactDetails":{"website":"https://www.fitko.de/produktmanagement/115"},"provenance":{"source":"https://www.fitko.de/produktmanagement/115","crawledAt":"2026-03-15T16:00:01.276810Z","crawlId":"organizations-seeded-1773590401","cra