INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('18d9f4f4-6666-4800-af39-514e7e0e8358', 'contacts', 'https://familienportal.de/familienportal', 'active', NULL, '2026-03-15T17:53:33.438327+00:00', '{"id":"18d9f4f4-6666-4800-af39-514e7e0e8358","title":"Familienportal","summary":{"de":"Das Familienportal bündelt alle relevanten Informationen zu staatlichen Familienleistungen, gesetzlichen Regelungen und Beratungsangeboten für Familien."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Hier finden Sie Informationen rund um die Familie. Informationen für Pflegefamilien Sie möchten Pflegeeltern werden? Wir informieren Sie über Voraussetzungen und Unterstützungsangebote für Pflegeeltern. Sie möchten Pflegeeltern werden? Wir informieren Sie über Voraussetzungen und Unterstützungsangebote für Pflegeeltern. Checklisten rund um die Geburt Bevor und nachdem ein Baby auf die Welt kommt, gibt es viel zu organisieren. Damit Sie nichts vergessen, gibt es unsere praktischen Checklisten: Digital oder zum Ausdrucken. Bevor und nachdem ein Baby auf die Welt kommt, gibt es viel zu organisieren. Damit Sie nichts vergessen, gibt es unsere praktischen Checklisten: Digital oder zum Ausdrucken."},"url":"https://familienportal.de/familienportal","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:33.438327+00:00","lastSeen":"2026-03-15T17:53:33.438327+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal","crawledAt":"2026-03-15T17:53:33.438327Z","crawlId":"contacts-seeded-1773597213","c