INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a0d71083-331a-4f37-83bf-c277ab7b81ff', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/ausbildung-studium-mit-kind', 'active', NULL, '2026-03-15T17:53:35.433842+00:00', '{"id":"a0d71083-331a-4f37-83bf-c277ab7b81ff","title":"Ausbildung & Studium mit Kind","summary":{"de":"Von Elterngeld über BAföG bis Steuerentlastungen: Hier finden Sie Informationen zur Unterstützung von Studierenden und Auszubildenden mit Kind."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Für Eltern in Studium und Ausbildung gibt es verschiedene finanzielle Unterstützungen, Hilfen und Beratungsangebote für ihre spezielle Situation. Wenn Sie studieren oder eine Ausbildung machen, können Sie Elterngeld bekommen. Mehr Informationen dazu finden Sie unter Elterngeld während des Studiums oder der Ausbildung. Wenn Sie BAföG beantragen, wird Ihr Elterngeld wie Einkommen behandelt und auf das BAföG angerechnet, sofern Ihr Elterngeld über dem Mindestbetrag liegt. Hier finden Sie weitere Informationen zu Elterngeld und BAföG. Auszubildende und Studierende können Elternzeit nehmen. Hier finden Sie weitere Informationen, wenn Sie wissenschaftliche Mitarbeiterin oder Mitarbeiter oder"},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/ausbildung-studium-mit-kind","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:35.433842+00:00","lastSeen":"2026-03-15T17:53:35.433842+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/ausbildung-studium-mit-kind","crawledAt":"2026-03-15T17:53:35.434842Z","crawlId":"contacts-seeded-1773597215","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"143e5ea7bf344bfd25d7ed3ed96ef51d3a913cb88b0f43785fab1ce261443d29"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:35.434842+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('806306a8-e3c1-46f1-868f-40c6830a5b33', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/freiwilliges-engagement', 'active', NULL, '2026-03-15T17:53:35.993738+00:00', '{"id":"806306a8-e3c1-46f1-868f-40c6830a5b33","title":"Freiwilliges Engagement","summary":{"de":"Ob Freiwilliges Soziales Jahr oder Bundesfreiwilligendienst: Hier erfahren Sie alles über freiwilliges Engagement."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. In Deutschland engagieren sich mehr als 30 Millionen Menschen aktiv für das Gemeinwohl. Sie stellen sich täglich in den Dienst anderer und tragen damit wesentlich zum Zusammenhalt unserer Gesellschaft bei. Ehrenämter, Freiwilligenarbeit und bürgerschaftliches Engagement sind wichtige Bestandteile unserer Demokratie. Ob bei der Freiwilligen Feuerwehr, im Sportverein, in einer Kindertagesstätte oder bei einer Bürgerinitiative – in vielen spannenden Tätigkeitsfeldern können Sie sich freiwillig engagieren. So bringen Sie sich in die Gesellschaft ein und gestalten sie mit. Von diesem Engagement profitieren Sie auch persönlich: Sie sind aktiv, lernen dazu, knüpfen neue Kontakte und können das Gefühl genießen, etwas Gutes zu tun. Um das Engagement zu würdigen, erhalten Aktive zudem eine steuerliche Förderung. Freiwilliges Engagement ist etwas für junge und ältere Menschen."},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/freiwilliges-engagement","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:35.993738+00:00","lastSeen":"2026-03-15T17:53:35.993738+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/freiwilliges-engagement","crawledAt":"2026-03-15T17:53:35.993738Z","crawlId":"contacts-seeded-1773597215","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"591e0bde526fe24567adcf07e9a35f2a4ffbdb545d77bdc949240e840d0f28c2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:35.993738+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4c55123a-0055-421a-9388-1dfadaeb8dee', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/kinderbetreuung', 'active', NULL, '2026-03-15T17:53:36.471982+00:00', '{"id":"4c55123a-0055-421a-9388-1dfadaeb8dee","title":"Kinderbetreuung","summary":{"de":"Wie finde ich einen Kita-Platz? Was ist, wenn mein Kind krank ist? Hier finden Sie Antworten rund um Fragen zur Kinderbetreuung."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Bei der Suche nach einem geeigneten Betreuungsangebot vor Ort unterstützt Sie Ihr jeweiliges Landesministerium mit hilfreichen Informationen. Darüber hinaus stellen einige Bundesländer Übersichten der Angebote zu Kinderbetreuung nach Landkreisen und Bezirken zur Verfügung. Vereinzelt ist auch ein zentrales Anmeldeverfahren möglich. In Städten, Landkreisen und Bezirken ist in der Regel Ihr Jugendamt für die Vermittlung eines Kitaplatzes zuständig. Das Serviceportal Baden-Württembergs stellt Informationen für die Anmeldung und Aufnahmen in Kindertageseinrichtungen bereit. Der Kommunalverband für Jugend und Soziales Baden-Württemberg stellt zudem eine Übersicht aller Kindertageseinrichtungen in Städten und Landkreisen bereit. Das Bayerische Staatsministerium für Familie, Arbeit und Soziales stellt Informationen rund um die Kindertagesbetreuung bereit. Darunter auch Links zu Info-Filmen und Antworten auf häufige Fragen (FAQ) von Eltern."},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/kinderbetreuung","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:36.471982+00:00","lastSeen":"2026-03-15T17:53:36.471982+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/kinderbetreuung","crawledAt":"2026-03-15T17:53:36.471982Z","crawlId":"contacts-seeded-1773597216","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"080cf9bce1c251d5c1c03bb52b8d0817166cbc4399ccb294ebebf82644283813"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:36.471982+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e5edbecb-c90a-4828-8fa3-57d4b3a1225e', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/selbststaendigkeit', 'active', NULL, '2026-03-15T17:53:36.932977+00:00', '{"id":"e5edbecb-c90a-4828-8fa3-57d4b3a1225e","title":"Selbstständigkeit mit Kind","summary":{"de":"Von Elterngeld bis Mutterschaftsleistungen: Hier finden Sie Informationen zur Unterstützung von Selbstständingen mit Kind."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Für Selbstständige gibt es Familienleistungen, wie das Kindergeld und unter bestimmten Voraussetzungen Kinderzuschlag oder Leistungen für Bildung und Teilhabe. Für Elterngeld und Mutterschaftsleistungen gelten teilweise spezielle Regelungen. Eine Übersicht dazu finden Sie hier. Als selbständige Person können Sie Elterngeld erhalten. Maßgeblich für die Bemessung des Elterngeldbetrags ist dabei, ob sie als selbständig oder nicht-selbständig gelten. Wie sich eine selbständige Tätigkeit auf die Berechnung des Elterngelds auswirkt, finden Sie hier: Wie wird mein bisheriges Einkommen für die Berechnung des Elterngelds bestimmt? Welches Einkommen wird für mein Elterngeld berücksichtigt, wenn ich vor der Geburt meines Kindes selbständig war?"},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/selbststaendigkeit","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:36.932977+00:00","lastSeen":"2026-03-15T17:53:36.932977+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/selbststaendigkeit","crawledAt":"2026-03-15T17:53:36.932977Z","crawlId":"contacts-seeded-1773597216","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"308ab62a293f6bbb579cef6acdf3afbe70234a53b2b0307bd3c0fddfc88adde5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:36.932977+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b9f161fb-84bf-4dc2-a183-3f8ad2a9e9f5', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/vereinbarkeit-familie-und-beruf', 'active', NULL, '2026-03-15T17:53:37.475992+00:00', '{"id":"b9f161fb-84bf-4dc2-a183-3f8ad2a9e9f5","title":"Vereinbarkeit Familie & Beruf","summary":{"de":"Die Mehrheit der Eltern möchte Beruf und Familie besser miteinander vereinbaren können. Hier erfahren Sie, worauf Sie achten sollten."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Die Mehrheit der Eltern möchte Beruf und Familie besser miteinander vereinbaren können. Dazu sind vor allem familienfreundliche Arbeitgeber, geregelte Kinderbetreuung und finanzielle Sicherheit wichtig. Familienfreundliche Arbeitsbedingungen tragen viel dazu bei, dass Eltern Familie und Beruf miteinander vereinbaren können. Neun von zehn Arbeitnehmerinnen und Arbeitnehmern mit Kindern sagen, dass ihnen familienfreundliche Angebote mindestens so wichtig sind wie die Höhe des Gehalts. In den vergangenen Jahren sind viele Fortschritte erzielt worden. Das zeigt etwa das Unternehmensnetzwerk Erfolgsfaktor Familie des Familienministeriums und des Deutschen Industrie- und Handelskammertages. Es vereint bundesweit über 6.700 Unternehmen und Institutionen, die sich zu einer familienbewussten Personalpolitik bekennen. Familienfreundlichkeit rechnet sich: Unternehmen binden damit qualifizierte Beschäftigte an sich. Das eröffnet Vorteile beim Wettbewerb um die besten Köpfe - gerade vor dem Hintergrund der demografischen Entwicklung. Wer Beschäftigte mit familiären Verpflichtungen gewinnen möchte, punktet vor allem mit familienbewussten Arbeitszeiten, denn für die Arbeitnehmerinnen und Arbeitnehmer ist die Frage, wie sich der Alltag organisieren lässt, oft entscheidend."},"url":"https://familienportal.de/familienportal/lebenslagen/ausbildung-beruf/vereinbarkeit-familie-und-beruf","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:37.475992+00:00","lastSeen":"2026-03-15T17:53:37.475992+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/ausbildung-beruf/vereinbarkeit-familie-und-beruf","crawledAt":"2026-03-15T17:53:37.475992Z","crawlId":"contacts-seeded-1773597217","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"e10ecffcaabfe44e71a7d0f933aa2154e3bf68c2582a86f15f08a3dbd2e3b66a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:37.475992+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0a603f73-609f-49ee-bfd3-79d9b9abf5ab', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/familienversicherung', 'active', NULL, '2026-03-15T17:53:38.445225+00:00', '{"id":"0a603f73-609f-49ee-bfd3-79d9b9abf5ab","title":"Familienversicherung","summary":{"de":"Sie können Familienmitglieder beitragsfrei mitversichern. Hier finden Sie alle Informationen zur Familienversicherung."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Sowohl in der gesetzlichen Krankenversicherung als auch in der sozialen Pflegeversicherung haben Sie die Möglichkeit, Familienmitglieder beitragsfrei mitzuversichern. In der Familienversicherung können Sie Familienangehörige mitversichern, wenn diese einen Wohnsitz oder gewöhnlichen Aufenthalt in Deutschland haben, nicht versicherungsfrei oder von der Versicherung befreit sind, kein über einer bestimmten Grenze liegendes regelmäßiges Gesamteinkommen haben."},"url":"https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/familienversicherung","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:38.445225+00:00","lastSeen":"2026-03-15T17:53:38.445225+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinder-jugendliche/familienversicherung","crawledAt":"2026-03-15T17:53:38.445225Z","crawlId":"contacts-seeded-1773597218","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"ed18739f0fb808f4b6b16f3e39489ea16cd24a5026f0d1e61f80e3266a2acf6b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:38.445225+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7949c5bb-e4fb-4d00-a392-a2dac25b663a', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/gesundheit-erholung', 'active', NULL, '2026-03-15T17:53:39.025492+00:00', '{"id":"7949c5bb-e4fb-4d00-a392-a2dac25b663a","title":"Gesundheit & Erholung","summary":{"de":"Hier finden Sie Informationen zu Kuren, Familienerholung und das Thema Gesundheit und Ernährung."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Die Verantwortung für eine Familie zu tragen kann außerordentlich anstrengend und für Körper und Psyche sehr belastend sein. Wenn Sie im Zusammenhang mit familiären Belastungen ein erhöhtes Risiko für bestimmte Krankheiten haben oder schon krank sind, haben Sie einen gesetzlichen Anspruch auf stationäre Vorsorge- und Rehabilitationsmaßnahmen. Das Müttergenesungswerk unterstützt mit über 70 Einrichtungen bundesweit Mütter, Väter und pflegende Angehörige mit umfassenden Gesundheitsangeboten. Die vom Müttergenesungswerk anerkannten, gemeinnützigen Kliniken bieten Kuren für Mütter und Väter sowie für pflegende Angehörige an. Es gibt Mütter-Kuren (ohne Kinder), Mutter-Kind-Kuren und Vater-Kind-Kuren oder Kuren speziell für pflegende Angehörige. Die Mutter-Kind-Kuren und Vater-Kind-Kuren sind eine Pflichtleistung der gesetzlichen Krankenversicherung. Eine solche Kur dauert in der Regel drei Wochen und soll Ihnen helfen, den Alltag besser zu meistern und mit Zuversicht in die Zukunft zu schauen. Wenn bei Ihnen eine Kurbedürftigkeit vorliegt, kann Ihr Arzt Ihnen eine Kur verschreiben, die Sie dann bei ihrer Krankenkasse beantragen müssen. Wenn Sie den gesetzlichen Eigenanteil für eine Kur nicht bezahlen können, können Sie Unterstützung beim Deutschen Müttergenesungswerk beantragen. Die Beratungsstellen der Wohlfahrtsverbände im Müttergenesungswerk-Verbund stehen als Anlaufpunkte für Fragen zu Mütter-Kuren sowie Mutter-Kind-Kuren oder Vater-Kind-Kuren zur Verfügung. Sie erhalten dort Unterstützung beim Antragsverfahren, bei der Wahl der geeigneten Klinik sowie Hilfe bei der Organisation der Kurmaßnahme. Die nächstgelegene Beratungsstelle finden Sie auf der Internetseite des Deutschen Müttergenesungswerks. Dort gibt es auch nähere Informationen zu den Schwerpunktmaßnahmen für alleinerziehende Mütter und Väter."},"url":"https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/gesundheit-erholung","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:39.025492+00:00","lastSeen":"2026-03-15T17:53:39.025492+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinder-jugendliche/gesundheit-erholung","crawledAt":"2026-03-15T17:53:39.025492Z","crawlId":"contacts-seeded-1773597219","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"57efccfac787b570c18fa3a965deb5f635f287744ddd837f6e2a76b9a10683d6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:39.025492+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('044d5708-6f92-473d-8ed6-7614c9dbd8e2', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/kinder-jugendschutz', 'active', NULL, '2026-03-15T17:53:39.526711+00:00', '{"id":"044d5708-6f92-473d-8ed6-7614c9dbd8e2","title":"Kinder- & Jugendschutz","summary":{"de":"Was ist der Kinder- und Jugendschutz? Wie kann ich mein Kind vor Alkoholmissbrauch schützen? Hier finden Sie Antworten auf diese und weitere Fragen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Kinder und Jugendliche sind sich nicht immer der Gefahren und Risiken des Alltags bewusst. Deshalb ist es wichtig, sie vor Gewalt, Missbrauch, Vernachlässigungen und anderen gefährdenden Einflüssen zu schützen. Helfen Sie Ihrem Kind dabei, Gefahren zu erkennen. Unter Mitwirkung der Erzieherinnen und Erzieher in den Kitas und der Lehrerinnen und Lehrer in der Schule sind Sie gefordert, Ihrem Kind alle Kompetenzen zu vermitteln, die es braucht, und ihm Grenzen aufzuzeigen. Aber auch der Staat setzt sich für das Wohl von Kindern und Jugendlichen ein und unterstützt Eltern in ihrem Erziehungsauftrag. Das \"Übereinkommen über die Rechte des Kindes\" wurde am 20. November 1989 von der Vollversammlung der Vereinten Nationen verabschiedet. Am 5. April 1992 trat die Kinderrechtskonvention in Deutschland in Kraft. Sie regelt umfassend den Schutz, die Förderung und Befähigung sowie die Teilhabe und Beteiligung von Kindern und Jugendlichen und gilt in fast allen Staaten der Erde. In Deutschland ist der Kinder- und Jugendschutz eine staatliche Aufgabe mit Verfassungsrang. Er fällt unter den Auftrag der öffentlichen Fürsorge (Artikel 74 Absatz 1 Nr. 7 Grundgesetz). Dadurch ist der Staat verpflichtet, Eltern bei der Erziehung ihrer Kinder, zum Schutz vor Gefährdungen und zum Schutz des Kindeswohls, zu unterstützen (sogenanntes \"Wächteramt\" auf Basis von Artikel 6 Absatz 2 Satz 2 Grundgesetz). Kinder und Jugendliche bedürfen entsprechend ihrem Alter und Entwicklungsstand des Schutzes, der Hilfe und der Förderung, um sich zu eigenverantwortlichen Persönlichkeiten innerhalb der sozialen Gemeinschaft zu entwickeln und an ihr teilzuhaben. Deshalb hat das Grundrecht auf Entfaltung ihrer Persönlichkeit (Artikel 2 Absatz 1 Grundgesetz) sowie der Schutz der Menschenwürde (Artikel 1 Absatz 1 Grundgesetz) für sie eine besondere Bedeutung."},"url":"https://familienportal.de/familienportal/lebenslagen/kinder-jugendliche/kinder-jugendschutz","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:39.526711+00:00","lastSeen":"2026-03-15T17:53:39.526711+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinder-jugendliche/kinder-jugendschutz","crawledAt":"2026-03-15T17:53:39.526711Z","crawlId":"contacts-seeded-1773597219","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"d30d63e32643cedafa38cd2eb2200e6ce797f5aea2ba0f298a360274e04dc976"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:39.526711+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('05b63e72-50c5-46d2-9577-2948710dc629', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/adoption', 'active', NULL, '2026-03-15T17:53:40.487719+00:00', '{"id":"05b63e72-50c5-46d2-9577-2948710dc629","title":"Adoption","summary":{"de":"Informationen des Bundesfamilienministeriums zu den Themen Adoption, Vermittlung, Voraussetzungen, finanzielle Hilfen und weiteres mehr..."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. In Deutschland dürfen Adoptionen nur von bestimmten Stellen vermittelt werden. Wenn Sie ein Kind adoptieren möchten, wenden Sie sich an: Adoptionsdienst in evangelischer Trägerschaft oder die Adoptionsvermittlungsstelle in nichtkonfessioneller Trägerschaft. Die Adoptionsvermittlungsstellen haben den Auftrag, für jedes zu vermittelnde Kind die Eltern auszuwählen, die am besten zum Kind passen. Dabei stehen das Wohl des Kindes und die Wahrung seiner Rechte und Bedürfnisse im Mittelpunkt. Es besteht kein Rechtsanspruch auf Vermittlung eines Kindes. Im Zentrum jeder Adoption steht das Wohl des Kindes. Das heißt, es werden die besten Eltern für ein Kind gesucht, das aus unterschiedlichen Gründen nicht bei seinen leiblichen Eltern aufwachsen kann. Ziel einer Adoption ist es, dass das Kind Geborgenheit und Zuwendung in einer neuen Familie findet."},"url":"https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/adoption","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:40.487719+00:00","lastSeen":"2026-03-15T17:53:40.487719+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/adoption","crawledAt":"2026-03-15T17:53:40.487719Z","crawlId":"contacts-seeded-1773597220","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"60efb70664094907a7346282b232423319f9e4a8c9239c129a207ddceecd14f2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:40.487719+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b77a1188-f601-45f3-a8f1-79bed06f150d', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/kinderwunsch', 'active', NULL, '2026-03-15T17:53:40.955948+00:00', '{"id":"b77a1188-f601-45f3-a8f1-79bed06f150d","title":"Kinderwunsch","summary":{"de":"Hier finden Sie Informationen zu ungewollter Kinderlosigkeit, Kinderwunsch-Behandlung und finanzielle Zuschüssen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Frauen und Männer, die auf natürlichem Weg keine Kinder bekommen können, haben die Möglichkeit sich reproduktionsmedizinisch behandeln zu lassen. Den verschiedenen reproduktionsmedizinischen Behandlungsmethoden gehen meist ärztliche Untersuchungen voraus, um Gründe und Ursachen zu diagnostizieren und die geeignete Methode auszuwählen. Unerfüllter Kinderwunsch – Behandlungs­möglichkeiten © BMFSFJ Von ungewollter Kinderlosigkeit spricht man, wenn nach zwölf Monaten mit regelmäßigem ungeschütztem Geschlechtsverkehr (ca. zweimal pro Woche), keine Schwangerschaft eingetreten ist. Eine ungewollte Kinderlosigkeit kann körperliche Gründe haben, die Fertilität kann aufgrund emotionaler Belastungen oder aufgrund einer ungesunden Lebensweise beeinträchtigt sein. Manche Paare schieben den Kinderwunsch so lange auf, bis es aufgrund ihres Alters schwierig wird, dass eine Schwangerschaft auf natürlichem Wege eintritt. Wenn Sie nicht schwanger werden, ist es wichtig, sich untersuchen zu lassen: Reproduktionsmedizinische Zentren oder Spezialpraxen bieten umfassende Diagnose- und Behandlungsmöglichkeiten an. Eine gute Übersicht, wenn auch nicht vollständig, da die Angaben freiwillig sind, bietet die Datenbank auf dem Informationsportal-Kinderwunsch.de."},"url":"https://familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/kinderwunsch","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:40.955948+00:00","lastSeen":"2026-03-15T17:53:40.955948+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/kinderwunsch-adoption/kinderwunsch","crawledAt":"2026-03-15T17:53:40.955948Z","crawlId":"contacts-seeded-1773597220","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"1532cc75a852b64b09eba90b92f3ef475d0a0ff36742b647612b15b91f7fdd59"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:40.955948+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('800c47aa-fe5d-4468-8ac1-58b66ea8450c', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/krisetelefone-anlaufstellen', 'active', NULL, '2026-03-15T16:06:54.374311+00:00', '{"id":"800c47aa-fe5d-4468-8ac1-58b66ea8450c","title":"Krisentelefone & Anlaufstellen in schwierigen Situationen","summary":{"de":"Ob Probleme mit dem Partner, am Arbeitsplatz oder finanzielle Schwierigkeiten: In Notsituationen können Sie Hilfe und professionelle Beratung erhalten."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Ganz gleich, ob Sie Probleme mit dem Partner oder im Job haben oder in finanziellen Schwierigkeiten sind - in Notlagen können Sie Hilfe und professionelle Beratung erhalten. Beratungsangebot der Antidiskriminierungsstelle des Bundes Hilfe vor Ort: Einrichtungen, die bei Gewalt und Missbrauch helfen Frag Oskar: Sorgentelefon vom Bundesverband Kinderhospiz Pflegetelefon und Informationsportal Wege zur Pflege"},"url":"https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/krisetelefone-anlaufstellen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:54.374311+00:00","lastSeen":"2026-03-15T16:06:54.374311+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/krise-und-konflikt/krisetelefone-anlaufstellen","crawledAt":"2026-03-15T16:06:54.374311Z","crawlId":"contacts-seeded-1773590814","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"0df06c76ed60c7ba9d1b9201db1e786251360e58df53bf947b0900efd7e22863"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:06:54.374311+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ef7ef7f9-3cd4-4c73-8561-ddafdb0654f1', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/tod-eines-angehoerigen', 'active', NULL, '2026-03-15T17:53:41.941807+00:00', '{"id":"ef7ef7f9-3cd4-4c73-8561-ddafdb0654f1","title":"Tod eines Angehörigen","summary":{"de":"Hilfe für Verwitwete und Waisen: Hier finden Sie Antworten auf wichtige Fragen nach dem Tod eines Angehörigen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Verwitwete und Waisen erhalten zur Absicherung nach einem Todesfall eine Hinterbliebenenrente. Wenn Sie einen Elternteil oder gar beide verloren haben, können Sie eine Waisenrente bekommen. Wenn Ihr Ehemann oder Ihre Ehefrau verstorben ist, können Sie die Witwenrente oder Witwerrente bekommen. Mehr Informationen zur Waisenrente und Hinterbliebenenrente für Verwitwete finden Sie auf den Seiten der Deutschen Rentenversicherung. Verwitwete Elternteile gelten als Alleinerziehende. Hier finden Sie Informationen zu Unterstützungsangeboten für alleinerziehende Eltern. Wenn Sie verwitwet sind, können Sie für Ihr Kind Unterhaltsvorschuss bekommen. Weitere Informationen finden Sie unter Unterhaltsvorschuss für Verwitwete. Verwitwete und Waisen erhalten zur Absicherung nach einem Todesfall eine Hinterbliebenenrente. Diese wird nicht bei der Berechnung des Elterngeldes berücksichtigt. Allerdings kann das Elterngeld Einfluss auf die Höhe der Hinterbliebenenrente haben. Mehr dazu finden Sie unter Elterngeld für Verwitwete und Waisen."},"url":"https://familienportal.de/familienportal/lebenslagen/krise-und-konflikt/tod-eines-angehoerigen","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:41.941807+00:00","lastSeen":"2026-03-15T17:53:41.941807+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/krise-und-konflikt/tod-eines-angehoerigen","crawledAt":"2026-03-15T17:53:41.941807Z","crawlId":"contacts-seeded-1773597221","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"f58a0a821502a477bbd8f968c1f58508633fc833ab5bc9f10365d4829d5b1e67"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:41.941807+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d7686dec-91d8-4f8e-9331-4d5fa4431a9f', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/ausbildung-arbeit-mit-behinderung', 'active', NULL, '2026-03-15T17:53:42.961955+00:00', '{"id":"d7686dec-91d8-4f8e-9331-4d5fa4431a9f","title":"Ausbildung und Arbeit mit Behinderung","summary":{"de":"Um Menschen mit Behinderungen die Teilhabe am allgemeinen Arbeitsmarkt zu ermöglichen, gibt es besondere Hilfen und Angebote."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Menschen mit Behinderungen finden häufig nur schwer eine Beschäftigung auf dem allgemeinen Arbeitsmarkt. Besondere Hilfestellungen und Angebote können betroffenen Menschen die Teilhabe am Arbeitsleben ermöglichen. Hier finden Sie eine Übersicht: Besteht aufgrund der Beeinträchtigung Bedarf auf besondere Unterstützung während der Ausbildung, haben junge Menschen mit Behinderungen die Möglichkeit in einem Berufsbildungswerk eine erste Berufsausbildung in einem anerkannten Ausbildungsberuf zu erhalten. Berufsbildungswerke sind meistens eine Kombination aus Ausbildungsstätten, Berufsschulen und Wohngelegenheiten. Zudem wird der Ausbildungsweg fachlich betreut und somit die Selbstständigkeit und Entwicklung der Persönlichkeit gefördert. Bei Ihrer Arbeitsagentur erhalten Sie mehr Informationen über eine passende Einrichtung. Die Mitarbeiterinnen und Mitarbeiter beraten die Jugendlichen über die verschiedenen Ausbildungsmöglichkeiten. Anträge auf die Förderung der Ausbildung können Sie bei Ihrer örtlichen Arbeitsagentur stellen. Bei der Bundesarbeitsgemeinschaft Berufsbildungswerke e.V. finden Sie Berufsbildungswerke in Ihrer Nähe. Eine Behinderung sollte kein Grund sein, um nicht zu studieren. Damit auch junge Menschen mit Beeinträchtigungen eine Hochschule besuchen können, gibt es verschiedene Hilfsangebote:"},"url":"https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/ausbildung-arbeit-mit-behinderung","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:42.961955+00:00","lastSeen":"2026-03-15T17:53:42.961955+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/ausbildung-arbeit-mit-behinderung","crawledAt":"2026-03-15T17:53:42.961955Z","crawlId":"contacts-seeded-1773597222","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"50eda8d69292f18f2dde511c7e8145d1b2fcce8b1ee3f88d521f1fbf78a182c5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:42.961955+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4d6ccd88-ec01-49b7-803c-ed2e1d17b316', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/bedarfsgerechtes-wohnen', 'active', NULL, '2026-03-15T17:53:43.486003+00:00', '{"id":"4d6ccd88-ec01-49b7-803c-ed2e1d17b316","title":"Bedarfsgerechtes Wohnen","summary":{"de":"Um Menschen mit Behinderung bedarfsgerechtes Wohnen zu ermöglichen, gibt es zahlreiche Hilfsangebote. Hier finden Sie alle Informationen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Für viele Menschen mit Beeinträchtigungen ist das Leben in einer normalen Wohnung oft schwierig bis unmöglich. Deshalb gibt es Hilfsangebote, die das bedarfsgerechte Wohnen ermöglichen und den Wohnalltag erleichtern. Beim Wohnungsamt können Menschen mit Behinderungen einen Wohnberechtigungsschein oder Dringlichkeitsschein erhalten. Mit dem Schein haben Sie Anspruch auf günstigere Wohnungen. Auch das Sozialamt kann Ihnen bei der Wohnungssuche helfen. Eine barrierefreie Einrichtung erleichtert das Leben von Menschen mit Behinderungen erheblich. Die Soziale Wohnraumförderung fördert deshalb den Bau und Umbau von behinderungsgerechten Wohnungen. Wenn Hilfsmittel im Haushalt ergänzt werden müssen oder Sie die Wohnung sogar umbauen müssen, können die Kosten von unterschiedlichen Trägern übernommen werden. Welcher Träger für welche Kosten zuständig ist, ist manchmal kompliziert nachzuvollziehen. Informieren Sie sich bei den unterschiedlichen Kostenträgern, über mögliche Leistungen. Bundesarbeitsgemeinschaft der Integrationsämter und Hauptfürsorgestellen (BIH) Einige Länder und Kommunen bieten öffentliche Fördermittel für notwendige Umbaumaßnahmen an. Die Fördersuche des Bundeswirtschaftsministeriums kann Ihnen helfen, Fördermittel zu finden."},"url":"https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/bedarfsgerechtes-wohnen","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:43.486003+00:00","lastSeen":"2026-03-15T17:53:43.486003+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/bedarfsgerechtes-wohnen","crawledAt":"2026-03-15T17:53:43.486003Z","crawlId":"contacts-seeded-1773597223","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"54429ff7ff43218c143eebac608dcce746a20a9e0e53a486b5ced1940f6d5a8d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:43.486003+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('372bdb6d-a9bf-47b3-a72c-fa7526c457b6', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/eltern-mit-behinderung', 'active', NULL, '2026-03-15T17:53:43.939636+00:00', '{"id":"372bdb6d-a9bf-47b3-a72c-fa7526c457b6","title":"Eltern mit Behinderung","summary":{"de":"Verschiedene Hilfsangebote können das Leben von Eltern mit Behinderungen erleichtern. Hier finden Sie weitere Informationen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Eine Behinderung sollte dem Wunsch nach einem Kind nicht im Wege stehen. Elternsein ist manchmal anstrengend, besonders wenn man körperlich oder psychisch beeinträchtigt ist. Verschiedene Hilfsangebote erleichtern das Leben von Eltern mit Behinderungen. Jeder Mensch hat das Recht eine Familie zu gründen. Menschen mit Behinderungen dürfen selbst entscheiden, ob sie ein Kind bekommen möchten. Auch die Anzahl der Kinder ist ihre persönliche Entscheidung. Das Sorgerecht haben immer die Eltern. Das gilt auch für Eltern mit Behinderungen. Das Jugendamt kann im Einzelfall prüfen, ob das Kindeswohl gegeben ist. Im Streitfall kann ein Familiengericht darüber entscheiden. Elterngeld ist eine Leistung für Eltern von Säuglingen und Kleinkindern. Es soll den Eltern ermöglichen, ihr Kind zu erziehen und zu betreuen. Wenn Sie Ihr Kind betreuen, können Sie Elterngeld bekommen. Wenn Sie weitere Kinder haben, die ebenfalls in Ihrem Haushalt leben, dann können Sie einen Zuschlag auf Ihr Elterngeld erhalten - den sogenannten \"Geschwisterbonus\". Für Eltern von Kindern mit Behinderungen gelten hierbei besondere Regelungen."},"url":"https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/eltern-mit-behinderung","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:43.939636+00:00","lastSeen":"2026-03-15T17:53:43.939636+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/eltern-mit-behinderung","crawledAt":"2026-03-15T17:53:43.939636Z","crawlId":"contacts-seeded-1773597223","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"ff377a4142f970ea093537e719c92e9e74a34866f4a5ea5fa8b0a465f21cbb9b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:43.939636+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6832f12a-16f8-4bcd-a382-70ace7d4146f', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/gesundheit-und-praevention', 'active', NULL, '2026-03-15T17:53:44.456568+00:00', '{"id":"6832f12a-16f8-4bcd-a382-70ace7d4146f","title":"Gesundheit und Prävention","summary":{"de":"Alle Möglichkeiten für gesundheitsfördernde Maßnahmen für Menschen mit Behinderungen finden Sie hier."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Menschen mit Behinderungen benötigen häufig besondere Unterstützung und gesundheitsfördernde Maßnahmen. Welche Möglichkeiten es gibt, zeigt unsere Übersicht. Verschiedene Untersuchungen können dabei helfen, eine Erkrankung oder Behinderung frühzeitig zu erkennen und zu behandeln und über Möglichkeiten der Förderung der Gesundheit zu informieren. Die Untersuchungen finden in unterschiedlichen Lebensphasen des Kindes statt. Untersuchungen während der Schwangerschaft dienen dazu, mögliche Gefahren für Leben und Gesundheit von Mutter und Kind zu erkennen und abzuwenden. Und es sollen Erkrankungen rechtzeitig erkannt und frühzeitig behandelt werden. Viele Vorsorgeuntersuchungen werden von der Krankenkasse bezahlt. Auf Familienplanung.de finden Sie weiterführende Informationen über die Untersuchungen der Pränataldiagnostik. Als Eltern haben Sie das Recht darauf, nicht über die Behinderung Ihres Kindes informiert zu werden. Dafür müssen Sie den Wunsch der Ärztin oder dem Arzt mitteilen. Bis zum 7. Geburtstag des Kindes gibt es – beginnend ab der Geburt und im Säuglings- und Kleinkinderalter - aktuell insgesamt zehn Gesundheitsuntersuchungen für Ihr Kind, die sogenannten U-Untersuchungen. Die Untersuchungen dienen dazu, den Gesundheitszustand zu untersuchen und Entwicklungsverzögerungen, Erkrankungen und Behinderungen möglichst früh festzustellen. Die Ärztinnen und Ärzte untersuchen unter anderem die Entwicklung von Sprache, Bewegung und Wachstum oder die Fähigkeiten des Hören und Sehens. Dabei berät die Ärztin oder der Arzt auch über Möglichkeiten der Gesundheits- und Entwicklungsförderung."},"url":"https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/gesundheit-und-praevention","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:44.456568+00:00","lastSeen":"2026-03-15T17:53:44.456568+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/gesundheit-und-praevention","crawledAt":"2026-03-15T17:53:44.456568Z","crawlId":"contacts-seeded-1773597224","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"0a99df661847e59c8a8b378c587af6b356b81ee1f7852edf3e59d2535d7e0347"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:44.456568+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('453f1db0-1eb8-4449-a59b-9a19689b2e1e', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/unterstuetzung-und-finanzielles', 'active', NULL, '2026-03-15T17:53:44.978905+00:00', '{"id":"453f1db0-1eb8-4449-a59b-9a19689b2e1e","title":"Staatliche Leistungen für Menschen mit Behinderung","summary":{"de":"Für Menschen mit Behinderungen oder pflegende Angehörige gibt es zahlreiche staatliche Leistungen. Welche Ihnen zustehen, erfahren Sie hier."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Eltern von Kindern mit Behinderungen können eine Reihe von finanziellen Leistungen und Unterstützungen bekommen. Einen ersten Überblick erhalten Sie hier. Der Mutterschutz ist ein besonderer Schutz für Arbeitnehmerinnen, die schwanger sind oder ein Kind stillen. Wenn bei Ihrem Kind in den ersten Wochen nach der Geburt eine Behinderung festgestellt wird, gelten besondere Regelungen. Hier erfahren Sie mehr über die Mutterschutzfrist im Fall, dass das Kind mit Behinderung zur Welt kam. In diesem Zeitraum haben Sie auch Anspruch auf Mutterschaftsleistungen. Die Mutterschaftsleistungen sichern Ihr Einkommen während der Schwangerschaft und nach der Geburt. Elterngeld ist eine Leistung für Eltern von Säuglingen und Kleinkindern. Es soll den Eltern ermöglichen, ihr Kind zu erziehen und zu betreuen. Wenn Sie weitere Kinder haben, die ebenfalls in Ihrem Haushalt leben, dann können Sie einen Zuschlag auf Ihr Elterngeld erhalten - den sogenannten Geschwisterbonus."},"url":"https://familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/unterstuetzung-und-finanzielles","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:44.978905+00:00","lastSeen":"2026-03-15T17:53:44.978905+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/leben-mit-behinderung/unterstuetzung-und-finanzielles","crawledAt":"2026-03-15T17:53:44.978905Z","crawlId":"contacts-seeded-1773597224","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"8c5132b635c03e4062731f149cbfe1e7f99464bc211458ffc81c2d61823ffbd1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:44.978905+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fa098324-aff4-4da3-87c7-2ae37eccf116', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/pflegefamilien/was-sollte-ich-fuer-eine-pflegeelternschaft-mitbringen-', 'active', NULL, '2026-03-15T17:53:46.075841+00:00', '{"id":"fa098324-aff4-4da3-87c7-2ae37eccf116","title":"Was sollte ich für eine Pflegeelternschaft mitbringen?","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Pflegefamilien sind ganz unterschiedlich. Wichtig ist vor allem, dass Sie sich der Aufgabe gewachsen fühlen und bereit sind, eng mit dem Jugendamt und den leiblichen Eltern zusammenzuarbeiten. Die Pflegeelternschaft ist unabhängig vom Familienstand möglich. Es können Paare mit und ohne Kinder, heterosexuelle oder gleichgeschlechtliche Paare oder auch Alleinstehende sein. Zwar gibt es keine starren Altersgrenzen für die Aufnahme eines Pflegekindes, die Pflegekinderdienste stellen jedoch sicher, dass es einen familienentsprechenden Altersunterschied zwischen Ihnen und Ihrem Pflegekind gibt. In der Regel sollten Sie nicht jünger als 25 Jahre sein. Wenn das Pflegekind volljährig wird, sollten Sie nicht älter als 63 Jahre sein. In der Regel müssen Sie geordnete wirtschaftliche Verhältnisse und ausreichend Wohnraum nachweisen. Vorzulegen sind ein erweitertes Führungszeugnis und ein ärztliches Attest. Eine Berufstätigkeit stellt grundsätzlich keinen Hinderungsgrund für die Aufnahme eines Pflegekindes dar. Als Pflegeeltern haben Sie, wie alle Eltern, einen Anspruch auf Elternzeit."},"url":"https://familienportal.de/familienportal/lebenslagen/pflegefamilien/was-sollte-ich-fuer-eine-pflegeelternschaft-mitbringen-","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:46.075841+00:00","lastSeen":"2026-03-15T17:53:46.075841+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/pflegefamilien/was-sollte-ich-fuer-eine-pflegeelternschaft-mitbringen-","crawledAt":"2026-03-15T17:53:46.075841Z","crawlId":"contacts-seeded-1773597226","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"69d7d046abd10d760f9e951d7d3773061e28f2671f66571fc597bb89f0a9db33"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:46.075841+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('20a9c987-c67d-4114-9b91-ddb9e35e6601', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/pflegefamilien/was-sollte-ich-ueber-pflegeelternschaft-allgemein-wissen-', 'active', NULL, '2026-03-15T17:53:46.544493+00:00', '{"id":"20a9c987-c67d-4114-9b91-ddb9e35e6601","title":"Was sollte ich über Pflegeelternschaft allgemein wissen?","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Als Pflegefamilie öffnen Sie Ihr Zuhause für ein Kind, das aus verschiedenen Gründen (gerade) nicht bei seinen Eltern leben kann. Das Jugendamt vermittelt ein Kind vorübergehend oder längerfristig an eine Pflegefamilie, wenn eine dem Kindeswohl entsprechende Erziehung in der eigenen Familie - auch zeitweise - nicht möglich ist. Als Pflegeeltern begleiten Sie den jungen Menschen im Alltag, tragen Verantwortung und schenken ihm Zuwendung, Erziehung und Fürsorge. Sie gestalten zusammen ein \"neues\" - gegebenenfalls weiteres und zeitlich befristetes - Zuhause. In Pflegefamilien können alle Kinder und Jugendlichen mit und ohne Behinderung aufgenommen werden, die (zeitweise) nicht mehr bei ihrer Familie leben können. Die Kinder sind oft noch sehr jung, es können aber auch ältere Kinder und Jugendliche in Pflegefamilien aufgenommen werden. Ausschlaggebend ist der individuelle Bedarf des jungen Menschen. Wie lange ein Kind in einer Pflegefamilie lebt, kann sehr verschieden sein. In der sogenannten Bereitschaftspflege oder Übergangspflege bleibt ein Kind in der Regel nur für kurze Zeit, zum Beispiel, wenn in seiner Familie gerade eine akut schwierige Situation besteht. In anderen Fällen richtet sich die Dauer nach dem Bedarf des Kindes und danach, ob und wann eine Rückkehr zu den Eltern möglich ist. Wenn das nicht möglich ist, kann aus dem zeitlich begrenzten auch ein dauerhaftes Zuhause werden. Sie haben bereits den ersten Schritt gemacht, um Pflegefamilie oder Pflegeperson zu werden: Sie informieren sich über Pflegefamilien und was es bedeutet, das eigene Zuhause für ein (weiteres) Kind zu öffnen. Bei Ihrem Jugendamt und Pflegekinderdienst erhalten Sie weitere Informationen. Diese bieten regelmäßig Informationsveranstaltungen für Interessierte an, denn es gibt einen großen Bedarf an engagierten Pflegefamilien. Dort werden Sie über die Voraussetzungen, den Ablauf und die Unterstützungsangebote informiert. Zudem werden Schulungen und Seminare angeboten, die Sie auf die Aufgabe als Pflegeeltern vorbereiten. In einer Kennenlernphase kommen sich Pflegekind und Pflegeeltern näher und überprüfen, ob sie zusammenpassen. Nur nach einem gemeinsamen Einverständnis zwischen Pflegeeltern, Träger und dem Jugendamt wird das Pflegekind auch vermittelt."},"url":"https://familienportal.de/familienportal/lebenslagen/pflegefamilien/was-sollte-ich-ueber-pflegeelternschaft-allgemein-wissen-","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:46.544493+00:00","lastSeen":"2026-03-15T17:53:46.544493+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/pflegefamilien/was-sollte-ich-ueber-pflegeelternschaft-allgemein-wissen-","crawledAt":"2026-03-15T17:53:46.544493Z","crawlId":"contacts-seeded-1773597226","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"38a073a543f724fb098376aed001270918e796b990607a212793b225c8655ec9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:46.544493+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a9a3d736-50a1-426a-a806-14c6c66ab401', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/pflegefamilien/wie-ist-der-rechtliche-status-von-pflegefamilien-', 'active', NULL, '2026-03-15T17:53:47.057365+00:00', '{"id":"a9a3d736-50a1-426a-a806-14c6c66ab401","title":"Wie ist der rechtliche Status von Pflegefamilien?","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Das Sorgerecht verbleibt entweder bei den leiblichen Eltern oder geht auf eine Vormundin oder einen Vormund über. Pflegeeltern erhalten die Vollmacht, um Entscheidungen im Alltag für das Pflegekind zu treffen. Die leiblichen Eltern haben ein Recht auf Umgang mit ihrem Kind. Dies gilt auch, wenn ihnen die elterliche Sorge entzogen wurde. Nur bei Gefährdung des Kindeswohls kann dieses Recht zeitweise ruhen. Zu den Aufgaben von Pflegeeltern gehört es, die Beziehung des Pflegekindes zu seinen Eltern zu unterstützen, beispielsweise indem sie Besuche ermöglichen. Das Pflegekind bleibt rechtlich das Kind seiner (leiblichen) Eltern. Ziel ist es, ihm für die Zeit, in der es nicht bei seinen Eltern leben kann, ein stabiles Familienumfeld zu geben. In manchen Fällen kann sich daraus später auch eine Adoption ergeben. Zum Beispiel dann, wenn eine Rückkehr zur leiblichen Familie ausgeschlossen ist. In diesem Fall können die Eltern, die Pflegeeltern und das Jugendamt gemeinsam überlegen, ob ein Dauerpflegeverhältnis oder eine Adoption in Betracht kommt."},"url":"https://familienportal.de/familienportal/lebenslagen/pflegefamilien/wie-ist-der-rechtliche-status-von-pflegefamilien-","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:47.057365+00:00","lastSeen":"2026-03-15T17:53:47.057365+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/pflegefamilien/wie-ist-der-rechtliche-status-von-pflegefamilien-","crawledAt":"2026-03-15T17:53:47.057365Z","crawlId":"contacts-seeded-1773597227","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"c68efd00447eea4ad1441229476d6137fa4ea9f60cccb4681cdbeebec70489d3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:47.057365+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ff6d03f6-65c5-4185-be2b-d478c1bb859f', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/pflegefamilien/wie-werden-pflegefamilien-unterstuetzt-', 'active', NULL, '2026-03-15T17:53:47.562475+00:00', '{"id":"ff6d03f6-65c5-4185-be2b-d478c1bb859f","title":"Wie werden Pflegefamilien unterstützt?","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Als Pflegeeltern steht Ihnen ein monatliches Pflegegeld zu, das von Ihrem Jugendamt ausgezahlt wird. Pflegegeld erhalten Sie für Pflegekinder unter 18 Jahren, unter Umständen auch für Pflegekinder bis zum 21. Geburtstag, im Einzelfall bis zum 27. Geburtstag. Zuständig für die Berechnung ist Ihr Jugendamt. Mit dem Geld können Sie Kosten für Verpflegung, Unterkunft, Bekleidung und weitere Bedürfnisse des Pflegekindes decken. Das Pflegegeld enthält auch einen Anteil für Ihren Erziehungsaufwand. Die Höhe des Pflegegeldes variiert je nach Bundesland und Kommune. Auch das Alter Ihres Pflegekindes ist entscheidend für die Höhe des Betrags. Das Pflegegeld ist steuerfrei. Wenn Sie mit Ihrem Pflegekind verwandt sind, zum Beispiel als Großeltern, bekommen Sie ebenfalls Pflegegeld. Die Höhe wird in diesen Fällen nochmal individuell berechnet und kann etwas niedriger ausfallen als in den Fällen, in denen die Pflegeeltern nicht mit dem Pflegekind verwandt sind. Sie können außerdem Beihilfe und Zuschüsse für besondere Anlässe beantragen, beispielsweise für die Erstausstattung, wichtige persönliche Anlässe sowie für Urlaub und Ferienreisen. Das Kindergeld ist für den jungen Menschen bestimmt. Das Jugendamt kann daher einen Antrag auf Auszahlung des Kindergeldes an die junge Person stellen. Unter Umständen können Sie als Pflegeeltern aber auch Kindergeld erhalten. Sie müssen dafür mit Ihrem Pflegekind familienähnlich und auf längere Dauer zusammenleben. Hier erfahren Sie mehr zu den Voraussetzungen, unter denen Sie für Ihr Pflegekind Kindergeld bekommen können."},"url":"https://familienportal.de/familienportal/lebenslagen/pflegefamilien/wie-werden-pflegefamilien-unterstuetzt-","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:47.562475+00:00","lastSeen":"2026-03-15T17:53:47.562475+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/pflegefamilien/wie-werden-pflegefamilien-unterstuetzt-","crawledAt":"2026-03-15T17:53:47.562475Z","crawlId":"contacts-seeded-1773597227","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"2260e0e88678c3087f79d43e12350d75ee2f9dc4e39ce5d78ce8b1059d31d14b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:47.562475+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ad123369-de9c-44fe-8a13-a12c975eaa96', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/pflegefamilien/zeitdiepraegt', 'active', NULL, '2026-03-15T17:53:48.181797+00:00', '{"id":"ad123369-de9c-44fe-8a13-a12c975eaa96","title":"Informationen für Pflegefamilien","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Als Pflegefamilie öffnen Sie Ihr Zuhause für ein Kind, das aus verschiedenen Gründen (gerade) nicht bei seinen Eltern leben kann. Pflegefamilien bieten vielen Kindern und Jugendlichen ein neues Zuhause, in dem sie gut aufwachsen können © Theresa Maria Forthaus In Deutschland gibt es viele Kinder und Jugendliche, die aus unterschiedlichen Gründen nicht bei ihren leiblichen Eltern leben können. Sie brauchen einen sicheren Ort, an dem sie Geborgenheit, Stabilität und Zuwendung erfahren. Als Pflegefamilie schenken Sie einem Kind nicht nur ein Dach über dem Kopf, sondern vor allem Zuwendung, Fürsorge und Zeit, die prägt. Es ist eine verantwortungsvolle Aufgabe, die das Leben aller Beteiligten nachhaltig bereichert. Der Weg zur Pflegefamilie ist zunächst mit vielen offenen Fragen verbunden. Hier finden Sie alle wichtigen Informationen. Ihr persönlicher Kontakt: Finden Sie mit unserer einfachen Suche schnell und unkompliziert das für Sie zuständige Jugendamt. Antworten auf Ihre Fragen: Wir klären die häufigsten Fragen - von den notwendigen Voraussetzungen bis zur finanziellen Unterstützung. Einblicke aus erster Hand: Lesen Sie Erfahrungsberichte von Pflegefamilien, ehemaligen Pflegekindern und Expertinnen und Experten."},"url":"https://familienportal.de/familienportal/lebenslagen/pflegefamilien/zeitdiepraegt","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:48.181797+00:00","lastSeen":"2026-03-15T17:53:48.181797+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/pflegefamilien/zeitdiepraegt","crawledAt":"2026-03-15T17:53:48.181797Z","crawlId":"contacts-seeded-1773597228","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"45d415b1e0cc2902b6a901b586e1750977cdae3b3b6238123995ae39afa1512b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:48.181797+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ec237987-e7d7-466a-b42f-c918811e1adf', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/regenbogenfamilien', 'active', NULL, '2026-03-15T17:53:48.568718+00:00', '{"id":"ec237987-e7d7-466a-b42f-c918811e1adf","title":"Regenbogenfamilien","summary":{"de":"Hier finden Sie alle Informationen für Regenbogenfamilien und zu Elternschaft bei gleichgeschlechtlichen Paaren."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Regenbogenfamilien sind Familien, in denen mindestens ein Elternteil lesbisch, schwul, bisexuell, transgeschlechtlich beziehungsweise intergeschlechtlich und/ oder nichtbinär ist. Diese Familienkonstellationen können auf vielfältige Weise entstehen: Regenbogenfamilien entstehen, weil sich lesbische, schwule, bisexuelle, transgeschlechtliche und intergeschlechtliche Menschen Kinder wünschen und Familien gründen. Mütterfamilien erfüllen sich Ihren Kinderwunsch meist mithilfe einer Samenspende. Väterfamilien nehmen in Deutschland vor allem Pflegekinder auf. Manchmal werden Vater-Mutter-Kind-Familien zu Regenbogenfamilien. Zum Beispiel, wenn sich die Mutter in eine Frau verliebt oder, wenn der Vater sich als transgeschlechtlich outet. Adoptivkinder finden in Mütterfamilien oder Väterfamilien bislang nur vereinzelt ein neues Zuhause. Sie werden meist entweder im Ausland adoptiert oder lebten zuvor bereits in einem Pflegeverhältnis mit einem Mütterpaar oder Väterpaar innerhalb Deutschlands. Auch Mehrelternkonstellationen, in denen sich Menschen zusammenfinden, um einen Kinderwunsch zu verwirklichen, ohne ein Liebespaar zu sein, werden von manchen zu den Regenbogenfamilien gezählt."},"url":"https://familienportal.de/familienportal/lebenslagen/regenbogenfamilien","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:48.568718+00:00","lastSeen":"2026-03-15T17:53:48.568718+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/regenbogenfamilien","crawledAt":"2026-03-15T17:53:48.568718Z","crawlId":"contacts-seeded-1773597228","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"17e646b9f7f6d8270a12a0fa78a5647c936dcae26a811d25eae8124b81fd6d82"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:48.569710+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('622e6f74-243e-4d28-8702-ecfeabbb69b4', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/anmeldung-standesamt', 'active', NULL, '2026-03-15T17:53:49.550694+00:00', '{"id":"622e6f74-243e-4d28-8702-ecfeabbb69b4","title":"Anmeldung Ihres Kindes beim Standesamt","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Nach der Geburt müssen Sie Ihr Kind innerhalb 1 Woche beim Standesamt anmelden, das für den Geburtsort des Kindes zuständig ist. Das Standesamt stellt die Geburtsurkunde und weitere Bescheinigungen aus. Das Standesamt erledigt die Anmeldung beim Einwohnermeldeamt dann automatisch. Dies ist unter anderem für die Ausstellung eines Kinderausweises und für die Eintragung des Kindes in die Lohnsteuerkarte wichtig. Für die Anmeldung beim Standesamt benötigen Sie die Geburtsbescheinigung. Wenn Ihr Kind in einem Krankenhaus, Geburtshaus oder einer Geburtsklinik geboren wurde, benachrichtigt die Einrichtung das zuständige Standesamt und übermittelt die Geburtsbescheinigung. Wenn Ihr Kind zu Hause geboren wurde, stellen Hebammen, Geburtshelferin oder Geburtshelfer, Ärztinnen oder Ärzte die Geburtsbescheinigung aus. Diese müssen Sie dem zuständigen Standesamt dann innerhalb 1 Woche vorlegen."},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/anmeldung-standesamt","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:49.550694+00:00","lastSeen":"2026-03-15T17:53:49.550694+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/anmeldung-standesamt","crawledAt":"2026-03-15T17:53:49.550694Z","crawlId":"contacts-seeded-1773597229","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"55059f824d580d38420c255971e502660bd2c7a6a3adab6fcc535e55a33e50e7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:49.550694+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b0820777-ab6f-4a28-a1ae-407fd8c2d4eb', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/checklisten', 'active', NULL, '2026-03-15T17:53:50.073651+00:00', '{"id":"b0820777-ab6f-4a28-a1ae-407fd8c2d4eb","title":"Checklisten rund um die Geburt","summary":{"de":"Rund um die Geburt sind viele Behördengänge und andere Termine zu erledigen. Hier finden Sie alle Informationen in Checklisten."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Rund um die Geburt sind viele Behördengänge und andere Termine zu erledigen. Hier finden Sie alle wichtigen Infos auf einen Blick. In unserer praktischen Checkliste vor der Geburt (PDF, barrierefrei) erfahren Sie ausführliche Informationen und hilfreiche Tipps. Sie können die Checkliste auch herunterladen und ausdrucken. Damit für Sie als Arbeitnehmerin der Mutterschutz gilt, müssen Sie Ihrem Arbeitgeber Ihre Schwangerschaft und den errechneten Entbindungstermin mitteilen. Mutterschutzlohn beantragen, wenn Sie vor und nach den Mutterschutzfristen nicht arbeiten dürfen, zum Beispiel wegen eines ärztlichen Beschäftigungsverbots."},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/checklisten","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:50.073651+00:00","lastSeen":"2026-03-15T17:53:50.073651+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/checklisten","crawledAt":"2026-03-15T17:53:50.073651Z","crawlId":"contacts-seeded-1773597230","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"42b790086632fcab0ddf4d4d570305bba867a0c3fcea9a906c04abe339852e93"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:50.073651+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ee0d5520-1868-48fd-afe8-29d63475a24d', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/fruehgeborene', 'active', NULL, '2026-03-15T17:53:50.556262+00:00', '{"id":"ee0d5520-1868-48fd-afe8-29d63475a24d","title":"Frühgeborene","summary":{"de":"Hier finden Sie Informationen zu Hilfen, Unterstützungsangebote und staatliche Leistungen bei Frühgeburten."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Eine Schwangerschaft dauert ungefähr 40 Wochen. Wenn Ihr Baby vor der vollendeten 37. Schwangerschaftswoche geboren wird, dann ist es ein \"Frühchen\". Frühchen müssen nach der Geburt häufig auf einer Frühgeborenenstation versorgt werden. Die intensive medizinische Betreuung und Ihre elterliche Fürsorge und Nähe erhöhen die Chancen, dass Ihr Frühgeborenes zu einem gesunden Baby heranwächst. Nach wenigen Tagen oder Wochen übernehmen Sie die Pflege und Versorgung Ihres Kindes zu Hause. Diese emotionale Ausnahmesituation kann für Ihre ganze Familie eine große Belastung darstellen. Daher gibt es verschiedene Regelungen zur Entlastung und finanziellen Unterstützung für Eltern von frühgeborenen Babys. Telefonische Hilfe und Beratung finden Sie unter anderem hier: Eltern-Hotline des Bundesverbands Das frühgeborene Kind: 0800 - 875 877 0 Montag, Dienstag, Donnerstag und Freitag von 9 Uhr bis 12 Uhr und Mittwoch von 16 Uhr bis 19 Uhr Elterntelefon der Nummer gegen Kummer: 0800 - 111 0 550 Montag bis Freitag von 9 Uhr bis 17 Uhr Dienstag und Donnerstag von 9 Uhr bis 19 Uhr"},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/fruehgeborene","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:50.556262+00:00","lastSeen":"2026-03-15T17:53:50.556262+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/fruehgeborene","crawledAt":"2026-03-15T17:53:50.556262Z","crawlId":"contacts-seeded-1773597230","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"e27a0b7d2dd5083fed7a58ad08169fe0dd63c37f6592a64feb8a6b40df6b90d3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:50.556262+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d79e1414-aa0e-4d49-a01e-01ac2950f8ba', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/namensrecht-sorgerecht', 'active', NULL, '2026-03-15T17:53:51.096973+00:00', '{"id":"d79e1414-aa0e-4d49-a01e-01ac2950f8ba","title":"Namensrecht & Sorgerecht","summary":{"de":"Welchen Nachnamen bekommt mein Kind? Was regelt das Sorgerecht? Hier finden Sie Antworten zu Fragen rund um die Themen Namensrecht und Sorgerecht."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Wenn Sie für Ihr Kind sorgeberechtigt sind, können Sie den Vornamen für Ihr Kind bestimmen. Die Entscheidung, welchen Namen Ihr Kind tragen soll, treffen Sie in Ausübung der Verantwortung für Ihr Kind. Das Gesetz schreibt keine ausdrücklichen Regeln für die Bestimmung des Vornamens vor. Daher haben Sie normalerweise freie Wahl. Die Grenze der Wahlfreiheit ist aber dann erreicht, wenn durch die Wahl des Vornamens das Kindeswohl gefährdet ist. Wenn Sie gemeinsam sorgeberechtigt sind, müssen Sie den Vornamen des Kindes gemeinsam bestimmen. Anstößige oder lächerliche Vornamen verstoßen gegen das Kindeswohl. Der Name darf kein Ortsname oder Familienname sein. Wenn Sie Fragen zur Bestimmung des Vornamens haben, berät Sie Ihr zuständiges Standesamt. Informationen zur Reform des Namensrechts beim Bundesjustizministerium"},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/namensrecht-sorgerecht","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:51.096973+00:00","lastSeen":"2026-03-15T17:53:51.096973+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/namensrecht-sorgerecht","crawledAt":"2026-03-15T17:53:51.096973Z","crawlId":"contacts-seeded-1773597231","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"72420634b720f6a153594e4124cf632f2ef0057b5cc77b50cbc75d11557ce7bd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:51.096973+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('774a2674-39e4-4d16-bdee-5f840160be91', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/vaterschaftanerkennung', 'active', NULL, '2026-03-15T17:53:51.594787+00:00', '{"id":"774a2674-39e4-4d16-bdee-5f840160be91","title":"Vaterschaftsanerkennung","summary":{"de":"Wann benötige ich eine Vaterschaftsanerkennung? Wo kann ich meine Vaterschaft anerkennen lassen? Hier finden Sie Antworten zu den wichtigsten Fragen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Sind Sie mit der Mutter Ihres Kindes verheiratet, gelten Sie kraft Gesetzes als Vater, eine Vaterschaftsanerkennung ist nicht notwendig. Nach Anmeldung der Geburt werden Sie ohne weitere Schritte in die Geburtsurkunde eingetragen und sind gemeinsam mit der Mutter sorgeberechtigt. Wenn Sie zum Zeitpunkt der Geburt nicht mit der Mutter Ihres Kindes verheiratet sind, müssen Sie eine Vaterschaftsanerkennung abgeben, um rechtlich als Vater zu gelten. Die Anerkennung ist freiwillig und bedarf der Zustimmung der Mutter. Welche Dokumente Sie für die Vaterschaftsanerkennung benötigen, erfahren Sie im Bundesportal. Sie müssen Ihre Erklärung zur Anerkennung der Vaterschaft persönlich bei einer zuständigen Stelle abgeben, zum Beispiel: Die Mutter muss ebenfalls persönlich ihre Zustimmung zur Vaterschaftsanerkennung erklären. Die zuständige Stelle beurkundet die Erklärung des Vaters und die Zustimmung der Mutter. Je nach Bundesland kann die Vaterschaftsanerkennung beim Notar oder Amtsgericht kostenpflichtig sein. Sie können die Vaterschaftsanerkennung schon vor der Geburt abgeben. Die Anerkennung vor der Geburt hat den Vorteil, dass Sie nach Anmeldung der Geburt sogleich in die Geburtsurkunde Ihres Kindes eingetragen werden. Geben Sie die Vaterschaftsanerkennung erst nach der Geburt ab, muss eine neue Geburtsurkunde ausgestellt werden."},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/vaterschaftanerkennung","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:51.594787+00:00","lastSeen":"2026-03-15T17:53:51.594787+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/vaterschaftanerkennung","crawledAt":"2026-03-15T17:53:51.594787Z","crawlId":"contacts-seeded-1773597231","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"e4bc67fa5732c034a6e3adfd752f667481f5c96869324dd4ca18fa21f0d7079b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:51.594787+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('10fab4e5-1d4b-4144-b1c9-e0eb7ea96877', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/zwillinge-mehrlinge', 'active', NULL, '2026-03-15T17:53:52.045756+00:00', '{"id":"10fab4e5-1d4b-4144-b1c9-e0eb7ea96877","title":"Zwillinge & Mehrlinge","summary":{"de":"Bei der Geburt gelten für Eltern von Mehrlingen besondere Regelungen und sie erhalten zusätzliche Unterstützung."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Wenn Sie erfahren, dass Sie Zwillinge oder mehr Kinder erwarten, ist die Überraschung oft groß. Die Geburt von Mehrlingen bringt neben der Freude auch besondere Herausforderungen mit sich. Die Betreuung mehrerer Babys nimmt mehr Zeit in Anspruch als bei einem einzelnen Neugeborenen, zum Beispiel für das Füttern, Wickeln und Pflegen. Zudem muss die Babyausstattung mehrfach angeschafft werden. Daher gelten für Eltern von Mehrlingen auch besondere Regelungen und sie erhalten zusätzliche Unterstützung. Wenn Sie Zwillinge oder Mehrlinge haben, dann bekommen Sie für diese nur einmal Elterngeld. Denn das Elterngeld schafft einen Ausgleich für Ihren Verdienstausfall in der Zeit, in der Sie Ihre Kinder in den ersten Lebensmonaten betreuen und erziehen. Das Elterngeld erhöht sich aber: Sie bekommen einen Mehrlings-Zuschlag auf das Elterngeld, der sich mit der Anzahl der Mehrlinge erhöht. Bei Drillingen bekommen Sie den doppelten Zuschlag, bei Vierlingen den dreifachen, und so weiter."},"url":"https://familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/zwillinge-mehrlinge","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:52.045756+00:00","lastSeen":"2026-03-15T17:53:52.045756+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/schwangerschaft-geburt/zwillinge-mehrlinge","crawledAt":"2026-03-15T17:53:52.045756Z","crawlId":"contacts-seeded-1773597232","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"bdbcafda78239b2532d846046c012b64ba32ea24a703f748335e1cc260ca6246"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:52.045756+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0fa00249-353c-48df-8f83-7c121bb06aae', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/trennung/allein-und-getrennt-erziehende-eltern', 'active', NULL, '2026-03-15T17:53:53.078736+00:00', '{"id":"0fa00249-353c-48df-8f83-7c121bb06aae","title":"Getrennt erziehend & Alleinerziehend","summary":{"de":"Hier finden Sie Informationen und Unterstützungsangebote für getrennt Erziehende und Alleinerziehende."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Eine Trennung oder Scheidung ist traurig, häufig emotional und belastend - sowohl für die betroffenen Kinder als auch für die Eltern. Mit einer Trennung der Eltern ist in der Regel eine Auflösung der bisherigen Familie verbunden. Es findet eine Neuorientierung statt. Das Elternpaar trennt sich, die Elternschaft bleibt bestehen. Oft können Beziehungsprobleme vor, während und nach einer Trennung durch kompetente Hilfe von außen gelöst werden. Eltern haben Anspruch auf kostenlose Beratung und können umfangreiche und unbürokratische Hilfe bei einer Erziehungsberatung, Eheberatung oder Familienberatung beim Jugendamt oder freien Trägern bekommen. Nutzen Elternpaare frühzeitig Beratungsangebote, können möglicherweise Konflikte gelöst und Trennungen vermieden werden. Auch in der Trennungsphase kann die Beratung dazu führen, gemeinsame konstruktive Lösungen zu finden, um den Interessen des Kindes zu entsprechen und es ihm zu ermöglichen, eine stabile und sichere Bindung zu beiden Elternteilen beizubehalten beziehungsweise aufzubauen. Bei der Beratung durch Erziehungs- und Familienberatungsstellen (EFB) in öffentlicher und freier Trägerschaft stehen die Interessen des Kindes im Zentrum. Die Eltern sollen befähigt werden, ihrer Erziehungsverantwortung nachzukommen. Die Beratung kann auch darauf abzielen, weitere Eskalationen der Streitigkeiten zwischen den Eltern zu verhindern und sie im Interesse der Kinder wieder zu einer Kooperation auf der Elternebene zu führen. Auch spezielle Elternkurse unterstützen getrennt lebende Eltern dabei, die elterliche Erziehungskompetenz und die Kommunikation zwischen getrennten Eltern zu stärken, wie beispielhaft das Programm Kinder im Blick. Die Eltern werden nach einer Trennung darüber entscheiden, wo und in welchem Umfang das Kind oder die Kinder leben. Dabei geht es um Fragen des Sorgerechts und Umgangsrechts. Das Umgangsrecht macht deutlich, dass jedes Kind ein Recht auf Umgang mit beiden Elternteilen hat - und jeder Elternteil hat das Recht und die Pflicht zum Umgang mit dem Kind. Unabhängig von den Problemen der Eltern steht fest, dass das Wohl der Kinder im Mittelpunkt stehen muss. Daher sollten die Eltern möglichst einvernehmliche Vereinbarungen zugunsten des Kindes treffen."},"url":"https://familienportal.de/familienportal/lebenslagen/trennung/allein-und-getrennt-erziehende-eltern","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:53.078736+00:00","lastSeen":"2026-03-15T17:53:53.078736+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/trennung/allein-und-getrennt-erziehende-eltern","crawledAt":"2026-03-15T17:53:53.078736Z","crawlId":"contacts-seeded-1773597233","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"656d7004a90690b8fbc5edfca583d4063c2d450cff2bd79104b4ba6425e1f798"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:53.078736+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('33317e69-ced4-44a8-9aef-791ab28dd482', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/trennung/patchworkfamilien', 'active', NULL, '2026-03-15T17:53:53.555696+00:00', '{"id":"33317e69-ced4-44a8-9aef-791ab28dd482","title":"Patchworkfamilien","summary":{"de":"Hier finden Patchworkfamilien Informationen zum Sorgerecht, Umgangsrecht und zu finanziellen Regelungen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Aufgrund von Trennungen wandeln sich Familienstrukturen. Neue Lebenspartner mit Kindern aus früheren Beziehungen, Ex-Partner mit dem Wunsch, ins neue Familienleben integriert zu werden, oder die Adoption eines nicht leiblichen Kindes führen zu vielfältigen und komplexen Familienkonstellationen - den so genannten Stief- und Patchworkfamilien. Wenn Sie das alleinige Sorgerecht ausüben, haben Sie ein Alleinentscheidungsrecht in Angelegenheiten von erheblicher Bedeutung für das Kind. Ihre neue Ehepartnerin oder Ihr neuer Ehepartner kann bei alltäglichen Fragen mitentscheiden. Voraussetzung ist, dass Sie, als der allein sorgeberechtigte Elternteil damit einverstanden sind. Im Rahmen des Umgangsrechts kann auch der nicht alleinsorgeberechtigte Elternteil über Angelegenheiten des täglichen Lebens entscheiden. Unabhängig vom Sorgerecht können Sie, wenn sich Ihr Kind bei Ihnen aufhält, über Alltagsfragen allein entscheiden, etwa über Schlafens- und Ausgehzeiten oder Kontrollbesuche beim Arzt. Der neue Stiefelternteil hat nur eine Entscheidungsbefugnis, wenn Sie und der andere Elternteil eine Vollmacht unterschreiben, die ihm ein Erziehungs- und Mitspracherecht einräumt. Wenn Sie kein Sorgerecht haben, aber umgangsberechtigt sind, haben Sie für das Kind während der Zeit des Umgangs die Entscheidungsbefugnis für auf den Besuch bezogene alltägliche Entscheidungen."},"url":"https://familienportal.de/familienportal/lebenslagen/trennung/patchworkfamilien","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:53.555696+00:00","lastSeen":"2026-03-15T17:53:53.555696+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/trennung/patchworkfamilien","crawledAt":"2026-03-15T17:53:53.555696Z","crawlId":"contacts-seeded-1773597233","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"7a4ce49721eb81cfcd88a829339474eef1fd4e5e071d80dceb98440bbcafd7c1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:53.555696+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('26e8f96a-27df-436f-a6d7-6c1adf8e801a', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/trennung/sorgerecht-umgangsrecht-und-namensrecht', 'active', NULL, '2026-03-15T17:53:54.110041+00:00', '{"id":"26e8f96a-27df-436f-a6d7-6c1adf8e801a","title":"Sorgerecht, Umgangsrecht & Namensrecht","summary":{"de":"Sorgerecht, Umgangsrecht und Namensrecht: Hier erfahren Sie, welche Regelungen gelten."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Neben dem Wunsch, für ein gemeinsames Kind da zu sein, haben Sie auch die Pflicht und das Recht, für Ihr minderjähriges Kind zu sorgen. Die elterliche Sorge (Sorgerecht) umfasst die Sorge für die Person des Kindes (Personensorge), die Begründung sowie Änderung des Wohnsitzes und des Aufenthaltes (Aufenthaltsbestimmungsrecht), die Auswahl und Anmeldung in einer Kindertagesstätte oder Schule, In vielen Fällen tragen die Eltern die elterliche Sorge für ihr Kind gemeinsam. Sind die Eltern verheiratet, erlangen beide mit der Geburt des Kindes automatisch die gemeinsame elterliche Sorge."},"url":"https://familienportal.de/familienportal/lebenslagen/trennung/sorgerecht-umgangsrecht-und-namensrecht","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:54.110041+00:00","lastSeen":"2026-03-15T17:53:54.110041+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/trennung/sorgerecht-umgangsrecht-und-namensrecht","crawledAt":"2026-03-15T17:53:54.110041Z","crawlId":"contacts-seeded-1773597234","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"0aa70c21e2602c08e96af4ce8f89d2f063aaa1a4ae865052e4d07d2b8cd121cc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:54.110041+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dcb619a1-b0a7-42e8-ae18-52520e10127e', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/zuwanderung-und-integration/informationen-ukraine', 'active', NULL, '2026-03-15T17:53:55.070621+00:00', '{"id":"dcb619a1-b0a7-42e8-ae18-52520e10127e","title":"Informationen für Geflüchtete aus der Ukraine","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Hier finden Sie einen Überblick zu Familienleistungen für Geflüchtete, Regelungen zur Einreise nach Deutschland sowie nützliche Informationen zu Hilfsangeboten und Beratungsstellen. Geflüchtete aus der Ukraine können Kindergeld, Kinderzuschlag, Elterngeld und Unterhaltsvorschuss unter bestimmten Voraussetzungen bekommen, wenn sie eine Aufenthaltserlaubnis nach § 24 AufenthG für mindestens sechs Monate haben. Zudem müssen Sie die übrigen Voraussetzungen für die jeweilige Leistung erfüllen. Hier finden Sie weitere Informationen zu den Voraussetzungen für Kindergeld, Kinderzuschlag, Elterngeld und Unterhaltsvorschuss. Hier finden Sie Informationen zu den Familienleistungen auf Englisch und weiteren Sprachen. Informationen zu den Familienleistungen auf Ukrainisch, und Russisch und Englisch finden Sie auf dem Portal Germany4Ukraine. Darüber hinaus bietet das Portal Informationen für Schwangere und Eltern mit Kleinkind in den Sprachen Ukrainisch, Russisch und Englisch."},"url":"https://familienportal.de/familienportal/lebenslagen/zuwanderung-und-integration/informationen-ukraine","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:55.070621+00:00","lastSeen":"2026-03-15T17:53:55.070621+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/zuwanderung-und-integration/informationen-ukraine","crawledAt":"2026-03-15T17:53:55.070621Z","crawlId":"contacts-seeded-1773597235","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"383a0a35fcc35178f4e072ef1b96a2420821c83f0644e505f68d9bb71bcc45d3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:55.070621+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('36a9a8a8-e35d-4472-868d-2030ff5d5228', 'contacts', 'https://familienportal.de/familienportal/lebenslagen/zuwanderung-und-integration/zuwanderung', 'active', NULL, '2026-03-15T17:53:55.622385+00:00', '{"id":"36a9a8a8-e35d-4472-868d-2030ff5d5228","title":"Unterstützung für Zugewanderte und ihre Familien","summary":{"de":"Sie sind gerade in Deutschland angekommen und wollen wissen, an wen Sie sich für die ersten Schritte wenden sollten? Hier finden Sie wichtige Informationen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Sie sind gerade in Deutschland angekommen und wollen wissen, an wen Sie sich für die ersten Schritte in Deutschland wenden sollten? Einen Überblick über die wichtigsten Schritte nach der Einreise bietet das Bundesamt für Migration und Flüchtlinge. Wenn Sie aus einem Drittstaat nach Deutschland kommen wollen, benötigen Sie einen Aufenthaltstitel. Dieser richtet sich nach dem Zweck des Aufenthalts in Deutschland. Weitere Informationen zum Thema Einreise und Aufenthalt finden Sie auf den Seiten des Bundesamtes für Migration und Flüchtlinge. Als politische verfolgte Person haben Sie in Deutschland laut Grundgesetz ein individuelles Recht auf Asyl. Mehr Informationen zu den Themen Asyl- und Flüchtlingsschutz finden Sie beim Bundesinnenministerium. Die Sozialplattform informiert über Unterstützungsangebote, die Sie erhalten, wenn Sie Asyl beantragt haben. Informationen zu den aufenthaltsrechtlichen Regelungen für unbegleitete Minderjährige finden Sie beim Bundesamt für Migration und Flüchtlinge. Wenn Sie in Deutschland leben möchten, sollten Sie Deutsch lernen. Außerdem sollten Sie einiges über Deutschland wissen, zum Beispiel über die Geschichte, die Kultur und die Rechtsordnung. Dies bieten die Integrationskurse. Dies sind Deutschsprachkurse bis zum Sprachniveau B2. Informationen zu Integrationskursen finden Sie beim Bundesamt für Migration und Flüchtlinge. Dort erfahren Sie, wie und wo Sie an einem Integrationskurs teilnehmen können. Im Rahmen der Allgemeinen Integrationskurse gibt es auch spezielle Kursarten, zum Beispiel für Frauen, Eltern, junge Erwachsene."},"url":"https://familienportal.de/familienportal/lebenslagen/zuwanderung-und-integration/zuwanderung","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:55.622385+00:00","lastSeen":"2026-03-15T17:53:55.622385+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/lebenslagen/zuwanderung-und-integration/zuwanderung","crawledAt":"2026-03-15T17:53:55.622385Z","crawlId":"contacts-seeded-1773597235","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"835fbba70dca5405cba3538baef2f37733121aafde18cab40eda28fd9569596c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:55.622385+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('43a18fa2-f463-4e70-b96b-b65fb3b9f963', 'contacts', 'https://familienportal.de/familienportal/meta/erklaerung-zur-barrierefreiheit', 'active', NULL, '2026-03-15T17:53:57.655035+00:00', '{"id":"43a18fa2-f463-4e70-b96b-b65fb3b9f963","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Das Portal für Familien des Bundesfamilienministeriums"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend hat die Website www.familienportal.de barrierefrei gestaltet. Rechtsgrundlage sind das Behindertengleichstellungsgesetz (BGG) und die Barrierefreie-Informationstechnik-Verordnung (BITV 2.0). Die BITV 2.0 verweist im Wesentlichen auf die Web Content Accessibility Guidelines (WCAG 2.1) als Standard für die barrierefreie Gestaltung einer Website. Die Anforderungen der Barrierefreiheit ergeben sich aus §§ 3 Absätze 1 bis 4 und 4 der BITV 2.0, die auf der Grundlage von § 12d BGG erlassen wurde. Aufgrund der Überprüfung ist die Website mit den zuvor genannten Anforderungen vollständig vereinbar. Eine Überprüfung der Seite durch den BIK BITV-Test vom 11.10.2022 bestätigt die BITV-Konformität auf Basis einer repräsentativen Seitenauswahl. Falls Sie Anmerkungen in Bezug auf die barrierefreie Gestaltung von familienportal.de haben, können Sie sich gern an uns wenden. Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend Referat DG2 Glinkastraße 24 10117 Berlin info@familienportal.de Sollten Sie der Ansicht sein, durch eine nicht ausreichende barrierefreie Gestaltung von www.familienportal.de benachteiligt zu sein, können Sie sich nach §16 BGG an die Schlichtungsstelle wenden:"},"url":"https://familienportal.de/familienportal/meta/erklaerung-zur-barrierefreiheit","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:57.655035+00:00","lastSeen":"2026-03-15T17:53:57.655035+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/erklaerung-zur-barrierefreiheit","crawledAt":"2026-03-15T17:53:57.655035Z","crawlId":"contacts-seeded-1773597237","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"73467fe5f56ce3d4ad5e6f66d1080d2f381e7fff780361005af2421076b281f9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:57.655035+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dffc2e29-768c-437a-99f2-841eac7a2b15', 'contacts', 'https://familienportal.de/familienportal/meta/gebaerdensprache', 'active', NULL, '2026-03-15T17:53:58.164279+00:00', '{"id":"dffc2e29-768c-437a-99f2-841eac7a2b15","title":"Gebärdensprache","summary":{"de":"Wir erklären das Familienportal in deutscher Gebärdensprache."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Das Familienportal in Deutscher Gebärdensprache erklärt © BMFSFJ"},"url":"https://familienportal.de/familienportal/meta/gebaerdensprache","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:58.164279+00:00","lastSeen":"2026-03-15T17:53:58.164279+00:00","sourceUnavailable":false,"contactType":"accessibility","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/gebaerdensprache","crawledAt":"2026-03-15T17:53:58.164279Z","crawlId":"contacts-seeded-1773597238","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"e46f855136fccf87b1d599d120ed5609ab33be0f305aa155a85f3c952a4e54fd"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:53:58.164279+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('79c87421-efae-491b-98c1-99acc5471da8', 'contacts', 'https://familienportal.de/familienportal/meta/kontakt', 'active', NULL, '2026-03-15T16:06:54.722623+00:00', '{"id":"79c87421-efae-491b-98c1-99acc5471da8","title":"Kontakt","summary":{"de":"Wenn Sie Fragen haben oder eine Nachricht an das Bundesfamilienministerium senden wollen, können Sie das Kontaktformular auf dieser Seite nutzen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Manchmal bleibt trotz der Fülle an Informationen eine Frage offen. Wenn Sie Fragen haben oder eine Nachricht an das Bundesfamilienministerium senden wollen, nutzen Sie gern das Kontaktformular. Wir bemühen uns, Ihr Anliegen so schnell wie möglich zu bearbeiten. Um Ihre Fragen ausführlich beantworten und eventuell Informationsmaterial mitschicken zu können, geben Sie bitte zusätzlich zur E-Mail-Adresse auch Ihre Postanschrift an. Außerdem können Sie sich auch schriftlich oder telefonisch an uns wenden: 030 201 791 30 Montag bis Donnerstag von 9:00 bis 18:00 Uhr"},"url":"https://familienportal.de/familienportal/meta/kontakt","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:54.722623+00:00","lastSeen":"2026-03-15T16:06:54.722623+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://www.familienportal.de/familienportal/meta/kontakt","crawledAt":"2026-03-15T16:06:54.722623Z","crawlId":"contacts-seeded-1773590814","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"9bf4932517677922e26b1fedc9805c1c779cdb71444cdb1ef0204e5f97455e05"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:06:54.722623+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('634649b3-ecab-4723-8224-0600b2eb61cd', 'contacts', 'https://familienportal.de/familienportal/meta/languages/obiteljske-beneficije', 'active', NULL, '2026-03-15T17:53:59.229463+00:00', '{"id":"634649b3-ecab-4723-8224-0600b2eb61cd","title":"Obiteljske beneficije","summary":{"de":"Podatke o obiteljskim davanjima na hrvatskom jeziku"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Naknadu za djecu (Kindergeld) dobivaju sve obitelji, i to neovisno o dohotku. Isplaćuje se načelno za svu djecu do navršene 18. godine života. Ako je vaše dijete nezaposleno, naknada za djecu isplaćuje se do navršene 21. godine života djeteta, a ako se vaše dijete školuje, dobivate naknadu za djecu do navršene 25. godine života djeteta. Za dobivanje naknade za djecu potreban je pisani zahtjev. Nadležno tijelo kojem se podnosi zahtjev u pravilu je Fond za pomoć obiteljima (Familienkasse) Savezne agencije za zapošljavanje (Bundesagentur für Arbeit). Dječji doplatak iznosi 259 eura mjesečno po djetetu. Pod određenim uvjetima i djeca sa stranim državljanstvom mogu dobivati naknadu za djecu. Dopunski dječji doplatak dobivaju roditelji koji zarađuju dovoljno za sebe, no čiji je dohodak nedovoljan ili jedva dovoljan za pokrivanje svih potreba obitelji. Dopunski dječji doplatak iznosi najviše 297 eura mjesečno po djetetu. Isplaćuje se za svako nevjenčano dijete do navršene 25. godine života ako ispunjavate sljedeće uvjete: Za dotično dijete morate primati dječji doplatak (Kindergeld). Osim toga, Vaš dohodak ne smije biti manji od određenog minimuma koji iznosi 900 eura bruto za parove i 600 eura bruto za samohranog roditelja. Osim toga, možete dobivati dopunski dječji doplatak i u slučaju da Vaš dohodak od nesamostalnog rada ili samostalne djelatnosti, dopunski dječji doplatak i naknada za stanovanje (Wohngeld) zajedno iznose do 100 eura manje od davanja na koja biste imali pravo na osnovi Druge knjige Socijalnog zakonika (SGB II). Od dohotka Vaše djece, npr. uzdržavanja ili predujma za uzdržavanje, uračunava se samo 45 posto u dopunski dječji doplatak. Podnošenje zahtjeva se također isplati ako ste samohrani roditelj i ako imate mali dohodak. Uz dopunski dječji doplatak možete dobivati davanja za obrazovanje i socijalnu uključenost, npr. besplatno sudjelovanje u zajedničkom ručku u školama i jaslicama/vrtićima te paket za školske potrepštine u iznosu od 195 eura."},"url":"https://familienportal.de/familienportal/meta/languages/obiteljske-beneficije","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:59.229463+00:00","lastSeen":"2026-03-15T17:53:59.229463+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/obiteljske-beneficije","crawledAt":"2026-03-15T17:53:59.229463Z","crawlId":"contacts-seeded-1773597239","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"db142896bb7229e4b753cc337e36f5a262d739e85b7246412eb85f8e812eaa16"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:59.229463+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('61b27691-1c4d-459c-98ff-456b84be75ea', 'contacts', 'https://familienportal.de/familienportal/meta/languages/oikogeneiakes-paroches', 'active', NULL, '2026-03-15T17:53:59.715937+00:00', '{"id":"61b27691-1c4d-459c-98ff-456b84be75ea","title":"Oικογενειακές παροχές","summary":{"de":"Πληροφορίες σχετικά με τις οικογενειακές παροχές στα ελληνικά."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Επίδομα τέκνων (Kindergeld) λαμβάνουν όλες οι οικογένειες,ανεξαρτήτως του εισοδήματός τους. Καταβάλλεται γενικά για όλα τα παιδιά έως 18 ετών. Αν το παιδί σας είναι άνεργο, τότε το επίδομα τέκνων καταβάλλεται έως και το 21ο έτος. Αν το παιδί σας βρίσκεται σε εκπαίδευση, λαμβάνετε το επίδομα τέκνων έως τα 25 έτη. Η αίτηση για το επίδομα τέκνων γίνεται γραπτώς. Κατά κανόνα αρμόδιο για αυτό είναι το Οικογενειακό Ταμείο (Familienkasse) της Ομοσπονδιακής Υπηρεσίας Απασχόλησης Το μηνιαίο επίδομα τέκνου είναι 259 ευρώ ανά παιδί. Υπό ορισμένες συνθήκες, το επίδομα τέκνου μπορεί επίσης να καταβληθεί για τέκνα που είναι αλλοδαποί. Προσαύξηση λόγω τέκνων (Kinderzuschlag) λαμβάνουν γονείς που κερδίζουν αρκετά για τους ίδιους, το εισόδημά τους ωστόσο δεν επαρκεί ή επαρκεί ελάχιστα, για να καλύψει όλες τις ανάγκες της οικογένειας. Η προσαύξηση λόγω τέκνων (Kinderzuschlag) ανέρχεται ανά μήνα σε 297 ευρώ το μέγιστο ανά παιδί. Καταβάλλεται για κάθε ανύπαντρο παιδί ηλικίας έως 25 ετών, εφόσον πληροίτε τις ακόλουθες προϋποθέσεις: Πρέπει να λαμβάνετε επίδομα τέκνων (Kindergeld) για το εν λόγω παιδί. Το εισόδημά σας πρέπει εκτός αυτού να μην είναι κάτω από ένα ελάχιστο όριο. Αυτό είναι στα 900 ευρώ μεικτά για ζευγάρια και 600 ευρώ για γονείς που μεγαλώνουν τα παιδιά μόνοι τους. Εκτός αυτού, μπορείτε να λαμβάνετε την προσαύξηση λόγω τέκνων (Kinderzuschlag), αν με το εισόδημα από την εργασία σας, την προσαύξηση λόγω τέκνων (Kinderzuschlag) και το επίδομα στέγασης (Wohngeld) παραμένετε περισσότερο από 100 ευρώ κάτω από το όριο για δικαίωμα παροχών βάσει του δεύτερου βιβλίου του κοινωνικού κώδικα (SGB II). Το εισόδημα των παιδιών σας, για παράδειγμα διαβίωση ή προκαταβαλλόμενη διατροφή (Unterhaltsvorschuss), προστίθεται μόνο κατά 45 τοις εκατό στην προσαύξηση λόγω τέκνων (Kinderzuschlag). Μια αίτηση αξίζει και όταν μεγαλώνετε μόνοι σας το παιδί και έχετε μικρό εισόδημα. Εκτός από την προσαύξηση λόγω τέκνων (Kinderzuschlag) μπορείτε να λαμβάνετε παροχές για εκπαίδευση και συμμετοχή, για παράδειγμα τη δωρεάν συμμετοχή σε ένα γεύμα στο σχολείο και στον παιδικό σταθμό και ένα πακέτο για τις σχολικές ανάγκες 195 ευρώ."},"url":"https://familienportal.de/familienportal/meta/languages/oikogeneiakes-paroches","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:59.715937+00:00","lastSeen":"2026-03-15T17:53:59.715937+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/oikogeneiakes-paroches","crawledAt":"2026-03-15T17:53:59.715937Z","crawlId":"contacts-seeded-1773597239","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"99481a0c1049302522ea5aeab035c32b27b89fc0af671d12a7dc3c96d7d76a4b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:59.715937+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d2328f19-f71c-40a3-9330-b79beef9f27b', 'contacts', 'https://familienportal.de/familienportal/meta/languages/presta%c8%9bii-familiale', 'active', NULL, '2026-03-15T17:54:00.218592+00:00', '{"id":"d2328f19-f71c-40a3-9330-b79beef9f27b","title":"Prestații familiale","summary":{"de":"Informații despre prestațiile familiei în limba română"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Toate familiile sunt îndreptăţte să primească alocaţie de stat pentru familii (Kindergeld), indiferent de venitul lor. De principiu, alocaţia se acordă pentru toţi copii, până la vârsta de 18 ani. Dacă copilul dvs. este şomer, alocaţia de stat pentru copii se va plăti până la vârsta de 21 de ani. Dacă copilul dvs. participă la un curs de formare profesională, vi se va acorda o alocaţie pentru copii până la vârsta de 25 de ani. Alocaţia pentru copii va fi solicitată de dvs. în scris. De regulă, cererea va fi preluată de Agenţia pentru prestaţii familiale din cadrul Oficiului Federal pentru ocuparea forţei de muncă (Familienkasse/Bundesagentur für Arbeit). Alocaţia de stat pentru copii este de 259 de euro pe lună pentru fiecare copil. În anumite condiţii, şi copii de cetăţenie străină pot beneficia de alocaţie de stat pentru copii. Suplimentul de alocație pentru copii este acordat acelor părinţi care câştigă suficient pentru a-şi asigura propria subzistenţă, dar nu câștigă sau nu câștigă suficient pentru a acoperi întregul necesar al familiei lor. Suplimentul de alocație este de cel mult 297 € pe lună pentru fiecare copil. Acesta se plăteşte pentru fiecare copil necăsătorit, până la vârsta de 25 de ani, dacă îndepliniţi următoarele condiţii: Trebuie să beneficiaţi de alocaţie de stat pentru copilul respectiv. În plus, venitul dvs. nu nu se poate situa sub un anumit venit minim. Acesta se ridică la 900 € brut pentru perechi şi la 600 € brut pentru părinţii singuri. Totodată, puteți beneficia de suplimentul de alocaţie pentru copii şi atunci când, însumând venitul dvs. din muncă, suplimentul de alocaţie pentru copii şi ajutorul pentru locuinţă, vă veţi plasa cu cel mult 100 € sub nivelul prestaţiei cuvenite conform Codului Social SGB II. Venitul copiilor dvs., de pildă pensia de întreținere sau avansul la pensia de întreținere, vor fi luate în considerare la calcul suplimentului de alocație doar în măsură de 45 la sută. Merită, deci, să depuneţi o cerere chiar şi atunci când sunteți părinte singur şi aveţi un venit mic."},"url":"https://familienportal.de/familienportal/meta/languages/presta%c8%9bii-familiale","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:00.218592+00:00","lastSeen":"2026-03-15T17:54:00.218592+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/presta%C8%9Bii-familiale","crawledAt":"2026-03-15T17:54:00.218592Z","crawlId":"contacts-seeded-1773597240","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"cf2dcddf73fcb37dcf7ec139ae95f5c47c8aff6a561bd79c6c9c4f621bd21849"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:00.218592+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('699c9a94-3d98-48af-b352-eff16503a216', 'contacts', 'https://familienportal.de/familienportal/meta/languages/prestaciones-familiares', 'active', NULL, '2026-03-15T17:54:00.757469+00:00', '{"id":"699c9a94-3d98-48af-b352-eff16503a216","title":"Prestaciones familiares","summary":{"de":"Información en español sobre prestaciones familiares."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Todas las familias perciben Kindergeld (el subsidio por hijos), independientemente de sus ingresos. Esta prestación se concede por cada hijo hasta que cumple los 18 años. Si sus hijo está desempleado, se le abonará el Kindergeld (subsidio por hijos) hasta los 21 años. En caso de que su hijo se encuentra en periodo de formación recibirá el Kindergeld hasta que cumpla los 25. El Kindergeld (subsidio por hijos) se solicita por escrito. Por lo general es competencia de la Familienkasse (Caja Familiar) de la Bundesagentur für Arbeit (Agencia Federal de Empleo). El subsidio familiar por hijos es de 259 euros mensuales por cada hijo. En determinadas circunstancias, también podrán recibir la prestación niños de nacionalidad extranjera. El suplemento por hijos lo reciben progenitores que ganan lo suficiente para sí, pero cuyos ingresos no alcanzan o apenas alcanzan para cubrir todos los gastos de la familia. El suplemento por hijos es de un máximo de 297 euros por niño y por mes. Se paga por cada hijo soltero hasta que cumple 25 años si usted cumple con las siguientes condiciones. Usted debe cobrar ya para ese hijo subsidio por hijos. Además, sus ingresos no deben ser inferiores a un mínimo. Ese mínimo es de 900 euros brutos para parejas y de 600 euros brutos para familias monoparentales. Además, puede percibir el suplemento por hijos también si la suma de sus ingresos por actividades remuneradas, el suplemento por hijos y el subsidio para la vivienda no es menor en más de 100 euros al importe al que tiene derecho según el SGB II (Libro 2 del Código de Seguridad Social)."},"url":"https://familienportal.de/familienportal/meta/languages/prestaciones-familiares","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:00.757469+00:00","lastSeen":"2026-03-15T17:54:00.757469+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/prestaciones-familiares","crawledAt":"2026-03-15T17:54:00.757469Z","crawlId":"contacts-seeded-1773597240","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"486ef474146af146096c591fcc079d1098c8f3b33a7c7a9c56d4a2112d231411"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:00.757469+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e6997f8e-d166-4b8b-96bc-66fa03d95840', 'contacts', 'https://familienportal.de/familienportal/meta/languages/prestacoes-familiares', 'active', NULL, '2026-03-15T17:54:01.228981+00:00', '{"id":"e6997f8e-d166-4b8b-96bc-66fa03d95840","title":"Prestações familiares","summary":{"de":"Informações sobre benefícios familiares em português"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. O abono de família (Kindergeld) é concedido, independentemente do rendimento, para todos os filhos até aos 18 anos. Se o seu filho estiver desempregado, tem direito ao abono até aos 21 anos, e se estiver a estudar, até aos 25 anos. Tem de ser pedido por escrito. A entidade competente é, regra geral, a Caixa de Família da Agência Federal de Emprego. O abono de família é de 259 euros por mês, por cada filho. Sob certas condições, também crianças de nacionalidade estrangeira podem receber o abono. O suplemento por filho é pago a pais que ganham o suficiente para o seu próprio sustento, mas não para cobrir as despesas de toda a família, ou apenas à justa. O suplemento por filho é, no máximo, de 297 euros por mês e filho. É pago por cada filho solteiro até aos 25 anos de idade, desde que reunidas as seguintes condições: Você tem de receber abono de família para o filho em questão. Além disso, o seu rendimento não pode ser inferior ao limite mínimo. Este é de 900 euros ilíquidos para casais e 600 euros ilíquidos para famílias monoparentais. Também pode receber o suplemento por filho se o seu rendimento mais o suplemento por filho e o subsídio de habitação não ficar mais de 100 euros abaixo do limite do SGB II. Apenas 45% do rendimento dos seus filhos, p. ex. a pensão de alimentos ou o adiantamento da mesma, é levado em conta para efeitos de cálculo do suplemento por filho. Para famílias monoparentais com um rendimento pequeno também vale a pena requerer o suplemento."},"url":"https://familienportal.de/familienportal/meta/languages/prestacoes-familiares","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:01.228981+00:00","lastSeen":"2026-03-15T17:54:01.228981+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/prestacoes-familiares","crawledAt":"2026-03-15T17:54:01.229982Z","crawlId":"contacts-seeded-1773597241","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"c15ce975681b6b7f0aededca716ca6771471b2894eda39d53780fd492e00c69e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:01.229982+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('582f7aab-3520-4515-a1c0-5e4b9b40ea3f', 'contacts', 'https://familienportal.de/familienportal/meta/languages/prestations-familiales', 'active', NULL, '2026-03-15T17:54:01.731220+00:00', '{"id":"582f7aab-3520-4515-a1c0-5e4b9b40ea3f","title":"Prestations familiales","summary":{"de":"Informations concernant les prestations familiales en français."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Toutes les familles ont droit aux allocations familiales (Kindergeld), indépendamment de leurs revenus. Elles sont versées pour tout enfant jusqu’à ses 18 ans, jusqu’à ses 21 ans s’il est au chômage, ou, s’il est en formation professionnelle ou universitaire, jusqu’à ses 25 ans. Ces allocations doivent être demandées par écrit, généralement à la caisse familiale de l’Agence fédérale pour l’Emploi. Les allocations familiales s’élèvent à 259 euros par mois et par enfant. Sous certaines conditions, cette allocation est aussi versée pour les enfants de nationalité étrangère. Peuvent bénéficier d’une majoration pour enfants les parents capables d’assurer leur propre subsistance mais dont le revenu ne suffit pas ou ne suffit que tout juste pour satisfaire les besoins de la famille entière. La majoration pour enfants mensuelle correspond au maximum à 297 € par enfant. Elle est versée pour chaque enfant non marié de moins de 25 ans si vous remplissez les conditions suivantes: Vous devez percevoir des allocations familiales pour l’enfant en cause. Votre revenu n’est pas inférieur à un certain seuil de revenu minimum. Celui-ci correspond à 900 € bruts pour les couples et à 600 € bruts pour les parents isolés. En outre, vous pouvez également bénéficier d’une majoration pour enfants même si la somme de votre revenu d’activité, de la majoration pour enfants et de l’allocation de logement est inférieure de 100 € au maximum aux prestations auxquelles vous avez droit au titre du Livre II du Code social. Seuls 45 % du revenu de vos enfants, par exemple: la pension alimentaire ou l’avance sur pension alimentaire, sont imputés à la majoration pour enfants. Par conséquent, même si vous êtes parent isolé et que vous disposez d’un revenu modeste, il vaut la peine de présenter une demande."},"url":"https://familienportal.de/familienportal/meta/languages/prestations-familiales","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:01.731220+00:00","lastSeen":"2026-03-15T17:54:01.731220+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/prestations-familiales","crawledAt":"2026-03-15T17:54:01.731220Z","crawlId":"contacts-seeded-1773597241","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"93a259732ff252a2e5fde96ebb1fddd6e92678f49436b377a92e5012e941819d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:01.731220+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('64306fb2-81d6-4a93-a4d0-0e2c3fd254ae', 'contacts', 'https://familienportal.de/familienportal/meta/languages/prestazioni-familiari', 'active', NULL, '2026-03-15T17:54:02.258124+00:00', '{"id":"64306fb2-81d6-4a93-a4d0-0e2c3fd254ae","title":"Prestazioni familiari","summary":{"de":"Informazioni italiane sugli prestazioni familiari"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Gli assegni familiari (Kindergeld) sono corrisposti, indipendentemente dal reddito, a tutti i nuclei familiari e in linea di principio per tutti i figli fino ai 18 anni. Se il figlio è disoccupato, gli assegni sono versati fino ai 21 anni. Se il figlio frequenta un corso di formazione, gli assegni vengono corrisposti fino ai 25 anni. La domanda deve essere presentata per iscritto. Di regola l’ufficio competente è la Cassa per la Famiglia (Familienkasse) dell’Agenzia Federale per il Lavoro (Bundesagentur für Arbeit). Gli assegni familiari ammontano a 259 euro per figlio. A determinate condizioni, gli assegni familiari vengono corrisposti anche per i figli con la cittadinanza straniera. L''indennità integrativa per i figli a carico la percepiscono i genitori che hanno redditi sufficienti per provvedere a se stessi, ma che non sono in grado di provvedere o solo a malapena riescono a provvedere alle esigenze dell''intera famiglia. L''indennità integrativa per i figli a carico ammonta a un massimo di 297 euro mensili per figlio. L''indennità viene corrisposta per ogni figlio non coniugato di età inferiore ai 25 anni, se sono soddisfatte le seguenti condizioni: Si percepiscono gli assegni familiari per tale figlio. Inoltre, il reddito non deve essere inferiore a una determinata soglia minima. La soglia minima ammonta a 900 euro lordi per le coppie e 600 euro lordi per le famiglie monoparentali. Inoltre è possibile percepire l''indennità integrativa per i figli a carico anche se, sommando il reddito da lavoro, l''indennità integrativa per i figli a carico e l''indennità di alloggio, mancano al massimo 100 euro al limite delle prestazioni previste dal libro II del Codice di previdenza sociale (SGB II). Il reddito dei figli, per esempio gli assegni di mantenimento o l''anticipo sugli assegni di mantenimento, viene considerato solo nella misura del 45 per cento nel calcolo dell''indennità integrativa per i figli a carico. Vale la pena fare richiesta anche per le famiglie monoparentali che dispongono di un reddito basso."},"url":"https://familienportal.de/familienportal/meta/languages/prestazioni-familiari","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:02.258124+00:00","lastSeen":"2026-03-15T17:54:02.258124+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/prestazioni-familiari","crawledAt":"2026-03-15T17:54:02.258124Z","crawlId":"contacts-seeded-1773597242","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"a52567e35a3e018aad662fc3b3938e88085725b4ff2c7ba78c95f6b81aec3b4d"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:54:02.258124+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7533a043-1c75-4b3e-9871-cb21244ed56f', 'contacts', 'https://familienportal.de/familienportal/meta/languages/semeinite-obezshteteniya', 'active', NULL, '2026-03-15T17:54:02.722232+00:00', '{"id":"7533a043-1c75-4b3e-9871-cb21244ed56f","title":"Семейни обезщетения","summary":{"de":"Информация относно семейните обезщетения на български език"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Детски надбавки (Kindergeld) получават всички семейства, независимо от дохода. Принципно те се изплащат за всички деца до 18-годишна възраст. Ако детето Ви е безработно, детски надбавки се изплащат докато то навърши 21 години. Ако детето е в процес на обучение, Вие получавате детски надбавки докато то навърши 25 години. За детски надбавки следва да кандидатствате писмено. Обикновено за тях отговаря Семейната каса на Федералната служба по заетостта. Детските надбавки възлизат на 259 € месечно за всяко дете. При определени условия деца с чуждо гражданство също имат право да получават Детски надбавки. Допълнителна подробна информация за отделните обезщетения и помощи ще намерите на уеб страниците на Федералното министерство за семейството, както и на т. нар. „Семеен портал“ (Familienportal). Използвайте също и инфотула (Infotool) на Федералното министерство за семейството. По този начин – въз основа на минимални данни – можете да установите какви семейни помощи са приложими във Вашия случай. Семейни помощи за деца получават родители, които печелят достатъчно за себе си, но доходът им не покрива изцяло или едва покрива всички нужди на семейството. Размерът на семейните помощи за деца възлиза на максимално 297 евро месечно за дете. Те се изплащат за всяко неомъжено/неженено дете под 25 год., ако са изпълнени следните условия: Трябва да получавате детски надбавки за съответното дете. Доходът ви не може да е под определен минимален праг. Той възлиза на 900 евро бруто за двойки и 600 евро бруто за самотни родители. Освен това може да получавате семейни помощи за деца и тогава, когато заедно с дохода от трудова дейност, семейните помощи за деца и жилищната помощ не сте с повече от 100 евро под сумата, даваща право на обезщетения съгласно разпоредбите на книга II от Социалния кодекс (SGB II-Anspruch). Доходът на децата ви, например издръжка или авансово плащане на издръжка се начислява само до 45% върху семейните помощи за деца. Заслужава си да подадете молба дори и да сте самотен родител с имате нисък доход."},"url":"https://familienportal.de/familienportal/meta/languages/semeinite-obezshteteniya","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:02.722232+00:00","lastSeen":"2026-03-15T17:54:02.722232+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/semeinite-obezshteteniya","crawledAt":"2026-03-15T17:54:02.722232Z","crawlId":"contacts-seeded-1773597242","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"f9397a313ed4a596c62d01840a63fa07d11e570d4665e84a8510547badb0aefb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:02.723234+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f35af571-9e98-4683-a0dc-d80722cb573c', 'contacts', 'https://familienportal.de/familienportal/meta/languages/swiadczenia-rodzinne', 'active', NULL, '2026-03-15T17:54:03.237603+00:00', '{"id":"f35af571-9e98-4683-a0dc-d80722cb573c","title":"Świadczenia rodzinne","summary":{"de":"Polskie informacje dotyczące świadczeń rodzinnych"},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Zasiłek rodzinny (Kindergeld) otrzymują wszystkie rodziny, niezależnie od osiąganego dochodu. Z zasady jest on wypłacany na wszystkie dzieci w wieku do 18 lat. Jeżeli Twoje dziecko jest bezrobotne, zasiłek rodzinny jest wypłacany do 21. roku życia, a jeżeli dziecko dalej się uczy, zasiłek rodzinny jest wypłacany do 25. roku życia. Wniosek o przyznanie zasiłku rodzinnego musisz złożyć pisemnie, zwykle w Kasie Świadczeń Rodzinnych Federalnej Agencji Pracy (Familienkasse der Bundesagentur für Arbeit). Zasiłek rodzinny przysługujący miesięcznie to 259 euro na każde dziecko. Przy spełnieniu określonych warunków dzieci posiadające obywatelstwo innego państwa również mogą otrzymać zasiłek rodzinny. Dodatek na dziecko otrzymują rodzice, których zarobki wystarczają na pokrycie własnych kosztów utrzymania, ale nie wystarczają lub ledwo wystarczają na zaspokojenie potrzeb całej rodziny. Dodatek na dziecko wynosi miesięcznie maksymalnie 297 euro na każde dziecko. Jest on wypłacany na każde dziecko niepozostające w związku małżeńskim do 25. roku życia, przy spełnieniu następujących warunków: Rodzice muszą pobierać na to dziecko zasiłek rodzinny. Poza tym dochód rodziców nie może być niższy od określonego ustawowo progu minimalnego. Wynosi on 900 euro brutto w przypadku par oraz 600 euro brutto w przypadku samotnych rodziców. Poza tym rodzice mogą otrzymać dodatek na dziecko również w przypadku, gdy ich dochód łącznie z dodatkiem na dziecko i dodatkiem mieszkaniowym jest niższy o nie więcej niż 100 euro od przysługującej podstawy wymiaru określonej w Kodeksie prawa socjalnego II (SGB II). Dochód dzieci, np. świadczenia alimentacyjne lub zaliczka z tytułu świadczeń alimentacyjnych, przy ustalaniu dodatku na dziecko wlicza się tylko w 45 procentach. Wniosek warto też złożyć, jeżeli jesteś osobą samotnie wychowującą dziecko i masz niskie dochody. Ponadto do dodatku na dziecko możesz dodatkowo otrzymać świadczenia na cele edukacyjne i udział w życiu społecznym, jak na przykład oferowany w szkole oraz w żłobku i przedszkolu darmowy obiad a także wyprawkę szkolną w wysokości 195 euro."},"url":"https://familienportal.de/familienportal/meta/languages/swiadczenia-rodzinne","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:03.237603+00:00","lastSeen":"2026-03-15T17:54:03.237603+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/languages/swiadczenia-rodzinne","crawledAt":"2026-03-15T17:54:03.237603Z","crawlId":"contacts-seeded-1773597243","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"a44345df4144c6dc5ceaa92b4186ccb1f9bc3d1a38ac396d8e0c01ab864de6e1"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:54:03.237603+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6107395b-aea4-45e8-9f24-239bd6de1212', 'contacts', 'https://familienportal.de/familienportal/meta/leichte-sprache', 'active', NULL, '2026-03-15T17:54:03.795181+00:00', '{"id":"6107395b-aea4-45e8-9f24-239bd6de1212","title":"Leichte Sprache","summary":{"de":"Wir erklären das Familienportal in leichter Sprache. Das Familienportal informiert über alle wichtigen Informationen zu staatlichen Familienleistungen."},"content":{"de":"Beratung vor Ort Finden Sie zuständige Behörden und Beratungsstellen. Herzlich willkommen auf der Internet-Seite www.familienportal.de. Das Familien-Portal ist ein Informations-Angebot im Internet vom B undes- M inisterium für B ildung, F amilie, S enioren, F rauen und J ugend, kurz BMBFSFJ. Sie finden im Familien-Portal alle wichtigen Informationen über die staatlichen Familien-Leistungen in Deutschland. Zu den Familien-Leistungen gehören finanzielle Hilfen, zum Beispiel Eltern-Geld, Kinder-Geld oder Kinder-Zuschlag. Familien-Leistungen sind aber auch Regeln und Gesetze zur Unterstützung von Familien, zum Beispiel Mutter-Schutz. In diesem Bereich finden Sie Informationen in Leichter Sprache über die Nutzung der Internet-Seite www.familienportal.de. Die Informationen in Leichter Sprache haben diese 5 Teile: Oben links im Familien-Portal finden Sie dieses Logo: Hier kommen Sie immer zurück zur Start-Seite. Sie verlassen dann die Informationen in Leichter Sprache. Wenn Sie oben auf der Seite auf Leichte Sprache klicken, kommen Sie wieder zurück zu den Informationen in Leichter Sprache."},"url":"https://familienportal.de/familienportal/meta/leichte-sprache","topics":["family","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["families","single_parents","general_public","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:03.795181+00:00","lastSeen":"2026-03-15T17:54:03.795181+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Familienportal","provenance":{"source":"https://www.familienportal.de/familienportal/meta/leichte-sprache","crawledAt":"2026-03-15T17:54:03.795181Z","crawlId":"contacts-seeded-1773597243","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"familienportal","providerName":"Familienportal","providerLevel":"federal","checksum":"0d508041d78e940ac34a083474bf1edcbe6126b61db123253a785709a11988d5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:03.795181+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7908ab07-ffaa-41a0-b67f-224062c5993d', 'contacts', 'https://iab.de/kontakt', 'active', NULL, '2026-03-15T16:07:17.097485+00:00', '{"id":"7908ab07-ffaa-41a0-b67f-224062c5993d","title":"Kontakt - IAB","summary":{"de":"Institutsadresse Institut für Arbeitsmarkt- und Berufsforschung (IAB) der Bundesagentur für Arbeit (BA) Regensburger Straße 10490478 Nürnberg Sie möchten uns eine Nachricht senden? Bitte beachten Sie, dass Kundenanfragen der Bundesagentur für Arbeit (bspw. Terminanfragen, Jobvermittlung) nicht vom IAB bearbeitet werden können. Unter diesem Link finden Sie Kontaktmöglichkeiten zur BA: https://www.arbeitsagentur.de/ueber-uns/ansprechpartner Die Ansprechpartner zu IAB-Befragungen können Sie direkt...weiterlesen \"Kontakt\""},"content":{"de":"Institutsadresse Institut für Arbeitsmarkt- und Berufsforschung (IAB) der Bundesagentur für Arbeit (BA) Regensburger Straße 10490478 Nürnberg Sie möchten uns eine Nachricht senden? Bitte beachten Sie, dass Kundenanfragen der Bundesagentur für Arbeit (bspw. Terminanfragen, Jobvermittlung) nicht vom IAB bearbeitet werden können. Unter diesem Link finden Sie Kontaktmöglichkeiten zur BA: https://www.arbeitsagentur.de/ueber-uns/ansprechpartner Die Ansprechpartner zu IAB-Befragungen können Sie direkt...weiterlesen \"Kontakt\""},"url":"https://iab.de/kontakt","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:17.097485+00:00","lastSeen":"2026-03-15T16:07:17.097485+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://iab.de/kontakt","crawledAt":"2026-03-15T16:07:17.097485Z","crawlId":"contacts-seeded-1773590837","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"879eb99c1dafdab547dd0a961a57141453c524781e4c3d239c043fe0bd662265"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:17.097485+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a0fbd8c8-e09a-4fba-84f8-6e6c88a78530', 'contacts', 'https://ifightdepression.com/de', 'active', NULL, '2026-03-15T16:07:17.817875+00:00', '{"id":"a0fbd8c8-e09a-4fba-84f8-6e6c88a78530","title":"Was Sie über die Erkrankung Depression wissen sollten","summary":{"de":"Was Sie über die Erkrankung Depression wissen sollten Zum Selbsttest Selbstmanagement Es gibt zahlreiche Möglichkeiten um die psychische Gesundheit zu stärken. Mehr Informationen Zum Selbsttest"},"content":{"de":"Depression ist eine weltweit verbreitete Erkrankung, von der über 300 Millionen Menschen betroffen sind. Eine Depression unterscheidet sich von gewöhnlichen Stimmungsschwankungen und kurzlebigen emotionalen Reaktionen auf alltägliche Probleme. Die Depression entsteht durch eine komplexe Interaktion von sozialen, psychologischen und biologischen Faktoren (Weltgesundheitsorganisation, WHO, 2017). Depression ist eine Erkrankung, die nicht nur die Psyche oder das Gehirn, sondern den gesamten Körper, Essverhalten, Schlafgewohnheiten, Gefühle gegenüber sich selbst und anderen Personen, sowie Gedanken beeinflusst. Es ist kein vergänglicher, normaler Gemütszustand und weder ein Zeichen persönlicher Schwäche, noch ein Zustand, dem man sich '' entreißen '' kann. Allgemein gesprochen kann jeder an einer Depression erkranken: Männer und Frauen jeden Hintergrunds, aller Berufsgruppen und in jeder Lebensphase. Selbst Menschen, die augenscheinlich ein sorgenfreies und glückliches Leben führen, können von der Erkrankung Depression betroffen sein. Depression ist behandelbar. Wenn Sie glauben, an einer Depression erkrankt zu sein, suchen Sie sich Hilfe. ist ein internetbasiertes, begleitetes Selbstmanagement-Programm, das Menschen mit leichten Depressionsformen helfen soll, mit den Symptomen umzugehen. Wenn Sie Ihr Hausarzt oder Psychotherapeuten auf das Tool verwiesen hat und Sie einen persönlichen Nutzeraccount besitzen, können Sie sich hier einloggen: Wenn Sie Ihren Patienten das Tool zur Verfügung stellen möchten, können Sie kostenfrei am Online-Training teilnehmen."},"url":"https://ifightdepression.com/de","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:17.817875+00:00","lastSeen":"2026-03-15T16:07:17.817875+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://ifightdepression.com/de","crawledAt":"2026-03-15T16:07:17.817875Z","crawlId":"contacts-seeded-1773590837","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"ef9636b714aa744650a8ba2d0e8abab79d01e3b61121d9b90185fb38c40f1919"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:17.817875+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fdbd102f-2051-4c43-8da8-bff7a4c343de', 'contacts', 'https://kompetenznetz-einsamkeit.de/angebote/angebote-fuer-betroffene', 'active', NULL, '2026-03-15T16:07:21.439918+00:00', '{"id":"fdbd102f-2051-4c43-8da8-bff7a4c343de","title":"Auflistung von Angeboten bei Einsamkeit","summary":{"de":"Angebote bei Einsamkeit: Es gibt nicht die eine Antwort auf die Linderung eines subjektiven Leidens. Denn Einsamkeit ist so vielseitig, wie die Menschen, die"},"content":{"de":"Angebote bei Einsamkeit: Es gibt nicht die eine Antwort auf die Linderung eines subjektiven Leidens. Denn Einsamkeit ist so vielseitig, wie die Menschen, die"},"url":"https://kompetenznetz-einsamkeit.de/angebote/angebote-fuer-betroffene","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:21.439918+00:00","lastSeen":"2026-03-15T16:07:21.439918+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://kompetenznetz-einsamkeit.de/angebote/angebote-fuer-betroffene","crawledAt":"2026-03-15T16:07:21.439918Z","crawlId":"contacts-seeded-1773590841","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"77d54b92386ef81fe5c9b17a9f7532336dc9ec1d652fc0aaaab571f446932079"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T16:07:21.439918+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6b530541-1041-4628-87c7-9ac3bd948dd6', 'contacts', 'https://plaudernetz.malteser.de/', 'active', NULL, '2026-03-15T16:07:24.992738+00:00', '{"id":"6b530541-1041-4628-87c7-9ac3bd948dd6","title":"Gespräche verbinden. Dein Plaudernetz.","summary":{"de":"Gute Gespräche führen am Telefon ✔ kostenlos ✔ unkompliziert ✔ anonym ✔ Jedes Gespräch eine einmalige Begegnung. Jetzt testen!"},"content":{"de":"Das Plaudernetz ist ein kostenloses Gesprächsangebot der Malteser, bei dem du neue Menschen kennenlernen und dich mit ihnen am Telefon unterhalten kannst. Ihr entscheidet, worüber gesprochen wird, z.B. über Hobbies, Alltagserlebnisse oder das Wetter. Menschen, die den Wunsch nach einem Gespräch haben, werden mit unseren Plauderpartnerinnen und Plauderpartnern verbunden, die sich ehrenamtlich engagieren. Diese stellen ihre Zeit für Gespräche zur Verfügung, bieten jedoch keine Beratung an und verweisen in Notfällen auf bestehende Angebote. Jedes Gespräch ist eine einmalige Begegnung, kostenlos und anonym. Probiere es einfach mal aus und plaudere los. Bitte beachten Sie: Sobald Sie sich das Video ansehen, werden Informationen darüber an Youtube/Google übermittelt. Weitere Informationen dazu finden Sie unter Google Datenschutzerklärung. Du hast einen Gesprächswunsch und wählst die Plaudernetz-Nummer 0800 330 1111. Dein Anruf wird zu einer Plauderpartnerin oder einem Plauderpartner durchgestellt."},"url":"https://plaudernetz.malteser.de/","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:24.992738+00:00","lastSeen":"2026-03-15T16:07:24.992738+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://plaudernetz.malteser.de/","crawledAt":"2026-03-15T16:07:24.992738Z","crawlId":"contacts-seeded-1773590844","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"702052342db2287beec60a9b599a57433bf087165b2087750548bcb266dc472e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:24.992738+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('cd2aee2f-ef92-4411-8907-1bf211761c77', 'contacts', 'https://www.115.de/', 'active', NULL, '2026-03-15T16:06:48.197980+00:00', '{"id":"cd2aee2f-ef92-4411-8907-1bf211761c77","title":"Alle Behörden. Ihre Fragen. 115 wählen!","summary":{"de":"Erhalten Sie strukturierte Antworten auf alle Verwaltungsfragen bei Behördennummer 115. Schnell & zuverlässig, Mo-Fr, 8-18 Uhr. Jetzt anrufen!"},"content":{"de":"Die 115 ist deutsch­land­weit bereits für über 71 Millionen Bürgerinnen und Bürger erreichbar. 54 Servicecenter sorgen deutschlandweit für einen einheitlichen und zuverlässigen Service. Die 115 bietet ein Gebärdentelefon für Menschen mit Höreinschränkung an. Über 6 Millionen Menschen vertrauen jedes Jahr der 115. Von A wie Anmeldung bis Z wie Zulassung: Das Team der Behörden­nummer 115 beant­wortet Ihre Fragen zu Leistungen der Verwaltung von Bund, Ländern und Kommunen. Wir helfen Ihnen schnell und zuverlässig von Montag bis Freitag, 8:00 bis 18:00 Uhr."},"url":"https://www.115.de/","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:48.197980+00:00","lastSeen":"2026-03-15T16:06:48.197980+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://www.115.de/","crawledAt":"2026-03-15T16:06:48.197980Z","crawlId":"contacts-seeded-1773590808","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"fb1eba4c04a7e0e9cb6358b8506477def6e5c6d347e28e8d29de6f69171878ad"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:06:48.197980+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d9171858-4a21-4fe3-bf8c-e88eaa82e6ef', 'contacts', 'https://www.115.de/barrierefreiheitserklaerung', 'active', NULL, '2026-03-15T16:06:59.496524+00:00', '{"id":"d9171858-4a21-4fe3-bf8c-e88eaa82e6ef","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Als öffentliche Stelle im Sinne der Richtlinie (EU) 2016/2102 sind wir bemüht, unsere Websites und mobilen Anwendungen im Einklang mit den Bestimmungen des Hessischen Behinderten-Gleichstellungsgesetzes (HessBGG) sowie der Hessischen Verordnung über barrierefreie Informationstechnik (BITV HE 2019) zur Umsetzung der Richtlinie (EU) 2016/2102 barrierefrei zugänglich zu machen."},"content":{"de":"Diese Erklärung zur digitalen Barrierefreiheit gilt für die unter www.115.de veröffentlichte Website der FITKO (Föderale IT-Kooperation). Die Anforderungen der Barrierefreiheit ergeben sich aus § 3 Absätze 1 bis 4 und § 4 der BITV HE 2019, die auf Grundlage von § 14 des HessBGG erlassen wurde. Die Überprüfung der Einhaltung der Anforderungen beruht auf einer am 31.07.2024 durchgeführten BITV-Selbstbewertung. Aufgrund der Überprüfung ist die Website mit den zuvor genannten Anforderungen wegen der folgenden Unvereinbarkeiten teilweise vereinbar. Die nachstehend aufgeführten Inhalte sind unvereinbar mit § 3 Absatz 1 der BITV HE 2019 und aus folgenden Gründen nicht barrierefrei: Es fehlen Bedienelemente für die Kontrastauswahl und Textvergrößerung."},"url":"https://www.115.de/barrierefreiheitserklaerung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:59.496524+00:00","lastSeen":"2026-03-15T16:06:59.496524+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"http://www.115.de/barrierefreiheitserklaerung","crawledAt":"2026-03-15T16:06:59.496524Z","crawlId":"contacts-seeded-1773590819","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"07baee818847d739642379b073a17bd70f22b38484cdd6cf6d41378378db1560"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:06:59.496524+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e74cd978-1c61-45a5-bb0a-6be53a59ca44', 'contacts', 'https://www.115.de/de-leicht', 'active', NULL, '2026-03-15T16:07:00.539247+00:00', '{"id":"e74cd978-1c61-45a5-bb0a-6be53a59ca44","title":"Alle Ämter. Ihre Fragen. Rufen Sie die 115 an!","summary":{"de":"Erhalten Sie strukturierte Antworten auf alle Verwaltungsfragen bei Behördennummer 115. Schnell & zuverlässig, Mo-Fr, 8-18 Uhr. Jetzt anrufen!"},"content":{"de":"Die Telefonnummer 115 kann man in ganz Deutschland benutzen. Mehr als 69 Millionen Menschen können die Nummer anrufen. In ganz Deutschland gibt es 54 Servicecenter. Sie bieten überall den gleichen guten Service an. Bei der 115 gibt es ein besonderes Telefon. Das ist für Menschen, die nicht gut hören können. Dieses Telefon benutzt Gebärden. Jedes Jahr erleben mehr als 6 Millionen Menschen, dass die 115 gut hilft. Sie bekommen Antworten auf alle Ihre Fragen zu Ämtern. Montag bis Freitag von 8 Uhr morgens bis 6 Uhr abends."},"url":"https://www.115.de/de-leicht","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:00.539247+00:00","lastSeen":"2026-03-15T16:07:00.539247+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"http://www.115.de/de-leicht","crawledAt":"2026-03-15T16:07:00.539247Z","crawlId":"contacts-seeded-1773590820","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"39a1e5aef1c612755839ad229dab7356da7308810041181e99387b1efffbf7f0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:00.539247+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ecb0213d-7f66-4bc2-bebe-688cf888b24b', 'contacts', 'https://www.115.de/gebaerdensprache', 'active', NULL, '2026-03-15T16:07:04.212233+00:00', '{"id":"ecb0213d-7f66-4bc2-bebe-688cf888b24b","title":"Gebärdentelefon","summary":{"de":"Alle Behördeninfos der 115 in deutscher Gebärdensprache. Nutzen Sie das Gebärdentelefon online – einfach via Smartphone oder PC/Mac mit Webcam!"},"content":{"de":"Sie erreichen unser Angebot in Gebärdensprache ganz einfach online. Jedes Smartphone mit Frontkamera und Internetverbindung ist geeignet. Für den Zugang über PC oder Mac wird zusätzlich zur Internet­verbindung eine integrierte oder externe Webcam benötigt. Montag bis Donnerstag von 8:00 bis 17:00 Uhr und Freitag von 8:00 bis 12:00 Uhr. Über das Gebärdentelefon beantworten ausgebildete Mitarbeitende in Deutscher Gebärdensprache (DGS) Ihre Fragen zu Verwaltungsleistungen. Inhaltlich unterscheidet sich unser Angebot in Gebärdensprache nicht vom telefonischen Leistungsumfang. Das Gebärdentelefon wird von der Telemark Rostock betrieben und im Auftrag des Bundesministeriums für Arbeit und Soziales (BMAS) für die 115 bereitgestellt. Sie benötigen ein Gerät mit Frontkamera und Internetanschluss. Das kann ein Tablet oder Smartphone, aber auch jeder PC oder Mac sein. Die beste Erfahrung machen User mit einer schnellen Internetverbindung. Das Gebärdentelefon ist nicht an einen Anbieter oder Bezahldienst gebunden und wird kostenfrei angeboten. Möglicherweise fallen Kosten für Ihre Internetverbindung an, sofern Sie keine Flatrate oder vorhandenes Datenvolumen nutzen können."},"url":"https://www.115.de/gebaerdensprache","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:04.212233+00:00","lastSeen":"2026-03-15T16:07:04.212233+00:00","sourceUnavailable":false,"contactType":"accessibility","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"http://www.115.de/gebaerdensprache","crawledAt":"2026-03-15T16:07:04.212233Z","crawlId":"contacts-seeded-1773590824","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b63ae4c745e4913e75e776fdaeca61985fee8fbed21d51ac73113085a3bb3df8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:04.212233+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b9163b46-d458-482e-adb9-fcbed1559de4', 'contacts', 'https://www.115.de/kontakt', 'active', NULL, '2026-03-15T16:07:05.207691+00:00', '{"id":"b9163b46-d458-482e-adb9-fcbed1559de4","title":"Ob Personalausweis, Reisepass oder Gewerbeanmeldung: Sie benötigen Hilfe? Dann wählen Sie die 115!","summary":{"de":"Sie möchten Teil des 115-Verbundes werden, haben Presseanfragen oder Fragen zu anderen Themen? Kontaktieren Sie gerne unser Produktmanagement!"},"content":{"de":"Wir sind Montags bis Freitags von 8:00 bis 18:00 Uhr für Fragen von A wie Anmeldung bis Z wie Zulassung für Sie erreichbar. Die Behördennummer 115 wird von der FITKO (Föderale IT-Kooperation) im Auftrag des deutschen IT-Planungsrats gesteuert. Sie möchten Teil des 115-Verbundes werden, haben Presseanfragen oder benötigen Informationen zu anderen Themen? Unser Produktmanagement ist für Sie da! Bei konkreten Fragen zu Verwaltungsleistungen wählen Sie bitte die 115."},"url":"https://www.115.de/kontakt","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:05.207691+00:00","lastSeen":"2026-03-15T16:07:05.207691+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"http://www.115.de/kontakt","crawledAt":"2026-03-15T16:07:05.208545Z","crawlId":"contacts-seeded-1773590825","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"96deb80921d8a725e5f546a47fec634ef23551b9b7d1ca183bc663a2b1742854"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:05.208545+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e6228bfd-c9fe-442d-8995-2a11b444a276', 'contacts', 'https://www.115.de/ueber-die-115', 'active', NULL, '2026-03-15T16:07:08.227518+00:00', '{"id":"e6228bfd-c9fe-442d-8995-2a11b444a276","title":"Unser Serviceversprechen","summary":{"de":"Die 115 ist Ihr Kontakt in die Verwaltung - egal, wo Sie sind und welche Frage Sie haben. Sie erreichen uns Montag bis Freitag von 08.00 bis 18.00 Uhr."},"content":{"de":"Die 115 ist Ihr Kontakt in die Verwaltung - egal, wo Sie sind und welche Frage Sie haben. Sie erreichen unsere freundlichen, kompetenten Mitarbeitenden schnell und zuverlässig, Montag bis Freitag von 8:00 bis 18:00 Uhr. Ihre Angelegenheit wird beim ersten Kontakt erledigt. Sollte dies einmal nicht möglich sein, leiten wir diese zur Bearbeitung weiter. Ob Kommune, Land oder Bundesbehörde - alle föderalen Ebenen beteiligen sich am 115-Verbund Die Kommunen sind mit ihren Servicecentern die erste Kontaktstelle für die Bürgerinnen und Bürger. Kommunen aller Größenordnungen sind im Verbund vertreten. Beispiele für nachgefragte Leistungen der Kommunen:"},"url":"https://www.115.de/ueber-die-115","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:08.227518+00:00","lastSeen":"2026-03-15T16:07:08.227518+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"http://www.115.de/ueber-die-115","crawledAt":"2026-03-15T16:07:08.227518Z","crawlId":"contacts-seeded-1773590828","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"44562727783202edf55fe11348eb815175283a8efb3db13735da5790557bdb92"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:08.227518+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ca204451-5795-4348-9a22-2391b471a4aa', 'contacts', 'https://www.arbeitsagentur.de/erklaerung-barrierefreiheit', 'active', NULL, '2026-03-15T16:30:36.646420+00:00', '{"id":"ca204451-5795-4348-9a22-2391b471a4aa","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Die Bundesagentur für Arbeit ist bemüht, die Webseiten unter www.arbeitsagentur.de und mobilen Anwendungen barrierefrei zugänglich zu gestalten. Rechtsgrundlagen sind die UN-Behindertenrechtskonvention (UN-BRK), das Behindertengleichstellungsgesetz (BGG) sowie die Barrierefreie Informationstechnik-Verordnung (BITV 2.0) in ihren jeweils gültigen Fassungen."},"content":{"de":"Die Überprüfung der Einhaltung der Anforderungen beruht auf unabhängigen BITV 2.0-Tests, die im Rahmen der Weiterentwicklung an jeweiligen Teilbereichen des Internetauftritts kontinuierlich durchgeführt werden. Die Webseiten und mobilen Anwendungen sind mit den genannten Anforderungen zum größten Teil vereinbar. Die Bundesagentur für Arbeit ist bemüht, die verbleibenden Barrieren schnellstmöglich zu beheben. Die nachstehend aufgeführten Inhalte sind aus folgenden Gründen nicht barrierefrei: Unvereinbarkeit mit der BITV 2.0: Anmeldung/Registrierung: Die Nutzung eines Freischaltcodes ist derzeit noch nicht barrierefrei möglich. An einer barrierefreien Lösung auch für § 10 BGG-Kunden wird gearbeitet. Online-Portal - Menü: Das Hauptmenu ist derzeit eingeschränkt barrierefrei bedienbar. Eine barrierefreie Lösung soll bis 02/2026 zur Verfügung stehen. PDF-Dokumente: PDF-Dokumente älteren Datums sind nicht durchgehend barrierefrei. Neu herausgegebene PDF-Dokumente werden in der Regel in barrierefreier Version zur Verfügung gestellt oder zeitnah durch eine solche ersetzt. Falls Sie eine bestimmte PDF-Datei von uns benötigen, die noch nicht barrierefrei zur Verfügung steht, teilen Sie uns dies gerne über unser Kontaktformular mit."},"url":"https://www.arbeitsagentur.de/erklaerung-barrierefreiheit","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:36.646420+00:00","lastSeen":"2026-03-15T16:30:36.646420+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/erklaerung-barrierefreiheit","crawledAt":"2026-03-15T16:30:36.647430Z","crawlId":"contacts-seeded-1773592236","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6ce5a9bc680a8ca316c63c254618684b3570353056f4302dea15e9d1b227ad5b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:36.647430+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fd40478a-c442-487d-98ae-a81b754609e6', 'contacts', 'https://www.arbeitsagentur.de/gebaerdensprache', 'active', NULL, '2026-03-15T16:30:37.149622+00:00', '{"id":"fd40478a-c442-487d-98ae-a81b754609e6","title":"Informationen in Gebärdensprache","summary":{"de":"Übersicht zu den Seiten rund um die Angebote für Arbeitgeberinnen und Arbeitgeber"},"content":{"de":"Sehen Sie im Video, wie das Portal der BA aufgebaut ist und wie Sie schnell die Informationen finden, die Sie suchen. Überblick zu den Portalseiten für Bildungsträger, Netzwerke und Schulen Informationen zu den Voraussetzungen beim Bezug von Kurzarbeitergeld für Unternehmen Informationen zum Kurzarbeitergeld-Verfahren für Unternehmen Die Videos in Gebärdensprache finden Sie direkt in den monatlichen Presseinformationen zum Arbeitsmarkt. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/gebaerdensprache","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:37.149622+00:00","lastSeen":"2026-03-15T16:30:37.149622+00:00","sourceUnavailable":false,"contactType":"accessibility","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/gebaerdensprache","crawledAt":"2026-03-15T16:30:37.149622Z","crawlId":"contacts-seeded-1773592237","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c798792476ad56d4f3cc353f7d4d37f22c7fca97a362b6dad2b3d48c7c8a0659"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:37.149622+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8d957452-19b6-4b8c-a47a-701672a27fb8', 'contacts', 'https://www.arbeitsagentur.de/leichte-sprache', 'active', NULL, '2026-03-15T16:30:38.152416+00:00', '{"id":"8d957452-19b6-4b8c-a47a-701672a27fb8","title":"Herzlich willkommen auf der Internet-Seite von der Bundesagentur für Arbeit!","summary":{"de":"Die Seite der Bundes-Agentur für Arbeit in Leichter Sprache. Jetzt informieren"},"content":{"de":"Infos über die Bundesagentur für Arbeit in Leichter Sprache Die Bundesagentur für Arbeit ist eine der größten deutschen Behörden. Es arbeiten über 110.000 Personen für die Bundesagentur für Arbeit. Zur Bundesagentur für Arbeit gehören: Der Hauptsitz ist in der Stadt Nürnberg. Ein Vorstand leitet die Bundesagentur für Arbeit. Andrea Nahles ist seit August 2022 die Vorsitzende vom Vorstand. Alle Menschen in Deutschland sollen eine Arbeit haben. Die Bundesagentur für Arbeit hilft dabei. Zum Beispiel: Sie hilft Menschen, die ihre Arbeit verloren haben. Sie hilft Arbeitgebern, die neue Mitarbeiter suchen."},"url":"https://www.arbeitsagentur.de/leichte-sprache","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:38.152416+00:00","lastSeen":"2026-03-15T16:30:38.152416+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/leichte-sprache","crawledAt":"2026-03-15T16:30:38.152416Z","crawlId":"contacts-seeded-1773592238","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"dc1a1ad7bbdb4a76394906a2a1056281ca7783d374f27b504f36b08f47c2b648"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:38.152416+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('de005494-c6d4-4fc6-8303-e4feddce802d', 'contacts', 'https://www.arbeitsagentur.de/rechtliche-hinweise', 'active', NULL, '2026-03-15T16:30:39.641479+00:00', '{"id":"de005494-c6d4-4fc6-8303-e4feddce802d","title":"Rechtliche Hinweise","summary":{"de":"Rechtliche Hinweise für Inhalte der Bundesagentur für Arbeit"},"content":{"de":"Es ist das Anliegen der Bundesagentur für Arbeit (BA), die Inhalte ihres Internetangebots stets inhaltlich richtig und aktuell verfügbar zu halten. Die Inhalte der Webseite werden sorgfältig verfasst und regelmäßig auf ihre Aktualität hin überprüft. Das Auftreten von Fehlern kann bei der Vielzahl von Themen und Informationen nicht völlig ausgeschlossen werden. Die BA übernimmt daher keine Gewähr dafür, dass alle Angaben des Internetauftritts zu jeder Zeit vollständig, richtig und in letzter Aktualität dargestellt sind. Die Darstellung der Inhalte orientiert sich an den Bedürfnissen der Kundinnen und Kunden der BA. Die BA bemüht sich, rechtliche Inhalte klar und verständlich darzustellen und dabei Rechts- oder Fachbegriffe nach Möglichkeit zu vermeiden. Trotzdem gilt: Rechtlich verbindlich ist das, was im Gesetz steht. Die Angaben im Internetauftritt der BA berücksichtigen möglicherweise nicht Ihre persönliche Situation. Suchen Sie daher bei weiteren Fragen die persönliche Beratung in der für Sie zuständigen Agentur für Arbeit oder Ihrem Jobcenter. Alle Angaben können ohne vorherige Ankündigung ergänzt, entfernt oder geändert werden. Für einzelne Inhalte des Internetauftritts der BA, insbesondere Dienste, die eine vorherige Registrierung/Anmeldung erfordern, können gesonderte zusätzliche Nutzungsbedingungen gelten, die ggf. bei der Nutzung zu beachten sind. Links zu Webseiten Dritter werden auf dieser Website als reine Serviceleistung, bzw. als Hinweis auf weiterführende Quellen angeboten. Für die Inhalte, zu denen verlinkt wird, sind die Anbieter der jeweiligen Webseiten ausschließlich selbst verantwortlich. Die BA macht sich diese Inhalte nicht zu eigen. Anbieter sind für die eigenen Inhalte, die sie zur Nutzung bereithalten, nach den allgemeinen Gesetzen verantwortlich. Von diesen eigenen Inhalten sind Querverweise auf die von anderen Anbietern bereitgehaltenen Inhalte zu unterscheiden."},"url":"https://www.arbeitsagentur.de/rechtliche-hinweise","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:39.641479+00:00","lastSeen":"2026-03-15T16:30:39.641479+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/rechtliche-hinweise","crawledAt":"2026-03-15T16:30:39.641479Z","crawlId":"contacts-seeded-1773592239","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"3709778f1f7afaa00eeb2998c6e90ea6f318b37dc18711decf37e308cf08942d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:39.642428+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b1482eb8-8abd-4edd-9b70-0e531188a0b6', 'contacts', 'https://www.arbeitsagentur.de/service-bereich/so-erreichen-sie-uns', 'active', NULL, '2026-03-15T16:06:46.324126+00:00', '{"id":"b1482eb8-8abd-4edd-9b70-0e531188a0b6","title":"So erreichen Sie uns","summary":{"de":"Wir helfen Ihnen gerne persönlich weiter! So erreichen Sie uns."},"content":{"de":"Gerne helfen wir Ihnen persönlich weiter! Unseren Service für Bürgerinnen und Bürger erreichen Sie zu folgenden Zeiten: Montag bis Donnerstag von 08:00 bis 18:00 Uhr Freitag von 08:00 bis 14:00 Uhr Servicetelefon für Menschen mit Hörbeeinträchtigungen Technischer Support für Online-Angebote 0800 4 555501 (gebührenfrei) Aus dem Ausland: +49 911 178 1780 Familienkasse: Allgemeine Auskünfte 0800 4 555530 (gebührenfrei) Arbeitgeberservice 0800 4 555520 (gebührenfrei) Montag bis Freitag von 08:00 bis 18:00 Uhr Sie möchten bestimmte Geschäftsbereiche oder Dienststellen erreichen? In unserer Übersicht finden Sie Informationen zu den betreffenden Ansprechpartnerinnen und Ansprechpartnern. Falls Sie sich über ein spezielles Thema informieren möchten, schicken Sie uns am besten eine E-Mail."},"url":"https://www.arbeitsagentur.de/service-bereich/so-erreichen-sie-uns","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:46.324126+00:00","lastSeen":"2026-03-15T16:06:46.324126+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/service-bereich/so-erreichen-sie-uns","crawledAt":"2026-03-15T16:06:46.324126Z","crawlId":"contacts-seeded-1773590806","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"e971ea480da58b0b4a59f91786092ef36e2b36f97e42a2eca6a07c44b6337582"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:06:46.324126+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3833904e-e36c-4398-ad83-a372b0fee9b0', 'contacts', 'https://www.arbeitsagentur.de/ueber-uns/antikorruptionsbeauftragter', 'active', NULL, '2026-03-15T16:30:40.162177+00:00', '{"id":"3833904e-e36c-4398-ad83-a372b0fee9b0","title":"Antikorruptionsbeauftragter","summary":{"de":"Sie möchten ein Hinweise auf Korruption melden? Lesen Sie, wie Sie dazu vorgehen."},"content":{"de":"Mitarbeitende der Bundesagentur für Arbeit (BA) sind explizit aufgefordert, Korruption und sonstige Rechtsverstöße in der BA zu melden. Aber auch Sie als unsere Kundinnen und Kunden, als Bürgerinnen und Bürger oder als Geschäftspartnerinnen und Geschäftspartner haben dazu die Möglichkeit. Sie möchten einen Hinweis auf Korruption oder einen sonstigen Rechtsverstoß innerhalb der Bundesagentur für Arbeit (BA) melden? Dann wenden Sie sich an unseren Antikorruptionsbeauftragten. Hinweise können (anonymisiert) per E-Mail, per Telefon oder auch in einem persönlichen Gespräch erfolgen. Auf ausdrücklichen Wunsch bleibt der Hinweisgeber im weiteren Verlauf ungenannt. Dies gilt jedoch nicht gegenüber Ermittlungs- und Strafverfolgungsbehörden. Anhaltspunkte auf ein Fehlverhalten gibt der Antikorruptionsbeauftragte an den Fachbereich Interne Ermittlungen bei der Zentrale der BA weiter. Wichtig: Hinweis: Der Antikorruptionsbeauftragte ist nicht zuständig für allgemeine Anregungen, Fragen, Kritik, Beschwerden oder Hinweise darauf, dass Personen Leistungen zu Unrecht erhalten."},"url":"https://www.arbeitsagentur.de/ueber-uns/antikorruptionsbeauftragter","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:40.162177+00:00","lastSeen":"2026-03-15T16:30:40.162177+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/antikorruptionsbeauftragter","crawledAt":"2026-03-15T16:30:40.162177Z","crawlId":"contacts-seeded-1773592240","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6d53d292a1287f0b632f23e74747eedcb1e7178f6fca9e5027b5049650444b7d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:40.162177+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c1ba191b-dd52-47c8-8748-b50fa46a38c6', 'contacts', 'https://www.arbeitsagentur.de/ueber-uns/compliance', 'active', NULL, '2026-03-15T16:30:40.671337+00:00', '{"id":"c1ba191b-dd52-47c8-8748-b50fa46a38c6","title":"Compliance | Bundesagentur für Arbeit","summary":{"de":"Lernen Sie die Grundsätze der BA kennen und erfahren Sie, wie die Maßnahmen und Prinzipien gewährleisten werden."},"content":{"de":"Tipp: Definition Compliance: Für die Bundesagentur für Arbeit bedeutet Compliance neben der ordnungsgemäßen Aufgabenwahrnehmung und der Einhaltung von Gesetzen und Regelungen auch die Beachtung und Pflege ethisch-moralischer Grundsätze, wie zum Beispiel Integrität, Verlässlichkeit und vorurteilsfreies Verhalten jedes einzelnen Beschäftigten. Die Bundesagentur für Arbeit (BA) hat die Pflicht, ihre Aufgaben loyal, unparteiisch, rechtmäßig und zum Wohl der Allgemeinheit zu erfüllen. Das Handeln der BA muss zu jedem Zeitpunkt transparent und nachvollziehbar sein. Kunden und die Öffentlichkeit im Allgemeinen müssen Vertrauen in die Integrität der BA haben. Der Vorstand der BA räumt der Integrität der BA einen hohen Stellenwert ein. Deshalb wurde ein umfassendes System zur Prävention und Bekämpfung von Korruption und sonstigen strafbewehrten Handlungen installiert. Dieses System enthält eine Vielzahl an Maßnahmen und Vorkehrungen zur Risikominimierung. Anwendung der Richtlinie der Bundesregierung zur Korruptionsprävention in der Bundesverwaltung Schulungen zu Compliance und zur Korruptionsprävention Regelmäßige Analyse und Feststellung von besonders korruptionsgefährdeten Arbeitsgebieten"},"url":"https://www.arbeitsagentur.de/ueber-uns/compliance","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:40.671337+00:00","lastSeen":"2026-03-15T16:30:40.671337+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/compliance","crawledAt":"2026-03-15T16:30:40.671337Z","crawlId":"contacts-seeded-1773592240","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7088693ffcccefafe36406d0c4fabf07766ee61b45b674181e3c5ef707fcee7c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:40.671337+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('272ace05-735c-47dd-83b5-bc24b41e50a1', 'contacts', 'https://www.arbeitsagentur.de/ueber-uns/europavertretung', 'active', NULL, '2026-03-15T16:30:41.152432+00:00', '{"id":"272ace05-735c-47dd-83b5-bc24b41e50a1","title":"Schnittstelle Europavertretung","summary":{"de":"Erfahren Sie mehr über die vielfältigen Aufgaben der Europavertretung. Jetzt informieren!"},"content":{"de":"Die Europavertretung der Bundesagentur für Arbeit ist seit mehr als 10 Jahren das zentrale Bindeglied zwischen der Europäischen Union (EU), ihren Institutionen und der BA. Die Mitarbeiterinnen und Mitarbeiter der Europavertretung der BA nehmen vielfältige Aufgaben wahr. Dazu zählen unter anderem: positiv: die beratende Mitwirkung am politischen Entscheidungsprozess der EU positiv: die Analyse und Bewertung aller für die BA wichtigen Entscheidungen, Trends und Entwicklungen in der EU positiv: die Beteiligung an der Meinungsbildung zu den Themen Beschäftigung, Bildung, Migration und Soziales positiv: die Betreuung und Beratung europäischer Institutionen, Interessensvertreter und Netzwerke. Dazu zählt zum Beispiel die Kooperation mit unseren Partnern im Europäischen Netzwerk der öffentlichen Arbeitsmarktservices („European Network of Public Employment Services“)."},"url":"https://www.arbeitsagentur.de/ueber-uns/europavertretung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:41.152432+00:00","lastSeen":"2026-03-15T16:30:41.152432+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/europavertretung","crawledAt":"2026-03-15T16:30:41.152432Z","crawlId":"contacts-seeded-1773592241","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"8393d4b12c7050f1f5abd29b85d2f6a6afe66b1b7b1c365a1583ff8a21503f52"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:41.152432+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('28d225e3-7553-4d99-a4c5-7650188e9219', 'contacts', 'https://www.arbeitsagentur.de/ueber-uns/hauptstadtvertretung', 'active', NULL, '2026-03-15T16:30:41.646006+00:00', '{"id":"28d225e3-7553-4d99-a4c5-7650188e9219","title":"Hauptstadtvertretung","summary":{"de":"Finden Sie Informationen die Hauptstadtvertretung als Bindeglied zwischen der Bundesagentur für Arbeit und den Ministerien und dem Bundestag."},"content":{"de":"Die Hauptstadtvertretung ist die Verbindung zwischen der Zentrale der Bundesagentur für Arbeit und den in Berlin ansässigen Ministerien sowie dem Bundestag. Ihre Mitarbeiterinnen und Mitarbeiter nehmen vielfältige Aufgaben wahr, unter anderem folgende: positiv: Bewertung und Analyse BA-relevanter Gesetzesvorhaben, politischer Entscheidungen, Themen und Entwicklungen positiv: Information des Vorstands und der Führungskräfte der BA über diese Vorhaben oder Entscheidungen positiv: Informations- und Meinungsaustausch mit Vertretern von Bundestag, Bundesrat, Kanzleramt, Ministerien und Verbänden über die aktuelle BA-Geschäftspolitik positiv: erste Bewertung und Koordinierung der Anfragen von Abgeordneten"},"url":"https://www.arbeitsagentur.de/ueber-uns/hauptstadtvertretung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:41.646006+00:00","lastSeen":"2026-03-15T16:30:41.646006+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/hauptstadtvertretung","crawledAt":"2026-03-15T16:30:41.646006Z","crawlId":"contacts-seeded-1773592241","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"ab63e1f82a7ae6fb02dee6685b62478e93338e04fddab28fecb2b1641d34f63c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:41.646006+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9f581aa1-05b3-4543-83bc-69620987908f', 'contacts', 'https://www.arbeitsagentur.de/ueber-uns/regionaldirektionen', 'active', NULL, '2026-03-15T16:30:42.178863+00:00', '{"id":"9f581aa1-05b3-4543-83bc-69620987908f","title":"Regionaldirektionen","summary":{"de":"Die Regionaldirektionen sind für den Erfolg der regionalen Arbeitsmarktpolitik verantwortlich. Erfahren Sie hier mehr über ihre Aufgaben."},"content":{"de":"Sie setzen die Strategie der Bundesagentur für Arbeit um. Zur Abstimmung ihrer Aufgaben mit der Arbeitsmarkt-, Struktur- und Wirtschaftspolitik der Länder arbeiten sie eng mit den Landesregierungen zusammen. Die Regionaldirektionen führen die Agenturen für Arbeit. Sie haben spezielle Fragen? Dann wenden Sie sich mit Ihrem Anliegen direkt an die passenden Ansprechpartnerinnen und Ansprechpartner. Sie helfen Ihnen gerne weiter. Weitere Informationen zur Regionaldirektion Baden-Württemberg Weitere Informationen zur Regionaldirektion Bayern Friedrichstraße 34 10969 Berlin Fax: 030 555599-4999 Weitere Informationen zur Regionaldirektion Berlin-Brandenburg"},"url":"https://www.arbeitsagentur.de/ueber-uns/regionaldirektionen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:42.178863+00:00","lastSeen":"2026-03-15T16:30:42.178863+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/ueber-uns/regionaldirektionen","crawledAt":"2026-03-15T16:30:42.178863Z","crawlId":"contacts-seeded-1773592242","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"e2071e079a5c08ec314e60a010b222db92222f54048dd383a1172e9f2fc1b1bd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:42.179863+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e0c70e59-02db-40e6-99b1-7ea32822e8ef', 'contacts', 'https://www.arbeitsagentur.de/vor-ort/fba/startseite', 'active', NULL, '2026-03-15T16:30:42.669442+00:00', '{"id":"e0c70e59-02db-40e6-99b1-7ea32822e8ef","title":"Willkommen bei Ihrer Führungsakademie der BA","summary":{"de":"Die Führungsakademie (FBA) steht für Bildung, Weiterbildung, Führungskräfte-Entwicklung und Management-Seminare in der Bundesagentur für Arbeit (BA)."},"content":{"de":"Die Führungsakademie ist der interne Bildungsdienstleister der Bundesagentur für Arbeit (BA). Wir haben unser Verständnis von Führung weiterentwickelt und kompakt formuliert. Alle relevanten Aspekte werden sukzessive an dieser Stelle zur Verfügung gestellt. Erfahren Sie mehr über die Tätigkeiten für die wir Verstärkung suchen. Hinweis zur Verwendung von Bildern: Weitere Informationen zu Copyright und Markenschutz finden Sie in unserem Impressum."},"url":"https://www.arbeitsagentur.de/vor-ort/fba/startseite","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:42.669442+00:00","lastSeen":"2026-03-15T16:30:42.669442+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/vor-ort/fba/startseite","crawledAt":"2026-03-15T16:30:42.669442Z","crawlId":"contacts-seeded-1773592242","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b72cecd66b54386786d69c9f0cceda641573a4228e11c63d11cd1603d7f7af2c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:42.669442+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d10b337d-bc3f-4507-8ca6-9e7fb2d219da', 'contacts', 'https://www.arbeitsagentur.de/vor-ort/zav/startseite', 'active', NULL, '2026-03-15T16:30:43.174468+00:00', '{"id":"d10b337d-bc3f-4507-8ca6-9e7fb2d219da","title":"Zentrale Auslands- und Fachvermittlung (ZAV)","summary":{"de":"Im Netzwerk der Bundesagentur für Arbeit (BA) ist die Zentrale Auslands- und Fachvermittlung (ZAV) vor allem für die Zuwanderung von Fachkräften aus dem Ausland und für die Vermittlung besonderer Berufsgruppen verantwortlich."},"content":{"de":"First point of contact for all questions about living and working in Germany We support skilled workers and trainees in our projects and programs on their way to Germany Find out more about all aspects of working and living in Germany in our online WebTutorials, or meet us in person at selected job fairs in Europe Wissenswertes zu Studium, Ausbildung, Praktika und Überbrückungsmöglichkeiten/Gap Year in Deutschland Überblick über unsere Projekte und Programme zur Anwerbung von Fachkräften und Auszubildenden im Ausland. Wir helfen Ihnen in ausgewählten Berufen und Branchen Ihr Personal im Ausland zu finden. Sie möchten ausländische Arbeits- oder Fachkräfte beschäftigen – wir unterstützen Sie dabei und beraten Sie bei der Zulassung zum deutschen Arbeitsmarkt"},"url":"https://www.arbeitsagentur.de/vor-ort/zav/startseite","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:30:43.174468+00:00","lastSeen":"2026-03-15T16:30:43.174468+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesagentur fuer Arbeit","provenance":{"source":"https://www.arbeitsagentur.de/vor-ort/zav/startseite","crawledAt":"2026-03-15T16:30:43.175975Z","crawlId":"contacts-seeded-1773592243","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"e6446a71c13d36bcbcfc39ac67fffb3192f86726b6a0a85b31c47b142bb3a67b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:30:43.175975+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5b85f265-eb03-4226-b806-c090cccde6f4', 'contacts', 'https://www.bafza.de/klartext', 'active', NULL, '2026-03-15T16:31:05.628934+00:00', '{"id":"5b85f265-eb03-4226-b806-c090cccde6f4","title":"Klartext","summary":{"de":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben"},"content":{"de":"Für die Mitarbeitenden des Bundesamtes für Familie und zivilgesellschaftliche Aufgaben ( BAFzA ) ist der Name Programm: Wir engagieren uns gemeinsam für eine tolerante und offene Gesellschaft, fördern zivilgesellschaftliche Projekte und setzen uns für die Belange der Bürger*innen ein. Ausgrenzung, Spaltung, Intoleranz, gruppenbezogene Menschenfeindlichkeit sowie jedes Verhalten, das sich gegen die demokratische Grundordnung und die rechtsstaatlichen Grundsätze richtet, haben in unserem Denken und Handeln keinen Platz. Für uns zählt das Miteinander. Denn eine freiheitliche Demokratie lebt von der aktiven Teilhabe und dem sozialen Engagement ihrer Mitglieder. Telefon: 0221 3673-0 Telefax: 0221 3673-4661 E-Mail: service[at]bafza.bund.de Postanschrift: Bundesamt für Familie und zivilgesellschaftliche Aufgaben 50964 Köln Besucheranschrift: An den Gelenkbogenhallen 2-6 50679 Köln"},"url":"https://www.bafza.de/klartext","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:05.628934+00:00","lastSeen":"2026-03-15T16:31:05.628934+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://www.bafza.de/klartext","crawledAt":"2026-03-15T16:31:05.628934Z","crawlId":"contacts-seeded-1773592265","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"143b5a24437e544e81d26e3eaf25ed1996fc3dc5f42a4c10b97971d6a22fb856"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:05.628934+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3bfbd479-9b28-4c83-9c79-6734e0cc6472', 'contacts', 'https://www.bafza.de/ueber-das-bundesamt/wegbeschreibung/bafza-koeln', 'active', NULL, '2026-03-15T16:31:20.280137+00:00', '{"id":"3bfbd479-9b28-4c83-9c79-6734e0cc6472","title":"BAFz A Köln","summary":{"de":"Bundesamt für Familie und zivilgesellschaftliche Aufgaben"},"content":{"de":"Sofern Sie die Funktion „ Find my Location “ benutzen, werden Ihre Standortdaten an das Bundesamt für Kartographie und Geodäsie übermittelt. Weiter Informationen hierzu finden Sie hier. Aus allen Richtungen folgen Sie bitte den grünen Hinweisschildern: Kölnmesse Congress Centrum Ost. Direkt gegenüber dem Messeeingang befindet sich das weiße Bürogebäude. Vom Kölner Hauptbahnhof haben Sie folgende Möglichkeiten, um zum Bahnhof Köln-Deutz/Messe zu gelangen: Den Bahnhof Köln-Deutz/Messe durch den Hauptausgang verlassen und links halten (an den Gleisen entlang) Unter der Eisenbahnbrücke links in die Deutz-Mülheimer Straße einbiegen"},"url":"https://www.bafza.de/ueber-das-bundesamt/wegbeschreibung/bafza-koeln","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:20.280137+00:00","lastSeen":"2026-03-15T16:31:20.280137+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://www.bafza.de/ueber-das-bundesamt/wegbeschreibung/bafza-koeln","crawledAt":"2026-03-15T16:31:20.280137Z","crawlId":"contacts-seeded-1773592280","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"8a598cb511103790158b5825cf9938dec4872e9c7a769b873100b199a6db694a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:20.280137+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('118b532e-3b10-4194-97e4-13a4c2120c7a', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Beschaeftigungssicherung/beschaeftigungssicherung.html', 'active', NULL, '2026-03-15T17:45:26.123172+00:00', '{"id":"118b532e-3b10-4194-97e4-13a4c2120c7a","title":"Beschäftigungssicherung","summary":{"de":"Instrumente der Beschäftigungssicherung bieten Unterstützung bei Arbeits- und Lohnausfällen sowie bei Personalanpassungsmaßnahmen."},"content":{"de":"Instrumente der Beschäftigungssicherung bieten Unterstützung bei Arbeits- und Lohnausfällen sowie bei Personalanpassungsmaßnahmen."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Beschaeftigungssicherung/beschaeftigungssicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:45:26.123172+00:00","lastSeen":"2026-03-15T17:45:26.123172+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Beschaeftigungssicherung/beschaeftigungssicherung.html","crawledAt":"2026-03-15T17:45:26.124262Z","crawlId":"contacts-seeded-1773596726","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"de0ff154915458ebf45fd2861419772d4deae38c02ba56c3f22b45ada1ea39cc"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:45:26.124262+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a377e359-41d9-41b4-8265-5047999ee45e', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Programme-fuer-Beschaeftigungschancen/programme-fuer-beschaeftigungschancen.html', 'active', NULL, '2026-03-15T16:31:23.468523+00:00', '{"id":"a377e359-41d9-41b4-8265-5047999ee45e","title":"Programme für Beschäftigungschancen (SGB III)","summary":{"de":"Ziel der Richtlinie ist, Personen mit Migrationshintergrund zu den erforderlichen Qualifizierungen zu verhelfen, die zur vollen Anerkennung ausländischer Berufsqualifikationen benötigt werden oder die eine bildungsadäquate Erwerbsmöglichkeit der Teilnehmerinnen und Teilnehmer ermöglichen."},"content":{"de":"Der Europäische Sozialfonds und nationale Bundesprogramme erhöhen mit unterschiedlichen Förderschwerpunkten die Beschäftigungschancen von Menschen, die eine Arbeit oder einen Ausbildungsplatz suchen. Ziel des Programms ist es, junge Menschen in eine Berufsausbildung einzugliedern. Leistungsschwächere Schülerinnen und Schüler, die Probleme haben, einen Schulabschluss zu erlangen und damit auch Gefahr laufen, den erfolgreichen Start ins Berufsleben zu verpassen, werden individuell und kontinuierlich von der Schule bis in die Berufsausbildung von sogenannten Berufseinstiegsbegleiter/-innen unterstützt. Der ESF hat in der vergangenen Förderperiode einen Beitrag zur Sicherung des Fachkräftebedarfs geleistet sowie die soziale Inklusion gefördert und Armut bekämpft. In der Förderperiode 2021-2027 wird der neue ESF Plus noch stärker auf den Gedanken eines sozialeren Europas ausgerichtet und investiert vor Ort in Maßnahmen, um Menschen bei der Bewältigung wirtschaftlicher und sozialer Herausforderungen zu unterstützen. Das Sonderprogramm zur \"Förderung der beruflichen Mobilität von ausbildungsinteressierten Jugendlichen aus Europa (MobiPro-EU)\" leistete einen Beitrag zur Bekämpfung der Jugendarbeitslosigkeit in Europa und unterstützte seit 2013 Jugendliche und junge Erwachsene aus der EU dabei, in Deutschland eine betriebliche Berufsausbildung erfolgreich zu absolvieren. Als ein zentrales arbeitsmarktpolitisches Instrument der Bundesregierung hat sich in den letzten Jahren das vom BMAS initiierte und inzwischen gemeinsam mit dem BMBF und der BA durchgeführte Förderprogramm \"Integration durch Qualifizierung ( IQ )\" etabliert."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Programme-fuer-Beschaeftigungschancen/programme-fuer-beschaeftigungschancen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:23.468523+00:00","lastSeen":"2026-03-15T16:31:23.468523+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/Programme-fuer-Beschaeftigungschancen/programme-fuer-beschaeftigungschancen.html","crawledAt":"2026-03-15T16:31:23.470069Z","crawlId":"contacts-seeded-1773592283","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"a4b951ed740c83efd70fa4138cb2b62d73142278cc1f9d4a781cfa786754953a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:23.470069+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('61fb4c0e-48c9-4116-8044-cabfb125d10b', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/arbeitsfoerderung.html', 'active', NULL, '2026-03-15T16:31:24.029118+00:00', '{"id":"61fb4c0e-48c9-4116-8044-cabfb125d10b","title":"Arbeitsförderung","summary":{"de":"Arbeitslosigkeit soll gar nicht erst entstehen – oder möglichst kurz gehalten werden. Das ist ein Kernanliegen der Arbeitsförderung. Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Arbeitslosigkeit soll gar nicht erst entstehen – oder möglichst kurz gehalten werden. Das ist ein Kernanliegen der Arbeitsförderung. Bundesministerin Bärbel Bas zu den Arbeitsmarktzahlen im Januar 2026. Das Bundeskabinett beschließt die Vierte Verordnung über die Bezugsdauer für das Kurzarbeitergeld. Sozialleistungen bei Arbeitslosigkeit & Arbeitssuche - Sozialplattform"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/arbeitsfoerderung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:24.029118+00:00","lastSeen":"2026-03-15T16:31:24.029118+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsfoerderung/arbeitsfoerderung.html","crawledAt":"2026-03-15T16:31:24.030118Z","crawlId":"contacts-seeded-1773592284","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"24060fd7a9dc045b5691f4f1c644d1def177970df5ecbf28ea809fec90ab2761"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:24.030118+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('acb5f2bb-a0dd-4253-b880-afc81cfdd3e3', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Aktionsplan-Tarifverhandlungen/aktionsplan-tarifverhandlungen.html', 'active', NULL, '2026-03-15T16:31:24.788911+00:00', '{"id":"acb5f2bb-a0dd-4253-b880-afc81cfdd3e3","title":"Nationaler Aktionsplan zur Förderung von Tarifverhandlungen","summary":{"de":"Die Richtlinie ( EU ) 2022/2041 über angemessene Mindestlöhne in der Europäischen Union (EU- Mindestlohn-Richtlinie) hat zur Verbesserung der Lebens- und Arbeitsbedingungen in der Europäischen Union unter anderem einen Rahmen geschaffen, mit dem Tarifverhandlungen zur Lohnfestsetzung gefördert werden. Hierzu gehört, dass alle Mitgliedstaaten der Europäischen Union einen Nationalen Aktionsplan zur Förderung von Tarifverhandlungen vorlegen müssen, wenn die tarifvertragliche Abdeckung unterhalb einer Schwelle von 80 Prozent liegt. Deutschland erreicht diesen Schwellenwert nicht und wird einen Nationalen Aktionsplan vorlegen."},"content":{"de":"Die Sozialpartner haben im Rahmen eines Konsultationsverfahrens die Möglichkeit erhalten, ihre Vorstellungen zu möglichen Maßnahmen zur Förderung von Tarifverhandlungen einzubringen. Die Stellungnahmen der Sozialpartner werden in den Nationalen Aktionsplan einfließen. Der Nationale Aktionsplan wird von der Bundesregierung beschlossen und an die Europäische Kommission übersandt. Die Konsultationsphase fand im Zeitraum 17. Juli 2025 bis 15. August 2025 statt. Die eingereichten Stellungnahmen finden Sie hier: Bundesvereinigung der Deutschen Arbeitgeberverbände (BDA) [PDF, 260KB] Bundesindustrieverband Technische Gebäudeausrüstung e. V. (BTGA) [PDF, 180KB] Caritas-Dienstgeber (DGS AK Caritas) und der Verband diakonischer Dienstgeber in Deutschland (derzeit nicht barrierefrei) [PDF, 191KB] Christliche Gewerkschaft Metall (CGM) [PDF, 170KB]"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Aktionsplan-Tarifverhandlungen/aktionsplan-tarifverhandlungen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:24.788911+00:00","lastSeen":"2026-03-15T16:31:24.788911+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Aktionsplan-Tarifverhandlungen/aktionsplan-tarifverhandlungen.html","crawledAt":"2026-03-15T16:31:24.788911Z","crawlId":"contacts-seeded-1773592284","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"fa4b1f51e840ad1b97f657eb0283c6646023c9eec1a328af75f9f93fb7845f34"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:24.788911+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b0f6bc26-83d0-423d-b634-8c9c4fe4c058', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Betriebliche-Mitbestimmung/betriebliche-mitbestimmung.html', 'active', NULL, '2026-03-15T16:31:25.399266+00:00', '{"id":"b0f6bc26-83d0-423d-b634-8c9c4fe4c058","title":"Betriebliche Mitbestimmung","summary":{"de":"Das Betriebsverfassungsgesetz (BetrVG) regelt die Mitbestimmung der Arbeitnehmerinnen und Arbeitnehmer in betrieblichen Angelegenheiten, die sie unmittelbar an ihrem Arbeitsplatz betreffen."},"content":{"de":"In jedem Betrieb der privaten Wirtschaft auf dem Gebiet der Bundesrepublik Deutschland mit mindestens fünf wahlberechtigten Arbeitnehmerinnen oder Arbeitnehmern, von denen drei wählbar sind, haben die Arbeitnehmerinnen und Arbeitnehmer das Recht, einen Betriebsrat zu wählen. Für Betriebe ohne Betriebsrat gilt: Ein Betriebsrat kann jederzeit gewählt werden. Bei Betrieben mit einem Betriebsrat finden die regelmäßigen Wahlen zwischen dem 1. März und dem 31. Mai statt, zuletzt im Jahr 2022. Die nächste Wahl erfolgt im Jahr 2026. Die Amtszeit eines Betriebsrats beträgt vier Jahre. Hier finden Sie die Wahlordnungen zum Betriebsverfassungsgesetz. Die Wahl des Betriebsrats ist ein wesentliches Element der Betriebsverfassung. Deshalb hat der Gesetzgeber auch für einen besonderen Schutz der Betriebsratswahl gesorgt. So wird die Behinderung oder unzulässige Beeinflussung der Wahl unter Strafe gestellt. Wahlvorstand, Wahlbewerber zum Betriebsrat und die ersten drei Arbeitnehmerinnen oder Arbeitnehmer, die zu einer Wahlversammlung einladen verfügen über einen besonderen Kündigungsschutz. Ein Verstoß gegen Wahlvorschriften kann zur Anfechtung der Wahl vor dem Arbeitsgericht führen. Wird die Wahl für ungültig erklärt, muss eine neue angesetzt werden. Sämtliche mit dem Wahlvorgang verbundenen Kosten trägt der Arbeitgeber. Die Größe des Betriebsrats hängt von den regelmäßig beschäftigten wahlberechtigten Arbeitnehmerinnen und Arbeitnehmern ab. Er besteht mindestens aus einer Person (bei 5 bis 20 wahlberechtigten Arbeitnehmerinnen und Arbeitnehmer) bis zu über 35 Mitgliedern (bei mehr als 9.000 Arbeitnehmerinnen und Arbeitnehmern)."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Betriebliche-Mitbestimmung/betriebliche-mitbestimmung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:25.399266+00:00","lastSeen":"2026-03-15T16:31:25.399266+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Betriebliche-Mitbestimmung/betriebliche-mitbestimmung.html","crawledAt":"2026-03-15T16:31:25.399266Z","crawlId":"contacts-seeded-1773592285","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"fc6fc402b363b0897faa30f3bc556c399a3546049063a9079316eea7e821bd20"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:25.399266+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('70d80041-3c44-486e-98fd-f4f8bbe011aa', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Jugendarbeitsschutz/jugendarbeitsschutz.html', 'active', NULL, '2026-03-15T16:31:26.623573+00:00', '{"id":"70d80041-3c44-486e-98fd-f4f8bbe011aa","title":"Jugendarbeitsschutz","summary":{"de":"Kinder und Jugendliche in der Arbeitswelt müssen besonders geschützt werden. Spezielle Regelungen zum Schutz junger Menschen bei der Arbeit enthalten das Jugendarbeitsschutzgesetz und die Kinderarbeitsschutzverordnung."},"content":{"de":"Kinder und Jugendliche sind weniger widerstandsfähig als Erwachsene und dürfen deshalb in der Arbeitswelt nicht den gleichen Belastungen ausgesetzt werden. Das Gesetz zum Schutz der arbeitenden Jugend (JArbSchG) enthält besondere Regelungen zum Schutz von Kindern und Jugendlichen in der Arbeitswelt. Ziel des Jugendarbeitsschutzgesetzes ist es, Kinder und Jugendliche vor Überlastun­gen zu schützen. Das Gesetz schützt deshalb junge Menschen vor Arbeit, die zu früh beginnt, die zu lange dauert, die zu schwer ist, die sie gefährdet oder die für sie unge­eignet ist. Kinderarbeit ist grundsätzlich verboten. Das Jugendarbeitsschutzgesetz schützt junge Menschen unter 18 Jahren. Personen unter 15 Jahren gelten als Kinder. Jugendliche sind Personen, die 15 aber noch nicht 18 Jahre alt sind. Für Jugendliche, die noch Vollzeit schulpflichtig sind, gelten diesel­ben Bestimmungen wie für Kinder. Ein wesentlicher Garant für die Gesundheit junger Menschen ist deren aktiver Schutz in der Arbeitswelt. Die Verordnung über den Kinderarbeitsschutz (KindArbSchV) konkretisiert die nach dem Jugendarbeitsschutzgesetz für Kinder über 13 Jahren und Vollzeit schulpflichtige Jugendliche ausnahmsweise zulässigen leichten und für sie geeigneten Arbeiten. Zugelassen werden – mit Ausnahme des Austragens von Zeitungen, Zeitschriften, Anzeigenblättern und Werbeprospekten – nur Beschäftigungen im nichtgewerblichen Bereich."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Jugendarbeitsschutz/jugendarbeitsschutz.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:26.623573+00:00","lastSeen":"2026-03-15T16:31:26.623573+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Jugendarbeitsschutz/jugendarbeitsschutz.html","crawledAt":"2026-03-15T16:31:26.623573Z","crawlId":"contacts-seeded-1773592286","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b36a65b44e4257c9ff572f080becd19ad8c64a4c4599a26917bef91c6d5f2a1f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:26.623573+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0aebf7da-fb2d-4992-bc02-5069a239ed2a', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Kuendigungsschutz/kuendigungsschutz.html', 'active', NULL, '2026-03-15T16:31:27.273122+00:00', '{"id":"0aebf7da-fb2d-4992-bc02-5069a239ed2a","title":"Kündigungsschutz","summary":{"de":"Wird ein Arbeitsverhältnis beendet, so besteht für Arbeitnehmerinnen und Arbeitnehmer ein allgemeiner Kündigungsschutz."},"content":{"de":"Besonderer Kündigungsschutz bestimmter Arbeitnehmergruppen Die Beendigung des Arbeitsverhältnisses ist nur unter bestimmten Voraussetzungen möglich, die das Kündigungsschutzrecht näher regelt. In Betrieben mit mehr als zehn Arbeitnehmerinnen bzw. Arbeitnehmern gilt das Kündigungsschutzgesetz. In diesem Fall kann der Arbeitgeber das Arbeitsverhältnis nur kündigen, wenn ein Kündigungsgrund vorliegt. Kündigungsgründe, die das Kündigungsschutzgesetz zulässt, sind Gründe in der Person oder dem Verhalten der Arbeitnehmerin bzw. des Arbeitnehmers sowie betriebsbedingte Gründe. Die Broschüre informiert über den allgemeinen und besonderen Kündigungsschutz. Sowohl Arbeitgeber als auch Arbeitnehmerin bzw. Arbeitnehmer müssen die gesetzlichen oder vereinbarten Kündigungsfristen einhalten. Eine fristlose Kündigung kann nur dann ausgesprochen werden, wenn ein wichtiger Grund vorliegt. Eine Arbeitnehmerin bzw. ein Arbeitnehmer, die bzw. der die Wirksamkeit seiner Kündigung gerichtlich überprüfen lassen möchte, kann innerhalb von drei Wochen nach Zugang der schriftlichen Kündigung Kündigungsschutzklage erheben. Wird die Frist versäumt, gilt die Kündigung als von Anfang an rechtswirksam."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Kuendigungsschutz/kuendigungsschutz.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:27.273122+00:00","lastSeen":"2026-03-15T16:31:27.273122+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Kuendigungsschutz/kuendigungsschutz.html","crawledAt":"2026-03-15T16:31:27.273122Z","crawlId":"contacts-seeded-1773592287","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"32581184b7b9e920126796b4974911a6942242f17f10a70cc612ed5306c8b1cd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:27.273122+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('738a2036-cafa-4bad-9493-82096f544465', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Regelungen-zur-Arbeitszeit/regelungen-zur-arbeitszeit.html', 'active', NULL, '2026-03-15T16:31:27.896979+00:00', '{"id":"738a2036-cafa-4bad-9493-82096f544465","title":"Regelungen zur Arbeitszeit","summary":{"de":"Informationen zum Arbeitszeitgesetz, zur Arbeitszeiterfassung und zum Ladenschlussgesetz"},"content":{"de":"Um die Sicherheit und den Gesundheitsschutz der Beschäftigten in Deutschland zu gewährleisten, gibt es Regelungen zur Arbeitszeitgestaltung. Das Arbeitszeitgesetz (ArbZG) legt die Grundnormen dafür fest, wann und wie lange Arbeitnehmerinnen und Arbeitnehmer in Deutschland höchstens arbeiten dürfen. Das Gesetz stellt den Gesundheitsschutz der Beschäftigten sicher, indem es die tägliche Höchstarbeitszeit begrenzt sowie Mindestruhepausen während der Arbeit und Min­destruhezeiten nach Arbeitsende festlegt. Nachtarbeitnehmerinnen und Nachtarbeit­nehmer sind besonders geschützt. Besondere Regelungen gibt es z. B. in den Bundes- und Landesgesetzen für Beamtinnen und Beamte oder im Jugendarbeitsschutzgesetz für Jugendliche. Wöchentlicher Ruhetag ist grundsätzlich der Sonntag. Die Sonn- und Feiertagsruhe wird durch ein grundsätzliches Beschäftigungsverbot gewährleistet. Arbeiten sind an diesen Tagen nur ausnahmsweise unter den im Gesetz festgelegten Bedingungen zulässig. Da das Gesetz sich auf die zum Schutz von Sicherheit und Gesundheit erforderlichen Regelungen beschränkt, schafft es mit seinen Rahmenbedingungen einen weiten Spielraum für die Vereinbarung flexibler Arbeitszeiten. Das Bundesarbeitsgericht (BAG) hat mit Beschluss vom 13. September 2022 festgestellt, dass in Deutschland die gesamte Arbeitszeit der Arbeitnehmerinnen und Arbeitnehmer aufzuzeichnen ist. Arbeitgeber sind nach § 3 Abs. 2 Nr. 1 des Arbeitsschutzgesetzes (ArbSchG) verpflichtet, ein System einzuführen, mit dem die von den Arbeitnehmern geleistete Arbeitszeit erfasst werden kann."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Regelungen-zur-Arbeitszeit/regelungen-zur-arbeitszeit.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:27.896979+00:00","lastSeen":"2026-03-15T16:31:27.896979+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Regelungen-zur-Arbeitszeit/regelungen-zur-arbeitszeit.html","crawledAt":"2026-03-15T16:31:27.896979Z","crawlId":"contacts-seeded-1773592287","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b636eebcc754c83608a06fd94bf52519b8211445940a632d24dcc7119c5aab81"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:27.896979+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ce134070-6953-48c0-a26b-de8a7203c005', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Schutz-fuer-Paketboten/schutz-fuer-paketboten.html', 'active', NULL, '2026-03-15T16:31:28.499181+00:00', '{"id":"ce134070-6953-48c0-a26b-de8a7203c005","title":"Schutz für Paketboten","summary":{"de":"Für bessere Arbeitsbedingungen in der Paketbranche"},"content":{"de":"Seit November 2019 gilt in Deutschland das Paketboten-Schutz-Gesetz. Damit wurde die Nachunternehmerhaftung für die korrekte Zahlung von Sozial­versicherungsbeiträgen, die bereits seit Jahren in der Fleischwirtschaft und am Bau wirkt, auf die Paketbranche ausgeweitet. Wer einen Auftrag an einen Sub­unternehmer weiter vergibt, haftet also für die abzuführenden Beiträge. Führt der Subunternehmer keine Beiträge ab, steht der Hauptunternehmer ein. Die Evaluierung des Gesetzes hat nun seine Wirksamkeit gezeigt: Seit 2019 ist der Anteil der sozialversicherungspflichtig Beschäftigten in der Branche gestiegen. Viele Subunternehmer bemühen sich um eine Präqualifikation und achten auf die korrekte Zahlung ihrer Beiträge. Pressemitteilung vom 30.07.25: Gute Arbeitsbedingungen für Paketboten und Kuriere Gesetz zur Neuregelung maschinenrechtlicher Vorschriften und zur Änderung des Paketboten-Schutz-Gesetzes"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Schutz-fuer-Paketboten/schutz-fuer-paketboten.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:28.499181+00:00","lastSeen":"2026-03-15T16:31:28.499181+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/Schutz-fuer-Paketboten/schutz-fuer-paketboten.html","crawledAt":"2026-03-15T16:31:28.499181Z","crawlId":"contacts-seeded-1773592288","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"5bbd08c7751954b97481ab7beda729391e1536e306419c595e2113143fec8b6d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:28.499181+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c9daccca-51a1-4a02-8eed-9fbded002e2d', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/arbeitnehmerrechte.html', 'active', NULL, '2026-03-15T17:45:33.026282+00:00', '{"id":"c9daccca-51a1-4a02-8eed-9fbded002e2d","title":"Arbeitnehmerrechte","summary":{"de":"Mit einer Vielzahl von Regelungen werden Arbeitnehmerinnen und Arbeitnehmer in Deutschland geschützt und gesichert."},"content":{"de":"Mit einer Vielzahl von Regelungen werden Arbeitnehmerinnen und Arbeitnehmer in Deutschland geschützt und gesichert."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/arbeitnehmerrechte.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:45:33.026282+00:00","lastSeen":"2026-03-15T17:45:33.026282+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Arbeitnehmerrechte/arbeitnehmerrechte.html","crawledAt":"2026-03-15T17:45:33.027522Z","crawlId":"contacts-seeded-1773596733","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"6d52b153a30b94d3b69fce7f615f58d524b0d81d91872703aac8d920e13f2a2f"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:45:33.027522+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('33639af7-bb56-4d77-9bca-13c754edc0ea', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Entsendung-von-Arbeitnehmern/entsendung-von-arbeitnehmern.html', 'active', NULL, '2026-03-15T16:31:29.648761+00:00', '{"id":"33639af7-bb56-4d77-9bca-13c754edc0ea","title":"Entsendung von Arbeitnehmern","summary":{"de":"Bei der Entsendung von Arbeitnehmern nach Deutschland ist das Arbeitnehmer-Entsendegesetz zu beachten. Das Arbeitnehmer-Entsendegesetz setzt die EU -Entsenderichtlinie um. Das Gesetz folgt dem Arbeitsortsprinzip, d.h. der Arbeitgeber muss seinen Arbeitnehmern für die Zeit der vorübergehenden Beschäftigung in Deutschland bestimmte, am jeweiligen Arbeitsort in Deutschland maßgebliche Arbeitsbedingungen gewähren."},"content":{"de":"Das Gesetz gilt für Arbeitgeber aller Branchen. Soweit Arbeitsbedingungen im Sinne des Arbeitnehmer-Entsendegesetzes in Tarifverträgen geregelt sind, müssen im Ausland ansässige Arbeitgeber sie ihren vorübergehend in Deutschland beschäftigten Arbeitnehmern nur dann gewähren, wenn diese Arbeitsbedingungen (durch eine Rechtsverordnung oder eine Allgemeinverbindlicherklärung im Sinne des Arbeitnehmer-Entsendegesetzes) auch für alle entsprechenden deutschen Arbeitgeber zwingend vorgeschrieben sind. In der Pflegebranche (Altenpflege und ambulante Krankenpflege) können Arbeitgeber durch eine Rechtsverordnung verpflichtet werden, die von einer Kommission vorgeschlagenen Arbeitsbedingungen einzuhalten. Das Pflegelöhneverbesserungsgesetz, das am 29. November 2019 in Kraft getreten ist, sieht verschiedene Änderungen im Arbeitnehmer-Entsendegesetz (AEntG) vor. Mit dem Gesetz wurde zum einen der bereits bestehende Weg zur Festlegung verbindlicher Lohnuntergrenzen durch Rechtsverordnung des BMAS auf Empfehlung der Pflegekommission novelliert. Unter anderem sieht das Gesetz nun vor, dass die Pflegekommission künftig dauerhaft eingerichtet wird (mit fünfjähriger Amtszeit). Zum anderen wurde mit dem Gesetz ein zweiter Weg zur Festsetzung verbindlicher Lohnuntergrenzen im AEntG gangbarer gemacht: die Erstreckung eines Tarifvertrags auf die Pflegebranche. Des Weiteren sind nach dem Arbeitnehmer-Entsendegesetz verschiedene Pflichten zu beachten, die der Kontrolle der Einhaltung der vorgeschriebenen Arbeitsbedingungen dienen, wie z.B. Meldepflichten, Arbeitszeitdokumentation. Ausführliche Informationen zu den maßgeblichen Arbeitsbedingungen sowie zum Verfahren finden Sie auf der Website der mit der Kontrolle des Gesetzes beauftragten Behörden der Zollverwaltung. Die Informationen sind auch auf Englisch ( Posting of Workers ) eingestellt. Die Website der Zollverwaltung ist die „einzige offizielle nationale Website“ im Sinne von Artikel 5 der Richtlinie 2014/67/EU die Durchsetzung der EU -Entsenderichtlinie. Merk­blatt für nach Deutsch­land ent­sand­te Ar­beit­neh­me­rin­nen und Ar­beit­neh­mer [PDF, 103KB]"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Entsendung-von-Arbeitnehmern/entsendung-von-arbeitnehmern.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:29.648761+00:00","lastSeen":"2026-03-15T16:31:29.648761+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Entsendung-von-Arbeitnehmern/entsendung-von-arbeitnehmern.html","crawledAt":"2026-03-15T16:31:29.648761Z","crawlId":"contacts-seeded-1773592289","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"cdede097fc161dfe65cea204df0618ef0a5c0b1238953a5406e47bc513b37884"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:29.648761+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f7a32122-33cd-49d7-b665-130da441c4c7', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Leiharbeit-Werkvertraege/leiharbeit-werkvertraege.html', 'active', NULL, '2026-03-15T16:31:30.366145+00:00', '{"id":"f7a32122-33cd-49d7-b665-130da441c4c7","title":"Leiharbeit / Werkverträge","summary":{"de":"Flexibilität für Unternehmen, Sicherheit für Arbeitnehmerinnen und Arbeitnehmer"},"content":{"de":"Unsere Arbeitswelt ändert sich durch Digitalisierung und neue Arbeitsformen. Aber auch bisher gab es in Deutschland neben den klassischen Arbeitsverhältnissen verschiedene Möglichkeiten des flexiblen Personaleinsatzes für Unternehmen, wie zum Beispiel die Arbeitnehmerüberlassung. Die Arbeitnehmerüberlassung (auch Leih- oder Zeitarbeit) ist darauf ausgerichtet, fehlendes eigenes Personal vorübergehend zu ersetzen oder zu ergänzen. Dies kann für eine Auftragsspitze genauso gelten wie für den krankheitsbedingten Ausfall von Mitarbeitern. In den vergangenen Jahren haben Unternehmen Aufgaben ausgelagert (\" Outsourcing \"). Über Werk- und Dienstleistungsverträge können sich Unternehmen die Erbringung von Arbeiten oder Dienstleistungen einkaufen, die sie selbst nicht durchführen. Das gilt insbesondere für spezialisierte Arbeitsaufträge oder auch Bereiche, die nicht zum Kerngeschäft eines Unternehmens gehören. Unternehmen können dementsprechend verschiedene Mechanismen nutzen, die alle den Zweck der Flexibilität erfüllen. Allerdings bedeutet Flexibilität oft auch mehr Unsicherheit für Arbeitnehmerinnen und Arbeitnehmer. So wurden mit den letzten Änderungen des Arbeitnehmerüberlassungsgesetzes die Rechte der Leiharbeitnehmern gestärkt, damit Leiharbeit nicht zu Lasten von Arbeitnehmerinnen und Arbeitnehmern genutzt wird. Auch ist mittlerweile gesetzlich definiert, wann ein Arbeitsvertrag vorliegt. Gesetz zur Änderung des Arbeitnehmerüberlassungsgesetzes und anderer Gesetze"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Leiharbeit-Werkvertraege/leiharbeit-werkvertraege.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:30.366145+00:00","lastSeen":"2026-03-15T16:31:30.366145+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Leiharbeit-Werkvertraege/leiharbeit-werkvertraege.html","crawledAt":"2026-03-15T16:31:30.366145Z","crawlId":"contacts-seeded-1773592290","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"5da68ad0506bbe8766bad1585ff0c9e3a3d06284612b4b171437d9e5fdba83f0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:30.366145+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d3553674-5931-4241-ab3a-7bc28e3b3b5e', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Branchenmindestlohn/branchenmindestlohn.html', 'active', NULL, '2026-03-15T16:31:31.070587+00:00', '{"id":"d3553674-5931-4241-ab3a-7bc28e3b3b5e","title":"Branchenmindestlöhne","summary":{"de":"In einigen Branchen, insbesondere in verschiedenen Zweigen des Baugewerbes, gibt es verbindliche Mindestlöhne, die über dem allgemeinen gesetzlichen Mindestlohn liegen."},"content":{"de":"Sechste Aus- und Weiterbildungsdienstleistungenarbeitsbedingungenverordnung Die Sechste Verordnung über zwingende Arbeitsbedingungen für Aus- und Weiterbildungsdienstleistungen nach dem Zweiten oder Dritten Buch Sozialgesetzbuch knüpft an die am 31. Dezember 2022 außer Kraft getretene Fünfte Mindestlohnverordnung für Aus- und Weiterbildungsdienstleistungen nach dem Zweiten oder Dritten Buch Sozialgesetzbuch an. Zehnte Gebäudereinigungsarbeits­bedingungenverordnung Am 1. Februar 2025 ist die Zehnte Gebäudereinigungsarbeitsbedingungen­verordnung in Kraft getreten. Mit der Verordnung werden auf der Grundlage eines Tarifvertrags der Tarifparteien des Gebäudereiniger-Handwerks (Industriegewerkschaft Bauen-Agrar-Umwelt und Bundesinnungsverband des Gebäudereiniger-Handwerk) bundesweite Mindeststundenentgelte für die gewerblichen Arbeitnehmerinnen und Arbeitnehmer in der Branche festgesetzt. Zwölfte Verordnung über zwingende Arbeitsbedingungen für das Maler- und Lackiererhandwerk Am 1. August 2025 ist die Zwölfte Verordnung über zwingende Arbeitsbedingungen für das Maler- und Lackiererhandwerk in Kraft getreten. Mit der Verordnung werden auf der Grundlage eines Tarifvertrags der Tarifparteien des Maler- und Lackiererhandwerks Mindeststundenentgelte für die gewerblichen gelernten Arbeitnehmerinnen und Arbeitnehmer (Gesellinnen und Gesellen) in der Branche festgesetzt."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Branchenmindestlohn/branchenmindestlohn.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:31.070587+00:00","lastSeen":"2026-03-15T16:31:31.070587+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Branchenmindestlohn/branchenmindestlohn.html","crawledAt":"2026-03-15T16:31:31.070587Z","crawlId":"contacts-seeded-1773592291","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"175e1f75878ad9cdbb5ec36c0a6d5efc1afe8ee377c764bfac8b39410992e7c6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:31.070587+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9894eea6-076d-4397-82ea-3191ef2d0fbd', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Dokumentationspflicht/dokumentationspflicht.html', 'active', NULL, '2026-03-15T16:31:31.681045+00:00', '{"id":"9894eea6-076d-4397-82ea-3191ef2d0fbd","title":"Dokumentationspflicht","summary":{"de":"Um sicherzustellen, dass der Mindestlohn tatsächlich für jede Arbeitsstunde bezahlt wird, besteht in bestimmten Branchen die Pflicht, die Arbeitszeiten zu notieren."},"content":{"de":"Seit dem 1. Januar 2026 gilt in Deutschland der gesetzliche Mindestlohn von brutto 13,90 Euro je Zeitstunde. Um sicherzustellen, dass dieser tatsächlich für jede Arbeitsstunde bezahlt wird, besteht in bestimmten Branchen die Pflicht, die Arbeitszeiten zu notieren (Dokumentationspflicht). Die Dokumentationspflicht gilt generell nur für geringfügig Beschäftigte (Ausnahme: Minijobber im privaten Bereich) und die im Schwarzarbeitsbekämpfungsgesetz genannten Wirtschaftsbereiche, in denen eine besondere Missbrauchsgefahr besteht. Dazu zählen z.B. das Baugewerbe, Gaststätten und Herbergen, das Speditions-, Transport - und Logistik gewerbe einschließlich der plattformbasierten Lieferdienste, Gebäudereinigung, Messebau, die Fleischwirtschaft mit Ausnahme des Fleischerhandwerks sowie das Friseur- und Kosmetikgewerbe. Auch Zeitungszustellerinnen und -zusteller und Beschäftigte bei Paketdiensten müssen regelmäßig ihre Arbeitszeit aufzeichnen. Eine entsprechende Dokumentationspflicht aufgrund des Arbeitnehmer-Entsendegesetzes besteht in Wirtschaftsbereichen, in denen ein Tarifvertrag nach dem Arbeitnehmer-Entsendegesetz allgemein verbindlich ist. Auf einem Zettel oder Vordruck (siehe unseren Musterbogen [PDF, 19KB] ) muss der Arbeitgeber notieren (oder notieren lassen): das Ende der Arbeitszeit (ebenfalls für jeden Arbeitstag) die Dauer der täglichen Arbeitszeit, also bspw. die Stunden. Achtung: Pausenzeiten gehören nicht zur Arbeitszeit, sind also herauszurechnen; die konkrete Dauer und Lage der jeweiligen Pausen müssen nicht aufgezeichnet werden. Es ist egal, ob die Liste handschriftlich oder maschinell erstellt und ausgefüllt wird."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Dokumentationspflicht/dokumentationspflicht.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:31.681045+00:00","lastSeen":"2026-03-15T16:31:31.681045+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Dokumentationspflicht/dokumentationspflicht.html","crawledAt":"2026-03-15T16:31:31.682052Z","crawlId":"contacts-seeded-1773592291","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b61939ea02c177b4ff8f476681e8d2c0f950cf8efe7dc2141ad1c2ec60b1e47c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:31.682052+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('56e97f7d-e779-40e0-832e-7ab129fe6567', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Einfuehrung-und-Anpassungen-Mindestlohn/einfuehrung-und-anpassung-mindestlohn.html', 'active', NULL, '2026-03-15T16:31:32.317731+00:00', '{"id":"56e97f7d-e779-40e0-832e-7ab129fe6567","title":"Einführung und Anpassungen des Mindestlohns","summary":{"de":"Einen allgemeinen gesetzlichen Mindestlohn gibt es in Deutschland seit dem 1. Januar 2015. Damit wurde eine Lohnuntergrenze eingeführt, die nicht unterschritten werden darf. Für wen und wann der Mindestlohn zu zahlen ist, wie die Höhe bestimmt und wie die Einhaltung durchgesetzt und kontrolliert wird, regelt das Mindestlohngesetz (MiLoG)."},"content":{"de":"Über die Anpassung des allgemeinen gesetzlichen Mindestlohns entscheidet nach der Konzeption des MiLoG alle zwei Jahre eine unabhängige Kommission der Tarifpartner, die sich aus Vertretern der Arbeitgeberverbände sowie den Gewerkschaften zusammen­setzt und außerdem von Wissenschaftlern beraten wird. Die Bestimmung des gesetzlichen Mindestlohns durch die sachnäheren Sozialpartner bedeutet ebenfalls eine Stärkung der Tarifautonomie. Die Mindestlohnkommission prüft für ihre Entscheidung im Rahmen einer Gesamtabwägung, welche Höhe des Mindestlohns geeignet ist, zu einem angemessenen Mindestschutz der Arbeitnehmerinnen und Arbeitnehmer beizutragen, faire und funktionierende Wettbewerbsbedingungen zu ermöglichen sowie Beschäftigung nicht zu gefährden. Sie orientiert sich dabei auch nachlaufend an der Tariflohnentwicklung. Bei diesen Kriterien handelt es sich ebenfalls um Vorgaben des MiLoG. Die Bundesregierung kann den Vorschlag der Mindestlohnkommission nur unverändert umsetzen und nicht ei­genständig eine andere Höhe festsetzen. Mit entsprechenden Regierungsverordnungen werden die vorgeschlagenen Mindestlohnhöhen für alle Arbeitgeber sowie Arbeitnehmerinnen und Arbeitnehmer rechtsverbindlich umgesetzt. Der Mindestlohn wurde zum 1. Oktober 2022 einmalig durch Änderung des Mindestlohngesetzes (siehe weitere Informationen: Mindestlohnerhöhungsgesetz) auf 12 Euro je Zeitstunde angehoben. Gleichzeitig wurde festgelegt, dass über künftige Anpassungen der Höhe des Mindestlohns weiterhin die Mindestlohnkommission entscheidet. Eine Übersicht über die Entwicklung der bisher festgesetzten Mindestlöhne haben wir Ihnen anbei zusammengestellt."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Einfuehrung-und-Anpassungen-Mindestlohn/einfuehrung-und-anpassung-mindestlohn.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:32.317731+00:00","lastSeen":"2026-03-15T16:31:32.317731+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Einfuehrung-und-Anpassungen-Mindestlohn/einfuehrung-und-anpassung-mindestlohn.html","crawledAt":"2026-03-15T16:31:32.317731Z","crawlId":"contacts-seeded-1773592292","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c95f86e9ae08d835223a84055de002b70a52351ad54ea343a06bda19bba7170f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:32.317731+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3b5d7887-d535-44b7-9bba-d9028e170844', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Mindestlohn-und-Praktikum/mindestlohn-praktikum.html', 'active', NULL, '2026-03-15T16:31:33.601496+00:00', '{"id":"3b5d7887-d535-44b7-9bba-d9028e170844","title":"Mindestlohn und Praktikum","summary":{"de":"Handelt es sich um ein Praktikum, das nach Mindestlohn bezahlt werden muss?"},"content":{"de":"Mindestlohn im Praktikum? Diese Frage lässt sich mit untenstehendem Klickpfad beantworten. Einfach Schritt für Schritt eine Auswahl treffen und erfahren was gilt. Hinweis: Dieses Angebot dient nur zur Orientierung. Die angezeigten Informationen erheben nicht den Anspruch der vollständigen Berücksichtigung aller Spezialfälle. Sollten Sie hier keine Antwort auf Ihre Frage erhalten, nutzen Sie unsere Mindestlohn-Hotline unter 030/60 28 00 28. Min­dest­lohn für Stu­die­ren­de – Fra­gen und Ant­wor­ten"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Mindestlohn-und-Praktikum/mindestlohn-praktikum.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:33.601496+00:00","lastSeen":"2026-03-15T16:31:33.601496+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Mindestlohn-und-Praktikum/mindestlohn-praktikum.html","crawledAt":"2026-03-15T16:31:33.601496Z","crawlId":"contacts-seeded-1773592293","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"241e5faf354de596519607612c278f96957a995be7dcebf7f30f9a6060924d5b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:33.601496+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ac2f40ce-6205-436f-a34d-4b38485c7bf7', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Mindestlohnkommission/mindestlohnkommission.html', 'active', NULL, '2026-03-15T16:31:34.151188+00:00', '{"id":"ac2f40ce-6205-436f-a34d-4b38485c7bf7","title":"Mindestlohnkommission","summary":{"de":"Zur Anpassung des gesetzlichen Mindestlohns hat die Bundesregierung eine ständige unabhängige Mindestlohnkommission eingerichtet."},"content":{"de":"Seit dem 1. Januar 2026 beträgt der gesetzliche Mindestlohn in Deutschland brutto 13,90 Euro je Zeitstunde. Der gesetzliche Mindestlohn wurde im Jahr 2015 eingeführt. Er gilt, mit wenigen Ausnahmen, für alle Arbeitnehmer*innen in Deutschland. Die Höhe des gesetzlichen Mindestlohns wird alle zwei Jahre von einer ständigen Kommission der Tarifpartner (Mindestlohnkommission) überprüft und kann durch Rechtsverordnung der Bundesregierung geändert werden. Die Mindestlohnkommission evaluiert laufend die Auswirkungen des Mindestlohns auf den Schutz der Arbeitnehmer*innen, die Wettbewerbs­bedingungen und die Beschäftigung in Bezug auf bestimmte Branchen und Regionen sowie die Produktivität und stellt ihre Erkenntnisse der Bundes­regierung in einem Bericht alle zwei Jahre gemeinsam mit ihrem Beschluss zur Verfügung. Website der unabhängigen Mindestlohn­kommission mit Informationen zur Anpassung des Mindestlohns. Sie prüft im Rahmen einer Gesamtabwägung, welche Höhe des Mindestlohns geeignet ist, zu einem angemessenen Mindestschutz der Arbeitnehmer*innen beizutragen, faire und funktionierende Wettbewerbsbedingungen zu ermöglichen sowie Beschäftigung nicht zu gefährden. Die Mindestlohn­kommission orientiert sich bei der Festsetzung des Mindestlohns nachlaufend an der Tarifentwicklung. Die Kommission hat zuletzt am 27. Juni 2025 ihren fünften Beschluss zur Anpassung des Mindestlohns für die Zeit ab 1. Januar 2026 gefasst. Die Mindestlohnkommission wird von der Bundesregierung errichtet und gemäß § 4 Abs. 2 MiLoG alle fünf Jahre neu berufen. Sie tagt nach Bedarf, jedoch mindestens drei Mal im Jahr und hält ihre Sitzungsergebnisse protokollarisch fest. Die Kommission besteht aus einer/einem Vorsitzenden, sechs stimm­berechtigten ständigen Mitgliedern aus dem Kreis der Sozialpartner und zwei beratenden Mitgliedern aus der Wissenschaft ohne Stimmrecht. Die Kommission ist beschlussfähig, wenn mindestens die Hälfte ihrer stimm­berechtigten Mitglieder anwesend ist. Die Beschlussfassung erfolgt in den Sitzungen der Kommission."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Mindestlohnkommission/mindestlohnkommission.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:34.151188+00:00","lastSeen":"2026-03-15T16:31:34.151188+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/Mindestlohnkommission/mindestlohnkommission.html","crawledAt":"2026-03-15T16:31:34.151188Z","crawlId":"contacts-seeded-1773592294","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"eaff4b0d4f95c68b4d0ab87482675acf990ff549e7213f27cdb3444f5f41aced"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:34.151188+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('64c633e5-b5ce-454e-86aa-6974558d03e2', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/mindestlohn.html', 'active', NULL, '2026-03-15T16:31:35.031906+00:00', '{"id":"64c633e5-b5ce-454e-86aa-6974558d03e2","title":"Allgemeiner gesetzlicher Mindestlohn","summary":{"de":"Der allgemeine gesetzliche Mindestlohn ist in Deutschland die Lohnuntergrenze, die nicht unterschritten werden darf. Seit 1. Januar 2026 gilt ein Mindestlohn von 13,90 Euro."},"content":{"de":"Hier finden Sie das Infoblatt zum Mindestlohn in 14 Sprachen. Here you can find the information sheet on the minimum wage translated into 14 languages. Mindestlohn für Studierende – Fragen und Antworten Gesamtbericht zur Evaluation des allgemeinen gesetzlichen Mindestlohns nach § 23 Mindestlohngesetz Der Mindestlohn – Merkblatt für Arbeitgeber [PDF, 78KB] Praxishinweise zur Anwendung des Mindestlohngesetzes [PDF, 237KB]"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/mindestlohn.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:35.031906+00:00","lastSeen":"2026-03-15T16:31:35.031906+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Mindestlohn/mindestlohn.html","crawledAt":"2026-03-15T16:31:35.031906Z","crawlId":"contacts-seeded-1773592295","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b3ae9157278d951bed4c74d49fac3eaa996da77e6fa60b5771f1979c13f1f43e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:35.031906+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('496f80dc-f219-46de-bf35-a6b6d7c954f2', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tariftreue/Oeffentliche-Konsultation-zur-Tariftreue/oeffentliche-konsultation-zur-tariftreue.html', 'active', NULL, '2026-03-15T16:31:36.007132+00:00', '{"id":"496f80dc-f219-46de-bf35-a6b6d7c954f2","title":"Öffentliche Konsultation zur Bindung der Auftragsvergabe des Bundes an die Einhaltung von Tarifverträgen (\"Bundes-Tariftreue\")","summary":{"de":"durch das Bundesministerium für Wirtschaft und Energie und das Bundesministerium für Arbeit und Soziales in der 20. Legislaturperiode."},"content":{"de":"Der zwischen SPD, BÜNDNIS 90/DIE GRÜNEN und FDP im Jahr 2021 vereinbarte Koalitionsvertrag \"Mehr Fortschritt wagen\" hatte das Ziel, die Tarifautonomie, die Tarifpartner und die Tarifbindung zu stärken, damit faire Löhne in Deutschland bezahlt werden – dies befördert auch die nötige Lohnangleichung zwischen Ost und West. Zur Stärkung der Tarifbindung, des fairen Wettbewerbs und der sozialen Nachhaltigkeit sollte die öffentliche Auftragsvergabe des Bundes an die Einhaltung eines repräsentativen Tarifvertrages der jeweiligen Branche gebunden werden, wobei die Vergabe auf einer einfachen, unbürokratischen Erklärung beruhen sollte. Betroffenen Organisationen, Unternehmen und Verbänden sowie interessierten Bürgerinnen und Bürgern wurde zu diesem Zweck im Rahmen eines digitalen öffentlichen Konsultationsverfahrens die Möglichkeit gegeben, ihre Einschätzungen und Ideen frühzeitig, transparent und bürokratiearm mittels eines bereitgestellten PDF-Formulars zu übermitteln. Die Stakeholder konnten so ihr Wissen, ihre Erfahrungen und ihre Erwartungen den verantwortlichen Ministerien mitteilen. Die Konsultationsphase fand im Zeitraum vom 7. bis 23. Dezember 2022 statt. Die eingegangenen Antworten sind in die Erarbeitung eines gemeinsamen Gesetzesentwurfes durch das Bundesministerium für Wirtschaft und Energie und Klimaschutz und das Bundesministerium für Arbeit und Soziales eingeflossen. Sämtliche Stellungnahmen sind sowohl auf der Internetseite des Bundesministeriums für Arbeit und Soziales als auch des Bundesministeriums für Wirtschaft und Energie publiziert, sofern der Veröffentlichung nicht vorab widersprochen wurde. K. Peter Mahlo & Sohn Baugesellschaft [PDF, 176KB]"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tariftreue/Oeffentliche-Konsultation-zur-Tariftreue/oeffentliche-konsultation-zur-tariftreue.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:36.007132+00:00","lastSeen":"2026-03-15T16:31:36.007132+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tariftreue/Oeffentliche-Konsultation-zur-Tariftreue/oeffentliche-konsultation-zur-tariftreue.html","crawledAt":"2026-03-15T16:31:36.007132Z","crawlId":"contacts-seeded-1773592296","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"d0ef56ffedf89630257cab4829ee6966d3e58aee93fa7dc30507cbc219ec8f98"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:36.007132+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('27f8827b-481f-46c0-86dd-00825c2d232b', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tariftreue/tariftreue.html', 'active', NULL, '2026-03-15T16:31:36.757724+00:00', '{"id":"27f8827b-481f-46c0-86dd-00825c2d232b","title":"Tariftreue","summary":{"de":"Alle Informationen zum Bundestariftreuegesetz."},"content":{"de":"Tarifverträge sorgen für einen fairen Interessenausgleich zwischen Arbeitnehmerinnen und Arbeitnehmern und bieten Planungssicherheit für Unternehmen. Mit dem Bundestariftreuegesetz stärkt die Bundesregierung die Unternehmen, die Tarifverträge anwenden und einen fairen Wettbewerb bei Vergaben des Bundes. Bisher hatten tarifgebundene Unternehmen im Wettbewerb um Vergaben des Bundes oft einen Wettbewerbsnachteil. Da sie ihren Beschäftigten tarifliche Arbeitsbedingungen, zum Beispiel eine bessere Entlohnung, Urlaubsansprüche oder Regelungen zu Ruhezeiten, gewähren, hatten sie im Vergleich zu Unternehmen, die ihre Lohn- und Personalkosten niedriger halten, oft höhere Kosten. Diesen Nachteil für tarifgebundene Arbeitgeber, die gute Löhne zahlen, beseitigen wir. Wer Aufträge des Bundes ab einem bestimmten Schwellenwert ausführen möchte, muss für tarifliche Arbeitsbedingungen sorgen. Hierfür schaffen wir mit dem Bundestariftreuegesetz die notwendige Grundlage. Unternehmen, die einen öffentlichen Auftrag des Bundes ausführen, sollen ihre bei der Ausführung des Auftrags eingesetzten Arbeitnehmerinnen und Arbeitnehmer nach dem einschlägigen Branchentarifvertrag entlohnen und den Urlaub gewähren müssen. Bei öffentlichen Aufträgen des Bundes sollen zudem die tarifvertraglich geregelten Höchstarbeitszeiten, Mindestarbeitszeiten und Ruhezeiten eingehalten werden müssen. Das Bundestariftreuegesetz schafft hierfür die gesetzliche Grundlage. Konkret werden die für die jeweilige Branche geltenden tarifvertraglichen Arbeitsbedingungen durch Verordnungen des Bundesministeriums für Arbeit und Soziales bestimmt. Grundsätzlich sind Unternehmen zur Gewährleistung tariflicher Arbeitsbedingungen nur verpflichtet, wenn sie tarifgebunden sind. Dies ist der Fall, wenn das Unternehmen Mitglied in einem tarifvertragschließenden Arbeitgeberverband ist oder einen Firmentarifvertrag abgeschlossen hat. Mit Tariftreuegesetzen können auch nicht tarifgebundene Unternehmen zur Einhaltung der tarifvertraglichen Arbeitsbedingungen verpflichtet werden, wenn sie einen öffentlichen Auftrag ausführen."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tariftreue/tariftreue.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:36.757724+00:00","lastSeen":"2026-03-15T16:31:36.757724+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tariftreue/tariftreue.html","crawledAt":"2026-03-15T16:31:36.757724Z","crawlId":"contacts-seeded-1773592296","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"1f5fe9ee9c9214a4df1240944c57ab268857c5297b05d77e057fe776ee5adc5f"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T16:31:36.757724+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1db98331-b869-45ba-9d8d-c8b1b93da8f9', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Allgemeinverbindliche-Tarifvertraege/allgemeinverbindliche-tarifvertraege.html', 'active', NULL, '2026-03-15T16:31:37.508869+00:00', '{"id":"1db98331-b869-45ba-9d8d-c8b1b93da8f9","title":"Allgemeinverbindliche Tarifverträge","summary":{"de":"Allgemeinverbindlicherklärung nach § 5 des Tarifvertragsgesetzes"},"content":{"de":"Rechtsverordnungen nach §§ 7, 7a des Arbeitnehmer-Entsendegesetzes Rechtsverordnung nach § 3a des Arbeitnehmerüberlassungsgesetzes Tarifgestützte zwingende Arbeitsbedingungen für grenzüberschreitend entsandte und in Deutschland beschäftigte Arbeitnehmerinnen und Arbeitnehmer Verzeichnis der für allgemeinverbindlich erklärten Tarifverträge Tarifnormen können durch eine Allgemeinverbindlicherklärung nach dem Tarifvertragsgesetz, durch eine Rechtsverordnung nach dem Arbeitnehmer-Entsendegesetz oder durch eine Rechtsverordnung nach dem Arbeitnehmerüberlassungsgesetz verbindlich angeordnet werden. Daraus folgt, dass auch die nicht an den Tarifvertrag gebundenen Arbeitgeber und ihre Beschäftigten im Geltungsbereich des Tarifvertrags daran gebunden sind. Die verschiedenen Arten der verbindlichen Anordnung von Tarifnormen, ihre Wirkung sowie Besonderheiten werden hier erläutert. Das Verzeichnis der für allgemeinverbindlich erklärten Tarifverträge enthält eine nach Branchen geordnete Übersicht der betroffenen Tarifverträge. Das Bundesministerium für Arbeit und Soziales kann nach § 5 des Tarifvertragsgesetzes einen Tarifvertrag im Einvernehmen mit einem aus je drei Vertretern der Spitzenorganisationen der Arbeitgeber und der Arbeitnehmer bestehenden Ausschuss (Tarifausschuss) auf gemeinsamen Antrag der Tarifvertragsparteien unter bestimmten Voraussetzungen für allgemeinverbindlich erklären."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Allgemeinverbindliche-Tarifvertraege/allgemeinverbindliche-tarifvertraege.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:37.508869+00:00","lastSeen":"2026-03-15T16:31:37.508869+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Allgemeinverbindliche-Tarifvertraege/allgemeinverbindliche-tarifvertraege.html","crawledAt":"2026-03-15T16:31:37.508869Z","crawlId":"contacts-seeded-1773592297","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"d8dc8b934e6baf39b93452e37f648dcb0f87ab82502ce44dcab3075b2c7c1c0a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:37.508869+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6b305ad0-5ac1-499b-910a-2ca7b4129b81', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Tarifregister/tarifregister.html', 'active', NULL, '2026-03-15T16:31:38.237828+00:00', '{"id":"6b305ad0-5ac1-499b-910a-2ca7b4129b81","title":"Tarifregister","summary":{"de":"Auskünfte Welche Angaben benötigt das Tarifregister, um Ihnen eine Auskunft erteilen zu können? Kontakt Online-Anfrage: Auskunft zu Tarifverträgen"},"content":{"de":"Welche Angaben benötigt das Tarifregister, um Ihnen eine Auskunft erteilen zu können? Beim Bundesministerium für Arbeit und Soziales wird auf Rechtsgrundlage des § 6 Tarifvertragsgesetz (TVG) ein Tarifregister geführt, in das der Abschluss, die Änderung und die Aufhebung solcher Tarifverträge sowie der Beginn und die Beendigung der Allgemeinverbindlichkeit eingetragen werden. Tarifverträge können dabei für die Bundesrepublik Deutschland, für mehrere Bundesländer, für ein Bundesland oder für einzelne Regionen in einem Bundesland abgeschlossen worden sein. Nach § 7 des Tarifvertragsgesetzes sind die Tarifvertragsparteien verpflichtet, alle Tarifabschlüsse und auch deren Außerkrafttreten dem Bundesministerium für Arbeit und Soziales sowie den obersten Arbeitsbehörden der Länder, auf deren Gebiet sich ihre Tarifverträge erstrecken, zu übersenden. Das Tarifregister des Bundesministeriums für Arbeit und Soziales ist für die Registrierung der im Geltungsbereich der Bundesrepublik Deutschland geschlossenen Tarifverträge zuständig. Zur Beobachtung der tarifpolitischen Entwicklung wird jeder einzelne Tarifvertrag so verwaltet, dass Übersichten über alle Tarifverträge sowie deren wesentlichen Regelungsinhalte gegeben sind. Die Datenbank des Bundestarifregisters umfasst seit Jahresbeginn 2026 mehr als 90.000 gültige Tarifverträge. Im Jahr 2025 wurden 5.580 Tarifverträge abgeschlossen und in das Tarifregister des Bundesministeriums für Arbeit und Soziales eingetragen. Dabei handelt es sich in 3.719 Fällen um Firmen- bzw. Unternehmenstarifverträge. Die Gesamtzahl der in das Tarifregister von 1949 bis 2025 eingetragenen Tarifverträge beträgt 472.717. Zum 31.12.2025 waren davon 89.965 gültig."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Tarifregister/tarifregister.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:38.237828+00:00","lastSeen":"2026-03-15T16:31:38.237828+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Tarifregister/tarifregister.html","crawledAt":"2026-03-15T16:31:38.237828Z","crawlId":"contacts-seeded-1773592298","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"e69955556702ee9d3aae3bad3423a1fb65c10c5210cb79e710a5f76b985b872e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:38.237828+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3437cb90-8d9e-432e-86e4-524ad0e42115', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Tarifvertragliche-Sozialkassen/tarifvertragliche-sozialkassen.html', 'active', NULL, '2026-03-15T16:31:38.898128+00:00', '{"id":"3437cb90-8d9e-432e-86e4-524ad0e42115","title":"Tarifvertragliche Sozialkassen","summary":{"de":"Alle Arbeitgeber bzw. Betriebe in bestimmten Wirtschaftszweigen sind verpflichtet, an Sozialkassen-Verfahren teilzunehmen."},"content":{"de":"Sozialkassen sind gemeinsame Einrichtungen von Tarifvertragsparteien, die auf allgemeinverbindlichen Tarifverträgen beruhen. Die Arbeitgeber und Arbeitnehmer dieser Wirtschaftszweige erhalten die nach den Sozialkassentarifverträgen vorgesehenen Leistungen; die Arbeitgeber haben außerdem die festgesetzten Beiträge abzuführen. Sozialkassenverfahren gibt es in folgenden Branchen: Steine- und Erden-Industrie, Betonsteinhandwerk und Ziegelindustrie in Bayern In dem Merkblatt sind die Kontaktdaten der Sozialkassen bzw. Beitragseinzugsstellen aufgeführt. Unternehmen, die in einem der angegebenen Wirtschaftszweige tätig werden, wird dringend empfohlen, sich wegen der Beitragspflichten mit der zuständigen Stelle in Verbindung zu setzen. Andernfalls besteht die Gefahr, dass es zu Beitragsnachforderungen kommt. Mit dem Sozialkassenverfahrensicherungsgesetz (SokaSiG) vom 16. Mai 2017 ( BGBl. I S. 1210) wurden die allgemeinverbindlich erklärten Tarifverträge, die dem Sozialkassenverfahren im Baugewerbe zugrunde liegen, beginnend mit dem 1. Januar 2006 kraft Gesetzes mittels statischer Verweisung für alle Arbeitgeber verbindlich angeordnet. Das Gesetz ist eine eigenständige Rechtsgrundlage für die Sozialkassenverfahren im Baugewerbe. Mit dem Zweiten Sozialkassenverfahrensicherungsgesetz (SokaSiG2) vom 1. September 2017 ( BGBl. I S. 3356) wurde entsprechend für weitere Sozialkassentarifverträge in anderen Branchen eine eigenständige Rechtsgrundlage geschaffen."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Tarifvertragliche-Sozialkassen/tarifvertragliche-sozialkassen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:38.898128+00:00","lastSeen":"2026-03-15T16:31:38.898128+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/Tarifvertraege/Tarifvertragliche-Sozialkassen/tarifvertragliche-sozialkassen.html","crawledAt":"2026-03-15T16:31:38.899138Z","crawlId":"contacts-seeded-1773592298","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c0ff1d1cea39479f5c1cf4f1552331cbf46b6a2ff5d6e28deb0fb0aa6e782cd5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:38.899138+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('594f2849-e0fe-4f98-b38d-5df6522852bc', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsrecht/arbeitsrecht.html', 'active', NULL, '2026-03-15T16:31:40.843953+00:00', '{"id":"594f2849-e0fe-4f98-b38d-5df6522852bc","title":"Arbeitsrecht","summary":{"de":"Mindestlohn, Tarifverträge oder Teilzeitmodelle: Mit einer Vielzahl von Maßnahmen schützt das Arbeitsrecht Bürgerinnen und Bürger. Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Mindestlohn, Tarifverträge oder Teilzeitmodelle: Mit einer Vielzahl von Maßnahmen schützt das Arbeitsrecht Bürgerinnen und Bürger. Am 13. März startet auf Einladung des BMAS der Branchendialog Lebensmitteleinzelhandel und Ernährungsindustrie. Ziel ist es, Unternehmen bei der Umsetzung ihrer Sorgfaltspflichten zu unterstützen. Die vorschlags­berechtigten Verbände und Gremien sind nunmehr aufgefordert, geeignete Mitglieder vorzuschlagen. Zum 1. Januar 2026 haben die Beratungsstellen ihre Arbeit auf neuer gesetzlicher Grundlage aufgenommen. Ziel ist es, durch eine arbeits- und sozialrechtliche Beratung Drittstaatsangehörige vor Ausbeutung und zugleich Einheimische vor Lohndumping zu schützen. Geringfügige Beschäftigung und Beschäftigung im Übergangsbereich"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/arbeitsrecht.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:40.843953+00:00","lastSeen":"2026-03-15T16:31:40.843953+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsrecht/arbeitsrecht.html","crawledAt":"2026-03-15T16:31:40.843953Z","crawlId":"contacts-seeded-1773592300","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"98bbe60318fef3d9a95c9b4e5dfa57eb1d5cecccbfdc568fdbfc9b6b1786e656"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:40.843953+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('77d5a24d-51d8-489d-a97f-7e455a5559ba', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Arbeitsschutzausschuesse/arbeitsschutzausschuesse.html', 'active', NULL, '2026-03-15T16:31:41.521564+00:00', '{"id":"77d5a24d-51d8-489d-a97f-7e455a5559ba","title":"Arbeitsschutzausschüsse","summary":{"de":"Das BMAS wird in allen Fragen der Sicherheit und Gesundheit der Beschäftigten durch staatliche Ausschüsse beraten."},"content":{"de":"Ausschuss für Sicherheit und Gesundheit bei der Arbeit (ASGA) Das Bundesministerium für Arbeit und Soziales wird in allen Fragen der Sicherheit und Gesundheit der Beschäftigten durch staatliche Ausschüsse beraten. Wesentliche Aufgabe der Arbeitsschutzausschüsse ist die Ermittlung von staatlichen Regeln. Funktion des staatlichen Regelwerks ist es, durch Konkretisierung der Anforderungen mögliche Lösungen zur Umsetzung der rechtlich verbindlichen Vorgaben des Arbeitsschutzrechts zu beschreiben. Die gesetzliche Ermächtigung zur Einrichtung staatlicher Ausschüsse ist in § 18 Abs. 2 Nr. 5 des Arbeitsschutzgesetzes festgelegt, welche in den jeweiligen Arbeitsschutzverordnungen ausgefüllt wird. Ergänzt wird diese Ermächtigung durch den § 24a des Arbeitsschutzgesetzes. Den staatlichen Ausschüssen gehören Vertreterinnen und Vertreter der Arbeitgeber, Gewerkschaften, Länderbehörden, der gesetzlichen Unfallversicherung und der Wissenschaft sowie Sachverständige an. Folgende Arbeitsschutzausschüsse beraten das BMAS: Der ASGA ist gemäß § 24a des Arbeitsschutzgesetzes eingerichtet und hat jeweils 15 ehrenamtliche Mitglieder und stellvertretende Mitglieder. Gruppenbild des Ausschusses für Sicherheit und Gesundheit bei der Arbeit (ASGA)"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Arbeitsschutzausschuesse/arbeitsschutzausschuesse.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:41.521564+00:00","lastSeen":"2026-03-15T16:31:41.521564+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Arbeitsschutzausschuesse/arbeitsschutzausschuesse.html","crawledAt":"2026-03-15T16:31:41.522565Z","crawlId":"contacts-seeded-1773592301","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"5d8503d03aced738aadb14dde461c81f05d0ba7fb16841f45d4a98d1bb63c4e8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:41.522565+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b2baf89c-e877-4410-ad6a-c342b4e63289', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Arbeitsmedizinische-Vorsorge/arbeitsmedizinische-vorsorge.html', 'active', NULL, '2026-03-15T16:31:42.102915+00:00', '{"id":"b2baf89c-e877-4410-ad6a-c342b4e63289","title":"Arbeitsmedizinische Vorsorge","summary":{"de":"Die Veränderungen in der Arbeitswelt bringen für die Beschäftigten neue Belastungen und Beanspruchungen mit sich. Gleichzeitig erfordert die demografische Entwicklung Anstrengungen zum Erhalt der Beschäftigungsfähigkeit."},"content":{"de":"Die Verhütung arbeitsbedingter Erkrankungen und der Erhalt der Beschäftigungsfähigkeit der Menschen sowie die Fortentwicklung des betrieblichen Gesundheitsschutzes sind für Politik, Betriebe und Beschäftigte von wachsender Bedeutung. Arbeitsmedizinische Vorsorge kann technische und organisatorische Schutzmaßnahmen nicht ersetzen, durch persönliche Aufklärung und Beratung der Beschäftigten über arbeitsbedingte Gesundheitsgefahren aber gut ergänzen. Ziel arbeitsmedizinischer Vorsorge ist die Früherkennung und Verhütung arbeitsbedingter Erkrankungen. Zugleich soll arbeitsmedizinische Vorsorge einen Beitrag zum Erhalt der Beschäftigungsfähigkeit und zur Fortentwicklung des betrieblichen Arbeitsschutzes leisten. Beschäftigte haben das Recht, sich auf ihren Wunsch hin arbeitsmedizinisch beraten und untersuchen zu lassen. Bei bestimmten Gefährdungen am Arbeitsplatz muss der Arbeitgeber den Beschäftigten arbeitsmedizinische Vorsorge anbieten. Sind die Gefährdungen besonders groß, ist eine Pflichtvorsorge vorgeschrieben. arbeitsmedizinische Vorsorgetermine bei der Betriebsärztin oder dem Betriebsarzt einschließlich der Aufklärung und Beratung des Beschäftigten über die mit bestimmten Tätigkeiten verbundenen Gesundheitsgefährdungen sowie körperliche und klinische Untersuchungen, sofern diese erforderlich sind und der oder die Beschäftigte diese Untersuchungen nicht ablehnt, die Erfassung und Bewertung der Ergebnisse und Befunde aus der Vorsorge, arbeitsmedizinisch begründete Vorschläge an den Arbeitgeber für Maßnahmen des Arbeitsschutzes im Betrieb. Rechtliche Grundlage ist die Verordnung zur arbeitsmedizinischen Vorsorge (ArbMedVV)."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Arbeitsmedizinische-Vorsorge/arbeitsmedizinische-vorsorge.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:42.102915+00:00","lastSeen":"2026-03-15T16:31:42.102915+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Arbeitsmedizinische-Vorsorge/arbeitsmedizinische-vorsorge.html","crawledAt":"2026-03-15T16:31:42.102915Z","crawlId":"contacts-seeded-1773592302","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c8b8819d60bcc8764074d348ecbc9221592ba042d624d8c46ff8fb34a470bd89"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:42.102915+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1876b388-5c0b-4b29-bdc3-2717a226abc6', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Betriebliche-Eingliederungsmanagement/betriebliches-eingliederungsmanagement.html', 'active', NULL, '2026-03-15T16:31:42.697086+00:00', '{"id":"1876b388-5c0b-4b29-bdc3-2717a226abc6","title":"Betriebliches Eingliederungsmanagement","summary":{"de":"Von der Arbeitsunfähigkeit zur Beschäftigungsfähigkeit"},"content":{"de":"Seit 2004 sind Arbeitgeber verpflichtet, länger erkrankten Beschäftigten ein Betriebliches Eingliederungsmanagement (kurz: BEM) anzubieten. Das BEM dient dem Erhalt der Beschäftigungsfähigkeit und ist ein Instrument, um den Folgen des demographischen Wandels wirksam zu begegnen. Gleichzeitig sichert das BEM durch frühzeitige Intervention die individuellen Chancen den Arbeitsplatz zu behalten. Gesetzlich verankert ist das BEM in § 167 Absatz 2 Neuntes Buch Sozialgesetzbuch (SGB IX). Dort ist festgelegt, dass ein Arbeitgeber alle Beschäftigten, die innerhalb eines Jahres länger als sechs Wochen ununterbrochen oder wiederholt arbeitsunfähig sind, ein BEM anzubieten hat. Das bedeutet, dass der Arbeitgeber klären muss, \"wie die Arbeitsunfähigkeit möglichst überwunden werden und mit welchen Leistungen oder Hilfen erneuter Arbeitsunfähigkeit vorgebeugt und der Arbeitsplatz erhalten werden kann.\" Wie diese Klärung im Detail auszusehen hat, gibt § 167 Absatz 2 SGB IX bewusst nicht vor. Vielmehr ist ein BEM „ein verlaufs- und ergebnisoffener Suchprozess“. In jedem Betrieb und in jeder Dienststelle sind angemessene individuelle Lösungen zu finden. Gesetzlich vorgegeben ist – bei Zustimmung des Betroffenen – lediglich die Beteiligung der zuständigen Interessenvertretung der Beschäftigten (Betriebs- oder Personalrat), bei schwerbehinderten Beschäftigten außerdem die Beteiligung der Schwerbehindertenvertretung. Beschäftigte, die an einem BEM-Verfahren teilnehmen, erhalten die Möglichkeit zusätzlich eine Vertrauensperson eigener Wahl zum BEM-Verfahren hinzuziehen. Weiter sollen der Werks- oder Betriebsarzt hinzugezogen werden, wenn dies erforderlich ist. Soweit für die Überwindung der Arbeitsunfähigkeit und der Vorbeugung erneuter Erkrankung Leistungen zur Teilhabe oder begleitende Hilfen im Arbeitsleben in Betracht kommen, werden vom Arbeitgeber die Rehabilitationsträger oder bei schwerbehinderten Beschäftigten das Integrationsamt hinzugezogen. Ein erfolgreiches BEM entlastet die Sozialkassen (etwa durch die Vermeidung von Krankengeldzahlungen oder Erwerbsminderungsrenten) und kann einen Beitrag dazu leisten, die Beschäftigungsfähigkeit insbesondere älterer Menschen dauerhaft zu sichern. Für den Arbeitgeber rechnet es sich, weil es die Gesundheit und Leistungsfähigkeit der Beschäftigten fördert, Fehlzeiten verringert und damit Personalkosten senkt. In Zeiten des Fachkräftemangels ist das BEM aber auch ein wichtiges Instrument, um das krankheitsbedingte Ausscheiden von Beschäftigten zu verhindern. Für die betroffenen Beschäftigten selbst ist BEM ein Angebot, das vor Arbeitslosigkeit oder Frühverrentung schützen kann. Beim BEM wird oftmals im Laufe des Verfahrens eine angemessene Beschäftigungsmöglichkeit entdeckt und Hilfen ausfindig gemacht, mit denen die Arbeitsunfähigkeit überwunden und damit die (Weiter-) Beschäftigung gesichert werden kann. Zum BEM gezwungen werden die Beschäftigten nicht. Die Teilnahme ist immer freiwillig. Inzwischen ist das BEM Gegenstand zahlreicher (vor allem arbeits-) gerichtlicher Entscheidungen geworden. Das Bundesarbeitsgericht hat die kündigungsschutzrechtliche Bedeutung des BEM herausgearbeitet (Vergl. Bundesarbeitsgericht Urteil vom 10.12.2009 – 2 AZR 400/08). Demnach ist die Durchführung eines BEM zwar keine formelle Wirksamkeitsvoraussetzung für den Ausspruch einer krankheitsbedingten Kündigung. Die Verpflichtung des Arbeitgebers, ein BEM durchzuführen, stellt aber eine Konkretisierung des dem gesamten Recht des Kündigungsschutzes innewohnenden Verhältnismäßigkeitsgrundsatzes dar. Denn das BEM hat das Ziel, Maßnahmen zu identifizieren, die ein milderes Mittel gegenüber einer Kündigung darstellen (etwa die technisch-organisatorische Umgestaltung des Arbeitsplatzes, eine stufenweise Wiedereingliederung). Verzichtet ein Arbeitgeber – entgegen seiner Verpflichtung nach § 167 Absatz 2 SGB IX – vor Ausspruch einer krankheitsbedingten Kündigung darauf, diese milderen Alternativen zu einer Kündigung zu identifizieren, liegt bei ihm die Beweislast, dass auch bei Durchführung eines BEM das Arbeitsverhältnis nicht hätte erhalten werden können. Das bedeutet, dass ein Arbeitgeber, der vor der krankheitsbedingten Kündigung eines Arbeitnehmers kein BEM durchführt, einem erheblichen Risiko ausgesetzt ist, einen nachfolgenden Kündigungsschutzprozess zu verlieren."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Betriebliche-Eingliederungsmanagement/betriebliches-eingliederungsmanagement.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:42.697086+00:00","lastSeen":"2026-03-15T16:31:42.697086+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Betriebliche-Eingliederungsmanagement/betriebliches-eingliederungsmanagement.html","crawledAt":"2026-03-15T16:31:42.697086Z","crawlId":"contacts-seeded-1773592302","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"32a380d4c75a38ff844b5939aea1cfa52a9414a31d6b7b7a214b2f1e96beca6e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:42.697086+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('310d29b8-6fb2-41d3-8160-8257e07d3963', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Lastenhandhabung/lastenhandhabung.html', 'active', NULL, '2026-03-15T16:31:43.303241+00:00', '{"id":"310d29b8-6fb2-41d3-8160-8257e07d3963","title":"Lastenhandhabung","summary":{"de":"Sind die Lasten zu schwer, werden sie zu häufig oder in ungünstigen Körperhaltungen gehoben und getragen, kann dies zu Verschleißerscheinungen und anderen Gesundheitsschäden führen."},"content":{"de":"Bei vielen beruflichen Tätigkeiten müssen Gegenstände, Arbeitsmittel und Werkzeuge unter Einsatz von menschlicher Muskelkraft bewegt werden. Sind solche Lasten zu schwer oder werden sie zu häufig oder in ungünstigen Körperhaltungen gehoben und getragen, kann dies zu Verschleißerscheinungen und anderen Gesundheitsschäden führen. Gesundheitsstörungen und -schäden durch Lastenhandhabung mit Heben, Halten, Tragen, Ziehen oder Schieben von Lasten treten vorwiegend im Bereich des unteren Rückens auf. Sie äußern sich bei akuten Überlastungen mit Rückenbeschwerden wie dem \"Hexenschuss\" oder einem Ischiassyndrom. Wenn solche Belastungen über einen längeren Zeitraum vorkommen, können sich chronische Beschwerden und Erkrankungen durch degenerative bandscheibenbedingte Veränderungen, aber auch durch arthrotische Veränderungen der Knie- und Hüftgelenke entwickeln. Es gibt auch Berufskrankheiten, die mit den Belastungen des Muskel-Skelett-Systems in Zusammenhang stehen. Auf der Grundlage des Arbeitsschutzgesetzes gilt für den Bereich der manuellen Lastenhandhabung die Verordnung über Sicherheit und Gesundheitsschutz bei der manuellen Handhabung von Lasten ( Lastenhandhabungsverordnung ), mit der die Europäische Richtlinie 90/269/ EWG vom 4. Dezember 1996 umgesetzt wird. Die Verordnung schreibt vor, dass der Arbeitgeber dafür sorgen muss, dass manuelle Lastenhandhabungen, die die Gesundheit der Beschäftigten gefährden, vermieden werden. Weil das nicht immer möglich ist gilt ein \"Minimierungsgebot\", das heißt, die Belastung soll so gering wie möglich sein und eine Gesundheitsgefährdung soll möglichst vermieden werden. Zur Beurteilung der Höhe der Gefährdung und zur Ableitung geeigneter Schutzmaßnahmen enthält der Anhang der LasthandhabV verschiedene Maßnahmen. Danach müssen zahlreiche Kriterien berücksichtigt werden, die die Last als solche, die Arbeitsaufgabe und die Beschaffenheit des Arbeitsplatzes betreffen. Für die betriebliche Praxis wurde ein vereinfachtes Verfahren zur Beurteilung der Arbeitsbedingungen, die sogenannte Leitmerkmalmethode, entwickelt. Die Leitmerkmalmethoden decken insgesamt sechs Belastungsarten ab. Für die Prüfung, welche körperlichen Belastungen am zu bewertenden Arbeitsplatz vorliegen gibt es einen Basis-Check kombiniert mit einem Einstiegsscreening. Konkrete Lastgewichte allein sind für eine vollständige Gefährdungsbeurteilung nicht geeignet und werden deshalb in der Verordnung nicht genannt. Einerseits können bei großen Häufigkeiten, ungünstigen Körperhaltungen und eingeschränkten Ausführungsbedingungen bereits geringere Lastgewichte bzw. Aktionskräfte als schwere Last zu werten, andererseits können bei seltenen Lastenhandhabungen in guter Körperhaltung und unter guten ergonomischen Bedingungen auch höhere Gewichte bzw. Aktionskräfte akzeptabel sein."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Lastenhandhabung/lastenhandhabung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:43.303241+00:00","lastSeen":"2026-03-15T16:31:43.303241+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Lastenhandhabung/lastenhandhabung.html","crawledAt":"2026-03-15T16:31:43.303241Z","crawlId":"contacts-seeded-1773592303","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7ea77e3bd8e8ce163ea4d5f4a9487d1c1cee70b5d6d5906c89770dc0285166dd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:43.303241+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7233d585-48f2-430b-9ceb-b58a53b3f059', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Nationaler-Asbestdialog/nationaler-asbestdialog.html', 'active', NULL, '2026-03-15T16:31:44.065432+00:00', '{"id":"7233d585-48f2-430b-9ceb-b58a53b3f059","title":"BMAS - Nationaler Asbestdialog","summary":{"de":"Die Bundesressorts BMAS, BMI und BMU stellen den im nationalen Asbestdialog erreichten Sachstand vor und laden die Dialogpartnerinnen und -partner zu einer abschließenden Befragung ein."},"content":{"de":"Im vierten Dialogforum wurden die Positionen der Dialogbeteiligten zu den anstehenden Änderungen des Rechtsrahmens diskutiert. Die Leitlinie wurde von der Bundesanstalt für Arbeitsschutz und Arbeitsmedizin (BAuA), dem Umweltbundesamt (UBA) und dem Bundesinstitut für Bau-, Stadt- und Raumforschung (BBSR) erarbeitet und steht nun als PDF zur Verfügung. Die Ergebnisse des Asbestdialogs wurden bereits durch Vorträge auf verschiedenen Fachveranstaltungen vorgestellt. Nun liegen sie auch in schriftlicher Form vor. Wie umgehen mit Asbest beim Bauen im Bestand? Um diese Frage zu beantworten, haben das BMAS und das BMUB einen neuen Weg der fachpolitischen Auseinandersetzung beschritten und im Dezember 2016 den Nationalen Asbestdialog ins Leben gerufen. Hintergründe und Ergebnisse des ersten Dialogforums. Im zweiten Dialogforum des Nationalen Asbestdialogs wurden Lösungsvorschläge vorgestellt und diskutiert."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Nationaler-Asbestdialog/nationaler-asbestdialog.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:44.065432+00:00","lastSeen":"2026-03-15T16:31:44.065432+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Nationaler-Asbestdialog/nationaler-asbestdialog.html","crawledAt":"2026-03-15T16:31:44.065432Z","crawlId":"contacts-seeded-1773592304","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6a53a8b8ac087e75f4ca44e5ffb5fb3f63245d5b065881c45560b5cfefbb7806"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:44.065432+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('84604063-df0c-4dbd-a5d0-a01b51a5abbb', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Nichtraucherschutz-fuer-Beschaeftigte/nichtraucherschutz-fuer-beschaeftigte.html', 'active', NULL, '2026-03-15T16:31:44.742873+00:00', '{"id":"84604063-df0c-4dbd-a5d0-a01b51a5abbb","title":"Nichtraucherschutz für Beschäftigte","summary":{"de":"Die Regelungen zum Nichtraucherschutz fallen in Deutschland in unterschiedliche Rechtsbereiche."},"content":{"de":"Für Einrichtungen des Bundes und im öffentlichen Verkehr gilt ein komplettes Rauchverbot. Dieses ist mit dem Gesetz zum Schutz der Nichtraucher vor den Gefahren des Passivrauchens vom Bundesnichtraucherschutzgesetz geregelt. Den Schutz der Nichtrauchenden vor Gefährdungen durch Passivrauchen regelt die Arbeitsstättenverordnung (ArbStättV) in § 5 \"Nichtraucherschutz\". Die Regelung des § 5 (1) der ArbStättV geht ursprünglich auf eine Initiative des Deutschen Bundestages aus dem Jahr 2001 zurück. Nach § 5 der ArbStättV hat der Arbeitgeber die Pflicht, Schutzmassnahmen für nichtrauchende Beschäftigte in Arbeitsstätten wie folgt zu treffen: (1) Der Arbeitgeber hat die erforderlichen Maßnahmen zu treffen, damit die nicht rauchenden Beschäftigten in Arbeitsstätten wirksam vor den Gesundheitsgefahren durch Rauche und Dämpfe von Tabak- und Cannabisprodukten sowie elektronischen Zigaretten geschützt sind. Soweit erforderlich, hat der Arbeitgeber ein allgemeines oder auf einzelne Bereiche der Arbeitsstätte beschränktes Rauchverbot zu erlassen. (2) In Arbeitsstätten mit Publikumsverkehr hat der Arbeitgeber beim Einrichten und Betreiben von Arbeitsräumen der Natur des Betriebes entsprechende und der Art der Beschäftigung angepasste technische oder organisatorische Maßnahmen nach Absatz 1 zum Schutz der nicht rauchenden Beschäftigten zu treffen. Die ArbStättV gilt grundsätzlich und ausschließlich für das Verhältnis zwischen Arbeitgeber und Beschäftigten hinsichtlich Sicherheit und Gesundheitsschutz bei der Arbeit. Die ArbStättV umfasst jedoch nicht den Schutz dritter Personen, z.B. von Kunden oder Gästen."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Nichtraucherschutz-fuer-Beschaeftigte/nichtraucherschutz-fuer-beschaeftigte.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:44.742873+00:00","lastSeen":"2026-03-15T16:31:44.742873+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Nichtraucherschutz-fuer-Beschaeftigte/nichtraucherschutz-fuer-beschaeftigte.html","crawledAt":"2026-03-15T16:31:44.742873Z","crawlId":"contacts-seeded-1773592304","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"39480d3772bc27f699a14f0077cdfc7365834fd9ec1e4b1b24922bff0eeab9ca"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:44.742873+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0832654a-3021-4269-967e-ffbc9d0bfa48', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Praeventive-Arbeitsmedizin/praeventive-arbeitsmedizin.html', 'active', NULL, '2026-03-15T16:31:45.357712+00:00', '{"id":"0832654a-3021-4269-967e-ffbc9d0bfa48","title":"Präventive Arbeitsmedizin","summary":{"de":"Das Gebiet Arbeitsmedizin umfasst als präventivmedizinisches Fach die Wechselbeziehungen zwischen Arbeits- und Lebenswelten einerseits sowie Gesundheit und Krankheiten andererseits."},"content":{"de":"Tätigkeitsfelder für Ärztinnen und Ärzte für Arbeitsmedizin Das Gebiet Arbeitsmedizin umfasst als präventivmedizinisches Fach die Wechselbeziehungen zwischen Arbeits- und Lebenswelten einerseits sowie Gesundheit und Krankheiten andererseits. Im Mittelpunkt stehen dabei der Erhalt und die Förderung der physischen und psychischen Gesundheit und Leistungsfähigkeit des arbeitenden Menschen, die Gefährdungsbeurteilung der Arbeitsbedingungen, die Vorbeugung, Erkennung, Behandlung und Begutachtung arbeits- und umweltbedingter Risikofaktoren, Erkrankungen und Berufskrankheiten, die Verhütung arbeitsbedingter Gesundheitsgefährdungen einschließlich individueller und betrieblicher Gesundheitsberatung, die Vermeidung von Erschwernissen und Unfallgefahren sowie die berufsfördernde Rehabilitation (Bundesärztekammer 2019). Die Arbeitsmedizin stellt wissenschaftliche Grundlagen für die menschengerechte Gestaltung von Arbeit bereit. erkennen arbeitsbedingte Erkrankungen frühzeitig und können helfen, sie zu verhindern: Sie decken Ursachen von arbeitsbedingten Gesundheitsgefährdungen, arbeitsbedingten Erkrankungen, Berufskrankheiten und Arbeitsunfällen auf und leiten mit multidisziplinären Methoden präventive Maßnahmen ab; leisten einen Beitrag zum Erhalt der Beschäftigungsfähigkeit, indem sie bei der Förderung, dem Erhalt und der Wiederherstellung der individuellen Arbeits- und Beschäftigungsfähigkeit mitwirken; entwickeln den betrieblichen Gesundheitsschutz weiter."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Praeventive-Arbeitsmedizin/praeventive-arbeitsmedizin.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:45.357712+00:00","lastSeen":"2026-03-15T16:31:45.357712+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Praeventive-Arbeitsmedizin/praeventive-arbeitsmedizin.html","crawledAt":"2026-03-15T16:31:45.358721Z","crawlId":"contacts-seeded-1773592305","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"96499eb0222c307c1b632487effb1d38b88e4db733e46aa1afac83a86ecac27b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:45.358721+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a3eb2af1-0c1e-45d7-a023-7ab512d04306', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Psychische-Gesundheit/psychische-gesundheit.html', 'active', NULL, '2026-03-15T16:31:45.966166+00:00', '{"id":"a3eb2af1-0c1e-45d7-a023-7ab512d04306","title":"Psychische Gesundheit","summary":{"de":"Psychische Gesundheit ist eine unverzichtbare Grundlage für das Wohlbefinden und die Motivation von Mitarbeitenden – und damit auch für den Unternehmenserfolg. Gut gestaltete Arbeitsbedingungen können einen entscheidenden Unterschied machen."},"content":{"de":"Mit dem Wandel der Arbeitswelt, der fortschreitenden Digitalisierung und schwindenden Grenzen von Arbeitszeit nehmen Stress und Belastung zu. Eine gute Arbeitsgestaltung fördert die Gesundheit, während eine schlecht gestaltete Arbeit sie negativ beeinflussen kann. So macht Stress nicht automatisch psychisch krank, doch der Grat zwischen Belastung und Überlastung ist schmal. Maßnahmen zum Schutz, der Förderung und Wiederherstellung der psychischen Gesundheit sind gut erforscht und verfügbar. Psychische Störungen bilden anhaltend eine der häufigsten Ursachen für Arbeitsunfähigkeiten. Für die Betroffenen kann das im schlimmsten Fall den Abschied vom Berufsleben bedeuten. Die Ursachen für psychische Belastungen und Erkrankungen sind komplex und vielfältig. Sie lassen sich nicht auf das Arbeitsumfeld reduzieren. Welche Rolle die Arbeitsgestaltung für die psychische Gesundheit der Beschäftigten spielt, hat die Bundesanstalt für Arbeitsschutz und Arbeitsmedizin (BAuA) im Rahmen einer wissenschaftlichen Standortbestimmung 2017 aufbereitet. In der Verantwortung der Arbeitgeber liegt es, die Arbeitsbedingungen so zu gestalten, dass sie die Gesundheit der Beschäftigten nicht gefährdet ( § 4 ArbSchG ). Entscheidend hierfür ist eine Gefährdungsbeurteilung im Betrieb zu machen und dabei auch das Thema psychische Belastung im Blick zu haben. Gute Arbeitsgestaltung bei psychischer Belastung ist bereits seit 2013 ein Schwerpunktthema in der Gemeinsamen deutschen Arbeitsschutzstrategie (GDA). Die Empfehlungen zur „Berücksichtigung psychischer Belastung in der Gefährdungsbeurteilung“ sind eine anerkannte Referenz für die betriebliche Arbeitsschutzpraxis. Aktuell wird eine staatliche Regel zu psychischer Belastung erstellt. Die menschengerechte Gestaltung der Arbeitsbedingungen bildet die Grundlage zum Schutz der psychischen Gesundheit und kann sinnvoll durch Unterstützungsangebote auf betrieblicher und individueller Ebene flankiert werden. Krankenkassen sind nach dem Präventionsgesetz ( § 20b SGB V ) dazu verpflichtet Betriebe bei der betrieblichen Gesundheitsförderung zu unterstützen."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Psychische-Gesundheit/psychische-gesundheit.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:45.966166+00:00","lastSeen":"2026-03-15T16:31:45.966166+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/Psychische-Gesundheit/psychische-gesundheit.html","crawledAt":"2026-03-15T16:31:45.966166Z","crawlId":"contacts-seeded-1773592305","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"29142f215041b59495867a4cfad299e4974ad5601caa75475a3794d4f10d39d0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:45.966166+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ff20c919-2002-4d4c-b763-136cfaff09b7', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/gesundheit-am-arbeitsplatz.html', 'active', NULL, '2026-03-15T17:45:59.921570+00:00', '{"id":"ff20c919-2002-4d4c-b763-136cfaff09b7","title":"Gesundheit am Arbeitsplatz","summary":{"de":"Im klassischen Arbeitsschutz sind die Grundpflichten des Arbeitgebers in Rechtsvorschriften geregelt. In einem modernen, wettbewerbsfähigen Betrieb gehört es zu einer guten Unternehmenskultur, die oft allgemein oder abstrakt gehaltenen Grundregeln mit Leben zu erfüllen."},"content":{"de":"Empfehlungen des BMAS zum betrieblichen Infektionsschutz vor COVID-19, Grippe und Erkältungskrankheiten"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/gesundheit-am-arbeitsplatz.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:45:59.921570+00:00","lastSeen":"2026-03-15T17:45:59.921570+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Gesundheit-am-Arbeitsplatz/gesundheit-am-arbeitsplatz.html","crawledAt":"2026-03-15T17:45:59.921570Z","crawlId":"contacts-seeded-1773596759","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"4491fee0337741393a1378c1dfb8ad67976e1acf222eceda175d1ba104913cda"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:45:59.921570+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8a0eba9d-e069-4986-ab8b-66256f640248', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Produktsicherheit/produktsicherheit.html', 'active', NULL, '2026-03-15T16:31:47.221136+00:00', '{"id":"8a0eba9d-e069-4986-ab8b-66256f640248","title":"Produktsicherheit","summary":{"de":"Die Produktsicherheit umfasst zahlreiche Rechtsvorschriften, die die Bereitstellung von Produkten auf dem Markt zum Gegen­stand haben."},"content":{"de":"Zentrales Regelungsziel ist dabei ein hohes Maß an Sicherheit und Gesundheitsschutz für Verbraucher und Beschäftigte. Diese Rechtsvorschriften regeln den freien Waren­verkehr im europäischen Binnenmarkt. Die zentrale Rechtsvorschrift für die Sicherheit von Geräten, Produkten und Anlagen ist in Deutschland das Gesetz über die Bereitstellung von Produkten auf dem Markt (Produktsicherheitsgesetz - ProdSG). Es umfasst eine breite Palette verschiedenster Produkte. Mit dem ProdSG sowie den auf Grundlage § 8 ProdSG erlassenen Produktsicherheitsverordnungen (ProdSV) werden insgesamt 11 europäische Binnenmarktrichtlinien sowie die Richtlinie über die allgemeine Produktsicherheit 2001/95/EG in deutsches Recht umgesetzt. Die für das BMAS zuständigen Binnenmarktrichtlinien und die dadurch beschriebenen Produktgruppen sind im Folgenden aufgelistet: Elektrische Betriebsmittel dürfen nur auf dem Markt bereitgestellt werden, wenn sie den Bestimmungen der europäischen Niederspannungsrichtlinie 2014/35/EU entsprechen. Die Richtlinie gilt für sämtliche elektrischen Betriebsmittel, die für eine Nenn-Betriebsspannung zwischen 50 und 1.000 Volt Wechselstrom bzw. 75 und 1.500 Volt Gleichstrom ausgelegt sind. Druckgeräte und die aus mehreren Druckgeräten zusammengefügten Baugruppen dürfen nur in den Verkehr gebracht werden, wenn sie den Bestimmungen der Richtlinie 2014/68/EU (Druckgeräterichtlinie) entsprechen. Der Anwendungsbereich umfasst Druckgeräte und Baugruppen, die zur Verwendung mit einem maximal zulässigen Druck von mehr als 0,5 bar ausgelegt sind. Einfache Druckbehälter dürfen nur auf dem Markt bereitgestellt werden, wenn sie den Bestimmungen der Richtlinie 2014/29/EU entsprechen. Der Anwendungsbereich umfasst bestimmte geschweißte Behälter, die zur Aufnahme von Luft oder Stickstoff bei einem relativen Innendruck von mehr als 0,5 bar gedacht sind."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Produktsicherheit/produktsicherheit.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:47.221136+00:00","lastSeen":"2026-03-15T16:31:47.221136+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Produktsicherheit/produktsicherheit.html","crawledAt":"2026-03-15T16:31:47.221136Z","crawlId":"contacts-seeded-1773592307","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"a58dc1fa562c34d06845ea9767bfe830e8474b94aaaedff3f7f98d63768550c4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:47.221136+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('cd7e76c0-8896-4c30-b79b-350f554e8a11', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Arbeitsschutz-auf-Baustellen/arbeitsschutz-auf-baustellen.html', 'active', NULL, '2026-03-15T16:31:47.832964+00:00', '{"id":"cd7e76c0-8896-4c30-b79b-350f554e8a11","title":"Arbeitsschutz auf Baustellen","summary":{"de":"Zum Schutz der Beschäftigten in der Bauwirtschaft wurden spezielle gesetzliche Regelungen erlassen."},"content":{"de":"Die Bauwirtschaft ist einer der bedeutendsten Wirtschaftszweige in Deutschland. Arbeitsbedingungen auf Baustellen sind gekennzeichnet durch ständige Veränderungen der Arbeitsumgebung infolge des Baufortschritts, gleichzeitig ablaufende Arbeitsprozesse, ungünstige Witterungseinflüsse, häufig gefährliche und mit hohen körperlichen Beanspruchungen einhergehende Arbeiten sowie großen Zeit- und Termindruck. Im Jahr 2018 war das Baugewerbe in Deutschland der Wirtschaftszweig mit der höchsten Unfallquote 1). Zur Bekämpfung der überdurchschnittlich hohen Zahl von Arbeitsunfällen und Berufserkrankungen in der Bauwirtschaft und zur nationalen Umsetzung der europäischen Baustellenrichtlinie 92/57/ EWG wurden folgende gesetzliche Regelungen erlassen: Vorschriften der Arbeitsstättenverordnung im Hinblick auf Sicherheit und Gesundheitsschutz der Beschäftigten beim Einrichten und Betreiben von Arbeitsstätten (einschließlich Orte auf Baustellen) und ergänzend dazu die spezifischen Anforderungen und Maßnahmen für Baustellen in Ziffer 5.2 Anhang ArbStättV, Vorschriften der Betriebssicherheitsverordnung im Hinblick auf Sicherheit und Gesundheitsschutz der Beschäftigten bei der Verwendung von Arbeitsmitteln, auch auf Baustellen. Für Baustellen besonders relevante Vorschriften enthält Anhang 1 Nummer 2 (Verwendung von Arbeitsmitteln zum Heben von Lasten) und Nummer 3 (Verwendung von Leitern und Gerüsten). Vorschriften der Baustellenverordnung in Hinblick auf die Verbesserung der Sicherheit auf Baustellen durch bessere Koordination bei Planung und Ausführung von Bauvorhaben, u. a. durch die Bestellung eines Sicherheits- und Gesundheitsschutzkoordinators und der Erarbeitung eines Sicherheits- und Gesundheitsschutzplans. Weitere Informationen zur Baustellenverordnung sind abrufbar auf den Internetseiten der Bundesanstalt für Arbeitsschutz und Arbeitsmedizin ( BAuA). Darüber hinaus gelten auch für Beschäftigte auf Baustellen die Vorschriften des Arbeitsschutzgesetzes und der darauf gestützten Verordnungen."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Arbeitsschutz-auf-Baustellen/arbeitsschutz-auf-baustellen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:47.832964+00:00","lastSeen":"2026-03-15T16:31:47.832964+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Arbeitsschutz-auf-Baustellen/arbeitsschutz-auf-baustellen.html","crawledAt":"2026-03-15T16:31:47.832964Z","crawlId":"contacts-seeded-1773592307","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"bac68592a483c5e5128991d912a10bc0c57314797a56da250b7cdbd6e39d599f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:47.832964+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('25d605f1-1fab-480b-8e02-2e1cca31def6', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Betriebs-und-Anlagensicherheit/betriebs-und-anlagensicherheit.html', 'active', NULL, '2026-03-15T16:31:48.474223+00:00', '{"id":"25d605f1-1fab-480b-8e02-2e1cca31def6","title":"Betriebs- und Anlagensicherheit","summary":{"de":"Die Betriebssicherheitsverordnung enthält Anforderungen für die sichere Verwendung von Arbeitsmitteln und überwachungsbedürftiger Anlagen."},"content":{"de":"Die BetrSichV enthält Anforderungen für die sichere Verwendung von Arbeitsmitteln und überwachungsbedürftiger Anlagen. Die BetrSichV dient dem Ziel, die Sicherheit und den Schutz der Gesundheit von Beschäftigten bei der Verwendung von Arbeitsmitteln zu gewährleisten. Dies soll insbesondere erreicht werden durch Auswahl geeigneter Arbeitsmittel im Hinblick auf den vorgesehenen Verwendungszweck, Die BetrSichV verlangt, dass die zur Verfügung gestellten Arbeitsmittel den für sie zum Zeitpunkt ihres Inverkehrbringens geltenden Vorschriften ( z.B. Maschinenverordnung) entsprechen müssen. Darüber hinaus legt sie Schutzziele fest, die der Arbeitgeber im Einzelfall auf der Grundlage einer Gefährdungsbeurteilung mit konkreten Maßnahmen erfüllen muss, damit die Verwendung der Arbeitsmittel sicher ist. Bei der Gefährdungsbeurteilung muss der Arbeitgeber neben sicherheitsrelevanten auch ergonomische Aspekte sowie mögliche psychische Belastungen bei der Verwendung von Arbeitsmitteln berücksichtigen. Für die Erfüllung der Schutzziele erhält der Arbeitgeber Hilfestellung in Form von Technischen Regeln für Betriebssicherheit (TRBS), die vom Ausschuss für Betriebssicherheit (ABS) ermittelt werden. Bei Einhaltung dieser Regeln und Erkenntnisse kann der Arbeitgeber davon auszugehen, dass die in der Verordnung gestellten Anforderungen erfüllt sind. Die BetrSichV setzt die EU - Richtlinie 2009/104/ EG über Mindestvorschriften für Sicherheit und Gesundheitsschutz bei Benutzung von Arbeitsmitteln durch Arbeitnehmer bei der Arbeit in deutsches Recht um und ist dazu auf das Arbeitsschutzgesetz gestützt. Darüber hinaus enthält die BetrSichV rein nationale, aber seit vielen Jahrzehnten etablierte Regelungen zum sicheren Betrieb überwachungsbedürftiger Anlagen ( z.B. Dampfkessel, Druckbehälter, Tankstellen und Aufzugsanlagen)."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Betriebs-und-Anlagensicherheit/betriebs-und-anlagensicherheit.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:48.474223+00:00","lastSeen":"2026-03-15T16:31:48.474223+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Betriebs-und-Anlagensicherheit/betriebs-und-anlagensicherheit.html","crawledAt":"2026-03-15T16:31:48.474223Z","crawlId":"contacts-seeded-1773592308","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4720492e6b35499f653dac25bed1ca47743b84b3a254d88178252da29761d04f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:48.475242+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('67f069c9-7b5f-45c0-93c0-56087cd71157', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Biologische-Arbeitsstoffe/biologische-arbeitsstoffe.html', 'active', NULL, '2026-03-15T16:31:49.150313+00:00', '{"id":"67f069c9-7b5f-45c0-93c0-56087cd71157","title":"Biologische Arbeitsstoffe","summary":{"de":"Unter biologischen Arbeitsstoffen (Biostoffen) werden alle Mikroorganismen - einschließlich gentechnisch veränderter - verstanden, die beim Menschen Infektionen hervorrufen können oder sensibilisierende oder toxische Eigenschaften besitzen."},"content":{"de":"Darüber hinaus werden mit dem Begriff auch Endoparasiten (Parasiten, die im Menschen leben) sowie die Erreger von BSE / TSE erfasst. Biologische Arbeitsstoffe sind allgegenwärtig und jeder ist ihnen täglich ausgesetzt. Allein das Anfassen einer Türklinke bringt uns in Kontakt mit unzähligen Mikroorganismen, von denen manche auch human pathogen sind. Dieses reine \"Ausgesetzt sein\" gegenüber biologischen Arbeitsstoffen besteht für alle Menschen. Mit der SARS-CoV-2-Pandemie ist dies vielen erstmals bewusstgeworden. Neben dem reinen „Ausgesetzt sein“ gibt es aber auch eine Vielzahl von beruflichen Tätigkeiten, bei denen biologische Arbeitsstoffe hergestellt, verwendet oder freigesetzt werden. Für Beschäftigte, die diese Tätigkeiten ausüben, besteht ein zusätzliches Risiko. Hier ist es Aufgabe des Arbeitgebers, die erforderlichen Maßnahmen zum Schutz dieser Beschäftigten zu treffen. Die Verordnung über Sicherheit und Gesundheitsschutz bei Tätigkeiten mit biologischen Arbeitsstoffen - kurz Biostoffverordnung oder BioStoffV -, fasst diese Maßnahmen zusammen. Mit der BioStoffV werden die EG -Richtlinie 2000/54/EG sowie ihre Änderungs-Richtlinien 2019/1833/ EU und 2020/739/EU in nationales Recht umgesetzt wird. Kernvorschrift der BioStoffV sind die Regelungen zur Gefährdungsbeurteilung, die die Anforderungen des § 5 Arbeitsschutzgesetz speziell für den Bereich der biologischen Einwirkungen untersetzen. Sie umfasst die Schritte Informationsbeschaffung, Beurteilung der Gefährdung und Festlegung der Schutzmaßnahmen und die Dokumentation. Regelungen zur arbeitsmedizinischen Vorsorge bei Tätigkeiten mit biologischen Arbeitsstoffen enthält die ArbMedVV. Ein wichtiges Instrumentarium für die Gefährdungsbeurteilung ist das Schutzstufensystem, das dem Arbeitgeber insbesondere bei gezielten Tätigkeiten die Festlegung der erforderlichen Schutzmaßnahmen sehr erleichtert, da die Schutzstufe mit der Risikogruppe des verwendeten Mikroorganismus korrespondiert. Einer Schutzstufe zuzuordnen sind Tätigkeiten in Laboratorien, in der Versuchstierhaltung, in der Biotechnologie sowie in Einrichtungen des Gesundheitsdienstes. Keiner Schutzstufe zugeordnet werden müssen beispielsweise Tätigkeiten in der Land-, Forst-, Abwasser- und Abfallwirtschaft, Reinigungsarbeiten ( z.B. öffentliche Toiletten) oder die Sanierung von mit Schimmelpilzen befallenen Wänden (nicht gezielte Tätigkeiten). Bei Tätigkeiten, die keiner Schutzstufe zuzuordnen sind, bedarf der Arbeitgeber bei der Erstellung der Gefährdungsbeurteilung besonderer Unterstützung. Diese erhält er durch den Ausschuss für biologische Arbeitsstoffe (ABAS). Der ABAS hat seit in Kraft treten der Verordnung im April 1999 insbesondere für die Bereiche mit nicht gezielten Tätigkeiten kontinuierlich technische Regeln zu biologischen Arbeitsstoffen (TRBA) erarbeitet, um dem Arbeitgeber durch transparente, praxisnahe und Anwender freundliche Konkretisierungen der Verordnung Hilfestellung zu geben. Die TRBA geben den Stand der Technik wieder und werden regelmäßig vom ABAS auf Aktualität überprüft. Die TRBA und weitergehende Informationen zu biologischen Arbeitsstoffen finden sich auf der Homepage des BAuA."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Biologische-Arbeitsstoffe/biologische-arbeitsstoffe.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:49.150313+00:00","lastSeen":"2026-03-15T16:31:49.150313+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Biologische-Arbeitsstoffe/biologische-arbeitsstoffe.html","crawledAt":"2026-03-15T16:31:49.150313Z","crawlId":"contacts-seeded-1773592309","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"fd53ac68a9e7b60fd0bcd23187239b50747eb924e2c7712cfb76952e38797f86"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:49.150313+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('83d333a3-a733-4adc-939c-ffcdd39addba', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Elektromagnetische-Felder/elektromagnetische-felder.html', 'active', NULL, '2026-03-15T16:31:49.806303+00:00', '{"id":"83d333a3-a733-4adc-939c-ffcdd39addba","title":"Elektromagnetische Felder","summary":{"de":"Die Verordnung zum Schutz der Beschäftigten vor Gefährdungen durch elektromagnetische Felder - EMFV ist am 15. November 2016 in Kraft getreten. Mit dieser Verordnung kommt Deutschland seiner europäischen Verpflichtung nach, die europäische Arbeitsschutz-Richtlinie 2013/35/EU zu elektromagnetischen Feldern national umzusetzen."},"content":{"de":"Die Verordnung zum Schutz der Beschäftigten vor Gefährdungen durch elektromagnetische Felder - EMFV ist am 15. November 2016 in Kraft getreten. Mit dieser Verordnung kommt Deutschland seiner europäischen Verpflichtung nach, die europäische Arbeitsschutz-Richtlinie 2013/35/EU zu elektromagnetischen Feldern national umzusetzen. Die EMF -Arbeitsschutzverordnung stützt sich auf das Arbeitsschutzgesetz (ArbSchG) und orientiert sich an der Konzeption der Arbeitsschutzverordnungen zu physikalischen Einwirkungen (Lärm und Vibrationen; künstliche optische Strahlung). Die Anforderungen der EMFV werden Anfang 2019 durch ein praxistaugliches Technisches Regelwerk konkretisiert. Dadurch wird die Anwendung der Verordnung in den Betrieben erleichtert. Das Regelwerk wird durch den Ausschuss für Betriebssicherheit (ABS) erarbeitet, welcher das Bundesministerium für Arbeit und Soziales (BMAS) zu allen Fragen des Arbeits- und Gesundheitsschutzes in Bezug auf elektromagnetische Felder am Arbeitsplatz berät. Für die Technischen Regeln werden detaillierte Angaben zur Berücksichtigung des Standes der Technik, zum konkreten Vorgehen bei einer Gefährdungsbeurteilung von EMF am Arbeitsplatz und der Bewertung von Messergebnissen und Berechnungen erarbeitet. Dies schließt auch Präventions- und Schutzmaßnahmen für die Beschäftigten sowie Festlegungen zur Gesundheitsüberwachung und Durchführung von Unterweisungen als auch Festlegungen zur Schulung der Beschäftigten ein. Arbeitgeber, die diese Regeln in Ihrem Betrieb anwenden, können davon ausgehen, dass sie die Vorschriften der EMF-Verordnung eingehalten haben (Vermutungswirkung). Verordnung zum Schutz der Beschäftigten vor Gefährdungen durch elektromagnetische Felder (EMFV)"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Elektromagnetische-Felder/elektromagnetische-felder.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:49.806303+00:00","lastSeen":"2026-03-15T16:31:49.806303+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Elektromagnetische-Felder/elektromagnetische-felder.html","crawledAt":"2026-03-15T16:31:49.806303Z","crawlId":"contacts-seeded-1773592309","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"06593beb0488f739dde045f5f80fd267c31bd7632367904d0f08b7401877e79d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:49.806303+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d5a8fab4-917b-4e0b-a0ac-478fa655860c', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Gefahrstoffe/gefahrstoffe.html', 'active', NULL, '2026-03-15T16:31:50.667471+00:00', '{"id":"d5a8fab4-917b-4e0b-a0ac-478fa655860c","title":"Gefahrstoffe","summary":{"de":"Der richtige Umgang mit Gefahrstoffen schützt Beschäftigte vor Risiken am Arbeitsplatz."},"content":{"de":"Ein Ziel des Arbeitsschutzes ist es, Tätigkeiten mit gefährlichen Stoffen, Stoffgemischen und bestimmten Erzeugnissen (Gefahrstoffen) sicher zu gestalten und mögliche Gefährdungen zu minimieren. Die rechtlichen Rahmenbedingungen hierfür sind in der Gefahrstoffverordnung festgelegt. Im Jahr 2026 verleiht das Bundesministerium für Arbeit und Soziales (BMAS) mit Unterstützung durch die Bundesanstalt für Arbeitsschutz und Arbeitsmedizin (BAuA) zum 16. Mal den Deutschen Gefahrstoffschutzpreis. Die Auszeichnung wird mit einem Preisgeld in Höhe von 10.000 Euro vergeben. Gesucht werden neue Ideen und Anregungen zur Vermeidung von Risiken im Umgang mit Gefahrstoffen. Diese möchten wir öffentlich bekannt und sichtbar machen, damit auch andere Unternehmen – und Beschäftigte – davon profitieren und Sicher. Besser. Arbeiten. können. Teilnehmen können Einzelpersonen, Personengruppen sowie Organisationen und Unternehmen. Angesprochen sind hier vor allem die Branchen Recycling- und Kreislaufwirtschaft, Baugewerbe, Chemieindustrie, Holzwirtschaft, Metallindustrie sowie Verkehr und Logistik. Bewerbungen können bis einschließlich 31. März 2026 unter gefahrstoffschutzpreis@baua.bund.de eingereicht werden. Auslobung 16. Deutscher Gefahrstoffschutzpreis (GSP) [PDF, 263KB] \"Sicher. Besser. Arbeiten.\" lautete das Motto des Deutschen Gefahrstoffschutzpreises 2024, mit dem das Bundesministerium für Arbeit und Soziales am 26. September 2024 innovative Lösungen bei Tätigkeiten mit krebserzeugenden Gefahrstoffen am Arbeitsplatz honoriert hat."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Gefahrstoffe/gefahrstoffe.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:50.667471+00:00","lastSeen":"2026-03-15T16:31:50.667471+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Gefahrstoffe/gefahrstoffe.html","crawledAt":"2026-03-15T16:31:50.667471Z","crawlId":"contacts-seeded-1773592310","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"ed00c00b3514c1294a1a697b91c4441c4e38ec2137414d72901de3b479ba38d2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:50.667471+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c5cd5e79-3051-418f-9b64-7af3730fc48d', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Laerm-und-Vibrationsschutz/laerm-und-vibrationsschutz.html', 'active', NULL, '2026-03-15T16:31:51.291726+00:00', '{"id":"c5cd5e79-3051-418f-9b64-7af3730fc48d","title":"Lärm- und Vibrationsschutz","summary":{"de":"Die Lärm- und Vibrations-Arbeitsschutzverordnung ist am 9. März 2007 in Kraft getreten."},"content":{"de":"Die Lärm- und Vibrations-Arbeitsschutzverordnung wurde am 8. März 2007 im Bundesgesetzblatt veröffentlicht und ist am 9. März 2007 in Kraft getreten. Die Bundesregierung setzt damit die EG -Arbeitsschutzrichtlinien über Lärm und Vibrationen und das Übereinkommen des Internationalen Arbeitsamtes zu Lärm und Vibrationen (ILO-Übereinkommen Nr. 148) in nationales Recht um. Die Verordnung richtet sich an alle Arbeitgeber, deren Beschäftigte Lärm oder Vibrationen ausgesetzt sind. Ziel ist es, die Beschäftigten vor Gesundheitsschäden zu schützen. Die Grenzwerte für Lärm und Vibration am Arbeitsplatz wurden bei der Umsetzung der EG -Lärmrichtlinie auf den Stand der wissenschaftlichen und arbeitsmedizinischen Erkenntnisse festgelegt und verbindlich gemacht. Im Einzelnen wurden für die Lärmbelastung der Expositionsgrenzwerte von 87 dB (A) auf 85 dB (A) und für die Spitzenbelastung von 140 dB (C) auf 137 dB (C) abgesenkt. Bei Belastungen durch Vibrationen, wie sie z.B. bei Baumaschinen auftreten, wurden der Beschleunigungswert in Längsrichtung der Wirbelsäule von 1,15 m/s 2 auf 0,8 m/s 2 gesenkt. Dies bedeutet einen großen Fortschritt für die Gesundheit und Sicherheit der Beschäftigten. Mit der neuen Verordnung wird in den Betrieben mehr Sicherheit und Gesundheitsschutz für Beschäftigte gewährleistet. Insbesondere wird damit der sich weiter ausbreitenden Lärmschwerhörigkeit begegnet, die seit langem an der Spitze der Berufskrankheiten steht und die Kassen der gesetzlichen Unfallversicherung erheblich belastet. Allein im Jahr 2005 wurden den Unfallversicherungsträgern 10.000 neue Verdachtsfälle von beruflich bedingter Lärmschwerhörigkeit gemeldet. Davon wurden 6.000 Fälle als Berufskrankheit neu anerkannt. Die jährlichen Rentenzahlungen der gewerblichen Berufsgenossenschaften beziffern sich auf weit über 150 Mio. Euro im Jahr. Des Weiteren soll mit der neuen Verordnung Gesundheitsschäden durch Hand-Arm- oder Ganzkörpervibrationen entgegengewirkt werden. Betroffen sind hier häufig die Bereiche der Land- und Forstwirtschaft und der Bauindustrie ( z.B. Land- und Forstmaschinen, Presslufthämmer etc. ). Vibrationen können bei länger andauernder Exposition schwere Muskel- und Skelett-Erkrankungen hervorrufen sowie neurologische Störungen und Gefäßerkrankungen auslösen. Lärmschwerhörigkeit wie auch Muskel- und Skelettkrankheiten sind für die betroffenen Menschen mit einem erheblichen Verlust an Lebensqualität verbunden. Die Sozialsysteme werden durch die Vielzahl der Erkrankungen erheblich belastet. Die Bundesregierung will dieser Entwicklung gezielt entgegenwirken und den Gesundheitsschutz der Beschäftigten verbessern. Die neue Lärm- und Vibrations-Arbeitsschutzverordnung leistet dazu einen wesentlichen Beitrag. Tech­ni­sche Re­geln zur Lärm-Ar­beits­schutz­ver­ord­nung (TRLV Lärm)"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Laerm-und-Vibrationsschutz/laerm-und-vibrationsschutz.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:51.291726+00:00","lastSeen":"2026-03-15T16:31:51.291726+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Laerm-und-Vibrationsschutz/laerm-und-vibrationsschutz.html","crawledAt":"2026-03-15T16:31:51.291726Z","crawlId":"contacts-seeded-1773592311","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"89dcd012e15acfec6240a760a828ece5e8d97f627a9fac5c0fcbf3a92630d9ec"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:51.291726+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c13726d2-2f61-43e2-9957-9c4ee2c927e2', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Optische-Strahlungen/optische-strahlungen.html', 'active', NULL, '2026-03-15T16:31:51.952155+00:00', '{"id":"c13726d2-2f61-43e2-9957-9c4ee2c927e2","title":"Künstliche optische Strahlung am Arbeitsplatz","summary":{"de":"Die Verordnung zum Schutz der Beschäftigten vor Gefährdungen durch künstliche optische Strahlung (OStrV) ist am 27. Juli 2010 in Kraft getreten ( BGBl I Nr. 38 S. 960). Damit sind die drei EU -Arbeitsschutz-Richtlinien zu Lärm, Vibrationen und künstlicher optischer Strahlung in nationales Recht umgesetzt."},"content":{"de":"Egal, ob in kleinen oder großen Betrieben, die Vorschriften der OStrV gewährleisten mehr Sicherheit und Gesundheitsschutz für Beschäftigte am Arbeitsplatz. Gesundheitsgefährdende künstliche optische Strahlung tritt insbesondere bei Schweißarbeiten, bei der Glas- und Quarzverarbeitung, bei der Metallherstellung und -verarbeitung sowie bei den immer häufiger anzutreffenden Laseranwendungen auf. Optische Strahlung aus künstlichen Strahlungsquellen ( z.B. Laser oder UV -/IR-Strahlung) kann bei Exposition zu ernsthaften Augen- und Hautschäden führen und damit die Gesund¬heit und die Sicherheit von Beschäftigten an vielen Arbeitsplätzen gefährden. Kurzfristige Schädigungen zeigen sich beispielsweise in Form von Verbrennungen der Haut und Schädigungen an der Horn-, Binde- sowie der Netzhaut der Augen. Langfristig hohe Expositionen der Haut mit intensiver UV-Strahlung können Spätfolgen in Form von Hautkrebs auslösen. Bei der Anwendung von Lasern ergibt sich ein hohes Gefährdungspotential für die Beschäftigten aufgrund der hohen Energiedichte der erzeugten Laserstrahlung. Bestrahlungen durch Hochleistungslaser führen ohne zwingend einzuhaltende Schutzmaßnahmen meist unmittelbar zu schwersten und irreversiblen Schädigungen der Augen und der Haut. Bei der Verwendung von besonders gefährlichen Lasern in den Betrieben schreibt die Verordnung daher konsequent die Anwesenheit eines sachkundigen Laserschutzbeauftragten vor. Die Anwendungsgebiete sind vielfältig und sind zum Beispiel bei der Materialbe- und verarbeitung, in der Medizin oder bei der elektronischen Datenverarbeitung zu finden. Die präventiven Maßnahmen der OStrV sollen sowohl zur Verbesserung der Sicherheit und des Gesundheitsschutzes der Beschäftigten als auch zur Kostensenkung bei den sozialen Sicherungssystemen beitragen. Der Ausschuss für Betriebssicherheit hat zwei technische Regeln zur praxisgerechten Konkretisierung der Vorschriften der OStrV erarbeitet. Bei Anwendung dieser Technischen Regeln kann der Arbeitgeber davon ausgehen, dass er die Bestimmungen der OStrV eingehalten hat (Vermutungswirkung). Die Technischen Regeln zu den Bereichen \"Inkohärente optische Strahlung\" und \"Laserstrahlung\" sind vom BMAS im Gemeinsamen Ministerialblatt veröffentlicht worden. Die Technischen Regeln sowie andere Informationen zum Bereich optische Strahlung sind über die Internetseiten der BAuA verfügbar. Arbeitsschutzverordnung zu künstlicher optischer Strahlung"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Optische-Strahlungen/optische-strahlungen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:51.952155+00:00","lastSeen":"2026-03-15T16:31:51.952155+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Optische-Strahlungen/optische-strahlungen.html","crawledAt":"2026-03-15T16:31:51.952155Z","crawlId":"contacts-seeded-1773592311","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"52b43fce53e1f884604ec1441e95468b2c21c4e594b7a5b3b5fb55c1b3f612f6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:51.952155+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8a96fa81-c1db-4bcb-be5e-73135ccf5e67', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Sicherheit-in-Arbeitsstaetten/sicherheit-in-arbeitsstaetten.html', 'active', NULL, '2026-03-15T16:31:52.520196+00:00', '{"id":"8a96fa81-c1db-4bcb-be5e-73135ccf5e67","title":"Sicherheit in Arbeitsstätten","summary":{"de":"Die Sicherheit und der Gesundheitsschutz der Beschäftigten in Arbeitsstätten wird in der Verordnung über Arbeitsstätten geregelt."},"content":{"de":"Die Sicherheit und der Gesundheitsschutz der Beschäftigten in Arbeitsstätten wird in der Verordnung über Arbeitsstätten ( ArbStättV ) geregelt. Die Arbeitsstättenverordnung setzt die EU-Richtlinien über der EU-Richtlinie 89/654/EWG des Rates vom 30. November 1989 über Mindestvorschriften für Sicherheit und Gesundheitsschutz in Arbeitsstätten (Erste Einzelrichtlinie im Sinne des Artikels 16 Absatz 1 der Richtlinie 89/391/EWG) (ABl. EG Nr. L 393 S. 1) und der EU-Richtlinie 90/270/EWG des Rates vom 29. Mai 1990 über die Mindestvorschriften bezüglich der Sicherheit und des Gesundheitsschutzes bei der Arbeit an Bildschirmgeräten (Fünfte Einzelrichtlinie im Sinne des Artikels 16 Absatz 1 der Richtlinie 89/391/EWG) (ABl. EG Nr. L 156 S. 14) und der EU-Richtlinie 92/58/EWG des Rates vom 24. Juni 1992 über Mindestvorschriften für die Sicherheits- und/oder Gesundheitsschutzkennzeichnung am Arbeitsplatz (Neunte Einzelrichtlinie im Sinne des Artikels 16 Absatz 1 der Richtlinie 89/391/EWG) (ABl. EG Nr. L 245 S. 23) und des Anhangs IV (Mindestvorschriften für Sicherheit und Gesundheitsschutz auf Baustellen) der EU-Richtlinie 92/57/EWG des Rates vom 24. Juni 1992 über die auf zeitlich begrenzte oder ortsveränderliche Baustellen anzuwendenden Mindestvorschriften für die Sicherheit und den Gesundheitsschutz (Achte Einzelrichtlinie im Sinne des Artikels 16 Absatz 1 der Richtlinie 89/391/EWG) (ABl. EG Nr. L 245 S. 6)"},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Sicherheit-in-Arbeitsstaetten/sicherheit-in-arbeitsstaetten.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:52.520196+00:00","lastSeen":"2026-03-15T16:31:52.520196+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/Technischer-Arbeitsschutz/Sicherheit-in-Arbeitsstaetten/sicherheit-in-arbeitsstaetten.html","crawledAt":"2026-03-15T16:31:52.521827Z","crawlId":"contacts-seeded-1773592312","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"cae349914a20cdc392a34211e5424ed564e27e66c03d34329d5f739f55813b6e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:52.521827+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6cd9044c-da5b-4168-b3be-b58190f47cfc', 'contacts', 'https://www.bmas.de/DE/Arbeit/Arbeitsschutz/arbeitsschutz.html', 'active', NULL, '2026-03-15T16:31:53.866579+00:00', '{"id":"6cd9044c-da5b-4168-b3be-b58190f47cfc","title":"Arbeitsschutz","summary":{"de":"Wer arbeitet, muss dabei sicher sein. Dafür braucht es Regeln und Bestimmungen, die dies gewährleisten. Hier finden Sie aktuelle Informationen und Neuigkeiten zum Thema Arbeitsschutz."},"content":{"de":"Wer arbeitet, muss dabei sicher sein. Dafür braucht es Regeln und Bestimmungen, die dies gewährleisten. Das Bundesministerium für Arbeit und Soziales (BMAS) hat den 16. Deutschen Gefahrstoffschutzpreis in Höhe von 10.000 Euro ausgeschrieben. Am 4. Februar, erinnert das Aktionsbündnis \"Roadmap on Carcinogens\" unter Federführung des BMAS Unternehmen an ihre Verantwortung für eine sichere Arbeitsumgebung. Die Herbstveranstaltung des Ausschusses für Arbeitsmedizin 2025 am 13. November führte zu dem Ergebnis: KI wird ein unverzichtbarer Partner auch für Betriebsärztinnen und Betriebsärzte. Die Initiative Neue Qualität der Arbeit wurde vom Bundesministerium für Arbeit und Soziales ins Leben gerufen. Ziel der Initiative ist eine Verbesserung der Qualität der Arbeit – für Unternehmen und Beschäftigte. Auf dem Portal für psychische Gesundheit am Arbeitsplatz (psyGA) finden Sie für die Praxis aufbereitetes Wissen rund um das Thema psychische Gesundheit in der Arbeitswelt."},"url":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/arbeitsschutz.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:53.866579+00:00","lastSeen":"2026-03-15T16:31:53.866579+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Arbeitsschutz/arbeitsschutz.html","crawledAt":"2026-03-15T16:31:53.866579Z","crawlId":"contacts-seeded-1773592313","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"3f0310efed9f23cd6707f8b67ba5e7c9efe26819eae0b511c7ee461702ab0898"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:53.866579+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('740a9cca-ce44-45e5-bdf7-0dd01e1370d7', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Allianz-fuer-Aus-und-Weiterbildung/allianz-fuer-aus-und-weiterbildung.html', 'active', NULL, '2026-03-15T16:31:54.552998+00:00', '{"id":"740a9cca-ce44-45e5-bdf7-0dd01e1370d7","title":"Allianz für Aus- und Weiterbildung2023 bis 2026","summary":{"de":"Bundesregierung, Spitzenverbände der Wirtschaft, Gewerkschaften, Länder und Bundesagentur für Arbeit haben die Allianz für Aus- und Weiterbildung geschlossen."},"content":{"de":"Die Allianz für Aus- und Weiterbildung ist die zentrale politische Plattform und ein Aktionsbündnis für die Stärkung der dualen Ausbildung. Das Ende 2014 gegründete Bündnis setzt sich dafür ein, die Attraktivität, Qualität und Leistungsfähigkeit sowie die Integrationskraft der beruflichen Bildung weiter zu stärken. Hier arbeiten Ministerien, Behörden, Wirtschaft und Gewerkschaften gemeinsam daran, die Aus- und Weiterbildung zu unterstützen, zur Fachkräftesicherung beizutragen und den Wandel am Arbeitsmarkt mit zu gestalten. Die Spitzen der Allianz für Aus- und Weiterbildung haben am 29. Mai 2023 die Allianzvereinbarung für die Jahre 2023 bis 2026 unterzeichnet. Die Allianz für Aus- und Weiterbildung verfolgt das Ziel, möglichst alle Menschen zu einem qualifizierten Berufsabschluss zu bringen. Mit der 2023 erneuerten Allianzvereinbarung nehmen die Partner stärker als bisher die Zeit vor der Ausbildung in den Blick. Ziel ist es, die Berufsorientierung weiter auszubauen und den Übergang von der Schule in den Beruf zu erleichtern. Im überarbeiteten Vereinbarungstext sind u.a. die Ausbildungsgarantie und die Exzellenzinitiative berufliche Bildung enthalten. Gleichzeitig wollen die Allianzpartner auch die Qualität und Attraktivität der dualen Ausbildung weiter steigern und jungen Menschen zeigen, welche spannenden und anspruchsvollen beruflichen Möglichkeiten mit einer Ausbildung verbunden sind. Darüber hinaus soll die die höherqualifizierende bzw. höhere Berufsbildung gefördert werden. Das macht Ausbildungsberufe attraktiver, weil sich gleichwertige Entwicklungsmöglichkeiten neben dem hochschulischen Bildungsweg eröffnen. Flankiert werden die Maßnahmen der Allianz für Aus- und Weiterbildung durch den jährlichen \"Sommer der Berufsausbildung\", einer gemeinsamen Aktion aller Allianzpartner, in der für die berufliche Ausbildung geworben wird."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Allianz-fuer-Aus-und-Weiterbildung/allianz-fuer-aus-und-weiterbildung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:54.552998+00:00","lastSeen":"2026-03-15T16:31:54.552998+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Allianz-fuer-Aus-und-Weiterbildung/allianz-fuer-aus-und-weiterbildung.html","crawledAt":"2026-03-15T16:31:54.552998Z","crawlId":"contacts-seeded-1773592314","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"65d565cff52a8088214f086e627a9bff8dac3172bd68b85670d0748919c064ba"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:54.552998+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9275862a-57b3-454a-a20a-cdb869a1ff57', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Ausbildungsgarantie/ausbildungsgarantie.html', 'active', NULL, '2026-03-15T16:31:55.249588+00:00', '{"id":"9275862a-57b3-454a-a20a-cdb869a1ff57","title":"Ausbildungsgarantie","summary":{"de":"Trotz zunehmender unbesetzter Ausbildungsstellen bleiben in Deutschland zu viele junge Menschen ohne Ausbildungsvertrag. Ein gelungener Übergang von der Schule in den Beruf ist aber für jede/n Einzelne/n und auch gesamt­gesellschaftlich von zentraler Bedeutung."},"content":{"de":"Um allen jungen Menschen ohne Berufsabschluss den Zugang zu einer vollqualifizierenden, möglichst betrieblichen Ausbildung zu ermöglichen, gibt es künftig eine Ausbildungsgarantie. Sie umfasst verschiedene Beratungs- und Unterstützungsangebote, angefangen bei der beruflichen Orientierung und Beratung, bis zu Hilfen bei der Aufnahme und für den erfolgreichen Abschluss einer Berufsausbildung. Die Ausbildungsgarantie ist Teil des Aus- und Weiterbildungsgesetzes und umfasst folgende gesetzliche Neuerungen: Einführung eines geförderten Berufsorientierungspraktikums durch einen neuen § 48a SGB III mit Beratung zu kurzen, auch überregionalen Praktika unter Übernahme der entstehenden Fahrt- und Unterkunftskosten. Erleichterungen zur Teilnahme an Einstiegsqualifizierungen in § 54a SGB III durch eine Verkürzung der Mindestdauer auf vier Monate, Erleichterungen für eine Durchführung in Teilzeit, Öffnung für Menschen mit Behinderungen, die eine Fachpraktikerausbildung anstreben sowie Öffnung der Förderung für vorherige Ausbildungsabbrechende bei demselben Arbeitgeber. Einführung eines Mobilitätszuschusses durch einen neuen § 73a SGB III, auf dessen Grundlage Fahrtkosten für zwei (fiktive) Familienheimfahrten pro Monat im ersten Ausbildungsjahr übernommen werden können, wenn Ausbildungsuchende eine wohnortferne Ausbildung aufnehmen. Änderungen in der außerbetrieblichen Berufsausbildung in § 76 SGB III: Rechtsanspruch auf Förderung in einer außerbetrieblichen Berufsausbildung, wenn die jeweiligen Fördervoraussetzungen erfüllt sind. Öffnung auch für sogenannte Marktbenachteiligte, die in einer Region wohnen, in der die Agentur für Arbeit oder das Jobcenter unter Einbindung der Sozialpartner eine erhebliche Unter­versorgung an Ausbildungsplätzen festgestellt hat."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Ausbildungsgarantie/ausbildungsgarantie.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:55.249588+00:00","lastSeen":"2026-03-15T16:31:55.249588+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Ausbildungsgarantie/ausbildungsgarantie.html","crawledAt":"2026-03-15T16:31:55.249588Z","crawlId":"contacts-seeded-1773592315","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"399ba84de1f038759101228534d8e85cfe825f1aeabbee97f2bc07ce9722f97e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:55.249588+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bc81c719-3f01-4f91-8924-9bb58933e8cd', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Bildungsketten/bildungsketten.html', 'active', NULL, '2026-03-15T16:31:55.934089+00:00', '{"id":"bc81c719-3f01-4f91-8924-9bb58933e8cd","title":"Bildungsketten bis zum Ausbildungsabschluss","summary":{"de":"Die Initiative Bildungsketten unterstützt junge Menschen auf ihrem Weg von der Schule ins Berufsleben. Alle Jugendlichen, die eine Ausbildung machen möchten, sollen bis zum erfolgreichen Abschluss derselben begleitet werden."},"content":{"de":"Ein flüssiger Übergang von der Schule in den Beruf ist von wesentlicher Bedeutung. Damit er leichter gelingt, gibt es eine gemeinsame Initiative vom BMAS und vom BMBF (Bundesministerium für Bildung und Forschung). Sie lautet mit vollem Titel „Abschluss und Anschluss – Bildungsketten bis zum Ausbildungsabschluss“ und begleitet junge Menschen von der Vorbereitung auf den Schulabschluss bis hin zu ihrem gewünschten Ausbildungsziel. Bund, Länder und Bundesagentur für Arbeit (BA) übernehmen gemeinsam Verantwortung, um den Azubis unter die Arme zu greifen. Dazu sind konkrete Vereinbarungen mit jedem der 16 Bundesländer geplant. Bisher konnten solche Vereinbarungen mit 14 Bundesländern geschlossen werden. Aus den Vereinbarungen soll ein gemeinsames, aufeinander abgestimmtes Maßnahmenbündel für den Übergang Schule-Ausbildung-Beruf entstehen. Gemeinsam mit den Ländern setzt sich der Bund dafür ein, erfolgreiche Förderinstrumente zu einem ganzheitlichen und in sich stimmigen Fördersystem zur Berufsorientierung und im Übergangsbereich zu verzahnen. Dabei sollen regionale Anforderungen besonders berücksichtigt werden. Mit den neuen Bildungsketten-Vereinbarungen wird die Zusammenarbeit zwischen Bund, Ländern und BA weiter gestärkt. In den früheren Vereinbarungen stand die Berufsorientierung im Fokus, nun soll der reibungslose Übergang ins Berufsleben stärker in den Blick genommen werden. Dieser kann beispielsweise durch Berufseinstiegsbeleiterinnen und -begleiter und andere Maßnahmengefördert werden. Neben der weiterentwickelten Assistierten Ausbildung unterstützt das BMAS den Ausbau der Jugendberufsagenturen. In Jugendberufsagenturen arbeiten die beteiligten Leistungsträger rechtskreisübergreifend zusammen an dem Ziel, junge Menschen beim Übergang von der Schule in den Beruf gut zu begleiten."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Bildungsketten/bildungsketten.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:55.934089+00:00","lastSeen":"2026-03-15T16:31:55.934089+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Bildungsketten/bildungsketten.html","crawledAt":"2026-03-15T16:31:55.934089Z","crawlId":"contacts-seeded-1773592315","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"0d44d600deb2b24cf6e705994c0343bb3369862ce9c6132e33e9d2cd066e72b6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:55.934089+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('16384ee6-c048-4cb5-a69a-f1c20dd68acc', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Deutscher-Aufbau-und-Resilienzplan-DARP/deutscher-aufbau-und-resilienzplan.html', 'active', NULL, '2026-03-15T16:31:56.516309+00:00', '{"id":"16384ee6-c048-4cb5-a69a-f1c20dd68acc","title":"Deutscher Aufbau- und Resilienzplan (DARP)","summary":{"de":"Mit dem Bundesprogramm \"Ausbildungsplätze sichern\""},"content":{"de":"Die Corona-Krise und deren Folgen war eine der größten Herausforderungen in der Geschichte der Europäischen Union und der Bundesrepublik Deutschland – in gesundheitlicher, gesellschaftlicher und insbesondere auch ökonomischer Hinsicht. Die Europäische Union hat auf diese Krise kraftvoll reagiert: Die Aufbau- und Resilienzfazilität (ARF) ist ein befristetes Instrument der Europäischen Kommission, welches Europa helfen soll, stärker und robuster aus dieser Krise zu kommen. Die Aufbau- und Resilienzfazilität (ARF) ist ein befristetes Instrument und das Herzstück von NextGeneration EU. Sie soll Europa helfen, stärker und robuster aus der Krise zu kommen. Um die Mittel der ARF zu erhalten, mussten die Mitgliedstaaten Pläne für umfangreiche Investitionen und Reformen vorlegen, die die wirtschaftliche Erholung befördern und die soziale Resilienz stärken. Deutschland hatte den ersten Entwurf für einen Deutschen Aufbau- und Resilienzplan (DARP) im Dezember 2020 an die Europäische Kommission übermittelt. Der DARP umfasst ein Gesamtvolumen von etwa 28 Milliarden Euro für den Zeitraum 2020 bis 2026 und beinhaltet ca. 40 Maßnahmen."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Deutscher-Aufbau-und-Resilienzplan-DARP/deutscher-aufbau-und-resilienzplan.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:56.516309+00:00","lastSeen":"2026-03-15T16:31:56.516309+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Deutscher-Aufbau-und-Resilienzplan-DARP/deutscher-aufbau-und-resilienzplan.html","crawledAt":"2026-03-15T16:31:56.516309Z","crawlId":"contacts-seeded-1773592316","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"1f4d1625cdac0649250063d6718e35947532de8316256c2d266dbef236c668ed"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:56.516309+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('264c356e-dbb0-406d-8063-19b6b4d468d8', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Foerderung-von-Jugendwohnheimen/foerderung-von-jugendwohnheimen.html', 'active', NULL, '2026-03-15T16:31:57.209196+00:00', '{"id":"264c356e-dbb0-406d-8063-19b6b4d468d8","title":"Förderung von Jugendwohnheimen","summary":{"de":"Bezahlbarer Wohnraum ist für viele junge Menschen ausschlaggebend, wenn es darum geht, außerhalb ihrer Heimatregion eine Ausbildung aufzunehmen. Die Förderung von Wohnheimplätzen durch die Bundesagentur für Arbeit (BA) ist ein Baustein, um bezahlbaren Wohnraum für Auszubildende sicherzustellen."},"content":{"de":"Aufbau, Erweiterung, Umbau und Ausstattung von Jugendwohnheimen können durch Darlehen und Zuschüsse der BA an die Träger der Wohnheime gefördert werden. Voraussetzung für diese Förderung ist, dass sie zum Ausgleich auf dem Ausbildungsmarkt und zur Förderung der Berufsausbildung erforderlich ist. Die Träger oder Dritte müssen sich angemessen an den Kosten beteiligen. Die Einzelheiten kann die BA in einer Anordnung regeln. Mit einem Sonderprogramm \"Junges Wohnen\" fördert die Bundesregierung die Schaffung von Wohnheimplätzen für Studierende und Auszubildende. Darüber hinaus hat das das Bundesministerium für Wohnen, Stadtentwicklung und Bauwesen (BMWSB) Ende März 2023 ein Sonderprogramm für studentisches Wohnen, für junges Wohnen und Wohnen für Auszubildende (\"Junges Wohnen\") aufgelegt. Das Programm \"Junges Wohnen\" ist ein Teilprogramm im Rahmen des sozialen Wohnungsbaus und zielt auf den Aus-, Neu- oder Umbau neuer bzw. die Modernisierung bestehender Wohnheimplätze für Auszubildende und Studierende."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Foerderung-von-Jugendwohnheimen/foerderung-von-jugendwohnheimen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:57.209196+00:00","lastSeen":"2026-03-15T16:31:57.209196+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Foerderung-von-Jugendwohnheimen/foerderung-von-jugendwohnheimen.html","crawledAt":"2026-03-15T16:31:57.209196Z","crawlId":"contacts-seeded-1773592317","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"f939c31567e98ef8e8cdf1d07363d9a5768ad5d4268648e198f4a8b3fd123b2b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:57.209196+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2e07f17d-f459-420c-8bee-5ae821545d04', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Jugendberufsagenturen/jugendberufsagenturen.html', 'active', NULL, '2026-03-15T16:31:57.981774+00:00', '{"id":"2e07f17d-f459-420c-8bee-5ae821545d04","title":"Jugendberufsagenturen","summary":{"de":"Man findet sie in vielen deutschen Städten: spezielle Anlaufstellen, die jungen Menschen bei allen Fragen und Problemen rund um den Berufsstart helfen. Dahinter stehen die Agenturen für Arbeit, die Jobcenter sowie die örtliche Jugendhilfe."},"content":{"de":"IT-Tool \"Selbstbewertung für Jungendberufsagenturen\" Die Jugendberufsagenturen arbeiten rechtskreisübergreifend. Das heißt, dass die verschiedenen oben genannten Träger gemeinsam an dem Ziel arbeiten Jugendliche und junge Erwachsene in Gesellschaft, Ausbildung und Arbeit bestmöglich zu integrieren und zu beraten. Weil Hilfs- und Serviceangebote der Träger bei den Jugendberufsagenturen gebündelt werden, ist das Angebot für junge Ratsuchende gut zu erfassen: Sie wissen immer, an wen sie sich im ersten Schritt wenden können. Die Beratung und Anlaufstelle so transparent und einfach zu gestalten, war den Trägern bei der Planung und Umsetzung ein wichtiges Anliegen. Je nach Lage vor Ort kann die Art der Zusammenarbeit der Träger ganz unterschiedlich aussehen. Mal geht es um die bessere Einbindung von Schulen, mal steht die Vernetzung mit anderen wichtigen Partnern im Vordergrund. Regionale und strukturelle Rahmenbedingungen sind vielfältig und individuell. Das bedeutet natürlich einen erheblichen zeitlichen und organisatorischen Aufwand für die beteiligten Partner einer Jugendberufsagentur. Um eine Übersicht über die verschiedenen Bündnisse zu ermöglichen und ihre Aktivitäten transparent zu machen, wurde die Servicestelle Jugendberufsagenturen eingerichtet. Die Servicestelle Jugendberufsagenturen bündelt Informationen rund um die rechtskreisübergreifende Zusammenarbeit am Übergang von Schule zu Beruf. Hier geht’s direkt zum Erklärfilm \"Was ist eine Jugendberufsagentur?\""},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Jugendberufsagenturen/jugendberufsagenturen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:57.981774+00:00","lastSeen":"2026-03-15T16:31:57.981774+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Jugendberufsagenturen/jugendberufsagenturen.html","crawledAt":"2026-03-15T16:31:57.982774Z","crawlId":"contacts-seeded-1773592317","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b10de5d5c0873983d7131fff51f857ef06027b8a2e10dffe6c0e2f8c4877a8a0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:57.982774+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2382998e-52df-43d2-a914-0123a4a21c67', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Jugendgarantie/jugendgarantie.html', 'active', NULL, '2026-03-15T16:31:58.598326+00:00', '{"id":"2382998e-52df-43d2-a914-0123a4a21c67","title":"Jugendgarantie","summary":{"de":"Die Jugendgarantie ist eine wichtige europäische Initiative zur Bekämpfung der Jugendarbeitslosigkeit in der EU. Zentrales Ziel der bereits seit 2013 bestehenden Jugendgarantie ist es, dass alle jungen Menschen innerhalb von vier Monaten nach Schul- oder Ausbildungsabschluss bzw. nachdem sie arbeitslos geworden sind, ein hochwertiges Angebot für eine Beschäftigung, eine Aus- oder Weiterbildung oder ein Praktikum erhalten."},"content":{"de":"Im Oktober 2020 haben die EU-Mitgliedstaaten einstimmig eine Ratsempfehlung zur Stärkung der Jugendgarantie angenommen. Die Empfehlung basiert auf einem Vorschlag der Kommission vom 1. Juli 2020 zur Stärkung der Jugendgarantie, der wiederum Teil eines Pakets zur Unterstützung der Jugendbeschäftigung ist. Die einstimmige Annahme der Empfehlungen zur verstärkten Jugendgarantie ist ein wichtiges Signal, dass die Bekämpfung der Jugendarbeitslosigkeit, weiterhin Priorität auf der europäischen Agenda hat. Von der weiterentwickelten Jugendgarantie können nunmehr junge Menschen bis zum 29. Lebensjahr profitieren. Der Fokus wird dabei auf besonders schutzbedürftige junge Menschen gelegt – wie beispielweise diejenigen, die mit einer Behinderung leben, die einer Minderheit angehören oder die in abgelegenen ländlichen Gebieten oder benachteiligten Stadtteilen wohnen. Jungen Menschen soll eine möglichst frühzeitige und individuell zugeschnittene Beratung angeboten und der Erwerb von – angesichts des Wandels der Arbeitswelt erforderlichen – digitalen und ökologischen Qualifikationen ermöglicht werden. In Deutschland koordiniert das Bundesministerium für Arbeit und Soziales (BMAS) die Umsetzung der EU-Jugendgarantie. Es ist für die Einbindung aller an der Umsetzung beteiligten Akteure und Partner auf allen Ebenen und in allen Bereichen zuständig. Das BMAS ist in seiner Funktion als \"Jugendgarantie-Koordinator\" auch Hauptansprechpartner gegenüber der Europäischen Kommission in Fragen der Umsetzung der EU-Jugendgarantie in Deutschland. Wichtigster Partner bei der Umsetzung der Jugendgarantie ist die Bundesagentur für Arbeit (BA). Als maßgeblicher Dienstleister am Arbeitsmarkt erbringt sie für die Bürgerinnen und Bürger sowie für Unternehmen und Institutionen umfassende Leistungen am Arbeits- und Ausbildungsmarkt. Der BA kommt bei der Umsetzung der Jugendgarantie somit eine zentrale Rolle zu. Auf örtlicher Ebene werden die Leistungen über ein flächendeckendes Netz von Agenturen für Arbeit sowie von Jobcentern zur Verfügung gestellt. Die Jobcenter setzen die Grundsicherung für Arbeitsuchende um; sie erbringen Leistungen der Vermittlung und Beratung, zur Aktivierung und beruflichen Eingliederung, zur Berufsausbildung, beruflichen Weiterbildung sowie zur Aufnahme einer Beschäftigung mit dem Ziel der Beendigung oder Verringerung der Hilfebedürftigkeit. In vielen Kommunen bilden die örtliche Agentur für Arbeit, das Jobcenter und der örtliche Träger der Jugendhilfe gemeinsam ein Kooperationsbündnis. Vielerorts sind auch die Schulen einbezogen. Die Bündnisse werden übergeordnet als \"Jugendberufsagentur\" (JBA) bezeichnet. Eine JBA dient jungen Menschen als zentrale Anlaufstelle vor Ort für alle Fragen rund um den Übergang von der Schule in den Beruf. Die einzelnen Träger sind dabei weiterhin in unterschiedlicher Weise und mit unterschiedlichen gesetzlichen Zielen für die Beratung und Integration junger Menschen in Gesellschaft, Ausbildung und Arbeit verantwortlich. Jeder Träger zeichnet sich in der Praxis durch ein differenziertes Hilfe- und Dienstleistungsangebot aus, das im Rahmen einer JBA jedoch gebündelt und so gezielter und passgenauer unterbreitet werden kann. Aktuelle Schwerpunkte des BMAS für die Umsetzung der Jugendgarantie sind unter anderem"},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Jugendgarantie/jugendgarantie.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:58.598326+00:00","lastSeen":"2026-03-15T16:31:58.598326+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/Jugendgarantie/jugendgarantie.html","crawledAt":"2026-03-15T16:31:58.598326Z","crawlId":"contacts-seeded-1773592318","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"b7a69b39c7a4fc6213d3dbcc62695ccbd36484f8dbca7fdfd191cb2349c6fb9f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:31:58.598326+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('21f0d0c5-25cc-40b7-a944-ded7f05a6764', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/berufliche-ausbildung.html', 'active', NULL, '2026-03-15T16:31:59.204508+00:00', '{"id":"21f0d0c5-25cc-40b7-a944-ded7f05a6764","title":"Berufliche Ausbildung","summary":{"de":"Wie junge Menschen in Deutschland ihre Perspektiven in der Berufsausbildung verbessern können."},"content":{"de":"Der Flyer informiert über die verschiedenen Wege der Berufs- und Ausbildungsberatung nach der Schule. Meldung, 05.05.23: Allianz für Ausbildung informiert bundesweit über Ausbildungsmöglichkeiten"},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/berufliche-ausbildung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:31:59.204508+00:00","lastSeen":"2026-03-15T16:31:59.204508+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Ausbildung/berufliche-ausbildung.html","crawledAt":"2026-03-15T16:31:59.205510Z","crawlId":"contacts-seeded-1773592319","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"ad968f5f1234c28b3fa1c8df9b9aadaf9877a5ea023eb082788fdaf07be12957"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T16:31:59.205510+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('96df20ff-cd8c-4e05-a169-00e771917ecb', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Foerderung-der-beruflichen-Weiterbildung/foerderung-der-beruflichen-weiterbildung.html', 'active', NULL, '2026-03-15T16:32:00.153687+00:00', '{"id":"96df20ff-cd8c-4e05-a169-00e771917ecb","title":"Ihr Weg zur Förderung der beruflichen Weiterbildung","summary":{"de":"Eine Übersicht über Gesetze, Regelungen und Möglichkeiten der beruflichen Weiterbildung."},"content":{"de":"II. Beschäftigte Arbeitnehmerinnen und Arbeitnehmer III. Förderung von arbeitslosen Arbeitnehmer*innen ohne Berufsabschluss (Geringqualifizierte) V. Fördermöglichkeiten außerhalb der Arbeitsförderung Wir stehen im Zeitalter der Digitalisierung und vielfältigen Veränderungen in Branchen, Betrieben und Berufen vor tiefgreifenden neuen Herausforderungen auch in der beruflichen Weiterbildung und Qualifizierung. Auch wenn die Verantwortung für die betriebliche Weiterbildung vorrangig bei den Arbeitgebern und Betrieben liegt, bleibt es wichtige Aufgabe der arbeitsmarktpolitischen Weiterbildung, Arbeitnehmer*innen sowie die Betriebe bei qualifikatorischen Anpassungen zu unterstützen. Die Leistungen der Weiterbildungsförderung der Bundesagentur für Arbeit ( BA ) richten sich nicht nur an arbeitslose oder von Arbeitslosigkeit bedrohten Arbeitnehmer*innen. Auch Arbeitnehmer*innen in einem Beschäftigungsverhältnis können bei Vorliegen der gesetzlichen Voraussetzungen von einer Förderung profitieren. Das gilt insbesondere auch für Beschäftigte ohne oder nicht mehr verwertbaren Berufsabschluss, da sie ein überdurchschnittlich hohes Arbeitslosigkeitsrisiko haben. Die Regelungen zur Weiterbildungsförderung nach dem Dritten Buch Sozialgesetzbuch ( SGB III ) finden grundsätzlich auch im Zweiten Buch Sozialgesetzbuch ( SGB II ) für die Förderung erwerbsfähiger Leistungsberechtigter durch die Jobcenter Anwendung. Auf der Webseite der Bundesagentur für Arbeit finden Sie weitere Informationen zu Karriere und Weiterbildung sowie zur Weiterbildung für Ihr Personal. Das BMAS und die Bundesagentur für Arbeit sehen es als wichtige Aufgabe an, Arbeitnehmer*innen bei ihrer beruflichen Weiterbildung und Betriebe bei erhöhtem Weiterbildungsbedarf der Beschäftigten zu unterstützen. Für die betriebliche Weiterbildung sind in erster Linie die Arbeitgeber*innen zuständig."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Foerderung-der-beruflichen-Weiterbildung/foerderung-der-beruflichen-weiterbildung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:00.153687+00:00","lastSeen":"2026-03-15T16:32:00.153687+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Foerderung-der-beruflichen-Weiterbildung/foerderung-der-beruflichen-weiterbildung.html","crawledAt":"2026-03-15T16:32:00.153687Z","crawlId":"contacts-seeded-1773592320","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"406c15ec0a33bd6e76fd40ef7ca100b7784cac1d6513430d04aa7e066d893a98"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:00.153687+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c4761879-3d1a-4d8a-95ac-79bf3d9f0c82', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Nationale-Weiterbildungsstrategie/nationale-weiterbildungsstrategie.html', 'active', NULL, '2026-03-15T16:32:00.809789+00:00', '{"id":"c4761879-3d1a-4d8a-95ac-79bf3d9f0c82","title":"Nationale Weiterbildungsstrategie","summary":{"de":"Plattform für Kooperation und Koordination in der Weiterbildungspolitik in Deutschland"},"content":{"de":"Unser gemeinsamer Leitfaden hin zu einer neuen Weiterbildungskultur Die Nationale Weiterbildungsstrategie ist einmalig: Zum ersten Mal gibt es eine solche Strategie in Deutschland, die von Bund, Ländern, Wirtschaft, Gewerkschaften und der Bundesagentur für Arbeit getragen wird. Die Ziele: Weiterbildungen als festen Bestandteil beruflicher und unternehmerischer Entwicklung zu etablieren und eine gemeinsame Weiterbildungskultur in Deutschland zu schaffen. Die Nationale Weiterbildungsstrategie ist ein langfristig angelegter, übergreifender und partnerschaftlicher Austausch- und Beratungsprozess zur Weiterbildungspolitik, der stetig fortgesetzt und weiterentwickelt wird. Das Bundesministerium für Arbeit und Soziales (BMAS) setzt den Strategieprozess in gemeinsamer Federführung mit dem Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ) um. Ob Arbeitsuchende, Arbeitnehmer*innen oder Unternehmer*innen – sie alle profitieren von der Nationalen Weiterbildungsstrategie: Arbeitsuchende erhalten mit Weiterbildungen neue Chancen auf einen Arbeitsplatz"},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Nationale-Weiterbildungsstrategie/nationale-weiterbildungsstrategie.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:00.809789+00:00","lastSeen":"2026-03-15T16:32:00.809789+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Nationale-Weiterbildungsstrategie/nationale-weiterbildungsstrategie.html","crawledAt":"2026-03-15T16:32:00.809789Z","crawlId":"contacts-seeded-1773592320","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4759564d3ad14c45fc015a0fea47ef2211206f88ae36b0ac7d3b39dccf232e74"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:00.809789+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e2dd6c87-9ac7-49f6-bebc-4a6c8051cc8f', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Nationales-Onlineportal-fuer-berufliche-Weiterbildung/nationales-onlineportal-fuer-berufliche-weiterbildung.html', 'active', NULL, '2026-03-15T16:32:01.644141+00:00', '{"id":"e2dd6c87-9ac7-49f6-bebc-4a6c8051cc8f","title":"Nationales Onlineportal für berufliche Weiterbildung","summary":{"de":"Ein zentrales digitales Portal, um Informationen und Angebote der beruflichen Weiterbildung zu bündeln"},"content":{"de":"Die Bundesagentur für Arbeit (BA) hat im Rahmen der Nationalen Weiterbildungsstrategie das Portal \"mein NOW\" entwickelt. Seit dem 1. Januar 2024 ist die erste Version von \"mein NOW\" live. Aktuell ist der Markt für berufliche Weiterbildung für Menschen im Erwerbsleben und Arbeitgeber*innen unübersichtlich. Es bestehen viele verschiedene Informationsquellen und die Suche ist sehr aufwendig. Es fällt nicht immer leicht, Informationen zu finden, die zu den eigenen Bedürfnissen passen. Ziel des Portals ist es, ein zentrales und niedrigschwelliges Online-Eingangsportal zum Thema berufliche Weiterbildung anzubieten. \"mein NOW\" bietet damit Orientierung und macht das komplexe System der beruflichen Weiterbildung für die Zielgruppen digital an einem Ort zugänglich. Elena arbeitet in einem kleinen Unternehmen in der Veranstaltungsbranche. Wie für Millionen Menschen, hat sich auch ihr Arbeitsalltag digitalisiert. Seit der Corona-Pandemie buchen Elenas Kund*innen digitale Events oder hybride Formate, also eine Mischung aus virtueller und Live-Veranstaltung. Anfangs verursachte ihr die Organisation Stress. Doch seitdem Elena sich weitergebildet hat, weiß sie genau worauf sie achten muss, damit die Live-Übertragung nicht abbricht und Teilnehmende ein tolles digitales Erlebnis haben. Ihre Weiterbildungen hat Elena über \"mein NOW\" gefunden. Ein paar Stichwörter genügten, und schon zeigte die Weiterbildungssuche den passenden Kurs in ihrer Region und Möglichkeiten für einen finanziellen Zuschuss an. Kim leitet ein mittelständisches Pflegeunternehmen und hat soeben einige neue Mitarbeitende eingestellt. Diese sollen nun im Umgang mit dem neuen EDV -System geschult werden. Die Suche nach passenden Weiterbildungs­angeboten für das Personal ist zeitaufwendig, da das Angebot groß und vielfältig ist."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Nationales-Onlineportal-fuer-berufliche-Weiterbildung/nationales-onlineportal-fuer-berufliche-weiterbildung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:01.644141+00:00","lastSeen":"2026-03-15T16:32:01.644141+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Nationales-Onlineportal-fuer-berufliche-Weiterbildung/nationales-onlineportal-fuer-berufliche-weiterbildung.html","crawledAt":"2026-03-15T16:32:01.644141Z","crawlId":"contacts-seeded-1773592321","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"a783be979ae203c994c5d52e39f4f32a1a134dafcdf5d3d71eb9b2dedc1ac3e6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:01.644141+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('14835613-85e1-417f-9d7d-0665b996268d', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Weiterbildungsverbuende/weiterbildungsverbuende.html', 'active', NULL, '2026-03-15T16:32:02.522199+00:00', '{"id":"14835613-85e1-417f-9d7d-0665b996268d","title":"Das Bundesprogramm\"Aufbau von Weiterbildungsverbünden\"","summary":{"de":"Die Organisation von Weiterbildung im Unternehmen neu denken"},"content":{"de":"Was sind Weiterbildungsverbünde und welche Aufgaben übernehmen sie? Welche Ziele werden mit den Weiterbildungsverbünden verfolgt? An wen wende ich mich bei Fragen und Interesse an weitergehenden Informationen? Wir erleben eine tiefgreifende Transformation der Wirtschaft: Der ökologische Wandel, die Digitalisierung und die demografische Entwicklung sind zentrale Herausforderungen, die auch die Arbeitswelt grundlegend verändern. Weiterbildung rückt dabei immer stärker in den Fokus. Es braucht neue Wege und betriebliche Strategien, um den Austausch der Unternehmen untereinander zu fördern und weitere Zugänge zu Wissen und Bildung für möglichst viele Beschäftigte zu schaffen. Vor allem kleine und mittlere Unternehmen (KMU) verfügen aber oft nicht über die zeitlichen, finanziellen oder personellen Ressourcen, um Weiterbildung für ihre Beschäftigten im ausreichenden Maße umzusetzen. Ihre Weiterbildungsbeteiligung ist nachweislich geringer gegenüber größeren Unternehmen. In der Nationalen Weiterbildungsstrategie (NWS) wurde daher bereits 2019 die Vereinbarung getroffen, dezentrale Weiterbildungsverbünde und regionale Kooperationen zwischen Unternehmen, insbesondere zwischen KMU, voranzutreiben und im Rahmen von Modellprojekten finanziell zu unterstützen. Mit dem Bundesprogramm \"Aufbau von Weiterbildungsverbünden\" kommt das Bundesministerium für Arbeit und Soziales diesem zentralen Vorhaben aus der NWS nach und leistet damit einen wichtigen Beitrag. Unternehmen werden bei der Fachkräftesicherung unterstützt und die Beschäftigungsfähigkeit der Arbeitnehmerinnen und Arbeitnehmer erhalten. Weiterbildungsverbünde sind Netzwerke, bei denen mehrere Unternehmen und Akteure der Weiterbildungslandschaft sowie regionale Arbeitsmarktakteure Kooperationen eingehen, sodass Weiterbildungsmaßnahmen ressourceneffizient über Betriebsgrenzen hinaus organisiert und durchgeführt werden können. Im Fokus stehen dabei insbesondere der Austausch unter den Partnern eines Verbundes, die Identifikation der Weiterbildungsbedarfe in den Betrieben sowie die Beratung zu und Recherche nach geeigneten Weiterbildungsangeboten bzw. die Konzeption neuer Weiterbildungsmaßnahmen gemäß dem ermittelten Bedarf der Unternehmen."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Weiterbildungsverbuende/weiterbildungsverbuende.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:02.522199+00:00","lastSeen":"2026-03-15T16:32:02.522199+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/Weiterbildungsverbuende/weiterbildungsverbuende.html","crawledAt":"2026-03-15T16:32:02.522199Z","crawlId":"contacts-seeded-1773592322","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"92395f7521a8f75c3e62740169f933759422d0d1367ef4b3a506a3445d8214fc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:02.522199+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1ed5f51b-3675-47c3-916e-4afdbb25c766', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/berufliche-weiterbildung.html', 'active', NULL, '2026-03-15T16:32:03.380953+00:00', '{"id":"1ed5f51b-3675-47c3-916e-4afdbb25c766","title":"Berufliche Weiterbildung","summary":{"de":"Mit Weiterbildung fit für die Arbeit von Morgen"},"content":{"de":"Das zentrale Portal der BA, um Informationen und Angebote der beruflichen Weiterbildung zu bündeln. Angelehnt an die Handlungsfelder der Fachkräftestrategie der Bundesregierung gehen wir in sieben Fokusthemen die Fachkräftesicherung an."},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/berufliche-weiterbildung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:03.380953+00:00","lastSeen":"2026-03-15T16:32:03.380953+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/Berufliche-Weiterbildung/berufliche-weiterbildung.html","crawledAt":"2026-03-15T16:32:03.380953Z","crawlId":"contacts-seeded-1773592323","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"3611af1c106bcad5d4c03089ee5bbcfa79e021755e03ba85ce219ed1dcab19a5"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T16:32:03.382543+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('33bbdaa5-96ca-4358-8efd-e5cdeb7c05ba', 'contacts', 'https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/aus-und-weiterbildung.html', 'active', NULL, '2026-03-15T16:32:03.974322+00:00', '{"id":"33bbdaa5-96ca-4358-8efd-e5cdeb7c05ba","title":"Aus- und Weiterbildung","summary":{"de":"Menschen in den Beruf bringen und im Beruf weiterbringen. Das ist das Ziel aller Maßnahmen der Aus- und Weiterbildung des BMAS. Hier finden Sie aktuelle Neuigkeiten und Infos zu diesem Thema."},"content":{"de":"Menschen in den Beruf bringen und im Beruf weiterbringen. Das ist das Ziel aller Maßnahmen der Aus- und Weiterbildung des BMAS. In Berlin setzen das BMAS und das BMBFSFJ zusammen mit den Partnern der Nationalen Weiterbildungsstrategie den Auftakt für eine gemeinsame Weiterbildungsoffensive. Ziel ist es, lebensbegleitendes Lernen als selbstverständlichen Bestandteil der Arbeits- und Lebenswelt in Deutschland zu verankern. Die Allianz für Aus- und Weiterbildung arbeitet daran, jungen Menschen die Perspektiven einer beruflichen Ausbildung aufzuzeigen. Am 10. November treffen sich die Spitzenvertreterinnen und -vertreter der Allianz in Berlin. Der am 7. März 2025 veröffentlichte NWS-Umsetzungsbericht beleuchtet die Aktivitäten und Beiträge aller Partner der letzten Jahre. Die Wirkungsanalyse hat gezeigt, dass die Berufseinstiegsbegleitung vor allem langfristig positive Effekte hat. Klischeefrei: Initiative zur Berufs- und Studienwahl"},"url":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/aus-und-weiterbildung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:03.974322+00:00","lastSeen":"2026-03-15T16:32:03.974322+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Aus-und-Weiterbildung/aus-und-weiterbildung.html","crawledAt":"2026-03-15T16:32:03.974322Z","crawlId":"contacts-seeded-1773592323","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"2803fa622672ed81fd2152e4510d65e235bee8c2e61375532167e93f61dba94b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:03.974322+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a55be756-7b1a-4421-8a05-9a95a464328c', 'contacts', 'https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/Denkfabrik-Digitale-Arbeitsgesellschaft/denkfabrik-digitale-arbeitsgesellschaft-arbeit-neu-denken.html', 'active', NULL, '2026-03-15T16:32:04.775668+00:00', '{"id":"a55be756-7b1a-4421-8a05-9a95a464328c","title":"Denkfabrik Digitale Arbeitsgesellschaft: Arbeit neu denken","summary":{"de":"Mit der Denkfabrik Digitale Arbeitsgesellschaft hat das BMAS eine für Ministerien neuartige, interdisziplinär und agil arbeitende Organisationseinheit eingerichtet."},"content":{"de":"Mit der Denkfabrik Digitale Arbeitsgesellschaft hat das Bundesministerium für Arbeit und Soziales eine für Ministerien neuartige, interdisziplinär und agil arbeitende Organisationseinheit eingerichtet, die Funktionen und Arbeitsweisen eines klassischen Think Tanks und eines zeitgenössischen Future Labs verbindet. Im Oktober 2018 hat die Denkfabrik ihre Arbeit aufgenommen. Ziel ist es, neue Handlungsfelder, die für das Arbeits- und Sozialministerium durch die Digitalisierung und andere Trends entstehen, frühzeitig zu identiﬁzieren, die Arbeitswelt stärker im gesellschaftlichen Kontext zu erfassen und neue Lösungsansätze für die Arbeitsgesellschaft der Zukunft zu entwickeln. Eine sich rasant verändernde Arbeitswelt erfordert das Engagement vieler Akteure. Die Denkfabrik bringt sie zusammen. Die Denkfabrik Digitale Arbeitsgesellschaft bündelt Projekte und Prozesse rund um die digitale Transformation innerhalb des BMAS und bildet eine zentrale Anspielstation für Wissenschaft, Technik, Praxis und Sozialpartner zu diesem Thema. Der Ansatz der Denkfabrik ist es, die Digitalisierung konsequent und systematisch von den Menschen und ihren sozialen und gesellschaftlichen Beziehungen her zu denken. Dem zugrunde liegt die Überzeugung, dass sich in einer sich stetig wandelnden digitalen Wirtschaft der Rahmen so gestalten lässt, dass alle Beteiligten – Wirtschaft, Gesellschaft und Beschäftigte – davon profitieren, wenn sich Entwicklung und Einsatz digitaler Anwendungen an den Bedürfnissen der Beschäftigten und den Anforderungen an gute Arbeit orientieren. In der Denkfabrik Digitale Arbeitsgesellschaft werden aktuell unter anderem folgende Schwerpunkte bearbeitet: Intelligente Verkehrslenkung, Ridesharing, Playlisten auf Streamingdiensten, Onlinedating- oder Jobsharing-Plattformen: Für viele ist Künstliche Intelligenz (KI) zunehmend ein fester, meist unbewusster Bestandteil des Alltags. Die Debatte über Chancen und Risiken bleibt aber oftmals abstrakt und wirft ethische, rechtliche, kulturelle und soziale Fragen auf. Die Bundesregierung hat mit der KI-Strategie einen Handlungsrahmen für die nächsten Jahre geschaffen, um durch die Unterstützung von Grundlagen- und anwendungsorientierter Forschung sowie der Entwicklung von innovativen KI-Anwendungen in allen wirtschaftlichen und gesellschaftlichen Bereichen Deutschland eine Spitzenposition im weltweiten Wettbewerb zu sichern. Voraussetzung dafür ist, im Rahmen eines intensiven Austauschs KI ethisch, rechtlich, kulturell und institutionell in die Gesellschaft einzubetten. Mehr Nachhaltigkeit und Vernetzung: Bundesregierung schreibt KI-Strategie fort"},"url":"https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/Denkfabrik-Digitale-Arbeitsgesellschaft/denkfabrik-digitale-arbeitsgesellschaft-arbeit-neu-denken.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:04.775668+00:00","lastSeen":"2026-03-15T16:32:04.775668+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/Denkfabrik-Digitale-Arbeitsgesellschaft/denkfabrik-digitale-arbeitsgesellschaft-arbeit-neu-denken.html","crawledAt":"2026-03-15T16:32:04.775668Z","crawlId":"contacts-seeded-1773592324","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"9e151a329af896c6be8cfda21f297bd7cae06366cfcf1b1603d31fcbf55bc130"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:04.775668+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bd2b4deb-a865-4895-b0ea-ec75f1a00a1d', 'contacts', 'https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/Rat-der-Arbeitswelt/rat-der-arbeitswelt.html', 'active', NULL, '2026-03-15T16:32:05.570177+00:00', '{"id":"bd2b4deb-a865-4895-b0ea-ec75f1a00a1d","title":"Rat der Arbeitswelt","summary":{"de":"Die Mitglieder des Rates der Arbeitswelt zum Juni 2024; obere Reihe v.l.n.r. Prof. Dr. Melanie Arntz, Franz Donner, Michaela Evans-Borchers, Alexandra Friedrich, Sinischa Horvat, Anna Kaiser, Dr. Luitwin Mallmann untere Reihe v.l.n.r. Mathias Möreke, Prof. Dr. Sabine Pfeiffer, Isabel Rothe, Prof. Dr. Wolfgang Schroeder, Prof. Dr. Ing. Sascha Stowasser, Prof. Dr. Ulrich Walwei"},"content":{"de":"Der Rat der Arbeitswelt war ein unabhängiges Expertengremium, das vom damaligen Bundesarbeitsminister Hubertus Heil im Januar 2020 berufen wurde. Ziel des Projektes war es, Impulse für einen sozial, ökologisch und wirtschaftlich nachhaltigen Wandel der Arbeitswelt zu geben. Dafür wurden die Entwicklungen in der Arbeitswelt faktenbasiert und zahlengestützt nachgezeichnet und durch Expertinnen und Experten aus Wissenschaft und Praxis eingeordnet. Das Gremium war interdisziplinär und praxisbezogen besetzt, um auch bei Unternehmen, Beschäftigten und Sozialpartnern Gehör zu finden. Während seines Mandats hat der Rat zwei Arbeitswelt-Berichte veröffentlicht, die sich nicht nur an Politik und Öffentlichkeit richteten, sondern auch an die betrieblichen Gestalterinnen und Gestalter. Die Themen setzte sich das Gremium selbst: Im Mai 2021 übergab der Rat seinen ersten Arbeitswelt-Bericht mit Impulsen für eine nachhaltige Arbeitswelt zwischen Pandemie und Wandel an den Bundesminister. Der zweite Arbeitswelt-Bericht wurde im Mai 2023 an den Bundesminister übergeben und widmete sich der Transformation in bewegten Zeiten  Nachhaltige Arbeit als wichtigste Ressource. Zum Juni 2024 endete das Mandat des Rates. Prof. Dr. Melanie Arntz, Stellvertretende Leiterin des Forschungsbereichs \"Arbeitsmärkte und Sozialversicherungen\" am Zentrum für Europäische Wirtschaftsforschung (ZEW) und Leibniz-Professorin für Volkswirtschaftslehre an der Universität Heidelberg; Franz Donner, Of Counsel bei Pusch Wahlig Workplace Law, alternierender Vorstandsvorsitzender der Berufsgenossenschaft Energie Textil Elektro Medienerzeugnisse, ehemaliger Leiter der Corporate Human Resources der ZEISS Group; Michaela Evans-Borchers, Direktorin des Forschungsschwerpunktes Arbeit & Wandel am Institut Arbeit und Technik (IAT) der Westfälischen Hochschule, Gelsenkirchen; Alexandra Friedrich, Vorsitzende des Gemeinschaftsbetriebsrates am Standort Melsungen der B. Braun Melsungen AG;"},"url":"https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/Rat-der-Arbeitswelt/rat-der-arbeitswelt.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:05.570177+00:00","lastSeen":"2026-03-15T16:32:05.570177+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/Rat-der-Arbeitswelt/rat-der-arbeitswelt.html","crawledAt":"2026-03-15T16:32:05.570177Z","crawlId":"contacts-seeded-1773592325","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6eb2201d04d18d0b7327e13582a7987864f052ef85127d381b490433f978d5d1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:05.570177+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d08fc8c9-006e-4658-87cb-95e628a68df4', 'contacts', 'https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/digitalisierung-der-arbeitswelt.html', 'active', NULL, '2026-03-15T16:32:06.275507+00:00', '{"id":"d08fc8c9-006e-4658-87cb-95e628a68df4","title":"Digitalisierung und Transformation der Arbeitswelt","summary":{"de":"In diesem Bereich beschäftigt sich das BMAS mit Auswirkungen auf die Arbeitswelt, die durch technologische und gesellschaftliche Trends ausgelöst werden."},"content":{"de":"Die Fachabteilung beschäftigt sich mit den Auswirkungen der Digitalisierung auf die Arbeitswelt und folgend der Sicherung von Beschäftigtenrechten, der Modernisierung der Arbeits- und Sozialverwaltung sowie mit der Verbreitung gemeinwohlorientierter KI. Aktuelle Pressemitteilungen und Meldungen zum Themenbereich Digitalisierung."},"url":"https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/digitalisierung-der-arbeitswelt.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:06.275507+00:00","lastSeen":"2026-03-15T16:32:06.275507+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Digitalisierung-der-Arbeitswelt/digitalisierung-der-arbeitswelt.html","crawledAt":"2026-03-15T16:32:06.275507Z","crawlId":"contacts-seeded-1773592326","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"1d68b8103f801cb013d20589b3b3e1196ed9d14bdf9f7919aab7aec35c966828"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:06.275507+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6f6ace0a-984e-4177-acc6-43bf9df1cfa9', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Deutscher-Fachkraeftepreis/deutscher-fachkraeftepreis.html', 'active', NULL, '2026-03-15T16:32:06.963973+00:00', '{"id":"6f6ace0a-984e-4177-acc6-43bf9df1cfa9","title":"Deutscher Fachkräftepreis","summary":{"de":"Für den DFKP 2025 hat das Bundesministerium für Arbeit und Soziales in sieben Kategorien nach den besten Ideen zur Fachkräftesicherung gesucht. Aus über 400 Einreichungen haben wir je Kategorie die drei besten Projekte ermittelt."},"content":{"de":"Die Bundesregierung prämiert nachhaltige Lösungsansätze bei der Fachkräftesicherung In sieben Kategorien hat das Bundesministerium für Arbeit und Soziales nachhaltige Lösungen zur Fachkräftesicherung mit dem Deutschen Fachkräftepreis ausgezeichnet. Deutschlandweit waren Unternehmen, Institutionen und Netzwerke aufgerufen, sich mit ihren Projekten und Ansätzen zu bewerben. Auf Basis einer Bewertungsmatrix und der Expertise der Mitarbeiter*innen aus den zuständigen Fachreferaten wurde eine Shortlist ermittelt. Diese Shortlist anonymisierten wir und legten sie einer namenhaften Jury vor. Der Deutsche Fachkräftepreis wird in Anlehnung an die Handlungsfelder der Fachkräftestrategie der Bundesregierung in sieben Kategorien verliehen. Die Bundesregierung der 21. Legislaturperiode wird die Fachkräftestrategie aktualisieren und weiterentwickeln. Mehr Informationen zur Fachkräftestrategie der Bundesregierung, ihren Handlungsfeldern und unseren Ansätzen und Maßnahmen. Wegen der Überarbeitung und Aktualisierung pausiert der Deutsche Fachkräftepreis und wird voraussichtlich erst wieder im Jahr 2027 verliehen. Melden Sie sich für unseren Haupt-Newsletter an, um direkt alle Neuigkeiten zum Preis und einer Bewerbungsphase in Ihr Postfach zu bekommen."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Deutscher-Fachkraeftepreis/deutscher-fachkraeftepreis.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:06.963973+00:00","lastSeen":"2026-03-15T16:32:06.963973+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Deutscher-Fachkraeftepreis/deutscher-fachkraeftepreis.html","crawledAt":"2026-03-15T16:32:06.963973Z","crawlId":"contacts-seeded-1773592326","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"15c8ba1a064f566c0ac4f28b391b0007c968b849f879c8a0f688ef4b4887733c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:06.963973+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('64712e33-f011-4849-b6e7-e73c9906ac45', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftemonitoring/fachkraeftemonitoring.html', 'active', NULL, '2026-03-15T16:32:07.744231+00:00', '{"id":"64712e33-f011-4849-b6e7-e73c9906ac45","title":"Zahlen und Fakten zur Fachkräfteentwicklung","summary":{"de":"Schlussfolgerungen der Mittelfristprognose bis 2029"},"content":{"de":"Schlussfolgerungen der Szenarien über die Erhöhung des Arbeitskräftepotenzials Die Mittelfristprognose des Fachkräftemonitorings nimmt die Arbeitsmarktströme von Arbeitskräfteangebot und -bedarf für 2025 bis 2029 detailliert in den Blick. Die Szenarienrechnungen geben eine Einschätzung zu den ungenutzten Potenzialen bei Frauen, Nicht-Deutschen und Älteren für die Fachkräftesicherung in 5, 10 und 15 Jahren. Das Fachkräftemonitoring für das Bundesministerium für Arbeit und Soziales (BMAS) schätzt plausible mittel- und langfristige Fachkräftebedarfe sowie wahrscheinliche Fachkräfteengpässe und Fachkräfteüberschüsse in Berufsgruppen ab, auf Grundlage der aktuellen Welle der Qualifikations- und Berufsprojektionen ( Qube-Projekt ). Das Fachkräftemonitoring für das BMAS baut auf dem wissenschaftlich unabhängigen Projekt \"Qualifikation und Beruf in der Zukunft\" auf, das solche Projektionen bereits seit 2007 unter der gemeinsamen Leitung des Bundesinstituts für Berufsbildung (BIBB) und des Instituts für Arbeitsmarkt- und Berufsforschung (IAB) in Zusammenarbeit mit der Gesellschaft für Wirtschaftliche Strukturforschung (GWS) erstellt. Das Fachkräftemonitoring für das BMAS berücksichtigt zusätzliche Annahmen – zu einer beschleunigten Digitalisierung, zum Klimawandel, zur Zeiten- und Energiewende sowie die größeren Unsicherheiten bezogen auf die möglichen Entwicklungen des Außenhandels (Zollpolitik der USA). Diese Annahmen werden regelmäßig mit einem wissenschaftlichen Projektbeirat, der wesentlicher Teil des Fachkräftemonitorings für das BMAS ist, diskutiert und erst anschließend final gesetzt. Der wissenschaftliche Projektbeirat für das Fachkräftemonitoring berät bei der Weiter­entwicklung des Analyseinstruments und bringt in­terdisziplinäre Sichtweisen ein. Das Fachkräftemonitoring ist eine zentrale empirische Referenz in der fachkräftepolitischen Diskussion in Deutschland und zugleich Grundlage für die Fachkräftestrategie der Bundesregierung. Es zeigt auf, in welchen Berufsgruppen künftig Arbeitsplätze wegfallen oder neu entstehen können und wie sich Neuzugänge aus dem Bildungs- und Ausbildungssystem, Übergänge in den Ruhestand und die berufliche Mobilität entwickeln."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftemonitoring/fachkraeftemonitoring.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:07.744231+00:00","lastSeen":"2026-03-15T16:32:07.744231+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftemonitoring/fachkraeftemonitoring.html","crawledAt":"2026-03-15T16:32:07.744231Z","crawlId":"contacts-seeded-1773592327","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"ce3eb57082288037d94cd998951675746c9f1c145bf29bdd7e554645f962a467"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:07.744231+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a1617715-2a38-4ba8-adf2-e0d800c62607', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/INQA-Coaching/inqa-coaching.html', 'active', NULL, '2026-03-15T16:32:08.415715+00:00', '{"id":"a1617715-2a38-4ba8-adf2-e0d800c62607","title":"INQA-Coaching","summary":{"de":"Das Beratungsprogramm für kleine und mittlere Unternehmen (KMU)."},"content":{"de":"Fehlende Fachkräfte? Veraltete Prozesse? Verzögerte Digitalisierung? Das Beratungsprogramm der Initiative Neue Qualität der Arbeit (INQA) hilft kleinen und mittleren Unternehmen, im digitalen Wandel wettbewerbsfähig und attraktiv für Fachkräfte zu bleiben. 80% gefördert, 100% gestärkt in die Zukunft! Seit dem Start des Programms im Sommer 2023 haben mehr als 2100 Betriebe das Angebot genutzt und bereits einen Coaching-Scheck erhalten. Damit knüpft INQA-Coaching an den Erfolg des Vorgängerprogramms unternehmensWert:Mensch (uWM) an. Ein Programm nah an der Praxis: Der Film zeigt, was INQA-Coaching kann und wie es funktioniert. Geschäftsführende und Beschäftigte spüren es jeden Tag: Die Digitalisierung der Arbeitswelt schreitet in großen Schritten voran. Das kann herausfordernd sein, bringt aber auch jede Menge Chancen mit sich. Genau hier setzt das Beratungsprogramm INQA-Coaching an: Gemeinsam mit einem professionellen Coach wird der Wandel im Betrieb aktiv angegangen und gestaltet. Der Coach begleitet dabei, individuelle Lösungen für Herausforderungen in Unternehmen zu finden. Dabei werden die Vorteile des digitalen Fortschritts und neuer Technologien genutzt, z.B. um Arbeitsabläufe zu verbessern oder neue Geschäftsideen umzusetzen. So werden Unternehmen attraktiver für Fachkräfte und stärken ihre Wettbewerbsfähigkeit. INQA-Coaching richtet sich an kleine und mittlere Unternehmen, unabhängig von der Branche. Bis zu 12 Coaching-Tage werden gefördert, 80 Prozent der Kosten übernommen."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/INQA-Coaching/inqa-coaching.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:08.415715+00:00","lastSeen":"2026-03-15T16:32:08.415715+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/INQA-Coaching/inqa-coaching.html","crawledAt":"2026-03-15T16:32:08.416715Z","crawlId":"contacts-seeded-1773592328","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7b85f5cd5dc024add86f750e139f5184477babd641416c9be792b8ba117611c5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:08.416715+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6ba02f5a-c41d-4790-8a79-266a6a67b2ba', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/INQA/inqa.html', 'active', NULL, '2026-03-15T16:32:09.010660+00:00', '{"id":"6ba02f5a-c41d-4790-8a79-266a6a67b2ba","title":"INQA – Initiative Neue Qualität der Arbeit","summary":{"de":"Die Gestaltung der Arbeitswelt gelingt am besten, wenn ihre wichtigsten Akteure an einem Strang ziehen. Daran arbeitet die Initiative Neue Qualität der Arbeit (INQA)."},"content":{"de":"Die Gestaltung der Arbeitswelt gelingt am besten, wenn ihre wichtigsten Akteure an einem Strang ziehen - deshalb wird die Initiative Neue Qualität der Arbeit (INQA) gemeinsam von Bund, Ländern, Sozialversicherungsträgern, Gewerkschaften, Stiftungen und Arbeitgebern getragen und vom Bundesministerium für Arbeit und Soziales gefördert. INQA unterstützt vor allem kleine und mittelständische Unternehmen (KMU) bei der Gestaltung der Transformation der Arbeitswelt und hat besonders die Arbeitsbedingungen im Fokus. Ziel ist es, Maßnahmen für ein gutes und gesundes Arbeitsklima, für moderne Führung und Zusammenarbeit im Unternehmen sowie eine ausgeglichene Balance zwischen Arbeit und Privatleben zu fördern. Als Einstiegsinstrument bietet INQA für Unternehmen die kostenlosen INQA-Checks. Dabei handelt es sich um praxiserprobte Checklisten, mit denen Unternehmen ihre Stärken und Schwächen systematisch unter die Lupe nehmen können, insbesondere zu den Handlungsfeldern Führung, Vielfalt, Gesundheit und Kompetenz. Zudem werden darin hilfreiche Tools vorgestellt. Darüber hinaus fördert INQA gute Arbeitsgestaltung durch konkrete Projektförderung im Rahmen von betrieblichen Lern- und Experimentierräumen sowie durch ein passgenaues Coaching- und Beratungsangebot für Unternehmen (INQA-Coaching). INQA bietet eine Plattform für Arbeitsqualität und den Wandel der Arbeit – mit serviceorientierten Angeboten und Inhalten. Die Webseite www.inqa.de richtet sich an Beschäftigte ebenso wie an Geschäftsführung, Führungskräfte, Personalverantwortliche und Betriebsräte und bringt die verschiedenen Akteure persönlich und virtuell zusammen. Sie ermöglicht einen schnellen und unkomplizierten Zugang sowohl zu aktuellen Inhalten als auch zu den bewährten Förderungsangeboten der Initiative."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/INQA/inqa.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:09.010660+00:00","lastSeen":"2026-03-15T16:32:09.010660+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/INQA/inqa.html","crawledAt":"2026-03-15T16:32:09.012242Z","crawlId":"contacts-seeded-1773592329","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"277b5800051147a248673ad86aedf37cea99ef2139576284c4e595da755ca632"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:09.012242+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f8a3f0b6-9fe8-4793-965b-f3446515f57b', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/Lern-und-Experimentierraeume/lern-und-experimentierraeume.html', 'active', NULL, '2026-03-15T16:32:09.688659+00:00', '{"id":"f8a3f0b6-9fe8-4793-965b-f3446515f57b","title":"INQA-Experimentierräume","summary":{"de":"Das BMAS fördert Unternehmen bei der Erprobung innovativer Arbeitsansätze – aus der Praxis für die Praxis"},"content":{"de":"Wie wollen wir in Zukunft arbeiten? Wer kreative Lösungen für die Gestaltung der Arbeitswelt im Wandel finden will, muss Neues wagen. Genau das unterstützen die INQA -Experimentierräume. Ihr Ziel ist es, Räume für gemeinsames Ausprobieren zu öffnen und voneinander zu lernen. Dabei gilt die Regel: Was funktioniert, wird fortgeführt, was nicht klappt, wird verändert oder verworfen. Im Fokus: die Beschäftigten mit ihren Fähigkeiten und ihrem Erfahrungswissen. So entstehen in einem iterativen Prozess und unter wissenschaftlicher Begleitung in der Praxis funktionierende Lösungen, von denen auch andere Betriebe profitieren. Die INQA-Experimentierräume werden vom Bundesministerium für Arbeit und Soziales über einen mehrjährigen Zeitraum gefördert. Einen Einblick und Ergebnisse bisheriger INQA-Experimentierräume erhalten Sie unter www.inqa.de/exp. Im aktuellen Förderzeitraum stehen Projekte im Fokus, die innovative Lösungen in kleinen und mittleren Unternehmen (KMU) entwickeln und erproben. Ziel ist es, die Integration und Teilhabe von Beschäftigten im Bereich Diversität zu verbessern. Denn in Zeiten von Personalengpässen, alternden Belegschaften sowie veränderten Erwartungen von Mitarbeitenden und Kund*innen trägt die Förderung von Vielfalt im Betrieb dazu bei, Fachkräfte zu sichern und langfristig wettbewerbsfähig zu bleiben. Die INQA-Experimentierräume Diversität laufen von 2025 bis 2027. Kurz erklärt: So funktionieren die INQA-Experimentierräume. Seit dem Jahr 2017 hat das BMAS insgesamt 38 Projekte unterstützt: Siebzehn INQA-Experimentierräume Digitalisierung, die sich schwerpunktmäßig mit dem Wandel der Arbeitswelt durch die Digitalisierung beschäftigen, beispielsweise mit digitaler Unterstützung im Handwerksbereich oder im öffentlichen Nahverkehr."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/Lern-und-Experimentierraeume/lern-und-experimentierraeume.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:09.688659+00:00","lastSeen":"2026-03-15T16:32:09.688659+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/Lern-und-Experimentierraeume/lern-und-experimentierraeume.html","crawledAt":"2026-03-15T16:32:09.688659Z","crawlId":"contacts-seeded-1773592329","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"67de1ca8c7abf8a2a57cc8eac1b2568bdffb9c0295571c1413e2ab8bc5003e3d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:09.688659+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6e794488-09c6-4a4d-9fe2-ffae53e64479', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/Zukunftszentren/zukunftszentren.html', 'active', NULL, '2026-03-15T16:32:10.426265+00:00', '{"id":"6e794488-09c6-4a4d-9fe2-ffae53e64479","title":"BMAS - Zukunftszentren","summary":{"de":"Der Schwerpunkt der \"Zukunftszentren\" liegt auf der Befähigung von Unternehmen und deren Beschäftigten sowie von (Solo-)Selbstständigen, den demografischen, digitalen und ökologischen Wandel zu gestalten. Mit den \"Zukunftszentren\" legt das Bundesministerium für Arbeit und Soziales ( BMAS ) den Fokus darauf, KMU zu beraten und zu vernetzen sowie innovative Konzepte zur Weiterbildung im Betrieb zu entwickeln und erproben. Weiterhin sollen Einführungs- und Anwendungsprozesse von digitalen Technologien und KI -basierten Systemen partizipativ, das heißt gemeinsam mit den Beschäftigten, gestaltet werden."},"content":{"de":"In Folge 1 des Podcasts „Zukunftsmusik“ ist Dr. Gunilla Fincke, Abteilungsleiterin für Qualifizierung, Aus- und Weiterbildung sowie Fachkräftesicherung des BMAS, zu Gast. Sie erklärt, was die Zukunftszentren ausmacht. Wie KMU vom Informations-, Beratungs- und Qualifizierungsangebot der \"Zukunftszentren\" profitieren, zeigen die nachfolgenden Praxisbeispiele. Mit Hilfe des Regionalen Zukunftszentrums \" Zentrum Digitale Transformation Thüringen \" (ZeTT) führte die asphericon GmbH aus Jena Virtual Reality ein, um Quereinsteiger*innen für komplexe Tätigkeiten zu schulen und so neue Fachkräfte für das Unternehmen schnell und individuell zu qualifizieren. Überwachende Routinetätigkeiten in der Produktion durch Künstliche Intelligenz bewerkstelligen – diesen Schritt ist die Kudernak GmbH in Südhessen gegangen. Das Familienunternehmen hat gemeinsam mit dem \"Zukunftszentrum für menschenzentrierte KI in der Produktionsarbeit\" ( ZUKIPRO ) Herstellungsprozesse durch den Einsatz von Künstlicher Intelligenz effizienter und sicherer machen können. Das \"Zukunftszentrum Mecklenburg-Vorpommern\" ( ZMV+ ) begab sich gemeinsam mit der Dröge GmbH auf \" Transformationsreise Wirtschaft \". Das Unternehmen für Landwirtschafstechnik konnte durch die Unterstützung des geförderten Projektes nachhaltige Produkte vor allem im Bereich Tierwohl im Geschäftsmodell aufnehmen. Die \"Transformationsreise Wirtschaft\" ist ein Angebot des ZMV+ in Kooperation mit der Initiative Zukunftshandeln. Mehr Zeit für Kund*innen durch weniger Telefonate – das konnte das Unternehmen Gutsmann Friseure in Dresden mit der Einführung einer Online-Terminbuchung erreichen. Das \"Zukunftszentrum Sachsen\" unterstützte den Friseursalon bei der Suche und Einrichtung einer geeigneten Softwarelösung und schulte die Mitarbeiterinnen für eine sichere Bedienung im Arbeitsalltag."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/Zukunftszentren/zukunftszentren.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:10.426265+00:00","lastSeen":"2026-03-15T16:32:10.426265+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/Zukunftszentren/zukunftszentren.html","crawledAt":"2026-03-15T16:32:10.426265Z","crawlId":"contacts-seeded-1773592330","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"0c9117382fb9e4ae7650a6340d20ea6484ba1c49853f260a6087912a7635893e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:10.426265+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5cfe951f-eff7-4fed-9912-de436a33371a', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/fachkraeftesicherung-in-der-praxis.html', 'active', NULL, '2026-03-15T16:32:10.963593+00:00', '{"id":"5cfe951f-eff7-4fed-9912-de436a33371a","title":"BMAS - Fachkräftesicherung in der Praxis","summary":{"de":"Projekte und Initiativen des BMAS stellen sich vor"},"content":{"de":"Das BMAS fördert Projekte in Betrieben, um Veränderungen zu erproben. Denn ob Digitalisierung, Fachkräftesicherung oder eine neue Arbeits- und Führungskultur: Der Veränderungsdruck in Betrieben, Wirtschaft und Gesellschaft ist spürbar, aber auch gestaltbar. Unternehmen und Beschäftigte sollen unterstützt werden, die aktuellen und zukünftigen Herausforderungen, insbesondere durch den digitalen Wandel der Arbeitswelt, zu bewältigen. Dazu gehört auch (weiterhin) eine gute Arbeitsqualität zu sichern und ihre Erkenntnisse (\"best practice\") für die breite betriebliche Praxis sicht- und nutzbar zu machen. Das Bundesministeriums für Arbeit und Soziales nutzt diesen betriebsbezogenen Diskurs, um daraus Handlungsempfehlungen und politischen Handlungsbedarf zur Gestaltung der Arbeit der Zukunft abzuleiten. Die folgenden vier Projekte fördern Vernetzung und Austausch und die Entwicklung von Lösungsmöglichkeiten für den Wandel der Arbeitswelt."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/fachkraeftesicherung-in-der-praxis.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:10.963593+00:00","lastSeen":"2026-03-15T16:32:10.963593+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftesicherung-in-der-Praxis/fachkraeftesicherung-in-der-praxis.html","crawledAt":"2026-03-15T16:32:10.963593Z","crawlId":"contacts-seeded-1773592330","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"267b799901a3f06984d39962244f1433e5e59856284b453650af9845dede3368"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:10.963593+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fdc292da-4603-4293-b848-0e63db0e2674', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftestrategie/fachkraeftestrategie.html', 'active', NULL, '2026-03-15T16:32:11.612333+00:00', '{"id":"fdc292da-4603-4293-b848-0e63db0e2674","title":"Fachkräftestrategie der Bundesregierung","summary":{"de":"Eine Strategie für Fachkräfte und Beschäftigte"},"content":{"de":"Dieses vom BMAS entwickelte Impulspapier soll als inhaltliche Grundlage für die weiteren Diskussionen dienen, den geplanten Prozess skizzieren und die Debatte strukturieren. Deutschland braucht nicht nur viele, sondern auch gut qualifizierte Fachkräfte. Nur so kann sichergestellt werden, dass unser Sozialsystem auch in Zukunft nachhaltig funktioniert. Ebenso ist es aus verschiedenen Gründen der sinnvollste Weg, um Herausforderungen wie Klimaschutz, Digitalisierung und demografischen Wandel zu meistern. Um genügend Fachkräfte sichern zu können, sind einige Herausforderungen zu überwinden. Zum Beispiel ein Phänomen, das \"Fachkräfteparadox\" genannt wird und stetig wächst. Der Strukturwandel von der traditionellen zur digitalen Gesellschaft führt dazu, dass ein Ungleichgewicht auf dem Arbeitsmarkt entsteht. Das heißt: In einigen Branchen und Regionen gibt es zu wenige Fachkräfte, in anderen zu wenige Jobs. Erschwerend dazu kommt der demografische Wandel. Immer mehr Arbeitskräfte verschwinden vom Markt und der internationale Wettbewerb um gut qualifizierten Ersatz nimmt zu. Auch lange andauernde Krisen wie Covid-19 oder der Krieg gegen die Ukraine spielen eine große Rolle. Ihre Folgen für den Arbeitsmarkt sind oft noch nicht abzusehen. Unter Federführung des BMAS haben alle Ressorts und zahlreiche Beauftragte der Bundesregierung zusammengearbeitet, um die Fachkräftestrategie neu aufzustellen. Das Ergebnis wurde beim Fachkräftegipfel am 7. September 2022 mit führenden Vertretern von Gewerkschaften, Arbeitgeberverbänden, Kammern (wie Handwerk oder Handel), Ländern, Kommunen und der Bundesagentur für Arbeit diskutiert. Mit Erfolg: Am 12. Oktober 2022 hat die Bundesregierung die neue Fachkräftestrategie beschlossen. Die Herausforderungen für die Fachkräftesicherung und den Arbeitsmarkt in Deutschland sind gewachsen. Die Publikation liefert detaillierte Informationen über die Fachkräftesicherung, Chancen und Herausforderungen des Standortes Deutschland sowie prioritäre Handlungsfelder für den deutschen Arbeitsmarkt."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftestrategie/fachkraeftestrategie.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:11.612333+00:00","lastSeen":"2026-03-15T16:32:11.612333+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Fachkraeftestrategie/fachkraeftestrategie.html","crawledAt":"2026-03-15T16:32:11.612985Z","crawlId":"contacts-seeded-1773592331","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"fa275cbf507671c670f02a8b1421bb5d048d8c2dafd4586cdd5aaa934a533aa5"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T16:32:11.612985+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e43c30f8-3284-4849-bf31-025565e94d77', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Regionale-Fachkraeftewerkstaetten/regionale-fachkraeftewerkstaetten.html', 'active', NULL, '2026-03-15T16:32:12.864594+00:00', '{"id":"e43c30f8-3284-4849-bf31-025565e94d77","title":"Regionale Fachkräftewerkstatt 2026","summary":{"de":"Mit den Regionalen Fachkräftewerkstätten treten wir in den Austausch mit Ländern, betrieblicher Praxis und regionalen Arbeitsmarktakteuren vor Ort."},"content":{"de":"Die Sicherung von Fachkräften ist eine Frage der sozialen Verantwortung und ein entscheidender Faktor für den wirtschaftlichen Erfolg unseres Landes. Diese Verantwortung nehmen viele Menschen in den Regionen Deutschlands mit großem Engagement wahr – in Betrieben, Netzwerken, Organisationen und in gelebter Sozialpartnerschaft. Dieses Engagement und die vielen lokalen Lösungen wollen wir mit Regionalen Fachkräftewerkstätten sichtbar machen und die bundesweite Vernetzung fördern. Ich bin allen Beteiligten für Ihren Einsatz zur Sicherung von Fachkräften, insbesondere durch soziale und nachhaltige Arbeitsbedingungen, sehr dankbar. Sie sind mit ihren Ideen und Angeboten gute Beispiele in den Regionen und darüber hinaus. Dieses vom BMAS entwickelte Impulspapier soll als inhaltliche Grundlage für die weiteren Diskussionen dienen, den geplanten Prozess skizzieren und die Debatte strukturieren. Die Regionalen Fachkräftewerkstätten finden an verschiedenen Standorten in Deutschland statt. An dem Fachdialog nehmen Mitarbeitende des gastgebenden Unternehmens, Mitglieder von Netzwerken und Vertretungen des Bundesministeriums für Arbeit und Soziales, der Landespolitik sowie der regionalen Wirtschaft teil. Die erste Regionale Fachkräftewerkstatt fand am 12. März 2026 beim Triebwerkshersteller Rolls Royce statt. Für 2026 sind noch weitere Regionale Fachkräftewerkstätten geplant. Melden Sie sich gerne für unseren Haupt-Newsletter des Hauses an und bleiben Sie informiert!"},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Regionale-Fachkraeftewerkstaetten/regionale-fachkraeftewerkstaetten.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:12.864594+00:00","lastSeen":"2026-03-15T16:32:12.864594+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/Regionale-Fachkraeftewerkstaetten/regionale-fachkraeftewerkstaetten.html","crawledAt":"2026-03-15T16:32:12.865598Z","crawlId":"contacts-seeded-1773592332","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"e6d65c36050a67e896c7b5f726ebf8b0fe8ad35166b871dd9e3dba374a99255b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:12.865598+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('178e9b22-2965-4d09-8b78-2fea1dc78982', 'contacts', 'https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/fachkraeftesicherung.html', 'active', NULL, '2026-03-15T16:32:13.712782+00:00', '{"id":"178e9b22-2965-4d09-8b78-2fea1dc78982","title":"Fachkräfteland Deutschland","summary":{"de":"Im Oktober 2022 hat die Bundesregierung eine neue Strategie zur Fachkräftesicherung vorgestellt. Erfahren Sie hier mehr zur Umsetzung entsprechender Gesetze, Vorhaben und Projekte."},"content":{"de":"Unsere Maßnahmen und Vorhaben der Fachkräftesicherung Im Oktober 2022 hat die Bundesregierung eine neue Strategie zur Fachkräftesicherung vorgestellt. Sie ist die Grundlage aller politischen Vorhaben und Neuregelungen für das Fachkräfteland Deutschland. Das Bundesministerium für Arbeit und Soziales hatte bei der Entwicklung der Strategie die Federführung inne und ging auch bei der Umsetzung mit Gesetzen, Vorhaben und Projekten voran. Wie gelingt Fachkräftesicherung vor Ort? Mit dem Dialogformat nehmen wir erfolgreiche Lösungswege und Herausforderungen in den Blick. Die ressortübergreifende Strategie beleuchtet fünf Handlungsfelder, in denen Potenziale für die Fachkräftegewinnung und -sicherung bestehen. Das BMAS unterstützt den Transfer von Erkenntnissen zur Gestaltung guter Arbeit in die betriebliche Praxis - und nimmt fortwährend Impulse zur Gestaltung guter Politik auf."},"url":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/fachkraeftesicherung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:13.712782+00:00","lastSeen":"2026-03-15T16:32:13.712782+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Fachkraeftesicherung/fachkraeftesicherung.html","crawledAt":"2026-03-15T16:32:13.713853Z","crawlId":"contacts-seeded-1773592333","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"2e2af30d10ae4614415085cabad674e9828af99577c748eb7f6c73a03f158d0c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:13.713853+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5dc1cde2-e8ce-4830-a420-41a76313bf06', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Anerkennung-Ihrer-Qualifikationen/anerkennung-ihrer-qualifikationen.html', 'active', NULL, '2026-03-15T16:32:14.349472+00:00', '{"id":"5dc1cde2-e8ce-4830-a420-41a76313bf06","title":"Anerkennung Ihrer Qualifikationen","summary":{"de":"Mit einem Berufsabschluss oder einem Schul- oder Hochschulabschluss haben Sie mehr Chancen auf gute Arbeit. Hier erfahren Sie, wie in Deutschland Ihre Qualifikation überprüft und anerkannt wird."},"content":{"de":"Haben Sie im Ausland eine Berufsausbildung oder ein Studium abgeschlossen, können Sie Ihre Qualifikation in Deutschland anerkennen lassen. Die Bundesregierung hat deshalb das sogenannte Anerkennungsgesetz (\"Gesetz zur Verbesserung der Feststellung und Anerkennung im Ausland erworbener Berufsqualifikationen\") zur Vereinfachung geschaffen. Das Gesetz schafft für alle bundesrechtlich geregelten Berufe möglichst einheitliche und transparente Verfahren. So kann die Gleichwertigkeit des ausländischen Berufsabschlusses mit dem deutschen Abschluss ermittelt werden. Dies ist in vielen Berufen Voraussetzung dafür, in diesem Beruf zu arbeiten oder sich selbständig zu machen. Das gilt vor allem für die reglementierten Berufe, so im zulassungspflichtigen Handwerk, für Ärztinnen und Ärzte, Krankenpflegerinnen und -pfleger oder Apothekerinnen und Apotheker. Wenn Sie sich noch im Ausland aufhalten, steht Ihnen die Hotline \"Arbeiten und Leben in Deutschland\" auch für Fragen zur Anerkennung Ihrer Qualifikationen zur Verfügung. Die Hotline verweist Sie ggf. für eine vertiefte Beratung und Unterstützung im Anerkennungsverfahren an die Zentrale Servicestelle Berufsanerkennung (ZSBA). Wenn Sie schon in Deutschland sind, wenden Sie sich zuallererst an Ihre Bundesagentur für Arbeit bzw. Ihr Jobcenter. Dort werden Sie hinsichtlich Ihrer Qualifikationen und dem deutschen Arbeitsmarkt beraten. Ihre Beraterin oder Ihr Berater verweist Sie bei konkreten Fragen an die Anlaufstellen des Netzwerks „Integration durch Qualifizierung – IQ“. Diese bieten in allen Bundesländern auf regionaler Ebene Beratung für Anerkennungssuchende an. Der Bund fördert diese Beratung im Rahmen des Förderprogramms \"Integration durch Qualifizierung – IQ\", das vom Bundesministerium für Arbeit und Soziales sowie dem Europäischen Sozialfonds gefördert und in Kooperation mit dem Bundesministerium für Bildung und Forschung sowie der Bundesagentur für Arbeit umgesetzt wird. Ein Anerkennungsverfahren nach dem Anerkennungsgesetz ist nur für berufliche Abschlüsse möglich. Das Verfahren beginnt mit einem Antrag auf die Prüfung der Gleichwertigkeit einer ausländischen Berufsqualifikation. Der Antrag wird bei der für den jeweiligen Beruf zuständigen Anerkennungsstelle eingereicht. Je nach Bundesland und Beruf sind unterschiedliche Stellen für die Überprüfung der Gleichwertigkeit zuständig. Im Ausland erworbene Schulabschlüsse können unter bestimmten Voraussetzungen einem deutschen Schulabschluss gleichgestellt werden. Hierüber entscheiden die Zeugnisanerkennungsstellen der Länder."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Anerkennung-Ihrer-Qualifikationen/anerkennung-ihrer-qualifikationen.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:14.349472+00:00","lastSeen":"2026-03-15T16:32:14.349472+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Anerkennung-Ihrer-Qualifikationen/anerkennung-ihrer-qualifikationen.html","crawledAt":"2026-03-15T16:32:14.349472Z","crawlId":"contacts-seeded-1773592334","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"4e0610fd4269f59e8b73a341e669691c2c1e6edbc09674485a6d054661c60f91"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:14.349472+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d718d537-b603-4706-bb32-7488f3684224', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Deutsch-lernen-fuer-den-Beruf/deutsch-lernen-fuer-den-beruf.html', 'active', NULL, '2026-03-15T16:32:14.945162+00:00', '{"id":"d718d537-b603-4706-bb32-7488f3684224","title":"Deutsch lernen für den Beruf","summary":{"de":"Das Erlernen der deutschen Sprache ist Voraussetzung, um möglichst schnell in Deutschland Fuß zu fassen. Hier erfahren Sie, wo Sie Hilfe zum Spracherwerb erhalten."},"content":{"de":"Das Erlernen der deutschen Sprache ist für die meisten Zugewanderten in Deutschland der erste Schritt und die wichtigste Voraussetzung für eine erfolgreiche Integration in Gesellschaft und Arbeit. Mit dem Gesamtprogramm Sprache hat die Bundesregierung deshalb im Inland ein flächendeckend ausgebautes, ausdifferenziertes und zugleich kohärentes Angebot der Deutschsprachförderung geschaffen. Es richtet sich an Neuzugewanderte aus Drittstaaten und der EU ebenso wie an Migrantinnen und Migranten, die bereits länger in Deutschland leben, an Spätaussiedlerinnen und Spätaussiedler sowie Deutsche mit Migrationshintergrund und Sprachförderbedarf. Das Gesamtprogramm Sprache besteht aus einem modularen Angebot für verschiedene Zielgruppen mit dem Basisangebot der bereits 2005 eingeführten Integrationskurse und den darauf aufbauenden Kursen der berufsbezogenen Deutschsprachförderung, die Mitte 2016 in den Strukturen der Regelförderung etabliert wurden. Für die Integrationskurse ist das Bundesministerium des Innern, für Bau und Heimat und für die berufsbezogene Deutschsprachförderung das Bundesministerium für Arbeit und Soziales zuständig. Beide Sprachförderangebote werden vom Bundesamt für Migration und Flüchtlinge (BAMF) administriert. Das Ziel aller Angebote des Gesamtprogramms ist die bestmögliche Förderung der Teilnahmeberechtigten beim Erlernen der deutschen Sprache. Je nach Vorkenntnissen und individuellem Lernfortschritt ist eine durchgehende Förderung bis C1 (nach dem gemeinsamen europäischen Referenzrahmen GER) und künftig auch bis zur kompetenten Sprachbeherrschung möglich, die dem Sprachniveau C2 des GER entspricht. Das Ziel der Integrationskurse ist die Vermittlung von Sprachkenntnissen auf dem Niveau B1 GER sowie von Kenntnissen der Rechtsordnung, der Kultur und Geschichte der Bundesrepublik. Diese Kenntnisse sollen die Kursteilnehmenden in die Lage versetzen, eigenständig im Alltag zu agieren. Der allgemeine Integrationskurs umfasst in der Regel 600 Unterrichtseinheiten im Sprachkurs und zusätzlich 100 Unterrichtseinheiten im Orientierungskurs. Daneben gibt es spezielle Integrationskurse mit einem Umfang von bis zu 900 Unterrichtseinheiten im Sprachkurs für Analphabetinnen und Analphabeten, Zweitschriftlernende, Jugendliche, Eltern und Frauen sowie für Teilnehmende mit Behinderungen. Viele Integrationskurse finden zurzeit als Alphabetisierungskurse statt. Bei diesen Kursen geht das Curriculum bereits konzeptuell von einem Kursergebnis auf dem Sprachniveau A2 aus. Nähere Informationen erhalten Sie direkt von der Ausländerbehörde Ihres Aufenthaltsorts, von der Bundesagentur für Arbeit oder Ihrem Jobcenter."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Deutsch-lernen-fuer-den-Beruf/deutsch-lernen-fuer-den-beruf.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:14.945162+00:00","lastSeen":"2026-03-15T16:32:14.945162+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Deutsch-lernen-fuer-den-Beruf/deutsch-lernen-fuer-den-beruf.html","crawledAt":"2026-03-15T16:32:14.945162Z","crawlId":"contacts-seeded-1773592334","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"0ab14bdd13109043c61557e9d32eb9108666313e1e66da0458c1e8ded5c79ec2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:14.945162+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('893ec06d-ecbc-4a99-b377-ee2396bda168', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Erlangen-einer-Qualifikation/erlangen-einer-qualifikation.html', 'active', NULL, '2026-03-15T16:32:15.696699+00:00', '{"id":"893ec06d-ecbc-4a99-b377-ee2396bda168","title":"Erlangen einer Qualifikation","summary":{"de":"Berufe in Deutschland verlangen eine Berufs- oder Hochschulausbildung. Dafür gibt es viele Möglichkeiten, sich weiterzubilden."},"content":{"de":"Eine schulische Ausbildung können Sie in Deutschland jederzeit beginnen. Eine Berufsausbildung in einem Betrieb in Deutschland ist möglich, wenn ein Arbeitsmarktzugang besteht. Mit einer Aufenthaltsgestattung oder Duldung, bei der die Beschäftigung nicht untersagt ist, brauchen Sie dazu die Erlaubnis der Ausländerbehörde. Als anerkannter Flüchtling oder Asylberechtigter können Sie direkt loslegen. Berufsausbildungen in Betrieben erfolgen in Deutschland dual, das bedeutet dass sich praktische Phasen in einem Unternehmen und schulischer Unterricht abwechseln. Daher müssen Sie sich auf Ausbildungsstellen bei Unternehmen bewerben. Dafür erhalten Sie aber Unterstützung von den Agenturen für Arbeit oder Jobcentern. Weitere Informationen erhalten Sie unter Unterstützung erhalten. Die Agenturen für Arbeit und die Jobcenter können Sie zur Vorbereitung auf eine Berufsausbildung und während einer Berufsausbildung in einem Betrieb unterstützen. Die Förderung von Berufsausbildung und Berufsausbildungsvorbereitung im SGB III und SGB II war bislang für Ausländerinnen und Ausländer deutlich eingeschränkt. Sie knüpfte beispielsweise an Voraussetzungen wie Staatsangehörigkeit, Aufenthaltsstatus oder Voraufenthaltszeiten an. Durch das Ausländerbeschäftigungsförderungsgesetz ist seit 1. August 2019 die Förderung von Berufsausbildungsvorbereitung und einer betrieblichen Berufsausbildung weitgehend vom Aufenthaltsrecht entkoppelt und für Ausländerinnen und Ausländer weit geöffnet. Generelle Voraussetzung bleibt, dass Sie in Deutschland arbeiten. Wenn Sie sich gestattet oder geduldet hier aufhalten, ist die Berufsausbildungsvorbereitung allerdings auch weiterhin an Vorfristen geknüpft. Zudem war bisher der Lebensunterhalt für Gestattete und Geduldete bei einer Ausbildung oder einem Studium nicht durchgängig gesichert. Diese Förderlücke ist nun zum 1. September 2019 im Asylbewerberleistungsgesetz geschlossen worden, so dass die Aufnahme einer betrieblichen oder schulischen Ausbildung oder eines Studiums nun nicht mehr am fehlenden Lebensunterhalt scheitert. Geduldete bleiben häufig langjährig in Deutschland und integrieren sich in dieser Zeit oftmals gut in den Arbeitsmarkt. Ab 1. Januar 2020 gelten einfachere Voraussetzungen für den Erwerb einer Duldung bei Ausbildung und Beschäftigung. Eine bundeseinheitliche Praxis soll zu mehr Rechtssicherheit führen."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Erlangen-einer-Qualifikation/erlangen-einer-qualifikation.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:15.696699+00:00","lastSeen":"2026-03-15T16:32:15.696699+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Erlangen-einer-Qualifikation/erlangen-einer-qualifikation.html","crawledAt":"2026-03-15T16:32:15.696699Z","crawlId":"contacts-seeded-1773592335","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"568b62966f0d99a54842f2ee114ce187c4cfcd0cf7f2c8fdee8511ed12a00795"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:15.696699+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9923574a-7f72-4d12-8ec8-4faf766054dc', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Foerderprogramm-IQ/foerderprogramm-iq.html', 'active', NULL, '2026-03-15T16:32:16.370936+00:00', '{"id":"9923574a-7f72-4d12-8ec8-4faf766054dc","title":"Förderprogramm \"Integration durch Qualifizierung","summary":{"de":"Als ein zentrales arbeitsmarktpolitisches Instrument der Bundesregierung hat sich das vom Bundesministerium für Arbeit und Soziales initiierte durchgeführte „Förderprogramm-IQ Integration durch Qualifizierung\" (nachfolgend Förderprogramm -IQ) etabliert. Das Förderprogramm- IQ dient zur Verbesserung der nachhaltigen und bildungsadäquaten Integration von erwachsenen Menschen ausländischer Herkunft und ausländischer Berufsqualifikation in den Arbeitsmarkt. Nach seinem erfolgreichen Verlauf in der ESF-Förderperiode 2014 bis 2020 und vor dem Hintergrund der zunehmenden beruflichen Passungsprobleme am Arbeitsmarkt, wird das Programm in der ESF Plus-Förderperiode 2021 bis 2027 weiterentwickelt. Zur nachhaltigen Stärkung der Fachkräftegewinnung und -sicherung in Deutschland knüpft das Programm an den bisher erzielten Ergebnissen an und entwickelt inhaltlich neue Konzepte und Lösungen. IQ wird durch das Bundesministerium für Arbeit und Soziales (BMAS) und die Europäische Union über den ESF Plus in zwei Förderrunden – 2023 bis 2025 und 2026 bis 2028 – finanziert und vom Bundesamt für Migration und Flüchtlinge (BAMF) administriert. In der Förderrunde 2023 bis 2025 arbeiten bundesweit rund 270 Teilvorhaben an der Zielsetzung. Zu den teilnehmerbezogenen Angeboten für die Menschen ausländischer Herkunft berät das Förderprogramm-IQ bundesweit in 60 Anerkennungs- und Qualifizierungsberatungsstellen, sowie in 16 Beratungsstellen zu Fairer Integration. In 23 Regionalen Integrationsnetzwerken werden Qualifizierungsbegleitungen, Anpassungsqualifizierungen, Coaching und Begleitung, Kompetenzfeststellung angeboten. Für KMU und andere Arbeitsmarktakteure finden Beratungen, Schulungen, Veranstaltungen und andere Austauschformaten statt. Partner in der Umsetzung des Förderprogramms-IQ sind das Bundesministerium für Bildung und Forschung (BMBF) und die Bundesagentur für Arbeit (BA)."},"content":{"de":"Für nähere Informationen siehe auch: www.netzwerk-iq.de und www.esf.de. Ab­lauf des An­er­ken­nungs­ver­fah­rens nach Bun­des­recht [PDF, 524KB]"},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Foerderprogramm-IQ/foerderprogramm-iq.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:16.370936+00:00","lastSeen":"2026-03-15T16:32:16.370936+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Anerkennung-und-Qualifizierung/Foerderprogramm-IQ/foerderprogramm-iq.html","crawledAt":"2026-03-15T16:32:16.370936Z","crawlId":"contacts-seeded-1773592336","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"1cbdb1c5b90d7f531033e305e375d41cfcc4206edb5501063499d29b53584244"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T16:32:16.370936+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a0885ef6-ebe5-40a6-a5ce-e69fe1b4ae7e', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Arbeitsmarktzugang-fuer-Gefluechtete/arbeitsmarktzugang-fuer-gefluechtete.html', 'active', NULL, '2026-03-15T16:32:18.030837+00:00', '{"id":"a0885ef6-ebe5-40a6-a5ce-e69fe1b4ae7e","title":"Arbeitsmarktzugang für Geflüchtete","summary":{"de":"I.) Ein Arbeitsmarktzugang ist in folgenden Fällen grundsätzlich möglich"},"content":{"de":"Der Arbeitsmarktzugang von Schutzsuchenden bzw. Geflüchteten ist in den folgenden Fällen möglich, Voraussetzung ist jedoch grundsätzlich eine Arbeitserlaubnis (Weiteres hierzu siehe II ) II.) Erfordernis einer Arbeitserlaubnis für Asylbewerbende und Geduldete III. Änderungen bei der Beschäftigungsduldung und der Ausbildungsduldung/Einführung der Aufenthaltserlaubnis zur Berufsausbildung für ausreisepflichtige Ausländer und Ausländerinnen Auf der Website des Bundesamts für Migration und Flüchtlinge können Sie nach zuständigen Außenbehörden suchen und sich die Ergebnisse auf einer Deutschlandkarte anzeigen lassen. nach drei Monaten, wenn sie nicht zum Wohnen in einer Aufnahmeeinrichtung verpflichtet sind, nach sechs Monaten, wenn sie zum Wohnen in einer Aufnahmeeinrichtung verpflichtet sind."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Arbeitsmarktzugang-fuer-Gefluechtete/arbeitsmarktzugang-fuer-gefluechtete.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:18.030837+00:00","lastSeen":"2026-03-15T16:32:18.030837+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Arbeitsmarktzugang-fuer-Gefluechtete/arbeitsmarktzugang-fuer-gefluechtete.html","crawledAt":"2026-03-15T16:32:18.030837Z","crawlId":"contacts-seeded-1773592338","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c6967307db491576e43746cbdaa414b6fc1e01bd907d239258ec572cf25de81a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:18.031372+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('494f7004-55d7-49ea-9c6e-857421e50d42', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Der-Asylprozess-und-staatliche-Unterstuetzung/der-asylprozess-und-staatliche-unterstuetzung.html', 'active', NULL, '2026-03-15T16:32:18.786784+00:00', '{"id":"494f7004-55d7-49ea-9c6e-857421e50d42","title":"Der Asylprozess und staatliche Unterstützung","summary":{"de":"Der Asylantragsstatus ist wichtig für den Aufenthaltstitel, den Zugang zu Unterstützungsleistungen und den Arbeitsmarkt. Unter Umständen erhalten Sie Unterstützung bei der Sicherung des Lebensunterhalts. Welche rechtlichen Bestimmungen dafür zu Grunde liegen, erfahren Sie hier."},"content":{"de":"Nach Ankunft einer Asylbewerberin oder eines Asylbewerbers in Deutschland erfolgt so bald wie möglich die Registrierung und die Verteilung auf eine Aufnahmeeinrichtung. Nähere Angaben hierzu finden sich auf der Seite des Bundesamtes für Migration und Flüchtlinge (BAMF). Asylbewerberinnen und Asylbewerber erhalten Leistungen nach dem Asylbewerberleistungsgesetz (AsylbLG) und haben, solange sie verpflichtet sind, in der Aufnahmeeinrichtung zu wohnen, in der Regel nach neun Monaten einen Arbeitsmarktzugang (nach sechs Monaten, wenn sie minderjährige Kinder haben). Sofern keine Verpflichtung besteht, in einer Aufnahmeeinrichtung zu wohnen, besteht grundsätzlich bereits nach drei Monaten ein Arbeitsmarktzugang. Asylbewerberinnen und Asylbewerber mit guter Bleibeperspektive (ab dem 1. März 2021: Herkunftsländer Syrien, Eritrea und Somalia) können bereits in dieser Phase zur Teilnahme an Integrationskursen und Berufssprachkursen im Rahmen verfügbarer Plätze zugelassen werden. Auch Asylbewerberinnen und Asylbewerber mit unklarer Bleibeperspektive ( z.B. aus Afghanistan, Iran, Irak, Somalia) können an diesen Kursen teilnehmen, wenn sie vor dem 1. August 2019 eingereist sind und sich seit mindestens drei Monaten gestattet in Deutschland aufhalten. Gegebenenfalls erfolgt eine Kompetenzfeststellung über \" Early Intervention \". Nach der Registrierung und Verteilung wird der Antrag auf Asyl beim BAMF gestellt. Für Personen mit guter Bleibeperspektive sollen bereits frühzeitig erste Integrationsmaßnahmen beginnen (siehe oben). Für die Bearbeitung der Asylanträge ist das BAMF zuständig. Die Antragsstellenden erhalten während des Asylverfahrens Leistungen nach dem AsylbLG. Sofern sich im Asylverfahren ergibt, dass eine Schutzberechtigung besteht, erfolgt die Anerkennung der Schutzberechtigung durch das BAMF und die Ausstellung einer entsprechenden Aufenthaltserlaubnis durch die Ausländerbehörde. Mit Erteilung der Aufenthaltserlaubnis erhalten die Schutzberechtigten u. a. einen unbeschränkten Arbeitsmarktzugang. Ziel ist dabei, durch Sprachförderung und aktive Arbeitsmarktpolitik eine schnelle Arbeitsmarktintegration zu ermöglichen. Nach der Anerkennung als Asylberechtigte/r, Geflüchtete oder subsidiär Schutzberechtigte/r können die betroffenen Personen Leistungen nach dem Zweiten Buch Sozialgesetzbuch (SGB II) erhalten, soweit die Voraussetzungen im Einzelfall (insbesondere Erwerbsfähigkeit und Hilfebedürftigkeit) vorliegen. Sie können u. a. an einem Integrationskurs inklusive Sprachkurs teilnehmen. Liegen die Voraussetzungen des SGB II (insbesondere Erwerbsfähigkeit) nicht vor, kann u. U. ein Anspruch auf Sozialhilfe nach dem Zwölften Buch Sozialgesetzbuch (SGB XII) bestehen; diese ist beim lokal zuständigen Sozialamt zu beantragen. In Einzelfällen, z. B. während einer Berufsausbildung oder bei fehlender Hilfebedürftigkeit, bleiben die Agenturen für Arbeit zuständig für die Eingliederung in den Arbeitsmarkt. Bei Ablehnung des Asylantrags besteht eine Pflicht zur Ausreise. Die Vollstreckung der Ausreisepflicht kann durch eine Duldung befristet ausgesetzt werden, wenn ein Duldungsgrund (Abschiebehindernis wie z. B. Krankheit) vorliegt. Asylbewerberinnen und Asylbewerber, Geduldete sowie weitere vom AsylbLG umfasste Personengruppen erhalten in Deutschland Leistungen nach dem AsylbLG. Während der ersten 36 Monate haben sie dabei regelmäßig Anspruch auf eine Grundversorgung, die in der Erstaufnahmeeinrichtung beginnt. Im Anschluss entspricht die Versorgung bei der Hilfe zum Lebensunterhalt sowie bei der Hilfe zur Krankheit und Pflege grundsätzlich der Versorgung nach dem Zwölften Buch Sozialgesetzbuch (SGB XII)."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Der-Asylprozess-und-staatliche-Unterstuetzung/der-asylprozess-und-staatliche-unterstuetzung.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:18.786784+00:00","lastSeen":"2026-03-15T16:32:18.786784+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Der-Asylprozess-und-staatliche-Unterstuetzung/der-asylprozess-und-staatliche-unterstuetzung.html","crawledAt":"2026-03-15T16:32:18.786784Z","crawlId":"contacts-seeded-1773592338","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"7eda3a955c59b973e1348619741c80611fd85a0e9853e853cb10576ae40e5860"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:18.786784+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6e1f018e-e440-43b1-9adc-dd98ac2595c5', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/ESF-Plus-Programm-WIR/esf-plus-programm-wir.html', 'active', NULL, '2026-03-15T16:32:19.406386+00:00', '{"id":"6e1f018e-e440-43b1-9adc-dd98ac2595c5","title":"ESF-Plus Programm \"WIR\" für Geflüchtete","summary":{"de":"Das ESF- Plus Programm „WIR - Netzwerke integrieren Geflüchtete in den regionalen Arbeitsmarkt“ zielt darauf ab, Geflüchtete über einen längeren Zeitraum hinweg zu begleiten und bei ihrer Teilhabe am Arbeitsmarkt zu unterstützen. Zur Zielgruppe gehören Geflüchtete mit Aufenthaltserlaubnis, Personen mit Aufenthaltsgestattung sowie Personen mit einer Duldung, die keinem absoluten Arbeitsverbot unterliegen. Besondere Berücksichtigung sollen Personen mit Beeinträchtigung oder Behinderung sowie mit fluchtspezifischen Folgeerkrankungen finden."},"content":{"de":"Ziel des Programms \"WIR - Netzwerke integrieren Geflüchtete in den regionalen Arbeitsmarkt\" ist die Unterstützung von Geflüchteten bei ihrer Teilhabe am Arbeitsmarkt in Deutschland. Insgesamt 41 Projektverbünde arbeiten an der Erreichung dieser Ziele und haben u.a. diese Angebote parat: Maßnahmen zur Arbeitsmarktintegration mit dem Ziel der Aufnahme einer Beschäftigung und/oder Ausbildung; Maßnahmen für die Begleitung des Übergangs von der Schule in den Beruf Maßnahmen zur Förderung der Beschäftigungsfähigkeit Hierunter fallen beispielsweise arbeitsmarktbezogene Beratung und Berufsorientierung, Unterstützung beim Zugang zu den Leistungen des regulären Hilfesystems, bei Bedarf individuell erforderliche Qualifizierungsmaßnahmen, die Vermittlung von Praktika und Ähnliches. Ein besonderes Augenmerk soll dabei auf die langfristige Begleitung und Beratung der Teilnehmenden gelegt werden, auch nach Aufnahme einer Arbeit oder Ausbildung. Dieser präventive Ansatz soll die Nachhaltigkeit der Arbeitsmarktintegration sichern. Optional können auch weitere Familienmitglieder mit in die Beratung einbezogen werden."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/ESF-Plus-Programm-WIR/esf-plus-programm-wir.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:19.406386+00:00","lastSeen":"2026-03-15T16:32:19.406386+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/ESF-Plus-Programm-WIR/esf-plus-programm-wir.html","crawledAt":"2026-03-15T16:32:19.407392Z","crawlId":"contacts-seeded-1773592339","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"936ee19691046dd88cdd7a14fb0ad8a540a7d0e4d39e3b886d772b256364391a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:19.407392+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8751c823-4378-44e2-aa3d-5996b1243d83', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Turbo-zur-Arbeitsmarktintegration-von-Gefluechteten/turbo-zur-arbeitsmarktintegration-von-gefluechteten.html', 'active', NULL, '2026-03-15T16:32:20.213600+00:00', '{"id":"8751c823-4378-44e2-aa3d-5996b1243d83","title":"Job-Turbo zur Arbeitsmarktintegration von Geflüchteten","summary":{"de":"Sofortiger Arbeitsmarktzugang und intensive Integrationskurse zur Vermeidung von Arbeitslosigkeit"},"content":{"de":"Deutschland hat aus den Erfahrungen mit früheren Migrationsbewegungen gelernt. Um Integrationsverläufe zu beschleunigen, setzt das BMAS mit dem Job-Turbo nun weitere Maßnahmen um. Deutschland hat in den vergangenen anderthalb Jahren bei der Aufnahme schutzsuchender Menschen, vorrangig aus der Ukraine, Herausragendes geleistet. Ukrainische Geflüchtete haben auf Grundlage europäischer Beschlüsse sofortigen Zugang zum Arbeitsmarkt. Mit dem Zugang zum SGB II profitierten Geflüchtete von der umfassenden Unterstützung und Aktivierung durch die Jobcenter (Informationen, Zusteuerung in Deutschkurse, Vermittlung und arbeits­marktpolitische Förderleistungen). Das Integrationskurssystem konnte in kurzer Zeit enorm ausgeweitet werden. In letzter Zeit haben allein 100.000 Ukrainerinnen und Ukrainer den Integrationskurs abgeschlossen, weitere 100.000 werden dies in den kommenden Monaten tun. Das BMAS und die Bundesagentur für Arbeit setzen deshalb die folgenden Maßnahmen um, mit dem Ziel, die Integrationsverläufe für Geflüchtete zu beschleunigen. Der typische Integrationsverlauf folgt einem \"Drei-Phasen-Modell\"."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Turbo-zur-Arbeitsmarktintegration-von-Gefluechteten/turbo-zur-arbeitsmarktintegration-von-gefluechteten.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:20.213600+00:00","lastSeen":"2026-03-15T16:32:20.213600+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/Turbo-zur-Arbeitsmarktintegration-von-Gefluechteten/turbo-zur-arbeitsmarktintegration-von-gefluechteten.html","crawledAt":"2026-03-15T16:32:20.213600Z","crawlId":"contacts-seeded-1773592340","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"c7b609ab87a2efa47b8d39d8c08a3739da73dcb0a7c8d512d8c4064934c378b7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:20.213600+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('076300e5-6ca8-4664-a01c-b8711364eebf', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/flucht-und-asyl.html', 'active', NULL, '2026-03-15T16:32:20.815755+00:00', '{"id":"076300e5-6ca8-4664-a01c-b8711364eebf","title":"Flucht und Asyl","summary":{"de":"Auf dieser Seite finden Sie weitere Informationen zu Asylverfahren und Arbeitsmarktintegration"},"content":{"de":"Um Integrationsverläufe in den Arbeitsmarkt weiter zu beschleunigen, setzt das BMAS mit dem \"Turbo zur Arbeitsmarkt­integration\" nun weitere Maßnahmen um, die wir auf dieser Seite näher erläutern. Das BMAS hilft Menschen, die im Zuge des Krieges nach Deutschland geflüchtet sind, bei den Themen Arbeit und Soziale Sicherung."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/flucht-und-asyl.html","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:32:20.815755+00:00","lastSeen":"2026-03-15T16:32:20.815755+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Flucht-und-Aysl/flucht-und-asyl.html","crawledAt":"2026-03-15T16:32:20.816754Z","crawlId":"contacts-seeded-1773592340","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"5667a1206f1a9f3a5ae3bff725cd113b6ef3df26930feb629c871900f0e86125"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:32:20.816754+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0795113e-5d9e-49dd-920c-9aa7ea4e543a', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Arbeitsvermittlung-aus-dem-Ausland/arbeitsvermittlung-aus-dem-ausland.html', 'active', NULL, '2026-03-15T17:47:06.662287+00:00', '{"id":"0795113e-5d9e-49dd-920c-9aa7ea4e543a","title":"Arbeitsvermittlung aus dem Ausland","summary":{"de":"Das Online-Portal \" Make it in Germany \" ist fester Bestandteil der Maßnahmen der Bundesregierung zur Steigerung der Fachkräfteeinwanderung. Seit Juni 2012 informiert \" Make it in Germany \" Fachkräfte aus dem Ausland über das Arbeiten und Leben in Deutschland. Seit November 2018 ist es das gemeinsame Dach-Portal der Bundesregierung zur Information von Fachkräften aus dem Ausland."},"content":{"de":"Für Unionsbürgerinnen und Unionsbürger gibt es darüber hinaus das EURES-Portal. Hier können Unionsbürgerinnen und Unionsbürger ihre Bewerbung hochladen und europaweit nach Stellen suchen. EURES ( European Employment Services ) ist das Kooperationsnetz der Europäischen Kommission, der öffentlichen Arbeitsverwaltungen der EWR -Mitgliedstaaten ( EU -Mitgliedstaaten plus Norwegen, Island und Liechtenstein), der Schweiz und anderen Partnerorganisationen. Rund 1.000 Beraterinnen und Berater unterstützen alle Bürgerinnen und Bürger, die vom Recht auf Freizügigkeit Gebrauch machen möchten und helfen Arbeitgebern bei der Vermittlung entsprechender Arbeitskräfte. Das Online-Portal \" Make it in Germany \" informiert Fachkräfte aus dem Ausland (Drittstaaten und Mitgliedsstaaten der Europäischen Union) über das Arbeiten und Leben in Deutschland. Unternehmen finden auf dem Portal Informationen zur Suche von ausländischen Fachkräften und deren Einstellung. Zusätzliche Dienstleistungen von Kooperationspartnern zur Beratung, wie der Hotline \"Arbeiten und Leben in Deutschland\", Chats und der Jobbörse, erweitern das Angebot von \" Make it in Germany \". Das Portal ist auch in englischer, spanischer und französischer Sprache verfügbar. Daneben gibt es noch Informationsseiten auf weiteren Sprachen. Neben der Recherche in Zeitungen und im Internet können Interessentinnen und Interessenten die Informationsangebote der Bundesagentur für Arbeit und des Kooperationsnetzes EURES (für Unionsbürgerinnen und Unionsbürger) nutzen. Diese bieten folgende Möglichkeiten für die Suche nach einer Beschäftigung auf dem deutschen Arbeitsmarkt: Ein erster Anlaufpunkt für arbeitsuchende Unionsbürgerinnen und Unionsbürger ist die EURES-Beratung im Herkunftsland. EURES ist das Kooperationsnetz der Europäischen Kommission, der öffentlichen Arbeitsverwaltungen der EWR-Mitgliedstaaten (EU-Mitgliedstaaten plus Norwegen, Island und Liechtenstein) und anderen Partnerorganisationen. EURES verfügt europaweit über rund 1.000 Beraterinnen und Berater, die Informationen, Beratung und Vermittlung für Arbeitskräfte und Arbeitgeber sowie generell für alle Bürgerinnen und Bürger anbieten, die vom Recht auf Freizügigkeit Gebrauch machen möchten. Das Dienstleistungsangebot wurde auf der EURES-Homepage zusammengestellt. Für die grenzüberschreitende Arbeitsvermittlung ist bei der Bundesagentur für Arbeit die Zentrale Auslands- und Fachvermittlung (ZAV) zuständig. Die ZAV hat auf ihrer Homepage für Arbeitskräfte aus dem Ausland (auch Drittstaaten), die in Deutschland arbeiten wollen, umfangreiche Hinweise zusammengestellt. Die Bundesagentur für Arbeit hat auf ihrer Homepage das Portal \" JOBBÖRSE \" eingerichtet. Hier können in- und ausländische Arbeitsuchende nach veröffentlichten Stellenangeboten von Arbeitgebern aus Deutschland recherchieren und ein eigenes Bewerberprofil einstellen."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Arbeitsvermittlung-aus-dem-Ausland/arbeitsvermittlung-aus-dem-ausland.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:06.662287+00:00","lastSeen":"2026-03-15T17:47:06.662287+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Arbeitsvermittlung-aus-dem-Ausland/arbeitsvermittlung-aus-dem-ausland.html","crawledAt":"2026-03-15T17:47:06.662287Z","crawlId":"contacts-seeded-1773596826","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"91281e0a9538525a9844b774bf2d997a6073c932d6cabe58f49bb9c52698ddbe"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:06.662287+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0c0c5aad-e42c-442c-baf8-a3bac825697d', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Arbeitsvermittlung-ins-Ausland/arbeitsvermittlung-ins-ausland.html', 'active', NULL, '2026-03-15T17:47:07.982961+00:00', '{"id":"0c0c5aad-e42c-442c-baf8-a3bac825697d","title":"Arbeitsvermittlung ins Ausland","summary":{"de":"Die Zentrale Auslands- und Fachvermittlung (ZAV) bietet einen umfassenden Service zur Beantwortung aller Fragen, die mit der Aufnahme einer Beschäftigung im Ausland zusammenhängen."},"content":{"de":"Die Zentrale Auslands- und Fachvermittlung (ZAV) als besondere Dienststelle der Bundesagentur für Arbeit bietet für die Personen einen umfassenden Service, die Fragen zur Aufnahme einer Beschäftigung im Ausland haben, aber auch ihre berufliche Herausforderung im Ausland suchen. Die zehn regionalen Zentren der ZAV-Auslandsvermittlung und die Arbeitsagenturen in den Grenzregionen bieten für alle interessierten Bürgerinnen und Bürger folgenden Service an: Informationen über Arbeits- und Bildungsmöglichkeiten weltweit Informationen rund um das Thema Leben und Arbeiten im jeweiligen Zielland Beratung für ausländische Arbeitsuchende, die in ihre Heimat zurückkehren wollen Erste grundlegende Informationen dazu erhalten Interessierte auch bei den EURES-Assistenten in den Selbstinformationseinrichtungen der Agenturen für Arbeit."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Arbeitsvermittlung-ins-Ausland/arbeitsvermittlung-ins-ausland.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:07.982961+00:00","lastSeen":"2026-03-15T17:47:07.982961+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Arbeitsvermittlung-ins-Ausland/arbeitsvermittlung-ins-ausland.html","crawledAt":"2026-03-15T17:47:07.983960Z","crawlId":"contacts-seeded-1773596827","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"5ecb7b7ee44c8f1f09195082d1f4fe066d7ee0b04b5cdd7ef0fdc7d4b9b386b8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:07.983960+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('82b6b167-a1ce-4c6d-b093-86fb18ce2e75', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Orientierung-auf-dem-Arbeitsmarkt/orientierung-auf-dem-arbeitsmarkt.html', 'active', NULL, '2026-03-15T17:47:09.185659+00:00', '{"id":"82b6b167-a1ce-4c6d-b093-86fb18ce2e75","title":"Orientierung auf dem Arbeitsmarkt","summary":{"de":"Es ist nicht einfach, sich in einem fremden Land zurecht zu finden. Daher gibt es verschiedene Möglichkeiten, wie Sie erste praktische Erfahrung auf dem deutschen Arbeitsmarkt erlangen können."},"content":{"de":"Viele Initiativen, Kammern oder Verbände sowie Unternehmen bieten vor Ort berufliche Orientierungsmöglichkeiten an. So können Sie evtl. Vorkenntnisse beweisen und Erfahrung sammeln. Asylbewerberinnen und Asylbewerber sowie geduldete Personen, die verpflichtet sind, in einer Aufnahmeeinrichtung zu wohnen, dürfen grundsätzlich bereits neun (mit minderjährigen Kindern nach sechs) bzw. sechs (für Geduldete) Monate nach Registrierung Beschäftigungen beginnen. Sofern keine Verpflichtung besteht, in einer Aufnahmeeinrichtung zu wohnen, besteht bereits grundsätzlich nach drei Monaten ein Arbeitsmarktzugang. Sie können allerdings nur dann eine Beschäftigung aufnehmen, wenn die Ausländerbehörde dies genehmigt und in der Bescheinigung über die Aufenthaltsgestattung bzw. Duldung vermerkt hat. Im Regelfall muss die Bundesagentur für Arbeit zustimmen. Sie prüft dabei, ob Sie zu vergleichbaren Bedingungen wie deutsche Arbeitnehmer beschäftigt werden. Sie können dabei zwischen verschiedenen Formen wählen: Als Hospitantin oder Hospitant sind Sie \"Gast\" in einem Unternehmen und benötigen keine Zustimmung Ihrer lokalen Ausländerbehörde. Es handelt sich um keine Beschäftigung. Hierbei dürfen Sie sich lediglich die Betriebsabläufe ansehen. Sie dürfen insofern nicht tätig werden, auch nicht probeweise. In einem Orientierungspraktikum mit Hinblick auf eine Berufsausbildung oder ein Studium können Sie auch richtig mit anpacken. Sie benötigen für ein Orientierungspraktikum die Erlaubnis der lokalen Ausländerbehörde. Wenn das Orientierungspraktikum maximal drei Monate dauert, gibt es allerdings Erleichterungen im Verfahren. Eine Zustimmung der Bundesagentur für Arbeit ist in diesem Fall nicht erforderlich. Wollen Sie eine gemeinnützige Tätigkeit betreiben, ist der Bundesfreiwilligendienst oder ein Freiwilliges Soziales Jahr das richtige für Sie. Dabei können Sie v.a. soziale Tätigkeiten kennenlernen, brauchen aber ebenfalls eine Genehmigung der lokalen Ausländerbehörde. Darüberhinausgehende Praktika, die nicht der Orientierung dienen oder länger als drei Monate dauern, sind auch möglich. Hierfür ist jedoch eine Zustimmung der Bundesagentur für Arbeit erforderlich."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Orientierung-auf-dem-Arbeitsmarkt/orientierung-auf-dem-arbeitsmarkt.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:09.185659+00:00","lastSeen":"2026-03-15T17:47:09.185659+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Orientierung-auf-dem-Arbeitsmarkt/orientierung-auf-dem-arbeitsmarkt.html","crawledAt":"2026-03-15T17:47:09.186663Z","crawlId":"contacts-seeded-1773596829","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"72d5271b379971e7e2b65f27a17a2db8c72e7189e803a20b024eae6e2b3d9970"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:09.186663+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e942f251-0163-40ac-8763-4442d569e8fa', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Wer-Was-Wo/wer-was-wo.html', 'active', NULL, '2026-03-15T17:47:10.389405+00:00', '{"id":"e942f251-0163-40ac-8763-4442d569e8fa","title":"Wer? Was? Wo?","summary":{"de":"In Deutschland erhalten Sie Beratung und Hilfe bei der Vermittlung in Arbeit von der Bundesagentur für Arbeit und den Jobcentern. Abhängig vom Status Ihres Asylverfahrens können Sie zudem weitere Bildungs- und Unterstützungsleistungen erhalten, sodass Sie schnell eine Arbeit aufnehmen können."},"content":{"de":"Ob bei der Ausbildungs- oder Arbeitsplatzsuche können Sie in Deutschland vielfältige Unterstützungsleistungen erhalten. Dabei sind für Sie je nach Aufenthaltsstatus unterschiedliche Institutionen zuständig. Das sind entweder die Agenturen für Arbeit oder die Jobcenter vor Ort. Neben einer Beratung zu Ihren Qualifikationen und den beruflichen Anforderungen erhalten Sie Vermittlung auf konkrete Stellen, aber auch weitergehende Hilfe, sofern Ihnen für den Einstieg noch Kenntnisse fehlen. Dann kann z. B. auch die Teilnahme an Maßnahmen zur beruflichen Eingliederung oder Weiterbildung gefördert werden. Sobald Sie in Deutschland als asylsuchend registriert sind oder eine aufenthaltsrechtliche Duldung erhalten, ist die Agentur für Arbeit vor Ort für Sie zuständig. Dort können Sie das Beratungsangebot nutzen und in diesem Rahmen Ihre Qualifikationen im Hinblick auf den deutschen Arbeitsmarkt überprüfen lassen. Sobald Sie Zugang zum Arbeits- oder Ausbildungsmarkt bekommen, steht Ihnen auch die Ausbildungs- und Arbeitsvermittlung offen. Sie können auch mit Maßnahmen ( z. B. Bewerbungstraining) gefördert werden, die für eine berufliche Eingliederung erforderlich sind. Mit der Anerkennung eines Asylantrags wechselt die Zuständigkeit in den Rechtskreis des Zweiten Buches Sozialgesetzbuch (SGB II). Dieses regelt die Grundsicherung für Arbeitsuchende für die nicht die Bundesagentur für Arbeit (BA) mit ihren Agenturen für Arbeit, sondern die lokalen Jobcenter zuständig sind. Ab diesem Zeitpunkt ist es möglich, bei Vorliegen der sonstigen Voraussetzungen, Leistungen der Grundsicherung für Arbeitsuchende zu erhalten. Die nachfolgenden Unterstützungsleistungen werden dann überwiegend durch die Jobcenter erbracht. Neben der Beratung und Vermittlung können Sie von der Agentur für Arbeit oder dem Jobcenter eine Unterstützung, zum Beispiel für Bewerbungskosten und Vorstellungsgespräche erhalten. Spezielle Maßnahmen bei Trägern mit Praxisanteil in Unternehmen und berufliche Erprobungen bei Arbeitgebern sind weitere Möglichkeiten, um Berufsbilder und Arbeitsplätze kennen zu lernen. Für Asylbewerberinnen und -bewerber mit guter Bleibeperspektive können diese vermittlungsunterstützenden Leistungen bereits frühzeitig vor dem Arbeitsmarktzugang erbracht werden. Arbeitgeber können mit dem sogenannten Eingliederungszuschuss Zuschüsse zum Arbeitsentgelt erhalten, wenn sie Arbeitsuchende einstellen, deren Vermittlung erschwert und bei denen dies zur Förderung zur beruflichen Eingliederung erforderlich ist. Arbeitslose können zudem unter bestimmten Voraussetzungen bei Aufnahme einer selbständigen Tätigkeit gefördert werden. Zuletzt können geförderte Arbeitsgelegenheiten in gemeinnütziger Arbeit ein Sprungbrett in den Arbeitsmarkt darstellen. Weitere Leistungen bieten BA und Jobcenter mit Unterstützung des Europäischen Sozialfonds (ESF) im Handlungsschwerpunkt IvAF \"Integration von Asylbewerber/-innen und Flüchtlingen\" an."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Wer-Was-Wo/wer-was-wo.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:10.389405+00:00","lastSeen":"2026-03-15T17:47:10.389405+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/Wer-Was-Wo/wer-was-wo.html","crawledAt":"2026-03-15T17:47:10.390920Z","crawlId":"contacts-seeded-1773596830","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"6d4c94309cc7067d06eb375ea2bb9f4fd4abdf9215de072a5be0afcd3a710b18"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:10.390920+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('70701729-f7ec-4168-963b-c58d213d0864', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/orientierung-und-vermittlung.html', 'active', NULL, '2026-03-15T17:47:11.820855+00:00', '{"id":"70701729-f7ec-4168-963b-c58d213d0864","title":"Orientierung und Vermittlung","summary":{"de":"Finden Sie die richtigen Ansprechpartner*innen für Bildungs- und Unterstützungsleistungen sowie die Arbeitsvermittlung – auch ins Ausland."},"content":{"de":"Finden Sie die richtigen Ansprechpartner*innen für Bildungs- und Unterstützungsleistungen sowie die Arbeitsvermittlung – auch ins Ausland."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/orientierung-und-vermittlung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:11.820855+00:00","lastSeen":"2026-03-15T17:47:11.820855+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Orientierung-und-Vermittlung/orientierung-und-vermittlung.html","crawledAt":"2026-03-15T17:47:11.821366Z","crawlId":"contacts-seeded-1773596831","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"da04965b080a5b828186d8e5c407e975c7df3b5dea477475ebce6f0a8deea72d"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:47:11.821366+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ee750017-628f-48ea-a8a5-4f0256fc6fd6', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Fachkraefteeinwanderungsgesetz/fachkraefteeinwanderungsgesetz.html', 'active', NULL, '2026-03-15T17:47:13.307876+00:00', '{"id":"ee750017-628f-48ea-a8a5-4f0256fc6fd6","title":"Fachkräfteeinwanderungsgesetz","summary":{"de":"Fachkräfte aus dem Ausland sind unverzichtbar für einen zukunftsfähigen Arbeitsmarkt in Deutschland. Die Fachkräftestrategie ist klar: Wir brauchen mehr qualifizierte Einwanderung als bisher, um künftigen Fachkräfteengpässen entgegenzuwirken. Die wichtigste rechtliche Grundlage zu Migration und Arbeit ist das Fachkräfteeinwanderungsgesetz. Dieses sogenannte Gesetz ist schon seit 2020 ein Oberbegriff für die Maßnahmen beider Ressorts. Mit der Weiterentwicklung des Fachkräfteeinwanderungsgesetzes wird nun unter Federführung des BMI das Aufenthaltsgesetz angepasst. Diese Anpassung wird ergänzt durch die „Verordnung zur Weiterentwicklung der Fachkräfteeinwanderung“, welche in der Zuständigkeit des BMAS liegt."},"content":{"de":"Es ist dazu gedacht, formale und bürokratische Hürden abzubauen. Der Weg in eine Beschäftigung soll kürzer, einfacher und schneller werden. Die gesetzlichen Änderungen haben bereits erhebliche Erleichterungen für ausländische Fachkräfte gebracht, etwa bei der Anerkennung von Qualifikationen, und werden kontinuierlich an aktuelle Entwicklungen und neue Anforderungen angepasst und erweitert. Arbeit ist eine wichtige Grundvoraussetzung für gelungene Integration und damit gesellschaftliche Teilhabe. Für gleichberechtigte Chancen auf einen Zugang zum Arbeitsmarkt werden ausländische Arbeitsuchende durch verschiedene Maßnahmen unterstützt: Die Grundsicherung für Arbeitsuchende gilt auch für erwerbsfähige Migrant*innen, die hilfebedürftig sind und über eine Bleibeperspektive verfügen. Sie haben Anspruch auf Beratung, Vermittlung, Förderung und Lebensunterhaltsleistungen. Für Beratung und Vermittlung sind die Bundesagentur für Arbeit und die Jobcenter zuständig. So können ausländische Arbeitsuchende beispielsweise prüfen lassen, ob ihr jeweiliger Berufsabschluss sie für einen Zugang zum deutschen Arbeitsmarkt berechtigt. Hierzu sind auch Personen berechtigt, die als asylsuchend registriert sind oder über eine aufenthaltsrechtliche Duldung verfügen. Arbeitsuchende mit Zugang zum Arbeitsmarkt können darüber hinaus weitere Angebote in Anspruch nehmen: etwa zur Weiterbildung, als Bewerbungstraining oder finanzielle Unterstützung für Kosten für Vorstellungsgespräche. Auch jungen Migrant*innen ohne berufliche Erfahrung und Abschluss wird der Zugang zum Arbeitsmarkt ermöglicht: Sie können alle eine Berufsausbildung weitgehend unabhängig von ihrem Aufenthaltsstatus beginnen. Flankiert werden diese Maßnahmen von einem breiten Angebot an Integrations- und Berufssprachkursen, das künftig noch ausgeweitet und noch bedarfsgerechter gestaltet werden soll. Wer daran interessiert ist, in Deutschland zu arbeiten, setzt sich mit einer Vielzahl von Regelungen und Gesetzen auseinander. Das mehrsprachige Portal „ Make it in Germany “ der Bundesregierungen bündelt alle notwendigen Informationen – ob Einreise und Visum, Jobsuche, Berufsanerkennung oder das Einleben in Deutschland. Hier erhalten Einwanderungsinteressierte individuelle Beratung."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Fachkraefteeinwanderungsgesetz/fachkraefteeinwanderungsgesetz.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:13.307876+00:00","lastSeen":"2026-03-15T17:47:13.307876+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Fachkraefteeinwanderungsgesetz/fachkraefteeinwanderungsgesetz.html","crawledAt":"2026-03-15T17:47:13.307876Z","crawlId":"contacts-seeded-1773596833","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"009d1e7f22931d4932cfa24a93edaaf20b8c0742221917b1f7dfb7c7bcc6ca6b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:13.307876+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7d7bedd8-c708-44ab-8606-feaf9608f9f4', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Schutzrechte-fuer-Arbeitnehmerinnen/schutzrechte-fuer-arbeitnehmerinnen.html', 'active', NULL, '2026-03-15T17:47:14.583716+00:00', '{"id":"7d7bedd8-c708-44ab-8606-feaf9608f9f4","title":"Schutzrechte für Arbeitnehmer*innen","summary":{"de":"Im deutschen Arbeitsmarkt gelten verschiedene Schutzbestimmungen, die Sie als Arbeitnehmer vor schlechter Arbeit und zu niedriger Bezahlung schützen. Hier erhalten Sie einen Überblick."},"content":{"de":"Grundvoraussetzung für jegliche Beschäftigung in Deutschland ist das Vorliegen eines Arbeitsvertrages. Er regelt, wie Ihre Arbeitsstelle genau aussieht. Lesen Sie ihn gründlich durch und haken Sie nach, wenn Ihnen etwas unklar ist oder nicht den mündlich getroffenen Vereinbarungen entspricht. Schließlich müssen Sie ihn unterschreiben, damit er rechtsverbindlich wird. Darum sollten Sie auch stets auf einem schriftlichen Vertrag bestehen, der aber in Deutschland auch der Normalfall ist. Sollte Ihnen kein Arbeitsvertrag ausgehändigt werden, ist Misstrauen angebracht – fragen Sie beim Berufsverband oder in Ihrer Agentur für Arbeit nach. Im Arbeitsvertrag geregelt sind sowohl Ihre Rechte und Pflichten als auch die des Arbeitgebers. Am wichtigsten sind die Beschreibung Ihrer Arbeitsaufgaben und Ihre Bezahlung, die Dauer der Probezeit, die Arbeitszeiten und der Einsatzort, Ihr Gehalt und die vereinbarten Nebenleistungen sowie die Pausen- und Urlaubsregelungen. Oft wird im Arbeitsvertrag auf einen geltenden Tarifvertrag verwiesen, den der zuständige Arbeitgeberverband mit der jeweiligen Gewerkschaft abgeschlossen hat. Wenn Sie möchten, schauen Sie dort hinein (fragen Sie Ihren Arbeitgeber oder den Betriebsrat danach). Die Wochenarbeitszeit beträgt laut Tarifvertrag meist zwischen 37 und 40 Stunden. Tatsächlich arbeiten die Deutschen allerdings durchschnittlich fast 41 Stunden pro Woche. Häufig gibt es flexible Arbeitszeitmodelle (\"Gleitzeitregelungen\"), die Ihnen erlauben, Ihre Arbeitszeit zu einem gewissen Teil selbst zu bestimmen. In manchen Berufen werden spezielle Zuschläge für Nacht- und Feiertagsarbeit gezahlt, zum Beispiel im Gesundheitssektor, im Sicherheitsgewerbe und im Schichtdienst in Betrieben. In Deutschland gilt ein einheitlicher Mindestlohn von 13,90 Euro pro Stunde. Jeder Arbeitnehmer und jede Arbeitnehmerin hat Anspruch auf mindestens diesen Lohn. In einigen Branchen gibt es höhere Mindestlöhne, die verbindlich für alle Arbeitnehmerinnen und Arbeitnehmer zu zahlen sind. Zum Beispiel in der Gebäudereinigung und in der Pflege. Die Löhne werden in Tarifverhandlungen zwischen Gewerkschaften und Arbeitgeberverbänden ausgehandelt. Wenn es in Ihrer Branche keinen Tarifvertrag gibt, müssen Sie das Gehalt mit dem Arbeitgeber selbst verhandeln. Als Arbeitnehmer oder Arbeitnehmerin in Deutschland sind Sie Mitglied des nationalen Sozialversicherungssystems. Es umfasst die gesetzliche Kranken-, Pflege-, Unfall-, Renten- und Arbeitslosenversicherung. Sobald Sie als Versicherter oder Versicherte gemeldet wurden, erhalten Sie die sogenannte Sozialversicherungsnummer. Teilen Sie diese dem Arbeitgeber mit und bewahren Sie sie zu Hause gut auf."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Schutzrechte-fuer-Arbeitnehmerinnen/schutzrechte-fuer-arbeitnehmerinnen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:14.583716+00:00","lastSeen":"2026-03-15T17:47:14.583716+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Schutzrechte-fuer-Arbeitnehmerinnen/schutzrechte-fuer-arbeitnehmerinnen.html","crawledAt":"2026-03-15T17:47:14.584505Z","crawlId":"contacts-seeded-1773596834","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"33cb8cee7ed82b1e63a58e7dffdb2c89d8546505e4f0ad00db558aa82553cdc6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:14.584505+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e8e46edb-0268-47b9-bbb0-6b713e9f3aa5', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Voraussetzungen-fuer-Zugang-zum-deutschen-Arbeitsmarkt/voraussetzungen-fuer-zugang-zum-deutschen-arbeitsmarkt.html', 'active', NULL, '2026-03-15T17:47:16.018055+00:00', '{"id":"e8e46edb-0268-47b9-bbb0-6b713e9f3aa5","title":"Voraussetzungen für Zugang zum deutschen Arbeitsmarkt","summary":{"de":"Staatsangehörige der EU-Mitgliedstaaten sowie Islands, Liechtensteins, Norwegens (Mitglieder im Europäische Wirtschaftsraum – EWR-Staaten) und der Schweiz sind freizügigkeitsberechtigt und können ohne weitere Voraussetzungen eine Beschäftigung in Deutschland aufnehmen."},"content":{"de":"Bisher hatten nur akademisch ausgebildete Fachkräfte unbeschränkten Arbeitsmarktzugang. Künftig können auch Fachkräfte mit einer ausländischen beruflichen Qualifikation in allen Berufen ein Visum oder einen Aufenthaltstitel zur Beschäftigung erhalten. Die bisherige Beschränkung auf sogenannte Engpassberufe entfällt. Die Änderungen wurden zum 1. März 2020 durch das Fachkräfteeinwanderungsgesetz eingeführt. Zur Erteilung des Visums oder Aufenthaltstitels zur Beschäftigung von Fachkräften sind neben den allgemeinen aufenthaltsrechtlichen Regelungen nur die Feststellung der Gleichwertigkeit der Qualifikation und ein konkretes Arbeitsplatzangebot nachzuweisen. Es ist die Ausübung jeder qualifizierten Tätigkeit erlaubt, zu der die Qualifikation befähigt. Wie bisher prüft die Bundesagentur für Arbeit, ob die Beschäftigungsbedingungen denen vergleichbarer inländischer Arbeitnehmer entsprechen. Eine Vorrangprüfung wird nicht mehr durchgeführt. Außerdem werden die Möglichkeiten des Aufenthalts zur Anerkennung der beruflichen Qualifikation und zur Arbeitsuche erweitert. Mit dem beschleunigten Fachkräfteverfahren wird die Möglichkeit eines schnelleren und planungssicheren Visumverfahrens eingeführt. Voraussetzung ist eine Vereinbarung zwischen dem Arbeitgeber und der zuständigen Ausländerbehörde. Sobald alle Unterlagen vorliegen und die Ausländerbehörde die Zustimmung zur Einreise erteilt hat, erhält die Fachkraft innerhalb von drei Wochen einen Termin in der Auslandsvertretung und innerhalb weiterer drei Wochen das Visum. Für Akademikerinnen und Akademiker aus Drittstaaten gelten zudem die Regelungen zur Blauen Karte EU, wenn sie einen ihrer beruflichen Qualifikation angemessenen Arbeitsplatz vorweisen können und ein bestimmtes Mindestgehalt verdienen. Besonders attraktive Bedingungen zur Aufnahme einer Beschäftigung haben Personen, die ein Hochschulstudium in Deutschland abgeschlossen haben. Wer im Anschluss an das Studium noch keinen entsprechenden Arbeitsplatz gefunden hat, kann von der Ausländerbehörde eine 18 Monate geltende Aufenthaltserlaubnis zur Suche nach einem angemessenen Arbeitsplatz erhalten. In dieser Zeit ist die Aufnahme jeder T ätigkeit erlaubt, um den Lebensunterhalt sicherzustellen. Für Absolventinnen und Absolventen einer qualifizierten Berufsausbildung im Bundesgebiet oder Ausländerinnen und Ausländer, bei denen die Gleichwertigkeit der Qualifikation festgestellt wurde (Anerkennung der beruflichen Qualifikation), gelten die v. g. Möglichkeiten für zwölf Monate."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Voraussetzungen-fuer-Zugang-zum-deutschen-Arbeitsmarkt/voraussetzungen-fuer-zugang-zum-deutschen-arbeitsmarkt.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:16.018055+00:00","lastSeen":"2026-03-15T17:47:16.018055+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/Voraussetzungen-fuer-Zugang-zum-deutschen-Arbeitsmarkt/voraussetzungen-fuer-zugang-zum-deutschen-arbeitsmarkt.html","crawledAt":"2026-03-15T17:47:16.019079Z","crawlId":"contacts-seeded-1773596836","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"670b0fee05bc20908f62de09abc062c2bb3f5779a79217c431df85445177df0e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:16.019079+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7c9e15ec-9641-4575-a80b-fa4f89bfd69f', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/rechtliches-zu-einreise-arbeitsmarktzugang-und-absicherung.html', 'active', NULL, '2026-03-15T17:47:17.293556+00:00', '{"id":"7c9e15ec-9641-4575-a80b-fa4f89bfd69f","title":"Rechtliche Rahmenbedingungen","summary":{"de":"Informationen zur Beschäftigung ausländischer Arbeitnehmer aus EU - und Drittstaaten, Schutzrechte für Arbeitnehmer*innen, Förderung in der Grundsicherung sowie der Einreise per Visum nach Deutschland."},"content":{"de":"Informationen zur Beschäftigung ausländischer Arbeitnehmer aus EU - und Drittstaaten, Schutzrechte für Arbeitnehmer*innen, Förderung in der Grundsicherung sowie der Einreise per Visum nach Deutschland."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/rechtliches-zu-einreise-arbeitsmarktzugang-und-absicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:17.293556+00:00","lastSeen":"2026-03-15T17:47:17.293556+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/Rechtliches-zu-Einreise-Arbeitsmarktzugang-und-Absicherung/rechtliches-zu-einreise-arbeitsmarktzugang-und-absicherung.html","crawledAt":"2026-03-15T17:47:17.293556Z","crawlId":"contacts-seeded-1773596837","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"be2826609fa7d1a48bd4c71a3f3773f833f72ed82672a8316ee2b8305ce4a2ac"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:17.293556+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1cc6e1d0-262a-43b8-ab5d-b6479361ba11', 'contacts', 'https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/migration-und-arbeit.html', 'active', NULL, '2026-03-15T17:47:18.538060+00:00', '{"id":"1cc6e1d0-262a-43b8-ab5d-b6479361ba11","title":"Migration und Arbeit","summary":{"de":"Migration und Integration gehen oft Hand in Hand. Hier erhalten Sie Informationen zur Zuwanderung, zur Anerkennung und zum Erwerb von Qualifikationen sowie zur Arbeitsvermittlung vom und ins Ausland."},"content":{"de":"Mit einer zeit­gemäßen Aus­bildung, gezielten Weiter­bildungen und einer modernen Einwanderungs­politik wollen wir die Arbeit als Fach­kraft wieder attraktiver machen und Unternehmen bei der Fach­kräfte­sicherung unterstützen."},"url":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/migration-und-arbeit.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:18.538060+00:00","lastSeen":"2026-03-15T17:47:18.538060+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Migration-und-Arbeit/migration-und-arbeit.html","crawledAt":"2026-03-15T17:47:18.538060Z","crawlId":"contacts-seeded-1773596838","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"eb32e602e53747356f70dc32353529f6c1c445313f50a95a15849f53bf7f599c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:18.539047+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('18d89e50-ff9f-4405-a265-ced8b56f5cab', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Andre-Goerner/andre-goerner.html', 'active', NULL, '2026-03-15T17:47:20.570281+00:00', '{"id":"18d89e50-ff9f-4405-a265-ced8b56f5cab","title":"„Meine Arbeit erlaubt mir, der zu sein, der ich immer sein wollte. “","summary":{"de":"Friseur André Goerner schöpft die Leidenschaft für seinen Beruf aus dem Kontakt mit seinen Gästen."},"content":{"de":"Schon vor mehr als 20 Jahren hat André „Luxus“ für sich neu definiert: Luxuriös zu leben bedeutet für ihn, arbeiten zu können, wo er will - und wie er will. Nach seiner Ausbildung arbeitete André zehn Jahre für den Star-Friseur Gerhard Meir, leitete unter anderem dessen Geschäft im Berliner Hotel Adlon. „Ich versuche jeden Tag, die Welt ein Stück schöner zu machen.“ 2004 machte er sich mit einem Think Tank für Frisöre selbstständig. Er wollte nicht mehr nur Haare stylen, sondern auch die Prozesse dahinter gestalten: Welche Standards gelten in der Friseurbranche, welche braucht es? Aus Andrés Überlegungen entstanden Industriepartnerschaften und mehrere spezialisierte Geschäfte. Doch bei allem Erfolg gilt Andrés Leidenschaft weiterhin dem Handwerk – weshalb er sich nach 20 Jahren wieder verstärkt auf die Arbeit mit Gästen konzentrieren wollte und seinen eigenen Salon im Herzen der Hauptstadt eröffnet hat: im Hotel Adlon. Das fühlte sich für den heute 49-jährigen wie eine Heimkehr an. Tatsächlich passt André mit seinem gepflegten Äußeren und souveränen Auftritt gut in diese Welt. Doch ihm geht es nicht um Geld oder Bekanntheit. Die Arbeit im Adlon ermöglicht ihm, viele spannende und einflussreiche Persönlichkeiten zu treffen. Mit Weiterbildung fit für die Arbeit von Morgen sein - wir wollen Deutschland mit neuen Fördermöglichkeiten für berufliche Weiterbildung zu einer Weiterbildungsrepublik machen. André freut sich jeden Morgen, ins Geschäft zu kommen. Er weiß, das ist nicht selbstverständlich: „Viele Leute wollen arbeiten, aber können nicht aufgrund von Krankheit oder sie dürfen es nicht.“ Für André bedeutet seine Arbeit, so sein zu können, wie er schon immer sein wollte. Mit seinen Worten: Luxus!"},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Andre-Goerner/andre-goerner.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:20.570281+00:00","lastSeen":"2026-03-15T17:47:20.570281+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Andre-Goerner/andre-goerner.html","crawledAt":"2026-03-15T17:47:20.571307Z","crawlId":"contacts-seeded-1773596840","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"54d0df4e238306624badd78289594d31350bfd10bc9a0926d9dfb69fe12e49a1"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:20.571307+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fa4a4b91-f086-4a13-9732-fb6c9280321b', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Anna-Lena-Bogenhauser/anna-lena-bogenhauser.html', 'active', NULL, '2026-03-15T17:47:22.592134+00:00', '{"id":"fa4a4b91-f086-4a13-9732-fb6c9280321b","title":"„Mit meiner Arbeit kann ich Menschen Liebe schenken. “","summary":{"de":"Anna Lena ist Pflegehelferin in der Notaufnahme. Mit ihrer Arbeit will sie anderen helfen – und allen Menschen mit Down-Syndrom ein Vorbild sein."},"content":{"de":"Anna Lena muss zur regelmäßigen Herzuntersuchung in dasselbe Krankenhaus, in dem ihre Mutter als Krankenschwester arbeitet. Eines Tages blieb sie mit ihrer Mutter vor Ort, weil sich der lange Heimweg nicht lohnte. Stattdessen hospitierte Anna Lena in ihrer ersten Spätschicht – und war sofort begeistert. Inzwischen arbeitet sie seit fast 10 Jahren als Pflegehelferin. „Ich will den Patienten ein Lächeln ins Gesicht zaubern.“ Zur Frühschicht fängt Anna Lena um 06:15 Uhr an, wäscht Patient*innen, bringt ihnen Frühstück, macht die Betten und kümmert sich um spontane Anfragen. An die Hektik musste sie sich erst einmal gewöhnen. Doch die Freude, mit Menschen zusammenzuarbeiten, überwiegt gegenüber der Anstrengung. Das spüren auch ihre Patient*innen: Viele wenden sich mit ihren Anliegen direkt an sie. „Weil ich ein Engel bin“, sagt sie lächelnd. Wir erzählen die Geschichten von Menschen und ihren Gründen, ihrer Arbeit nachzugehen. So ehrlich, aufregend und bunt, wie das Arbeitsleben eben ist. Die Arbeit erlaubt es Anna Lena, ihr Leben nach ihren eigenen Vorstellungen zu führen: Aktuell macht sie ihren Führerschein, später will sie eine Familie gründen und nach Kalifornien auswandern. Menschen mit Behinderung haben ein Recht auf Selbstbestimmung und umfassende Teilhabe. Das bedeutet Barrierefreiheit in allen Gebieten des Lebens für eine inklusive Gesellschaft."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Anna-Lena-Bogenhauser/anna-lena-bogenhauser.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:22.592134+00:00","lastSeen":"2026-03-15T17:47:22.592134+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Anna-Lena-Bogenhauser/anna-lena-bogenhauser.html","crawledAt":"2026-03-15T17:47:22.592134Z","crawlId":"contacts-seeded-1773596842","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"780d9d2e0a228e4e1200f9f4dd7d206fc85eaa6df7d005d75fa0b1a5af2bc53a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:22.593135+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0d51d6a9-3d97-4d80-a823-808f706d431f', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Damian-Strauss/damian-strauss.html', 'active', NULL, '2026-03-15T17:47:24.749457+00:00', '{"id":"0d51d6a9-3d97-4d80-a823-808f706d431f","title":"BMAS - Damian Strauß","summary":{"de":"Damian Strauß, 21 Jahre, macht eine Ausbildung zum Anlagenmechaniker für Rohrsystemtechnik."},"content":{"de":"Damian betritt die Werkstatt der Berliner Wasserbetriebe in der Fischerstraße mit einem breiten Lächeln. Er fühlt sich wohl an diesem Ort. Die Werkbank, das Werkzeug, der Geruch von Metall und Öl – all das sind Dinge, die Damian ein vertrautes Gefühl geben. Schon als Teenager arbeitete er jeden Sommer drei Wochen in dem Metall-Betrieb eines Freundes der Familie. Dort konnte er sich ausprobieren, schmieden, schrauben und werkeln. „Ich wusste immer, dass ich nach meinem Fachabitur direkt arbeiten und etwas Handwerkliches machen möchte.“ Damian steht selbstbewusst im Scheinwerferlicht, während er für die Kampagne fotografiert wird. „Bist du jetzt Model?“, scherzen seine Kollegen. Allgemeines Lachen. Für ihn ist die gute Zusammenarbeit mit seiner „Truppe“, wie er seine Kollegen nennt, wichtig: Gemeinsam etwas lernen und gestalten – und lachen. Gute Arbeit ist für ihn auch: Freude an der Sache. Arbeit bedeutet für die Gesellschaft: Leben. Ein gemeinsames und gutes Leben funktioniert nur, wenn jeder seine gelernten Fertigkeiten weitergibt. Damian brennt für seine Ausbildung. Seine Leidenschaft für das Handwerk ist spürbar, er erzählt lebhaft von den Dingen, die er bei den Berliner Wasserbetrieben lernt. Wie junge Menschen in Deutschland ihre Perspektiven in der Berufsausbildung mit der Ausbildungsgarantie, Fördermöglichkeiten und Beratungsangeboten verbessern können."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Damian-Strauss/damian-strauss.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:24.749457+00:00","lastSeen":"2026-03-15T17:47:24.749457+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Damian-Strauss/damian-strauss.html","crawledAt":"2026-03-15T17:47:24.750573Z","crawlId":"contacts-seeded-1773596844","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"25c8f3810b129382c638a0cb45fc3c1d9535dc0fc763d14a536ed4ddfed3e96a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:24.750573+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2fab08f9-613f-442d-a4e8-b127ef9c9c8c', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Eva-Sachse/eva-sachse.html', 'active', NULL, '2026-03-15T17:47:27.100060+00:00', '{"id":"2fab08f9-613f-442d-a4e8-b127ef9c9c8c","title":"„Meine Arbeit hat mir gezeigt: Ich kann das noch! “","summary":{"de":"In der Rente fing Eva Sachse an, an einer Tankstelle zu arbeiten. Im Ruhestand sieht sie die Chance, sich neuen Herausforderungen zu stellen."},"content":{"de":"43 Jahre lang arbeitete Eva als Erzieherin in einem Hort. Das sei eine schöne Erfahrung gewesen – aber auch 43 Jahre lang das Gleiche. Als dann der Ruhestand kam, fühlte sie sich aber beruflich noch nicht am Ende. „Ich wollte lieber schauen: Was gibt es noch für andere Arbeitsleben? Was geht da noch?“ Als zeitgleich die Raststätte „Leubinger Fürstenhügel“ in ihrer Thüringer Heimat öffnete, bewarb sie sich kurzerhand auf eine Stelle. „Ich wollte schon immer mal an einer Tanke arbeiten“, erzählt sie. „Es ist schön, wenn man merkt, dass man sich noch einbringen kann. Das hebt auch das Selbstwertgefühl.“ Dort, wo Eva vor über 50 Jahren als Kind mit dem Schlitten fuhr, lernte sie nun, Waren zu scannen und abzukassieren. Da es in der neuen Raststätte noch keine festen Abläufe gab, gestalten die 70-Jährige und ihr Team viele Prozesse gemeinsam. Und mit jeder gemeisterten Herausforderung wächst ihr Selbstvertrauen. Da merkt man, dass man doch anders im Leben bleibt, als wenn man nur den persönlichen Interessen nachgehen würde. Dabei könne sie sich immer auf ihre Chefin und ihr Team verlassen. Dass „Teamarbeit“ auf dem Leubinger Fürstenhügel mehr als nur ein Wort ist, erleben wir auch während des Interviews: Ständig scherzen die Kolleg*innen miteinander – und trotz der Filmaufnahmen hilft Eva, wo sie kann. Wir schaffen die Rahmenbedingungen für eine solide Alterssicherung für alle Bürgerinnen & Bürger und führen Dialogprozesse, um die Erwerbstätigkeit im Alter attraktiver zu gestalten."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Eva-Sachse/eva-sachse.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:27.100060+00:00","lastSeen":"2026-03-15T17:47:27.100060+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Eva-Sachse/eva-sachse.html","crawledAt":"2026-03-15T17:47:27.100762Z","crawlId":"contacts-seeded-1773596847","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"aeb7ac7d962bdcb948cab4b26e5a1d0f0028130c69f08264bb18e3843e111289"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:27.100762+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('75b36ea9-00e1-4150-800a-ffc18febb933', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Greta-Silver/greta-silver.html', 'active', NULL, '2026-03-15T17:47:29.014318+00:00', '{"id":"75b36ea9-00e1-4150-800a-ffc18febb933","title":"„Meine Arbeit macht mich selbstbewusst. “","summary":{"de":"Die Youtuberin und Autorin Greta Silver betrachtet das Alter als Chance und berät hierzu auch die Wirtschaft."},"content":{"de":"Jeden Morgen nimmt sich Greta vor, aufzustehen wie an ihrem Kindergeburtstag – mit der Erwartung, dass etwas Tolles passieren wird. „Unser Gehirn wird alles tun, damit wir recht behalten“, versichert sie und grinst. Mit 66 Jahren startete Greta aus einer fixen Idee heraus ihren YouTube-Kanal. Inzwischen hat sie Millionen von Klicks, schreibt Bestseller und berät Unternehmen. Ihre Botschaft: Von der Arbeit im Alter profitieren alle. „Für mich ist Alter kein Schimpfwort, sondern ein Ritterschlag.“ Mit 48 Jahren hat sich die ehemalige Hausfrau selbstständig gemacht. Nach dem Jobverlust ihres Mannes konnte Greta die Familie damit allein ernähren. Mangelnde Erfahrung hat sie dabei nicht aufgehalten: „Die anderen hatten Grenzen im Kopf, die ich nicht hatte.“ Jetzt, mit 76 Jahren, denkt sie immer noch nicht daran, aufzuhören. Greta ist sicher, dass alte Menschen mit ihrer Erfahrung Unternehmen stabilisieren können. Sie hätten bereits viele Krisen hinter sich und könnten anderen die Unsicherheit nehmen, sagt sie. Umgekehrt bereichert ihre Arbeit ihr Leben enorm: Sie liebt die Selbstwirksamkeit und die Freiheit, die ihr ihre Arbeit gibt. Wenn ich denke ‚Alter ist schrecklich‘ oder ‚Meine Arbeit ist schrecklich‘, dann sehe ich die Chancen nicht. Angst vorm Scheitern habe sie nicht – ein weiterer Vorteil des Alters sei eine große Portion Gelassenheit. Das demonstriert Greta uns auch bei unserem Fotoshooting, als sie Bryan Adams voll aufdreht und tanzt, als wären wir gar nicht da."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Greta-Silver/greta-silver.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:29.014318+00:00","lastSeen":"2026-03-15T17:47:29.014318+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Greta-Silver/greta-silver.html","crawledAt":"2026-03-15T17:47:29.015828Z","crawlId":"contacts-seeded-1773596849","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"507cda2e402e7f931478f7d556556fedaffbb23eb58d4d71e7ce51131b096052"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:29.015828+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('652cde7e-19a2-44d7-909d-64a1e1d3dbca', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Katharina-Baecker/katharina-baecker.html', 'active', NULL, '2026-03-15T17:47:30.983970+00:00', '{"id":"652cde7e-19a2-44d7-909d-64a1e1d3dbca","title":"„Für meine Arbeit motivieren mich die Generationen von morgen. “","summary":{"de":"Katharina Bäcker, 40 Jahre, ist Försterin bei den Bayerischen Staatsforsten."},"content":{"de":"Für Katharina war immer klar: Sie möchte etwas draußen machen. Als sie ein Praktikum beim Forstbetrieb Fichtelberg absolvierte, war es um sie geschehen. Sie verliebte sie sich in den Beruf der Försterin – und hat es seitdem keinen Tag bereut. In ihrem 1800 Hektar großen Revier im Fichtelgebirge bewahrt Katharina den Wald für künftige Generationen. Sie kämpft gegen Herausforderungen wie den Borkenkäfer oder den Klimawandel. Eine Aufgabe, die sie mit Sinn erfüllt. „Jeder Aspekt meiner Arbeit ist sinnvoll. Waldumbau und Naturschutz liegen mir besonders am Herzen.“ Bei Katharina gleicht kein Tag dem anderen. Als Försterin hat sie vielfältige Aufgaben: Bäume fällen, Wegebau, Jagdmanagement, Tourismus und Naturschutz sind nur einige Schlagwörter, wenn sie über ihren Beruf spricht. Und natürlich ist da auch noch die Büroarbeit, denn auch Försterinnen müssen am Computer sitzen. Dort plant Katharina die Maßnahmen für den Wald von morgen – eine Herzensangelegenheit für sie. Es vergeht kein Tag, an dem ich nicht gerne zur Arbeit gehe. Immer an ihrer Seite: Ilse. Die junge Hündin wird gerade zum Jagdhund ausgebildet. Ilse werde mal die beste Jägerin im Fichtelgebirge, feixt Katharina stolz. Dass die beiden schon jetzt ein Dreamteam sind, merkt man sofort. Für Katharina ist Arbeit viel mehr als nur Geld verdienen. Die Bundesregierung verfolgt eine neue Strategie zur Fachkräftesicherung. Sie ist die Grundlage aller politischen Vorhaben und Neuregelungen für das Fachkräfteland Deutschland."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Katharina-Baecker/katharina-baecker.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:30.983970+00:00","lastSeen":"2026-03-15T17:47:30.983970+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Katharina-Baecker/katharina-baecker.html","crawledAt":"2026-03-15T17:47:30.983970Z","crawlId":"contacts-seeded-1773596850","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"b149caa7f83c2d9cdd831eb83071f575b3482fa3d06b7f58c5f3da2666289b5c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:30.983970+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('40ef15fc-0ba5-4df8-85c0-e437b45766fd', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Olha-Maletska/olha-maletska.html', 'active', NULL, '2026-03-15T17:47:33.179877+00:00', '{"id":"40ef15fc-0ba5-4df8-85c0-e437b45766fd","title":"„Meine Arbeit hat mir geholfen, hier anzukommen. “","summary":{"de":"Olha Maletska, 37 Jahre alt, ist Social-Media-Managerin in Erlangen."},"content":{"de":"Als der Krieg in der Ukraine ausbrach, musste Olha mit ihren zwei Kindern nach Deutschland fliehen. Um hier aber richtig anzukommen, war ihr von Anfang an eines wichtig: Einen Job zu finden. Olha ist keine, die auf Hilfe wartet - sie sucht aktiv nach Lösungen. Mit Unterstützung des Jobcenters Nürnberg-Stadt fand sie eine Anstellung bei der Kommunikationsagentur swz. Für beide Seiten ein Glücksfall, denn Olha arbeitet bereits seit zehn Jahren im Digitalmarketing. „Wenn man Kinder hat, macht man sich ständig Gedanken über ihre Zukunft. Deshalb war es für mich wichtig, in Deutschland so schnell wie möglich, eine Arbeit zu finden.“ Von ihren Teamkolleginnen und -kollegen wurde sie mit offenen Armen empfangen: Olha freut sich über die familiäre und freundschaftliche Atmosphäre, die im Betrieb herrscht. Für ihre Integration in Deutschland sei das wichtig gewesen, sagt sie. Ich bin gesund, noch nicht so alt und ich möchte arbeiten. Ich lebe jetzt in Deutschland und ich möchte auch zu diesem Land gehören. In den anderthalb Jahren in der Agentur haben sich ihre Deutschkenntnisse verbessert. Sogar in Kundenterminen spricht sie jetzt schon Deutsch. Arbeit bedeutet für Olha, sich in Deutschland zugehörig zu fühlen. Wenn man Olha fragt, welche Bedeutung Arbeit für sie habe, zögert sie nicht lange."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Olha-Maletska/olha-maletska.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:33.179877+00:00","lastSeen":"2026-03-15T17:47:33.179877+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Olha-Maletska/olha-maletska.html","crawledAt":"2026-03-15T17:47:33.180881Z","crawlId":"contacts-seeded-1773596853","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"6ad026573beca80ee0c67b7d2e4183d5255f42f3646a2e34b96fecdc4f1f7522"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:33.181395+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('97b64b1b-43b6-4c09-995e-001dde4757a9', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Peter-Kossen/peter-kossen.html', 'active', NULL, '2026-03-15T17:47:35.454755+00:00', '{"id":"97b64b1b-43b6-4c09-995e-001dde4757a9","title":"„Arbeit bedeutet für mich, dem Leben zu begegnen. “","summary":{"de":"Pfarrer Peter Kossen schöpft Kraft aus der Begegnung mit anderen Menschen – und gibt diese in seiner Arbeit an sie zurück."},"content":{"de":"Als wir Peter zum Interview treffen, ist er schon seit 5 Uhr morgens auf den Beinen. Für den Gemeindepfarrer nichts Ungewöhnliches: Nach dem Morgengebet kümmert er sich um Papierkram, dann bricht er auf zu Gesprächen, Ortsterminen, Gottesdiensten. Der 55-Jährige schätzt diese Fülle und Vielfalt sehr an seiner Arbeit. Dabei wollte Peter ursprünglich gar nicht Priester werden, sondern Lehrer oder Psychologe. Sogar ein Praktikum beim Förster hat er absolviert. Am Ende ließ er sich überzeugen, dass das Theologiestudium das Richtige für ihn sei. „Jede Begegnung hinterlässt Spuren, auch bei mir.“ Seit über sieben Jahren arbeitet Peter in der katholischen Kirchengemeinde in Lengerich im nördlichen Münsterland. Er freut sich, andere Menschen ein Stück auf ihrem Lebensweg begleiten zu können, sie zu trösten oder ihre Freude mit ihnen zu teilen. Mit der Zeit habe er gelernt, Menschen nicht vorschnell zu beurteilen. Auch mit seinen eigenen Schwächen gehe er nachsichtiger um. Der Mensch, so wie er sich vorfindet, hat eine Würde. Nicht erst dann, wenn er oder sie etwas geleistet hat. Bei unserem Treffen erleben wir Peters Gastfreundlichkeit aus erster Hand. Im Pfarrhaus kocht er geduldig Kaffee für die gesamte Crew – wegen der kleinen Maschine immer nur zwei Tassen auf einmal. Dabei erzählt er auch von seinem politischen Einsatz für faire Arbeitsbedingungen u.a. in der Fleischindustrie. Mindestlohn, Tarifverträge sowie Teilzeitmodelle: Mit einer Vielzahl von Maßnahmen schützt das Arbeitsrecht Bürgerinnen und Bürger. Damit die Arbeit zum Leben passt."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Peter-Kossen/peter-kossen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:35.454755+00:00","lastSeen":"2026-03-15T17:47:35.454755+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Peter-Kossen/peter-kossen.html","crawledAt":"2026-03-15T17:47:35.455364Z","crawlId":"contacts-seeded-1773596855","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"3446669a31e6d00d5fdccb1dc1fffe0558b8b3a5318b2c9e2fa5092447c24940"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:35.455987+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a8727759-bd75-4774-b514-759496d6b48f', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Till-Gurka/till-gurka.html', 'active', NULL, '2026-03-15T17:47:37.523780+00:00', '{"id":"a8727759-bd75-4774-b514-759496d6b48f","title":"„Bei meiner Arbeit kann ich mein Talent ausleben. “","summary":{"de":"Mit seiner eigenen Bäckerei hat sich Bäckermeister Till Gurka einen Raum geschaffen, frei seiner Leidenschaft nachzugehen."},"content":{"de":"Till war noch nie ein Frühaufsteher. Was für die Bäckerbranche ungewöhnlich wirkt, machte er zum Geschäftsmodell, als er seine eigene Bäckerei eröffnete: sie öffnet erst um 11 Uhr. Doch das ist nicht die einzige Besonderheit von Tills „Brotwerkstatt“ in Freiburg: Der 31-Jährige verkauft dort nur Sauerteigprodukte. „Brot ist für mich ein sehr emotionales Produkt, da immer alle Sinne angesprochen werden.“ Der Sprung in die Selbstständigkeit war riskant. Doch das innovative Konzept führte schnell zum Erfolg: Innerhalb von zwei Jahren haben sich die Verkaufszahlen der Brotwerkstatt vervierfacht, laufend erhält Till Presseanfragen. Das fühle sich nach wie vor unwirklich an, bemerkt er. Doch Till kümmert sich wenig um Geld oder Bekanntheit. Seine Leidenschaft besteht darin, Gebäcke nach seine Vorstellung zu kreieren: naturnah und ohne Zusätze. Bis heute experimentiert Till gerne mit neuen Produkten. Seinem Team lässt er dabei große Freiheiten. „Ich habe mich nie so richtig als Chef gefühlt“, bekennt er. Das Wichtigste sei für ihn der Zusammenhalt und die Offenheit im Team. Alle können ihre Ideen und Erfahrungen einbringen. Till genießt es, selbstbestimmt zu arbeiten. Früher musste er nach den Vorgaben seiner Vorgesetzten arbeiten, heute gestaltet er Produkte und Abläufe selbst. Während unseres Gesprächs hilft Till dem Team bei der Vorbereitung, belegt Focaccia oder prüft die Croissants. Die Bundesregierung verfolgt eine neue Strategie zur Fachkräftesicherung. Sie ist die Grundlage aller politischen Vorhaben und Neuregelungen für das Fachkräfteland Deutschland."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Till-Gurka/till-gurka.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:37.523780+00:00","lastSeen":"2026-03-15T17:47:37.523780+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Till-Gurka/till-gurka.html","crawledAt":"2026-03-15T17:47:37.524578Z","crawlId":"contacts-seeded-1773596857","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"d5f447fed5c467a70a0dc3beef1f14410174608788da43b288143aa6442d691d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:37.524578+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f7618339-7f76-4c81-8c8d-b2b32e1b4056', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Valentina-Popovic/valentina-popovic.html', 'active', NULL, '2026-03-15T17:47:39.679204+00:00', '{"id":"f7618339-7f76-4c81-8c8d-b2b32e1b4056","title":"„Arbeitet bedeutet für mich, anderen eine Heimat zu geben. “","summary":{"de":"Valentina Popovic führt eine Gaststätte in Hamburg-Mitte. Mit ihrer Arbeit gestaltet sie ihr Leben nach ihren Vorstellungen."},"content":{"de":"Lange haben Valentina und ihre Familie überlegt, wie sie das Thämer’s am Großneumarkt bezeichnen wollen. Für eine Kneipe sei das Lokal zu schick, für ein Restaurant nicht schick genug. „Das perfekte Wort ist ‚Heimat‘“, meint Valentina. „Wenn die Gäste herkommen, fühlen sie sich wie zuhause.“ Die Leute kommen her, um gemeinsam zu lachen, zu weinen, zu feiern. „Man kann nicht die ganze Welt verändern, aber man kann seine eigene Welt verändern.“ Beim Interview ist die familiäre Atmosphäre gleich zu spüren. Kein Wunder, schließlich haben schon Valentinas Großeltern im Thämer‘s gearbeitet. Inzwischen leiten Valentina und ihre Mutter das Geschäft. Ursprünglich hat Valentina Schauspiel studiert. Nebenbei arbeitet sie als Schauspiel-Coach. Doch vor allem ist Valentina leidenschaftliche Gastgeberin. Auch als Geschäftsführerin hilft sie beim Kochen und Putzen oder bedient die Gäste. Sie liebt die Abwechslung und den Gestaltungsspielraum, den ihr die Arbeit bietet. Was ich ganz wichtig finde, ist, dass man es für sich macht. Valentina wünscht sich, dass mehr Leute ihren Leidenschaften nachgehen. Dass sie sich morgens fragen, was sie aus einem Tag machen können. Insbesondere jungen Menschen rät die zweifache Mutter, sich auszuprobieren und mit den Eltern oder der Familie den eigenen Leidenschaften auf den Grund zu gehen."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Valentina-Popovic/valentina-popovic.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:39.679204+00:00","lastSeen":"2026-03-15T17:47:39.679204+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/Valentina-Popovic/valentina-popovic.html","crawledAt":"2026-03-15T17:47:39.680226Z","crawlId":"contacts-seeded-1773596859","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"6d3e6253760a7a88d2118e848c4ea3ddfcc0ed65fabf6c339c667839dceb2de3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:39.680226+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('87fc03f2-802a-420f-8af3-088d9286c5cd', 'contacts', 'https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/unser-land-in-arbeit.html', 'active', NULL, '2026-03-15T17:47:41.182230+00:00', '{"id":"87fc03f2-802a-420f-8af3-088d9286c5cd","title":"Unser Land in Arbeit","summary":{"de":"Kultur, Austausch, Integration, Selbstverwirklichung: Zehn Bürgerinnen und Bürger erzählen hier, warum sie arbeiten. So ehrlich, aufregend und bunt, wie das Arbeitsleben eben ist."},"content":{"de":"Stolz. Würde. Leidenschaft. Fürsorge. Verantwortung. Sicherheit. Und auch: Heimat. Fragt man Menschen, was sie mit ihrer Arbeit verbinden, geben sie sehr unterschiedliche Antworten. Denn Arbeiten ist viel mehr, als Geld zu verdienen. Arbeit ist Kultur, Austausch, Integration, Selbstverwirklichung. Bürgergeld, Mindestlohn, Rente – über Arbeit wird viel und engagiert diskutiert. Noch wichtiger sind aber die, die durch ihre Arbeit das Land am Laufen halten. Die, die uns pflegen, unsere Kinder unterrichten, für uns backen, uns die Haare schneiden. Die, die ihre Träume verwirklichen oder gute Bedingungen für kommende Generationen schaffen möchten. Wir erzählen die Geschichten von Menschen und ihren Gründen, ihrer Arbeit nachzugehen. So ehrlich, aufregend und bunt, wie das Arbeitsleben eben ist. Seit dem 25. September im ganzen Land −­ und hier. Wählen Sie eine der Kacheln aus und erfahren Sie mehr zu den Personen."},"url":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/unser-land-in-arbeit.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:41.182230+00:00","lastSeen":"2026-03-15T17:47:41.182230+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Arbeit/Unser-Land-in-Arbeit/unser-land-in-arbeit.html","crawledAt":"2026-03-15T17:47:41.183210Z","crawlId":"contacts-seeded-1773596861","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"7f9c3ea00ec627e4ada995f9af1edfba21d132c3b193664fcb7e1cd9c0d8b025"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:41.183210+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1a8ad946-9fd7-4ff3-bcbc-326ea73178d4', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Arbeitnehmerentsendung/arbeitnehmerentsendung.html', 'active', NULL, '2026-03-15T17:47:42.579455+00:00', '{"id":"1a8ad946-9fd7-4ff3-bcbc-326ea73178d4","title":"Arbeitnehmerentsendung","summary":{"de":"Eine Arbeitnehmerentsendung liegt vor, wenn ein Arbeitgeber mit Sitz in einem anderen Mitgliedstaat bei ihm beschäftigte Arbeitnehmer für einen gewissen Zeitraum nach Deutschland schickt, damit sie dort Arbeiten für ihn ausführen. Damit macht der Arbeitgeber von seiner Dienstleistungsfreiheit Gebrauch. Diese wird ihm in Art. 56 AEUV garantiert. Für die Arbeitnehmer sind ihre Rechte hinsichtlich des Arbeitsrechts in der Entsende-Richtlinie ausgestaltet. Darin ist festgelegt, welche Rechte ( z.B. Lohn, Urlaub, Unterkunft) er im Aufnahmestaat mindestens hat. Die Entsende-RL regelt damit, dass der Arbeitnehmer, obwohl er in einem anderen Mitgliedstaat bei seinem Arbeitgeber angestellt ist, dennoch in den Genuss bestimmter Arbeitsbedingungen des Aufnahmestaates gelangen kann."},"content":{"de":"Hand­ha­bung der Be­schei­ni­gung A 1 bei kurz­fris­tig an­be­raum­ten und kurz­zei­ti­gen Tä­tig­kei­ten im EU-Aus­land, den EWR-Staa­ten Is­land, Liech­ten­stein und Nor­we­gen so­wie der Schweiz [PDF, 311KB]"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Arbeitnehmerentsendung/arbeitnehmerentsendung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:42.579455+00:00","lastSeen":"2026-03-15T17:47:42.579455+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Arbeitnehmerentsendung/arbeitnehmerentsendung.html","crawledAt":"2026-03-15T17:47:42.579455Z","crawlId":"contacts-seeded-1773596862","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"73b7d8bd48dc7297707d6c540f135bc4d5a96367177dc1f4e1888c49297b8377"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:42.579455+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('649db80a-411e-4a72-9bb2-8b10503fc839', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Arbeitnehmerfreizuegigkeit/arbeitnehmerfreizuegigkeit.html', 'active', NULL, '2026-03-15T17:47:43.794954+00:00', '{"id":"649db80a-411e-4a72-9bb2-8b10503fc839","title":"Arbeitnehmerfreizügigkeit","summary":{"de":"Mobile Arbeitnehmer*innen der Europäischen Union genießen umfassenden Schutz vor Benachteiligungen aufgrund ihrer Staatsangehörigkeit."},"content":{"de":"Die Arbeitnehmerfreizügigkeit gibt Staatsangehörigen der EU-Mitgliedstaaten das Recht, ihren Arbeitsplatz innerhalb der EU frei zu wählen. Sie benötigen keine Arbeitserlaubnis und haben in jedem anderen Mitgliedstaat den gleichen Zugang zu Beschäftigung wie die Staatsangehörigen dieses Mitgliedstaats. Das heißt, sie und ihre Familienangehörigen haben dort ein Aufenthaltsrecht zur Ausübung ihrer Erwerbstätigkeit. Nach der Rechtsprechung des Europäischen Gerichtshofs gilt als Arbeitnehmer, wer für einen anderen nach dessen Weisung eine tatsächliche und echte Tätigkeit ausübt, und eine Leistung erbringt, für die er als Gegenleistung eine Vergütung erhält. Über das Vorliegen der Arbeitnehmereigenschaft ist im Rahmen einer Gesamtschau aller Umstände sowohl der fraglichen Tätigkeiten als auch des fraglichen Vertragsverhältnisses zu entscheiden. Dabei bleiben Tätigkeiten, die einen so geringen Umfang haben, dass sie sich als völlig untergeordnet und unwesentlich darstellen, außer Betracht. Die Arbeitnehmerfreizügigkeit verbietet gemäß Artikel 45 Absatz 2 des Vertrags über die Arbeitsweise der Europäischen Union (AEUV) die Diskriminierung von EU-Arbeitnehmer/innen aufgrund ihrer Staatsangehörigkeit. Dies erstreckt sich auch auf die Gewährung aller sozialen und steuerlichen Vergünstigungen. Auch eine mittelbare (\"versteckte\") Diskriminierung ist verboten, d.h., Maßnahmen, die typischerweise Ausländer*innen gegenüber Inländer*innen benachteiligen, ohne sich direkt auf das Merkmal der Staatsangehörigkeit zu beziehen, sind ebenfalls unzulässig. Eine solche mittelbare Diskriminierung kann zum Beispiel gegeben sein, wenn für eine Stelle in Deutschland deutsche Sprachkenntnisse gefordert werden, die objektiv nicht erforderlich sind. Ist es für eine Arbeitsstelle konkret erforderlich deutsche Sprachkenntnisse zu haben, darf der Arbeitgeber für diese Stelle auch einen Nachweis von Sprachkenntnissen verlangen. Er darf jedoch nicht verlangen, dass die Sprachprüfung in Deutschland abgelegt wurde. Zudem darf ein Arbeitgeber eine Unionsbürgerin oder einen Unionsbürger auch nicht allein wegen des Wohnsitzes in einem anderen Mitgliedstaat gegenüber anderen Bewerberinnen und Bewerbern benachteiligen. Als Unionsbürger*in darf man auch in einen anderen Mitgliedstaat einreisen und sich dort zur Arbeitsuche aufhalten. Jedoch besteht dieses Recht zunächst nur für einen Zeitraum von bis zu sechs Monaten, darüber hinaus nur, solange der Betroffene nachweisen kann, dass er weiterhin Arbeit sucht und begründete Aussicht hat, eingestellt zu werden ( § 2 Absatz 2 Nr. 1a Freizügigkeitsgesetz/EU ). Grundsätzlich besteht während dieses Aufenthalts zur Arbeitssuche kein Anspruch auf Leistungen der Grundsicherung für Arbeitssuche nach dem Sozialgesetzbuch II (§ 7 Abs. 1 Satz 2 lit. b SGB II, siehe weiter unten ausführlich). Die Arbeitnehmerfreizügigkeit gilt unter bestimmten Umständen (zum Beispiel bei vorübergehender Arbeitsunfähigkeit nach einem Unfall oder bei unfreiwilliger Arbeitslosigkeit) auch nach Beendigung des Arbeitsverhältnisses für sechs Monate oder länger fort und verleiht der Unionsbürgerin oder dem Unionsbürger und den Familienangehörigen während dieser Zeit ein ansonsten voraussetzungsloses Aufenthaltsrecht. Mit der im Jahr 2014 verabschiedeten EU-Richtlinie 2014/54/EU über Maßnahmen zur Erleichterung der Ausübung der Rechte, die Arbeitnehmer*innen im Rahmen der Freizügigkeit zustehen, wurden Maßnahmen eingeführt, die die Arbeitnehmerfreizügigkeitsrechte in der Praxis stärken sollen. Die Richtlinie verpflichtet die Mitgliedstaaten insbesondere zur Einrichtung von nationalen Beratungsstellen für Wanderarbeitnehmer und ihre Familienangehörigen, hinsichtlich des Zugangs zur Beschäftigung, Beschäftigungs- und Arbeitsbedingungen, Zugang zu sozialen und steuerlichen Vergünstigungen, Zugang zu beruflicher Bildung und Wohnraum, und deren Aufgabe darüber hinaus in der Erhebung von Daten und wissenschaftlichen Analysen zur Arbeitnehmerfreizügigkeit liegt. In Deutschland wurde im Mai 2016 die EU-Gleichbehandlungsstelle eingerichtet, die allen EU-Arbeitnehmerinnen und EU-Arbeitnehmern offensteht. Sie stellt Informationen zu den Themen Arbeiten und Leben in zehn Fremdsprachen zur Verfügung. Sie bietet Orientierungshilfen zu allen Fragen der Arbeitnehmerfreizügigkeit und hilft den Arbeitnehmerinnen und Arbeitnehmern eine unabhängige rechtliche Beratung zu finden. Die Stelle kooperiert mit allen für das Themenfeld relevanten Akteuren, fördert die Vernetzung mit Gewerkschaften und Arbeitgeberverbänden sowie mit staatlichen und nichtstaatlichen Einrichtungen."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Arbeitnehmerfreizuegigkeit/arbeitnehmerfreizuegigkeit.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:43.794954+00:00","lastSeen":"2026-03-15T17:47:43.794954+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Arbeitnehmerfreizuegigkeit/arbeitnehmerfreizuegigkeit.html","crawledAt":"2026-03-15T17:47:43.795955Z","crawlId":"contacts-seeded-1773596863","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"fbf25bcdc089c2c89a12cf87397c9d62c53f9e1e5769e92a144f48a1020f173b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:43.795955+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e9cdf99e-713f-42df-b7aa-8add25dd20df', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Faire-Mobilitaet/faire-mobilitaet.html', 'active', NULL, '2026-03-15T17:47:44.992994+00:00', '{"id":"e9cdf99e-713f-42df-b7aa-8add25dd20df","title":"Faire Mobilität","summary":{"de":"Die Bundesregierung unterstützt die wachsende Arbeitskräftemobilität in der Europäischen Union mit Informations- und Beratungsangeboten für europäische Arbeitskräfte über arbeits- und sozialrechtliche Bedingungen auf dem deutschen Arbeitsmarkt."},"content":{"de":"Das Beratungs- und Informationsangebot \"Faire Mobilität\" des Deutschen Gewerkschaftsbundes (DGB) wird seit dem 1. Januar 2021 auf Grundlage des Arbeitnehmer-Entsendegesetzes (AEntG) durchgeführt. Zuvor hat das BMAS das Beratungsangebot zehn Jahre als Projekt gefördert. Ziel ist es, die Freizügigkeit und die Mobilität der EU -Arbeitnehmerinnen und Arbeitnehmer fair zu gestalten. Dazu müssen sie ihre Rechte in Deutschland kennen, um diese auch in der Praxis wahrnehmen zu können. Das Beratungsnetzwerk \"Faire Mobilität\" setzt sich für gerechte Löhne und bessere Arbeitsbedingungen dieser Zielgruppe ein. Faire Mobilität informiert, berät und unterstützt EU-Arbeitnehmerinnen und Arbeitnehmer zu arbeits- und sozialrechtlichen Themen ( u.a. Lohn, Arbeitszeit, Kündigung etc. ) in deren Herkunftssprache. Die Beratungsstellen von “Faire Mobilität“ sind bundesweit an dreizehn Standorten (Kiel, Oldenburg, Dortmund, Berlin, Frankfurt a.M., Stuttgart, München, Nürnberg, Mannheim, Erfurt, Grünheide, Rheda-Wiedenbrück und Freiburg im Breisgau) vertreten. Die Beratung wird sowohl durch aufsuchende Beratung als auch telefonisch, über E-Mail und bundesweite Aktionen angeboten. Zudem werden über die Internetseite, Social Media und durch Informationsmaterialien mehrsprachige Informationen zur Verfügung gestellt und verbreitet. Viele Bundesländer haben in den letzten Jahren ebenfalls Informations- und Beratungsstellen für mobile Beschäftigte aus den EU-Mitgliedstaaten aufgebaut. Bundes- und landesfinanzierte Beratungsstellen arbeiten eng zusammen, um eine möglichst flächendeckende und qualitativ hochwertige Beratung sicherzustellen. Projekt \"Faire Mobilität und seinen Beratungsleistungen Seit dem 1. August 2022 bestehen nach § 23c AEntG Informationspflichten für inländische Arbeitgeber, die einen Unionsbürger mit Wohnsitz oder gewöhnlichem Aufenthalt in einem anderen Mitgliedstaat in Deutschland einstellen. Spätestens am ersten Arbeitstag müssen Arbeitnehmerinnen und Arbeitnehmer schriftlich in einer für sie verständlichen Sprache auf die bestehenden Informations- und Beratungsangebote von \"Faire Mobilität\" hingewiesen und die aktuellen Kontaktdaten der Beratungsstelle angegeben werden. Dies umfasst den Hinweis auf das kostenlose und von der Mitgliedschaft in einer Gewerkschaft losgelöste Beratungsangebot zu arbeits- und sozialrechtlichen Themen. Als Kontaktdaten sollten zumindest die E-Mail-Adresse von \"Faire Mobilität\" sowie die Telefonnummern der verschiedensprachigen Hotline des Beratungsangebotes angegeben werden."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Faire-Mobilitaet/faire-mobilitaet.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:44.992994+00:00","lastSeen":"2026-03-15T17:47:44.992994+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Faire-Mobilitaet/faire-mobilitaet.html","crawledAt":"2026-03-15T17:47:44.993591Z","crawlId":"contacts-seeded-1773596864","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f9ab2916424f5a48e373a53ea54f38f9bb61e6e6cd923c97326853c2b6447b82"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:44.993591+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6ff805c9-2a29-4aab-808a-fc7c37c6beb2', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Koordinierung-sozialer-Rechte/koordinierung-sozialer-rechte.html', 'active', NULL, '2026-03-15T17:47:46.225881+00:00', '{"id":"6ff805c9-2a29-4aab-808a-fc7c37c6beb2","title":"Koordinierung sozialer Rechte","summary":{"de":"Sie planen einen Aufenthalt im EU -Ausland, in Norwegen, Island, Liechtenstein oder der Schweiz? Als Arbeitnehmerin oder Urlauber? Oder Sie wollen im Ausland wohnen, z. B. um dort Ihre Zeit als Rentner zu verbringen? Dann müssen Sie einiges beachten, um auf der \"sozial sicheren Seite\" zu bleiben."},"content":{"de":"Falls Sie als Arbeitnehmer oder Arbeitnehmerin in einem Mitgliedstaat eine Beschäftigung ausüben wollen, gelten für Sie grundsätzlich die Rechtsvorschriften des Beschäftigungsstaates. Für Unionsbürgerinnen und -bürger, die z. B. bei einem Arbeitgeber in Deutschland beschäftigt sind, gelten demnach grundsätzlich die deutschen Rechtsvorschriften zur sozialen Sicherheit. Ausnahmen von der genannten Grundregel gelten vor allem für aus anderen Mitgliedstaaten entsandte Arbeitnehmerinnen und Arbeitnehmer und für Personen, die in zwei oder mehr Mitgliedstaaten beschäftigt sind. Hier finden Sie detailliertere Informationen zu den Regelungen in besonderen Fällen: Praktischer Leitfaden zum anwendbaren Recht in der EU, dem EWR und der Schweiz (2013) der Europäischen Kommission Deutschen Verbindungsstelle Krankenversicherung - Ausland (DVKA) Handhabung der Bescheinigung A 1 bei kurzfristig anberaumten und kurzzeitigen Tätigkeiten im EU-Ausland, den EWR-Staaten Island, Liechtenstein und Norwegen sowie der Schweiz [PDF, 311KB] Wenn Sie einen Kurzaufenthalt oder Urlaub im Ausland machen, können Sie medizinische Leistungen, etwa bei einem Arzt oder in einem Krankenhaus, die während eines Urlaubs oder anderen vorübergehenden Aufenthalts in einem dieser Länder notwendig werden, zu denselben Bedingungen wie die Staatsangehörigen des betreffenden Landes in Anspruch nehmen. Ihre Europäische Krankenversicherungskarte hilft Ihnen dabei, Ihre Ansprüche nachzuweisen. In Deutschland gesetzlich krankenversicherte Personen haben diese sogenannte EHIC in der Regel auf der Rückseite der Gesundheitskarte abgedruckt. Auf der Internetseite der Europäischen Kommission sind Beispiele für EHICs aus sämtlichen EU-Staaten abgebildet. Dort finden Sie außerdem Informationen zum Umfang der Krankenbehandlung und zu den Gesundheitssystemen der einzelnen EU-Länder."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Koordinierung-sozialer-Rechte/koordinierung-sozialer-rechte.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:46.225881+00:00","lastSeen":"2026-03-15T17:47:46.225881+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Koordinierung-sozialer-Rechte/koordinierung-sozialer-rechte.html","crawledAt":"2026-03-15T17:47:46.226907Z","crawlId":"contacts-seeded-1773596866","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"2003c23d583b80df7f9003bc09d73b005b63ea670f9b7f0eec1b2374aae7e368"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:46.226907+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b0806c3a-0585-470a-9e1d-4de7d42f1a4c', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Rechtsgrundlagen/rechtsgrundlagen.html', 'active', NULL, '2026-03-15T17:47:47.568515+00:00', '{"id":"b0806c3a-0585-470a-9e1d-4de7d42f1a4c","title":"Rechtsgrundlagen","summary":{"de":"Die (Arbeitnehmer-) Freizügigkeit ist in den Europäischen Verträgen verankert und wird durch EU -Richtlinien und -Verordnungen konkretisiert."},"content":{"de":"Die Personenfreizügigkeit der Unionsbürger*innen beinhaltet das Recht, sich in der Europäischen Union (EU) frei zu bewegen, in jeden Mitgliedstaat einzureisen und sich dort aufzuhalten. Sie ist in Artikel 21 des Vertrags über die Anwendungsweise der Europäischen Union (AEUV) verankert und enthält im Zusammenwirken mit Art. 18 AEUV auch ein Verbot der Diskriminierung aus Gründen der Staatsangehörigkeit. Das Recht auf Freizügigkeit ist vor allem in der Richtlinie 2004/38/EG (\"Freizügigkeitsrichtlinie\") ausgestaltet und durch das Freizügigkeitsgesetz/EU in nationales Recht umgesetzt. Die Freizügigkeitsrichtlinie (im Nachfolgenden zitiert mit Artikelbezeichnung) und das Freizügigkeitsgesetz/EU (im Nachfolgenden zitiert mit Paragraphenbezeichnung) sehen ein gestaffeltes Recht auf Aufenthalt für verschiedene Personengruppen und Konstellationen vor: Daueraufenthaltsstatus nach regelmäßig fünf Jahren ununterbrochenen rechtmäßigen Aufenthalts (Artikel 16; § 2 Absatz 2 Nr. 7) Erwerbstätigenstatus (als Arbeitnehmer oder Selbständiger) sowie ein der Erwerbstätigkeit nachwirkender Status ( Art. 7 Absatz 1 lit. a); § 2 Absatz 2 Nr. 1 und 2 oder Art. 7 Absatz 3; § 2 Absatz 3) Nichterwerbstätige mit ausreichenden eigenen Existenzmitteln und Krankenversicherungsschutz (Artikel 7 Absatz 1 lit. b); § 2 Absatz 2 Nr. 5) Arbeitsuchende für die Dauer von regelmäßig sechs Monaten und länger, wenn entsprechende Einstellungsaussichten bestehen ( EuGH -Urteil \"Antonissen\" [C-292/89]; § 2 Absatz 2 Nr. 1a)"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Rechtsgrundlagen/rechtsgrundlagen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:47.568515+00:00","lastSeen":"2026-03-15T17:47:47.568515+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/Rechtsgrundlagen/rechtsgrundlagen.html","crawledAt":"2026-03-15T17:47:47.568515Z","crawlId":"contacts-seeded-1773596867","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"b0914015d4d2962fccd58bf763634b69db46935128eb960923f3771c3785fd5a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:47.569516+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f61d4a46-ed09-40cb-8ae4-eeb0bfb930c9', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/arbeiten-innerhalb-der-EU.html', 'active', NULL, '2026-03-15T17:47:48.698593+00:00', '{"id":"f61d4a46-ed09-40cb-8ae4-eeb0bfb930c9","title":"Arbeiten innerhalb der EU","summary":{"de":"Ein Überblick über die Rechtsgrundlagen, die Differenzierung fachlicher Termini und Informationen zu Leistungsansprüchen"},"content":{"de":"Die Mobilität innerhalb der Europäischen Union ist eine der wichtigsten Errungenschaften der europäischen Integration. Staatsangehörige eines Mitgliedstaates der EU haben das Recht, ihren Arbeitsplatz innerhalb der EU frei zu wählen und Zugang zu Sozialleistungen zu erhalten. Diese Freiheiten sind durch Verträge festgelegt und geschützt. Unter dem Motto \"Mobilität ist Ihre Entscheidung, Schutz ist Ihr Recht\" informiert die Europäische Arbeitsbehörde (ELA), wie man bei einem Umzug zum Arbeiten oder bei der Entsendung von Arbeitnehmern ins Ausland sozialversichert bleibt, Leistungen beantragt und Verpflichtungen erfüllt."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/arbeiten-innerhalb-der-EU.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:48.698593+00:00","lastSeen":"2026-03-15T17:47:48.698593+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Arbeiten-innerhalb-der-EU/arbeiten-innerhalb-der-EU.html","crawledAt":"2026-03-15T17:47:48.699610Z","crawlId":"contacts-seeded-1773596868","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"536e13f8c7fcbe9b8009d323d33f115d7ee645873f8ad79018b3a44bd803c132"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:48.699610+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d2f89d48-cc3a-460c-9024-569694321854', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Europaeische-Saeule-sozialer-Rechte/essr.html', 'active', NULL, '2026-03-15T17:47:50.058782+00:00', '{"id":"d2f89d48-cc3a-460c-9024-569694321854","title":"Europäische Säule sozialer Rechte","summary":{"de":"Die Europäische Säule sozialer Rechte (ESSR) ist seit ihrer Proklamation 2017 der gemeinsame Kompass für ein koordiniertes Vorgehen der EU -Mitgliedstaaten im Bereich Beschäftigungs- und Sozialpolitik. Sie soll dazu beitragen, Ungleichheiten innerhalb der EU zu reduzieren, die Lebensverhältnisse der Bürgerinnen und Bürger in der gesamten EU zu verbessern und den sozialen Schutz zu stärken."},"content":{"de":"Die ESSR umfasst insgesamt 20 Grundsätze aus dem Bereich der Beschäftigungs- und Sozialpolitik. Diese sind in drei Kapitel unterteilt Die Bundesregierung bekennt sich zur Umsetzung der ESSR als Grundpfeiler zur Stärkung der sozialen Dimension Europas. Die COVID-19 Pandemie und der russische Angriffskrieg auf die Ukraine und dessen Folgen haben die Welt vor neue Herausforderungen gestellt - so auch die EU. Auch und gerade zur Bewältigung der wirtschaftlichen und sozialen Folgen bildet die ESSR die gemeinsame Grundlage für Aktivitäten und Initiativen auf europäischer, aber auch auf nationaler, regionaler und lokaler Ebene. Die Maßnahmen sollten sich ergänzen und gegenseitig verstärken, um konkrete und spürbare Verbesserungen für die Bürgerinnen und Bürger überall in der EU zu erreichen. Im Jahr 2021 hat die EU-Kommission einen Aktionsplan zur weiteren Umsetzung der ESSR vorgelegt. Dieser schlägt zur Förderung der sozialen Aufwärtskonvergenz drei neue sozial- und beschäftigungspolitische Kernziele für die Zeit bis 2030 vor. Bis 2030 sollen mindestens 78 Prozent der Bevölkerung im Alter von 20 bis 64 Jahren erwerbstätig sein (Erwerbstätigkeitsziel), sollen mindestens 60 Prozent aller Erwachsenen im Alter von 25 bis 64 Jahren jedes Jahr an einer Weiterbildungsmaßnahme teilnehmen (Weiterbildungsziel),"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Europaeische-Saeule-sozialer-Rechte/essr.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:50.058782+00:00","lastSeen":"2026-03-15T17:47:50.058782+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Europaeische-Saeule-sozialer-Rechte/essr.html","crawledAt":"2026-03-15T17:47:50.058782Z","crawlId":"contacts-seeded-1773596870","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f5f3a709f6ac14d18e641b90900335d5d1dfe509d8e3188ac275d3489b72e629"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:50.060368+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2138d135-7e3d-49cc-81a1-7c79cf9a2313', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Jugendgarantie/jugendgarantie.html', 'active', NULL, '2026-03-15T17:47:51.266274+00:00', '{"id":"2138d135-7e3d-49cc-81a1-7c79cf9a2313","title":"Jugendgarantie","summary":{"de":"Die Jugendgarantie ist eine wichtige europäische Initiative zur Bekämpfung von Jugendarbeitslosigkeit in der EU. Sie soll junge Menschen schnell und zielgerichtet beim Einstieg ins Berufsleben unterstützen."},"content":{"de":"Aufgrund einer Empfehlung des Rates der Europäischen Union aus dem Jahr 2013 haben alle Mitgliedstaaten die EU -Jugendgarantie umgesetzt. Damit sollen alle jungen Menschen innerhalb von vier Monaten nach Schul- oder Ausbildungsabschluss bzw. nachdem sie arbeitslos geworden sind, ein hochwertiges Angebot für eine Beschäftigung, eine Aus- oder Weiterbildung oder ein Praktikum erhalten. Zentrales Anliegen ist, über eine möglichst frühzeitige Unterstützung von Beginn an zu verhindern, dass junge Menschen über einen längeren Zeitraum arbeitslos bleiben. Zur Finanzierung der Umsetzung der Jugendgarantie konnten Mitgliedstaaten mit einer hohen Jugend-Arbeitslosigkeit bis 2023 finanzielle Unterstützung aus EU-Mitteln im Rahmen der Beschäftigungsinitiative junge Menschen erhalten. Die Jugendgarantie hat jungen Menschen Chancen eröffnet und Impulse für strukturelle Reformen und Innovation in den Mitgliedstaaten gegeben. Als Ergebnis haben die meisten öffentlichen Arbeitsverwaltungen ihre Dienste für junge Menschen verbessert und ausgebaut. Bereits in den ersten sieben Jahren nach Einführung der Jugendgarantie sank die Anzahl junger Menschen in der EU, die weder in Beschäftigung noch in Bildung oder Ausbildung waren ( sog. NEETs), um ungefähr 1,7 Millionen. Nach einem zwischenzeitlichen Anstieg in der Corona-Pandemie erreichten sowohl NEET -Quote mit 11,7 Prozent als auch die Jugenderwerbslosigkeitsquote mit 11,3 Prozent zuletzt ihren jeweils niedrigsten Stand in den EU-27 seit Einführung der Jugendgarantie. Die nationale Umsetzung der Jugendgarantie wird im Rahmen des Europäischen Semesters, also der sozioökonomischen Koordinierung auf europäischer Ebene, regelmäßig von der Europäischen Kommission anhand von Indikatoren überwacht. Diese messen die Effektivität der Leistungserbringung für junge Menschen. Im Oktober 2020 haben die EU-Mitgliedstaaten einstimmig eine Ratsempfehlung zur Stärkung der Jugendgarantie angenommen. Die Empfehlung basiert auf einem Vorschlag der Kommission vom 1. Juli 2020 zur Stärkung der Jugendgarantie, der wiederum Teil eines Pakets zur Unterstützung der Jugendbeschäftigung ist. Die weiterentwickelte Jugendgarantie sieht gegenüber der Empfehlung aus 2013 eine Ausweitung der Altersgrenze von unter 25 auf 29 Jahre vor, damit mehr junge Menschen von der Jugendgarantie profitieren können. Neu ist auch der Fokus auf besonders schutzbedürftige junge Menschen – wie beispielweise diejenigen, die mit einer Behinderung leben, die einer Minderheit angehören oder die in abgelegenen ländlichen Gebieten oder benachteiligten Stadtteilen wohnen. Jungen Menschen soll eine möglichst frühzeitige und individuell zugeschnittene Beratung angeboten und der Erwerb von – angesichts des Wandels der Arbeitswelt erforderlichen – digitalen und ökologischen Qualifikationen ermöglicht werden."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Jugendgarantie/jugendgarantie.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:51.266274+00:00","lastSeen":"2026-03-15T17:47:51.266274+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Jugendgarantie/jugendgarantie.html","crawledAt":"2026-03-15T17:47:51.266274Z","crawlId":"contacts-seeded-1773596871","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"a21dcadfbdfb0ef5c71e281578ac0e9d7cadb22d461cd73cd4002cb6ec0e6f3f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:51.266274+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5e145f86-eb48-4c74-a3d2-366c7b1ff01e', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Menschen-mit-Behinderung/menschen-mit-behinderung.html', 'active', NULL, '2026-03-15T17:47:52.631696+00:00', '{"id":"5e145f86-eb48-4c74-a3d2-366c7b1ff01e","title":"Menschen mit Behinderung","summary":{"de":"Rund 70 Millionen Menschen in der Europäischen Union (ein Sechstel der Bevölkerung) haben leichte bis schwere Behinderungen. Nach wie vor stehen sie vor zahlreichen Hindernissen, wenn es etwa um die gleichberechtigte und selbstbestimmte Teilhabe am gesellschaftlichen Leben, dem Zugang zur Arbeitswelt oder zum Gesundheitssystem geht. Die Teilhabe von Menschen mit Behinderung ist daher auch auf europäischer Ebene ein zentrales Thema. Bei der Gewährleistung von Gleichberechtigung und Inklusion geht es um grundlegende Rechte. Von ihrer Gewährleistung profitiert die gesamte Gesellschaft."},"content":{"de":"Im März 2021 hat die Europäische Kommission die \" Strategie für die Rechte von Menschen mit Behinderungen 2021-2030 \" angenommen. Diese Zehnjahresstrategie zur Verbesserung des Lebens von Menschen mit Behinderungen in Europa und weltweit baut auf den Ergebnissen der vorangegangenen \" Europäische Strategie zugunsten von Menschen mit Behinderungen 2010-2020\". Die neue Strategie umfasst ein Bündel von Maßnahmen und Leitinitiativen in verschiedenen Bereichen und hat folgende Prioritäten, wie: Barrierefreiheit: grundlegende Voraussetzung, um sich frei bewegen und Zugang zu allen Bereichen des öffentlichen und privaten Lebens zu haben. ein unabhängiges, selbstbestimmtes Leben mit guter Lebensqualität zu gewährleisten, eine gleichberechtigte Teilhabe zu gewährleisten, da Menschen mit Behinderungen wirksam vor jeglicher Form von Diskriminierung und Gewalt geschützt, Chancengleichheit und gleichberechtigten Zugang zu Justiz, Bildung, Kultur, Sport und Tourismus sichergestellt, aber auch ein gleichberechtigter Zugang zu allen Gesundheitsdiensten gewährleistet werden soll. EU-Behindertenausweis: Die Europäische Kommission hat einen Europäischen Behindertenausweis vorschlagen, der für alle EU-Länder gilt. Der Ausweis wird es Menschen mit Behinderungen erleichtern, angemessene Unterstützung zu erhalten, wenn sie in ein anderes Land der Europäischen Union reisen. Die Verhandlungen sollen bis zur Europawahl im Juni 2024 abgeschlossen werden."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Menschen-mit-Behinderung/menschen-mit-behinderung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:52.631696+00:00","lastSeen":"2026-03-15T17:47:52.631696+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Menschen-mit-Behinderung/menschen-mit-behinderung.html","crawledAt":"2026-03-15T17:47:52.632622Z","crawlId":"contacts-seeded-1773596872","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"14aa70b62ec0e269c10bc879cbd340c8f1ca7c6a2764f6c4d1031c5431f43e8a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:52.632622+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b94ac3df-1a5e-4d9f-ae96-42c660ecd99e', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Themen-der-europaeischen-Arbeitswelt/ueberblick-themen-der-europaeischen-arbeitswelt.html', 'active', NULL, '2026-03-15T17:47:53.692266+00:00', '{"id":"b94ac3df-1a5e-4d9f-ae96-42c660ecd99e","title":"Überblick: Themen der europäischen Arbeitswelt","summary":{"de":"Europa und die Zusammenarbeit auf EU-Ebene spielen eine wichtige Rolle für das Bundesministerium für Arbeit und Soziales (BMAS). Denn auch wenn die Arbeitsmarkt- und Sozialpolitik in der Aufgabenverteilung zwischen der Europäischen Union (EU) und ihren Mitgliedstaaten weitgehend auf nationaler Ebene festgelegt werden, so reichen vielfach rein nationale Regelungen heute nicht mehr aus."},"content":{"de":"Durch grenzüberschreitendes Arbeiten, die Mobilität in der EU, aber auch durch Prozesse wie bspw. die Digitalisierung sehen wir, dass wir auch europäische Regelungen brauchen, um Arbeitnehmerinnen und Arbeitnehmer ausreichend zu schützen. Das gilt zu Beispiel, wenn es um die Rechte und Arbeitsbedingungen von Arbeitnehmerinnen und Arbeitnehmern aus anderen EU-Ländern geht, die als entsandte oder mobile Beschäftigte in Deutschland im Einsatz sind. Oder wenn geregelt wird, dass und wie die unterschiedlichen Sozialversicherungssysteme über die Ländergrenzen hinweg koordiniert werden. Schließlich ist es von enormer Bedeutung, dass zum Beispiel Bürgerinnen und Bürger, die im Laufe ihres Lebens im verschiedenen EU-Ländern gearbeitet haben, auch Renten entsprechend ihrer Beiträge aus den verschiedenen Ländern bekommen, selbst wenn sie mittlerweile in einem anderen EU-Land wohnen. Ganz konkret schafft die EU mit ihren Richtlinien und Verordnungen europaweite Standards für den Arbeits- und Gesundheitsschutz, die dann an jedem Arbeitsplatz in Deutschland gelten - zum Beispiel die Begrenzung von krebserregenden Chemikalien. Oder sie legt über die Europäische Arbeitszeitrichtlinie fest, wie viele Stunden Arbeitnehmerinnen und Arbeitnehmer überall in der EU maximal wöchentlich arbeiten dürfen. Das sind nur einige Beispiele. Sie zeigen aber, wie sehr Europapolitik und Europarecht die deutsche Arbeitsmarkt- und Sozialpolitik bewegen und dass die Entscheidungen der EU wesentlichen Einfluss darauf haben, wie wir in Deutschland leben und arbeiten. Das BMAS setzt sich deshalb für ein starkes soziales Europa ein - ein Europa, das zu Wohlstand und Teilhabe, zu beruflichen Chancen, fairer Mobilität und zur sozialen Sicherheit der Bürgerinnen und Bürger beiträgt und das sozialen Fortschritt und Zusammenhalt fördert. Dazu bringen sich das Ministerium aktiv in Entscheidungsprozesse auf EU-Ebene ein - sei es im Rahmen von europäischer Rechtsetzung oder politischen Initiativen - und arbeitet eng mit den europäischen Institutionen, den anderen Mitgliedstaaten der EU, den Sozialpartnern und der Zivilgesellschaft zusammen."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Themen-der-europaeischen-Arbeitswelt/ueberblick-themen-der-europaeischen-arbeitswelt.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:53.692266+00:00","lastSeen":"2026-03-15T17:47:53.692266+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/Themen-der-europaeischen-Arbeitswelt/ueberblick-themen-der-europaeischen-arbeitswelt.html","crawledAt":"2026-03-15T17:47:53.692266Z","crawlId":"contacts-seeded-1773596873","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"99e939b6a8bde16f4c8a39161352de989fecddcb98800c438ccadd2bf8b32744"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:53.692266+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('51388555-e8a4-4715-948f-7e0742f7bcee', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/beschaeftigungs-und-sozialpolitik-in-der-eu.html', 'active', NULL, '2026-03-15T17:47:54.555728+00:00', '{"id":"51388555-e8a4-4715-948f-7e0742f7bcee","title":"Beschäftigungs- und Sozialpolitik in der EU","summary":{"de":"Zu den Zielen der Europäischen Union gehören die Förderung von Beschäftigung und die Sicherung sozialer Grundrechte."},"content":{"de":"Zu den Zielen der Europäischen Union gehören die Förderung von Beschäftigung und die Sicherung sozialer Grundrechte."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/beschaeftigungs-und-sozialpolitik-in-der-eu.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:54.555728+00:00","lastSeen":"2026-03-15T17:47:54.555728+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Beschaeftigungs-und-Sozialpolitik-in-der-EU/beschaeftigungs-und-sozialpolitik-in-der-eu.html","crawledAt":"2026-03-15T17:47:54.555728Z","crawlId":"contacts-seeded-1773596874","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"2ab59ad50a479ca5f63d38f9315a64beef14dae1f0dbaa1b89d69a72b640f7bb"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:47:54.555728+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('036f77ac-9c50-4fa4-be6c-b0c92fa767e3', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Freihandelsabkommen/freihandelsabkommen-der-eu.html', 'active', NULL, '2026-03-15T17:47:55.333235+00:00', '{"id":"036f77ac-9c50-4fa4-be6c-b0c92fa767e3","title":"Freihandelsabkommen","summary":{"de":"Das BMAS setzt sich bei der Aushandlung von Freihandelsabkommen der EU mit Drittstaaten für eine sozial nachhaltige wirtschaftliche Kooperation ein."},"content":{"de":"In der EU ist der Handel im Europäischen Binnenmarkt so geregelt, dass die Barrieren zwischen den Mitgliedstaaten praktisch beseitigt sind, d.h., dass zum Beispiel keine Zölle erhoben werden und Arbeitnehmerinnen und Arbeitnehmer problemlos in allen Mitgliedstaaten arbeiten können. Damit herrschen zugleich auch faire Bedingungen auch für Arbeitnehmerinnen und Arbeitnehmer. Freihandelsabkommen der EU dienen dazu, Handelsbeschränkungen wie Zölle oder unterschiedliche Produktzulassungsregeln auch im Verhältnis zur übrigen Welt weitgehend aufzuheben und hierbei eine sozial nachhaltige wirtschaftliche Entwicklung sicherzustellen. Das Bundesministerium für Arbeit und Soziales (BMAS) setzt sich für Freihandelsabkommen ein, die Wachstum und Beschäftigung stärken, europäische Schutzstandards etwa aus dem Bereich Arbeitsschutz oder soziale Sicherheit nicht beeinträchtigen und internationale Arbeitsstandards fördern. Bei den Verhandlungen zu Fragen der Nachhaltigkeit in allen Handelsabkommen der EU liegt inzwischen ein zentraler Fokus auf der Achtung wichtiger Übereinkommen und Erklärungen der Internationalen Arbeitsorganisation (IAO), einer Sonderorganisation der Vereinten Nationen. Das BMAS setzt sich dafür ein, dass diese dann auch wirksam durchgesetzt werden. Die Europäische Kommission verhandelt die Handelsabkommen mit den Handelspartnern innerhalb eines vom Rat der Handelsminister festgelegten Mandats: Making trade policy (europa.eu). Im Mandat formulieren die Mitgliedstaaten gemeinsam Auftrag und Grenzen eines möglichen Abkommens. Innerhalb der Bundesregierung ist das Bundesministerium für Wirtschaft und Klimaschutz federführend zuständig für die Umsetzung der deutschen Position gegenüber der Kommission und begleitet die Verhandlungen. Das BMAS ist bei allen Fragen der Wahrung von Arbeitnehmerrechten und Sozialstandards beteiligt. Das betrifft zum Beispiel Maßnahmen des Arbeitsschutzes oder des Schutzes der Sozialen Dienstleistungen, aber auch die Einbindung der internationalen Regeln zum Arbeitnehmerschutz. Nach Abschluss der Verhandlungen wird das Abkommen von den Vertragspartnern nach völkerrechtlichen Regeln unterzeichnet und ratifiziert, also in EU-Recht übernommen. Wenn Inhalte des Abkommens auch Kompetenzen von Mitgliedstaaten berühren und nicht ausschließlich der EU-Handelspolitik zuzuordnen sind, entscheiden auch die Parlamente der Mitgliedstaaten mit."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Freihandelsabkommen/freihandelsabkommen-der-eu.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:55.333235+00:00","lastSeen":"2026-03-15T17:47:55.333235+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Freihandelsabkommen/freihandelsabkommen-der-eu.html","crawledAt":"2026-03-15T17:47:55.333957Z","crawlId":"contacts-seeded-1773596875","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"dff3774dc6a0bd6750dbff9a5a2ed1c5f432d1722d6c82c89c9b6dbe0c3133c8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:55.333957+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c69ac9c5-eda3-4306-99d7-70a3f6ffeee7', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Migration-aus-Drittstaaten/migration-aus-drittstaaten.html', 'active', NULL, '2026-03-15T17:47:56.346218+00:00', '{"id":"c69ac9c5-eda3-4306-99d7-70a3f6ffeee7","title":"Migration aus Drittstaaten","summary":{"de":"EU-Richtlinien regeln den Zugang zu Arbeitsmarkt und Sozialleistungen für Menschen aus Nicht-EU-Ländern."},"content":{"de":"EU-Richtlinien regeln den Zugang zu Arbeitsmarkt und Sozialleistungen für Menschen aus Nicht-EU-Ländern."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Migration-aus-Drittstaaten/migration-aus-drittstaaten.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:56.346218+00:00","lastSeen":"2026-03-15T17:47:56.346218+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Migration-aus-Drittstaaten/migration-aus-drittstaaten.html","crawledAt":"2026-03-15T17:47:56.347724Z","crawlId":"contacts-seeded-1773596876","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"34226eca7f2585570510d112d5e365dd4367d1b3f53edb6975609ab8c4e08177"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:47:56.347724+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('efd7124d-ba9f-4933-90fc-27878ee22359', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Ukraine/ukraine.html', 'active', NULL, '2026-03-15T17:47:57.433612+00:00', '{"id":"efd7124d-ba9f-4933-90fc-27878ee22359","title":"Informationen für Geflüchteteaus der Ukraine","summary":{"de":"Das BMAS hilft Menschen, die im Zuge des Krieges nach Deutschland geflüchtet sind, bei den Themen Arbeit und Soziale Sicherung."},"content":{"de":"Alle aktuellen Informationen des BMAS zum Thema Ukraine erhalten Sie auf dieser Seite. Unterkunft, Basisinformationen oder medizinische Versorgung: Mit dem Hilfe-Portal \"Germany4Ukraine\" bietet die Bundesregierung ukrainischen Geflüchteten eine zentrale und vertrauenswürdige digitale Anlaufstelle. Das Hilfe-Portal bündelt Informationen auf Ukrainisch, Russisch, Englisch sowie Deutsch und unterstützt die Geflüchteten bei Einreise, Orientierung und dem Überblick über Hilfsangebote. Bei der Zentralstelle für ausländisches Bidlungswesen (ZAB) finden Sie Informationen über die Anerkennung ausländischer Hochschulabschlüsse. Die Bundeskontaktstelle vermittelt und koordiniert Angebot und Nachfrage neu einreisender Geflüchteter aus der Ukraine mit Behinderungen und/oder Pflegebedarf. Die Verbraucherzentrale stellt geflüchteten Menschen aus der Ukraine wichtige Informationen, Videos und digitale Tools zu Verbraucherthemen wie Handyverträge, Versicherungen, Datenschutz etc. zur Verfügung. 6,8 Millionen vertriebene Ukrainer können nun Entschädigung beantragen."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Ukraine/ukraine.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:47:57.433612+00:00","lastSeen":"2026-03-15T17:47:57.433612+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europa/Ukraine/ukraine.html","crawledAt":"2026-03-15T17:47:57.433612Z","crawlId":"contacts-seeded-1773596877","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"218481c41643cf96818d5d95350997b96e36745319a879573f4f5b791986f00c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:47:57.433612+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f390482a-2f93-4764-82c4-a490caaf6966', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Globalisierungsfonds/europaeischer-globalisierungsfonds.html', 'active', NULL, '2026-03-15T17:51:52.176471+00:00', '{"id":"f390482a-2f93-4764-82c4-a490caaf6966","title":"Europäischer Globalisierungsfonds in Deutschland","summary":{"de":"Der Europäische Fonds für die Anpassung an die Globalisierung zugunsten entlassener Arbeitnehmer (EGF) unterstützt Arbeitnehmer*innen sowie Selbstständige, die ihre Arbeit verloren haben, bei der Reintegration in den Arbeitsmarkt."},"content":{"de":"Mit den durch die EU kofinanzierten EGF-Mitteln wird die Reintegration von 915 entlassenen Beschäftigten in den Arbeitsmarkt aktiv gefördert. Erstmalig hat das jährliche Treffen der EU-Kommission mit den EGF-Kontaktpersonen aus den 27 Mitgliedstaaten der Europäischen Union in Deutschland stattgefunden. Der Europäische Globalisierungsfonds (EGF) unterstützt Arbeitnehmer*innen sowie Selbstständige, die ihre Arbeit verloren haben, bei der Reintegration in den Arbeitsmarkt."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Globalisierungsfonds/europaeischer-globalisierungsfonds.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:52.176471+00:00","lastSeen":"2026-03-15T17:51:52.176471+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Globalisierungsfonds/europaeischer-globalisierungsfonds.html","crawledAt":"2026-03-15T17:51:52.176471Z","crawlId":"contacts-seeded-1773597112","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"757e39a5559a59e4bf8b5f9355d8d1fcd4895f95f76607ad87f4bd92ff3c707d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:52.176471+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ac53b37a-3bd2-48a5-91d9-7e55438125ea', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Hilfsfonds/europaeischer-hilfsfonds.html', 'active', NULL, '2026-03-15T17:51:52.961075+00:00', '{"id":"ac53b37a-3bd2-48a5-91d9-7e55438125ea","title":"Europäischer Hilfsfonds für die am stärksten benachteiligten Personen (EHAP)","summary":{"de":"Der EHAP leistete von 2016 bis 2022 einen Beitrag zur Bekämpfung von Armut und sozialer Ausgrenzung als ein Kernziel der Europa-2020-Strategie."},"content":{"de":"Wie hilft der EHAP? Welche Aktivitäten werden unterstützt? Ziel des EHAP war es, die Lebenssituation von armutsgefährdeten und von sozialer Ausgrenzung bedrohten Personen zu verbessern. Damit leistet der EHAP einen wichtigen Beitrag zur Europa-2020-Strategie, die eine deutliche Senkung der Anzahl der betroffenen Menschen bis zum Jahr 2020 vorsah, sowie zur Europäischen Säule sozialer Rechte, die neue und wirksamere Rechte für die Bürgerinnen und Bürger gewährleisten soll. Besonderes Gewicht legte der EHAP auf die Gleichbehandlung von Männern und Frauen und die Vermeidung jeglicher Art von Diskriminierung. Dieser Fonds, auf Englisch FEAD, ist erstmalig für die EU-Förderperiode 2014-2020 eingerichtet worden und wurde in Deutschland in mehreren Förderrunden umgesetzt. Offiziell eingeführt wurde er in Deutschland am 22. Februar 2016 im Rahmen einer Auftaktveranstaltung in Berlin. Am 31. September 2022 endete die Förderung, zum 15. Februar 2025 erfolgt offiziell der Abschluss mit Einreichung der Abschlussunterlagen inklusive Abschlussbericht bei der Europäischen Kommission (siehe unten für weitere Hinweise zur neuen Förderperiode 2021-2027 und dem EhAP Plus im ESF Plus). Aus Mitteln des EHAP werden Projekte für Menschen in Deutschland unterstützt, die unter Armut leiden und keinen oder nur unzureichenden Zugang zu den lokal oder regional vorhandenen Hilfeangeboten haben. Das sind: besonders benachteiligte neuzugewanderte Unionsbürger*innen, darunter Eltern mit ihren Kindern im Vorschulalter bis zu sieben Jahren,"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Hilfsfonds/europaeischer-hilfsfonds.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:52.961075+00:00","lastSeen":"2026-03-15T17:51:52.961075+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Hilfsfonds/europaeischer-hilfsfonds.html","crawledAt":"2026-03-15T17:51:52.961075Z","crawlId":"contacts-seeded-1773597112","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"71fd495fc1245d566c47dffc6df2ec669e5c51fabfbaae283c2822990bb336c6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:52.961075+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3709f444-b7f1-4b0b-8ae4-2b5d99715d2d', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Sozialfonds/europaeischer-sozialfonds.html', 'active', NULL, '2026-03-15T17:51:53.619777+00:00', '{"id":"3709f444-b7f1-4b0b-8ae4-2b5d99715d2d","title":"Europäischer Sozialfonds Plus","summary":{"de":"Mit dem Europäischen Sozialfonds Plus (ESF Plus) wird die Arbeitsmarkt- und Beschäftigungspolitik in den Mitgliedstaaten der EU gefördert."},"content":{"de":"ESF Plus-Bundesprogramm in der Förderperiode 2021-2027 Als das wichtigste Instrument der Europäischen Union zur Förderung der Beschäftigung und sozialen Integration in Europa wirkt der Europäische Sozialfonds Plus ( ESF Plus ) vor Ort mit tausenden von praxisnahen Projekten. Diese unterstützen Menschen, in Arbeit oder Ausbildung zu kommen oder in Arbeit zu bleiben. In der alten Förderperiode 2014-2020 konnte der ESF EU-weit bereits rund 20 Mio. Menschen erreichen, die ohne Beschäftigung oder inaktiv waren, rund 10 Mio. Angehörige benachteiligter Gruppen unterstützen und mehr als 520.000 kleine und mittlere Unternehmen fördern. In der jetzigen Förderperiode 2021-2027 ist der ESF als „ESF Plus“ noch stärker auf den Gedanken eines sozialeren Europas ausgerichtet. Der bisherige Europäische Hilfsfonds für die am stärksten benachteiligten Personen (EHAP), die Jugendbeschäftigungsinitiative (YEI) und das EU-Programm für Beschäftigung und soziale Innovation (EaSI) werden unter einem Dach zusammengefasst. Die Europäische Union verfolgt mit dem ESF Plus das Ziel, Menschen eine berufliche Perspektive zu geben. Der ESF Plus hilft den Menschen in Deutschland und in Europa, ihr Bildungsniveau und ihre Qualifikationen zu verbessern und damit ihre beruflichen Chancen zu erhöhen. Ziel ist, dass alle Menschen eine berufliche Perspektive erhalten. Im Fokus stehen arbeitslose Menschen, Jugendliche und junge Erwachsene beim Übergang in Ausbildung und Beruf, Arbeitnehmer*innen, aber auch Existenzgründer*innen sowie kleine und mittelständische Unternehmen und Solo-Selbstständige. Besonderes Gewicht legt der ESF Plus auf die Gleichbehandlung von Männern und Frauen und die Vermeidung jeglicher Art von Diskriminierung. Daher kümmert sich der ESF Plus besonders um diejenigen, die Gefahr laufen, aus dem Arbeitsmarkt ausgegrenzt zu werden, wie z. B. benachteiligte junge Menschen, Migrant*innen sowie wohnungslose Personen."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Sozialfonds/europaeischer-sozialfonds.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:53.619777+00:00","lastSeen":"2026-03-15T17:51:53.619777+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/Europaeischer-Sozialfonds/europaeischer-sozialfonds.html","crawledAt":"2026-03-15T17:51:53.619777Z","crawlId":"contacts-seeded-1773597113","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"bc4a5130d8dd40e7f4218958c4eeef349fe0c4d30070806246d7f76e82e707bf"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:53.619777+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ffaa7a2f-3e7f-40c8-811d-90d7a8b5b0e5', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/europaeische-fonds.html', 'active', NULL, '2026-03-15T17:51:54.913316+00:00', '{"id":"ffaa7a2f-3e7f-40c8-811d-90d7a8b5b0e5","title":"Programme und Fonds","summary":{"de":"Mit den verschiedenen Fonds setzt sich die Europäische Union für soziale Politik, Gestaltung der Globalisierung oder benachteiligte Menschen ein. Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Mit den verschiedenen Fonds setzt sich die Europäische Union für soziale Politik, Gestaltung der Globalisierung oder benachteiligte Menschen ein. Im ESF Plus-Förderprogramm \" MY TURN - Frauen mit Migrationserfahrung starten durch\" konnten bislang knapp 30.000 Teilnehmerinnen von einem umfangreichen, zielgruppenspezifischen Angebot profitieren. Der Europäische Sozialfonds Plus (ESF Plus) ist das wichtigste Instrument der Europäischen Union zur Förderung der Beschäftigung in Europa. Mit den durch die EU kofinanzierten EGF-Mitteln wird die Reintegration von 915 entlassenen Beschäftigten in den Arbeitsmarkt aktiv gefördert."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/europaeische-fonds.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:54.913316+00:00","lastSeen":"2026-03-15T17:51:54.913316+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/Europaeische-Fonds/europaeische-fonds.html","crawledAt":"2026-03-15T17:51:54.913316Z","crawlId":"contacts-seeded-1773597114","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"9a81adddc4185ebae1fc59beeb44a9f9f9d8525371980b7d5f956a2c9259e476"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:54.914267+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c81a97fd-ea49-4f32-9f49-5aaf85d942e7', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/Beschaeftigungs-und-Sozialpolitik-von-G7-G20/beschaeftigungs-und-sozialpolitik-von-g7-g20.html', 'active', NULL, '2026-03-15T17:51:55.610117+00:00', '{"id":"c81a97fd-ea49-4f32-9f49-5aaf85d942e7","title":"Beschäftigungs- und Sozialpolitik im Rahmen von G7/G20","summary":{"de":"Internationaler Austausch: Deutschland ist sowohl Mitglied der Gruppe der sieben führenden Industriestaaten (G7) als auch der Gruppe der wichtigsten Industrie- und Schwellenländer (G20)."},"content":{"de":"Bei der G7 und der G20 handelt es sich um informelle Foren für multilaterale Zusammenarbeit. Sie bieten die Möglichkeit eines multilateralen Austauschs führender Wirtschaftsnationen, ohne in die Strukturen Internationaler Organisationen eingebunden zu sein. Insbesondere in geopolitisch schwierigen Zeiten können diese Formate wichtige Weichen stellen. Die Staats- und Regierungschefs der Mitgliedsländer treffen sich in jährlichen Abständen zu Gipfeltreffen, um globale Themen und Fragestellungen zu diskutieren und abzustimmen. Daneben gibt es regelmäßige Treffen der verschiedenen Fachressorts, wie beispielsweise der Arbeits- und Beschäftigungsminister. Zur \"Gruppe der Sieben\" (G7) gehören Deutschland, Frankreich, Großbritannien, Italien, Japan, Kanada und die Vereinigten Staaten von Amerika, außerdem ist die Europäische Kommission vertreten. Der Vorsitz der Gruppe wechselt jährlich unter den Mitgliedern. Deutschland hatte den G7-Vorsitz zuletzt im Jahr 2022 inne. Im vergangenen Jahr lag der Vorsitz bei Italien. Die von den G7 Arbeits- und Beschäftigungsminister*innen in Cagliari, Italien, verabschiedete LEMM-Erklärung finden Sie hier [PDF, 901KB]. Schwerpunkte der italienischen G7-Präsidentschaft im Bereich Arbeit waren der Einsatz von Künstlicher Intelligenz in der Arbeitswelt und alternde Gesellschaften. Ergänzend zur Abschlusserklärung der G7-Arbeitsminister*innen wurde ein G7-Aktionsplan für den verantwortungsvollen Einsatz von Künstlicher Intelligenz in der Arbeitswelt verabschiedet. Dieser soll helfen, die Produktivität zu steigern, menschenwürdige Arbeit sicherzustellen und Arbeitnehmerrechte zu stärken. Die Arbeits- und Beschäftigungsminister*innen setzen sich für einen vertrauenswürdigen und transparenten Einsatz von KI in den westlichen Industrienationen ein. Dadurch wollen die G7 ein Signal setzen und mit gutem Beispiel vorangehen. Beim Thema inklusive Arbeitsmärkte lag ein besonderer Fokus auf den Herausforderungen durch alternde Gesellschaften. So wurde ein weiterer G7-Aktionsplan für verbesserte Arbeitsbedingungen in der Pflege und gerechter Lohnpolitik, bessere Arbeitsbedingungen und mehr Geschlechtergerechtigkeit verabschiedet. Zu diesen Themen diskutierte die unter deutscher G7-Präsidentschaft 2022 fest verankerte Arbeitsgruppe Beschäftigung ( Employment Working Group, EWG ) in ihren Sitzungen unter italienischer Präsidentschaft und bereitete die gemeinsame Abschlusserklärung der Arbeitsminister*innen vor, die in Cagliari verabschiedet wurde. In diesem Jahr hat Kanada den G7-Vorsitz inne. Aufgrund der Wahlen hat die Arbeit der einzelnen Arbeitsgruppen sich verzögert. Im Bereich Arbeit und Soziales stehen die Themen robuste Arbeitsmärkte als Folge wirtschaftlicher Schocks, Steigerung der Beschäftigungsquoten und des Arbeitsvolumens als Folge der Schaffung inklusiver Arbeitsmärkte sowie die Umsetzung des G7 KI-Aktionsplans im Mittelpunkt. Ein Treffen der G7-Arbeits- und Beschäftigungsministerinnen soll in diesem Jahr virtuell stattfinden. Während der deutschen G7-Präsidentschaft 2022 verständigten sich die G7 in einem ambitionierten Kommuniqué auf die nächsten Schritte, um den strukturellen Wandel gerecht zu gestalten und gute Arbeit in einer sozial-ökologischen Marktwirtschaft zu sichern."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Beschaeftigungs-und-Sozialpolitik-von-G7-G20/beschaeftigungs-und-sozialpolitik-von-g7-g20.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:55.610117+00:00","lastSeen":"2026-03-15T17:51:55.610117+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Beschaeftigungs-und-Sozialpolitik-von-G7-G20/beschaeftigungs-und-sozialpolitik-von-g7-g20.html","crawledAt":"2026-03-15T17:51:55.610117Z","crawlId":"contacts-seeded-1773597115","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"3d52570e1744a2d13159495cdf490396c6d14220fb64df17d7d3725af45b2d75"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:55.610117+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('33a670b7-4a29-453e-bc75-ff87616ba6d2', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/Gesellschaftliche-Verantwortung-Unternehmen/gesellschaftliche-verantwortung-unternehmen.html', 'active', NULL, '2026-03-15T17:51:56.186222+00:00', '{"id":"33a670b7-4a29-453e-bc75-ff87616ba6d2","title":"Gesellschaftliche Verantwortung von Unternehmen","summary":{"de":"Unternehmen können wesentlich dazu beitragen, gute Arbeit weltweit durchzusetzen. Die Bundesregierung unterstützt Unternehmen im Rahmen ihrer CSR -Strategie dabei, ihrer Verantwortung gerecht zu werden."},"content":{"de":"Zur Bewältigung der zentralen Aufgaben des 21. Jahrhunderts bedarf es einer gesamtgesellschaftlichen Anstrengung. Weder Politik, Wirtschaft, noch Zivilgesellschaft sind in der Lage, globale Herausforderungen wie Klimawandel, Armutsbekämpfung oder Menschenrechtsschutz im Alleingang zu lösen. Neben politischem Handeln und zivilgesellschaftlichem Engagement sind es vor allem verantwortungsbewusst handelnde Unternehmen, die mit ihrer Präsenz und ihrem Einfluss im In- und Ausland wesentlich zur Lösung gesellschaftlicher Probleme beitragen. Das tun sie zum Beispiel, indem sie international anerkannte Sozial- und Umweltstandards einhalten, wenn im Produktionsland keine entsprechende Gesetzgebung besteht oder diese nicht umgesetzt wird. Die Bundesregierung fördert die gesellschaftliche Verantwortung von Unternehmen (engl. \" Corporate Social Responsibility \", abgekürzt CSR) bereits seit vielen Jahren. Seit 2010 verfolgt sie in Federführung des Bundesministeriums für Arbeit und Soziales eine systematische CSR-Politik, die insbesondere auch auf Empfehlungen des Nationalen CSR-Forums beruht, einem „Multi-Stakeholder“-Gremium mit Vertretern aus Wirtschaft, Zivilgesellschaft, Ministerien, Gewerkschaften und Wissenschaft. Wesentliche Einzelmaßnahmen des Aktionsplan CSR von 2010 sind mittlerweile umgesetzt. Bei CSR geht es darum, dass Unternehmen gesellschaftliche Verantwortung übernehmen – und zwar über ihre gesetzlichen Verpflichtungen hinaus. Ziel der Weiterentwicklung der nationalen CSR-Strategie der Bundesregierung ist es, CSR in Deutschland im Einklang mit den internationalen Entwicklungen voranzutreiben - und als Im- und Exportnation eine Vorreiterrolle zu übernehmen. Die Verantwortung in der Liefer- und Wertschöpfungskette und die Umsetzung unternehmerischer Sorgfaltspflicht stehen dabei im Mittelpunkt. Mit der Verabschiedung der UN-Leitprinzipien für Wirtschaft und Menschenrechte durch den UN -Menschenrechtsrat sowie der Überarbeitung der OECD -Leitsätze für multinationale Unternehmen im Jahre 2011 rückte die unternehmerische Sorgfaltspflicht ( engl. \" due diligence \") bei der Einhaltung von Arbeits-, Sozial- und Umweltstandards ins Blickfeld. Am 21. Dezember 2016 hat die Bundesregierung den Nationalen Aktionsplan Wirtschaft und Menschenrechte (NAP) verabschiedet. Mit dem NAP sollen die VN-Leitprinzipien für Wirtschaft und Menschenrechte umgesetzt und damit die menschenrechtliche Lage entlang der Liefer- und Wertschöpfungsketten in Deutschland und weltweit verbessert werden. Mit dem Nationalen Aktionsplan (NAP) will die Bundesregierung die Einhaltung von Menschenrechten in globalen Liefer- und Wertschöpfungsketten durchsetzen. Der NAP bildet zugleich den Grundstein des deutschen Lieferkettengesetzes: Eine Unternehmensbefragung der Bundesregierung in den Jahren 2019 und 2020 hat gezeigt, dass nur rund ein Fünftel aller in Deutschland ansässigen Unternehmen mit mehr als 500 Beschäftigten ihrer menschenrechtlichen Sorgfaltspflicht entlang der eigenen Lieferketten genügend nachkam. Freiwillige Selbstverpflichtung reichte also nicht aus. Im damaligen Koalitionsvertrag hat die Bundesregierung für diesen Fall vereinbart, national gesetzlich tätig zu werden und sich gleichzeitig auf europäischer Ebene für verbindliche Regeln einzusetzen. Das deutsche Lieferkettengesetz (LkSG) ist am 1. Januar 2023 zunächst für Unternehmen mit mindestens 3000 Arbeitnehmer*innen im Inland in Kraft getreten, im Jahr 2024 sankt die Beschäftigtenschwelle auf 1000. Mit dem LkSG wird die unternehmerische Verantwortung für die Einhaltung von Menschenrechten in den Lieferketten erstmals gesetzlich geregelt."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/Gesellschaftliche-Verantwortung-Unternehmen/gesellschaftliche-verantwortung-unternehmen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:56.186222+00:00","lastSeen":"2026-03-15T17:51:56.186222+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/Gesellschaftliche-Verantwortung-Unternehmen/gesellschaftliche-verantwortung-unternehmen.html","crawledAt":"2026-03-15T17:51:56.187222Z","crawlId":"contacts-seeded-1773597116","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"2e0b62aad1a5b8275344aa7e0e02fd45480fd9e36eb781d1267b56af531878e0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:56.187222+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7df4e6ac-f350-4064-862f-04c56d6adf5a', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/Menschenrechte-und-gute-Arbeit-globale-Wertschoepfungskette/menschenrechte-und-gute-arbeit-globale-wertschoepfungskette.html', 'active', NULL, '2026-03-15T17:51:56.728953+00:00', '{"id":"7df4e6ac-f350-4064-862f-04c56d6adf5a","title":"Menschenrechte und gute Arbeit in globalen Wertschöpfungsketten","summary":{"de":"Die Einhaltung von sozialen, menschenrechts- und Umweltstandards in globalen Wertschöp­fungsketten ist ein Schwerpunktthema der internationalen Arbeit des BMAS."},"content":{"de":"Am 24. April 2013 stürzte der Gebäudekomplex Rana Plaza in Bangladesch ein. Über 1100 Menschen starben und mindestens doppelt so viele wurden schwer verletzt. Die Tragödie stieß international eine längst überfällige Debatte über unmenschliche Arbeitsbedingungen, Ausbeutung und Verantwortlichkeiten von Unternehmen und Staaten an. 10 Jahre nach der Katastrophe hat sich einiges in Bangladesch und weltweit getan. Einige Länder verabschiedeten Gesetze, wie z. B. Frankreich und Deutschland. In Deutschland gilt seit dem 1. Januar 2023 das Lieferkettensorgfaltspflichtengesetz. Auch auf europäischer Ebene wird an einer entsprechenden EU -Richtlinie gearbeitet. Das deutsche Lieferkettengesetz ist am 1. Januar 2023 in Kraft getreten. Das Gesetz regelt die unternehmerische Verantwortung für die Einhaltung von Menschenrechten in den globalen Lieferketten und den Schutz der Umwelt. Davon profitieren die Menschen in den Lieferketten, Unternehmen und auch die Konsumenten. Dennoch können wir noch nicht zufrieden sein. 1,4 Milliarden Arbeitnehmerinnen und Arbeitnehmer arbeiten weltweit immer noch unter menschenunwürdigen Bedingungen. Die Zahl der Opfer von Zwangsarbeit und Sklaverei steigt signifikant. Nach jüngsten Schätzungen der ILO sind es nunmehr 28 Mio. Menschen. Ebenso werden weltweit immer mehr Kinder zur Arbeit gezwungen - in den Goldminen von Burkina Faso, als Textilarbeiterinnen und -arbeiter in Bangladesch oder auf Kakaoplantagen in der Cȏte d‘Ivoire. Durch die Pandemie hat sich die Situation weiter verschlechtert. Die ILO geht aktuell von rund 160 Millionen arbeitenden Kinder aus. Die Hälfte von ihnen ist jünger als 12 Jahre. Zwangsarbeit und Kinderarbeit werden so lange weiterbestehen und sogar noch verschlimmert, wie erwerbstätige Erwachsene keine gerechten und menschenwürdigen Löhne erhalten. Die Missachtung des Arbeits- und Gesundheitsschutzes, und des Rechts, Gewerkschaften bzw. Mitarbeitervertretungen zu bilden, verschlechtert die Lage weiter. Das BMAS hat das Thema daher immer wieder prominent auf die internationale Agenda gesetzt und nutzt Foren wie die G7, um international gleiche Wettbewerbsbedingungen zu schaffen."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/Menschenrechte-und-gute-Arbeit-globale-Wertschoepfungskette/menschenrechte-und-gute-arbeit-globale-wertschoepfungskette.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:56.728953+00:00","lastSeen":"2026-03-15T17:51:56.728953+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/Menschenrechte-und-gute-Arbeit-globale-Wertschoepfungskette/menschenrechte-und-gute-arbeit-globale-wertschoepfungskette.html","crawledAt":"2026-03-15T17:51:56.728953Z","crawlId":"contacts-seeded-1773597116","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"7abb3b39f1688a2404dbd1b0c7ccf927374546be3ec0ccd708df7e228ed290ad"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:56.729952+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2efcf969-3897-48b3-886b-a90cfae5bd6c', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/gesellschaftliche-verantwortung-von-unternehmen.html', 'active', NULL, '2026-03-15T17:51:57.297255+00:00', '{"id":"2efcf969-3897-48b3-886b-a90cfae5bd6c","title":"BMAS - Gesellschaftliche Verantwortung von Unternehmen (CSR)","summary":{"de":"Die Bundesregierung unterstützt Unternehmen im Rahmen ihrer CSR -Strategie dabei, ihrer Verantwortung gerecht zu werden."},"content":{"de":"Die Bundesregierung unterstützt Unternehmen im Rahmen ihrer CSR -Strategie dabei, ihrer Verantwortung gerecht zu werden."},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/gesellschaftliche-verantwortung-von-unternehmen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:57.297255+00:00","lastSeen":"2026-03-15T17:51:57.297255+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Gesellschaftliche-Verantwortung-von-Unternehmen/gesellschaftliche-verantwortung-von-unternehmen.html","crawledAt":"2026-03-15T17:51:57.297255Z","crawlId":"contacts-seeded-1773597117","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"b3b3308f6f78cd558ae67ae6db6d4400cb0d6a2b0057f1513db73fe8dbceb8bc"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:51:57.297255+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6c273c4c-9ffd-4a47-b01d-bca5ee747a59', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/Internationale-Beschaeftigungs-und-Sozialpolitik/internationale-beschaeftigungs-und-sozialpolitik.html', 'active', NULL, '2026-03-15T17:51:57.901972+00:00', '{"id":"6c273c4c-9ffd-4a47-b01d-bca5ee747a59","title":"Internationale Beschäftigungs- und Sozialpolitik","summary":{"de":"Fragen der Beschäftigungs- und Sozialpolitik gewinnen in einer stark vernetzten Weltgemeinschaft auch international zunehmend an Bedeutung. Sinn und Zweck der internationalen Arbeit des BMAS ist der Austausch von Erfahrungen mit internationalen Partnern und die soziale Gestaltung der Globalisierung."},"content":{"de":"Mit Herausforderungen wie dem demographischen Wandel, dem Klimawandel, der digitalen Transformation und Entwicklungen der Künstlichen Intelligenz, der Arbeitsmarktintegration von Migrantinnen und Migranten oder auch dem Fachkräftemangel steht Deutschland nicht alleine da. Zentrale Themen unserer Arbeitsmarkt- und Sozialpolitik spielen auch in anderen Ländern eine bedeutende Rolle. Das Bundesministerium für Arbeit und Soziales (BMAS) steht deshalb sowohl auf politischer Ebene als auch auf Arbeitsebene in regem Austausch mit zuständigen Ministerien, Verwaltungen und Sozialpartnern in Partnerländern - in Europa und der ganzen Welt. Durch den Welthandel und die internationale Arbeitsteilung ergeben sich in einer globalisierten Welt darüber hinaus zahlreiche Aufgaben, die Deutschland nur gemeinsam mit internationalen Partnern lösen kann. Die COVID-19-Pandemie mit ihren Folgen für Arbeitsmärkte und Einkommensschutz weltweit hat dies erneut in den Vordergrund gerückt. Die führenden Industrienationen tragen eine besondere Verantwortung, wenn es um Menschenrechte, Sozial- und Umweltstandards und Arbeitsschutz in globalen Wertschöpfungsketten geht. Sie können auch einen Beitrag leisten, um mehr Menschen den Zugang zu Sozialschutz zu ermöglichen. Mehr dazu in unserem G7-Schwerpunkt \"Gute Arbeit weltweit\". Konkrete Themen der internationalen Arbeit des BMAS sind: die Förderung des sozialen Dialogs zwischen Arbeitgebern und Arbeitnehmern, insbesondere durch die Sozialpartner, die Umsetzung der Normen der Internationalen Arbeitsorganisation, insbesondere der grundlegenden Rechte und Prinzipien bei der Arbeit (ILO-Kernarbeitsnormen),"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Internationale-Beschaeftigungs-und-Sozialpolitik/internationale-beschaeftigungs-und-sozialpolitik.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:57.901972+00:00","lastSeen":"2026-03-15T17:51:57.901972+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Internationale-Beschaeftigungs-und-Sozialpolitik/internationale-beschaeftigungs-und-sozialpolitik.html","crawledAt":"2026-03-15T17:51:57.901972Z","crawlId":"contacts-seeded-1773597117","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"e9117b318c4bd6e9aaefb0aa9371efe21e8b62ea7ffbb6fa12217250272c9e20"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:57.901972+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c612f2b3-eda6-4d16-8e01-0792959c9842', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/Sozialversicherungsabkommen/sozialversicherungsabkommen.html', 'active', NULL, '2026-03-15T17:51:58.585303+00:00', '{"id":"c612f2b3-eda6-4d16-8e01-0792959c9842","title":"Sozialversicherungsabkommen","summary":{"de":"Die wirtschaftliche Verflechtung der hoch entwickelten Industriestaaten erfordert auf dem Gebiet der sozialen Sicherung den rechtlichen Ausbau der Beziehungen der Bundesrepublik Deutschland zu anderen Staaten."},"content":{"de":"Die wirtschaftliche Verflechtung der hoch entwickelten Industriestaaten und der damit verbundene Austausch von Arbeitskräften, die Ausländerbeschäftigung in der Bundesrepublik Deutschland, sowie der internationale Tourismus erfordern auf dem Gebiet der sozialen Sicherung den rechtlichen Ausbau der Beziehungen der Bundesrepublik Deutschland zu anderen Staaten. Diesem Ziel dienen Abkommen, die auf der Grundlage der Gegenseitigkeit und der Gleichbehandlung der beiderseitigen Staatsangehörigen abgeschlossen werden. Dadurch wird deren sozialer Schutz auch im Fall eines Aufenthalts im jeweils anderen Vertragsstaat sichergestellt. Etliche Abkommen, die abgeschlossen worden sind, sind zwischenzeitlich wegen des EU -Beitritts der entsprechenden Staaten durch die Regelungen der Verordnung ( EG ) 883/2004 abgelöst worden. Über­blick der bi­la­te­ra­len So­zi­al­ver­si­che­rungs­ab­kom­men – Stand: 01.05.2023 (der­zeit nicht bar­rie­re­frei) [PDF, 133KB]"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Sozialversicherungsabkommen/sozialversicherungsabkommen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:58.585303+00:00","lastSeen":"2026-03-15T17:51:58.585303+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Sozialversicherungsabkommen/sozialversicherungsabkommen.html","crawledAt":"2026-03-15T17:51:58.585303Z","crawlId":"contacts-seeded-1773597118","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"53194506c8fef002e7ad55406eac9f5bd9b8f5526ef0e859a3b1a5595a337e14"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:58.585303+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('18213d91-6107-49f1-8e33-e18d89a7b934', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/Twinning-Verwaltungspartnerschaften/twinning-verwaltungspartnerschaften.html', 'active', NULL, '2026-03-15T17:51:59.216580+00:00', '{"id":"18213d91-6107-49f1-8e33-e18d89a7b934","title":"Twinning in der Arbeits- und Sozialpolitik (Verwaltungspartnerschaften)","summary":{"de":"\"Twinning\" ist ein von der EU finanziertes Instrument, das die Zusammenarbeit zwischen Behörden der EU-Mitgliedstaaten und öffentlichen Verwaltungen in Beitrittsländern zur EU fördern soll."},"content":{"de":"Ziel eines Twinning-Projekts ist es, EU-Kandidatenländer und potenzielle Kandidaten der EU bei der Übernahme des gemeinschaftlichen EU-Rechts (\"acquis communautaire\") und dem Aufbau der dazu notwendigen Verwaltungskapazitäten zu unterstützen. Auch für bestimmte Nachbarstaaten ist das Twinning-Programm zugänglich. Bei dieser Zusammenarbeit steht die Annäherung an EU-Recht sowie an EU-Standards im Mittelpunkt. Für (potenzielle) Kandidatenländer steht das EU-Annäherungs-Programm IPA (\"Instrument for Pre-Accession\") zur Verfügung, für Nachbarschaftsstaaten das \"European Neighbourhood Policy Instrument\" (ENPI). In beiden Programmen geben Expertinnen und Experten aus den verschiedenen Bereichen der Verwaltungen in EU-Mitgliedstaaten ihr Wissen und ihre Erfahrungen in der Umsetzung des EU-Rechts im jeweiligen Partnerland weiter. Das IPA-Programm zur Beitrittsvorbereitung bezieht die sog. Kandidatenländer, d.h. Albanien, Montenegro, Nordmazedonien, Serbien und die Türkei, und die sog. potenziellen Kandidatenländer des Westbalkans, d.h. Bosnien-Herzegowina und Kosovo, ein. Im Rahmen der EU-Nachbarschaftspolitik ist das Twinning-Programm darüber hinaus auch für Staaten zugänglich, die keine Beitrittskandidaten sind, aber von der Annäherung an die EU profitieren können und eine gerechte soziale und wirtschaftliche Entwicklung fördern wollen. Mitarbeiterinnen und Mitarbeiter öffentlicher Verwaltungen können in den Projekten als Projektleiter, Langzeitberater und Kurzzeitexperten eingesetzt werden. Bei Interesse wenden Sie sich gern an: Referat VI b 1 Internationale Beschäftigungs- und Sozialpolitik, Twinning Wilhelmstraße 49 10117 Berlin E-Mail: VIb1@bmas.bund.de"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Twinning-Verwaltungspartnerschaften/twinning-verwaltungspartnerschaften.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:59.216580+00:00","lastSeen":"2026-03-15T17:51:59.216580+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/Twinning-Verwaltungspartnerschaften/twinning-verwaltungspartnerschaften.html","crawledAt":"2026-03-15T17:51:59.216580Z","crawlId":"contacts-seeded-1773597119","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"79b9e4bff64be9bcc23371c3a558989e6b89a1a2fd5b593d6cb97526ec6dc50d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:59.216580+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0d0c8fbc-9f13-4051-aaba-b8f7d85e1019', 'contacts', 'https://www.bmas.de/DE/Europa-und-die-Welt/International/international.html', 'active', NULL, '2026-03-15T17:51:59.768299+00:00', '{"id":"0d0c8fbc-9f13-4051-aaba-b8f7d85e1019","title":"Internationale Beschäftigungs- und Sozialpolitik","summary":{"de":"Sinn und Zweck der Internationalen und Bilateralen Beschäftigungs- und Sozialpolitik ist der gegenseitige Austausch von Erfahrungen auf diesem Gebiet. Hier finden Sie dazu aktuelle Infos und Neuigkeiten."},"content":{"de":"Sinn und Zweck der Internationalen und Bilateralen Beschäftigungs- und Sozialpolitik ist der gegenseitige Austausch von Erfahrungen auf diesem Gebiet. Am 27. Februar 2026 nahm Staatssekretär Dr. Schäfer an der internationalen Fachkonferenz „ AI and Work: Managing Transformation, Multiplying Opportunities “ teil. Staatssekretärin Katja Mast empfing im BMAS Mitglieder der koreanischen Nationalversammlung, um über Präventionsstrategien im Arbeitsschutz und zukunftsfähige Wege der Rentenfinanzierung zu sprechen. Inklusion, Fachkräftesicherung und der Einsatz von KI waren die Schwerpunkte der internationalen Videokonferenz. Das Lieferkettengesetz - zur Achtung von Menschenrechten in weltweiten Lieferketten. Maßnahmen und weitere Informationen Strategie und Maßnahmen gegen Menschenhandel und Ausbeutung"},"url":"https://www.bmas.de/DE/Europa-und-die-Welt/International/international.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:51:59.768299+00:00","lastSeen":"2026-03-15T17:51:59.768299+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Europa-und-die-Welt/International/international.html","crawledAt":"2026-03-15T17:51:59.768299Z","crawlId":"contacts-seeded-1773597119","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"eec1fcf698a7f1432a1fec5cda07c3b1fec4ecef601393f4b60849c9bde040c7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:51:59.768299+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e80e5cd8-587e-4fc4-b01f-107a161e1dc2', 'contacts', 'https://www.bmas.de/DE/Leichte-Sprache/Kontakt-mit-dem-BMAS/kontakt-mit-dem-bmas.html', 'active', NULL, '2026-03-15T17:52:00.316983+00:00', '{"id":"e80e5cd8-587e-4fc4-b01f-107a161e1dc2","title":"Kontakt mit dem BMAS","summary":{"de":"Sie möchten mehr wissen? Wir helfen Ihnen gerne weiter. Sie können uns kosten-los anrufen:"},"content":{"de":"Wir haben auch ein Telefon für Menschen mit Hör-Schädigung. Bundesministerium für Arbeit und Soziales 11017 Berlin Die Adressen stehen auch auf der Internet-Seite in Alltags-Sprache."},"url":"https://www.bmas.de/DE/Leichte-Sprache/Kontakt-mit-dem-BMAS/kontakt-mit-dem-bmas.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:00.316983+00:00","lastSeen":"2026-03-15T17:52:00.316983+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Leichte-Sprache/Kontakt-mit-dem-BMAS/kontakt-mit-dem-bmas.html","crawledAt":"2026-03-15T17:52:00.317989Z","crawlId":"contacts-seeded-1773597120","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"5b12d4718fb8009fa20d06d5dd95c9e3cf6162deb52d709f7988237599d52644"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:00.317989+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=e