INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('20676fdc-8d41-400b-8daf-9f01e15d960f', 'contacts', 'https://www.bmas.de/DE/Service/Kontakt/Buergertelefon/buergertelefon.html', 'active', NULL, '2026-03-17T06:26:33.797961+00:00', '{"id":"20676fdc-8d41-400b-8daf-9f01e15d960f","title":"Bürgertelefon des BMAS","summary":{"de":"Sie haben Fragen zu Ihrer Rente, zur Arbeitslosenversicherung, zu Minijobs oder zu anderen Aufgabenbereichen des Ministeriums?"},"content":{"de":"Das Bürgertelefon des BMAS ist montags bis donnerstags von 8.00 bis 17.00 Uhr sowie freitags von 8.00 bis 12.00 Uhr für Sie erreichbar. Ihr Anliegen können Sie direkt mit den Mitarbeiterinnen und Mitarbeitern unseres Bürgertelefons besprechen. An fünf Tagen in der Woche helfen sie Ihnen weiter und beantworten gern Ihre Fragen. Für diese Themenbereiche des BMAS wählen Sie bitte eine der folgenden Durchwahl-Nummern: Arbeitslosenversicherung/Grundsicherung für Arbeitsuchende: 030 221 911 003 Informationen für Menschen mit Behinderungen: 030 221 911 006 Grundsicherung im Alter und bei Erwerbsminderung: 030 221 911 008"},"url":"https://www.bmas.de/DE/Service/Kontakt/Buergertelefon/buergertelefon.html","topics":["contacts","financial_support"],"tags":["official_contact_source","helpline"],"targetGroups":["general_public","unemployed","families"],"status":"active","firstSeen":"2026-03-17T06:26:33.797961+00:00","lastSeen":"2026-03-17T06:26:33.797961+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Service/Kontakt/Buergertelefon/buergertelefon.html","crawledAt":"2026-03-17T06:26:33.797961Z","crawlId":"contacts-seeded-1773728793","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"e5a9d4b0b67271c7cf4179a8305a1f7c6e87f1c3d91aae1b566cde4f51a23970"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T06:26:33.797961+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bf16f8a5-29a3-4f1b-8fef-ef0e8efe7916', 'contacts', 'https://www.bmas.de/DE/Service/Kontakt/Kontaktformular/kontaktformular.html', 'active', NULL, '2026-03-17T06:26:35.373679+00:00', '{"id":"bf16f8a5-29a3-4f1b-8fef-ef0e8efe7916","title":"Kontakt","summary":{"de":"Haben Sie Fragen oder Anregungen zur Arbeit des Bundesministeriums für Arbeit und Soziales? Bitte nutzen Sie das Kontaktformular oder die unten aufgeführte Postadresse."},"content":{"de":"Zur schnelleren Bearbeitung Ihrer Anliegen werden diese automatisch an das Kommunikationszentrum in Rostock weitergeleitet, das hierfür vom Bundesministerium für Arbeit und Soziales beauftragt worden ist. Mit dem gesicherten Kontaktformular wird Ihre Nachricht zudem verschlüsselt übermittelt. Wenn sich Ihr Anliegen auf eine bestimmte nachgeordnete Behörde des BMAS (z.B. Arbeitsagentur, Rentenversicherung) bezieht, kann es sinnvoll sein, Ihre Daten an die betreffende Behörde weiterzuleiten. Die Weiterleitung erfolgt allein zu dem Zweck, Ihr Anliegen umfassend zu bewerten und zu beantworten. Von der Weiterleitung sind die von Ihnen übermittelten personenbezogenen Daten betroffen. Es können auch sogenannte besondere Kategorien personenbezogener Daten wie Gesundheitsdaten umfasst sein. Diese Einwilligung können Sie jederzeit mit Wirkung für die Zukunft widerrufen. Wenn sich Ihr Anliegen (auch) auf einen Sachverhalt bezieht, für welches das BMAS nicht zuständig ist, kann das BMAS eine Weiterleitung an die zuständige Behörde (z.B. ein anderes Bundesministerium) übernehmen. Die Weiterleitung erfolgt zu dem Zweck, Ihr Anliegen von den zuständigen Behörden zügiger bearbeiten und beantworten zu lassen. Von der Weiterleitung sind die von Ihnen übermittelten personenbezogenen Daten betroffen. Es können auch sogenannte besondere Kategorien personenbezogener Daten wie Gesundheitsdaten umfasst sein."},"url":"https://www.bmas.de/DE/Service/Kontakt/Kontaktformular/kontaktformular.html","topics":["contacts","financial_support"],"tags":["official_contact_source","contact_form"],"targetGroups":["general_public","unemployed","families"],"status":"active","firstSeen":"2026-03-17T06:26:35.373679+00:00","lastSeen":"2026-03-17T06:26:35.373679+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Service/Kontakt/Kontaktformular/kontaktformular.html","crawledAt":"2026-03-17T06:26:35.373679Z","crawlId":"contacts-seeded-1773728795","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"61dc837a4e394a923653d74f091e5cf740a3e84d39a8c33b96636e0052b12374"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-17T06:26:35.373679+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4a464bcb-1b95-494d-a0eb-00af8f7dd48c', 'contacts', 'https://www.bmas.de/DE/Service/Kontakt/kontakt.html', 'active', NULL, '2026-03-01T20:18:00Z', '{"id":"4a464bcb-1b95-494d-a0eb-00af8f7dd48c","title":"BMAS – Kontakt","translations":{"de-LEICHT":{"title":"Kontakt zum Arbeits-Ministerium","timestamp":"2026-03-01T20:18:00Z","provenance":{"source":"https://www.bmas.de/DE/Service/Kontakt/kontakt.html","crawledAt":"2026-03-01T20:18:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Die BMAS-Kontaktseite stellt Kontaktformular, Bürgertelefon und ergänzende Informationsangebote bereit."},"content":{"de":"Sie bietet konkrete Kontaktwege für Fragen an das Bundesministerium für Arbeit und Soziales und enthält Hinweise in Leichter Sprache. Damit wird der Zugang zu ministeriellen Auskünften strukturiert erleichtert."},"url":"https://www.bmas.de/DE/Service/Kontakt/kontakt.html","topics":["employment","financial_support"],"tags":["urgent","application_required"],"targetGroups":["unemployed","disabled"],"status":"active","contactType":"office","specialization":["Sozialpolitik","Arbeitsmarkt"],"availability":{"hours":"Montag bis Donnerstag 08:00-17:00, Freitag 08:00-12:00","languages":["de"]},"linkedOrganization":"Bundesministerium für Arbeit und Soziales","firstSeen":"2026-03-01T20:18:00Z","lastSeen":"2026-03-01T20:18:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.bmas.de/DE/Service/Kontakt/kontakt.html","crawlId":"manual-curation-20260301-realdata-v1","checksum":"60b2c0f6d455f2fd10a4b880315eb5fc9bbf0c19eaef2a1c6334a084f4f3f4af","crawledAt":"2026-03-01T20:18:00Z"},"qualityScores":{"iqs":79.9,"ais":50.3,"computedAt":"2026-03-01T20:18:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bb0f2c23-419c-4867-b381-677b5cb5b2a8', 'contacts', 'https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Aerztlicher-Sachverstaendigenbeirat/aerztliche-sachverstaendigenbeirat.html', 'active', NULL, '2026-03-15T17:52:00.962105+00:00', '{"id":"bb0f2c23-419c-4867-b381-677b5cb5b2a8","title":"Ärztlicher Sachverständigenbeirat Berufskrankheiten","summary":{"de":"Der Ärztliche Sachverständigenbeirat Berufskrankheiten erarbeitet wissenschaftliche Empfehlungen und Stellungnahmen zu Berufskrankheiten"},"content":{"de":"Der Ärztliche Sachverständigenbeirat Berufskrankheiten ist ein internes, weisungsunabhängiges Beratungsgremium, das das Bundesministerium für Arbeit und Soziales in medizinisch-wissenschaftlichen Fragen bei seiner Entscheidungsfindung unterstützt. Aufgabe des Beirates ist die Sichtung und Bewertung des wissenschaftlichen Erkenntnisstands im Hinblick auf die Aktualisierung bestehender oder die Aufnahme neuer Berufskrankheiten in die Berufskrankheiten-Verordnung. Der Beirat gibt dem Ministerium auf Basis bestehender Erkenntnisse Empfehlungen und Stellungnahmen ab. Die wissenschaftlichen Empfehlungen des Sachverständigenbeirats werden vom Ministerium veröffentlicht. Sie bilden die wissenschaftliche Grundlage für die Entscheidung der Bundesregierung über die Aufnahme neuer Erkrankungen in die Berufskrankheitenliste und die Anerkennung als Berufskrankheit im Einzelfall durch die gesetzlichen Unfallversicherungsträger. Der Sachverständigenbeirat besteht aus zwölf Mitgliedern, die vom Ministerium für die Dauer von jeweils fünf Jahren berufen werden. Die Tätigkeit im Beirat wird ehrenamtlich ausgeübt und nicht vergütet. Entsprechend der Aufgabenstellung des Gremiums sind die Mitglieder überwiegend Hochschullehrer*innen der Fachrichtung Arbeitsmedizin; außerdem gehören dem Beirat zwei staatliche Gewerbeärzt*innen und zwei Betriebsärzt*innen an. Der Beirat wählt aus dem Kreis seiner Mitglieder eine*n Vorsitzende*n sowie eine*n stellvertretende*n Vorsitzende*n. Sofern zu einzelnen Fragestellungen spezieller Sachverstand anderer Fachrichtungen benötigt wird, werden zu den Beratungen externe Sachverständige hinzugezogen. Die Arbeit des Beirats wird außerdem durch seine Wissenschaftliche Geschäftsstelle bei der Bundesanstalt für Arbeitsschutz und Arbeitsmedizin unterstützt. Als ständige Gäste ohne Stimmrecht nehmen zwei Vertreter der gesetzlichen Unfallversicherung an den Sitzungen teil. Hier finden Sie die Geschäftsordnung des Ärztlichen Sachverständigenbeirats Berufskrankheiten [PDF, 321KB]. Prof. Dr. med. Thomas Kraus, Vorsitzender Direktor des Instituts für Arbeits-, Sozial- und Umweltmedizin der RWTH Aachen"},"url":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Aerztlicher-Sachverstaendigenbeirat/aerztliche-sachverstaendigenbeirat.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:00.962105+00:00","lastSeen":"2026-03-15T17:52:00.962105+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Aerztlicher-Sachverstaendigenbeirat/aerztliche-sachverstaendigenbeirat.html","crawledAt":"2026-03-15T17:52:00.962105Z","crawlId":"contacts-seeded-1773597120","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"b93a1b6146a787be14be2026e5835a3b9e1d400a841552f494c479a127f250ff"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:00.962105+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2a277204-dcae-4b83-9bba-edf0e086be77', 'contacts', 'https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Berufskrankheiten/berufskrankheiten.html', 'active', NULL, '2026-03-15T17:52:02.091322+00:00', '{"id":"2a277204-dcae-4b83-9bba-edf0e086be77","title":"Was sind Berufskrankheiten?","summary":{"de":"Berufskrankheiten sind Erkrankungen, die Versicherte durch ihre berufliche Tätigkeit erleiden und die in der Berufskrankheiten-Verordnung (BKV) aufgeführt sind"},"content":{"de":"Welche Leistungen gibt es bei Anerkennung einer Berufskrankheit? Berufskrankheiten sind Erkrankungen, die Versicherte durch ihre berufliche Tätigkeit erleiden und die in der Berufskrankheiten-Verordnung (BKV) aufgeführt sind. Ursache dafür können verschiedenste gesundheitsschädliche Einwirkungen sein. Insbesondere kommen bestimmte Chemikalien, physikalische Einwirkungen wie Druck, Vibrationen oder das Tragen schwerer Lasten und Arbeiten unter Lärm oder Staub in Betracht. Nicht jede Erkrankung kann aber als Berufskrankheit anerkannt werden. Als Berufskrankheit kommen nur solche Erkrankungen in Frage, die nach den Erkenntnissen der medizinischen Wissenschaft durch besondere Einwirkungen verursacht werden. Diesen Einwirkungen müssen bestimmte Personengruppen durch ihre Arbeit in erheblich höherem Grade als die übrige Bevölkerung ausgesetzt sein. Die derzeit anerkennungsfähigen Berufskrankheiten finden Sie in der Anlage 1 zur BKV. Hier finden Sie Berufskrankheitenliste mit Merkblättern und wissenschaftlichen Begründungen. Ob eine Erkrankung als Berufskrankheit anerkannt werden kann, entscheiden die gesetzlichen Unfallversicherungsträger. die gewerblichen Berufsgenossenschaften (für Beschäftigte in privaten Wirtschaftsunternehmen),"},"url":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Berufskrankheiten/berufskrankheiten.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:02.091322+00:00","lastSeen":"2026-03-15T17:52:02.091322+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Berufskrankheiten/berufskrankheiten.html","crawledAt":"2026-03-15T17:52:02.092322Z","crawlId":"contacts-seeded-1773597122","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"1746f04e8d7886be0320c6a5163c9a2686ed2b5d1c03faa56364ddc1a75a3d59"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:02.092322+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d0bd8eaa-7b5f-40df-9046-b8bccfbde241', 'contacts', 'https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Fragen-und-Antworten/fragen-und-antworten.html', 'active', NULL, '2026-03-15T17:52:02.700985+00:00', '{"id":"d0bd8eaa-7b5f-40df-9046-b8bccfbde241","title":"Fragen und Antworten","summary":{"de":"Wo ist die gesetzliche Unfallversicherung geregelt?"},"content":{"de":"Die gesetzliche Unfallversicherung ist im Siebten Buch Sozialgesetzbuch (SGB VII) geregelt. Weitere wichtige Verordnungen sind die Berufskrankheiten-Verordnung sowie die Unfallversicherungs-Anzeigeverordnung. Wer ist in der gesetzlichen Unfallversicherung versichert? Der Versicherungsschutz erstreckt sich auf verschiedene Personengruppen; die weitaus größte Gruppe bilden die Arbeitnehmer. Kraft Gesetzes sind alle Beschäftigten versichert unabhängig von der Höhe ihres Arbeitsentgelts, d.h. auch Auszubildende. Darüber hinaus sind folgende Personengruppen pflichtversichert: bestimmte ehrenamtlich tätige Personen (z.B. ehrenamtliche Mitarbeiter der Freiwilligen Feuerwehr) Personen, die im Interesse der Allgemeinheit tätig sind, wie z. B. Mitarbeiter in Hilfsorganisationen, Lebensretter, Blutspender, Zeugen, Schöffen Kinder, die in Kindertageseinrichtungen oder durch geeignete Tagespflegepersonen betreut werden, Schüler und Studierende in Schulen und Hochschulen sowie Personen in der beruflichen Aus- und Fortbildung"},"url":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Fragen-und-Antworten/fragen-und-antworten.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:02.700985+00:00","lastSeen":"2026-03-15T17:52:02.700985+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Fragen-und-Antworten/fragen-und-antworten.html","crawledAt":"2026-03-15T17:52:02.700985Z","crawlId":"contacts-seeded-1773597122","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"50c493ccb05a02f3e075ae53f2d8c9c3022fe970fb06bf35ab87e88df10c9ed4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:02.700985+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ebeb8abf-0082-41c7-b0df-08385099288e', 'contacts', 'https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Unfallversicherung-im-Ueberblick/unfallversicherung-im-ueberblick.html', 'active', NULL, '2026-03-15T17:52:03.318841+00:00', '{"id":"ebeb8abf-0082-41c7-b0df-08385099288e","title":"Überblick zur Unfallversicherung","summary":{"de":"Die gesetzliche Unfallversicherung ist ein Zweig der Sozialversicherung. Als Pflichtversicherung gleicht sie Gesundheitsschäden aus, die Versicherte infolge einer versicherten Tätigkeit erleiden. Gesetzliche Grundlage ist das Siebte Buch Sozialgesetzbuch ( SGB VII )."},"content":{"de":"Versicherte Personen in der gesetzlichen Unfallversicherung Versicherungsfälle in der gesetzlichen Unfallversicherung Die gesetzliche Unfallversicherung hat die Aufgabe, mit allen geeigneten Mitteln Versicherungsfälle (Arbeitsunfälle und Berufskrankheiten) sowie arbeitsbedingte Gesundheitsgefahren zu verhüten, nach Eintritt von Versicherungsfällen die Gesundheit und Leistungsfähigkeit der Versicherten wiederherzustellen und die Versicherten oder ihre Hinterbliebenen durch Geldleistungen zu entschädigen."},"url":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Unfallversicherung-im-Ueberblick/unfallversicherung-im-ueberblick.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:03.318841+00:00","lastSeen":"2026-03-15T17:52:03.318841+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Unfallversicherung-im-Ueberblick/unfallversicherung-im-ueberblick.html","crawledAt":"2026-03-15T17:52:03.318841Z","crawlId":"contacts-seeded-1773597123","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"62ea19150e2f54377ac789ee032225496de186c78ed6bb75035e09c5947e1a52"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:03.318841+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6cce1199-8133-4427-b085-64ec6570590d', 'contacts', 'https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Was-sind-Arbeitsunfaelle/was-sind-arbeitsunfaelle.html', 'active', NULL, '2026-03-15T17:52:03.866485+00:00', '{"id":"6cce1199-8133-4427-b085-64ec6570590d","title":"Was sind Arbeitsunfälle?","summary":{"de":"Arbeitsunfälle können in vielen Bereichen des täglichen Lebens passieren. Nicht nur Unfälle unmittelbar am Arbeitsplatz stehen unter dem Schutz der gesetzlichen Unfallversicherung."},"content":{"de":"Welche Leistungen gibt es bei der Anerkennung eines Arbeitsunfalls? Arbeitsunfälle können in vielen Bereichen des täglichen Lebens passieren. Nicht nur Unfälle unmittelbar am Arbeitsplatz stehen unter dem Schutz der gesetzlichen Unfallversicherung. Beispielsweise liegt auch in folgenden Fällen grundsätzlich ein Arbeitsunfall vor: Unfall bei Pflege eines nahen Angehörigen im eigenen Wohnhaus Unfall während einer Hilfeleistung nach einem Verkehrsunfall Wegeunfälle sind ebenfalls vom Versicherungsschutz umfasst. Dabei ist nicht nur der direkte Weg zum oder vom Ort der versicherten Tätigkeit (Arbeitsplatz, Schule, Kita etc. ) versichert, auch bestimmte Umwege können unter Unfallversicherungsschutz stehen (versichert sind z.B. auch Eltern, wenn sie auf dem Weg zur Arbeit einen Umweg zur Kita machen). Allgemein kann man deshalb sagen: Arbeitsunfälle sind die Unfälle, die versicherte Personen infolge einer versicherten Tätigkeit erleiden. Einen Überblick über die versicherten Personen und Tätigkeiten finden Sie bei den Fragen und Antworten zur gesetzlichen Unfallversicherung."},"url":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Was-sind-Arbeitsunfaelle/was-sind-arbeitsunfaelle.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:03.866485+00:00","lastSeen":"2026-03-15T17:52:03.866485+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/Was-sind-Arbeitsunfaelle/was-sind-arbeitsunfaelle.html","crawledAt":"2026-03-15T17:52:03.866485Z","crawlId":"contacts-seeded-1773597123","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"d7d045b09f188a5deebefab1b3ffbc87fd77d539482540a4aa51b8a7a1ff4fd8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:03.866485+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('26455a17-5420-44a4-aa3a-e16d926428de', 'contacts', 'https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/gesetzliche-unfallversicherung.html', 'active', NULL, '2026-03-15T17:52:04.423677+00:00', '{"id":"26455a17-5420-44a4-aa3a-e16d926428de","title":"Gesetzliche Unfallversicherung","summary":{"de":"Die gesetzliche Unfallversicherung ist ein Zweig der Sozialversicherung. Gesetzliche Grundlage ist das Siebte Buch Sozialgesetzbuch (SGB VII). Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Die gesetzliche Unfallversicherung ist ein Zweig der Sozialversicherung. Gesetzliche Grundlage ist das Siebte Buch Sozialgesetzbuch ( SGB VII ). Zu Ihrer Sicherheit - Unfallversichert bei häuslicher Pflege von Angehörigen Zu Ihrer Sicherheit – Unfallversichert in der Schule"},"url":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/gesetzliche-unfallversicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:04.423677+00:00","lastSeen":"2026-03-15T17:52:04.423677+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Gesetzliche-Unfallversicherung/gesetzliche-unfallversicherung.html","crawledAt":"2026-03-15T17:52:04.424679Z","crawlId":"contacts-seeded-1773597124","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"741e7730d2769337cb5f89ef53f59a437f3fd88ab1f5957e32661ca10fe893a0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:04.424679+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1f52fbfd-2813-4cd2-80e6-cc652936b109', 'contacts', 'https://www.bmas.de/DE/Soziales/Modernisierung-des-Sozialstaats/modernisierung-des-sozialstaats.html', 'active', NULL, '2026-03-15T17:52:05.265350+00:00', '{"id":"1f52fbfd-2813-4cd2-80e6-cc652936b109","title":"Modernisierung des Sozialstaats","summary":{"de":"Hintergründe und Informationen über die Kommission zur Sozialstaatsreform (KSR), auch bekannt als Sozialstaatskommission."},"content":{"de":"Hintergründe und Informationen über die Kommission zur Sozialstaatsreform (KSR) Die Kommission zur Sozialstaatsreform hat Vorschläge für einen modernen Sozialstaat im Sinne der Bürgerinnen und Bürger erarbeitet. Das Bundesministerium für Arbeit und Soziales hat die Leitung dieser Regierungskommission inne und setzt damit einen Auftrag aus dem Koalitionsvertrag um. Der KSR gehören Vertreterinnen und Vertretern des Bundes, der Länder und der kommunalen Spitzenverbände an. Am 27. Januar 2026 übergab die Kommission ihre Empfehlungen im Bundesministerium für Arbeit und Soziales an Bundesministerin Bärbel Bas. Das Dokument wurde von den Mitgliedern und dem parlamentarischen Begleitgremium erstellt. Der Bericht stellt ein umfassendes Reformkonzept für die steuerfinanzierten Sozialleistungen mit dem dreifachen Ziel dar, spürbare Erleichterungen für Bürger*innen zu erzielen, den Verwaltungsvollzug deutlich zu vereinfachen und einen digitalen Neustart des Sozialstaats auf den Weg zu bringen. Die Empfehlungen der Kommission sollen zudem positive Arbeitsmarkt- und Fiskaleffekte bewirken. Der Sozialstaat muss einfacher und verständlicher werden, durch:"},"url":"https://www.bmas.de/DE/Soziales/Modernisierung-des-Sozialstaats/modernisierung-des-sozialstaats.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:05.265350+00:00","lastSeen":"2026-03-15T17:52:05.265350+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Modernisierung-des-Sozialstaats/modernisierung-des-sozialstaats.html","crawledAt":"2026-03-15T17:52:05.265350Z","crawlId":"contacts-seeded-1773597125","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"366cde4d05625e942ffe7e4437dba506d8f47124f4cc270b08d5666453e813f6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:05.265350+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a0a84c7e-cf58-4f36-885c-a7d1155a6734', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Dialogprozess-Arbeit-und-Rente/dialogprozess-arbeit-und-rente.html', 'active', NULL, '2026-03-15T17:52:07.394205+00:00', '{"id":"a0a84c7e-cf58-4f36-885c-a7d1155a6734","title":"Dialogprozess \"Arbeit&Rente\"","summary":{"de":"Informationen zum Dialogprozess \"Arbeit & Rente\"."},"content":{"de":"Um Erwerbstätigkeit im Alter attraktiver zu gestalten, hat das BMAS unter Beteiligung der Sozialpartner den Dialogprozess \"Arbeit & Rente\" durchgeführt. Ziel war die Beseitigung von Hemmnissen und die Schaffung von Anreizen, um einen freiwilligen längeren Verbleib im Erwerbsleben zu fördern. Der Dialogprozess \"Arbeit & Rente\" soll einen Beitrag dazu leisten, dass künftig noch mehr Menschen im Alter von über 60 Jahren erwerbstätig sind und somit auch zur Fachkräftesicherung beitragen. Kernbestandteil des Dialogprozesses war der Austausch mit verschiedenen Akteuren in Fachdialogen im Mai 2024. Dabei wurden viele Impulse und Ideen dazu erarbeitet, welche Voraussetzungen es braucht, damit Menschen länger arbeiten können und wollen. Am 16. Mai 2024 fand der Fachdialog mit der Wissenschaft und am 31. Mai 2024 der Fachdialog mit betroffenen Verbänden und Trägern statt. Hierbei haben sich Wissenschaftlerinnen und Wissenschaftler bzw. die Verbände und Träger mit Vertreterinnen und Vertretern von DGB, BDA und der Bundesregierung zu verschiedenen Vorschlägen ausgetauscht und in Workshops Lösungsansätze erarbeitet. In den Workshops wurden die Themen Altersteilzeit, Arbeitsrecht, Arbeitszeit, monetäre Anreize, die betriebliche Ebene sowie Information und Beratung behandelt. Im Anschluss wurde jeweils zu der Frage diskutiert, welche Herausforderungen unbedingt gelöst werden müssen, damit Menschen im Alter von 60+ freiwillig länger arbeiten. Am 29. Mai 2024 wurden zwei Fachdialoge im digitalen Format durchgeführt. Am Vormittag gab es einen Austausch mit Betriebs- und Personalräten. Die Teilnehmenden diskutierten unter anderem über alters- und alternsgerechte Arbeitsbedingungen, Gesundheitsvorsorge und flexible Arbeitsmodelle. Am Nachmittag fand der Fachdialog mit Personalverantwortlichen statt. In zwei Workshops wurde diskutiert, wie arbeits- und sozialrechtliche Regelungen zu mehr Beschäftigung von älteren Arbeitnehmerinnen und Arbeitnehmern beitragen können. Auch die Perspektive der Bürgerinnen und Bürger ist in den Dialogprozess eingeflossen. Am 27. Mai 2024 hat der Bürgerdialog Hin.Gehört. mit Bundesminister Hubertus Heil in Bautzen zum Thema \"Arbeit & Rente\" stattgefunden, bei dem die Bürgerinnen und Bürger Fragen und eigene Vorschläge äußern konnten."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Dialogprozess-Arbeit-und-Rente/dialogprozess-arbeit-und-rente.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:07.394205+00:00","lastSeen":"2026-03-15T17:52:07.394205+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Dialogprozess-Arbeit-und-Rente/dialogprozess-arbeit-und-rente.html","crawledAt":"2026-03-15T17:52:07.394205Z","crawlId":"contacts-seeded-1773597127","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"b41d283c861533f97c0d86a813395e7b44f1851a0cf226ae202a8f21518b57ef"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:52:07.394205+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6bb25cad-7d74-41b3-abae-8610dd6aca7d', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Digitale-Rentenuebersicht/digitale-rentenuebersicht.html', 'active', NULL, '2026-03-15T17:52:07.950144+00:00', '{"id":"6bb25cad-7d74-41b3-abae-8610dd6aca7d","title":"BMAS - Digitale Rentenübersicht","summary":{"de":"Informationen und Links zur Digitalen Rentenübersicht der Deutschen Rentenversicherung."},"content":{"de":"Das Informationsportal über die individuellen Ansprüche in der gesetzlichen, betrieblichen und privaten Altersvorsorge Es ist nie zu früh, sich um die eigene Rente zu kümmern und für das Alter vorzusorgen. Die Digitale Rentenübersicht, ein staatliches und kostenfreies Angebot, schafft die Voraussetzungen dafür. Sie gibt allen Bürgerinnen und Bürgern eine Übersicht über den Stand ihrer individuellen Altersvorsorgeansprüche: Nicht nur über die gesetzliche Rentenversicherung, sondern auch über die betriebliche und private Altersvorsorge. Denn nur wer gut informiert ist, kann möglichen Handlungsbedarf erkennen und rechtzeitig angehen. Die Digitale Rentenübersicht sammelt die verfügbaren Informationen über die eigene Altersvorsorge bei den verschiedenen Anbietern ein, bereitet die Informationen über die einzelnen Altersvorsorgeansprüche nach einer einheitlichen Systematik auf und stellt diese übersichtlich nebeneinander dar. So lässt sich auf einen Blick erkennen, mit welchen Leistungen im Alter zu rechnen ist. Das Portal ergänzt nicht nur die jährlichen Informationen oder Standmitteilungen zu den Altersvorsorgeansprüchen der gesetzlichen, betrieblichen oder privaten Altersvorsorge, sie führt diese auch zu einem Gesamtüberblick zusammen. Somit hilft die Digitale Rentenübersicht dabei, sich ein Bild von der zu erwartenden finanziellen Situation im Ruhestand zu machen und ermöglicht es dadurch zu prüfen, ob die derzeitige Altersvorsorge zu den individuellen Plänen im Alter passt. Sofern Handlungsbedarf besteht, kann die Digitale Rentenübersicht gespeichert und als Grundlage einer Beratung dienen, die die Auskunfts- und Beratungsstellen der Deutschen Rentenversicherung oder die Verbraucherzentralen anbieten. Ebenso beraten die Anbieter von Altersvorsorgeprodukten zu ihren Angeboten."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Digitale-Rentenuebersicht/digitale-rentenuebersicht.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:07.950144+00:00","lastSeen":"2026-03-15T17:52:07.950144+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Digitale-Rentenuebersicht/digitale-rentenuebersicht.html","crawledAt":"2026-03-15T17:52:07.950144Z","crawlId":"contacts-seeded-1773597127","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"301bf6cae572cd8da48eed9618b04760a7b969cacf0118a9525e7022e2eddfdf"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:07.950144+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c5ab220b-d829-48cb-a1db-6119749bf1ad', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alternde-Gesellschaft/alternde-gesellschaft.html', 'active', NULL, '2026-03-15T17:52:08.582246+00:00', '{"id":"c5ab220b-d829-48cb-a1db-6119749bf1ad","title":"Alternde Gesellschaft","summary":{"de":"Ist die Bevölkerungsentwicklung eine Belastung für das Sozialsystem?"},"content":{"de":"Die Lebenserwartung bei Geburt hat sich in den letzten rund 150 Jahren in etwa verdoppelt. Die Lebenserwartung in Deutschland ist in den vergangenen knapp 150 Jahren massiv angestiegen. So hat sich die Lebenserwartung bei Geburt seit 1871 bei beiden Geschlechtern in etwa verdoppelt und liegt aktuell bei 78,2 Jahren (Männer) bzw. 83,0 Jahren (Frauen). Diese Entwicklung ist wesentlich auf in dieser Zeitspanne verbesserte Ernährungs-, Hygiene- und Wohnbedingungen sowie eine bessere Gesundheitsversorgung zurückzuführen, die die Mortalität von Säuglingen, Kindern und Müttern deutlich senkten. Die zu beobachtende Zunahme der Langlebigkeit schlägt sich wiederum in der ferneren Lebenserwartung ab einem Alter von 65 Jahren nieder. Sie beträgt bei Männern 17,5 Jahre und bei Frauen 20,8 Jahre, womit sich die verbleibende Lebenszeit 65-Jähriger in den letzten 40 Jahren für beide Geschlechter um etwa fünf Jahre erhöht hat. Dabei hat sich der Anstieg der Lebenserwartung in den letzten Jahren abgeschwächt bzw. war leicht rückläufig. Aktuelle Bevölkerungsvorausberechnungen gehen jedoch weiterhin von einem künftigen Anstieg der Lebenserwartung aus. Bei den Sterbetafeln des Statistischen Bundesamtes (Periodentafeln) handelt sich um eine Momentaufnahme der Sterblichkeitsverhältnisse der gesamten Bevölkerung für den jeweiligen Zeitpunkt. Eine Prognose der zukünftigen Entwicklung der Lebenserwartung ist nicht eingeschlossen. Die Lebenserwartung Neugeborener gibt an, wie lange sie den aktuellen Überlebensverhältnissen entsprechend durchschnittlich leben würden. 65-Jährige erreichen statistisch gesehen ein höheres Lebensalter als Neugeborene, weil Sterberisiken vor dem Alter 65 bereits überlebt wurden. Es handelt sich um Durchschnittswerte für die Gesamtbevölkerung, die in unterschiedlichen demografischen Gruppen unterschiedlich hoch ausfallen können. Bekannt sind insbesondere Unterschiede nach Bildung, Einkommen und Gesundheit. Seit Ende der 1970er Jahre liegt die Zahl der Geburten unter dem bestandserhaltenden Niveau. Zusammengefasste Geburtenziffer (durchschnittliche Kinderzahl je Frau): Summe der altersspezifischen Geburtenziffern nach der Geburtsjahrmethode. Ab 2011: Ergebnisse auf Grundlage des Zensus 2011. Stand: 23. Januar 2025"},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alternde-Gesellschaft/alternde-gesellschaft.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:08.582246+00:00","lastSeen":"2026-03-15T17:52:08.582246+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alternde-Gesellschaft/alternde-gesellschaft.html","crawledAt":"2026-03-15T17:52:08.582246Z","crawlId":"contacts-seeded-1773597128","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f7a53a4e5f6ebfd03d9848dd969315073a115df7aff7110ce11c415f33f67209"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:08.582246+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d84a16ce-b8e8-4086-91af-dd5cc48889e0', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alterseinkommen-und-zusaetzliche-Vorsorge/alterseinkommen-und-zusaetzliche-vorsorge.html', 'active', NULL, '2026-03-15T17:52:09.190475+00:00', '{"id":"d84a16ce-b8e8-4086-91af-dd5cc48889e0","title":"Alterseinkommen und zusätzliche Vorsorge","summary":{"de":"Was ist die bedeutendste Einkommensquelle im Alter?"},"content":{"de":"In welchem Verhältnis stehen eigentlich Beiträge und Leistungen? Wie hat sich die Verbreitung der zusätzlichen Altersvorsorge seit den \"Riester-Reformen\" entwickelt? Welche Zusammenhänge bestehen zwischen Einkommen und zusätzlicher Vorsorge? Bedeutet eine niedrige Altersrente auch ein niedriges Alterseinkommen? Gut die Hälfte der Alterseinkommen der 65-Jährigen und Älteren stammen aus der gesetzlichen Rentenversicherung. Die gesetzliche Rentenversicherung ist die wichtigste Einkommensquelle im Alter. Sie zahlt rund 53 Prozent der Alterseinkommen an die 65-Jährigen und Älteren. Die betriebliche Altersversorgung macht rund 7 Prozent aus. Aus den anderen Alterssicherungssystemen stammen 17 Prozent. Zusammen erreichen die übrigen Einkommensquellen (Erwerbseinkommen, private Vorsorge, Transferleistungen und sonstige Einkommen) rund 22 Prozent."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alterseinkommen-und-zusaetzliche-Vorsorge/alterseinkommen-und-zusaetzliche-vorsorge.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:09.190475+00:00","lastSeen":"2026-03-15T17:52:09.190475+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alterseinkommen-und-zusaetzliche-Vorsorge/alterseinkommen-und-zusaetzliche-vorsorge.html","crawledAt":"2026-03-15T17:52:09.190475Z","crawlId":"contacts-seeded-1773597129","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"445322ef0bfb6d0f313526974c0c44038275228e3aab0a282217259900d6b4bc"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:09.190475+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f6602a9f-dd36-4a76-be6c-21cd882c693b', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alterssicherung-im-internationalen-Vergleich/alterssicherung-im-internationalen-vergleich.html', 'active', NULL, '2026-03-15T17:52:09.731493+00:00', '{"id":"f6602a9f-dd36-4a76-be6c-21cd882c693b","title":"Alterssicherung im internationalen Vergleich","summary":{"de":"Deutschlands Altersgrenze ist vergleichsweise hoch, lässt aber begründete Ausnahmen zu. Das ist fair für Versicherte und gut für die Finanzierung unseres Rentensystems. Um die finanzielle Tragfähigkeit der Systeme abzusichern, haben viele Staaten die Altersgrenzen angehoben. In Deutschland erfolgt die Anhebung in behutsamen Schritten. Die Regelaltersgrenze von 67 Jahren wird erst im Jahr 2030 erreicht. Wie in den meisten anderen Ländern gibt es in Deutschland die Möglichkeit, unter bestimmten Voraussetzungen oder mit Abschlägen schon vorzeitig eine Altersrente zu beziehen. Bei langjährig Versicherten ist das ab 63 Jahren möglich."},"content":{"de":"Die Regelaltersgrenze bezeichnet das Alter, ab dem der Versicherte bei Erfüllung der Wartezeit Anspruch auf eine abschlagsfreie Rente hat. Das frühestmögliche Alter für den Renteneintritt ist das Alter, ab dem der Versicherte eine Rente mit Abschlägen oder unter spezifischen Anspruchsvoraussetzungen wie langjährige Beitragszeiten beziehen kann. Deutschlands Rentenausgaben liegen gemessen am Bruttoinlandsprodukt einen Prozentpunkt unter dem EU -Durchschnitt. Im internationalen Vergleich kann die Höhe der Rentenausgaben an der Wirtschaftsleistung eines Landes gemessen werden. Da die Rentensysteme in den Ländern Europas sehr unterschiedlich aufgebaut sind, ist es ratsam, möglichst alle Rentenausgaben zu erfassen: aus staatlicher, betrieblicher und privater Vorsorge. Der Vergleich zeigt, dass Deutschland trotz eines hohen Anteils älterer Menschen an der Bevölkerung gemessen am Bruttoinlandsprodukt relativ moderate Rentenausgaben aufweist, die unter dem Durchschnitt der EU-Mitgliedsstaaten liegen. Als Rentenausgaben werden von EUROSTAT, dem statistischen Amt der Europäischen Union, alle periodischen Geldleistungen erfasst, die langfristig ein Erwerbseinkommen ersetzen. Dazu zählen Altersrenten einschließlich vorgezogene Altersrenten und Teilrenten, Hinterbliebenenrenten, Erwerbsminderungsrenten und Unfallrenten aus den gesetzlichen Sicherungssystemen einschließlich der Beamtenversorgungen. Einbezogen sind auch betriebliche und private Rentenleistungen sowie Leistungen, die nur nach einer Bedarfsprüfung gewährt werden. Diese breite Definition der Rentenausgaben auf europäischer Ebene kann von nationalen Statistiken über Rentenausgaben abweichen. Deutschland weist ein hohes Niveau der Erwerbstätigkeit auf, was wichtig ist für das Funktionieren eines tragfähigen Alterssicherungssystems. Das gilt auch für die Erwerbstätigkeit im Alter. Die Erwerbstätigenquote in der Altersgruppe der 60- bis 64-Jährigen liegt in allen Ländern unter der Quote der Gesamtbevölkerung. Deutschland zählt dabei sowohl bei der Gesamtbevölkerung als bei den 60- bis 64-Jährigen zu den Ländern mit den höchsten Erwerbsquoten."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alterssicherung-im-internationalen-Vergleich/alterssicherung-im-internationalen-vergleich.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:09.731493+00:00","lastSeen":"2026-03-15T17:52:09.731493+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Alterssicherung-im-internationalen-Vergleich/alterssicherung-im-internationalen-vergleich.html","crawledAt":"2026-03-15T17:52:09.731493Z","crawlId":"contacts-seeded-1773597129","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"fa8089584690e513dbfb95d9c1bea117511fc82af44bf1e093e464a3565d51e0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:09.731493+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('76432c9a-cba4-41e0-9283-ea1a8315c0d4', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Gesetzliche-Rentenversicherung/gesetzliche-rentenversicherung.html', 'active', NULL, '2026-03-15T17:52:10.718143+00:00', '{"id":"76432c9a-cba4-41e0-9283-ea1a8315c0d4","title":"Gesetzliche Rentenversicherung","summary":{"de":"Wie viele Beschäftigte sind gesetzlich rentenversichert?"},"content":{"de":"Welchen Beitrag leisten die Steuerzahler zur Finanzierung der gesetzlichen Rentenversicherung? Stimmt es, dass der Beitragssatz zur gesetzlichen Rentenversicherung seit langer Zeit steigt? Von rund 41,4 Mio. aktiven Arbeitnehmerinnen und Arbeitnehmern sind rund 33,4 Mio. in der gesetzlichen Rentenversicherung versichert. Von den rund 41,4 Mio. aktiven Arbeitnehmern verfügen rund 36,2 Mio. Personen über eine obligatorische Alterssicherung. Für rund 33,4 Mio. Arbeitnehmer ist die gesetzliche Rentenversicherung die wichtigste Form der Absicherung im Alter. Die größte Personengruppe der Arbeitnehmer ohne obligatorische Alterssicherung (als Folge der Möglichkeit, die obligatorische rentenrechtliche Absicherung zu verlassen) stellen die ausschließlich geringfügig Beschäftigten dar. Bei den Selbstständigen sind nur 0,3 Mio. in der gesetzlichen Rentenversicherung abgesichert. 0,6 Mio. Selbstständige verfügen über eine obligatorische Absicherung durch die Berufsständischen Versorgungswerke oder die Alterssicherung der Landwirte. Drei Mio. Selbstständige verfügen über keine obligatorische Alterssicherung. Bei der in der Übersicht genannten Zahlen handelt es sich um Schätzungen auf Basis verschiedener statistischer Daten für das Jahr 2023. Datenquellen sind die Erwerbstätigenrechnung im Rahmen der volkswirtschaftlichen Gesamtrechnung, Statistiken der Deutschen Rentenversicherung Bund, der Bundesagentur für Arbeit, des Statistischen Bundesamtes (Mikrozensus, Elterngeldstatistik), der Sozialversicherung für Landwirtschaft, Forsten und Gartenbau sowie Angaben der Arbeitsgemeinschaft berufsständischer Versorgungseinrichtungen.Bei der in der Übersicht genannten Zahlen handelt es sich um Schätzungen auf Basis verschiedener statistischer Daten für das Jahr 2023. Datenquellen sind die Erwerbstätigenrechnung im Rahmen der volkswirtschaftlichen Gesamtrechnung, Statistiken der Deutschen Rentenversicherung Bund, der Bundesagentur für Arbeit, des Statistischen Bundesamtes (Mikrozensus, Elterngeldstatistik), der Sozialversicherung für Landwirtschaft, Forsten und Gartenbau sowie Angaben der Arbeitsgemeinschaft berufsständischer Versorgungseinrichtungen. Mittel aus dem Bundeshaushalt decken seit einigen Jahren gut 30 Prozent der Ausgaben der gesetzlichen Rentenversicherung."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Gesetzliche-Rentenversicherung/gesetzliche-rentenversicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:10.718143+00:00","lastSeen":"2026-03-15T17:52:10.718143+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Gesetzliche-Rentenversicherung/gesetzliche-rentenversicherung.html","crawledAt":"2026-03-15T17:52:10.718143Z","crawlId":"contacts-seeded-1773597130","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"17462c975c943285c8cadc75baa70e08446fdf3e631ac42b0ef292eb3b64ca1c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:10.718143+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('60a92c0f-e745-4778-a960-137f19f4c1ee', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Grundsicherung-im-Alter/grundsicherung-im-alter.html', 'active', NULL, '2026-03-15T17:52:11.245723+00:00', '{"id":"60a92c0f-e745-4778-a960-137f19f4c1ee","title":"Grundsicherung im Alter","summary":{"de":"Im Alter ist ein deutlich geringerer Teil der Bevölkerung auf Mindestsicherungsleistungen angewiesen als insgesamt."},"content":{"de":"1) Gesamtregelleistung (Arbeitslosengeld II / Sozialgeld) nach dem Zweiten Buch Sozialgesetzbuch (SGB II \"Bürgergeld, Grundsicherung für Arbeitsuchende\") 2) Hilfe zum Lebensunterhalt außerhalb von Einrichtungen nach dem SGB XII \"Sozialhilfe\" 3) Grundsicherung im Alter und bei Erwerbsminderung nach dem SGB XII \"Sozialhilfe\" 4) Regelleistungen nach dem Asylbewerberleistungsgesetz (AsylbLG). Quellen: Für SGB II-Daten: Statistik der Bundesagentur für Arbeit. Für alle weiteren Daten: Statistische Ämter des Bundes und der Länder. Der Anteil der Personen, die auf Grundsicherung im Alter angewiesen sind, ist seit 2006 von 2,3 Prozent auf 3,9 Prozent im Jahr 2023 gestiegen. In der Gesamtbevölkerung ist dagegen ein deutlich höherer Anteil der Menschen bedürftig. Die sogenannte Mindestsicherungsquote ist mit aktuell 8,6 Prozent mehr als doppelt so hoch. Die vom Statistischen Bundesamt errechnete Mindestsicherungsquote ist die Zahl der Personen, die Leistungen nach dem SGB II \"Grundsicherung für Arbeitsuchende\" (Bürgergeld), nach dem 3. und 4. Kapitel SGB XII (Hilfe zum Lebensunterhalt außerhalb von Einrichtungen und Grundsicherung im Alter und bei Erwerbsminderung) und die Regelleistungen nach dem Asylbewerberleistungsgesetz erhalten, im Verhältnis zur Gesamtbevölkerung Deutschlands dar. Die Grundsicherungsquote stellt die Zahl der Personen, die Grundsicherung im Alter nach dem 4. Kapitel des SGB XII beziehen im Verhältnis zur gleichaltrigen Bevölkerung in Deutschland dar. Die Mehrheit der Bezieherinnen und Bezieher von Grundsicherung im Alter hat keine oder nur eine geringe Altersrente."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Grundsicherung-im-Alter/grundsicherung-im-alter.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:11.245723+00:00","lastSeen":"2026-03-15T17:52:11.245723+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/Grundsicherung-im-Alter/grundsicherung-im-alter.html","crawledAt":"2026-03-15T17:52:11.245723Z","crawlId":"contacts-seeded-1773597131","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"8e76518a14e5ce11244af00d1720bf31823df30a44f7cc79ec2fc75539a98870"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:11.245723+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('eee515c8-f70e-49e3-b673-349962b7e988', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/fakten-zur-rente.html', 'active', NULL, '2026-03-15T17:52:11.846599+00:00', '{"id":"eee515c8-f70e-49e3-b673-349962b7e988","title":"Fakten zur Rente","summary":{"de":"Wir leisten einen Beitrag zur Versachlichung der Diskussion über die Zukunft der Alterssicherung – mit Zahlen und Fakten."},"content":{"de":"Hier stehen alle Daten zum Thema Alterssicherung zum Download bereit. Hier finden Sie alle Informationen zum Thema Rente und Altersvorsorge."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/fakten-zur-rente.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:11.846599+00:00","lastSeen":"2026-03-15T17:52:11.846599+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Fakten-zur-Rente/fakten-zur-rente.html","crawledAt":"2026-03-15T17:52:11.847599Z","crawlId":"contacts-seeded-1773597131","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"a2cb4fc5f4b677ae7dccd355317a1e0a511beec99ca079ed601c8067f2750349"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:11.847599+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('067d04d2-735b-44c1-a94e-9f463a2d0b69', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Finanzierung-Gesetzliche-Rentenversicherung/finanzierung-der-gesetzlichen-rentenversicherung.html', 'active', NULL, '2026-03-15T17:52:12.458852+00:00', '{"id":"067d04d2-735b-44c1-a94e-9f463a2d0b69","title":"Finanzierung der Gesetzlichen Rentenversicherung","summary":{"de":"Die Finanzierung des Rentensystems beruht auf dem Umlageverfahren: Danach werden die Ausgaben der gesetzlichen Rentenversicherung eines Kalenderjahres aus den Einnahmen desselben Kalenderjahres bestritten. Das heißt, dass insbesondere mit den monatlichen Beiträgen der sozialversicherungspflichtig Beschäftigten und der Arbeitgeber sogleich insbesondere die Renten derjenigen gezahlt werden, die heute Rentenbeziehende sind."},"content":{"de":"Auf diese Weise sorgt die jeweils arbeitende Generation solidarisch u. a. für die Renten ihrer Eltern- und Großelterngeneration. Deshalb ist im Grundsatz die Zahl der Beitragszahlenden und die Höhe der von ihnen versicherten Einkommen ausschlaggebend dafür, wie viel Geld durch Beitragseinnahmen in das Rentensystem fließt. Auf der Auszahlungsseite richtet sich die Höhe der persönlichen Rente in erster Linie nach der Anzahl der Beitragsjahre und der Höhe der versicherten Arbeitsentgelte. Die Beiträge zur Rentenversicherung für versicherungspflichtige Beschäftigte werden von ihnen und ihren Arbeitgebern grundsätzlich zu gleichen Teilen getragen (Parität). Der Beitragssatz zur allgemeinen Rentenversicherung erreichte 1997/98 seinen Höchstwert ( 20,3 Prozent ). Aufgrund der umgesetzten Rentenreformen zu Beginn der 2000er-Jahre sowie der sehr guten Arbeitsmarktentwicklung konnte der Beitragssatz gesenkt werden und liegt seit 2018 stabil bei 18,6 Prozent. In den kommenden Jahren ist mit einem Anstieg zu rechnen, weil die geburtenstarken Jahrgänge der 1960er-Jahre mehr und mehr das Rentenalter erreichen. Die Rentenversicherung erbringt neben den Leistungen, die durch Beiträge gedeckt sind, auch eine Reihe von Leistungen, um gesamtgesellschaftliche Aufgaben zu erfüllen, wie zum Beispiel die Gewährung von Kindererziehungszeiten. Zur pauschalen Abgeltung dieser sogenannten nicht beitragsgedeckten Leistungen erhält die gesetzliche Rentenversicherung Mittel aus dem Bundeshaushalt. Mit den Bundeszuschüssen wird darüber hinaus die Funktions- und Leistungsfähigkeit der gesetzlichen Rentenversicherung garantiert. Die Finanzierung der Rentenversicherung setzt sich somit aus Beiträgen der Versicherten und Bundesmitteln zusammen. Die Bundesmittel beliefen sich im Jahr 2025 auf insgesamt rund 120 Milliarden Euro. Die Mittel aus dem Bundeshaushalt machen seit Anfang der 2000er-Jahre rund 30 Prozent der Einnahmen der gesetzlichen Rentenversicherung aus, die im Jahr 2025 bei rund 420 Milliarden Euro lagen. Die Eurobeträge der Ausgaben der Rentenversicherung bzw. der Bundesmittel lassen sich kaum einordnen. Für eine Bewertung ist es sinnvoll, wenn diese Werte in Relation beispielsweise zum Bruttoinlandsprodukt (BIP) in Deutschland gesetzt werden, also der gesamtwirtschaftlichen Leistungsfähigkeit. Dabei zeigt sich, dass die Ausgaben der gesetzlichen Rentenversicherung seit den frühen 2000er-Jahren im Verhältnis zum BIP vergleichsweise stabil zwischen 9 und 10 Prozent liegen. Gleiches gilt für die Bundesmittel, die im Zeitablauf rund 3 Prozent des BIP ausmachen. Zurück zur Übersicht Gesetzliche Rentenversicherung"},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Finanzierung-Gesetzliche-Rentenversicherung/finanzierung-der-gesetzlichen-rentenversicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:12.458852+00:00","lastSeen":"2026-03-15T17:52:12.458852+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Finanzierung-Gesetzliche-Rentenversicherung/finanzierung-der-gesetzlichen-rentenversicherung.html","crawledAt":"2026-03-15T17:52:12.459924Z","crawlId":"contacts-seeded-1773597132","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"da8ffbc3ef57053b36290b43091bcf9e8c0e79fa8ef2b1c0e31312685560425d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:12.459924+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7cfca34d-3e9c-466e-9757-5a9b9e5b7641', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Geschichte-Gesetzliche-Rentenversicherung/geschichte-der-gesetzlichen-rentenversicherung.html', 'active', NULL, '2026-03-15T17:52:13.143274+00:00', '{"id":"7cfca34d-3e9c-466e-9757-5a9b9e5b7641","title":"Historie der Gesetzlichen Rentenversicherung","summary":{"de":"Seit den Anfängen der gesetzlichen Rentenversicherung vor mehr als 125 Jahren haben sich die Renten von einem bloßen Zuschuss zum Lebensunterhalt zu einer Leistung entwickelt, die heute für die meisten Versicherten die wesentliche Grundlage ihrer Altersversorgung bildet. Während dieser Entwicklung musste die Rentenversicherung immer wieder an die gesellschaftlichen und wirtschaftlichen Veränderungen angepasst werden."},"content":{"de":"Unter Reichskanzler Otto von Bismarck verabschiedete der Reichstag nach zweijähriger intensiver öffentlicher Diskussion am 22. Juni 1889 das Gesetz über die Invaliditäts- und Altersversicherung. Nach dem schon 1883 eingeführten Krankenversicherungsgesetz für die Arbeiter und dem Unfallversicherungsgesetz von 1884 war damit die Grundlage der gesetzlichen Rentenversicherung für alle Arbeiter ab dem 16. Lebensjahr und Angestellte mit einem Jahreseinkommen bis zu 2.000 Mark geschaffen. Eine Rente wurde allerdings primär im Falle einer Arbeitsinvalidität ausgezahlt. Altersrente wurde als \"Sicherheitszuschuss zum Lebensunterhalt\" erst ab Vollendung des 70. Lebensjahres gezahlt, was weit über der durchschnittlichen Lebenserwartung der Arbeiter zu dieser Zeit lag (Durchschnittliche Lebenserwartung von Männern im Jahr 1910: 45 Jahre; von Frauen: 48 Jahre ). Der Beitragssatz für diese Rente lag bei lediglich 1,7 Prozent und wurde je zur Hälfte von den Arbeitern und den Arbeitgebern getragen. Die sog. Invalidenversicherung finanzierte sich als zum Teil kapitalgedecktes System vor allem aus diesen Beiträgen sowie einem Zuschuss des Reiches aus Steuermitteln. Dieser sog. Reichsbeitrag wurde als Zusicherung des Existenzminimums durch den Staat mittels der Sozialversicherung begründet und umfasste im Durchschnitt immerhin etwa ein Drittel, zeitweise bis zu 40 Prozent der Ausgaben. Das Leistungsniveau der Invalidenversicherung ist allerdings mit dem der heutigen gesetzlichen Rentenversicherung nicht annähernd vergleichbar. Mit der Reichsversicherungsordnung von 1911 wurden die drei Sozialversicherungsgesetze schließlich formal zusammengefasst. Mit der Reichsversicherungsordnung wurde auch die Hinterbliebenenversorgung für Witwen und Waisen eingeführt; damals allerdings für Witwen nur für den Fall der Invalidität. Für die Angestellten trat mit dem Versicherungsgesetz für Angestellte im selben Jahr eine eigene Altersversicherung in Kraft. Die Angestelltenversicherung erhielt bis 1945 keine Reichszuschüsse. Der Erste Weltkrieg und seine Folgen erfasste neben allen anderen gesellschaftlichen Bereichen auch das Rentensystem. Dementsprechend wurde der Kriegsdienst auf die Rentenzeiten angerechnet. Zudem wurde das Renteneintrittsalter generell auf 65 Jahre abgesenkt, mit dem Ergebnis, dass sich der Bestand der Altersrenten zum Jahresende 1916 verdoppelte. Als Folge des Krieges vervielfachte sich der Rentenbestand – insbesondere der Kriegswitwen- und Waisenrenten – nochmals. Durch die Anpassung der Beitragsgestaltung und Rentenzulagen versuchte der Gesetzgeber dem Wertverlust der Renten während der Inflation in den zwanziger Jahren entgegen zu steuern. Damit sank die praktische Bedeutung der Rentenversicherung auf den Berechtigungsnachweis der Sonderfürsorge ab. Als die Weltwirtschaftskrise der Jahre 1930 bis 1932 hinzukam, konnte die Rentenversicherung nur noch mit mehrfachen Einschränkungen des Leistungsrechts reagieren."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Geschichte-Gesetzliche-Rentenversicherung/geschichte-der-gesetzlichen-rentenversicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:13.143274+00:00","lastSeen":"2026-03-15T17:52:13.143274+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Geschichte-Gesetzliche-Rentenversicherung/geschichte-der-gesetzlichen-rentenversicherung.html","crawledAt":"2026-03-15T17:52:13.143274Z","crawlId":"contacts-seeded-1773597133","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"607f3347843eff3fd12ce75ddfffe7d3103c9da4c383c6e4771c96f78465edaa"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:13.143274+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('aaff7c1b-d3d0-4fd2-9699-37f7ccef29a9', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Rentenberechnung/rentenberechnung.html', 'active', NULL, '2026-03-15T17:52:13.784482+00:00', '{"id":"aaff7c1b-d3d0-4fd2-9699-37f7ccef29a9","title":"Rentenberechnung","summary":{"de":"Bei der Berechnung der individuellen Rente wird sowohl die persönliche Beitragsdauer und -höhe als auch die allgemeine durchschnittliche Lohnentwicklung berücksichtigt."},"content":{"de":"Die Renten werden jedes Jahr zum 1. Juli angepasst. Hierfür wird der neue aktuelle Rentenwert anhand der gesetzlichen Berechnungsvorschriften bestimmt und mit einer Rechtsverordnung festgelegt. Von besonderer Bedeutung für die Rentenversicherung sind die Rechengrößen. Die Deutsche Rentenversicherung bietet Ihnen einige Berechnungsprogramme an. So können Sie beispielsweise mit Hilfe Ihrer letzten Renteninformation den frühestmöglichen, den regulären Beginn und die Höhe Ihrer Altersrente ermitteln. Zur Übersicht auf der Seite der Deutschen Rentenversicherung"},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Rentenberechnung/rentenberechnung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:13.784482+00:00","lastSeen":"2026-03-15T17:52:13.784482+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Rentenberechnung/rentenberechnung.html","crawledAt":"2026-03-15T17:52:13.784482Z","crawlId":"contacts-seeded-1773597133","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"15a25a29baf3991c4b9eefb394f7c62bfb8bebf6b11ee56174bbdca3b4c5b57b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:13.784482+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('67ede3ab-40aa-4c1d-b66a-172a445c481a', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Wer-ist-versichert/wer-ist-versichert.html', 'active', NULL, '2026-03-15T17:52:14.298301+00:00', '{"id":"67ede3ab-40aa-4c1d-b66a-172a445c481a","title":"Wer ist versichert?","summary":{"de":"Eine Übersicht, welche Personengruppen gesetzlich versichert sind"},"content":{"de":"In der gesetzlichen Rentenversicherung sind grundsätzlich alle Arbeitnehmer*innen pflichtversichert. Ebenso pflichtversichert sind z.B. Auszubildende, Personen, die Kinder erziehen, bestimmte Gruppen von selbstständig Erwerbstätigen und Bezieher*innen von Entgeltersatzleistungen. Nicht versicherungspflichtige Personen können freiwillig Beiträge in die gesetzliche Rentenversicherung zahlen. Voraussetzung ist, dass sie mindestens 16 Jahre alt sind und in der Bundesrepublik Deutschland wohnen bzw. gewöhnlich dort leben oder sich als Deutsche im Ausland aufhalten. Auch wer bereits eine vorgezogene Altersvollrente erhält, kann bis zum Erreichen der Regelaltersgrenze freiwillige Beiträge zahlen. Daneben haben bestimmte Personenkreise die Möglichkeit, die Versicherungspflicht zu beantragen. Im Folgenden werden die eben genannten verschiedenen Personenkreise noch einmal näher erläutert. Die Angaben sind aus dem Sozialgesetzbuch (SGB) Sechstes Buch ( VI ) entnommen. In der gesetzlichen Rentenversicherung sind bis auf wenige Ausnahmen alle Personen pflichtversichert, die als Arbeitnehmer*innen gegen Entgelt beschäftigt sind."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Wer-ist-versichert/wer-ist-versichert.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:14.298301+00:00","lastSeen":"2026-03-15T17:52:14.298301+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/Wer-ist-versichert/wer-ist-versichert.html","crawledAt":"2026-03-15T17:52:14.299309Z","crawlId":"contacts-seeded-1773597134","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"7d2269ccd7137d289c04ee45453d0966ef73c95615e8c04cae92c833d2d95407"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:14.299309+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6e2de989-9f9c-4c26-8414-ccd6f2c7e361', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/gesetzliche-rentenversicherung.html', 'active', NULL, '2026-03-15T17:52:14.868016+00:00', '{"id":"6e2de989-9f9c-4c26-8414-ccd6f2c7e361","title":"Gesetzliche Rentenversicherung","summary":{"de":"Die gesetzliche Rentenversicherung ist und bleibt die wichtigste Säule der Alterssicherung in Deutschland."},"content":{"de":"Bis zum Jahr 2031 bleibt das Rentenniveau an die Lohnentwicklung gekoppelt (sogenannte Haltelinie). Damit stärken wir die gesetzliche Rente für jetzige und künftige Rentnerinnen und Rentner. Informationen zu den Alters-, Erwerbsminderungs- und Hinterbliebenenrenten sowie zur Grundrente und Reha sind in einem eigenen Themenbereich gebündelt. Auf der Webseite der Deutschen Rentenversicherung, finden Sie alle Themen rund um die Leistungen der gesetzlichen Rentenversicherung. Ein Portal mit Informationen zum individuellen Stand der gesetzlichen, betrieblichen und privaten Altersvorsorge. Übersicht über die Leistungen der Gesetzlichen Rentenversicherung"},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/gesetzliche-rentenversicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:14.868016+00:00","lastSeen":"2026-03-15T17:52:14.868016+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Gesetzliche-Rentenversicherung/gesetzliche-rentenversicherung.html","crawledAt":"2026-03-15T17:52:14.868016Z","crawlId":"contacts-seeded-1773597134","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"fb225c2026175c2bba6103d4586bcbcc660c5591278f3105181dd1eb30217b88"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:14.868016+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d53f8601-a31f-4f93-b308-d7c60aff1004', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Rentenlexikon/rentenlexikon.html', 'active', NULL, '2026-03-15T17:52:15.522173+00:00', '{"id":"d53f8601-a31f-4f93-b308-d7c60aff1004","title":"Rentenlexikon","summary":{"de":"Diese Seite beinhaltet das Rentenlexikon des Bundesministeriums für Arbeit und Soziales und erklärt wichtige Begriffe zum Thema Rente."},"content":{"de":"Das Rentenlexikon erläutert die wichtigsten Fachbegriffe aus der gesetzlichen Rentenversicherung und der zusätzlichen Altersvorsorge."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Rentenlexikon/rentenlexikon.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:15.522173+00:00","lastSeen":"2026-03-15T17:52:15.522173+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Rentenlexikon/rentenlexikon.html","crawledAt":"2026-03-15T17:52:15.522173Z","crawlId":"contacts-seeded-1773597135","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"286cf658f33b97d8e11798feeaf70dbce10d54b5b472acbc1770439ac402a721"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:15.522173+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6f8d23c4-86e6-4b66-8f47-ffe7ef459206', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Rentenreform-2025/rentenreform-2025.html', 'active', NULL, '2026-03-15T17:52:16.871539+00:00', '{"id":"6f8d23c4-86e6-4b66-8f47-ffe7ef459206","title":"Die Rentenreform 2025","summary":{"de":"Die gesetzliche Rente ist und bleibt das Herzstück der Alterssicherung"},"content":{"de":"Heutige und zukünftige Rentnerinnen und Rentner sollen sich auf die Absicherung im Alter verlassen können. Deshalb wird durch das Gesetz zur Stabilisierung des Rentenniveaus und zur vollständigen Gleichstellung der Kindererziehungszeiten (sogenanntes \" Rentenpaket 2025 \") die Haltelinie in der gesetzlichen Rentenversicherung bis 2031 verlängert. Das gewährleistet, dass das Rentenniveau bis 2031 nicht unter 48 Prozent fällt. Rund die Hälfte aller Seniorinnen und Senioren haben im Alter nur Einkommen aus der gesetzlichen Rentenversicherung. Im Osten betrifft es sogar Dreiviertel aller Rentnerinnen und Rentner. Mit der Stabilisierung des Rentenniveaus sichern wir ihre Rente ab. Kinder sind nicht nur eine Bereicherung, ihre Erziehung ist Arbeit und ihr gesellschaftlicher Beitrag immens. Deshalb werden Erziehungszeiten nun vollumfänglich für bis zu drei Jahre für jedes Kind anerkannt - unabhängig vom Geburtsjahr des Kindes. Von der Verbesserung der \"Mütterrente\" profitieren rund 10 Millionen Menschen, vor allem Frauen, die aufgrund fehlender Betreuungsangebote ihre beruflichen Tätigkeiten oft unterbrechen mussten bzw. müssen. Die Höhe der Rente folgt grundsätzlich der Entwicklung von Löhnen und Gehältern. Die Rentenanpassungsformel enthält jedoch auch sogenannte Dämpfungsfaktoren, durch die die Renten auf lange Sicht geringer steigen als die Löhne und Gehälter. Um eine Entkoppelung der Renten von den Löhnen und Gehältern zu verhindern, gilt seit 2019 die sogenannte Haltelinie, die dafür sorgt, dass das Rentenniveau nicht unter 48 Prozent fällt. Nach geltendem Recht würde diese Haltelinie jedoch Ende 2025 auslaufen. Mit dem Rentenpaket 2025 wird die Geltung der Haltelinie bis 2031 verlängert. Ansonsten würde das Rentenniveau dann bis 2031 um rund einen Prozentpunkt sinken – bei einer Monatsrente von beispielsweise 1.500 Euro wären das rund 35 Euro weniger im Monat. Das sogenannte Rentenniveau wird im Gesetz als „Sicherungsniveau vor Steuern“ bezeichnet und ist eine standardisierte Kenngröße, welche die Entwicklung des Leistungsniveaus der gesetzlichen Rentenversicherung im Zeitablauf abbildet. Dieses Niveau ist der Verhältniswert aus der verfügbaren Standardrente und dem verfügbaren Durchschnittsentgelt. Die zu zahlenden Sozialbeiträge auf die Rente und den Lohn werden dabei abgezogen. Die sogenannte Standardrente entspricht einer Rente nach 45 Jahren Beitragszahlung mit Durchschnittsverdienst. Vereinfacht ausgedrückt wird mit dem Rentenniveau gezeigt, wie sich die Renten im Zeitablauf im Verhältnis zu den Löhnen entwickeln. Ein Rentenniveau von 48 Prozent stellt jedoch nicht – wie oft irrtümlich angenommen – auf das letzte Gehalt vor dem Renteneintritt ab."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Rentenreform-2025/rentenreform-2025.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:16.871539+00:00","lastSeen":"2026-03-15T17:52:16.871539+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Rentenreform-2025/rentenreform-2025.html","crawledAt":"2026-03-15T17:52:16.871539Z","crawlId":"contacts-seeded-1773597136","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"301fdf06393d995cb9f96ea7c26e3ad0192c27c55e1ae0af98e1843d9602a4d4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:16.871539+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9fcc7d9d-5b4c-419a-92cb-550f87e793d7', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/Fragen-zur-zusaetzlichen-Altersvorsorge/fragen-zur-zusaetzlichen-altersvorsorge.html', 'active', NULL, '2026-03-15T17:52:18.069782+00:00', '{"id":"9fcc7d9d-5b4c-419a-92cb-550f87e793d7","title":"Fragen und Antworten zur Zusätzlichen Altersvorsorge","summary":{"de":"Antworten auf häufig gestellte Fragen zur Zusätzlichen Altersvorsorge finden Sie hier."},"content":{"de":"Was hat sich bei der betrieblichen Altersversorgung durch das Betriebsrentenstärkungsgesetz geändert? Durch das am 1. Januar 2018 in Kraft getretene Betriebsrentenstärkungsgesetz soll eine weitere Verbreitung von Betriebsrenten erreicht werden, insbesondere in kleinen Unternehmen und bei Geringverdienenden. Dazu wurden die gesetzlichen Rahmen- und Förderbedingungen verbessert: Die Rolle der Tarifparteien bei der Organisation der betrieblichen Altersversorgung wurde gestärkt. Gewerkschaften und Arbeitgeberverbände verfügen über neue Instrumente, um passgenaue und kostengünstige Betriebsrentenmodelle zu installieren (sogenannte \"Sozialpartnermodell Betriebsrente\"). Sofern für die Betriebsrente die Entgeltumwandlung genutzt wird, muss der Arbeitgeber spätestens ab 2022 grundsätzlich einen Arbeitgeberzuschuss von 15 Prozent des umgewandelten Gehalts zusätzlich an die Versorgungseinrichtung abführen. Steuerfreie Zahlungen an Einrichtungen der betrieblichen Altersversorgung wurden ausgeweitet. Seit 2018 sind Beiträge, die zur betrieblichen Altersvorsorge in eine Pensionskasse, einen Pensionsfonds oder eine Direktversicherung investiert werden, bis zu einer Grenze von acht Prozent der Beitragsbemessungsgrenze in der gesetzlichen Rentenversicherung einkommensteuerfrei (also in 2021 bis zu 568 Euro monatlich) und bis zu einer Grenze von vier Prozent (284 Euro monatlich) sozialversicherungsfrei. Das bedeutet zum Beispiel, dass bis zu diesen Grenzen umgewandeltes Arbeitsentgelt \"brutto wie netto\" in die Betriebsrente fließen kann. Die später ausgezahlten Betriebsrenten müssen dann allerdings versteuert werden. Sie unterliegen dann auch der Beitragspflicht in der gesetzlichen Kranken- und Pflegeversicherung, wobei es für Krankenversicherungsbeiträge von Pflichtversicherten ab 2020 eine Freibetragsregelung gibt. Im Steuerrecht wurde außerdem ein neues Fördermodell für Beschäftigte mit niedrigem Einkommen eingeführt. Zahlt der Arbeitgeber für Beschäftigte mit einem monatlichen Bruttoeinkommen von max. 2.575 Euro zum Beispiel jährlich 960 Euro in eine betriebliche Altersversorgung ein, werden dem Arbeitgeber davon 288 Euro vom Staat erstattet."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/Fragen-zur-zusaetzlichen-Altersvorsorge/fragen-zur-zusaetzlichen-altersvorsorge.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:18.069782+00:00","lastSeen":"2026-03-15T17:52:18.069782+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/Fragen-zur-zusaetzlichen-Altersvorsorge/fragen-zur-zusaetzlichen-altersvorsorge.html","crawledAt":"2026-03-15T17:52:18.069782Z","crawlId":"contacts-seeded-1773597138","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"c61c270def9564b535455a9d5822a736c19b7384601550d7cfaeb7eb5295dd78"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:18.069782+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('296a082d-15f3-42a1-80bd-bf81a318e7f2', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/Private-Altersvorsorge/private-altersvorsorge.html', 'active', NULL, '2026-03-15T17:52:18.640372+00:00', '{"id":"296a082d-15f3-42a1-80bd-bf81a318e7f2","title":"Private Altersvorsorge","summary":{"de":"Um zusätzlich für das Alter zu sparen oder Geld Gewinn bringend für später anzulegen, gibt es viele Angebote für alle Bedürfnisse und jeden Geldbeutel. Deshalb sollte man sich vor der Entscheidung für eine Form der privaten Vorsorge immer informieren und fachkundig beraten lassen."},"content":{"de":"Seit 2002 fördert der Staat unter bestimmten Bedingungen den Aufbau einer privaten kapitalgedeckten Altersvorsorge. Diese so genannte Riester-Förderung erfolgt auf zwei Wegen: mit finanziellen Zuschüssen (Zulagen) und Steuerersparnissen ( Sonderausgabenabzug). Statistik zu den bestehenden Verträgen der zusätzlichen geförderten privaten Altersvorsorge (Riester-Rente) in Deutschland."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/Private-Altersvorsorge/private-altersvorsorge.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:18.640372+00:00","lastSeen":"2026-03-15T17:52:18.640372+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/Private-Altersvorsorge/private-altersvorsorge.html","crawledAt":"2026-03-15T17:52:18.640372Z","crawlId":"contacts-seeded-1773597138","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"7ed69963520573addffb44c9b6b0d875296e911cb2687e2cd84bde505a2a3aff"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:18.640372+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('26e93b4a-85c9-4b50-87b7-efba05366d5b', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/zusaetzliche-altersvorsorge.html', 'active', NULL, '2026-03-15T17:52:19.192088+00:00', '{"id":"26e93b4a-85c9-4b50-87b7-efba05366d5b","title":"Zusätzliche Altersvorsorge","summary":{"de":"Um zusätzlich für das Alter zu sparen oder Geld Gewinn bringend für später anzulegen, gibt es Angebote für alle Bedürfnisse und jeden Geldbeutel. Doch wer die Wahl hat, hat bekanntlich auch die Qual."},"content":{"de":"Die Publikation ist ein praktischer Ratgeber auf dem Weg zu einem finanziell gesicherten Ruhestand. Checkliste Private Altersvorsorge (nicht barrierefrei) [PDF, 106KB] Checkliste Betriebliche Altersvorsorge [PDF, 16KB] Beratung zur zusätzlichen Altersvorsorge (nicht barrierefrei) [PDF, 74KB]"},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/zusaetzliche-altersvorsorge.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:19.192088+00:00","lastSeen":"2026-03-15T17:52:19.192088+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/Zusaetzliche-Altersvorsorge/zusaetzliche-altersvorsorge.html","crawledAt":"2026-03-15T17:52:19.192088Z","crawlId":"contacts-seeded-1773597139","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"7b0ec5c8c0292ad617af79101b31e4d51893d28788c73f970ae97f6b6ff73ce6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:19.192088+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2e08179a-e986-40a0-b770-4fb5e7480af7', 'contacts', 'https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/rente-und-altersvorsorge.html', 'active', NULL, '2026-03-15T17:52:19.813342+00:00', '{"id":"2e08179a-e986-40a0-b770-4fb5e7480af7","title":"Rente und Altersvorsorge","summary":{"de":"Das Bundesministerium für Arbeit und Soziales schafft die Rahmen­bedingungen für eine solide Alterssicherung für alle Bürgerinnen und Bürger. Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Das Bundesministerium für Arbeit und Soziales schafft die Rahmen­bedingungen für eine solide Alterssicherung für alle Bürgerinnen und Bürger. Zum 1. Juli 2026 steigen die Renten in Deutschland um 4,24 Prozent. Das geht aus aktuellen Daten des Statistischen Bundesamtes und der Deutschen Rentenversicherung Bund hervor. Die Bundesministerin für Arbeit und Soziales, Bärbel Bas, hat heute die Mitglieder der Alterssicherungskommission ernannt. Die Kommission hat unmittelbar darauf mit ihrer Arbeit begonnen. Das Bundeskabinett hat den vom BMAS vorgelegten Einsetzungsbeschluss für eine Alterssicherungskommission gefasst. Um Erwerbstätigkeit im Alter attraktiver zu gestalten, hat das BMAS unter Beteiligung der Sozialpartner den Dialogprozess \"Arbeit & Rente\" ins Leben gerufen."},"url":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/rente-und-altersvorsorge.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:19.813342+00:00","lastSeen":"2026-03-15T17:52:19.813342+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Rente-und-Altersvorsorge/rente-und-altersvorsorge.html","crawledAt":"2026-03-15T17:52:19.813342Z","crawlId":"contacts-seeded-1773597139","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"3b759b73a283e03a60974c9da9997813766930e6baacaadc0c563a2dd2efd354"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:19.813342+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f71fd721-7ea6-4271-9e3b-43b93b79e139', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Entschaedigte-nach-dem-alten-SER/entschaedigte-nach-dem-alten-ser.html', 'active', NULL, '2026-03-15T17:52:20.411742+00:00', '{"id":"f71fd721-7ea6-4271-9e3b-43b93b79e139","title":"BMAS - Entschädigte nach dem alten SER","summary":{"de":"Informationen zur Sozialen Entschädigung bis zum 31. Dezember 2023."},"content":{"de":"Für Personen, die bereits vor dem 1. Januar 2024 Leistungen nach dem bisherigen Recht (nach dem BVG bzw. den hierauf verweisenden Gesetzen, etwas dem OEG ) erhalten haben, besteht ein Wahlrecht. Sie können also wählen, ob sie in das neue Recht wechseln oder Leistungen im Rahmen des sogenannten Besitzstandsschutzes, das auf dem alten Recht aufbaut, weiter beziehen möchten (siehe aber nachfolgend \"Krankenbehandlung/Absicherung gegen Krankheit\"). Personen, die bis zum 31. Dezember 2023 Leistungen nach dem alten Recht beziehen oder einen entsprechenden Antrag auf diese Leistungen gestellt haben, erhalten damit weiterhin qualitativ hochwertige Versorgungsleistungen. Hinweis: Löschungsbewilligungen zu Grundbucheinträgen zählen zur Gesetzesdurchführung. Diese obliegt im Bereich der Sozialen Entschädigung nach Artikel 83 und 84 des Grundgesetzes den Ländern und deren Behörden."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Entschaedigte-nach-dem-alten-SER/entschaedigte-nach-dem-alten-ser.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:20.411742+00:00","lastSeen":"2026-03-15T17:52:20.411742+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Entschaedigte-nach-dem-alten-SER/entschaedigte-nach-dem-alten-ser.html","crawledAt":"2026-03-15T17:52:20.411742Z","crawlId":"contacts-seeded-1773597140","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"c8af91cb469c3dcc10dd29ad4f37d9cadb8cc734e9a65feecfe0071f401db790"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:20.411742+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('172a8ada-b0c7-4c9e-b25d-47315c2a3796', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Gesetze-und-Verordnungen/gesetze-und-verordnungen.html', 'active', NULL, '2026-03-15T17:52:21.025783+00:00', '{"id":"172a8ada-b0c7-4c9e-b25d-47315c2a3796","title":"Gesetze und Verordnungen","summary":{"de":"Sozialgesetzbuch - Vierzehntes Buch - Soziale Entschädigung (SGB XIV)"},"content":{"de":"Strafrechtliches Rehabilitierungsgesetz (StrRehaG) Verwaltungsrechtliches Rehabilitierungsgesetz (VwRehaG) SGBXIV-Berufsschadensausgleichsverordnung – SGBXIVBSchAV Verordnung zum Einkommen und Vermögen im SGB XIV — EVV Verordnung zur Anpassung der Entschädigungszahlungen nach dem Vierzehnten Buch Sozialgesetzbuch zum 1. Juli 2025 5. Verordnung zur Änderung der Versorgungsmedizin-Verordnung vom 11. Oktober 2012 (Bundesgesetzblatt) [PDF, 102KB]"},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Gesetze-und-Verordnungen/gesetze-und-verordnungen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:21.025783+00:00","lastSeen":"2026-03-15T17:52:21.025783+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Gesetze-und-Verordnungen/gesetze-und-verordnungen.html","crawledAt":"2026-03-15T17:52:21.025783Z","crawlId":"contacts-seeded-1773597141","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"32fd32e98a152d10c16000b1cc1f906ffe5feeab742d1792e73d679ea6e14926"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:21.025783+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a22cadd6-489c-410e-8a3e-5618b6e5808f', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/Krankenbehandlung/krankenbehandlung.html', 'active', NULL, '2026-03-15T17:52:21.572017+00:00', '{"id":"a22cadd6-489c-410e-8a3e-5618b6e5808f","title":"Krankenbehandlung","summary":{"de":"Geschädigte haben für anerkannte Schädigungsfolgen Anspruch auf Krankenbehandlung der Sozialen Entschädigung."},"content":{"de":"Versorgung mit Arznei-, Verband-, Heil- und Hilfsmitteln Für diese Leistungen sind grundsätzlich die Vorschriften der gesetzlichen Krankenversicherung maßgeblich. Dies gilt unabhängig davon, ob die geschädigte Person gesetzlich krankenversichert ist oder nicht. Für Geschädigte, die Mitglied einer Krankenkasse oder dort familienversichert sind, erbringt diese Krankenkasse die Leistungen. Die übrigen Geschädigten wählen eine Krankenkasse. Ausnahme: Die Hilfsmittelversorgung richtet sich nach dem Recht der gesetzlichen Unfallversicherung und wird von der jeweiligen Unfallkasse des Landes erbracht. Wegen der besonderen Verantwortung des Staates gegenüber den Geschädigten gibt es abweichend vom Recht der gesetzlichen Krankenversicherung einige Besserstellungen, wie zum Beispiel die Zuzahlungsfreiheit bei Medikamenten oder die ergänzenden Leistungen. Neben medizinischen Leistungen im eigentlichen Sinne umfasst die Krankenbehandlung der Sozialen Entschädigung noch weitere Leistungen wie beispielsweise Entrichtung von Sozialversicherungsbeiträgen durch die zuständige Verwaltungsbehörde ( z.B. zur Arbeitsförderung, zur gesetzlichen Rentenversicherung) während des Bezugs von Krankengeld der Sozialen Entschädigung."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/Krankenbehandlung/krankenbehandlung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:21.572017+00:00","lastSeen":"2026-03-15T17:52:21.572017+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/Krankenbehandlung/krankenbehandlung.html","crawledAt":"2026-03-15T17:52:21.572017Z","crawlId":"contacts-seeded-1773597141","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"baeff9c434bf27bf541dba674e1507fe03a7b910bb64d31ea4699db8c0f1f50e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:21.572017+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1991ea5f-7346-4b82-b1af-893e2687ebf1', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/neues-soziales-entschaedigungsrecht.html', 'active', NULL, '2026-03-15T17:52:22.111839+00:00', '{"id":"1991ea5f-7346-4b82-b1af-893e2687ebf1","title":"BMAS - Neues Soziales Entschädigungsrecht","summary":{"de":"Mit dem SGB XIV hat sich der Gesetzgeber von dem System des Bundesversorgungsgesetzes gelöst, das noch sehr auf die Bedürfnisse der Kriegsopfer zugeschnitten und in seinen Leistungen nicht mehr zeitgemäß war. Leistungen an Opfer werden zukünftig schneller, zielgenauer und stärker an den Bedarfen der Berechtigten orientiert erbracht."},"content":{"de":"Voraussetzung für Leistungen nach dem SGB XIV ist ein schädigendes Ereignis (z.B. Raubüberfall), das zu einem gesundheitlichen Schaden (z.B. Beinbruch) führt, oder gesundheitliche (Gehbehinderung) und/oder wirtschaftliche (z.B. Einkommenseinbuße) Folgen verursacht. Wie definiert das neue Soziale Entschädigungsrecht Gewalt? Wer hat als Opfer einer Gewalttat Anspruch auf Entschädigungs­leistungen? Was sind die wichtigsten Änderungen des neuen Sozialen Entschädigungsrechts? In diesem Video erfahren Sie mehr zu diesem Thema."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/neues-soziales-entschaedigungsrecht.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:22.111839+00:00","lastSeen":"2026-03-15T17:52:22.111839+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Neues-Soziales-Entschaedigungsrecht/neues-soziales-entschaedigungsrecht.html","crawledAt":"2026-03-15T17:52:22.111839Z","crawlId":"contacts-seeded-1773597142","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"6a9f452617dfd17a1a584158e274648d9880d92f842704fdff57b439cc53f38d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:22.111839+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bd1ce8a7-e13e-40fb-8c13-e58927310030', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Rundschreiben/rundschreiben.html', 'active', NULL, '2026-03-15T17:52:22.590404+00:00', '{"id":"bd1ce8a7-e13e-40fb-8c13-e58927310030","title":"Rundschreiben zur Sozialen Entschädigung","summary":{"de":"Hier finden Sie alle Rundschreiben (chronologisch sortiert)."},"content":{"de":"Durchführung des 14. Buches Sozialgesetzbuch (SGB XIV ) - Klarstellung zum Regelungsgehalt von § 77 Absatz 3 SGB XIV Gewährung der allgemeinen Zustimmung zur Anwendung der Härtefallregelung in § 100 Abs. 3 SGB XIV zur Übernahme der Überführungs- und Bestattungskosten an Personen ohne Wohnsitz oder gewöhnlichen Aufenthalt im Inland. Gemeinsames Rundschreiben des Bundesministeriums für Arbeit und Soziales und des Bundesministeriums für Familie, Senioren, Frauen und Jugend vom 19. Februar 2025 - Vb6-53408/8 - Kostenerstattung zwischen den Trägern der öffentlichen Jugendhilfe ( SGB VIII ) und der Sozialen Entschädigung (SGB XIV ) bei der Leistungserbringung an geschädigte sowie hinterbliebene Kinder und Jugendliche. Durchführung des 14. Buches Sozialgesetzbuch ( SGB XIV ) – \"Erhebliche Vernächlässigung von Kindern\" ( § 14 Abs. 1 Nr. 5 SGB XIV ) Durchführung des 14. Buches Sozialgesetzbuch (SGB XIV ) – Auslegung des § 149 SGB XIV Stellungnahme des BMAS bzgl. der Auslegung des §145 Abs. 3 SGB XIV."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Rundschreiben/rundschreiben.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:22.590404+00:00","lastSeen":"2026-03-15T17:52:22.590404+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Rundschreiben/rundschreiben.html","crawledAt":"2026-03-15T17:52:22.590404Z","crawlId":"contacts-seeded-1773597142","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"c2979ed72869cffc1bdac2f5537aad2be91755fd09d9df0eaa2f431b7a2c0896"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:22.590404+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b00e5c73-6fbe-4c9d-bf4d-c584d62e4a22', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Soziale-Entschaedigung/soziale-entschaedigung.html', 'active', NULL, '2026-03-15T17:52:23.223987+00:00', '{"id":"b00e5c73-6fbe-4c9d-bf4d-c584d62e4a22","title":"Soziale Entschädigung","summary":{"de":"Informationen zur Sozialen Entschädigung"},"content":{"de":"Wer einen gesundheitlichen Schaden erleidet, für dessen Folgen die Gemeinschaft einsteht, hat Anspruch auf Versorgung. Damit sollen besondere Opfer zumindest finanziell abgegolten werden. Opfer von (körperlichen und seelischen) Gewalttaten, aber auch Menschen, die durch eine Schutzimpfung oder eine Maßnahme der Prophylaxe oder Einwirkungen der Weltkriege gesundheitlich geschädigt wurden. Anspruch auf Leistungen haben auch Opfer des SED-Regimes. Art und Umfang der Leistungen richten sich ab dem 1. Januar 2024 nach dem Vierzehnten Buch des Sozialgesetzbuchs (SGB XIV)."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Soziale-Entschaedigung/soziale-entschaedigung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:23.223987+00:00","lastSeen":"2026-03-15T17:52:23.223987+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Soziale-Entschaedigung/soziale-entschaedigung.html","crawledAt":"2026-03-15T17:52:23.224987Z","crawlId":"contacts-seeded-1773597143","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"31987a14aa1ef70de15ff05b01cc70f911fd4c6941ed977784d593b687148f44"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:52:23.224987+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5ac7f4f2-56c7-4931-8539-bb7b549fd0da', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Zahlen-und-Daten/zahlen-und-daten.html', 'active', NULL, '2026-03-15T17:52:23.821042+00:00', '{"id":"5ac7f4f2-56c7-4931-8539-bb7b549fd0da","title":"Zahlen und Daten zur Sozialen Entschädigung","summary":{"de":"Empfängerinnen und Empfänger von Versorgungsleistungen"},"content":{"de":"Empfänger/innen von Versorgungsleistungen der Sozialen Entschädigung im Inland und Ausland [PDF, 86KB] Diese Übersicht zeigt die Anzahl der Empfängerinnen und Empfänger von Versorgungsleistungen der Sozialen Entschädigung im Inland und Ausland mit dem Stand Dezember 2023. Neben den Versorgungsberechtigten nach dem Bundesversorgungsgesetz werden u.a. auch die Leistungsempfängerinnen und -empfänger nach dem Opferentschädigungsgesetz und dem Soldatenversorgungsgesetz aufgelistet. Statistik der Versorgung von Kriegsopfern und gleichgestellten Personen im Ausland Statistik der Versorgung von Kriegsopfern und gleichgestellten Personen im Ausland [PDF, 90KB] Diese Statistik zeigt die Anzahl der Empfängerinnen und Empfänger von Versorgungsleistungen nach dem Sozialen Entschädigungsrecht, die sich im Ausland aufhalten mit dem Stand Dezember 2023. Hierbei wird vorrangig zwischen den einzelnen Aufenthaltsstaaten unterschieden. Diese Statistik wird alle zwei Jahre vom Statistischen Bundesamt veröffentlicht. Sie stellt die Anzahl der Empfängerinnen und Empfänger sowie die Bundesausgaben für die Fürsorgerischen Leistungen der Sozialen Entschädigung (Leistungen der Kriegsopferfürsorge) dar. Die Auflistung enthält u.a. eine Unterteilung in einzelne Leistungsarten. Die aktuelle Statistik wurde mit dem Stand zum 31. Dezember 2020 erstellt."},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Zahlen-und-Daten/zahlen-und-daten.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:23.821042+00:00","lastSeen":"2026-03-15T17:52:23.821042+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/Zahlen-und-Daten/zahlen-und-daten.html","crawledAt":"2026-03-15T17:52:23.821042Z","crawlId":"contacts-seeded-1773597143","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"d1eec7b904527ce88b6ce0c7c6d5c914d6975c69bbd82950a813b1a6aa8ad893"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:23.821042+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('608ec052-78a8-4653-9246-03c936f50993', 'contacts', 'https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/soziale-entschaedigung.html', 'active', NULL, '2026-03-15T17:52:24.394630+00:00', '{"id":"608ec052-78a8-4653-9246-03c936f50993","title":"Soziale Entschädigung","summary":{"de":"Wer einen gesundheitlichen Schaden erleidet, für dessen Folgen die Gemeinschaft einsteht, hat Anspruch auf Versorgung. Hier finden Sie aktuelle Infos und Neuigkeiten zum Thema Soziale Entschädigung."},"content":{"de":"Wer einen gesundheitlichen Schaden erleidet, für dessen Folgen die Gemeinschaft einsteht, hat Anspruch auf Versorgung. Damit sollen beispielsweise besondere Opfer zumindest finanziell abgegolten werden. Am 12. und 13. November 2025 fand die Tagung \"Großschadensereignisse aus Sicht des SGB XIV \" statt. Ergebnisse der Tagung sind, dass die Leistungen des SGB XIV bei unterstützenden Personen bekannter gemacht werden sollen und Betroffene von Bürokratie und Mehrfachbefragungen entlastet werden. Das Treffen zwischen der VN-Sonderberichterstatterin zu Kinderhandel und Kinderprostitution, Mama Fatima Singhateh, und Staatssekretär Dr. Rolf Schmachtenberg fand am 18. Oktober 2024 im Rahmen ihres offiziellen Länderbesuchs statt. Nach über sechs Jahren beendet die Einrichtung von Bund, Ländern und Kirchen ihre wichtige Arbeit. Gesetze und Verordnungen zum Sozialen Entschädigungsrecht Adressen und Internetseiten der Landesversorgungsbehörden [PDF, 255KB]"},"url":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/soziale-entschaedigung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:24.394630+00:00","lastSeen":"2026-03-15T17:52:24.394630+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Soziale-Entschaedigung/soziale-entschaedigung.html","crawledAt":"2026-03-15T17:52:24.395633Z","crawlId":"contacts-seeded-1773597144","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"c97cf800bc17c3b0e7a7ff8d6810b7242eb180ee7efe9504b3a09a660a15cfd5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:24.395633+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8d2e17fb-85c6-441a-84d1-b5a55c586a80', 'contacts', 'https://www.bmas.de/DE/Soziales/Sozialversicherung/Kuenstlersozialversicherung/kuenstlersozialversicherung.html', 'active', NULL, '2026-03-15T17:52:25.516158+00:00', '{"id":"8d2e17fb-85c6-441a-84d1-b5a55c586a80","title":"BMAS - Künstlersozialversicherung","summary":{"de":"Über die Künstlersozialversicherung erhalten selbständige Künstler und Publizisten den Schutz der gesetzlichen Renten- und Krankenversicherung sowie der sozialen Pflegeversicherung."},"content":{"de":"Über die Künstlersozialversicherung erhalten selbständige Künstler und Publizisten den Schutz der gesetzlichen Renten- und Krankenversicherung sowie der sozialen Pflegeversicherung."},"url":"https://www.bmas.de/DE/Soziales/Sozialversicherung/Kuenstlersozialversicherung/kuenstlersozialversicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:25.516158+00:00","lastSeen":"2026-03-15T17:52:25.516158+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialversicherung/Kuenstlersozialversicherung/kuenstlersozialversicherung.html","crawledAt":"2026-03-15T17:52:25.516158Z","crawlId":"contacts-seeded-1773597145","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"e60c421c3a8e3c665d5bdc1c985e9aa49e06015e26f97b2063598fc51e83f310"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:25.516158+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4d7c5471-5746-46c2-86a1-44bec2bda139', 'contacts', 'https://www.bmas.de/DE/Soziales/Sozialversicherung/Sozialversicherungspflichtige-Beschaeftigung/sozialversicherungspflichtige-beschaeftigung.html', 'active', NULL, '2026-03-15T17:52:26.070144+00:00', '{"id":"4d7c5471-5746-46c2-86a1-44bec2bda139","title":"Sozialversicherungspflichtige Beschäftigung","summary":{"de":"Der Begriff der Beschäftigung hat zentrale Bedeutung für das Sozialversicherungsrecht. Die Vorschriften über die Versicherungspflicht knüpfen an die Beschäftigung an. Beschäftigte sind nach Maßgabe der besonderen Vorschriften in den Sozialgesetzbüchern versichert. Das heißt, sie sind einerseits verpflichtet, Sozialversicherungsbeiträge zu entrichten und kommen andererseits in den Genuss der Leistungen der Sozialversicherung."},"content":{"de":"§ 7 des Vierten Buches Sozialgesetzbuch ( SGB IV ) beschreibt Beschäftigung als nichtselbständige Arbeit, insbesondere in einem Arbeitsverhältnis. Ein Beschäftigungsverhältnis liegt damit jedenfalls dann vor, wenn ein Arbeitsverhältnis besteht. Als Anhaltspunkte für eine Beschäftigung nennt das Gesetz eine Tätigkeit nach Weisungen und eine Eingliederung in die Arbeitsorganisation des Weisungsgebers. Ob es sich bei einer Erwerbstätigkeit um eine Beschäftigung oder um eine selbständige Tätigkeit handelt, ist im Einzelfall anhand des Gesamtbildes der Arbeitsleistung zu beurteilen. Das Bundessozialgericht hat zur Abgrenzung des Erwerbsstatus zahlreiche Indizien entwickelt, die für oder gegen eine Beschäftigung sprechen. Ob jemand beschäftigt oder selbständig tätig ist, hängt davon ab, welche Merkmale in der Gesamtbetrachtung überwiegen. Für den Fall, dass die tatsächlichen Verhältnisse von den Vereinbarungen abweichen, kommt es darauf an, wie das Vertragsverhältnis in der Praxis umgesetzt wird. Für die Auslegung und die Entscheidung im Einzelfall ist der zuständige Sozialversicherungsträger und im Streitfall das Sozialgericht zuständig. Damit sich die Beteiligten eines Auftragsverhältnisses möglichst frühzeitig Klarheit über den Rechtscharakter ihrer Vertragsbeziehung verschaffen können, steht ihnen das Statusfeststellungsverfahren in der Sozialversicherung nach § 7a SGB IV zur Verfügung. Beschäftigung liegt auch für den Zeitraum vor, in dem ein Wertguthaben (auch Sabbatical, Langzeitkonto, Lebensarbeitszeitkonto oder im Steuerrecht Zeitwertkonto genannt) in Anspruch genommen wird. Wertguthaben ermöglichen Beschäftigten längerfristige sozialversicherte Freistellungen von der Arbeit: hierfür zahlen sie Bestandteile ihres Arbeitsentgelts oder auch Zeitanteile in das Wertguthaben ein und erhalten daraus während ihrer längerfristigen Freistellung ihr Arbeitsentgelt. Diese bezahlte und sozialversicherungsrechtlich geschützte Auszeit kann flexibel eingesetzt werden, etwa für Weiterbildung, die Kindererziehung, die Pflege Angehöriger oder ein Sabbatical."},"url":"https://www.bmas.de/DE/Soziales/Sozialversicherung/Sozialversicherungspflichtige-Beschaeftigung/sozialversicherungspflichtige-beschaeftigung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:26.070144+00:00","lastSeen":"2026-03-15T17:52:26.070144+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialversicherung/Sozialversicherungspflichtige-Beschaeftigung/sozialversicherungspflichtige-beschaeftigung.html","crawledAt":"2026-03-15T17:52:26.070144Z","crawlId":"contacts-seeded-1773597146","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"fd04003e50f46790253991dffba23c9d0bb9883f0eaba6ed7d9f14273f3cd5bf"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:26.070144+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('59d7e5db-26dc-454c-849f-eb432cd24d30', 'contacts', 'https://www.bmas.de/DE/Soziales/Sozialversicherung/Sozialversicherungswahlen/sozialversicherungswahlen.html', 'active', NULL, '2026-03-15T17:52:26.706204+00:00', '{"id":"59d7e5db-26dc-454c-849f-eb432cd24d30","title":"Sozialversicherungswahlen","summary":{"de":"Die Sozialwahlen bilden das Kernstück der Demokratie in der Sozialversicherung."},"content":{"de":"Am 23. Juni 2023 fand die Pressekonferenz des Bundewahlbeauftragten für die Sozialversicherungswahlen im Presseraum des BMAS statt, in der er die Ergebnisse der Sozialwahlen 2023 vorgestellt hat. Die Aufzeichnung der Pressekonferenz und die Ergebnisse der Sozialwahlen findet man unter www.bundessozialwahlbeauftragter.de. Ende September fand die Übergabe des Schlussberichts der Sozialwahlen 2023 im BMAS statt. Die Bundeswahlbeauftragten stellten die Ergebnisse vor. Am 23. November 2023 fand die Anhörung der beiden Bundes­wahl­beauf­trag­ten für die Sozial­versicher­ungswahlen zur Zukunft der Sozialen Selbstverwaltung und der Sozialwahlen statt. Sehen Sie die Aufzeichnung der Veranstaltung online."},"url":"https://www.bmas.de/DE/Soziales/Sozialversicherung/Sozialversicherungswahlen/sozialversicherungswahlen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:26.706204+00:00","lastSeen":"2026-03-15T17:52:26.706204+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialversicherung/Sozialversicherungswahlen/sozialversicherungswahlen.html","crawledAt":"2026-03-15T17:52:26.706794Z","crawlId":"contacts-seeded-1773597146","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"12718a15bc69fe9e12ad34ec6068f88067e5657741fa9702e69e2097c92086bb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:26.706794+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('49c2a0a8-93a0-4b19-ba81-b6f8dc1e54e1', 'contacts', 'https://www.bmas.de/DE/Soziales/Sozialversicherung/sozialversicherung.html', 'active', NULL, '2026-03-15T17:52:27.261678+00:00', '{"id":"49c2a0a8-93a0-4b19-ba81-b6f8dc1e54e1","title":"Sozialversicherung","summary":{"de":"Die Sozialversicherung ist zentrales Element des Sozialstaats und sichert einen Großteil der Bevölkerung gegen Existenzgefährdungen ab. Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Die Sozialversicherung ist zentrales Element des Sozialstaats und sichert einen Großteil der Bevölkerung gegen Existenzgefährdungen ab. Die Deutsche Rentenversicherung Bund berichtet über die Erfahrungen mit dem zum 1. April 2022 reformierten Verfahren der sozialversicherungsrechtlichen Statusfeststellung. Das Kabinett hat am 8. Oktober 2025 die Verordnung über die Sozialversicherungsrechengrößen 2026 beschlossen. Mit der Verordnung werden die maßgeblichen Rechengrößen der Sozialversicherung u. a. auch die Beitragsbemessungsgrenzen aktualisiert. Mit der Verordnung werden die maßgeblichen Rechengrößen der Sozialversicherung für das Jahr 2026 nach gesetzlichen Regelungen neu bestimmt, die der Bundesregierung kein Ermessen einräumen."},"url":"https://www.bmas.de/DE/Soziales/Sozialversicherung/sozialversicherung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:27.261678+00:00","lastSeen":"2026-03-15T17:52:27.261678+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Sozialversicherung/sozialversicherung.html","crawledAt":"2026-03-15T17:52:27.261678Z","crawlId":"contacts-seeded-1773597147","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"e754b8f2325f498c8eeffdb792b439a96ffdfb9ee26397863a4c0ac0e3964c9c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:27.261678+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('31f84ece-5fde-4cb8-9ead-94de21f6cd5c', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/bundesinitiative-barrierefreiheit.html', 'active', NULL, '2026-03-15T17:52:27.932505+00:00', '{"id":"31f84ece-5fde-4cb8-9ead-94de21f6cd5c","title":"Bundesinitiative Barrierefreiheit","summary":{"de":"Unter der Federführung des Bundesministeriums für Arbeit und Soziales werden zahlreiche Maßnahmen umgesetzt, um Barrieren im öffentlichen wie im privaten Bereich abzubauen."},"content":{"de":"Unter der Federführung des Bundesministeriums für Arbeit und Soziales werden zahlreiche Maßnahmen umgesetzt, um Barrieren im öffentlichen wie im privaten Bereich abzubauen."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/bundesinitiative-barrierefreiheit.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:27.932505+00:00","lastSeen":"2026-03-15T17:52:27.932505+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/bundesinitiative-barrierefreiheit.html","crawledAt":"2026-03-15T17:52:27.932505Z","crawlId":"contacts-seeded-1773597147","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"3580a86e50c2232bf482a14b60f023223d4866e3198dfc6ad30c6d6c930bb504"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:27.932505+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4f65e850-dc9e-4bcf-9211-5b017d001af0', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/deutschland-wird-barrierefrei.html', 'active', NULL, '2026-03-15T17:52:29.266745+00:00', '{"id":"4f65e850-dc9e-4bcf-9211-5b017d001af0","title":"Deutschland wird barrierefrei","summary":{"de":"Die Kampagne lief November 2025 deutschlandweit vor allem als Werbeunterbrechnung auf Streamingportalen. Wir haben sie gemeinsam mit Menschen mit Behinderungen entwickelt. Sie haben Inhalte mitgestaltet, Entscheidungen getroffen und stehen selbst vor der Kamera. So entsteht ein authentischer Blick aus eigener Perspektive, nicht über sie hinweg."},"content":{"de":"Eine Kampagne der Bundesinitiative Barrierefreiheit Unter dem Motto „Deutschland wird barrierefrei. Mit dir.“ machen wir sichtbar, wie leicht Barrieren fallen können – durch kleine Gesten, die Teilhabe ermöglichen. Und weil Barrierefreiheit dort entsteht, wo Menschen miteinander ins Gespräch kommen und Nähe entsteht, duzen wir im Rahmen der Kampagne. Wir wollen zeigen, wie leicht Zugänglichkeit entstehen kann, wenn alle mitdenken. Jede Rücksichtnahme zählt – und macht Teilhabe selbstverständlich. Barrieren sind oft unsichtbar, prägen aber den Alltag vieler Menschen mit und ohne Behinderungen. Unsere Spots zeigen Situationen, in denen Teilhabe unnötig schwer wird. Wer aufmerksam ist, kann viel verändern: Wege freihalten, Rücksicht auf Lautstärke nehmen, Untertitel einschalten, Inhalte klar und verständlich weitergeben oder beim Einkaufen die Stille Stunde respektieren. Solche kleinen Gesten machen das Umfeld offener und stressfreier – für alle. Wir haben Ideen vorbereitet, mit denen du mehr Barrierefreiheit ins Leben bringst. Gemeinsam arbeiten wir daran, Barrieren Schritt für Schritt abzubauen – für ein inklusives Miteinander. Wir kommunizieren nicht alle gleich. Deswegen haben wir die wichtigsten Informationen zum Absender und über die Kampagne in zwei weiteren Sprachen aufbereitet:"},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/deutschland-wird-barrierefrei.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:29.266745+00:00","lastSeen":"2026-03-15T17:52:29.266745+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/deutschland-wird-barrierefrei.html","crawledAt":"2026-03-15T17:52:29.266745Z","crawlId":"contacts-seeded-1773597149","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"6060445ed77183e436a54a7ee746ebd458715cae138a16f6110cca07cfb86185"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:29.266745+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('357620f7-b2e0-4386-a98a-e8d01381edc1', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/ueber-die-bundesinitiative-barrierefreiheit.html', 'active', NULL, '2026-03-15T17:52:30.049090+00:00', '{"id":"357620f7-b2e0-4386-a98a-e8d01381edc1","title":"Über die Bundesinitiative Barrierefreiheit","summary":{"de":"Wir wollen konkrete Fortschritte beim Abbau von Barrieren erzielen – eine gemeinsame Aufgabe aller Ressorts unter Federführung des Bundesministeriums für Arbeit und Soziales."},"content":{"de":"Wie genau arbeitet die Bundesinitiative Barrierefreiheit? Wir zeigen dir, wie du mit einfachen Ideen mehr Barrierefreiheit in den Alltag bringst – für ein inklusives Miteinander, das alle einschließt. Deutschland wird barrierefrei – das Ziel ist hoch gesteckt, aber notwendig. In Deutschland leben rund 13 Millionen Menschen mit Beeinträchtigungen, die durch vielfältige Barrieren an einer unabhängigen und gleichberechtigten Lebensgestaltung gehindert werden. Sie wollen zur Arbeit fahren, frei ihren behandelnden Arzt oder ihre Ärztin aussuchen können, das Internet nutzen oder auch einfach ins Museum oder ins Kino gehen. Von einem barrierefreien Nah- und Fernverkehr, barrierefreien ärztlichen Praxen und barrierefreien Gebäuden insgesamt profitieren auch Freund*innen, Angehörige und Kolleg*innen wie auch ältere Menschen, Menschen mit geringen Deutschkenntnissen und Familien mit Kindern. Barrierefreiheit in Deutschland entscheidend voranzubringen, ist daher ein zentrales und langfristiges Anliegen der Bundesregierung. Unter dem Dach der Initiative werden zahlreiche Maßnahmen umgesetzt, um Barrieren im öffentlichen wie im privaten Bereich abzubauen. Im Mittelpunkt stehen gesetzgeberische Maßnahmen und vielfältige Schritte für eine barrierefreie Mobilität, ein barrierefreies Gesundheitswesen, barrierefreies Wohnen und Bauen sowie barrierefreie Digitalisierung. Zudem soll das Thema Barrierefreiheit durch Öffentlichkeitsarbeit und Sensibilisierung breit in der Gesellschaft verankert werden. Barrierefreiheit ist eine gesamtgesellschaftliche Aufgabe – deshalb arbeiten alle Ressorts im Rahmen der Bundesinitiative eng zusammen, um Maßnahmen für mehr Barrierefreiheit und Inklusion konsequent und koordiniert voranzubringen."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/ueber-die-bundesinitiative-barrierefreiheit.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:30.049090+00:00","lastSeen":"2026-03-15T17:52:30.049090+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Bundesinitiative-Barrierefreiheit/ueber-die-bundesinitiative-barrierefreiheit.html","crawledAt":"2026-03-15T17:52:30.049090Z","crawlId":"contacts-seeded-1773597150","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"bcde6661dafa5cbd1027d09663cbf484624073d4a70dcb0d21da5f898aa909d3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:30.049090+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e97580ef-c0b0-426a-97ab-3848e21f9ab8', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Leichte-Sprache-anwenden/leichte-sprache-anwenden.html', 'active', NULL, '2026-03-15T17:52:30.547795+00:00', '{"id":"e97580ef-c0b0-426a-97ab-3848e21f9ab8","title":"Leichte Sprache anwenden","summary":{"de":"Ratgeber und Icon-Download zur Leichten Sprache"},"content":{"de":"Damit alle Menschen am gesellschaftlichen und politischen Leben mitwirken können, müssen Informationen für alle verständlich sein – egal ob gesprochen oder geschrieben. Leichte Sprache wurde speziell für Menschen mit Behinderungen entwickelt, zum Beispiel für Menschen mit Lernschwierigkeiten. Sie folgt klaren Regeln und ist stärker vereinfacht als Einfache Sprache und Alltagssprache. Auch Menschen mit geringen Deutschkenntnissen oder Lese- und Rechtschreib­schwierigkeiten greifen oft auf Leichte Sprache zurück – weil sie hilft, Inhalte schneller und leichter zu erfassen. Die folgenden Informationen richten sich an alle, die sich mit Leichter Sprache beschäftigen möchten – insbesondere an diejenigen, die selbst in Leichter Sprache kommunizieren oder entsprechende Inhalte erstellen wollen. Für die Ratgeber wurden Personen interviewt, die sich täglich mit der Leichten Sprache auseinandersetzen. Die einzelnen Interviews sind über Links und QR-Codes in den Publikationen abrufbar. Hier haben wir noch einmal die Interviews gesammelt. Mit einigen Videos sind wir noch in der Postproduktion. Wir versuchen, auch diese schnellstmöglich online zu stellen. Dörte Hinrichs, Mitarbeiterin im Sprachendienst des Bundesministeriums für Arbeit und Soziales Ralf Beekveldt, Gründer des Verlags \"Spaß am Lesen\""},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Leichte-Sprache-anwenden/leichte-sprache-anwenden.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:30.547795+00:00","lastSeen":"2026-03-15T17:52:30.547795+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Leichte-Sprache-anwenden/leichte-sprache-anwenden.html","crawledAt":"2026-03-15T17:52:30.548816Z","crawlId":"contacts-seeded-1773597150","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"64b0a4d415307dd2641ef07d8b1d2056e3eb393028e3a0e6baa5fb03af9c8621"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:52:30.548816+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0ce2eca4-fafc-4a38-8f89-9dd5d3398667', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Assistenzhunde/assistenzhunde.html', 'active', NULL, '2026-03-15T17:52:31.107020+00:00', '{"id":"0ce2eca4-fafc-4a38-8f89-9dd5d3398667","title":"Assistenzhunde","summary":{"de":"Assistenzhunde sind speziell ausgebildete Hunde, die Aufgaben erlernen, um Menschen mit einer Behinderung im Alltag zu helfen."},"content":{"de":"Februar 2026: Übergangsregelungen für Assistenzhunde vom Kabinett beschlossen Am 11. Februar 2026 wurde der Gesetzentwurf zur Änderung des Behindertengleichstellungsgesetzes (BGG) und damit auch die Übergangslösungen zu den Assistenzhunden im Kabinett beschlossen. Der Entwurf sieht vor, dass das Erfordernis einer Zulassung durch eine fachliche Stelle nach § 12i Satz 1 BGG für Ausbildungsstätten übergangsweise entfällt bis eine neue fachliche Stelle nach § 12j Absatz 1 BGG ihre Tätigkeit über zwölf Monate ausgeübt hat. Damit sollen die akkreditierten Prüfer (derzeit die Zertifizierung Bau GmbH (ZertBau) und die Gesellschaft zur Qualitätssicherung von Mensch Assistenzhund Gemeinschaften eGbR (GMAG)) vorübergehend Prüfungen und Zertifizierungen von Mensch-Assistenzhund-Gemeinschaften durchführen können, die ihre Ausbildung nach dem 1. Juli 2023 begonnen haben, selbst wenn ihre Ausbildung in einer nicht zugelassenen Ausbildungsstätte stattgefunden hat. Voraussetzung ist, dass sie die Anforderungen nach § 12i Satz 3 Nummer 1 und 2 sowie des Abschnitts 3 der Assistenzhundeverordnung erfüllen. Ferner sieht der Entwurf vor, dass Mensch-Assistenzhund-Gemeinschaften, die vor dem 1. Juli 2023 mit ihrer Ausbildung begonnen haben, bis zu 6 Monate nach Verkündung des Gesetzes ihre Prüfung abschließen können. Für sie bleibt die bereits veröffentlichte Prüferliste bis auf Weiteres gültig. Die Frist für die Anerkennung durch die Länderstellen soll bis zum 31. Dezember 2027 verlängert werden. Nächste Schritte: Der Gesetzentwurf wird nun im Bundestag beraten. Die o.g. Regelungen sollen am Tag nach Verkündung des Gesetzes in Kraft treten. Nach aktuellem Stand ist mit einem Abschluss des Gesetzgebungsverfahrens im Herbst 2026 zu rechnen. Februar 2025: Umsetzung der AHundV verzögert sich in einigen Bereichen"},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Assistenzhunde/assistenzhunde.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:31.107020+00:00","lastSeen":"2026-03-15T17:52:31.107020+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Assistenzhunde/assistenzhunde.html","crawledAt":"2026-03-15T17:52:31.107020Z","crawlId":"contacts-seeded-1773597151","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"2bcea03497ac40fab54a937ee71e3751e05df6e98606ff2314eafcc4ab198ec5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:31.107020+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('85bc8617-ad03-4f71-afe3-3cf46e2c52dc', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Behindertenrechtskonvention-der-Vereinten-Nationen/behindertenrechtskonvention-der-vereinten-nationen.html', 'active', NULL, '2026-03-15T17:52:31.691502+00:00', '{"id":"85bc8617-ad03-4f71-afe3-3cf46e2c52dc","title":"Behindertenrechtskonvention der Vereinten Nationen","summary":{"de":"Am 3. Mai 2008 trat das Übereinkommen der Vereinten Nationen über die Rechte von Menschen mit Behinderungen (UN-Behindertenrechtskonvention - UN-BRK) in Kraft."},"content":{"de":"Das Übereinkommen über Schutz der Rechte von Menschen mit Behinderungen Ziel des Übereinkommens sowie des dazugehörigen Fakultativprotokolls ist es, den gleichberechtigten Genuss der Menschenrechte und Grundfreiheiten durch Menschen mit Behinderungen zu fördern, zu schützen und zu gewährleisten. Dem Großteil der weltweit rund 1 Milliarde Menschen mit Behinderungen hat die UN-Behindertenrechtskonvention (UN-BKR) erstmalig einen Zugang zu verbrieften Rechten verschafft. Die Vereinten Nationen schätzen, dass nur etwa 40 Staaten, zumeist Industrienationen, eine nationale behindertenpolitische Gesetzgebung haben. Zwei Drittel Menschen mit Behinderungen leben in Entwicklungsländern. Im Einzelnen konkretisiert die UN- BRK z.B. das Recht auf Zugang zu Bildung, das Recht auf Zugang zur Arbeitswelt oder das Recht auf Teilhabe am kulturellen Leben. Dabei wird der abstrakte Teilhabebegriff in den jeweiligen Artikeln auf einzelne Lebensbereiche heruntergebrochen, für die jeweils konkrete Maßnahmen und Ziele zur Umsetzung von Chancengleichheit beschrieben werden. Zur Überwachung der UN- BRK wurde bei den Vereinten Nationen ein \"Ausschuss für die Rechte von Menschen mit Behinderungen\" mit Sitz in Genf gebildet, der sich aus einer bestimmten Anzahl von Expert*innen aus den einzelnen Vertragsstaaten zusammensetzt. Die Vertragsstaaten legen dem Ausschuss unter anderem regelmäßig Staatenberichte über den Stand dieser Umsetzung des Übereinkommens vor, die der Ausschuss prüft und zu denen er Stellung nehmen kann. Das Fakultativprotokoll, das Deutschland ebenfalls ratifiziert hat, erweitert die Kompetenzen des Vertragsausschusses um ein Individualbeschwerde- und ein Untersuchungsverfahren. Nach vierjähriger Verhandlungszeit hat die Generalversammlung der Vereinten Nationen am 13. Dezember 2006 das \"Übereinkommen der Vereinten Nationen über die Rechte von Menschen mit Behinderungen\" sowie das dazugehörige Fakultativprotokoll angenommen. Deutschland hat das Übereinkommen und das Protokoll am 30. März 2007 unterzeichnet. Das Ratifikationsgesetz wurde im Dezember 2008 von Bundestag und Bundesrat verabschiedet und ist am 01. Januar 2009 in Kraft getreten. Am 24. Februar 2009 wurde die Ratifikations­urkunde in New York hinterlegt. Nach Ablauf der 30-Tage-Frist ist das Übereinkommen und das Fakultativprotokoll seit dem 26. März 2009 für Deutschland verbindlich. Nach vierjähriger Verhandlungszeit hat die Generalversammlung der Vereinten Nationen das \"Übereinkommen der Vereinten Nationen über die Rechte von Menschen mit Behinderungen\" sowie das dazugehörige Fakultativprotokoll angenommen."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Behindertenrechtskonvention-der-Vereinten-Nationen/behindertenrechtskonvention-der-vereinten-nationen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:31.691502+00:00","lastSeen":"2026-03-15T17:52:31.691502+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Behindertenrechtskonvention-der-Vereinten-Nationen/behindertenrechtskonvention-der-vereinten-nationen.html","crawledAt":"2026-03-15T17:52:31.691502Z","crawlId":"contacts-seeded-1773597151","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f597e3f9f567e2f1b352126fc9fce40e26e6f27172d4ad221754d7b0b21b34ff"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:31.691502+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('48f375b9-aa44-4f84-87b0-7eb3d381ee4d', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Beschaeftigung-schwerbehinderter-Menschen/beschaeftigung-schwerbehinderter-menschen.html', 'active', NULL, '2026-03-15T17:52:32.520877+00:00', '{"id":"48f375b9-aa44-4f84-87b0-7eb3d381ee4d","title":"Beschäftigung schwerbehinderter Menschen","summary":{"de":"Einige der Nachteile behinderter Menschen im Arbeitsleben versucht das Schwerbehindertenrecht in Teil 3 des SGB IX ( §§ 151 ff. SGB IX ) auszugleichen"},"content":{"de":"Einige der Nachteile behinderter Menschen im Arbeitsleben versucht das Schwerbehindertenrecht in Teil 3 des SGB IX ( §§ 151 ff. SGB IX ) auszugleichen. Es gilt für schwerbehinderte und ihnen gleich gestellte Menschen. Menschen mit Behinderung mit einem GdB von weniger als 50, aber wenigstens 30, die infolge ihrer Behinderung keinen geeigneten Arbeitsplatz erlangen oder behalten können, werden auf Antrag von der Agentur für Arbeit schwerbehinderten Menschen gleich gestellt. Das SGB IX sieht für schwerbehinderte Menschen vielfältige Eingliederungshilfen vor: Förderung der Einstellung und Beschäftigung schwerbehinderter Menschen durch Geldleistungen an Arbeitgeber. Besonderer Kündigungsschutz: Jeder Auflösung oder Änderung des Arbeitsverhältnisses muss vorher das Integrationsamt zustimmen. Zusatzurlaub für schwerbehinderte Menschen von einer Arbeitswoche (gilt nicht für Gleichgestellte). Werden ständig wenigstens fünf schwerbehinderte Menschen beschäftigt, so ist zusätzlich zum Betriebs- und Personalrat eine Schwerbehindertenvertretung zu wählen."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Beschaeftigung-schwerbehinderter-Menschen/beschaeftigung-schwerbehinderter-menschen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:32.520877+00:00","lastSeen":"2026-03-15T17:52:32.520877+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Beschaeftigung-schwerbehinderter-Menschen/beschaeftigung-schwerbehinderter-menschen.html","crawledAt":"2026-03-15T17:52:32.520877Z","crawlId":"contacts-seeded-1773597152","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"7029136f3c57c95d3d394192010df2b90526be4512b721c7133d62ac149d3aeb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:32.520877+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('aa8f815b-fa61-483a-83f3-4805ce887aeb', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Politik-Menschen-Behinderungen/politik-menschen-behinderungen.html', 'active', NULL, '2026-03-15T17:52:33.239601+00:00', '{"id":"aa8f815b-fa61-483a-83f3-4805ce887aeb","title":"Politik für Menschen mit Behinderungen","summary":{"de":"Niemand darf wegen seiner Behinderung benachteiligt werden. So steht es in Artikel 3 des Grundgesetzes der Bundesrepublik Deutschland."},"content":{"de":"Niemand darf wegen seiner Behinderung benachteiligt werden. So steht es in Artikel 3 des Grundgesetzes der Bundesrepublik Deutschland. Gleichbehandlung und die Förderung von Chancengleichheit als eine Voraussetzung für Selbstbestimmung und Teilhabe behinderter und von Behinderung bedrohter Menschen stehen deshalb im Zentrum der Behindertenpolitik der Bundesregierung. Die Vorschrift bindet als individuelles Grundrecht Gesetzgebung, vollziehende Gewalt und Rechtsprechung unmittelbar, nicht nur auf Bundesebene, sondern auch in Ländern und Gemeinden sowie sonstigen Institutionen und Organisationen der \"öffentlichen Gewalt\". Auf Rechtsbeziehungen zwischen Privaten wirkt das Benachteiligungsverbot mittelbar, indem es bei der Auslegung und Anwendung bürgerlichen Rechts berücksichtigt werden muss. Mit dem Neunten Buch Sozialgesetzbuch (SGB IX, 2001) und dem Behindertengleichstellungsgesetz (BGG, 2002) wurden grundlegende gesetzliche Voraussetzungen zur Umsetzung des Benachteiligungsverbots des Grundgesetzes und für eine verbesserte Teilhabe von Menschen mit Behinderungen geschaffen. Im SGB IX wurde das zersplitterte Recht zur Rehabilitation und Teilhabe von Menschen mit Behinderungen sowie das Schwerbehindertenrecht zusammengefasst und weiterentwickelt. Dabei trägt das SGB IX dem Grundsatz des selbstbestimmten Lebens und der Eigenverantwortlichkeit von Menschen mit Behinderungen Rechnung und löste das bisher an Fürsorge und Versorgung behinderter Menschen orientierte Prinzip ab. Mit dem Bundesteilhabegesetz wurde das Recht der Eingliederungshilfe in das SGB IX als Teil 2 überführt und das Prinzip der Selbstbestimmung auch für diesen Bereich gestärkt. Das Behindertengleichstellungsgesetz setzt das Gleichbehandlungsgebot des Grundgesetzes um und regelt Barrierefreiheit in einem umfassenden Sinn: Das BGG regelt Barrierefreiheit in einem umfassenden Sinn und erkennt die Deutsche Gebärdensprache, die lautsprachbegleitenden Gebärden an sowie das Recht, diese und andere geeignete Kommunikationsformen zu verwenden. Der Paradigmenwechsel, der in der Behindertenpolitik in Deutschland insbesondere mit dem SGB IX und dem BGG eingeleitet wurde, wurde mit dem Allgemeinen Gleichbehandlungsgesetz (AGG) fortgesetzt. Das SGB IX bietet bereits einen weitgehenden Schutz für Menschen mit schweren Behinderungen im Arbeitsleben, das AGG weitet diesen Schutz jetzt auf alle Menschen mit Behinderungen aus. Er erstreckt sich auf alle Bereiche des Arbeitslebens. Dieser Schutz reicht von der Bewerberauswahl über den Zugang zu beruflichen Bildungschancen bis hin zu Beförderungen. Im Alltagsleben wirkt das Gesetz Diskriminierungen bei so genannten Massengeschäften – z.B. bei Kaufverträgen, Hotelbuchungen und Ähnlichem – entgegen und verbietet Benachteiligungen auch bei privaten Versicherungen. Die nationale Politik der Bundesregierung findet mit dem VN -Übereinkommen über die Rechte von Menschen mit Behinderungen seine Entsprechung auf internationaler Ebene. Deutschland hat das VN-Übereinkommen und das Zusatzprotokoll als einer der ersten Staaten am 30. März 2007 unterzeichnet und, nachdem die gesetzlichen Voraussetzungen mit dem Ratifizierungsgesetz am 1. Januar 2009 geschaffen wurden, am 24. Februar 2009 mit Hinterlegung der Ratifikationsurkunde in New York ratifiziert. Seit dem 26. März 2009 sind VN-Übereinkommen und Zusatzprotokoll für Deutschland verbindlich. Das Übereinkommen als erstes universelles Rechtsinstrument, ist auf die Lebenssituation von weltweit über 600 Millionen Bürgerinnen und Bürgern mit Behinderungen zugeschnitten, es definiert soziale Standards, an denen die Vertragsstaaten ihr politisches Handeln zukünftig messen lassen müssen. Ein gesellschaftlicher Wandel ist damit vorgezeichnet. Dieser Wandel ist von klaren Zielen bestimmt: Dabei geht es um Teilhabe, Selbstbestimmung und uneingeschränkte Gleichstellung. Es geht um das Ziel, alle Bürgerinnen und Bürger zu befähigen, ihr Leben selbstbestimmt nach den eigenen Vorstellungen und Wünschen führen zu können. Und es geht um Politik, die die berechtigten Ansprüche und die Rechte der Bürgerinnen und Bürger mit Behinderungen in den Mittelpunkt stellt. Behindertenrechtskonvention der Vereinten Nationen"},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Politik-Menschen-Behinderungen/politik-menschen-behinderungen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:33.239601+00:00","lastSeen":"2026-03-15T17:52:33.239601+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/Politik-Menschen-Behinderungen/politik-menschen-behinderungen.html","crawledAt":"2026-03-15T17:52:33.239601Z","crawlId":"contacts-seeded-1773597153","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"a3da475a92e58c4a9484de27d26ea6c9350f9f83160d20f9444c2ef3c817fa25"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:33.239601+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('fcb2e53d-c40b-4c3b-a33a-653eb8cfe657', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/politik-fuer-menschen-mit-behinderungen.html', 'active', NULL, '2026-03-15T17:52:33.807998+00:00', '{"id":"fcb2e53d-c40b-4c3b-a33a-653eb8cfe657","title":"Politik für Menschen mit Behinderungen","summary":{"de":"In einer inklusiven Gesellschaft ist es von entscheidender Bedeutung, sicherzustellen, dass soziale Politik die Bedürfnisse und Rechte aller Menschen berücksichtigt, unabhängig von ihrer körperlichen oder geistigen Verfassung."},"content":{"de":"\"Gemeinsam einfach machen\" ist ein Informationsportal zur Umsetzung der UN-Behindertenrechtskonvention."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/politik-fuer-menschen-mit-behinderungen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:33.807998+00:00","lastSeen":"2026-03-15T17:52:33.807998+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Politik-fuer-Menschen-mit-Behinderungen/politik-fuer-menschen-mit-behinderungen.html","crawledAt":"2026-03-15T17:52:33.807998Z","crawlId":"contacts-seeded-1773597153","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"07fd34ac03d133a335f9e015e1a77852f5a340fe018dc346d8c4bbf83a94aedd"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:33.807998+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b6dae0cf-e30f-443b-93d7-d5173028922c', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Bundesteilhabegesetz/bundesteilhabegesetz.html', 'active', NULL, '2026-03-15T17:52:34.753526+00:00', '{"id":"b6dae0cf-e30f-443b-93d7-d5173028922c","title":"Bundesteilhabegesetz","summary":{"de":"Das Bundesteilhabegesetz (BTHG) ist ein umfassendes Gesetzespaket, das in vier zeitversetzten Reformstufen bis 2023 in Kraft tritt und das für Menschen mit Behinderungen viele Verbesserungen vorsieht. Mit dem BTHG wurden mehr Möglichkeiten der Teilhabe und mehr Selbstbestimmung für Menschen mit Behinderungen geschaffen. Menschen mit Behinderungen, die Eingliederungshilfe beziehen, können mehr von ihrem Einkommen und Vermögen behalten."},"content":{"de":"Gleichzeitig werden die Kommunen und Länder entlastet, da Grundsicherungs- und Eingliederungshilfeleistungen getrennt sowie teilweise vom Bund übernommen werden. Das BTHG verpflichtet die Träger von Reha-Maßnahmen (wie z.B. die Bundesagentur für Arbeit oder die gesetzliche Rentenversicherung), frühzeitig drohende Behinderungen zu erkennen und gezielt Prävention noch vor Eintritt der Rehabilitation zu ermöglichen. Ziel ist es, bereits vor Eintritt einer chronischen Erkrankung oder Behinderung durch geeignete präventive Maßnahmen entgegenzuwirken und die Erwerbsfähigkeit zu erhalten. Zur Unterstützung dieser gesetzlichen Pflicht hat das BMAS im Mai 2018 das Bundesprogramm \"Innovative Wege zur Teilhabe am Arbeitsleben – rehapro\" mit dem ersten Förderaufruf gestartet. Antragsteller sind Jobcenter und/oder Träger der gesetzlichen Rentenversicherung. Das Ziel des Bundesprogramms rehapro ist es, aus den Modellprojekten neue Erkenntnisse zu innovativen Ansätzen zu gewinnen, die dann allen Betroffenen zugutekommen sollen. Zur Umsetzung des Bundesprogramms rehapro stehen bis 2026 Mittel in Höhe von rund 1 Milliarde Euro zur Verfügung. Psychische Störungen, insbesondere Depressionen, führen häufig zum Bezug von Renten wegen verminderter Erwerbsfähigkeit. Die Modellprojekte können dabei helfen, spezielle, auf die Bedürfnisse psychisch erkrankter Menschen ausgerichtete Leistungen zu entwickeln, um bei den Betroffenen die Erwerbsfähigkeit wiederherzustellen und somit eine Rückkehr auf den Arbeitsmarkt zu ermöglichen. Ein einziger Reha-Antrag ist ausreichend, um ein umfassendes Prüf- und Entscheidungsverfahren in Gang zu setzen, auch wenn es bei den unterschiedlichen Zuständigkeiten von Sozialamt, Jugendamt, Rentenversicherung, Bundesagentur für Arbeit, Unfall- und Krankenkasse bleibt. Dafür sind die Regelungen zur Zuständigkeit und zur Einführung eines trägerübergreifenden Teilhabeplanverfahrens für alle Rehabilitationsträger gesetzlich definiert worden. Ist ein Mensch mit Gehbehinderungen z. B. auf einen Rollstuhl angewiesen und benötigt zudem noch Assistenzleistungen, wurden in der Vergangenheit vielfach zwei Leistungen bei zwei unterschiedlichen Stellen beantragt; der Rollstuhl bei der Krankenkasse und die Assistenzleistung, z. B. ein Fahrdienst, bei dem Träger der Eingliederungshilfe. Nun genügt ein Antrag für beide Leistungen bei lediglich einem der beiden Träger, der die Leistungen in einem Teilhabeplan zusammenführen und abstimmen muss. Das bedeutet für die Betroffenen eine erhebliche Erleichterung und Zeitersparnis. Orientierungs-, Planungs- und Entscheidungshilfe zu Fragen der Rehabilitation und Teilhabe und das bereits im Vorfeld der Beantragung konkreter Leistungen ermöglicht ein vom Bund gefördertes träger- und leistungserbringerunabhängiges Netzwerk von Beratungsangeboten für Menschen mit (drohenden) Behinderungen und deren Angehörige. Das Besondere: Die Beratung erfolgt von Betroffenen durch Betroffene unter Nutzung der Beratungsmethode des \" Peer Counseling \" und stärkt deren Selbstbestimmung und Eigenverantwortung. Mit dem Gesetz zur Entlastung unterhaltsverpflichteter Angehöriger in der Sozialhilfe und in der Eingliederungshilfe (kurz: \"Angehörigen-Entlastungsgesetz\") wurde die Weiterführung und Aufstockung der bisherigen Projektfinanzierung mit einem Finanzierungsvolumen ab 2023 von 65 Mio. Euro jährlich beschlossen, wodurch Ratsuchende eine Perspektive in Bezug auf den Fortbestand niedrigschwelliger, qualifizierter Beratung zu Fragen der Rehabilitation und Teilhabe über 2022 hinaus erhalten."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Bundesteilhabegesetz/bundesteilhabegesetz.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:34.753526+00:00","lastSeen":"2026-03-15T17:52:34.753526+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Bundesteilhabegesetz/bundesteilhabegesetz.html","crawledAt":"2026-03-15T17:52:34.753526Z","crawlId":"contacts-seeded-1773597154","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"3bdd2262f0d0d6b5022c8c4852cf6e1df4b53e047571264d122aba8080d896bf"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:34.753526+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f4043477-5483-4cec-a3b3-26b97ff260ec', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Foerderprogramm-rehapro/foerderprogramm-rehapro.html', 'active', NULL, '2026-03-15T17:52:35.287998+00:00', '{"id":"f4043477-5483-4cec-a3b3-26b97ff260ec","title":"Förderprogramm rehapro","summary":{"de":"Im Rahmen des Bundesteilhabegesetzes wurde in § 11 SGB IX die Förderung von Modellvorhaben zur Stärkung der Rehabilitation beschlossen. Den Auftrag setzt das Bundesministerium für Arbeit und Soziales mit dem Bundesprogramm \"Innovative Wege zur Teilhabe am Arbeitsleben – rehapro\" um. In drei Förderaufrufen führen die antragsberechtigten Jobcenter und Rentenversicherungsträger insgesamt 122 Modellprojekte mit einem Fördervolumen von rund 590 Mio. Euro durch."},"content":{"de":"Ziel des Bundesprogramms ist es, durch die Erprobung von innovativen Leistungen und innovativen organisatorischen Maßnahmen neue Wege zu finden, die Erwerbsfähigkeit von Menschen mit gesundheitlichen Beeinträchtigungen besser zu erhalten bzw. wiederherzustellen sowie die Zusammenarbeit der Akteure im Bereich der medizinischen und beruflichen Rehabilitation weiter zu verbessern. Mit den Modellprojekten werden insbesondere neue Ansätze zur frühzeitigen Intervention (\"Prävention vor Rehabilitation\" und \"Rehabilitation vor Rente\") sowie zur Unterstützung von Menschen mit psychischen Beeinträchtigungen und komplexen gesundheitlichen Unterstützungsbedarfen erprobt. Auf der Website des Bundesprogramms rehapro finden Sie alle Informationen über die Modellprojekte und deren Abwicklung. Mit der gesetzlichen Regelung des § 11 Absatz 4 SGB IX wurde der Deutschen Rentenversicherung Knappschaft-Bahn-See (DRV KBS) die Aufgabe übertragen, die zuwendungsrechtliche und organisatorische Abwicklung der Modellvorhaben zu übernehmen. Bei der DRV KBS wurde dafür die unabhängige Fachstelle rehapro eingerichtet, die als Projektträger die Förderung im Auftrag des BMAS umsetzt. Än­de­rung der För­der­richt­li­nie zum 20. Ju­ni 2018 [PDF, 37KB] Startschuss für das Bundesprogramm \"Innovative Wege zur Teilhabe am Arbeitsleben – rehapro\""},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Foerderprogramm-rehapro/foerderprogramm-rehapro.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:35.287998+00:00","lastSeen":"2026-03-15T17:52:35.287998+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Foerderprogramm-rehapro/foerderprogramm-rehapro.html","crawledAt":"2026-03-15T17:52:35.288998Z","crawlId":"contacts-seeded-1773597155","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"80692df547f503973d36eeedceaba5bf4f3b151d8307918998bd62c6daaa88ed"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:35.288998+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0d90ae78-0cfe-488e-bbcd-79a34724f342', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Foerderung-der-Ausbildung-und-Beschaeftigung/foerderung-der-ausbildung-und-beschaeftigung.html', 'active', NULL, '2026-03-15T17:52:35.827646+00:00', '{"id":"0d90ae78-0cfe-488e-bbcd-79a34724f342","title":"Förderung der Ausbildung und Beschäftigung","summary":{"de":"Leistungen für Arbeitgeber, die Menschen mit Behinderungen ausbilden oder beschäftigen"},"content":{"de":"Die Bundesagentur für Arbeit, die Integrationsämter und andere Rehabilitationsträger bieten finanzielle und beratende Unterstützungsangebote für Arbeitgeber an, die behinderte oder schwerbehinderte Menschen ausbilden oder beschäftigen."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Foerderung-der-Ausbildung-und-Beschaeftigung/foerderung-der-ausbildung-und-beschaeftigung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:35.827646+00:00","lastSeen":"2026-03-15T17:52:35.827646+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Foerderung-der-Ausbildung-und-Beschaeftigung/foerderung-der-ausbildung-und-beschaeftigung.html","crawledAt":"2026-03-15T17:52:35.827646Z","crawlId":"contacts-seeded-1773597155","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"048c04db00ed1bff8b62d8ad3ed3afd128c16220f11bde0d01c540ae83602d4b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:35.827646+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2d5a5b56-d429-49b0-93f6-d47a28fc3528', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Hilfsfonds-des-Bundes-fuer-Rehabilitation-und-Teilhabe/hilfsfonds-des-bundes-fuer-rehabilitation-und-teilhabe.html', 'active', NULL, '2026-03-15T17:52:36.416925+00:00', '{"id":"2d5a5b56-d429-49b0-93f6-d47a28fc3528","title":"Hilfsfonds des Bundes für Rehabilitation und Teilhabe","summary":{"de":"Im Jahr 2022 sind in Deutschland die Kosten speziell für Energie und Wärme stark gestiegen. Um den Menschen, aber auch den Unternehmen und den sozialen Einrichtungen im Land dabei zu helfen, diese Mehrkosten zu schultern, hat die Bundesregierung eine Vielzahl von Unterstützungsleistungen und Härtefallregelungen entwickelt."},"content":{"de":"Zu diesen Leistungen zählt der neugeschaffene Hilfsfonds des Bundes für Rehabilitation und Teilhabe nach § 36a des Neunten Buches Sozialgesetzbuch (SGB IX). Denn Einrichtungen der Rehabilitation und Teilhabe (in der Folge \"soziale Dienstleister\" genannt) können die gestiegenen Energiekosten nicht ohne Weiteres an ihre Kostenträger oder an die Rehabilitanden weitergeben oder anderweitig gegenfinanzieren. Der Fonds ist eine Ergänzung zu der Einmalzahlung im Dezember sowie den geplanten Energiepreisbremsen. Auf Antrag wird ein einmaliger Zuschuss zu den gestiegenen Energiekosten für Gas, Fernwärme und andere Brennstoffe sowie Strom im Jahr 2022 gezahlt. Der Zuschuss beträgt i.d.R. 95 Prozent der Differenz zwischen den entstandenen Energiekosten des Jahres 2022 und denen des Jahres 2021. Das Nähere zum Antragsverfahren ist in der Rehabilitationshilfsfonds-Verordnung (ReHV) geregelt. Mit seinem Urteil vom 15. November 2023 hat das Bundesverfassungsgericht den zweiten Nachtragshaushalt 2021 für nichtig erklärt. Bei Übertragung der Maßstäbe aus den Entscheidungsgründen betrifft das Urteil des Bundesverfassungsgerichts auch den Wirtschaftsstabilisierungsfonds (WSF). Die Bundesregierung hat daher am 27. November 2023 unter anderem beschlossen, die aus dem WSF finanzierten Leistungen zum Ende des Jahres 2023 auslaufen zu lassen. Die notwendigen gesetzlichen Änderungen werden über das Haushaltsfinanzierungsgesetz umgesetzt. Dies betrifft auch den Hilfsfonds des Bundes für Rehabilitation und Teilhabe nach § 36a SGB IX i.V.m. der ReHV und den hieraus gewährten Zuschuss zu den Kosten für Erdgas, Wärme und Strom für Rehabilitationseinrichtungen, die Vorsorge-, Rehabilitations- und Teilhabeleistungen. Das Haushaltsfinanzierungsgesetz wurde am 28. Dezember 2023 verkündet. Anträge für den Energie-Zuschuss an soziale Dienstleister können daher ab dem 29. Dezember 2023 nicht mehr gestellt werden. Die Einrichtungen, die Vorsorge-, Rehabilitations- und Teilhabeleistungen erbringen (Soziale Dienstleister) konnten die im Jahr 2022 gestiegenen Energiekosten für ihre Einrichtungen aufgrund längerfristig vertraglich festgelegter Vergütungen nicht ausgleichen und unmittelbar an ihre Kostenträger weitergeben. Auch an die Leistungsberechtigten (Teilnehmenden) können die höheren Energiekosten nicht weitergegeben werden. Bei gemeinnützigen Trägern können zudem keine Rücklagen gebildet werden, aus denen die höheren Kosten finanziert werden könnten. Einsparpotenziale beim Energieverbrauch sind aber aufgrund der Vulnerabilität der Teilnehmenden in den Einrichtungen begrenzt."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Hilfsfonds-des-Bundes-fuer-Rehabilitation-und-Teilhabe/hilfsfonds-des-bundes-fuer-rehabilitation-und-teilhabe.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:36.416925+00:00","lastSeen":"2026-03-15T17:52:36.416925+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Hilfsfonds-des-Bundes-fuer-Rehabilitation-und-Teilhabe/hilfsfonds-des-bundes-fuer-rehabilitation-und-teilhabe.html","crawledAt":"2026-03-15T17:52:36.416925Z","crawlId":"contacts-seeded-1773597156","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"b0c6984a4f6f251cd5b9a596af0f5f56ea3a0af1d4ebc884ed585bc6325ba99f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:36.416925+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9d2564b6-edbd-4181-b485-265c980880d3', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Persoenliches-Budget/persoenliches-budget.html', 'active', NULL, '2026-03-15T17:52:36.940724+00:00', '{"id":"9d2564b6-edbd-4181-b485-265c980880d3","title":"Persönliches Budget","summary":{"de":"Die Leistungsform des Persönlichen Budgets wurde mit dem Neunten Buch Sozialgesetzbuch (SGB IX) zum 1. Juli 2001 eingeführt. Mit dem Persönlichen Budget können Leistungsempfänger*innen von den Rehabilitationsträgern anstelle von Dienst- oder Sachleistungen zur Teilhabe ein Budget wählen. Hieraus bezahlen sie die Aufwendungen, die zur Deckung ihres persönlichen Hilfebedarfs erforderlich sind. Damit werden Menschen mit Behinderungen zu Budgetnehmer*innen, die den \"Einkauf\" der Leistungen eigenverantwortlich, selbständig und selbstbestimmt regeln können; sie werden Käufer, Kunden oder Arbeitgeber. Als Experten in eigener Sache entscheiden sie so selbst, welche Hilfen für sie am besten sind und welcher Dienst und welche Person zu dem von ihnen gewünschten Zeitpunkt eine Leistung erbringen soll."},"content":{"de":"Diese Wahlfreiheit fördert die Selbstbestimmung behinderter Menschen. Das Persönliche Budget löst das bisherige Dreieck zwischen Leistungsträger, Leistungsempfänger*innen und Leistungserbringer auf; Sachleistungen werden durch Geldleistungen oder Gutscheine ersetzt. Besondere Bedeutung für die Fortentwicklung der Leistungen zur Teilhabe haben trägerübergreifende Persönliche Budgets als Komplexleistungen. Hiervon spricht man, wenn mehrere Leistungsträger unterschiedliche Teilhabe- und Rehabilitationsleistungen in einem Budget erbringen. Seit dem 1. Juli 2004 ist geregelt, dass heute neben allen Leistungen zur Teilhabe auch andere Leistungen der gesetzlichen Krankenkassen, Leistungen der sozialen Pflegeversicherung, Leistungen der Unfallversicherung bei Pflegebedürftigkeit sowie Pflegeleistungen der Sozialhilfe in trägerübergreifende Persönliche Budgets einbezogen werden können. Für ein Persönliches Budget müssen Menschen mit Behinderungen einen entsprechenden Antrag beim Leistungsträger stellen. Seit dem 1. Januar 2008 besteht auf Leistungen in Form des Persönlichen Budgets ein Rechtsanspruch. Das bedeutet, dass dem Wunsch- und Wahlrecht der potentiellen Budgetnehmer*innen in vollem Umfang entsprochen wird und bei Vorliegen der rechtlichen Voraussetzungen grundsätzlich alle Anträge auf Bewilligung von Persönlichen Budgets zu genehmigen sind. All­tags­spra­che: Das trä­ger­über­grei­fen­de Per­sön­li­che Bud­get Be­richt der Bun­des­re­gie­rung über die Aus­füh­rung der Leis­tun­gen des Per­sön­li­chen Bud­gets [PDF, 1MB]"},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Persoenliches-Budget/persoenliches-budget.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:36.940724+00:00","lastSeen":"2026-03-15T17:52:36.940724+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Persoenliches-Budget/persoenliches-budget.html","crawledAt":"2026-03-15T17:52:36.941705Z","crawlId":"contacts-seeded-1773597156","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"a664d6fcfcb9d4a53728a7425b01d631f1b1cde5113ad843d6809ffb6184a1db"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:36.941705+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2ec526f0-aa3d-4a2d-979c-a0a9fe2e3d16', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Rehabilitation-Teilhabe/rehabilitation-teilhabe.html', 'active', NULL, '2026-03-15T17:52:37.542336+00:00', '{"id":"2ec526f0-aa3d-4a2d-979c-a0a9fe2e3d16","title":"Rehabilitation und Teilhabe","summary":{"de":"Menschen mit Behinderungen soll durch Leistungen zur Teilhabe die volle Teilhabe am gesellschaftlichen Leben eröffnet werden. Sie sollen ihr Leben nach ihren Neigungen und Fähigkeiten gestalten. Eine umfassende Teilhabe ist dann erreicht, wenn der Mensch mit Behinderung (wieder) vollständig in das Leben der Gemeinschaft eingegliedert ist. Diesen Zustand zu erhalten, gehört selbstverständlich auch zu den Aufgaben der Leistungen zur Teilhabe."},"content":{"de":"Leistungen zur Teilhabe sind umso erfolgreicher, je früher sie eingeleitet und durchgeführt werden. Sie setzen nicht erst dann ein, wenn eine Behinderung schon vorliegt. Bei Krankheiten und Unfällen beginnen sie möglichst mit der Akutbehandlung, auch im Krankenhaus. Die Leistungen werden unterteilt in Leistungen zur medizinischen Rehabilitation, Leistungen zur Teilhabe am Arbeitsleben, unterhaltssichernde und ergänzende Leistungen, Leistungen zur Teilhabe an Bildung und Leistungen zur sozialen Teilhabe. Zusätzlich erhalten schwerbehinderte Menschen besondere Hilfen. Die einzelnen Leistungen zur Teilhabe sind keine streng zu trennenden, schematisch aufeinanderfolgenden Vorgänge. Rehabilitation und Teilhabe führen dann zum besten Ergebnis, wenn die mit den Menschen mit Behinderungen jeweils abgestimmten einzelnen Phasen und Bereiche nahtlos ineinander greifen und sich gegenseitig ergänzen. Rehabilitation und Teilhabe muss als Ganzes, als ein einheitlicher Prozess gesehen und durchgeführt werden. Kann durch Vorsorge und Frühförderung das Entstehen einer Behinderung nicht abgewendet werden oder tritt diese durch ein plötzliches Ereignis ein, stehen zur Rehabilitation in der Regel zunächst medizinische Leistungen im Vordergrund. Genau genommen sind die Ziele der Rehabilitation – eine drohende Behinderung oder abzuwendende Pflegebedürftigkeit, eine Behinderung zu beseitigen, zu mindern bzw. auszugleichen, ihre Verschlimmerung zu verhüten oder ihre Folgen zu mildern – bei allen medizinischen Leistungen zu beachten, auch bei jeder Akutbehandlung. Darüber hinaus gibt es zur medizinischen Rehabilitation spezifische Leistungen mit diesen Zielen. Wichtiger Bestandteil aller Leistungen ist es dabei, die verbliebenen Kräfte zu stärken und gleichzeitig solche Funktionen und Fähigkeiten zu fördern und zu entwickeln, die die ausgefallenen ausgleichen. Weitere Informationen finden sich hier:"},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Rehabilitation-Teilhabe/rehabilitation-teilhabe.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:37.542336+00:00","lastSeen":"2026-03-15T17:52:37.542336+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Rehabilitation-Teilhabe/rehabilitation-teilhabe.html","crawledAt":"2026-03-15T17:52:37.543342Z","crawlId":"contacts-seeded-1773597157","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f7a19a0b74fcea9207b261372c10be541d93f15230c8057d43cc6e165b8bcbf6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:37.543342+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d22286f1-ebdb-457a-9cea-8fad19b705b1', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Was-ist-Teilhabe-von-Menschen-mit-Behinderungen/was-ist-teilhabe-von-menschen-mit-behinderungen.html', 'active', NULL, '2026-03-15T17:52:38.152651+00:00', '{"id":"d22286f1-ebdb-457a-9cea-8fad19b705b1","title":"Was ist Teilhabe von Menschen mit Behinderungen?","summary":{"de":"Menschen mit Behinderungen wollen genauso leben wie nichtbehinderte Menschen auch."},"content":{"de":"Menschen mit Behinderungen wollen genauso leben wie nichtbehinderte Menschen auch. Sie möchten mobil sein und ihren Alltag ohne fremde Hilfe meistern können. Und sie haben ein Recht darauf. Denn niemand darf wegen seiner Behinderung benachteiligt werden - so steht es im Grundgesetz der Bundesrepublik Deutschland. Daher ist es eine wesentliche Aufgabe des Bundesministeriums für Arbeit und Soziales als federführendes Ressort, Chancengleichheit für Menschen mit Behinderungen herzustellen und ihnen eine gleichberechtigte berufliche und gesellschaftliche Teilhabe zu ermöglichen. Das Behindertengleichstellungsgesetz (BGG), das Allgemeine Gleichbehandlungsgesetz (AGG), das Neunte Buch Sozialgesetzbuch (SGB IX) sowie das Übereinkommen der Vereinten Nationen über die Rechte von Menschen mit Behinderung bilden auf nationaler und internationaler Ebene den Rahmen für diese Politik. Besondere Schwerpunkte der Arbeit des Ministeriums für Menschen mit Behinderung bilden die Bereiche Ausbildung und Beschäftigung ( Unterstützte Beschäftigung ), Rehabilitation sowie die Herstellung einer umfassend verstandenen Barrierefreiheit. Im Rahmen der eGovernment-Strategie der Bundesregierung ist das BMAS darüber hinaus für die Internetplattform Einfach-Teilhaben.de verantwortlich."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Was-ist-Teilhabe-von-Menschen-mit-Behinderungen/was-ist-teilhabe-von-menschen-mit-behinderungen.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:38.152651+00:00","lastSeen":"2026-03-15T17:52:38.152651+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/Was-ist-Teilhabe-von-Menschen-mit-Behinderungen/was-ist-teilhabe-von-menschen-mit-behinderungen.html","crawledAt":"2026-03-15T17:52:38.152651Z","crawlId":"contacts-seeded-1773597158","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"f3216237ea6455547729f3af32aa10aee8ecd81255b91dad4a2e96cadb2b15a2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:38.152651+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0ad7b9bb-56d8-474a-a1f5-db1c0933edb9', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/rehabilitation-und-teilhabe.html', 'active', NULL, '2026-03-15T17:52:38.683455+00:00', '{"id":"0ad7b9bb-56d8-474a-a1f5-db1c0933edb9","title":"Rehabilitation und Teilhabe","summary":{"de":"Leistungen zur Teilhabe sollen Menschen mit Behinderung die Teilhabe am Leben in der Gesellschaft ermöglichen bzw. verbessern."},"content":{"de":"Leistungen zur Teilhabe sollen Menschen mit Behinderung die Teilhabe am Leben in der Gesellschaft ermöglichen bzw. verbessern."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/rehabilitation-und-teilhabe.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:38.683455+00:00","lastSeen":"2026-03-15T17:52:38.683455+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Rehabilitation-und-Teilhabe/rehabilitation-und-teilhabe.html","crawledAt":"2026-03-15T17:52:38.683455Z","crawlId":"contacts-seeded-1773597158","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"1427655d79ce6741908799884267fb6f64ec8186a2a51f611de5061302a526c4"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:38.683455+00:00"}}') ON CONFLICT(id) DO UPDATE SET