INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('af46a41b-cd08-4935-b644-aeb53f9685d9', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Teilhabeforschung/teilhabeforschung.html', 'active', NULL, '2026-03-15T17:52:39.252569+00:00', '{"id":"af46a41b-cd08-4935-b644-aeb53f9685d9","title":"Teilhabeforschung","summary":{"de":"Hier finden Sie Berichte, Studien und Forschungsprojekte zur Lebenssituation und zur Teilhabe von Menschen mit Beeinträchtigungen und Behinderungen."},"content":{"de":"Hier finden Sie Daten zur Teilhabe von Menschen mit Beeinträchtigungen und Behinderungen in zentralen Lebensbereichen. Die Repräsentativbefragung zur Teilhabe von Menschen mit Behinderungen (kurz: Teilhabesurvey) untersucht die Teilhabe von Menschen mit Behinderungen und Beeinträchtigungen in unterschiedlichen Lebensbereichen. Der dritte Teilhabebericht der Bundesregierung bietet den Leserinnen und Lesern in mittlerweile bewährter Form einen systematischen und ausführlichen Forschungsüberblick über die Entwicklung der Teilhabe von Menschen mit Beeinträchtigungen. Die Studie enthält vielfältige Ergebnisse zur Lebenssituation von Familien mit beeinträchtigten bzw. behinderten Kindern, zur Suche nach bzw. Inanspruchnahme von inklusiven Bildungs- und Betreuungsangeboten, zum Verhalten des sozialen Umfelds sowie zu Erfahrungen mit der Beantragung und Bewilligung von Unterstützungsleistungen."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Teilhabeforschung/teilhabeforschung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:39.252569+00:00","lastSeen":"2026-03-15T17:52:39.252569+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/Teilhabeforschung/teilhabeforschung.html","crawledAt":"2026-03-15T17:52:39.252569Z","crawlId":"contacts-seeded-1773597159","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"27c9825e7389fb8ef0d0fc1994a2030f4de818644ba4c114116f35cb41e7e511"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:39.252569+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('632d5f50-6b5c-45dd-af1b-214114e95dff', 'contacts', 'https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/teilhabe-und-inklusion.html', 'active', NULL, '2026-03-15T17:52:39.912685+00:00', '{"id":"632d5f50-6b5c-45dd-af1b-214114e95dff","title":"Teilhabe und Inklusion","summary":{"de":"Die EUTB® berät Menschen mit (absehbaren) Behinderungen sowie deren Angehörige neutral, kostenlos und bundesweit."},"content":{"de":"Menschen mit Behinderung haben ein Recht auf umfassende Teilhabe. Das bedeutet Barrierefreiheit in allen Gebieten des Lebens. In dem Gesetz stehen Regeln zur Barriere·freiheit. Barriere·freiheit ist wichtig für die Teilhabe von Menschen mit Behinderungen. Der Gesetzentwurf enthält wichtige Regelungen zur Verbesserung der Barrierefreiheit im öffentlichen und im privaten Bereich. Innovative Projekte zum Thema \"BERUFSEINSTIEG INKLUSIV – Übergang von der beruflichen Bildung in den Arbeitsmarkt für junge Menschen mit Behinderungen\" gesucht. \"Gemeinsam einfach machen\" ist ein Informationsportal zur Umsetzung der UN-Behindertenrechtskonvention. Der Behindertenbeauftragte der Bundesregierung setzt sich für Inklusion, Barrierefreiheit und Gleichberechtigung von Menschen mit Behinderungen ein."},"url":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/teilhabe-und-inklusion.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:39.912685+00:00","lastSeen":"2026-03-15T17:52:39.912685+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Teilhabe-und-Inklusion/teilhabe-und-inklusion.html","crawledAt":"2026-03-15T17:52:39.912685Z","crawlId":"contacts-seeded-1773597159","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"08822372297bd380ce543b23972be87b3ce5ba0a8eaeaf4b2c62a2b01aafe7b7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:39.912685+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('15c789ad-f408-4b05-b708-918f0c196bc8', 'contacts', 'https://www.bmas.de/DE/Soziales/Versorgungsmedizin/Versorgungsmedizin-Verordnung/versorgungsmedizin-verordnung.html', 'active', NULL, '2026-03-15T17:52:41.098166+00:00', '{"id":"15c789ad-f408-4b05-b708-918f0c196bc8","title":"Versorgungsmedizin-Verordnung","summary":{"de":"Die Versorgungsmedizin-Verordnung stellt die Grundsätze auf, nach denen das Ausmaß einer nach dem Bundesversorgungsgesetz auszugleichenden Schädigungsfolge sowie der Grad der Behinderung gemäß SGB IX festzustellen sind."},"content":{"de":"Die Versorgungsmedizin-Verordnung stellt die Grundsätze auf, nach denen das Ausmaß einer nach dem Bundesversorgungsgesetz auszugleichenden Schädigungsfolge sowie der Grad der Behinderung gemäß Neuntem Buch Sozialgesetzbuch (SGB IX) festzustellen sind. Grundlage für die Begutachtung im Versorgungswesen war ursprünglich eine Richtlinie, die 1916 durch den wissenschaftlichen Senat bei der Kaiser-Wilhelm-Akademie verfasst, 1920 erweitert und dann vom jeweiligen für Arbeit bzw. Soziales zuständigen Ministerium herausgegeben wurde. Die Begutachtungsrichtlinie, die den Namen \"Anhaltspunkte\" trug, war zunächst nur auf das Versorgungswesen und somit nur für die Begutachtung von Kriegsopfern, anzuwenden. Nach in Kraft treten des Gesetzes zur Sicherung der Eingliederung Schwerbehinderter in Arbeit, Beruf und Gesellschaft 1974 entstanden 1977 die \"Anhaltspunkte für die ärztliche Begutachtung Behinderter nach dem Schwerbehindertenrecht\". Ab 1983 erschienen die gemeinsamen \"Anhaltspunkte für die ärztliche Gutachtertätigkeit im Sozialen Entschädigungsrecht und nach dem Schwerbehindertenrecht ( Teil 2 SGB IX )\". Nachdem die Rechtsprechung (Bundesverfassungsgericht, Bundessozialgericht) die demokratische Legitimierung der als antizipiertes Sachverständigengutachten anerkannten \"Anhaltspunkte\" angemahnt hatte, wurde durch das Gesetz zur Änderung des Bundesversorgungsgesetzes vom 13. Dezember 2007 mit § 30 Absatz 17 Bundesversorgungsgesetz die geforderte Ermächtigungsgrundlage geschaffen. Diese wurde durch die Versorgungsmedizin-Verordnung (VersMedV) konkretisiert. Die VersMedV trat am 1. Januar 2009 in Kraft und hat die \"Anhaltspunkte\" abgelöst. In die Anlage zu § 2 \"Versorgungsmedizinische Grundsätze\" wurden die in den Anhaltspunkten niedergelegten Grundsätze und Kriterien übernommen und an die seit Jahren bewährten Bewertungsgrundsätze und Verfahrensabläufe angeknüpft. Die \"Versorgungsmedizinischen Grundsätze\" werden auf Grundlage des aktuellen Stands der medizinischen Wissenschaft unter Anwendung der Grundsätze der evidenzbasierten Medizin fortentwickelt. Basis hierfür sind die Beschlüsse des unabhängigen Ärztlichen Sachverständigenbeirats Versorgungsmedizin [PDF, 122KB], der das Bundesministerium für Arbeit und Soziales zu allen versorgungsärztlichen Angelegenheiten berät und die Fortentwicklung vorbereitet. Die Umsetzung erfolgt durch Verordnungen zur Änderung der VersMedV. Zur Versorgungsmedizin gehört insbesondere auch die Versorgung mit Hilfsmitteln, die auf Grund fachärztlicher Verordnung in technisch-wissenschaftlich anerkannter Ausführung zu gewähren sind, den persönlichen und beruflichen Bedürfnissen angepasst sein müssen und dem allgemein anerkannten Stand der medizinischen Erkenntnisse und der technischen Entwicklung zu entsprechen haben. Hilfsmittel sind beispielsweise Prothesen, Stützapparate, orthopädisches Schuhwerk, Gehilfen, Rollstühle, Hör- und Sehhilfen, Kommunikationshilfen, aber auch Blindenführhunde. Mit­glie­der des Sach­ver­stän­di­gen­bei­rats Ver­sor­gungs­me­di­zi­ni­sche Be­gut­ach­tung beim Bun­des­mi­nis­te­ri­um für Ar­beit und So­zia­les [PDF, 122KB]"},"url":"https://www.bmas.de/DE/Soziales/Versorgungsmedizin/Versorgungsmedizin-Verordnung/versorgungsmedizin-verordnung.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:41.098166+00:00","lastSeen":"2026-03-15T17:52:41.098166+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Versorgungsmedizin/Versorgungsmedizin-Verordnung/versorgungsmedizin-verordnung.html","crawledAt":"2026-03-15T17:52:41.098166Z","crawlId":"contacts-seeded-1773597161","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"33c3530d3095ab5af5d27b5e2bde6aba90627fc54b3e891d53357a67627bda14"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:41.098166+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1786b49a-2a2d-4946-b031-7e88d7cbe600', 'contacts', 'https://www.bmas.de/DE/Soziales/Versorgungsmedizin/versorgungsmedizin.html', 'active', NULL, '2026-03-15T17:52:41.740487+00:00', '{"id":"1786b49a-2a2d-4946-b031-7e88d7cbe600","title":"Versorgungsmedizin","summary":{"de":"Die Versorgungsmedizin-Verordnung stellt die Grundsätze auf, nach denen das Ausmaß einer auszugleichenden Schädigungsfolge festzustellen sind. Hier finden Sie aktuelle Infos und Neuigkeiten zu diesem Thema."},"content":{"de":"Die Versorgungsmedizin-Verordnung stellt die Grundsätze auf, nach denen das Ausmaß einer auszugleichenden Schädigungsfolge festzustellen sind."},"url":"https://www.bmas.de/DE/Soziales/Versorgungsmedizin/versorgungsmedizin.html","topics":["employment","financial_support","contacts","public_service"],"tags":["application_required","contact"],"targetGroups":["unemployed","general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:41.740487+00:00","lastSeen":"2026-03-15T17:52:41.740487+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Arbeit und Soziales","provenance":{"source":"https://www.bmas.de/DE/Soziales/Versorgungsmedizin/versorgungsmedizin.html","crawledAt":"2026-03-15T17:52:41.740487Z","crawlId":"contacts-seeded-1773597161","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmas","providerName":"Bundesministerium für Arbeit und Soziales","providerLevel":"federal","checksum":"64d2116001ead024c7313e1564442fa4d4c181148b45159b780ed49d12d7855e"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:52:41.740487+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=exclude