INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('587b6f51-ed58-4991-9560-1f66e2fd2cfb', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj', 'active', NULL, '2026-03-15T17:52:42.469042+00:00', '{"id":"587b6f51-ed58-4991-9560-1f66e2fd2cfb","title":"BMBFSFJ","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Am 8. März ist Bundesfrauenministern Karin Prien nach New York gereist, um an der 70. Frauenrechtskommission der Vereinten Nationen (UN) teilzunehmen. Im Fokus der Konferenz: der Zugang zu Recht und Justiz für Frauen und Mädchen weltweit. Mit der Braunschweiger Zeitung hat Bundesfrauenministerin Karin Prien darüber gesprochen, wie es um die Gleichstellung von Frauen steht und welche Rolle Künstliche Intelligenz (KI) dabei spielt. Am 10. März hat die Parlamentarische Staatssekretärin im Bundesbildungsministerium, Mareike Wulf, in Köln die didacta miteröffnet. Das Motto \"Alles im Wandel. Bildung im Fokus\" stellt Innovationen und mentale Gesundheit ins Zentrum. Das Bundesfamilienministerium bietet einen umfassenden Überblick über finanzielle Unterstützung für Familien in 2026. Informieren Sie sich über Kindergeld, Elterngeld, Kinderzuschlag und mehr. Flyer Das Pflegetelefon - Schnelle Hilfe für Angehörige"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:42.469042+00:00","lastSeen":"2026-03-15T17:52:42.469042+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj","crawledAt":"2026-03-15T17:52:42.469042Z","crawlId":"contacts-seeded-1773597162","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c200a0b0f26294581a089eff7ca31385ccef9df728a1aaf0215f7ff845db689e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:42.469042+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('07ddfdf0-4e1a-434b-965e-f3756d3b2efa', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles', 'active', NULL, '2026-03-15T17:52:42.689699+00:00', '{"id":"07ddfdf0-4e1a-434b-965e-f3756d3b2efa","title":"Aktuell","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bundesfamilienministerin Karin Prien hat den Wettbewerb \"Kleine Lösungen - große Wirkung\" gestartet. Gesucht werden kleine und mittlere Unternehmen mit kreativen Ideen für die Vereinbarkeit von Familie und Beruf. Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Das Bundesfrauenministerium hat Dr. Petra Volke als deutsche Kandidatin für die Expertengruppe GREVIO des Europarats vorgestellt - ein bedeutender Beitrag Deutschlands zur Bekämpfung von geschlechtsspezifischer und häuslicher Gewalt. Presse Medienschaffende finden hier alle wichtigen Informationen aus der Pressestelle des Ministeriums: Pressemitteilungen, Kontaktdaten und Termine sowie Porträts. Medienschaffende finden hier alle wichtigen Informationen aus der Pressestelle des Ministeriums: Pressemitteilungen, Kontaktdaten und Termine sowie Porträts. Reden und Interviews Medieninterviews sowie ausgewählte Reden der Ministerin, der Parlamentarischen Staatssekretäre sowie der Staatssekretärin finden Sie hier."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:42.689699+00:00","lastSeen":"2026-03-15T17:52:42.689699+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles","crawledAt":"2026-03-15T17:52:42.689699Z","crawlId":"contacts-seeded-1773597162","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f994c8bf75325abbcfdaacd7f526856533411e7a0a74a8a87084363b9c59786f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:42.689699+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
