INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('24b41c11-1294-4480-8a36-8f7055299c39', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/rss', 'active', NULL, '2026-03-15T17:52:45.178694+00:00', '{"id":"24b41c11-1294-4480-8a36-8f7055299c39","title":"RSS-Service","summary":{"de":"Mit unserem Serviceangebot sind Sie immer topaktuell über die Themen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend informiert."},"content":{"de":"RSS-Feeds helfen Ihnen, sich schnell über Neuigkeiten auf unserer Internet-Seite zu informieren. Dafür müssen Sie die Seite nicht einmal besuchen. Besonders, wenn Sie über viele unterschiedliche Themen und Websites aktuell informiert sein wollen, hilft Ihnen der RSS-Service viel Zeit für die Recherche zu sparen. RSS ist eine Technik zur Übertragung von aktuellen Inhalten aus Internetseiten auf ein spezielles Leseprogramm, das Feed-Reader oder Newsreader genannt wird. Immer dann, wenn www.bmbfsfj.de aktualisiert wird, erhalten Sie die neuesten Meldungen bequem mit Hilfe Ihres aktivierten Feed-Reader auf Ihren Rechner. Um die Nachrichten automatisiert zu empfangen, müssen Sie den entsprechenden RSS-Feed über Ihren Feed-Reader oder Ihren Internet-Browser abonnieren. Der RSS-Service des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend informiert Sie über alle Themenbereiche des Hauses. Sie können auswählen, ob Sie unsere aktuelle Meldungen oder unsere Pressemitteilungen abonnieren möchten. Aktuelle Meldungen RSS Zusammenstellung von aktuellen Artikeln und Meldungen"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/rss","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:45.178694+00:00","lastSeen":"2026-03-15T17:52:45.178694+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/aktuelles/rss","crawledAt":"2026-03-15T17:52:45.178694Z","crawlId":"contacts-seeded-1773597165","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"3df749ad872acf42abeb8d2acfd94d16f5a3901bf346c2cea73dd8930496630f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:45.178694+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4084742a-3fbc-4de8-bb26-9896914e956a', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242', 'active', NULL, '2026-03-15T17:52:45.677743+00:00', '{"id":"4084742a-3fbc-4de8-bb26-9896914e956a","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Diese Erklärung zur Barrierefreiheit gilt für die unter www.bmbfsfj.bund.de veröffentlichte Website. Als öffentliche Stelle im Sinne der Richtlinie (EU) 2016/2102 ist das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend bestrebt, die Website www.bmbfsfj.bund.de im Einklang mit den Bestimmungen des Behindertengleichstellungsgesetztes des Bundes (BGG) sowie der Barrierefreien-Informationstechnik-Verordnung (BITV 2.0) zur Umsetzung der Richtlinie (EU) 2016/2102 barrierefrei zugänglich zu machen. Die Anforderungen der Barrierefreiheit ergeben sich aus § 3 Abs. 1 bis 4 und § 4 der BITV 2.0, die auf der Grundlage von § 12d BGG erlassen wurde. Zur Überprüfung der Anforderungen wurde im September 2023 ein BITV-Test durch den Prüfverbund BIK durchgeführt. Dabei wurde eine repräsentative Seitenauswahl untersucht. Der vollständige Prüfbericht kann hier eingesehen werden. Aufgrund der Überprüfung ist die Website mit den zuvor genannten Anforderungen teilweise vereinbar. Einige der im Prüfbericht festgestellten Mängel wurden zwischenzeitlich behoben. Die nachstehend aufgeführten Mängel bestehen nach wie vor: Die Inhalte im Logoband auf der Startseite sind im Lesemodus des Screenreaders nur eingeschränkt nutzbar. Das Verhalten (Ein- und Ausblenden von Inhalten) wird über Fokus-Events gesteuert, die im Screenreader zu leeren oder irreführenden Ausgaben führen können (WCAG 2.1, 1.3.2 Meaningful Sequence, Level A). Anderssprachige Inhalte (Wörter, Textabschnitte) in Überschriften sind nicht ausgezeichnet, das kann die Nutzung mit dem Screenreader erschweren (WCAG 2.1, 3.1.2 Language of Parts, Level AA)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:45.677743+00:00","lastSeen":"2026-03-15T17:52:45.677743+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/erklaerung-zur-barrierefreiheit-135242","crawledAt":"2026-03-15T17:52:45.677743Z","crawlId":"contacts-seeded-1773597165","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"feadc44acb9ad20dcaad43b1da0cb958c2b45955db76933862eb00fc355f27b0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:45.677743+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('05fd512a-a5d0-418b-8ea3-211fd4a891b6', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428', 'active', NULL, '2026-03-15T17:52:46.699745+00:00', '{"id":"05fd512a-a5d0-418b-8ea3-211fd4a891b6","title":"Informationen zur Verarbeitung personenbezogener Daten","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Zu den Aufgaben des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ) gehört es unter anderem, die Öffentlichkeit über seine Arbeit zu informieren. Dies umfasst die Bereitstellung von Informationen im Internet und in Sozialen Netzwerken, die direkte Kommunikation mit Bürgerinnen und Bürgern beziehungsweise der Fachöffentlichkeit, den Empfang von Besuchergruppen im Ministerium und die Organisation von Fachveranstaltungen. Sofern bei diesen Tätigkeiten personenbezogene Daten verarbeitet werden, geschieht dies auf Grundlage der rechtlichen Bestimmungen, insbesondere der Europäischen Datenschutz-Grundverordnung (EU DSGVO) und dem Bundesdatenschutzgesetz (BDSG). Personenbezogene Daten sind alle Informationen, die sich auf einen (lebenden) Menschen beziehen, der entweder bereits identifiziert ist oder der durch diese Informationen identifizierbar wird. Identifizierbarkeit kann entweder durch eine Zusammenführung der vorliegenden Informationen oder unter Einbeziehung von zusätzlichen Maßnahmen erfolgen, zum Beispiel der Zuordnung zu einer Namenskennung, einer Kennnummer, zu Standortdaten, einer Online-Kennung oder mittels einer Recherche in allgemein zugänglichen Informationspools wie Datenbanken, Bibliotheken oder dem Internet. Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend ]init[ AG (Auftragsverarbeiter für Hosting und Betrieb) Köpenicker Str. 9, 10997 Berlin TV1 GmbH, Beta-Straße 9a, 85774 Unterföhring (Auftragsverarbeiter für Video-Streaming)"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:46.699745+00:00","lastSeen":"2026-03-15T17:52:46.699745+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428","crawledAt":"2026-03-15T17:52:46.699745Z","crawlId":"contacts-seeded-1773597166","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"35eef7bab5852508814a3fcf9c251535a1a47d12ceaa034eef369a324f1d7d34"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:46.699745+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d0a55df4-ce90-4ece-a36e-667f406fd282', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/informationsfreiheitsgesetz-99434', 'active', NULL, '2026-03-15T17:52:47.173908+00:00', '{"id":"d0a55df4-ce90-4ece-a36e-667f406fd282","title":"Informationsfreiheitsgesetz","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Für die Behörden des Bundes gilt das Informationsfreiheitsgesetz (IFG). Danach hat jede Bürgerin und jeder Bürger einen voraussetzungslosen, wenn auch nicht ausnahmslosen Anspruch auf Zugang zu amtlichen Informationen gegenüber den Behörden des Bundes. Es liegt im eigenen Interesse von Antragstellern und Antragstellerinnen, den Antrag so bestimmt zu fassen, dass das Informationsbegehren klar erkennbar ist. Dem Informationsanspruch können Ausnahmegründe entgegenstehen. Das IFG schützt – mit unterschiedlichen Abwägungsmaßstäben – öffentliche Belange (§ 3 IFG), laufende Verfahren (§ 4 IFG), personenbezogene Daten (§ 5 IFG) sowie Betriebs- und Geschäftsgeheimnisse und das geistige Eigentum (§ 6 IFG). Die Informationen sollen Antragstellern innerhalb eines Monats zugänglich gemacht werden. Sofern es sich nicht um die Erteilung einer einfachen Auskunft handelt, werden für Amtshandlungen der Behörden (Bearbeitungsaufwand für die Antragsbearbeitung) nach dem IFG Gebühren und Auslagen erhoben (§ 10 IFG). Nähere Informationen hierzu finden Sie in der Verordnung über die Gebühren und Auslagen nach dem Informationsfreiheitsgesetz."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/informationsfreiheitsgesetz-99434","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:47.173908+00:00","lastSeen":"2026-03-15T17:52:47.173908+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/informationsfreiheitsgesetz-99434","crawledAt":"2026-03-15T17:52:47.173908Z","crawlId":"contacts-seeded-1773597167","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"96c55719b99f13f4532f5d257f3b7ca5048465b10bc4db7e7084ae5f10361154"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:47.173908+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7d721cd6-2d94-4983-b2aa-760004f692a1', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/inhalt-107174', 'active', NULL, '2026-03-15T17:52:47.694925+00:00', '{"id":"7d721cd6-2d94-4983-b2aa-760004f692a1","title":"Inhalt","summary":{"de":"Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."},"content":{"de":"Hier finden Sie die Inhalte der Website im Überblick: Themen Familie Familienleistungen Familie und Arbeitswelt Schwangerschaft und Kinderwunsch Chancen und Teilhabe für Familien Kinderbetreuung KiTa-Qualität Smarte Gesellschaftspolitik Nationaler Aktionsplan Kinderchancen Ältere Menschen Aktiv im Alter Hilfe und Pflege Zehn Jahre Pflegetelefon Vereinbarkeit von Pflege und Beruf Pflegeausbildung - Berufsfeld Pflege Demenz Letzte Wege Zuhause im Alter Internationale Politik für ältere Menschen Gleichstellung Wirtschaftliche Gleichstellung, Frauen und Arbeitswelt Lohngerechtigkeit Entgelttransparenzgesetz Frauen in Führungspositionen Jungen und Männer Frauen vor Gewalt schützen Prostituiertenschutzgesetz Aufwertung sozialer Berufe Gleichstellung und Teilhabe Gleichstellungsberichte der Bundesregierung Sexuelle und geschlechtliche Vielfalt Gender Care Gap Internationale Gleichstellungspolitik Digitaler Gleichstellungsatlas Feministische Digitalpolitik Kinder und Jugend Kinder- und Jugendschutz Schutz vor sexualisierter Gewalt Kinderrechte Kinderbetreuung KiTa-Qualität Jugendbildung Jugendstrategie Medienkompetenz Integration und Chancen für junge Menschen Kinder- und Jugendgesundheit Engagement und Gesellschaft Deutsche Stiftung für Engagement und Ehrenamt Demografischer Wandel und Nachhaltigkeit Engagement stärken Menschen stärken Menschen Beratung bei Auswanderung Mehrgenerationenhäuser Allianz gegen Einsamkeit Flüchtlingspolitik und Integration Freiwilligendienste Jugendfreiwilligendienste Bundesfreiwilligen