INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f14a702a-7667-47f4-b5d7-c8622c86af60', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/meta/en', 'active', NULL, '2026-03-15T17:52:55.244544+00:00', '{"id":"f14a702a-7667-47f4-b5d7-c8622c86af60","title":"Federal Ministry for Education, Family Affairs, Senior Citizens, Women and Youth","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Accept Decline"},"content":{"de":"Families Family is where people of different generations accept long-term responsibility for one another and in doing so, support and care for each other. Family is where people of different generations accept long-term responsibility for one another and in doing so, support and care for each other. Older Persons Policy-making for senior citizens means policy-making with them - they must be allowed to participate. Valuing their experience and life achievements and giving them more scope and influence makes society stronger. Policy-making for senior citizens means policy-making with them - they must be allowed to participate. Valuing their experience and life achievements and giving them more scope and influence makes society stronger. Equality Germany''s Grundgesetz (Basic Law) states that women and men are equal and that the state has to promote substantive, de facto gender equality. Germany is also committed to fulfilling its gender equality obligations under European law as well as international human rights law, for example by having ratified the UN Convention on the Elimination of All Forms of Discrimination against Women and its Optional Protocol. Germany''s Grundgesetz (Basic Law) states that women and men are equal and that the state has to promote substantive, de facto gender equality. Germany is also committed to fulfilling its gender equality obligations under European law as well as international human rights law, for example by having ratified the UN Convention on the Elimination of All Forms of Discrimination against Women and its Optional Protocol."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/en","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:55.244544+00:00","lastSeen":"2026-03-15T17:52:55.244544+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/en","crawledAt":"2026-03-15T17:52:55.244544Z","crawlId":"contacts-seeded-1773597175","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"94457891122f14214fb68464e2c1ccadf5ab794b0023da809551715c8f7387e2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:55.244544+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7e4d748c-49c0-4601-8a25-0b8c11bc7525', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/meta/gebaerdensprache', 'active', NULL, '2026-03-15T17:52:55.700764+00:00', '{"id":"7e4d748c-49c0-4601-8a25-0b8c11bc7525","title":"Deutsche Gebärdensprache","summary":{"de":"Arbeit und Aufgaben des Bundesfamilien­ministeriums gebaerdensprache-aufgaben Das Bundesfamilienministerium ist zuständig für die Politikbereiche \"Familie\", \"Ältere Menschen\"..."},"content":{"de":"Das Bundesfamilienministerium ist zuständig für die Politikbereiche \"Familie\", \"Ältere Menschen\", \"Gleichstellung\", \"Kinder und Jugend\" und \"Freiwilliges Engagement\". In diesem Video erklären wir Ihnen Arbeit und Aufgaben des Ministeriums."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/gebaerdensprache","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:55.700764+00:00","lastSeen":"2026-03-15T17:52:55.700764+00:00","sourceUnavailable":false,"contactType":"accessibility","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/gebaerdensprache","crawledAt":"2026-03-15T17:52:55.700764Z","crawlId":"contacts-seeded-1773597175","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"64b37ea700941608bbc6ef25dba2c4e0a6e9bd8b3494d185bc392ac8422ac947"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:55.700764+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=