INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('617cde29-09df-4af0-9ed4-633249109ae1', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/meta/leichte-sprache', 'active', NULL, '2026-03-15T17:52:56.290051+00:00', '{"id":"617cde29-09df-4af0-9ed4-633249109ae1","title":"Leichte Sprache","summary":{"de":"Herzlich willkommen auf der Internet-Seite vom Bundes-Ministerium für Bildung, Familie, Senioren, Frauen und Jugend Auf dieser Seite erklären wir Ihnen die Aufgaben vom Bundes-Ministerium. Und..."},"content":{"de":"Auf dieser Seite erklären wir Ihnen die Aufgaben vom Bundes-Ministerium. Und wir erklären Ihnen die Internet-Seite. Das Bundes-Ministerium gehört zur Bundes-Regierung. Ein wichtiges Thema vom Bundes-Ministerium sind Familien. Deshalb heißt das Ministerium auch kurz: Bundes-Familien-Ministerium. Wir machen zum Beispiel Vorschläge für Gesetze, damit Familien Geld bekommen. Und wir helfen Familien bei der Kinder-Erziehung. Ein anderes Thema vom Ministerium sind alte Menschen. Wir wollen, dass alte Menschen gut und sicher leben. Manchmal brauchen alte Menschen Hilfe von der Familie. Die Familie soll genug Zeit haben für alte Menschen. Zum Beispiel bei der Pflege. Wir setzen uns für Gleich-Stellung ein. Gleich-Stellung heißt: Männer und Frauen werden gleich behandelt. Und sie haben die gleichen Möglichkeiten. Frauen sollen für ihre Arbeit gleich viel Geld bekommen wie Männer. Und wir wollen Frauen vor Gewalt schützen. Viele Mütter und Väter arbeiten. Dann muss sich jemand um das Kind kümmern."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/leichte-sprache","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:56.290051+00:00","lastSeen":"2026-03-15T17:52:56.290051+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/meta/leichte-sprache","crawledAt":"2026-03-15T17:52:56.290051Z","crawlId":"contacts-seeded-1773597176","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"e60e9e79beda221f71fcf6c4437b0a0a96e1fb13538455b2b35dfefd92b04418"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:56.290051+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f36b1576-f6ba-4965-8ad5-444c135f735c', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/service/kontakt', 'active', NULL, '2026-03-15T16:06:47.369399+00:00', '{"id":"f36b1576-f6ba-4965-8ad5-444c135f735c","title":"Kontakt","summary":{"de":"Sie wollen mit dem Bundesministerium für Familie, Senioren, Frauen und Jugend in Kontakt treten? Die Kontaktdaten finden Sie hier."},"content":{"de":"Unter info[at]bmbfsfjservice.bund.de können Sie eine Nachricht an das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend senden. Postanschrift: Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend, 11018 Berlin Servicetelefon: 030 201 791 30 Montag bis Donnerstag von 9:00 bis 18:00 Uhr Für unser Serviceangebot wünschen wir uns ein respektvolles Miteinander. Deshalb weisen wir darauf hin, dass Gespräche insbesondere bei Beleidigungen, einer vulgären Wortwahl oder menschenverachtenden Aussagen umgehend beendet werden. Für allgemeine Fragen an alle Ämter und Behörden steht Ihnen auch die einheitliche Behördenrufnummer 115 zur Verfügung. In den teilnehmenden Regionen erreichen Sie die 115 von Montag bis Freitag zwischen 8.00 und 18.00 Uhr. Die 115 ist sowohl aus dem Festnetz als auch aus vielen Mobilfunknetzen zum Ortstarif und damit kostenlos über Flatrates erreichbar. Gehörlose haben die Möglichkeit, über www.gebaerdentelefon.de/115 Informationen zu erhalten. Ob in Ihrer Region die 115 erreichbar ist und weitere Informationen zur einheitlichen Behördenrufnummer finden Sie unter https://www.115.de Für die Behörden des Bundes gilt das Informationsfreiheitsgesetz (IFG). Danach hat jede Bürgerin und jeder Bürger einen voraussetzungslosen, wenn auch nicht ausnahmslosen Anspruch auf Zugang zu amtlichen Informationen gegenüber den Behörden des Bundes."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/service/kontakt","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:47.369399+00:00","lastSeen":"2026-03-15T16:06:47.369399+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/service/kontakt","crawledAt":"2026-03-15T16:06:47.369399Z","crawlId":"contacts-seeded-1773590807","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"6574dcd2315aca1a7925a2bf628478450b366a1a09cea2d7e0a2cb5361400eb0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:06:47.369926+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dae5525f-5d64-4b33-9337-82c4d9800182', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen', 'active', NULL, '2026-03-15T17:52:56.727959+00:00', '{"id":"dae5525f-5d64-4b33-9337-82c4d9800182","title":"Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bildung ist der Schlüssel zu gesellschaftlicher Teilhabe, sozialem Aufstieg, Fortschritt und persönlicher Freiheit. Indem wir uns für beste Bildung einsetzen, unterstützen wir Menschen dabei, Chancen zu erkennen und ihre Ziele und Träume zu verwirklichen. Familien darin zu unterstützen, ihr Leben nach den eigenen Vorstellungen gestalten zu können - das ist das Ziel einer guten Familienpolitik. Dafür brauchen Familien vor allem Zeit für Kinder und Beruf, finanzielle Stabilität und eine gute Kinderbetreuung. Auch im hohen Alter selbstbestimmt leben und an der Gesellschaft teilhaben - das wünschen sich die meisten Menschen. Sie dabei zu unterstützen, ist zentrales Ziel der Seniorenpolitik. Die Gleichstellung von Frauen und Männern ist eine der zentralen Herausforderungen, um das Leben in unserem Land zukunftsfähig und gerecht zu gestalten. Dafür müssen Frauen und Männer auf dem gesamten Lebensweg die gleichen Chancen erhalten – persönlich, beruflich und familiär. Alle Kinder und Jugendlichen haben ein Recht auf ein beschütztes Auf­wachsen und gleiche Chancen - unabhängig von Herkunft, Geschlecht, Religion oder dem sozialen Status. Chancengleichheit und der Schutz von Kindern und Jugendlichen ist daher ein zentrales Anliegen des Bundesjugendministeriums. Das Bundesfamilienministerium versteht sich als Partner der Zivilgesellschaft - auf Augenhöhe mit Millionen von freiwillig engagierten Bürgerinnen und Bürgern, Vereinen, Verbänden, Unternehmen und Stiftungen. Deshalb unterstützt es die starke Engagementlandschaft in Deutschland."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:56.727959+00:00","lastSeen":"2026-03-15T17:52:56.727959+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen","crawledAt":"2026-03-15T17:52:56.727959Z","crawlId":"contacts-seeded-1773597176","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5c8a852fa97b07ffeea2ec303b9313bf319b00b91fa62d452c32ec118a14a7fb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:56.727959+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b297ae2d-027c-40de-a124-6f78d70045a8', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen', 'active', NULL, '2026-03-15T17:52:57.289584+00:00', '{"id":"b297ae2d-027c-40de-a124-6f78d70045a8","title":"Politik für ältere Menschen","summary":{"de":"Selbstbestimmung und Teilhabe an der Gesellschaft auch im Alter - das ist zentrales Ziel der Seniorenpolitik des Bundesseniorenministeriums."},"content":{"de":"Eine neue Studie zeigt: Die große Mehrheit der über 65-Jährigen nutzt das Internet und wünscht sich mehr Tempo bei der Digitalisierung. Karin Prien und Bitkom-Präsident Ralf Wintergerst stellten die Ergebnisse am 15. Januar vor. Michael Brand hat sich in Köln mit dem Direktor des Zentrums für Palliativmedizin Prof. Dr. Raymond Voltz und Ärztin Dr. Birgit Weihrauch über neue Ansätze zur Betreuung und Begleitung schwerstkranker und sterbender Menschen ausgetauscht. Der Parlamentarische Staatssekretär Michael Brand spricht zum Bundeshaushalt 2026 im Bundestag und betont, wie wichtig gezielte und strukturelle Reformen für bessere Bildung, starke Familien und eine resiliente Demokratie sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:57.289584+00:00","lastSeen":"2026-03-15T17:52:57.289584+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen","crawledAt":"2026-03-15T17:52:57.289584Z","crawlId":"contacts-seeded-1773597177","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"2c0d5a25b11896c444b90d2f2a106243c785544205b0ab947a6214b0a35478e2"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:57.289584+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0fc0ca06-92db-484e-a9d7-e256ae36f765', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter', 'active', NULL, '2026-03-15T17:52:57.764629+00:00', '{"id":"0fc0ca06-92db-484e-a9d7-e256ae36f765","title":"Aktiv im Alter","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bildung und Digitalisierung im Alter Bildung und digitale Kompetenzen sind für ältere Menschen eine wichtige Voraussetzung, um aktiv und selbstbestimmt am gesellschaftlichen Leben teilzuhaben. Das Bundesseniorenministerium unterstützt sie dabei. Bildung und digitale Kompetenzen sind für ältere Menschen eine wichtige Voraussetzung, um aktiv und selbstbestimmt am gesellschaftlichen Leben teilzuhaben. Das Bundesseniorenministerium unterstützt sie dabei. Allianz gegen Einsamkeit Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung wirksam zu begegnen - zum Beispiel mit Orten, an die sich einsame Menschen wenden können. Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung wirksam zu begegnen - zum Beispiel mit Orten, an die sich einsame Menschen wenden können. Altersberichte Seit 1993 erscheint in jeder Legislaturperiode ein Altersbericht zu einem seniorenpolitischen Thema. Die Altersberichte sind wichtige Entscheidungsgrundlage für die Seniorenpolitik des Bundes. Seit 1993 erscheint in jeder Legislaturperiode ein Altersbericht zu einem seniorenpolitischen Thema. Die Altersberichte sind wichtige Entscheidungsgrundlage für die Seniorenpolitik des Bundes."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:57.764629+00:00","lastSeen":"2026-03-15T17:52:57.764629+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/aktiv-im-alter","crawledAt":"2026-03-15T17:52:57.764629Z","crawlId":"contacts-seeded-1773597177","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"520d6e86e064b2b1ec02aecb4900fa0d8648b57297a5c3a584336e5d83355727"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:57.764629+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f29987ee-d183-40d8-9d14-e786edc555e3', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege', 'active', NULL, '2026-03-15T17:52:58.225278+00:00', '{"id":"f29987ee-d183-40d8-9d14-e786edc555e3","title":"Pflegeausbildung","summary":{"de":"Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der..."},"content":{"de":"Ausbildung zur Pflegefachperson Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Eckpunkte für eine neue bundeseinheitliche Pflegeassistenzausbildung Eine neue bundeseinheitliche Pflegeassistenzausbildung soll die Ausbildung attraktiver machen und einen effektiven Qualifikationsmix in der Pflege unterstützen. Eine neue bundeseinheitliche Pflegeassistenzausbildung soll die Ausbildung attraktiver machen und einen effektiven Qualifikationsmix in der Pflege unterstützen. Ausbildungsoffensive Pflege Um die Einführung der neuen Pflegeausbildungen nach dem Pflegeberufegesetz zu unterstützen, hat das Bundesfamilienministerium gemeinsam mit dem Bundesgesundheitsministerium und dem Bundesarbeitsministerium eine Ausbildungsoffensive gestartet. Um die Einführung der neuen Pflegeausbildungen nach dem Pflegeberufegesetz zu unterstützen, hat das Bundesfamilienministerium gemeinsam mit dem Bundesgesundheitsministerium und dem Bundesarbeitsministerium eine Ausbildungsoffensive gestartet."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:58.225278+00:00","lastSeen":"2026-03-15T17:52:58.225278+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege","crawledAt":"2026-03-15T17:52:58.225278Z","crawlId":"contacts-seeded-1773597178","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"8ea4ec2ccafdbb598c5d8d89b4f2d3bdbfd72be9a6d830d619e2a2e89a08b87c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:58.225278+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('42afcce6-a9df-44dd-9af8-6f709a32584e', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen', 'active', NULL, '2026-03-15T17:52:58.721708+00:00', '{"id":"42afcce6-a9df-44dd-9af8-6f709a32584e","title":"Ausbildung zur Pflegefachperson","summary":{"de":"Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller..."},"content":{"de":"Seit dem 1. Januar 2020 gibt es die neue Pflegeausbildung. Damit wird die Ausbildung zur Pflegefachperson moderner und attraktiver. Die generalistische Ausbildung befähigt dazu, Menschen aller Altersgruppen in allen Versorgungsbereichen zu pflegen. Das Pflegeberufegesetz führt die bisherigen Berufsausbildungen der Altenpflege, der Gesundheits- und Krankenpflege und der Gesundheits- und Kinderkrankenpflege zusammen. Am 1. Januar 2020 ist die Pflegeausbildung zur Pflegefachperson gestartet. Sie ermöglicht es, in allen Versorgungsbereichen zu arbeiten. Damit werden die Ausbildungsbedingungen verbessert und die Attraktivität des Berufsfeldes Pflege wird gesteigert. Für die Ausbildung muss nun kein Schulgeld mehr bezahlt werden, die Auszubildenden erhalten eine angemessene Ausbildungsvergütung. Außerdem ist eine Ausbildung an einer Hochschule mit Bachelor-Niveau möglich. Damit wird die Pflegeausbildung attraktiver und neue Zielgruppen werden für die Pflege angesprochen. Mit dem Pflegeberufegesetz werden erstmals bestimmte berufliche Tätigkeiten festgelegt, die nur den Pflegefachpersonen vorbehalten sind. Der Pflegeberuf wird durch zusätzliche Einsatz- und Aufstiegsmöglichkeiten aufgewertet. Zum ersten Mal ist auch langfristig eine verbindliche Regelung vorgesehen, die Ausbildungskosten bei Umschulungsmaßnahmen vollständig zu finanzieren. Alle Auszubildenden starten mit dem Berufsziel \"Pflegefachperson\". Das ist im Ausbildungsvertrag mit dem Träger der praktischen Ausbildung festgelegt. Neben dem generalistischen Berufsabschluss nach drei Jahren in Vollzeitform beziehungsweise bis zu fünf Jahren in Teilzeitform können Auszubildende auch einen gesonderten Abschluss erlangen - als \"Altenpflegerin\" oder \"Altenpfleger\", als \"Gesundheits- und Kinderkrankenpfleger\" beziehungsweise \"Gesundheits- und Kinderkrankenpflegerin\". Die Möglichkeit, nach zwei Dritteln der Ausbildung einen gesonderten Abschluss zu wählen, haben die Auszubildenden, die zu Beginn ihrer Ausbildung einen Vertiefungseinsatz in der Altenpflege oder Kinderkrankenpflege gewählt haben. Mit dem Pflegeberufegesetz wird ein Pflegestudium zur unmittelbaren Berufsqualifizierung mit erweitertem Ausbildungsziel eingeführt. Die Berufsbezeichnung \"Pflegefachperson\" wird in Verbindung mit dem akademischen Grad (zum Beispiel \"B.Sc.\") geführt. Die mit dem Pflegestudiumstärkungsgesetz eingeführte Ausbildungsvergütung für Studierende erhöht die Attraktivität einer hochschulischen Pflegeausbildung zusätzlich."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:58.721708+00:00","lastSeen":"2026-03-15T17:52:58.721708+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/berufsfeld-pflege/neue-pflegeausbildungen","crawledAt":"2026-03-15T17:52:58.721708Z","crawlId":"contacts-seeded-1773597178","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5ed1bdc8af236aa8deea247068eea027ae26944a5fe84b068d34f18053daad75"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:58.721708+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ce9fa327-6ef1-453a-a4c3-f787b8c998ab', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz', 'active', NULL, '2026-03-15T17:52:59.211043+00:00', '{"id":"ce9fa327-6ef1-453a-a4c3-f787b8c998ab","title":"Demenz","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Informationen rund um Demenz Wegweiser Demenz, Alzheimer Telefon, Lokale Allianzen: Mit einem Wissens- und Hilfenetzwerk unterstützt das Bundesseniorenministerium Menschen mit Demenz und ihre Angehörigen. Wegweiser Demenz, Alzheimer Telefon, Lokale Allianzen: Mit einem Wissens- und Hilfenetzwerk unterstützt das Bundesseniorenministerium Menschen mit Demenz und ihre Angehörigen. Nationale Demenzstrategie Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern. Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern. Lokale Allianzen für Menschen mit Demenz Lokale Allianzen für Menschen mit Demenz sind Hilfe- und Unterstützungsnetzwerke mit Angeboten für Menschen mit Demenz und ihre Angehörigen. Das Bundesseniorenministerium fördert die Allianzen mit einem Bundesprogramm. Lokale Allianzen für Menschen mit Demenz sind Hilfe- und Unterstützungsnetzwerke mit Angeboten für Menschen mit Demenz und ihre Angehörigen. Das Bundesseniorenministerium fördert die Allianzen mit einem Bundesprogramm."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:59.211043+00:00","lastSeen":"2026-03-15T17:52:59.211043+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz","crawledAt":"2026-03-15T17:52:59.211043Z","crawlId":"contacts-seeded-1773597179","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"6b2aa1ac1edfc346832f886a187c8b6be4541727db5bf889489af5c92444ef70"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:59.211043+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('1d51ee00-ebf8-4c7d-ae17-d3d67025a769', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie', 'active', NULL, '2026-03-15T17:52:59.707891+00:00', '{"id":"1d51ee00-ebf8-4c7d-ae17-d3d67025a769","title":"Nationale Demenzstrategie","summary":{"de":"Mit der Nationalen Demenzstrategie setzt sich die Bundesregierung gemeinsam mit Partnerinnen und Partnern dafür ein, die Lebenssituation für Menschen mit Demenz und ihre Angehörigen zu verbessern."},"content":{"de":"In Deutschland leben rund 1,8 Millionen Menschen mit einer Demenz. Bis zum Jahr 2050 wird die Zahl der Betroffenen voraussichtlich auf 2,8 Millionen steigen. Um dieser Herausforderung zu begegnen und um die Gesellschaft demenzfreundlich zu gestalten, hat die Bundesregierung die Nationale Demenzstrategie verabschiedet. Die Umsetzung hat am 23. September 2020 begonnen. Ziel der Strategie ist, die Lebenssituation von Menschen mit Demenz und ihren Angehörigen in Deutschland zu verbessern und ein offenes Klima für den Umgang mit Betroffenen zu schaffen. Dafür enthält die Nationale Demenzstrategie über 160 konkrete Maßnahmen, die in den kommenden Jahren umgesetzt werden sollen. Die Strategie definiert dafür vier Handlungsfelder: Strukturen zur gesellschaftlichen Teilhabe von Menschen mit Demenz an ihrem Lebensort aus- und aufbauen Menschen mit Demenz und ihre Angehörigen unterstützen Medizinische und pflegerische Versorgung von Menschen mit Demenz weiterentwickeln"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:52:59.707891+00:00","lastSeen":"2026-03-15T17:52:59.707891+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/demenz/nationale-demenzstrategie","crawledAt":"2026-03-15T17:52:59.707891Z","crawlId":"contacts-seeded-1773597179","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0271e6bbf3419f4f5ab1478b7a3d6449a8473eecaafef9b61e48e1fc95749507"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:52:59.707891+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ccaef8ec-2faa-4fdf-a604-6ffa77ecdd45', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen', 'active', NULL, '2026-03-15T17:53:00.219402+00:00', '{"id":"ccaef8ec-2faa-4fdf-a604-6ffa77ecdd45","title":"Internationale Politik für ältere Menschen","summary":{"de":"Der Anteil älterer Menschen an der Bevölkerung steigt weltweit. Das Bundesseniorenministerium setzt sich für ihre Belange, Rechte und gleichberechtigte Teilhabe ein - auch international. Das..."},"content":{"de":"Der Anteil älterer Menschen an der Bevölkerung steigt weltweit. Das Bundesseniorenministerium setzt sich für ihre Belange, Rechte und gleichberechtigte Teilhabe ein - auch international. Das stärkt den Zusammenhalt über Generationen und Länder hinweg. Die Menschen werden bei guter Gesundheit immer älter. In internationalen Gremien setzt sich die Bundesrepublik Deutschland für die Stärkung der Rechte Älterer ein - bei den Vereinten Nationen (VN), im Europarat, in der Europäischen Union (EU) und im direkten Erfahrungsaustausch mit Partnerstaaten. Insbesondere der fachliche Austausch mit Frankreich, Polen und Japan stellen hier Schwerpunkte dar. Die offene Arbeitsgruppe Altern (Open-Ended Working Group on Ageing - OEWGA) der VN befasste sich in 14 Sitzungen mit der Stärkung der Rechte älterer Menschen. Im Rahmen der jährlich stattfindenden Sitzungen in New York wurden in einer offenen Debatte wichtige Themenbereiche beleuchtet und mögliche Schutzlücken diskutiert. Am 23. Mai 2024 hat die OEWGA in einer Abschlussempfehlung 14 Bereiche für potentielle Lücken im internationalen Menschenrechtsschutz älterer Menschen identifiziert und elf Handlungsoptionen, wie diesen begegnet werden kann, vorgeschlagen. Die VN-Generalversammlung hat am 13. August 2024 das Mandat der OEWGA für erfüllt erklärt und die Arbeit der OEWGA mit einer Entschließung am 20. Dezember beendet. Alle einschlägigen VN-Gremien sind aufgefordert, sich mit den Empfehlungen der OEWGA zu befassen. Am 8. Mai 2025 wird ein hochrangiges Treffen entscheiden, welcher Nachfolgeprozess international aufgesetzt wird. In der Zwischenzeit hat der Menschenrechtsrat am 3. April 2025 die Einsetzung einer intergouvernementalen Arbeitsgruppe beschlossen, die einen Entwurf für ein rechtlich bindendes Instrument zum Schutz der Menschenrechte Älterer erarbeiten soll. Der Zweite Weltaltenplan der VN wurde im Jahr 2002 in Madrid beschlossen ( Madrid International Plan of Action on Ageing - MIPAA ). Dieser politische Aktionsplan wird von den Mitgliedsstaaten mit Hilfe von nationalen Aktionsplänen, die auf regionalen Implementierungsstrategien basieren, umgesetzt. Alle fünf Jahre informiert ein Nationaler Bericht über den Stand der Umsetzung des Weltaltenplans. Der letzte Bericht wurde 2021 unter Federführung des Bundesseniorenministeriums erstellt. Für die Umsetzung des Zweiten Weltaltenplans auf europäischer Ebene ist die Regionalkommission UNECE (United Nations Economic Commission for Europe) verantwortlich. Die zugehörige ständige Arbeitsgruppe Altern (UNECE - Standing Working Group on Ageing - UNECE-SWGA) hält alle fünf Jahre eine Ministerkonferenz ab, um europäische Lösungen zu entwickeln."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:00.219402+00:00","lastSeen":"2026-03-15T17:53:00.219402+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/internationale-politik-fuer-aeltere-menschen","crawledAt":"2026-03-15T17:53:00.219402Z","crawlId":"contacts-seeded-1773597180","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0e79177d210264ee341c215e290b9e0c45ff0b5e5b6c90fb77df5298f3b749fa"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:00.219402+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0087b780-ed4f-42d8-aef9-66c7c9c42506', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege', 'active', NULL, '2026-03-15T17:53:00.751177+00:00', '{"id":"0087b780-ed4f-42d8-aef9-66c7c9c42506","title":"Letzte Wege - Begleitung am Lebensende","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Diagnose einer lebensbedrohlichen Erkrankung ändert alles. Unsicherheit, Trauer und Angst schleichen sich schnell auch in das Leben von Angehörigen. Das Bundesfamilienministerium fördert Projekte der Hospiz-und Palliativversorgung, um Sterbenden und deren Angehörigen beizustehen und sie gut zu unterstützen. Nana starb 2012 an Knochenkrebs. 15 Monate lang wurde sie von ihrer Familie in der Krankheit und zum Schluss auch im Sterben begleitet. Ihre Mutter, Barbara Stäcker, spricht im Interview über das, was in dieser Zeit wichtig war. Ihre Tochter Nana starb mit nur 21 Jahren an Krebs. Sie und Ihre Familie sind den Weg mit ihr gemeinsam gegangen. Was hat Ihnen allen in dieser Zeit besonders geholfen? BARBARA STÄCKER: Für Nana war am wichtigsten, dass sie ihre ganze Familie um sich hatte. Wir waren damals zu sechst im Haus: Nana und ihr Freund, unser Sohn mit seiner Freundin und wir Eltern. Damit hat man ganz automatisch eine gewisse Normalität im Alltag, die wir bis zum Schluss aufrechterhalten konnten. Jeder von uns ist sehr unterschiedlich mit Nana umgegangen und daher konnten wir ganz individuell auf ihre Bedürfnisse eingehen. Was war für Nana in dieser Zeit besonders wichtig? Ihr hat es viel bedeutet, dass sie ihre Ressourcen in dieser Zeit nutzen konnte. Wir haben kurze Ausflüge gemacht, wenn es ihr gut genug ging. Wir sind spontan alle zusammen in den Urlaub gefahren. Sie hat in dieser Zeit ihr Schmink- und Fotoprojekt \"Recover your Smile\" ins Leben gerufen. Am wichtigsten war ihr aber, dass wir offen und ehrlich miteinander umgegangen sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:00.751177+00:00","lastSeen":"2026-03-15T17:53:00.751177+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/letzte-wege","crawledAt":"2026-03-15T17:53:00.751177Z","crawlId":"contacts-seeded-1773597180","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"ca2e5b7aef363ef734bbe26c02aebd71d325d20f0160cbcc0095e858caa3c859"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:00.751177+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5969c401-7b59-41d8-a532-4f16dbdb5c93', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf', 'active', NULL, '2026-03-15T17:53:01.227351+00:00', '{"id":"5969c401-7b59-41d8-a532-4f16dbdb5c93","title":"Vereinbarkeit von Pflege und Beruf","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Pflegetelefon Das Pflegetelefon des Bundesfamilienministeriums bietet Hilfe und Beratung. Es ist bundesweit von Montag bis Donnerstag derzeit zwischen 9:00 und 16:00 Uhr und per E-Mail: info@wege-zur-pflege.de erreichbar. Das Pflegetelefon des Bundesfamilienministeriums bietet Hilfe und Beratung. Es ist bundesweit von Montag bis Donnerstag derzeit zwischen 9:00 und 16:00 Uhr und per E-Mail: info@wege-zur-pflege.de erreichbar. Beirat für die Vereinbarkeit von Pflege und Beruf Der Unabhängige Beirat für die Vereinbarkeit von Pflege und Beruf besteht aus 21 Mitgliedern und befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Der Unabhängige Beirat für die Vereinbarkeit von Pflege und Beruf besteht aus 21 Mitgliedern und befasst sich ehrenamtlich mit Fragen der Vereinbarkeit von Pflege und Beruf und ihrer gesetzlichen Umsetzung. Familienpflegezeit Die Familienpflegezeit unterstützt Angehörige bei der Vereinbarkeit von Pflege und Beruf. Beschäftigte können sich für die Pflege eines nahen Angehörigen bis zu 24 Monate teilweise von der Arbeit freistellen lassen. Die Familienpflegezeit unterstützt Angehörige bei der Vereinbarkeit von Pflege und Beruf. Beschäftigte können sich für die Pflege eines nahen Angehörigen bis zu 24 Monate teilweise von der Arbeit freistellen lassen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:01.227351+00:00","lastSeen":"2026-03-15T17:53:01.227351+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/vereinbarkeit-von-pflege-und-beruf","crawledAt":"2026-03-15T17:53:01.227351Z","crawlId":"contacts-seeded-1773597181","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"7fb43fb67300e845c1034961ea0a6cda6512ce5a80e131bf73347530a0ab8f5c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:01.227351+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b51301b8-85e0-4148-b65f-8304dbc92745', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter', 'active', NULL, '2026-03-15T17:53:01.718092+00:00', '{"id":"b51301b8-85e0-4148-b65f-8304dbc92745","title":"Zuhause im Alter","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Sicherheit im Alter In gemeinsamen Projekten haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei Konzepte erarbeitet, wie ältere Menschen besser vor Eigentums- und Vermögensdelikten oder gewalttätigen Übergriffen geschützt werden können. In gemeinsamen Projekten haben das Bundesseniorenministerium und die Deutsche Hochschule der Polizei Konzepte erarbeitet, wie ältere Menschen besser vor Eigentums- und Vermögensdelikten oder gewalttätigen Übergriffen geschützt werden können. Serviceportal \"Zuhause im Alter\" Das Serviceportal bietet Informationen und Hinweise zum Thema selbstständiges und selbstbestimmtes Wohnen im Alter. Das Serviceportal bietet Informationen und Hinweise zum Thema selbstständiges und selbstbestimmtes Wohnen im Alter. Eine neue Studie zeigt: Die große Mehrheit der über 65-Jährigen nutzt das Internet und wünscht sich mehr Tempo bei der Digitalisierung. Karin Prien und Bitkom-Präsident Ralf Wintergerst stellten die Ergebnisse am 15. Januar vor. Das Projekt \"Digitaler Engel\" des Vereins Deutschland sicher im Netz e. V. bietet digitale Aufklärung für ältere Menschen. Es wurde bei den European Digital Skills Awards 2025 in Brüssel in der Kategorie \"Cybersecurity Skills\" ausgezeichnet."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:01.718092+00:00","lastSeen":"2026-03-15T17:53:01.718092+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/aeltere-menschen/zuhause-im-alter","crawledAt":"2026-03-15T17:53:01.718092Z","crawlId":"contacts-seeded-1773597181","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b6d455b1602fc26f2558bfd4c1a15cd2e2860c146348b08b5461b651498151dd"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:01.718092+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7fd5397b-309e-414b-8929-3745af67bf78', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung', 'active', NULL, '2026-03-15T17:53:02.220246+00:00', '{"id":"7fd5397b-309e-414b-8929-3745af67bf78","title":"Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Bundesbildungsministerin Karin Prien hat die Qualifizierungsoffensive Berufliche Bildung gestartet. Die Initiative soll dem Fachkräftemangel begegnen und die Ausbildung entlang der gesamten Bildungskette stärken. Für einen besseren Jugendmedienschutz ist die Kooperation der Online-Plattformen wichtig. Das betonte Dr. Petra Bahr, Staatssekretärin im Bundesjugendministerium, bei einem Austausch mit Vertretern der Unternehmen und Verbände. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:02.220246+00:00","lastSeen":"2026-03-15T17:53:02.220246+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung","crawledAt":"2026-03-15T17:53:02.220246Z","crawlId":"contacts-seeded-1773597182","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"8e0f40a143d44347caafede74962ba2dd5bb99120904f771e73cd5c94826df61"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:02.220246+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0ed7d462-58e1-46aa-a21a-12ff4514a55f', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung', 'active', NULL, '2026-03-15T17:53:02.730641+00:00', '{"id":"0ed7d462-58e1-46aa-a21a-12ff4514a55f","title":"Ausbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Ausbildung Wichtige praktische Berufserfahrungen und strukturiertes Lernen: Die duale Ausbildung bereitet junge Menschen perfekt auf ihre berufliche Karriere vor. Nebenbei sichert sie Fachkräfte für die Betriebe in Deutschland. Wichtige praktische Berufserfahrungen und strukturiertes Lernen: Die duale Ausbildung bereitet junge Menschen perfekt auf ihre berufliche Karriere vor. Nebenbei sichert sie Fachkräfte für die Betriebe in Deutschland. Berufliche Orientierung Stärken erkunden, Berufe ausprobieren: Berufliche Orientierung unterstützt junge Menschen mit vielfältigen Angeboten bei der Wahl ihres beruflichen Weges und stärkt so Teilhabe und Fachkräftesicherung. Stärken erkunden, Berufe ausprobieren: Berufliche Orientierung unterstützt junge Menschen mit vielfältigen Angeboten bei der Wahl ihres beruflichen Weges und stärkt so Teilhabe und Fachkräftesicherung. Auszubildende Während ihrer Ausbildung haben junge Menschen die Möglichkeit, konkrete praktische Erfahrungen mit theoretischem Wissen aus der Berufsschule zu verknüpfen. Auszubildende erhalten somit den idealen Start in die berufliche Karriere. Während ihrer Ausbildung haben junge Menschen die Möglichkeit, konkrete praktische Erfahrungen mit theoretischem Wissen aus der Berufsschule zu verknüpfen. Auszubildende erhalten somit den idealen Start in die berufliche Karriere."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:02.730641+00:00","lastSeen":"2026-03-15T17:53:02.730641+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausbildung","crawledAt":"2026-03-15T17:53:02.730641Z","crawlId":"contacts-seeded-1773597182","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"6773a46ab6180748f241031446ac26634b1ae0013ddfc61973c3012c09810800"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:02.730641+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('961c018c-4980-477b-aab4-fa7133887549', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung', 'active', NULL, '2026-03-15T17:53:03.208919+00:00', '{"id":"961c018c-4980-477b-aab4-fa7133887549","title":"Außerschulische Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Außerschulische Bildung Von der Kita bis ins hohe Alter: Menschen bilden sich auch außerhalb der Schule weiter. Deshalb fördert das Bundesbildungsministerium unterschiedliche Programme, um Menschen die Möglichkeit zu geben, sich frei entfalten zu können. Von der Kita bis ins hohe Alter: Menschen bilden sich auch außerhalb der Schule weiter. Deshalb fördert das Bundesbildungsministerium unterschiedliche Programme, um Menschen die Möglichkeit zu geben, sich frei entfalten zu können. MINT-Bildung Die Ausbildung in einem MINT-Fach vermittelt zukunftsorientiertes Wissen für naturwissenschaftliche und technologische Zusammenhänge. Der MINT-Aktionsplan soll vor allem junge Menschen für MINT-Bildung begeistern. Die Ausbildung in einem MINT-Fach vermittelt zukunftsorientiertes Wissen für naturwissenschaftliche und technologische Zusammenhänge. Der MINT-Aktionsplan soll vor allem junge Menschen für MINT-Bildung begeistern. Stiftung Kinder forschen Wieso, weshalb, warum: Kinder sind neugierig und wollen die Welt mit allen Sinnen begreifen. Durch Bildung in den Bereichen Mathematik, Informatik, Naturwissenschaften und Technik (MINT) lernen Kinder, die Welt nachhaltig mitzugestalten. Wieso, weshalb, warum: Kinder sind neugierig und wollen die Welt mit allen Sinnen begreifen. Durch Bildung in den Bereichen Mathematik, Informatik, Naturwissenschaften und Technik (MINT) lernen Kinder, die Welt nachhaltig mitzugestalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:03.208919+00:00","lastSeen":"2026-03-15T17:53:03.208919+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/ausserschulische-bildung","crawledAt":"2026-03-15T17:53:03.208919Z","crawlId":"contacts-seeded-1773597183","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"75c7b5ce8a9a8699f743f43cf0677f874ea4e2c7921f9ce4e837bad009bbfbe7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:03.208919+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d3038620-c498-40d3-a3b6-66f223aec86b', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung', 'active', NULL, '2026-03-15T17:53:03.775774+00:00', '{"id":"d3038620-c498-40d3-a3b6-66f223aec86b","title":"Berufliche Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Beruflicher Erfolg wird praktisch erlebbar Moderne Rahmenbedingungen machen Berufsbildung attraktiv. Das Bundesbildungsministerium entwickelt Ausbildungsberufe weiter und gestaltet sie zukunftssicher, nachhaltig und digital. Moderne Rahmenbedingungen machen Berufsbildung attraktiv. Das Bundesbildungsministerium entwickelt Ausbildungsberufe weiter und gestaltet sie zukunftssicher, nachhaltig und digital. Anerkennung ausländischer Berufsqualifikationen Der Fachkräftemangel ist eine unserer größten Herausforderungen. Wir konkurrieren international um Fachkräfte. Unser Ziel: Ausländische Fachkräfte sollen ihre Fähigkeiten noch einfacher im Arbeitsmarkt einsetzen können. Der Fachkräftemangel ist eine unserer größten Herausforderungen. Wir konkurrieren international um Fachkräfte. Unser Ziel: Ausländische Fachkräfte sollen ihre Fähigkeiten noch einfacher im Arbeitsmarkt einsetzen können. Teilqualifikationen An- oder ungelernte Menschen können mit Teilqualifikationen einen Berufsabschluss erlangen. Das Bundesbildungsministerium fördert den Ausbau dieses Instruments zur Fachkräftesicherung, damit mehr Menschen eine berufliche Perspektive erhalten. An- oder ungelernte Menschen können mit Teilqualifikationen einen Berufsabschluss erlangen. Das Bundesbildungsministerium fördert den Ausbau dieses Instruments zur Fachkräftesicherung, damit mehr Menschen eine berufliche Perspektive erhalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:03.775774+00:00","lastSeen":"2026-03-15T17:53:03.775774+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/berufliche-bildung","crawledAt":"2026-03-15T17:53:03.776774Z","crawlId":"contacts-seeded-1773597183","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f3685ec34be9ef29ec41dd0d453b9120c66262cbabe3c9355b89ad2cc81460ee"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:03.776774+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('df19cb3f-f1b4-40e1-ab73-076b3bd3cd10', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung', 'active', NULL, '2026-03-15T17:53:04.219164+00:00', '{"id":"df19cb3f-f1b4-40e1-ab73-076b3bd3cd10","title":"Bildungsforschung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Bildungsforschung beschäftigt sich mit den Voraussetzungen, die es braucht, damit alle Menschen in Deutschland die beste Bildung erhalten. Bildungsforschende untersuchen hierbei fortlaufend die Stärken und Schwächen unseres Bildungssystems. Wie ermöglichen wir die beste Bildung für alle in Deutschland lebenden Menschen? Zur Beantwortung dieser Frage liefert die Bildungsforschung wichtige Erkenntnisse. Ob gleiche Chancen für alle, bessere Bildung oder Innovationen beim Lernen und Lehren: Bildungsforschung hilft, das Bildungssystem in Deutschland zu verbessern. Bildungsforschung trägt dazu bei, Ungleichheiten im Bildungssystem aufzuzeigen und wirksame Gegenstrategien zu entwickeln - damit alle Menschen gleiche Bildungschancen erhalten. Bildungsforschende werten fortlaufend die Stärken und Schwächen des Bildungswesens aus. Auf der Grundlage ihrer Erkenntnisse entstehen gezielte Maßnahmen zur Verbesserung der Qualität. Bildungsforschende liefern stichhaltige Daten und Erkenntnisse im Hinblick darauf, was oder wie wir lernen und welche Fähigkeiten wir in Zukunft brauchen. Fachleute aus Politik, Bildung und Verwaltung erhalten dadurch eine wissenschaftliche Grundlage, um Bildungsangebote an die Bedürfnisse der Bevölkerung anzupassen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:04.219164+00:00","lastSeen":"2026-03-15T17:53:04.219164+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/bildungsforschung","crawledAt":"2026-03-15T17:53:04.219164Z","crawlId":"contacts-seeded-1773597184","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"e6aea29ac447fba75208332a477ea32fbee7574edbecb249f91eaca15f8b5226"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:04.219164+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('12e4c704-9514-4f10-afe4-46c47788f70a', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung', 'active', NULL, '2026-03-15T17:53:04.708518+00:00', '{"id":"12e4c704-9514-4f10-afe4-46c47788f70a","title":"Frühe Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Frühe Bildung Die frühe Bildung fördert Kinder in den ersten Lebensjahren und gibt ihnen die bestmöglichen Chancen für ihre spätere schulische und persönliche Entwicklung. Die frühe Bildung fördert Kinder in den ersten Lebensjahren und gibt ihnen die bestmöglichen Chancen für ihre spätere schulische und persönliche Entwicklung. Sprachliche Bildung Eine gute sprachliche Entwicklung stärkt Lernen, Austausch und Teilhabe an der Gesellschaft. Gezielte frühe sprachliche Förderung ermöglicht es Kindern, sich sicher mitzuteilen und Bildungswege erfolgreich zu gestalten. Eine gute sprachliche Entwicklung stärkt Lernen, Austausch und Teilhabe an der Gesellschaft. Gezielte frühe sprachliche Förderung ermöglicht es Kindern, sich sicher mitzuteilen und Bildungswege erfolgreich zu gestalten. Bildung für nachhaltige Entwicklung Bildung für nachhaltige Entwicklung (BNE) befähigt Menschen zu zukunftsfähigem Denken und Handeln. Sie vermittelt früh Kompetenzen, um ökologische, soziale und wirtschaftliche Zusammenhänge aktiv zu verstehen und nachhaltig mitzugestalten. Bildung für nachhaltige Entwicklung (BNE) befähigt Menschen zu zukunftsfähigem Denken und Handeln. Sie vermittelt früh Kompetenzen, um ökologische, soziale und wirtschaftliche Zusammenhänge aktiv zu verstehen und nachhaltig mitzugestalten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:04.708518+00:00","lastSeen":"2026-03-15T17:53:04.708518+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/fruehe-bildung","crawledAt":"2026-03-15T17:53:04.708518Z","crawlId":"contacts-seeded-1773597184","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"a216e7bfd7291d04b999c35292b9f1a8c20dbbaba5cf24e9c664f2ea3e5b10c7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:04.708518+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7e507fdf-ba59-41e4-ae3b-02417f9df270', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung', 'active', NULL, '2026-03-15T17:53:05.215050+00:00', '{"id":"7e507fdf-ba59-41e4-ae3b-02417f9df270","title":"Integration durch Bildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Inklusive Bildung Inklusive Bildung bedeutet, dass Menschen mit unterschiedlichen Lern- und Leistungsvoraussetzungen gemeinsam und gleichberechtigt lernen. Sie bildet die Grundlage für die persönliche Entwicklung und soziale Teilhabe aller Lernenden. Inklusive Bildung bedeutet, dass Menschen mit unterschiedlichen Lern- und Leistungsvoraussetzungen gemeinsam und gleichberechtigt lernen. Sie bildet die Grundlage für die persönliche Entwicklung und soziale Teilhabe aller Lernenden. Informationen für Geflüchtete Wer als Geflüchtete oder Geflüchteter nach Deutschland kommt, hat viele Fragen. Auf dieser Seite finden Sie einen ersten Überblick sowie hilfreiche Informationen zu bildungsspezifischen Unterstützungsangeboten in verschiedenen Sprachen. Wer als Geflüchtete oder Geflüchteter nach Deutschland kommt, hat viele Fragen. Auf dieser Seite finden Sie einen ersten Überblick sowie hilfreiche Informationen zu bildungsspezifischen Unterstützungsangeboten in verschiedenen Sprachen. Bildung für alle in der Einwanderungsgesellschaft Bildung ist der Schlüssel für Integration und Teilhabe. Als Gesellschaft profitieren wir, wenn alle ihre Talente und Fähigkeiten bestmöglich entwickeln und einbringen können. Bildung ist der Schlüssel für Integration und Teilhabe. Als Gesellschaft profitieren wir, wenn alle ihre Talente und Fähigkeiten bestmöglich entwickeln und einbringen können."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:05.215050+00:00","lastSeen":"2026-03-15T17:53:05.215050+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/integration-durch-bildung","crawledAt":"2026-03-15T17:53:05.215050Z","crawlId":"contacts-seeded-1773597185","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b66480e4c53ad83765ab2b082bfe0e2adc6c89b2c929b08c2f4ec08b84052a17"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:05.215050+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c38e14ea-01e1-4a46-a42c-854ab11a9f9a', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement', 'active', NULL, '2026-03-15T17:53:05.731108+00:00', '{"id":"c38e14ea-01e1-4a46-a42c-854ab11a9f9a","title":"Kommunales Bildungsmanagement","summary":{"de":"Bessere Planung und Verteilung lokaler Ressourcen, bessere Transparenz über die Bildungsbedürfnisse der Menschen: ein datenbasiertes Bildungsmanagement bietet zahlreiche Vorteile für die Menschen..."},"content":{"de":"Bessere Planung und Verteilung lokaler Ressourcen, bessere Transparenz über die Bildungsbedürfnisse der Menschen: ein datenbasiertes Bildungsmanagement bietet zahlreiche Vorteile für die Menschen vor Ort. Die \" Transferinitiative Kommunales Bildungsmanagement\" unterstützt Städte und Landkreise darin, ein datenbasiertes Bildungsmanagement aufzubauen. Dieses hilft, vor Ort passende Bildungsangebote für alle Lebensphasen anzubieten und zukunftsfähig zu gestalten. Ein datenbasiertes kommunales Bildungsmanagement hilft, mehr Transparenz über die Bildungsbedürfnisse der Menschen in allen Lebensphasen zur Bereitstellung eines individualisierten Bildungsangebots zu schaffen. Eine bessere Planung und Verteilung lokaler Ressourcen unter Einbindung der Zivilgesellschaft und von Kooperationsnetzwerken werden möglich. Außerdem ergibt sich eine stärkere Resilienz bei Krisensituationen durch schnellen Zugriff auf kontinuierlich fortgeschriebene Bildungsdaten und Bildungssteuerung in kommunaler Verantwortungsgemeinschaft. Die Förderung von Chancengerechtigkeit und Teilhabe in der kommunalen Bildungslandschaft wird verbessert."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:05.731108+00:00","lastSeen":"2026-03-15T17:53:05.731108+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/kommunales-bildungsmanagement","crawledAt":"2026-03-15T17:53:05.731108Z","crawlId":"contacts-seeded-1773597185","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"1d1799c715bf210a4ef2f1d405d166a3bcf4dc6475c7dea40ddbad275882fe1b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:05.731108+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f1436bdb-7068-4331-89d6-507203bc3a36', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule', 'active', NULL, '2026-03-15T17:53:06.264953+00:00', '{"id":"f1436bdb-7068-4331-89d6-507203bc3a36","title":"Schule","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Startchancen-Programm Das Startchancen-Programm des Bundesbildungsministeriums unterstützt Schulen mit einem hohen Anteil sozial benachteiligter Schülerinnen und Schüler. Das Startchancen-Programm des Bundesbildungsministeriums unterstützt Schulen mit einem hohen Anteil sozial benachteiligter Schülerinnen und Schüler. Digitalisierung der Bildung Die Digitalisierung des Lehrens und Lernens ist unverzichtbar. Das Bundesbildungsministerium setzt sich für eine gut funktionierende Infrastruktur, moderne Ausstattung der Schulen und entsprechend ausgebildete Lehrkräfte ein. Die Digitalisierung des Lehrens und Lernens ist unverzichtbar. Das Bundesbildungsministerium setzt sich für eine gut funktionierende Infrastruktur, moderne Ausstattung der Schulen und entsprechend ausgebildete Lehrkräfte ein. DigitalPakt Schule Digitale Bildung schafft neue Möglichkeiten: Der DigitalPakt Schule unterstützt Schulen beim Ausbau digitaler Infrastruktur und Ausstattung - für flexibles Lernen, mehr Chancengleichheit und einen guten Start in die digitale Arbeitswelt. Digitale Bildung schafft neue Möglichkeiten: Der DigitalPakt Schule unterstützt Schulen beim Ausbau digitaler Infrastruktur und Ausstattung - für flexibles Lernen, mehr Chancengleichheit und einen guten Start in die digitale Arbeitswelt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:06.264953+00:00","lastSeen":"2026-03-15T17:53:06.264953+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/schule","crawledAt":"2026-03-15T17:53:06.264953Z","crawlId":"contacts-seeded-1773597186","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"f90e133abb70e9ca7a217616e2018f7c260225885172d5926aea5991730bb7f9"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:06.264953+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('651c1c2c-eef6-4dce-bed0-3c7474c233a2', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung', 'active', NULL, '2026-03-15T17:53:06.719415+00:00', '{"id":"651c1c2c-eef6-4dce-bed0-3c7474c233a2","title":"Weiterbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Weiterbildung Ob berufliche oder allgemeine Weiterbildung: In einer sich ständig verändernden Welt ist es wichtig, stetig neue Kompetenzen zu erwerben. Eine Weiterbildung hilft bei der beruflichen wie auch persönlichen Weiterentwicklung. Ob berufliche oder allgemeine Weiterbildung: In einer sich ständig verändernden Welt ist es wichtig, stetig neue Kompetenzen zu erwerben. Eine Weiterbildung hilft bei der beruflichen wie auch persönlichen Weiterentwicklung. Allgemeine Weiterbildung Viele Bildungsangebote außerhalb des beruflichen Aufgabenbereiches fördern Schlüsselkompetenzen, die nicht nur für den Alltag wichtig sind. Eine allgemeine Weiterbildung ermöglicht es somit Kompetenzen zu erwerben, die auch beruflich weiterhelfen. Viele Bildungsangebote außerhalb des beruflichen Aufgabenbereiches fördern Schlüsselkompetenzen, die nicht nur für den Alltag wichtig sind. Eine allgemeine Weiterbildung ermöglicht es somit Kompetenzen zu erwerben, die auch beruflich weiterhelfen. Alphabetisierung und Grundbildung In Deutschland gibt es etwa 6,2 Millionen Erwachsene, die nicht oder nur auf niedrigstem Niveau lesen und schreiben können. Die AlphaDekade ermöglicht den Betroffenen einen Zugang zu Lern- und Unterstützungsangeboten. In Deutschland gibt es etwa 6,2 Millionen Erwachsene, die nicht oder nur auf niedrigstem Niveau lesen und schreiben können. Die AlphaDekade ermöglicht den Betroffenen einen Zugang zu Lern- und Unterstützungsangeboten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:06.719415+00:00","lastSeen":"2026-03-15T17:53:06.719415+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/bildung/weiterbildung","crawledAt":"2026-03-15T17:53:06.719415Z","crawlId":"contacts-seeded-1773597186","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"e7869c2aae2b2b142e996eaae3e9514b82fc94889c7a1abcc71f2b425108b5be"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:06.719415+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('9e0d6ee6-ae4a-416f-acc0-01af0b09f2b8', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft', 'active', NULL, '2026-03-15T17:53:07.249667+00:00', '{"id":"9e0d6ee6-ae4a-416f-acc0-01af0b09f2b8","title":"Engagement und Gesellschaft","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Am 10. März hat die Parlamentarische Staatssekretärin im Bundesbildungsministerium, Mareike Wulf, in Köln die didacta miteröffnet. Das Motto \"Alles im Wandel. Bildung im Fokus\" stellt Innovationen und mentale Gesundheit ins Zentrum. Am 26. Februar hat die Staatssekretärin im Bundesbildungsministerium, Dr. Petra Bahr, an der Veranstaltung \"Wem gehört die Kindheit?\" teilgenommen und insbesondere darüber diskutiert, wie die Interessen von Kindern angemessen berücksichtigt werden. Am 3. Februar empfing Karin Prien die japanische Botschafterin Mitsuko Shino. Die Politikerinnen tauschten sich zu gesellschafts- und bildungspolitischen Initiativen aus, die aufgrund ähnlicher Entwicklungen für beide Länder von Interesse sind."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:07.249667+00:00","lastSeen":"2026-03-15T17:53:07.249667+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft","crawledAt":"2026-03-15T17:53:07.249667Z","crawlId":"contacts-seeded-1773597187","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"7ea002627c4abd939f835c7cc4e1dd7202967266d5558e8dc99f8e79d68b8777"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:07.249667+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b9bc8b4a-7b95-45b2-acdf-3b54424ff3b4', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit', 'active', NULL, '2026-03-15T17:53:07.733692+00:00', '{"id":"b9bc8b4a-7b95-45b2-acdf-3b54424ff3b4","title":"Allianz gegen Einsamkeit","summary":{"de":"Einsamkeit kann jede und jeden treffen. Das Bundesgesellschaftsministerium setzt sich dafür ein, dieser gesamtgesellschaftlichen Herausforderung..."},"content":{"de":"Wissen zu Einsamkeit vertiefen Einsamkeit ist ein vielschichtiges Phänomen mit unterschiedlichen Ursachen. Davon betroffen sind sowohl ältere als auch jüngere Menschen. Einsamkeit ist ein vielschichtiges Phänomen mit unterschiedlichen Ursachen. Davon betroffen sind sowohl ältere als auch jüngere Menschen. Modellprojekte gegen Einsamkeit Um Einsamkeit und Isolation wirksam zu begegnen, fördert das Bundesgesellschaftsministerium Orte für Gemeinsamkeit und gemeinsames Erleben. Um Einsamkeit und Isolation wirksam zu begegnen, fördert das Bundesgesellschaftsministerium Orte für Gemeinsamkeit und gemeinsames Erleben. Über Einsamkeit reden Betroffene sprechen häufig nicht über ihre Einsamkeit. Deshalb muss das Thema sichtbarer und dafür sensibilisiert werden. Betroffene sprechen häufig nicht über ihre Einsamkeit. Deshalb muss das Thema sichtbarer und dafür sensibilisiert werden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:07.733692+00:00","lastSeen":"2026-03-15T17:53:07.733692+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/allianz-gegen-einsamkeit","crawledAt":"2026-03-15T17:53:07.733692Z","crawlId":"contacts-seeded-1773597187","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b4fffdc2e2f8c04a58572c71c9fcfeae3898acb585de570eb6238ea46fe11d67"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:07.733692+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a8abc2f3-dc87-4b70-b592-ab6d7913616e', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948', 'active', NULL, '2026-03-15T17:53:08.218393+00:00', '{"id":"a8abc2f3-dc87-4b70-b592-ab6d7913616e","title":"Bundesprogramm \"Demokratie leben! \"","summary":{"de":"Demokratie fördern. Vielfalt gestalten. Extremismus vorbeugen - das sind die Kernziele des Bundesprogramms \"Demokratie leben!\". Dieser inhaltliche Dreiklang ist handlungsleitend."},"content":{"de":"\"Demokratie leben!\" ist seit 2015 als lernendes Bundesprogramm konzipiert. Es reagiert auf aktuelle gesellschaftliche Herausforderungen und wird kontinuierlich weiterentwickelt. Über bereits zwei Förderperioden hinweg hat sich \"Demokratie leben!\" zum inhaltlich umfassendsten Präventions- und Gestaltungsprogramm des Bundes zur zivilgesellschaftlichen Demokratieförderung, Vielfaltgestaltung und Extremismusprävention entwickelt. Für die 3. Förderperiode (2025 bis 2032) hat das Bundesfamilienministerium das Bundesprogramm angepasst. Dabei wurden die Ziele und Strukturen neu justiert und stärker fokussiert - vor allem mit Blick auf die aktuellen gesellschaftlichen Herausforderungen und auf Grundlage der gewonnenen Erfahrungen aus der ersten (2015 bis 2019) und zweiten (2020 bis 2024) Förderperiode. Das Bundesprogramm ist im Januar 2025 in seine 3. Förderperiode (2025 bis 2032) gestartet. Mit dem Programm fördert das Bundesfamilienministerium zivilgesellschaftliches Engagement auf allen Ebenen des Staates für ein vielfältiges und demokratisches Miteinander und die Arbeit gegen Radikalisierungen und Polarisierungen in der Gesellschaft. In seiner 3. Förderperiode (2025 bis 2032) ist das Bundesprogramm Teil der Strategie \"Gemeinsam für Demokratie und gegen Extremismus - Strategie der Bundesregierung für eine starke, wehrhafte Demokratie und eine offene und vielfältige Gesellschaft\". Sie ersetzt die \" Strategie der Bundesregierung zur Extremismusprävention und Demokratieförderung \" aus dem Jahr 2016. Ziel des Bundesprogramms ist es, zur Stärkung der Demokratie und eines friedlichen, respektvollen Zusammenlebens beizutragen, Teilhabe zu fördern und die Arbeit gegen jede Form von Gruppenbezogener Menschenfeindlichkeit und Demokratiefeindlichkeit zu ermöglichen. Dazu wird das Bundesprogramm in drei Handlungsfeldern aktiv: Demokratie fördern - Vielfalt gestalten - Extremismus vorbeugen. Das Bundesprogramm stärkt die Zivilgesellschaft in diesen Handlungsfeldern durch geeignete Rahmenbedingungen in diesen Handlungsfeldern."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:08.218393+00:00","lastSeen":"2026-03-15T17:53:08.218393+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/bundesprogramm-demokratie-leben--73948","crawledAt":"2026-03-15T17:53:08.218393Z","crawlId":"contacts-seeded-1773597188","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"96cbc6dce8ae8f84305733be267da719a16e84e667c6ec4b5b08899bfbdaa50c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:08.218393+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('39b71e6a-b2ea-4724-9eca-5bdfe115bad1', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit', 'active', NULL, '2026-03-15T17:53:08.732078+00:00', '{"id":"39b71e6a-b2ea-4724-9eca-5bdfe115bad1","title":"Demografischer Wandel und Nachhaltigkeit","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Antworten auf den demografischen Wandel Die demografische Entwicklung wird unsere Gesellschaft tiefgreifend verändern. Im Dialog mit Wissenschaft und Praxis erarbeitet das Bundesfamilienministerium neue Ansätze, wie Kommunen sich darauf einstellen können. Die demografische Entwicklung wird unsere Gesellschaft tiefgreifend verändern. Im Dialog mit Wissenschaft und Praxis erarbeitet das Bundesfamilienministerium neue Ansätze, wie Kommunen sich darauf einstellen können. Zukunftsraum Demografie Das Netzwerk \"Zukunftsraum Demografie\" unterstützt Gemeinden, Städte und Landkreise dabei, die Herausforderungen des demografischen Wandels zu gestalten. Das Netzwerk \"Zukunftsraum Demografie\" unterstützt Gemeinden, Städte und Landkreise dabei, die Herausforderungen des demografischen Wandels zu gestalten. Nachhaltige Entwicklung Die Herausforderungen unserer Zeit sind vielfältig, überschreiten Grenzen und betreffen uns alle. Das Bundesfamilienministerium trägt mit seinen gesellschaftspolitischen Maßnahmen zu einer nachhaltigen Entwicklung bei. Die Herausforderungen unserer Zeit sind vielfältig, überschreiten Grenzen und betreffen uns alle. Das Bundesfamilienministerium trägt mit seinen gesellschaftspolitischen Maßnahmen zu einer nachhaltigen Entwicklung bei."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:08.732078+00:00","lastSeen":"2026-03-15T17:53:08.732078+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/demografischer-wandel-und-nachhaltigkeit","crawledAt":"2026-03-15T17:53:08.732078Z","crawlId":"contacts-seeded-1773597188","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"a49444d8edcd372db243438ad91d75747f4d8e59918c76d4a5ba5c57f9b75cce"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:08.732078+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('aec67133-69db-42af-a354-116f89025453', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt', 'active', NULL, '2026-03-15T17:53:09.237705+00:00', '{"id":"aec67133-69db-42af-a354-116f89025453","title":"Deutsche Stiftung für Engagement und Ehrenamt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Engagement für Geflüchtete aus der Ukraine fördern Mit dem Förderprogramm \"Ehrenamt hilft gemeinsam\" stärkt die Deutsche Stiftung für Engagement und Ehrenamt zivilgesellschaftliche Strukturen im Bereich des Bürgerschaftlichen Engagements für ukrainische Geflüchtete. Mit dem Förderprogramm \"Ehrenamt hilft gemeinsam\" stärkt die Deutsche Stiftung für Engagement und Ehrenamt zivilgesellschaftliche Strukturen im Bereich des Bürgerschaftlichen Engagements für ukrainische Geflüchtete. Hilfe für die Ukraine: Die Stiftung vernetzt und informiert Die Deutsche Stiftung für Engagement und Ehrenamt vernetzt deutschlandweit Engagierte, die sich für Geflüchtete aus der Ukraine einsetzten wollen und gibt einen Überblick über Unterstützungsmöglichkeiten. Die Deutsche Stiftung für Engagement und Ehrenamt vernetzt deutschlandweit Engagierte, die sich für Geflüchtete aus der Ukraine einsetzten wollen und gibt einen Überblick über Unterstützungsmöglichkeiten. Der Gründungs-Vorstand der Stiftung Der erste Vorstand der Deutschen Stiftung für Engagement und Ehrenamt besteht aus einer Doppelspitze. Katarina Peranić und Jan Holze werden die Stiftung aufbauen. Der erste Vorstand der Deutschen Stiftung für Engagement und Ehrenamt besteht aus einer Doppelspitze. Katarina Peranić und Jan Holze werden die Stiftung aufbauen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:09.237705+00:00","lastSeen":"2026-03-15T17:53:09.237705+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/deutsche-stiftung-fuer-engagement-und-ehrenamt","crawledAt":"2026-03-15T17:53:09.237705Z","crawlId":"contacts-seeded-1773597189","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0a74af998e776d949673001155fa72c4c9eb5abaa01decab5cc0c5a9bf4d9874"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:09.237705+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b75d29f8-a88e-4719-9052-6e6a14926fe3', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken', 'active', NULL, '2026-03-15T17:53:09.763892+00:00', '{"id":"b75d29f8-a88e-4719-9052-6e6a14926fe3","title":"Engagement stärken","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Menschen stärken Menschen Mit dem Bundesprogramm \"Menschen stärken Menschen\" fördert und unterstützt das Bundesfamilienministerium bürgerschaftliches Engagement in Form von Patenschaften - für mehr gesellschaftlichen Zusammenhalt und bessere Teilhabechancen. Mit dem Bundesprogramm \"Menschen stärken Menschen\" fördert und unterstützt das Bundesfamilienministerium bürgerschaftliches Engagement in Form von Patenschaften - für mehr gesellschaftlichen Zusammenhalt und bessere Teilhabechancen. Verbände, Stiftungen und Spenden Verbände, Stiftungen und Spenden sind wichtige Säulen der Engagementpolitik. Deshalb arbeitet das Bundesfamilienministerium eng mit Verbänden der freien Wohlfahrtspflege zusammen. Es unterstützt Bürgerstiftungen und fördert die Spendenberatung. Verbände, Stiftungen und Spenden sind wichtige Säulen der Engagementpolitik. Deshalb arbeitet das Bundesfamilienministerium eng mit Verbänden der freien Wohlfahrtspflege zusammen. Es unterstützt Bürgerstiftungen und fördert die Spendenberatung. Engagementberichterstattung Die Engagementberichte der Bundesregierung sind eine Bestandsaufnahme zur Entwicklung des bürgerschaftlichen Engagements in Deutschland. Die Engagementberichte der Bundesregierung sind eine Bestandsaufnahme zur Entwicklung des bürgerschaftlichen Engagements in Deutschland."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:09.763892+00:00","lastSeen":"2026-03-15T17:53:09.763892+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/engagement-staerken","crawledAt":"2026-03-15T17:53:09.763892Z","crawlId":"contacts-seeded-1773597189","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"7034dc87cae436546cdb0e4a2d00fad4e2292b116fe9a1457ca9137522e9ed0b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:09.763892+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3a431062-9e68-4010-b47d-1871d383b411', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration', 'active', NULL, '2026-03-15T17:53:10.243339+00:00', '{"id":"3a431062-9e68-4010-b47d-1871d383b411","title":"Flüchtlingspolitik und Integration","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Angebote zur Sprachförderung und Integration Sprachkurse, Patenschaften, Existenzgründung - mit unterschiedlichen Maßnahmen sorgt die Bundesregierung dafür, dass Integration gelingt. Eine aktuelle Publikation gibt einen Überblick. Sprachkurse, Patenschaften, Existenzgründung - mit unterschiedlichen Maßnahmen sorgt die Bundesregierung dafür, dass Integration gelingt. Eine aktuelle Publikation gibt einen Überblick. Informationen für geflüchtete Menschen Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Viele davon sind in verschiedenen Sprachen erhältlich. Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Viele davon sind in verschiedenen Sprachen erhältlich. Jugendmigrationsdienste Als Teil der Initiative \"JUGEND STÄRKEN\" beraten und begleiten die Jugendmigrationsdienste junge Menschen mit Einwanderungsgeschichte im Alter zwischen 12 und 27 Jahren. Das vielseitige Angebot hilft bei Fragen zum Schulbesuch, bei der... Als Teil der Initiative \"JUGEND STÄRKEN\" beraten und begleiten die Jugendmigrationsdienste junge Menschen mit Einwanderungsgeschichte im Alter zwischen 12 und 27 Jahren. Das vielseitige Angebot hilft bei Fragen zum Schulbesuch, bei der..."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:10.243339+00:00","lastSeen":"2026-03-15T17:53:10.243339+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration","crawledAt":"2026-03-15T17:53:10.243339Z","crawlId":"contacts-seeded-1773597190","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d3da4df93fb99beb354166ab3560991bb5d946763f0bf0466c9b2ba8ae9eb210"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:10.243339+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4169d12e-53f0-4b76-aaf4-f4b375b7a945', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete', 'active', NULL, '2026-03-15T17:53:10.762089+00:00', '{"id":"4169d12e-53f0-4b76-aaf4-f4b375b7a945","title":"Informationen für geflüchtete Menschen","summary":{"de":"Das Bundesfamilienministerium steht nach Deutschland geflüchteten Menschen mit umfassenden Unterstützungs- und Hilfsangeboten zur Seite. Einige..."},"content":{"de":"Mit dem \"Bericht zu dem Gesetz zur Verbesserung der Unterbringung, Versorgung und Betreuung ausländischer Kinder und Jugendlicher\" kommt die Bundesregierung ihrer Verpflichtung nach, jährlich über die Situation unbegleiteter ausländischer Minderjähriger (UMA) in Deutschland zu informieren. Mindeststandards in Flüchtlingsunterkünften Das Bundesfamilienministerium und das Kinderhilfswerk UNICEF haben gemeinsam Mindeststandards zum Schutz von Kindern, Jugendlichen und Frauen in Flüchtlingsunterkünften erarbeitet. Das Bundesfamilienministerium und das Kinderhilfswerk UNICEF haben gemeinsam Mindeststandards zum Schutz von Kindern, Jugendlichen und Frauen in Flüchtlingsunterkünften erarbeitet. Menschen stärken Menschen Ein Flyer informiert über unterschiedliche Möglichkeiten des persönlichen Engagements für Flüchtlinge im Programm \"Menschen stärken Menschen\" - ob als Patin oder Pate, Gastfamilie oder Vormund. Ein Flyer informiert über unterschiedliche Möglichkeiten des persönlichen Engagements für Flüchtlinge im Programm \"Menschen stärken Menschen\" - ob als Patin oder Pate, Gastfamilie oder Vormund. Hilfs- und Beratungsangebote für Frauen und LSBTI Unter den derzeit nach Deutschland kommenden Flüchtlingen sind Frauen und LSBTI besonders schutzbedürftig. Mit einem mehrsprachigen Flyer sollen sie schnell Zugang zum deutschen Hilfesystem finden."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:10.762089+00:00","lastSeen":"2026-03-15T17:53:10.762089+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/fluechtlingspolitik-und-integration/informationen-fuer-gefluechtete","crawledAt":"2026-03-15T17:53:10.762089Z","crawlId":"contacts-seeded-1773597190","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"64a76884b84a3fad227c3804fcab236f4135429c004bc14502f5203c27c5628f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:10.762089+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b57f0d73-7f14-448b-acbe-1901d43bf719', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste', 'active', NULL, '2026-03-15T17:53:11.235493+00:00', '{"id":"b57f0d73-7f14-448b-acbe-1901d43bf719","title":"Freiwilligendienste","summary":{"de":"Rund 100.000 Menschen leisten Jahr für Jahr einen Freiwilligendienst. Politische Aufmerksamkeit gilt vor allem finanziellen und organisatorischen..."},"content":{"de":"Die Jugendfreiwilligendienste Nach der Schulzeit etwas Neues ausprobieren und gleichzeitig Gutes tun: Knapp 55.000 Jugendliche und junge Erwachsene verwirklichen diesen Wunsch jedes Jahr. Nach der Schulzeit etwas Neues ausprobieren und gleichzeitig Gutes tun: Knapp 55.000 Jugendliche und junge Erwachsene verwirklichen diesen Wunsch jedes Jahr. Der Bundesfreiwilligendienst Der Bundesfreiwilligendienst ist eine Erfolgsgeschichte. Viele Bürgerinnen und Bürger nutzen die Möglichkeit, sich für die Gesellschaft und das Gemeinwohl zu engagieren. Der Bundesfreiwilligendienst ist eine Erfolgsgeschichte. Viele Bürgerinnen und Bürger nutzen die Möglichkeit, sich für die Gesellschaft und das Gemeinwohl zu engagieren. Wie ermöglicht ein Freiwilliges Ökologisches Jahr positive Demokratie- und Selbstwirksamkeitserfahrungen? Zu diesen und weiteren Fragen tauschte sich Michael Brand auf der Fachtagung 2026 aus. Wie können junge Menschen sich über Schule hinaus bilden? Wie können junge Menschen einen Beitrag für eine nachhaltige Zukunft leisten? Diese und weitere Fragen diskutierte Karin Prien bei der Jahrestagung 2025 Freiwilliges Soziales Jahr."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:11.235493+00:00","lastSeen":"2026-03-15T17:53:11.235493+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/freiwilligendienste","crawledAt":"2026-03-15T17:53:11.235493Z","crawlId":"contacts-seeded-1773597191","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"bc14732491078e5802ba5ad809dc4df99ba577d72f725d0cc0a5650b3c92891d"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:11.235493+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('42c8759f-127e-4ae4-94fe-f88a0b072ab4', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser', 'active', NULL, '2026-03-15T17:53:11.736984+00:00', '{"id":"42c8759f-127e-4ae4-94fe-f88a0b072ab4","title":"Mehrgenerationenhäuser","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Die Programmschwerpunkte Um die Herausforderungen vor Ort zu meistern und passende Lösungen zu entwickeln, brauchen die Mehrgenerationenhäuser Handlungsspielraum. Deshalb legen die Häuser die Schwerpunkte ihrer Arbeit selbst fest. Um die Herausforderungen vor Ort zu meistern und passende Lösungen zu entwickeln, brauchen die Mehrgenerationenhäuser Handlungsspielraum. Deshalb legen die Häuser die Schwerpunkte ihrer Arbeit selbst fest. Die Querschnittsaufgaben Generationenübergreifende Arbeit, Teilhabe, freiwilliges Engagement und Sozialraumorientierung: Das sind die vier Querschnittsaufgaben der Mehrgenerationenhäuser. Generationenübergreifende Arbeit, Teilhabe, freiwilliges Engagement und Sozialraumorientierung: Das sind die vier Querschnittsaufgaben der Mehrgenerationenhäuser. Am 23. September hielt der Parlamentarische Staatssekretär Michael Brand das Grußwort bei der Ideenkonferenz des Bundesprogramms Mehrgenerationenhaus mit dem Thema \"Gemeinsam stark - Lokale Kooperationen und Fundraising für nachhaltigen Erfolg\". Die Aktionstage finden unter dem Motto \"Nachbarschaft mit Herz und Hand\" bundesweit statt und bieten die Möglichkeit, sich über die Arbeit der Mehrgenerationenhäuser zu informieren. Karin Prien eröffnete sie mit einer Kochaktion in Berlin."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:11.736984+00:00","lastSeen":"2026-03-15T17:53:11.736984+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/engagement-und-gesellschaft/mehrgenerationenhaeuser","crawledAt":"2026-03-15T17:53:11.738501Z","crawlId":"contacts-seeded-1773597191","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"bde9c6580977f6e3876e9e448796ef7ae12fb69b42699c5946e64e10397e1565"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:11.738501+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7bbd40cb-bd7a-4bc7-9adb-82032313dcfe', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie', 'active', NULL, '2026-03-15T17:53:12.284867+00:00', '{"id":"7bbd40cb-bd7a-4bc7-9adb-82032313dcfe","title":"Familienpolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Elterngeldrechner Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link) Mit dem Elterngeldrechner kann ein möglicher Elterngeldanspruch in wenigen Minuten ermittelt werden. (Externer Link) Nationaler Aktionsplan für chancengerechtes Aufwachsen Bundesfamilienministerin Karin Prien hat den Wettbewerb \"Kleine Lösungen - große Wirkung\" gestartet. Gesucht werden kleine und mittlere Unternehmen mit kreativen Ideen für die Vereinbarkeit von Familie und Beruf. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun. Die ehemalige Bundesfrauenministerin und Bundestagspräsidentin Prof. Dr. Rita Süssmuth ist verstorben. Karin Prien und Nina Warken würdigten sie als großes Vorbild und Vorkämpferin für Frauenrechte und sozialen Zusammenhalt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:12.284867+00:00","lastSeen":"2026-03-15T17:53:12.284867+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie","crawledAt":"2026-03-15T17:53:12.284867Z","crawlId":"contacts-seeded-1773597192","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d9a13e717cf403d403f438068ed910aee762257048d6e08f53171908b34e44b6"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:12.284867+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
