elfältige Unterstützungsangebote zurückgreifen. Die Erziehung und Förderung der eigenen Kinder sowie der Umgang mit Problemen und Konflikten sind oft mit vielen Fragen verbunden. Eltern können auf vielfältige Unterstützungsangebote zurückgreifen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/chancen-und-teilhabe-fuer-familien","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:12.739841+00:00","lastSeen":"2026-03-15T17:53:12.739841+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/chancen-und-teilhabe-fuer-familien","crawledAt":"2026-03-15T17:53:12.740850Z","crawlId":"contacts-seeded-1773597192","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0adda72b02030c3225062c9cd66e551030230bc66366535c090e2b59a3c24d82"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:12.740850+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
