INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0a2acabf-0a1f-448a-b14b-6766927fbdd5', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung', 'active', NULL, '2026-03-15T17:53:13.797201+00:00', '{"id":"0a2acabf-0a1f-448a-b14b-6766927fbdd5","title":"Gute Kinderbetreuung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"KiTa-Qualität Die Qualitätsentwicklung in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe, die der Bund mit dem KiTa-Qualitätsgesetz und weiteren Initiativen unterstützt. Die Qualitätsentwicklung in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe, die der Bund mit dem KiTa-Qualitätsgesetz und weiteren Initiativen unterstützt. Kita-Ausbau Um eine gute frühkindliche Bildung, Betreuung und Erziehung sicherzustellen, unterstützt der Bund die Länder beim Ausbau und der Weiterentwicklung von Angeboten der Kindertagesbetreuung. Um eine gute frühkindliche Bildung, Betreuung und Erziehung sicherzustellen, unterstützt der Bund die Länder beim Ausbau und der Weiterentwicklung von Angeboten der Kindertagesbetreuung. Ganztagsbetreuung für Grundschulkinder Ab 2026 gibt es einen Rechtsanspruch auf Ganztagsbetreuung für Grundschulkinder. Das stärkt die Kinder und hilft den Eltern bei der Vereinbarkeit von Familie und Beruf. Ab 2026 gibt es einen Rechtsanspruch auf Ganztagsbetreuung für Grundschulkinder. Das stärkt die Kinder und hilft den Eltern bei der Vereinbarkeit von Familie und Beruf."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:13.797201+00:00","lastSeen":"2026-03-15T17:53:13.797201+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung","crawledAt":"2026-03-15T17:53:13.797201Z","crawlId":"contacts-seeded-1773597193","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"3797851dead661669827720017501e49068711c2bc54f8e2d52984f7fa16e6ce"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:13.797201+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('37afcbc8-30ca-4b2b-be06-02ed39da0795', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet', 'active', NULL, '2026-03-15T17:53:14.240555+00:00', '{"id":"37afcbc8-30ca-4b2b-be06-02ed39da0795","title":"Mehr Qualität in der frühen Bildung","summary":{"de":"Kitas sind ein Bildungs- und Zukunftsort. Um die Qualität der Kindertagesbetreuung und der Kindertagespflege weiterzuentwickeln und zu stärken..."},"content":{"de":"Für gute Kinderbetreuung bundesweit: das KiTa-Qualitätsgesetz Die Weiterentwicklung der Qualität in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe und gemeinsames Ziel von Bund, Ländern und Kommunen. Hier setzt das KiTa-Qualitätsgesetz an. Die Weiterentwicklung der Qualität in Kitas und in der Kindertagespflege ist eine gesamtgesellschaftliche Aufgabe und gemeinsames Ziel von Bund, Ländern und Kommunen. Hier setzt das KiTa-Qualitätsgesetz an. Die Verträge der Bundesländer zum KiTa-Qualitäts- und -Teilhabeverbesserungsgesetz Um die Qualität in der frühkindlichen Bildung, Betreuung und Erziehung zu verbessern, unterstützt der Bund die Länder im Rahmen des KiTa-Qualitäts- und Teilhabeverbesserungsgesetzes seit 2019 mit zusätzlichen Mitteln. Um die Qualität in der frühkindlichen Bildung, Betreuung und Erziehung zu verbessern, unterstützt der Bund die Länder im Rahmen des KiTa-Qualitäts- und Teilhabeverbesserungsgesetzes seit 2019 mit zusätzlichen Mitteln. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun. Kindern ein Zuhause geben, wo sie Zuwendung, Stabilität und \"Zeit, die prägt\" erfahren können: Eine neue Kampagne des Bundesfamilienministeriums rückt Pflegeelternschaft stärker ins öffentliche Bewusstsein und will neue Pflegefamilien gewinnen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:14.240555+00:00","lastSeen":"2026-03-15T17:53:14.240555+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/kinderbetreuung/kita-qualitaet","crawledAt":"2026-03-15T17:53:14.240555Z","crawlId":"contacts-seeded-1773597194","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"67382eca6d53455f1f573a30ea1a8ea774136f07fa933ce2179188508ddbe883"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:14.240555+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d2a0f65d-ffde-471d-8322-bd704db13223', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/nationaler-aktionsplan-kinderchancen', 'active', NULL, '2026-03-15T17:53:14.760392+00:00', '{"id":"d2a0f65d-ffde-471d-8322-bd704db13223","title":"Nationaler Aktionsplan \"Neue Chancen für Kinder in Deutschland\"","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Was ist der Nationale Aktionsplan? Der Nationale Aktionsplan soll die Zugänge benachteiligter Kinder und Jugendlicher in fünf Handlungsfeldern verbessern. Der Nationale Aktionsplan soll die Zugänge benachteiligter Kinder und Jugendlicher in fünf Handlungsfeldern verbessern. Wer wirkt wie am Nationalen Aktionsplan mit? Ein Ausschuss begleitet die Umsetzung und Weiterentwicklung des Nationalen Aktionsplans. Ein Ausschuss begleitet die Umsetzung und Weiterentwicklung des Nationalen Aktionsplans. In welchem europäischen Kontext steht der Nationale Aktionsplan? Die Kindergarantie der Europäischen Union ist eine wichtige Grundlage für den Aktionsplan. Die Kindergarantie der Europäischen Union ist eine wichtige Grundlage für den Aktionsplan."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/nationaler-aktionsplan-kinderchancen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"s