INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('8346184a-cf23-4dc7-84ea-b27819e9dd3e', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch', 'active', NULL, '2026-03-15T17:53:15.307642+00:00', '{"id":"8346184a-cf23-4dc7-84ea-b27819e9dd3e","title":"Schwangerschaft und Kinderwunsch","summary":{"de":"Eine Schwangerschaft kann werdende Eltern vor Herausforderungen stellen. Hilfe erhalten sie durch die Bundesstiftung Mutter und Kind. Auch Paare mit..."},"content":{"de":"Familienplanung von Frauen und Männern Schwangere oder Männer und Frauen mit Kinderwunsch stehen oft vor vielen Fragen. Ein dichtes Netz von Beratungsstellen und Online-Angebote informiert über Familienplanung, Schwangerschaft und Verhütungsmöglichkeiten. Schwangere oder Männer und Frauen mit Kinderwunsch stehen oft vor vielen Fragen. Ein dichtes Netz von Beratungsstellen und Online-Angebote informiert über Familienplanung, Schwangerschaft und Verhütungsmöglichkeiten. Ungewollte Kinderlosigkeit Der medizinische und technische Fortschritt ermöglicht vielen ungewollt kinderlosen Paaren die Erfüllung des Kinderwunsches. Viele Bundesländer unterstützen die Behandlung finanziell. Der medizinische und technische Fortschritt ermöglicht vielen ungewollt kinderlosen Paaren die Erfüllung des Kinderwunsches. Viele Bundesländer unterstützen die Behandlung finanziell. Informationsportal Kinderwunsch Das Informationsportal Kinderwunsch zeigt Beratungsangebote und finanzielle Fördermöglichkeiten für ungewollt kinderlose Paare auf. Das Informationsportal Kinderwunsch zeigt Beratungsangebote und finanzielle Fördermöglichkeiten für ungewollt kinderlose Paare auf."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:15.307642+00:00","lastSeen":"2026-03-15T17:53:15.307642+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/schwangerschaft-und-kinderwunsch","crawledAt":"2026-03-15T17:53:15.307642Z","crawlId":"contacts-seeded-1773597195","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c3a00d017545768226fffefd2a6d1e8a11f41b65647b1b22f0ce0c656238aa1a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:15.307642+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b83d569b-e8c6-40fe-9077-5a41cb9a565d', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik', 'active', NULL, '2026-03-15T17:53:15.777087+00:00', '{"id":"b83d569b-e8c6-40fe-9077-5a41cb9a565d","title":"Agenda für smarte Gesellschaftspolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Agenda für smarte Gesellschaftspolitik Überblick: Die neue Strategie für die digitale Gesellschaft Mit der \"Agenda für smarte Gesellschaftspolitik\" präsentiert das Bundesministerium für Bildung und Familie seine Vision für die digitale Gesellschaft von morgen. Ziel ist eine intelligente und innovative Digitalpolitik, die Mensch und Gemeinwohl in den Mittelpunkt stellt. Mit der \"Agenda für smarte Gesellschaftspolitik\" präsentiert das Bundesministerium für Bildung und Familie seine Vision für die digitale Gesellschaft von morgen. Ziel ist eine intelligente und innovative Digitalpolitik, die Mensch und Gemeinwohl in den Mittelpunkt stellt. Handlungsfeld 1: Smarte Lebensführung Mit Technik das Alltagsleben erleichtern Digitale Innovationen können die Vereinbarkeit von Familie und Beruf verbessern und ein längeres selbstbestimmtes Leben zu Hause ermöglichen. Wie smarte Lebensführung den Alltag erleichtert. Digitale Innovationen können die Vereinbarkeit von Familie und Beruf verbessern und ein längeres selbstbestimmtes Leben zu Hause ermöglichen. Wie smarte Lebensführung den Alltag erleichtert. Handlungsfeld 2: Digitale Teilhabe Digitalisierung als Chance für mehr Vielfalt und Teilhabe nutzen Bunter, freier und demokratischer kann die Gesellschaft durch die Digitalisierung werden. Aber nur, wenn alle mit anpacken und sich engagieren. Bunter, freier und demokratischer kann die Gesellschaft durch die Digitalisierung werden. Aber nur, wenn alle mit anpacken und sich engagieren."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:15.777087+00:00","lastSeen":"2026-03-15T17:53:15.777087+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/familie/smarte-gesellschaftspolitik","crawledAt":"2026-03-15T17:53:15.777087Z","crawlId":"contacts-seeded-1773597195","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"936df3c2d29bfce91578f9b7936bfff90961f392286ec30f7e89d3196351812c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:15.777087+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d0835552-9651-4cf2-af33-f2b139a50afa', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung', 'active', NULL, '2026-03-15T17:53:16.268170+00:00', '{"id":"d0835552-9651-4cf2-af33-f2b139a50afa","title":"Gleichstellungspolitik: Politik für Frauen und Männer","summary":{"de":"Frauen und Männer müssen die gleichen Chancen erhalten – persönlich, beruflich und familiär. Hier finden Sie Informationen zur Gleichstellungspolitik."},"content":{"de":"Digitaler Gleichstellungsatlas Der digitale Gleichstellungsatlas liefert einen umfassenden Überblick über die regionalen Unterschiede bei der Gleichstellung von Männern und Frauen in Deutschland. (Nicht barrierefrei) Der digitale Gleichstellungsatlas liefert einen umfassenden Überblick über die regionalen Unterschiede bei der Gleichstellung von Männern und Frauen in Deutschland. (Nicht barrierefrei) Am 10. März hat die Parlamentarische Staatssekretärin im Bundesbildungsministerium, Mareike Wulf, in Köln die didacta miteröffnet. Das Motto \"Alles im Wandel. Bildung im Fokus\" stellt Innovationen und mentale Gesundheit ins Zentrum. Gleichstellungspolitik gelingt nur, wenn auch Jungen und Männer adressiert werden. Das Frauentags-Vernetzungstreffen anlässlich des Internationalen Frauentags rückte daher die Rolle von Männlichkeitsbildern für die Gleichstellung in den Fokus. Das Bundesfrauenministerium hat Dr. Petra Volke als deutsche Kandidatin für die Expertengruppe GREVIO des Europarats vorgestellt - ein bedeutender Beitrag Deutschlands zur Bekämpfung von geschlechtsspezifischer und häuslicher Gewalt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:16.268170+00:00","lastSeen":"2026-03-15T17:53:16.268170+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung","crawledAt":"2026-03-15T17:53:16.268170Z","crawlId":"contacts-seeded-1773597196","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"5ddcf2ecf04a47be1395152f39fcdc47af1ffe0134b434e4e87d998fff7f27f7"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:16.268170+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d254cce4-3398-42e1-90db-dc0684b6b812', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe', 'active', NULL, '2026-03-15T17:53:16.733481+00:00', '{"id":"d254cce4-3398-42e1-90db-dc0684b6b812","title":"Politik für die Aufwertung sozialer Berufe","summary":{"de":"Soziale Berufe tragen zur Bildung, Gesundheit und Teilhabe bei und sichern ein gutes Zusammenleben"},"content":{"de":"Erzieherberufe - guter Einstieg und Aufstieg 3,7 Millionen Kinder nutzten im Jahr 2019 deutschlandweit Angebote der Kindertagesbetreuung. Sie wurden von insgesamt rund 676.000 Beschäftigten betreut und gefördert. 3,7 Millionen Kinder nutzten im Jahr 2019 deutschlandweit Angebote der Kindertagesbetreuung. Sie wurden von insgesamt rund 676.000 Beschäftigten betreut und gefördert. Pflegeausbildung - Berufsfeld Pflege Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der Pflegeberufe zu verbessern, wird die Pflegeausbildung reformiert. Die Lebensqualität für pflegebedürftige Menschen steht und fällt mit der Pflege. Um den Fachkräftebedarf zu sichern und die Attraktivität der Pflegeberufe zu verbessern, wird die Pflegeausbildung reformiert."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:16.733481+00:00","lastSeen":"2026-03-15T17:53:16.733481+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/aufwertung-sozialer-berufe","crawledAt":"2026-03-15T17:53:16.733481Z","crawlId":"contacts-seeded-1773597196","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"23a8a7aac11a8608c957cc9b5fe9e209d4de15e62590dfddc111e97776f34ab3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:16.733481+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
