Gap führt dazu, dass viele Frauen wirtschaftliche Nachteile haben. Für eine gerechte Verteilung der unbezahlten Sorgearbeit analysiert das Gender-Care-Gap-Projekt die Unterschiede und entwickelt Handlungsempfehlungen. Wie können pflegende Angehörige im Alltag besser unterstützt werden? Unter anderem darum ging es bei einer internationalen Online-Konferenz zur Geschlechtergerechtigkeit in der Pflege."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:18.761289+00:00","lastSeen":"2026-03-15T17:53:18.761289+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/gender-care-gap","crawledAt":"2026-03-15T17:53:18.761289Z","crawlId":"contacts-seeded-1773597198","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"a003b535960a9d116f38741b43cf2b1e2459412ad9149d8aaafd9be887468c52"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:18.761289+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
