INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('bbd6ced7-6b5a-45c5-b8ca-58578329314f', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk', 'active', NULL, '2026-03-15T17:53:20.310417+00:00', '{"id":"bbd6ced7-6b5a-45c5-b8ca-58578329314f","title":"Internationale Gleichstellungspolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Gleichstellungspolitik in Europa Die uneingeschränkte und gleichberechtigte Teilhabe von Frauen und Männern am öffentlichen Leben - insbesondere am Erwerbsleben - ist ein wesentliches Ziel europäischer Politik. Die uneingeschränkte und gleichberechtigte Teilhabe von Frauen und Männern am öffentlichen Leben - insbesondere am Erwerbsleben - ist ein wesentliches Ziel europäischer Politik. Gleichstellung im Rahmen der Vereinten Nationen Deutschland setzt sich in den VN-Gremien für die Gleichstellung und den Schutz der Frauenrechte ein. Seit April 2019 ist Deutschland wieder Mitglied der Frauenrechtskommission. Zuvor war Deutschland von 1997 bis 2017 ununterbrochen Mitglied. Deutschland setzt sich in den VN-Gremien für die Gleichstellung und den Schutz der Frauenrechte ein. Seit April 2019 ist Deutschland wieder Mitglied der Frauenrechtskommission. Zuvor war Deutschland von 1997 bis 2017 ununterbrochen Mitglied. Multilaterale Gleichstellungspolitik der G7- und G20-Staaten Die Beseitigung von Ungleichheiten, insbesondere mit Blick auf die Gleichstellung der Geschlechter, ist eines der zentralen Anliegen der G7- und G20-Staaten. Die Beseitigung von Ungleichheiten, insbesondere mit Blick auf die Gleichstellung der Geschlechter, ist eines der zentralen Anliegen der G7- und G20-Staaten."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:20.310417+00:00","lastSeen":"2026-03-15T17:53:20.310417+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk","crawledAt":"2026-03-15T17:53:20.310417Z","crawlId":"contacts-seeded-1773597200","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"77c0088566b7e3a9894899d1817b36a34d007c3b650ac4c7913f307e8ba7b631"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:20.310417+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('43624ce9-1ef4-44b5-9ce0-d2e35a08b105', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk/gleichstellungspolitik-in-europa', 'active', NULL, '2026-03-15T17:53:20.756029+00:00', '{"id":"43624ce9-1ef4-44b5-9ce0-d2e35a08b105","title":"Gleichstellungspolitik in Europa","summary":{"de":"Die uneingeschränkte und gleichberechtigte Teilhabe von Frauen und Männern am öffentlichen Leben - insbesondere am Erwerbsleben - ist ein wesentliches Ziel europäischer Politik."},"content":{"de":"Sowohl die Europäische Union (EU) als auch der Europarat setzen sich für die Verwirklichung der Gleichstellung der Geschlechter ein. Die EU ist durch mehrere Artikel im Vertrag über die EU, im Vertrag über die Arbeitsweise der EU sowie in der Charta der Grundrechte dazu verpflichtet, die Gleichstellung von Frauen und Männern zu fördern. Ihre Institutionen (Kommission, Rat und Parlament) arbeiten seit vielen Jahren darauf hin, dass Männer und Frauen sowohl auf europäischer Ebene als auch in den einzelnen Mitgliedstaaten vor dem Gesetz und im gelebten Alltag gleichgestellt sind. Das Bundesfrauenministerium setzt sich dafür in den relevanten Gremien des Rates und in allen anderen für die Gleichstellungspolitik wichtigen Expertengruppen und Ausschüssen auf EU-Ebene ein - zum Beispiel im Beratenden Ausschuss für die Chancengleichheit von Frauen und Männern der EU-Kommission. Gleichstellungspolitik wurde in der Europäischen Union von 2016 bis 2019 im Rahmen des strategischen Engagements für die Gleichstellung der Geschechter betrieben. Im März 2020 hat die Europäische Kommission ihre Strategie für die Gleichstellung der Geschlechter für den Zeitraum von 2020 bis 2025 in Form einer verbindlichen Kommissionsmitteilung vorgestellt. Inhaltlich werden durch die Gleichstellungsstrategie sechs Aktionsschwerpunkte gesetzt: Gleichberechtigte Führungsverantwortung in der Gesellschaft; Gender Mainstreaming und eine intersektionelle Perspektive in EU-Politikmaßnahmen;"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk/gleichstellungspolitik-in-europa","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:20.756029+00:00","lastSeen":"2026-03-15T17:53:20.756029+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/internationale-gleichstellungspolitk/gleichstellungspolitik-in-europa","crawledAt":"2026-03-15T17:53:20.756029Z","crawlId":"contacts-seeded-1773597200","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"ca38304e554275df077c7a7d156619c8cd8637cda582d706893533cf14e0b049"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:20.756029+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('815e9be6-4158-41f0-bf7c-b65bd090b155', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/jungen-und-maenner', 'active', NULL, '2026-03-15T17:53:21.295550+00:00', '{"id":"815e9be6-4158-41f0-bf7c-b65bd090b155","title":"Jungen und Männer","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Gleichstellungspolitik für Jungen und Männer Das Bundesfamilienministerium unterstützt Jungen und Männer bei der selbstbestimmten Berufs- und Lebensplanung jenseits von Rollenklischees und hilft bei Problemen und in Krisen. Das Bundesfamilienministerium unterstützt Jungen und Männer bei der selbstbestimmten Berufs- und Lebensplanung jenseits von Rollenklischees und hilft bei Problemen und in Krisen. Geschlechterstereotypen in allen Lebensbereichen überwinden Das Bundesfamilienministerium unterstützt alle Menschen unabhängig von ihrem Geschlecht dabei, ihre Potenziale und Interessen voll zu entfalten. Das Bundesfamilienministerium unterstützt alle Menschen unabhängig von ihrem Geschlecht dabei, ihre Potenziale und Interessen voll zu entfalten. Neue Wege für Jungs: Boys''Day - Jungen-Zukunftstag Der Boys''Day soll dazu beitragen, dass überholte Rollenbilder überwunden und neue Perspektiven für Jungen eröffnet werden, zum Beispiel im erzieherischen Bereich und der Gesundheitsbranche. Der Boys''Day soll dazu beitragen, dass überholte Rollenbilder überwunden und neue Perspektiven für Jungen eröffnet werden, zum Beispiel im erzieherischen Bereich und der Gesundheitsbranche."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/jungen-und-maenner","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:21.295550+00:00","lastSeen":"2026-03-15T17:53:21.295550+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/jungen-und-maenner","crawledAt":"2026-03-15T17:53:21.296557Z","crawlId":"contacts-seeded-1773597201","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"231f5422eb1afd0d19cd3473371b970a8995eb0dc8d1cb928208c191de80eeda"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:21.296557+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('058cb01c-d3d3-48ea-8e0b-766f7cc900a8', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/sexuelle-und-geschlechtliche-vielfalt', 'active', NULL, '2026-03-15T17:53:21.743741+00:00', '{"id":"058cb01c-d3d3-48ea-8e0b-766f7cc900a8","title":"Sexuelle und geschlechtliche Vielfalt","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Gleichstellungspolitische Meilensteine Für mehr Akzeptanz und weniger Diskriminierung von LSBTIQ*-Personen: Die politisch und gesetzlichen Meilensteine der vergangenen Jahre. Für mehr Akzeptanz und weniger Diskriminierung von LSBTIQ*-Personen: Die politisch und gesetzlichen Meilensteine der vergangenen Jahre. Aufklärung und Beratung fördern Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend arbeitet kontinuierlich daran, Informations-, Beratungs- und Unterstützungsstrukturen für LSBTIQ*-Personen und ihre Angehörigen auszubauen. Das Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend arbeitet kontinuierlich daran, Informations-, Beratungs- und Unterstützungsstrukturen für LSBTIQ*-Personen und ihre Angehörigen auszubauen. Gesetz über die Selbstbestimmung in Bezug auf den Geschlechtseintrag (SBGG) Das Selbstbestimmungsgesetz soll trans-, intergeschlechtlichen und nichtbinären Personen erleichtern, ihren Geschlechtseintrag ändern zu lassen. Antworten auf die wichtigsten Fragen. Das Selbstbestimmungsgesetz soll trans-, intergeschlechtlichen und nichtbinären Personen erleichtern, ihren Geschlechtseintrag ändern zu lassen. Antworten auf die wichtigsten Fragen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/sexuelle-und-geschlechtliche-vielfalt","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:21.743741+00:00","lastSeen":"2026-03-15T17:53:21.743741+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/gleichstellung/sexuelle-und-geschlechtliche-vielfalt","crawledAt":"2026-03-15T17:53:21.744737Z","crawlId":"contacts-seeded-1773597201","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"0fea974455130ad6ce48a866a732014333282c64ed51a93f1fe45611f6c756c4"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:21.744737+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
