INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d60dccbe-d5c6-4975-a29f-6aa816f230a4', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/erasmus-plus', 'active', NULL, '2026-03-15T17:53:22.737658+00:00', '{"id":"d60dccbe-d5c6-4975-a29f-6aa816f230a4","title":"Erasmus+","summary":{"de":"Als EU-Programm, das Menschen dabei hilft, über Ländergrenzen hinweg interkulturelle Kompetenzen zu erwerben, steht Erasmus+ vor allem für erleichterte Mobilität für Lernende, die die heimische..."},"content":{"de":"Als EU-Programm, das Menschen dabei hilft, über Ländergrenzen hinweg interkulturelle Kompetenzen zu erwerben, steht Erasmus+ vor allem für erleichterte Mobilität für Lernende, die die heimische Komfortzone verlassen möchten. Ein Auslandssemester in Estland, ein Berufspraktikum in Frankreich, ein Austausch mit einer Schulklasse in Polen, ein Freiwilligendienst in Griechenland: Erasmus+ macht Europa erfahrbar. Ziel ist die Förderung des interkulturellen Austauschs und die Stärkung der europäischen Identität. Durch das Verlassen der heimischen Komfortzone schafft das Erasmus+ Programm die Chance, den eigenen Horizont zu erweitern und sich somit persönlich weiterzuentwickeln. Eine Auslandserfahrung und das Erlernen einer zusätzlichen Sprache kann zudem ein attraktiver Faktor auf dem Arbeitsmarkt sein und sogar neue Berufsperspektiven ermöglichen. Nichts stärkt die europäische Identität mehr als Begegnung und gelebtes Miteinander über Ländergrenzen hinweg. Dafür steht auch Erasmus+, das EU-Programm für allgemeine und berufliche Bildung, Jugend und Sport (2021 - 2027)."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/erasmus-plus","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:22.737658+00:00","lastSeen":"2026-03-15T17:53:22.737658+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/erasmus-plus","crawledAt":"2026-03-15T17:53:22.737658Z","crawlId":"contacts-seeded-1773597202","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"9f97ef32270e040c225621107c7c66cb80e9c8cbaa86094a86e8d465f986384e"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:22.737658+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c4cfae1d-1240-4795-a159-3e0d311eb698', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/europaeischer-sozialfonds-esf', 'active', NULL, '2026-03-15T17:53:23.242765+00:00', '{"id":"c4cfae1d-1240-4795-a159-3e0d311eb698","title":"Europäischer Sozialfonds","summary":{"de":"Der Europäische Sozialfonds (ESF) ist Europas wichtigstes Instrument zur Förderung der Beschäftigung und sozialer Integration in Europa."},"content":{"de":"Seit über 60 Jahren verbessert der Europäische Sozialfonds (ESF) die Beschäftigungschancen der Menschen in Deutschland und in Europa: Er fördert eine bessere Bildung, unterstützt durch Ausbildung und Qualifizierung und trägt zum Abbau von Benachteiligungen am Arbeitsmarkt bei. Der Europäische Sozialfonds (ESF) wird auch künftig als ESF Plus wichtigstes Finanzierungs- und damit auch Förderinstrument der Europäischen Union (EU) für Investitionen in Menschen sein. Hauptziel ist es, zu einem sozialeren Europa beizutragen und die europäische Säule sozialer Rechte in die Praxis umzusetzen. Der ESF investiert vor Ort in Maßnahmen, um Menschen bei der Bewältigung wirtschaftlicher und sozialer Herausforderungen zu unterstützen. In der aktuellen Förderperiode wird der neue ESF Plus noch stärker auf den Gedanken eines sozialeren Europas ausgerichtet. Inhaltlich soll der ESF Plus insbesondere den Zugang zu Beschäftigung, allgemeiner und beruflicher Bildung verbessern, die sozioökonomische Integration von Drittstaatsangehörigen,"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/europaeischer-sozialfonds-esf","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:23.242765+00:00","lastSeen":"2026-03-15T17:53:23.242765+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/europaeischer-sozialfonds-esf","crawledAt":"2026-03-15T17:53:23.242765Z","crawlId":"contacts-seeded-1773597203","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"70e8c65190d4461aca67dbbe938918b2280a2000390b8b7a3746b6aed13b4290"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:23.242765+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('2e80985c-5166-4daf-aa4c-7fdba07fe291', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-familienpolitik', 'active', NULL, '2026-03-15T17:53:23.749017+00:00', '{"id":"2e80985c-5166-4daf-aa4c-7fdba07fe291","title":"Internationale Familienpolitik","summary":{"de":"Familienpolitik liegt in erster Linie in nationaler Zuständigkeit und ist daher von den in den Mitgliedstaaten der Europäischen Union (EU) jeweils vorherrschenden Einstellungen..."},"content":{"de":"Die Mitgliedstaaten der Europäischen Union (EU) stehen alle vor ähnlichen familienpolitischen Herausforderungen. Ihre Familienpolitik zielt daher auf die Vereinbarkeit von Familie und Beruf sowie gute Entwicklungschancen für Kinder ab. Familienpolitik liegt in erster Linie in nationaler Zuständigkeit und ist daher von den in den Mitgliedstaaten der Europäischen Union (EU) jeweils vorherrschenden Einstellungen, gesellschaftlichen Rahmenbedingungen und Traditionen geprägt. Entsprechend groß ist die Bandbreite von Erwerbs- und Vereinbarkeitsmodellen in Europa. In allen EU-Staaten zielt die Familienpolitik jedoch auf die Vereinbarkeit von Familie und Beruf sowie gute Entwicklungschancen für alle Kinder ab. Die Vereinbarkeitsrichtlinie der Europäischen Union schafft einen EU-weiten Mindeststandard für eine partnerschaftliche Aufteilung der Familienarbeit. Das Bundeskabinett hat im Juni 2022 einem Gesetz zugestimmt, um die wenigen in Deutschland noch offenen Punkte aus der Richtlinie bis Ende des Jahres 2022 umzusetzen. Ziel ist, eine bessere Vereinbarkeit von Beruf und Privatleben für Eltern und pflegende Angehörige. Der Rat der Europäischen Union hat im Juni 2021 einstimmig eine Empfehlung zur Einführung einer EU-Kindergarantie beschlossen. Deren Ziel ist es, die soziale Ausgrenzung von Kindern zu bekämpfen, Kinderrechte zu stärken und Chancengleichheit zu fördern. Dabei geht es um den Zugang zu In einem Nationalen Aktionsplan \"Neue Chancen für Kinder in Deutschland\" mit einer Laufzeit bis 2030 soll die Ratsempfehlung zu einer EU-Kindergarantie umgesetzt werden. Zur Steuerung dieses Prozesses ernannte die damalige Bundesministerin Lisa Paus die damalige Parlamentarische Staatssekretärin Ekin Deligöz zur Nationalen Kinderchancen-Koordinatorin. Die Erarbeitung des Nationalen Aktionsplans soll von einem breit angelegten Beteiligungsprozess mit Akteurinnen und Akteuren aus Politik und Zivilgesellschaft begleitet werden. Die Verabschiedung des Nationalen Aktionsplans im Bundeskabinett ist für Anfang 2023 geplant."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-familienpolitik","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:23.749017+00:00","lastSeen":"2026-03-15T17:53:23.749017+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-familienpolitik","crawledAt":"2026-03-15T17:53:23.749017Z","crawlId":"contacts-seeded-1773597203","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"d4628100618188903718d1514232022412b3689502c38220bf6c8f40116c6c75"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:23.749017+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('4b5c4ef5-5f97-478d-b184-1e18d27f6e33', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik', 'active', NULL, '2026-03-15T17:53:24.246222+00:00', '{"id":"4b5c4ef5-5f97-478d-b184-1e18d27f6e33","title":"Internationale und europäische Jugendpolitik","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Jugend und Europa Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Das Europäische Jahr der Jugend 2022 Die Europäische Union hat 2022 das Europäische Jahr der Jugend ausgerufen. Es soll neue Chancen für junge Menschen eröffnen und ihren Meinungen und Ideen mehr Gehör verschaffen. Die Europäische Union hat 2022 das Europäische Jahr der Jugend ausgerufen. Es soll neue Chancen für junge Menschen eröffnen und ihren Meinungen und Ideen mehr Gehör verschaffen. Die Jugendstrategie der Bundesregierung \"In gemeinsamer Verantwortung: Politik für, mit und von Jugend\" unter diesem Motto steht die Jugendstrategie der Bundesregierung. Im Mittelpunkt stehen junge Menschen zwischen zwölf und 27 Jahren. \"In gemeinsamer Verantwortung: Politik für, mit und von Jugend\" unter diesem Motto steht die Jugendstrategie der Bundesregierung. Im Mittelpunkt stehen junge Menschen zwischen zwölf und 27 Jahren."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:24.246222+00:00","lastSeen":"2026-03-15T17:53:24.246222+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik","crawledAt":"2026-03-15T17:53:24.247222Z","crawlId":"contacts-seeded-1773597204","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"1081f1816c2f44c56ba521f077670fa9e030f04d713163f1977744a00216d05f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:24.247222+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c2bc4190-7b14-4cc0-985d-0109da10512e', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik/internationale-und-europaeische-jugendpolitik', 'active', NULL, '2026-03-15T17:53:24.746510+00:00', '{"id":"c2bc4190-7b14-4cc0-985d-0109da10512e","title":"Internationale und europäische Jugendpolitik","summary":{"de":"Durch die internationale und europäische Jugendpolitik wird die bi- und multilaterale Zusammenarbeit und Verständigung im Jugendbereich mit anderen Ländern in Europa sowie weltweit aktiv..."},"content":{"de":"Durch die internationale und europäische Jugendpolitik wird die bi- und multilaterale Zusammenarbeit und Verständigung im Jugendbereich mit anderen Ländern in Europa sowie weltweit aktiv gefördert und nachhaltig gestärkt. Die internationale und europäische Jugendpolitik ist ein wichtiger Bestandteil der nationalen Jugendpolitik sowie der auswärtigen Kultur- und Bildungspolitik und umfasst die bi- und multilaterale Zusammenarbeit mit Ländern in Europa und anderen Regionen der Welt. Wichtige Partnerinnen und Partner sind dabei die Europäische Union (EU), der Europarat und die Vereinten Nationen. Die 2019 verabschiedete Jugendstrategie der Bundesregierung stellt die Interessen und Bedürfnisse der jungen Generationen in den Fokus. \"Europa und die Welt\" bildet eines von neun Handlungsfeldern, mit denen die Lebenslage junger Menschen verbessert werden soll. Dabei steht die Förderung von grenzüberschreitender Mobilität im Vordergrund, außerdem soll jungen Menschen die Möglichkeit gegeben werden, sich mit internationalen Entwicklungen auseinanderzusetzen und Europa aktiv mitzugestalten. Der internationale Jugendaustausch ist auch ein wichtiges Mittel, um Fremdenfeindlichkeit und Rassismus vorzubeugen. Internationale Erfahrungen bringen andere Menschen und andere Sprachen näher und schärfen den Blick für das eigene Land und die eigene Kultur. Jugendaustausch stärkt den europäischen Gedanken und fördert Verständigung und Toleranz auch über Europa hinaus. Das Bundesjugendministerium fördert daher zahlreiche Jugendbegegnungen und Fachkräfteprogramme und ermöglicht jungen Menschen, internationale Erfahrungen zu sammeln, interkulturelle Kompetenzen zu erwerben und Vielfalt wertschätzen zu lernen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik/internationale-und-europaeische-jugendpolitik","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:24.746510+00:00","lastSeen":"2026-03-15T17:53:24.746510+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-jugendpolitik/internationale-und-europaeische-jugendpolitik","crawledAt":"2026-03-15T17:53:24.746510Z","crawlId":"contacts-seeded-1773597204","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"9b28d01af667faf47ac16409828c093e2138657ab50955bfd0f2b928f32551c5"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:24.746510+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('f588e78d-4e1c-4846-9072-719db72aaa42', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-politik-fuer-demokratie-und-engagement', 'active', NULL, '2026-03-15T17:53:25.242196+00:00', '{"id":"f588e78d-4e1c-4846-9072-719db72aaa42","title":"Internationale Politik für Demokratie und Engagement","summary":{"de":"Millionen Menschen engagieren sich für ein friedliches, demokratisches und vielfältiges Miteinander im In- und Ausland. Das Bundesfamilienministerium fördert zahlreiche Projekte."},"content":{"de":"Täglich engagieren sich Menschen freiwillig in und außerhalb von Vereinen, Stiftungen oder Initiativen für ein friedliches, demokratisches und vorurteilfreies Miteinander. Auch international setzt sich die Bundesregierung dafür ein, diese Menschen zu unterstützen und in ihrem Engagement zu fördern, denn Engagement macht nicht an Landesgrenzen halt: Ob über den deutsch-französischen Bürgerfonds oder den Internationalen Jugendfreiwilligendienst - es gibt verschiedene Formate, in denen sich Bürgerinnen und Bürger über Grenzen hinweg für eine gute Sache einsetzen. Hier finden Sie Informationen zu den vom Bundesfamilienministerium geförderten, grenzüberschreitenden Engagementprogrammen und -formaten. Seit April 2020 werden mithilfe des Deutsch-Französischen Bürgerfonds Städtepartnerschaften und Bürgerinitiativen gefördert und unterstützt. Deutschland und Frankreich haben gemeinsam mit dem Vertrag von Aachen, der im Januar 2019 unterzeichnet wurde, ein klares Signal für die Stärkung des grenzüberschreitenden bürgerschaftlichen Engagements gesetzt. Der Deutsch-Französische Bürgerfonds soll helfen, die deutsche und die französische Zivilgesellschaft einander noch näherzubringen und den intergenerationellen Austausch zwischen den Bürgerinnen und Bürgern beider Staaten in einem geeinten Europa zu bestärken und zu vertiefen. Neue Ideen und innovative Projekte können so niedrigschwelligen Zugang zur Förderung erhalten. Gefördert werden kleine Projekte und Initiativen mit bis zu 5000 Euro sowie mittelgroße Projekte bis hin zu Leuchtturmprojekten mit über 50.000 Euro. Der Internationale Jugendfreiwilligendienst (IJFD) ist der Auslandsfreiwilligendienst des Bundesfamilienministeriums. Er ermöglicht jungen Menschen durch einen freiwilligen Dienst im Ausland interkulturelle, gesellschaftspolitische und persönliche Erfahrungen zu sammeln und so die eigene Persönlichkeit zu bereichern und sich weiterzubilden. In der Regel findet der Einsatz im sozialen oder ökologischen Bereich sowie in der Friedens- und Versöhnungsarbeit statt. Weitere Informationen über den IJFD bietet eine Website des Bundesfamilienministeriums. Mit dem Programm \"Citizens, Equality, Rights and Values\" (CERV) verfolgt die Europäische Union (EU) das Ziel, die in den EU-Verträgen verankerten Rechte und Werte zu fördern und zu schützen. CERV fördert Projekte mit einem Gesamtbudget von bis zu 1,55 Milliarden Euro für den Zeitraum 2021 bis 2027 in vier Aktionsbereichen:"},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-politik-fuer-demokratie-und-engagement","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:25.242196+00:00","lastSeen":"2026-03-15T17:53:25.242196+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/internationales/internationale-politik-fuer-demokratie-und-engagement","crawledAt":"2026-03-15T17:53:25.242196Z","crawlId":"contacts-seeded-1773597205","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"4ae614ac8b805cf0afb05ee0342706a22bb0eafec388a6d3d2045e102ae3c92f"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:25.242196+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('16b715b7-11b9-4464-8b6b-14d57ac41ab3', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend', 'active', NULL, '2026-03-15T17:53:25.802328+00:00', '{"id":"16b715b7-11b9-4464-8b6b-14d57ac41ab3","title":"Politik für Kinder und Jugendliche","summary":{"de":"Alle Kinder und Jugendlichen haben ein Recht auf gutes Aufwachsen und gleiche Chancen - unabhängig von Herkunft, Geschlecht, Religion oder sozialem..."},"content":{"de":"Bundesbildungsministerin Karin Prien hat die Qualifizierungsoffensive Berufliche Bildung gestartet. Die Initiative soll dem Fachkräftemangel begegnen und die Ausbildung entlang der gesamten Bildungskette stärken. Für einen besseren Jugendmedienschutz ist die Kooperation der Online-Plattformen wichtig. Das betonte Dr. Petra Bahr, Staatssekretärin im Bundesjugendministerium, bei einem Austausch mit Vertretern der Unternehmen und Verbände. Mit dem KiTa-Qualitätsgesetz wollen Bund und Länder die frühkindliche Bildung verbessern. Der fünfte Monitoringbericht zum Gesetz zeigt Fortschritte. Um bundesweit gleiche Bedingungen für alle Kinder zu schaffen, bleibt aber noch einiges zu tun."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:25.802328+00:00","lastSeen":"2026-03-15T17:53:25.802328+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend","crawledAt":"2026-03-15T17:53:25.803342Z","crawlId":"contacts-seeded-1773597205","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"b489bfa1ccac9a7d381364bcb6dad68d90405b2ca0b133c43823ffc9993b154a"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:25.803342+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('d8e59309-86a3-4b1c-859a-643397d7a419', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/integration-und-chancen-fuer-junge-menschen', 'active', NULL, '2026-03-15T17:53:26.269093+00:00', '{"id":"d8e59309-86a3-4b1c-859a-643397d7a419","title":"Integration und Chancen für junge Menschen","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Initiative \"JUGEND STÄRKEN\" Mit den Programmen \"Jugendmigrationsdienste\", \"Respekt Coaches\" und \"JUGEND STÄRKEN - Brücken in die Eigenständigkeit\" unterstützt das Bundesjugendministerium junge Menschen und fördert Toleranz und Vielfalt im sozialen und schulischen Bereich. Mit den Programmen \"Jugendmigrationsdienste\", \"Respekt Coaches\" und \"JUGEND STÄRKEN - Brücken in die Eigenständigkeit\" unterstützt das Bundesjugendministerium junge Menschen und fördert Toleranz und Vielfalt im sozialen und schulischen Bereich. Garantiefonds Hochschule Mit den Richtlinien \"Garantiefonds Hochschule\" werden Spätaussiedlerinnen und Spätaussiedler, Flüchtlinge und Zugewanderte auf dem Weg zum Abitur und ins Studium unterstützt. Mit den Richtlinien \"Garantiefonds Hochschule\" werden Spätaussiedlerinnen und Spätaussiedler, Flüchtlinge und Zugewanderte auf dem Weg zum Abitur und ins Studium unterstützt. Kriminalitäts- und Gewaltprävention Das Bundesjugendministerium trägt aktiv zu Handlungsstrategien bei, um Kinder- und Jugendkriminalität vorzubeugen. Es regt Fachdiskussionen an und setzt thematische Schwerpunkte. Das Bundesjugendministerium trägt aktiv zu Handlungsstrategien bei, um Kinder- und Jugendkriminalität vorzubeugen. Es regt Fachdiskussionen an und setzt thematische Schwerpunkte."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/integration-und-chancen-fuer-junge-menschen","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:26.269093+00:00","lastSeen":"2026-03-15T17:53:26.269093+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/integration-und-chancen-fuer-junge-menschen","crawledAt":"2026-03-15T17:53:26.269093Z","crawlId":"contacts-seeded-1773597206","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"bfdb2f3524af51591e9a6eac9199110d55c9d8cf23ec5ca4d414caab10cd7680"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:26.269093+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('0612fd36-ec92-4d88-bb49-da2c1c00c3be', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung', 'active', NULL, '2026-03-15T17:53:26.749241+00:00', '{"id":"0612fd36-ec92-4d88-bb49-da2c1c00c3be","title":"Jugendbildung","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"Kinder- und Jugendarbeit Kinder- und Jugendarbeit setzt an den Stärken junger Menschen an und unterstützt ihre Entwicklung zu eigenverantwortlichen und gemeinschaftsfähigen Persönlichkeiten. Kinder- und Jugendarbeit setzt an den Stärken junger Menschen an und unterstützt ihre Entwicklung zu eigenverantwortlichen und gemeinschaftsfähigen Persönlichkeiten. Jugend und Europa Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Die Bundesregierung setzt sich dafür ein, dass junge Menschen fit werden für ein Leben in internationalen und interkulturellen Bezügen. Dafür fördert sie Initiativen und Projekte, sowie Begegnungen junger Menschen in Europa. Förderprogramm \"Jugend erinnert\" Ziel des Förderprogramms \"Jugend erinnert\" ist es, möglichst vielen Jugendlichen den Besuch eines Lernorts der NS-Vergangenheit zu ermöglichen. Dabei berücksichtigt das Programm auch weniger bekannte Gedenkstätten und Opfergruppen. Ziel des Förderprogramms \"Jugend erinnert\" ist es, möglichst vielen Jugendlichen den Besuch eines Lernorts der NS-Vergangenheit zu ermöglichen. Dabei berücksichtigt das Programm auch weniger bekannte Gedenkstätten und Opfergruppen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:26.749241+00:00","lastSeen":"2026-03-15T17:53:26.749241+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung","crawledAt":"2026-03-15T17:53:26.749241Z","crawlId":"contacts-seeded-1773597206","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"fdd57768b0b379ea18e4d99a6d03b092adc48f07cce89032360b0f1e8f286735"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:26.749241+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6c3e63cd-9c39-4bae-88fd-8f00f653cbae', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung/jugendstrategie/jugendstrategie', 'active', NULL, '2026-03-15T17:53:27.292644+00:00', '{"id":"6c3e63cd-9c39-4bae-88fd-8f00f653cbae","title":"Die Jugendstrategie der Bundesregierung","summary":{"de":"Mit ihrer gemeinsamen Jugendstrategie zeigt die Bundesregierung, dass sie die Interessen und Bedürfnisse der jungen Generation berücksichtigt. Die Jugendstrategie umfasst 163 Maßnahmen in neun..."},"content":{"de":"Mit ihrer gemeinsamen Jugendstrategie zeigt die Bundesregierung, dass sie die Interessen und Bedürfnisse der jungen Generation berücksichtigt. Die Jugendstrategie umfasst 163 Maßnahmen in neun Handlungsfeldern. Um die Jugendstrategie umzusetzen, wird die interministerielle Zusammenarbeit fortgesetzt. Bestehende Maßnahmen der Jugendstrategie werden weiterentwickelt, die Ressorts konzipieren neue Formate und Angebote für, mit und von Jugendlichen. Alle Ressorts sind dabei beteiligt. Mit der Interministeriellen Arbeitsgruppe (IMA) Jugend unter Federführung des Bundesjugendministeriums wird die ressortübergreifende Zusammenarbeit im Bereich Jugendpolitik gestärkt. I n Deutschland leben 14 Millionen junge Menschen zwischen 12 und 27 Jahren. Das sind 17 Prozent der Gesamtbevölkerung. Jugend ist ebenso vielfältig wie die Gesellschaft, deren Teil sie ist. Aber für alle Jugendlichen und jungen Erwachsenen geht es in dieser Lebensphase darum, selbstständig zu werden, sich zu qualifizieren und ihren Platz in der Gesellschaft zu finden. Ob bedarfsgerechter Nahverkehr, schnelles Internet, bezahlbare Mieten oder wirksamer Klimaschutz - Maßnahmen in allen Politikfeldern können Auswirkungen auf die junge Generation haben. Daher hat die Bundesregierung unter Federführung des Bundesjugendministeriums gemeinsam mit allen Ressorts eine Jugendstrategie entwickelt. Bei der Entwicklung der Jugendstrategie wurden junge Menschen als Expertinnen und Experten in eigener Sache beteiligt. Viele von ihnen brachten ihre Vorstellungen und Wünsche ein bei den JugendPolitikTagen, in themenspezifischen Audits oder via Online-Konsultation."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung/jugendstrategie/jugendstrategie","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:27.292644+00:00","lastSeen":"2026-03-15T17:53:27.292644+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/jugendbildung/jugendstrategie/jugendstrategie","crawledAt":"2026-03-15T17:53:27.292644Z","crawlId":"contacts-seeded-1773597207","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"3a1baf00b03f9ac0d90a31d51718bee31a4e58ac2e7905e052086b633cbe8582"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:27.292644+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b22d4045-27b6-481a-bcd5-caa0be410434', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendgesundheit', 'active', NULL, '2026-03-15T17:53:27.749893+00:00', '{"id":"b22d4045-27b6-481a-bcd5-caa0be410434","title":"Kinder- und Jugendgesundheit","summary":{"de":"Körperliche und seelische Gesundheit ist eine wesentliche Voraussetzung für ein gutes Aufwachsen von Kindern und Jugendlichen. Das..."},"content":{"de":"Mentale Gesundheit Die mentale Gesundheit von Kindern und Jugendlichen ist weiterhin stark gefordert. Das Bundesjugendministerium unterstützt junge Menschen bei der Stärkung ihrer mentalen Gesundheit. Die mentale Gesundheit von Kindern und Jugendlichen ist weiterhin stark gefordert. Das Bundesjugendministerium unterstützt junge Menschen bei der Stärkung ihrer mentalen Gesundheit. Suizidprävention Suizid ist die häufigste Todesursache bei jungen Menschen. Rund 500 junge Menschen nehmen sich jedes Jahr in Deutschland das Leben. Häufig haben sie Ängste und Sorgen, die suizidale Gedanken auslösen können. Darüber zu sprechen fällt vielen schwer. Suizid ist die häufigste Todesursache bei jungen Menschen. Rund 500 junge Menschen nehmen sich jedes Jahr in Deutschland das Leben. Häufig haben sie Ängste und Sorgen, die suizidale Gedanken auslösen können. Darüber zu sprechen fällt vielen schwer. Kinder und Jugendliche nach der Pandemie Welche Auswirkungen hatte die Corona-Pandemie auf junge Menschen? Eine von der Bundesregierung geleitete Arbeitsgruppe aus Expertinnen und Experten hat die Folgen analysiert und Lösungsansätze entwickelt. Welche Auswirkungen hatte die Corona-Pandemie auf junge Menschen? Eine von der Bundesregierung geleitete Arbeitsgruppe aus Expertinnen und Experten hat die Folgen analysiert und Lösungsansätze entwickelt."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendgesundheit","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:27.749893+00:00","lastSeen":"2026-03-15T17:53:27.749893+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendgesundheit","crawledAt":"2026-03-15T17:53:27.749893Z","crawlId":"contacts-seeded-1773597207","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"6c95801b13233347eaeec2ee982e0aacb7c610e55e709f9ed5f9e01c6e862946"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:27.749893+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7900e26e-b8ea-4783-b055-73d4866cac14', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz', 'active', NULL, '2026-03-15T17:53:28.264435+00:00', '{"id":"7900e26e-b8ea-4783-b055-73d4866cac14","title":"Kinder- und Jugendschutz","summary":{"de":"Kinder und Jugendliche haben ein Recht auf Schutz vor körperlicher, sexueller und seelischer Gewalt. Im Kinder- und Jugendschutz geht es sowohl um..."},"content":{"de":"Bundesstiftung Frühe Hilfen Die Bundesstiftung Frühe Hilfen unterstützt werdende und junge Eltern in schwierigen Situationen. Im Fokus steht ein gesundes und gewaltfreies Aufwachsen von Kindern. Die Bundesstiftung Frühe Hilfen unterstützt werdende und junge Eltern in schwierigen Situationen. Im Fokus steht ein gesundes und gewaltfreies Aufwachsen von Kindern. Schutz vor sexualisierter Gewalt Die Bundesregierung unternimmt eine Reihe von Maßnahmen, um den Schutz von Kindern und Jugendlichen vor sexualisierter Gewalt kontinuierlich zu verbessern. Die Bundesregierung unternimmt eine Reihe von Maßnahmen, um den Schutz von Kindern und Jugendlichen vor sexualisierter Gewalt kontinuierlich zu verbessern. Hilfe-Telefon Sexueller Missbrauch Bei Verdachtsfällen von sexuellem Missbrauch berät das Hilfe-Telefon unter der Nummer 0800 22 55 530 montags, mittwochs und freitags von 9:00 bis 14:00 Uhr sowie dienstags und donnerstags von 15:00 bis 20:00 Uhr - kostenfrei und anonym. Bei Verdachtsfällen von sexuellem Missbrauch berät das Hilfe-Telefon unter der Nummer 0800 22 55 530 montags, mittwochs und freitags von 9:00 bis 14:00 Uhr sowie dienstags und donnerstags von 15:00 bis 20:00 Uhr - kostenfrei und anonym."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:28.264435+00:00","lastSeen":"2026-03-15T17:53:28.264435+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz","crawledAt":"2026-03-15T17:53:28.264435Z","crawlId":"contacts-seeded-1773597208","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"e3e4b72e410785f7faa3d27d16c9d263f54421612c9d330f7ca90159ba3d89fb"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:28.264435+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('dff696a1-a631-491b-9ab1-4d725aa15cb1', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz/aktiver-jugendschutz', 'active', NULL, '2026-03-15T17:53:28.751940+00:00', '{"id":"dff696a1-a631-491b-9ab1-4d725aa15cb1","title":"Aktiver Jugendschutz","summary":{"de":"Kinder und Jugendliche begegnen in ihrem Alltag immer wieder Gefahren für ihre körperliche und geistige Gesundheit. Das Jugendschutzgesetz regelt den Umgang mit diesen Gefahrenquellen."},"content":{"de":"Kinder und Jugendliche begegnen in ihrem Alltag immer wieder Gefahren für ihre körperliche und geistige Gesundheit. Das Jugendschutzgesetz regelt den Umgang mit diesen Gefahrenquellen, zum Beispiel durch Bestimmungen für die Abgabe von Alkohol oder Tabak. Aufgabe des Staates ist es, Kinder und Jugendliche durch effektive und praxiswirksame Jugendschutzvorschriften vor Gefährdungen in der Öffentlichkeit zu schützen und ein gutes Aufwachsen mit Medien zu gewährleisten. Das Jugendschutzgesetz (JuSchG) regelt unter anderem den Verkauf und die Abgabe von Tabak, Alkohol, Filmen, Computerspielen sowie den Aufenthalt in Diskotheken und Gaststätten. Gemeinsam mit dem Jugendmedienschutz-Staatsvertrag (JMStV) der Länder wurde eine einheitliche Rechtsgrundlage für den Jugendschutz in den elektronischen Medien (Internet, Fernsehen, Rundfunk) geschaffen. Das vom Bundesjugendministerium vorgelegte Gesetz zum Schutz von Kindern und Jugendlichen vor den Gefahren des Konsums von elektronischen Zigaretten und elektronischen Shishas ist am 1. April 2016 in Kraft getreten. Damit werden die Abgabe- und Konsumverbote des Jugendschutzgesetzes und des Jugendarbeitsschutzgesetzes für Tabakwaren auf E-Zigaretten und E-Shishas ausgedehnt. Zudem wird sichergestellt, dass die Abgabeverbote von Tabakwaren, E-Zigaretten- und E-Shishas an Kinder und Jugendliche auch im Wege des Versandhandels gelten. Das Ziel des \"Zweiten Gesetzes zur Änderung des Jugendschutzgesetzes\" ist ein zeitgemäßer und zukunftssicherer Kinder- und Jugendmedienschutz, der die wesentlichen Risiken erfasst und Kindern und Jugendlichen ein gutes Aufwachsen mit Medien gewährleistet. Das Gesetz ist am 1. Mai 2021 in Kraft getreten. Schutz von Kindern und Jugendlichen vor Interaktionsrisiken wie Mobbing, sexueller Anmache oder Kostenfallen."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz/aktiver-jugendschutz","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:28.751940+00:00","lastSeen":"2026-03-15T17:53:28.751940+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinder-und-jugendschutz/aktiver-jugendschutz","crawledAt":"2026-03-15T17:53:28.751940Z","crawlId":"contacts-seeded-1773597208","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"c0563542545bc0d62ccf368ba4b4303ac227288b7bd68cd8b49a40d91d8692da"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:28.751940+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('28656670-ba76-47a9-a028-7445c1901bd3', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinderrechte', 'active', NULL, '2026-03-15T17:53:29.276268+00:00', '{"id":"28656670-ba76-47a9-a028-7445c1901bd3","title":"Starke Kinder","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"UN-Kinderrechtskonvention Die UN-Kinderrechtskonvention wurde 1989 verabschiedet und trat 1992 in Deutschland in Kraft. Sie schützt weltweit die Rechte der Kinder. Die UN-Kinderrechtskonvention wurde 1989 verabschiedet und trat 1992 in Deutschland in Kraft. Sie schützt weltweit die Rechte der Kinder. Kinderrechte im Alltag Die Rechte von Kindern stehen im Alltag oft in Konflikt mit anderen Interessen. Aber die UN-Kinderrechtskonvention sagt klar: Das Kindeswohl hat Vorrang. Die Rechte von Kindern stehen im Alltag oft in Konflikt mit anderen Interessen. Aber die UN-Kinderrechtskonvention sagt klar: Das Kindeswohl hat Vorrang. Partnerinnen und Partner Das Bundesbildungsministerium steht im stetigen Austausch mit vielen Organisationen, die Kinder und Jugendliche unterstützen und ihre Rechte stärken. Das Bundesbildungsministerium steht im stetigen Austausch mit vielen Organisationen, die Kinder und Jugendliche unterstützen und ihre Rechte stärken."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinderrechte","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:29.276268+00:00","lastSeen":"2026-03-15T17:53:29.276268+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/kinderrechte","crawledAt":"2026-03-15T17:53:29.276268Z","crawlId":"contacts-seeded-1773597209","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"aa2e9c9a4174cc09e6e4c5dd4c1e4e6d3fda9941a9936062148db0ce9b81a824"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:29.276268+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5147ed7b-8568-40d8-87dc-afc9c774ad2f', 'contacts', 'https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/medienkompetenz', 'active', NULL, '2026-03-15T17:53:29.778786+00:00', '{"id":"5147ed7b-8568-40d8-87dc-afc9c774ad2f","title":"Medienkompetenz","summary":{"de":"Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Einwilligen Ablehnen"},"content":{"de":"\"SCHAU HIN! - Was Dein Kind mit Medien macht\" Medien spielen für Kinder und Jugendliche eine zentrale Rolle. Viele Eltern und Erziehende stehen vor der Herausforderung: Wie unterstütze ich mein Kind dabei, Smartphone, Konsole, Apps und soziale Netzwerke altersgerecht und sicher zu nutzen? Medien spielen für Kinder und Jugendliche eine zentrale Rolle. Viele Eltern und Erziehende stehen vor der Herausforderung: Wie unterstütze ich mein Kind dabei, Smartphone, Konsole, Apps und soziale Netzwerke altersgerecht und sicher zu nutzen? Kinder-Ministerium Das Kinder-Ministerium ist ein Online-Angebot für Kinder zwischen sieben und elf Jahren. Spielerisch können sie dort mehr über die Themen Politik und Kinderrechte erfahren. Das Kinder-Ministerium ist ein Online-Angebot für Kinder zwischen sieben und elf Jahren. Spielerisch können sie dort mehr über die Themen Politik und Kinderrechte erfahren. Bundesbildungsministerin Karin Prien hat die Qualifizierungsoffensive Berufliche Bildung gestartet. Die Initiative soll dem Fachkräftemangel begegnen und die Ausbildung entlang der gesamten Bildungskette stärken. Bund und Länder investieren bis 2030 gemeinsam fünf Milliarden Euro in die digitale Modernisierung der Schulen. Darauf verständigte sich die Bildungsministerkonferenz in Berlin."},"url":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/medienkompetenz","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:29.778786+00:00","lastSeen":"2026-03-15T17:53:29.778786+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Bundesministerium fuer Bildung, Familie, Senioren, Frauen und Jugend","provenance":{"source":"https://www.bmbfsfj.bund.de/bmbfsfj/themen/kinder-und-jugend/medienkompetenz","crawledAt":"2026-03-15T17:53:29.778786Z","crawlId":"contacts-seeded-1773597209","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"bmbfsfj_bund_de","providerName":"bmbfsfj.bund.de","providerLevel":"federal","checksum":"bf40af409ea283f1dd4a22ec8e8ede01b034c19aa8f6fd5897ff32021b0913e0"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:53:29.778786+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('06a86ebd-13a2-4701-b01f-169605fa8c94', 'contacts', 'https://www.diakonie.de/informieren/einrichtungssuche', 'active', NULL, '2026-03-15T17:53:31.818389+00:00', '{"id":"06a86ebd-13a2-4701-b01f-169605fa8c94","title":"Einrichtungssuche","summary":{"de":"Aktuelles Bundeshaushalt 2026 Einschätzung zum Koalitionsvertrag 2025-2029 Studie zur Aufarbeitung sexualisierter Gewalt"},"content":{"de":"Aktuelles Bundeshaushalt 2026 Einschätzung zum Koalitionsvertrag 2025-2029 Studie zur Aufarbeitung sexualisierter Gewalt"},"url":"https://www.diakonie.de/informieren/einrichtungssuche","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:53:31.818389+00:00","lastSeen":"2026-03-15T17:53:31.818389+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"diakonie.de","provenance":{"source":"https://www.diakonie.de/informieren/einrichtungssuche","crawledAt":"2026-03-15T17:53:31.819384Z","crawlId":"contacts-seeded-1773597211","crawlerVersion":"0.1.0","sourceTier":"tier_2_ngo_watchdog","institutionType":"ngo","jurisdiction":"DE","sourceId":"diakonie_de","providerName":"diakonie.de","providerLevel":"civil_society","checksum":"cc27be9c06abcc30fe2230a779b5d46b6934b1238fc0632ae99b8c580e091bb7"},"qualityScores":{"iqs":84.58,"ais":80.0,"computedAt":"2026-03-15T17:53:31.819384+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('80882013-8371-4673-8c66-c1bcaf3a7215', 'contacts', 'https://www.fitko.de/', 'active', NULL, '2026-03-15T17:54:05.183964+00:00', '{"id":"80882013-8371-4673-8c66-c1bcaf3a7215","title":"Willkommen bei der FITKO!","summary":{"de":"FITKO (Föderale IT-Kooperation) mit Sitz in Frankfurt am Main bündelt die bisherigen Geschäfts- und Koordinierungsstellen des IT-Planungsrats."},"content":{"de":"Wir – die Föderale IT-Kooperation oder kurz: FITKO – gestalten gemeinsam mit Bund, Ländern und Kommunen die Digitalisierung der Verwaltung in Deutschland. Als zentrale Koordinierungs- und Vernetzungsstelle bündeln wir die Kräfte des föderalen Systems, schaffen die notwendigen Rahmenbedingungen für eine effektive Verwaltungsdigitalisierung und sorgen für die Umsetzung der Entscheidungen des IT-Planungsrats. So tragen wir zu einer wirkungsvollen digitalen Verwaltung für Bürger:innen und Unternehmen bei. Kooperativ Wir fördern gemeinsame Lösungen und stärken die föderale Zusammenarbeit über alle Ebenen hinweg. Wir fördern gemeinsame Lösungen und stärken die föderale Zusammenarbeit über alle Ebenen hinweg. Vernetzt Durch Vernetzung ermöglichen wir Synergieeffekte und zuverlässigen Wissensaustausch. Durch Vernetzung ermöglichen wir Synergieeffekte und zuverlässigen Wissensaustausch. Kompetent Wir bündeln fachliches Know-How und schaffen so die Grundlagen für qualifizierte Entscheidungen."},"url":"https://www.fitko.de/","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:05.183964+00:00","lastSeen":"2026-03-15T17:54:05.183964+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/","crawledAt":"2026-03-15T17:54:05.184469Z","crawlId":"contacts-seeded-1773597245","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"1b57124825b1453b84836570fd73625b9b8dca864bdabe3b067fc7b4f53d6fa8"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:05.184469+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('e2ab0ce0-4ede-4962-98e2-d3ecafdf125b', 'contacts', 'https://www.fitko.de/barrierefreiheitserklaerung', 'active', NULL, '2026-03-15T17:54:05.940255+00:00', '{"id":"e2ab0ce0-4ede-4962-98e2-d3ecafdf125b","title":"Erklärung zur Barrierefreiheit","summary":{"de":"Als öffentliche Stelle im Sinne der Richtlinie (EU) 2016/2102 und gemäß § 2 der Hessischen Verordnung über barrierefreie Informationstechnik sind wir bemüht, unsere Websites im Einklang mit den Bestimmungen des Hessischen Gesetzes zur Gleichstellung von Menschen mit Behinderungen (HessBGG) und der Hessischen Verordnung über barrierefreie Informationstechnik (HVBIT) barrierefrei zugänglich zu machen."},"content":{"de":"Diese Erklärung zur Barrierefreiheit gilt für die unter der unter https://www.fitko.de veröffentlichten Webseiten der FITKO (Föderale IT-Kooperation) AöR. Zum § 2 der Hessischen Verordnung über barrierefreie Informationstechnik Zum Hessischen Gesetz zur Gleichstellung von Menschen mit Behinderungen (HessBGG) Zur Hessischen Verordnung über barrierefreie Informationstechnik (HVBIT) Die Anforderungen der Barrierefreiheit ergeben sich aus §§ 3 Absätze 1 bis 4 und 4 der HVBIT, die auf der Grundlage von §14 des HessBGG erlassen wurde. Die Überprüfung der Einhaltung der Anforderungen beruht auf einer im September 2021 vor Abnahme der neu erstellten Website mit Hilfe von https://testen.bitv-test.de/selbstbewertung/test.php durchgeführten Selbstbewertung."},"url":"https://www.fitko.de/barrierefreiheitserklaerung","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:05.940255+00:00","lastSeen":"2026-03-15T17:54:05.940255+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/barrierefreiheitserklaerung","crawledAt":"2026-03-15T17:54:05.940255Z","crawlId":"contacts-seeded-1773597245","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"d2ca9d6ec69ccf6186bf82cd28c5801389d994d572286f4baa993e6b0e01bb8b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:05.940255+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('6b8eab77-0053-41cd-8e62-1730502e7e54', 'contacts', 'https://www.fitko.de/der-it-planungsrat/foederale-digitalstrategie', 'active', NULL, '2026-03-15T17:54:07.903146+00:00', '{"id":"6b8eab77-0053-41cd-8e62-1730502e7e54","title":"Föderale Digitalstrategie für die Verwaltung","summary":{"de":"Die Seite Föderale Digitalstrategie der FITKO."},"content":{"de":"Mit der Föderalen Digitalstrategie für die Verwaltung hat der IT-Planungsrat ein Instrument geschaffen, um die Verwaltung zukunftsfähig zu machen und die Zusammenarbeit von Bund, Ländern und Kommunen bei der Verwaltungsdigitalisierung effizienter zu gestalten. Ziel ist es, das Motto des IT-Planungsrats „Gemeinsam wirksam“ in die Praxis zu überführen. Ein Zukunftsbild der Verwaltung sowie Leitlinien leisten dabei einen wichtigen Beitrag, den Erwartungen von Bürger:innen, Unternehmen, Mitarbeitenden der Verwaltung und politischen Entscheider:innen gerecht zu werden: die Verwaltung als effiziente Dienstleisterin und Arbeitgeberin für ein modernes Deutschland. Die Erstellung der Föderalen Digitalstrategie für die Verwaltung wurde im November 2023 vom IT-Planungsrat initiiert und besteht aus 3 Komponenten. Die Dachstrategie legt die gesamtstrategische Ausrichtung fest. Sie beinhaltet ein Zukunftsbild der Verwaltung sowie die Leitlinien, die die Rahmensetzung für eine Umsetzung geben. In den Schwerpunktthemen – Digitale Transformation, Digitale Infrastruktur, Digitale Anwendungen, Datennutzung, Informationssicherheit – wurden in partizipativen Formaten konkrete Zielbilder für die Umsetzung entwickelt. Im dritten Schritt werden konkrete Umsetzungsvorhaben abgeleitet. Einige von ihnen sind bereits umgesetzt, andere werden derzeit neu miteinander verknüpft, und weitere sind noch zu initiieren. Das Zukunftsbild der Verwaltung spiegelt die Überzeugung wider, dass die föderale Gemeinschaft durch gemeinsame Strategien, Strukturen und Standards weiterkommt. Die Leitlinien beschreiben die gemeinsamen Handlungsgrundsätze und gehen in ihrer Ambition weit über die staatsvertraglich vereinbarten Aufgaben hinaus, um einen Impuls über Ressortgrenzen hinweg zu geben."},"url":"https://www.fitko.de/der-it-planungsrat/foederale-digitalstrategie","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:07.903146+00:00","lastSeen":"2026-03-15T17:54:07.903146+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/der-it-planungsrat/foederale-digitalstrategie","crawledAt":"2026-03-15T17:54:07.903146Z","crawlId":"contacts-seeded-1773597247","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"c72094f07962800bb919acc53e7476bc3aaf88c6eb2b6db548784aec2bf2b886"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:54:07.903146+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('5cdd3a0c-0c64-4457-8659-973cdd300eba', 'contacts', 'https://www.fitko.de/foederale-it-architektur', 'active', NULL, '2026-03-15T17:54:08.369856+00:00', '{"id":"5cdd3a0c-0c64-4457-8659-973cdd300eba","title":"Föderale IT-Architektur","summary":{"de":"Der IT-Planungsrat hat die FITKO damit beauftragt, in Kooperation mit Bund und Ländern federführend eine föderale IT-Architektur zu erarbeiten. Mit einem föderalen IT-Architekturmanagement sorgen wir für gemeinsame Standards und Basiskomponenten für alle angeschlossenen Verwaltungen."},"content":{"de":"Fachlich & strategisch. Wir gestalten die zukünftige Infrastruktur mit. Eine moderne digitale Verwaltung kann nur erfolgreich sein, wenn die IT-Landschaften aller Verwaltungsebenen optimal zusammenspielen und aufeinander abgestimmt sind. Deshalb hat der IT-Planungsrat uns als FITKO damit beauftragt, in Kooperation mit Bund und Ländern federführend eine föderale IT-Architektur zu erarbeiten. Mit einem föderalen IT-Architekturmanagement sorgen wir für gemeinsame Standards und Basiskomponenten für alle angeschlossenen Verwaltungen. So stellen wir eine einheitliche Architektur sicher, bei der sich einzelne Infrastrukturelemente durch ihre standardisierten Schnittstellen und Datenformate flexibel miteinander kombinieren lassen und für andere Bereiche nachnutzbar sind. Wir ermitteln die bereits bestehenden Infrastrukturelemente, die es in die föderale IT-Architektur zu integrieren gilt (IST-Architektur). Darauf aufbauend identifizieren wir die zusätzlich benötigte Infrastruktur auf Basis strategischer Ziele und externer Anforderungen. Abschließend erarbeiten wir eine entsprechende SOLL-Architektur."},"url":"https://www.fitko.de/foederale-it-architektur","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:08.369856+00:00","lastSeen":"2026-03-15T17:54:08.369856+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/foederale-it-architektur","crawledAt":"2026-03-15T17:54:08.369856Z","crawlId":"contacts-seeded-1773597248","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"aab2c499778010453fd9e13aef9cbcd98ff6cad93abaa75bff76f97b9ce3774b"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:08.369856+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('a3c023eb-1c22-4563-9015-2c963fb037f6', 'contacts', 'https://www.fitko.de/foederale-it-architektur/foederales-it-architekturmanagement', 'active', NULL, '2026-03-15T17:54:08.857160+00:00', '{"id":"a3c023eb-1c22-4563-9015-2c963fb037f6","title":"Föderales IT-Architekturmanagement","summary":{"de":"Die Seite Föderales IT-Architekturmanagement der FITKO."},"content":{"de":"Eine einheitliche IT-Architektur von Bund, Ländern und Kommunen braucht ein abgestimmtes Vorgehen. Genau das leistet das föderale IT-Architekturmanagement der FITKO. Es stellt sicher, dass sich einzelne Infrastrukturelemente der verschiedenen föderalen IT-Architekturen durch standardisierte Schnittstellen und Datenformate flexibel miteinander kombinieren lassen und für andere Bereiche nachnutzbar sind. Als FITKO steuern wir diesen Prozess, unterstützen die Akteur:innen bei der strategischen Planung und begleiten die Umsetzung der Vorhaben. Bei der Erarbeitung eines föderalen IT-Architekturmanagements geht es darum, vor allem folgende Fragen zu beantworten: Wie können die Bedarfe aller föderalen Stakeholder adäquat erfasst und adressiert werden? Wie kann eine föderale Antragsarchitektur schnell genug realisiert und umgesetzt werden, um mit der engen Umsetzungsfrist des Onlinezugangsgesetzes Schritt zu halten? Auf welche Weise kann ein Ausgleich zwischen dezentraler Entscheidungsfreiheit und zentral verbindlichen Standards und Infrastrukturen geschaffen werden?"},"url":"https://www.fitko.de/foederale-it-architektur/foederales-it-architekturmanagement","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:08.857160+00:00","lastSeen":"2026-03-15T17:54:08.857160+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/foederale-it-architektur/foederales-it-architekturmanagement","crawledAt":"2026-03-15T17:54:08.857160Z","crawlId":"contacts-seeded-1773597248","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"2f09b57c16daa2c6f1243d9a24a1a1cf65b811d3e89ca15a9b765f9339fb0378"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:08.857160+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('b716514f-6ea4-4289-b979-e81f4a4ef3c0', 'contacts', 'https://www.fitko.de/foederale-it-architektur/standards', 'active', NULL, '2026-03-15T17:54:09.323030+00:00', '{"id":"b716514f-6ea4-4289-b979-e81f4a4ef3c0","title":"Föderale IT-Standards","summary":{"de":"Die Seite Föderale IT-Standards der FITKO."},"content":{"de":"Damit ein einfacher Datenaustausch zwischen den Verwaltungen von Bund, Ländern und Kommunen erfolgen kann, bedarf es abgestimmter Standards, z. B. Schnittstellenformate und technische Systeme. Die Standards werden vom IT-Planungsrat beschlossen. Als FITKO unterstützen wir diesen bei Entwicklung, Betrieb und Pflege der Standards. Nach dem IT-Staatsvertrag beschließt der IT-Planungsrat fachunabhängige und fachübergreifende IT-Interoperabilitäts- und Sicherheitsstandards. Als FITKO stehen wir hierbei unterstützend und steuernd zur Seite und übernehmen folgende Aufgaben: Unterstützung & Überblick Über unser Architektur-, Projekt- und Produktmanagement unterstützen wir den IT-Planungsrat bei der Entwicklung und dem Betrieb von Standards. Dabei behalten wir den Überblick über das Portfolio aller aktiven IT-Standards. Über unser Architektur-, Projekt- und Produktmanagement unterstützen wir den IT-Planungsrat bei der Entwicklung und dem Betrieb von Standards. Dabei behalten wir den Überblick über das Portfolio aller aktiven IT-Standards. Beratung & Koordination bei Standardisierungsbedarfen Im Rahmen der Führung der Standardisierungsagenda beraten und koordinieren wir den IT-Planungsrat bei neuen Standardisierungsbedarfen. Im Rahmen der Führung der Standardisierungsagenda beraten und koordinieren wir den IT-Planungsrat bei neuen Standardisierungsbedarfen."},"url":"https://www.fitko.de/foederale-it-architektur/standards","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:09.323030+00:00","lastSeen":"2026-03-15T17:54:09.323030+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/foederale-it-architektur/standards","crawledAt":"2026-03-15T17:54:09.323030Z","crawlId":"contacts-seeded-1773597249","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"eb4f184783bf0b1af878525f84366b985b9ad7e275f93239d597a7fbe98385b6"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:54:09.323030+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('567bed0f-5026-492f-a1b1-ec989936bc08', 'contacts', 'https://www.fitko.de/foederale-koordination', 'active', NULL, '2026-03-15T17:54:09.903888+00:00', '{"id":"567bed0f-5026-492f-a1b1-ec989936bc08","title":"Föderale Koordination","summary":{"de":"Als FITKO sorgen wir dafür, dass die beteiligten Akteur:innen und Entscheider:innen von Bund, Ländern und Kommunen in den Austausch kommen, zu gemeinsamen Lösungen finden und so die Digitalisierung der Verwaltung sowohl im Sinne der Nutzer:innen als auch der Verwaltungen selbst gemeinschaftlich voranbringen."},"content":{"de":"Vernetzt & auf Augenhöhe. Wir sorgen für föderalen Dialog. Die föderale Zusammenarbeit im Bereich IT und digitaler Verwaltung lebt von weitreichenden Dialogstrukturen, die alle relevanten Stakeholder aktiv miteinbezieht und gut miteinander vernetzt. Als FITKO sorgen wir dafür, dass die beteiligten Akteur:innen und Entscheider:innen von Bund, Ländern und Kommunen in den Austausch kommen, zu gemeinsamen Lösungen finden und so die Digitalisierung der Verwaltung sowohl im Sinne der Nutzer:innen als auch der Verwaltungen selbst gemeinschaftlich voranbringen. Koordination IT-Planungsrat Wir unterstützen den IT-Planungsrat organisatorisch und strategisch – vom Sitzungsmanagement bis zur allgemeinen Steuerung des IT-Planungsrats und seiner Themen. Zur Koordination IT-Planungsrat Wir unterstützen den IT-Planungsrat organisatorisch und strategisch – vom Sitzungsmanagement bis zur allgemeinen Steuerung des IT-Planungsrats und seiner Themen. Föderale Digitalstrategie Die Föderale Digitalstrategie schafft ein Zukunftsbild der Verwaltung und beschreibt Leitlinien für gemeinsame Handlungsgrundsätzeleisten. Zur Föderalen Digitalstrategie Die Föderale Digitalstrategie schafft ein Zukunftsbild der Verwaltung und beschreibt Leitlinien für gemeinsame Handlungsgrundsätzeleisten."},"url":"https://www.fitko.de/foederale-koordination","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:09.903888+00:00","lastSeen":"2026-03-15T17:54:09.903888+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/foederale-koordination","crawledAt":"2026-03-15T17:54:09.903888Z","crawlId":"contacts-seeded-1773597249","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"beae5d1430456c8ecdbf4f8fd6783c566b0ef8759609d1f6aff7eef62081963c"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:09.903888+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('3dc5929e-753e-467e-946d-05715f15581c', 'contacts', 'https://www.fitko.de/foederale-koordination/gremienarbeit', 'active', NULL, '2026-03-15T17:54:10.419344+00:00', '{"id":"3dc5929e-753e-467e-946d-05715f15581c","title":"Gremienarbeit","summary":{"de":"Die Seite Gremienarbeit des IT-Planungsrats."},"content":{"de":"Verschiedene Gremien und Arbeitsgruppen, bei Bedarf auch temporäre Projektstrukturen, beraten den IT-Planungsrat bei seiner Entscheidungsfindung und der Ausgestaltung seiner Beschlüsse. Als FITKO unterstützen wir die Gremienarbeit des IT-Planungsrats. Hierfür koordinieren wir den Informationsfluss, bündeln die Entscheidungsprozesse, beteiligen uns häufig an der Umsetzung von Beschlüssen oder übernehmen Aufgaben des IT-Planungsrats in eigener Verantwortung. Zudem sind wir selbst aktives Mitglied in verschiedenen Gremien und Arbeitsgruppen. Hier ist eine Übersicht der Gremien, an denen wir beteiligt sind. Die vollständige Übersicht der Gremienlandschaft des IT-Planungsrats gibt es auf der Website des IT-Planungsrats: Die Abteilungsleitungsrunde fungiert als vorbereitendes Gremium für den IT-Planungsrat. Sie bereitet dessen Sitzungen fachlich vor und gibt hierzu Beschlussempfehlungen ab. Darüber hinaus trifft sie abschließende Entscheidungen zu konkret durch den IT-Planungsrat übertragen Aufgaben. Die FITKO fungiert als beratendes Mitglied und Organisator und führt das Sitzungsmanagement. Leopold Klemencic Koordination IT-Planungsrat Telefon +49 (69) 401270 228 E-Mail Kontakt aufnehmen"},"url":"https://www.fitko.de/foederale-koordination/gremienarbeit","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:10.419344+00:00","lastSeen":"2026-03-15T17:54:10.419344+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/foederale-koordination/gremienarbeit","crawledAt":"2026-03-15T17:54:10.419344Z","crawlId":"contacts-seeded-1773597250","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"1f194db0ce4abcc9819ed5ff81d62ddaa6c87f651c663c33314a6f3abe0b4079"},"qualityScores":{"iqs":84.58,"ais":79.0,"computedAt":"2026-03-15T17:54:10.419344+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c93cf793-cc52-4ab7-9711-fe3588d475ac', 'contacts', 'https://www.fitko.de/foederale-koordination/gremienarbeit/foederales-it-architekturboard', 'active', NULL, '2026-03-15T17:54:10.872451+00:00', '{"id":"c93cf793-cc52-4ab7-9711-fe3588d475ac","title":"Föderales IT-Architekturboard","summary":{"de":"Die Seite Föderales IT-Architekturboard der FITKO."},"content":{"de":"Das föderale Architekturboard unterstützt und berät den IT-Planungsrat in strategischen Fragen bei der Entwicklung und Umsetzung von Maßnahmen der IT-Architektur. Zu den Aufgaben des Boards gehören u. a. die Beschreibung und Fortführung föderaler IT-Architekturrichtlinien, die Initiierung von Architekturvorhaben sowie die kurzfristige Bereitstellung dringend benötigter Lösungen im Rahmen der Umsetzung des Onlinezugangsgesetzes. Das Architekturboard begleitet zudem mit sog. „Projektpaten“ Infrastrukturprojekte mit Auswirkungen auf die föderale IT-Architektur. Die FITKO hat das föderale Architekturboard initiiert und den Vorsitz inne. Die Abteilungsleiterrunde und der IT-Planungsrat sollen ohne vorherige Einbindung des Boards keine Entscheidungen mit Relevanz für die föderale IT-Architektur treffen. Die Arbeit findet zwischen den Sitzungen statt. Das föderale IT-Architekturboard initialisiert Arbeitspakete, in denen es die Themen selbst inhaltlich erarbeitet. Die Arbeitspakete werden von einem Team in einem definierten Zeitraum zur Entscheidungsreife gebracht. Das Architekturboard priorisiert die Arbeitspakete auf Grundlage von gewichteten und intern abgestimmten Kriterien. Gestaltung und Konzeption der föderalen IT-Architektur, Definition von Architekturrichtlinien. Bund (Bundesministerium des Innern und für Heimat)"},"url":"https://www.fitko.de/foederale-koordination/gremienarbeit/foederales-it-architekturboard","topics":["public_service","contacts"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T17:54:10.872451+00:00","lastSeen":"2026-03-15T17:54:10.872451+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"FITKO","provenance":{"source":"https://www.fitko.de/foederale-koordination/gremienarbeit/foederales-it-architekturboard","crawledAt":"2026-03-15T17:54:10.872451Z","crawlId":"contacts-seeded-1773597250","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","sourceId":"fitko","providerName":"FITKO","providerLevel":"federal","checksum":"4d8c269ac37bc86c59f5e5f338a61f5afb27db1995ed18c3fb718575ea97d855"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T17:54:10.872451+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('c2c5e33c-12ad-4110-8ec1-5a1cddd1186c', 'contacts', 'https://www.fitko.de/kontakt', 'active', NULL, '2026-03-15T16:06:57.084330+00:00', '{"id":"c2c5e33c-12ad-4110-8ec1-5a1cddd1186c","title":"Kontakt","summary":{"de":"Wenn Sie mit uns in Kontakt treten möchten, schreiben Sie uns gerne eine E-Mail oder rufen Sie uns an: +49 (69) 401270 0"},"content":{"de":"Die Kontaktdaten aller FITKO-Mitarbeitenden finden Sie hier: Informationen und Ansprechpersonen zu einem von der FITKO betreuten Thema, Produkt oder Projekt finden Sie auf der jeweiligen Unterseite, die Sie über das Menü erreichen. Unsere Postanschrift (im Gebäude der Oberfinanzdirektion Frankfurt) lautet: FITKO (Föderale IT-Kooperation) Zum Gottschalkhof 3 60594 Frankfurt am Main Wenn Sie uns besuchen, nutzen Sie am besten den Eingang „Zum Laurenburger Hof“, dort finden Sie uns im 4. Stock: Zum Laurenburger Hof 76 60594 Frankfurt am Main S-Bahn: S 1, S 2, S 8, S 9 (Richtung Rödermark, Offenbach, Hanau) bis Mühlberg (Fahrtzeit ca. 10 min + Laufweg ca. 12 min) S-Bahn: S 3, S 4, S 5, S 6 (Richtung Darmstadt, Langen, Frankfurt Süd) bis Lokalbahnhof | Ausgang Siemensstraße (Fahrtzeit ca. 10 min + Laufweg ca. 15 min) S-Bahn: S 3, S 4, S 5, S 6 (Richtung Bad Soden, Kronberg, Friedrichsdorf, Friedberg), bis Lokalbahnhof | Ausgang Siemensstraße (Fahrtzeit ca. 1 min + Laufweg ca. 15 min) Straßenbahn: Tram 15 und 16 (Richtung Offenbach) bis Heister-/Seehofstr. (Fahrtzeit ca. 4 min + Laufweg ca. 15 min) Bus: Buslinie 45 bis Haltestelle Deutschherrnbrücke (Fahrtzeit ca. 10 min, hält direkt vor MAIN TRIANGEL) S-Bahn: S 8, S 9 (Richtung Offenbach, Hanau) bis Mühlberg (Fahrtzeit ca. 20 Min. + Laufweg ca. 12 min) Verbindungsauskunft des Rhein-Main-Verkehrsverbundes"},"url":"https://www.fitko.de/kontakt","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:57.084330+00:00","lastSeen":"2026-03-15T16:06:57.084330+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://www.fitko.de/kontakt","crawledAt":"2026-03-15T16:06:57.084330Z","crawlId":"contacts-seeded-1773590817","crawlerVersion":"0.1.0","sourceTier":"tier_1_official","institutionType":"government","jurisdiction":"DE","checksum":"bd72e9e9931224284d4394ff5962b46ce8f997080f8778a0b79225f0dca278bf"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:06:57.084330+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('340a9572-a6b0-4c3b-85e8-07793f40fdc5', 'contacts', 'https://www.fitko.de/produktmanagement/115', 'active', NULL, '2026-03-15T16:06:57.378244+00:00', '{"id":"340a9572-a6b0-4c3b-85e8-07793f40fdc5","title":"115","summary":{"de":"Einheitliche Behördennummer für Bürger:innen und Unternehmen Die bundesweit einheitliche Rufnummer 115 ist ein bürger:innennaher und direkter Kanal in die Verwaltung. Ihr Kern ist die telefonische Antwort auf Fragen zu allen Angelegenheiten der öffentlichen Verwaltung auf kommunaler, Landes- und Bundesebene. Für gehörlose oder hörgeschädigte Personen steht das 115-Gebärdentelefon zur Verfügung. Zur Website von 115"},"content":{"de":"Die bundesweit einheitliche Rufnummer 115 ist ein bürger:innennaher und direkter Kanal in die Verwaltung. Ihr Kern ist die telefonische Antwort auf Fragen zu allen Angelegenheiten der öffentlichen Verwaltung auf kommunaler, Landes- und Bundesebene. Für gehörlose oder hörgeschädigte Personen steht das 115-Gebärdentelefon zur Verfügung. Thorsten Maid Teamleitung | Produktmanagement 115 Telefon +49 (69) 401270 106 E-Mail Kontakt aufnehmen Antje Zahn Produktmanagement 115 | Flächendeckung und Qualitätsmanagement Telefon +49 (69) 401270 151 E-Mail Kontakt aufnehmen Produktmanagement 115 | Flächendeckung und Qualitätsmanagement"},"url":"https://www.fitko.de/produktmanagement/115","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:06:57.378244+00:00","lastSeen":"2026-03-15T16:06:57.378244+00:00","sourceUnavailable":false,"contactType":"helpline","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"https://www.fitko.de/produktmanagement/115","crawledAt":"2026-03-15T16