INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('7f132650-e2a2-4b57-a34d-440865f00de4', 'contacts', 'https://www.gebaerdentelefon.de/115', 'active', NULL, '2026-03-01T20:18:00Z', '{"id":"7f132650-e2a2-4b57-a34d-440865f00de4","title":"Gebärdentelefon 115","translations":{"de-LEICHT":{"title":"115 in Gebärdensprache","timestamp":"2026-03-01T20:18:00Z","provenance":{"source":"https://www.115.de/DE/Service/Gebaerdentelefon/gebaerdentelefon_node.html","crawledAt":"2026-03-01T20:18:00Z"},"method":"human","reviewed":true}},"summary":{"de":"Das Gebärdentelefon 115 erweitert den Zugang zur Behördennummer 115 um barrierearme Kommunikation für hörbeeinträchtigte Menschen."},"content":{"de":"Das Angebot ergänzt den regulären 115-Service um einen inklusiven Zugangskanal. Dadurch wird die Erreichbarkeit von Behördeninformationen für eine wichtige Zielgruppe verbessert."},"url":"https://www.gebaerdentelefon.de/115","topics":["employment","family"],"tags":["urgent","automatic"],"targetGroups":["disabled","refugees","families"],"status":"active","contactType":"accessibility","specialization":["Barrierefreie Behördenkommunikation"],"availability":{"hours":"Siehe Anbieterhinweise","languages":["de"]},"linkedOrganization":"115-Verbund / FITKO","firstSeen":"2026-03-01T20:18:00Z","lastSeen":"2026-03-01T20:18:00Z","sourceUnavailable":false,"provenance":{"source":"https://www.gebaerdentelefon.de/115","crawlId":"manual-curation-20260301-realdata-v1","checksum":"32db8b7788386f2bbcd7cd8b95b5376d42fb1f0f01adf17f7e1aa7364fa56178","crawledAt":"2026-03-01T20:18:00Z"},"qualityScores":{"iqs":77.8,"ais":49.8,"computedAt":"2026-03-01T20:18:00Z"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
INSERT INTO entries (id, domain, url, status, title_de, updated_at, entry_json) VALUES ('ad73132a-b914-42a2-934c-7b720cc444dd', 'contacts', 'https://www.pausentaste.de/', 'active', NULL, '2026-03-15T16:07:09.855881+00:00', '{"id":"ad73132a-b914-42a2-934c-7b720cc444dd","title":"Wer anderen hilft, braucht manchmal selber Hilfe.","summary":{"de":"Du kümmerst dich um ein krankes Familienmitglied? Hier bist du richtig! Ein Angebot des Bundesfamilienministeriums für pflegende Kinder und Jugendliche."},"content":{"de":"Dein Alltag und Du: Drück die Pausentaste und schau, was dich in deinem Alltag stark macht! Eben war noch alles normal – jetzt ist alles anders: Wenn deine Mutter oder dein Vater Krebs bekommen, verändert das auch dein Leben. Zum Weltkrebstag… Ennie Skoras Bruder Mads hat das Down-Syndrom – und tausende Fans auf Social Media: Als @twoandadownmen geben Mads und seine Mitbewohner einem großen… Kurz mal durchatmen: Fünf Auszeiten, für die du weder Planung, noch Vorbereitung brauchst. Studentin Tilda kümmert sich um ihre kleine Schwester Ida und die alkoholkranke Mutter. Im neuen Teil der Close Up-Reihe sprechen wir mit der Grundschullehrkraft Desiree Wollik."},"url":"https://www.pausentaste.de/","topics":["contacts","public_service"],"tags":["contact"],"targetGroups":["general_public","families","persons_with_disabilities"],"status":"active","firstSeen":"2026-03-15T16:07:09.855881+00:00","lastSeen":"2026-03-15T16:07:09.855881+00:00","sourceUnavailable":false,"contactType":"office","specialization":["Buergeranfragen","Leistungsinformationen"],"availability":{"hours":"Siehe verlinkte Quelle","languages":["de"]},"linkedOrganization":"Oeffentliche Verwaltung","provenance":{"source":"http://www.pausentaste.de/","crawledAt":"2026-03-15T16:07:09.855881Z","crawlId":"contacts-seeded-1773590829","crawlerVersion":"0.1.0","sourceTier":"tier_unknown","institutionType":"unknown","jurisdiction":"DE","checksum":"8e286ac10d4a345f9b02aa557031cc5e3700c4f9fd6d25c218d434ad0a79dee3"},"qualityScores":{"iqs":84.58,"ais":84.0,"computedAt":"2026-03-15T16:07:09.855881+00:00"}}') ON CONFLICT(id) DO UPDATE SET domain=excluded.domain, url=excluded.url, status=excluded.status, title_de=excluded.title_de, updated_at=excluded.updated_at, entry_json=excluded.entry_json;
